-- ============================================
-- SP: BI_HR_LeaveCost_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_HR_LeaveCost_sp]   @Date DATETIME2,  @EmployeeTypeId INT = 0,  @EmployeeSubTypeId INT = 0,  @DepartmentId INT = 0,  @DivisionId INT = 0      AS  BEGIN     SET NOCOUNT ON;    SELECT   e.[Employee_ID], e.[FirstName], e.[Surname], dep.[DepartmentDesc], div.[DivisionDesc], pos.[ScoaShortDesc], pos.[ScoaDesc],   leave.[LeaveTypeDesc] AS 'LeaveType',   LTRIM(FORMAT(e.[AnnualSalary], '### ### ##0.00')) AS 'AnnualSalary',   LTRIM(FORMAT(RatePerDay, '### ### ##0.00')) AS 'RatePerDay',   ISNULL(leave.[LeaveBalance], 0) AS 'LeaveBalance',   LTRIM(FORMAT(CAST(ISNULL(leave.LeaveBalance, 0) * ISNULL(RatePerDay, 0) AS DECIMAL(15, 2)), '### ### ##0.00')) AS 'LeaveCost',   @Date AS 'Calcdate',   et.[EmployeeTypeDescription], est.[EmployeeSubtypeDesc]  FROM   (    SELECT     pe.[Employee_ID], pe.[FirstName], pe.[Surname], pe.[JobProfileID],     ISNULL(eh.[AnnualSalary], pe.[AnnualSalary]) AS 'AnnualSalary',     ISNULL(eh.[RPD_Monthly], pe.[RPD_Monthly]) AS 'RPD_Monthly',     ISNULL(eh.[EmployeeTypeID], pe.[EmployeeTypeID]) AS 'EmployeeTypeID',     ISNULL(eh.[EmployeeSubtypeID], pe.[EmployeeSubtypeID]) AS 'EmployeeSubtypeID',     CASE WHEN Isnull(Rate,0) <> 0 then Rate else pe.FixedSalary/pe.WDPM_Monthly END AS 'RatePerDay'    FROM     Payroll_Employee pe    LEFT JOIN     Payroll_EmployeeHistory eh ON pe.[Employee_ID] = eh.[EmployeeID]             AND eh.[Enabled] = 1             AND @Date BETWEEN eh.[StartDate] AND eh.[EndDate]   ) e  OUTER APPLY   (    SELECT DISTINCT     ph.[DepartmentID], ph.[DivisionID], func.[ScoaShortDesc], func.[ScoaDesc]    FROM     Payroll_PositionHistory ph    LEFT JOIN     Const_SCOA_Function_Structure func ON ph.[FunctionID] = func.[ScoaID]    WHERE     ph.[Enabled] = 1    AND ph.[EmployeeID] = e.[Employee_ID]    AND ph.[JobProfileID] = e.[JobProfileID]    AND @Date BETWEEN ph.[StartDate] AND ph.[EndDate]   ) pos  FULL OUTER JOIN   Const_Department dep ON pos.[DepartmentID] = dep.[Department_ID]  FULL OUTER JOIN   Const_Division div ON pos.[DivisionID] = div.[Division_ID]  FULL OUTER JOIN   Const_EmployeeType_sys et ON e.[EmployeeTypeID] = et.[EmployeeType_ID]  FULL OUTER JOIN   Payroll_EmployeeSubtypes est ON e.[EmployeeSubtypeID] = est.[EmployeeSubtype_ID]  OUTER APPLY   (    SELECT     lt.[LeaveTypeDesc], SUM(elt.[Value]) AS 'LeaveBalance'    FROM     Const_LeaveType lt    INNER JOIN     payroll_employeeLeaveTransactions elt ON lt.[LeaveType_ID] = elt.[LeaveTypeID]               AND elt.[EndDate] <= @Date    WHERE     lt.[LeaveClassificationID] = 1    AND elt.[EmployeeID] = e.[Employee_ID]    GROUP BY     lt.[LeaveTypeDesc]   ) leave  WHERE  (e.[EmployeeTypeID] = ISNULL(@EmployeeTypeId,0) OR ISNULL(@EmployeeTypeId,0) = 0)   AND (e.[EmployeeSubtypeID] = ISNULL(@EmployeeSubTypeId,0) OR ISNULL(@EmployeeSubTypeId,0) = 0)   AND (pos.[DepartmentID] = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)  AND (pos.[DivisionID] = ISNULL(@DivisionId,0) OR ISNULL(@DivisionId,0) = 0)  AND leave.[LeaveBalance] > 0   ORDER BY   e.[Employee_ID]  END

GO

-- ============================================
-- SP: BI_HR_LeaveExcess_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_HR_LeaveExcess_sp]   @Date DATETIME2,  @EmployeeTypeId INT = 0,  @EmployeeSubTypeId INT = 0,  @DepartmentId INT = 0,  @DivisionId INT = 0,  @Excess INT = 0,  @LeaveTypeId INT = 0    AS  BEGIN     SET NOCOUNT ON;    SELECT emp.Employee_ID, emp.FirstName, emp.Surname, balance.LeaveBalance, dep.DepartmentDesc, div.DivisionDesc, leaveT.LeaveTypeDesc, emptype.EmployeeTypeDescription, empsub.EmployeeSubtypeDesc  FROM     payroll_Employee AS emp LEFT OUTER JOIN                    payroll_position AS pos ON emp.Employee_ID = pos.EmployeeID FULL OUTER JOIN                    Const_Department AS dep ON dep.Department_ID = pos.DepartmentID FULL OUTER JOIN                    Const_Division AS div ON div.Division_ID = pos.DivisionID FULL OUTER JOIN                    Payroll_EmployeeSubtypes AS empsub ON empsub.EmployeeSubtype_ID = emp.EmployeeSubtypeID FULL OUTER JOIN                    Const_EmployeeType_sys AS emptype ON emptype.EmployeeType_ID = emp.EmployeeTypeID LEFT OUTER JOIN                        (SELECT LeaveTypeID, EmployeeID, SUM(Value) AS LeaveBalance                         FROM      payroll_employeeLeaveTransactions AS leave                         WHERE   (EndDate <= @Date)                         GROUP BY LeaveTypeID, EmployeeID) AS balance ON balance.EmployeeID = emp.Employee_ID FULL OUTER JOIN                    Const_LeaveType AS leaveT ON leaveT.LeaveType_ID = balance.LeaveTypeID  WHERE  (balance.LeaveTypeID = @LeaveTypeId OR                    ISNULL(@LeaveTypeId, 0) = 0) AND (pos.DepartmentID = @DepartmentId OR                    ISNULL(@DepartmentId, 0) = 0) AND (pos.DivisionID = @DivisionId OR                    ISNULL(@DivisionId, 0) = 0) AND (emp.EmployeeTypeID = @EmployeeTypeId OR                    ISNULL(@EmployeeTypeId, 0) = 0) AND (emp.EmployeeSubtypeID = @EmployeeSubTypeId OR                    ISNULL(@EmployeeSubTypeId, 0) = 0) AND (balance.LeaveBalance >= @Excess)  END

GO

-- ============================================
-- SP: BI_Payroll_LeaveBalance_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_Payroll_LeaveBalance_sp]      @Date DATETIME2,      @DepartmentId INT = 0,      @DivisionId INT = 0,      @EmployeeSubtypeId INT = 0,      @LeaveTypeId INT = 0,      @EmployeeTypeId INT = 0,      @EmployeeId INT = 0  AS  BEGIN    SELECT       E.Employee_ID AS EmployeeId,      E.FirstName,       E.Surname,       DEP.DepartmentDesc,       DIV.DivisionDesc,      LT.LeaveTypeDesc,      SUM(Value) AS LeaveBalance  FROM Payroll_EmployeeLeaveTransactions AS ELT      JOIN Payroll_Employee AS E WITH (NOLOCK) ON ELT.EmployeeID = E.Employee_ID      JOIN Const_LeaveType AS LT WITH (NOLOCK) ON ELT.LeaveTypeID = LT.LeaveType_ID      LEFT JOIN Payroll_Position AS P WITH (NOLOCK) ON E.Employee_ID = P.EmployeeID AND e.[JobProfileID] = p.[JobProfileID]      LEFT JOIN Const_Department AS DEP WITH (NOLOCK) ON DEP.Department_ID = P.DepartmentID      LEFT JOIN Const_Division AS DIV WITH (NOLOCK) ON DIV.Division_ID = P.DivisionID      JOIN Const_EmployeeType_sys AS ET WITH (NOLOCK) ON ET.EmployeeType_ID = E.EmployeeTypeID      JOIN Payroll_EmployeeSubtypes AS EST WITH (NOLOCK) ON EST.EmployeeSubtype_ID = E.EmployeeSubtypeID  WHERE ELT.EndDate <= @Date AND ELT.Enabled = 1          AND (ISNULL(@EmployeeId, 0) = 0 OR E.Employee_ID = @EmployeeId)      AND (ISNULL(@DepartmentId, 0) = 0 OR DEP.Department_ID = @DepartmentId)      AND (ISNULL(@DivisionId, 0) = 0 OR DIV.Division_ID = @DivisionId)      AND (ISNULL(@EmployeeTypeId, 0) = 0 OR E.EmployeeTypeID = @EmployeeTypeId)      AND (ISNULL(@EmployeeSubtypeId, 0) = 0 OR E.EmployeeSubtypeID = @EmployeeSubtypeId)      AND (ISNULL(@LeaveTypeId, 0) = 0 OR LT.LeaveType_ID = @LeaveTypeId)  GROUP BY ELT.LeaveTypeID, LT.LeaveTypeDesc, E.Employee_ID, E.FirstName, E.Surname, DEP.DepartmentDesc, DIV.DivisionDesc  HAVING SUM(ELT.Value) > 0    END

GO

-- ============================================
-- SP: BI_Payroll_LeaveForfeit
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_Payroll_LeaveForfeit]      @LeaveBalanceDate DATETIME      ,@LeaveForfeitWithin INT = 6      ,@EmployeeId INT      ,@LeaveTypeId INT      ,@DepartmentId INT      ,@DivisionId INT      ,@EmployeeTypeId INT      ,@EmployeeSubTypeId INT      ,@LeaveClassificationId INT = 0   ,@FromDate DATETIME      ,@ToDate DATETIME   ,@Future nvarchar(5) = 'false'  AS  BEGIN    IF @Future = 'true'  BEGIN    DECLARE @CycleStartFixedDate INT = 1  DECLARE @CycleStartJoiningDate INT = 2  DECLARE @CycleStartCalendarYear INT = 3    DECLARE @LeaveStatusApproved INT = 3    DECLARE @ForfeitFilterEndDate DATETIME = DATEADD(MONTH, @LeaveForfeitWithin, @LeaveBalanceDate);    SELECT      PE.Employee_ID AS EmployeeNumber      ,PE.FirstName AS EmployeeName      ,PE.Surname AS EmployeeSurname      ,Department.DepartmentDesc AS Department      ,Division.DivisionDesc AS Division      ,CLT.LeaveTypeDesc AS LeaveType      ,CLTD.ExtentionDays AS ExtentionDays      ,ForfeitDate.EndDate AS CycleEndDate      ,DATEADD(DAY, CLTD.ExtentionDays, ForfeitDate.EndDate) AS LeaveForfeitedDate      ,ForfeitDays.Value AS DaysForfeited  FROM Payroll_Employee AS PE  LEFT JOIN Payroll_Position AS PP ON PE.Employee_ID = PP.EmployeeID AND PE.Enabled = 1  LEFT JOIN Const_Department AS Department ON PP.DepartmentID = Department.Department_ID  LEFT JOIN Const_Division AS Division ON PP.DivisionID = Division.Division_ID  JOIN Const_LeaveScheme AS CLS ON PE.LeaveSchemeID = CLS.LeaveScheme_ID  JOIN Const_LeaveSchemeTypeDetails AS CLSTD ON CLSTD.LeaveSchemeId = CLS.LeaveScheme_ID  JOIN Const_AbsenceType AS CAT ON CAT.AbsenceType_ID = CLSTD.LeaveTypeId  JOIN Payroll_AbsencePriority AS PAP ON PAP.AbsenceTypeID = CAT.AbsenceType_ID  JOIN Const_LeaveTypeDetails AS CLTD ON CLTD.LeaveTypeId = PAP.LeaveTypeID  JOIN Const_LeaveType AS CLT on CLT.LeaveType_ID = CLTD.LeaveTypeId    CROSS APPLY (SELECT       TOP 1 DT.StartDate      ,DT.EndDate       FROM GenerateDateRanges(       CASE CLT.CyclePeriodIDStart          WHEN @CycleStartJoiningDate THEN PE.JoiningDate          WHEN @CycleStartFixedDate THEN CLT.CycleStartDate          WHEN @CycleStartCalendarYear THEN DATEFROMPARTS(YEAR(CLT.StartDate), 1, 1)      END      ,@ForfeitFilterEndDate, CLT.CycleEnd, 'MONTH') AS DT          WHERE @LeaveBalanceDate BETWEEN DT.StartDate AND DT.EndDate          ORDER BY DT.StartDate ASC          ) AS ForfeitDate    CROSS APPLY (SELECT SUM(PELT.Value) AS Value       FROM Payroll_EmployeeLeaveTransactions AS PELT      WHERE PELT.EmployeeID = PE.Employee_ID           AND PELT.LeaveTypeID = CLT.LeaveType_ID           AND PELT.LeaveStatusID = @LeaveStatusApproved      GROUP BY PELT.LeaveTypeID      HAVING SUM(PELT.Value) > 0  ) AS ForfeitDays         WHERE (PE.Employee_ID = @EmployeeId OR ISNULL(@EmployeeId, 0) = 0)      AND CLTD.Forfeit = 1       AND CLTD.Enabled = 1      AND CLSTD.Enabled = 1      AND @LeaveBalanceDate BETWEEN CLTD.StartDate AND CLTD.EndDate      AND ForfeitDate.EndDate IS NOT NULL      AND ForfeitDays.Value IS NOT NULL      AND (Department.Department_ID = @DepartmentId OR ISNULL(@DepartmentId, 0) = 0)      AND (Division.Division_ID = @DivisionId OR ISNULL(@DivisionId, 0) = 0)      AND (PE.EmployeeTypeID = @EmployeeTypeId OR ISNULL(@EmployeeTypeId, 0) = 0)      AND (PE.EmployeeSubtypeID = @EmployeeSubTypeId OR ISNULL(@EmployeeSubTypeId, 0) = 0)      AND (CLT.LeaveType_ID = @LeaveTypeId OR ISNULL(@LeaveTypeId, 0) = 0)      AND (CLT.LeaveClassificationID = @LeaveClassificationId OR @LeaveClassificationId = 0)  ORDER BY      PE.Employee_ID    END    ELSE    BEGIN  DECLARE @leaveStatus_approved INT = 3  DECLARE @adjustmentType_forfeit INT = 4  DECLARE @cycleStart_fixedDate INT = 1  DECLARE @cycleStart_joiningDate INT = 2  DECLARE @cycleStart_calendarYear INT = 3    SELECT      PE.Employee_ID AS EmployeeNumber      ,PE.FirstName AS EmployeeName      ,PE.Surname AS EmployeeSurname      ,Department.DepartmentDesc AS Department      ,Division.DivisionDesc AS Division      ,CLT.LeaveTypeDesc AS LeaveType      ,DATEADD(DAY, -1, CycleStartDate.Dt) AS CycleEndDate      ,DATEADD(DAY, CLTD.ExtentionDays, DATEADD(DAY, -1, CycleStartDate.Dt)) AS LeaveForfeitedDate      ,CLTD.ExtentionDays AS ExtentionDays      ,PELT.Value AS DaysForfeited  FROM Payroll_EmployeeLeaveTransactions AS PELT      JOIN Payroll_Employee AS PE ON PELT.EmployeeID = PE.Employee_ID      LEFT JOIN Payroll_Position AS PP ON PE.Employee_ID = PP.EmployeeID      LEFT JOIN Const_Department AS Department ON PP.DepartmentID = Department.Department_ID      LEFT JOIN Const_Division AS Division ON PP.DivisionID = Division.Division_ID      JOIN Const_LeaveType AS CLT ON PELT.LeaveTypeID = CLT.LeaveType_ID      CROSS APPLY (          SELECT CASE              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_fixedDate                  THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, PELT.StartDate, SubCLT.CycleStartDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, SubCLT.CycleStartDate)              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_joiningDate                  THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, PELT.StartDate, PE.JoiningDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, PE.JoiningDate)              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_calendarYear                  THEN DATEFROMPARTS(YEAR(PELT.StartDate), 1, 1)              ELSE NULL          END AS Dt          FROM Const_LeaveType AS SubCLT          WHERE SubCLT.LeaveType_ID = CLT.LeaveType_ID) AS CycleStartDate      LEFT JOIN Const_LeaveTypeDetails AS CLTD ON CLT.LeaveType_ID = CLTD.LeaveTypeId AND (DATEADD(DAY, -1, CycleStartDate.Dt) BETWEEN CLTD.StartDate AND CLTD.EndDate)  WHERE PELT.StartDate >= @FromDate      AND PELT.EndDate <= @ToDate      AND PELT.LeaveAdjustmentTypeID = @adjustmentType_forfeit      AND PELT.LeaveStatusID = @leaveStatus_approved      AND PELT.Enabled = 1      AND (Department.Department_ID = @DepartmentId OR ISNULL(@DepartmentId, 0) = 0)      AND (Division.Division_ID = @DivisionId OR ISNULL(@DivisionId, 0) = 0)      AND (PE.EmployeeTypeID = @EmployeeTypeId OR ISNULL(@EmployeeTypeId, 0) = 0)      AND (PE.EmployeeSubtypeID = @EmployeeSubTypeId OR ISNULL(@EmployeeSubTypeId, 0) = 0)      AND (CLT.LeaveType_ID = @LeaveTypeId OR ISNULL(@LeaveTypeId, 0) = 0)      AND (PE.Employee_ID = @EmployeeId OR ISNULL(@EmployeeId, 0) = 0)  ORDER BY      PE.Employee_ID    END    END

GO

-- ============================================
-- SP: BI_Payroll_LeaveRegister
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_Payroll_LeaveRegister]      @StartDate DATETIME2,      @EndDate DATETIME2,      @DepartmentId INT,      @DivisionId INT,      @CycleId INT,      @LeaveTypeId INT,      @LeaveSchemeId INT,      @EmployeeId INT  AS  BEGIN    DECLARE      @leaveStatus_declined INT = 4,      @leaveStatus_cancelled INT = 5,   @TermCycle INT = (select Cycle_ID from Const_Cycle where CycleDesc = 'Ad Hoc Termination')    Select  E.Employee_ID AS EmployeeId,      E.EmpCode,      E.FirstName,      E.Surname,      E.JoiningDate,      LS.LeaveScheme_ID,      LS.LeaveSchemeDesc,      LT.LeaveType_ID,      LT.LeaveTypeDesc,      LAT.LeaveAdjustmentType,      ELT.DocumentNumber,      ELT.StartDate,      ELT.EndDate,      'Approved' AS 'Status',     ELT.Value AS Days      from(      --Opening balances     select EmployeeID,LeaveTypeId,Min(StartDate)StartDate,DATEADD(day,-1,@StartDate) EndDate,SUM(Value)Value,'Opening Balance' Notes,''DocumentNumber, 0 LeaveSchemeId,1 LeaveAdjustmentTypeID      from Payroll_EmployeeLeaveTransactions      where Enabled = 1      and LeaveStatusID = 3       and StartDate <= @StartDate      group by EmployeeID,LeaveTypeID    --Transactions     UNION ALL     select EmployeeID,LeaveTypeId, StartDate,EndDate,Value,Notes,DocumentNumber,LeaveSchemeID,LeaveAdjustmentTypeID      from Payroll_EmployeeLeaveTransactions      where Enabled = 1      and LeaveStatusID = 3        and StartDate > @StartDate      and EndDate <= @EndDate   )ELT      JOIN Payroll_Employee AS E WITH (NOLOCK) ON ELT.EmployeeID = E.Employee_ID    LEFT JOIN Payroll_Position AS P WITH (NOLOCK) ON P.Position_ID = E.PositionID    LEFT JOIN Const_Department AS DEP WITH (NOLOCK) ON P.DepartmentID = DEP.Department_ID    LEFT JOIN Const_Division AS DIV WITH (NOLOCK) ON P.DivisionID = DIV.Division_ID    LEFT JOIN Const_LeaveScheme LS WITH (NOLOCK) ON ELT.LeaveSchemeID = LS.LeaveScheme_ID    LEFT JOIN Const_LeaveType AS LT WITH (NOLOCK) ON ELT.LeaveTypeID = LT.LeaveType_ID    LEFT JOIN Const_LeaveAdjustmentType_sys AS LAT WITH (NOLOCK) ON ELT.LeaveAdjustmentTypeID = LAT.LeaveAdjustmentType_ID      WHERE  (ISNULL(@EmployeeId, 0) = 0 OR E.Employee_ID = @EmployeeId)      AND (ISNULL(@DepartmentId, 0) = 0 OR DEP.Department_ID = @DepartmentId)      AND (ISNULL(@DivisionId, 0) = 0 OR DIV.Division_ID = @DivisionId)      AND (ISNULL(@CycleId, 0) = 0 OR E.CycleID = @CycleId)      AND (E.EndDate >= @StartDate)      AND (ISNULL(@LeaveSchemeId, 0) = 0 OR ELT.LeaveSchemeID = @LeaveSchemeId)      AND (ISNULL(@LeaveTypeId, 0) = 0 OR ELT.LeaveTypeID = @LeaveTypeId)       order by ELT.EmployeeID,ELT.LeaveTypeID,ELT.StartDate    END

GO

