CREATE PROCEDURE [dbo].[BI_Payroll_Paypoint]       AS  BEGIN  select pp.[PayPoint_ID]        ,pp.[PayPointCode]        ,pp.[PayPointDesc]       ,d.Department_id      ,d.Departmentcode     ,d.departmentDesc            ,pp.[PayPointAddress]        ,pp.[PayPointLocation]        ,pp.[StartDate]        ,pp.[EndDate]        ,pp.[Enabled]        ,pp.[DateCaptured]        ,pp.[CapturerID]        ,pp.[DateModified]        ,pp.[ModifierID] from payroll_paypoint pp  left  join payroll_paypointdetails ppd on ppd.paypointid  = pp.payPoint_id  left join const_department d on d.department_id = ppd.DepartmentID  END

