-- ============================================
-- SP: BI_Payroll_SalaryTransactionDetail_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_Payroll_SalaryTransactionDetail_sp]   @TaxYear NVARCHAR(MAX),   @Cycle INT,   @Period INT,   @TransactionType  INT ,   @SalaryTransaction NVARCHAR(MAX)  ,   @Department INT,   @ExcessValue FLOAT,      @TrialRun BIT    AS   BEGIN    DECLARE @Periods NVARCHAR(MAX) =''    DECLARE @PurpuseYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    IF(@Cycle !=0)   SELECT @Periods = CAST(@Period AS NVARCHAR(MAX)) + ','  ELSE   SELECT @Periods = @Periods + CAST(Period_ID AS NVARCHAR(MAX)) + ','    FROM Payroll_CyclePeriodDetails    WHERE TaxYear = @TaxYear     AND Processed != @TrialRun     AND Enabled = 1     AND PeriodEndDate BETWEEN (SELECT PCPD.PeriodStartDate FROM Payroll_CyclePeriodDetails AS PCPD WHERE PCPD.Period_ID = @Period)      AND (SELECT PCPD.PeriodEndDate FROM Payroll_CyclePeriodDetails AS PCPD WHERE PCPD.Period_ID = @Period)    DROP TABLE IF EXISTS #Results  CREATE TABLE #Results  (  EmployeeID INT,  Amount FLOAT,  TransactionTypeID INT,  PeriodID INT,  SalaryHeadID INT  )    IF (@TrialRun = 0)   BEGIN    INSERT INTO #Results(EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID)    SELECT EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID    FROM Payroll_PayrollResults     WHERE (CycleID = @Cycle OR @Cycle = 0)      AND (@TransactionType = 0 OR TransactionTypeID = @TransactionType )     AND (SalaryHeadID IN (SELECT VALUE FROM  STRING_SPLIT(@SalaryTransaction,',')) OR @SalaryTransaction = '')     AND Amount> @ExcessValue      AND TaxYear = @PurpuseYear     AND PeriodID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))     AND (DepartmentID = @Department OR @Department=0)   END  ELSE   BEGIN    INSERT INTO #Results(EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID)    SELECT EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID    FROM Payroll_TrialResults     WHERE (CycleID = @Cycle OR @Cycle = 0)      AND (@TransactionType = 0 OR TransactionTypeID = @TransactionType )     AND (SalaryHeadID IN (SELECT VALUE FROM  STRING_SPLIT(@SalaryTransaction,',')) OR @SalaryTransaction = '')     AND Amount> @ExcessValue      AND TaxYear = @PurpuseYear     AND PeriodID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))     AND (DepartmentID = @Department OR @Department=0)   END    SELECT P_PR.EmployeeId AS EmployeeNumber     ,PE.FirstName AS EmployeeName     ,PE.Surname AS EmployeeSurname    ,C_Dep.DepartmentDesc AS Department    ,C_Div.DivisionDesc AS Division     ,C_C.CycleDesc AS PayrollCycle     ,C_TT.TransactionTypeDesc AS TransactionType        , P_SH.SalaryHeadName AS SalaryTranaction    , SUM(P_PR.Amount) AS Amount    FROM #Results AS P_PR  JOIN Payroll_Employee AS PE     ON P_PR.EmployeeID = PE.Employee_ID  CROSS APPLY (SELECT TOP 1 P_EH.EmployeeID, P_EH.CycleID, P_EH.DepartmentID, P_EH.DivisionID    FROM Payroll_EmployeeHistory as P_EH       JOIN Payroll_CyclePeriodDetails AS P_CPD     ON P_CPD.Period_ID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))    WHERE P_EH.EmployeeID = PE.Employee_ID     AND (P_EH.StartDate < P_CPD.PeriodEndDate AND P_EH.EndDate >P_CPD.PeriodStartDate)     AND P_EH.Enabled = 1) AS P_E  JOIN Const_Cycle AS C_C   ON P_E.CycleID = C_C.Cycle_ID  JOIN Const_Department AS C_Dep   ON P_E.DepartmentID = C_Dep.Department_ID  JOIN Const_Division AS C_Div    ON P_E.DivisionID = C_Div.Division_ID  JOIN Const_TransactionType AS C_TT   ON P_PR.TransactionTypeID = C_TT.TransactionType_ID   JOIN Payroll_CyclePeriodDetails AS P_CPD   ON P_PR.PeriodID=P_CPD.Period_ID  JOIN Payroll_SalaryHead AS P_SH   ON P_PR.SalaryHeadID=P_SH.SalaryHead_ID  GROUP BY P_PR.EmployeeId   , P_PR.PeriodID   , P_SH.SalaryHeadName   , PE.FirstName   , PE.Surname   , P_CPD.Period_ID   , C_Dep.DepartmentDesc    , C_Div.DivisionDesc    , C_C.CycleDesc    , C_TT.TransactionTypeDesc   ORDER BY P_SH.SalaryHeadName    DROP TABLE IF EXISTS #Results    END

GO

-- ============================================
-- SP: BI_rptIrp5TaxTotalDetailPerEmployee
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_rptIrp5TaxTotalDetailPerEmployee]    @TaxYear nvarchar(9),    @EmployeeId int = 0,    @Irp5CodeId int = 0,    @Month int = 2    AS  BEGIN    SELECT      RIGHT('00000000' + CAST(aa.[EmployeeID] AS VARCHAR), 8) AS 'EmployeeID',  aa.[EmployeeID],  aa.[Initials],  aa.[Surname],  aa.[IRP5Code],  aa.[SalaryHeadName],  aa.[IsRFI],  aa.[CurrentMonth],  aa.[Amount],  aa.[AnnualAmount]  FROM  (  SELECT  pr.[EmployeeID],  e.[Initials],  e.[Surname],  /*CASE  WHEN pr.[IRP5Code] IN ('4001', '4472') THEN '4001'  WHEN pr.[IRP5Code] IN ('4005', '4474') THEN '4005'  WHEN pr.[IRP5Code] IN ('4003', '4473') THEN '4003'  ELSE pr.[IRP5Code]  END AS 'IRP5Code',*/  pr.[IRP5Code],  sh.[SalaryHeadName],  pr.[IsRFI],  aa.[MinAmount] AS 'CurrentMonth',  SUM(pr.[Amount]) AS 'Amount',  aa.[MinAmount] * CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 12  /* WEEKLY */  WHEN 2 THEN 52  /* Bi-WEEKLY */  WHEN 3 THEN 26  END AS 'AnnualAmount'  FROM  Payroll_PayrollResults pr  INNER JOIN  Payroll_Employee e ON pr.[EmployeeID] = e.[Employee_ID]  INNER JOIN  Const_Cycle c ON e.[CycleID] = c.[Cycle_ID]  AND c.[Enabled] = 1  INNER JOIN  Payroll_CyclePeriodDetails cpd ON pr.[PeriodID] = cpd.[Period_ID]   AND cpd.[Enabled] = 1  INNER JOIN  Payroll_IRP5Code irp ON pr.[IRP5CodeID] = irp.[IRP5Code_ID]  AND irp.[Enabled] = 1  AND NOT (irp.[TransactionTypeID] = 2 and ISNULL(irp.[IRP5CertCode], irp.[IRP5Code]) = 0)  INNER JOIN  Payroll_SalaryHead sh ON pr.[SalaryHeadID] = sh.[SalaryHead_ID]  AND sh.[Enabled] = 1  OUTER APPLY  (  SELECT DISTINCT  ibb.[MinAmount]  FROM  (  SELECT TOP 1  icpd.[Period_ID]  FROM  Payroll_CyclePeriodDetails icpd  WHERE  cpd.[CycleID] = icpd.[CycleID]  AND cpd.[TaxYear] = icpd.[TaxYear]  AND icpd.[Enabled] = 1  AND icpd.[Processed] = 1  ORDER BY  icpd.[ProcessedDate] DESC  ) iaa  OUTER APPLY  (  SELECT  SUM(ipr.[Amount]) AS 'MinAmount'  FROM  Payroll_PayrollResults ipr  WHERE  ipr.[EmployeeID] = pr.[EmployeeID]  AND ipr.[PeriodID] = iaa.[Period_ID]  AND ipr.[IRP5Code] = pr.[IRP5Code]  AND ipr.[SalaryHeadID] = pr.[SalaryHeadID]  ) ibb  ) aa  WHERE  pr.[TaxYear] = @TaxYear  AND (@EmployeeId = 0 OR pr.[EmployeeID] = @EmployeeId)  AND (@Irp5CodeId = 0 OR irp.[IRP5Code_ID] = @Irp5CodeId)  AND (@Month = 2 OR pr.[TaxPeriod] <= CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 6  /* WEEKLY */  WHEN 2 THEN 26  /* Bi-WEEKLY */  WHEN 3 THEN 13  END) -- Half the periods when Month 8 is selected, meaning half year values  GROUP BY  pr.[EmployeeID],  e.[Initials],  e.[Surname],  /*CASE  WHEN pr.[IRP5Code] IN ('4001', '4472') THEN '4001'  WHEN pr.[IRP5Code] IN ('4005', '4474') THEN '4005'  WHEN pr.[IRP5Code] IN ('4003', '4473') THEN '4003'  ELSE pr.[IRP5Code]  END,*/  pr.[IRP5Code],  sh.[SalaryHeadName],  pr.[IsRFI],  aa.[MinAmount],  c.[CycleTypeID]  UNION  SELECT  e.[Employee_ID],  e.[Initials],  e.[Surname],  irp.[IRP5Code],  ISNULL(irp.[SalaryHeadName], irp.[IRP5CodeDesc]) AS 'SalaryHeadName',  0 AS 'IsRFI',  pre.[CurrentTaxCredits] AS 'CurrentMonth',  bb.[TaxCredits] AS 'Amount',  pre.[CurrentTaxCredits] * CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 12  /* WEEKLY */  WHEN 2 THEN 52  /* Bi-WEEKLY */  WHEN 3 THEN 26  END AS 'AnnualAmount'  FROM  Payroll_Employee e  INNER JOIN  Const_Cycle c ON e.[CycleID] = c.[Cycle_ID]  AND c.[Enabled] = 1  CROSS APPLY  (  SELECT DISTINCT  i.[IRP5Code_ID], i.[IRP5Code], i.[IRP5CodeDesc], s.[SalaryHeadName]  FROM  Payroll_IRP5Code i  LEFT JOIN  Payroll_SalaryHead s ON i.[IRP5Code_ID] = s.[IRP5CodeId]  AND s.[Enabled] = 1  WHERE  i.[IRP5Code] = '4116'  AND i.[Enabled] = 1  ) irp  OUTER APPLY  (  SELECT TOP 1  icpd.[Period_ID], icpd.[TaxYear]  FROM  Payroll_CyclePeriodDetails icpd  WHERE  icpd.[CycleID] = e.[CycleID]  AND icpd.[TaxYear] = CAST(@TaxYear - 1 AS VARCHAR(4)) + '/' + CAST(@TaxYear AS VARCHAR(4))  AND icpd.[Enabled] = 1  AND icpd.[Processed] = 1  ORDER BY  icpd.[ProcessedDate] DESC  ) aa  OUTER APPLY  (  SELECT  SUM(ISNULL(ipre.[TaxCredits], 0)) AS 'CurrentTaxCredits'  FROM  Payroll_PayrollRun_History_Employees ipre  WHERE  ipre.[Employee_ID] = e.[Employee_ID]  AND ipre.[TaxYear] = aa.[TaxYear]  AND ipre.[Period_ID] = aa.[Period_ID]  ) pre  OUTER APPLY  (  SELECT  SUM(ISNULL(ipre.[TaxCredits], 0)) AS 'TaxCredits'  FROM  Payroll_PayrollRun_History_Employees ipre  WHERE  ipre.[Employee_ID] = e.[Employee_ID]  AND ipre.[TaxYear] = CAST(@TaxYear - 1 AS VARCHAR(4)) + '/' + CAST(@TaxYear AS VARCHAR(4))  AND (@Month = 2 OR ipre.[Period] <= CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 6  /* WEEKLY */  WHEN 2 THEN 26  /* Bi-WEEKLY */  WHEN 3 THEN 13  END) -- Half the periods when Month 8 is selected, meaning half year values  ) bb  WHERE  (@EmployeeId = 0 OR e.[Employee_ID] = @EmployeeId)  AND (@Irp5CodeId = 0 OR irp.[IRP5Code_ID] = @Irp5CodeId)  AND (ISNULL(pre.[CurrentTaxCredits], 0) <> 0 OR ISNULL(bb.[TaxCredits], 0) <> 0)  ) aa  ORDER BY  aa.[EmployeeID], aa.[IRP5Code];  END

GO

