CREATE PROCEDURE [dbo].[BI_rptIrp5TaxTotalDetailPerIRP5Code]    @TaxYear nvarchar(9),    @EmployeeId int = 0,    @Irp5CodeId int = 0,    @Month int = 2    AS  BEGIN    SELECT  a.[EmployeeID],  a.[Initials],  a.[Surname],  a.[IsRFI],  SUM(a.[CurrentMonth]) AS 'CurrentMonth',  SUM(a.[Amount]) AS 'Amount',  SUM(a.[AnnualAmount]) AS 'AnnualAmount'  FROM  (  SELECT  RIGHT('00000000' + CAST(aa.[EmployeeID] AS VARCHAR), 8) AS 'EmployeeID',  aa.[Initials],  aa.[Surname],  aa.[IRP5Code],  aa.[SalaryHeadName],  aa.[IsRFI],  aa.[CurrentMonth],  aa.[Amount],  aa.[AnnualAmount]  FROM  (  SELECT  pr.[EmployeeID],  e.[Initials],  e.[Surname],  CASE  WHEN pr.[IRP5Code] IN ('4001', '4472') THEN '4001'  WHEN pr.[IRP5Code] IN ('4005', '4474') THEN '4005'  WHEN pr.[IRP5Code] IN ('4003', '4473') THEN '4003'  ELSE pr.[IRP5Code]  END AS 'IRP5Code',  sh.[SalaryHeadName],  pr.[IsRFI],  aa.[MinAmount] AS 'CurrentMonth',  SUM(pr.[Amount]) AS 'Amount',  aa.[MinAmount] * CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 12  /* WEEKLY */  WHEN 2 THEN 52  /* Bi-WEEKLY */  WHEN 3 THEN 26  END AS 'AnnualAmount'  FROM  Payroll_PayrollResults pr  INNER JOIN  Payroll_Employee e ON pr.[EmployeeID] = e.[Employee_ID]  INNER JOIN  Const_Cycle c ON e.[CycleID] = c.[Cycle_ID]  AND c.[Enabled] = 1  INNER JOIN  Payroll_CyclePeriodDetails cpd ON pr.[PeriodID] = cpd.[Period_ID]   AND cpd.[Enabled] = 1  INNER JOIN  Payroll_IRP5Code irp ON pr.[IRP5CodeID] = irp.[IRP5Code_ID]  AND irp.[Enabled] = 1  AND NOT (irp.[TransactionTypeID] = 2 and ISNULL(irp.[IRP5CertCode], irp.[IRP5Code]) = 0)  INNER JOIN  Payroll_SalaryHead sh ON pr.[SalaryHeadID] = sh.[SalaryHead_ID]  AND sh.[Enabled] = 1  OUTER APPLY  (  SELECT DISTINCT  ibb.[MinAmount]  FROM  (  SELECT TOP 1  icpd.[Period_ID]  FROM  Payroll_CyclePeriodDetails icpd  WHERE  cpd.[CycleID] = icpd.[CycleID]  AND cpd.[TaxYear] = icpd.[TaxYear]  AND icpd.[Enabled] = 1  AND icpd.[Processed] = 1  ORDER BY  icpd.[ProcessedDate] DESC  ) iaa  OUTER APPLY  (  SELECT  SUM(ipr.[Amount]) AS 'MinAmount'  FROM  Payroll_PayrollResults ipr  WHERE  ipr.[EmployeeID] = pr.[EmployeeID]  AND ipr.[PeriodID] = iaa.[Period_ID]  AND ipr.[IRP5Code] = pr.[IRP5Code]  AND ipr.[SalaryHeadID] = pr.[SalaryHeadID]  ) ibb  ) aa  WHERE  pr.[TaxYear] = @TaxYear  AND (@EmployeeId = 0 OR pr.[EmployeeID] = @EmployeeId)  AND (@Irp5CodeId = 0 OR irp.[IRP5Code_ID] = @Irp5CodeId)  AND (@Month = 2 OR pr.[TaxPeriod] <= CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 6  /* WEEKLY */  WHEN 2 THEN 26  /* Bi-WEEKLY */  WHEN 3 THEN 13  END) -- Half the periods when Month 8 is selected, meaning half year values  GROUP BY  pr.[EmployeeID],  e.[Initials],  e.[Surname],  CASE  WHEN pr.[IRP5Code] IN ('4001', '4472') THEN '4001'  WHEN pr.[IRP5Code] IN ('4005', '4474') THEN '4005'  WHEN pr.[IRP5Code] IN ('4003', '4473') THEN '4003'  ELSE pr.[IRP5Code]  END,  sh.[SalaryHeadName],  pr.[IsRFI],  aa.[MinAmount],  c.[CycleTypeID]  UNION  SELECT  e.[Employee_ID],  e.[Initials],  e.[Surname],  irp.[IRP5Code],  ISNULL(irp.[SalaryHeadName], irp.[IRP5CodeDesc]) AS 'SalaryHeadName',  0 AS 'IsRFI',  pre.[CurrentTaxCredits] AS 'CurrentMonth',  bb.[TaxCredits] AS 'Amount',  pre.[CurrentTaxCredits] * CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 12  /* WEEKLY */  WHEN 2 THEN 52  /* Bi-WEEKLY */  WHEN 3 THEN 26  END AS 'AnnualAmount'  FROM  Payroll_Employee e  INNER JOIN  Const_Cycle c ON e.[CycleID] = c.[Cycle_ID]  AND c.[Enabled] = 1  CROSS APPLY  (  SELECT DISTINCT  i.[IRP5Code_ID], i.[IRP5Code], i.[IRP5CodeDesc], s.[SalaryHeadName]  FROM  Payroll_IRP5Code i  LEFT JOIN  Payroll_SalaryHead s ON i.[IRP5Code_ID] = s.[IRP5CodeId]  AND s.[Enabled] = 1  WHERE  i.[IRP5Code] = '4116'  AND i.[Enabled] = 1  ) irp  OUTER APPLY  (  SELECT TOP 1  icpd.[Period_ID], icpd.[TaxYear]  FROM  Payroll_CyclePeriodDetails icpd  WHERE  icpd.[CycleID] = e.[CycleID]  AND icpd.[TaxYear] = CAST(@TaxYear - 1 AS VARCHAR(4)) + '/' + CAST(@TaxYear AS VARCHAR(4))  AND icpd.[Enabled] = 1  AND icpd.[Processed] = 1  ORDER BY  icpd.[ProcessedDate] DESC  ) aa  OUTER APPLY  (  SELECT  SUM(ISNULL(ipre.[TaxCredits], 0)) AS 'CurrentTaxCredits'  FROM  Payroll_PayrollRun_History_Employees ipre  WHERE  ipre.[Employee_ID] = e.[Employee_ID]  AND ipre.[TaxYear] = aa.[TaxYear]  AND ipre.[Period_ID] = aa.[Period_ID]  ) pre  OUTER APPLY  (  SELECT  SUM(ISNULL(ipre.[TaxCredits], 0)) AS 'TaxCredits'  FROM  Payroll_PayrollRun_History_Employees ipre  WHERE  ipre.[Employee_ID] = e.[Employee_ID]  AND ipre.[TaxYear] = CAST(@TaxYear - 1 AS VARCHAR(4)) + '/' + CAST(@TaxYear AS VARCHAR(4))  AND (@Month = 2 OR ipre.[Period] <= CASE c.[CycleTypeID]  /* MONTHLY */  WHEN 1 THEN 6  /* WEEKLY */  WHEN 2 THEN 26  /* Bi-WEEKLY */  WHEN 3 THEN 13  END) -- Half the periods when Month 8 is selected, meaning half year values  ) bb  WHERE  (@EmployeeId = 0 OR e.[Employee_ID] = @EmployeeId)  AND (@Irp5CodeId = 0 OR irp.[IRP5Code_ID] = @Irp5CodeId)  AND (ISNULL(pre.[CurrentTaxCredits], 0) <> 0 OR ISNULL(bb.[TaxCredits], 0) <> 0)  ) aa  ) a  GROUP BY  a.[EmployeeID],  a.[Initials],  a.[Surname],  a.[IsRFI]  ORDER BY  a.[EmployeeID];  END

