-- ============================================
-- SP: BI_rptPayrollRunVariance
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[BI_rptPayrollRunVariance]          @PeriodId int       AS        BEGIN    Select Results.*, emp.FirstName + ' ' + emp.Surname As Employee,  CASE  WHEN TransactionTypeId = 1 THEN 'Earning'  WHEN TransactionTypeId = 2 THEN 'Deduction'  WHEN TransactionTypeId = 3 THEN 'Company Contribution'  WHEN TransactionTypeId = 4 THEN 'Fringe Benefit'    END AS TType   from  (Select  -1 as tableName,'Employee Trial Payslip' as TableDesc, EmployeePayslip.EmployeeId,Amount,SalHead.SalaryHead_ID,SalaryHeadName,Irp5.TransactionTypeId, TaxSavePurpose,  0 as DataError   from  (Select * from payroll_employeetrialpayslip where periodid = @PeriodId)EmployeePayslip  LEFT OUTER JOIN Payroll_EmployeePayrollDefinition EmpDef  ON EmpDef.EmployeePayrollDefinition_ID = EmployeePayslip.PayrollDefinationId  LEFT OUTER JOIN Payroll_SalaryHead SalHead  ON SalHead.SalaryHead_ID = EmpDef.PayrollSalaryHeadId  LEFT OUTER JOIN Payroll_Irp5Code Irp5  ON Irp5.Irp5Code_ID = SalHead.Irp5CodeId  UNION ALL  Select  1 as tableName,'Employee Payslip' as TableDesc, EmployeePayslip.EmployeeId,Amount,SalHead.SalaryHead_ID,SalaryHeadName,Irp5.TransactionTypeId, TaxSavePurpose,  0 as DataError   from  (Select * from payroll_employeepayslip where periodid = @PeriodId)EmployeePayslip  LEFT OUTER JOIN Payroll_EmployeePayrollDefinition EmpDef  ON EmpDef.EmployeePayrollDefinition_ID = EmployeePayslip.PayrollDefinationId  LEFT OUTER JOIN Payroll_SalaryHead SalHead  ON SalHead.SalaryHead_ID = EmpDef.PayrollSalaryHeadId  LEFT OUTER JOIN Payroll_Irp5Code Irp5  ON Irp5.Irp5Code_ID = SalHead.Irp5CodeId  UNION ALL  Select tableName,TableDesc,EmployeeId,SUM(Amount)Amount,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose,SUM(DataError)DataError from  (Select -2 as tableName,'Trial Results' as TableDesc, EmployeeId,Amount,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose,  CASE WHEN TransactionTypeID <> 4 AND (ScoaItemId is NULL OR ControlVoteId is NULL OR PlanProjectItemId is NULL OR ScoaProjectId is NULL OR ScoaCostingId is NULL OR ScoaFunctionId is NULL OR ScoaFundingId is NULL OR ScoaRegionId is NULL OR ContraScoaProjectId is NULL OR ContraScoaItemId is NULL OR ContraScoaCostingId is NULL OR ContraScoaFunctionId is NULL OR ContraScoaFundingId is NULL OR ContraScoaRegionID is NULL OR ContraPlanProjectItemId  is NULL) THEN 1 ELSE 0 END AS DataError   from Payroll_TrialResults where PeriodId = @PeriodId)TrialResults   GROUP BY tableName,TableDesc,EmployeeId,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose   UNION ALL  Select tableName,TableDesc,EmployeeId,SUM(Amount)Amount,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose,SUM(DataError)DataError from  (Select 2 as tableName,'Trial Results' as TableDesc, EmployeeId,Amount,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose,  CASE WHEN TransactionTypeID <> 4 AND (ScoaItemId is NULL OR ControlVoteId is NULL OR PlanProjectItemId is NULL OR ScoaProjectId is NULL OR ScoaCostingId is NULL OR ScoaFunctionId is NULL OR ScoaFundingId is NULL OR ScoaRegionId is NULL OR ContraScoaProjectId is NULL OR ContraScoaItemId is NULL OR ContraScoaCostingId is NULL OR ContraScoaFunctionId is NULL OR ContraScoaFundingId is NULL OR ContraScoaRegionID is NULL OR ContraPlanProjectItemId  is NULL) THEN 1 ELSE 0 END AS DataError   from Payroll_PayrollResults where PeriodId = @PeriodId)FinalResults   GROUP BY tableName,TableDesc,EmployeeId,SalaryHeadId,SalaryTitle,TransactionTypeId,TaxSavePurpose   )  Results  LEFT OUTER JOIN Payroll_Employee emp  ON emp.Employee_ID = Results.EmployeeId  END

GO

-- ============================================
-- SP: Billing_EmployeeArrangementContractRpt_Sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Hardik Shah  -- Create date: 28/07/2016  -- Description: Employee Arrangement Contract Report  -- call : Billing_EmployeeArrangementContractRpt_Sp 1  -- 2016-09-14 Eben Roux: Getting interest rate from Billing_BillingCycleProcess  -- =============================================  CREATE PROCEDURE [dbo].[Billing_EmployeeArrangementContractRpt_Sp] @ArrangmentID INT  AS      BEGIN             SELECT  ( SELECT    MunicipalityName                    FROM      Payroll_Municipality                  ) AS MunicipalityName ,                  ( SELECT    dbo.GetMuncipalityAddress()                  ) AS MuncipalityAddress ,                  ( SELECT    dbo.GetMuncipalityContact()                  ) AS ContactDetails ,                  dbo.BufferString_fxn(CACC.Account_ID, 12, '0') AS AccountNumber ,                  dbo.BufferString_fxn(CACC.UnitID, 12, '0') AS PropertyNumber ,                  'EA - ' + dbo.BufferString_fxn(DA.EmployeeArrangement_ID, 10,                                                 '0') AS FileNumber ,                  --CONVERT(NVARCHAR(50), DA.EmployeeArrangement_ID) AS FileNumber ,                  RTRIM(LTRIM(( ISNULL(CN.Surname_Company, '') + ' '                                + ISNULL(CN.FirstNames, '') ))) AS FullName ,                  ISNULL(CN.Tel_Home, '') AS Tel_Home ,                  ISNULL(CN.Employer, '') AS EmployeedBy ,                  ISNULL(CN.Tel_Work, '') AS Tel_Work ,                  ISNULL(CU.StreetNo, '') + ' ' + ISNULL(CS.StreetName, '')                  + ', ' + ISNULL(S.SuburbName, '') + ', ' + ISNULL(T.Town, '') AS PhysicalAddress ,        --getdate() CurrentDate,                    CONVERT(VARCHAR, GETDATE(), 106) AS CurrenDate ,                  CASE ISNULL(CN.IdNo_RegistrationNo, '')                    WHEN '' THEN ISNULL(CN.PassportNo, '')                    ELSE ISNULL(CN.IdNo_RegistrationNo, '')                  END AS PersonIDNumber ,                  CN.DateofBirth AS DateofBirth ,                  '' AS MarriedCommunity ,                  LTRIM(RTRIM(( ISNULL(CN.Kin_Surname, '') + ' '                                + ISNULL(CN.Kin_FirstName, '') ))) AS SpouseName ,                  '' AS SpouseEmployeedBy ,                  ISNULL(CN.Kin_Mobile, '') AS SpouseTel ,                  NULL AS SpousDOB ,                  DA.OutStandingAmount AS DebtAmount ,                  0.00 AS Costs ,                  (SELECT TOP 1 InterestRate FROM dbo.Billing_BillingCycleProcess WHERE CycleTypeID = 2 AND ReviewStatus = 'Approved' ORDER BY PeriodID DESC) AS BillingInterestPercentage ,                  DA.ArrangementDate AS DebtArrangementDate ,                  ISNULL(DA.InstallmentAmount, 0) AS InstallmentAmount ,                  ( SELECT TOP ( 1 )                              ( dbo.GetMonthNameFromId(DATEPART(MONTH,                                                                A.InstalmentDate))                                + ' ' + CONVERT(NVARCHAR(4), DATEPART(YEAR,                                                                A.InstalmentDate)) )                    FROM      dbo.Billing_EmployeeArrangementDetails A                    WHERE     A.EmployeeArrangementID = @ArrangmentID                    ORDER BY  A.EmployeeArrangementDetails_ID ASC                  ) AS InstallmentStartMonth ,                  ( SELECT TOP ( 1 )                              ( dbo.GetMonthNameFromId(DATEPART(MONTH,                                                                A.InstalmentDate))                                + ' ' + CONVERT(NVARCHAR(4), DATEPART(YEAR,                                                                A.InstalmentDate)) )                    FROM      dbo.Billing_EmployeeArrangementDetails A                    WHERE     A.EmployeeArrangementID = @ArrangmentID                    ORDER BY  A.EmployeeArrangementDetails_ID DESC                  ) AS InstallmentEndMonth ,                  ( SELECT TOP ( 1 )                              A.InstalmentDate                    FROM      dbo.Billing_EmployeeArrangementDetails A                    WHERE     A.EmployeeArrangementID = @ArrangmentID                    ORDER BY  A.EmployeeArrangementDetails_ID DESC                  ) AS LastInstallmentDate ,                  ISNULL(CN.MarriedStatusID, 0) AS MarriedStatusID ,                  PE.EmpCode + PE.IdNo AS EmployeeNumber          FROM    dbo.Billing_EmployeeArrangement DA                  INNER JOIN dbo.Billing_EmployeeArrangementDetails DAD ON DA.EmployeeArrangement_ID = DAD.EmployeeArrangementID                  INNER JOIN Cons_Account CACC ON CACC.Account_ID = DA.AccountId                  INNER JOIN dbo.Cons_Unit CU ON CACC.UnitID = CU.Unit_ID                  INNER JOIN dbo.Cons_Name CN ON CN.Name_ID = CACC.NameID                  INNER JOIN Const_Street CS ON CS.Street_ID = CU.StreetID                  INNER JOIN Const_Suburb S ON S.Suburb_ID = CS.SuburbID                  INNER JOIN Const_Town T ON T.Town_ID = S.TownID                  INNER JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = DA.EmployeeID          WHERE   DA.EmployeeArrangement_ID = @ArrangmentID;        END;  

GO

-- ============================================
-- SP: Billing_EmployeeArrangementSearch_Sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Shah Hardik  -- Create date: 21 July 2016  -- Description: Returns List Of Arrangement  -- 2016 12 10 Shah h - New outstanding amount logic  -- =============================================  CREATE PROCEDURE [dbo].[Billing_EmployeeArrangementSearch_Sp] --'0', '', ''       @AccountNumber VARCHAR(255) ,      @EmployeeNumber VARCHAR(255) ,      @Name VARCHAR(255) ,      @SGNumber VARCHAR(255) ,      @Address NVARCHAR(255) ,      @IsTerminated BIT  AS      BEGIN           IF ISNULL(@IsTerminated, 0) = 0              BEGIN                  SELECT  CONVERT(NVARCHAR(100), EA.EmployeeArrangement_ID) AS ID ,                          dbo.BufferString_fxn(EA.AccountId, 12, '0') AS AccountNumber ,                          '' AS OldPropertyCode ,                          CAT.AccountDesc AS AccountType ,                          RTRIM(LTRIM(ISNULL(CN.Surname_Company, '') + ' '                                      + ISNULL(CN.FirstNames, ''))) AS Name ,                          CU.SGNumber AS SGNumber ,                          CU.StreetNo AS PropertyAddress ,                          CS.StatusDesc AS AccountStatus ,                          ( SELECT  SUM(ISNULL(Amount,0)) + SUM(ISNULL(VatAmount,0))+SUM(ISNULL(InterestAmount,0))          FROM dbo.Billing_AmountTransactions_vw AS vw         WHERE   vw.AccountId = CA.Account_ID           ) AS OutStandingAmount                  FROM    dbo.Billing_EmployeeArrangement EA                          INNER JOIN dbo.Cons_Account CA ON CA.Account_ID = EA.AccountId                          INNER JOIN dbo.Cons_Unit CU ON CU.Unit_ID = CA.UnitID                          LEFT JOIN dbo.Const_AccountType CAT ON CAT.AccountType_ID = CA.AccountTypeID                          LEFT JOIN dbo.Const_Status CS ON CS.Status_ID = CA.AccountStatusID                          INNER JOIN dbo.Cons_Name CN ON CN.Name_ID = CA.NameID                  WHERE   ( CA.Account_ID = CAST(@AccountNumber AS INT)                            OR @AccountNumber = ''                          )                          AND ( CONVERT(NVARCHAR(100), EA.EmployeeID) = @EmployeeNumber                                OR @EmployeeNumber = ''                              )                          AND ( RTRIM(LTRIM(ISNULL(CN.Surname_Company, '') + ' '                                            + ISNULL(CN.FirstNames, ''))) LIKE '%'                                + @Name + '%'                                OR @Name = ''                              )                          AND ( CU.SGNumber = @SGNumber                                OR @SGNumber = ''                              );              END;                        END;    

GO

-- ============================================
-- SP: Billing_EmployeeDeductionContractRpt_Sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Hardik Shah  -- Create date: 30/07/2016  -- Description: Employee Deduction Contract Report  -- call : Billing_EmployeeDeductionContractRpt_Sp 4  -- 2025-09-16 Niren P WI123694 Changed JOin for Address Fields , from Inner to Left Join  -- 2025-09-25 Niren P WI123694 Added Employee Number  -- =============================================  CREATE PROCEDURE [dbo].[Billing_EmployeeDeductionContractRpt_Sp] @DeductionID INT  AS      BEGIN             SELECT  ( SELECT    MunicipalityName                    FROM      Payroll_Municipality                  ) AS MunicipalityName ,                  ( SELECT    dbo.GetMuncipalityAddress()                  ) AS MuncipalityAddress ,                  ( SELECT    dbo.GetMuncipalityContact()                  ) AS ContactDetails ,                  dbo.BufferString_fxn(CACC.Account_ID, 12, '0') AS AccountNumber ,                  'ED - ' + dbo.BufferString_fxn(DA.EmployeeDeduction_ID, 10,                                                 '0') AS FileNumber ,                  PE.FirstName + ' ' + PE.Surname AS EmployeeName ,                  dbo.BufferString_fxn(DA.EmployeeID, 10, '0') AS EmployeeNumber,                  RTRIM(LTRIM(( ISNULL(CN.Surname_Company, '') + ' '                                + ISNULL(CN.FirstNames, '') ))) AS AccountName ,                  CU.SGNumber ,                  DA.MaximumAmount ,                  ISNULL(CI.InstitutionDesc, '') AS AccountGrouping ,                  ISNULL(CG.GroupCodeDesc, '') AS SubAccountGrouping ,                  dbo.BufferString_fxn(CACC.UnitID, 12, '0') AS PropertyNumber ,                                    --CONVERT(NVARCHAR(50), DA.EmployeeArrangement_ID) AS FileNumber ,                  ISNULL(CN.Tel_Home, '') AS Tel_Home ,                  ISNULL(CN.Employer, '') AS EmployeedBy ,                  ISNULL(CN.Tel_Work, '') AS Tel_Work ,                  ISNULL(CU.StreetNo, '') + ' ' + ISNULL(CS.StreetName, '')                  + ', ' + ISNULL(S.SuburbName, '') + ', ' + ISNULL(T.Town, '') AS PhysicalAddress         --getdate() CurrentDate,            FROM    dbo.Billing_EmployeeDeduction DA                  INNER JOIN Cons_Account CACC ON CACC.Account_ID = DA.AccountId                  INNER JOIN dbo.Cons_Unit CU ON CACC.UnitID = CU.Unit_ID                  INNER JOIN dbo.Cons_Name CN ON CN.Name_ID = CACC.NameID                  LEFT JOIN Const_Street CS ON CS.Street_ID = CU.StreetID                  LEFT JOIN Const_Suburb S ON S.Suburb_ID = CS.SuburbID                  LEFT JOIN Const_Town T ON T.Town_ID = S.TownID                  LEFT JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = DA.EmployeeID                  LEFT OUTER JOIN Const_Institution CI ON CI.Institution_ID = DA.AccountGrouping                  LEFT OUTER JOIN Const_GroupCode CG ON CG.GroupCode_ID = DA.SubAccountGrouping                                                        AND CG.InstitutionID = CI.Institution_ID          WHERE   DA.EmployeeDeduction_ID = @DeductionID;        END;

GO

-- ============================================
-- SP: Billing_EmployeeDeductionSearch_Sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Shah Hardik  -- Create date: 21 July 2016  -- Description: Returns List Of Employee Deduction  -- 2016 12 10 Shah h - New outstanding amount logic  -- 2017 05 10 Maulik P - Remove the extra column which was removed  -- 2017 05 10 Maulik P - Add is null for the outstanding amount  -- 2020 08 20 Niren Patel - Addede Additional Columns, Employee Number, Maximum Amount  -- 2020 08 23 Niren Patel - Updated Addres field to include whole address instead of just street No  -- 2020 08 24 Niren Patel - Updated Outstanding Amount  -- =============================================  CREATE PROCEDURE [dbo].[Billing_EmployeeDeductionSearch_Sp] --'', '', '', '','',0      @AccountNumber VARCHAR(255) ,      @EmployeeNumber VARCHAR(255) ,      @Name VARCHAR(255) ,      @SGNumber VARCHAR(255) ,      @Address NVARCHAR(255) ,      @IsTerminated BIT  AS      BEGIN             -----------------------------------------------------    -- CONST    -----------------------------------------------------    DECLARE @maxInt int = 2147483647    -----------------------------------------------------    -- #ENUM ##    -----------------------------------------------------    DECLARE @ptBillPeriod int = 1, @ttAccTotal int = 101    -----------------------------------------------------    -- Variables    -----------------------------------------------------    DECLARE @AccountId INT = CAST(@AccountNumber AS INT)      DECLARE @accountId_To int = CASE WHEN @AccountId = 0 THEN @maxInt ELSE @AccountId END      DECLARE @summarySearch TABLE (     AccountId int,     Balance decimal(18,2),     ArrearsBalance decimal(18,2),     CurrentAge decimal(18,2)    )      INSERT INTO @summarySearch    SELECT ASM.AccountId,ASM.Balance,         (ASM.Days30Amt +ASM.Days30Int +ASM.Days30Vat+ASM.Days60Amt +ASM.Days60Int +ASM.Days60Vat +ASM.Days90Amt +ASM.Days90Int +ASM.Days90Vat +ASM.Days120Amt +ASM.Days120Int +ASM.Days120Vat      + ASM.Days150Amt +ASM.Days150Int +ASM.Days150Vat +ASM.Days180Amt +ASM.Days180Int +ASM.Days180Vat + ASM.Days210P_Amt +ASM.Days210P_Int +ASM.Days210P_Vat)     AS ArrearsBalance,        ASM.Days0Amt + ASM.Days0Int + ASM.Days0Vat AS CurrentAge    FROM dbo.Billing_AccountSummary ASM        INNER JOIN (                   SELECT AccountId,MAX(PeriodId) AS MaxPeriodId            FROM dbo.Billing_AccountSummary            WHERE AccountId BETWEEN @AccountId AND @accountId_To       AND PeriodType = @ptBillPeriod       AND TransType = @ttAccTotal            GROUP BY AccountId)     AS LST ON LST.AccountId=ASM.AccountId AND LST.MaxPeriodId=ASM.PeriodId AND ASM.TransType=@ttAccTotal    ORDER BY AccountId      IF (@AccountId <> 0  AND (SELECT COUNT(*) FROM @summarySearch WHERE AccountId = @AccountId) = 0)    BEGIN     INSERT INTO @summarySearch VALUES(@AccountId, 0, 0, 0)      END            IF ISNULL(@IsTerminated, 0) = 0              BEGIN                  SELECT  CONVERT(NVARCHAR(100), EA.EmployeeDeduction_ID) AS ID ,                          dbo.BufferString_fxn(EA.AccountId, 12, '0') AS AccountNumber ,                          CA.OldAccountCode AS OldPropertyCode ,                          CAT.AccountDesc AS AccountType ,                          RTRIM(LTRIM(ISNULL(CN.Surname_Company, '') + ' '                                      + ISNULL(CN.FirstNames, ''))) AS Name ,                          ISNULL(CU.SGNumber, CU.Description) AS SGNumber ,                          ISNULL(dbo.Billing_GetLocationAddress(CA.UnitID,0), '') AS PropertyAddress ,                          CS.StatusDesc AS AccountStatus ,                          ISNULL(ss.Balance, 0.00) AS OutStandingAmount,        ISNULL(dbo.BufferString_fxn(EA.EmployeeID,12,'0'),'') AS EmployeeNumber,        ISNULL(EA.MaximumAmount,0) AS MaximumAmount                  FROM    dbo.Billing_EmployeeDeduction EA                          INNER JOIN @summarySearch AS ss ON ss.AccountId = EA.AccountId                           INNER JOIN dbo.Cons_Account CA ON CA.Account_ID = EA.AccountId                          INNER JOIN dbo.Cons_Unit CU ON CU.Unit_ID = CA.UnitID                          LEFT JOIN dbo.Const_AccountType CAT ON CAT.AccountType_ID = CA.AccountTypeID                          LEFT JOIN dbo.Const_Status CS ON CS.Status_ID = CA.AccountStatusID                          INNER JOIN dbo.Cons_Name CN ON CN.Name_ID = CA.NameID                  WHERE   EA.TerminationDate IS NULL        AND ( CA.Account_ID = CAST(@AccountNumber AS INT)           OR @AccountNumber = ''         )                          AND ( CONVERT(NVARCHAR(100), EA.EmployeeID) = @EmployeeNumber                                OR @EmployeeNumber = ''                              )                          AND ( RTRIM(LTRIM(ISNULL(CN.Surname_Company, '') + ' '                                            + ISNULL(CN.FirstNames, ''))) LIKE '%'                                + @Name + '%'                                OR @Name = ''                              )                          AND ( CU.SGNumber = @SGNumber                                OR @SGNumber = ''                              );              END;          ELSE              IF ISNULL(@IsTerminated, 0) = 1                  BEGIN                      SELECT  CONVERT(NVARCHAR(100), EA.EmployeeDeduction_ID) AS ID ,                              dbo.BufferString_fxn(EA.AccountId, 12, '0') AS AccountNumber ,                              CA.OldAccountCode AS OldPropertyCode ,                              CAT.AccountDesc AS AccountType ,                              RTRIM(LTRIM(ISNULL(CN.Surname_Company, '') + ' '                                          + ISNULL(CN.FirstNames, ''))) AS Name ,                              ISNULL(CU.SGNumber, CU.Description) AS SGNumber ,                              ISNULL(dbo.Billing_GetLocationAddress(CA.UnitID,0), '') AS PropertyAddress ,                              CS.StatusDesc AS AccountStatus ,                              0.00 AS OutStandingAmount,            ISNULL(dbo.BufferString_fxn(EA.EmployeeID,12,'0'),'') AS EmployeeNumber,            ISNULL(EA.MaximumAmount,0) AS MaximumAmount                      FROM    dbo.Billing_EmployeeDeduction EA                              INNER JOIN dbo.Cons_Account CA ON CA.Account_ID = EA.AccountId                              INNER JOIN dbo.Cons_Unit CU ON CU.Unit_ID = CA.UnitID                              LEFT JOIN dbo.Const_AccountType CAT ON CAT.AccountType_ID = CA.AccountTypeID                              LEFT JOIN dbo.Const_Status CS ON CS.Status_ID = CA.AccountStatusID               INNER JOIN dbo.Cons_Name CN ON CN.Name_ID = CA.NameID                      WHERE   ( CA.Account_ID = CAST(@AccountNumber AS INT)                                    OR @AccountNumber = ''                                  )                              AND ( CONVERT(NVARCHAR(100), EA.EmployeeID) = @EmployeeNumber                                    OR @EmployeeNumber = ''                                  )                              AND ( RTRIM(LTRIM(ISNULL(CN.Surname_Company, '')                                                + ' ' + ISNULL(CN.FirstNames, ''))) LIKE '%'                                    + @Name + '%'                                    OR @Name = ''                                  )                              AND ( CU.SGNumber = @SGNumber                                    OR @SGNumber = ''                                  );                  END;      END;

GO

-- ============================================
-- SP: Const_DepartmentDivision_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Carol Brooking  -- Create date:  14/04/2014  -- Description: Getting the list of the department divisions to be used for creating votes  -- CALLS : Const_DepartmentDivision_sp 'IE'  -- 2016 03 02  CB Remove the Control Vote details - no longer required, add order by and do not display disabled items  -- 2016 07 20 Shah H set DivisionCode varchar(50) for table #temp  -- [Const_DepartmentDivision_sp] 'IE'  -- 23-12-2016 SNagpal : Optimize Stored procedure by adding Indexes. As before it taking long time to load  -- =============================================    CREATE PROCEDURE [dbo].[Const_DepartmentDivision_sp] --'IE234'   @VoteType nvarchar(50)  AS  BEGIN   SET FMTONLY OFF      create table #temp   (TID int identity(1,1),    DivID int);        create table #temp2    (TID int identity(1,1),     DivisionParentID int,     Division_ID int,     DivisionDesc nvarchar(200) COLLATE Latin1_General_CI_AS,     DivisionCode nvarchar(50) COLLATE Latin1_General_CI_AS,     DepartmentID int,     DivEnabled bit,     DeptEnabled bit);       CREATE CLUSTERED INDEX IX_temp2 ON #temp2 (TID,Division_ID);     CREATE CLUSTERED INDEX IX_temp ON #temp (TID,DivID);     --Recursive code found on net     WITH DeptDivGroup (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   AS   (   -- Anchor member definition    SELECT e.DivisionParentID, e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID    FROM dbo.Const_Division AS e    WHERE DivisionParentID IS NULL     UNION ALL   -- Recursive member definition    SELECT e.DivisionParentID,e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID     FROM dbo.Const_Division AS e    INNER JOIN DeptDivGroup AS d     ON e.DivisionParentID = d.Division_ID    )       Insert into #temp2 (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   Select    DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID   From     DeptDivGroup        Insert into #temp(DivID)    Select Distinct DivisionParentID    From #temp2    where DivisionParentID is not null      Update #temp2    set DivEnabled = (Select Enabled from Const_Division where Division_ID = #temp2.Division_ID)     If @VoteType = 'IE' --Income & expense   begin    select      DepartmentCode + '/' + DivisionCode as MunicipalClassification     ,DepartmentDesc + ' / ' + DivisionDesc as MunicipalClassDesc     ,Division_ID     ,DivisionDesc     ,DivisionCode     ,DepartmentDesc     ,DepartmentCode      ,Department_ID     ,DivEnabled     ,Const_Department.Enabled as DeptEnabled    from #temp2    inner join Const_Department on #temp2.DepartmentID = Const_Department.Department_ID    where Division_ID not in (Select DivID from #temp)    and Department_ID <> 0    and Enabled = 1 and DivEnabled = 1    order by DepartmentCode, DivisionCode   end      Else If @VoteType = 'ALL'    begin    select      DepartmentCode + '/' + DivisionCode as MunicipalClassification     ,DepartmentDesc + ' / ' + DivisionDesc as MunicipalClassDesc     ,Division_ID     ,DivisionDesc     ,DivisionCode     ,DepartmentDesc     ,DepartmentCode      ,Department_ID     ,DivEnabled     ,Const_Department.Enabled as DeptEnabled    from #temp2    inner join Const_Department on #temp2.DepartmentID = Const_Department.Department_ID    where Enabled = 1 and DivEnabled = 1    order by DepartmentCode, DivisionCode   end      Else    begin    select      DepartmentCode + '/' + DivisionCode as MunicipalClassification     ,DepartmentDesc + ' / ' + DivisionDesc as MunicipalClassDesc     ,Division_ID     ,DivisionDesc     ,DivisionCode     ,DepartmentDesc     ,DepartmentCode      ,Department_ID     ,DivEnabled     ,Const_Department.Enabled as DeptEnabled    from #temp2    inner join Const_Department on #temp2.DepartmentID = Const_Department.Department_ID    where Enabled = 1 and DivEnabled = 1    order by DepartmentCode, DivisionCode   end      drop table #temp   drop table #temp2  END  

GO

-- ============================================
-- SP: Const_DepartmentDivisionFullPath_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author: Carol Brooking  -- Create date:  14/04/2014  -- Description: Getting the list of the departments & full path of divisions. Used on DeptDivisionAdd page for exporting  -- Martin Moonsamy 02/12/2014 - Removed apostrophes from DepartmentCode and DivisionCode - made change in code for this.    -- CB 25/11/2015 Add in order by clause  -- CALLS : Const_DepartmentDivisionFullPath_sp  -- CB 2016/03/02 remove control dept & div, add order by and enabled flags  -- =============================================  CREATE PROCEDURE [dbo].[Const_DepartmentDivisionFullPath_sp]   AS  BEGIN   SET FMTONLY OFF         create table #temp2    (TID int identity(1,1),     DivisionParentID int,     Division_ID int,     DivisionDesc nvarchar(500) COLLATE SQL_Latin1_General_CP1_CI_AS,     DivisionCode nvarchar(200) COLLATE SQL_Latin1_General_CP1_CI_AS,     DepartmentID int);         Insert into #temp2 (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   Select    DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID   From     dbo.Const_RecursiveDivision_fxn() --Recursive function to call division levels        Declare @count int,     @DivParentID int,     @Desc nvarchar(100),     @Code nvarchar(10)        Select @count = 1        While @count <= (Select MAX(TID) from #temp2)    begin    Select @DivParentID = DivisionParentID from #temp2 where TID = @Count    if(@DivParentID is not null)    begin     Select @Desc = DivisionDesc, @Code = DivisionCode from #temp2 where Division_ID = @DivParentID          Update #temp2     set DivisionDesc = @Desc + '#' + DivisionDesc,      DivisionCode = @Code + '#' + DivisionCode     where TID = @Count    end        Select @Count = @count + 1    end     Select    DepartmentDesc    ,''+ DepartmentCode as DepartmentCode     ,Department_ID    ,DivisionDesc    ,'' + DivisionCode as DivisionCode    ,Division_ID    ,(select Enabled from Const_Division where Division_ID = #temp2.Division_ID) as DivEnabled    ,Const_Department.Enabled as DeptEnabled   from    Const_Department   left join #temp2     ON Const_Department.Department_ID = #temp2.DepartmentID   Order by DepartmentDesc, DivisionDesc     drop table #temp2  END         

GO

-- ============================================
-- SP: Const_DepartmentDivisionSearch_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Carol Brooking  -- Create date:  14/04/2014  -- Description: Getting the list of the departments & count of divisions. Used on DeptDivisionAdd page  -- CALLS : Const_DepartmentDivisionSearch_sp ''  --2016 07 07 Shardik  Incrace DivisionCode 10 to 50   -- 14 July 2017 - Nidhi Desai-  Added StartDate in Select  -- =============================================  CREATE PROCEDURE [dbo].[Const_DepartmentDivisionSearch_sp] --'',''      @DeptCode NVARCHAR(100) ,      @DeptDesc NVARCHAR(100)  AS      BEGIN          SET FMTONLY OFF;            IF ( @DeptCode = '' )              SELECT  @DeptCode = NULL;              IF ( @DeptDesc = '' )              SELECT  @DeptDesc = NULL;             CREATE TABLE #temp2              (                TID INT IDENTITY(1, 1) ,                DivisionParentID INT ,                Division_ID INT ,                DivisionDesc NVARCHAR(200) COLLATE SQL_Latin1_General_CP1_CI_AS ,                DivisionCode VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS ,                DepartmentID INT              );                INSERT  INTO #temp2                  ( DivisionParentID ,                    Division_ID ,                    DivisionDesc ,                    DivisionCode ,                    DepartmentID                  )                  SELECT  DivisionParentID ,                          Division_ID ,                          DivisionDesc ,                          DivisionCode ,                          DepartmentID                  FROM    dbo.Const_RecursiveDivision_fxn();  --Recursive function to call division levels            DECLARE @count INT ,              @DivParentID INT ,              @Desc NVARCHAR(100);               SELECT  @count = 1;              WHILE @count <= ( SELECT    MAX(TID)                            FROM      #temp2                          )              BEGIN                  SELECT  @DivParentID = DivisionParentID                  FROM    #temp2                  WHERE   TID = @count;                  IF ( @DivParentID IS NOT NULL )                      BEGIN                          SELECT  @Desc = DivisionDesc                          FROM    #temp2                          WHERE   Division_ID = @DivParentID;                               UPDATE  #temp2                          SET     DivisionDesc = @Desc + '#' + DivisionDesc                          WHERE   TID = @count;                              END;                      SELECT  @count = @count + 1;                     END;               SELECT  DepartmentDesc ,                  DepartmentCode ,                  Department_ID ,                  Enabled ,                  DivCount ,                  StartDate          FROM    Const_Department                  LEFT JOIN ( SELECT  COUNT(*) AS DivCount ,                                      DepartmentID                              FROM    #temp2                              GROUP BY DepartmentID                            ) AS DivCounting ON Const_Department.Department_ID = DivCounting.DepartmentID                         --WHERE             --(@DeptCode ='' OR Const_Department.DepartmentCode=@DeptCode)            --AND  (@DeptDesc ='' OR Const_Department.DepartmentDesc=@DeptDesc)                      WHERE   /*Department_ID <> 0   and*/       DepartmentCode LIKE '%' + ISNULL(@DeptCode, '')                  + '%'                  AND DepartmentDesc LIKE '%' + ISNULL(@DeptDesc, '')                  + '%'          ORDER BY DepartmentDesc ASC;            DROP TABLE #temp2;      END;  

GO

-- ============================================
-- SP: Const_DepartmentSearch
-- Schema: dbo
-- ============================================
  /* =============================================   Author  : Ferdi Botha   Create Date : 09/04/2019   Description : Getting the list of the Departments and Divisions   ============================================= */  create procedure [Const_DepartmentSearch] @DeptCode varchar(50) = null, @DeptDesc varchar(200) = null  as  begin     set nocount on;     select [DEP].[Department_ID], [DEP].[DepartmentCode], [DEP].[DepartmentDesc], isnull([DIV].[NoDivisions], 0) as [NoDivisions], [DEP].[FinYear], [DEP].[StartDate], [DEP].[Enabled]      from [Const_Department] as [DEP] with(nolock)      left outer join (       select [DepartmentID], count([DepartmentID]) as [NoDivisions]        from [Const_Division] with(nolock)         group by [DepartmentID]      ) as [DIV] on [DIV].[DepartmentID] = [DEP].[Department_ID]      where ([DEP].[DepartmentCode] like '%' + isnull(@DeptCode, '') + '%' and [DEP].[DepartmentDesc] like '%' + isnull(@DeptDesc, '') + '%')       order by [DEP].[DepartmentDesc]     set nocount off;    end  

GO

-- ============================================
-- SP: Const_DivisionSearch
-- Schema: dbo
-- ============================================
  /* =============================================   Author  : Ferdi Botha   Create Date : 09/04/2019   Description : Getting the list of the Divisions   ============================================= */  create procedure [Const_DivisionSearch] @DivCode varchar(50) = null, @DivDesc varchar(200) = null  as  begin     set nocount on;     select [DEP].[Department_ID], [DIV].[Division_ID], [DEP].[DepartmentCode], [DEP].[DepartmentDesc], [DIV].[DivisionCode], [DIV].[DivisionDesc], [DEP].[FinYear] as [DEPFinYear], [DIV].[FinYear] as [DIVFinYear], [DEP].[Enabled] as [DEPEnabled], [DIV].[Enabled] as [DIVEnabled]      from [Const_Division] as [DIV] with(nolock)       join [Const_Department] as [DEP] on [DEP].[Department_ID] = [DIV].[DepartmentID]      where ([DIV].[DivisionCode] like '%' + isnull(@DivCode, '') + '%' and [DEP].[DepartmentDesc] like '%' + isnull(@DivDesc, '') + '%')       order by [DEP].[DepartmentDesc], [DIV].[DivisionDesc]     set nocount off;    end  

GO

-- ============================================
-- SP: Const_DivisionTree_sp
-- Schema: dbo
-- ============================================
    -- =============================================      -- Author:  CB      -- Create date: 26 August 2013      -- Description: Returns List of items under a parent asset      -- [Const_DivisionTree_sp]  93  -- Modified:  -- 2016 07 18 Brooking C Add in the indefinite recursion code   -- 2019 03 30 BC 82403 Multiyear  -- 2019 04 16 Ferdi Botha => Updated mappings to use Fin Year on Const_Division    -- =============================================      CREATE PROCEDURE [dbo].[Const_DivisionTree_sp]   @DepartmentID int,   @FinYear varchar(9)      AS      BEGIN            SET NOCOUNT ON;      DECLARE @chartVersion varchar(10)     Select @chartVersion = (Select Top 1 Version from Const_Scoa_Function_Structure_ByYear(@FinYear));           WITH DeptDivGroup (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   AS   (      SELECT e.DivisionParentID, e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID    FROM Const_Division AS e    WHERE DivisionParentID IS NULL and DepartmentID = isnull(@DepartmentID, DepartmentID) and [FinYear] = @FinYear    UNION ALL    SELECT e.DivisionParentID,e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID    FROM Const_Division AS e    INNER JOIN DeptDivGroup AS d     ON e.DivisionParentID = d.Division_ID and e.FinYear = @FinYear   )         Select    DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID,@chartVersion As VersionNo   From     DeptDivGroup    inner join Const_Department on DeptDivGroup.DepartmentID = Const_Department.Department_ID and Const_Department.FinYear = @FinYear    where Department_ID <> 0    ORDER BY DivisionParentID ASC, DivisionDesc ASC   option (maxrecursion 0)     END          

GO

-- ============================================
-- SP: Const_GetEmployeeDetailWithDepandDiv_sp
-- Schema: dbo
-- ============================================
    -- =============================================    -- Author: CarolBrooking  -- Create date: 10/10/2014  -- Description: Get Employee, Dep and Div based on searching the surname  -- calls : Exec [Const_GetEmployeeDetailWithDepandDiv_sp] null,65  -- 05/08/2015 RC: TP 23045 Link was division_ID to departmentID fixed to be from division_ID to divisionID  --2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================    CREATE PROCEDURE [dbo].[Const_GetEmployeeDetailWithDepandDiv_sp]     @Surname NVARCHAR(50),    @EmpID int  AS    BEGIN         SELECT  Surname + ' ' + FirstName + '   ( ' + DepartmentDesc + '/' + DivisionDesc + ')'    + '  |' + CONVERT(nvarchar, Employee_ID) + '|' + CONVERT(nvarchar, Division_ID)  AS EMPDEP   FROM dbo.Payroll_Employee    INNER JOIN Payroll_Position AS PP ON PP.Position_ID = PositionID    INNER JOIN Payroll_JobProfile AS PSG ON PSG.JobProfile_ID = PP.JobProfileID    INNER JOIN Const_Department AS Dep ON Dep.Department_ID = PP.DepartmentID    INNER JOIN Const_Division AS Div ON Div.Division_ID = PP.DivisionID   WHERE dbo.Payroll_Employee.Enabled = 1    --AND surname LIKE @Surname  + '%'    AND ((Employee_ID = @EmpID) OR (@EmpID = 0))   ORDER BY Surname  END    

GO

-- ============================================
-- SP: Const_GetEmployeeDetailWithDepDiv
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL  -- Create date: 17 JULY 2014  -- Description: Get Employee, Dep and Div  --2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- calls : Const_GetEmployeeDetailWithDepDiv 'B',0  -- =============================================    CREATE PROCEDURE [dbo].[Const_GetEmployeeDetailWithDepDiv]     @FirstName NVARCHAR(50),    @ProcurementPlanID INT  AS    BEGIN         SELECT  dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (Employee_ID)), 8,'0') + ' - ' +      FirstName + ' ' + Surname + ' - (' + DepartmentCode + ') ' + DepartmentDesc AS EMPDEP   FROM dbo.Payroll_Employee    INNER JOIN Payroll_Position AS PP ON PP.Position_ID = PositionID    INNER JOIN dbo.Payroll_JobProfile  AS PJP ON PP.JobProfileID = PJP.JobProfile_ID AND PJP.Enabled = 1    INNER JOIN dbo.Const_Department ON Department_ID = PP.DepartmentID AND dbo.Const_Department.Enabled = 1   WHERE dbo.Payroll_Employee.Enabled = 1    AND FirstName LIKE @FirstName + '%' AND    Employee_ID NOT IN (SELECT EmployeeID FROM dbo.SCM_ProcurementPlanTeam WHERE ProcurementPlanID = @ProcurementPlanID)   ORDER BY FirstName  END    

GO

