-- ============================================
-- SP: Const_PMSAnnualFieldSearch_sp
-- Schema: dbo
-- ============================================
-- ===================================================================  -- Author:  Chris Moodley  -- Edited:  Themba Tshabalala  -- Create date: July 2024  -- Description: Search for indicator custom fields per financial year  -- ===================================================================  CREATE PROCEDURE [dbo].[Const_PMSAnnualFieldSearch_sp]      -- Add the parameters for the stored procedure here   @financialYear VARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here     SELECT    AnnualFieldHeader_ID,    FinancialYear,    AnnualFieldDesc   FROM    Const_PMSAnnualField_Header header LEFT JOIN     (      SELECT DISTINCT        AnnualFieldHeaderID,       STUFF((SELECT '#' + CONVERT(VARCHAR, AnnualFieldOrderID) + '.' + AnnualFieldDesc         FROM Const_PMSAnnualField_Detail detail1         WHERE detail1.AnnualFieldHeaderID = detail2.AnnualFieldHeaderID AND detail1.AnnualFieldEnabled = 1         FOR XML PATH('')), 1, 1, '') AS AnnualFieldDesc      FROM       Const_PMSAnnualField_Detail detail2     ) detail ON      header.AnnualFieldHeader_ID = detail.AnnualFieldHeaderID   WHERE    header.FinancialYear = @financialYear OR ISNULL(header.FinancialYear, '') = ISNULL(@financialYear, ISNULL(header.FinancialYear, ''))       END

GO

-- ============================================
-- SP: Const_PMSCoreCompetencyRequirement_sp
-- Schema: dbo
-- ============================================
  -- ==================================================================================  -- Author:  Chris Moodley  -- Create date: 18 November 2014  -- Description: Return core competency requirements per type and description search  -- ==================================================================================  CREATE PROCEDURE [dbo].[Const_PMSCoreCompetencyRequirement_sp]    -- Add the parameters for the stored procedure here   @ccrDesc NVARCHAR(200),   @ccrTypeID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    CoreCompetencyRequirement_ID,    CoreCompetencyRequirementTypeID,    CoreCompetencyRequirementTypeDesc,    CoreCompetencyRequirementDesc,    ccr.Enabled   FROM    Const_PMSCoreCompetencyRequirement ccr LEFT JOIN     Const_PMSCoreCompetencyRequirementType_sys ccrType ON      ccr.CoreCompetencyRequirementTypeID = ccrType.CoreCompetencyRequirementType_ID   WHERE    (ccr.CoreCompetencyRequirementDesc LIKE '%' + @ccrDesc + '%') AND    ((ccr.CoreCompetencyRequirementTypeID = @ccrTypeID) OR (@ccrTypeID = 0 ))  END    

GO

-- ============================================
-- SP: Const_PMSCustomFieldSearch_sp
-- Schema: dbo
-- ============================================
-- ===================================================================  -- Author:  Chris Moodley  -- Create date: 24 July 2014  -- Description: Search for indicator custom fields per financial year  -- ===================================================================  CREATE PROCEDURE [dbo].[Const_PMSCustomFieldSearch_sp]    -- Add the parameters for the stored procedure here   @financialYear VARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here     SELECT    CustomFieldHeader_ID,    FinancialYear,    CustomFieldDesc   FROM    Const_PMSIndicatorCustomField_Header header LEFT JOIN     (      SELECT DISTINCT        CustomFieldHeaderID,       STUFF((SELECT '#' + CONVERT(VARCHAR, CustomFieldOrderID) + '.' + CustomFieldDesc         FROM Const_PMSIndicatorCustomField_Detail detail1         WHERE detail1.CustomFieldHeaderID = detail2.CustomFieldHeaderID AND detail1.CustomFieldEnabled = 1         FOR XML PATH('')), 1, 1, '') AS CustomFieldDesc      FROM       Const_PMSIndicatorCustomField_Detail detail2     ) detail ON      header.CustomFieldHeader_ID = detail.CustomFieldHeaderID   WHERE    header.FinancialYear = @financialYear OR ISNULL(header.FinancialYear, '') = ISNULL(@financialYear, ISNULL(header.FinancialYear, ''))       END  

GO

-- ============================================
-- SP: Const_PMSDepartmentNKPAWeightingDetail_sp
-- Schema: dbo
-- ============================================
  -- ===================================================  -- Author:  Chris Moodley  -- Create date: 16 December 2014  -- Description: Return NKPA weighting per department  -- ===================================================  CREATE PROCEDURE [dbo].[Const_PMSDepartmentNKPAWeightingDetail_sp] --'2014/2015', 5   -- Add the parameters for the stored procedure here   @financialYear NVARCHAR(50),   @departmentID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT DISTINCT    NationalKPADetail_ID,    NationalKPANumber,    NationalKPADesc,    ISNULL(DepartmentNKPAWeightingHeader_ID, 0) AS DepartmentNKPAWeightingHeader_ID,    ISNULL(DepartmentNKPAWeightingDetail_ID, 0) AS DepartmentNKPAWeightingDetail_ID,    ISNULL(Weighting, 0) AS Weighting   FROM    Const_IDPNationalKPA_Header idpHeader INNER JOIN     Const_IDPNationalKPA_Detail idpDetail ON      idpHeader.NationalKPAHeader_ID = idpDetail.NationalKPAHeaderID LEFT JOIN     (      SELECT       DepartmentNKPAWeightingHeader_ID,      DepartmentNKPAWeightingDetail_ID,      NationalKPADetailID,      Weighting      FROM      Const_PMSDepartmentNKPAWeighting_Header nkpaWeightingHeader LEFT JOIN       Const_PMSDepartmentNKPAWeighting_Detail nkpaWeightingDetail ON        nkpaWeightingHeader.DepartmentNKPAWeightingHeader_ID = nkpaWeightingDetail.DepartmentNKPAWeightingHeaderID AND nkpaWeightingHeader.DepartmentID = @departmentID     ) nKPADepartmentWeighting ON      idpDetail.NationalKPADetail_ID = nKPADepartmentWeighting.NationalKPADetailID   WHERE    idpHeader.FinancialYear = @financialYear AND    NationalKPAEnabled = 1   ORDER BY    NationalKPANumber    END    

GO

-- ============================================
-- SP: Const_PMSDepartmentNKPAWeightingHeader_sp
-- Schema: dbo
-- ============================================
  -- ==================================================  -- Author:  Chris Moodley  -- Create date: 15 December 2014  -- Description: Search for Department NKPA Weighting  -- ==================================================  CREATE PROCEDURE [dbo].[Const_PMSDepartmentNKPAWeightingHeader_sp] --'2014/2015', 5   -- Add the parameters for the stored procedure here   @financialYear NVARCHAR(50),   @departmentID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here    SELECT     header.DepartmentNKPAWeightingHeader_ID,    header.FinancialYear,    header.DepartmentID,    dept.DepartmentDesc,    deptNKPAWeightingDetail   FROM    Const_PMSDepartmentNKPAWeighting_Header header INNER JOIN     (       SELECT DISTINCT        DepartmentNKPAWeightingHeaderID,       STUFF((SELECT '#' + nkpaDetail.NationalKPADesc + ' - ' + CONVERT(VARCHAR, Weighting) + '%'           FROM Const_PMSDepartmentNKPAWeighting_Detail detail1 INNER JOIN           Const_IDPNationalKPA_Detail nkpaDetail ON            detail1.NationalKPADetailID = nkpaDetail.NationalKPADetail_ID           WHERE detail1.DepartmentNKPAWeightingHeaderID = detail2.DepartmentNKPAWeightingHeaderID           FOR XML PATH('')), 1, 1, '') AS deptNKPAWeightingDetail      FROM       Const_PMSDepartmentNKPAWeighting_Detail detail2     ) detail ON      detail.DepartmentNKPAWeightingHeaderID = header.DepartmentNKPAWeightingHeader_ID INNER JOIN     Const_Department dept ON      header.DepartmentID = dept.Department_ID   WHERE    header.FinancialYear = @financialYear OR ISNULL(header.FinancialYear, '') = ISNULL(@financialYear, ISNULL(header.FinancialYear, '')) AND    (header.DepartmentID = @departmentID OR @departmentID = 0)    END    

GO

-- ============================================
-- SP: Const_PMSMidYearFieldSearch_sp
-- Schema: dbo
-- ============================================
-- ===================================================================  -- Author:  Chris Moodley  -- Edited:  Themba Tshabalala  -- Create date: July 2024  -- Description: Search for indicator custom fields per financial year  -- ===================================================================  CREATE PROCEDURE [dbo].[Const_PMSMidYearFieldSearch_sp]    -- Add the parameters for the stored procedure here   @financialYear VARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;         -- Insert statements for procedure here      SELECT    MidYearFieldHeader_ID,    FinancialYear,    MidYearFieldDesc   FROM    Const_PMSMidYearField_Header header LEFT JOIN     (      SELECT DISTINCT        MidYearFieldHeaderID,       STUFF((SELECT '#' + CONVERT(VARCHAR, MidYearFieldOrderID) + '.' + MidYearFieldDesc         FROM Const_PMSMidYearField_Detail detail1         WHERE detail1.MidYearFieldHeaderID = detail2.MidYearFieldHeaderID AND detail1.MidYearFieldEnabled = 1         FOR XML PATH('')), 1, 1, '') AS MidYearFieldDesc      FROM       Const_PMSMidYearField_Detail detail2     ) detail ON      header.MidYearFieldHeader_ID = detail.MidYearFieldHeaderID   WHERE    header.FinancialYear = @financialYear OR ISNULL(header.FinancialYear, '') = ISNULL(@financialYear, ISNULL(header.FinancialYear, ''))  END

GO

-- ============================================
-- SP: Const_PMSOrganisationNKPAWeightingDetail_sp
-- Schema: dbo
-- ============================================
-- ===================================================  -- Author:  Chris Moodley  -- Create date: 16 December 2014  -- Description: Return NKPA weighting  -- ===================================================  CREATE PROCEDURE [dbo].[Const_PMSOrganisationNKPAWeightingDetail_sp]    -- Add the parameters for the stored procedure here   @financialYear NVARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT DISTINCT    NationalKPADetail_ID,    NationalKPANumber,    NationalKPADesc,    ISNULL(OrganisationNKPAWeightingHeader_ID, 0) AS OrganisationNKPAWeightingHeader_ID,    ISNULL(OrganisationNKPAWeightingDetail_ID, 0) AS OrganisationNKPAWeightingDetail_ID,    ISNULL(Weighting, 0) AS Weighting   FROM    Const_IDPNationalKPA_Header idpHeader INNER JOIN     Const_IDPNationalKPA_Detail idpDetail ON      idpHeader.NationalKPAHeader_ID = idpDetail.NationalKPAHeaderID LEFT JOIN     (      SELECT       OrganisationNKPAWeightingHeader_ID,      OrganisationNKPAWeightingDetail_ID,      NationalKPADetailID,      Weighting      FROM      Const_PMSOrganisationNKPAWeighting_Header nkpaWeightingHeader LEFT JOIN       Const_PMSOrganisationNKPAWeighting_Detail nkpaWeightingDetail ON        nkpaWeightingHeader.OrganisationNKPAWeightingHeader_ID = nkpaWeightingDetail.OrganisationNKPAWeightingHeaderID     ) nKPAOrganisationWeighting ON      idpDetail.NationalKPADetail_ID = nKPAOrganisationWeighting.NationalKPADetailID   WHERE    idpHeader.FinancialYear = @financialYear AND    NationalKPAEnabled = 1   ORDER BY    NationalKPANumber  END  

GO

-- ============================================
-- SP: Const_PMSOrganisationNKPAWeightingHeader_sp
-- Schema: dbo
-- ============================================
-- ==================================================  -- Author:  Chris Moodley  -- Create date: 19 January 2015  -- Description: Search for Organisation NKPA Weighting  -- ==================================================  CREATE PROCEDURE [dbo].[Const_PMSOrganisationNKPAWeightingHeader_sp]    -- Add the parameters for the stored procedure here   @financialYear NVARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     header.OrganisationNKPAWeightingHeader_ID,    header.FinancialYear,    orgNKPAWeightingDetail   FROM    Const_PMSOrganisationNKPAWeighting_Header header INNER JOIN     (       SELECT DISTINCT        OrganisationNKPAWeightingHeaderID,       STUFF((SELECT '#' + nkpaDetail.NationalKPADesc + ' - ' + CONVERT(VARCHAR, Weighting) + '%'           FROM Const_PMSOrganisationNKPAWeighting_Detail detail1 INNER JOIN           Const_IDPNationalKPA_Detail nkpaDetail ON            detail1.NationalKPADetailID = nkpaDetail.NationalKPADetail_ID           WHERE detail1.OrganisationNKPAWeightingHeaderID = detail1.OrganisationNKPAWeightingHeaderID           FOR XML PATH('')), 1, 1, '') AS orgNKPAWeightingDetail      FROM       Const_PMSOrganisationNKPAWeighting_Detail detail1     ) detail ON      detail.OrganisationNKPAWeightingHeaderID = header.OrganisationNKPAWeightingHeader_ID   WHERE    header.FinancialYear = @financialYear OR ISNULL(header.FinancialYear, '') = ISNULL(@financialYear, ISNULL(header.FinancialYear, ''))  END  

GO

-- ============================================
-- SP: Const_PMSPostCoreCompetencyRequirementDetail_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Chris Moodley  -- Create date: 21 November 2014  -- Description: Return CCR details per post  -- =============================================  CREATE PROCEDURE [dbo].[Const_PMSPostCoreCompetencyRequirementDetail_sp] --181   -- Add the parameters for the stored procedure here   @jobProfileID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     CoreCompetencyRequirement_ID,    CoreCompetencyRequirementTypeID,    CoreCompetencyRequirementDesc,    CoreCompetencyRequirementTypeDesc,    PostCoreCompetencyRequirementHeader_ID,    JobProfileID,    Submitted,    ISNULL(PostCoreCompetencyRequirementDetail_ID, 0) AS PostCoreCompetencyRequirementDetail_ID,    CoreCompetencyRequirementID,    ISNULL(Assigned, 0) AS Assigned,    ISNULL(Weighting, 0) AS Weighting   FROM     Const_PMSCoreCompetencyRequirement ccr LEFT JOIN     Const_PMSCoreCompetencyRequirementType_sys ccrType ON      ccr.CoreCompetencyRequirementTypeID = ccrType.CoreCompetencyRequirementType_ID LEFT JOIN     (SELECT       ccrHeader.PostCoreCompetencyRequirementHeader_ID,      JobProfileID,      Submitted,      ccrDetail.PostCoreCompetencyRequirementDetail_ID,      ccrDetail.CoreCompetencyRequirementID,      ccrDetail.Assigned,      ccrDetail.Weighting       FROM Const_PMSPostCoreCompetencyRequirement_Header ccrHeader LEFT JOIN       Const_PMSPostCoreCompetencyRequirement_Detail ccrDetail ON        ccrHeader.PostCoreCompetencyRequirementHeader_ID = ccrDetail.PostCoreCompetencyRequirementHeaderID AND JobProfileID = @jobProfileID) postCCR ON      ccr.CoreCompetencyRequirement_ID = postCCR.CoreCompetencyRequirementID   WHERE    ccr.Enabled = 1 AND ccrType.Enabled = 1     END    

GO

-- ============================================
-- SP: Const_PMSPostCoreCompetencyRequirementHeader_sp
-- Schema: dbo
-- ============================================
  -- ===========================================================  -- Author:  Chris Moodley  -- Create date: 21 November 2014  -- Description: Return Post Core Competency Requirement Header  -- ===========================================================  CREATE PROCEDURE [dbo].[Const_PMSPostCoreCompetencyRequirementHeader_sp]   -- Add the parameters for the stored procedure here   @jobProfileID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    PostCoreCompetencyRequirementHeader_ID,    JobProfileID,    JobTitle,    Submitted   FROM    Const_PMSPostCoreCompetencyRequirement_Header postCCRHeader INNER JOIN     Payroll_JobProfile jobProfile ON      postCCRHeader.JobProfileID = jobProfile.JobProfile_ID   WHERE    ((postCCRHeader.JobProfileID = @jobProfileID) OR (@jobProfileID = 0 ))  END    

GO

-- ============================================
-- SP: Const_PMSUnitMeasureSearch_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 22 July 2014  -- Description: Returns KPI unit of measure  -- =============================================  CREATE PROCEDURE [dbo].[Const_PMSUnitMeasureSearch_sp]   -- Add the parameters for the stored procedure here     AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    unitmeasure.UnitMeasure_ID,    unitmeasure.UnitMeasureDesc,    unitmeasure.UnitMeasureEnabled,    datatype.DataType_ID,    datatype.DataTypeName,    datatype.DataTypeDesc,    datatype.DataTypeEnabled   FROM    Const_PMSIndicatorUnitMeasure unitmeasure LEFT JOIN     Const_PMSDataType_Sys datatype ON      unitmeasure.DataTypeID = datatype.DataType_ID  END  

GO

-- ============================================
-- SP: Const_UpdateLeaveTypeDetais
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,03 Apr 2014>  -- Description: <Description,,>  -- Call SP    : Const_LeaveTypeDetais_lst_sp  -- =============================================  CREATE PROCEDURE [dbo].[Const_UpdateLeaveTypeDetais]  @SequenceNo int =null,  @AccrualDays int =null,  @LeaveTypeDetailsId int,  @LeaveType_ID int,  @MaxAccumulation int =null,  @Compulsary int =null,  @StartDate DateTime =null,  @EndDate DateTime =null  AS  BEGIN     update Const_LeaveTypeDetails   set [SequenceNo] = @SequenceNo,    AccrualDays = @AccrualDays,    MaxAccumulation = IsNull(@MaxAccumulation,MaxAccumulation),    CompulsoryDays = Isnull(@Compulsary,CompulsoryDays)   where LeaveTypeDetailsId =@LeaveTypeDetailsId     update Const_LeaveType   set StartDate =Isnull(@StartDate,StartDate),   EndDate = Isnull(@EndDate,EndDate)   where LeaveType_ID = @LeaveType_ID        END    

GO

-- ============================================
-- SP: Const_UpdateLeaveTypeDetais_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,03 Apr 2014>  -- Description: <Description,,>  -- Call SP    : Const_LeaveTypeDetais_lst_sp  -- =============================================  CREATE PROCEDURE [dbo].[Const_UpdateLeaveTypeDetais_sp]  @SequenceNo int,  @AccrualDays int,  @CycleRepeatFrequency int,  @MaxAccumulation int,  @StartDate DateTime ,  @EndDate DateTime,  @LeaveTypeDetailsId int,  @LeaveType_ID int  AS  BEGIN  UPDATE Const_LeaveTypeDetails  SET SequenceNo = @SequenceNo,   AccrualDays = @AccrualDays,   CycleRepeatFrequency =@CycleRepeatFrequency,   MaxAccumulation = @MaxAccumulation  WHERE LeaveTypeDetailsId = @LeaveTypeDetailsId  AND LeaveTypeId = @LeaveType_ID    UPDATE Const_LeaveType  SET  StartDate =@StartDate,   EndDate =@EndDate  WHERE LeaveType_ID = @LeaveType_ID    END    

GO

-- ============================================
-- SP: Payroll_AddAdhocPayrollRunEmployee_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 17 APR 2016  -- Description: Add employees to adhoc period run  -- Call: [Payroll_AddAdhocPayrollRunEmployee_sp]  -- 2015-02-17 TP35407 Saleem Khan: Created  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_AddAdhocPayrollRunEmployee_sp]      @PeriodID INT = 2634,   @EmployeeTypeID INT = NULL,   @DivisionID INT = NULL,   @EmployeeID INT = NULL,   @Type NVARCHAR(20),   @CapturerID INT = 1  AS    BEGIN        IF UPPER(@Type) = 'ALL' AND @PeriodID IS NOT NULL    BEGIN     INSERT INTO [dbo].[Payroll_CyclePeriodAdhocEmployee]          ([PeriodID]          ,[EmployeeID]          ,[Enabled]          ,[DateCaptured]          ,[CapturerID]          ,[DateModified]          ,[ModifierID])     SELECT @PeriodID,       E.Employee_ID,1,       getdate(),       @CapturerID,       getdate(),1     FROM [dbo].Payroll_Employee E     LEFT JOIN Payroll_CyclePeriodDetails C ON E.CycleID = C.CycleID     WHERE C.Period_ID = @PeriodID AND       E.Enabled=1     END    ELSE IF UPPER(@Type) = 'EMPLOYEETYPE' AND @PeriodID IS NOT NULL AND @EmployeeTypeID IS NOT NULL    BEGIN     INSERT INTO [dbo].[Payroll_CyclePeriodAdhocEmployee]          ([PeriodID]          ,[EmployeeID]          ,[Enabled]          ,[DateCaptured]          ,[CapturerID]          ,[DateModified]          ,[ModifierID])     SELECT @PeriodID,       E.Employee_ID,       1,       getdate(),       @CapturerID,       getdate(),       1     FROM [dbo].Payroll_Employee E     LEFT JOIN Payroll_Position PP       ON E.PositionID = PP.Position_ID     LEFT JOIN Payroll_JobProfile C       ON C.JobProfile_ID = PP.JobProfileID     WHERE C.EmployeeTypeID = @EmployeeTypeID     AND E.Enabled = 1    END    ELSE IF UPPER(@Type) = 'DIVISION' AND @PeriodID IS NOT NULL AND @DivisionID IS NOT NULL    BEGIN     INSERT INTO [dbo].[Payroll_CyclePeriodAdhocEmployee]          ([PeriodID]          ,[EmployeeID]          ,[Enabled]          ,[DateCaptured]          ,[CapturerID]          ,[DateModified]          ,[ModifierID])     SELECT @PeriodID,       E.Employee_ID,       1,       getdate(),       @CapturerID,       getdate(),       1     FROM Payroll_Employee E     LEFT JOIN Payroll_Position PP       ON E.PositionID = PP.Position_ID     LEFT JOIN Payroll_JobProfile C      ON C.JobProfile_ID = PP.JobProfileID       WHERE PP.DivisionID = @DivisionID AND       E.Enabled=1     END    ELSE IF UPPER(@Type) = 'EMPLOYEE' AND @PeriodID IS NOT NULL AND @EmployeeID IS NOT NULL    BEGIN       IF NOT EXISTS (SELECT * FROM [dbo].[Payroll_CyclePeriodAdhocEmployee] WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID)     BEGIN      INSERT INTO [dbo].[Payroll_CyclePeriodAdhocEmployee]           ([PeriodID]           ,[EmployeeID]           ,[Enabled]           ,[DateCaptured]           ,[CapturerID]           ,[DateModified]           ,[ModifierID])      VALUES( @PeriodID,@EmployeeID,1,getdate(),@CapturerID,getdate(),1)     END    END        SELECT 1 AS ResultCount        END

GO

-- ============================================
-- SP: Payroll_AddEmployeePayrollDefinition_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 02 01 2014  -- Name: Payroll_AddEmployeePayrollDefinition_sp  -- Description: Creates a single link between a SalaryHead and an employee.  -- Called From: HR/Payroll->Payslip: When you add an unlinked salaryhead to an employee  -- 2015-02-07 James Roodt: Added IsRFI parameter  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_AddEmployeePayrollDefinition_sp]   @EmployeeId INT,   @PayrollSalaryHeadId INT,   @FunctionCodeId INT,   @LoggedUserId INT,   @SCOACostingID INT,   @SCOAFundsID INT,   @SCOAProjectID INT,   @SCOARegionID INT,   @SCOAItemID INT,   @IsRFI BIT  AS  BEGIN   SET NOCOUNT ON;     INSERT INTO dbo.Payroll_EmployeePayrollDefinition          (      EmployeeID, PayrollSalaryHeadID , FunctionCodeID , Percentage , CustomAction ,      SCOACostingID, SCOAFundsID, SCOAProjectID, SCOARegionID, SCOAItemID,     Enabled , DateCaptured , CapturerID, IsRFI          )   VALUES      (      @EmployeeId, @PayrollSalaryHeadId , @FunctionCodeId , 100.00 , 1 ,      @SCOACostingID, @SCOAFundsID, @SCOAProjectID, @SCOARegionID, @SCOAItemID,     1 , GETDATE() , @LoggedUserId, @IsRFI       )          SELECT @@IDENTITY AS PayrollDefinitionID  END  

GO

-- ============================================
-- SP: Payroll_AddLeaveAccruals
-- Schema: dbo
-- ============================================
     -- =================================================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/12>  -- Description: <Leave Accruals>     -- Modify: 2025/01/23 - Richa M - Fix leavebalance when leave is captured over 2 months    -- =================================================================================================  CREATE PROCEDURE [dbo].[Payroll_AddLeaveAccruals]   @EmployeeID INT,  @EmployeeStartDate DATETIME,  @CycleTypeID INT,  @CalcDate DATETIME,  @LeaveTypeId INT,  @LeaveDetailId INT,  @AccrualDays DECIMAL(18,2),  @AccrualInterval INT,  @LeaveSchemeId INT,  @CycleIdPeriodStart INT = 1,  @CycleEnd INT = 12,  @CycleStartDate DATETIME,  @AbsenceTypeId INT,  @ExtensionDays INT,  @BalanceForAdditionalDays DECIMAL(18,2),  @AdditionalDays DECIMAL(18,2),  @MaxDays DECIMAL(18,2),  @PeriodStart int      AS  BEGIN  DECLARE @NextAccrualDate DATETIME  DECLARE @DaysAccrued DECIMAL(18, 2) = 0  DECLARE @ForfeitDate DATETIME  DECLARE @DaysToForfeit decimal(18,4)    DECLARE @EmpCycleStartDate DATETIME  DECLARE @EmpCycleEndDate DATETIME  DECLARE @ForfeitLeave bit      select @ForfeitLeave = (select Forfeit from Const_LeaveTypeDetails where LeaveTypeDetailsId = @LeaveDetailId)    DECLARE @ForfeitDatesTable Table  (   ForfeitDate DateTime  )     --CALCULATE CYCLE START AND CYCLE END   IF @CycleIdPeriodStart = 1 -- fixed   BEGIN    SET @EmpCycleStartDate = @CycleStartDate    SET @EmpCycleEndDate = DATEADD(DAY, -1, DATEADD(MONTH, @CycleEnd, @CycleStartDate))    WHILE ( @CalcDate > @EmpCycleEndDate)    BEGIN     SET @EmpCycleStartDate  = DATEADD(Year,1,@EmpCycleStartDate)     SET @EmpCycleEndDate = DATEADD(DAY,-1, DATEADD(MONTH,@CycleEnd,@EmpCycleStartDate))    END     END     IF @CycleIdPeriodStart = 2 --Employee Start Date   BEGIN    SET @EmpCycleStartDate = @EmployeeStartDate     SELECT @EmpCycleEndDate = DATEADD(DAY,-1, DATEADD(MONTH,@CycleEnd,@EmployeeStartDate))      SET @ForfeitDate = DATEADD(DAY,@ExtensionDays,@EmpCycleEndDate)      Insert Into @ForfeitDatesTable     Select @ForfeitDate       WHILE ( @CalcDate > @EmpCycleEndDate)    BEGIN     SET @EmpCycleStartDate  = DATEADD(Month,@CycleEnd,@EmpCycleStartDate)     SET @EmpCycleEndDate = DATEADD(DAY,-1, DATEADD(MONTH,@CycleEnd,@EmpCycleStartDate))       SET @ForfeitDate = DATEADD(DAY,@ExtensionDays,@EmpCycleEndDate)     Insert Into @ForfeitDatesTable      Select @ForfeitDate    END     END     IF @CycleIdPeriodStart = 3 --CalenderYear   BEGIN    SET @EmpCycleStartDate = DATEADD(yy, DATEDIFF(yy, 0, @CalcDate), 0)    SET @EmpCycleEndDate = DATEADD(DAY, -1, DATEADD(MONTH, @CycleEnd, @EmpCycleStartDate))   END       --Get the next accrualDate   IF @AccrualInterval = 3--Monthly   BEGIN    --WHEN accrueing monthly the accrue date will ALWAYS be the last day of the month        SELECT @NextAccrualDate = CONVERT(VARCHAR(25), DATEADD(dd, -(DAY(DATEADD(mm, 1, @CalcDate))),DATEADD(mm, 1, @CalcDate)), 101)      END   IF @AccrualInterval = 1--Once Off   BEGIN   --Once off will always be on the FIRST cycle start date    SELECT @NextAccrualDate = @EmpCycleStartDate   END     DECLARE @FirstAccrualDate Datetime   IF @AccrualInterval = 2--Yearly   BEGIN    Select @FirstAccrualDate = DATEADD(MONTH,@PeriodStart, @EmployeeStartDate)    Select @NextAccrualDate = DATEADD(MONTH,0, @EmpCycleStartDate)   END     if( @NextAccrualDate is null)    set @NextAccrualDate =DATEADD(yy, DATEDIFF(yy, 0, @CalcDate), 0)       Select * into #temp from(     select EmployeeId,StartDate,EndDate,Value,NumberOfDaysRequested,StartDate Date,1 shift,1 leave,0 publicH,Value Average,LeaveAdjustmentTypeID from Payroll_EmployeeLeaveTransactions where EmployeeID = @EmployeeID and Enabled = 1 and LeaveTypeID = @LeaveTypeId and LeaveStatusID = 3 and Startdate = enddate    UNION ALL    select * from(    select l.EmployeeID,l.StartDate,l.EndDate, value,l.NumberOfDaysRequested,cal.Date,cal.Shift,cal.Leave,cal.PublicH,(abs(value)/l.NumberOfDaysRequested)* -1 Average,LeaveAdjustmentTypeID from(    select EmployeeID, StartDate,EndDate,Value,NumberOfDaysRequested,LeaveAdjustmentTypeID from  Payroll_EmployeeLeaveTransactions where EmployeeID = @EmployeeID and Enabled = 1 and LeaveTypeID = @LeaveTypeId and LeaveStatusID = 3 and Startdate <> enddate)l    join Payroll_EmployeeCalander cal on cal.date BETWEEN l.StartDate and l.EndDate and cal.EmployeeID = l.EmployeeID     where shift = 1 and cal.PublicH = 0)v1)v2      DECLARE @LeaveBalance decimal(18,2) = (select SUM(Average) from #temp where date <= @CalcDate)   -- DECLARE @LeaveBalance decimal(18,2) = (select SUM(Value) from payroll_employeeleaveTransactions where employeeid = @EmployeeID and LeaveTypeId = @LeaveTypeId and EndDate < @CalcDate and Enabled = 1 and LeaveStatusID = 3)       If @MaxDays > 0    begin    if @LeaveBalance + @AccrualDays > @MaxDays    select @AccrualDays = @MaxDays - @LeaveBalance    end    --Update relevant tables    --ADD THE ACCRUAL TRANSACTION IF NECESSARY    IF (@CalcDate = @NextAccrualDate OR @CalcDate = @FirstAccrualDate) and @AccrualDays > 0    BEGIN     INSERT INTO Payroll_EmployeeLeaveTransactions (EmployeeID, LeaveSchemeID, LeaveTypeID, LeaveAdjustmentTypeID, LeaveStatusID, Enabled, StartDate, EndDate, Value, Notes, DateCaptured, CapturerID, DateModified, ModifierID, NumberOfDaysRequested,AbsenceTypeId)      VALUES (@EmployeeID, @LeaveSchemeId, @LeaveTypeId, 2, 3, 1, @CalcDate, @CalcDate, ISNULL(@AccrualDays,0), 'Leave Accrued', GETDATE(), 1, NULL, NULL, @AccrualDays,@AbsenceTypeId);      SET @DaysAccrued = @AccrualDays    END      if(@ForfeitLeave = 1)    begin    --FORFEIT THE BALANCE    IF @CalcDate in (Select ForfeitDate from @ForfeitDatesTable)    BEGIN       DECLARE @DaysTaken decimal(18,2)      --SET @DaysToForfeit  = (select SUM(Value) from payroll_employeeleaveTransactions where employeeid = @EmployeeID and LeaveTypeId = @LeaveTypeId and EndDate < @EmpCycleEndDate and Enabled = 1 and LeaveStatusID = 3) --+ isnull(@DaysTaken,0)          declare @maxDate datetime = DATEADD(DAY,-@ExtensionDays,@CalcDate)       select @DaysToForfeit = (select sum(average) from #temp       where Date <= @maxDate)        select @DaysTaken = (select sum(average) from #temp      where date > @maxDate and date < @CalcDate and leaveAdjustmentTypeId = 3)         select @DaysToForfeit = isnull(@DaysToForfeit,0) + isNULL(@DaysTaken,0)           IF @DaysToForfeit > 0      BEGIN       INSERT INTO Payroll_EmployeeLeaveTransactions (EmployeeID, LeaveSchemeID, LeaveTypeID, LeaveAdjustmentTypeID, LeaveStatusID, Enabled, StartDate, EndDate, Value, Notes, DateCaptured, CapturerID, DateModified, ModifierID, NumberOfDaysRequested,AbsenceTypeId)       VALUES (@EmployeeID, @LeaveSchemeId, @LeaveTypeId, 4, 3, 1, @CalcDate, @CalcDate, ISNULL(@DaysToForfeit,0) * -1, 'Leave Forfeited', GETDATE(), 1, NULL, NULL, @DaysToForfeit,@AbsenceTypeId);         END     end    END      IF EXISTS(SELECT ID FROM Payroll_LeaveAccrualDates WHERE EmployeeId = @EmployeeID AND LeaveTypeId = @LeaveTypeId)    BEGIN     --UPDATE THE LAST ACCRUAL DATE     UPDATE Payroll_LeaveAccrualDates     SET DaysAccrued = @DaysAccrued        ,LastAccrualCalcDate = @CalcDate     WHERE EmployeeId = @EmployeeID     AND LeaveTypeId = @LeaveTypeId    END    ELSE    BEGIN     --INSERT RECORD     INSERT INTO Payroll_LeaveAccrualDates     (EmployeeId,LeaveTypeId,LastAccrualCalcDate,DaysAccrued)     VALUES     (@EmployeeID,@LeaveTypeId,@CalcDate,@DaysAccrued)    END      Update Payroll_EmployeeLeaveBalance set CalcDate = @CalcDate, NextAccrualDate = @NextAccrualDate, ForfeitDate = @ForfeitDate,CyclestartDate = @EmpCycleStartDate, CycleEndDate = @EmpCycleEndDate,Notes = 'UpdateBalance' where EmployeeId = @EmployeeID and LeaveTypeId = @LeaveTypeId      END

GO

-- ============================================
-- SP: Payroll_AddLeaveDefinition_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 16 July 2013  -- Description: Leave Definition insert process  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_AddLeaveDefinition_sp]       @LeaveTypeDesc varchar(200) = NULL,    @FixedLeaveDays decimal(18, 2) = NULL,    @FALSuspendYear decimal(18, 2)  = NULL,    @InCrementalLeaveDays decimal(18, 2)  = NULL,    @ICALeaveValue decimal(18, 2)  = NULL,    @ICALMaxLimit decimal(18, 2)  = NULL,    @ICALMinEnCashValue decimal(18, 2)  = NULL,    @ICALMaxEnCashValue decimal(18, 2)  = NULL,    @SickLeaveDays decimal(18, 2)  = NULL,    @SLSuspendYear decimal(18, 2)  = NULL,    @FullSickLeaveDays decimal(18, 2)  = NULL,    @HalfSickLeaveDays decimal(18, 2)  = NULL,    @HSLSalaryDeduct decimal(18, 2)  = NULL,    @CompanyAccidentLeaveDays decimal(18, 2)  = NULL,    @AccidentLeaveDays decimal(18, 2)  = NULL,    @SpecialLeaveDays decimal(18, 2)  = NULL,    @FamilyLeaveDays decimal(18, 2)  = NULL,    @MaternityLeaveDays decimal(18, 2)  = NULL,    @AdditionalMLeaveDays decimal(18, 2)  = NULL,    @AMPayOfBasicSalary decimal(18, 2)  = NULL,    @AdoptionLeaveDays decimal(18, 2)  = NULL,    @AdditionalALeaveDays decimal(18, 2)  = NULL,    @APayOfBasicSalary decimal(18, 2)  = NULL,    @YearRange decimal(18, 2)  = NULL,    @BonusValue decimal(18, 2)  = NULL,    @BonusLeave decimal(18, 2)  = NULL,    @SBLMaxLimit decimal(18, 2)  = NULL,    @SBLMinEnCashValue decimal(18, 2)  = NULL,    @SBLMaxEnCashValue decimal(18, 2)  = NULL,    @Enabled BIT,    @DateCaptured DATETIME,    @CapturerID INT     AS  BEGIN      SET NOCOUNT ON;        INSERT INTO dbo.Payroll_LeaveDefinition              ( LeaveTypeDesc ,                FixedLeaveDays ,                FALSuspendYear ,                InCrementalLeaveDays ,                ICALeaveValue ,                ICALMaxLimit ,                ICALMinEnCashValue ,                ICALMaxEnCashValue ,                SickLeaveDays ,                SLSuspendYear ,                FullSickLeaveDays ,                HalfSickLeaveDays ,                HSLSalaryDeduct ,                CompanyAccidentLeaveDays ,                AccidentLeaveDays ,                SpecialLeaveDays ,                FamilyLeaveDays ,                MaternityLeaveDays ,                AdditionalMLeaveDays ,                AMPayOfBasicSalary ,                AdoptionLeaveDays ,                AdditionalALeaveDays ,                APayOfBasicSalary ,                YearRange ,                BonusValue ,                BonusLeave ,                SBLMaxLimit ,                SBLMinEnCashValue ,                SBLMaxEnCashValue ,                [Enabled] ,                DateCaptured ,                CapturerID              )      VALUES  ( @LeaveTypeDesc ,                @FixedLeaveDays ,                @FALSuspendYear ,                @InCrementalLeaveDays ,                @ICALeaveValue ,                @ICALMaxLimit ,                @ICALMinEnCashValue ,                @ICALMaxEnCashValue ,                @SickLeaveDays ,                @SLSuspendYear ,                @FullSickLeaveDays ,                @HalfSickLeaveDays ,                @HSLSalaryDeduct ,                @CompanyAccidentLeaveDays ,                @AccidentLeaveDays ,                @SpecialLeaveDays ,                @FamilyLeaveDays ,                @MaternityLeaveDays ,                @AdditionalMLeaveDays ,                @AMPayOfBasicSalary ,                @AdoptionLeaveDays ,                @AdditionalALeaveDays ,                @APayOfBasicSalary ,                @YearRange ,                @BonusValue ,                @BonusLeave ,                @SBLMaxLimit ,                @SBLMinEnCashValue ,                @SBLMaxEnCashValue ,                @Enabled ,                @DateCaptured ,                @CapturerID              )  END  

GO

-- ============================================
-- SP: Payroll_AddLeaveEscalationReassigneHistory_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,04 Apr 2014>  -- Description: <Description,,Insert Payroll Leave Escalation Or Reassigne History>  -- Call SP    : Payroll_AddLeaveEscalationReassigneHistory_sp 15, 0, 0, 0  --2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions    -- =============================================  CREATE PROCEDURE [dbo].[Payroll_AddLeaveEscalationReassigneHistory_sp]   @LeaveApproveId INT,   @IsReassign BIT,   @ReassignTo INT,   @UserId INT  AS  BEGIN   DECLARE @EmployeeId INT, @JobGradingId INT, @ProfileSubGroupId INT, @History_Id INT, @ProfileGroupId INT, @HistoryId INT      SELECT @EmployeeId = P_LR.EmployeeID, @ProfileSubGroupId = PP.JobProfileID FROM dbo.Payroll_LeaveApproveRequest AS P_LR   INNER JOIN dbo.Payroll_Employee AS P_E ON P_LR.EmployeeID = P_E.Employee_ID   INNER JOIN dbo.Payroll_Position  AS PP ON PP.Position_ID = P_E.PositionID   INNER JOIN Payroll_JobProfile AS PSG ON PSG.JobProfile_ID = PP.JobProfileID   WHERE LeaveApproveRequest_ID = @LeaveApproveId      IF @IsReassign = 0 BEGIN    DELETE FROM Payroll_LeaveEscalationReassigneHistory WHERE LeaveApproveRequestId = @LeaveApproveId        INSERT INTO dbo.Payroll_LeaveEscalationReassigneHistory (LeaveApproveRequestId, JobProfileId, CapturerId, IsApproved)    SELECT @LeaveApproveId, ToWomDoesThisPositionReport, @UserId, 0 FROM dbo.Payroll_JobProfile    WHERE JobProfile_ID = @ProfileSubGroupId    SET @HistoryId = SCOPE_IDENTITY()    EXEC dbo.Payroll_LeaveEscalationReassignEmail @History_Id = @HistoryId -- int       END   ELSE BEGIN    SELECT TOP 1 @History_Id = History_Id FROM dbo.Payroll_LeaveEscalationReassigneHistory WHERE LeaveApproveRequestId = @LeaveApproveId    AND IsProcessed = 0        UPDATE dbo.Payroll_LeaveEscalationReassigneHistory SET IsProcessed = 1 WHERE LeaveApproveRequestId = @LeaveApproveId        INSERT INTO dbo.Payroll_LeaveEscalationReassigneHistory (LeaveApproveRequestId, EmployeeId, IsReassigned, FromHistoryId, CapturerId, IsApproved)    SELECT @LeaveApproveId, @ReassignTo, 1, @History_Id, @UserId, 0    SET @HistoryId = SCOPE_IDENTITY()    EXEC dbo.Payroll_LeaveEscalationReassignEmail @History_Id = @HistoryId -- int   END  END    

GO

-- ============================================
-- SP: Payroll_AddLeaveSchemeDefinition_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 16 July 2013  -- Description: Leave Definition insert process  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_AddLeaveSchemeDefinition_sp]       @LeaveTypeID INT = NULL,    @LeaveSchemeID INT = NULL,    @FixedLeaveDays decimal(18, 2) = NULL,    @FALSuspendYear decimal(18, 2)  = NULL,    @InCrementalLeaveDays decimal(18, 2)  = NULL,    @ICALeaveValue decimal(18, 2)  = NULL,    @ICALMaxLimit decimal(18, 2)  = NULL,    @ICALMinEnCashValue decimal(18, 2)  = NULL,    @ICALMaxEnCashValue decimal(18, 2)  = NULL,    @SickLeaveDays decimal(18, 2)  = NULL,    @SLSuspendYear decimal(18, 2)  = NULL,    @FullSickLeaveDays decimal(18, 2)  = NULL,    @HalfSickLeaveDays decimal(18, 2)  = NULL,    @HSLSalaryDeduct decimal(18, 2)  = NULL,    @CompanyAccidentLeaveDays decimal(18, 2)  = NULL,    @AccidentLeaveDays decimal(18, 2)  = NULL,    @SpecialLeaveDays decimal(18, 2)  = NULL,    @FamilyLeaveDays decimal(18, 2)  = NULL,    @MaternityLeaveDays decimal(18, 2)  = NULL,    @AdditionalMLeaveDays decimal(18, 2)  = NULL,    @AMPayOfBasicSalary decimal(18, 2)  = NULL,    @AdoptionLeaveDays decimal(18, 2)  = NULL,    @AdditionalALeaveDays decimal(18, 2)  = NULL,    @APayOfBasicSalary decimal(18, 2)  = NULL,    @YearRange decimal(18, 2)  = NULL,    @BonusValue decimal(18, 2)  = NULL,    @BonusLeave decimal(18, 2)  = NULL,    @SBLMaxLimit decimal(18, 2)  = NULL,    @SBLMinEnCashValue decimal(18, 2)  = NULL,    @SBLMaxEnCashValue decimal(18, 2)  = NULL,    @Enabled BIT,    @DateCaptured DATETIME,    @CapturerID INT     AS  BEGIN      SET NOCOUNT ON;        INSERT INTO dbo.Const_LeaveSchemeDetails              ( LeaveTypeID ,       LeaveSchemeID,                FixedLeaveDays ,                FALSuspendYear ,                InCrementalLeaveDays ,                ICALeaveValue ,                ICALMaxLimit ,                ICALMinEnCashValue ,                ICALMaxEnCashValue ,                SickLeaveDays ,                SLSuspendYear ,                FullSickLeaveDays ,                HalfSickLeaveDays ,                HSLSalaryDeduct ,                CompanyAccidentLeaveDays ,                AccidentLeaveDays ,                SpecialLeaveDays ,                FamilyLeaveDays ,                MaternityLeaveDays ,                AdditionalMLeaveDays ,                AMPayOfBasicSalary ,                AdoptionLeaveDays ,                AdditionalALeaveDays ,                APayOfBasicSalary ,                YearRange ,                BonusValue ,                BonusLeave ,                SBLMaxLimit ,                SBLMinEnCashValue ,                SBLMaxEnCashValue ,                [Enabled] ,                DateCaptured ,                CapturerID,                MunicipalityID              )      VALUES  ( @LeaveTypeID ,          @LeaveSchemeID,                @FixedLeaveDays ,                @FALSuspendYear ,                @InCrementalLeaveDays ,                @ICALeaveValue ,                @ICALMaxLimit ,                @ICALMinEnCashValue ,                @ICALMaxEnCashValue ,                @SickLeaveDays ,                @SLSuspendYear ,                @FullSickLeaveDays ,                @HalfSickLeaveDays ,                @HSLSalaryDeduct ,                @CompanyAccidentLeaveDays ,                @AccidentLeaveDays ,                @SpecialLeaveDays ,                @FamilyLeaveDays ,                @MaternityLeaveDays ,                @AdditionalMLeaveDays ,                @AMPayOfBasicSalary ,                @AdoptionLeaveDays ,                @AdditionalALeaveDays ,                @APayOfBasicSalary ,                @YearRange ,                @BonusValue ,                @BonusLeave ,                @SBLMaxLimit ,                @SBLMinEnCashValue ,                @SBLMaxEnCashValue ,                @Enabled ,                @DateCaptured ,                @CapturerID,                (SELECT Top 1 Municipality_ID FROM Payroll_Municipality)              )  END  

GO

-- ============================================
-- SP: Payroll_AddPayeExplainLine
-- Schema: dbo
-- ============================================
   /*    Author  : Richa M   Create date : 2025/12/15   Description : Add PAYE ExplanationRows   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation  */  CREATE PROCEDURE [dbo].[Payroll_AddPayeExplainLine]      @EmployeeID       INT,      @PeriodID         INT,      @TaxYear          VARCHAR(10),      @IsTrialRun       BIT,      @SequenceNo       INT,      @Section          VARCHAR(50),      @LineCode         VARCHAR(50),      @LineDescription  VARCHAR(200),      @SourceAmount     DECIMAL(18,6) = NULL,      @YTDAmount        DECIMAL(18,6) = NULL,      @CalculatedAmount DECIMAL(18,6) = NULL,      @ExtraInfo        VARCHAR(MAX)  = NULL,      @CreatedBy        INT           = NULL  AS  BEGIN      SET NOCOUNT ON;        INSERT INTO [dbo].[Payroll_PayeCalculationExplain] (          EmployeeID, PeriodID, TaxYear, IsTrialRun,          SequenceNo, Section, LineCode, LineDescription,          SourceAmount, YTDAmount, CalculatedAmount, ExtraInfo,          CreatedOn, CreatedBy      )      VALUES (          @EmployeeID, @PeriodID, @TaxYear, @IsTrialRun,          @SequenceNo, @Section, @LineCode, @LineDescription,          @SourceAmount, @YTDAmount, @CalculatedAmount, @ExtraInfo,          GETDATE(), @CreatedBy      );  END;  

GO

-- ============================================
-- SP: Payroll_AllMyLeave
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,06 Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_AllMyLeave 2, 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_AllMyLeave]   @UserId INT,   @Approved BIT  AS  BEGIN   DECLARE @EmployeeId INT   SELECT @EmployeeId = EmpID FROM dbo.User_UserDetail WHERE User_ID = @UserId      IF @Approved = 1 BEGIN    SELECT L.LeaveApproveRequest_ID, EmployeeID, Emp.FirstName + ' ' + Emp.Surname AS FullName, Emp.FirstName, Emp.Surname, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Emp.Employee_ID )), 8,'0') AS EmpNo , Emp.IdNo, Emp.PassportNumber, LeaveType, RequestFromDate, RequestToDate, RequestNoOfDays, ApproveFromDate, ApproveToDate, ApproveNoOfDays, RequestReason, ApproveReason FROM dbo.Payroll_LeaveApproveRequest AS L    INNER JOIN dbo.Const_LeaveType AS LT ON L.LeaveTypeID = LT.LeaveType_ID    INNER JOIN dbo.Payroll_Employee AS Emp ON L.EmployeeID = Emp.Employee_ID    WHERE EmployeeID = @EmployeeId AND ApprovalStatus = 3   END   ELSE BEGIN    SELECT L.LeaveApproveRequest_ID, EmployeeID, Emp.FirstName + ' ' + Emp.Surname AS FullName, Emp.FirstName, Emp.Surname, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Emp.Employee_ID )), 8,'0') AS EmpNo , Emp.IdNo, Emp.PassportNumber, LeaveType, RequestFromDate, RequestToDate, RequestNoOfDays, ApproveFromDate, ApproveToDate, ApproveNoOfDays, RequestReason, ApproveReason FROM dbo.Payroll_LeaveApproveRequest AS L    INNER JOIN dbo.Const_LeaveType AS LT ON L.LeaveTypeID = LT.LeaveType_ID    INNER JOIN dbo.Payroll_Employee AS Emp ON L.EmployeeID = Emp.Employee_ID    WHERE EmployeeID = @EmployeeId AND ApprovalStatus = 2   END     END  

GO

-- ============================================
-- SP: Payroll_ApplyEmployeeSalaryIncreaseByNotch_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 09 MAR 2016  -- Description: The function will take the supplied Employee, look at his salary, rpd and notch level.  --  Then take his current notch level and if possible up it with one.  --  compare the current salary withe new notch related salary and if lower replace it with the new notch salary.  --  Bonuses: If the Bonus is equal to the old salary then apply the new notch salary as th enew bonus as well. Else, compute the ratio of the old b onus against the old salary and apply the same ration to the new salary to get the new bonus amount.  --  i.e. Salary 1000, bonus 600 thus ratio is 60%. New salary is R1200 thus R1200*60%=R720  --  It will then return these new values  -- Call: [Payroll_ApplyEmployeeSalaryIncreaseByNotch_sp]  -- 2015-03-09 TP32276 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_ApplyEmployeeSalaryIncreaseByNotch_sp]      @EmployeeID INT =null      AS    SET NOCOUNT ON;   DECLARE @CurrentFixedSalary DECIMAL(18,2) = 0   DECLARE @CurrentBonus DECIMAL(18,2) = 0   DECLARE @CurrentNotchID INT   DECLARE @Notch INT   DECLARE @TaskGradeId nvarchar(200)   DECLARE @NotchFixedSalary DECIMAL(18,2) = 0   DECLARE @NewNotchFixedSalary DECIMAL(18,2) = 0   DECLARE @NewNotch INT   --   DECLARE @NewFixedSalary DECIMAL(18,2) = 0   DECLARE @NewBonus DECIMAL(18,2) = 0   --   DECLARE @BonusRatio INT   DECLARE @NewNotchSalary TABLE   (    FixedSalary DECIMAL(18,2),    Bonus DECIMAL(18,2),    Notch INT   )     BEGIN       --Get the Employee details   SELECT @CurrentFixedSalary = pe.FixedSalary,     @CurrentBonus = pe.BonusAmount,     @CurrentNotchID = pe.NotchId,     @TaskGradeId = TG.TaskGrade_Id,     @Notch = pn.Notch,     @NotchFixedSalary = pn.MonthlySalary   FROM [dbo].[Payroll_Employee] pe   INNER JOIN  [dbo].[Payroll_Notch] pn ON PN.Notch_Id = pe.NotchId   INNER JOIN [dbo].[Payroll_TaskGrade] TG WITH (NOLOCK) ON TG.TaskGrade_Id = pn.TaskGradeId   WHERE pe.Employee_ID = @EmployeeID          -- Get New Notch details   SELECT @NewNotchFixedSalary = MonthlySalary, @NewNotch = Notch   FROM [dbo].[Payroll_Notch]    WHERE TaskGradeId = @TaskGradeId AND Notch = @Notch + 1     PRINT 'Calculating New Salary for employee :'+ CONVERT(nvarchar, @EmployeeID)   PRINT 'Current salary:' + CONVERT(nvarchar, @CurrentFixedSalary)   PRINT 'Current bonus:' + CONVERT(nvarchar, @CurrentBonus)   PRINT 'Current notch:' + CONVERT(nvarchar, @Notch)   PRINT '----------------------------------------------------'   --Calc New salary   IF @NewNotchFixedSalary IS NOT NULL AND @CurrentFixedSalary < @NewNotchFixedSalary   BEGIN    PRINT 'Current salary less than new notch salary - Applying new Notch salary'        SET @NewFixedSalary = @NewNotchFixedSalary    PRINT 'New Salary :' + CONVERT(nvarchar, @NewFixedSalary)    PRINT 'New Notch :' + CONVERT(nvarchar, @NewNotch)         --Calc new bonus    IF @CurrentBonus = @CurrentFixedSalary    BEGIN     PRINT 'Current bonus = to current salary'     SET @NewBonus = @NewFixedSalary     PRINT 'New bonus is :' + CONVERT(nvarchar,@NewBonus)    END    ELSE    BEGIN     PRINT 'Current bonus != to current salary, applying same ratio to get new bonus'     SET @BonusRatio = (@CurrentBonus/@CurrentFixedSalary) * 100     SET @NewBonus = (@NewFixedSalary/100) * @BonusRatio     PRINT 'Bonus ratio :' + CONVERT(nvarchar,@BonusRatio)     PRINT 'New Bonus :' + CONVERT(nvarchar,@NewBonus)    END      INSERT INTO @NewNotchSalary VALUES(@NewFixedSalary,@NewBonus,@NewNotch)   END   ELSE IF @CurrentFixedSalary > @NewNotchFixedSalary   BEGIN    PRINT 'Salary greater than next notch, increasing notch'    INSERT INTO @NewNotchSalary VALUES(@CurrentFixedSalary,@CurrentBonus,@NewNotch)    END   ELSE   BEGIN    PRINT 'No new notch to apply or Salary already greater than new notch salary'    INSERT INTO @NewNotchSalary VALUES(@CurrentFixedSalary,@CurrentBonus,@Notch)   END     SELECT * FROM @NewNotchSalary        END

GO

-- ============================================
-- SP: Payroll_ApproveAA88TransactionDetail_SP
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Tshekedi Mogwere  -- Create date: 17/08/2017  -- Description: Create a stub Proc till all the logic is written - Process the AATransaction Details into Payroll_CostCenter tables  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_ApproveAA88TransactionDetail_SP]   @TransactionDetailId INT,   @Approve bit,   @UserId INT  AS  BEGIN       declare @DefinationId INT   declare @municipalityId INT   declare @TaxYear NVARCHAR(13)   declare @FinancialYear NVARCHAR(13)       UPDATE Payroll_AA88TransactionDetail   set Approved = @Approve    WHERE TransactionDetailId = @TransactionDetailId     -- Now Process the Record       SELECT @municipalityId = Municipality_Id FROM Payroll_Municipality     SELECT @TaxYear = KeyValue from AAAA_ConfigSettings where KeyName  = 'TaxYear'   SELECT @FinancialYear = KeyValue from AAAA_ConfigSettings where KeyName  = 'TaxYear'     SELECT @DefinationId = PayrollDefination_ID FROM Payroll_PayrollDefination D WITH(NOLOCK)   INNER JOIN Payroll_SalaryHead S WITH(NOLOCK) ON S.SalaryHead_ID = D.PayrollSalaryHeadID   WHERE S.SalaryHeadName = 'Pay-as-you-earn (PAYE: Tax Over Deduction)'      INSERT INTO [dbo].[Payroll_CostCenter]             ([PayrollDefinationID]             ,[EmployeeID]             ,[CostAmount]             ,[CostDesc]             ,[EntryDate]             ,[MunicipalityID]             ,[FinancialYear]             ,[Enabled]             ,[DateCaptured]             ,[CapturerID]                      ,[EarDedTypeId]                       ,[PeriodID]             ,[TaxYear]             ,[IsApproved]                        ,[IsApprovalRequired]                       ,[RunEveryMonth]           ,[TaxableAmount]       ,[Rate]                  ,[EffectiveDate]             ,[EndDate]             )      SELECT  @DefinationId        ,EmployeeID             ,AA88MonthlyDeduction             ,'AA88 Deductions'             ,GETDATE()             ,@municipalityId             ,@FinancialYear             ,1             ,GETDATE()             ,@UserId                       ,2             ,2 -- Period             ,@TaxYear             ,1                       ,0                        ,0                       ,AA88MonthlyDeduction             , AA88MonthlyDeduction             ,AA88StartDate             ,AA88EndDate               FROM Payroll_AA88TransactionDetail where TransactionDetailId = @TransactionDetailId       END

GO

