-- ============================================
      create procedure [dbo].[Payroll_BulkErrors_sp] @table [Payroll_BulkErrors] readonly   as     begin       begin try        delete from [Payroll_BulkErrors] where [BulkUploadHeaderID] = (select top 1 [BulkUploadHeaderID] from @table )        insert into [dbo].[Payroll_BulkErrors]          ([EmployeeID],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate],[ValidationType],[Blocking],[BulkUploadHeaderID])             select [EmployeeID],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate],[ValidationType],[Blocking],[BulkUploadHeaderID] from @table           select 1       end try       begin catch        select 0       end catch       end  

GO

