on]         ,[MaidenName],[EquityDisabled],[NotchId],[TaxCalculationType],[BonusCalculation],[IsTemporary],[NatureOfPersonID],[PhysicalAddressTypeID],[PostalAddressTypeID],[PhysicalPOBoxNo],[PostalPOBoxNo]                   ,[PhysicalPostOffice],[PostalPostOffice],[QualificationID],[NewLabour],[Learners],[IsContractor],[BonusAmount],[KinContactFullName],[PhysicalSuburbID],[PostalSuburbID],[WorkSuburbID]                 ,[KinTownID],[KinSuburbID],[KinStreetID],[KinStreetNumber],[KinTelephoneHome],[PhysicalStreetID],[PhysicalComplexName],[PhysicalFlatUnitSuiteNo],[PostalStreetID],[PostalComplexName]         ,[PostalFlatUnitSuiteNo],[ERSID],[ERSFingerPrintCount],[ERSStatusID],[ExcludeUIFNonContributorReasonID],[PackageAmount],[PackageOverriden],[DisabilityTypeID],[EmailAddressSecondary]         ,[FarmId],[PostalAddress3],[PostalAddress4],[AddressIndicator],[CareOfIntermediary],[AlternateIDNumber],[AlternateIDType],[PhyWorkUnit],[PhyWorkComplex],[PhyWorkStreetNo]                  ,[PhyWorkStreetId],[PhyWorkSuburbId] ,[PhyWorkCountryId],[PhysicalStreetNo] ,[PostalAddressNo],[PostalStreetName],[IsCareOfPostalAddress],[PostalAddressIndId],[PoSpecialService]         ,[PostalAddressUnitNumber],[PositionID] ,[EmployeeTypeID],[EmployeeSubtypeID] ,[PhysicalAddress3] ,[PhysicalAddress4] ,[ShiftRotationID],[BonusValueMOCID],[BonusPaymentDateID]              ,[PhyAddressComplex],[PhyAddressUnit],[MarritalStatusDate],[PayPointID])            select                [EmpCode] ,[IdNo],[TitleID] ,[Initials],[FirstName] ,[SecondName],[Surname],[KnownAsName],[DateOfBirth],[GenderID],[LanguageID],[MarriedID],[Dependants]         ,[PassportNumber],[PassportCountryID],[EmailAddress],[HomeNumber] ,[WorkNumber],[CellNumber],[FaxNumber],[JoiningDate],[EndDate],[WorkOutside]         ,[IncomeTaxNumber],[ExcludeUIF] ,[ExcludeSDL],[PhysicalAddress1] ,[PhysicalAddress2],[PhysicalPostalCode],[PhysicalCountryID],[PhysicalProvinceID],[PhysicalTownID]         ,[PostalSameAsPhysical] ,[PostalAddress1],[PostalAddress2],[PostalPostalCode] ,[PostalCountryID],[PostalProvinceID],[PostalTownID] ,[WorkSameAsPhysical],[WorkSameAsCompany]         ,[WorkAddress1],[WorkAddress2] ,[WorkPostalCode] ,[WorkCountryID],[WorkProvinceID],[WorkTownID],[PaymentTypeID],[AccountTypeID],[AccountHolderName],[AccountHolderRelationshipID]         ,[AccountNumber],[BankID] ,[BranchID] ,[WHPD_Other],[WDPW_Other],[RPD_Other],[RPH_Other],[RPW_Other],[WHPM_Monthly],[WDPM_Monthly] ,[WHPD_Monthly],[RPD_Monthly],[RPH_Monthly]         ,[AnnualSalary],[FixedSalary],[BE].[Enabled],[BE].[CapturerID],[BE].[DateCaptured],[IsDummy],[LeaveBased],[Monday],[Tuesday],[Wednesday],[Thursday] ,[Friday],[Saturday]         ,[Sunday] ,[ShiftID],[AllowOverTime],[MunicipalityID],[BE].[CycleID],[PayrollDefinitionGroupID],[EthnicGroupID],[IsMarried],[IsYough],[ImagePath],[MarriedIdNo],[MarriedDateOfBirth]                  ,[MarriedGenderID],[MarriedTitleID],[MarriedInitials],[MarriedFirstName],[MarriedSecondName],[MarriedSurname],[MarriedKnownAsName],[MarriedPassportCountryID],[MarriedPassportNumber]                   ,[KinContactRelationshipID],[KinContactName],[KinContactNo] ,[JobProfileID],[TerminationReasonID],[LeaveSchemeID],[ConditionOfServiceID],[Isforeigner],[HowthePersonMarried],[MethodofCommunication]         ,[MaidenName],[EquityDisabled],[NotchId],[TaxCalculationType],[BonusCalculation],[IsTemporary],[NatureOfPersonID],[PhysicalAddressTypeID],[PostalAddressTypeID],[PhysicalPOBoxNo],[PostalPOBoxNo]                   ,[PhysicalPostOffice],[PostalPostOffice],[QualificationID],[NewLabour],[Learners],[IsContractor],[BonusAmount],[KinContactFullName],[PhysicalSuburbID],[PostalSuburbID],[WorkSuburbID]                 ,[KinTownID],[KinSuburbID],[KinStreetID],[KinStreetNumber],[KinTelephoneHome],[PhysicalStreetID],[PhysicalComplexName],[PhysicalFlatUnitSuiteNo],[PostalStreetID],[PostalComplexName]         ,[PostalFlatUnitSuiteNo],[ERSID],[ERSFingerPrintCount],[ERSStatusID],[ExcludeUIFNonContributorReasonID],[PackageAmount],[PackageOverriden],[DisabilityTypeID],[EmailAddressSecondary]         ,[FarmId],[PostalAddress3],[PostalAddress4],[AddressIndicator],[CareOfIntermediary],[AlternateIDNumber],[AlternateIDType],[PhyWorkUnit],[PhyWorkComplex],[PhyWorkStreetNo]                  ,[PhyWorkStreetId],[PhyWorkSuburbId] ,[PhyWorkCountryId],[PhysicalStreetNo] ,[PostalAddressNo],[PostalStreetName],[IsCareOfPostalAddress],[PostalAddressIndId],[PoSpecialService]         ,[PostalAddressUnitNumber],[PositionID] ,[EmployeeTypeID],[EmployeeSubtypeID] ,[PhysicalAddress3] ,[PhysicalAddress4] ,[ShiftRotationID],[BonusValueMOCID],[BonusPaymentDateID]              ,[PhyAddressComplex],[PhyAddressUnit],[MarritalStatusDate],[PayPointID] from [Payroll_BulkUploadEmployeeDetails] [BE] with(nolock)         join [Payroll_BulkUploadHeader] as [BH] with(nolock) on [BH].[BulkUploadHeader_ID] = [BE].[BulkUploadHeaderID] and [BH].[BulkUploadHeader_ID] = @BulkUploadHeaderID         where [BH].[StatusID] = 153 and [BE].[Employee_ID] is null or [BE].[Employee_ID] = 0                    declare @table table(        [ID][int] identity,      [Col][nvarchar](200)        )        insert into @table ([Col]) (        select [PEc].[name] from [sys].[columns] [PEc]        join [sys].[tables] [PE] on [PEc].[object_id] = [PE].[object_id]        )             declare @count int = (select count([ID]) from @table) , @col nvarchar(200)        while (@count > 0)      begin             (select @col = [Col] from @table where [ID] = @count)         exec('update [PE] set [PE].'+ @col + '= [BE].' + @col +'          from [Payroll_Employee][PE] with(nolock)           join [Payroll_BulkUploadEmployeeDetails] [BE] with(nolock) on [BE].[Employee_ID] = [PE].[Employee_ID] and [BE].[Enabled] = 1 and [PE].[Enabled] = 1         join [Payroll_BulkUploadHeader] as [BH] with(nolock) on [BH].[BulkUploadHeader_ID] = [BE].[BulkUploadHeaderID] and [BH].[BulkUploadHeader_ID] =' + @BulkUploadHeaderID +                 'where [BH].[StatusID] = 153')           set @count = @count - 1        end             select 1          end  try      begin catch        select 0        end catch              set nocount off;     end

