-- ============================================
-- SP: Payroll_BulkTransactionSearch_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 03 SEPT 2016  -- Description: Returns all Bulk upload approvals which match the required search parameters  -- Call: [Payroll_BulkTransactionSearch_sp]  -- 2016-09-03 TP:43647 Seipei Mathole: Created  -- Update date : 15/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 04/03/2019 - Updated the Bulk Load Mappings - Ferdi Botha  -- Update date : 05/04/2019 - Added NULL to @BulkTypeID Parameter and updated the where clause - FERDI BOTHA  -- Update date : 16/05/2019 - Added return results UploadBy - FERDI BOTHA  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_BulkTransactionSearch_sp]      @BulkTypeID INT = NULL,      @BulkDate   DATETIME = NULL  AS  BEGIN      SET NOCOUNT ON;        DECLARE @StatusID INT =      (          SELECT Status_ID          FROM Const_Status          WHERE StatusDesc = 'Requested'            AND UsedBy     = 'BulkUploadApprovals'      );        SELECT DISTINCT             BUH.BulkUploadHeader_ID,             BUH.UploadDate,             UUD.FirstName + ' ' + UUD.LastName AS UploadBy,             CC.CycleDesc,             BUT.[Description] AS UploadTypeDesc,             SH.SalaryHeadName,             CASE BUH.BulkUploadTypeID                 WHEN 1 THEN (SELECT COUNT(1) FROM Payroll_BulkUploadTransactionDetails BTD2 WITH (NOLOCK) WHERE BTD2.BulkUploadHeaderID = BUH.BulkUploadHeader_ID)                 WHEN 6 THEN (SELECT COUNT(1) FROM Payroll_BulkUploadLeaveTransactions  BLT2 WITH (NOLOCK) WHERE BLT2.BulkUploadHeaderID = BUH.BulkUploadHeader_ID)                 ELSE       (SELECT COUNT(1) FROM Payroll_BulkUploadEmployeeDetails    BED2 WITH (NOLOCK) WHERE BED2.BulkUploadHeaderID = BUH.BulkUploadHeader_ID)             END AS AmountOfLines,             (SELECT SUM(Value)                FROM Payroll_BulkUploadTransactionDetails BTD2 WITH (NOLOCK)               WHERE BTD2.BulkUploadHeaderID = BUH.BulkUploadHeader_ID) AS CostAmount,             BUH.FileName,             CAST(0 AS BIT) AS Selected      FROM Payroll_BulkUploadHeader           BUH WITH (NOLOCK)      JOIN User_UserDetail                    UUD WITH (NOLOCK) ON UUD.User_ID             = BUH.CapturerID      LEFT JOIN Const_Cycle                   CC  WITH (NOLOCK) ON CC.Cycle_ID             = BUH.CycleID          AND CC.Enabled = 1      JOIN Const_Status                       CS  WITH (NOLOCK) ON CS.Status_ID            = BUH.StatusID         AND CS.Enabled = 1      JOIN Payroll_BulkUploadType_sys         BUT WITH (NOLOCK) ON BUT.BulkUploadType_ID   = BUH.BulkUploadTypeID AND BUT.Enabled = 1      LEFT JOIN Payroll_BulkUploadTransactionDetails BTD WITH (NOLOCK) ON BTD.BulkUploadHeaderID = BUH.BulkUploadHeader_ID      LEFT JOIN Payroll_BulkUploadEmployeeDetails   BED WITH (NOLOCK) ON BED.BulkUploadHeaderID = BUH.BulkUploadHeader_ID      LEFT JOIN Payroll_BulkUploadLeaveTransactions BL  WITH (NOLOCK) ON BL.BulkUploadHeaderID  = BUH.BulkUploadHeader_ID      LEFT JOIN Payroll_SalaryHead                 SH  WITH (NOLOCK) ON SH.SalaryHead_ID        = BTD.SalaryHeadID AND SH.Enabled = 1      WHERE BUH.Enabled = 1        AND BUH.StatusID = @StatusID        AND (@BulkTypeID IS NULL OR BUH.BulkUploadTypeID = @BulkTypeID);  END

GO

-- ============================================
-- SP: Payroll_BulkTransactionSearchRejected_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author  : Ferdi Botha  -- Create Date : 21/05/2019  -- Description : Returns all Bulk Upload Rejected Transactions  -- ==============================================================================  create procedure [Payroll_BulkTransactionSearchRejected_sp] @BulkTypeID int = null, @BulkDate datetime = null  as  begin     declare @statusID int = (select [Status_ID] from [Const_Status] where ([StatusDesc] = 'Rejected' and [UsedBy] = 'BulkUploadApprovals'))     select distinct [BUH].[BulkUploadHeader_ID], [BUH].[UploadDate], (select [FirstName] + ' ' + [LastName] from [User_UserDetail] with(nolock) where ([User_ID] = [BUH].[CapturerID])) as [UploadBy],      [CC].[CycleDesc], [BUT].[Description] as [UploadTypeDesc], [SH].[SalaryHeadName],      (case         when [BUH].[BulkUploadTypeID] = 1 then (select count(1) from [Payroll_BulkUploadTransactionDetails] as [BTD] with(nolock) where ([BTD].[BulkUploadHeaderID] = [BUH].[BulkUploadHeader_ID]))       else (select count(1) from [Payroll_BulkUploadEmployeeDetails] as [BTD] with(nolock) where ([BTD].[BulkUploadHeaderID] = [BUH].[BulkUploadHeader_ID]))      end) as [AmountOFLines],      (select sum([Value]) from [Payroll_BulkUploadTransactionDetails] as [BTD] with(nolock) where ([BTD].[BulkUploadHeaderID] = [BUH].[BulkUploadHeader_ID])) as [CostAmount],      [BUH].[FileName], cast(0 as bit) as [Selected]      from [Payroll_BulkUploadHeader] as [BUH] with(nolock)       left join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [BUH].[CycleID] and [CC].[Enabled] = 1       join [Const_Status] as [CS] with(nolock) on [CS].[Status_ID] = [BUH].[StatusID] and [CS].[Enabled] = 1       join [Payroll_BulkUploadType_sys] as [BUT] with(nolock) on [BUT].[BulkUploadType_ID] = [BUH].[BulkUploadTypeID] and [BUT].[Enabled] = 1       left join [Payroll_BulkUploadEmployeeDetails] as [BED] with(nolock) on [BED].[BulkUploadHeaderID] = [BUH].[BulkUploadHeader_ID]       left join [Payroll_BulkUploadTransactionDetails] as [BTD] with(nolock) on [BTD].[BulkUploadHeaderID] = [BUH].[BulkUploadHeader_ID]       left join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [BTD].[SalaryHeadID] and [SH].[Enabled] = 1      where ([BUH].[BulkUploadTypeID] = (case when @BulkTypeID is null then [BUH].[BulkUploadTypeID] else @BulkTypeID end) and [BUH].[Enabled] = 1 and [BUH].[StatusID] = @StatusID)       end  

GO

-- ============================================
-- SP: Payroll_CapturedLeaveTransactions
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-10  -- Description: Used as a dataset for Captured Leave Transactions report (Payroll_CapturedLeaveTransactions.rdl)  --              Returns all Leave Transactions captured by HR department during specific period  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_CapturedLeaveTransactions]      @CapturedFromDate DATETIME2,      @CapturedToDate DATETIME2,      @DepartmentId INT,      @DivisionId INT,      @CycleId INT,      @LeaveTypeId INT,      @LeaveSchemeId INT  AS  BEGIN    DECLARE @adjustmentType_taken INT = 3    SELECT      E.Employee_ID,      E.EmpCode,      E.Initials,      E.Surname,      LS.LeaveSchemeDesc,      LT.LeaveTypeDesc,      ELT.DocumentNumber,      ELT.StartDate,      ELT.EndDate,      ELT.NumberOfDaysRequested AS Days,      ELT.DateCaptured,   ELT.CapturerID,   UD.UserName,      ELT.Notes AS Reason  FROM Payroll_EmployeeLeaveTransactions AS ELT WITH (NOLOCK)      JOIN Payroll_Employee AS E WITH (NOLOCK) ON ELT.EmployeeID = E.Employee_ID      LEFT JOIN Payroll_Position AS P WITH (NOLOCK) ON P.Position_ID = E.PositionID      LEFT JOIN Const_Department AS DEP WITH (NOLOCK) ON P.DepartmentID = DEP.Department_ID      LEFT JOIN Const_Division AS DIV WITH (NOLOCK) ON P.DivisionID = DIV.Division_ID      JOIN Const_LeaveScheme AS LS WITH (NOLOCK) ON ELT.LeaveSchemeID = LS.LeaveScheme_ID      JOIN Const_LeaveType AS LT WITH (NOLOCK) ON ELT.LeaveTypeID = LT.LeaveType_ID   LEFT JOIN User_UserDetail AS UD WITH (NOLOCK) ON UD.User_ID = ELT.CapturerID  WHERE CONVERT(date, ELT.DateCaptured) >= @CapturedFromDate AND (@CapturedToDate IS NULL OR CONVERT(date, ELT.DateCaptured) <= @CapturedToDate)      AND E.EndDate > @CapturedFromDate      AND ELT.LeaveAdjustmentTypeID = @adjustmentType_taken      AND (ISNULL(@DepartmentId, 0) = 0 OR DEP.Department_ID = @DepartmentId)      AND (ISNULL(@DivisionId, 0) = 0 OR DIV.Division_ID = @DivisionId)      AND (ISNULL(@CycleID, 0) = 0 OR E.CycleID = @CycleID )      AND (ISNULL(@LeaveSchemeId, 0) = 0 OR ELT.LeaveSchemeID = @LeaveSchemeId)      AND (ISNULL(@LeaveTypeId, 0) = 0 OR ELT.LeaveTypeID = @LeaveTypeId)  END

GO

-- ============================================
-- SP: Payroll_CarriedOverDeductions_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,Lungisani khumalo>  -- Create date: <Create Date,17/06/2017>  -- Description: <Description,>  -- ============================================  create procedure [dbo].[Payroll_CarriedOverDeductions_rpt]      @EmployeeID int,@PeriodID int    as  begin    select distinct [DCO].[EmployeeID] as EmployeeID , [TransactionTypeID], sum(isnull([Balance], 0)) as Balance, sum(isnull([Outstanding], 0)) as Outstanding, [SH].[SalaryHeadTitle] as  TransactionTypeDescription , 'Carried Over Deductions' as TransactionTypeDesc     from [Payroll_DeductionPriorityBalance] as [DCO] with(nolock)      join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [DCO].[IRP5CodeID] and [IRP5].[Enabled] = 1      join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1     where ([DCO].[EmployeeID] = @EmployeeID and [DCO].[PeriodID] = @PeriodID and [TransactionTypeID] = 2)      group by [DCO].[EmployeeID], [TransactionTypeID], [SH].[SalaryHeadTitle]    end      

GO

-- ============================================
-- SP: Payroll_CarryForwardCostCenterEntries
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 17 JAN 2014  -- Description: Carry forward cost center every month tickmark values in next finance year  -- 2015-04-20 James Roodt: Changed financial year to payroll year  -- 2015-04-20 James Roodt: Removed RepeateEveryYear as it is not used  -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CarryForwardCostCenterEntries]     AS  BEGIN   SET NOCOUNT ON;         DECLARE @ActivePY NVARCHAR(10)   Select @ActivePY = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'     DECLARE @tbl TABLE   (    PyDate DATETIME,    ActPYear NVARCHAR(10)   )     INSERT INTO @tbl (PyDate, ActPYear)   Select PeriodEndDate, @ActivePY FROM dbo.Payroll_CyclePeriodDetails WHERE    TaxYear = @ActivePY AND CycleID = 1     --Select * FROM @tbl     DECLARE @tbl1 TABLE   (    PayrollDefinitionID INT,     EmployeeID INT,     Amount DECIMAL(18,2),    DESCRIPTION NVARCHAR(MAX),     MunicipalityID INT,    ENABLE BIT   )      INSERT INTO @tbl1    ( PayrollDefinitionID , EmployeeID , Amount , DESCRIPTION , MunicipalityID, ENABLE )       SELECT     PCEM.PayrollDefinitionID, PCEM.EmployeeID, PCEM.Amount, PCEM.Description, PCEM.MunicipalityID, 1   FROM Payroll_CostCenter_EveryMonth AS PCEM     INNER JOIN Payroll_EmployeePayrollDefinition AS PEPD ON PCEM.PayrollDefinitionID = PEPD.EmployeePayrollDefinition_ID   WHERE PEPD.Enabled = 1 --AND RepeateEveryYear = 1     Select * FROM @tbl1     INSERT INTO dbo.Payroll_CostCenter           ( PayrollDefinationID , EmployeeID , CostAmount , CostDesc , EntryDate , MunicipalityID ,             TaxYear , Enabled , DateCaptured, CapturerID           )   Select     [@tbl1].PayrollDefinitionID, [@tbl1].EmployeeID, [@tbl1].Amount, [@tbl1].DESCRIPTION,     [@tbl].PyDate, [@tbl1].MunicipalityID, [@tbl].ActPYear, [@tbl1].ENABLE, GETDATE() , 1   FROM @tbl, @tbl1       END  

GO

-- ============================================
-- SP: Payroll_CheckDivisionIsEnabled_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Author,,SR>  -- Create date: <Create Date,,08 July 2016>  -- Description: <Description,,>  -- Call SP    : Payroll_CheckDivisionIsEnabled_sp  -- 2016-05-31 TP39812 Seipei Mathole  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckDivisionIsEnabled_sp]    @CycleID INT     AS  BEGIN         SELECT emp.Employee_ID, div.DivisionDesc      FROM payroll_employee as emp     INNER JOIN Payroll_Position as PP ON PP.Position_ID = emp.PositionID  --Inner join on jobprofile as it has it's own validation test     INNER JOIN Const_Division as div on div.Division_ID = PP.DivisionID   --Inner join on division as it has it's own validation test      WHERE  emp.CycleID = @CycleID   AND div.Enabled = 0   AND emp.IsDummy = 0     END    

GO

-- ============================================
-- SP: Payroll_CheckEmployeeDefintionGroupConfigured_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Employees with no Group Definitions Assigned  */  create procedure [Payroll_CheckEmployeeDefintionGroupConfigured_sp] @CycleID int  as    begin     set nocount on;     declare @PeriodID int = (select top 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [CycleID] = @CycleID and [CycleModeID] = 1))     select distinct [dbo].[BufferString_fxn](convert(nvarchar(10), [Employee_ID]), 8, '0') as [EmpNo], [Employee_ID], isnull([EmpCode], '') as [EmpCode], [IdNo], [Surname], [FirstName], [PassportNumber], [PE].[Enabled], [EmailAddress], [CellNumber], [HomeNumber], [JoiningDate], [PE].[EndDate]      from [Payroll_Employee] as [PE] with(nolock)      where (not [Employee_ID] in(       select [Employee_ID]        from [Payroll_Employee] as [PE] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeeID] = [Employee_ID] and [EPD].[Enabled] = 1        where ([IsDummy] = 0)       )      )     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_CheckEmployeeNotLinkedToJobProfile_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Author,Seipei Mathole>  -- Create date: <Create Date,,2 June 2016>  -- Description: <Description,,>  -- Call SP    : [Payroll_CheckEmployeeNotLinkedToJobProfile_sp] 2576   -- 2016-06-02 TP37849  Validating Payroll_CheckEmployeeNotLinkedToJobProfile_sp  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckEmployeeNotLinkedToJobProfile_sp]    @CycleID INT    AS    BEGIN       SELECT emp.Employee_ID,PP.JobProfileID     FROM Payroll_Employee as emp   INNER JOIN Payroll_Position PP on PP.Position_ID= emp.PositionID     WHERE emp.Enabled = 1     AND emp.CycleID = @CycleID     AND emp.IsDummy = 0     AND PP.JobProfileID IS NULL      END    

GO

-- ============================================
-- SP: Payroll_CheckEmployeeOverTimeFlage_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL   -- Create date:  23 JUL 2013  -- Description:  CHECK EMPLOYEE OVER TIME FLAG  -- CALLS : Payroll_CheckEmployeeOverTimeFlage_sp '06/02/2013',1  -- =============================================  create procedure [Payroll_CheckEmployeeOverTimeFlage_sp] @OverTimeDate datetime, @EmployeeId int  as  begin     DECLARE @FromDate DATETIME   DECLARE @ToDate DATETIME   DECLARE @OverTimeFlag BIT   DECLARE @STARTDAYS NVARCHAR(10)   DECLARE @ENDDAYS INT   SET @STARTDAYS =1   DECLARE @TotalNo int   DECLARE @DATENAME NVARCHAR(50)   DECLARE @Parameter_Definition NVARCHAR(max)   DECLARE @SQL NVARCHAR(max)      SET @DATENAME = DATENAME (DW,@OverTimeDate)      SET @Parameter_Definition = N' @rowCount_out nvarchar(50) OUTPUT '   SET @SQL = 'SELECT  @rowCount_out=COUNT(*) FROM Payroll_Employee WHERE  ' + @DATENAME + ' = CAST(0 AS BIT) and '+@DATENAME + ' is not null and Employee_ID ='+ convert (nvarchar,@EmployeeId) + ' '   EXEC SP_EXECUTESQL @SQL, @Parameter_Definition, @rowCount_out=@TotalNo Output       IF(@TotalNo >0)    BEGIN    SET @OverTimeFlag = 1    END   ELSE IF((SELECT COUNT(HOLIDAY_ID) FROM Const_holiday WHERE HOLIDAYDATE = CAST(@OverTimeDate AS DATETIME)) > 0)    BEGIN    SET @OverTimeFlag = 1    END   ELSE   BEGIN    SET @OverTimeFlag =0   END      SELECT @OverTimeFlag as OverTimeFlag      END  

GO

-- ============================================
-- SP: Payroll_CheckEmployeePositionNotLinkedToJobProfile_sp
-- Schema: dbo
-- ============================================
  -- =============================================================================  -- Author:  <Author,Seipei Mathole>  -- Create date: <Create Date,,2 June 2016>  -- Description: <Description,,>  -- Call SP    : [Payroll_CheckEmployeeNotLinkedToJobProfile_sp] 2576   -- 2016-06-02 TP37849  Validating Payroll_CheckEmployeeNotLinkedToJobProfile_sp  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckEmployeePositionNotLinkedToJobProfile_sp]    @CycleID INT    AS    BEGIN       SELECT emp.Employee_ID,emp.PositionID     FROM Payroll_Employee as emp   INNER JOIN Payroll_Position PP on PP.Position_ID= emp.PositionID     WHERE emp.Enabled = 1     AND emp.CycleID = @CycleID     AND emp.IsDummy = 0     AND PP.JobProfileID IS NULL      END    

GO

-- ============================================
-- SP: Payroll_CheckEmployeesalaryHeadsonPeriod_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author  :Varun Parvataneni  -- Create date :27/08/2016  -- Description :Returns the salaryheads on adhoc period ID  -- Calls  : Payroll_CheckEmployeesalaryHeadsonPeriod_sp 1539  -- Update date : 15/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_CheckEmployeesalaryHeadsonPeriod_sp]   @PeriodID INT  AS  BEGIN   SELECT DISTINCT Def.SalaryHeadID as PayrollSalaryHeadID,(SalaryHeadTitle+'-'+IRP.IRP5Code) as SalaryHeadData   FROM   dbo.Payroll_CyclePeriodAdhocSalaryHead AS Def                                      INNER JOIN dbo.Payroll_SalaryHead AS Head ON Def.SalaryHeadID = Head.SalaryHead_ID           INNER JOIN dbo.Payroll_IRP5Code AS IRP ON Head.IRP5CodeId = IRP.IRP5Code_ID           WHERE PeriodID = @PeriodID AND Def.Enabled = 1 GROUP BY Def.SalaryHeadID,SalaryHeadTitle,IRP.IRP5Code    END  

GO

-- ============================================
-- SP: Payroll_CheckEmployeeScoaItemsNotConfiguredForCurrentFinancialYear_Trial_sp
-- Schema: dbo
-- ============================================
-- ==================================================================================================================================  -- Author: Varun Parvataneni  -- Create date: 21 JULY 2016  -- Description: Check is there any ScoaItemsNotConfiguredForCurrentFinancialYear when doing Trail Run  -- Calls : Payroll_CheckEmployeeScoaItemsNotConfiguredForCurrentFinancialYear_Trial_sp 0,'2015/2016'  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- ===================================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CheckEmployeeScoaItemsNotConfiguredForCurrentFinancialYear_Trial_sp]   @EmployeeID INT,   @ActiveFinYear NVARCHAR(10)    AS  BEGIN    select Distinct CSS.ScoaCode  from Payroll_EmployeeTrialPayslip ETP  join Payroll_EmployeePayrollDefinition EPD on ETP.PayrollDefinationID =EPD.EmployeePayrollDefinition_ID  join Payroll_Employee Emp on EPD.EmployeeID = Emp.Employee_ID  join Payroll_SalaryHead SH on EPD.PayrollSalaryHeadID =SH.PayrollSalaryHead_ID  join Payroll_Position PP on Emp.PositionID=PP.Position_ID  join Payroll_JobProfile PSG on PP.JobProfileID=PSG.JobProfile_ID  join Const_Department Dep on PP.DepartmentID = Dep.Department_ID  join Const_Division Div on PP.DivisionID = Div.Division_ID  join Const_SCOA_Structure CSS on EPD.SCOAItemID = CSS.ScoaID  join Const_SCOA_Costing_Structure CSCS on EPD.SCOACostingID = CSCS.ScoaID  join Const_SCOA_Project_Structure CSPS on EPD.SCOAProjectID = CSPS.ScoaID  join Const_SCOA_Regional_Structure CSRS on EPD.SCOARegionID = CSRS.ScoaID  join Const_SCOA_Funds_Structure CSFundS on EPD.SCOAFundsID = CSFundS.ScoaID  join Const_SCOA_Function_Structure CSFS on EPD.FunctionCodeID = CSFS.ScoaID  where (Emp.Employee_ID = @EmployeeID or @EmployeeID = 0)        AND Dep.Enabled = 1 AND Div.Enabled = 1 AND Emp.Enabled = 1 AND EPD.Enabled = 1 AND PSG.Enabled = 1 AND SH.Enabled = 1        AND CSS.ScoaID NOT IN(Select lv.SCOAItemID from Led_Vote lv where lv.FinYear = @ActiveFinYear)    END    

GO

-- ============================================
-- SP: Payroll_CheckEmployeeWithDuplicateBankAccount
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,11 Sep 2014>  -- Description: <Description,,Check employee with same id no>  -- Call SP    : Payroll_CheckEmployeeWithDuplicateBankAccount 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckEmployeeWithDuplicateBankAccount] @CycleId INT  AS   BEGIN    DECLARE @AccountHolderRelationship_Joint INT = 2    SELECT       dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (Emp.Employee_ID)), 8,'0') AS EmpNo,      Emp.Surname,       Emp.FirstName,       Emp.Employee_ID,       Emp.IdNo,       Emp.EmailAddress,       Emp.CellNumber,       Emp.HomeNumber,       Emp.FaxNumber,       Emp.AccountNumber  FROM dbo.Payroll_Employee AS Emp  INNER JOIN (      SELECT AccountNumber      FROM dbo.Payroll_Employee      GROUP BY AccountNumber      HAVING COUNT(*) > 1  ) AS E ON Emp.AccountNumber = E.AccountNumber  WHERE Emp.IsDummy = 0      AND (Emp.CycleID = @CycleId OR @CycleId = 0)      AND Emp.Enabled = 1      AND Emp.AccountNumber IS NOT NULL      AND Emp.AccountHolderRelationshipID <> @AccountHolderRelationship_Joint      AND E.AccountNumber <> 'NA'      AND E.AccountNumber <> ''    END

GO

-- ============================================
-- SP: Payroll_CheckEmployeeWithDuplicateId
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,11 Sep 2014>  -- Description: <Description,,Check employee with same id no>  -- Call SP    : Payroll_CheckEmployeeWithDuplicateId 1  -- 2015-04-22 James Roodt: Only check for enabled employees  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckEmployeeWithDuplicateId] @CycleId INT  AS       BEGIN          SELECT  dbo.BufferString_fxn(CONVERT(NVARCHAR(10), ( Emp.Employee_ID )), 8, '0') AS EmpNo,Isnull(Emp.EmpCode,'') EmpCode, Emp.Surname, Emp.FirstName, Emp.Employee_ID, Emp.IdNo, Emp.EmailAddress, Emp.CellNumber, Emp.HomeNumber, Emp.FaxNumber          FROM    dbo.Payroll_Employee AS Emp                  INNER JOIN ( SELECT IdNo                               FROM   dbo.Payroll_Employee          WHERE Enabled = 1                               GROUP BY IdNo                               HAVING COUNT(*) > 1                             ) AS E ON Emp.IdNo = E.IdNo          WHERE   Emp.IsDummy = 0                  AND ( Emp.CycleID = @CycleId                        OR @CycleId = 0                      )                  AND Emp.Enabled = 1                  AND E.IdNo <> 'NA'      END  

GO

-- ============================================
-- SP: Payroll_CheckEmployeeWithDuplicateVendorBankAccount
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,02 Feb 2016>  -- Description: <Description,,Check employee account number with vendor account number>  -- Call SP    : Payroll_CheckEmployeeWithDuplicateVendorBankAccount 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckEmployeeWithDuplicateVendorBankAccount] @CycleId INT  AS       BEGIN           SELECT DISTINCT dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (Emp.Employee_ID)), 8,'0') AS EmpNo,  Emp.Surname, Emp.FirstName, Emp.Employee_ID, Emp.IdNo, Emp.EmailAddress, Emp.CellNumber, Emp.HomeNumber, Emp.FaxNumber, Emp.AccountNumber,E.Vendor_ID,E.VendorName          FROM    dbo.Payroll_Employee AS Emp                  CROSS APPLY (SELECT TOP 1 * FROM Cons_vendor where Emp.AccountNumber = BankAccountNumber) E          WHERE   (Emp.CycleID = @CycleId OR @CycleId = 0)                  AND Emp.AccountNumber <> 'NA'                  AND Emp.AccountNumber <> ''      AND EMP.IsDummy = 0      END  

GO

-- ============================================
-- SP: Payroll_CheckHRPayrollSCOAFunction_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,31 May 2016>  -- Description: <Description,,>  -- Call SP    : Payroll_CheckHRPayrollSCOAFunction_sp  -- 2016-05-31 TP37377 Seipei Mathole: Validating HRPayrollSCOAFunctionID  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckHRPayrollSCOAFunction_sp]    @CycleID INT     AS  BEGIN       SELECT emp.Employee_ID, div.DivisionDesc      FROM payroll_employee as emp     INNER JOIN Payroll_Position as pp ON pp.Position_ID=emp.PositionID  --Inner join on jobprofile as it has it's own validation test     INNER JOIN Const_Division as div on div.Division_ID=pp.DivisionID and div.Enabled=1  --Inner join on division as it has it's own validation test      WHERE emp.Enabled=1      AND emp.CycleID=@CycleID   AND emp.IsDummy = 0   AND div.SCOAFunctionID is null     END    

GO

