-- =============================================================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,31 May 2016>  -- Description: <Description,,>  -- Call SP    : Payroll_CheckHRPayrollSCOAFund_sp  -- 2016-05-31 TP37377 Seipei Mathole: Validating HRPayrollSCOAFundID  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckHRPayrollSCOAFund_sp]  @CycleID INT  AS  BEGIN       SELECT emp.Employee_ID, div.DivisionDesc   FROM payroll_employee as emp  --  select emp.Employee_ID, div.DivisionDesc from payroll_employee as emp   INNER JOIN Payroll_Position as pp ON pp.Position_ID=emp.PositionID  --Inner join on jobprofile as it has it's own validation test   INNER JOIN Const_Division as div on div.Division_ID=pp.DivisionID and div.Enabled=1  --Inner join on division as it has it's own validation test   WHERE emp.Enabled = 1   AND emp.CycleID = @CycleID   AND EMP.IsDummy = 0   AND div.HRPayrollSCOAFundID is null    --and div.SCOAFunctionID is null  END    

GO

-- ============================================
-- SP: Payroll_CheckInvalidHRPayrollSCOAFunction_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Author,,SR>  -- Create date: <Create Date,,08 July 2016>  -- Description: <Description,,>  -- Call SP    : Payroll_CheckInvalidHRPayrollSCOAFunction_sp  -- 2016-05-31 TP39812 Seipei Mathole: Invalid HRPayrollSCOAFunctionID  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckInvalidHRPayrollSCOAFunction_sp]    @CycleID INT     AS  BEGIN         SELECT emp.Employee_ID, div.DivisionDesc      FROM payroll_employee as emp     INNER JOIN Payroll_Position as pp ON pp.Position_ID=emp.PositionID  --Inner join on jobprofile as it has it's own validation test     INNER JOIN Const_Division as div on div.Division_ID=pp.DivisionID and div.Enabled=1  --Inner join on division as it has it's own validation test      WHERE emp.Enabled=1      AND emp.CycleID = @CycleID   AND emp.IsDummy = 0   AND div.SCOAFunctionID NOT IN (Select ScoaID from Const_SCOA_Function_Structure)   AND div.SCOAFunctionID IS NOT NULL     END    

