-- ============================================
-- SP: Payroll_CheckJobProfileNotLinkedToDivision_sp
-- Schema: dbo
-- ============================================
  -- =============================================================================  -- Author:  <Author,Seipei Mathole>  -- Create date: <Create Date,,2 June 2016>  -- Description: <Description,,>  -- Call SP    : [Payroll_CheckJobProfileNotLinkedToDivision_sp] 4   -- 2016-06-02 TP37490  Validating Payroll_CheckJobProfileNotLinkedToDivision_sp  -- 2016-09-01 TP43798  PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- we are replacing jobprofile with positions so check the positions not linked to division  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckJobProfileNotLinkedToDivision_sp]    @CycleID INT    AS    BEGIN       SELECT emp.Employee_ID ,PJ.JobTitle as  JobTitle     FROM Payroll_Position as pp     INNER JOIN Payroll_JobProfile as PJ ON PJ.JobProfile_ID = pp.JobProfileID      INNER JOIN Payroll_Employee as emp ON emp.PositionID = pp.Position_ID        WHERE emp.Enabled = 1 AND IsDummy = 0       AND emp.CycleID = @CycleID       AND pp.DivisionID IS NULL     END    

GO

-- ============================================
-- SP: Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncode_sp
-- Schema: dbo
-- ============================================
  -- =====================================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Check that all Jobprofiles used by the enabled employees belonging to the selected payroll cycle have an enabled Primary Function code  -- Call: [Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncode_sp]  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncode_sp]      @CycleID INT  AS    BEGIN      SELECT P_E.Employee_ID, P_E.EmpCode, P_JP.JobProfile_ID, C_D.SCOAFunctionID     FROM Payroll_Employee P_E    LEFT OUTER JOIN Payroll_Position PP ON P_E.PositionID = PP.Position_ID    LEFT OUTER JOIN Payroll_JobProfile P_JP ON PP.JobProfileID = P_JP.JobProfile_ID    LEFT OUTER JOIN Const_Division C_D ON PP.DivisionID = C_D.Division_ID    WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND C_D.SCOAFunctionID IS NULL AND P_E.IsDummy = 0      --SELECT P_E.Employee_ID, P_E.EmpCode, pp.Position_ID , C_D.SCOAFunctionID     --FROM Payroll_Employee P_E    --LEFT OUTER JOIN Payroll_Position PP ON P_E.PositionID = PP.Position_ID    --LEFT OUTER JOIN Const_Division C_D ON PP.DivisionID = C_D.Division_ID    --WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND C_D.SCOAFunctionID IS NULL AND P_E.IsDummy = 0        END    

GO

-- ============================================
-- SP: Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncodeWhichTotals100_sp
-- Schema: dbo
-- ============================================
  -- =====================================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Check that all Jobprofiles used by the enabled employees belonging to the selected payroll cycle   --    have Primary & secondary Function code entries which totals 100%.  -- Call: [Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncodeWhichTotals100_sp] 1  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncodeWhichTotals100_sp]       @CycleID INT  AS    BEGIN      --SELECT Employee_ID, EmpCode, JobProfileID, SUM(Percentage) TotalPercentage    --FROM    --(    -- SELECT P_E.Employee_ID, P_E.EmpCode, P_JP.JobProfile_ID AS JobProfileID, P_JP.PercentageForCostingAllocationToSCOAFunction AS Percentage    -- FROM Payroll_Employee P_E    -- LEFT OUTER JOIN Payroll_JobProfile P_JP ON P_E.JobProfileID = P_JP.JobProfile_ID    -- LEFT OUTER JOIN Const_Division C_D ON P_JP.DivisionID = C_D.Division_ID    -- WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND P_JP.Enabled = 1 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL         -- UNION ALL      -- SELECT P_E.Employee_ID, P_E.EmpCode, P_JPED.JobProfileID, P_JPED.CostPercentage AS Percentage    -- FROM Payroll_Employee P_E    -- LEFT OUTER JOIN Payroll_JobProfileExtraDivisionFunctionCode P_JPED ON P_E.JobProfileID = P_JPED.JobProfileID    -- LEFT OUTER JOIN Const_Division C_D ON P_JPED.DivisionID = C_D.Division_ID    -- WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND P_JPED.Enabled = 1 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL      --) temp    --GROUP BY Employee_ID, EmpCode, JobProfileID    --HAVING SUM(Percentage) != 100.00      SELECT Employee_ID, EmpCode, JobProfileID, SUM(Percentage) TotalPercentage    FROM    (     SELECT P_E.Employee_ID, P_E.EmpCode, PP.Position_ID AS JobProfileID, PP.Capacity AS Percentage     FROM Payroll_Employee P_E     LEFT OUTER JOIN Payroll_Position PP ON P_E.PositionID = PP.Position_ID     LEFT OUTER JOIN Const_Division C_D ON PP.DivisionID = C_D.Division_ID     WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL          UNION ALL       SELECT P_E.Employee_ID, P_E.EmpCode, P_JPED.JobProfileID, P_JPED.CostPercentage AS Percentage     FROM Payroll_Employee P_E     LEFT OUTER JOIN Payroll_Position PP ON P_E.PositionID = PP.Position_ID     LEFT OUTER JOIN Payroll_JobProfileExtraDivisionFunctionCode P_JPED ON PP.Position_Id = P_JPED.PositionId     LEFT OUTER JOIN Const_Division C_D ON P_JPED.DivisionID = C_D.Division_ID     WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND P_JPED.Enabled = 1 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL      ) temp    GROUP BY Employee_ID, EmpCode, JobProfileID    HAVING SUM(Percentage) != 100.00        END    

GO

-- ============================================
-- SP: Payroll_CheckNegativeLeaveBalance
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,11 Sep 2014>  -- Description: <Description,,Check negative leave balance>  -- Call SP    : Payroll_CheckNegativeLeaveBalance 1  -- 2015-05-29 James Roodt: Added check to only check employees with negative leave that actually belongs to the provided cycle.  -- 2016-05-04 Ravindra: Added ActivePayrollYear filter to get current period.  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckNegativeLeaveBalance]    @CycleID INT  AS       BEGIN    DECLARE @TaxYear NVARCHAR(10),    @TaxYearStartDate DATETIME,    @TaxYearEndDate DATETIME      SELECT  @TaxYear = KEYVALUE              FROM    AAAA_ConfigSettings              WHERE   KeyName = 'TaxYear'         SELECT TOP 1 @TaxYearStartDate = MIN(PeriodStartDate), @TaxYearEndDate = MAX(PeriodEndDate) from Payroll_CyclePeriodDetails where FinancialYear = @TaxYear --ORDER BY PeriodInTaxYear ASC                DECLARE @EndDate DATETIME          SELECT TOP 1                  @EndDate = PeriodEndDate          FROM    dbo.Payroll_CyclePeriodDetails          WHERE   CycleID = @CycleID                  AND Processed = 0                  AND ProcessedDate IS NULL AND CycleModeID = 1 AND TaxYear = @TaxYear                    SELECT R.Leavebalance, dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (Emp.Employee_ID)), 8,'0') AS EmpNo, Emp.Surname, Emp.FirstName, Emp.Employee_ID, Emp.IdNo, Emp.EmailAddress, Emp.CellNumber, Emp.HomeNumber, Emp.FaxNumber          FROM    dbo.Payroll_Employee AS Emp                  INNER JOIN ( SELECT SUM(AccrualLeave - TakenLeave - EncashLeave + AdjustedLeave) AS Leavebalance, EmployeeId                               FROM   dbo.Payroll_EmployeeLeaveSchemeTransaction                                     WHERE TranDate BETWEEN @TaxYearStartDate  AND @TaxYearEndDate AND LeaveTypeId <> 6                               GROUP BY EmployeeId, LeaveTypeId                             ) AS R ON Emp.Employee_ID = R.EmployeeId          WHERE   R.Leavebalance < 0      AND Emp.CycleID = @CycleID      AND Emp.IsDummy = 0                 END      

GO

-- ============================================
-- SP: Payroll_CheckNegativeNettSalary_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 13/12/2017   Description : Gets the Employees with a Negative Nett Salary  */  create procedure [Payroll_CheckNegativeNettSalary_sp] @PeriodID int  as     begin        select  [Employee_ID], [dbo].[BufferString_fxn](convert(nvarchar(10), ([Employee_ID])), 8, '0') as [EmpNo], [Surname], [FirstName], [IdNo], [EmailAddress], [CellNumber], [HomeNumber], [FaxNumber]      from [Payroll_Employee] as [PE] with(nolock)       join (select [EPD].[EmployeeID], sum((case IRP5.TransactionTypeID        when 1 then [Amount]        else [Amount] * -1        end)) as [Amount]         from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)          join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ETP].[EmployeeID]         where ([PeriodID] = @PeriodID and [IRP5].[TransactionTypeID] in(1, 2) and [TaxSavePurpose] = 0)          group by [EPD].[EmployeeID]        ) as [TRA] on [EmployeeID] = [Employee_ID]        where ([Amount] < 0)      order by [Employee_ID]    end  

GO

-- ============================================
-- SP: Payroll_CheckPositionHaveEnabledPrimaryFunctioncode_sp
-- Schema: dbo
-- ============================================
    -- =====================================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Check that all Positions used by the enabled employees belonging to the selected payroll cycle have an enabled Primary Function code  -- Call: [[Payroll_CheckPositionHaveEnabledPrimaryFunctioncode_sp]]  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CheckPositionHaveEnabledPrimaryFunctioncode_sp]      @CycleID INT  AS    BEGIN      SELECT P_E.Employee_ID, P_E.EmpCode, P_E.PositionID,pp.DivisionID, C_D.SCOAFunctionID     FROM Payroll_Employee P_E    LEFT OUTER JOIN Payroll_Position PP ON P_E.PositionID = PP.Position_ID    LEFT OUTER JOIN Payroll_JobProfile P_JP ON PP.JobProfileID = P_JP.JobProfile_ID    LEFT OUTER JOIN Const_Division C_D ON PP.DivisionID = C_D.Division_ID    WHERE P_E.Enabled = 1 AND P_E.CycleID = @CycleID AND C_D.SCOAFunctionID IS NULL AND P_E.IsDummy = 0        END    

GO

-- ============================================
-- SP: Payroll_CheckPositionHaveEnabledPrimaryFunctioncodeWhichTotals100_sp
-- Schema: dbo
-- ============================================
-- =====================================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Check that all Jobprofiles used by the enabled employees belonging to the selected payroll cycle   --    have Primary & secondary Function code entries which totals 100%.  -- Call: [Payroll_CheckJobProfilesHaveEnabledPrimaryFunctioncodeWhichTotals100_sp]  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CheckPositionHaveEnabledPrimaryFunctioncodeWhichTotals100_sp]      @CycleID INT, @PeriodID INT  AS    BEGIN      SELECT  Employee_ID, EmpCode, PositionID, SUM(Percentage) TotalPercentage    FROM    (     SELECT P_E.Employee_ID, P_E.EmpCode, PP.Position_ID AS PositionID, PP.Capacity AS Percentage     FROM Payroll_Employee P_E with(nolock)     INNER JOIN Payroll_Position PP with(nolock) ON P_E.PositionID = PP.Position_ID     INNER JOIN Const_Division C_D with(nolock) ON PP.DivisionID = C_D.Division_ID     INNER JOIN Payroll_CyclePeriodDetails as CPD with(nolock) ON CPD.Period_ID = @PeriodID     WHERE P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL                  AND(CAST(P_E.JoiningDate AS DATE) <= CAST(CPD.PeriodEndDate AS DATE))                  AND(CAST(P_E.EndDate AS DATE) >= CAST(CPD.PeriodStartDate AS DATE))                  AND NOT (P_E.Enabled = 0 AND P_E.EndDate = '9999-12-31')         UNION ALL       SELECT P_E.Employee_ID, P_E.EmpCode, PP.Position_ID AS PositionID, P_JPED.CostPercentage AS Percentage     FROM Payroll_Employee P_E with(nolock)     INNER JOIN Payroll_Position PP with(nolock) ON P_E.PositionID = PP.Position_ID     INNER JOIN Payroll_JobProfileExtraDivisionFunctionCode P_JPED with(nolock) ON PP.Position_ID = P_JPED.PositionId     INNER JOIN Const_Division C_D with(nolock) ON P_JPED.DivisionID = C_D.Division_ID     INNER JOIN Payroll_CyclePeriodDetails as CPD with(nolock) ON CPD.Period_ID = @PeriodID     WHERE P_E.CycleID = @CycleID AND P_E.CycleID = @CycleID AND P_E.IsDummy = 0 AND P_JPED.Enabled = 1 AND C_D.Enabled = 1 AND C_D.SCOAFunctionID IS NOT NULL                  AND(CAST(P_E.JoiningDate AS DATE) <= CAST(CPD.PeriodEndDate AS DATE))                  AND(CAST(P_E.EndDate AS DATE) >= CAST(CPD.PeriodStartDate AS DATE))                  AND NOT (P_E.Enabled = 0 AND P_E.EndDate = '9999-12-31')      ) temp    GROUP BY Employee_ID, EmpCode, PositionID    HAVING SUM(Percentage) != 100.00        END    

GO

-- ============================================
-- SP: Payroll_CheckPositionsNotLinkedToDivision_sp
-- Schema: dbo
-- ============================================
    -- =============================================================================  -- Author:  <Author,Seipei Mathole>  -- Create date: <Create Date,,2 June 2016>  -- Description: <Description,,>  -- Call SP    : [Payroll_CheckPositionsNotLinkedToDivision_sp] 4   -- 2016-06-02 TP37490  Validating Payroll_CheckJobProfileNotLinkedToDivision_sp  -- 2016-09-01 TP43798  PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- we are replacing jobprofile with positions so check the positions not linked to division  -- =============================================================================    CREATE PROCEDURE [dbo].[Payroll_CheckPositionsNotLinkedToDivision_sp]    @CycleID INT    AS    BEGIN       SELECT emp.Employee_ID ,emp.PositionID,pp.PositionDesc     FROM Payroll_Position as pp     INNER JOIN Payroll_JobProfile as PJ ON PJ.JobProfile_ID = pp.JobProfileID      INNER JOIN Payroll_Employee as emp ON emp.PositionID = pp.Position_ID        WHERE emp.Enabled = 1 AND IsDummy = 0       AND emp.CycleID = @CycleID       AND pp.DivisionID IS NULL     END    

GO

-- ============================================
-- SP: Payroll_CheckTrialLockDownForPayslipByEmpIdAndPeriodId_sp
-- Schema: dbo
-- ============================================
 -- Aurthor : Phuti Chokoe   -- Description : Check if employee belows to the current trial run cycle and if that cycle is in lock down(waiting for approval)   -- TP43097   -- 2016-08-16   --[Payroll_CheckTrialLockDownForPayslipByEmpIdAndPeriodId_sp] 5,2593   -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  CREATE proc [dbo].[Payroll_CheckTrialLockDownForPayslipByEmpIdAndPeriodId_sp]    @EmpID INT ,    @PeriodId INt     as  BEGIN    DECLARE @NormalCycleLockedDown bit,   @NormalCyclePeriodInTaxYear int,   @NormalPeriodID int,   @AdhocCycleLockedDownCount int,   @AdhocCycleLockedDown bit,   @TaxYear NVARCHAR(9),   @CycleID int,   @Locked bit,   @isAdhoc bit,   @cycleMode int    SELECT @CycleID=CycleID FROM Payroll_employee WHERE Employee_ID=@EmpID  select @cycleMode=CycleModeID from Payroll_CyclePeriodDetails where Period_ID = @PeriodId   SELECT @TaxYear=KeyValue FROM AAAA_Configsettings WHERE KeyName='TaxYear'    if(@cycleMode =1)  BEGIN --First we get the normal cycle and see of it is in lockdown         SELECT top 1 @NormalPeriodID=Period_ID, @NormalCyclePeriodInTaxYear=periodintaxyear, @NormalCycleLockedDown=LockedDown FROM payroll_cycleperioddetails AS pd      inner join Payroll_Employee as emp on emp.Employee_ID = @EmpID         WHERE 1=1         AND pd.CycleID=@CycleID         AND TaxYear=@TaxYear         AND CycleModeID=1         AND processed=0         ORDER BY PeriodInTaxYear  END      if(@cycleMode = 2)  BEGIN --Then we look at the adhocs and see of any of them are in lockdown        set @AdhocCycleLockedDownCount  = 0     set @AdhocCycleLockedDownCount = (select count(*) from Payroll_CyclePeriodAdhocEmployee adhoc    inner join payroll_cycleperioddetails as cd on cd.Period_ID = adhoc.PeriodID    where adhoc.EmployeeID = @EmpID    and cd.LockedDown = 1 and CycleModeID = 2 and CycleID = @CycleID and Period_ID = @PeriodId)           IF @AdhocCycleLockedDownCount>0         BEGIN           SELECT @AdhocCycleLockedDown=1         END  END    IF @NormalCycleLockedDown=1 OR @AdhocCycleLockedDown=1   set @Locked = 1   ELSE   set @Locked = 0      select @Locked as LockedDown    END  

GO

-- ============================================
-- SP: Payroll_CheckTrialLockDownStatusByempID_sp
-- Schema: dbo
-- ============================================
 -- Aurthor : Phuti Chokoe   -- Description : Check if employee belows to the current trial run cycle and if that cycle is in lock down(waiting for approval)   -- TP43097   -- 2016-08-16   --[Payroll_checkTrialLockDownStatus] 5   -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear   -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  CREATE PROC [dbo].[Payroll_CheckTrialLockDownStatusByempID_sp]    @EmpID INT     AS  BEGIN    DECLARE @NormalCycleLockedDown bit,   @NormalCyclePeriodInTaxYear int,   @NormalPeriodID int,   @AdhocCycleLockedDownCount int,   @AdhocCycleLockedDown bit,   @TaxYear NVARCHAR(9),   @CycleID int,   @Locked bit    SELECT @CycleID=CycleID FROM Payroll_employee WHERE Employee_ID=@EmpID    SELECT @TaxYear=KeyValue FROM AAAA_Configsettings WHERE KeyName='TaxYear'    BEGIN --First we get the normal cycle and see of it is in lockdown         SELECT top 1 @NormalPeriodID=Period_ID, @NormalCyclePeriodInTaxYear=periodintaxyear, @NormalCycleLockedDown=LockedDown FROM payroll_cycleperioddetails AS pd         WHERE 1=1         AND cycleid=@CycleID         AND TaxYear=@TaxYear         AND cyclemodeid=1         AND processed=0         ORDER BY PeriodInTaxYear  END    BEGIN --Then we look at the adhocs and see of any of them are in lockdown         SELECT @AdhocCycleLockedDown=0         SELECT @AdhocCycleLockedDownCount= count( Period_ID) FROM Payroll_CyclePeriodDetails         WHERE 1=1         AND cycleid=@CycleID         AND TaxYear=@TaxYear         AND cyclemodeid=2          AND PeriodInTaxYear=@NormalCyclePeriodInTaxYear         AND LockedDown=1      AND Processed = 0           IF @AdhocCycleLockedDownCount>0         BEGIN           SELECT @AdhocCycleLockedDown=1         END  END    IF @NormalCycleLockedDown=1 OR @AdhocCycleLockedDown=1   set @Locked = 1   ELSE   set @Locked = 0      select @Locked as LockedDown    END

GO

-- ============================================
-- SP: Payroll_CheckTrialLockDownStatusByPayrollCycleID_sp
-- Schema: dbo
-- ============================================
 -- Aurthor : Phuti Chokoe   -- Description : Check if employee belows to the current trial run cycle and if that cycle is in lock down(waiting for approval)   -- TP43097   -- 2016-08-16   --[Payroll_CheckTrialLockDownStatusByPayrollCycleID_sp] 1   -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  CREATE PROC [dbo].[Payroll_CheckTrialLockDownStatusByPayrollCycleID_sp]    @CycleID INT     AS  BEGIN    DECLARE @NormalCycleLockedDown bit,   @NormalCyclePeriodInTaxYear int,   @NormalPeriodID int,   @AdhocCycleLockedDownCount int,   @AdhocCycleLockedDown bit,   @TaxYear NVARCHAR(9),   @Locked bit    SELECT @TaxYear=KeyValue FROM AAAA_Configsettings WHERE KeyName='TaxYear'         BEGIN --First we get the normal cycle and see of it is in lockdown            SELECT top 1 @NormalPeriodID=Period_ID, @NormalCyclePeriodInTaxYear=periodintaxyear,@NormalCycleLockedDown=LockedDown FROM payroll_cycleperioddetails AS pd            WHERE 1=1            AND cycleid=@CycleID            AND TaxYear=@TaxYear            AND cyclemodeid=1            AND processed=0            ORDER BY PeriodInTaxYear       END         BEGIN --Then we look at the adhocs and see of any of them are in lockdown           SELECT @AdhocCycleLockedDown=0           SELECT @AdhocCycleLockedDownCount= count( Period_ID) FROM Payroll_CyclePeriodDetails           WHERE 1=1           AND cycleid=@CycleID           AND TaxYear=@TaxYear           AND cyclemodeid=2            AND PeriodInTaxYear=@NormalCyclePeriodInTaxYear           AND LockedDown=1             IF @AdhocCycleLockedDownCount>0           BEGIN          SELECT @AdhocCycleLockedDown=1           END       END    IF @NormalCycleLockedDown=1 OR @AdhocCycleLockedDown=1   set @Locked = 1   ELSE   set @Locked = 0      select @Locked as LockedDown    END  

GO

-- ============================================
-- SP: Payroll_CheckTrialLockDownStatusByPayrollPeriodID_sp
-- Schema: dbo
-- ============================================
 -- Aurthor : Phuti Chokoe   -- Description : Check if employee belows to the current trial run cycle and if that cycle is in lock down(waiting for approval)   -- TP43097   -- 2016-08-16   --[Payroll_checkTrialLockDownStatus] 5   -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear   -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  CREATE PROC [dbo].[Payroll_CheckTrialLockDownStatusByPayrollPeriodID_sp]    @PeriodID INT     AS  BEGIN    DECLARE @NormalCycleLockedDown bit,   @AdhocCycleLockedDownCount int,   @AdhocCycleLockedDown bit,   @TaxYear NVARCHAR(9),   @Locked bit    SELECT @TaxYear=KeyValue FROM AAAA_Configsettings WHERE KeyName='TaxYear'         BEGIN --First we get the normal cycle and see of it is in lockdown           SELECT @AdhocCycleLockedDownCount= count(Period_ID) FROM payroll_cycleperioddetails AS pd           WHERE 1=1            AND TaxYear=@TaxYear            AND cyclemodeid in (1,2)            AND processed=0            AND Enabled = 1            AND Period_ID = @PeriodID            AND LockedDown = 1                          IF @AdhocCycleLockedDownCount>0            BEGIN           SELECT @AdhocCycleLockedDown=1          END       END    IF  @AdhocCycleLockedDown=1   set @Locked = 1   ELSE   set @Locked = 0      select @Locked as LockedDown    END  

GO

-- ============================================
-- SP: Payroll_CheckValidEmpCode_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author   : Varun Parvataneni    -- Create date: <Create Date,,24 june 2016>  -- Description: Return is there any duplicate matching with Empcode   -- Call SP    : Payroll_CheckValidEmpCode_sp 1.'0004'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckValidEmpCode_sp]   @EmployeeId INT,  @EmpCode nvarchar(100)   AS       BEGIN           SELECT EmpCode          FROM    dbo.Payroll_Employee AS Emp          WHERE   (Emp.Employee_ID <> @EmployeeId)      AND Emp.EmpCode =@EmpCode      END  

GO

-- ============================================
-- SP: Payroll_CheckVirtualCashierandReciptRange
-- Schema: dbo
-- ============================================
     -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,11 Sep 2014>  -- Description: <Description,,Check virtual cashier and its receipt rage exists or not>  -- Call SP    : Payroll_CheckVirtualCashierandReciptRange   -- Modified   :   -- 34989 Varun parvataneni for prompt message was replaced with the username   -- 39365 2016-07-05 James Roodt: Added spaces and the system financial year to the message      -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CheckVirtualCashierandReciptRange]  AS       BEGIN          DECLARE @UserID INT ,              @FinancialYear NVARCHAR(50)                    DECLARE @Result TABLE ( Id INT, Msg NVARCHAR(500) )                    SELECT  @FinancialYear = KeyValue          FROM    dbo.AAAA_ConfigSettings          WHERE   KeyName = 'ActiveFinYear'          IF EXISTS ( SELECT  *                      FROM    dbo.POS_Cashier                      WHERE   Id = -1 )               BEGIN                    SELECT  @UserID = User_Id                  FROM    dbo.POS_Cashier                  WHERE   Id = -1                      IF EXISTS ( SELECT  *                              FROM    dbo.Const_CashierReceiptRange                              WHERE   IsCompleted = 0                                      AND FinYear = @FinancialYear                                      AND User_Id = @UserID )                       BEGIN                          DECLARE @AvailableCount INT ,                              @RequiredCount INT ,                              @PeriodID INT                          SELECT  @AvailableCount = SUM(EndRange - CurrentRange + 1)                          FROM    dbo.Const_CashierReceiptRange                          WHERE   IsCompleted = 0                                  AND FinYear = @FinancialYear                                  AND User_Id = @UserID                                                                    SELECT TOP 1                                  @PeriodID = PeriodID                          FROM    dbo.Payroll_EmployeeTrialPayslip                                                            SELECT  @RequiredCount = COUNT(1)                          FROM    dbo.Payroll_EmployeeBillingPaymentDetails                          WHERE   PeriodID = @PeriodID                          GROUP BY EmployeeID, AccountID                                                            IF @RequiredCount > @AvailableCount                               BEGIN                                  INSERT  INTO @Result ( Id, Msg )                                  VALUES  ( 3, -- Id - int                                            N'The Receipt Range defined for Billing integration for the Virtual Cashier is not long enough. Please go to Settings-> Billing Settings -> Cashier Receipt Range and define a bigger range for the '+(SELECT usr.FirstName+' '+usr.LastName  FROM POS_Cashier AS cash           LEFT JOIN User_UserDetail AS usr ON usr.User_ID=@UserID           WHERE cash.ID=-1) +' Cashier for FinYear ' + @FinancialYear  -- Msg - nvarchar(500)                                            )                              END                                                    END                                   END          ELSE               BEGIN                  INSERT  INTO @Result ( Id, Msg )                  VALUES  ( 1, -- Id - int                            N'Virtual cashier does not exists'  -- Msg - nvarchar(500)                            )              END          SELECT  *          FROM    @Result      END

GO

-- ============================================
-- SP: Payroll_Claims_SearchList_sp
-- Schema: dbo
-- ============================================
-- Author  :   -- Create date :   -- Description : Generates Payroll Claims list     -- Exec Payroll_Claims_SearchList_sp 'Jon', 'Smit','7507115800085', 0    -- 16/02/2021 Modified by Ivan Myroshychenko - Remove modifying PayrollCyclePeriodDetails.PeriodStartDate from DateTime to NVARCHAR #49385      CREATE PROCEDURE [dbo].[Payroll_Claims_SearchList_sp]   @Name NVARCHAR(100),   @Surname NVARCHAR(100),   @IDNo NVARCHAR(30),   @Flag BIT  AS    BEGIN   SELECT    Min(PAY_EC.EmployeeClaims_ID) EmployeeClaims_ID,    P_E.IdNo,    P_E.Surname,    P_E.FirstName,    Sum(PAY_EC.CostAmount) AS CostAmount,    PAY_EC.FinancialYear,    PAY_EC.TaxYear,    MIN(PayrollCyclePeriodDetails.PeriodStartDate) AS EntryDate,    CC.Claim_Type AS Claim_Type,    dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,    isnull(P_E.EmpCode,'') EmpCode,    PayrollCyclePeriodDetails.PeriodInTaxYear,    PayrollCyclePeriodDetails.PeriodEndDate   FROM Payroll_EmployeeClaims AS PAY_EC    LEFT JOIN Payroll_Employee AS P_E ON PAY_EC.EmployeeID = P_E.Employee_ID    LEFT JOIN Const_Claims AS CC ON PAY_EC.ClaimID = CC.Claim_ID    LEFT JOIN Payroll_CyclePeriodDetails AS PayrollCyclePeriodDetails ON PayrollCyclePeriodDetails.Period_ID = PAY_EC.PeriodID   WHERE (P_E.FirstName = @Name or @Name='' ) and  (P_E.Surname = @Surname or @Surname='') and  (P_E.IdNo = @IDNo or @IDNo='')    AND PAY_EC.Enabled = 1   GROUP BY    P_E.IdNo,    PayrollCyclePeriodDetails.PeriodInTaxYear,    P_E.Surname,    P_E.FirstName,    P_E.Employee_ID,    PAY_EC.FinancialYear,    PAY_EC.TaxYear,    P_E.EmpCode,    PayrollCyclePeriodDetails.PeriodInTaxYear,    PayrollCyclePeriodDetails.PeriodEndDate,    PayrollCyclePeriodDetails.PeriodStartDate,    CC.Claim_Type   ORDER BY P_E.Employee_ID  END

GO

-- ============================================
-- SP: Payroll_ClearPayrollTrialRun_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create Date : 04/04/2017   Description : Clear TrialRun Values   Update Date : 20/04/2017 - added the EmployeeID parameter to only clear employee specific results   Update Date : 21/04/2017 - removed clearing the [Payroll_EmployeeTrialPayslip] values as this is done in code just before the TrialRun   Update Date : 18/09/2017 - Add Payroll_TrialErrors clear   Update Date : 17/10/2018 - Updated Clearing Errors Where Clauses  */  create procedure [Payroll_ClearPayrollTrialRun_sp] @EmployeeID int, @PeriodID int, @Simulation bit  as    begin     set nocount on;     delete from [Payroll_TrailRun_History] where ([PeriodID] = @PeriodID)     delete from [Payroll_EmployeeTrialPayslipErrors] where (       ([EmployeeID] > 0 and [PeriodID] = @PeriodID and [Blocking] = 1 and ([EmployeeID] = @EmployeeID or isnull([EmployeeID], 0) = 0))        or       (isnull([EmployeeID], 0) = 0 and [PeriodID] = @PeriodID and [Blocking] = 1)     )     delete from [Payroll_EmployeeTrialPayslipErrors] where (       (([EmployeeID] > 0 and [PeriodID] = @PeriodID and [Blocking] = 0 and ([EmployeeID] = @EmployeeID or isnull([EmployeeID], 0) = 0))        or       (isnull([EmployeeID], 0) = 0 and [PeriodID] = @PeriodID and [Blocking] = 0)) and [Simulation] = @Simulation      )     delete from [Payroll_TrialErrors] where ([PeriodID] = @PeriodID and (case      when [EmployeeID] is null then 1      when [EmployeeID] = @EmployeeID then 1      when @EmployeeID = 0 then 1      else 0 end) = 1 and ([Simulation] = @Simulation))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_ClearPayrollTrialRunErrors
-- Schema: dbo
-- ============================================
CREATE procedure dbo.Payroll_ClearPayrollTrialRunErrors  @EmployeeID int,   @PeriodID int,   @Simulation bit    AS    BEGIN      DELETE from [Payroll_TrialErrors] where (          ([EmployeeID] = @EmployeeID OR IsNULL(@EmployeeID,0) = 0)           AND           ([PeriodID] = @PeriodID OR IsNULL(@PeriodID,0) = 0)          )    END

GO

-- ============================================
-- SP: Payroll_ClearTrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Clears the Employee Trial Simulation   Update Date : 11/04/2019 => Added Employee Trial Simulation @ Terminations  */  create procedure [Payroll_ClearTrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      delete from [Payroll_EmployeeTrialPayslipSimulation] where ([SimulationType] = @SimulationType and [EmployeeID] = @EmployeeID)      delete from [Payroll_TrialRun_History_EmployeeSimulation] where ([SimulationType] = @SimulationType and [EmployeeID] = @EmployeeID and [StartDate] = @StartDate and [UntilDate] = @UntilDate)     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_CoidaWcaReturnOfEarnings
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2021-01-21  -- Description: Used as a dataset for COIDA/WCA Return of Earnings report   --              (Payroll_CoidaWcaReturnOfEarnings.rdl)  --              Returns Detailed Earnings and COIDThreshold amount  -- 20211106 - Ruan - WI77827 - Correct logic for EmployeeHistory  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_CoidaWcaReturnOfEarnings]   @TaxYear NVARCHAR(10)      ,@SalaryHeadIds NVARCHAR(MAX)      ,@EmployeeSubtypeIds NVARCHAR(MAX)  AS  BEGIN    DECLARE      @TaxYearStartDate DATETIME = CONVERT(DATETIME, SUBSTRING(@TaxYear, 0, 5) + '-03-01')      ,@TaxYearEndDate DATETIME = DATEADD(DAY, -1, CONVERT(DATETIME, SUBSTRING(@TaxYear, 6, 9) + '-03-01'))      ,@ShortTaxYear INT = CAST(SUBSTRING(@TaxYear, 6, 9) AS INT)    SELECT   e.[Employee_ID] AS 'EmployeeNumber',   e.[Initials],   e.[Surname],   SUM(pr.[Amount]) AS 'Actual',   IIF(SUM(pr.[Amount]) > cct.[Amount], cct.[Amount], ROUND(SUM(pr.[Amount]), 0)) AS 'Adjust',   DATEDIFF(MONTH,             IIF(@TaxYearStartDate > e.[JoiningDate], @TaxYearStartDate, e.[JoiningDate]),             IIF(@TaxYearEndDate > ISNULL(e.[EndDate], @TaxYearEndDate), e.[EndDate], @TaxYearEndDate)        ) + 1 AS 'PeriodsEmployed'  FROM   Payroll_Employee e  INNER JOIN   Payroll_PayrollResults pr ON e.[Employee_ID] = pr.[EmployeeID]          AND pr.[TaxYear] = @ShortTaxYear          AND (ISNULL(@SalaryHeadIds, '') = '' OR pr.[SalaryHeadID] IN (SELECT * FROM STRING_SPLIT(@SalaryHeadIds, ',')))  LEFT JOIN   Payroll_EmployeeTermination et ON e.[Employee_ID] = et.[EmployeeID]            AND et.[Enabled] = 1            AND et.[Complete] = 1  CROSS APPLY   (    SELECT     *    FROM     Payroll_EmployeeHistory peh    WHERE     peh.[Enabled] = 1    AND peh.[EmployeeID] = e.[Employee_ID]    AND ISNULL(et.[TerminationStartDate], IIF(@TaxYearStartDate > e.[JoiningDate], @TaxYearStartDate, e.[JoiningDate])) BETWEEN peh.[StartDate] AND peh.[EndDate]    AND peh.[EmployeeSubtypeID] IN (SELECT * FROM STRING_SPLIT(@EmployeeSubtypeIds, ','))   ) eh  INNER JOIN   Const_COIDThreshold cct ON cct.[TaxYear] = @TaxYear           AND cct.[Enabled] = 1   WHERE   e.[Enabled] = 1  GROUP BY         e.[Employee_ID], e.[Initials], e.[Surname], e.[JoiningDate], e.[EndDate], cct.[Amount]  ORDER BY   e.[Employee_ID];    END

GO

-- ============================================
-- SP: Payroll_CompanyDetails_Benefit_Rpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,10 Jul 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_CompanyDetails_Benefit_Rpt  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CompanyDetails_Benefit_Rpt]     AS  BEGIN   SELECT Benefit_ID, BenefitType_ID, BenefitType, FundName, ClearanceNo, ContributionType, EmpContributionValue, EmplrContributionValue, '100% of the following earnings Wage' AS BasedOn FROM dbo.Payroll_BenefitDetail AS BD   INNER JOIN dbo.Const_BenefitType_sys AS BT ON BD.BenefitTypeID = BT.BenefitType_ID   WHERE BT.Enabled = 1  END  

