-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,10 Jul 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_CompanyDetails_MedicalAid_Rpt  -- 2015-06-23 : Ravindra Jijotia: TP19741 New flag has been introduced to support maximum dependants feature.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CompanyDetails_MedicalAid_Rpt]     AS  BEGIN   SELECT MS.MedicalScheme_ID, MSD.MedicalSchemeDetails_ID, FundName, EmployeeContributionValue, EmployerContributionValue, MemberAmount, AdultAmount, ChildAmount, IsMaxDependantChildEnabled, MaxDependantCount FROM dbo.Const_MedicalAIDScheme AS MS   INNER JOIN dbo.Const_MedicalAIDSchemeDetail AS MSD ON MS.MedicalScheme_ID = MSD.MedicalSchemeID   WHERE MS.Enabled = 1  END  

