-- ============================================
-- SP: Payroll_Const_BankFormats_new_tbl_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_Const_BankFormats_new_tbl_sp]   AS  BEGIN   IF Not EXISTS(SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'Const_BankFormats')    BEGIN    CREATE TABLE [dbo].[Const_BankFormats](     [ID] [int] IDENTITY(1,1) NOT NULL,     [BankID] [int] NOT NULL,     [BankFormatType] [varchar](200) NOT NULL,     [Enabled] [bit] NOT NULL,     [DateCaptured] [datetime] NOT NULL,     [CapturerID] [int] NOT NULL,     [DateModified] [datetime] NULL,     [ModifierID] [int] NULL,    CONSTRAINT [PK_Const_BankFormats] PRIMARY KEY CLUSTERED     (     [ID] ASC    )WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON) ON [PRIMARY]    ) ON [PRIMARY]        ALTER TABLE [dbo].[Const_BankFormats]  WITH CHECK ADD  CONSTRAINT [FK_Const_BankFormats_Const_Bank] FOREIGN KEY([BankID])    REFERENCES [dbo].[Const_Bank] ([Bank_ID])      ALTER TABLE [dbo].[Const_BankFormats] CHECK CONSTRAINT [FK_Const_BankFormats_Const_Bank]      SET ANSI_PADDING OFF       END  END  

GO

-- ============================================
-- SP: Payroll_CostCenter_EveryMonth_Disable
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  James Roodt  -- Create date: 2015-04-25  -- Description: Deletes an everymonth entry and mark all it's remaining cost center entries as inactive  -- EXEC Payroll_CostCenter_EveryMonth_Disable 1, 20171, '2015-04-30 12:00:00', 120.00  -- 2015-06-03 TP19717 James Roodt: Changed @LastValidDate parameter from nvarchar to datetime, added @OriginalAmount parameter  -- 2015-08-20 TP23516 James Roodt: Also update the Modified Date and User fields  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CostCenter_EveryMonth_Disable]    -- Add the parameters for the stored procedure here   @EmployeeID int,    @PayrollDefinitionID INT,   @LastValidDate DATETIME,   @OriginalAmount DECIMAL(18,2),   @UserID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     -- Deletes every month entry   DELETE TOP(1) FROM Payroll_CostCenter_EveryMonth   WHERE Payroll_CostCenter_EveryMonth.EmployeeID=@EmployeeID   AND Payroll_CostCenter_EveryMonth.PayrollDefinitionID=@PayrollDefinitionID   AND Payroll_CostCenter_EveryMonth.Amount=@OriginalAmount     -- Disable all remaining cost center entries      UPDATE Payroll_CostCenter SET Enabled=0, ModifierID = @UserID, DateModified = GETDATE()   WHERE EmployeeID=@EmployeeID   AND Payroll_CostCenter.PayrollDefinationID=@PayrollDefinitionID   AND Payroll_CostCenter.EntryDate>@LastValidDate   AND Payroll_CostCenter.CostAmount=@OriginalAmount  END  

GO

-- ============================================
-- SP: Payroll_CostCenter_Search_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 06 JUNE 2013  -- CALLS : Payroll_CostCenter_Search_sp  '','','','2015/2016',0  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- 2016-04-22 varun parvataneni:Modification show only S&T claims on cost center in the code TP:35707   -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- ==============================================================================  create procedure [Payroll_CostCenter_Search_sp]   @Name NVARCHAR(100)= null,   @Surname NVARCHAR(100)=null,   @IDNo NVARCHAR(30)=null,   @TaxYear NVARCHAR(50)=null,   @Flag BIT =null  AS    BEGIN   IF(@Flag = 0)   BEGIN    SELECT PAY_COST.CostCenter_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      CONST_TRAN.TransactionTypeDesc + '  '+ PAY_SAL.SalaryHeadTitle AS 'PayDefination',     PAY_COST.CostAmount,PAY_COST.CostDesc, PAY_COST.FinancialYear,     CASE WHEN PAY_COST.[Enabled] = 1 THEN ' True' ELSE 'False' END AS [STATUS],     PAY_COST.EntryDate, PAY_COST.CapturerID, PAY_COST.DateCaptured, PAY_COST.ModifierID,     PAY_COST.DateModified,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_CostCenter AS PAY_COST     INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID      INNER JOIN Payroll_EmployeePayrollDefinition ON PAY_COST.PayrollDefinationID = Payroll_EmployeePayrollDefinition.EmployeePayrollDefinition_ID       AND P_E.Employee_ID = Payroll_EmployeePayrollDefinition.EmployeeID      INNER JOIN Payroll_SalaryHead AS PAY_SAL ON Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      INNER JOIN Const_TransactionType AS CONST_TRAN ON Payroll_IRP5Code.TransactionTypeID = CONST_TRAN.TransactionType_ID    WHERE (P_E.FirstName = @Name OR isnull(@Name,'') ='') AND (P_E.Surname = @Surname  OR isnull(@Surname,'') ='')      AND ( P_E.IdNo = @IDNo OR isnull(@IDNo,'') ='') AND PAY_COST.TaxYear =@TaxYear      and Payroll_IRP5Code.TransactionTypeID=1 and Payroll_IRP5Code.IRP5Code in(3704,3705,3715,3716)    ORDER BY P_E.Employee_ID   END   ELSE   BEGIN    SELECT PAY_COST.CostCenter_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      CONST_TRAN.TransactionTypeDesc + '  '+ PAY_SAL.SalaryHeadTitle AS 'PayDefination',     PAY_COST.CostAmount,PAY_COST.CostDesc, PAY_COST.FinancialYear,     CASE WHEN PAY_COST.[Enabled] = 1 THEN ' True' ELSE 'False' END AS [STATUS],     PAY_COST.EntryDate, PAY_COST.CapturerID, PAY_COST.DateCaptured, PAY_COST.ModifierID,     PAY_COST.DateModified,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_CostCenter AS PAY_COST     INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID      INNER JOIN Payroll_EmployeePayrollDefinition ON PAY_COST.PayrollDefinationID = Payroll_EmployeePayrollDefinition.EmployeePayrollDefinition_ID       AND P_E.Employee_ID = Payroll_EmployeePayrollDefinition.EmployeeID      INNER JOIN Payroll_SalaryHead AS PAY_SAL ON Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      INNER JOIN Const_TransactionType AS CONST_TRAN ON Payroll_IRP5Code.TransactionTypeID = CONST_TRAN.TransactionType_ID    WHERE PAY_COST.TaxYear =@TaxYear and Payroll_IRP5Code.TransactionTypeID=1 and Payroll_IRP5Code.IRP5Code in(3704,3705,3715,3716)    ORDER BY P_E.Employee_ID   END  END  

GO

-- ============================================
-- SP: Payroll_CostCenterClaims_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:Varun Parvataneni  -- Description : To Generate S&TClaims reports on employee for selected dates  -- Create date: 7 APR 2016  -- CALLS : [Payroll_CostCenterClaims_sp]  '2015-03-01','2016-02-29',0,0,0,2   -- 2016/04/22 :Modified as per the tp:35707  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- 2020-10-20 US42239 Myroshnychenko: Remove 'ReportType' parameter, add CycleID and ExcessValue parameters, change call for getting more information  -- ==============================================================================  CREATE procedure [dbo].[Payroll_CostCenterClaims_sp]   @FromDate DATETIME,   @ToDate DATETIME,    @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT,      @CycleID INT,   @ExcessValue FLOAT  AS    BEGIN  SELECT DISTINCT    Employee_id,    dbo.BufferString_fxn(CONVERT(VARCHAR,(PE.EmployeeID)), 8, '0') as EmployeeNumber,    P_E.Surname as EmployeeSurname,    P_E.FirstName,    CASE     WHEN P_EC.ProjectID IS NOT NULL THEN 'Yes'     ELSE 'No'    END as OverrideProject,    C_D.DepartmentDesc as Department,    C_Div.DivisionDesc as Division,    P_EC.SubType as Subtype,    P_EC.ReferenceNo as ReferenceNumber,    P_EC.CostDesc as ReasonForTrip,    P_EC.EntryDate as StartDate,    P_EC.EndDate as EndDate,    P_EC.CostAmount as AmountClaimed       FROM dbo.Payroll_EmployeeClaims AS P_EC    JOIN Payroll_Employee AS P_E     ON P_EC.EmployeeId = P_E.Employee_ID    CROSS APPLY (SELECT TOP 1 P_EH.EmployeeID, P_EH.CycleID, P_EH.DepartmentID, P_EH.DivisionID       FROM Payroll_EmployeeHistory as P_EH             WHERE P_E.Employee_ID = P_EH.EmployeeID        AND (@CycleID = 0 OR P_EH.CycleID = @CycleID)       AND (P_EH.StartDate < @ToDate AND P_EH.EndDate >@FromDate)       AND P_EH.Enabled = 1) AS PE              INNER JOIN Payroll_EmployeePayrollDefinition AS P_EPD ON P_EC.PayrollDefinationID = P_EPD.EmployeePayrollDefinition_ID      AND P_E.Employee_ID = P_EPD.EmployeeID     INNER JOIN Payroll_SalaryHead AS PAY_SAL ON P_EPD.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID    INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID    INNER JOIN Const_TransactionType AS CONST_TRAN ON Payroll_IRP5Code.TransactionTypeID = CONST_TRAN.TransactionType_ID    INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID    INNER JOIN dbo.Const_Department AS C_D ON PE.DepartmentID = C_D.Department_ID     INNER JOIN dbo.Const_Division AS C_Div ON C_D.Department_ID = C_Div.DepartmentID AND C_Div.Division_ID = PE.DivisionID    INNER JOIN dbo.Const_Claims AS C_C on C_C.Claim_ID = P_EC.ClaimID   WHERE (P_EC.EntryDate between @FromDate and @ToDate)     AND (ISNULL(@DepartmentId,0) = 0 OR Department_ID = @DepartmentId)     AND (ISNULL(@DivisionId,0) = 0 OR Division_ID = @DivisionId)     AND Payroll_IRP5Code.TransactionTypeID = 1     AND C_C.Claim_Type = 'S & T'                 AND (ISNULL(@EmployeeID,0) = 0 OR @EmployeeID = PE.EmployeeID)     AND (ISNULL(@ExcessValue,0) = 0 OR P_EC.CostAmount > @ExcessValue)     AND P_EC.Processed = 1   ORDER BY P_E.Employee_ID  END

GO

-- ============================================
-- SP: Payroll_CreateChildPaymentBatch
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <lungisani,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- Himil Modi 26/03/2018 -- Put distinct for the number of transaction value to correct it.  -- =============================================  CREATE PROCEDURE dbo.Payroll_CreateChildPaymentBatch   @BatchID int,  @CapturerID int,  @IsInstructionApproval bit    AS  BEGIN    DECLARE @Success NVARCHAR(200)      BEGIN TRANSACTION      BEGIN TRY    DECLARE @temp TABLE(        empID INT        )        DECLARE @NewBatchId INT       IF(@IsInstructionApproval = 1)   BEGIN      INSERT INTO @temp SELECT employeeID  FROM Payroll_PaymentInstructions WHERE BatchID = @BatchID AND InstructionsStatus='Rejected'     END     IF(@IsInstructionApproval = 0)   BEGIN      INSERT INTO @temp SELECT employeeID  FROM Payroll_PaymentInstructions WHERE BatchID = @BatchID AND Include = 0     END      INSERT INTO Payroll_PaymentBatches (PayrollStatus ,LedgerPaymentStatus ,BatchType,Payroll_CycleID,NumberOfEmployees,NumberOfTransactions                                                         ,InvoiceTotalAmount,ProcessedDate,ParentID,DateCaptured,CapturerID,DateModified,ModifierID,PaymentDueDate           )                 (SELECT DISTINCT 'Excluded' ,LedgerPaymentStatus ,BatchType,Payroll_CycleID, (SELECT COUNT(empID)FROM @temp), (SELECT COUNT(pid.EmployeeID)                    FROM  Payroll_PaymentInstructionDetails pid             JOIN Payroll_PaymentInstructions ppi ON ppi.PaymentInstructions_ID=pid.PaymentInstructions_ID             WHERE ppi.BatchID = @BatchID             AND  ppi.EmployeeID IN (SELECT * FROM @temp)                  )            ,(SELECT SUM(InvoiceTotalAmount)  FROM Payroll_paymentInstructions   WHERE  BatchID = @BatchID   AND ppi.EmployeeID IN (SELECT * FROM @temp))              , ProcessedDate, @BatchID, GETDATE(), @CapturerID, NULL, NULL, ppi.PaymentDueDate           FROM Payroll_PaymentBatches pb           INNER JOIN Payroll_paymentInstructions ppi on ppi.BatchID = pb.Batch_ID           WHERE Batch_ID = @BatchID           AND ppi.EmployeeID in (SELECT * FROM @temp)      )           SET @NewBatchId = @@IDENTITY      UPDATE Payroll_PaymentInstructions SET BatchID  = @NewBatchId WHERE  BatchID = @BatchID AND EmployeeID IN (SELECT * FROM @temp)     ----------------------------------------Parent Batch update-----------------------------------------------------------------------------------     UPDATE Payroll_PaymentBatches SET NumberOfEmployees=((SELECT  COUNT( DISTINCT EmployeeID)  FROM Payroll_paymentInstructions WHERE  BatchID = @BatchID)),                                  InvoiceTotalAmount =((SELECT SUM(InvoiceTotalAmount)  FROM Payroll_paymentInstructions WHERE  BatchID = @BatchID)),               NumberOfTransactions =(SELECT COUNT(DISTINCT pid.EmployeeID) FROM  Payroll_PaymentInstructionDetails pid                                                  INNER JOIN Payroll_PaymentInstructions ppi ON ppi.PaymentInstructions_ID=pid.PaymentInstructions_ID                                                  WHERE ppi.BatchID = @BatchID)                                                                   WHERE  Batch_ID = @BatchID               ----------------------------------------new Batch update-----------------------------------------------------------------------------------   UPDATE Payroll_PaymentBatches SET NumberOfEmployees=((SELECT  COUNT( DISTINCT EmployeeID)  FROM Payroll_paymentInstructions WHERE  BatchID = @NewBatchId)),                                  InvoiceTotalAmount =((SELECT SUM(InvoiceTotalAmount)  FROM Payroll_paymentInstructions WHERE  BatchID = @NewBatchId)),               NumberOfTransactions =(SELECT COUNT(DISTINCT pid.EmployeeID) FROM  Payroll_PaymentInstructionDetails pid                                                  INNER JOIN Payroll_PaymentInstructions ppi ON ppi.PaymentInstructions_ID=pid.PaymentInstructions_ID                                                  WHERE ppi.BatchID = @NewBatchId)                                                                   WHERE  Batch_ID = @NewBatchId                        SET @Success ='successful'    COMMIT TRANSACTION         END TRY      BEGIN CATCH      ROLLBACK TRANSACTION      SET @Success ='Unsuccessful' + ERROR_MESSAGE()     End Catch    select @Success  END    

GO

-- ============================================
-- SP: Payroll_CreateEmployeeCalendar_sp
-- Schema: dbo
-- ============================================
/*   Author  : Richa Mills   Create Date : 2018/09/03   Description : Create Employee Calendar   Update Date : 2019/03/17 - Cater for updating the calendar when an employees start date lapses   Update Date : 12/09/2019 => Ferdi Botha: Create temp table to avoid table "locking"   Update Date : 02/09/2019 => Modiri: #94843 QA_Multi-HR Payroll- Scheduler not generating shifts as per Spec.   Update Date : 2019/10/08 => Modiri: #95001 QA_Multi_HRPayroll_no functionality for half day Leave Capture   Update Date : 2019/10/09 => Modiri: #94843 QA_Multi-HR Payroll- Scheduler not generating shifts as per Spec.      Update Date : 2021/03/19 => Myroshnychenko: #31957 Public Holiday on Sunday - Public holiday hot moved from Sunday to Monday.   Update Date : 2022/03/16 => Disabled ShiftRotation Details should not be included in Calendar  */    CREATE procedure [dbo].[Payroll_CreateEmployeeCalendar_sp] @EmployeeID int, @Create bit  as    begin     set nocount on;     declare @TaxYear varchar(10) = (select [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'TaxYear')),     @CycleId int = null,     @JoiningDate datetime = null,     @ShiftRotationID int = null,     @RotationID int = null,     @StartDate datetime = null,     @StartWeek datetime = null,     @UntilDate datetime = null,     @WeekNo int = null,     @NoOfWeeks int = null     declare @leaveDays as table (      [Date] datetime not null     )     declare @days as table (      [Date] datetime not null,    [Name] varchar(9) not null,    [DayNo] tinyint not null     )     declare @calendarDays as table (      [Date] datetime not null,    [Name] varchar(9) not null,    [DayNo] tinyint not null,    [WeekNo] int not null,    [WeekNoPerMnth] int null,    [ShiftID] int  null   )     select @CycleId = [CycleID], @JoiningDate = [JoiningDate], @ShiftRotationID = [ShiftRotationID], @RotationID = [RotationID] from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)     select @WeekNo = [WeekNo] from [Payroll_ShiftRotationDetail] where ([Rotation_ID] = @RotationID)     select @NoOfWeeks = count([Rotation_ID]) from [Payroll_ShiftRotationDetail] where ([ShiftRotationID] = @ShiftRotationID)      declare @TaxYearStartDate datetime = (select top 1 [PeriodStartDate] from [Payroll_CyclePeriodDetails] with(nolock) where ([CycleID] = @CycleID and [TaxYear] = @TaxYear and CycleModeID=1) ORDER BY PeriodStartDate)     set @StartDate = @TaxYearStartDate     if (@JoiningDate > @TaxYearStartDate)      set @StartDate = @JoiningDate     set @UntilDate = dateadd(year, 2, @StartDate)         if (@Create = 0)   begin      if (exists(select top 1 [Date] from [Payroll_EmployeeCalander] with(nolock) where ([EmployeeID] = @EmployeeID)))       select top 1 @StartDate = dateadd(day, 1, [Date]) from [Payroll_EmployeeCalander] with(nolock) where ([EmployeeID] = @EmployeeID) order by [Date] desc      set @UntilDate = dateadd(year, 1, @StartDate)      end     SET @UntilDate =dateadd(day, -1, @UntilDate);         if (not @StartDate is null and @Create=1)   begin      set @StartWeek = @StartDate      while((datepart(weekday, @StartWeek) - 1) > 1)    begin       set @StartWeek = dateadd(day, -1, @StartWeek)      end        insert into @days([Date], [Name], [DayNo])       select [Date],       datename(weekday, [Date]),       datepart(weekday, [Date])        from [Payroll_CreateCalendarDates] (@StartWeek, @UntilDate)         order by [Date]        insert into @calendarDays([Date], [Name], [DayNo], [WeekNo],WeekNoPerMnth)       select [Date], [Name], [DayNo], (((row_number() over(order by [Date]) - 1) / 7) + 1),     datediff(week, dateadd(week, datediff(week, 0, dateadd(month, datediff(month, 0, [Date]), 0)), 0), [Date] - 1) + 1      from @days      delete from @calendarDays where ([Date] < @StartDate)          insert into @leaveDays([Date])       select [Date] from [Payroll_EmployeeCalander] with(nolock) where ([EmployeeID] = @EmployeeID and [Leave] = 1)       /*Work on shift rotation*/     IF(SELECT count(*) FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID AND Enabled = 1) =1     BEGIN      UPDATE @calendarDays      SET ShiftID = (SELECT dbo.Payroll_ShiftRotationDetail.WeekNo FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID AND Enabled = 1)     END     ELSE     BEGIN      UPDATE @calendarDays      SET ShiftID =1      WHERE WeekNoPerMnth=0            UPDATE c      SET c.ShiftID =ps.WeekNo      FROM @calendarDays c      JOIN [Payroll_ShiftRotationDetail] PS on PS.WeekNo = c.WeekNoPerMnth AND ps.ShiftRotationID=@ShiftRotationID AND Enabled = 1        /*Deal with what is left as null on WeekNoPerMnth*/        IF(SELECT count(*) FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID And Enabled = 1) =2      BEGIN       UPDATE @calendarDays       SET ShiftID =1       WHERE (WeekNoPerMnth % 2) =0         UPDATE @calendarDays       SET ShiftID =2       WHERE (WeekNoPerMnth % 2) <> 0      END     END           delete from @calendarDays where ([Date] < @StartDate)          insert into @leaveDays([Date])       select [Date] from [Payroll_EmployeeCalander] with(nolock) where ([EmployeeID] = @EmployeeID and [Leave] = 1)           delete from [Payroll_EmployeeCalander] where ([EmployeeID] = @EmployeeID and [Date] >= @StartDate)        insert into [Payroll_EmployeeCalander]([RotationID], [EmployeeID], [Date], [WeekNo], [WeekDay], [DayName], [ShiftID], [NoOfHrs], [NightHrs], [PublicH], [Leave], [Shift], [OT], [Substitute], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [NoOfWorkingHrs])       select [RT].[ShiftRotationID], @EmployeeID, [CAL].[Date], [CAL].[WeekNo], [CAL].[DayNo], [CAL].[Name], [RT].[ShiftId], [CS].[ShiftHour], [CS].[NightHours], 0, 0, (case        when [CS].[TotalHoursWorked] > 0 then 1        else 0       end), 0, 0, getdate(), 1, null, null,       [CS].[TotalHoursWorked]       from @calendarDays as [CAL]        join (         select [ShiftRotationID], 'Monday' as [WeekDay], [Monday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Tuesday' as [WeekDay], [Tuesday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Wednesday' as [WeekDay], [Wednesday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Thursday' as [WeekDay], [Thursday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Friday' as [WeekDay], [Friday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Saturday' as [WeekDay], [Saturday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)         union all         select [ShiftRotationID],'Sunday' as [WeekDay], [Sunday] as [ShiftId], [WeekNo] from [Payroll_ShiftRotationDetail] with(nolock) where ([ShiftRotationID] = @ShiftRotationID and Enabled = 1)        ) as [RT] on [RT].[WeekNo] = [CAL].ShiftID and [RT].[WeekDay] = [CAL].[Name]        join [Const_Shift] as [CS] with(nolock) on [CS].[Shift_ID] = [RT].[ShiftId]          UPDATE pc      SET pc.publich =1      FROM [Payroll_EmployeeCalander] pc      JOIN [Const_Holiday] ch                       ON MONTH(ch.HolidayDate) = MONTH(PC.Date)                       AND DAY(ch.HolidayDate) = DAY(PC.Date)                       AND (YEAR(PC.Date) BETWEEN YEAR(ch.CalendarYearFrom) AND YEAR(ch.CalendarYearTo))                      AND [EmployeeID]= @EmployeeID                       AND [Date] > @Startdate      --Add public holiday on Monday when public holiday on Sunday                  DROP TABLE IF EXISTS #Days                  CREATE TABLE #Days                  (                  EmployeeID INT      , Date DATETIME      )        INSERT INTO #Days (EmployeeID, Date)      SELECT EmployeeID, Date      FROM Payroll_EmployeeCalander       WHERE PublicH = 1       AND WeekDay = 1       AND EmployeeID = @EmployeeID        UPDATE P_EC      SET P_EC.PublicH = 1      FROM Payroll_EmployeeCalander AS P_EC      JOIN #Days        ON P_EC.Date IN (SELECT DATEADD(DAY,1,Date) FROM #Days) AND P_EC.EmployeeID = #Days.EmployeeID        update [Payroll_EmployeeCalander] set [Leave] = 1 where ([EmployeeID] = @EmployeeID and [Date] in(select [Date] from @leaveDays))                    DROP TABLE #Days   END   set nocount off;    end

GO

-- ============================================
-- SP: Payroll_CreateMissingStrings_sp
-- Schema: dbo
-- ============================================
/*   Author  : Richa M   Create date : 10/11/2024   Description : CreateMissingPayrollStrings   Exec Payroll_CreateMissingStrings_sp 186,'2024/2025'  */  CREATE procedure [dbo].[Payroll_CreateMissingStrings_sp]    @PeriodID int,  @finyear varchar(10)  as    begin     set nocount on;    begin try    CREATE TABLE #TempResults (      ScoaItemId INT,      ScoaFunctionId INT,      ScoaRegionId INT,      DivisionId INT,      ProjectId INT,      ScoaFundId INT  )    DECLARE @finyearOld int = CAST(LEFT(@Finyear,4) AS INT)  DECLARE @PreviousFinyear varchar(10) = CAST(@finyearOld - 1 as varchar(5)) + '/' + CAST(@FinyearOld as varchar(5))  DECLARE @Count int    DECLARE @ScoaItemId int, @ScoafunctionId int, @ScoaRegionId int, @DivisionId int,@ProjectId int, @ScoaFundId int    DECLARE @DefaultFundId int =  (select top 1 SCOAFundId from Plan_ProjectItem where FinYear = @finyear and SCOAItemID in (select SalarySuspenseScoaItemID from Payroll_Municipality))  Update Payroll_MissingStrings set ScoaFundId = @DefaultFundId where isnull(scoaFundId,0) = 0    DECLARE db_cursor CURSOR FOR    SELECT DISTINCT scoaItemId,ScoaFunctionId,ScoaRegionId,DivisionId,Projectid,isnull(ScoafundId,@DefaultFundId)   FROM Payroll_MissingStrings    WHERE PeriodId = @PeriodID   and isnull(PlanProjectItemId,0) = 0   and ScoaItemId is not null    and ScoaRegionId is not null    and ScoaFunctionId is not null    and DivisionId is not null    and ProjectId is not null    and ScoaFundId is not null            OPEN db_cursor    FETCH NEXT FROM db_cursor INTO @ScoaItemId,@ScoaFunctionId,@ScoaRegionId,@DivisionId,@ProjectId,@ScoaFundID      WHILE @@FETCH_STATUS = 0    BEGIN      DECLARE @ProjectItemId INT = (select TOP 1 ProjectItem_ID from Const_ProjectItem where FinYear = @finyear and ItemDescription = (select ScoaDesc from Const_SCOA_Structure where ScoaID = @ScoaItemId))  DECLARE @HistoricalCode INT = (SELECT TOP 1 Project_ID FROM plan_Project WHERE ProjectCode = (SELECT ProjectCode FROM Plan_Project pp WHERE pp.Project_ID = @ProjectID AND pp.FinYear = @finyear) AND FinYear = @PreviousFinyear)    DECLARE @ProjectFundId INT = (SELECT TOP 1 ProjectFund_ID FROM Plan_ProjectFund WHERE ScoaFundID =  @ScoaFundId AND ProjectID = @ProjectId)  DECLARE @ProjectFundYearId INT = (SELECT TOP 1 ProjectFundYear_ID FROM Plan_ProjectFundYear WHERE ProjectFundID = @ProjectFundId AND FinYear = @finyear)     INSERT INTO Plan_ProjectItem   (ProjectID,ProjectItemID,SCOAItemID,FinYear,CapturerID,DateCaptured,ProjectFundYearID,SCOAFundId,BudgetAmount,BudgetAmountCurP1,BudgetAmountCurP2,SCOAFunctionId,SCOARegionId,DivisionId,BudgetSplitID,HistoricalProjectCode,SCOACostingID,CreditDebit)  select @ProjectID,@ProjectItemId,@ScoaItemId,@finyear,1,getdate(),@ProjectFundYearId,@ScoaFundId,1.00,1.00,1.00,@ScoafunctionId,@ScoaRegionId,@divisionId,12,@HistoricalCode, 20,'D'    DECLARE @id INT = @@Identity      insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,1,1,0,1,GETDATE()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,2,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,3,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,4,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,5,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,6,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,7,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,8,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,9,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,10,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,11,1,0,1,getdate()     insert into Plan_ProjectItemMonth    (PlanProjectItemID,MonthID,UnitQuantity,UnitPrice,CaptureID,DateCaptured)    select @id,12,1,0,1,getdate()        INSERT INTO #TempResults     (ScoaItemId, ScoaFunctionId, ScoaRegionId, DivisionId, ProjectId, ScoaFundId)    VALUES (@ScoaItemId, @ScoaFunctionId, @ScoaRegionId, @DivisionId, @ProjectId, @ScoaFundId);      FETCH NEXT FROM db_cursor INTO @ScoaItemId,@ScoaFunctionId,@ScoaRegionId,@DivisionId,@ProjectId,@ScoaFundID    END     CLOSE db_cursor    DEALLOCATE db_cursor    INSERT INTO Plan_BudgetConsumption  SELECT    ppi.FinYear,--FinYear   PlanProjectItem_ID,--PlanProjectItemID   1,--BudgetTransactionTypeID   10,--ModuleID   PlanProjectItem_ID,--PK_TransactionID   'Plan_ProjectItem',--TransactionTableName   BudgetAmount,--ConsumingTransactionAmount   BudgetAmountCurP1 + BudgetAmountCurP2,--ConsumingTransactionAmountMultiyear   BudgetAmount,--AdjustedTansactionAmount   BudgetAmount,--AvailableBudget   BudgetAmountCurP1 + BudgetAmountCurP2,--AvailableBudgetMultiyear   1,--ProcessingMonth   200,--BudgetConsumptionProcessID   BudgetAmount,--OriginalBudgetToDate   0,--AdjustedBudgetToDate   0,--CapturedExpenditureToDate   0,--CapturedExpenditureToDateMultiyear   0,--ReserveToDate   0,--ReserveToDateMultiyear   0,--CommitToDate   0,--ActualToDate   -BudgetAmount,--CurrentlyConsumedAmount   NULL,--CurrentlyConsumedAmountMultiYear   'Plan_ProjectItem_' + CONVERT(VARCHAR, PlanProjectItem_ID),--InitialLine   1,--CapturerID   GETDATE(),--DateCaptured   NULL,--ModifierID   NULL--DateModified    FROM   Plan_ProjectItem ppi   inner join Plan_Project pp on ppi.ProjectID = pp.Project_ID  WHERE   pp.FinYear = @finYear AND ProjectStatus = 24 and ISNULL(IsDeleted, 0) <> 1   AND PlanProjectItem_ID not in (select PlanProjectItemID from Plan_BudgetConsumption where FinYear = @finYear)    update strings  set strings.planProjectItemId = ppi.PlanProjectItem_ID   from(  select * from Payroll_MissingStrings where PeriodId = @PeriodID)strings  join Plan_ProjectItem ppi on ppi.SCOAItemID = strings.ScoaItemId   and ppi.ProjectID = strings.ProjectId  and ppi.DivisionId = strings.DivisionId  and ppi.SCOAFunctionId = strings.ScoaFunctionId  and ppi.SCOAFundId = strings.ScoaFundId  and ppi.SCOARegionId = strings.ScoaRegionId    select count(*)affectedRows from #TempResults          end try     begin catch   insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())      select 0 affectedRows from #TempResults      end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_CreateSCMInvoices
-- Schema: dbo
-- ============================================
 /*   Author  : Richa Mills   Create date : 2023/11/15   Description : Write SCM Invoices for Payroll   Payroll_CreateSCMInvoices 294,1,120     Modified :Richa M 2025/05/12 - Remove join to payroll_employeepayslip when updating SCM_Payroll_InvoiceDetails   */  CREATE PROCEDURE [dbo].[Payroll_CreateSCMInvoices]   @PeriodID int,    @UserId int,   @VendorId int,   @SalaryHeadIds nvarchar(2000),   @ConsolidatedEFT bit     as  begin     begin try     SET XACT_ABORT ON     set nocount on;  Begin transaction       declare @TaxYear varchar(10),@Finyear varchar(10)  select @TaxYear = TaxYear,@Finyear = FinancialYear from Payroll_CyclePeriodDetails where Period_ID = @PeriodID  declare @ledgerMonth int = (select Top 1 ProcessingMonth from Led_GeneralLedger where PayrollLinkID in (select TransactionGroup_ID from Payroll_TransactionsGroup where PeriodID = @PeriodID))    DECLARE @SalaryHeadSet TABLE (SalaryHeadID int PRIMARY KEY);    INSERT INTO @SalaryHeadSet (SalaryHeadID)  SELECT DISTINCT TRY_CAST(LTRIM(RTRIM(value)) AS int)  FROM STRING_SPLIT(@SalaryHeadIds, N'|')  WHERE TRY_CAST(LTRIM(RTRIM(value)) AS int) IS NOT NULL;    DECLARE @CommPercentage decimal(18,2),  @HasPayrollCommission bit,  @PaymentReference varchar(500),@DocCount int, @DocNumber varchar(10)    select @CommPercentage = CommissionPercentage,    @HasPayrollCommission = bPayrollCommission   from Cons_Vendor   where Vendor_ID = @VendorId    select @PaymentReference = Paymentreference from Cons_VendorBankingDetails where VendorID = @VendorId    select @DocCount = (select  MAX(CAST(right(DocNumber,Len(DocNumber) - 4) AS int)) from Payroll_TransactionsGroup where DocNumber like '132/%' )    if(@DocCount IS NULL)   select @DocCount = 1    Set @DocCount = @DocCount + 1    SELECT @DocNumber = '132/' + CAST(@DocCount AS varchar(5))    declare @COUNT int  declare @START int = 1    drop table if exists #incomeTrx      select min(PayrollResult_ID)Id into #incomeTrx      from Payroll_PayrollResults      where PeriodID = @PeriodId      and TransactionTypeID = 1     GROUP by EmployeeID    DECLARE @PayrollResults table  (   TrialResultId int,   SalaryHeadId int,   VendorId int,   EmployeeId int,   TransactionTypeId int,   Amount decimal(18,2),   SalaryTitle nvarchar(256),   ScoaFundId int,   ContraSCOAFundingID int,   ContraSCOACostingID int,   ContraScoaFunctionId int,   ContraScoaItemID int,   ContraScoaProjectId int,   ContraScoaRegionId int,   ContraPlanProjectItemId int,   PlanProjectItemId int,   DivisionId int,   CommAmount decimal(18,2),   VatAmount decimal(18,2),   RoundingTrans bit,   calculation ntext,   IncomeFundId int     )    insert into @PayrollResults    select pr.*,inc.SCOAFundingID incomeFundId from(     select PayrollResult_ID, SalaryHeadID,VendorID,EmployeeID,TransactionTypeID,Amount,SalaryTitle,SCOAFundingID, ContraSCOAFundingID,ContraSCOACostingID,ContraScoaFunctionId,ContraScoaItemID,ContraScoaProjectId,ContraScoaRegionId,ContraPlanProjectItemID, PlanProjectItemId,DivisionId,Amount CommAmount,0 VATAmount,0 RoundingTrx,Calculation    from Payroll_PayrollResults     where Amount <> 0 and periodid = @PeriodID     and TaxSavePurpose = 0     and VendorId = @VendorId     and TransactionTypeID IN (2,3)    AND SalaryHeadID IN (SELECT SalaryHeadID FROM @SalaryHeadSet)    )pr   left join (select EmployeeID, SCOAFundingID from Payroll_PayrollResults where PayrollResult_ID in (select ID from #incomeTrx)) inc on inc.EmployeeID = pr.EmployeeID     DECLARE @CommisionEarnedScoaItem int,@CommProjectId int, @CommisionDivId int, @CommFunctionId int, @CommRegionId int,@CommFundId int     DECLARE @VATProjectItemId int = (select top 1 [PlanProjectItemID] from [Led_VatTransactionTypeSetup] where ([VatTransactionTypeID] = 22 and [FinYear] = @finyear))     select @CommisionEarnedScoaItem = CommissionScoaItemID, @CommProjectId = CommissionProjectID,@CommisionDivId = CommDivisionId,@CommRegionId = CommRegionId, @CommFunctionId = CommFunctionId, @CommFundId = CommFundId from Payroll_Municipality     DECLARE @VATRate decimal(18,6)   DECLARE @VatIndicator int     select @VatIndicator = VatIndicatorID    from led_vote    where ScoaItemId =     (select CommissionScoaItemID from payroll_municipality)    and Finyear = @finyear     If IsNULL(@VatIndicator,0) in (0,1)   BEGIN    SET @VatIndicator = 6   END   If IsNULL(@VatIndicator,0) = 2   BEGIN    SET @VatIndicator = 5   END   SELECT @VatRate = (Select TOP 1 VATPercent from const_vatrate where VatIndicatorID = @VatIndicator and GetDate() >= EffectiveDate order by EffectiveDate desc)    if @CommPercentage > 0  begin   DECLARE @TotalComm decimal(18,2) = (Select SUM(Amount) * @CommPercentage/100 from @PayrollResults)   DECLARE @RoundingDiff decimal(18,2)   Update @PayrollResults set CommAmount = Amount * @CommPercentage/100     Select @RoundingDiff = (Select @TotalComm - SUM(CommAmount) from @PayrollResults)       Update @PayrollResults set VatAmount = CommAmount - (CommAmount / (1 + (@VATRate / cast(100 as decimal(18, 6)))))     if @RoundingDiff <> 0   BEGIN    Declare @RoundingTransactionId int = (select top 1 TrialResultId from @PayrollResults where CommAmount > ABS(@RoundingDiff))    update @PayrollResults set CommAmount = CommAmount + @RoundingDiff,RoundingTrans = 1 where TrialResultId = @RoundingTransactionId    Update @PayrollResults set VatAmount = CommAmount - (CommAmount / (1 + (@VATRate / cast(100 as decimal(18, 6))))) where TrialResultId = @RoundingTransactionId     END  end       insert into Payroll_TransactionsGroup   select     GetDate(),    gl.VendorScoaId,   --VendorId (Cr)    0,       --Credit    CASE     WHEN @HasPayrollCommission = 1 THEN SUM(Amount) - SUM(CommAmount)     ELSE SUM(Amount)    END,      --Debit    @PeriodId,     --PeriodId    132,      --DocumentTypeId    CASE WHEN tr.TransactionTypeId = 2 THEN tr.IncomeFundId ELSE tr.ScoaFundID END SCOAFundId,   --dt    pos.RegionID SCOARegionId,   --dt    piDt.ScoaCostingID,   --dt    dtProject.ScoaProjectID, --dt    pos.FunctionID SCOAFunctionId,  --dt    isnull(empType.SalarySuspenseScoaItemId, gl.SuspenseScoaItemID)  SCOAItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,pos.DivisionID    --Moidier    ,@DocNumber     --DocNumber    ,tr.SalaryHeadID   --SalaryHeadId    ,tr.VendorID    --VendorId    ,sh.SalaryHeadName   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,pos.DivisionID    --DivisionId    ,ctProject.ScoaProjectID --CreditScoaProjectId    ,gl.VendorScoaId   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,pos.FunctionID  --CreditFunctionId    ,CASE WHEN tr.TransactionTypeId = 2 THEN tr.IncomeFundId ELSE tr.ScoaFundID END   --CreditFund    ,pos.RegionID   --CreditRegion    ,Isnull(empType.SalaryProjectID, gl.SCOAProjectID)     --ProjectId Dt    ,piDt.PlanProjectItem_ID --PlanProjectItemId Dt    ,gl.VendorScoaProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct    from     (select * from @PayrollResults)tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     left join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piDt       on piDt.ScoaItemId =  isnull(empType.SalarySuspenseScoaItemId, gl.SuspenseScoaItemID)       and piDT.ProjectId =  Isnull(empType.SalaryProjectID, gl.SCOAProjectID)       and piDT.SCOARegionId = pos.RegionID       and piDT.SCOAFunctionId = pos.FunctionID       and piDt.DivisionId = pos.DivisionID        and piDt.ScoaFundId = CASE WHEN tr.TransactionTypeId = 2 THEN tr.IncomeFundId ELSE tr.ScoaFundID END     left join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID       left join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piCt       on piCt.SCOAItemID = gl.VendorScoaId       and piCt.ProjectId = gl.VendorScoaProjectId       and piCt.SCOARegionId = pos.RegionID       and piCt.SCOAFunctionId = pos.FunctionID       and piCt.DivisionId = pos.DivisionID       and piCt.ScoaFundId = CASE WHEN tr.TransactionTypeId = 2 THEN tr.IncomeFundId ELSE tr.ScoaFundID END      left join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID  group by     gl.VendorScoaId,    tr.TransactionTypeId,tr.IncomeFundId,tr.ScoaFundId,    pos.RegionID,     piDt.ScoaCostingID,     dtProject.ScoaProjectID,     pos.FunctionID,     empType.SalarySuspenseScoaItemId, gl.SuspenseScoaItemID,    tr.SalaryHeadID,         tr.VendorID,        sh.SalaryHeadName,         pos.DivisionID,         ctProject.ScoaProjectID,        gl.VendorScoaId,         piCt.SCOACostingID,        pos.FunctionID,        piCt.SCOAFundId,         piCt.SCOARegionId,          piDt.ProjectID,         piDt.PlanProjectItem_ID,    gl.VendorScoaProjectId,         piCt.PlanProjectItem_ID,empType.SalaryProjectID, gl.SCOAProjectID       if @CommPercentage > 0   BEGIN  --Cr COMM Control Account   --Dt Creditor Control     insert into Payroll_TransactionsGroup   select     GetDate(),    piCt.SCOAItemID,   --VendorId (Cr)    0,    CommAmount - VatAmount,     @PeriodId,     --PeriodId    132,      --DocumentTypeId    dt.SCOAFundId,   --dt    dt.SCOARegionId,   --dt    dt.ScoaCostingID,   --dt    dt.ScoaProjectID,   --dt    dt.SCOAFunctionId,  --dt    dt.SuspenseScoaItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,@CommisionDivId      --Moidier    ,@DocNumber     --DocNumber    ,0       --SalaryHeadId    ,@VendorId     --VendorId    ,'Commision Earned'   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,dt.DivisionID   --DivisionId    ,ctpp.ScoaProjectID          --CreditScoaProjectId    ,@CommisionEarnedScoaItem   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,@CommFunctionId  --CreditFunctionId    ,@CommFundId   --CreditFund    ,@CommRegionId   --CreditRegion    ,dt.ProjectID    --ProjectId Dt    ,dt.PlanProjectItem_ID     --PlanProjectItemId Dt    ,@CommProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct     from    (      select piDt.PlanProjectItem_Id,     SUM(tr.Amount)Amount,    SUM(Round(CommAmount,2)) CommAmount,    SUM(Round(VatAmount,2)) VatAmount,    piDt.SCOACostingID        ,pos.FunctionID SCOAFunctionId      ,@CommFundId SCOAFundId          ,pos.RegionID SCOARegionId        ,Isnull(empType.SalaryProjectId,gl.SCOAProjectID) ProjectID          ,Isnull(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID) SuspenseScoaItemID,    pp.ScoaProjectID,    pos.DivisionID,    SalarySuspenseScoaItemCreditId,    SalaryProjectid    from(     select * from @PayrollResults      )tr    join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1    join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID    join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id     join Payroll_Position pos       on pos.Position_ID = emp.PositionID    Left join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piDt       on piDt.SCOAItemID = Isnull(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID)         and piDt.ProjectId = Isnull(empType.SalaryProjectId,gl.SCOAProjectID) and piDt.SCOARegionId = pos.RegionID and piDt.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID and pidt.SCOAFundId = @CommFundId    Left join plan_project pp      on pp.Project_id = piDt.ProjectID    group by PlanProjectItem_Id,piDt.SCOACostingID        ,pos.FunctionID      ,piDt.PlanProjectItem_Id,    gl.SuspenseScoaItemID,empType.SalarySuspenseScoaItemId,    pp.ScoaProjectID,    pos.DivisionID    ,piDt.SCOAFundId          ,pos.RegionID        ,piDt.ProjectId,    SalarySuspenseScoaItemCreditId,    SalaryProjectid,    gl.SCOAProjectID    )dt        Left join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piCt      on piCt.SCOAItemID =  @CommisionEarnedScoaItem       and  piCt.ProjectId =  @CommProjectId           and piCt.SCOARegionId = @CommRegionId       and piCt.SCOAFunctionId = @CommFunctionId       and piCt.DivisionId = @CommisionDivId      and piCt.SCOAFundId = @CommFundId    Left join plan_project ctpp      on ctpp.Project_id = piCt.ProjectID     --Cr VAT Control Account   --Dt Creditor Control   declare @VatFundID int = (Select ScoaFundId from plan_projectItem where Planprojectitem_id = @VATProjectItemId)    insert into Payroll_TransactionsGroup   select     GetDate(),    piCt.SCOAItemID,   --VendorId (Cr)    0,     VatAmount,    @PeriodId,     --PeriodId    132,      --DocumentTypeId    dt.SCOAFundId,   --dt    dt.SCOARegionId,   --dt    dt.ScoaCostingID,   --dt    dt.ScoaProjectID,   --dt    dt.SCOAFunctionId,  --dt    dt.SuspenseScoaItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,piCt.DivisionId   --Moidier    ,@DocNumber     --DocNumber    ,0       --SalaryHeadId    ,@VendorId     --VendorId    ,'Commision Earned VAT'   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,dt.DivisionID   --DivisionId    ,ctpp.ScoaProjectID          --CreditScoaProjectId    ,piCt.SCOAItemID   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,piCt.SCOAFunctionId  --CreditFunctionId    ,piCt.SCOAFundId   --CreditFund    ,piCt.SCOARegionId   --CreditRegion    ,dt.ProjectID    --ProjectId Dt    ,dt.PlanProjectItem_ID     --PlanProjectItemId Dt    ,piCt.ProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct     from    (select piDt.PlanProjectItem_Id,     SUM(tr.Amount)Amount,    SUM(tr.CommAmount) CommAmount,    SUM(tr.VatAmount) vatAmount,    piDt.SCOACostingID        ,pos.FunctionID SCOAFunctionId      ,@VatFundID SCOAFundId          ,pos.RegionID SCOARegionId        ,IsNULL(empType.SalaryProjectID, gl.SCOAProjectID) ProjectId          ,IsNULL(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID)SuspenseScoaItemID ,pp.ScoaProjectID,pos.DivisionID     from(     select * from @PayrollResults     )tr    join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1    join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID    join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id    join Payroll_Position pos       on pos.Position_ID = emp.PositionID    left join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID, SCOAFundId ,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piDt       on piDt.SCOAItemID = IsNULL(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID)       and piDt.ProjectId = IsNULL(empType.SalaryProjectID, gl.SCOAProjectID)       and piDt.SCOARegionId = pos.RegionID       and piDt.SCOAFunctionId = pos.FunctionID       and piDt.DivisionId = pos.DivisionID       and pidt.SCOAFundId = @VatFundID    left join plan_project pp      on pp.Project_id = piDt.ProjectID    group by PlanProjectItem_Id,piDt.SCOACostingID        ,pos.FunctionID      ,piDt.PlanProjectItem_Id,gl.SuspenseScoaItemID,pp.ScoaProjectID,pos.DivisionID          ,pos.RegionID        ,empType.SalaryProjectID,gl.SCOAProjectID,empType.SalarySuspenseScoaItemId )dt        left join Plan_ProjectItem piCt      on piCt.PlanProjectItem_ID = @VATProjectItemId    left join plan_project ctpp      on ctpp.Project_id = piCt.ProjectID      END    --Validate ScoaInfo  DECLARE @invalidStrings int = (Select count(TransactionGroup_ID) from Payroll_TransactionsGroup where PeriodID = @PeriodID and VendorID = @VendorId and (IsNULL(PlanProjectItemID,0) = 0 OR isnull(ContraPlanProjectItemId,0)=0))      Insert Into Payroll_MissingStrings  select @PeriodID,getdate(),132,SCOAItemID,ProjectID,DivisionID,SCOAFunctionID,SCOAFundsID,SCOARegionID,1,null,null,null from Payroll_TransactionsGroup where PeriodId = @PeriodID and VendorID = @VendorId and DocumentTypeID = 132 and isnull(PlanProjectItemID,0) = 0  Insert Into Payroll_MissingStrings  select @PeriodID,getdate(),132,ContraSCOAItemID,ContraProjectId,ModifierID,ContraSCOAFunctionID,ContraSCOAFundingID,ContraSCOARegionID,0,null,null,null from Payroll_TransactionsGroup where PeriodId = @PeriodID and VendorID = @VendorId and DocumentTypeID = 132 and isnull(ContraPlanProjectItemId,0) = 0    if(@invalidStrings > 0)  BEGIN   delete from Payroll_TransactionsGroup where PeriodID = @PeriodID and VendorID = @VendorId and DocumentTypeID = 132    select cast(0 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(null as tinyint) as [ErrorGroup], cast(null as nvarchar(max)) as [ErrorMessage], cast(null as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast(null as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]   commit  END  ELSE  BEGIN  declare @StatusID int = (select Status_ID from Const_SCMVendorStatus_sys where Enabled = 1 and (Module = 'SCMInvoice' or Module = 'Invoice') and Status = ( select top 1 'Level' + Cast(ApprovalLevel as nvarchar(10)) from SCM_InvoiceApprovalSetup where IsEnabled = 1 and IsApproval = 1 order by ApprovalLevel desc))  declare @UserProcessingMonth INT = @LedgerMonth  declare @VoteSectionID int = (Select VoteSection_ID from dbo.Const_VoteSection_Sys with(nolock) where VoteSectionDesc = 'Payroll')  declare @CashbookId int = (Select CashBookID from Payroll_Municipality)  declare @RecordID int  declare @comments varchar(50) = case when @ConsolidatedEft = 1 then 'ConsolidatedEFT' else '' End       --***************************************************Create Invoice Header ***************************************************  insert into dbo.SCM_Invoice       ( InvoiceDate,     StatusID,     FinancialYear,     ProcessingMonth,    VoteSectionID,     VendorCreditorID,     PayrollPeriodID,     Enabled,     DateCaptured,     CapturerID,     ApprovedBy,     ApprovedDate ,     DocNumber,     Comments,     VendorInvoiceNumberCustom,    PaymentReference,    CashbookId,    FinalApprovedBy,    FinalApprovedDate       )    SELECT GetDate(),@StatusId,@finyear,@UserProcessingMonth, @VoteSectionId,@VendorId, @PeriodId,1,Getdate(),@UserId,@UserId,Getdate(),@DocNumber,@comments,@DocNumber,@PaymentReference,@CashbookId,@UserId,GetDAte()    select  @RecordID = @@Identity    EXEC SCM_GenerateInvoiceNumber_sp @RecordID  --Get Invoice No.    --***************************************************Create Invoice Detail ***************************************************  --NB - I'm adding the ScoaFundId in the cancelReason field in order to update the InvoiceDetailsFund table  if @ConsolidatedEFT = 1  begin  insert into dbo.SCM_InvoiceDetail    (QuantityOrder, QuantityReceived, InvoiceID, ItemDescription, UnitPrice, ReceivedUnitPrice, Amount, VatInclude, VatAmount, TotalAmount, VoteId,Enabled,DateCaptured,     CapturerID, StatusID, CancelReason, EmployeeID, SCOACostingID, SCOAFunctionID, SCOAItemID, SCOAProjectID, SCOARegionID, ApprovedBy, ApprovedDate, PlanProjectItemId, DivisionId)     select 1,1,@RecordId,SalaryTitle,Amount,Amount,Amount,0,0,Amount,Vote_ID,1,Getdate(),    @UserID,@StatusId,CAST(ContraScoaFundingId AS varchar(10)),TrialResultId,ContraScoaCostingId,     ContraScoaFunctionId,ContraScoaItemID,ContraScoaProjectId,ContraScoaRegionId,@UserID,GetDate(),PlanProjectItemId,DivisionId      from (select SalaryHeadId,   CASE     WHEN @HasPayrollCommission = 1 AND @CommPercentage > 0 THEN SUM(Amount)-SUM(CommAmount)    ELSE SUM(Amount)   END AS Amount,   SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId ,TrialResultId      from @PayrollResults      group by SalaryHeadId, SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId,TrialResultId)PayrollResults        left outer join Led_Vote lv     on lv.ScoaItemID = PayrollResults.ContraSCoaItemId AND FinYear = @finyear       end  else  begin  insert into dbo.SCM_InvoiceDetail    (QuantityOrder, QuantityReceived, InvoiceID, ItemDescription, UnitPrice, ReceivedUnitPrice, Amount, VatInclude, VatAmount, TotalAmount, VoteId,Enabled,DateCaptured,     CapturerID, StatusID, CancelReason, EmployeeID, SCOACostingID, SCOAFunctionID, SCOAItemID, SCOAProjectID, SCOARegionID, ApprovedBy, ApprovedDate, PlanProjectItemId, DivisionId)     select 1,1,@RecordId,SalaryTitle,Amount,Amount,Amount,0,0,Amount,Vote_ID,1,Getdate(),@UserID,@StatusId,CAST(ContraScoaFundingId AS varchar(10)),NULL,ContraScoaCostingId,     ContraScoaFunctionId,ContraScoaItemID,ContraScoaProjectId,ContraScoaRegionId,@UserID,GetDate(),PlanProjectItemId,DivisionId      from (select SalaryHeadId,   CASE     WHEN @HasPayrollCommission = 1 AND @CommPercentage > 0 THEN SUM(Amount)-SUM(CommAmount)    ELSE SUM(Amount)   END AS Amount,   SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId       from @PayrollResults      group by SalaryHeadId, SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId)PayrollResults        left outer join Led_Vote lv     on lv.ScoaItemID = PayrollResults.ContraSCoaItemId AND FinYear = @finyear   end  --***************************************************Create SCM_VendorInvoiceHistory *****************************************  insert into SCM_VendorInvoiceHistory   (VendorId,InvoiceId,InvoiceNumber,InvoiceDate,InvoiceTotalAmount,OutstandingInvoiceAmount,PaymentStatus,CaptureId,CaptureDate,VatAmount)    select VendorCreditorID, Invoice_ID, VendorInvoiceNumber, InvoiceDate, (select SUM(TotalAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID),(select SUM(TotalAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID), @StatusId,    @UserId, GETDATE(), (select SUM(VatAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID)    from SCM_Invoice where Invoice_ID = @RecordId    --***************************************************Create SCM_InvoiceDetailsFund ****************************************  insert  into dbo.SCM_InvoiceDetailsFund    ( InvoiceDetailID, SCOAFundID, Percentage, CapturerID, DateCaptured )    select InvoiceDetail_ID, CAST(CancelReason AS int),100,@UserId,Getdate() from SCM_InvoiceDetail where InvoiceId = @RecordId    --***************************************************Create SCM_Payroll_InvoiceDetails for 3rd Party report *****************  insert into SCM_Payroll_InvoiceDetails   select v1.EmployeeId,invoiceid,SalaryTitle,EmployeeAmount,EmployerAmount,PeriodId,ReferenceNo, case when @CommPercentage > 0 then CommAmount else 0 end  from(    select pr.EmployeeID,@RecordId invoiceid,SalaryTitle,      Case when pr.TransactionTypeID = 2 then pr.Amount Else 0 end as EmployeeAmount,      Case when pr.TransactionTypeID = 3 then pr.Amount Else 0 end as EmployerAmount,      CommAmount,      @periodId periodId,pr.calculation ReferenceNo    from      @PayrollResults pr   )v1    --***************************************************Create Payroll_Transactions *******************************************************************************  insert into Payroll_Transactions (TransactionDate, EmployeeID, VoteId, DebitAmount, CreditAmount, PeriodID, TransactionTypeID, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAFunctionID, SCOAItemID  , DateCaptured, CapturerID, ContraVoteID, EmployeePayrollDefinitionID, EntryGoesDirectlyToLedger, VendorID, SalaryHeadID, ReferenceNo, DivisionID, TrialResultID, MatchTranGuid, DocNumber, Authorized, Enabled,TransactionsGroupID)      --debit leg  select  GETDATE() AS TrxDate1        ,TR.EmployeeID         ,lv.Vote_ID        ,tr.Amount        ,0.00 CT        ,@PeriodId        ,TransactionTypeID        ,piDt.SCOAFundId        ,piDt.SCOARegionID        ,piDt.SCOACostingID        ,dtProject.SCOAProjectID        ,piDt.SCOAFunctionID        ,piDt.ScoaItemId        ,GETDATE() TrxDate        ,@UserID UserId        ,piCt.SCOAItemID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.DivisionID        ,TR.TrialResultID        ,null --group matchguid        ,null --group doc number        ,0 Auth         ,1 Enabled        ,null --groupid  from     @PayrollResults tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piDt       on piDt.ScoaItemId = gl.SuspenseScoaItemID and piDT.ProjectId = gl.SCOAProjectID and piDT.SCOARegionId = pos.RegionID and piDT.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID      join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID     join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piCt       on piCt.SCOAItemID = gl.VendorScoaId and piCt.ProjectId = gl.VendorScoaProjectId and piCt.SCOARegionId = pos.RegionID and piCt.SCOAFunctionId = pos.FunctionID and piCt.DivisionId = pos.DivisionID      join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID     join Led_vote lv      on lv.SCOAItemID = piDt.SCOAItemID and lv.Finyear = @finyear     join Payroll_EmployeePayrollDefinition EPD             on tr.SalaryHeadID = EPD.PayrollSalaryHeadID and EPD.EmployeeID = TR.EmployeeID and epd.Enabled = 1  UNION ALL  --credit leg  select  GETDATE() AS TrxDate1        ,TR.EmployeeID         ,lv.Vote_ID        ,0.00        ,tr.Amount        ,@PeriodId        ,TransactionTypeID        ,piCt.SCOAFundId        ,piCt.SCOARegionID        ,piCt.SCOACostingID        ,ctProject.SCOAProjectID        ,piCt.SCOAFunctionID        ,piCt.ScoaItemId        ,GETDATE() TrxDate        ,@UserID UserId        ,piDt.SCOAItemID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.DivisionID        ,TR.TrialResultID        ,null --group matchguid        ,null --group doc number        ,0 Auth         ,1 Enabled        ,null --groupid  from     @PayrollResults tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piDt       on piDt.ScoaItemId = gl.SuspenseScoaItemID and piDT.ProjectId = gl.SCOAProjectID and piDT.SCOARegionId = pos.RegionID and piDT.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionId     join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID     join (select Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID from Plan_ProjectItem       where FinYear = @Finyear      group by FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID      ) piCt       on piCt.SCOAItemID = gl.VendorScoaId and piCt.ProjectId = gl.VendorScoaProjectId and piCt.SCOARegionId = pos.RegionID and piCt.SCOAFunctionId = pos.FunctionID and piCt.DivisionId = pos.DivisionId     join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID     join Led_vote lv      on lv.SCOAItemID = piCt.SCOAItemID and lv.Finyear = @finyear     join Payroll_EmployeePayrollDefinition EPD             on tr.SalaryHeadID = EPD.PayrollSalaryHeadID and EPD.EmployeeID = TR.EmployeeID and epd.Enabled = 1    --***************************************************Cursor to update TransactionGroupId's in Payroll_Transactions *********************************************    declare @grpTransactionGroupId int, @dtScoaFundsId int, @dtScoaRegionId int,@dtScoaCostingId int,@dtScoaPRojectId int,@dtScoaFunctionId int, @dtScoaItemID int,@ctScoaFundsId int,     @ctScoaRegionId int,@ctScoaCostingId int,@ctScoaPRojectId int,@ctScoaFunctionId int, @ctScoaItemID int,@grpSalaryHeadId int,@grpMatchTranGuid uniqueidentifier, @grpDocNumber varchar(10),@trvendorId int    declare payrollcursor cursor for      select TransactionGroup_Id, ScoaFundsId, ScoaRegionId,ScoaCostingId,ScoaPRojectId,ScoaFunctionId, ScoaItemID,ContraSCOAFundingID, ContraSCOARegionID,ContraSCOACostingID,ContraSCOAProjectID,        ContraSCOAFunctionID, ContraSCOAItemID,SalaryHeadId,MatchTranGuid, DocNumber,vendorId      from payroll_transactionsgroup where DocumentTypeId = 132 and PeriodId = @PeriodId and VendorID = @VendorId    open payrollcursor;      fetch next from payrollcursor into @grpTransactionGroupId, @dtScoaFundsId, @dtScoaRegionId,@dtScoaCostingId,@dtScoaPRojectId,@dtScoaFunctionId, @dtScoaItemID, @ctScoaFundsId, @ctScoaRegionId,@ctScoaCostingId,@ctScoaPRojectId,      @ctScoaFunctionId, @ctScoaItemID, @grpSalaryHeadId,@grpMatchTranGuid, @grpDocNumber,@trvendorId    while @@FETCH_STATUS = 0      begin  --update debit entries   update payroll_transactions set TransactionsgroupId = @grpTransactionGroupId, DocNumber = @grpDocNumber, MatchTranGuid = @grpMatchTranGuid      where periodid = @periodid and debitAmount > 0 and SCoaFundsId = @dtScoaFundsId and SCOARegionID = @dtScoaRegionId and SCOACostingID = @dtScoaCostingId       and SCOAProjectID = @dtScoaPRojectId and SCOAFunctionID = @dtScoaFunctionId and scoaitemid = @dtScoaItemID and SalaryHeadId = @grpSalaryHeadId and vendorId = @trvendorId        and DocNumber Is NULL    ----update credit entries   update payroll_transactions set TransactionsgroupId = @grpTransactionGroupId, DocNumber = @grpDocNumber, MatchTranGuid = @grpMatchTranGuid      where periodid = @periodid and CreditAmount > 0 and SCoaFundsId = @ctScoaFundsId and SCOARegionID = @ctScoaRegionId and SCOACostingID = @ctScoaCostingId       and SCOAProjectID = @ctScoaPRojectId and SCOAFunctionID = @ctScoaFunctionId and scoaitemid = @ctScoaItemID and SalaryHeadId = @grpSalaryHeadId and vendorId = @trvendorId        and

GO

-- ============================================
-- SP: Payroll_CreateTrialResults_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swapped SCOA Debit and Credit legs for JournalEntryOnly flag   Modified    :   30/07/2019 - Ferdi Botha => Swapped SCOA Debit and Credit legs for Negative Entries   Modified : 15/08/2019 - Ferdi Botha => PAYE (Bonus) Tax Spread Recouping   Modified : 23/10/2019 - Ferdi Botha => Take the first Funding Source where duplicates are returned   Modified : 28/11/2019 - Ferdi Botha => Fringe Benifits did not write to the Trial Results causing PAYE Calculation issues   Modified : 2022/03/15 - Richa M => Trial Results duplicate if an employee has more than 1 Provident/Pension fund   Modified : 2023/04/29 - Richa M => Get Salary Control Id's from EmployeeType       Modified :   2024/01/30 - Richa M = Change SP to be in line with fundId changes (WI106438)    */  CREATE procedure [dbo].[Payroll_CreateTrialResults_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try     update const_employeetype_sys set SalaryProjectId = NULL where SalaryProjectId = 0   update const_employeetype_sys set SalarySuspenseScoaItemId = NULL where SalarySuspenseScoaItemId = 0   update const_employeetype_sys set SalarySuspenseScoaITemCreditId = NULL where SalarySuspenseScoaITemCreditId = 0   update payroll_employee set Enabled = 1 where Enabled = 0       declare @SCOAMonth tinyint = (select cast([KeyValue] as tinyint) from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'FinYearStartMonth')),      @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality] with(nolock)),      @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock))        declare @payrollTrialResults table (       [PeriodID] int null,     [TaxPeriod] tinyint null,     [EmployeeID] int null,     [CycleID] int null,     [PositionID] int null,     [TransactionTypeID] int null,     [IRP5CodeID] int null,     [SalaryHeadID] int null,     [VendorID] int null,     [PaymentTypeID] int null,     [DivisionID_DT] int null,     [DivisionID_CT] int null,     [SCOAProjectItemID_DT] int null,     [SCOAProjectItemID_CT] int null,     [SCOAProjectID_DT] int null,     [SCOAProjectID_CT] int null,     [SCOAItemID_DT] int null,     [SCOAItemID_CT] int null,     [SCOAFunctionID_DT] int null,     [SCOAFunctionID_CT] int null,     [SCOARegionID_DT] int null,     [SCOARegionID_CT] int null,     [SCOAFundID_DT] int null,     [SCOAFundID_CT] int null,     [SCOACostID_DT] int null,     [SCOACostID_CT] int null,     [JournalEntryOnly] bit not null default(0),     [SCOAProjectID] int null,     [Percentage] decimal(18, 2) null,     [Value] decimal(18, 2) null,     [TaxSavePurpose] bit not null,     [MOCDetailID] int null,     [PositionDesc] varchar(200) null,     [SalaryHeadTitleAddendum] nvarchar(200) null,     [ReferenceNo] nvarchar(50) null,     [IsRFI] BIT NOT NULL,     [ProjectId] INT null,     [ContraProjectId] INT null,     [ContraDivisionId] INT null    )      declare @employeeSplits table (       [PositionID] int null,     [Percentage] decimal(18, 2) null      )      declare @splitValues table (     [EmployeeId] int,     [SalaryHeadID] int,     [SalaryHeadTitleAddendum] nvarchar(100),     [Total] decimal (18,2)      )      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]       Select  [PlanProjectItem_ID]PlanProjectItemID, [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID],[SCOAFundId] into  [#Plan_ProjectItem] from Plan_ProjectItem where PlanProjectItem_ID in(     select ppi.PlanProjectItemID from(       select min([PlanProjectItem_ID]) as [PlanProjectItemID], [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID]          from [Plan_ProjectItem] with(nolock)          where ([FinYear] = @SCOAYear)           group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID] )ppi)         if (not object_id('tempdb..#Plan_ProjectItemCt') is null)       drop table [#Plan_ProjectItemCt]      select min([PlanProjectItem_ID])PlanProjectItem_ID, [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOAFundId], [SCOACostingID] into [#Plan_ProjectItemCt]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @SCOAYear)        group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID],[SCOAFundId]        /* DIVISION */     INSERT INTO @payrollTrialResults(      [PeriodID], [TaxPeriod], [EmployeeID], [CycleID], [PositionID],      [TransactionTypeID], [IRP5CodeID], [SalaryHeadID], [VendorID], [PaymentTypeID],      [DivisionID_DT], [DivisionID_CT],      [SCOAProjectItemID_DT], [SCOAProjectItemID_CT],      [SCOAProjectID_DT], [SCOAProjectID_CT],      [SCOAItemID_DT], [SCOAItemID_CT],      [SCOAFunctionID_DT], [SCOAFunctionID_CT],      [SCOARegionID_DT], [SCOARegionID_CT],      [SCOAFundID_DT], [SCOAFundID_CT],      [SCOACostID_DT], [SCOACostID_CT],      [JournalEntryOnly], [SCOAProjectID],      [Percentage], [Value], [TaxSavePurpose], [MOCDetailID],      [PositionDesc], [SalaryHeadTitleAddendum], [ReferenceNo], [IsRFI],      [ProjectId], [ContraProjectId], [ContraDivisionId]     )     SELECT      @PeriodID,      CAST(TP.[Month] AS TINYINT),      TP.[EmployeeID],      PE.[CycleID],      PE.[PositionID],      IRP5.[TransactionTypeID],      IRP5.[IRP5Code_ID],      SH.[SalaryHead_ID],      CASE       WHEN IRP5.[TransactionTypeID] IN (1,4) THEN NULL       ELSE TP.[VendorID]      END,      PE.[PaymentTypeID],        /* DivisionID_DT */      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1        THEN ISNULL(TP.[DivisionId], ISNULL(GL.[ScoaDivisionId], POS.[DivisionID]))       ELSE ISNULL(TP.[DivisionId], POS.[DivisionID])      END,        /* DivisionID_CT  */      CASE       WHEN IRP5.[TransactionTypeID] = 2 AND GL.[JournalEntryOnly] = 1         THEN GL.[ScoaDivisionId]       ELSE ISNULL(TP.[DivisionId], POS.[DivisionID])      END,        /* SCOAProjectItemID_DT / CT (from your joins) */      PI.[PlanProjectItemID],      PC.[PlanProjectItem_ID],        /* SCOAProjectID_DT (Debit Project) */      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1        THEN ISNULL(TP.[ProjectId], ISNULL(GL.[SCOAItemProjectID], POS.[ProjectID]))       WHEN [IRP5].[TransactionTypeID] IN (1,3) AND PE.EmployeeTypeID <> 1        THEN ISNULL(TP.ProjectId,  POS.ProjectID)       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SCOAProjectID]       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 0        THEN ISNULL(ET.[SalaryProjectId], @SalaryProjectID)      END,        /* SCOAProjectID_CT (credit stays GL-driven, unchanged) */      CASE       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SCOAItemProjectID]       ELSE GL.[SCOAProjectID]      END,        /* SCOAItemID_DT */      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) THEN        CASE PE.[EmployeeTypeID]         WHEN 1 THEN ISNULL(TP.[ScoaItemId], GL.[ScoaItemIDPermanentStaff])         WHEN 2 THEN ISNULL(TP.[ScoaItemId], ST.[GLScoaItem])         WHEN 3 THEN ISNULL(TP.[ScoaItemId], ST.[GLScoaItem])         WHEN 6 THEN ISNULL(TP.[ScoaItemId], GL.[ScoaItemIDPostRetirement])         WHEN 7 THEN ISNULL(TP.[ScoaItemId], ST.[GLScoaItem])        END       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SuspenseScoaItemID]       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 0        THEN ISNULL(ET.[SalarySuspenseScoaItemID], @SalaryControlID)      END,        /* SCOAItemID_CT */      CASE       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SCOAItemID]       ELSE        CASE         WHEN IRP5.[TransactionTypeID] IN (1,3) AND ISNULL(ET.[SalarySuspenseScoaItemCreditID],0) <> 0          THEN ET.[SalarySuspenseScoaItemCreditID]         WHEN TP.[Amount] > 0          THEN GL.[SuspenseScoaItemCreditID]         ELSE GL.[SuspenseScoaItemID]        END      END,        /* SCOAFunctionID_DT (TP → GL for 1/3 → POS) */      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1        THEN ISNULL(TP.[FunctionId], ISNULL(GL.[ScoaFunctionId], POS.[FunctionID]))       ELSE ISNULL(TP.[FunctionId], POS.[FunctionID])      END,        /* SCOAFunctionID_CT */      CASE       WHEN GL.[JournalEntryOnly] = 1        THEN GL.[ScoaFunctionId]       ELSE  ISNULL(TP.[FunctionId], POS.[FunctionID])           END,        /* SCOARegionID_DT*/      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1        THEN ISNULL(TP.[RegionId], ISNULL(GL.[ScoaRegionId], POS.[RegionID]))       ELSE ISNULL(TP.[RegionId], POS.[RegionID])      END,        /* SCOARegionID_CT */      CASE       WHEN GL.[JournalEntryOnly] = 1        THEN GL.[ScoaRegionId]        ELSE ISNULL(TP.[RegionId], POS.[RegionID])        END,        /* Fund & Costing (from matched Plan items) */      COALESCE(       TP.FundId,       CASE         WHEN IRP5.TransactionTypeID IN (1,3)           AND PE.EmployeeTypeID = 1           AND GL.ScoaFundId IS NOT NULL           AND TP.FundId IS NULL         THEN GL.ScoaFundId       END,       PI.SCOAFundId      ) AS SCOAFundID_DT,        -- SCOAFundID_CT (mirror DT side for consistency)      COALESCE(       TP.FundId,       CASE         WHEN IRP5.TransactionTypeID IN (1,3)           AND PE.EmployeeTypeID = 1           AND GL.ScoaFundId IS NOT NULL           AND TP.FundId IS NULL         THEN GL.ScoaFundId       END,       PI.SCOAFundId      ) AS SCOAFundID_CT,      PI.[SCOACostingID],      PC.[SCOACostingID],        ISNULL(GL.[JournalEntryOnly], 0),      GL.[SCOAProjectID],      0,      TP.[Amount],      TP.[TaxSavePurpose],      TP.[MOCDetailID],      POS.[PositionDesc],      TP.[SalaryHeadTitleAddendum],      TP.[ReferenceNo],      IIF(EBD.EmployeeBenefit_ID IS NOT NULL AND BDSH.Id IS NOT NULL, 1, SH.IsRFI) AS IsRFI,        /* ProjectId (repeat debit project logic here) */      CASE       WHEN IRP5.[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1        THEN ISNULL(TP.[ProjectId], ISNULL(GL.[SCOAItemProjectID], POS.[ProjectID]))       WHEN [IRP5].[TransactionTypeID] IN (1,3) AND PE.EmployeeTypeID <> 1        THEN ISNULL(TP.ProjectId,  POS.ProjectID)       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SCOAProjectID]       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 0        THEN ISNULL(ET.[SalaryProjectId], @SalaryProjectID)      END,        /* ContraProjectId (unchanged – CT side is GL-driven) */      CASE       WHEN IRP5.[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1        THEN GL.[SCOAItemProjectID]       ELSE GL.[SCOAProjectID]      END,        /* ContraDivisionId */      CASE       WHEN IRP5.[TransactionTypeID] = 2 AND GL.[JournalEntryOnly] = 1 THEN GL.[ScoaDivisionId]       ELSE  ISNULL(TP.[DivisionId], POS.[DivisionID])      END      from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1              LEFT JOIN Payroll_EmpBenefitDetail AS EBD WITH(NOLOCK) ON PE.Employee_ID = EBD.EmployeeId AND EBD.Enabled = 1 AND EBD.JoinDate <= @EndDate AND ISNULL(EBD.TerminationDate, @StartDate) >= @StartDate and IsPrivate = 0 and EBD.ReferenceNo = TP.ReferenceNo              LEFT JOIN [Payroll_BenefitDetail_SalaryHead] AS BDSH WITH(NOLOCK) ON SH.SalaryHead_ID = BDSH.SalaryHeadId AND EBD.BenefitSchemeID = BDSH.BenefitId          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID] and [EP].[Cycle_ID] = @CycleID         join [Const_EmployeeType_sys] as [ET] with (nolock) on [ET].EmployeeType_ID = [PE].[EmployeeTypeID]              /* DEBIT ITEM */        LEFT OUTER JOIN [#Plan_ProjectItem] AS [PI] WITH (NOLOCK) ON          -- Division         [PI].[DivisionId] =          CASE WHEN [IRP5].[TransactionTypeID] IN (1,3) AND PE.EmployeeTypeID = 1            THEN ISNULL(TP.DivisionId, ISNULL(GL.ScoaDivisionId, POS.DivisionID))            ELSE ISNULL(TP.DivisionId, POS.DivisionID)          END         -- Project        AND [PI].[ProjectID] =          CASE           WHEN [IRP5].[TransactionTypeID] IN (1,3) AND PE.EmployeeTypeID = 1            THEN ISNULL(TP.ProjectId, ISNULL(GL.SCOAItemProjectID, POS.ProjectID))           WHEN [IRP5].[TransactionTypeID] IN (1,3) AND PE.EmployeeTypeID <> 1            THEN ISNULL(TP.ProjectId,  POS.ProjectID)           WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1            THEN GL.SCOAProjectID           WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 0            THEN ISNULL(ET.SalaryProjectId, @SalaryProjectID)          END         -- Scoa Item          AND [PI].[SCOAItemID] =          CASE           WHEN [IRP5].[TransactionTypeID] IN (1,3) THEN            CASE PE.EmployeeTypeID             WHEN 1 THEN ISNULL(TP.ScoaItemId, GL.ScoaItemIDPermanentStaff)             WHEN 2 THEN ISNULL(TP.ScoaItemId, ST.GLScoaItem)             WHEN 3 THEN ISNULL(TP.ScoaItemId, ST.GLScoaItem)             WHEN 6 THEN ISNULL(TP.ScoaItemId, GL.ScoaItemIDPostRetirement)             WHEN 7 THEN ISNULL(TP.ScoaItemId, ST.GLScoaItem)            END           WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1            THEN GL.SuspenseScoaItemID           WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 0            THEN ISNULL(ET.SalarySuspenseScoaItemID, @SalaryControlID)          END         -- Function        AND [PI].[SCOAFunctionId] =          CASE WHEN [IRP5].[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1             THEN ISNULL(TP.FunctionId, ISNULL(GL.ScoaFunctionId, POS.FunctionID))            ELSE ISNULL(TP.FunctionId, POS.FunctionID)          END         -- Region        AND [PI].[SCOARegionId] =          CASE WHEN [IRP5].[TransactionTypeID] IN (1,3) and PE.EmployeeTypeID = 1             THEN ISNULL(TP.RegionId, ISNULL(GL.ScoaRegionId, POS.RegionID))            ELSE ISNULL(TP.RegionId, POS.RegionID)          END         -- fund        AND (            -- If neither TP.FundId nor (eligible) GL.ScoaFundId is present, don't restrict fund (use the first in PI)            COALESCE(             TP.FundId,             CASE WHEN IRP5.TransactionTypeID IN (1,3) AND PE.EmployeeTypeID = 1 THEN GL.ScoaFundId END            ) IS NULL              -- Otherwise, enforce equality to whichever won the priority above            OR PI.SCOAFundId = COALESCE(             TP.FundId,             CASE WHEN IRP5.TransactionTypeID IN (1,3) AND PE.EmployeeTypeID = 1 THEN GL.ScoaFundId END            )         )         /* CREDIT ITEM */        LEFT OUTER JOIN #Plan_ProjectItemCt AS [PC] WITH (NOLOCK)          ON [PC].[ScoaFundId] = [PI].[ScoaFundId]             -- Division           AND [PC].[DivisionId] = CASE          WHEN [IRP5].[TransactionTypeID] = 2 AND [GL].[JournalEntryOnly] = 1            THEN [GL].[ScoaDivisionId]                                               ELSE            ISNULL([TP].[DivisionId], [POS].[DivisionID])           END            -- Project           AND [PC].[ProjectID] = CASE          WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1            THEN [GL].[SCOAItemProjectID]          ELSE [GL].[SCOAProjectID]           END            -- Item           AND [PC].[SCOAItemID] = CASE          WHEN [IRP5].[TransactionTypeID] = 2 AND [JournalEntryOnly] = 1            THEN [GL].[SCOAItemID]          ELSE            CASE            WHEN [IRP5].[TransactionTypeID] IN (1,3) AND ISNULL([ET].[SalarySuspenseScoaItemCreditID],0) <> 0              THEN [ET].[SalarySuspenseScoaItemCreditID]            WHEN [TP].[Amount] > 0              THEN [GL].[SuspenseScoaItemCreditID]            ELSE [GL].[SuspenseScoaItemID]           END           END            -- Function           AND [PC].[SCOAFunctionId] = CASE          WHEN [GL].[JournalEntryOnly] = 1            THEN [GL].[ScoaFunctionId]                                             ELSE             ISNULL([TP].[FunctionId], [POS].[FunctionID])           END            -- Region          AND [PC].[SCOARegionId] = CASE          WHEN [GL].[JournalEntryOnly] = 1            THEN [GL].[ScoaRegionId]                                                ELSE            ISNULL([TP].[RegionId], [POS].[RegionID])           END         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[PeriodID] = @PeriodID and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]        where ([TP].[EmployeeID] = (case @EmployeeID          when 0 then [TP].[EmployeeID]          else @EmployeeID         end) and [TP].[PeriodID] = @PeriodID and (case          when @CycleModeID = 1 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1           else 0          end)          when @CycleModeID = 2 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0           else 1          end)          else 0         end) = 1)      /* DIVISION SPLITS */    insert into @payrollTrialResults([PeriodID], [TaxPeriod], [EmployeeID], [CycleID], [PositionID], [TransactionTypeID], [IRP5CodeID], [SalaryHeadID], [VendorID], [PaymentTypeID], [DivisionID_DT], [DivisionID_CT], [SCOAProjectItemID_DT], [SCOAProjectItemID_CT], [SCOAProjectID_DT], [SCOAProjectID_CT], [SCOAItemID_DT], [SCOAItemID_CT], [SCOAFunctionID_DT], [SCOAFunctionID_CT], [SCOARegionID_DT], [SCOARegionID_CT], [SCOAFundID_DT], [SCOAFundID_CT], [SCOACostID_DT], [SCOACostID_CT], [JournalEntryOnly], [SCOAProjectID], [Percentage], [Value], [TaxSavePurpose], [MOCDetailID], [PositionDesc], [SalaryHeadTitleAddendum], [ReferenceNo], [IsRFI],[ProjectId],[ContraProjectId],[ContraDivisionId])       select [TR].[PeriodID], [TR].[TaxPeriod], [TR].[EmployeeID], [TR].[CycleID], [JPD].[PositionID], [TR].[TransactionTypeID], [TR].[IRP5CodeID], [TR].[SalaryHeadID], [TR].[VendorID], [TR].[PaymentTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[PlanProjectItemID], [PC].[PlanProjectItemID], [PI].[ProjectID], [PC].[ProjectID], [PI].[SCOAItemID], [PC].[SCOAItemID], [PI].[SCOAFunctionId], [PC].[SCOAFunctionId], [PI].[SCOARegionId], [PC].[SCOARegionId], [PI].[SCOAFundId], [PC].[SCOAFundId], [PI].[SCOACostingID], [PC].[SCOACostingID], [TR].[JournalEntryOnly], [TR].[SCOAProjectID], isnull([JPD].[CostPercentage], 0),        [TR].[Value] * (isnull([JPD].[CostPercentage], 0) / 100), [TR].[TaxSavePurpose], [TR].[MOCDetailID],        [TR].[PositionDesc], [TR].[SalaryHeadTitleAddendum], [TR].[ReferenceNo], [TR].[IsRFI],[PI].[ProjectId],[PC].[ProjectId],[PC].[DivisionId]        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)         join @payrollTrialResults as [TR] on [TR].[PositionID] = [JPD].[PositionId]         join Payroll_Employee [EMP] on [EMP].[Employee_ID] = [TR].[EmployeeID]         join Const_EmployeeType_sys [ET] on [ET].EmployeeType_ID = EMP.EmployeeTypeID           /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [JPD].[DivisionID] and [PI].[ProjectID] = (case          when [TR].[TransactionTypeID] in(1, 3) then [JPD].[ProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1 then [TR].[SCOAProjectID_DT]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 0 then IsNULL([ET].[SalaryProjectId],@SalaryProjectID)         end) and [PI].[SCOAItemID] = [TR].[SCOAItemID_DT] and [PI].[SCOAFunctionId] = [JPD].[SCOAFunctionId] and [PI].[SCOARegionId] = [JPD].[SCOARegionId]         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = (              case when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1               then [TR].[DivisionID_CT] ELSE [JPD].[DivisionID] end) and               [PC].[ProjectID] = [TR].[SCOAProjectID_CT] and [PC].[SCOAItemID] = [TR].[SCOAItemID_CT] and [PC].[SCOAFunctionId] = (case          when [TR].[JournalEntryOnly] = 1 then [TR].[SCOAFunctionID_CT]          else [JPD].[SCOAFunctionId]         end) and [PC].[SCOARegionId] = (case          when [TR].[JournalEntryOnly] = 1 then [TR].[SCOAFunctionID_CT]          else [JPD].[SCOARegionId]         end)        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate)      /* DIVISION SPLITS (REMAINING PERCENTAGE) */    insert into @employeeSplits([PositionID], [Percentage])       select [JPD].[PositionId], sum(isnull([JPD].[CostPercentage], 0))        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate and [JPD].[PositionId] in(         select distinct [PositionId]          from @payrollTrialResults))         group by [JPD].[PositionId]      insert into @splitValues    select EmployeeID, SalaryHeadID,SalaryHeadTitleAddendum,sum(Value)Total          from @payrollTrialResults pr        join @employeeSplits es on es.PositionID = pr.PositionID and pr.Percentage <> 0      group by SalaryHeadID,SalaryHeadTitleAddendum,EmployeeID        update [TR] set [Percentage] = (100 - [ES].[Percentage]), [Value] = Value - Total       from @payrollTrialResults as [TR]        join @employeeSplits as [ES] on [ES].[PositionID] = [TR].[PositionID]        join @splitValues [Sp] on sp.SalaryHeadID = Tr.SalaryHeadID and sp.EmployeeId = tr.EmployeeID and tr.SalaryHeadTitleAddendum = sp.SalaryHeadTitleAddendum       where ([TR].[Percentage] = 0 and [ES].[Percentage] > 0)      /* UPDATE SCOA PROJECT ID (DEBIT ITEM) */    update [TR] set [SCOAProjectID_DT] = [PP].[ScoaProjectID]       from @payrollTrialResults as [TR]        join [Plan_Project] as [PP] on [PP].[Project_ID] = [TR].[SCOAProjectID_DT]      /* UPDATE SCOA PROJECT ID (CREDIT ITEM) */    update [TR] set [SCOAProjectID_CT] = [PP].[ScoaProjectID]       from @payrollTrialResults as [TR]        join [Plan_Project] as [PP] on [PP].[Project_ID] = [TR].[SCOAProjectID_CT]      /* WRITE TRIAL RUN ENTRIES */    insert into [Payroll_TrialResults]([CycleID], [PeriodID], [EmployeeID], [DepartmentID], [DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID], [TransactionTypeID], [PaymentTypeID], [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [TaxSavePurpose], [PaymentDate], [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc], [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID], [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [ContraPlanProjectItemID], [ContraSCOAProjectID], [ContraSCOAItemID], [ContraSCOACostingID], [ContraSCOAFunctionID], [ContraSCOAFundingID], [ContraSCOARegionID], [Amount], [MOCDetailID], [IsRFI],[ProjectId],[ContraProjectId],[ContraDivisionId],[Calculation])       select [TR].[CycleID], @PeriodID, [TR].[EmployeeID], [POS].[DepartmentID], IsNULL([TR].[DivisionID_DT], [POS].[DivisionID]), [TR].[IRP5CodeID], [TR].[SalaryHeadID], [TR].[VendorID], (case         when [TR].[Value] < 0 then [TR].[SCOAItemID_DT]         else [TR].[SCOAItemID_CT]        end), [TR].[TransactionTypeID], [TR].[PaymentTypeID], 0, row_number() over (partition by [TR].[EmployeeID] order by [TR].[EmployeeID], [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID]), isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]), (case         when [SH].[SalaryHeadTitle] = [TR].[SalaryHeadTitleAddendum] and len([TR].[ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [TR].[ReferenceNo] + ')'         when [SH].[SalaryHeadTitle] = [TR].[SalaryHeadTitleAddendum] and len([TR].[ReferenceNo]) = 0 then [SH].[SalaryHeadTitle]         else [SH].[SalaryHeadTitle] + isnull(' (' + [TR].[SalaryHeadTitleAddendum] + ')', '')        end), [TR].[TaxPeriod], cast(right(@TaxYear, 4) as int), [TR].[TaxSavePurpose], @PaymentDate, @SCOAMonth, @SCOAYear, [CD].[DepartmentDesc], [CDV].[DivisionDesc],             --[PlanProjectItemID]      (case         when [TR].[Value] < 0 then [TR].[SCOAProjectItemID_CT]         else [TR].[SCOAProjectItemID_DT]        end),             --[SCOAProjectID],      (case         when [TR].[Value] < 0 then [TR].[SCOAProjectID_CT]         else [TR].[SCOAProjectID_DT]        end),               --[SCOAItemID]      (case         when [TR].[Value] < 0 then [TR].[SCOAItemID_CT]         else [TR].[SCOAItemID_DT]        end),             --[SCOACostingID]      (case         when [TR].[Value] < 0 then [TR].[SCOACostID_CT]         else [TR].[SCOACostID_DT]        end),            --[SCOAFunctionID],      (case         when [TR].[Value] < 0 then [TR].[SCOAFunctionID_CT]         else [TR].[SCOAFunctionID_DT]        end),               --[SCOAFundingID]      (case         when [TR].[Value] < 0 then [TR].[SCOAFundID_CT]         else [TR].[SCOAFundID_DT]        end),            --[SCOARegionID]      (case         when [TR].[Value] < 0 then [TR].[SCOARegionID_CT]         else [TR].[SCOARegionID_DT]        end),             --ContraPlanProjectItemID      (case         when [TR].[Value] < 0 then [TR].[SCOAProjectItemID_DT]         else [TR].[SCOAProjectItemID_CT]        end),             --[ContraSCOAProjectID],      (case         when [TR].[Value] < 0 then [TR].[SCOAProjectID_DT]         else [TR].[SCOAProjectID_CT]        end),             --[ContraSCOAItemID],      (case         when [TR].[Value] < 0 then [TR].[SCOAItemID_DT]         else [TR].[SCOAItemID_CT]        end),               --[ContraSCOACostingID],      (case         when [TR].[Value] < 0 then [TR].[SCOACostID_DT]         else [TR].[SCOACostID_CT]        end),               --[ContraSCOAFunctionID]      (case         when [TR].[Value] < 0 then [TR].[SCOAFunctionID_DT]         else [TR].[SCOAFunctionID_CT]        end),             --[ContraSCOAFundingID],      (case         when [TR].[Value] < 0 then [TR].[SCOAFundID_DT]         else [TR].[SCOAFundID_CT]        end),             --[ContraSCOARegionID]      (case         when [TR].[Value] < 0 then [TR].[SCOARegionID_DT]         else [TR].[SCOARegionID_CT]        end),             [TR].[Value],             [TR].[MOCDetailID],             [TR].[IsRFI],        --[ProjectId],      (case         when [TR].[Value] < 0 then [TR].[ContraProjectId]         else [TR].[ProjectId]        end),             --[ContraProjectId]      (case         when [TR].[Value] < 0 then [TR].[ProjectId]         else [TR].[ContraProjectId]        end),         --[ContraDivisionId]      (case         when [TR].[Value] < 0 then [TR].[DivisionID_DT]         else [TR].[DivisionID_CT]        end),            [TR].[ReferenceNo]        from @payrollTrialResults as [TR]         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [TR].[PositionID]         join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [POS].[DepartmentID]         join [Const_Division] as [CDV] with(nolock) on [CDV].[Division_ID] = [POS].[DivisionID]         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [TR].[SalaryHeadID]         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [TR].[IRP5CodeID]      update [PTH] set [PTH].[PAYEType] = [PE].[BonusCalculation]       from [Payroll_TrialRun_History_Employees] as [PTH]        join [Payroll_Employee] as [PE] on [PE].[Employee_ID] = [PTH].[Employee_ID] and [PE].[CycleID] = [PTH].[Cycle_ID]       where ([PTH].[Period_ID] = @PeriodID and [PTH].[CycleModeID] = @CycleModeID)      update [PTH] set [PTH].[PAYEValue] = [PT].[Amount]       from [Payroll_TrialRun_History_Employees] as [PTH]        join [Payroll_TrialResults] as [PT] on [PT].[EmployeeID] = [PTH].[Employee_ID] and [PT].[PeriodID] = [PTH].[Period_ID] and [PT].[CycleID] = [PTH].[Cycle_ID]        join [Payroll_CyclePeriodDetails] as [CPD] on [CPD].[Period_ID] = [PTH].[Period_ID] and [CPD].[CycleModeID] = [PTH].[CycleModeID] and [CPD].[Processed] = 0       where ([PT].[SalaryHeadID] = 3 and [PTH].[Period_ID] = @PeriodID)      update [PTH] set [PTH].[PAYEBonus] = [PT].[Amount]       from [Payroll_TrialRun_History_Employees] as [PTH]        join [Payroll_TrialResults] as [PT] on [PT].[EmployeeID] = [PTH].[Employee_ID] and [PT].[PeriodID] = [PTH].[Period_ID] and [PT].[CycleID] = [PTH].[Cycle_ID]        join [Payroll_CyclePeriodDetails] as [CPD] on [CPD].[Period_ID] = [PTH].[Period_ID] and [CPD].[CycleModeID] = [PTH].[CycleModeID] and [CPD].[Processed] = 0       where ([PT].[SalaryHeadID] = 4 and [PTH].[Period_ID] = @PeriodID)      UPDATE e     SET e.PackageAmount = up.PackageValue     FROM dbo.Payroll_Employee      AS e     JOIN dbo.Payroll_JobProfile    AS jp ON jp.JobProfile_ID = e.JobProfileID     JOIN dbo.Payroll_UpperLimit    AS up ON up.JobProfileId   = e.JobProfileID     WHERE (e.NotchId IS NULL OR e.NotchId = 0)               AND ISNULL(jp.LimitID, 0) <> 0                          AND ISNULL(e.PackageAmount, -0) <> up.PackageValue       AND e.Employee_ID in (select EmployeeId from @payrollTrialResults)      update [Payroll_TrialResults] set [Processed] = 1 where ([PeriodID] = @PeriodID)      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_CreateTrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Create the Employee Trial Simulation   Update Date : 11/04/2019 => Added Employee Trial Simulation @ Terminations  */  create procedure [Payroll_CreateTrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      insert into [Payroll_TrialRun_History_EmployeeSimulation]([SimulationType], [EmployeeID], [StartDate], [UntilDate], [EmployeeChangeID], [TerminationID], [TaxCredits])         values(@SimulationType, @EmployeeID, @StartDate, @UntilDate, (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end), (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0)     end try     begin catch     end catch     set nocount off;    end  

GO

