  CREATE PROCEDURE [dbo].[Payroll_CyclePeriodDetails_alter_tbl_sp]   AS  BEGIN     IF Not EXISTS(SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'Payroll_CyclePeriodDetails' AND COLUMN_NAME = 'PayrollEFTFileName')    BEGIN    ALTER TABLE Payroll_CyclePeriodDetails ADD PayrollEFTFileName nvarchar(100) NULL   END    END  

GO

-- ============================================
-- SP: Payroll_CyclePeriodDetailsList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: PRERANA PARMAR  -- Create date:06 JULY 2013  -- Description: Return list of Payroll Run Period  -- calls : [Payroll_CyclePeriodDetailsList_sp] '2016/2017'  -- 2015-04-23 James Roodt: Add Cycle name to data being returned  -- 2016-04-14 TP:35293 - Seipei Mathole joined table Const_Payroll_CycleMode_sys to return additional column CycleModeDesc  -- 2016-04-21 James Roodt: Change inner joins to Left Joins to cater for broken data  -- 2021-10-01 E Beetge Take financial year into account  -- 2024-08-27 Richa M - Fix financial year   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CyclePeriodDetailsList_sp]     @FinancialYear NVARCHAR(50)  AS  BEGIN    SELECT cc.CycleDesc as CycleName, Period_ID, PeriodInTaxYear, ProcessingMonth, CONVERT(NVARCHAR(15),PeriodStartDate,103) as StartDate       ,CONVERT(NVARCHAR(15),PeriodEndDate,103) as EndDate, Processed, CONVERT(NVARCHAR(15),ProcessedDate,103)AS ProcessedDate,FinancialYear,       CASE WHEN cpd.[Enabled]=1 THEN 'ACTIVE' ELSE 'IN ACTIVE' END AS [STATUS], CycleID, pcm.CycleModeDesc AS PayrollRun            FROM Payroll_CyclePeriodDetails as cpd    LEFT JOIN Const_Cycle AS cc on cc.Cycle_ID=cpd.CycleID    LEFT JOIN Const_Payroll_CycleMode_sys pcm on cpd.CycleModeID = pcm.CycleMode_ID     WHERE cpd.TaxYear = @FinancialYear  END

GO

-- ============================================
-- SP: Payroll_CyclePeriodMonthlyCycle_sp
-- Schema: dbo
-- ============================================
        -- =============================================  -- Author:  James Roodt  -- Create date: 2015-04-25  -- Description: Creates cycle periods for the rest of the payroll year for the selected cycle id  -- 2015-04-30 James Roodt: Changed paramteres for Payroll_CyclePeriodOtherCycle_sp from cycleTypeID to CycleID  -- 2015-11-02 Suri Kandukuri: Check Payroll_CyclePeriodDetails not inserting from screen and changed the condition.  -- 2015-12-04 Suri Kandukuri: Rename CycleTypeID to CycleID.  -- 2015-12-08 Suri Kandukuri: Function changed from  GetYearFromFinanceYearAndMonth to GetYearFromPayrollYearAndMonth  -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- Modiri Selao 2019/07/22 Correct the hardcoded municipal id  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_CyclePeriodMonthlyCycle_sp]    -- Add the parameters for the stored procedure here   @CycleID int    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     DECLARE  @CYCLEENTRY TABLE   (    [CapturerID] INT,    [DateCaptured] DATETIME,    [Enabled] BIT,    [Processed] BIT,    [FinancialYear] NVARCHAR(50),    [ProcessingMonth] NVARCHAR(25),    [PeriodStartDate] DATETIME,    [PeriodEndDate] DATETIME,    [PeriodInTaxYear] INT   )     DECLARE @FYSTARTDATE DATETIME   DECLARE @FYENDDATE DATETIME   DECLARE @1stENDDATE DATETIME   DECLARE @FinancialStartMonth NVARCHAR(50)   DECLARE @PayrollYear NVARCHAR(10)   DECLARE @STARTDATE DATETIME   DECLARE @ENDDATE DATETIME   DECLARE @DateCapture DATETIME   SET @DateCapture = GETDATE()   DECLARE @TaxYearStartMonth INT   DECLARE @MONTH INT   DECLARE @COUNT INT       DECLARE @MunicipalityID INT   SELECT TOP 1 @MunicipalityID = Municipality_ID FROM dbo.Payroll_Municipality   SET @COUNT = 1       SELECT @TaxYearStartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxFinYearEndMonth'    SET @TaxYearStartMonth=@TaxYearStartMonth+1   IF @TaxYearStartMonth>12    BEGIN     SET @TaxYearStartMonth=1    END     SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SET @MONTH = @TaxYearStartMonth   WHILE(@COUNT <= 12)   BEGIN     SELECT @FinancialStartMonth = dbo.GetYearFromPayrollYearAndMonth(@PayrollYear, @MONTH)    SET @STARTDATE = CAST((@FinancialStartMonth +'/'+ CAST(@MONTH AS NVARCHAR(10)) +'/'+ '01') AS DATETIME )    SET @ENDDATE = DATEADD(d,-1,(DATEADD(M,1,@STARTDATE)))        IF @COUNT = 1    BEGIN     SET @FYSTARTDATE = @STARTDATE     SET @1stENDDATE = @ENDDATE    END    ELSE IF @COUNT = 12    BEGIN     SET @FYENDDATE = @ENDDATE    END            INSERT INTO @CYCLEENTRY     SELECT 1, @DateCapture, 1, 0, @PayrollYear, * FROM     (     (      SELECT DATENAME(month,@STARTDATE) AS CurrentMonth, @STARTDATE AS StartingDate,         @ENDDATE AS EndDate,@COUNT as TaxYear     )    ) AS TEMP                 IF(@MONTH < 12)    BEGIN     SET @MONTH = @MONTH + 1    END    ELSE IF(@MONTH = 12)    BEGIN     SET @MONTH = 1    END    ELSE  IF(@MONTH >= (@TaxYearStartMonth - 1))    BEGIN     SET @MONTH = @MONTH + 1    END        SET  @COUNT = @COUNT + 1    END      IF NOT EXISTS (SELECT Period_ID FROM Payroll_CyclePeriodDetails  WHERE TaxYear = @PayrollYear and CycleID = @CycleID)   BEGIN    INSERT INTO Payroll_CyclePeriodDetails (PeriodInTaxYear, ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed ,              MunicipalityID , FinancialYear , Enabled , DateCaptured ,              CapturerID , CycleID, CycleModeID)    SELECT [PeriodInTaxYear], [ProcessingMonth], [PeriodStartDate] ,[PeriodEndDate], [Processed],@MunicipalityID,      [FinancialYear], [Enabled], [DateCaptured], [CapturerID], @CycleID, 1 FROM @CYCLEENTRY   END      IF NOT EXISTS (SELECT CycleDetail_ID FROM Payroll_Municipality_CycleDetails  WHERE TaxYear = @PayrollYear and CycleID = @CycleID)   BEGIN   INSERT INTO dbo.Payroll_Municipality_CycleDetails   (     MunicipalityID , CycleID , FinancialYear , TaxYearStartDate , TaxYearEndDate ,    PeriodEndDate , [Enabled] , DateCaptured , CapturerID ,TaxYear   )   VALUES     (     @MunicipalityID, @CycleID, @PayrollYear, @FYSTARTDATE, @FYENDDATE, @1stENDDATE, 1, @DateCapture, 1, @PayrollYear   )   END       DECLARE @CycleTypeId INT      SELECT @CycleTypeId=cc.CycleTypeID FROM Const_Cycle as cc WHERE cc.Cycle_ID=@CycleId     --Calculate Bi-Weekly Process   if(@CycleTypeId = 3)   BEGIN    EXEC Payroll_CyclePeriodOtherCycle_sp @PayrollYear, @FYSTARTDATE, @FYENDDATE, 1, @DateCapture, @CycleID, @MunicipalityID   END   --Calculate Weekly Process   if(@CycleTypeId = 2)   BEGIN    EXEC Payroll_CyclePeriodOtherCycle_sp @PayrollYear, @FYSTARTDATE, @FYENDDATE, 1, @DateCapture, @CycleID, @MunicipalityID   END   UPDATE Payroll_CyclePeriodDetails set Processed=1, ProcessedDate=GETDATE()    WHERE PeriodEndDate<GETDATE()    AND CycleID=@CycleID  END          

GO

-- ============================================
-- SP: Payroll_CyclePeriodOtherCycle_sp
-- Schema: dbo
-- ============================================
  -- =========================================================================================================  -- Author: MEHUL PANCHAL  -- Create date: 12 JULY 2013  -- Description: <Description,,>  -- calls : [Payroll_CyclePeriodOtherCycle_sp] '2010/2011','03/01/2010','02/28/2011',1,'07/31/2013',3,1  -- 2015-04-29 James Roodt: Changed CycleTypeID Parameter to CycleID and fixed th ecod eto use both correctly  -- 2015-12-04 Suri Kandukuri: Rename CycleTypeID to CycleID.  -- 2016-04-13 TP:35001 Seipei Mathole: Added CycleMode on the INSERT INTO Payroll_CyclePeriodDetails  -- 2019/07/22 Modiri Selao Correct the hardcoded muncipal ID  -- ===========================================================================================================  CREATE PROCEDURE [dbo].[Payroll_CyclePeriodOtherCycle_sp]   @FinancialYear NVARCHAR(10),   @FromDate DATETIME,   @ToDate DATETIME,   @CapturerID INT,   @DateCaptured DATETIME,   @CycleId INT,   @MunicipalityID INT  AS  BEGIN     DECLARE  @CYCLEENTRY TABLE    (     [CapturerID] INT,      [DateCaptured] DATETIME,     [Enabled] BIT,     [Processed] BIT,     [FinancialYear] NVARCHAR(50),     [ProcessingMonth] NVARCHAR(25),     [PeriodStartDate] DATETIME,     [PeriodEndDate] DATETIME,     [PeriodInTaxYear] INT    )       DECLARE @WEEK  NVARCHAR(50)    DECLARE @STARTDATE DATETIME    DECLARE @ENDDATE DATETIME    DECLARE @FinYearStartMonth INT    DECLARE @MONTH INT    DECLARE @COUNT INT    DECLARE @CycleTypeId INT      SELECT @CycleTypeId=cc.CycleTypeID FROM Const_Cycle as cc WHERE cc.Cycle_ID=@CycleId     SET @COUNT = 1      WHILE(@FromDate < DATEADD(DAY,1,@ToDate))   BEGIN    SET @STARTDATE = @FromDate    IF(@CycleTypeId = 2)    BEGIN     SET @ENDDATE = DATEADD(DAY,6,@STARTDATE)     SET @WEEK ='Week '    END     ELSE IF(@CycleTypeId = 3)    BEGIN     SET @ENDDATE = DATEADD(DAY,13,@STARTDATE)     SET @WEEK ='Bi-Week '    END    IF(@ENDDATE > @ToDate)    BEGIN     SET @ENDDATE = @ToDate    END       INSERT INTO @CYCLEENTRY     SELECT @CapturerID,@DateCaptured,1,0,@FinancialYear,* FROM((SELECT  @WEEK + CONVERT(VARCHAR,@COUNT) AS CurrentMonth,           @STARTDATE AS StartingDate, @ENDDATE AS EndDate,@COUNT as TaxYear)) AS TEMP         SET @FromDate = DATEADD(DAY,1,@ENDDATE)        IF(@COUNT = 1)    BEGIN     INSERT INTO dbo.Payroll_Municipality_CycleDetails      (        MunicipalityID , CycleID , FinancialYear , TaxYearStartDate , TaxYearEndDate ,       PeriodEndDate , [Enabled] , DateCaptured , CapturerID      )     VALUES        (        @MunicipalityID, @CycleId, @FinancialYear, @STARTDATE, @ENDDATE, @ENDDATE, 1, @DateCaptured, @CapturerID       )    END    SET @COUNT = @COUNT + 1   END      IF NOT EXISTS (SELECT Period_ID FROM Payroll_CyclePeriodDetails  WHERE TaxYear = @FinancialYear AND CycleID = @CycleId)   BEGIN    INSERT INTO Payroll_CyclePeriodDetails (PeriodInTaxYear, ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed ,              MunicipalityID , FinancialYear , Enabled , DateCaptured ,              CapturerID , CycleID, CycleModeID,TaxYear)    SELECT [PeriodInTaxYear], [ProcessingMonth], [PeriodStartDate] ,[PeriodEndDate], [Processed], @MunicipalityID,      [FinancialYear], [Enabled], [DateCaptured], [CapturerID], @CycleId, 1,@FinancialYear FROM @CYCLEENTRY   END  END   

GO

-- ============================================
-- SP: Payroll_CyclePeriodYearly_sp
-- Schema: dbo
-- ============================================
-- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- Modiri 2019/07/22 Correct the hard coded municipal id  CREATE PROCEDURE [dbo].[Payroll_CyclePeriodYearly_sp]    AS  BEGIN     DECLARE  @CYCLEENTRY TABLE   (    [CapturerID] INT,    [DateCaptured] DATETIME,    [Enabled] BIT,    [Processed] BIT,    [FinancialYear] NVARCHAR(50),    [ProcessingMonth] NVARCHAR(25),    [PeriodStartDate] DATETIME,    [PeriodEndDate] DATETIME,    [PeriodInTaxYear] INT       )     DECLARE @FYSTARTDATE DATETIME   DECLARE @FYENDDATE DATETIME   DECLARE @1stENDDATE DATETIME   DECLARE @FinancialStartMonth NVARCHAR(50)   --DECLARE @FinancialYear NVARCHAR(10)   DECLARE @STARTDATE DATETIME   DECLARE @ENDDATE DATETIME   DECLARE @DateCapture DATETIME   SET @DateCapture = GETDATE()   --DECLARE @FinYearStartMonth INT   DECLARE @MONTH INT   DECLARE @COUNT INT   DECLARE @TaxYear NVARCHAR(10)   DECLARE @TaxYearStartMonth INT       DECLARE @MunicipalityID INT   SELECT TOP 1 @MunicipalityID = Municipality_ID FROM dbo.Payroll_Municipality   SET @COUNT = 1       --SELECT @FinYearStartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'FinYearStartMonth'    --SELECT @FinancialYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'ActiveFinYear'      --SET @MONTH = @FinYearStartMonth   SELECT @TaxYearStartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxFinYearEndMonth'    SET @TaxYearStartMonth=@TaxYearStartMonth+1   IF @TaxYearStartMonth>12    BEGIN     SET @TaxYearStartMonth=1    END     SELECT @TaxYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'   SET @MONTH = @TaxYearStartMonth   WHILE(@COUNT <= 12)   BEGIN     SELECT @FinancialStartMonth = dbo.GetYearFromPayrollYearAndMonth(@TaxYear, @MONTH)    SET @STARTDATE = CAST((@FinancialStartMonth +'/'+ CAST(@MONTH AS NVARCHAR(10)) +'/'+ '01') AS DATETIME )    SET @ENDDATE = DATEADD(d,-1,(DATEADD(M,1,@STARTDATE)))        IF @COUNT = 1    BEGIN     SET @FYSTARTDATE = @STARTDATE     SET @1stENDDATE = @ENDDATE    END    ELSE IF @COUNT = 12    BEGIN     SET @FYENDDATE = @ENDDATE    END            INSERT INTO @CYCLEENTRY     SELECT 1, @DateCapture, 1, 0, @TaxYear, * FROM     (     (      SELECT DATENAME(month,@STARTDATE) AS CurrentMonth, @STARTDATE AS StartingDate,         @ENDDATE AS EndDate,@COUNT as TaxYear     )    ) AS TEMP                 IF(@MONTH < 12)    BEGIN     SET @MONTH = @MONTH + 1    END    ELSE IF(@MONTH = 12)    BEGIN     SET @MONTH = 1    END    ELSE  IF(@MONTH >= (@TaxYear - 1))    BEGIN     SET @MONTH = @MONTH + 1    END        SET  @COUNT = @COUNT + 1    END   select * from @CYCLEENTRY   IF NOT EXISTS (SELECT Period_ID FROM Payroll_CyclePeriodDetails  WHERE TaxYear = @TaxYear)   BEGIN    INSERT INTO Payroll_CyclePeriodDetails (PeriodInTaxYear, ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed ,              MunicipalityID , FinancialYear , Enabled , DateCaptured ,              CapturerID , CycleID, CycleModeID, TaxYear)    SELECT [PeriodInTaxYear], [ProcessingMonth], [PeriodStartDate] ,[PeriodEndDate], [Processed], @MunicipalityID,      [FinancialYear], [Enabled], [DateCaptured], [CapturerID], 1, 1, @TaxYear FROM @CYCLEENTRY   END      INSERT INTO dbo.Payroll_Municipality_CycleDetails   (     MunicipalityID , CycleID , FinancialYear , TaxYearStartDate , TaxYearEndDate ,    PeriodEndDate , [Enabled] , DateCaptured , CapturerID , TaxYear   )   VALUES     (     @MunicipalityID, 1, @TaxYear, @FYSTARTDATE, @FYENDDATE, @1stENDDATE, 1, @DateCapture, 1 , @TaxYear   )      --Calculate Bi-Weekly Process   EXEC Payroll_CyclePeriodOtherCycle_sp @TaxYear, @FYSTARTDATE, @FYENDDATE, 1, @DateCapture, 3, @MunicipalityID      --Calculate Weekly Process   EXEC Payroll_CyclePeriodOtherCycle_sp @TaxYear, @FYSTARTDATE, @FYENDDATE, 1, @DateCapture, 2, @MunicipalityID  END         

GO

-- ============================================
-- SP: Payroll_DeactivateJobProfile_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author   : Varun Parvataneni  -- Create date: 30/09/2016  -- Description: Deactivate records on the Job profile baed on ParentID  -- Call SP    : Payroll_DeactivateJobProfile_sp  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_DeactivateJobProfile_sp]  @ParentID INT   AS  BEGIN     SELECT JobProfile_ID,TG.TaskGradeName GradeName,jp.StartDate,jp.EndDate,Occupation    from dbo.Payroll_JobProfile JP WITH(NOLOCK)   inner join [dbo].[Payroll_TaskGrade] TG WITH(NOLOCK) ON TG.TaskGrade_ID = JP.TaskGradeId   WHERE ParentID = @ParentID      END

GO

-- ============================================
-- SP: Payroll_DeductionPriorityEmployees_Trial_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 31/07/2017   Description : Gets the Employees for whom we need to execute Deduction Priority  */  CREATE procedure [dbo].[Payroll_DeductionPriorityEmployees_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10)  as    begin  BEGIN TRANSACTION;  BEGIN TRY     DROP TABLE IF EXISTS #EmployeeIds      SELECT Employee_ID AS EmployeeId      INTO #EmployeeIds      FROM Payroll_TrialRun_History_Employees WHERE Period_ID = @PeriodID AND (@EmployeeID = 0 OR Employee_ID = @EmployeeID)    DECLARE @EmployeeCount INT;    SELECT @EmployeeCount = COUNT(1) FROM #EmployeeIds    WHILE @EmployeeCount > 0  BEGIN  SET @EmployeeID = ( SELECT TOP 1 EmployeeId FROM #EmployeeIds)  DELETE #EmployeeIds WHERE EmployeeId = @EmployeeID  SET @EmployeeCount = @EmployeeCount - 1       DELETE Payroll_DeductionsCarriedOverTrial WHERE EmployeeId = @EmployeeId AND PeriodId = @PeriodId    DECLARE @EarningsAmount DECIMAL(18,2);  DECLARE @EarningRatio DECIMAL(18,2) = 1;    SELECT @EarningsAmount = SUM(ISNULL(PETP.Amount, 0)) * @EarningRatio FROM Payroll_EmployeeTrialPayslip AS PETP  JOIN Payroll_EmployeePayrollDefinition AS PEPD       ON PETP.PayrollDefinationID = PEPD.EmployeePayrollDefinition_ID AND PETP.EmployeeID = PEPD.EmployeeID  JOIN Payroll_SalaryHead AS PSH       ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID  JOIN Payroll_IRP5Code AS IRP5       ON PSH.IRP5CodeId = IRP5.IRP5Code_ID  WHERE PETP.EmployeeID = @EmployeeID AND PETP.PeriodID = @PeriodID AND IRP5.TransactionTypeID = 1 AND PETP.TaxSavePurpose = 0    SELECT       ROW_NUMBER() OVER(ORDER BY PSH.DeductionPriority, PSH.SalaryHead_ID ASC) AS [RowNumber]      ,PETP.Amount      ,PETP.PayrollDefinationID AS EmployeePayrollDefinitionId      ,PETP.Month, PETP.FinancialYear, PETP.SalaryHeadTitleAddendum, PETP.VendorID, PETP.ReferenceNo, PETP.TaxYear, PETP.ProjectID, PETP.DivisionId, PETP.ScoaItemID, PETP.FunctionId, PETP.RegionId, PETP.Simulation, PETP.MOCDetailID  INTO #DeductionAmounts  FROM Payroll_EmployeeTrialPayslip AS PETP  JOIN Payroll_EmployeePayrollDefinition AS PEPD       ON PETP.PayrollDefinationID = PEPD.EmployeePayrollDefinition_ID AND PETP.EmployeeID = PEPD.EmployeeID  JOIN Payroll_SalaryHead AS PSH       ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID  JOIN Payroll_IRP5Code AS IRP5       ON PSH.IRP5CodeId = IRP5.IRP5Code_ID  WHERE PETP.EmployeeID = @EmployeeID AND PETP.PeriodID = @PeriodID AND IRP5.TransactionTypeID = 2 AND PETP.TaxSavePurpose = 0  ORDER BY PSH.DeductionPriority, PSH.SalaryHead_ID ASC        DECLARE @i INT = 0;  DECLARE @DeductionCount INT;  SELECT @DeductionCount = COUNT(1) FROM #DeductionAmounts      WHILE @i < @DeductionCount  BEGIN      SET @i = @i + 1        DECLARE @DeductionAmount DECIMAL(18,2);      DECLARE @EmployeePayrollDefinitionId INT;        SELECT           @DeductionAmount = Amount,           @EmployeePayrollDefinitionId = EmployeePayrollDefinitionId      FROM #DeductionAmounts WHERE RowNumber = @i        SET @EarningsAmount = @EarningsAmount - @DeductionAmount        IF @EarningsAmount > 0 CONTINUE;        IF @EarningsAmount < 0      BEGIN          UPDATE Payroll_EmployeeTrialPayslip           SET Amount = Amount - ABS(@EarningsAmount)          WHERE EmployeeID = @EmployeeId               AND PeriodID = @PeriodId               AND PayrollDefinationID = @EmployeePayrollDefinitionId              AND Amount = @DeductionAmount                INSERT INTO Payroll_DeductionsCarriedOverTrial (PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)          SELECT @PeriodId, @EmployeeId, @EmployeePayrollDefinitionId, ABS(@EarningsAmount), Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID          FROM #DeductionAmounts WHERE RowNumber = @i      END        INSERT INTO Payroll_DeductionsCarriedOverTrial (PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)      SELECT @PeriodId, @EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID      FROM #DeductionAmounts WHERE RowNumber > @i        DELETE PETP      FROM Payroll_EmployeeTrialPayslip AS PETP      JOIN #DeductionAmounts AS DA ON PeriodID = @PeriodId           AND EmployeeID = @EmployeeId           AND PayrollDefinationID = EmployeePayrollDefinitionId           AND DA.Amount = PETP.Amount          AND RowNumber > @i        BREAK;    END    --Final    SELECT @EarningsAmount = SUM(CASE WHEN IRP5.TransactionTypeID = 1 THEN Amount ELSE 0 END) * @EarningRatio - SUM(CASE WHEN IRP5.TransactionTypeID = 2 THEN Amount ELSE 0 END)   FROM Payroll_EmployeeTrialPayslip AS PETP  JOIN Payroll_EmployeePayrollDefinition AS PEPD       ON PETP.PayrollDefinationID = PEPD.EmployeePayrollDefinition_ID AND PETP.EmployeeID = PEPD.EmployeeID  JOIN Payroll_SalaryHead AS PSH       ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID  JOIN Payroll_IRP5Code AS IRP5       ON PSH.IRP5CodeId = IRP5.IRP5Code_ID  WHERE PETP.EmployeeID = @EmployeeID AND PETP.PeriodID = @PeriodID AND IRP5.TransactionTypeID IN (1,2) AND PETP.TaxSavePurpose = 0      DECLARE @PreviousPeriodId INT;  SELECT TOP 1 @PreviousPeriodId = PeriodID FROM Payroll_PayrollResults WHERE EmployeeID = @EmployeeID ORDER BY PayrollResult_ID DESC    SELECT       ROW_NUMBER() OVER(ORDER BY PSH.DeductionPriority, PSH.SalaryHead_ID ASC) AS [RowNumber]      ,PDCOF.Amount      ,PDCOF.EmployeePayrollDefinitionId      ,PDCOF.Month, PDCOF.FinancialYear, PDCOF.SalaryHeadTitleAddendum, PDCOF.VendorID, PDCOF.ReferenceNo, PDCOF.TaxYear, PDCOF.ProjectID, PDCOF.DivisionId, PDCOF.ScoaItemID, PDCOF.FunctionId, PDCOF.RegionId, PDCOF.Simulation, PDCOF.MOCDetailID  INTO #FinalDeductionAmounts  FROM Payroll_DeductionsCarriedOverFinal AS PDCOF  JOIN Payroll_EmployeePayrollDefinition AS PEPD       ON PEPD.EmployeePayrollDefinition_ID = PDCOF.EmployeePayrollDefinitionId AND PDCOF.EmployeeId = PEPD.EmployeeID  JOIN Payroll_SalaryHead AS PSH       ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID  WHERE PDCOF.EmployeeID = @EmployeeID AND PDCOF.PeriodID = @PreviousPeriodId and PEPD.Enabled = 1  ORDER BY PSH.DeductionPriority, PSH.SalaryHead_ID ASC    DECLARE @FinalDeductionCount INT;  SELECT @FinalDeductionCount = COUNT(1) FROM #FinalDeductionAmounts    SET @i = 1  WHILE @i <= @FinalDeductionCount  BEGIN        DECLARE @FinalDeductionAmount DECIMAL(18,2);      DECLARE @FinalEmployeePayrollDefinitionId INT;      DECLARE @ReferenceNo NVARCHAR(50);        SELECT           @FinalDeductionAmount = Amount,           @FinalEmployeePayrollDefinitionId = EmployeePayrollDefinitionId,          @ReferenceNo = ReferenceNo      FROM #FinalDeductionAmounts WHERE RowNumber = @i        SET @EarningsAmount = @EarningsAmount - @FinalDeductionAmount            IF @EarningsAmount >= 0       BEGIN          IF EXISTS (SELECT TOP 1 1 FROM Payroll_EmployeeTrialPayslip WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID AND PayrollDefinationID = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo)          BEGIN              UPDATE Payroll_EmployeeTrialPayslip              SET Amount = Amount + @FinalDeductionAmount              WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID AND PayrollDefinationID = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo          END          ELSE          BEGIN              INSERT INTO Payroll_EmployeeTrialPayslip(EmployeeID, PayrollDefinationID, Amount, Month, FinancialYear, PeriodID, TaxSavePurpose, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)              SELECT @EmployeeID, EmployeePayrollDefinitionId, Amount, @Month, FinancialYear, @PeriodID, 0, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID              FROM #FinalDeductionAmounts WHERE RowNumber = @i          END      END      ELSE      BEGIN          IF EXISTS (SELECT TOP 1 1 FROM Payroll_EmployeeTrialPayslip WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID AND PayrollDefinationID = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo)          BEGIN              UPDATE Payroll_EmployeeTrialPayslip              SET Amount = Amount + @FinalDeductionAmount - ABS(@EarningsAmount)              WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID AND PayrollDefinationID = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo          END          ELSE          BEGIN              INSERT INTO Payroll_EmployeeTrialPayslip(EmployeeID, PayrollDefinationID, Amount, Month, FinancialYear, PeriodID, TaxSavePurpose, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)              SELECT @EmployeeID, EmployeePayrollDefinitionId,                   (Amount - ABS(@EarningsAmount)) AS Amount,                  @Month, FinancialYear, @PeriodID, 0, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID              FROM #FinalDeductionAmounts WHERE RowNumber = @i          END                    IF EXISTS (SELECT TOP 1 1 FROM Payroll_DeductionsCarriedOverTrial WHERE PeriodId = @PeriodID AND EmployeeId = @EmployeeID AND EmployeePayrollDefinitionId = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo)          BEGIN              UPDATE Payroll_DeductionsCarriedOverTrial              SET Amount = Amount + ABS(@EarningsAmount)              WHERE PeriodId = @PeriodID AND EmployeeId = @EmployeeID AND EmployeePayrollDefinitionId = @FinalEmployeePayrollDefinitionId AND ReferenceNo = @ReferenceNo          END          ELSE          BEGIN              INSERT INTO Payroll_DeductionsCarriedOverTrial(PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)              SELECT @PeriodID, @EmployeeID, @FinalEmployeePayrollDefinitionId, ABS(@EarningsAmount), @Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID               FROM #FinalDeductionAmounts WHERE RowNumber = @i          END      END        DELETE #FinalDeductionAmounts WHERE RowNumber = @i      DELETE Payroll_EmployeeTrialPayslip WHERE PeriodID = @PeriodID AND EmployeeID = @EmployeeID AND PayrollDefinationID = @FinalEmployeePayrollDefinitionId AND Amount = 0 AND ReferenceNo = @ReferenceNo        IF @EarningsAmount <= 0 BREAK;        SET @i = @i + 1  END    SELECT @FinalDeductionCount = COUNT(1) FROM #FinalDeductionAmounts    IF @FinalDeductionCount > 0  BEGIN      MERGE Payroll_DeductionsCarriedOverTrial AS Target      USING (SELECT * FROM #FinalDeductionAmounts) AS Source      ON (Target.PeriodId = @PeriodID AND Target.EmployeeId = @EmployeeID AND Target.EmployeePayrollDefinitionId = Source.EmployeePayrollDefinitionId AND Target.ReferenceNo = Source.ReferenceNo)      WHEN MATCHED THEN          UPDATE SET Target.Amount = Target.Amount + Source.Amount      WHEN NOT MATCHED BY TARGET THEN          INSERT (PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)          VALUES (@PeriodId, @EmployeeId, Source.EmployeePayrollDefinitionId, Source.Amount, @Month, Source.FinancialYear, Source.SalaryHeadTitleAddendum, Source.VendorID, Source.ReferenceNo, Source.TaxYear, Source.ProjectID, Source.DivisionId, Source.ScoaItemID, Source.FunctionId, Source.RegionId, Source.Simulation, Source.MOCDetailID);  END    DROP TABLE #DeductionAmounts  DROP TABLE #FinalDeductionAmounts      END  DROP TABLE #EmployeeIds  COMMIT;  END TRY  BEGIN CATCH      ROLLBACK;        INSERT INTO [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])      VALUES('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())    END CATCH  end

GO

-- ============================================
-- SP: Payroll_DeleteTaskGrade_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_DeleteTaskGrade_sp](@TaskGradeId INT)  AS  BEGIN   UPDATE Payroll_JobProfile   SET TaskGradeId = NULL   WHERE TaskGradeId = @TaskGradeId     DELETE FROM Payroll_NotchHistory where TaskGradeId = @TaskGradeId   DELETE FROM Payroll_Notch where TaskGradeId = @TaskGradeId     DELETE FROM Payroll_TaskGradeHistory WHERE TaskGradeID = @TaskGradeId   DELETE FROM Payroll_TaskGrade WHERE TaskGrade_ID = @TaskGradeId  END

GO

-- ============================================
-- SP: Payroll_DependantModeAutoUpdate_sp
-- Schema: dbo
-- ============================================
-- =======================================================================================================================  -- Author:  MEHUL PANCHAL  -- Create date: 17 JAN 2014  -- Description: Auto update dependant mode in dependant details  -- Payroll_DependantModeAutoUpdate_sp 10  -- 2015-08-11 TP19740 Ravindra Jijotia: Updated logic to update DependantMode to be a FIRST if there is no FIRST dependant.  --          Added and condition while calculating from date to get current period.  -- 2016-08-19 #43202V Varun Parvataneni:Replace code for Medical Aid dependants with Payroll_PersonRelationshipType.  -- 2015-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- ========================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_DependantModeAutoUpdate_sp]   @EmployeeID INT  AS  BEGIN   SET NOCOUNT ON;      DECLARE @TotalCount INT    DECLARE @Start INT   SET @Start = 1     DECLARE @DependantTbl TABLE   (    DependantID INT,    DependantMode INT,    [RowNo] INT   )            DECLARE @DependantID INT, @DependantMode INT      DECLARE @FirstFlag BIT = 0, @SecondFlag BIT = 0, @RuntimeSecondFlag BIT = 0     DECLARE @CycleID INT   SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID      DECLARE @MemberCount INT = 1, @AdultCount INT, @ChildCount INT   DECLARE @AdultCountBefore INT, @ChildCountBefore INT   DECLARE @MaxDependantCount INT      DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)   SELECT @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear          --Payroll_EmployeeDependantDetails Replaced with Payroll_PersonRelationshipType     INSERT INTO @DependantTbl      SELECT PersonRelationshipType_ID, DependantMode, ROW_NUMBER()OVER (ORDER BY DateOfBirth ASC) AS [RowNo]      FROM dbo.Payroll_PersonRelationshipType    WHERE EmployeeID = @EmployeeID AND Enabled = 1     AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null) AND(IsAdultDependant =1 or IsChildDependant=1)    ORDER BY DateOfBirth             SELECT @TotalCount = COUNT(1) FROM @DependantTbl            --Select @FirstFlag = ISNULL(COUNT(1),0) FROM @DependantTbl WHERE DependantMode = 1      --Select @SecondFlag = ISNULL(COUNT(1),0) FROM @DependantTbl WHERE DependantMode = 2            DECLARE @DATABASENAME NVARCHAR(50)          DECLARE @SQLQuery NVARCHAR(MAX)      SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'        WHILE(@Start <= @TotalCount)      BEGIN       SELECT @DependantID =  DependantID, @DependantMode = DependantMode       FROM @DependantTbl WHERE [RowNo]= @Start           SELECT @FirstFlag = ISNULL(COUNT(1),0) FROM Payroll_PersonRelationshipType     WHERE DependantMode = (select DependantMode_ID from Const_DependantModeType_Sys where [Description] = 'FIRST')     AND EmployeeID = @EmployeeID AND Enabled = 1     AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)         --IF(@DependantMode = 1 AND @FirstFlag = 1)       --BEGIN       -- PRINT 'Do Nothing'       --END       --ELSE IF(@DependantMode = 2 AND @SecondFlag = 1 AND @FirstFlag = 1)       --BEGIN       -- PRINT 'Do Nothing'       -- SET @RuntimeSecondFlag = 1       --END       --ELSE IF(@DependantMode = 2 AND @FirstFlag = 0)    --ELSE IF(@DependantMode = 3 AND @FirstFlag = 0)    IF(@FirstFlag = 0)       BEGIN        SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_PersonRelationshipType         (          AuditUserID , AuditDate , AuditUser , PersonRelationshipType_ID , EmployeeID , FullNames, Enabled, DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , MedAidJoiningDate ,DependantMode , MedAidTerminateDate , IsAdultDependant,IsChildDependant         )         SELECT 1, GETDATE(), ''Admin User'', PersonRelationshipType_ID, EmployeeID, FullNames,Enabled, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  MedAidJoiningDate, DependantMode,MedAidTerminateDate,IsAdultDependant,IsChildDependant FROM Payroll_PersonRelationshipType WHERE PersonRelationshipType_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     EXEC(@SQLQuery)               --PRINT 'Update with 1 ' + CAST(@DependantID AS NVARCHAR(10))        --UPDATE Payroll_EmployeeDependantDetails SET DependantMode = 1 WHERE EmployeeDependant_ID = @DependantID     UPDATE Payroll_PersonRelationshipType SET DependantMode = 2 WHERE PersonRelationshipType_ID = @DependantID       END      IF(@FirstFlag = 1 AND @DependantMode <> 3 AND @DependantMode <> 2)       BEGIN     SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_PersonRelationshipType         (          AuditUserID , AuditDate , AuditUser , PersonRelationshipType_ID , EmployeeID , FullNames, Enabled, DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , MedAidJoiningDate ,DependantMode , MedAidTerminateDate , IsAdultDependant,IsChildDependant         )         SELECT 1, GETDATE(), ''Admin User'', PersonRelationshipType_ID, EmployeeID, FullNames,Enabled, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  MedAidJoiningDate, DependantMode,MedAidTerminateDate,IsAdultDependant,IsChildDependant FROM Payroll_PersonRelationshipType WHERE PersonRelationshipType_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     EXEC(@SQLQuery)          UPDATE Payroll_PersonRelationshipType SET DependantMode = 2 WHERE PersonRelationshipType_ID = @DependantID       END       --  ELSE IF(@DependantMode = 3 AND @SecondFlag = 0)     --  BEGIN     --   SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeeDependantDetails     --    (     --     AuditUserID , AuditDate , AuditUser , EmployeeDependant_ID , EmployeeID , DependantName , MunicipalityID , Enable , DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , DependedJoinDate , DependantMode , TerminateDate , Dependant     --    )     --    SELECT 1, GETDATE(), ''Admin User'', EmployeeDependant_ID, EmployeeID, DependantName, MunicipalityID,  Enable, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  DependedJoinDate, DependantMode, TerminateDate, Dependant FROM Payroll_EmployeeDependantDetails WHERE EmployeeDependant_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     --EXEC(@SQLQuery)            --   --PRINT 'Update with 2 @SecondFlag ' + CAST(@DependantID AS NVARCHAR(10))     --   UPDATE Payroll_EmployeeDependantDetails SET DependantMode = 2 WHERE EmployeeDependant_ID = @DependantID     --   SET @RuntimeSecondFlag = 1     --   SET @SecondFlag = 1     --  END     --  ELSE IF(@DependantMode = 3 AND @RuntimeSecondFlag = 0)     --  BEGIN     --   SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeeDependantDetails     --    (     --     AuditUserID , AuditDate , AuditUser , EmployeeDependant_ID , EmployeeID , DependantName , MunicipalityID , Enable , DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , DependedJoinDate , DependantMode , TerminateDate , Dependant     --    )     --    SELECT 1, GETDATE(), ''Admin User'', EmployeeDependant_ID, EmployeeID, DependantName, MunicipalityID,  Enable, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  DependedJoinDate, DependantMode, TerminateDate, Dependant FROM Payroll_EmployeeDependantDetails WHERE EmployeeDependant_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     --EXEC(@SQLQuery)            --   --PRINT 'Update with 2 @RuntimeSecondFlag ' + CAST(@DependantID AS NVARCHAR(10))     --   UPDATE Payroll_EmployeeDependantDetails SET DependantMode = 2 WHERE EmployeeDependant_ID = @DependantID     --   SET @RuntimeSecondFlag = 1     --   SET @SecondFlag = 1     --  END     --  ELSE     --  BEGIN     --   SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeeDependantDetails     --    (     --     AuditUserID , AuditDate , AuditUser , EmployeeDependant_ID , EmployeeID , DependantName , MunicipalityID , Enable , DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , DependedJoinDate , DependantMode , TerminateDate , Dependant     --    )     --    SELECT 1, GETDATE(), ''Admin User'', EmployeeDependant_ID, EmployeeID, DependantName, MunicipalityID,  Enable, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  DependedJoinDate, DependantMode, TerminateDate, Dependant FROM Payroll_EmployeeDependantDetails WHERE EmployeeDependant_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     --EXEC(@SQLQuery)            --   --PRINT '3 ' + CAST(@DependantID AS NVARCHAR(10))     --   UPDATE Payroll_EmployeeDependantDetails SET DependantMode = 3 WHERE EmployeeDependant_ID = @DependantID     --  END       SET @Start = @Start + 1      END  END  

GO

-- ============================================
-- SP: Payroll_DisableCostCenterAndOverTimeById_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 31 12 2013  -- Description: <Description,,>  -- 2015-08-20 TP23516 James Roodt: Log the Modified Date and Modified User fields  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_DisableCostCenterAndOverTimeById_sp]   @ID INT,   @Mode INT,   @UserID INT  AS  BEGIN   SET NOCOUNT ON;      IF(@Mode = 1)    BEGIN     UPDATE dbo.Payroll_CostCenter SET Enabled = 0, ModifierID = @UserID, DateModified = GETDATE() WHERE CostCenter_ID = @ID    END   ELSE IF(@Mode = 2)    BEGIN     UPDATE dbo.Payroll_EmployeeOverTime SET Enabled = 0, ModifierID = @UserID, DateModified = GETDATE() WHERE EmployeeOverTime_ID = @ID    END   ELSE IF(@Mode = 3)   BEGIN    UPDATE dbo.Payroll_TravelEntry SET Enabled = 0, ModifierID = @UserID, DateModified = GETDATE() WHERE TravelEntry_ID = @ID   END   ELSE IF(@Mode = 4)   BEGIN    UPDATE dbo.Payroll_3rdPartyPayment SET Enabled = 0, ModifierID = @UserID, DateModified = GETDATE() WHERE PartyPayment_ID = @ID   END  END  

GO

-- ============================================
-- SP: Payroll_Disciplinarylst_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:  29/10/2013  -- Description: <Description,,>  -- Payroll_Disciplinarylst_sp '','','','','',0,'2012/2013','Requested'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_Disciplinarylst_sp]  @FROMDATE DATETIME,  @TODATE DATETIME,  @FIRSTNAME  NVARCHAR(50),  @LASTNAME NVARCHAR(50),  @IDNO NVARCHAR(50),  @EMPLOYEEID INT,  @FINANCIALYEAR NVARCHAR(50),  @STATUS NVARCHAR(50)  AS  BEGIN    SELECT PAY_EMP1.FirstName AS Submitted, PAY_EMP.FirstName AS Received,    CONS_DIS.DisiplinaryOffenceType ,PAY_DIS.DisiplinaryStartDate ,PAY_DIS.DisiplinaryEndDate,    PAY_DIS.Status,PAY_DIS.DisciplinaryDocUrl,PAY_DIS.Disiplinary_ID,PAY_DIS.FinalOutcome,    PAY_DIS.GroundsOfAppeal,PAY_DIS.AppealDate,PAY_DIS.Chairman,PAY_DIS.TaxYear     FROM Payroll_Disciplinary PAY_DIS    INNER JOIN Payroll_Employee PAY_EMP      ON PAY_DIS.EmployeeReceivingID =PAY_EMP.Employee_ID    INNER JOIN Payroll_Employee PAY_EMP1      ON PAY_DIS.EmployeeSubmittingID =PAY_EMP1.Employee_ID       INNER JOIN Const_DisiplinaryOffenceType CONS_DIS      ON CONS_DIS.DisiplinaryOffenceType_ID =PAY_DIS.DisciplinaryOffenceTypeID    WHERE (PAY_DIS.DisiplinaryStartDate =@FROMDATE OR @FROMDATE = '')          AND (PAY_DIS.DisiplinaryEndDate =@TODATE OR @TODATE = '')    AND (PAY_EMP.FirstName =@FIRSTNAME OR @FIRSTNAME = '')    AND (PAY_EMP.Surname =@LASTNAME OR @LASTNAME = '')    AND (PAY_EMP.IdNo =@IDNO OR @IDNO = '')    AND (PAY_EMP.Employee_ID =@EMPLOYEEID OR @EMPLOYEEID = 0)    AND (PAY_DIS.TaxYear =@FINANCIALYEAR )    AND (PAY_DIS.Status =@STATUS )  END  

GO

-- ============================================
