-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,15 Mar 2014>  -- Description: <Description,, Payroll_DisiplinaryDocumentDelete>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_DisiplinaryDocumentDelete]   @DocumentName varchar(100),   @DisciplinaryId INT  AS  BEGIN   DELETE FROM Payroll_DisciplinaryDocumentDetails WHERE DisiplinaryId = @DisciplinaryId AND DocumentName = @DocumentName  END      

GO

-- ============================================
-- SP: Payroll_EarningDeduction_rpt
-- Schema: dbo
-- ============================================
    -- =============================================    -- Author:  <Author,,GD>    -- Create date: <Create Date,,28 Apr 2014>    -- Description: <Description,,>  N  -- Call SP    : Payroll_EarningDeduction_rpt 0, 0, 0, 1, 'Admin'   -- 2015-07-01 TP20841 James Roodt: Adding vendorID to Report   -- 2015-07-03 TP20841 James Roodt: Added TaxSavePurposes=0 filter  -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  --  Update date : 28/11/2017 Richa Mills - Update report to read VendorId from PayrollResults instead of Payroll_GLItems  --EXEC Payroll_EarningDeduction_rpt 0,0,0,302,0,17    -- =============================================    CREATE procedure [dbo].[Payroll_EarningDeduction_rpt]     @TransactionTypeId INT,     @SalaryHeadId INT,     @DepartmentId INT,     @Month INT,  /* = @PeriodId */   @VendorId INT,   @CycleId INT  AS    BEGIN       DECLARE @PeriodEndDate DATETIME,    @PeriodStartDate DATETIME, @PeriodId int     DECLARE @CurrentFinancialYear varchar(10) = (Select KeyValue from AAAA_ConfigSettings WHERE KeyName = 'TaxYear')     SELECT @PeriodId = @Month     SELECT   @PeriodEndDate = PeriodEndDate     ,@PeriodStartDate = PeriodStartDate  FROM dbo.Payroll_CyclePeriodDetails  WHERE Period_ID = @PeriodId    SELECT   TransactionTypeDesc      ,Right('0000' + pr.IRP5Code,4) IRP5Code     ,SalaryHeadTitle AS PayrollSalaryHeadName     ,TransactionType_ID     ,SUM(CASE    WHEN pr.TransactionTypeID IN (1, 3) THEN Amount    ELSE 0   END) AS Employeer     ,SUM(CASE    WHEN pr.TransactionTypeID IN (2, 4) THEN Amount    ELSE 0   END) AS Employee     ,@PeriodEndDate AS PeriodEndDate     ,@PeriodStartDate AS PeriodStartDate     ,VendorName  FROM dbo.Payroll_PayrollResults pr  INNER JOIN dbo.Payroll_SalaryHead AS sh   ON pr.SalaryHeadID = sh.SalaryHead_ID  INNER JOIN dbo.Payroll_IRP5Code   ON sh.IRP5CodeId = dbo.Payroll_IRP5Code.IRP5Code_ID  INNER JOIN dbo.Const_TransactionType   ON dbo.Payroll_IRP5Code.TransactionTypeID = dbo.Const_TransactionType.TransactionType_ID  LEFT  outer JOIN dbo.Cons_Vendor cv   ON cv.Vendor_ID = pr.VendorID  WHERE TaxSavePurpose = 0   AND (SalaryHead_ID = @SalaryHeadId  OR @SalaryHeadId = 0)  AND (TransactionType_ID = @TransactionTypeId  OR @TransactionTypeId = 0)  AND pr.PeriodID = @PeriodId  AND (pr.VendorID = @VendorId  OR @VendorId = 0)  GROUP BY TransactionType_ID    ,TransactionTypeDesc    ,SalaryHeadTitle    ,VendorName    ,pr.IRP5Code  ORDER BY TransactionType_ID  END    

GO

-- ============================================
-- SP: Payroll_EarningDeductionTrial_rpt
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Create date : 18/09/2017   Description : Returns Employee Trial Run Earnings and Deductions      Update date : 28/11/2017 Richa Mills - Update report to read VendorId from PayrollResults instead of Payroll_GLItems   EXEC Payroll_EarningDeductionTrial_rpt 0,0,0,2,0,'test',1  */  CREATE procedure [dbo].[Payroll_EarningDeductionTrial_rpt]   @TransactionTypeId int = 0,   @SalaryHeadId int = 0,   @DepartmentId int = 0,   @VendorId int = 0,   @CycleId int,  @PeriodId int  as    begin      DECLARE @PeriodEndDate DATETIME,  @PeriodStartDate DATETIME    SELECT   @PeriodEndDate = PeriodEndDate     ,@PeriodStartDate = PeriodStartDate  FROM dbo.Payroll_CyclePeriodDetails  WHERE Period_ID = @PeriodId     SELECT   TransactionTypeDesc     ,Right('0000' + pr.IRP5Code,4) IRP5Code     ,SalaryHeadTitle AS PayrollSalaryHeadName     ,TransactionType_ID     ,SUM(CASE    WHEN pr.TransactionTypeID IN (1, 3) THEN Amount    ELSE 0   END) AS Employeer     ,SUM(CASE    WHEN pr.TransactionTypeID IN (2, 4) THEN Amount    ELSE 0   END) AS Employee     ,@PeriodEndDate AS PeriodEndDate     ,@PeriodStartDate AS PeriodStartDate     ,VendorName  FROM dbo.Payroll_TrialResults pr  INNER JOIN dbo.Payroll_SalaryHead AS sh   ON pr.SalaryHeadID = sh.SalaryHead_ID  INNER JOIN dbo.Payroll_IRP5Code   ON sh.IRP5CodeId = dbo.Payroll_IRP5Code.IRP5Code_ID  INNER JOIN dbo.Const_TransactionType   ON dbo.Payroll_IRP5Code.TransactionTypeID = dbo.Const_TransactionType.TransactionType_ID  LEFT JOIN dbo.Cons_Vendor cv   ON cv.Vendor_ID = pr.VendorID  WHERE  TaxSavePurpose = 0  AND (SalaryHead_ID = @SalaryHeadId  OR @SalaryHeadId = 0)  AND (TransactionType_ID = @TransactionTypeId  OR @TransactionTypeId = 0)  AND pr.PeriodID = @PeriodId  AND (pr.VendorID = @VendorId  OR @VendorId = 0)  GROUP BY TransactionType_ID    ,TransactionTypeDesc    ,SalaryHeadTitle    ,VendorName    ,pr.IRP5Code  ORDER BY TransactionType_ID    end  

GO

-- ============================================
-- SP: Payroll_EFTApproveNotification
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,07/11/2016,>  -- Description: <Description,notification grid,>  -- Modified: Himil Modi - Add sub condition for PayrollStatus ='Requested'  -- =============================================  CREATE PROCEDURE dbo.Payroll_EFTApproveNotification   AS  BEGIN   select ppi.PaymentDueDate,pb.BatchType+'(' + cc.CycleDesc +')' as InstructionType, pb.InvoiceTotalAmount,pb.NumberOfEmployees    from Payroll_PaymentInstructions ppi       inner join Payroll_PaymentBatches  pb on ppi.BatchID=pb.Batch_ID     inner join Const_Cycle cc on cc.Cycle_ID = pb.Payroll_CycleID   where InstructionsStatus='Requested' AND PayrollStatus = 'Requested'   group by ppi.BatchID,ppi.PaymentDueDate,BatchType,CycleDesc,pb.InvoiceTotalAmount,pb.NumberOfEmployees  END  

GO

-- ============================================
-- SP: Payroll_EFTFile_Generate_sp
-- Schema: dbo
-- ============================================
  -- ==========================================================================================================================================================================  -- Author:  Ravindra Jijotia    -- Create date: 02/02/2016    -- Description: This sp will decide which EFT file format to be used based on setup in Cashbook and will execute a respective sp.  -- Called by: Payroll_FinalRunCycleSalaryProcessing_sp (called by Final Payroll Run button)  -- EXEC Payroll_EFTFile_Generate_Sp 235, 4, 1234  -- ==========================================================================================================================================================================    CREATE PROCEDURE [dbo].[Payroll_EFTFile_Generate_sp]    @PeriodID INT,   @CashbookID INT,   @CashbookTransactionID INT  AS  BEGIN   BEGIN TRY   BEGIN TRAN      DECLARE @ExportFormatDesc VARCHAR(200), @StoredProcUsed VARCHAR(100)    DECLARE @sql varchar(200)        SELECT TOP 1 @ExportFormatDesc = ExportFormatDesc, @StoredProcUsed = StoredProcUsed    FROM Const_ExportFormat    WHERE ExportFormat_ID = (      SELECT ExportFormatID      FROM Const_CashbookExportType      WHERE CashbookID = @CashbookID       AND ExportTypeID = (        SELECT ExportType_ID        FROM Const_ExportType        WHERE ExportTypeDesc = 'EFTS - Salaries'        )      )        IF (@ExportFormatDesc = 'Standard Bank - Best 2000' AND @StoredProcUsed IS NOT NULL)    BEGIN     EXEC Payroll_EFTFile_STDBank_Best2000_Sp @PeriodID, @CashbookTransactionID      --SET @sql = 'EXEC ' + @StoredProcUsed + ' ' + CAST(@PeriodID AS VARCHAR) + ', ' + CAST(@CashbookTransactionID AS VARCHAR)          --execute sp_executesql @sql    END    --ELSE    --IF (@ExportFormatDesc = 'test 2')    --BEGIN    -- --EXEC Payroll_EFTFile_test2 @PeriodID, @CashbookTransactionID    --END    ELSE    BEGIN           INSERT  INTO Sys_ErrorLog ( moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName )     VALUES  ( 'Payroll', 'SQL Server', 'Payroll_EFTFile_Sp', 'Payroll EFT file Format is not specified or incorrect file format is setup.', 'SQL',       'Payroll EFT file Format is not specified or incorrect file format is setup.', GETDATE(), 'PayrollFinalRunUser' )          RAISERROR('Payroll EFT file Format is not specified or incorrect file format is setup.', 16, 1);    END      --IF (@ExportFormatDesc = 'Standard Bank - SSVS')    --BEGIN    -- EXEC Payroll_EFTFile_STDBank_SSVS_Sp @PeriodID, @CashbookID    --END     COMMIT TRAN   END TRY      BEGIN CATCH      DECLARE @ErrorMessage NVARCHAR(MAX), @ErrorSeverity INT, @ErrorState INT;      SELECT      @ErrorMessage = ERROR_MESSAGE(),     @ErrorSeverity = ERROR_SEVERITY(),     @ErrorState = ERROR_STATE();        RAISERROR (@ErrorMessage, -- Message text.       @ErrorSeverity, -- Severity.       @ErrorState -- State.      );              --ROLLBACK TRAN - Should only be in parent procedure      END CATCH  END

GO

-- ============================================
-- SP: Payroll_EFTFile_GetEFTFileDetailsByFormatTypeId_sp
-- Schema: dbo
-- ============================================
-- ==========================================================================================================================================================================  -- Author:  Ravindra Jijotia    -- Create date: 11 DEC 2015    -- Description: This sp will return EFT File format details based on FileFormatTypeId passed in parameter.  -- Called by: Settings > HR/Payroll Settings > EFT File Formats > Search Button  -- EXEC Payroll_EFTFile_FormatDetailList_sp 0  -- 24 06 2016 - Parikh N - Added EF.Enabled column  -- ==========================================================================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_EFTFile_GetEFTFileDetailsByFormatTypeId_sp]      @EFTFileFormatTypeId INT = 0  AS      BEGIN          SET NOCOUNT ON;            SELECT  EFTSet.EFTFileSettings_ID ,                  EF.ExportFormatDesc ,                  EF.ExportFormat_ID ,                  EFTSet.KeyName ,                  EFTSet.KeyValue ,                  EFTSet.KeyDescription ,                  EFTSet.[Enabled]          FROM    Const_Payroll_EFTFile_Settings EFTSet                  INNER JOIN Const_ExportFormat EF ON EFTSet.ExportFormatID = EF.ExportFormat_ID          WHERE   ( EFTSet.ExportFormatID = @EFTFileFormatTypeId                    OR @EFTFileFormatTypeId = 0                  )                  --AND EFTSet.[Enabled] = 1          ORDER BY EF.ExportFormatDesc;      END;  

GO

-- ============================================
-- SP: Payroll_EFTFile_GetEFTFileExportFormatsByExportTypeId_sp
-- Schema: dbo
-- ============================================
-- ==========================================================================================================================================================================  -- Author:  Ravindra Jijotia    -- Create date: 04 FEB 2016  -- Description: This sp will return EFT File formats based on Export TypeId passed in parameter.  -- Called by: Settings > HR/Payroll Settings > EFT File Format > Search Button  -- EXEC Payroll_EFTFile_GetEFTFileExportFormatsByExportTypeId_sp 0  -- 24 06 2016 - Parikh N - Added EF.Enabled column  -- ==========================================================================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_EFTFile_GetEFTFileExportFormatsByExportTypeId_sp] @ExportTypeId INT = 0  AS      BEGIN          SET NOCOUNT ON;            SELECT  EF.ExportFormat_ID ,                  EF.ExportFormatDesc ,                  ET.ExportTypeDesc ,                  ET.ExportType_ID ,                  EF.StoredProcUsed ,                  EF.Enabled          FROM    Const_ExportFormat EF                  INNER JOIN Const_ExportType ET ON EF.ExportType_ID = ET.ExportType_ID          WHERE   ( EF.ExportType_ID = @ExportTypeId                    OR @ExportTypeId = 0                  )                  --AND EF.Enabled = 1          ORDER BY EF.ExportFormatDesc;      END;  

GO

-- ============================================
-- SP: Payroll_EFTFile_STDBank_Best2000_Sp
-- Schema: dbo
-- ============================================
  -- ==========================================================================================================================================================================  -- Author:  Ravindra Jijotia    -- Create date: 02/02/2016    -- Description: This sp will insert data in Payroll_EFTFileData using Standard Bank - Best 2000 format.  -- Called by: Payroll_FinalRunCycleSalaryProcessing_sp (called by Final Payroll Run button)  -- EXEC Payroll_EFTFile_STDBank_Best2000_Sp 235, 1234  -- 2016-04-30 Ravindra Jijotia: Fixed Date on top, branch code, Nett pay there should be no point to separate the decimal cent.  -- 2016-05-02 Ravindra Jijotia: Added NULL check for @CashbookTransactionID  -- 2016-05-05 TP36430 Ravindra Jijotia: The amount should include the cent value but without a point or comma to separate it - EFTS File  -- 2016-07-18 TP40258 Lungisani Khumalo: Added a filter to only process employees using EFT  -- ==========================================================================================================================================================================    CREATE PROCEDURE [dbo].[Payroll_EFTFile_STDBank_Best2000_Sp]    @PeriodID INT,   @CashbookTransactionID INT  AS  BEGIN   BEGIN TRY   --BEGIN TRAN        DECLARE @ExportFormatDesc NVARCHAR(100), @ExportTypeDesc NVARCHAR(50), @Module VARCHAR(20), @PaymentTypeDesc NVARCHAR(20)      SET @ExportFormatDesc = 'Standard Bank - Best 2000'    SET @ExportTypeDesc = 'EFTS - Salaries'    SET @Module = 'Payroll'    SET @PaymentTypeDesc='EFT'      DELETE FROM Payroll_EFTFileData    DBCC CHECKIDENT ('Payroll_EFTFileData', RESEED, 0)       --***RECORD HEADER***    INSERT INTO Payroll_EFTFileData    SELECT       CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'HeaderErrorFlag' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(1)) --ERROR FLAG    + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'CompanyCode' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(4)) --COMPANY CODE 4??    + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'CompanyName' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(40)) --COMPANY NAME 40 ??    --+ CONVERT(VARCHAR(8), (select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'ActionDate' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1), 112)--ACTION DATE (CCYYMMDD) 8    + CONVERT(VARCHAR(8), GETDATE() , 112)--ACTION DATE (CCYYMMDD) 8    + (select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'Language' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) --LANGUAGE 1    + CAST(' ' as CHAR(8)) --FILLER SPACES(8)    + CAST(LEFT('               ', 15 - LEN((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'HeaderStatementReference' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1)))      + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'HeaderStatementReference' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) AS VARCHAR) as CHAR(15)) -- STATEMENT REFERENCE 15    + (select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'Sign' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) --SIGN 1??    + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'EntryClass' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(2)) -- ENTRY CLASS 2 ??    + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TaxCode' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(1)) -- TAX CODE 1 ??    + CAST(' ' as CHAR(9)) -- FILLER SPACES 9    + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'BatchNumber' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(2)) -- BATCH NUMBER 2 ??    + (select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'SystemType' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) -- TEST OR LIVE 4??            IF (@CashbookTransactionID IS NOT NULL)    BEGIN     --****TRANSACTION RECORD***     INSERT INTO Payroll_EFTFileData     SELECT        CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TransactionMethodOfPayment' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1  )as CHAR(1)) -- METHOD OF PAYMENT 1     + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'CompanyCode' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(4)) -- COMPANY CODE 4 ??     --+ CAST(LEFT('000000', 6 - LEN(ISNULL(PE.BranchID, 0))) + CAST(ISNULL(PE.BranchID, 0) AS VARCHAR) as CHAR(6)) -- BRANCH NUMBER – CREDITOR/ DEBTOR/ SALARY ACCOUNT 6 ??     + CAST(LEFT('000000', 6 - LEN(ISNULL((select BankBranchCode from Const_BankBranchCode where BankBranchCode_ID = PE.BranchID), 0))) + CAST(ISNULL((select BankBranchCode from Const_BankBranchCode where BankBranchCode_ID = PE.BranchID), 0) AS VARCHAR) as CHAR(6)) -- BRANCH NUMBER – CREDITOR/ DEBTOR/ SALARY ACCOUNT 6 ??     + CAST(LEFT('0000000', 7 - LEN(ISNULL(PE.Employee_ID, 0))) + CAST(ISNULL(PE.Employee_ID, 0) AS VARCHAR) as CHAR(7)) -- EMPLOYEE NUMBER (THIS FIELD IS NOT MANDATORY) 7     + CAST(LEFT('0000000000000000000', 19 - LEN(ISNULL(PE.AccountNumber, 0))) + CAST(ISNULL(PE.AccountNumber, 0) AS VARCHAR) as CHAR(19)) -- ACCOUNT NUMBER – CREDITOR/ DEBTOR/ SALARY ACCOUNT 19     + CAST(' ' as CHAR(1)) --FILLER SPACES(1)     + CAST(ISNULL(PE.AccountTypeID, 0) as CHAR(1)) -- ACCOUNT TYPE 1 ??     --+ CAST(LEFT('00000000000', 11 - LEN(ISNULL(LCV.VoteAmount, 0))) + CAST(ISNULL(LCV.VoteAmount, 0) AS VARCHAR) as CHAR(11)) -- AMOUNT (11)      + CAST(LEFT('00000000000', 11 - LEN(ISNULL(CAST(REPLACE(LCV.VoteAmount, '.', '') AS INT), 0))) + CAST(ISNULL(CAST(REPLACE(LCV.VoteAmount, '.', '') AS INT), 0) AS VARCHAR) as CHAR(11))      + CAST(ISNULL(PE.AccountHolderName, '') as CHAR(20)) -- ACCOUNT NAME – CREDITOR/ DEBTOR/ SALARY ACCOUNT 20     + CAST(' ' as CHAR(10)) -- FILLER 10     + CAST(LEFT('               ', 15 - LEN((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'HeaderStatementReference' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1)))       + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'HeaderStatementReference' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) AS VARCHAR) as CHAR(15)) -- STATEMENT REFERENCE 15     + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TransactionRTGSIndicator' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(1)) -- RTGS INDICATOR APPLICABLE FOR CREDITS ONLY.1     FROM Led_CashbookVote LCV        INNER JOIN Payroll_Employee PE ON LCV.EmployeeId = PE.Employee_ID AND PE.PaymentTypeID= (select PaymentType_ID from Const_PaymentType where PaymentTypeDesc=@PaymentTypeDesc)  --SELECT ONLY EMPLOYEES USING EFT      --select PaymentType_ID from Const_PaymentType where PaymentTypeDesc=@PaymentTypeDesc--CHEQUE      --select PaymentType_ID from Const_PaymentType where PaymentTypeDesc=@PaymentTypeDesc--CASH      WHERE LCV.CashbookTransactionID = @CashbookTransactionID and PE.Enabled = 1        END        IF (@CashbookTransactionID IS NOT NULL)    BEGIN     --***TRAILER RECORD***     INSERT INTO Payroll_EFTFileData     SELECT        CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TrailerErrorFlag' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(1)) -- ERROR FLAG 1     + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'CompanyCode' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(4)) -- COMPANY CODE 4 ??     + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TrailerIndicator' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(1)) -- TRAILER INDICATOR 1 ??     + CAST(' ' as CHAR(30)) -- FILLER 30     + CAST(LEFT('0000000000000', 13 - LEN(CAST(REPLACE(sum(LCV.VoteAmount), '.', '') AS INT))) + CAST((CAST(REPLACE(sum(LCV.VoteAmount), '.', '') AS INT)) AS VARCHAR) as CHAR(13)) -- AMOUNT (13) ??     + CAST(' ' as CHAR(14)) -- FILLER 14     + CAST((select KeyValue from Const_Payroll_EFTFile_Settings where KeyName = 'TrailerNumberOfTransaction' AND ExportFormatID = (SELECT ExportFormat_ID FROM Const_ExportFormat WHERE ExportFormatDesc = @ExportFormatDesc AND ExportType_ID = (SELECT ExportType_ID FROM Const_ExportType WHERE ExportTypeDesc = @ExportTypeDesc)) AND Module = @Module AND Enabled = 1) as CHAR(7)) -- NUMBER OF TRANSACTIONS 7     + CAST(' ' as CHAR(26)) -- FILLER 26      FROM Led_CashbookVote LCV        INNER JOIN Payroll_Employee PE ON LCV.EmployeeId = PE.Employee_ID         WHERE LCV.CashbookTransactionID = @CashbookTransactionID and PE.Enabled = 1      group by LCV.CashbookTransactionID    END       --COMMIT TRAN   END TRY      BEGIN CATCH      DECLARE @ErrorMessage NVARCHAR(MAX), @ErrorSeverity INT, @ErrorState INT;      SELECT      @ErrorMessage = ERROR_MESSAGE(),     @ErrorSeverity = ERROR_SEVERITY(),     @ErrorState = ERROR_STATE();      INSERT  INTO Sys_ErrorLog ( moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName )          VALUES  ( 'Payroll', 'SQL Server', 'Payroll_EFTFile_STDBank_Best2000_Sp', @ErrorMessage, 'SQL', @ErrorMessage, GETDATE(), 'PayrollFinalRunUser' )      RAISERROR (@ErrorMessage, -- Message text.       @ErrorSeverity, -- Severity.       @ErrorState -- State.      );                --ROLLBACK TRAN - Should only be in parent procedure      END CATCH  END  

GO

-- ============================================
-- SP: Payroll_EFTFileData_new_tbl_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_EFTFileData_new_tbl_sp]   AS  BEGIN   IF Not EXISTS(SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'Payroll_EFTFileData')    BEGIN     CREATE TABLE [dbo].[Payroll_EFTFileData] (     [ID] [int] IDENTITY(1, 1) NOT NULL     ,[Data] [varchar](96) NOT NULL    ,CONSTRAINT [PK_Payroll_EFTFileData] PRIMARY KEY CLUSTERED ([ID] ASC) WITH (     PAD_INDEX = OFF     ,STATISTICS_NORECOMPUTE = OFF     ,IGNORE_DUP_KEY = OFF     ,ALLOW_ROW_LOCKS = ON     ,ALLOW_PAGE_LOCKS = ON     ) ON [PRIMARY]    ) ON [PRIMARY]   END  END  

GO

-- ============================================
-- SP: Payroll_EFTGenerateNotification
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,07/11/2016,>  -- Description: <Description,notification grid,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EFTGenerateNotification]     AS  BEGIN    select  PaymentDueDate,pb.BatchType+'(' + cc.CycleDesc +')' as InstructionType, pb.InvoiceTotalAmount,pb.NumberOfEmployees   from  Payroll_PaymentBatches  pb     inner join Const_Cycle cc on cc.Cycle_ID = pb.Payroll_CycleID  where PayrollStatus ='New'  END    

GO

-- ============================================
-- SP: Payroll_EFTRejectedNotification
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,13/03/2018,>  -- Description: <Description,notification grid,>  -- =============================================  CREATE PROCEDURE dbo.Payroll_EFTRejectedNotification  AS  BEGIN   select [PB].[PaymentDueDate], [Batch_ID], [PayrollStatus], [LedgerPaymentStatus],       coalesce((select count([PaymentInstructions_ID])        from [Payroll_PaymentInstructions]        where ([BatchID] = [PB].[Batch_ID] and [Changed] = 1)), 0) as [Updated],       [BatchType], [NumberOfEmployees], [NumberOfTransactions], [PB].[InvoiceTotalAmount], [PB].[ProcessedDate], [CC].[CycleDesc] as [PayrollCycle]      from [Payroll_PaymentBatches] as [PB] with(nolock)       join [Const_Cycle] as [CC] on [CC].[Cycle_ID] = [PB].[Payroll_CycleID] and [CC].[Enabled] = 1      where PayrollStatus = 'Rejected'  END

GO

-- ============================================
-- SP: Payroll_Employee201Rpt_sp
-- Schema: dbo
-- ============================================
   -- =============================================      -- Modified date : 2022/06/13      -- Changes : Pavan (Replaced hardcoded '2016/2017' Year to @FinYear)      -- Changes : Richa M - This SP was over complicated and returned the incorrect results.  -- =============================================      CREATE Procedure [dbo].[Payroll_Employee201Rpt_sp]      @FinYear NVARCHAR(10)   ,@Month INT   ,@EmployeeID INT     ,@DepartmentId INT       AS    BEGIN     DECLARE @FromDate datetime  DECLARE @TaxYear varchar(10)  DECLARE @EndDate datetime     SELECT top 1 @FromDate = cp.PeriodStartDate,@EndDate = cp.PeriodEndDate,    @TaxYear = cp.TaxYear   FROM dbo.Payroll_CyclePeriodDetails CP WITH(NOLOCK)     INNER JOIN Payroll_EmployeePayslip EP WITH(NOLOCK) ON EP.PeriodID = CP.Period_ID     WHERE DATEPART(MONTH,PeriodStartDate) = @Month     AND DATEPART(YEAR, PeriodStartDate) = @FinYear     AND Processed = 1  order by CP.Period_ID asc        DECLARE @Period TABLE (Period_Id INT)        INSERT INTO @Period     SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails   WHERE DATEPART(MONTH,PeriodEndDate) = @Month     AND DATEPART(YEAR, PeriodEndDate) = @FinYear   AND Processed = 1       DECLARE @MunicipalityName varchar(500)   DECLARE @UIFRef varchar(50)   DECLARE @SDLRef varchar(50)   DECLARE @PAYERef varchar(50)     Select @MunicipalityName = MunicipalityName,@UIFRef = UIFReferenceNo,@SDLRef = SDLReferenceNo,@PAYERef = PayeRegistrationNo from Payroll_Municipality     DECLARE @PAYE decimal(18,4)   DECLARE @SDL decimal(18,4)   DECLARE @UIF decimal(18,4)        Select @PAYE = (select sum(Amount)PAYE from Payroll_PayrollResults where PeriodID in (select Period_ID from @Period) and IRP5Code = 4102)   Select @SDL = (select sum(Amount)PAYE from Payroll_PayrollResults where PeriodID in (select Period_ID from @Period) and IRP5Code = 4142)   Select @UIF = (select sum(Amount)PAYE from Payroll_PayrollResults where PeriodID in (select Period_ID from @Period) and IRP5Code = 4141)     select @MunicipalityName MunicipalityName,    DATENAME(MM, @FROMDATE) + ' ' + CONVERT(NVARCHAR, @FinYear) AS PAYMENTPERIOD,     @UIFRef UIFReferenceNo,    @SDLRef SDLReferenceNo,    @PAYERef PayeRegistrationNo,    RIGHT(@TaxYear,4)Year,    IsNULL(@UIF,0) UIF,    IsNULL(@SDL,0) SDL,    IsNULL(@PAYE,0) PAYE,    (CONVERT(VARCHAR(50), @EndDate, 103)) AS LastDayinMonth      END

GO

-- ============================================
-- SP: Payroll_Employee3rdPartyContribution_Trial_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,27-02-2017>  -- Description: <Description,,>  -- Update date: 22/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date: 28/06/2017 - Updated Parameters  -- Update date: 30/06/2017 - Updated the joins to the correct mappings  -- Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  -- Modified: Richa M 2021/02/21 - Only include Approved Installments  -- =============================================  CREATE procedure [dbo].[Payroll_Employee3rdPartyContribution_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int , @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try         declare @Periods table (        [ID] [int] identity(2,1) not null,    [PeriodId] [int]        )          insert into @Periods (PeriodId) select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails] where [CycleID] = @CycleID and [CycleModeID] = 1 and [Processed] = 1 and [Period_ID] < @PeriodID  order by [Period_ID] desc      if(not exists(select [PeriodId] from @Periods where [PeriodId] = @PeriodID))    begin     insert into @Periods (PeriodId) select @PeriodID    end      declare @rounding_reminder decimal(18, 2) = 0.01      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [VendorID], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear] , [Simulation])         select [EmployeeID], [EmployeePayrollDefinition_ID],[Amount], @Month, @SCOAYear, @PeriodID, [Vendor_ID],[SalaryHeadTitle], [ReferenceNo], @TaxYear, @Simulation              from (       select [PP].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID],                  sum(cast((case when ([PP].[Balance] - ([PP].[EMI] * [P].[ID])) >= 0 then ([PP].[EMI] * [P].[ID]) else [PP].[Balance] end) as decimal(18, 6))) as [Amount], [Vendor_ID] as [Vendor_ID], [SH].[SalaryHeadTitle] as [SalaryHeadTitle], [PP].[ReferenceNo] as [ReferenceNo]         from [Payroll_3rdPartyPayment] as [PP] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [PP].[SalaryheadID] = [SalaryHead_ID] and [SH].[Enabled] = 1                   join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadID] = [SalaryHead_ID] and [PP].[EmployeeID] = [EPD].[EmployeeID] and [EPD].[Enabled] = 1              join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = [PP].[Period_ID] and [CPD].[Enabled] = 1         left join [Cons_Vendor] as [CV] with(nolock) on [PP].[VendorID] = [Vendor_ID]         left join [Payroll_GLItems] as [GL] with(nolock) on [GL].[VendorID] = [Vendor_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear and [SH].[SalaryHead_ID] = [GL].[SalaryHeadID]              join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PP].[EmployeeID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]            left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         join @Periods [P] on [P].[PeriodId] = [PP].[Period_ID] and [P].[PeriodId] <> @PeriodID          where ([PP].[EmployeeID] = (case @EmployeeID when 0 then [PP].[EmployeeID] else @EmployeeID end) and ISNULL([PP].[Approved],0) = 1 and [PP].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [PP].[Balance] > 0 and ([CV].[StatusID] is null or [CV].[StatusID] in(1, 7)) and [TransactionTypeID] = 2                  and ([PP].[Processed] = 0  or [PP].[Processed] is null) and [PP].[PartyPayment_ID] not in (select[PartyPayment_ID] from [Payroll_3rdPartyPaymentHistory] with(nolock))             and       (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1)        group by [PP].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [Vendor_ID], [SH].[SalaryHeadTitle], [PP].[ReferenceNo], [PP].[Period_ID]             union                 select       [PP].[EmployeeID] as [EmployeeID],       [EPD].[EmployeePayrollDefinition_ID] as [EmployeePayrollDefinition_ID],      sum (case        when abs([PP].[Balance] - [PP].[EMI]) = @rounding_reminder or ([PP].[Balance] - [PP].[EMI]) < 0         then [PP].[Balance]       else [PP].[EMI]       end) as [Amount],      [Vendor_ID] as [Vendor_ID],       [SH].[SalaryHeadTitle] as [SalaryHeadTitle],       [PP].[ReferenceNo] as [ReferenceNo]         from [Payroll_3rdPartyPayment] as [PP] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [PP].[SalaryheadID] = [SalaryHead_ID] and [SH].[Enabled] = 1                   join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadID] = [SalaryHead_ID] and [PP].[EmployeeID] = [EPD].[EmployeeID] and [EPD].[Enabled] = 1              join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = [PP].[Period_ID] and [CPD].[Enabled] = 1         left join [Cons_Vendor] as [CV] with(nolock) on [PP].[VendorID] = [Vendor_ID]         left join [Payroll_GLItems] as [GL] with(nolock) on [GL].[VendorID] = [Vendor_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear and [SH].[SalaryHead_ID] = [GL].[SalaryHeadID]         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PP].[EmployeeID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]            left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         OUTER APPLY (SELECT COUNT(*) as Num FROM Payroll_3rdPartyPaymentHistory PPH WHERE PPH.PartyPayment_ID = PP.PartyPayment_ID) AS PeriodsPaid        where ([PP].[EmployeeID] = (case @EmployeeID when 0 then [PP].[EmployeeID] else @EmployeeID end) and [PP].[Enabled] = 1 and IsNULL([PP].[Approved],0) = 1  and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [PP].[Balance] > 0 and ([CV].[StatusID] is null or [CV].[StatusID] in(1, 7)) and [TransactionTypeID] = 2              and ([PP].[Processed] = 0  or [PP].[Processed] is null) and [PP].[Balance] > 0 and ([PP].[Period_ID] <= @PeriodID                 and [PP].[PartyPayment_ID] not in (                 select [PartyPayment_ID] from [Payroll_3rdPartyPayment] as [PP] with(nolock)                         join @Periods [P] on [P].[PeriodId] = [PP].[Period_ID] and [P].[PeriodId] <> @PeriodID             where ([PP].[EmployeeID] = (case @EmployeeID when 0 then [PP].[EmployeeID] else @EmployeeID end) and [PP].[Enabled] = 1 and [PP].[Balance] > 0 and ([CV].[StatusID] is null or [CV].[StatusID] in(1, 7)) and [TransactionTypeID] = 2                 and ([PP].[Processed] = 0  or [PP].[Processed] is null) and [PP].[PartyPayment_ID] not in (select[PartyPayment_ID] from [Payroll_3rdPartyPaymentHistory] with(nolock))           ))) and          (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1)        group by [PP].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [Vendor_ID], [SH].[SalaryHeadTitle], [PP].[ReferenceNo], [PP].[Period_ID]            ) [List] order by [Amount] desc   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_Employee501Rpt_sp
-- Schema: dbo
-- ============================================
        -- =============================================      -- Author:  <Author,,GD>      -- Create date: <Create Date,,10 Jul 2014>      -- Description: <Description,,>      -- Call SP    : Payroll_Employee501Rpt_sp '2014', 8      -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column      -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA   --2021/10/08 M Van Wyk WI59987 Added Month Filter  -- 2021/11/09 R Strydom WI77814 Correct logic for Payslips  -- =============================================            CREATE procedure [Payroll_Employee501Rpt_sp]       @FinYear NVARCHAR(10),       @Month INT      AS      BEGIN        DECLARE @MinYear INT,    @MaxYear INT,    @FinancialYear NVARCHAR(10),    @PeriodOfReconciliation DATETIME;    IF (@Month = 8)  BEGIN   SELECT @MinYear = CAST([Data] AS INT) FROM dbo.Split(@FinYear, '/') WHERE [Id] = 1;      SET @MaxYear = @MinYear + 1;   SET @FinancialYear = CONCAT(CAST(@MinYear AS NVARCHAR(4)), '/', CAST(@MaxYear AS NVARCHAR(4)));  END  ELSE IF (@Month = 2)  BEGIN   SELECT @MaxYear = CAST([Data] AS INT) FROM dbo.Split(@FinYear, '/') WHERE [Id] = 2;      SET @MaxYear = ISNULL(@MaxYear, @FinYear);   SET @MinYear = @MaxYear - 1;   SET @FinancialYear = CONCAT(CAST(@MinYear AS NVARCHAR(4)), '/', CAST(@MaxYear AS NVARCHAR(4)));  END;    SELECT @PeriodOfReconciliation = MAX([PeriodEndDate]) FROM Payroll_CyclePeriodDetails WHERE [FinancialYear] = @FinancialYear AND MONTH([PeriodEndDate]) = @Month;    ;WITH CyclePeriodDetails  AS  (   SELECT    cpd.*,    CASE c.[CycleTypeID]         /* MONTHLY */         WHEN 1 THEN CASE WHEN @Month = 2 THEN 12 ELSE 6 END         /* WEEKLY */         WHEN 2 THEN CASE WHEN @Month = 2 THEN 52 ELSE 26 END         /* Bi-WEEKLY */         WHEN 3 THEN CASE WHEN @Month = 2 THEN 26 ELSE 13 END      END AS 'CyclesInPeriod'   FROM    Payroll_CyclePeriodDetails cpd   INNER JOIN    Const_Cycle c ON cpd.[CycleID] = c.[Cycle_ID]        AND cpd.[PeriodInTaxYear] <= CASE c.[CycleTypeID]         /* MONTHLY */         WHEN 1 THEN CASE WHEN @Month = 2 THEN 12 ELSE 6 END         /* WEEKLY */         WHEN 2 THEN CASE WHEN @Month = 2 THEN 52 ELSE 26 END         /* Bi-WEEKLY */         WHEN 3 THEN CASE WHEN @Month = 2 THEN 26 ELSE 13 END        END   WHERE    cpd.[Enabled] = 1   AND cpd.[Processed] = 1   AND cpd.[TaxYear] = @FinancialYear  ),  Payslips  AS  (   SELECT    pr.[PeriodID],      pr.[EmployeeID],      YEAR(cpd.[PeriodEndDate]) AS 'Year',      MONTH(cpd.[PeriodEndDate]) AS 'Month',      DATENAME(MONTH, cpd.[PeriodEndDate]) AS 'MonthName',      SUM(pr.[Amount]) AS 'Amount',    irp.[IRP5Code]   FROM      CyclePeriodDetails cpd    INNER JOIN    Payroll_PayrollResults pr ON cpd.[Period_ID] = pr.[PeriodID]           AND cpd.[CyclesInPeriod] >= pr.[TaxPeriod]   INNER JOIN      Payroll_SalaryHead sh ON pr.[SalaryHeadID] = sh.[SalaryHead_ID]     INNER JOIN      Payroll_IRP5Code irp ON sh.[IRP5CodeId] = irp.[IRP5Code_ID]        AND irp.[IRP5Code] IN (         4141, -- UIF         4142, -- SDL         4102  -- PAYE         )   GROUP BY    pr.[PeriodID],      pr.[EmployeeID],     YEAR(cpd.[PeriodEndDate]),      MONTH(cpd.[PeriodEndDate]),      DATENAME(MONTH, cpd.[PeriodEndDate]),      irp.[IRP5Code]  ),  Totals  AS  (   SELECT    i.[PayrollPeriodID],    SUM(id.[Amount]) AS 'Amount'   FROM    CyclePeriodDetails cpd   INNER JOIN    SCM_Invoice i ON cpd.[Period_ID] = i.[PayrollPeriodID]   INNER JOIN    SCM_InvoiceDetail id ON i.[Invoice_ID] = id.[InvoiceID]         AND (           id.[ItemDescription] LIKE 'Pay-as-you-earn%'          OR id.[ItemDescription] = 'Skills Development Levy (SDL)'          OR id.[ItemDescription] = 'Unemployment Insurance Fund (UIF)'          )   INNER JOIN    Const_SCMVendorStatus_sys vs ON i.[StatusID] = vs.[Status_ID]           AND LOWER(vs.[Status]) IN ('partially paid', 'fully paid')   GROUP BY    i.[PayrollPeriodID]  )    SELECT   ep.[Year] AS 'YearNumber', ep.[Month] AS 'MonthNumber', ep.[MonthName],   SUM(CASE WHEN ep.[IRP5Code] = 4141 THEN ep.[Amount] ELSE 0 END) AS 'UIF',   SUM(CASE WHEN ep.[IRP5Code] = 4142 THEN ep.[Amount] ELSE 0 END) AS 'SDL',   SUM(CASE WHEN ep.[IRP5Code] = 4102 THEN ep.[Amount] ELSE 0 END) AS 'PAYE',   ISNULL(SUM(t.[Amount]), 0) AS 'TotalPayment',   @PeriodOfReconciliation AS 'PeriodOfReconciliation',   @MaxYear AS 'TraYear'  FROM   Payslips ep  LEFT JOIN   Totals t ON ep.[PeriodID] = t.[PayrollPeriodID]  WHERE   (@Month = 2 OR (ep.[Month] <= @Month AND ep.[Year] < @MaxYear))  GROUP BY   ep.[Year], ep.[Month], ep.[MonthName]  ORDER BY   ep.[Year], ep.[Month]   PRINT @PeriodOfReconciliation      END

GO

-- ============================================
-- SP: Payroll_EmployeeAllCostCentreCalculation_Trail_sp
-- Schema: dbo
-- ============================================
    /*   Author  : TSHEKEDI MOGWERE   Create date : 18/02/2017   Description : Calculates Employees S&T Claims   Update date : 11/05/2017 - Changed the mappings for Method of Calculation   Update date : 28/06/2017 - Updated Parameters   Update date : 30/06/2017 - Updated the joins to the correct mappings   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_EmployeeAllCostCentreCalculation_Trail_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try        declare @Periods table (        ID [int] identity(1,1) not null,    PeriodId [int]        )          insert into @Periods (PeriodId) select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails] where [CycleID] = @CycleID and [CycleModeID] = 1 and [Period_ID] <= @PeriodID      if(not exists(select [PeriodId] from @Periods where [PeriodId] = @PeriodID))    begin     insert into @Periods (PeriodId) select @PeriodID    end          insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [VendorID], [ReferenceNo], [TaxYear],[Simulation],    [ProjectID],[DivisionId],[ScoaItemID],[FunctionId],[RegionId],[FundId])       select   [EmployeeID], [PayrollDefinationID], [CostAmount], @Month, @SCOAYear, @PeriodID, [SalaryHeadTitle], [VendorID], [ReferenceNo], @TaxYear,@Simulation,     ProjectOverride,DivisionOverride,ScoaItemIdOverride,ScoaFunctionOverride,ScoaRegionOverride,ScoaFundOverride        from (         select distinct [CC].[EmployeeID], [CC].[PayrollDefinationID], sum((cast([CostAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as [CostAmount], [SalaryHeadTitle], [GL].[VendorID], [ReferenceNo],       [CC].[ScoaitemProjectId] ProjectOverride,       [CC].[ScoaDivisionId]DivisionOverride,        [CC].[ScoaItemId] ScoaItemIdOverride,       [CC].[ScoafunctionId] ScoaFunctionOverride,       [CC].[ScoaRegionId] ScoaRegionOverride,       [CC].[ScoaFundId] ScoaFundOverride          from [Payroll_CostCenter] as [CC] with(nolock)           join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [CC].[PayrollDefinationID] and [EPD].[EmployeeID] = [CC].[EmployeeID] and [EPD].[Enabled] = 1           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1              join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [CC].[EmployeeID]              join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = [CC].[PeriodID] and [CPD].[Enabled] = 1                                   join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [CC].[EmployeeID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]           join @Periods as [P] on [CC].[PeriodID] = [P].[PeriodId]             left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]          where ([CC].[EmployeeID] = (case @EmployeeID when 0 then [CC].[EmployeeID] else @EmployeeID end) and [CC].[Enabled] = 1 and  ([CC].[EveryMonth] is null or [CC].[EveryMonth] = 0)  and ([CC].[Processed] is null or [CC].[Processed] = 0) and            (case            when @CycleModeID = 1 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end            when @CycleModeID = 2 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end            else 0 end) = 1          )          group by [CC].[EmployeeID], [PayrollDefinationID], [SalaryHeadTitle], [TransactionTypeID], [GL].[VendorID], [ReferenceNo],[CC].[ScoaitemProjectId],       [CC].[ScoaDivisionId],        [CC].[ScoaItemId],       [CC].[ScoafunctionId],       [CC].[ScoaRegionId],       [CC].[ScoaFundId]         union all         select distinct [CC].[EmployeeID], [CC].[PayrollDefinationID], sum((cast([CostAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as [CostAmount], [SalaryHeadTitle], [GL].[VendorID], [ReferenceNo],       [CC].[ScoaitemProjectId] ProjectOverride,       [CC].[ScoaDivisionId]DivisionOverride,        [CC].[ScoaItemId] ScoaItemIdOverride,       [CC].[ScoafunctionId] ScoaFunctionOverride,       [CC].[ScoaRegionId] ScoaRegionOverride,       [CC].[ScoaFundId] ScoaFundOverride        from [Payroll_CostCenter] as [CC] with(nolock)           join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [CC].[PayrollDefinationID] and [EPD].[EmployeeID] = [CC].[EmployeeID] and [EPD].[Enabled] = 1           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1              join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [CC].[EmployeeID]              join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = [CC].[PeriodID] and [CPD].[Enabled] = 1                                   join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [CC].[EmployeeID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]           left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]          where ([CC].[EmployeeID] = (case @EmployeeID when 0 then [CC].[EmployeeID] else @EmployeeID end) and [CC].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and                    [CC].[EveryMonth] = 1 and ([CC].[PeriodID]  >= (select min([PeriodId]) from @Periods)) and           (case            when @CycleModeID = 1 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end            when @CycleModeID = 2 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end            else 0 end) = 1        )          group by [CC].[EmployeeID], [PayrollDefinationID], [SalaryHeadTitle], [TransactionTypeID], [GL].[VendorID], [ReferenceNo],[CC].[ScoaitemProjectId],       [CC].[ScoaDivisionId],        [CC].[ScoaItemId],       [CC].[ScoafunctionId],       [CC].[ScoaRegionId],       [CC].[ScoaFundId]              ) as [Costs]     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(),@Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeAllCostCentreCalculation_TrailSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Create date : 31/01/2019   Description : Calculates Employee S&T Claims (Simulation)   Update Date : 11/04/2019 => Added Employee S&T Claims (Simulation) @ Terminations  */  create procedure [Payroll_EmployeeAllCostCentreCalculation_TrailSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [TransactionTypeID], [SalaryHead_ID], [EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SalaryHeadTitle], [Value]        from (         select distinct [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [CC].[EmployeeID], [SH].[SalaryHeadTitle], sum((cast([CostAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as [Value]          from [Payroll_CostCenter] as [CC] with(nolock)           join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [CC].[PayrollDefinationID] and [EPD].[EmployeeID] = [CC].[EmployeeID] and [EPD].[Enabled] = 1           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1              join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [CC].[EmployeeID]           join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (            (isnull([TPS].[EmployeeChangeID], 0) = (case             when @SimulationType = 1 then @ParentID             else 0            end))            or            (isnull([TPS].[TerminationID], 0) = (case             when @SimulationType = 2 then @ParentID             else 0            end))           )          where ([CC].[EmployeeID] = @EmployeeID and [CC].[Enabled] = 1 and [CostAmount] > 0 and isnull([CC].[EveryMonth], 0) = 0  and isnull([CC].[Processed], 0) = 0)           group by [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [CC].[EmployeeID], [SH].[SalaryHeadTitle]         union         select distinct [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [CC].[EmployeeID], [SH].[SalaryHeadTitle], sum((cast([CostAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as [Value]          from [Payroll_CostCenter] as [CC] with(nolock)           join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [CC].[PayrollDefinationID] and [EPD].[EmployeeID] = [CC].[EmployeeID] and [EPD].[Enabled] = 1           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1              join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [CC].[EmployeeID]           join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (            (isnull([TPS].[EmployeeChangeID], 0) = (case             when @SimulationType = 1 then @ParentID             else 0            end))            or            (isnull([TPS].[TerminationID], 0) = (case             when @SimulationType = 2 then @ParentID             else 0            end))           )          where ([CC].[EmployeeID] = @EmployeeID and [CC].[Enabled] = 1 and isnull([ExcludeFromPayment], 0) = 0 and [CostAmount] > 0 and [CC].[EveryMonth] = 1 and           [CC].[EntryDate] <= @UntilDate and isnull([CC].[EndDate], @StartDate) >= @StartDate)           group by [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [CC].[EmployeeID], [SH].[SalaryHeadTitle]        ) as [Costs]     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeAllPensionAndArrearsCalculation_Trail_sp
-- Schema: dbo
-- ============================================
    /*   Author  : FERDI BOTHA   Create date : 07/03/2017   Description : Calculates Employees Pension, Provident, Retirement Funds   Update date : 29/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 05/09/2017 - Updated the Type ID to match the Benifit Type   Update date : 23/11/2017 - Updated the Retirement Fund Type ID checks   Update date : 30/11/2017 - Updated Added Private Pension, Provident and Retirement Funds (as they need to be added as Deductions for the Employee Tax Calculation) - Ferdi Botha   Update Date :   16/10/2019 - Artur Anzorge => Changes for employee termination   Update Date : 07/04/2020 - Ilya Skavronskiy => Updated reference number and Salary Head title for Persion Fund   Update Date : 27/09/2021 - Fix SP for Private Fund   Update Date : 20/01/2023 - Richa M - Fix SP for Employees with Fixed Amount PensionFund   Update Date :   01/06/2023 - Richa M - When an Employee belongs to eg Pension and Retirement fund the RFI is calculation incorrectly  */  CREATE procedure [dbo].[Payroll_EmployeeAllPensionAndArrearsCalculation_Trail_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @TypeID int, @Simulation bit  as    begin     set nocount on;     begin try   if exists ( select Processed from [Payroll_CyclePeriodDetails] [CPD] where [CPD].[PeriodStartDate] = @StartDate and [CPD].[PeriodEndDate] = @EndDate and [CPD].[Enabled] = 1 and [CPD].[Processed] = 0 and [Period_ID] = @PeriodID and [CycleID] = @CycleID and [CycleModeID] = 1)    begin        declare @Processing table (       [EmployeeID] int not null,     [ContributionType] bit not null,     [TypeID] int not null,     [FundType] int not null,     [VendorID] int null,     [VendorName] nvarchar(200) null,     [IsPrivate] bit not null default(0),     [ValueRFI] decimal(18, 6) not null,     [EmployeeValue] decimal(18, 6) not null,     [EmployerValue] decimal(18, 6) not null,     [FringeValue] decimal(18, 6) not null default(0),     [Const_EmployeeValue] decimal(18, 6) not null,     [Const_EmployerValue] decimal(18, 6) not null,     [Const_EmployeeMaxValue] decimal(18, 6) not null,     [Const_EmployerMaxValue] decimal(18, 6) not null,     [FundPercentage] decimal(18, 6) not null,     [ReferenceNo] nvarchar(50) null    )      declare @Processed table (       [EmployeeID] int not null,     [PayrollDefinationID] int not null,     [SalaryHeadTitle] nvarchar(50) not null,     [TransactionTypeID] int not null,     [FundType] int not null,     [VendorID] int null,     [VendorName] nvarchar(200) null,     [IsPrivate] bit not null default(0),     [EmployeeValue] decimal(18, 6) not null,     [EmployerValue] decimal(18, 6) not null,     [FringeValue] decimal(18, 6) not null default(0),     [EmployeeMaxValue] decimal(18, 6) not null,     [EmployerMaxValue] decimal(18, 6) not null,     [ReferenceNo] nvarchar(50) null    )      declare @IRP5Code table (       [TypeID] [int] not null,     [IRP5Code] [int] not null      )      declare @SalaryHead table (       [SalaryHeadID] [int] not null      )      /* PENSION FUNDS */    if (@TypeID = 1)    begin       /* BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) [3817] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 3817)       /* BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME [3867] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 3867)       /* CURRENT PENSION FUND CONTRIBUTIONS [4001] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4001)       /* ARREAR PENSION FUND CONTRIBUTIONS [4002] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4002)       /* ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF) [4026] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4026)       /* EMPLOYER'S PENSION FUND CONTRIBUTIONS [4472] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4472)       insert into @SalaryHead([SalaryHeadID])        values (15),        (16),        (17)      end      /* PROVIDENT FUNDS */    if (@TypeID = 2)    begin       /* BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) [3825] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 3825)       /* BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME [3875] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 3875)       /* CURRENT PROVIDENT FUND CONTRIBUTIONS [4003] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4003)       /* ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4004)       /* EMPLOYER'S PROVIDENT FUND CONTRIBUTIONS [4473] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4473)       insert into @SalaryHead([SalaryHeadID])        values (18),        (19),        (20)      end      /* RETIREMENT FUNDS */    if (@TypeID = 3)    begin       /* EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS [3828] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 3828)       /* EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME [3878] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 3878)       /* CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS [4006] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4006)       /* ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS [4007] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4007)       /* EMPLOYER'S RETIREMENT ANNUITY FUND CONTRIBUTIONS [4475] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4475)       insert into @SalaryHead([SalaryHeadID])        values (21),        (22),        (23)      end      insert into @Processing([EmployeeID], [ContributionType], [TypeID], [FundType], [VendorID], [VendorName], [IsPrivate], [ValueRFI], [EmployeeValue], [EmployerValue], [Const_EmployeeValue], [Const_EmployerValue], [Const_EmployeeMaxValue], [Const_EmployerMaxValue], [FundPercentage], [ReferenceNo])       select distinct [EBD].[EmployeeID], [ContributionType], [BenefitTypeID], [RetirementFundTypeID], [VendorID], [VendorName],       isnull([IsPrivate], 0),                   isnull(cast(                      IIF(BD.ProRata = 1 AND ISNULL(EEData.WDPM_Monthly, 0) > 0 AND ISNULL(EEData.WorkingDays, 0) > 0,                           [ValueRFI].[Value] / EEData.WDPM_Monthly * EEData.WorkingDays,                           [ValueRFI].[Value])                        as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([EBD].[EmployeeContribution] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([EBD].[EmployerContribution] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([BD].[EmpContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([BD].[EmplrContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([BD].[EmpContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([BD].[EmplrContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))),       isnull(cast([BD].[FundMemberCategoryFactors] as decimal(18, 6)), cast(0 as decimal(18, 6))),       ISNULL([EBD].[ReferenceNo], '')   from (Select * from [Payroll_EmpBenefitDetail] WHERE EmployeeId = @EmployeeID OR @EmployeeID = 0 and Enabled = 1) as [EBD]       left join (        select          [ETP].[EmployeeID],BenefitSchemeID, sum((cast(isnull(etp.Amount,0) as decimal(18,6)))) as Value                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [ETP].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID] and [EPD].[EmployeeID] = [ETP].[EmployeeID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        JOIN Payroll_EmpBenefitDetail AS EBD WITH(NOLOCK) ON PE.Employee_ID = EBD.EmployeeId AND EBD.Enabled = 1 AND EBD.IsPrivate = 0        JOIN Payroll_BenefitDetail BD on BD.Benefit_ID = EBD.BenefitSchemeID        LEFT JOIN [Payroll_BenefitDetail_SalaryHead] AS BDSH WITH(NOLOCK) ON SH.SalaryHead_ID = BDSH.SalaryHeadId AND EBD.BenefitSchemeID = BDSH.BenefitId        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1        join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [ETP].[EmployeeID] and [EP].[Period_ID] = [ETP].[PeriodID] and [EP].[Cycle_ID] = [PE].[CycleID]        left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]       where [ETP].[EmployeeID] = (case @EmployeeID when 0 then [ETP].[EmployeeID] else @EmployeeID end)         and [ETP].[PeriodID] = @PeriodID        AND EBD.JoinDate <= @EndDate AND ISNULL(EBD.TerminationDate, @StartDate) >= @StartDate        AND ((BDSH.Id IS NULL AND SH.IsRFI = 1) OR (BDSH.Id IS NOT NULL) OR (BD.ContributionType = 0 and BenefitTypeID <> 5))        and (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0 end) = 1       group by [ETP].[EmployeeID],BenefitTypeID,BenefitSchemeID)as ValueRFI on [ValueRFI].[EmployeeID] = [EBD].[EmployeeId] and Ebd.BenefitSchemeID = ValueRFI.BenefitSchemeID       join [Payroll_BenefitDetail] as [BD] with(nolock) on [Benefit_ID] = ValueRFI. [BenefitSchemeID] and [BD].[Enabled] = [EBD].[Enabled]      left outer join [Cons_Vendor] as [VEN] with(nolock) on [Vendor_ID] = [VendorID]                  CROSS APPLY (                      SELECT                           CASE                        WHEN @Simulation = 1 AND (NOT [ETI].[TerminationStartDate] IS NULL) AND [PEI].[UntilDays] > 0 THEN ISNULL([PEI].[UntilDays], 0)                        WHEN [PEI].[JoiningDate] BETWEEN @StartDate AND @EndDate AND [PEI].[StartDays] > 0 THEN ISNULL([PEI].[StartDays], 0)                        WHEN [PEI].[EndDate] BETWEEN @StartDate AND @EndDate AND [PEI].[UntilDays] > 0 THEN ISNULL([PEI].[UntilDays], 0)                        ELSE NULL                       END AS WorkingDays,                          PEI.WDPM_Monthly                      FROM Payroll_Employee AS PEI WITH(NOLOCK)                      LEFT JOIN Payroll_EmployeeTermination AS ETI WITH(NOLOCK) ON PEI.Employee_ID = ETI.EmployeeID AND ETI.Enabled = 1                      WHERE EBD.EmployeeID = PEI.Employee_ID                  ) AS EEData      where ([EBD].[Enabled] = 1 and [JoinDate] <= @EndDate and isnull([TerminationDate], @StartDate) >= @StartDate)            insert into @Processed([EmployeeID], [PayrollDefinationID], [SalaryHeadTitle], [TransactionTypeID], [FundType], [VendorID], [VendorName], [IsPrivate], [EmployeeValue], [EmployerValue], [FringeValue], [EmployeeMaxValue], [EmployerMaxValue], [ReferenceNo])       select [RFI].[EmployeeID], [EmployeePayrollDefinition_ID], [SalaryHeadTitle], [TransactionTypeID], [FundType], [VendorID], [VendorName], [IsPrivate],       (case         when [IsPrivate] = 1 then cast([EmployeeValue] as decimal(18, 6))         when [FundType] in(1, 2) then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployeeValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployeeValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployeeValue]          end)         when [FundType] = 3 then cast([EmployeeValue] as decimal(18, 6))         else 0        end) AS EmployeeValue,         (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         when [FundType] in(1, 2) then                (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployerValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployerValue]          end)         when [FundType] = 3 then cast([EmployerValue] as decimal(18, 6))         else 0        end) AS EmployerValue,             (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         when [FundType] = 1 then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployerValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployerValue]          end)         when [FundType] = 2 then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * (cast([FundPercentage] as decimal(18, 6)) - cast([Const_EmployeeValue] as decimal(18, 6)))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployeeValue]          end)         when [FundType] = 3 then cast([EmployerValue] as decimal(18, 6))         else 0        end) AS FringeValue,             (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         else cast([Const_EmployeeMaxValue] as decimal(18, 6))        end) AS EmployeeMaxValue,             (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         else cast([Const_EmployerMaxValue] as decimal(18, 6))        end) AS EmployerMaxValue,        [RFI].[ReferenceNo]        from [Payroll_IRP5Code] as [IRP5] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [PayrollSalaryHeadID] = [SH].[SalaryHead_ID] and [EPD].[Enabled] = 1         join @SalaryHead as [SHI] on [SHI].[SalaryHeadID] = [EPD].[PayrollSalaryHeadID]         join @Processing as [RFI] on [RFI].[EmployeeID] = [EPD].[EmployeeID] and         (case          when @TypeID = 1 and [TypeID] in(3, 7) then 1          when @TypeID = 2 and [TypeID] in(4, 8) then 1          when @TypeID = 3 and [TypeID] in(5, 9) then 1          else 0         end) = 1        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [IRP5].[Enabled] = 1         and isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code)         and ([IsPrivate] = 0 or ([IsPrivate] = 1 and [TransactionTypeID] = 2))        )      update @Processed set [EmployeeValue] = [EmployeeMaxValue] where ([FundType] in(1, 2) and [EmployeeValue] > [EmployeeMaxValue] and [EmployeeMaxValue] > 0)      update @Processed set [EmployerValue] = [EmployerMaxValue] where ([FundType] in(1, 2) and [EmployerValue] > [EmployerMaxValue] and [EmployerMaxValue] > 0)      update @Processed set [FringeValue] = [EmployerMaxValue] where ([FundType] = 1 and [FringeValue] > [EmployerMaxValue] and [EmployerMaxValue] > 0)      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [VendorID], [TaxYear], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxSavePurpose],[Simulation])       select       [EmployeeID],       [PayrollDefinationID],       (case       when [TransactionTypeID] = 2 then [EmployeeValue]       when [TransactionTypeID] = 3 then [EmployerValue]       when [TransactionTypeID] = 4 then [FringeValue]      end),       @Month,       @SCOAYear,       @PeriodID,       (case when [IsPrivate] = 1 then null else [VendorID] end),       @TaxYear,       (case when @TypeID = 1 then [VendorName] else [SalaryHeadTitle] end),       (case when @TypeID = 1 then [ReferenceNo] else left(isnull([VendorName], ''), 50) end),       [IsPrivate],       @Simulation       from @Processed       where ((case         when [TransactionTypeID] = 2 then [EmployeeValue]         when [TransactionTypeID] = 3 then [EmployerValue]         when [TransactionTypeID] = 4 then [FringeValue]        end) > 0)    end   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeAllPensionAndArrearsCalculation_TrailSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employee Pension, Provident, Retirement Funds (Simulation)   Update Date : 11/04/2019 => Added Employee Pension, Provident, Retirement Funds (Simulation) @ Terminations   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeAllPensionAndArrearsCalculation_TrailSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int, @TypeID int  as    begin     set nocount on;     begin try   if exists ( select Processed from [Payroll_CyclePeriodDetails] [CPD] where [CPD].[PeriodStartDate] = @StartDate and [CPD].[PeriodEndDate] = @UntilDate and [CPD].[Enabled] = 1 and [CPD].[Processed] = 0)    begin    declare @Processing table (       [EmployeeID] int not null,     [ContributionType] bit not null,     [TypeID] int not null,     [FundType] int not null,     [VendorID] int null,     [VendorName] nvarchar(200) null,     [IsPrivate] bit not null default(0),     [ValueRFI] decimal(18, 6) not null,     [EmployeeValue] decimal(18, 6) not null,     [EmployerValue] decimal(18, 6) not null,     [FringeValue] decimal(18, 6) not null default(0),     [Const_EmployeeValue] decimal(18, 6) not null,     [Const_EmployerValue] decimal(18, 6) not null,     [Const_EmployeeMaxValue] decimal(18, 6) not null,     [Const_EmployerMaxValue] decimal(18, 6) not null,     [FundPercentage] decimal(18, 6) not null      )      declare @Processed table (       [EmployeeID] int not null,     [PayrollDefinationID] int not null,     [SalaryHeadID] int not null,     [SalaryHeadTitle] nvarchar(50) not null,     [TransactionTypeID] int not null,     [FundType] int not null,     [VendorID] int null,     [VendorName] nvarchar(200) null,     [IsPrivate] bit not null default(0),     [EmployeeValue] decimal(18, 6) not null,     [EmployerValue] decimal(18, 6) not null,     [FringeValue] decimal(18, 6) not null default(0),     [EmployeeMaxValue] decimal(18, 6) not null,     [EmployerMaxValue] decimal(18, 6) not null      )      declare @IRP5Code table (       [TypeID] [int] not null,     [IRP5Code] [int] not null      )      /* PENSION FUNDS */    if (@TypeID = 1)    begin       /* BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) [3817] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 3817)       /* BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME [3867] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 3867)       /* CURRENT PENSION FUND CONTRIBUTIONS [4001] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4001)       /* ARREAR PENSION FUND CONTRIBUTIONS [4002] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4002)       /* ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF) [4026] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4026)       /* EMPLOYER'S PENSION FUND CONTRIBUTIONS [4472] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(3, 4472)      end      /* PROVIDENT FUNDS */    if (@TypeID = 2)    begin       /* BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) [3825] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 3825)       /* BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME [3875] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 3875)       /* CURRENT PROVIDENT FUND CONTRIBUTIONS [4003] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4003)       /* ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4004)       /* EMPLOYER'S PROVIDENT FUND CONTRIBUTIONS [4473] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(4, 4473)      end      /* RETIREMENT FUNDS */    if (@TypeID = 3)    begin       /* EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS [3828] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 3828)       /* EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME [3878] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 3878)       /* CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS [4006] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4006)       /* ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS [4007] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4007)       /* EMPLOYER'S RETIREMENT ANNUITY FUND CONTRIBUTIONS [4475] */     insert into @IRP5Code([TypeID], [IRP5Code]) values(5, 4475)      end      insert into @Processing([EmployeeID], [ContributionType], [TypeID], [FundType], [VendorID], [VendorName], [IsPrivate], [ValueRFI], [EmployeeValue], [EmployerValue], [Const_EmployeeValue], [Const_EmployerValue], [Const_EmployeeMaxValue], [Const_EmployerMaxValue], [FundPercentage])       select [EBD].[EmployeeID], [ContributionType], [BenefitTypeID], [RetirementFundTypeID], [VendorID], [VendorName], isnull([IsPrivate], 0), isnull(cast([ValueRFI].[Value] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([EBD].[EmployeeContribution] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([EBD].[EmployerContribution] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([BD].[EmpContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([BD].[EmplrContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([BD].[EmpContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([BD].[EmplrContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([BD].[FundMemberCategoryFactors] as decimal(18, 6)), cast(0 as decimal(18, 6)))        from [Payroll_EmpBenefitDetail] as [EBD] with(nolock) join (         select [ETP].[EmployeeID], sum(isnull([Value], cast(0 as decimal(18, 6)))) as [Value]          from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)           join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ETP].[EmployeeID]           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID] and [SH].[Enabled] = 1 and [SH].[IsRFI] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1           join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [ETP].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (            (isnull([TPS].[EmployeeChangeID], 0) = (case             when @SimulationType = 1 then @ParentID             else 0            end))            or            (isnull([TPS].[TerminationID], 0) = (case             when @SimulationType = 2 then @ParentID             else 0            end))           )          where ([ETP].[EmployeeID] = @EmployeeID)           group by [ETP].[EmployeeID]) as [ValueRFI] on [ValueRFI].[EmployeeID] = [EBD].[EmployeeId]          join [Payroll_BenefitDetail] as [BD] with(nolock) on [Benefit_ID] = [BenefitSchemeID] and [BD].[Enabled] = [EBD].[Enabled]          left outer join [Cons_Vendor] as [VEN] with(nolock) on [Vendor_ID] = [VendorID]        where ([EBD].[EmployeeId] = [ValueRFI].[EmployeeID] and [EBD].[Enabled] = 1 and [JoinDate] <= @UntilDate and isnull([TerminationDate], @StartDate) >= @StartDate)      insert into @Processed([EmployeeID], [PayrollDefinationID], [SalaryHeadID], [SalaryHeadTitle], [TransactionTypeID], [FundType], [VendorID], [VendorName], [IsPrivate], [EmployeeValue], [EmployerValue], [FringeValue], [EmployeeMaxValue], [EmployerMaxValue])       select [RFI].[EmployeeID], [EmployeePayrollDefinition_ID], [SalaryHead_ID], [SalaryHeadTitle], [TransactionTypeID], [FundType], [VendorID], [VendorName], [IsPrivate], (case         when [IsPrivate] = 1 then cast([EmployeeValue] as decimal(18, 6))         when [FundType] in(1, 2) then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployeeValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployeeValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployeeValue]          end)         when [FundType] = 3 then cast([EmployeeValue] as decimal(18, 6))         else 0        end), (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         when [FundType] in(1, 2) then                (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployerValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployerValue]          end)         when [FundType] = 3 then cast([EmployerValue] as decimal(18, 6))         else 0        end), (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         when [FundType] = 1 then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * cast([Const_EmployerValue] as decimal(18, 6))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployerValue]          end)         when [FundType] = 2 then          (case           when @TypeID = 3 and [TypeID] in(5, 9) then cast([EmployerValue] as decimal(18, 6))           when [ContributionType] = 1 then ((cast([ValueRFI] as decimal(18, 6)) * (cast([FundPercentage] as decimal(18, 6)) - cast([Const_EmployeeValue] as decimal(18, 6)))) / cast(100 as decimal(18, 6)))           when [ContributionType] = 0 then [Const_EmployeeValue]          end)         when [FundType] = 3 then cast([EmployerValue] as decimal(18, 6))         else 0        end), (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         else cast([Const_EmployeeMaxValue] as decimal(18, 6))        end), (case         when [IsPrivate] = 1 then cast(0 as decimal(18, 6))         else cast([Const_EmployerMaxValue] as decimal(18, 6))        end)        from [Payroll_IRP5Code] as [IRP5] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [PayrollSalaryHeadID] = [SalaryHead_ID] and [EPD].[Enabled] = 1         join @Processing as [RFI] on [RFI].[EmployeeID] = [EPD].[EmployeeID] and         (case          when @TypeID = 1 and [TypeID] in(3, 7) then 1          when @TypeID = 2 and [TypeID] in(4, 8) then 1          when @TypeID = 3 and [TypeID] in(5, 9) then 1          else 0         end) = 1        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [IRP5].[Enabled] = 1         and isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code)         and ([IsPrivate] = 0 or ([IsPrivate] = 1 and [TransactionTypeID] = 2))        )      update @Processed set [EmployeeValue] = [EmployeeMaxValue] where ([FundType] in(1, 2) and [EmployeeValue] > [EmployeeMaxValue] and [EmployeeMaxValue] > 0)      update @Processed set [EmployerValue] = [EmployerMaxValue] where ([FundType] in(1, 2) and [EmployerValue] > [EmployerMaxValue] and [EmployerMaxValue] > 0)      update @Processed set [FringeValue] = [EmployerMaxValue] where ([FundType] = 1 and [FringeValue] > [EmployerMaxValue] and [EmployerMaxValue] > 0)      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [TransactionTypeID], [SalaryHeadID], [EmployeeID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SalaryHeadTitle], (case          when [TransactionTypeID] = 2 then [EmployeeValue]          when [TransactionTypeID] = 3 then [EmployerValue]          when [TransactionTypeID] = 4 then [FringeValue]         end)        from @Processed        where ((case          when [TransactionTypeID] = 2 then [EmployeeValue]          when [TransactionTypeID] = 3 then [EmployerValue]          when [TransactionTypeID] = 4 then [FringeValue]         end) > 0)    end   end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeAttendanceManage_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 20/07/2013  -- Description: Employee Attendance manage  -- CALLS : Payroll_EmployeeAttendanceManage_sp 37,'2012/2013','07/01/2012','07/31/2013'  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_EmployeeAttendanceManage_sp]   @EmployeeID INT,   @FinanceYear NVARCHAR(10),   @FromDate  DATETIME,   @ToDate DATETIME,   @MONTH INT  AS  BEGIN    SET NOCOUNT ON;      DECLARE @EMPLOYEEPRESENT NVARCHAR(5)   DECLARE @STARTDAYS NVARCHAR(10)   SET @STARTDAYS = 1   DECLARE @TotalNo int   DECLARE @NEXTDATENAME NVARCHAR(50)   DECLARE @Parameter_Definition NVARCHAR(max)   DECLARE @SQL NVARCHAR(max)   DECLARE @EndMaxDate NVARCHAR(50)   SET @EMPLOYEEPRESENT = 'P'     SET @ToDate = DATEADD(DAY,1,@ToDate )   WHILE(@FromDate < @ToDate)    BEGIN    SELECT @NEXTDATENAME = DATENAME (DW,@FromDate)        IF (SELECT COUNT(EMPLOYEEID) FROM dbo.Payroll_LeaveApproveRequestDetails AS D INNER JOIN dbo.Payroll_LeaveApproveRequest AS R ON D.LeaveApproveRequestId = R.LeaveApproveRequest_ID WHERE LeaveDate = @FromDate and EmployeeID = @EmployeeID AND IsTaken = 1 ) > 0    BEGIN     SET @EMPLOYEEPRESENT = 'L'    END         SET @Parameter_Definition = N' @rowCount_out nvarchar(50) OUTPUT '    SET @SQL = 'SELECT  @rowCount_out=COUNT(*) FROM Payroll_Employee WHERE  ' + @NEXTDATENAME + ' = CAST(0 AS BIT) and '+@NEXTDATENAME + ' is not null and Employee_ID = ' + CONVERT(NVARCHAR,@EmployeeID) + ' '    EXEC SP_EXECUTESQL @SQL, @Parameter_Definition, @rowCount_out=@TotalNo Output         IF(@TotalNo > 0)     BEGIN     SET @EMPLOYEEPRESENT = 'DO'     END        IF((SELECT COUNT(HOLIDAY_ID) FROM Const_holiday WHERE HOLIDAYDATE = CAST(@FromDate AS DATETIME)  ) >0)     BEGIN     SET @EMPLOYEEPRESENT = 'H'     END    IF(@EMPLOYEEPRESENT = '')    BEGIN     SET @Parameter_Definition = N' @rowCount_out nvarchar(50) OUTPUT '     SET @SQL = 'SELECT  @rowCount_out=COUNT(*) FROM Payroll_Employee WHERE  '+@NEXTDATENAME + ' = CAST(1 AS BIT)  and '+@NEXTDATENAME + ' is not null and Employee_ID ='+ convert (nvarchar,@EmployeeID) +' '     EXEC SP_EXECUTESQL @SQL, @Parameter_Definition, @rowCount_out=@TotalNo Output       IF(@TotalNo > 0)      BEGIN      SET @EMPLOYEEPRESENT = 'P'      END    END    IF(@EMPLOYEEPRESENT != '')    BEGIN     SET @STARTDAYS = DAY(@FromDate)      IF(@STARTDAYS > 31)      BEGIN       SET @STARTDAYS =1      END           IF (SELECT COUNT(EmployeeAttendance_ID) from Payroll_EmployeeAttendance WHERE [MONTH] = @MONTH AND EMPLOYEEID = @EmployeeID and FinancialYear = @FinanceYear) > 0     BEGIN          SET @SQL = ' UPDATE Payroll_EmployeeAttendance SET [' + @STARTDAYS + '] = ''' + @EMPLOYEEPRESENT + '''      WHERE MONTH = '+ CONVERT(NVARCHAR, @MONTH) +' AND EMPLOYEEID = ' + CONVERT(NVARCHAR, @EmployeeID) + '  '      EXECUTE(@SQL)      SET @STARTDAYS = cast(@STARTDAYS as int ) + 1      IF(@FromDate < @ToDate)      BEGIN       SET @FromDate =  DATEADD(DAY,1,@FromDate)      END      SET @EMPLOYEEPRESENT = 'P'         END     ELSE     BEGIN         SET  @SQL = ' INSERT INTO Payroll_EmployeeAttendance  (EMPLOYEEID, FinancialYear, MONTH, [' + @STARTDAYS + ']) VALUES (' + CONVERT(NVARCHAR, @EmployeeID) + ','''+ @FinanceYear + ''',' + CONVERT(NVARCHAR, @MONTH ) +', '''+ @EMPLOYEEPRESENT + ''')'      EXECUTE(@SQL)            SET @STARTDAYS = cast(@STARTDAYS as int ) + 1       IF(@FromDate < @ToDate)      BEGIN       SET @FromDate =  DATEADD(DAY,1,@FromDate )      END      SET @EMPLOYEEPRESENT = 'P'     END    END    ELSE    BEGIN     SET @STARTDAYS = cast(@STARTDAYS as int ) + 1       IF(@FromDate < @ToDate)      BEGIN       SET @FromDate =  DATEADD(DAY,1,@FromDate )      END     SET @EMPLOYEEPRESENT = 'P'       END    -- print @EMPLOYEEPRESENT     END   END  

GO

