-- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_EmployeeAttendanceManageVer2_sp]    @EmployeeID int, -- 0 run for all Employees    @PeriodID int,     @CycleID int,     @CycleModeID int,        @FinancialYear NVARCHAR(10),    @FromDate  DATETIME,    @ToDate DATETIME     AS  BEGIN    SET NOCOUNT ON;     --Insert All Missing data   --Print 'Test 1'   --Return   --Print 'Test 2'   --insert into Payroll_EmployeeAttendance ([Month],EmployeeID,FinancialYear,TaxYear)   --select T2.EmpMonth, T2.EmpID, T2.PeriodYear,T2.PeriodYear from    -- (select DatePart(Month,T1.PeriodDate) as EmpMonth,T1.EmpID as EmpID, @FinancialYear as PeriodYear from   -- (select Convert(Datetime,   --    Convert(VarChar,DatePart(day ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Month ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Year ,(GetDate()-Number))) + ' 00:00:00:000',103) as PeriodDate,   --     Emp.Employee_ID as EmpID   --    from master..spt_values   --    cross apply    --    (   --    select Emp.Employee_ID from Payroll_Employee as Emp   --    inner join dbo.[Payroll_TrialRun_History_Employees] as [EP]  on [EP].[Employee_ID] = [Emp].[Employee_ID] and EP.Period_ID = @PeriodID  and [EP].[Cycle_ID] = @CycleID    --    where CycleID = @CycleID and (Emp.Employee_ID = @EmployeeID or @EmployeeID = 0)          --    ) as Emp   --    where type='p' and Convert(Datetime,   --    Convert(VarChar,DatePart(day ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Month ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Year ,(GetDate()-Number))) + ' 00:00:01:000',103)    --    between convert(DateTime,@FromDate,103) and    --    convert(DateTime,@ToDate,103)    --    ) as T1   --    group by DatePart(Month,T1.PeriodDate),T1.EmpID) as T2   --    left Join Payroll_EmployeeAttendance as AT on AT.EmployeeID = T2.EmpID and AT.[Month] = T2.EmpMonth and AT.FinancialYear = T2.PeriodYear   --    where AT.EmployeeAttendance_ID is null           -- update ATMain   -- set ATMain.[1] = Case when EH.EmployeeHistory_ID is Null then NULL else T2.AttendanceType end        -- from         -- Payroll_EmployeeAttendance as ATMain   -- inner join    -- (SELECT    -- case when e1.Employee_ID is not Null or E2.Employee_ID is not null or    -- E3.Employee_ID is not null or E4.Employee_ID is not null or E5.Employee_ID is not null    -- or E6.Employee_ID is not null or E7.Employee_ID is not null then    -- 'DO'   -- else   --  Case When H.Holiday_ID is not null then    --  'H'   --  else   --   case when D.Detail_Id is not Null then   --    'L'   --   else   --    'P'   --   end    --  end   -- end as AttendanceType,   -- T1.EmpID, T1.PeriodDate  from   -- (select Convert(Datetime,   --    Convert(VarChar,DatePart(day ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Month ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Year ,(GetDate()-Number))) + ' 00:00:00:000',103) as PeriodDate,   --     Emp.Employee_ID as EmpID   --    from master..spt_values   --    cross apply    --    (   --    select Emp.Employee_ID from Payroll_Employee as Emp   --    inner join dbo.[Payroll_TrialRun_History_Employees] as [EP]  on [EP].[Employee_ID] = [Emp].[Employee_ID] and EP.Period_ID = @PeriodID  and [EP].[Cycle_ID] = @CycleID    --    where CycleID = @CycleID and (Emp.Employee_ID = @EmployeeID or @EmployeeID = 0)          --    ) as Emp   --    where type='p' and Convert(Datetime,   --    Convert(VarChar,DatePart(day ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Month ,(GetDate()-Number))) + '/' +    --    Convert(VarChar,DatePart(Year ,(GetDate()-Number))) + ' 00:00:01:000',103)    --    between convert(DateTime,@FromDate,103) and    --    convert(DateTime,@ToDate,103)    --    ) as T1       -- left join dbo.Payroll_LeaveApproveRequestDetails AS D on D.LeaveDa