-- ============================================
-- SP: Payroll_EmployeeBankDetailsToApprove_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Modiri Selao   Create date : 2019/06/05   Description : #86527 Workflow not as specification  */  CREATE procedure [dbo].[Payroll_EmployeeBankDetailsToApprove_sp]  as    begin   select [empHist].[AccountDetailHistory_ID], [emp].[Surname],[emp].[FirstName] + ' ' + [emp].[SecondName] + ' ' As FullName, [emp].[Employee_ID], [emp].[EmpCode], [ptype].[PaymentTypeDesc],[acctype].[BankAccountType],[emphist].[AccountNumber],[cbank].[BankDesc],[cbranch].[BankBranchCode],[emphist].[AccountHolderName], [accrelation].[AccountHolderRelation],[emphist].[StartDate]   ,EPD.DocumentID,EPD.DocumentName,EPD.EmployeeDocument_ID,emphist.IsApproved      from [dbo].[Payroll_EmployeeAccountDetailHistory] emphist      left outer join [dbo].[Payroll_Employee] emp on [emp].[Employee_ID] = [emphist].[EmployeeId]      left outer join [dbo].[Const_PaymentType] ptype on [ptype].[PaymentType_ID] = [emphist].[PaymentTypeID]      left outer join [dbo].[Const_AccountHolderRelation_sys]  accrelation on [accrelation].[AccHolderRelation_ID] = [emphist].[AccountHolderRelationshipID]      left outer join [dbo].[Const_BankAccountType] acctype on [acctype].[BankAccountTypeID] = [emphist].[AccountTypeID]      left outer join [dbo].[Const_Bank] cbank on [cbank].[Bank_ID] = [emphist].[BankID]      left outer join [dbo].[Const_BankBranchCode] cbranch on [cbranch].[BankBranchCode_ID] = [emphist].[BranchID]    JOIN Payroll_EmployeeDocumentDetails EPD  on emphist.EmployeeDocument_ID = epd.EmployeeDocument_ID   WHERE emphist.IsApproved is null    END

GO

-- ============================================
-- SP: Payroll_EmployeeBasicSalaryCalculation_Trial_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create Date : 10/05/2017   Description : Calculates Employee Basic Salary   Update Date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update Date : 30/06/2017 - Updated the joins to the correct mappings   Update Date : 19/08/2019 - Put is null in  case statement for calculating amount where null is comming there   Update Date : 01/11/2019 - Calculation fails for Weekly and Bi-Weekly cycles   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeBasicSalaryCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try    if exists ( select Processed from [Payroll_CyclePeriodDetails] [CPD] where [CPD].[PeriodStartDate] = @StartDate and [CPD].[PeriodEndDate] = @EndDate and [CPD].[Enabled] = 1 and [CPD].[Processed] = 0 and [Period_ID] = @PeriodID and [CycleID] = @CycleID and [CycleModeID] = @CycleModeID)    begin        DECLARE @cycleType_weekly INT = 2    DECLARE @cycleType_biWeekly INT = 3        insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear], [Simulation])       select distinct [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], (case         when [CT].[CycleType_ID] in(@cycleType_weekly, @cycleType_biWeekly) then sum(cast(isnull([PE].[RPH_Other], 0) * isnull([EC].[NoOfWorkingHrs], 0) as decimal(18, 6)))         else (          min(           ((cast(isnull([PE].[FixedSalary], 0) as decimal(18, 6)) / (cast(case              when isnull([PE].[WDPM_Monthly], 0) <= 0 then cast((case               when @Simulation = 1 and (not [ET].[TerminationStartDate] is null) and [PE].[UntilDays] > 0 then isnull([PE].[UntilDays], 0)               when [PE].[JoiningDate] between @StartDate and @EndDate and [PE].[StartDays] > 0 then isnull([PE].[StartDays], 0)               when [PE].[EndDate] between @StartDate and @EndDate and [PE].[UntilDays] > 0 then isnull([PE].[UntilDays], 0)               else 1              end) as decimal(18, 6))              else isnull([PE].[WDPM_Monthly], 0)             end as decimal(18, 6))            )           ) * (             cast((case              when @Simulation = 1 and (not [ET].[TerminationStartDate] is null) and [PE].[UntilDays] > 0 then isnull([PE].[UntilDays], 0)              when [PE].[JoiningDate] between @StartDate and @EndDate and [PE].[StartDays] > 0 then isnull([PE].[StartDays], 0)              when [PE].[EndDate] between @StartDate and @EndDate and [PE].[UntilDays] > 0 then isnull([PE].[UntilDays], 0)              else isnull([PE].[WDPM_Monthly], 0)             end) as decimal(18, 6))            )           ) * cast([Percentage] as decimal(18, 6))          ) / cast(100 as decimal(18, 6))         )        end), @Month, @SCOAYear, [SH].[SalaryHeadTitle], @PeriodID, @TaxYear, @Simulation        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] = 1 and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = @PeriodID and [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [CC].[Cycle_ID]         JOIN Payroll_Position AS PP WITH(NOLOCK) ON PE.PositionID = PP.Position_ID       JOIN Payroll_JobProfile AS JP WITH(NOLOCK) ON PP.JobProfileID = JP.JobProfile_ID         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID] and [ACPD].[Enabled] = 1         left outer join [Payroll_EmployeeCalander] as [EC] with(nolock)         on [EC].[EmployeeID] = [PE].[Employee_ID]          and [EC].[Date] between @StartDate and @EndDate          and ([CT].[CycleType_ID] not in(@cycleType_weekly, @cycleType_biWeekly)           or ([CT].[CycleType_ID] in(@cycleType_weekly, @cycleType_biWeekly)            and [EC].[PublicH] = 0 and [EC].[Leave] = 0            and ([EC].[Shift] = 1 or [EC].[Substitute] = 1)))         left outer join [Payroll_EmployeeTermination] as [ET] with(nolock) on [ET].[EmployeeID] = [EPD].[EmployeeID] and [ET].[Enabled] = 1        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end)        and [EPD].[PayrollSalaryHeadID] = 1        and [EPD].[Enabled] = 1        AND (JP.LimitID IS NOT NULL OR JP.TaskGradeId IS NOT NULL)       and (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0        end) = 1)         group by [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID]    end   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeBasicSalaryCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create Date : 31/01/2019   Description : Calculates Employee Basic Salary (Simulation)   Update Date : 11/04/2019 => Added Employee Basic Salary (Simulation) @ Terminations   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeBasicSalaryCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try    begin    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle],        ((cast((case         when @SimulationType = 1 then (          coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)         )         when @SimulationType = 2 then (          coalesce((select ((cast(isnull([PE_].[FixedSalary], 0) as decimal(18, 6)) / (cast(case               when isnull([PE_].[WDPM_Monthly], 0) <= 0 then cast((case                when (not [ET].[TerminationStartDate] is null) and [PE_].[UntilDays] > 0 then [PE_].[UntilDays]                else 1               end) as decimal(18, 6))               else [PE_].[WDPM_Monthly]              end as decimal(18, 6))             )            ) * (              cast((case               when (not [ET].[TerminationStartDate] is null) and [PE_].[UntilDays] > 0 then [PE_].[UntilDays]               else [PE_].[WDPM_Monthly]              end) as decimal(18, 6))             )            )             from [Payroll_Employee] as [PE_] with(nolock)              join [Payroll_EmployeeTermination] as [ET] with(nolock) on [ET].[EmployeeID] = [PE_].[Employee_ID]             where ([PE_].[Employee_ID] = @EmployeeID)), 0)         )         else 0        end) as decimal(18, 6)) * cast([EPD].[Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6)))        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [EPD].[EmployeeID]         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 1 and [SH].[SalaryHead_ID] = 1)         group by [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [PE].[FixedSalary], [EPD].[Percentage]    end   end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeBebefitDetailsRpt_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_EmployeeBebefitDetailsRpt_sp 18  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeBebefitDetailsRpt_sp] @EmployeeId INT  AS       BEGIN          SELECT DISTINCT                  EmployeeId, BenefitType, FundName, JoinDate, BenefitType_ID          FROM    dbo.Payroll_EmpBenefitDetail                  INNER JOIN Payroll_BenefitDetail ON BenefitSchemeID = Benefit_ID                  INNER JOIN Const_BenefitType_sys ON dbo.Payroll_BenefitDetail.BenefitTypeID = dbo.Const_BenefitType_sys.BenefitType_ID          WHERE   EmployeeId = @EmployeeId                  AND dbo.Payroll_EmpBenefitDetail.Enabled = 1      END  

GO

-- ============================================
-- SP: Payroll_EmployeeBenefitDetailDelete_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 01 01 2014  -- Description: <Description,,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeBenefitDetailDelete_sp]   @EmployeeId INT  AS  BEGIN   SET NOCOUNT ON;        DECLARE @DATABASENAME NVARCHAR(50)          DECLARE @SQLQuery NVARCHAR(MAX)      SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'        SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeeBenefitDetail    (     AuditUserID,AuditDate,AuditUser,EmployeeBenefitDetail_ID, EmployeeID,      BenefitSchemeID, BenefitTypeID, ContributionType, ContributionValue,      ContributionFor, Amount1, Amount2, MunicipalityID, DateCaptured, CapturerID,     DateModified, ModifierID    )    SELECT      1, GETDATE(), ''Admin User'', EmployeeBenefitDetail_ID, EmployeeID,      BenefitSchemeID, BenefitTypeID, ContributionType, ContributionValue,      ContributionFor, Amount1, Amount2, MunicipalityID, DateCaptured, CapturerID,      DateModified, ModifierID     FROM Payroll_EmployeeBenefitDetail    WHERE EmployeeID = ' + CONVERT(NVARCHAR(50), @EmployeeID)        EXEC(@SQLQuery)      DELETE FROM Payroll_EmployeeBenefitDetail WHERE EmployeeID = @EmployeeId     END  

GO

-- ============================================
-- SP: Payroll_EmployeeBenefitDetailDeleteByID_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 01 01 2014  -- Description: <Description,,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeBenefitDetailDeleteByID_sp]   @EmployeeId INT,   @EmployeeBenefitDetailID INT  AS  BEGIN   SET NOCOUNT ON;        DECLARE @DATABASENAME NVARCHAR(50)          DECLARE @SQLQuery NVARCHAR(MAX)      SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'        SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeeBenefitDetail    (     AuditUserID,AuditDate,AuditUser,EmployeeBenefitDetail_ID, EmployeeID,      BenefitSchemeID, BenefitTypeID, ContributionType, ContributionValue,      ContributionFor, Amount1, Amount2, MunicipalityID, DateCaptured, CapturerID,     DateModified, ModifierID    )    SELECT      1, GETDATE(), ''Admin User'', EmployeeBenefitDetail_ID, EmployeeID,      BenefitSchemeID, BenefitTypeID, ContributionType, ContributionValue,      ContributionFor, Amount1, Amount2, MunicipalityID, DateCaptured, CapturerID,      DateModified, ModifierID     FROM Payroll_EmployeeBenefitDetail    WHERE EmployeeID = ' + CONVERT(NVARCHAR(50), @EmployeeID) + ' AND EmployeeBenefitDetail_ID = ' + CONVERT(NVARCHAR(50), @EmployeeBenefitDetailID)        EXEC(@SQLQuery)      DELETE FROM Payroll_EmployeeBenefitDetail WHERE EmployeeID = @EmployeeId AND EmployeeBenefitDetail_ID = @EmployeeBenefitDetailID     END  

GO

-- ============================================
-- SP: Payroll_EmployeeBillingCalculation_Trial_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 09/03/2017   Description : Calculates Employees Outstanding Bill Payments   Update date : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings  */  create procedure [Payroll_EmployeeBillingCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10)  as    begin     set nocount on;     begin try      declare @Values table (       [EmployeeID] int not null,     [PayrollDefinitionID] int not null,     [TransactionTypeID] int not null,     [AccountID] int not null,     [Percentage] decimal(18, 2) not null,     [Value] decimal(18, 2) not null default(0),     [PayrollSalaryHeadName] nvarchar(50) null      )      insert into @Values([EmployeeID], [PayrollDefinitionID], [TransactionTypeID], [AccountID], [Percentage], [Value], [PayrollSalaryHeadName])       select [PE].[Employee_ID], [EmployeePayrollDefinition_ID], [TransactionTypeID], [ID], [Percentage], isnull([dbo].[Billing_GetOutStandingAmountAccount]([AccountID]), 0), [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_EmployeeAccountDetails] as [ACC] with(nolock) on [ACC].[EmployeeID] = [EPD].[EmployeeID] and [ACC].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] in(1, 2) and         [SalaryHeadName] = 'Billing Account Payments' and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      update @Values set [Value] = [Value] * (case [TransactionTypeID] when 1 then 1 else -1 end)      update @Values set [Value] = (([Value] / [Percentage]) * 100)     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeBillPayment
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,11 Sep 2014>  -- Description: <Description,,Pay Employee bills at Payroll run time>  -- Call SP    : Payroll_EmployeeBillPayment 1, 1, 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeBillPayment]      @EmployeeID INT ,      @PeriodID INT ,      @UserID INT  AS       BEGIN          BEGIN TRAN          BEGIN TRY              DECLARE @EmployeeBills TABLE                  (                    Id INT IDENTITY(1, 1) ,                    AccountID INT ,                    OutstandingAmount DECIMAL(18, 2) ,                    PaidAmount DECIMAL(18, 2)                  )                 INSERT  INTO @EmployeeBills ( AccountID, OutstandingAmount, PaidAmount )                      SELECT  AccountID, OutstandingAmount, SUM(PaidAmount)                      FROM    dbo.Payroll_EmployeeBillingPaymentDetails                      WHERE   EmployeeID = @EmployeeID                              AND PeriodID = @PeriodID                      GROUP BY AccountID, OutstandingAmount                                DECLARE @AccountID INT ,                  @OutstandingAmount DECIMAL(18, 2) ,                  @PaidAmount DECIMAL(18, 2) ,                  @Start INT = 1 ,                  @Total INT= 0 ,                  @ReceiptID INT                            SELECT  @Total = COUNT(1)              FROM    @EmployeeBills                            WHILE ( @Start <= @Total )                   BEGIN                      SELECT  @AccountID = AccountID, @OutstandingAmount = OutstandingAmount, @PaidAmount = PaidAmount                      FROM    @EmployeeBills                      WHERE   Id = @Start                                        EXEC dbo.Billing_VirtualCashierPayment -1, @AccountID, @OutstandingAmount, @PaidAmount, @UserID, @ReceiptID OUT                                        UPDATE  dbo.Payroll_EmployeeBillingPaymentDetails                      SET     ReceiptID = @ReceiptID                      WHERE   EmployeeID = @EmployeeID                              AND AccountID = @AccountID                              AND PeriodID = @PeriodID                            SET @Start += 1                  END              COMMIT TRAN          END TRY          BEGIN CATCH              DECLARE @ExecuteStatus NVARCHAR(MAX)                SELECT  @ExecuteStatus = ERROR_MESSAGE()                      INSERT  INTO Sys_ErrorLog ( moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName )              VALUES  ( 'Payroll', 'SQL Server', 'Payroll_EmployeeBillPayment', @ExecuteStatus, 'SQL', @ExecuteStatus, GETDATE(), 'SQL' )                      ROLLBACK TRAN           END CATCH         END  

GO

-- ============================================
-- SP: Payroll_EmployeeBirthDayRpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 06 JULY 2013  -- Description: Get Employee Bithday List  -- Payroll_EmployeeBirthDayRpt_sp '2013/03/01','2013/04/12', 0, 0, NULL, '', 01  -- 2015-01-12 James Roodt: Added ISNULL checks at employee name and address to cater for empty fields.  -- 2016-01-04 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeBirthDayRpt_sp]   @BirthFromDate DATETIME,   @BirthToDate DATETIME,   @DepartmentId INT,   @DivisionId INT,   @Status BIT = NULL,   @UserName VARCHAR(100),   @CycleId INT  AS  BEGIN     DECLARE @Employee TABLE (IDNumber VARCHAR(50), EmployeeCode VARCHAR(10), EmployeeName VARCHAR(200), DateOfBirth VARCHAR(50), EmployeeNo VARCHAR(50), Employee_ID INT)      WHILE @BirthFromDate <= @BirthToDate BEGIN    INSERT INTO @Employee    SELECT DISTINCT ISNULL(IDno,'') AS IDNumber, ISNULL(EmpCode, '') AS EmployeeCode, ISNULL(FirstName + ' ','') + ISNULL(Surname,'') AS EmployeeName       ,CONVERT(NVARCHAR(15),DateOfBirth ,103) as DateOfBirth, dbo.BufferString_fxn(CONVERT(VARCHAR, (Employee_ID )), 8, '0') AS EmployeeNo, Employee_ID    FROM Payroll_Employee AS P_E     LEFT OUTER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID    WHERE (P_E.Enabled = @Status OR @Status IS NULL) AND    (PP.DepartmentID = @DepartmentId OR @DepartmentId = 0) AND    (PP.DivisionID = @DivisionId OR @DivisionId = 0)    AND DATEPART(DAY, DateOfBirth) = DATEPART(DAY, @BirthFromDate)    AND DATEPART(MONTH, DateOfBirth) = DATEPART(MONTH, @BirthFromDate)    AND (P_E.CycleID = @CycleId OR @CycleId = 0)    SET @BirthFromDate = DATEADD(DAY,1, @BirthFromDate)   END      SELECT * FROM @Employee   ORDER BY Employee_ID  END          

GO

-- ============================================
-- SP: Payroll_EmployeeBonusCalculation_Trial_sp
-- Schema: dbo
-- ============================================
     /*   Author  : FERDI BOTHA   Create date : 09/03/2017   Description : Calculates Employees Bonus Earnings   Update date : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings   Update date : 04/04/2018 - Updated Bonus (pro rata)   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination   Update date :   12/02/2020 - Ilya Skavronskiy => Added filtering to prevent setting bonus for upper limit employees            (because it is calculated on Payroll_EmployeeSalaryStructureCalculation_Trail_sp)    Update date :   24/02/2020 - Ilya Skavronskiy => Added Bonus processing for specific month   Update date :   25/02/2020 - Ilya Skavronskiy => Added filtering to prevent employee to receive a Bonus in his/her first month of employment   Update date : 28/09/2021 - Richa M => Fix Bonus calc for non pro-rata payments   Update date : 07/04/2022 - Richa M => Pro Rata Bonus not working  */  CREATE procedure [dbo].[Payroll_EmployeeBonusCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try    if exists ( select Processed from [Payroll_CyclePeriodDetails] [CPD] where [CPD].[PeriodStartDate] = @StartDate and [CPD].[PeriodEndDate] = @EndDate and [CPD].[Enabled] = 1 and [CPD].[Processed] = 0 and [Period_ID] = @PeriodID and [CycleID] = @CycleID and [CycleModeID] = @CycleModeID)    begin    declare @BonusDateID int = 0,      @BonusMonth int = 0      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      if (@BonusDateID > 0 or @BonusMonth > 0)    begin       insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [TaxYear],[Simulation])        select [EPD].[EmployeeID], [EmployeePayrollDefinition_ID], cast(         cast(case          when isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@EndDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@EndDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@EndDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@EndDate)) then 1          else 0         end as decimal(18, 6)) * ((cast((case          when [Years] > 0 then [BonusAmount]          when [Years] < 1 and isnull([IsProRata], 0) = 0 then [BonusAmount]          when [Years] < 1 and isnull([IsProRata], 0) = 1 then ([BonusAmount] / 12) * (DATEDIFF(month,PE.JoiningDate,cpd.PeriodEndDate))          else 0         end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6)), @Month, @SCOAYear, @PeriodID, [SalaryHeadTitle], @TaxYear, @Simulation         from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_EmployeeSubtypes] as [PES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ApplyBonus] = 1          join [Payroll_JobProfile] as [PJP] with(nolock) on [PE].[JobProfileID] = [PJP].[JobProfile_ID] and [PJP].[LimitID] is null          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1          join [Const_TaxBonusCalculation_sys] as [BNS] with(nolock) on [TaxBonusCalculation_ID] = [BonusCalculation] and [BNS].[Enabled] = 1          join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 1 and          [SalaryHead_ID] = 2 and          --No employee can receive a bonus or a pro-rate bonus in his/her first month of employment.        (         year(@EndDate) > year([PE].[JoiningDate])         or          (year(@EndDate) = year([PE].[JoiningDate]) and month(@EndDate) > month([PE].[JoiningDate]))         ) and          --Only one Bonus payment can be made during the Tax Year        not exists (         select top 1 1         from Payroll_PayrollResults AS PR         where [PR].[EmployeeID] = [EPD].[EmployeeID]          and [PR].[SalaryHeadID] = 2          and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int)        ) and          [BonusAmount] > 0 and (          (cast(           cast(case            when isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@EndDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@EndDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@EndDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@EndDate)) then 1            else 0           end as decimal(18, 6)) * ((cast((case            when [Years] > 0 then [BonusAmount]            when [Years] < 1 and isnull([IsProRata], 0) = 0 then [BonusAmount]            when [Years] < 1 and isnull([IsProRata], 0) = 1 then ([BonusAmount] / 12) * ((              select count(distinct [PeriodID])               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = [PE].[CycleID] and [CPR].[CycleModeID] = 1 and [CPR].[Enabled] = 1               where ([EmployeeID] = [EPD].[EmployeeID] and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int))             ) + 1)            else 0           end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))) > 0) and           (case            when @CycleModeID = 1 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end            when @CycleModeID = 2 then             case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end            else 0 end) = 1          )      end    end   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeBonusCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employees Bonus Earnings (Simulation)   Update Date : 11/04/2019 => Added Employee Bonus Earnings (Simulation) @ Terminations   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination   Update date :   12/02/2020 - Ilya Skavronskiy => Added filtering to prevent setting bonus for upper limit employees           (because it is calculated on Payroll_EmployeeSalaryStructureCalculation_TrailSimulation_sp)    Update date :   24/02/2020 - Ilya Skavronskiy => Added Bonus processing for specific month   Update date :   25/02/2020 - Ilya Skavronskiy => Added filtering to prevent employee to receive a Bonus in his/her first month of employment  */  CREATE procedure [Payroll_EmployeeBonusCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try    begin    declare @BonusDateID int = 0,      @BonusMonth int = 0,      @TaxYear int = (case when month(@StartDate) < 3 then year(@StartDate)          else year(@StartDate) + 1 end)      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      if (@BonusDateID > 0 or @BonusMonth > 0)    begin       insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])        select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle], cast(         cast(case          when isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@UntilDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@UntilDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@UntilDate)) then 1          when isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@UntilDate)) then 1          else 0         end as decimal(18, 6)) * ((cast((case          when [Years] > 0 then cast((case            when @SimulationType = 1 then (             coalesce((select [BonusSalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)            )            when @SimulationType = 2 then (             coalesce((select [BonusAmount] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)            )            else 0           end) as decimal(18, 6))          when [Years] < 1 and isnull([IsProRata], 0) = 1 then (cast((case            when @SimulationType = 1 then (             coalesce((select [BonusSalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)            )            when @SimulationType = 2 then (             coalesce((select [BonusAmount] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)            )            else 0           end) as decimal(18, 6)) / 12) * ((            select count(distinct [PeriodID])             from [Payroll_PayrollResults] as [PR] with(nolock)              join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = [PE].[CycleID] and [CPR].[CycleModeID] = 1 and [CPR].[Enabled] = 1             where ([EmployeeID] = [EPD].[EmployeeID] and [PR].[TaxYear] = @TaxYear)           ) + 1)          else 0         end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))         from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]          join [Payroll_EmployeeSubtypes] as [PES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ApplyBonus] = 1          join [Payroll_JobProfile] as [PJP] with(nolock) on [PE].[JobProfileID] = [PJP].[JobProfile_ID] and [PJP].[LimitID] is null          join [Const_TaxBonusCalculation_sys] as [BNS] with(nolock) on [TaxBonusCalculation_ID] = [BonusCalculation] and [BNS].[Enabled] = 1          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (           (isnull([TPS].[EmployeeChangeID], 0) = (case            when @SimulationType = 1 then @ParentID            else 0           end))           or           (isnull([TPS].[TerminationID], 0) = (case            when @SimulationType = 2 then @ParentID            else 0           end))          )         where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and cast((case           when @SimulationType = 1 then (            coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)           )           when @SimulationType = 2 then (            coalesce((select [FixedSalary] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)           )           else 0          end) as decimal(18, 6)) > 0 and                 --No employee can receive a bonus or a pro-rate bonus in his/her first month of employment.        (         year(@UntilDate) > year([PE].[JoiningDate])         or          (year(@UntilDate) = year([PE].[JoiningDate]) and month(@UntilDate) > month([PE].[JoiningDate]))         ) and                 --Only one Bonus payment can be made during the Tax Year        not exists (         select top 1 1         from Payroll_PayrollResults AS PR         where [PR].[EmployeeID] = [EPD].[EmployeeID]          and [PR].[SalaryHeadID] = 2          and [PR].[TaxYear] = @TaxYear        ) and (          (cast(           cast(case            when isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@UntilDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@UntilDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@UntilDate)) then 1            when isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@UntilDate)) then 1            else 0           end as decimal(18, 6)) * ((cast((case            when [Years] > 0 then cast((case              when @SimulationType = 1 then (               coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)              )              when @SimulationType = 2 then (               coalesce((select [FixedSalary] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)              )              else 0             end) as decimal(18, 6))            when [Years] < 1 and isnull([IsProRata], 0) = 1 then (cast((case              when @SimulationType = 1 then (               coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)              )              when @SimulationType = 2 then (               coalesce((select [FixedSalary] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)              )              else 0             end) as decimal(18, 6)) / 12) * ((              select count(distinct [PeriodID])               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = [PE].[CycleID] and [CPR].[CycleModeID] = 1 and [CPR].[Enabled] = 1               where ([EmployeeID] = [EPD].[EmployeeID] and [PR].[TaxYear] = @TaxYear)             ) + 1)            else 0           end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))) > 0))      end    end   end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeBonusTaxCalculation_Trial_sp
-- Schema: dbo
-- ============================================
   /*   Payroll_EmployeeBonusTaxCalculation_Trial_sp   Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE (Bonus)   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation   Update Date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update Date : 30/06/2017 - Updated the joins to the correct mappings   Update Date : 03/04/2018 - Updated Tax Spread (Bonus)   Update Date : 25/03/2019 - Updated Tax Spread (Bonus) vs Annual Payments   Update Date :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Update Date :   28/08/2019 - CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS   Update Date : 15/11/2019 - JOGEDA: PAYE calulation Emp 3 PAYE:Bonus incorrect   Update Date : 2021/08/11 - Richa M Fix Secondary and Tertiary Rebates to calculate if employee reaches the specific age within the YOA  */  CREATE procedure [dbo].[Payroll_EmployeeBonusTaxCalculation_Trial_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      delete from Payroll_PayrollRunLog where PeriodId = @PeriodId and (EmployeeId = @EmployeeId or @EmployeeID = 0) and Source = 'Payroll_EmployeeBonusTaxCalculation_Trial_sp'        declare @trialRunLogs varchar(max) = ''    declare @employeeType_seniorManagers int = 2    declare @employeeType_wardCouncilors int = 3    declare @employeeType_boardMembers int = 7        declare @bonusPeriod_monthOfEmploymentDate int = 1    declare @bonusPeriod_monthOfEmployeesBirthday int = 2    declare @bonusPeriod_allEmployeesOnSameMonth int = 3    declare @bonusPeriod_specificCalendarMonth int = 4      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)),      @TaxYearEndDate datetime = (select top 1 PeriodEndDate from Payroll_CyclePeriodDetails where TaxYear = @TaxYear and CycleId = @CycleID order by PeriodInTaxYear desc)      declare @i int = 1,      @c int,      @PeriodYearStart datetime = cast(left(@TaxYear, 4) + '-03-01' as datetime),      @PeriodYearUntil datetime = dateadd(day, -1, cast(right(@TaxYear, 4) + '-03-01' as datetime)),      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 1,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @BonusPaymentDateID int,      @Years decimal(18, 6),      @Months decimal(18, 6),      @EmploymentDate datetime,      @BirthDate datetime,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6) = 0,      @incomeBonusYearToDate decimal(18, 6) = 0,      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueAnnual decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6) = 0,      @payeValueCheck decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @payeHistoryType decimal(18, 6),      @payeHistoryPeriod int,      @payeHistoryValue decimal(18, 6),      @payeHistoryBonus decimal(18, 6),      @payeHistoryBalance decimal(18, 6),      @hasUpperLimits bit,      @LastEmployeeId int = -1;      declare @leapValue decimal(18, 6) = (1 + (case when ((year(@PeriodYearUntil) % 4 = 0 and year(@PeriodYearUntil) % 100 <> 0) or year(@PeriodYearUntil) % 400 = 0) then 1 else 0.25 end))      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [BonusPaymentDateID] int not null,     [BonusMonth] int null,     [EmploymentDate] datetime not null,     [BirthDate] datetime not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [VendorID] int null,     [SalaryHeadTitle] nvarchar(50) null,     [HasUpperLimits] bit not null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [BonusPaymentDateID], [BonusMonth],     [EmploymentDate], [BirthDate], [Age], [Amount], [PayrollDefinationID], [VendorID], [SalaryHeadTitle], [HasUpperLimits])    select      (      select isnull(max([PeriodInTaxYear]), @Periods)      from [Payroll_CyclePeriodDetails] with(nolock)      where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)     ) AS Periods,      (      select isnull(max([PeriodInTaxYear]), @Month)      from [Payroll_CyclePeriodDetails] with(nolock)      where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [Processed] = 1 and [TaxYear] = @TaxYear)     ) AS PeriodNo,      (      select count(distinct [PeriodID])      from [Payroll_PayrollResults] as [PR] with(nolock)      join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [PR].[PeriodID] = [CPR].[Period_ID] and  [CPR].[CycleID] = [PE].[CycleID] and [CPR].[CycleModeID] = 1 and [CPR].[Enabled] = 1      where ([EmployeeID] = [EPD].[EmployeeID] and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int))     ) AS PeriodsWorked,      [EPD].[EmployeeID],      (case      when [TaxCalculationType] is null then 1      when [TaxCalculationType] > 4 then 1      else [TaxCalculationType]     end) CalculationType,      isnull([BonusCalculation], 2),      isnull([BonusPaymentDateID], @BonusDateID),      isnull([BonusMonth], @BonusMonth),      [JoiningDate],      [DateOfBirth],      (floor(datediff(day, [DateOfBirth], @TaxYearEndDate) / (365.242199))) AS Age,      0,      [EmployeePayrollDefinition_ID],      [VendorID],      [SalaryHeadTitle],     (case       when PE.EmployeeTypeID in (@employeeType_seniorManagers, @employeeType_wardCouncilors, @employeeType_boardMembers) then 1      else 0     end) AS HasUpperLimits    from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1       join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID       join [Payroll_EmployeeSubtypes] as [PES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ApplyBonus] = 1       join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1       join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]       left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]      where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and       [SalaryHead_ID] = 4 and [BonusCalculation] = 3           and       (case        when @CycleModeID = 1 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end        when @CycleModeID = 2 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end        else 0 end) = 1      )      select @c = count([ID]) from @paye        while (@i <= @c)    begin     set @trialRunLogs = ''       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @BonusPaymentDateID = [BonusPaymentDateID], @EmploymentDate = [EmploymentDate], @BirthDate = [BirthDate], @Age = [Age], @hasUpperLimits = [HasUpperLimits], @BonusMonth = [BonusMonth] from @paye where ([ID] = @i)       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodID as [PeriodID], @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     IF (@EmployeeID <> @LastEmployeeId)  BEGIN      SELECT @income =          COALESCE(SUM(              CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *              (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)          ), 0.0)      FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)      JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)           ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID          AND EPD.Enabled = 1      JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)           ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID          AND SH.Enabled = 1      JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)           ON IRP5.IRP5Code_ID = SH.IRP5CodeId          AND IRP5.Enabled = 1      JOIN @IRP5Income AS ETR           ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)          AND ETR.[Type]    IN (1, 2, 3)          -- 01 + 02 + 03          AND ETR.Taxable   > 0                  -- taxable only          AND ETR.StartDate <= @EndDate          AND ETR.UntilDate >= @StartDate      JOIN Payroll_Employee AS PE                   WITH (NOLOCK)           ON PE.Employee_ID = ETP.EmployeeID          AND PE.CycleID = @CycleID      JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)           ON CPD.CycleID   = PE.CycleID          AND CPD.Period_ID = ETP.PeriodID          AND CPD.Enabled   = 1      JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)           ON EP.Period_ID   = ETP.PeriodID          AND EP.Employee_ID = ETP.EmployeeID          AND EP.Cycle_ID    = PE.CycleID      LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)           ON ACPD.PeriodID    = CPD.Period_ID          AND ACPD.SalaryHeadID = SH.SalaryHead_ID      WHERE          ETP.EmployeeID = @EmployeeID          AND ETP.PeriodID = @PeriodID          AND ETP.TaxSavePurpose = 0          AND (                CASE                   WHEN @CycleModeID = 1 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                   WHEN @CycleModeID = 2 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                   ELSE 0                END              ) = 1          AND IRP5.TransactionTypeID IN (1, 4);   -- ordinary & bonus taxable income        SET @LastEmployeeId = @EmployeeID;  END       /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = coalesce((select sum([Amount] * ([TatxablePercentage] / 100))               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = @CycleID and [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1               where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end) and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                [PR].[TransactionTypeID] in(1, 4) and not [PR].[SalaryHeadID] in(2) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(                 /* 01 - INCOME RECORD(S) */               3601, 3651, 3602, 3652, 3603, 3653, 3604, 3654, 3606, 3656, 3607, 3657, 3608, 3658, 3609, 3659, 3610, 3660, 3611, 3661, 3612, 3662, 3613, 3663, 3614, 3664, 3615, 3665, 3616, 3666, 3617, 3667, 3619, 3669, 3620, 3670, 3621,                 /* 02 - ALLOWANCE RECORD(S) */               3701, 3751, 3701, 3751, 3702, 3752, 3703, 3753, 3704, 3754, 3705, 3755, 3706, 3756, 3707, 3757, 3708, 3758, 3709, 3759, 3710, 3760, 3711, 3761, 3712, 3762, 3713, 3763, 3714, 3764, 3715, 3765, 3716, 3766, 3717, 3767, 3718, 3768, 3719, 3769, 3720, 3770, 3721, 3771,                 /* 03 - FRINGE BENEFIT RECORD(S) */               3801, 3851, 3802, 3852, 3803, 3853, 3804, 3854, 3805, 3855, 3806, 3856, 3807, 3857, 3808, 3858, 3809, 3859, 3810, 3860, 3813, 3863, 3815, 3865, 3816, 3866, 3817, 3867, 3820, 3870, 3821, 3871, 3822, 3872, 3825, 3875, 3828, 3878,3833                )               )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = @CycleID and [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end) and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and not [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = @CycleID and [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end) and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = @CycleID and [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and not [PR].[SalaryHeadID] in(4, 5) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102 and not [PR].[PeriodID] in(                   select [Period_ID] from [Payroll_PayrollRun_History_Employees] with(nolock) where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)                  ))), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS */     set @payeValueYearToDate = @payeValueYearToDate + coalesce((select sum([PAYEBalance] + [PAYEValue])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [CycleModeID] = @CycleModeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[CycleID] = @CycleID and [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end) and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = 4 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = coalesce((select sum([TaxCredits])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [TaxYear] = @TaxYear)), 0)       set @trialRunLogs = CONCAT(@trialRunLogs, '@YTDTaxableIncome,', @income + @incomeYearToDate, '@income=', @income, ' | @incomeYearToDate= ', @incomeYearToDate, ' | @incomeAnnual= ', @incomeAnnual, ' | @incomeAnnualYearToDate = ', @incomeAnnualYearToDate,' | @incomeBonus= ',@incomeBonus,' | @incomeBonusYearToDate= ',@incomeBonusYearToDate,' | @payeValueYearToDate= ',@payeValueYearToDate,' | @payeValueBonusYearToDate= ',@payeValueBonusYearToDate,' | @payeCreditsYearToDate= ',@payeCreditsYearToDate)       /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'       /* CALCULATE FUTURE-DATED ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     if (@incomeBonus = 0 and @incomeBonusYearToDate = 0)     begin        if (@BonusPaymentDateID = @bonusPeriod_monthOfEmploymentDate)         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when month(@EmploymentDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @EmploymentDate, 120), 6) as datetime)) + @leapValue) / (365.242199)))        else if (@BonusPaymentDateID = @bonusPeriod_monthOfEmployeesBirthday)         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when month(@BirthDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @BirthDate, 120), 6) as datetime)) + @leapValue) / (365.242199)))        else if (@BonusPaymentDateID in (@bonusPeriod_allEmployeesOnSameMonth, @bonusPeriod_specificCalendarMonth))         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when @BonusMonth < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + format(@BonusMonth, '-00') + format(month(@StartDate), '-00') as datetime)) + @leapValue) / (365.242199)))        if (@EmploymentDate < @PeriodYearStart)      begin         set @EmploymentDate = @PeriodYearStart         set @Months = (floor((datediff(day, @EmploymentDate, @PeriodYearUntil) + @leapValue) / (30.4375)))        end      else if (@EmploymentDate >= @PeriodYearStart)      begin         if (@BonusPaymentDateID = @bonusPeriod_monthOfEmploymentDate)          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when month(@EmploymentDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @EmploymentDate, 120), 6) as datetime)) + @leapValue) / (30.4375)))         else if (@BonusPaymentDateID = @bonusPeriod_monthOfEmployeesBirthday)          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when month(@BirthDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @BirthDate, 120), 6) as datetime)) + @leapValue) / (30.4375)))         else if (@BonusPaymentDateID in (@bonusPeriod_allEmployeesOnSameMonth, @bonusPeriod_specificCalendarMonth))          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when @BonusMonth < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + format(@BonusMonth, '-00') + format(month(@StartDate), '-00') as datetime)) + @leapValue) / (30.4375)))        end        set @incomeBonus = coalesce((select (cast((case                  when @Years > 0 or @hasUpperLimits = 1 then [BonusAmount]                  when @Years < 1 and isnull([IsProRata], 0) = 1 then ([BonusAmount] / @Periods) * @Months                  when @Years < 1 and isnull([IsProRata], 0) = 0 then [BonusAmount]                  else 0                 end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))                from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1                 join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID                 join [Payroll_EmployeeSubtypes] as [PES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ApplyBonus] = 1                 join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1                 join [Const_TaxBonusCalculation_sys] as [BNS] with(nolock) on [TaxBonusCalculation_ID] = [BonusCalculation] and [BNS].[Enabled] = 1                 join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]                 left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]                where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] = 1 and                 [SalaryHead_ID] = 2 and                 [BonusAmount] > 0 and (                 (cast(                  cast(1 as decimal(18, 6)) * ((cast((case                   when @Years > 0 or @hasUpperLimits = 1 then [BonusAmount]                   when @Years < 1 and isnull([IsProRata], 0) = 1 then ([BonusAmount] / @Periods) * @Months                   when @Years < 1 and isnull([IsProRata], 0) = 0 then [BonusAmount]                   else 0                  end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))) > 0)                                 and                  (case                   when @CycleModeID = 1 then                    case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end                   when @CycleModeID = 2 then                    case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end                   else 0 end) = 1                 )), 0)       end       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'CALCULATE FUTURE-DATED ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2]'       /* ANNUALIZE INCOME: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @income = (((@income + @incomeYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'ANNUALIZE INCOME'       /* ADD ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @income = @income + (@incomeAnnual + @incomeAnnualYearToDate)       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'DEDUCT ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'       /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))               from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID]

GO

-- ============================================
-- SP: Payroll_EmployeeBonusTaxCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE (Bonus)   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings   Update date : 03/04/2018 - Updated Tax Spread (Bonus)   Update date : 25/03/2019 - Updated Tax Spread (Bonus) vs Annual Payments   Update Date : 11/04/2019 => Added Employee PAYE (Bonus) (Simulation) @ Terminations  */  CREATE procedure [Payroll_EmployeeBonusTaxCalculation_TrialSimulation_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try    declare @employeeType_seniorManagers int = 2    declare @employeeType_wardCouncilors int = 3    declare @employeeType_boardMembers int = 7        declare @bonusPeriod_monthOfEmploymentDate int = 1    declare @bonusPeriod_monthOfEmployeesBirthday int = 2    declare @bonusPeriod_allEmployeesOnSameMonth int = 3    declare @bonusPeriod_specificCalendarMonth int = 4      declare @CycleID int = (select isnull([CycleID], 0) from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)),      @CycleModeID int = 1,      @TaxYear varchar(9) = (select [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'TaxYear'))      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID))      declare @i int = 1,      @c int,      @PeriodYearStart datetime = cast(left(@TaxYear, 4) + '-03-01' as datetime),      @PeriodYearUntil datetime = dateadd(day, -1, cast(right(@TaxYear, 4) + '-03-01' as datetime)),      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 1,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @BonusPaymentDateID int,      @Years decimal(18, 6),      @Months decimal(18, 6),      @EmploymentDate datetime,      @BirthDate datetime,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6) = 0,      @incomeBonusYearToDate decimal(18, 6) = 0,      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueAnnual decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6) = 0,      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @hasUpperLimits bit,        /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @XOR int = (1 ^ 8)      declare @leapValue decimal(18, 6) = (1 + (case when ((year(@PeriodYearUntil) % 4 = 0 and year(@PeriodYearUntil) % 100 <> 0) or year(@PeriodYearUntil) % 400 = 0) then 1 else 0.25 end))      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [BonusPaymentDateID] int not null,     [EmploymentDate] datetime not null,     [BirthDate] datetime not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [TransactionTypeID] int null,     [SalaryHeadID] int null,     [SalaryHeadTitle] nvarchar(50) null,     [HasUpperLimits] bit not null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [BonusPaymentDateID],      [EmploymentDate], [BirthDate], [Age], [Amount], [PayrollDefinationID],[TransactionTypeID], [SalaryHeadID], [SalaryHeadTitle], [HasUpperLimits])       select @Periods, 1, 0, [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), isnull([BonusPaymentDateID], @BonusDateID), [JoiningDate], [DateOfBirth], (floor(datediff(day, [DateOfBirth], getdate()) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [IRP5].[TransactionTypeID], [SalaryHead_ID], [SalaryHeadTitle],      (case        when PE.EmployeeTypeID in (@employeeType_seniorManagers, @employeeType_wardCouncilors, @employeeType_boardMembers) then 1       else 0      end) AS HasUpperLimits        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_EmployeeSubtypes] as [PES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ApplyBonus] = 1         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and [SalaryHead_ID] = 4 and [BonusCalculation] = 3)      select @c = count([ID]) from @paye      while (@i <= @c)    begin       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @BonusPaymentDateID = [BonusPaymentDateID], @EmploymentDate = [EmploymentDate], @BirthDate = [BirthDate], @Age = [Age], @hasUpperLimits = [HasUpperLimits] from @paye where ([ID] = @i)       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] @IRP5Income, '01 + 02 + 03', @EmployeeID, @StartDate, @UntilDate, @CycleID, @CycleModeID, @XOR, @SimulationType, @ParentID, 1, @income out       /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = 0       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [ETP].[SimulationType] = @SimulationType and [IRP5].[TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = 0       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslipSimul