nnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'       /* CALCULATE FUTURE-DATED ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     if (@incomeBonus = 0 and @incomeBonusYearToDate = 0)     begin        if (@BonusPaymentDateID = @bonusPeriod_monthOfEmploymentDate)         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when month(@EmploymentDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @EmploymentDate, 120), 6) as datetime)) + @leapValue) / (365.242199)))        else if (@BonusPaymentDateID = @bonusPeriod_monthOfEmployeesBirthday)         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when month(@BirthDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @BirthDate, 120), 6) as datetime)) + @leapValue) / (365.242199)))        else if (@BonusPaymentDateID in (@bonusPeriod_allEmployeesOnSameMonth, @bonusPeriod_specificCalendarMonth))         set @Years = (floor((datediff(day, @EmploymentDate, cast((case when @BonusMonth < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + format(@BonusMonth, '-00') + format(month(@StartDate), '-00') as datetime)) + @leapValue) / (365.242199)))        if (@EmploymentDate < @PeriodYearStart)      begin         set @EmploymentDate = @PeriodYearStart         set @Months = (floor((datediff(day, @EmploymentDate, @PeriodYearUntil) + @leapValue) / (30.4375)))        end      else if (@EmploymentDate >= @PeriodYearStart)      begin         if (@BonusPaymentDateID = @bonusPeriod_monthOfEmploymentDate)          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when month(@EmploymentDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @EmploymentDate, 120), 6) as datetime)) + @leapValue) / (30.4375)))         else if (@BonusPaymentDateID = @bonusPeriod_monthOfEmployeesBirthday)          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when month(@BirthDate) < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + right(convert(varchar(10), @BirthDate, 120), 6) as datetime)) + @leapValue) / (30.4375)))         else if (@BonusPaymentDateID in (@bonusPeriod_allEmployeesOnSameMonth, @bonusPeriod_specificCalendarMonth))          set @Months = (ceiling((datediff(day, @EmploymentDate, cast((case when @BonusMonth < 3 then right(@TaxYear, 4) else left(@TaxYear, 4) end) + format(@BonusMonth, '-00') + format(month(@StartDate), '-00') as datetime)) + @leapValue) / (30.4375)))        end        set @incomeBonus = coalesce((select ((cast((case                  when @Years > 0 or @hasUpperLimits = 1 then [BonusAmount]                  when @Years < 1 and isnull([IsProRata], 0) = 1 then ([BonusAmount] / @Periods) * @Months                  else 0                 end) as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6)))                from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1                 join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[