  if (@pension > (@income * @pension_percentage))         set @pension = (@income * @pension_percentage)        /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN PENSION IS CAPPED TO 350, 000 */      if (@pension > @pension_value)         set @pension = @pension_value        set @income = @income - @pension       end       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS'       /* CALCULATE TAX ACCORDING TO SARS TAX SCALES */     if (@CalculationType % 2 = 1)     begin        select @payeMinValue = cast([TaxThresholdsAmount] as decimal(18, 6)) from [Const_TaxThresholds] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and ([MaxAge] is null or [MaxAge] >= @Age) and [FinancialYear] = @TaxYear)        select @payeRebates = cast(sum(isnull([TaxRebatesAmount], 0)) as decimal(18, 6)) from [Const_TaxRebates] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and [FinancialYear] = @TaxYear)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; INCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */      if (@CalculationType % 2 = 1 and @income > @payeMinValue)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], @payeValueBonus as [payeValueBonus], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES'' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'        end        /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 0 and @income > @payeMinValue)      begin         set @payeStartValue = cast(0 as decimal(18, 6))         set @payeFixedValue = cast(0 as decimal(18, 6))         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVE */       if (@CalculationType = 2)       begin          select @payePercentage = coalesce((select sum((case             when [DirectiveTypeId] = 1 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @payeValue = coalesce((select sum((case             when [DirectiveTypeId] = 1 then (@income * (@payePercentage / cast(100 as decimal(18, 6))))             when [DirectiveTypeId] = 2 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @TaxDirectiveType = [DirectiveTypeId] from [Payroll_EmployeeTaxDirectives] with(nolock) where ([Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)         end         /* CALCULATE TAX ACCORDING TO EMPLOYEE PART TIME COUNCILLORS DIRECTIVE */       if (@CalculationType = 4)       begin          set @payePercentage = @payePercentageCouncillors          set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         end        end        set @payeValueBonus = 0        /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */      if (@BonusCalculationType = 3)      begin         set @incomeAnnual = @i

GO

-- ============================================
-- SP: Payroll_EmployeeCalander_sp
-- Schema: dbo
-- ============================================
    create procedure [dbo].[Payroll_EmployeeCalander_sp] @table [Payroll_EmployeeCalander] readonly  as  begin     set nocount on;       update  [PEC] set [RotationID] = [T].[RotationID], [Date] = [T].[Date] , [WeekNo] = [T].[WeekNo], [WeekDay] = [T].[WeekDay],[DayName] = [T].[DayName], [ShiftID] = [T].[ShiftID] ,[NoOfHrs] = [T].[NoOfHrs],                                                         [NightHrs] = [T].[NightHrs], [PublicH] = [T].[PublicH], [Leave] = [T].[Leave], [Shift] = [T].[Shift], [OT] = [T].[OT], [Substitute] = [T].[Substitute], [DateModified] = [T].[DateModified], [ModifierID] = [T].[ModifierID]        from [Payroll_EmployeeCalander] [PEC]      join @table [T] on [T].[EmployeeCalendar_ID] =  [PEC].[EmployeeCalendar_ID]         insert into [Payroll_EmployeeCalander]([RotationID], [EmployeeID], [Date], [WeekNo], [WeekDay], [DayName], [ShiftID], [NoOfHrs], [NightHrs], [PublicH], [Leave], [Shift], [OT], [Substitute], [DateCaptured], [CapturerID], [DateModified], [ModifierID])                   select [RotationID], [EmployeeID], [Date], [WeekNo], [WeekDay], [DayName], [ShiftID], [NoOfHrs], [NightHrs], [PublicH], [Leave], [Shift], [OT], [Substitute], [DateCaptured], [CapturerID], [DateModified], [ModifierID] from @table    end     set nocount off;      

GO

-- ============================================
-- SP: Payroll_EmployeeCalendarLeaveSplit
-- Schema: dbo
-- ============================================
/*   Modiri   2019/10/22   #93711_2 Calendar Look and feel not as per spesification.    PR to make sure the file is checkin in to master     Modified: R Mills - 2025/01/17 - Employee 1082 Issue with employee calendar     Payroll_EmployeeCalendarLeaveSplit 54  */    CREATE PROCEDURE  [dbo].[Payroll_EmployeeCalendarLeaveSplit]    @EmployeeID int  AS        DECLARE @tbl table(idx int identity(1,1),Transaction_ID int, startdate datetime, enddate datetime, LeaveTypeDesc varchar(100), Abbreviation varchar(10), Color varchar(30), LeaveClassification_ID int, Value float, ShiftStartTime varchar(40), ShiftEndTime  varchar(40), ShiftHour  varchar(40))    DECLARE @tblLeave table(idx int identity(1,1),Transaction_ID int, startdate datetime, enddate datetime, LeaveTypeDesc varchar(100), Abbreviation varchar(10), Color varchar(30), LeaveClassification_ID int, Value float, ShiftStartTime varchar(40), ShiftEndTime  varchar(40), ShiftHour  varchar(40))    INSERT INTO @tbl  (   Transaction_ID,      startdate,      enddate,      LeaveTypeDesc,      Abbreviation,      Color,      LeaveClassification_ID,      [Value],      ShiftStartTime,      ShiftEndTime,      ShiftHour  )  SELECT distinct lt.Transaction_ID, lt.StartDate, lt.EndDate, cl.LeaveTypeDesc, lc.Abbreviation, lc.Color, lc.LeaveClassification_ID, lt.Value, sh.ShiftStartTime, sh.ShiftStartTime, sh.ShiftHour from Payroll_Employee pe    join payroll_EmployeeLeaveTransactions lt on pe.Employee_ID = lt.EmployeeID    join Const_LeaveType cl on lt.LeaveTypeID = cl.LeaveType_ID    join Const_LeaveClassification_sys lc on cl.LeaveClassificationID = lc.LeaveClassification_ID    join Payroll_EmployeeCalander ec on ec.Date between lt.StartDate and lt.EndDate and ec.EmployeeID = lt.EmployeeID and ec.Leave = 1    join Const_Shift sh on ec.ShiftID = sh.Shift_ID    where lt.EmployeeID = @EmployeeID and pe.LeaveSchemeID = lt.LeaveSchemeID and lt.LeaveAdjustmentTypeID = 3    DECLARE @cnt int =1  WHILE @cnt <= (SELECT Count(*) FROM @tbl)  BEGIN     DECLARE @dtfrom datetime, @dtTo datetime   SELECT @dtfrom=t.startdate,@dtTo=t.enddate  FROM @tbl t WHERE t.idx =@cnt;     if(SELECT Count(*) FROM dbo.Const_Holiday ch where MONTH(ch.HolidayDate) BETWEEN MONTH(@dtfrom) AND MONTH(@dtTo) AND (DAY(ch.HolidayDate) BETWEEN DAY(@dtfrom) AND DAY(@dtTo)) ) >0   BEGIN         DECLARE @tmpEndLeave datetime, @month varchar(10)='' ,@day varchar(10)='', @dcnt int=1         SELECT @month =MONTH(ch.HolidayDate), @day=DAY(ch.HolidayDate) FROM dbo.Const_Holiday ch where MONTH(ch.HolidayDate) BETWEEN MONTH(@dtfrom) AND MONTH(@dtTo) AND (DAY(ch.HolidayDate) BETWEEN DAY(@dtfrom) AND DAY(@dtTo))       SET @tmpEndLeave= CONVERT(varchar(10),YEAR(@dtfrom))+'-'+CONVERT(varchar(10),@month)+'-'+CONVERT(varchar(10),@day)         INSERT INTO @tblLeave     (      Transaction_ID,       startdate,      enddate,      LeaveTypeDesc,      Abbreviation,      Color,      LeaveClassification_ID,      [Value],      ShiftStartTime,      ShiftEndTime,      ShiftHour     )     SELECT t.Transaction_ID, t.startdate,@tmpEndLeave,t.LeaveTypeDesc, t.Abbreviation, t.Color, t.LeaveClassification_ID, t.[Value], t.ShiftStartTime, t.ShiftEndTime, t.ShiftHour FROM @tbl t WHERE t.idx =@cnt;       --loop to set end date     WHILE( @tmpEndLeave < @dtTo)     BEGIN           SET @tmpEndLeave = DATEADD(DAY,1,@tmpEndLeave)        if(SELECT Count(*) FROM dbo.Const_Holiday ch where MONTH(ch.HolidayDate)= MONTH(@tmpEndLeave) AND (DAY(ch.HolidayDate) = DAY(@tmpEndLeave)) ) =0      BEGIN       DECLARE @tmpEnddt datetime       SET @month=''       SET @day=''         INSERT INTO @tblLeave       (       Transaction_ID,        startdate,        enddate,        LeaveTypeDesc,        Abbreviation,        Color,        LeaveClassification_ID,        [Value],        ShiftStartTime,        ShiftEndTime,        ShiftHour       )       SELECT t.Transaction_ID,@tmpEndLeave,t.enddate,t.LeaveTypeDesc, t.Abbreviation, t.Color, t.LeaveClassification_ID, t.[Value], t.ShiftStartTime, t.ShiftEndTime, t.ShiftHour FROM @tbl t WHERE t.idx =@cnt;        END           END         END   ELSE   BEGIN    INSERT INTO @tblLeave    (    Transaction_ID,     startdate,     enddate,     LeaveTypeDesc,     Abbreviation,     Color,     LeaveClassification_ID,     [Value],     ShiftStartTime,     ShiftEndTime,     ShiftHour    )    SELECT t.Transaction_ID,t.startdate,t.enddate,t.LeaveTypeDesc, t.Abbreviation, t.Color, t.LeaveClassification_ID, t.[Value], t.ShiftStartTime, t.ShiftEndTime, t.ShiftHour FROM @tbl t WHERE t.idx =@cnt;   END      SET @cnt = @cnt+1;  END    SELECT     idx,    Transaction_ID,    startdate,    enddate,    LeaveTypeDesc,    Abbreviation,    Color,    LeaveClassification_ID,    [Value],    ShiftStartTime,    ShiftEndTime,    ShiftHour  FROM @tblLeave

GO

-- ============================================
-- SP: Payroll_EmployeeCostToCompanyPerDepartmentAndRace
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2021-01-13  -- Description: Used as a dataset for Employee Cost to Company per Department and Race Report report   --              (Payroll_EmployeeCostToCompanyPerDepartmentAndRace.rdl)  --              Returns Payroll Run results grouped by department and race  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeCostToCompanyPerDepartmentAndRace]      @TaxYear VARCHAR(9) = ''   ,@CycleId INT = 0   ,@Period VARCHAR(500) = ''      ,@ExcludedSalaryHeadIds VARCHAR(MAX)        ,@DepartmentId INT = 0        ,@DivisionId INT = 0        ,@RemunerationType INT = 0    AS    BEGIN        DECLARE        @RemunerationTypeAll INT = 0        ,@RemunerationTypeTaskGrade INT = 1        ,@RemunerationTypeUpperLimit INT = 2        ,@RemunerationTypeWage INT = 3        ,@TransactionTypeEarnings INT = 1        ,@TransactionTypeCompanyContributions INT = 3      ;WITH CyclePeriods    AS    (     SELECT DISTINCT      [Period_ID],      [CycleID],      [TaxYear]     FROM      Payroll_CyclePeriodDetails     WHERE      [Enabled] = 1     AND (ISNULL(@TaxYear, '') = '' OR [TaxYear] = @TaxYear)     AND (ISNULL(@Period, '') = '' OR [ProcessingMonth] = @Period)     AND (ISNULL(@CycleId, 0) = 0 OR [CycleID] = @CycleId)    )    SELECT        PPR.DepartmentID AS DepartmentId        ,PPR.DepartmentDesc AS Department        ,CEG.Ethnic_ID AS RaceId        ,CEG.EthnicDesc AS Race        ,COUNT(DISTINCT PPR.EmployeeID) AS Employees        ,SUM(PPR.Amount) AS CostToCompany    FROM   CyclePeriods cp  INNER JOIN   Payroll_PayrollResults AS PPR  ON cp.[Period_ID] = PPR.[PeriodID]            AND cp.[CycleID] = PPR.[CycleID]  JOIN Payroll_CyclePeriodDetails AS PCPD ON PPR.PeriodID = PCPD.Period_ID    JOIN Payroll_Employee AS PE ON PE.Employee_ID = PPR.EmployeeID    LEFT JOIN Payroll_EmployeeTermination AS PET ON PET.EmployeeID = PE.Employee_ID AND PET.Complete = 1    JOIN Const_EthnicGroup AS CEG ON PE.EthnicGroupID = CEG.Ethnic_ID    CROSS APPLY (        SELECT TOP 1 PPHI.JobProfileID         FROM Payroll_PositionHistory AS PPHI         WHERE PPHI.EmployeeID = PPR.EmployeeID            AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PPHI.StartDate AND PPHI.EndDate)            AND PPHI.Enabled = 1    ) AS PPH    JOIN Payroll_JobProfileHistory AS PJPH ON PJPH.JobProfileID = PPH.JobProfileID        AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PJPH.StartDate AND PJPH.EndDate)        AND PJPH.Enabled = 1    WHERE PPR.SalaryHeadID NOT IN (SELECT * FROM STRING_SPLIT(@ExcludedSalaryHeadIds, ','))        AND (PPR.TransactionTypeID = @TransactionTypeEarnings OR PPR.TransactionTypeID = @TransactionTypeCompanyContributions)        AND (PPR.DepartmentID = @DepartmentId OR @DepartmentId = 0)        AND (PPR.DivisionID = @DivisionId OR @DivisionId = 0)        AND ((@RemunerationType = @RemunerationTypeAll)            OR (                (@RemunerationType = @RemunerationTypeTaskGrade AND PJPH.TaskGradeId IS NOT NULL AND PJPH.LimitID IS NULL)                OR (@RemunerationType = @RemunerationTypeUpperLimit AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeWage AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NULL))        )    GROUP BY         PPR.DepartmentID        ,PPR.DepartmentDesc        ,CEG.Ethnic_ID        ,CEG.EthnicDesc        END

GO

-- ============================================
-- SP: Payroll_EmployeeDependantList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 31 JULY 2013  -- Description:  SELECT EMPLOYEE DEPENDANT DETAILS    -- CALSS : [Payroll_employeeDependantList_sp] 26  -- 2015-07-21 : Ravindra Jijotia: TP19740 New flag has been introduced to display Employer Contribution value.  -- 2015-08-12 : Ravindra Jijotia: TP19740 Updated DependantMode = 2 as it is now 'FIRST' Dependant Mode.  -- 2016-08-19 : Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return Dependant result WHERE IsAdultDependant =1 or IsChildDependant=1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeDependantList_sp]     @EmployeeID INT  AS  BEGIN   SELECT  PAY_EMP_REL.EmployeeID,     dbo.BufferString_fxn(CONVERT(VARCHAR,(PAY_EMP_REL.PersonRelationshipType_ID)), 8, '0') AS EmployeeDependant_ID,         PAY_EMP_REL.FullNames as DependantName,     PAY_EMP.IdNo,      PAY_EMP.FirstName ,     PAY_EMP_REL.Surname,     CASE WHEN PAY_EMP_REL.DateOfBirth IS NULL THEN       '' --CONVERT(NVARCHAR(12),GETDATE(),103)     ELSE        CONVERT(NVARCHAR(12),PAY_EMP_REL.DateOfBirth,103)      END AS DateOfBirth,     CASE WHEN PAY_EMP_REL.MedAidJoiningDate IS NULL THEN       '' --CONVERT(NVARCHAR(12),GETDATE(),103)     ELSE       CONVERT(NVARCHAR(12),PAY_EMP_REL.MedAidJoiningDate,103)      END AS DependedJoinDate,     CASE WHEN PAY_EMP_REL.MedAidTerminateDate IS NULL THEN       '' --CONVERT(NVARCHAR(12),GETDATE(),103)     ELSE       CONVERT(NVARCHAR(12),PAY_EMP_REL.MedAidTerminateDate,103)      END AS TerminateDate,     '' as FinancialYear,     CASE      --WHEN PAY_EMP_REL.DependantMode = 1 THEN 'FIRST'     --WHEN PAY_EMP_REL.DependantMode = 2 THEN 'SECOND'     WHEN PAY_EMP_REL.DependantMode = 2 THEN 'FIRST'     WHEN PAY_EMP_REL.DependantMode = 4 THEN 'TERMINATED'     ELSE 'ADDITIONAL' END AS DependantMode,     CASE WHEN PAY_EMP_REL.Enabled = 1 THEN       'ACTIVE'     ELSE       'IN ACTIVE'      END AS ACTIVESTATUS ,          CASE WHEN PAY_EMP_REL.IsAdultDependant = 1 THEN       'Adult'     WHEN PAY_EMP_REL.IsChildDependant = 1 THEN       'Child'     ELSE ''        END AS Dependant,     CASE WHEN PAY_EMP_REL.IsMedAidEmployerContribute = 1 THEN       'Yes'     ELSE       'No'      END AS IsEmployerContribute      FROM Payroll_PersonRelationshipType PAY_EMP_REL   INNER JOIN Payroll_Employee PAY_EMP     ON PAY_EMP.Employee_ID= PAY_EMP_REL.EmployeeID   WHERE PAY_EMP_REL.EmployeeID = @EmployeeID AND PAY_EMP_REL.Enabled = 1 AND (IsAdultDependant =1 or IsChildDependant=1)   ORDER BY PAY_EMP_REL.DependantMode  END     

GO

-- ============================================
-- SP: Payroll_EmployeeDependantSel_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 31 JULY 2013  -- Description:  SELECT EMPLOYEE DEPENDANT DETAILS BY EMPLYEEID  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeDependantSel_sp]     @EmployeeID INT  AS  BEGIN   SELECT  EmployeeID,     EmployeeDependant_ID,     DependantMode,     DependantName,     MunicipalityID,     Enable,     DateCaptured,     CapturerID,     DateModified,     ModifierID   FROM Payroll_EmployeeDependantDetails   WHERE EmployeeID=@EmployeeID     END     

GO

-- ============================================
-- SP: Payroll_EmployeeDetailsRpt_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 08 JULY 2013  -- Description:GET EMPLOYEE DETAILS  -- CALLS : Payroll_EmployeeDetailsRpt_sp '1950/07/01','2014/07/31', 0, 0  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt: Added ISNULL checks at employee name and address to cater for empty fields.  -- 2016-01-05 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2021-04-12 TP59868 Myroshnychenko: Fix issue with Brunch and Addresses(Physical, Postal, Work)  -- 2021-04-19 TP59868 Myroshnychenko: Fix issue with Postal Address like PO Box  -- 2021-10-06 WI28637 Charl E changed Const_Bank INNER JOIN to LEFT JOIN for employees paid by cheque  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeDetailsRpt_sp]      @FromDate DATETIME ,      @ToDate DATETIME ,      @DepartmentId INT ,      @CycleId INT  AS       BEGIN                  DECLARE @PATH NVARCHAR(50)          SET @PATH = ( ( SELECT  KeyValue                          FROM    dbo.AAAA_ConfigSettings                          WHERE   keyname = 'DocViewerRootFolderPath'                        ) + ( SELECT  REPLACE(KeyValue, '\', '')                              FROM    dbo.AAAA_ConfigSettings                              WHERE   keyname = 'EmployeeDocument'                            ) )            SELECT DISTINCT                  PAY_EMP.Employee_ID      , ( SELECT   dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)) AS EmpID      , ISNULL(PAY_EMP.EmpCode, '') AS EmpCode      , ISNULL(PAY_EMP.FirstName + ' ', '') + ISNULL(PAY_EMP.SecondName + ' ', '') + ISNULL(PAY_EMP.Surname, '') AS EmployeeName      , '' AS FullNames      , dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo      , PAY_EMP.KnownAsName AS KnowAs      , PAY_EMP.IdNo AS ID      , PAY_EMP.PassportNumber      , CONVERT(NVARCHAR, PAY_EMP.DateOfBirth, 103) AS DateOfBirth      , DATEDIFF(YY, PAY_EMP.DateOfBirth, GETDATE()) AS Age      , CONST_COUN.CountryDesc AS PassPortCountry      , case when PhysicalAddressTypeID = 1 then C_S.StreetName +       IIF(LEN(TRIM(PAY_EMP.PhysicalStreetNo))=0 OR PAY_EMP.PhysicalStreetNo IS NULL,'',' ('+PAY_EMP.PhysicalStreetNo+')')+       IIF(LEN(TRIM(PAY_EMP.PhysicalComplexName)) = 0 OR PAY_EMP.PhysicalComplexName IS NULL,'',', ' + PAY_EMP.PhysicalComplexName)+       IIF(LEN(TRIM(PAY_EMP.PhyAddressUnit))=0 OR PAY_EMP.PhyAddressUnit IS NULL,'', ', ' + PAY_EMP.PhyAddressUnit)+       ', ' + PAY_EMP.PhysicalPostalCode +       ', ' +C_Sub.SuburbName + ', ' +       C_T.Town + ', ' +       C_P.ProvinceDesc + ', ' +       C_C.CountryDesc         else PhysicalAddress1 + ',' + PhysicalAddress2 + ',' + PhysicalAddress3 + ',' + PhysicalAddress4 end AS ResidentialAddress      ,CASE        WHEN PAY_EMP.PostalAddressTypeID = 2 THEN        IIF(PAY_EMP.PostalAddressIndId=1,'PO Box ',IIF(PAY_EMP.PostalAddressIndId=2,'Private Bag ','Other PO Special Service ')) +         IIF(PAY_EMP.PostalPOBoxNo IS NOT NULL,PAY_EMP.PostalPOBoxNo ,'') +        IIF(PAY_EMP.PoSpecialService IS NOT NULL AND PAY_EMP.PostalPOBoxNo IS NULL,PAY_EMP.PoSpecialService ,'') +        IIF(PAY_EMP.PoSpecialService IS NOT NULL AND PAY_EMP.PostalPOBoxNo IS NOT NULL,' ('+PAY_EMP.PoSpecialService + '),',',') +        PAY_EMP.PostalPostOffice + ', ' +        PAY_EMP.PostalPostalCode +', ' +        PC_Sub.SuburbName + ', ' +        PC_T.Town + ', ' +        PC_P.ProvinceDesc + ', ' +        PC_C.CountryDesc        ELSE         IIF(LEN(TRIM(PAY_EMP.PostalStreetName)) = 0 OR PAY_EMP.PostalStreetName IS NULL, PostalAddress1, PostalStreetName) +        IIF(LEN(TRIM(PAY_EMP.PostalAddressNo))=0 OR PAY_EMP.PostalAddressNo IS NULL,',',' ('+PAY_EMP.PostalAddressNo+'), ') +         IIF(LEN(TRIM(PAY_EMP.PostalComplexName)) = 0 OR PAY_EMP.PostalComplexName IS NULL,'',PAY_EMP.PostalComplexName + ', ') +        IIF(LEN(TRIM(PAY_EMP.PostalAddressUnitNumber))=0 OR PAY_EMP.PostalAddressUnitNumber IS NULL,'', PAY_EMP.PostalAddressUnitNumber +', ')+        PAY_EMP.PostalPostalCode +', ' +        PC_Sub.SuburbName + ', ' +        PC_T.Town + ', ' +        PC_P.ProvinceDesc + ', ' +        PC_C.CountryDesc        END AS PostalAddress      ,IIF(LEN(TRIM(PAY_EMP.WorkAddress1)) = 0 OR PAY_EMP.WorkAddress1 IS NULL,'',PAY_EMP.WorkAddress1)+        IIF(LEN(TRIM(PAY_EMP.PhyWorkStreetNo))=0 OR PAY_EMP.PhyWorkStreetNo IS NULL,', ',' ('+PAY_EMP.PhyWorkStreetNo+'), ')+        IIF(LEN(TRIM(PAY_EMP.PhyWorkComplex)) = 0 OR PAY_EMP.PhyWorkComplex IS NULL,'',PAY_EMP.PhyWorkComplex + ', ')+        IIF(LEN(TRIM(PAY_EMP.PhyWorkUnit))=0 OR PAY_EMP.PhyWorkUnit IS NULL,'', PAY_EMP.PhyWorkUnit +', ')+        PAY_EMP.WorkPostalCode +', ' +        WC_Sub.SuburbName + ', ' +        WC_T.Town + ', ' +        WC_P.ProvinceDesc + ', ' +        WC_C.CountryDesc        AS WorkAddress      , PAY_EMP.EmailAddress      , PAY_EMP.HomeNumber      , PAY_EMP.CellNumber      , PAY_EMP.WorkNumber      , PAY_EMP.FaxNumber      , CONST_PAY.PaymentTypeDesc AS PaymentType      , CONST_ACC.AccountDesc AS AccountType      , PAY_EMP.AccountHolderName      , CONST_BANK.BankDesc AS BankName      , CONST_BANK_BRANCH.BankBranchCode AS BranchNumber      , PAY_EMP.AccountNumber      , CONST_REL.AccountRelationship AS RelationShip      , CONST_BANK_BRANCH.BranchCodeDesc AS BranchName      , Const_Cycle.CycleDesc AS PayCycle      , Cycle_ID      , CONVERT(NVARCHAR, PAY_EMP.JoiningDate, 103) AS StartDate      , CONVERT(NVARCHAR, PAY_EMP.EndDate, 103) AS EndDate      , MOC.MethodOfTaxCalculation AS TaxStatus      , PAY_EMP.IncomeTaxNumber      , '' AS DirectiveNumber      , '' AS UIFStatus      , CASE     WHEN PAY_EMP.ExcludeSDL = 1 THEN 'YES'      ELSE 'NO'    END AS ExcludeForSDL      , '' AS EmployeeStatus      , '' AS Directiveper      , PAY_EMP.WHPD_Other      , PAY_EMP.WDPW_Other      , PAY_EMP.RPD_Other      , PAY_EMP.RPH_Other      , PAY_EMP.RPW_Other      , PAY_EMP.WHPM_Monthly      , PAY_EMP.WDPM_Monthly      , PAY_EMP.WHPD_Monthly      , PAY_EMP.RPD_Monthly      , PAY_EMP.RPH_Monthly      , dbo.Payroll_GetEmployeeWorkingDays(PAY_EMP.Employee_ID) AS WDPW_Monthly      , PAY_EMP.AnnualSalary      , PAY_EMP.FixedSalary      , '' AS Pension      , '' AS Retirement      , '' AS PensionStartDate      , '' AS RetirementStartDate      , ( @PATH + '/' + CONVERT(NVARCHAR, PAY_EMP.Employee_ID) + '/' + PAY_EMP.ImagePath ) AS EMPLOYEEPATH      , P_JP.JobTitle      , ExcludeUIF      , MOC.MethodOfTaxCalculation AS TaxCalculationType      , ExcludeSDL          FROM    Payroll_Employee PAY_EMP                  INNER JOIN Const_Country CONST_COUN ON PAY_EMP.PassportCountryID = CONST_COUN.Country_ID                  INNER JOIN Const_PaymentType CONST_PAY ON CONST_PAY.PaymentType_ID = PAY_EMP.PaymentTypeID                  LEFT OUTER JOIN Const_AccountType CONST_ACC ON CONST_ACC.AccountType_ID = PAY_EMP.AccountTypeID                  LEFT JOIN Const_Bank CONST_BANK ON CONST_BANK.Bank_ID = PAY_EMP.BankID                  LEFT JOIN Const_BankBranchCode CONST_BANK_BRANCH ON CONST_BANK_BRANCH.BankBranchCode_ID = PAY_EMP.BranchID                  LEFT JOIN Const_AccountRelationship CONST_REL ON CONST_REL.AccountRelationship_ID = PAY_EMP.AccountHolderRelationshipID                  INNER JOIN dbo.Const_Cycle ON dbo.Const_Cycle.Cycle_ID = PAY_EMP.CycleID                  LEFT OUTER JOIN dbo.Payroll_Position AS PP ON PAY_EMP.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile as P_JP ON PP.JobProfileID = P_JP.JobProfile_ID                  LEFT OUTER JOIN Const_MethodOfTaxCalculation_sys AS MOC ON MOC.MethodOfTaxCalculation_ID = PAY_EMP.TaxCalculationType      --Physical Address      LEFT JOIN Const_Street AS C_S        ON PAY_EMP.PhysicalStreetID = C_S.Street_ID      LEFT JOIN Const_Suburb AS  C_Sub       ON PAY_EMP.PhysicalSuburbID = C_Sub.Suburb_ID      LEFT JOIN Const_Town AS C_T       ON PAY_EMP.PhysicalTownID = C_T.Town_ID      LEFT JOIN Const_Province AS C_P       ON PAY_EMP.PhysicalProvinceID = C_P.Province_ID      LEFT JOIN Const_Country AS C_C       on PAY_EMP.PhysicalCountryID = C_C.Country_ID      ---Work Address      LEFT JOIN Const_Suburb AS  WC_Sub       ON PAY_EMP.WorkSuburbID = WC_Sub.Suburb_ID      LEFT JOIN Const_Town AS WC_T       ON PAY_EMP.WorkTownID= WC_T.Town_ID      LEFT JOIN Const_Province AS WC_P       ON PAY_EMP.WorkProvinceID = WC_P.Province_ID      LEFT JOIN Const_Country AS WC_C       ON PAY_EMP.WorkCountryID = WC_C.Country_ID      --Postall Adress      LEFT JOIN Const_Street AS PC_S        ON PAY_EMP.PostalStreetID = PC_S.Street_ID      LEFT JOIN Const_Suburb AS PC_Sub       ON PAY_EMP.PostalSuburbID = PC_Sub.Suburb_ID      LEFT JOIN Const_Town AS PC_T       ON PAY_EMP.PostalTownID= PC_T.Town_ID      LEFT JOIN Const_Province AS PC_P       ON PAY_EMP.PostalProvinceID = PC_P.Province_ID      LEFT JOIN Const_Country AS PC_C       on PAY_EMP.PostalCountryID = PC_C.Country_ID          WHERE   PAY_EMP.JoiningDate BETWEEN @FromDate AND @ToDate                  AND ( PP.DepartmentID = @DepartmentId                        OR @DepartmentId = 0                      )                  AND ( PAY_EMP.CycleID = @CycleId                        OR @CycleId = 0                      )      END

GO

-- ============================================
-- SP: Payroll_EmployeeEnabled_sp
-- Schema: dbo
-- ============================================
   -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 24 AUG 2013  -- Description: <Description,,>  -- 2016-08-19 : Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeEnabled_sp]   @EmployeeDependant_ID INT,   @EmployeePayrollDefinition_ID INT,   @Flag INT,   @EmployeeID INT  AS  BEGIN    IF(@Flag = 1)    BEGIN    UPDATE Payroll_PersonRelationshipType SET Enabled = 0 WHERE PersonRelationshipType_ID = @EmployeeDependant_ID    END   ELSE IF(@Flag = 2)   BEGIN    UPDATE Payroll_EmployeePayrollDefinition SET Enabled = 0 WHERE EmployeePayrollDefinition_ID = @EmployeePayrollDefinition_ID    END   ELSE IF(@Flag = 3)   BEGIN    UPDATE Payroll_PersonRelationshipType SET Enabled = 0 WHERE EmployeeID = @EmployeeID   END  END  

GO

-- ============================================
-- SP: Payroll_EmployeeEncashLeaveSearch_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- Call SP:  Payroll_EmployeeEncashLeaveSearch_sp '', '', '', 0  -- 2015-02-05 James Roodt: Linked P_EL.ApprovalStatus to Const_ApprovalStatus_sys  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeEncashLeaveSearch_sp]   @Name NVARCHAR(100) ,        @Surname NVARCHAR(100) ,        @IDNo NVARCHAR(30),      @ApprovalStatus INT  AS  BEGIN   SELECT Encash_ID, P_E.Employee_ID,isnull(P_E.EmpCode,'') EmpCode, P_E.IdNo, P_E.Surname, P_E.FirstName, LT.LeaveTypeDesc, RequestNoOfDays,    C_AS.ApprovalStatus as AppStatus,  ReasonForEncash, ApproveReason, P_EL.ApprovalStatus, ApproveNoOfDays,  LT.LeaveTypeDesc AS DetailDesc, LT.LeaveType AS DetailName   FROM Payroll_EmployeeLeaveEncashRequest AS P_EL   INNER JOIN Payroll_Employee AS P_E ON P_E.Employee_ID = P_EL.EmployeeId   INNER JOIN Const_LeaveType AS LT ON LT.LeaveType_ID = P_EL.LeaveTypeID   INNER JOIN dbo.Const_LeaveTypeDetails AS C_LTD ON P_EL.LeaveTypeDetailId = C_LTD.LeaveTypeDetailsId   INNER JOIN Const_ApprovalStatus_sys as C_AS ON C_AS.ApprovalStatus_ID=P_EL.ApprovalStatus   WHERE   ( P_E.FirstName = @Name                      OR @Name = ''                    )                    AND ( P_E.Surname = @Surname                          OR @Surname = ''                        )                    AND ( P_E.IdNo = @IDNo                          OR @IDNo = ''                        )      AND ( P_EL.ApprovalStatus = @ApprovalStatus                        OR @ApprovalStatus = 0                      )          ORDER BY P_E.Employee_ID  END      

GO

-- ============================================
-- SP: Payroll_EmployeeEquity_rpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,14 Apr 2014>  -- Description: <Description,,Employee Equity Report>  -- Call SP    : Payroll_EmployeeEquity_rpt 1, '2013/2014'  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  /*   Report Id List   1 - Total Employee   2 - Employees with disabilities   3 - Core Operation Function   4 - Support Function   5 - Recruitment Emplyee in current Financial Year   6 - Promotion of Emplyee in current Financial Year   7 - Termination of Emplyee in current Financial Year   8 - Skill Development of Emplyee in current Financial Year   9 - Skill Development of Emplyee with disabilities in current Financial Year   10 - Numeric Goals in current Financial Year   11 - Numeric Goals with disabilities in current Financial Year   12 - Numeric Targets in current Financial Year   13 - Numeric Targets with disabilities in current Financial Year   */   --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeEquity_rpt]   @ReportId INT,   @Financial_Year VARCHAR(50)  AS  BEGIN   DECLARE @Result TABLE (Id INT IDENTITY(1,1), OccupationLevel VARCHAR(500), M_Africa INT, M_Color INT, M_India INT, M_White INT, M_Fo INT,        F_Africa INT, F_Color INT, F_India INT, F_White INT, F_Fo INT, Total INT)      /* Current Financial Year */   DECLARE @C_Year INT, @Fin_StartDate DATETIME, @Fin_EndDate DATETIME   SELECT TOP 1 @C_Year = Data FROM dbo.Split(@Financial_Year,'/')   SET @Fin_StartDate = '01 Jul '+ CONVERT(NVARCHAR(10), @C_Year)   SET @Fin_EndDate = '30 Jun '+ CONVERT(NVARCHAR(10), @C_Year + 1)      /* Employee Table */        DECLARE @Employee TABLE(Employee_ID INT, GenderID INT, OccupationLevel VARCHAR(500), EthnicGroupID INT, Isforeigner BIT, EquityDisabled BIT, JoiningDate DATETIME, EndDate DATETIME, IsDummy BIT)      IF @ReportId = 1 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.Enabled = 1   END   ELSE IF @ReportId = 2 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.Enabled = 1 AND EquityDisabled = 1   END   ELSE IF @ReportId = 3 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.Enabled = 1 AND P_JP.CoreFunction = 1   END   ELSE IF @ReportId = 4 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.Enabled = 1 AND P_JP.CoreFunction = 0   END   ELSE IF @ReportId = 5 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate,P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.Enabled = 1 AND JoiningDate BETWEEN @Fin_StartDate AND @Fin_EndDate   END   ELSE IF @ReportId = 6 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      INNER JOIN dbo.Payroll_PerformanceApprisal AS P_PA ON P_PA.EmployeeID = P_E.Employee_ID AND P_PA.FinancialYear = @Financial_Year      WHERE P_E.Enabled = 1   END   ELSE IF @ReportId = 7 BEGIN    INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy )    SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy FROM dbo.Payroll_Employee AS P_E      --INNER JOIN dbo.Const_ProfileSubGroup AS C_PS ON P_E.JobProfileID = C_PS.ProfileSubGroup_ID      INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID      WHERE P_E.EndDate BETWEEN @Fin_StartDate AND @Fin_EndDate   END   /* Major Group Table */   DECLARE @Level TABLE (OccupationLevel NVARCHAR(500), Flag BIT)   DECLARE @OccupationLevel NVARCHAR(500)      INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Top management', 0   INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Senior management', 0   INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Professionally qualified and experienced specialists and mid-management', 0   INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Skilled technical and academically qualified workers, junior management, supervisors, foremen, and superintendents', 0   INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Semi-skilled and discretionary decision making', 0   INSERT INTO @Level (OccupationLevel, Flag)   SELECT 'Unskilled and defined decision making', 0      /* Ethnic Table */   DECLARE @African_Id INT, @India_Id INT, @White_Id INT   SELECT @African_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE '%African%'   SELECT @India_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'India%'   SELECT @White_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'White%'      /* Declare Variables*/   DECLARE @C_Count INT, @M_Africa INT, @M_Color INT, @M_India INT, @M_White INT, @M_Fo INT, @F_Africa INT, @F_Color INT, @F_India INT, @F_White INT, @F_Fo INT     /* For Male GenderId = 2 and For Female GenderId = 1*/   DECLARE @M_GenderId INT = 2, @F_GenderId INT = 1          WHILE EXISTS (SELECT * FROM @Level WHERE Flag = 0) BEGIN    SELECT TOP 1 @OccupationLevel = OccupationLevel FROM @Level WHERE Flag = 0        SELECT @M_Africa = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @M_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @F_Africa = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @F_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @M_Color = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @M_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0 AND IsDummy = 0        SELECT @F_Color = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @F_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0 AND IsDummy = 0        SELECT @M_India = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @M_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @F_India = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @F_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @M_White = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @M_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @F_White = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @F_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0 AND IsDummy = 0        SELECT @M_Fo = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @M_GenderId AND Isforeigner = 1 AND IsDummy = 0        SELECT @F_Fo = COUNT(*) FROM @Employee    WHERE OccupationLevel = @OccupationLevel AND GenderID = @F_GenderId AND Isforeigner = 1 AND IsDummy = 0        INSERT INTO @Result (OccupationLevel, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )    SELECT @OccupationLevel, @M_Africa, @M_Color, @M_India, @M_White, @M_Fo, @F_Africa, @F_Color, @F_India, @F_White, @F_Fo, (@M_Africa+ @M_Color+ @M_India+ @M_White+ @M_Fo+ @F_Africa+ @F_Color+ @F_India+ @F_White+ @F_Fo)        UPDATE @Level SET Flag = 1 WHERE OccupationLevel = @OccupationLevel   END      INSERT INTO @Result (OccupationLevel, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )   SELECT 'Total Permanent', SUM(M_Africa), SUM(M_Color), SUM(M_India), SUM(M_White), SUM(M_Fo), SUM(F_Africa), SUM(F_Color), SUM(F_India), SUM(F_White), SUM(F_Fo), SUM(Total)   FROM @Result      /*Temporary Employee*/   SELECT @M_Africa = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @African_Id AND IsDummy = 1      SELECT @F_Africa = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @African_Id AND IsDummy = 1      SELECT @M_Color = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND IsDummy = 1      SELECT @F_Color = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND IsDummy = 1      SELECT @M_India = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @India_Id AND IsDummy = 1      SELECT @F_India = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @India_Id AND IsDummy = 1      SELECT @M_White = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @White_Id AND IsDummy = 1      SELECT @F_White = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @White_Id AND IsDummy = 1      SELECT @M_Fo = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND Isforeigner = 1 AND IsDummy = 1      SELECT @F_Fo = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND Isforeigner = 1 AND IsDummy = 1      INSERT INTO @Result (OccupationLevel, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )   SELECT 'Temporary Employee', @M_Africa, @M_Color, @M_India, @M_White, @M_Fo, @F_Africa, @F_Color, @F_India, @F_White, @F_Fo, (@M_Africa+ @M_Color+ @M_India+ @M_White+ @M_Fo+ @F_Africa+ @F_Color+ @F_India+ @F_White+ @F_Fo)         /*Grand Total*/   INSERT INTO @Result (OccupationLevel, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )   SELECT 'GRAND Total', SUM(M_Africa), SUM(M_Color), SUM(M_India), SUM(M_White), SUM(M_Fo), SUM(F_Africa), SUM(F_Color), SUM(F_India), SUM(F_White), SUM(F_Fo), SUM(Total)   FROM @Result   WHERE OccupationLevel IN ('Temporary Employee', 'Total Permanent')      SELECT * FROM @Result  END    

GO

-- ============================================
-- SP: Payroll_EmployeeForLeaveReassign
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,04 Apr 2014>  -- Description: <Description,,Get Employee List for Leave Reassign>  -- Call SP    : Payroll_EmployeeForLeaveReassign 2  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeForLeaveReassign]   @UserId INT  AS  BEGIN   DECLARE @EmployeeId INT,@PositionId INT   DECLARE @ParentPositionId INT      SELECT @EmployeeId = EmpID FROM dbo.User_UserDetail WHERE User_ID = @UserId   PRINT @EmployeeId      --//Get the linked position   SELECT @PositionId = PositionID FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeId   PRINT @PositionId   --//get the parentpositionId linked to division by ManagerPositionID   SELECT @ParentPositionId = CD.ManagerPositionID  FROM dbo.Payroll_Position PP    INNER JOIN Const_Division CD on CD.Division_ID =PP.DivisionID    WHERE Position_ID = @PositionId   PRINT @ParentPositionId   --//Check that manager position is HOD to approve leave   SELECT P_E.Employee_ID, P_E.FirstName + ' ' + P_E.Surname AS Name   FROM dbo.Payroll_Position AS PP   INNER JOIN dbo.Payroll_Employee AS P_E ON PP.Position_ID = P_E.PositionID   WHERE pp.Position_ID = @ParentPositionId AND pp.HOD = 1     END    

GO

-- ============================================
-- SP: Payroll_EmployeeHeadcountGraph_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,29/11/2018>  -- Description: <Description,,Get data of Active Employee For Graph>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeHeadcountGraph_sp]   -- Add the parameters for the stored procedure here  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   DECLARE @Date DATETIME = GETDATE();     DECLARE @highDate datetime = '9999-12-31 00:00:00';     DECLARE @employees as table (    [Employee_ID] int not null   )     INSERT INTO @employees([Employee_ID])    SELECT DISTINCT [Employee_ID]     from [Payroll_Employee] as [PE] with(nolock)      join (       select [EmployeeID], [EPR].[Enabled], [StartDate], [EndDate]        from [Payroll_EmployeeHistory] as [EPH] with(nolock)         join [Payroll_ReasonEmployeeChange] as [EPR] with(nolock) on [Reason_ID] = [ReasonID] and [EPR].[Enabled] = 1       where (        --[DepartmentID] = (case isnull(@DepartmentID, 0) when 0 then [DepartmentID] else @DepartmentID end) and        --[DivisionID] = (case isnull(@DivisionID, 0) when 0 then [DivisionID] else @DivisionID end) AND        not [ReasonDescription] = 'Non-Employee' and        not exists(         select [PositionHistory_ID]         from [Payroll_PositionHistory] with(nolock)         where (          [PositionHistory_ID] = [EPH].[PositionHistoryID] and          [IsNonEmployee] = 1         )        )       )        group by [EmployeeID], [ReasonID], [EPR].[Enabled], [StartDate], [EndDate]      ) as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[StartDate] <= @Date and [PEH].[EndDate] >= @Date      where (     (      [IsDummy] = 0 and      [JoiningDate] <= @Date and [PE].[EndDate] >= @Date     ) and     not ([PE].[Enabled] = 0 and [PE].[EndDate] = @highDate)    )        SELECT COUNT(PE.Employee_ID) AS EmployeeId, cd.DepartmentDesc AS Department    FROM dbo.Payroll_Employee AS PE     INNER JOIN dbo.Payroll_Position AS pp ON pp.Position_ID = pe.PositionID    INNER JOIN dbo.Const_Department AS cd ON cd.Department_ID = pp.DepartmentID    INNER JOIN dbo.Const_Division AS ccd ON ccd.Division_ID = pp.DivisionID    WHERE PE.Employee_ID IN (    select [Employee_ID] from @employees)    GROUP BY cd.DepartmentDesc  END  

GO

-- ============================================
-- SP: Payroll_EmployeeHousingCalculation_Trial_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 10/01/2019   Description : Calculates Employee Housing Allowance   Update date : 24/01/2019 - Added Rules for Earnings and Deductions   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeHousingCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try    if exists ( select Processed from [Payroll_CyclePeriodDetails] [CPD] where [CPD].[PeriodStartDate] = @StartDate and [CPD].[PeriodEndDate] = @EndDate and [CPD].[Enabled] = 1 and [CPD].[Processed] = 0 and [Period_ID] = @PeriodID and [CycleID] = @CycleID and [CycleModeID] = @CycleModeID)    begin    /* ALLOCATION OF HOME OWNERS ALLOWANCE */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear], [Simulation])       select distinct [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], cast([EH].[Allowance] as decimal(18, 6)), @Month, @SCOAYear, [SH].[SalaryHeadTitle], @PeriodID, @TaxYear, @Simulation        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[SalaryHead_ID] = 34 and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_EmployeeHousing] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] is null and [EH].[StartDate] <= @EndDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 1 and cast([EH].[Allowance] as decimal(18, 6)) > 0 and         (case          when @CycleModeID = 1 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )        group by [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], [EH].[Allowance]      /* ALLOCATION OF HOME OWNERS DEDUCTION */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear], [Simulation])       select distinct [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], cast([EH].[Instalment] as decimal(18, 6)), @Month, @SCOAYear, [SH].[SalaryHeadTitle], @PeriodID, @TaxYear, @Simulation        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [SH].[HousingBond] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_EmployeeHousing] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] = [SH].[SalaryHead_ID] and [EH].[StartDate] <= @EndDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 2 and cast([EH].[Instalment] as decimal(18, 6)) > 0 and         (case          when @CycleModeID = 1 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )        group by [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], [EH].[Instalment]      /* ALLOCATION OF HOME OWNERS DEDUCTION (EXTRA) */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear], [Simulation])       select distinct [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], cast([EH].[Amount] as decimal(18, 6)), @Month, @SCOAYear, [SH].[SalaryHeadTitle], @PeriodID, @TaxYear, @Simulation        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [SH].[HousingBond] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_EmployeeHousingExtra] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] = [SH].[SalaryHead_ID] and [EH].[StartDate] <= @EndDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 2 and cast([EH].[Amount] as decimal(18, 6)) > 0 and         (case          when @CycleModeID = 1 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )        group by [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], [EH].[Amount]      end   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeHousingCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employee Housing Allowance (Simulation)   Update Date : 11/04/2019 => Added Employee Housing Allowance (Simulation) @ Terminations   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeHousingCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try    begin    /* ALLOCATION OF HOME OWNERS ALLOWANCE */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SH].[SalaryHeadTitle], cast([EH].[Allowance] as decimal(18, 6))        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[SalaryHead_ID] = 34 and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]         join [Payroll_EmployeeHousing] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] is null and [EH].[StartDate] <= @UntilDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 1 and cast([EH].[Allowance] as decimal(18, 6)) > 0)         group by [IRP5].[TransactionTypeID], [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [EH].[Allowance]      /* ALLOCATION OF HOME OWNERS DEDUCTION */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SH].[SalaryHeadTitle], cast([EH].[Instalment] as decimal(18, 6))        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [SH].[HousingBond] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]         join [Payroll_EmployeeHousing] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] = [SH].[SalaryHead_ID] and [EH].[StartDate] <= @UntilDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 2 and cast([EH].[Instalment] as decimal(18, 6)) > 0)         group by [IRP5].[TransactionTypeID], [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [EH].[Instalment]      /* ALLOCATION OF HOME OWNERS DEDUCTION (EXTRA) */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SH].[SalaryHeadTitle], cast([EH].[Amount] as decimal(18, 6))        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [SH].[HousingBond] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]         join [Payroll_EmployeeHousingExtra] as [EH] with(nolock) on [EH].[EmployeeID] = [PE].[Employee_ID] and [EH].[SalaryHeadID] = [SH].[SalaryHead_ID] and [EH].[StartDate] <= @UntilDate and [EH].[EndDate] >= @StartDate and [EH].[Enabled] = 1            join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1         join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 2 and cast([EH].[Amount] as decimal(18, 6)) > 0)         group by [IRP5].[TransactionTypeID], [PE].[Employee_ID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [CT].[CycleType_ID], [EH].[Amount]      end   end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeJoinLeaveProcess_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: MEHUL PANCHAL   -- Create date: 11 JULY 2013  -- Description:      -- Payroll_EmployeeJoinLeaveProcess_sp 104,22,1,'2012/2013','2012-07-02'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeJoinLeaveProcess_sp]     @EmployeeID INT,    @LeaveSchemeID INT,    @GenderID INT,    @FinancialYear NVARCHAR(50),    @EmployeeJoinDate DATETIME  AS  BEGIN       DECLARE @FinancialYearEndDate DATETIME   DECLARE @TotalDays INT   DECLARE @MUNICIPALITYID INT      SELECT TOP 1  @FinancialYearEndDate =  TaxYearEndDate FROM Payroll_Municipality_CycleDetails WHERE FinancialYear = @FinancialYear       SELECT  TOP 1 @MUNICIPALITYID = Municipality_ID  FROM Payroll_Municipality  ORDER BY Municipality_ID DESC        SET @TotalDays = DATEDIFF(DAY,@EmployeeJoinDate,@FinancialYearEndDate)     IF NOT EXISTS (SELECT EmployeeID FROM Payroll_EmployeeLeave WHERE EmployeeID = @EmployeeID AND FinancialYear = @FinancialYear AND Enabled = 1 AND LeaveSchemeID = @LeaveSchemeID)   BEGIN    UPDATE Payroll_EmployeeLeave SET Enabled = 0 WHERE EmployeeID = @EmployeeID AND FinancialYear = @FinancialYear AND Enabled = 1       INSERT INTO  Payroll_EmployeeLeave (EmployeeID,LeaveSchemeID, MunicipalityID,FinancialYear,LeaveTypeID, LeaveBalance, UsedLeave, [Enabled], DateCaptured, CapturerID,EntitledLeave)    SELECT @EmployeeID AS EmployeeId, @LeaveSchemeID, @MUNICIPALITYID, @FinancialYear, * FROM    (     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * FixedLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * FixedLeaveDays)/365),0),0)       END AS EntitledLeave      FROM Const_LeaveSchemeDetails      WHERE LeaveTypeID = 1 AND  LeaveSchemeID = @LeaveSchemeID)     UNION      (      SELECT        LeaveTypeID, '0' AS LEAVE, '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured,       1 AS CapturerID, '0' AS EntitledLeave      FROM Const_LeaveSchemeDetails      WHERE LeaveTypeID = 2 AND  LeaveSchemeID = @LeaveSchemeID)     UNION     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * SickLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * SickLeaveDays)/365),0),0)       END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 3 AND  LeaveSchemeID = @LeaveSchemeID)     UNION     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * FullSickLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable,GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * FullSickLeaveDays)/365),0),0)       END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 4 AND  LeaveSchemeID = @LeaveSchemeID)     UNION      (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * HalfSickLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * HalfSickLeaveDays)/365),0),0)       END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 5 AND  LeaveSchemeID = @LeaveSchemeID)     UNION     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * CompanyAccidentLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * CompanyAccidentLeaveDays)/365),0),0)       END AS EntitledLeave      FROM Const_LeaveSchemeDetails      WHERE LeaveTypeID = 6  AND  LeaveSchemeID = @LeaveSchemeID)     UNION     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * AccidentLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * AccidentLeaveDays)/365),0),0)       END AS EntitledLeave      FROM Const_LeaveSchemeDetails      WHERE LeaveTypeID = 7 AND LeaveSchemeID = @LeaveSchemeID)     UNION     (      SELECT        LeaveTypeID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * SpecialLeaveDays)/365),0),0)       END AS LEAVE,       '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,       CASE WHEN @TotalDays <= 365 THEN        ISNULL(ROUND((( @TotalDays * SpecialLeaveDays)/365),0),0)       END AS EntitledLeave      FROM Const_LeaveSchemeDetails      WHERE LeaveTypeID = 8 AND LeaveSchemeID = @LeaveSchemeID)     UNION       (       SELECT         LeaveTypeID,        CASE WHEN @TotalDays <= 365 THEN         ISNULL(ROUND((( @TotalDays * FamilyLeaveDays)/365),0),0)        END AS LEAVE,        '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN @TotalDays <= 365 THEN         ISNULL(ROUND((( @TotalDays * FamilyLeaveDays)/365),0),0)        END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 9 AND LeaveSchemeID = @LeaveSchemeID)     UNION       (       SELECT         LeaveTypeID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(ROUND((( @TotalDays * MaternityLeaveDays)/365),0),0)        ELSE          '0'          END AS LEAVE,        '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(ROUND((( @TotalDays * MaternityLeaveDays)/365),0),0)        ELSE         '0'        END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 10 AND LeaveSchemeID = @LeaveSchemeID)     UNION       (       SELECT         LeaveTypeID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdditionalMLeaveDays)/365 + 0.50), 0)        ELSE         '0'          END AS LEAVE,        '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdditionalMLeaveDays)/365 + 0.50), 0)        ELSE          '0'        END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 11 AND LeaveSchemeID = @LeaveSchemeID)     UNION      (       SELECT         LeaveTypeID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdoptionLeaveDays)/365 + 0.50), 0)        ELSE         '0'          END AS LEAVE,        '0.0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdoptionLeaveDays)/365 + 0.50), 0)        ELSE         '0'          END AS EntitledLeave        FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 12 AND LeaveSchemeID = @LeaveSchemeID)     UNION       (       SELECT         LeaveTypeID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdditionalALeaveDays)/365 + 0.50), 0)        ELSE         '0'          END AS LEAVE,        '0' AS UsedLeave, 1 AS Enable, GETDATE() AS DateCaptured, 1 AS CapturerID,        CASE WHEN (@TotalDays <= 365 AND @GenderID = 1) THEN         ISNULL(CONVERT(INT, (@TotalDays * AdditionalALeaveDays)/365 + 0.50), 0)       ELSE        '0'         END AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID = 13 AND LeaveSchemeID = @LeaveSchemeID)     UNION       (       SELECT         LeaveTypeID, '0' AS LEAVE, '0' AS UsedLeave, 1 AS Enable,        GETDATE() AS DateCaptured, 1 AS CapturerID, '0' AS EntitledLeave       FROM Const_LeaveSchemeDetails       WHERE LeaveTypeID  BETWEEN 14 AND 19 AND LeaveSchemeID = @LeaveSchemeID      )    ) AS TEMP   END       END  

GO

-- ============================================
-- SP: Payroll_EmployeeLeave_Calculation
-- Schema: dbo
-- ============================================
  -- ================================================================================================  -- Author:  <Author,,GD>      -- Create date: <Create Date,,04 Apr 2014>      -- Description: <Description,,>      -- Call SP    : Payroll_EmployeeLeave_Calculation 5, 26, 2     -- 2016-04-23 TP35916 : Ravindra Jijotia : Removed insert in Payroll_EmployeeLeaveSchemeTransaction  -- 2016-05-04 Ravindra: Implemented new changes for leave details.  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- 2016-10-12 Tshekedi Mogwere : changed the Insert logic into History Table TP#32221  -- 2017-07-28 Richa Mills - Add AccrualDays to Payroll_EmployeeLeaveSchemeTransaction  -- ================================================================================================      CREATE PROCEDURE [dbo].[Payroll_EmployeeLeave_Calculation]     @EmployeeId INT ,      @LeaveSchemeId INT ,      @UserId INT  AS       BEGIN                    DECLARE @Tbl TABLE              (                Id INT IDENTITY(1, 1) ,                LeaveTypeId INT ,                LeaveTypeDetailId INT ,                Flag BIT              )              DECLARE @Id INT ,              @LeaveTypeId INT ,              @LeaveTypeDetailId INT ,              @EmpJoiningDate DATETIME                     SELECT  @EmpJoiningDate = JoiningDate          FROM    dbo.Payroll_Employee          WHERE   Employee_ID = @EmployeeId                     DECLARE @IsFixedOrCalculated BIT ,              @AccrualFrequency INT ,              @NoOfDaysEarned INT ,              @ForNoOfDaysWorked INT ,              @CalenderOrWorkDays NVARCHAR(50)              DECLARE @CycleOn INT ,              @CycleStartDate DATETIME ,              @CycleEndDate DATETIME ,              @AccrualAfterMonths INT ,              @CycleType INT ,              @CycleRepeatFrequency INT                       INSERT  INTO @Tbl                  SELECT  C_LSTD.LeaveTypeId, C_LTD.LeaveTypeDetailsId, 0                  FROM    dbo.Const_LeaveSchemeTypeDetails AS C_LSTD With(NOLOCK)                           INNER JOIN dbo.Const_LeaveTypeDetails   AS C_LTD With(NOLOCK) ON C_LSTD.LeaveTypeId = C_LTD.LeaveTypeId                  WHERE   C_LSTD.LeaveSchemeId = @LeaveSchemeId --AND CycleType = 2 --AND IsFixedOrCalculated = 1         print 'After Insert into Temp table'         DECLARE @TaxYear NVARCHAR(10)      SELECT  @TaxYear = KEYVALUE    FROM    AAAA_ConfigSettings    WHERE   KeyName = 'TaxYear'            DECLARE @PeriodStartDate DATETIME ,              @PeriodEndDate DATETIME                     --SELECT TOP 1          --        @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate          --FROM    dbo.Payroll_CyclePeriodDetails          --WHERE   Processed = 0          --        AND ProcessedDate IS NULL          --        AND CycleID = 1 AND CycleModeID = 1          --ORDER BY Period_ID   --SELECT * FROM @Tbl             SELECT TOP 1 @PeriodStartDate = PeriodStartDate,  @PeriodEndDate = PeriodEndDate FROM  dbo.Payroll_CyclePeriodDetails cpd With(NOLOCK)     INNER JOIN Payroll_Employee emp With(NOLOCK)  ON emp.CycleID = cpd.CycleID    WHERE cpd.Processed = 0 AND cpd.CycleModeID = 1 AND cpd.ProcessedDate IS NULL    AND emp.Employee_ID = @EmployeeId AND cpd.CycleModeID = 1 AND cpd.TaxYear = @TaxYear                 DECLARE @RepeatCount INT ,              @LastDate DATETIME                     WHILE EXISTS ( SELECT   *                         FROM     @Tbl                         WHERE    Flag = 0 )               BEGIN                      SELECT TOP 1                          @Id = Id, @LeaveTypeId = LeaveTypeId, @LeaveTypeDetailId = LeaveTypeDetailId                  FROM    @Tbl                  WHERE   Flag = 0                              --SELECT  @IsFixedOrCalculated = IsFixedOrCalculated, @AccrualFrequency = AccrualFrequency, @AccrualDays = AccrualDays, @NoOfDaysEarned = NoOfDaysEarned, @CycleType = CycleType, @ForNoOfDaysWorked = ForNoOfDaysWorked, @CalenderOrWorkDays = LB.LeaveBased, @CycleOn = CycleOn, @CycleStartDate = CycleStartDate, @AccrualAfterMonths = AccrualAfterMonths, @CycleRepeatFrequency = CycleRepeatFrequency                  --FROM    dbo.Const_LeaveTypeDetails                  --        INNER JOIN dbo.Const_LeaveBased_sys AS LB ON LB.LeaveBased_ID = CalenderOrWorkDays                  --WHERE   LeaveTypeDetailsId = @LeaveTypeDetailId                                      --IF @CycleStartDate IS NOT NULL                   --    SET @CycleEndDate = DATEADD(MONTH, @AccrualAfterMonths, @CycleStartDate)                                  --IF @IsFixedOrCalculated = 1                   --    BEGIN --- Fixed                      --        IF @CycleType = 2                   --            BEGIN                      --                IF @CycleOn = 1                   --                    BEGIN                      --                        SELECT  @AccrualDays = SUM(WorkAccuralDays)                  --                        FROM    dbo.GetCalculatedWorkDay(@CycleStartDate, @CycleEndDate, @AccrualDays, @EmpJoiningDate, @AccrualFrequency)                      --                    END                  --                ELSE                   --                    IF @CycleOn = 3                   --                        BEGIN                      --                            SET @AccrualDays = 0                      --                        END                      --            END                      --        ELSE                   --            BEGIN                      --                SET @AccrualDays = 0                      --            END                      --    END                      --ELSE                   --    BEGIN                      --        IF @CycleType = 2                   --            BEGIN                      --                IF @CycleOn = 1                   --                    BEGIN                      --                        SET @AccrualDays = @NoOfDaysEarned ----- Need to check calculation (Ghanshyam Dhanani)                      --                    END                      --                ELSE                   --                    IF @CycleOn = 2                   --                        BEGIN                      --                            SET @AccrualDays = @NoOfDaysEarned                      --                        END                      --                    ELSE                   --                        BEGIN                      --                            SET @AccrualDays = 0                      --                        END                      --            END                      --        ELSE                   --            BEGIN                      --                SET @AccrualDays = 0                      --            END                      --    END                            --PRINT @Id                            IF NOT EXISTS ( SELECT  *                                  FROM    dbo.Payroll_EmployeeLeaveSchemeDetails With(NOLOCK)                                   WHERE   EmployeeId = @EmployeeId                                          AND LeaveSchemeId = @LeaveSchemeId                                          AND LeaveTypeDetailId = @LeaveTypeDetailId                                          AND IsEnabled = 1 )                       BEGIN                                             INSERT  INTO dbo.Payroll_EmployeeLeaveSchemeDetails ( EmployeeId, LeaveSchemeId, LeaveTypeId, LeaveTypeDetailId, IsEnabled, DateCaptured, CapturerId )                                  SELECT  @EmployeeId, @LeaveSchemeId, @LeaveTypeId, @LeaveTypeDetailId, 1, GETDATE(), @UserId                              DECLARE @LastId INT        SELECT TOP 1 @LastId = Id FROM Payroll_EmployeeLeaveSchemeHistoryLog With(NOLOCK) ORDER BY Id DESC          SET @LastId = ISNULL(@LastId,0) + 1                                   INSERT  INTO dbo.Payroll_EmployeeLeaveSchemeHistoryLog (Id, EmployeeId, LeaveSchemeId, LeaveTypeId, LeaveTypeDetailId, TransactionDate, IsEnabled, DateCaptured )                                  SELECT  @LastId, @EmployeeId, @LeaveSchemeId, @LeaveTypeId, @LeaveTypeDetailId, @EmpJoiningDate, 1, GETDATE()                      --Added by Richa Mills        --If accrualInterval = onceoff, the accrual days should be added immediately when Leave sheme is assigned to Employee        DECLARE @AccrualInterval int        DECLARE @AccrualDays decimal(18,2)        SELECT  @AccrualInterval = AccrualInverval, @AccrualDays = AccrualDays           FROM dbo.Const_LeaveTypeDetails           WHERE   LeaveTypeDetailsId = @LeaveTypeDetailId                              IF (@AccrualDays > 0 AND @AccrualInterval =1)                              BEGIN                                      INSERT  INTO Payroll_EmployeeLeaveSchemeTransaction ( EmployeeId, LeaveSchemeId, LeaveTypeId, LeaveTypeDetailId, AccrualLeave, TranDate, IsEnabled )                                          SELECT  @EmployeeId, @LeaveSchemeId, @LeaveTypeId, @LeaveTypeDetailId, @AccrualDays, @EmpJoiningDate, 1                                  END                                    END                           UPDATE  @Tbl                  SET     Flag = 1                  WHERE   Id = @Id                  END                 END     

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveAccrualCalculation
-- Schema: dbo
-- ============================================
-- =============================================  -- Richa M 2021/01/21   -- Payroll_EmployeeLeaveAccrualCalculation 454, '2021/06/30'  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveAccrualCalculation]   @EmployeeID INT,  @AccrualRunDate DATE  AS    BEGIN      DECLARE @UseLeave bit = (SELECT EnableLeave from Payroll_Municipality)      IF @UseLeave = 1   BEGIN      declare @OBdate datetime = (select Keyvalue from AAAA_ConfigSettings where KeyName = 'LeaveOBDate')      --Get Employee Variables    DECLARE @EmployeeCycleID INT, @EmployeeStartDate DATETIME, @EmployeeEndDate DATETIME, @LeaveSchemeId INT    SELECT     @EmployeeCycleID = CycleId       ,@EmployeeStartDate = JoiningDate       ,@EmployeeEndDate = EndDate       ,@LeaveSchemeId = LeaveSchemeID    FROM Payroll_Employee    WHERE Employee_ID = @EmployeeId      IF @LeaveSchemeId is not null --AND @AccrualRunDate < @EmployeeEndDate    BEGIN      --LeaveType Variables    DECLARE @LeaveTypeID INT        ,@LTStartDate DATETIME        ,@LTEndDate DATETIME        ,@LTCycleStartDate DATETIME        ,@LTCyclePeriodIdStart INT        ,@LTCycleEnd INT        ,@LTAbsenceTypeId INT      --Leave Type Detail Variables    DECLARE @LeaveTypeDetailId INT        ,@LTDAccrualDays DECIMAL(18,2)        ,@LTDAccrualInterval INT        ,@LTDNoOfDays INT        ,@StartDate DATE        ,@EndDate DATE        ,@ExtensionDays INT        ,@BalanceForAdditionalDays DECIMAL(18,2)        ,@AdditionalDays DECIMAL(18,2)        ,@MaxDays DECIMAL(18,2)        ,@PeriodIndicator int        ,@PeriodStart int        ,@PeriodEnd int      DECLARE @EmployeeLeaveTypes TABLE (       ID INT IDENTITY (1, 1) NOT NULL     ,AbsenceTypeId INT NOT NULL     ,LeaveTypeID INT NOT NULL     ,StartDateLT DATETIME NOT NULL     ,EndDateLT DATETIME NOT NULL     ,CycleStartDate DATETIME NULL     ,CyclePeriodIdStart INT NOT NULL     ,CycleEnd INT NULL     ,LeaveType INT NULL     ,[ExtentionDays] float null     ,[LeaveTypeDetailsId] int null     ,[AccrualDays] float null     ,[AccrualInverval] float null     ,[NoOfDays] float null     ,[StartDate] datetime null     ,[EndDate] datetime null     ,BalanceForAdditionalDays decimal(18,2)     ,AdditionalDays decimal(18,2)     ,MaxAccumulation decimal(18,2)     ,PeriodIndicator int     ,PeriodStart int     ,PeriodEnd int    )     --1=Female   2-Male    DECLARE @GenderId int =  (select GenderID from payroll_employee where Employee_ID = @EmployeeID)        INSERT INTO @EmployeeLeaveTypes        select          AbsenceType_ID       ,LT.LeaveType_ID      ,LT.StartDate      ,LT.EndDate      ,LTD.CycleStartDate      ,CyclePeriodIDStart      ,CycleEnd      ,LT.LeaveType_ID      ,ExtentionDays      ,LeaveTypeDetailsId      ,AccrualDays      ,AccrualInverval      ,ISNULL(NoOfDays,0)      ,LTD.StartDate      ,LTD.EndDate      ,LTD.LeaveBalanceForAdditionalLeave      ,LTD.AdditionalLeave      ,LTD.MaxAccumulation      ,LTD.PeriodIndicator      ,LTD.PeriodStart      ,LTD.PeriodEnd      from (select * from [Const_LeaveScheme] where LeaveScheme_ID = @LeaveSchemeId)ls      left join [Const_LeaveSchemeTypeDetails] lstd on lstd.LeaveSchemeId = ls.LeaveScheme_ID      left join [Const_AbsenceType] abt on abt.AbsenceType_ID = lstd.LeaveTypeId      left join [Payroll_AbsencePriority] abtp on abtp.AbsenceTypeID = abt.AbsenceType_ID      left join [Const_LeaveTypeDetails] ltd on ltd.LeaveTypeId = abtp.LeaveTypeID      left join [Const_LeaveType] lt on lt.LeaveType_ID = ltd.LeaveTypeId      where lstd.Enabled = 1 and AbsencePriority_ID is not null and ltd.Enabled = 1 and lt.LeaveClassificationID not in (CASE WHEN @GenderId = 1 THEN 9 ELSE 3 END)         DECLARE @LeaveTypeCount INT    DECLARE @Count INT = 1    DECLARE @LastAccrualDate DATETIME      SELECT     @LeaveTypeCount = COUNT(LeaveTypeId)    FROM @EmployeeLeaveTypes        --Loop through all leavetypes    WHILE (@Count <= @LeaveTypeCount)    BEGIN       --Set the Leave Type Variables     SELECT          @LeaveTypeID = [LeaveTypeID]        ,@LTStartDate = StartDateLT        ,@LTEndDate = EndDateLT        ,@LTCycleStartDate = CycleStartDate        ,@LTCyclePeriodIdStart = CyclePeriodIdStart        ,@LTCycleEnd = CycleEnd        ,@LTAbsenceTypeId = clt.AbsenceTypeId        ,@LeaveTypeDetailId = LeaveTypeDetailsId        ,@LTDAccrualDays = AccrualDays        ,@LTDAccrualInterval = AccrualInverval        ,@LTDNoOfDays = NoOfDays        ,@StartDate = StartDate        ,@EndDate = EndDate        ,@ExtensionDays = ISNULL(ExtentionDays,0)        ,@BalanceForAdditionalDays = ISNULL(BalanceForAdditionalDays,0)        ,@AdditionalDays = ISNULL(AdditionalDays,0)        ,@PeriodIndicator = PeriodIndicator        ,@PeriodStart = Case When @PeriodIndicator = 1 then PeriodStart Else PeriodStart * 12 end        ,@PeriodEnd = Case When @PeriodIndicator = 1 then PeriodEnd Else PeriodEnd * 12 end        ,@MaxDays = IsNULL(MaxAccumulation,0)       FROM @EmployeeLeaveTypes clt       WHERE ID = @Count       --Get Last AccrualDate     DECLARE @AccrualCount INT = (SELECT isnull(COUNT(ID),0) FROM Payroll_LeaveAccrualDates WHERE LeaveTypeId = @LeaveTypeId AND EmployeeId = @EmployeeId)       --If there is a date for this employee in the AccrualDates table, run the accruals from this date, else - get the last opening balance date     IF(@AccrualCount > 0)     BEGIN      SELECT @LastAccrualDate =  (Select LastAccrualCalcDate FROM Payroll_LeaveAccrualDates WHERE LeaveTypeId = @LeaveTypeId AND EmployeeId = @EmployeeId)     END     ELSE     BEGIN      SELECT @LastAccrualDate = @OBdate      if(@EmployeeStartDate > @LastAccrualDate)        select @LastAccrualDate = Dateadd(DAY,-1,@EmployeeStartDate)     END     DECLARE @LoopCount INT = 1       --We need to check for accruals since the day after the last accrualDate up until today     DECLARE @Days int = DATEDIFF(DAY, @LastAccrualDate, @AccrualRunDate)       SELECT @LastAccrualDate = DATEADD(DAY,1,@LastAccrualDate)     DECLARE @EmployeeNumberOfPeriods int     WHILE @LoopCount <= @Days     BEGIN        SELECT @EmployeeNumberOfPeriods  = (SELECT DATEDIFF(MONTH, @EmployeeStartDate, @LastAccrualDate))         IF((@EmployeeNumberOfPeriods >= @PeriodStart AND @EmployeeNumberOfPeriods <= @PeriodEnd) AND @EmployeeEndDate >= @LastAccrualDate AND @EmployeeStartDate <= @LastAccrualDate)      BEGIN          EXEC Payroll_AddLeaveAccruals @EmployeeID,@EmployeeStartDate,@LTCyclePeriodIdStart,@LastAccrualDate,@LeaveTypeId,@LeaveTypeDetailId,@LTDAccrualDays,@LTDAccrualInterval,@LeaveSchemeId,@LTCyclePeriodIdStart,@LTCycleEnd,@LTCycleStartDate,@LTAbsenceTypeId,@ExtensionDays,@BalanceForAdditionalDays,@AdditionalDays, @MaxDays,@PeriodStart              END      ELSE      BEGIN       Update payroll_leaveaccrualdates set LastAccrualCalcDate = @LastAccrualDate where EmployeeId = @EmployeeId and LeaveTypeId = @LeaveTypeId      END      SET @LastAccrualDate = DATEADD(DAY,1,@LastAccrualDate)      SET @LoopCount = @LoopCount + 1     END       IF NOT EXISTS (SELECT EmployeeLeaveBalanceID FROM Payroll_EmployeeLeaveBalance where EmployeeID = @EmployeeID and LeaveTypeID = @LeaveTypeID)     BEGIN       INSERT INTO Payroll_EmployeeLeaveBalance ([EmployeeID], [LeaveSchemeID], [LeaveTypeID], [Enabled], [CycleTypeID], [CycleStartDate], [CycleEndDate], [CycleMonths], [Balance],       [Accrued], [Taken], [Forfeit], [Encashed], [Accumulated], [Adjusted], [CalcDate], [NextAccrualDate], [Notes], [AbsenceTypeId], [LeaveDetailId], [ForfeitDate], [TotalLeaveDays])       SELECT        @EmployeeID           ,@LeaveSchemeId          ,@LeaveTypeId          ,1          ,@LTCyclePeriodIdStart          ,@LastAccrualDate--@LTCycleStartDate          ,@LTCycleEnd          ,@LTCyclePeriodIdStart          ,ISNULL(SUM(LeaveTrx.OpeningBalance),0)          ,ISNULL(SUM(LeaveTrx.Accrued),0)          ,ISNULL(SUM(LeaveTrx.Taken),0)          ,ISNULL(SUM(LeaveTrx.Forfeit),0)          ,ISNULL(SUM(LeaveTrx.Encashed),0)          ,ISNULL(SUM(LeaveTrx.Accumulated),0)          ,ISNULL(SUM(LeaveTrx.Adjusted),0)          ,@AccrualRunDate AS CalcDate          ,@AccrualRunDate --NextAccrualDate          ,''          ,@LTAbsenceTypeId          ,@LeaveTypeDetailId          ,NULL--ForfeitDate          ,(ISNULL(SUM(LeaveTrx.OpeningBalance),0) + ISNULL(SUM(LeaveTrx.Accrued),0) + ISNULL(SUM(LeaveTrx.Accumulated),0) + ISNULL(SUM(LeaveTrx.Adjusted),0))           +         (ISNULL(SUM(LeaveTrx.Taken),0) + ISNULL(SUM(LeaveTrx.Forfeit),0) + ISNULL(SUM(LeaveTrx.Encashed),0))         FROM (SELECT         pelt.StartDate           ,pelt.EndDate           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 1 THEN pelt.Value          ELSE 0         END AS 'OpeningBalance'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 2 THEN pelt.Value          ELSE 0         END AS 'Accrued'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 3 THEN pelt.Value          ELSE 0         END AS 'Taken'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 4 THEN pelt.Value          ELSE 0         END AS 'Forfeit'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 5 THEN pelt.Value          ELSE 0         END AS 'Encashed'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 6 THEN pelt.Value          ELSE 0         END AS 'Accumulated'           ,CASE          WHEN pelt.LeaveAdjustmentTypeID = 7 THEN pelt.Value          ELSE 0         END AS 'Adjusted'           ,pelt.Value AS Balance        FROM Payroll_EmployeeLeaveTransactions pelt        WHERE pelt.EmployeeID = @EmployeeId        AND pelt.LeaveTypeID = @LeaveTypeId        AND pelt.LeaveStatusID = 3        AND pelt.Enabled = 1        ) LeaveTrx      END     ELSE     BEGIN       Exec Payroll_UpdateEmployeeLeaveBalances @EmployeeId,@LeaveTypeId     END    SET @Count = @Count + 1    END    END  END  END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveAccrualCursor
-- Schema: dbo
-- ============================================
-- =================================================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/08/14>  -- Description: <Calculate Leave Accruals cursor>  -- Call SP    : Payroll_EmployeeLeaveAccrualPerEmployee (Payroll_EmployeeLeaveAccrualCalculation)  -- Modiri 20190725 #81947 No leave accrued on employee leave details  --https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/22767 Modiri 2020/02/12    --Exec Payroll_EmployeeLeaveAccrualCursor  -- =================================================================================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveAccrualCursor]   AS  BEGIN     DECLARE @EmployeeId int   DECLARE @date datetime = getdate()      DECLARE db_cursor CURSOR FOR    SELECT Employee_ID   FROM Payroll_Employee where EndDate > @date       OPEN db_cursor     FETCH NEXT FROM db_cursor INTO @EmployeeId       WHILE @@FETCH_STATUS = 0     BEGIN       EXEC Payroll_EmployeeLeaveAccrualCalculation @EmployeeID,@date     FETCH NEXT FROM db_cursor INTO @EmployeeId  END      CLOSE db_cursor     DEALLOCATE db_cursor       END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveBalanceForAbsenceTypeId
-- Schema: dbo
-- ============================================
  -- ===================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/08>  -- Description: <Get Employee Leave Balances by AbsenceTypeId>  -- Call SP    : Payroll_EmployeeLeaveBalanceForAbsenceTypeId 1, 43  --====================================================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveBalanceForAbsenceTypeId]  @EmployeeId INT,  @AbsenceTypeId INT  AS  BEGIN     DECLARE @EmployeeStartDate DATETIME,    @LeaveSchemeid INT    SELECT @EmployeeStartDate =JoiningDate, @LeaveSchemeid=LeaveSchemeID FROM Payroll_Employee WHERE Employee_ID = @EmployeeId   select      AB.LeaveTypeId, LeaveTypeDesc, LB.Accrued as AccrualDays, (ISNULL(Balance,0) + ISNULL(Accrued,0) + ISNULL(Taken,0) + ISNULL(Forfeit,0) + ISNULL(Encashed,0) + ISNULL(Adjusted,0)) as Balance, NegativeBalanceAllowed, NegativeLeave, DeductionOrder    from Payroll_EmployeeLeaveBalance  LB    join Payroll_AbsencePriority AB on AB.AbsenceTypeID= LB.AbsenceTypeId AND AB.LeaveTypeID = LB.LeaveTypeID    join Const_LeaveType CLT on CLT.LeaveType_ID=AB.LeaveTypeID     where EmployeeID=@EmployeeId and LB.AbsenceTypeId=@AbsenceTypeId AND LeaveSchemeID=@LeaveSchemeid    order by AB.DeductionOrder  END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveCalculation
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  MEHUL PANCHAL    -- Create date: 13/02/2014    -- Description: <Description,,>    -- =============================================    --SELECT * FROM Payroll_EmployeeLeaves WHERE EmployeeID=35  --Payroll_EmployeeLeaveCalculation 36,21,'2013/2014'  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveCalculation]      (        @EmployeeID INT ,        @LeaveSchemeID INT ,        @FinancialYear NVARCHAR(10)      )  AS      BEGIN             DECLARE @ErrorCode INT            DECLARE @LeaveTypeID INT             DECLARE @IsFixedOrCalculated BIT            DECLARE @Maximumdays DECIMAL(18,2)          DECLARE @IsFixedDate BIT            DECLARE @CycleStartDate DATETIME            DECLARE @CycleEndDate DATETIME            DECLARE @MunicipalityId INT             DECLARE @TotalCount INT            DECLARE @Start INT            DECLARE @EmploymentEndDate DATETIME          DECLARE @Type NVARCHAR(10)          DECLARE @AnnualAccrualFrequency INT          DECLARE @LeaveBalance DECIMAL(18, 2) = 0          DECLARE @JoiningDate DATE          DECLARE @CycleID INT    DECLARE @CurrentPeriodDate DATETIME    DECLARE @PeriodId INT              DECLARE @LeaveSchemeDetail TABLE              (                LeaveTypeID INT NULL ,                IsFixedOrCalculated BIT NULL ,                Maximumdays DECIMAL(18,2) NULL ,                IsFixedDate BIT NULL ,                CycleStartDate DATETIME NULL ,                CycleEndDate DATETIME NULL ,                MunicipalityId INT ,                Type NVARCHAR(10) ,                AnnualAccrualFrequency INT ,                RowNo INT              )      --DECLARE @Payroll_EmployeeLeaves TABLE    --(    -- EmployeeID INT, LeaveSchemeID  INT, LeaveTypeID  INT, LeaveBalance DECIMAL(18,2), UsedLeave DECIMAL(18,2),    -- OverDueLeave DECIMAL(18,2), EntitledLeave DECIMAL(18,2), MunicipalityID INT, FinancialYear NVARCHAR(15),    -- Enabled BIT, DateCaptured DATETIME, CapturerID INT    --)              SELECT  @JoiningDate = JoiningDate, @CycleID = CycleID FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID AND Enabled = 1 AND IsDummy = 0          Select TOP 1 @CurrentPeriodDate = PeriodStartDate, @PeriodId = Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE CycleID = 1 AND Processed = 0 AND TaxYear =  @FinancialYear             SET @EmploymentEndDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @JoiningDate))             BEGIN TRAN       INSERT  INTO @LeaveSchemeDetail      SELECT  LeaveTypeID , IsFixedOrCalculated , Maximumdays , IsFixedDate , CycleStartDate ,        CycleEndDate , MunicipalityId , Type , AnnualAccrualFrequency , ROW_NUMBER() OVER ( ORDER BY LeaveSchemeDetail_ID ASC ) AS RowNo      FROM    Const_LeaveSchemeDetail WHERE LeaveSchemeID = @LeaveSchemeID AND Enabled = 1       SELECT  @TotalCount = COUNT(1) FROM @LeaveSchemeDetail SET @Start = 1       WHILE ( @Start <= @TotalCount )     BEGIN        SELECT  @LeaveTypeID = LeaveTypeID , @IsFixedOrCalculated = IsFixedOrCalculated , @Maximumdays = Maximumdays , @IsFixedDate = IsFixedDate ,        @CycleStartDate = CycleStartDate , @CycleEndDate = CycleEndDate , @MunicipalityId = MunicipalityId , @Type = [Type] ,        @AnnualAccrualFrequency = AnnualAccrualFrequency      FROM    @LeaveSchemeDetail WHERE   RowNo = @Start                           IF (@IsFixedOrCalculated = 1 AND @Type = '2') -- Fixed Number Of Days Per Cycle AND Full Entitlement (Substitute)      BEGIN       IF ( @IsFixedDate = 1 )-- Fixed Date (Cycle Start & End Date)       BEGIN                PRINT @CycleStartDate        PRINT @CycleEndDate        PRINT @Maximumdays        PRINT @JoiningDate        PRINT @AnnualAccrualFrequency                SELECT @LeaveBalance = SUM(WorkAccuralDays)        FROM dbo.GetCalculatedWorkDay(@CycleStartDate, @CycleEndDate, @Maximumdays, @JoiningDate, @AnnualAccrualFrequency)        WHERE CAST(@CurrentPeriodDate AS DATE) BETWEEN CAST(StartDate AS DATE) AND CAST(EndDate AS DATE)       END       ELSE IF ( @IsFixedDate = 0 )-- Employment Date (Cycle Start & End Date)       BEGIN         --Employment and Substitute (Full Entitlement) then no need to calculate any things        SET @LeaveBalance = @Maximumdays                --Old Code by Sandeep        --SELECT @LeaveBalance = SUM(WorkAccuralDays)        --FROM dbo.GetCalculatedWorkDay(@JoiningDate, @EmploymentEndDate, @Maximumdays, @JoiningDate, @AnnualAccrualFrequency)       END      END                     --INSERT  INTO @Payroll_EmployeeLeaves      -- ( EmployeeID , LeaveSchemeID , LeaveTypeID , LeaveBalance , UsedLeave , OverDueLeave , EntitledLeave , MunicipalityID , FinancialYear , Enabled , DateCaptured , CapturerID )      --VALUES        -- (@EmployeeID, @LeaveSchemeID, @LeaveTypeID, @LeaveBalance, 0, 0, 0, @MunicipalityId, @FinancialYear, 1, GETDATE(), 1)                              --Select * FROM @Payroll_EmployeeLeaves                     IF NOT EXISTS (SELECT EmployeeID FROM Payroll_EmployeeLeaves               WHERE EmployeeID = @EmployeeID AND FinancialYear = @FinancialYear AND Enabled = 1                  AND LeaveSchemeID = @LeaveSchemeID AND LeaveTypeID = @LeaveTypeID           )       BEGIN        INSERT  INTO dbo.Payroll_EmployeeLeaves         ( EmployeeID , LeaveSchemeID , LeaveTypeID , LeaveBalance , UsedLeave , OverDueLeave , EntitledLeave , MunicipalityID , FinancialYear , Enabled , DateCaptured , CapturerID )        VALUES           (@EmployeeID, @LeaveSchemeID, @LeaveTypeID, @LeaveBalance, 0, 0, 0, @MunicipalityId, @FinancialYear, 1, GETDATE(), 1)                INSERT INTO dbo.Payroll_EmployeeLeaveLogHistory ( LeaveTypeId, EmployeeId, LeaveSchemeId, PeriodId, DateCaptured )        VALUES  ( @LeaveTypeID, -- LeaveTypeId - int                  @EmployeeID, -- EmployeeId - int                  @LeaveSchemeID, -- LeaveSchemeId - int                  @PeriodId, -- PeriodId - int                  @JoiningDate  -- DateCaptured - datetime                  )          INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AcrualLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, ISNULL(@LeaveBalance, 0), @JoiningDate               END          SET @Start = @Start + 1       SET @LeaveBalance = 0     END                SELECT  @ErrorCode = @@ERROR          IF ( @ErrorCode <> 0 )              GOTO PROBLEM              COMMIT TRAN              PROBLEM:          IF ( @ErrorCode <> 0 )              BEGIN                    PRINT 'Unexpected error occurred!'                    ROLLBACK TRAN                END         END    

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveCalculation_Periodic
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Ghanshyam Dhanani>  -- Create date: <Create Date,,26 Feb 2014>  -- Description: <Description,,Employee Leave Calculation>  -- Call SP    : Payroll_EmployeeLeaveCalculation_Periodic 1, '2013/2014'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveCalculation_Periodic]   @EmployeeID INT--,   --@LeaveSchemeID INT ,   --@FinYear NVARCHAR(10)  AS  BEGIN   ------ Get all Employee List -----   DECLARE @EmpTbl TABLE (Id INT IDENTITY(1, 1),          EmpLeaveId INT, LeaveSchemeID INT,          LeaveTypeID INT,          IsFixedOrCalculated BIT,          Maximumdays DECIMAL(18,2),         NoOfDaysEarned INT,         ForNoOfDaysWorked INT,         CalenderOrWorkDays VARCHAR(50),         IsFixedDate BIT,          CycleStartDate DATETIME,          CycleEndDate DATETIME,         [Type] VARCHAR(10),         AnnualAccrualFrequency INT,         MaxAccumulation INT,          RepeatTimes INT,         CycleForfeitTime INT,         FollowTypeId INT,         IsForfeit BIT,         ForfeitMonthsExtention INT,         CarryingOverNegativeBalances INT)      INSERT INTO @EmpTbl   SELECT EMPL.EmployeeLeave_ID, EMPL.LeaveSchemeID, EMPL.LeaveTypeID, IsFixedOrCalculated, Maximumdays, NoOfDaysEarned, ForNoOfDaysWorked, CalenderOrWorkDays,   IsFixedDate, CycleStartDate, CycleEndDate, [Type], AnnualAccrualFrequency, MaxAccumulation, RepeatTimes, CycleForfeitTime, FollowTypeId, IsForfeit, ISNULL(ForfeitMonthsExtention, 0), CarryingOverNegativeBalances   FROM dbo.Payroll_EmployeeLeaves AS EMPL   INNER JOIN dbo.Const_LeaveSchemeDetail AS LSD ON EMPL.LeaveSchemeID = LSD.LeaveSchemeID AND EMPL.LeaveTypeID = LSD.LeaveTypeID   WHERE EMPL.EmployeeID = @EmployeeID --AND EMPL.LeaveSchemeID = @LeaveSchemeID   AND EMPL.Enabled = 1      ----- Variable Diclaration -----   DECLARE @Start INT = 1, @EmpCount INT   DECLARE @EmpLeaveId INT, @LeaveSchemeID INT, @LeaveTypeID INT      DECLARE @IsFixedOrCalculated BIT, @Maximumdays DECIMAL(18,2), @IsFixedDate BIT, @CycleStartDate DATETIME, @CycleEndDate DATETIME, @Type NVARCHAR(10)      DECLARE @AnnualAccrualFrequency INT, @MaxAccumulation INT, @RepeatTimes INT, @LeaveBalance INT, @LastDate DATETIME, @RepeatCount INT, @LeaveAcrual INT, @CycleForfeitTime INT      DECLARE @NoOfDaysEarned INT, @ForNoOfDaysWorked INT, @CalenderOrWorkDays VARCHAR(50), @TakenLeave INT, @WorkingDays INT, @ForfeitMonthsExtention INT, @CarryingOverNegativeBalances INT      DECLARE @CycleId INT, @PeriodId INT, @JoinDate DATETIME, @PeriodCycleStartDate DATETIME, @PeriodCycleEndDate DATETIME, @FollowTypeId INT, @IsForfeit BIT         ----- Leave Calculation START -----   SELECT @EmpCount = COUNT(Id) FROM @EmpTbl   WHILE (@Start <= @EmpCount) BEGIN    SELECT @EmpLeaveId = EmpLeaveId, @LeaveSchemeID = LeaveSchemeID, @LeaveTypeID = LeaveTypeID,     @IsFixedOrCalculated = IsFixedOrCalculated, @Maximumdays = Maximumdays, @IsFixedDate = IsFixedDate,     @CycleStartDate = CycleStartDate, @CycleEndDate = CycleEndDate, @Type = [Type], @AnnualAccrualFrequency = AnnualAccrualFrequency,    @MaxAccumulation = MaxAccumulation, @RepeatTimes = RepeatTimes, @NoOfDaysEarned = NoOfDaysEarned, @ForNoOfDaysWorked = ForNoOfDaysWorked,    @CalenderOrWorkDays = CalenderOrWorkDays, @CycleForfeitTime = CycleForfeitTime, @ForfeitMonthsExtention = ForfeitMonthsExtention, @FollowTypeId = FollowTypeId,    @IsForfeit = IsForfeit, @CarryingOverNegativeBalances = CarryingOverNegativeBalances    FROM @EmpTbl WHERE Id = @Start        IF @CycleStartDate > @PeriodCycleStartDate BEGIN      GOTO NEXT    END      ----- Get Repeat Count from History Log Table    SELECT @RepeatCount = COUNT(*) FROM dbo.Payroll_EmployeeLeaveLogHistory WHERE LeaveSchemeId = @LeaveSchemeID AND EmployeeId = @EmployeeID AND LeaveTypeId = @LeaveTypeID    SELECT TOP 1 @LastDate = DateCaptured FROM dbo.Payroll_EmployeeLeaveLogHistory WHERE LeaveSchemeId = @LeaveSchemeID AND EmployeeId = @EmployeeID AND LeaveTypeId = @LeaveTypeID    ORDER BY DateCaptured DESC        SELECT @CycleId = CycleID, @JoinDate = JoiningDate FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID    SELECT TOP 1 @PeriodId = Period_ID, @PeriodCycleStartDate = PeriodStartDate, @PeriodCycleEndDate = PeriodEndDate FROM dbo.Payroll_CyclePeriodDetails WHERE Processed = 0 AND ProcessedDate IS NULL AND CycleID = 1        ----- Fix No of Days    IF @IsFixedOrCalculated = 1 BEGIN     IF @RepeatCount = 0 BEGIN      SELECT @Maximumdays = SUM(WorkAccuralDays) FROM dbo.GetCalculatedWorkDay(@PeriodCycleStartDate, @PeriodCycleEndDate, @Maximumdays, @JoinDate, @AnnualAccrualFrequency)      -- Log History      INSERT INTO dbo.Payroll_EmployeeLeaveLogHistory (LeaveTypeId, EmployeeId, LeaveSchemeId, PeriodId, DateCaptured )      SELECT  @LeaveTypeID, @EmployeeID, @LeaveSchemeID, @PeriodId, @PeriodCycleEndDate      -- Transacion Entry      INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AcrualLeave, TransactionDate)      SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate     END     ELSE BEGIN      IF (DATEDIFF(MONTH, @LastDate, @CycleEndDate)) = (@AnnualAccrualFrequency) AND @RepeatTimes > @RepeatCount BEGIN       -- Update Leave       UPDATE dbo.Payroll_EmployeeLeaves SET LeaveAcrual = @Maximumdays WHERE EmployeeLeave_ID = @EmpLeaveId       -- Log History       INSERT INTO dbo.Payroll_EmployeeLeaveLogHistory (LeaveTypeId, EmployeeId, LeaveSchemeId, PeriodId, DateCaptured )       SELECT  @LeaveTypeID, @EmployeeID, @LeaveSchemeID, @PeriodId, @PeriodCycleEndDate       -- Transacion Entry       INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AcrualLeave, TransactionDate)       SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate      END     END    END    ELSE BEGIN     IF @RepeatCount = 0 BEGIN      SET @LastDate = @JoinDate     END     IF @CalenderOrWorkDays = 'WorkDays' BEGIN      SET @WorkingDays = dbo.GetEmpWorkingDaysUsingFromToDate(@EmployeeID, @LastDate, @PeriodCycleEndDate)     END     ELSE IF @CalenderOrWorkDays = 'Calender' BEGIN      SET @WorkingDays = DATEDIFF(DAY, @LastDate, @PeriodCycleEndDate)      SELECT @WorkingDays = @WorkingDays - COUNT(*) FROM Const_Holiday WHERE HolidayDate BETWEEN @LastDate AND @PeriodCycleEndDate     END     IF @RepeatTimes > @RepeatCount BEGIN      SET @Maximumdays = @WorkingDays * @NoOfDaysEarned / @ForNoOfDaysWorked      -- Update Leave      UPDATE dbo.Payroll_EmployeeLeaves SET LeaveAcrual = @Maximumdays WHERE EmployeeLeave_ID = @EmpLeaveId      -- Log History      INSERT INTO dbo.Payroll_EmployeeLeaveLogHistory (LeaveTypeId, EmployeeId, LeaveSchemeId, PeriodId, DateCaptured )      SELECT  @LeaveTypeID, @EmployeeID, @LeaveSchemeID, @PeriodId, @PeriodCycleEndDate      -- Transacion Entry      INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AcrualLeave, TransactionDate)      SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate     END    END      IF @RepeatCount > 0 AND @RepeatTimes > @RepeatCount AND (DATEDIFF(MONTH, @CycleStartDate, @PeriodCycleEndDate) % @CycleForfeitTime ) = 0 BEGIN     SELECT @Maximumdays = ISNULL(SUM(AcrualLeave - OverDueLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave - WithoutPlayLeave), 0) FROM Payroll_EmployeeLeavesTransactions     WHERE EmployeeId = @EmployeeID AND LeaveSchemeID = @LeaveSchemeID AND LeaveTypeID = @LeaveTypeID     IF @FollowTypeId IS NOT NULL AND @FollowTypeId > 0 BEGIN      IF @ForfeitMonthsExtention = 0 BEGIN       IF @MaxAccumulation < @Maximumdays BEGIN        SET @Maximumdays = @Maximumdays - @MaxAccumulation          INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AdjustedLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @FollowTypeId, @Maximumdays, @PeriodCycleEndDate          INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AdjustedLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays * -1, @PeriodCycleEndDate       END       ELSE IF @Maximumdays < 0 AND @CarryingOverNegativeBalances = 2 BEGIN        INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, WithoutPlayLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate       END      END      ELSE BEGIN       UPDATE Payroll_EmployeeLeaves SET ForfietDate = @PeriodCycleEndDate WHERE EmployeeLeave_ID = @EmpLeaveId      END     END     ELSE IF @IsForfeit = 1 BEGIN      IF @ForfeitMonthsExtention = 0 BEGIN       IF @MaxAccumulation < @Maximumdays BEGIN        SET @Maximumdays = (@Maximumdays - @MaxAccumulation)        INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, ForfeitLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate       END       ELSE IF @Maximumdays < 0 AND @CarryingOverNegativeBalances = 2 BEGIN        INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, WithoutPlayLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @PeriodCycleEndDate       END         END      ELSE BEGIN       UPDATE Payroll_EmployeeLeaves SET ForfietDate = @PeriodCycleEndDate WHERE EmployeeLeave_ID = @EmpLeaveId      END     END    END    DECLARE @ForfietDate DATETIME    SELECT @ForfietDate = ForfietDate FROM Payroll_EmployeeLeaves WHERE EmployeeLeave_ID = @EmpLeaveId    IF @ForfietDate IS NOT NULL BEGIN     IF DATEDIFF(DAY, @ForfietDate, @PeriodCycleEndDate) <= @MaxAccumulation BEGIN      SELECT @Maximumdays = ISNULL(SUM(AcrualLeave - OverDueLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave - WithoutPlayLeave), 0) FROM Payroll_EmployeeLeavesTransactions      WHERE EmployeeId = @EmployeeID AND LeaveSchemeID = @LeaveSchemeID AND LeaveTypeID = @LeaveTypeID AND TransactionDate <= @ForfietDate      IF @MaxAccumulation < @Maximumdays BEGIN       SET @Maximumdays = (@Maximumdays - @MaxAccumulation)       IF @FollowTypeId IS NOT NULL AND @FollowTypeId > 0 BEGIN        INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AdjustedLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @FollowTypeId, @Maximumdays, @ForfietDate          INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, AdjustedLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays * -1, @ForfietDate       END       ELSE BEGIN        INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, ForfeitLeave, TransactionDate)        SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, @Maximumdays, @ForfietDate       END       UPDATE Payroll_EmployeeLeaves SET ForfietDate = NULL WHERE EmployeeLeave_ID = @EmpLeaveId      END     END    END    GOTO NEXT    NEXT:    SET @Start += 1   END     END    

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveCalculationCycleEnd
-- Schema: dbo
-- ============================================
--SELECT ForfeitMonthsExtention,,* FROM Const_LeaveSchemeDetail  --USE [Sebata_FMS]  --GO  --/****** Object:  StoredProcedure [dbo].[Payroll_EmployeeLeaveCalculationCycleEnd]    Script Date: 02/22/2014 14:09:30 ******/  --SET ANSI_NULLS ON  --GO  --SET QUOTED_IDENTIFIER ON  --GO  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveCalculationCycleEnd]  AS      BEGIN     /* Input Parameter Start*/          DECLARE @FinancialYear NVARCHAR(50)          SELECT  @FinancialYear = KeyValue          FROM    dbo.AAAA_ConfigSettings          WHERE   Keyname = 'ActiveFinYear'          --SET @FinancialYear = '2013/2014'  /* Input Parameter End*/    /*Declare Parameter For Employee While loop Start*/          DECLARE @Cycleid INT          DECLARE @PeriodId INT           DECLARE @PeriodStartDate DATETIME          DECLARE @PeriodEndDate DATETIME          DECLARE @JoiningDate DATETIME          DECLARE @LeaveSchemeId INT          DECLARE @EmpStart INT           DECLARE @EmpTotal INT           DECLARE @EmployeeId INT          DECLARE @DiffMonth INT            DECLARE @EmployeeInfo TABLE              (                EmployeeId INT ,                CycleId INT ,                JoiningDate DATETIME NULL ,                PeriodStartDate DATETIME NULL ,                PeriodEndDate DATETIME NULL ,                EmploymentEndDate DATETIME ,                PeriodId INT ,                RowNo INT              )  /*Declare Parameter For Employee While loop End*/    /*Declare Parameter For Leave Calculation While loop Start*/          DECLARE @LeaveSchemeDetailID INT              DECLARE @ErrorCode INT              DECLARE @LeaveTypeID INT               DECLARE @IsFixedOrCalculated BIT              DECLARE @Maximumdays DECIMAL(18, 2)          DECLARE @IsFixedDate BIT              DECLARE @CycleStartDate DATETIME              DECLARE @CycleEndDate DATETIME              DECLARE @MunicipalityId INT               DECLARE @TotalCount INT              DECLARE @Start INT              DECLARE @EmploymentEndDate DATETIME            DECLARE @Type NVARCHAR(10)            DECLARE @AnnualAccrualFrequency INT            DECLARE @LeaveBalance DECIMAL(18, 2)             DECLARE @MaxAccumulation DECIMAL(18, 2)          DECLARE @RepeatTimes INT            DECLARE @TotalMaxAccumulation DECIMAL(18, 2)          DECLARE @TotalRepeatTimes INT          SET @TotalRepeatTimes = 0          SET @TotalMaxAccumulation = 0          DECLARE @LeaveSchemeDetail TABLE              (                LeaveSchemeDetailID INT ,                LeaveTypeID INT NULL ,                IsFixedOrCalculated BIT NULL ,                Maximumdays DECIMAL(18, 2) NULL ,                IsFixedDate BIT NULL ,                CycleStartDate DATETIME NULL ,                CycleEndDate DATETIME NULL ,                MunicipalityId INT ,                Type NVARCHAR(10) ,                AnnualAccrualFrequency INT ,                LeaveSchemeId INT ,                MaxAccumulation DECIMAL(18, 2) DEFAULT NULL ,                RepeatTimes INT NULL ,                RowNo INT              )       /*Declare Variable For Leave Calculation End*/              INSERT  INTO @EmployeeInfo                  SELECT  Employee_Id ,                          PE.CycleID ,                          JoiningDate ,                          ( SELECT TOP 1                                      PeriodStartDate                            FROM      dbo.Payroll_CyclePeriodDetails                            WHERE     CycleID = PE.CycleID                                      AND Processed = 0                                      AND FinancialYear = @FinancialYear                          ) AS PeriodStartDate ,                          ( SELECT TOP 1                                      PeriodEndDate                            FROM      dbo.Payroll_CyclePeriodDetails                            WHERE     CycleID = PE.CycleID                                      AND Processed = 0                                      AND FinancialYear = @FinancialYear                          ) AS PeriodEndDate ,                          DATEADD(DAY, -1, DATEADD(YEAR, 1, @JoiningDate)) ,                          ( SELECT TOP 1                                      Period_ID                            FROM      dbo.Payroll_CyclePeriodDetails                            WHERE     CycleID = PE.CycleID                                      AND Processed = 0                                      AND FinancialYear = @FinancialYear                          ) AS PeriodId ,                          ROW_NUMBER() OVER ( ORDER BY Employee_Id ASC )                  FROM    Payroll_Employee AS PE                  WHERE   PE.Enabled = 1                    SET @EmpStart = 1          SELECT  @EmpTotal = COUNT(1)          FROM    @EmployeeInfo               WHILE ( @EmpStart <= @EmpTotal )              BEGIN                   SELECT  @EmployeeId = EmployeeId ,                          @CycleId = CycleId ,                          @JoiningDate = JoiningDate ,                          @PeriodStartDate = PeriodStartDate ,                          @PeriodEndDate = PeriodEndDate ,                          @EmploymentEndDate = EmploymentEndDate ,                          @PeriodId = PeriodId                  FROM    @EmployeeInfo                  WHERE   RowNo = @EmpStart                  DELETE  FROM @LeaveSchemeDetail                  INSERT  INTO @LeaveSchemeDetail                          SELECT  CLS.LeaveSchemeDetail_ID ,                                  CLS.LeaveTypeID ,                                  CLS.IsFixedOrCalculated ,                                  CLS.Maximumdays ,                                  CLS.IsFixedDate ,                                  CLS.CycleStartDate ,                                  CLS.CycleEndDate ,                                  CLS.MunicipalityId ,                                  CLS.Type ,                                  CLS.AnnualAccrualFrequency ,                                  PE.LeaveSchemeID ,                                  CLS.MaxAccumulation ,                                  CLS.RepeatTimes ,                                  ROW_NUMBER() OVER ( ORDER BY LeaveSchemeDetail_ID ASC )                          FROM    Const_LeaveSchemeDetail AS CLS                                  INNER JOIN Payroll_EmployeeLeaves AS PE ON PE.LeaveTypeID = CLS.LeaveTypeID                                                                AND PE.LeaveSchemeID = CLS.LeaveSchemeID                                                                AND PE.MunicipalityID = CLS.MunicipalityId                          WHERE   PE.EmployeeID = @EmployeeId                     SELECT  @TotalCount = COUNT(*)                  FROM    @LeaveSchemeDetail                  SET @Start = 1                          WHILE ( @Start <= @TotalCount )                      BEGIN                          SELECT  @LeaveSchemeDetailID = LeaveSchemeDetailID ,                                  @LeaveTypeID = LeaveTypeID ,                                  @IsFixedOrCalculated = IsFixedOrCalculated ,                                  @Maximumdays = Maximumdays ,                                  @IsFixedDate = IsFixedDate ,                                  @CycleStartDate = CycleStartDate ,                                  @CycleEndDate = CycleEndDate ,                                  @MunicipalityId = MunicipalityId ,                                  @Type = Type ,                                  @AnnualAccrualFrequency = AnnualAccrualFrequency ,                                  @LeaveSchemeID = LeaveSchemeID ,                                  @MaxAccumulation = MaxAccumulation ,                                  @RepeatTimes = RepeatTimes                          FROM    @LeaveSchemeDetail                          WHERE   RowNo = @Start                           SET @LeaveBalance = 0                          SET @DiffMonth = 0                          IF NOT EXISTS ( SELECT  *                                          FROM    dbo.Payroll_EmployeeLeaveLogHistory                                          WHERE   LeaveTypeId = @LeaveTypeID                                                  AND EmployeeId = @EmployeeId                                                  AND LeaveSchemeId = @LeaveSchemeId                                                  AND PeriodId = @PeriodId )                              BEGIN                                   SELECT  @TotalRepeatTimes = COUNT(*)                                  FROM    Payroll_EmployeeLeaveLogHistory                                  WHERE   LeaveTypeId = @LeaveTypeID                                          AND EmployeeId = @EmployeeId                                          AND LeaveSchemeId = @LeaveSchemeId                                   IF ( @RepeatTimes >= @TotalRepeatTimes                                       AND @RepeatTimes > 0                                     )                                      BEGIN                                           IF EXISTS ( SELECT  *                                                      FROM    dbo.Payroll_EmployeeLeaveLogHistory                                                      WHERE   LeaveTypeId = @LeaveTypeID                                                              AND EmployeeId = @EmployeeId                                                              AND LeaveSchemeId = @LeaveSchemeId )                                              BEGIN                                                   SELECT TOP 1                                                          @DiffMonth = CONVERT(DECIMAL(10,                                                                0), DATEDIFF(DD,                                                                DateCaptured,                                                                @PeriodEndDate)                                                          / ( 365.0 / 12 ))                                                  FROM    Payroll_EmployeeLeaveLogHistory                                                  WHERE   LeaveTypeId = @LeaveTypeID                                                          AND EmployeeId = @EmployeeId                                                          AND LeaveSchemeId = @LeaveSchemeId                                               END                                           ELSE                                              BEGIN                                   --PRINT '---------'                                  --PRINT @CycleStartDate                                  --PRINT @PeriodEndDate                                  --PRINT '---------'                                                  SELECT TOP 1                                                          @DiffMonth = CONVERT(DECIMAL(10,                                                                0), DATEDIFF(DD,                                                                @CycleStartDate,                                                                @PeriodEndDate)                                                          / ( 365.0 / 12 ))                                              END                           --PRINT '---------------'                          --PRINT @TotalRepeatTimes                          --PRINT @AnnualAccrualFrequency                          --PRINT '---------------'                                          IF ( @DiffMonth >= @AnnualAccrualFrequency )                                              BEGIN                                                   PRINT 1                                                  IF ( @IsFixedOrCalculated = 1 )--Fixed Number Of Days Per Cycle                                                      BEGIN                                                           IF ( @Type = '1' )--Periodic Entitlement(Accumulation)                                                                BEGIN                                                                 IF ( @IsFixedDate = 1 )--Fixed Date                                                                  BEGIN                                                                   SELECT TOP 1                                                                @LeaveBalance = workAccuralDays                                                                FROM                                                                dbo.GetCalculatedWorkDay(@CycleStartDate,                                                                @CycleEndDate,                                                                @Maximumdays,                                                                @JoiningDate,                                                                @AnnualAccrualFrequency)                                                                WHERE                                                                @PeriodStartDate BETWEEN StartDate AND EndDate                                                                END                                                                ELSE                                                                IF ( @IsFixedDate = 0 )                                                                BEGIN                                                                 SELECT TOP 1                                                                @LeaveBalance = workAccuralDays                                                                FROM                                                                dbo.GetCalculatedWorkDay(@JoiningDate,                                                                @EmploymentEndDate,                                                                @Maximumdays,                                                                @JoiningDate,                                                                @AnnualAccrualFrequency)                                                                WHERE                                                                @PeriodStartDate BETWEEN StartDate AND EndDate                                                                END                                                              END                                                                                                           INSERT                                                                INTO dbo.Payroll_EmployeeLeaveLogHistory                                                                (                                                                LeaveTypeId ,                                                                EmployeeId ,                                                                LeaveSchemeId ,                                                                PeriodId ,                                                                DateCaptured                                                                )                                                          VALUES                                                                (                                                                @LeaveTypeID , -- LeaveTypeId - int                                                                @EmployeeId , -- EmployeeId - int                                                                @LeaveSchemeId , -- LeaveSchemeId - int                                                                @PeriodId , -- PeriodId - int                                                                @PeriodStartDate-- DateCaptured - datetime                                                                )                                                          IF EXISTS ( SELECT                                                                EmployeeID                                                                FROM                                                                Payroll_EmployeeLeaves                                                                WHERE                                                                EmployeeID = @EmployeeID                                                                AND FinancialYear = @FinancialYear                                                                AND Enabled = 1                                                                AND LeaveSchemeID = @LeaveSchemeID                                                                AND LeaveTypeID = @LeaveTypeID )                                                              BEGIN                                                                SELECT                                                                @TotalMaxAccumulation = ( ISNULL(LeaveAcrual,                                                                0)                                                                + @LeaveBalance )                                                                FROM                                                                Payroll_EmployeeLeaves                                                                WHERE                                                                EmployeeID = @EmployeeID                                                                AND FinancialYear = @FinancialYear                                                                AND Enabled = 1                                                                AND LeaveSchemeID = @LeaveSchemeID                                                                AND LeaveTypeID = @LeaveTypeID                                                                                                                                 IF ( @TotalMaxAccumulation >= @MaxAccumulation )                                                                BEGIN                                                                 SET @TotalMaxAccumulation = @MaxAccumulation                                                                END                                                                 UPDATE                                                                Payroll_EmployeeLeaves                                                                SET                                                                LeaveAcrual = @TotalMaxAccumulation                                                                WHERE                                                                EmployeeID = @EmployeeID                                                                AND FinancialYear = @FinancialYear                                                                AND Enabled = 1                                                                AND LeaveSchemeID = @LeaveSchemeID                                                                AND LeaveTypeID = @LeaveTypeID                                                               END                                                      END                                                 END                          --PRINT @LeaveBalance                                      END                              END                          SET @Start = @Start + 1                      END                  SET @EmpStart = @EmpStart + 1              END       END  

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveCalendar
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,25 Mar 2014>  -- Description: <Description,,Payroll Employee Leave Details in calender>  -- Call SP:  Payroll_EmployeeLeaveCalendar '01 Jan 2013', '31 Dec 2014', 2  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveCalendar]   @FromDate DATETIME,   @ToDate DATETIME,   @EmployeeId INT  AS  BEGIN   set fmtonly off     ----- CREATE Temp Table   Declare @sql nvarchar(max)     If object_id('tempdb..##tmpCalender') is not null     Drop table ##tmpCalender     set @sql='CREATE TABLE ##tmpCalender      (Id INT IDENTITY(1, 1), [MonthName] NVARCHAR(50), [Month] INT, [Year] INT'     DECLARE @Day INT = 1, @Month INT = 1, @CurMonth INT, @CurYear INT     WHILE (@Day <= 31) BEGIN    SET @sql = @sql + ', [' + CONVERT(NVARCHAR, @Day) + '] NVARCHAR(50)'    SET @Day = @Day + 1   END     SET @sql = @sql + ')'     EXEC (@Sql)     ----- GET Employee Leave and Holidays   DECLARE @DayOfWeek  TABLE (DOW INT)   DECLARE @Mon BIT, @Tue BIT, @Wed BIT, @Thu BIT, @Fri BIT, @Sat BIT, @Sun BIT   SELECT @Mon = Monday, @Tue = Tuesday, @wed  = Wednesday, @Thu = Thursday, @Fri = Friday, @Sat = Saturday, @Sun = Sunday FROM dbo.Payroll_Employee   WHERE Employee_ID = @EmployeeId   IF @Sun = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 1   END   IF @Mon = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 2   END   IF @Tue = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 3   END   IF @Wed = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 4   END   IF @Thu = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 5   END   IF @Fri = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 6   END   IF @Sat = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 7   END     DECLARE @TblLeave TABLE (Id INT IDENTITY(1,1), DATES DATETIME, Color NVARCHAR(50))   DECLARE @WeekOffColor NVARCHAR(50), @PublicHolidayColor NVARCHAR(50)      SELECT @WeekOffColor = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'WeekOffColorCode'   SELECT @PublicHolidayColor = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'PublicHolidayColorCode'     INSERT INTO @TblLeave   SELECT LeaveDate, null --CASE IsTaken WHEN 1 THEN C_LT.TakenColorCode ELSE C_LT.PendingColorCode END    FROM  Payroll_LeaveApproveRequestDetails AS P_LAD    INNER JOIN Payroll_LeaveApproveRequest AS P_LA ON P_LA.LeaveApproveRequest_ID = P_LAD.LeaveApproveRequestId   INNER JOIN dbo.Const_LeaveType AS C_LT ON C_LT.LeaveType_ID = P_LA.LeaveTypeID   WHERE EmployeeID = @EmployeeId     DECLARE @Color NVARCHAR(50)   ----- Process the month    WHILE (@FromDate <= @ToDate) BEGIN    SET @CurMonth = DATEPART(MONTH, @FromDate)    SET @CurYear = DATEPART(YEAR, @FromDate)      INSERT INTO ##tmpCalender ([MonthName], [Month], [Year])    SELECT SUBSTRING(DATENAME(MONTH, @FromDate), 1, 3) + ' - '+ SUBSTRING(CONVERT(NVARCHAR, @CurYear), 3, 2), @CurMonth, @CurYear         WHILE (@FromDate <= @ToDate AND @CurMonth = DATEPART(MONTH, @FromDate)) BEGIN     SET @Sql = ''     IF NOT EXISTS (SELECT * FROM @DayOfWeek WHERE DOW = DATEPART(DW, @FromDate)) BEGIN      SELECT @Color = SUBSTRING(DATENAME(DW, @FromDate), 0, 3) + '|' + @WeekOffColor      SET @Sql = 'UPDATE ##tmpCalender SET [' + CONVERT(nvarchar, (DATEPART(DAY, @FromDate))) + '] = ''' + @Color + ''' WHERE [Month] = ' + CONVERT(nvarchar, @CurMonth) + ' AND [Year] = ' + CONVERT(nvarchar, @CurYear)      EXEC (@Sql)     END     ELSE IF EXISTS (SELECT * FROM Const_Holiday WHERE HolidayDate = @FromDate) BEGIN      SELECT @Color = SUBSTRING(DATENAME(DW, @FromDate), 0, 3) + '|' + @PublicHolidayColor      SET @Sql = 'UPDATE ##tmpCalender SET [' + CONVERT(nvarchar, (DATEPART(DAY, @FromDate))) + '] = ''' + @Color + ''' WHERE [Month] = ' + CONVERT(nvarchar, @CurMonth) + ' AND [Year] = ' + CONVERT(nvarchar, @CurYear)      EXEC (@Sql)     END     ELSE IF EXISTS (SELECT * FROM @TblLeave WHERE DATES = @FromDate) BEGIN      SELECT TOP 1 @Color = SUBSTRING(DATENAME(DW, @FromDate), 0, 3) + '|' + Color FROM @TblLeave WHERE DATES = @FromDate      SET @Sql = 'UPDATE ##tmpCalender SET [' + CONVERT(nvarchar, (DATEPART(DAY, @FromDate))) + '] = ''' + @Color + ''' WHERE [Month] = ' + CONVERT(nvarchar, @CurMonth) + ' AND [Year] = ' + CONVERT(nvarchar, @CurYear)      EXEC (@Sql)     END     ELSE BEGIN      SELECT @Color = SUBSTRING(DATENAME(DW, @FromDate), 0, 3)      SET @Sql = 'UPDATE ##tmpCalender SET [' + CONVERT(nvarchar, (DATEPART(DAY, @FromDate))) + '] = ''' + @Color + ''' WHERE [Month] = ' + CONVERT(nvarchar, @CurMonth) + ' AND [Year] = ' + CONVERT(nvarchar, @CurYear)      EXEC (@Sql)     END     SET @FromDate = DATEADD(DAY, 1, @FromDate)    END    END     SELECT * FROM ##tmpCalender     DECLARE @Calender TABLE (Id INT, [MonthName] NVARCHAR(50), [Month] INT, [Year] INT, [1] NVARCHAR(50),[2] NVARCHAR(50),[3] NVARCHAR(50),[4] NVARCHAR(50),[5] NVARCHAR(50),[6] NVARCHAR(50),[7] NVARCHAR(50),[8] NVARCHAR(50),        [9] NVARCHAR(50),[10] NVARCHAR(50),[11] NVARCHAR(50),[12] NVARCHAR(50),[13] NVARCHAR(50),[14] NVARCHAR(50),[15] NVARCHAR(50),[16] NVARCHAR(50)        ,[17] NVARCHAR(50),[18] NVARCHAR(50),[19] NVARCHAR(50),[20] NVARCHAR(50),[21] NVARCHAR(50),[22] NVARCHAR(50),[23] NVARCHAR(50),[24] NVARCHAR(50),[25] NVARCHAR(50)        ,[26] NVARCHAR(50),[27] NVARCHAR(50),[28] NVARCHAR(50),[29] NVARCHAR(50),[30] NVARCHAR(50),[31] NVARCHAR(50))     INSERT INTO @Calender   SELECT * FROM ##tmpCalender     SELECT * FROM @Calender    END    

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveDaysRequested
-- Schema: dbo
-- ============================================
  -- ===================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/08>  -- Description: <Get Number of Leave Days requested by Employee>  -- Call SP    : Payroll_EmployeeLeaveDaysRequested 1, '2017/12/01','2017/12/04'  --====================================================================  /*   Modiri   2019/10/08   #95001 QA_Multi_HRPayroll_no functionality for half day Leave Capture  */  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveDaysRequested]  @EmployeeId INT,  @DateFrom DATETIME,  @DateTo DATETIME,  @NoDays float =NULL  AS  BEGIN      if(@NoDays IS NULL)   BEGIN    SELECT Convert(float,COUNT(pec.EmployeeCalendar_ID)) AS NoOfDays, @DateTo AS 'DateTO' FROM Payroll_EmployeeCalander pec     WHERE pec.EmployeeID = @EmployeeId    AND pec.Shift = 1    AND pec.PublicH = 0    AND pec.Date >= @DateFrom    AND pec.Date <= @DateTo   END   ELSE   BEGIN    --calculate based on number of days.        DECLARE @dtTo date;    DECLARE @tmpNoDay float=1;    DECLARE @cnt int=1;      IF(@NoDays < 1)    BEGIN     SET @cnt=@NoDays     SET @dtTo =@DateFrom;     SET @tmpNoDay=999;    END      WHILE   @tmpNoDay <= @NoDays    BEGIN        SET @dtTo = DATEADD(DAY, @cnt, @DateFrom);           IF( SELECT COUNT(pec.EmployeeCalendar_ID) FROM Payroll_EmployeeCalander pec      WHERE  pec.EmployeeID = @EmployeeId      AND pec.Shift = 1     AND pec.PublicH = 0     AND MONTH(pec.Date) = MONTH(@dtTo) AND DAY(pec.Date) = DAY(@dtTo) and YEAR(pec.Date) = YEAR(@DateFrom)     )>0     BEGIN            SET @tmpNoDay = @tmpNoDay+ 1;     END     SET @cnt = @cnt+1;    END      DECLARE @dt int =0    SET @cnt = 1;    IF(@NoDays < 1)     SET @dt =1;      WHILE @dt=0    BEGIN        IF( SELECT COUNT(pec.EmployeeCalendar_ID) FROM Payroll_EmployeeCalander pec      WHERE  pec.EmployeeID = @EmployeeId      AND pec.Shift = 1     AND pec.PublicH = 0     AND MONTH(pec.Date) = MONTH(@dtTo) AND DAY(pec.Date) = DAY(@dtTo) and YEAR(pec.Date) = YEAR(@DateFrom)     )>0     BEGIN            SET @dt=1;      BREAK     END       SET @cnt = @cnt+1;     SET @dtTo = DATEADD(DAY, @cnt, @DateFrom);        END      SELECT @NoDays AS NoOfDays, @dtTo AS DateTO      END  END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveDeduction_sp
-- Schema: dbo
-- ============================================
    -- =============================================    -- Author: MEHUL PANCHAL    -- Create date: 11 JULY 2013    -- Description:  GET EMPLOYEE LEAVE DEDUCTION    -- CALLS : Payroll_EmployeeDeduction_sp '2013/05/01','2013/05/01',1,1,1,'2013-07-15 00:00:00.000',1,''    -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveDeduction_sp]      @LeaveApprovedFromDate DATETIME ,      @LeaveApprovedToDate DATETIME ,      @LeaveApproveRequestId INT  AS      BEGIN       DECLARE @FinancialYear NVARCHAR(12)   DECLARE @NoofLeave INT = 0   DECLARE @LeaveTypeID INT = 1 -- Still do resolve this   DECLARE @DateModified DATETIME = GETDATE()   DECLARE @ModifierID INT = 1 -- this will be part of the Stored Procedure     UPDATE Payroll_LeaveApproveRequestDetails SET IsApproved = 1 WHERE LeaveApproveRequestId = @LeaveApproveRequestId AND LeaveDate BETWEEN @LeaveApprovedFromDate AND @LeaveApprovedToDate      DECLARE @History_Id INT, @UserId INT, @EmployeeId INT   SELECT @UserId = ISNULL(ModifierID, CapturerID), @EmployeeId = EmployeeID FROM dbo.Payroll_LeaveApproveRequest WHERE LeaveApproveRequest_ID = @LeaveApproveRequestId      SELECT TOP 1 @History_Id = History_Id FROM Payroll_LeaveEscalationReassigneHistory WHERE LeaveApproveRequestId = @LeaveApproveRequestId AND IsProcessed = 0      UPDATE dbo.Payroll_LeaveEscalationReassigneHistory SET IsProcessed = 1 WHERE LeaveApproveRequestId = @LeaveApproveRequestId AND IsProcessed = 0      INSERT INTO dbo.Payroll_LeaveEscalationReassigneHistory (LeaveApproveRequestId, EmployeeId, FromHistoryId, IsApproved, IsProcessed, CapturerId)   SELECT @LeaveApproveRequestId, @EmployeeId, @History_Id, 1, 1, @UserId      SET @History_Id = SCOPE_IDENTITY()   EXEC dbo.Payroll_LeaveEscalationReassignEmail @History_Id = @History_Id             DECLARE @NoofHolidayDays INT            SET @NoofHolidayDays = 0                        DECLARE @LeaveBalance INT            SET @LeaveBalance = 0                  SELECT TOP 1                  @FinancialYear = FinancialYear          FROM    Payroll_CyclePeriodDetails          WHERE   PeriodStartDate >= @LeaveApprovedFromDate                  AND PeriodEndDate <= @LeaveApprovedToDate          ORDER BY Period_ID DESC                   DECLARE @EmployeeLeaveId INT          SELECT @EmployeeLeaveId = EmployeeLeave_ID FROM dbo.Payroll_EmployeeLeaves           WHERE EmployeeID = @EmployeeID /*AND LeaveTypeID = @LeaveTypeID*/ AND Enabled = 1 AND FinancialYear = @FinancialYear                    SELECT @NoofHolidayDays  = ISNULL(COUNT(*),0)  FROM Const_Holiday WHERE (TaxYear = @FinancialYear) AND(HolidayDate BETWEEN @LeaveApprovedFromDate AND @LeaveApprovedToDate)                  IF ( @NoofHolidayDays > 0 )              BEGIN                    SET @NoofLeave = @NoofLeave - @NoofHolidayDays                END            IF ( @NoofLeave > 0 )              BEGIN       --> TAKE LEAVE BALANCE                       SELECT  @LeaveBalance = LeaveBalance                  FROM    Payroll_EmployeeLeaves--Payroll_EmployeeLeave                  WHERE   ( EmployeeID = @EmployeeID )                          AND ( LeaveTypeID = @LeaveTypeID )               --> LEAVEBALANCE = LEAVEBALANCE - NOOFLEAVE                    SET @LeaveBalance = @LeaveBalance - @NoofLeave          --> IF (LEAVEBALANCE < 0)                    IF ( @LeaveBalance < 0 )                      BEGIN        --> SET IT TO OVERDUE                            UPDATE  Payroll_EmployeeLeaves--Payroll_EmployeeLeave                          SET     UsedLeave = UsedLeave + @NoofLeave ,                                  OverDueLeave = @LeaveBalance ,                                  LeaveBalance = 0 ,                                  DateModified = @DateModified ,                                  ModifierID = @ModifierID                          WHERE   ( EmployeeID = @EmployeeID )                                  AND ( LeaveTypeID = @LeaveTypeID )                      END                    ELSE                      BEGIN        --> ELSE UPDATE LEAVEBALANCE                            UPDATE  Payroll_EmployeeLeaves--Payroll_EmployeeLeave                          SET     UsedLeave = UsedLeave + @NoofLeave ,                                  LeaveBalance = LeaveBalance - @NoofLeave ,                                  DateModified = @DateModified ,                                  ModifierID = @ModifierID                          WHERE   ( EmployeeID = @EmployeeID )                                  AND ( LeaveTypeID = @LeaveTypeID )                       END   --> Insert Transaction      DECLARE @LeaveSchemeID INT, @Count INT = 1, @Total INT      SELECT @LeaveSchemeID = LeaveSchemeID FROM Payroll_EmployeeLeaves WHERE EmployeeID = @EmployeeID AND LeaveTypeID = @LeaveTypeID AND Enabled = 1      DECLARE @TblWorkingDays TABLE(Id INT, WorkingDate DATETIME)            INSERT INTO @TblWorkingDays SELECT * FROM [dbo].[GetEmpWorkingDatesByFromAndToDate](@EmployeeID, @LeaveApprovedFromDate, @LeaveApprovedToDate)      SELECT @Total = COUNT(*) FROM @TblWorkingDays            WHILE (@Count <= @Total) BEGIN       SELECT @LeaveApprovedFromDate = WorkingDate FROM @TblWorkingDays WHERE Id = @Count       INSERT INTO Payroll_EmployeeLeavesTransactions (EmployeeId, LeaveSchemeID, LeaveTypeID, TakenLeave, TransactionDate)       SELECT @EmployeeID, @LeaveSchemeID, @LeaveTypeID, 1, @LeaveApprovedFromDate       SET @Count = @Count + 1      END              END          END      

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveEncashDeduction
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,12 Mar 2014>  -- Description: <Description,,Payroll_EmployeeLeaveEncashDeduction>  -- CALL SP:  Payroll_EmployeeLeaveEncashDeduction 1  -- 2014-11-07 Thabiso Maboe: Added CycleTypeID  -- 2015-01-14 James Roodt: Use the ratePerDay as defined on the Leave Encash screen  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveEncashDeduction] @EncashId INT  AS  BEGIN   DECLARE @NoOfDays DECIMAL(18, 2)    ,@EmpId INT    ,@LeaveSchemeId INT    ,@LeaveTypeId INT    ,@EncashAmount DECIMAL(18, 2)    ,@LeaveTypeDetailId INT    ,@EncashAmount_Monthly DECIMAL(18, 2)    ,@EncashAmount_Other DECIMAL(18, 2)    ,@WHPD_Monthly DECIMAL(18, 2)    ,@WHPD_Other DECIMAL(18, 2)    ,@UserId INT    ,@CycleTypeID INT    ,@RatePerDayUsedForCalc DECIMAL(18, 2)     SELECT @NoOfDays = ApproveNoOfDays    ,@EmpId = EmployeeId    ,@LeaveTypeId = LeaveTypeId    ,@LeaveTypeDetailId = LeaveTypeDetailId    ,@UserId = ModifierID    ,@RatePerDayUsedForCalc = RatePerDayUsedForCalc   FROM Payroll_EmployeeLeaveEncashRequest   WHERE Encash_ID = @EncashId     SELECT @LeaveSchemeId = LeaveSchemeId   FROM dbo.Payroll_EmployeeLeaveSchemeDetails   WHERE EmployeeId = @EmpId    AND LeaveTypeId = @LeaveTypeId    AND LeaveTypeDetailId = @LeaveTypeDetailId    AND IsEnabled = 1     DECLARE @CycleID INT     SELECT @CycleID = CycleID    ,@CycleTypeID = CycleTypeID    ,@EncashAmount_Monthly = ISNULL(RPH_Monthly, 0)    ,@EncashAmount_Other = ISNULL(RPH_Other, 0)    ,@WHPD_Monthly = ISNULL(WHPD_Monthly, 0)    ,@WHPD_Other = ISNULL(WHPD_Other, 0)   FROM dbo.Payroll_Employee P_E    INNER JOIN Const_Cycle C_C ON P_E.CycleID = C_C.Cycle_ID   INNER JOIN Const_CycleType_sys C_CT ON C_C.CycleTypeID = C_CT.CycleType_ID   WHERE Employee_ID = @EmpId     IF (     @CycleTypeID = 1       )   BEGIN    --SET @EncashAmount = @EncashAmount_Monthly * @NoOfDays * @WHPD_Monthly    SET @EncashAmount = @RatePerDayUsedForCalc * @NoOfDays   END   ELSE   BEGIN    --SET @EncashAmount = @EncashAmount_Other * @NoOfDays * @WHPD_Other    SET @EncashAmount = @RatePerDayUsedForCalc * @NoOfDays   END     --INSERT INTO Payroll_EmployeeLeavesTransactions(EmployeeId, LeaveSchemeID, LeaveTypeID, EncashLeave, TransactionDate, EncashAmount)   --SELECT @EmpId, @LeaveSchemeId, @LeaveTypeId, @NoOfDays, GETDATE(), @EncashAmount   INSERT INTO dbo.Payroll_EmployeeLeaveSchemeTransaction (    EmployeeId    ,LeaveSchemeId    ,LeaveTypeId    ,LeaveTypeDetailId    ,EncashLeave    ,TranDate    ,EncashAmount    ,CapturerId    )   SELECT @EmpId    ,@LeaveSchemeId    ,@LeaveTypeId    ,@LeaveTypeDetailId    ,@NoOfDays    ,GETDATE()    ,@EncashAmount    ,@UserId     UPDATE Payroll_EmployeeLeaveEncashRequest   SET EncashAmount = @EncashAmount   WHERE Encash_ID = @EncashId     SELECT SCOPE_IDENTITY()  END  

GO

-- ============================================
-- SP: Payroll_EmployeeLeavesTransactionList
-- Schema: dbo
-- ============================================
   -- =============================================  -- Author:  <Author,,Richa M>  -- Create date: <Create Date,, Feb 2014>  -- Description: <Description,,Employee Leaves TransactionList By Employee Id>  -- Call SP    : Payroll_EmployeeLeavesTransactionList 403,0  -- Changes    : Artur Anzorge  -- Changes date : 2019/07/11  -- Description:  Add Balance column  -- Modiri 2019/12/05 https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/25891  -- Ferdi 29/01/2020 https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/27235  -- Modiri 05/02/2020 https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/27901  -- Richa M 2020/11/30 Fix Employee Leave grid  -- Ruan 2021/10/07 Fix Encash filter  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeLeavesTransactionList]   @EmpId INT,  @Encash BIT = NULL    AS    BEGIN        DECLARE @LeaveSchemeId int = (select LeaveSchemeId from payroll_employee where Employee_ID = @EmpId)       --1=Female   2-Male     DECLARE @GenderId int =  (select GenderID from payroll_employee where Employee_ID = @EmpId)          Select       LeaveType_ID AS ID,      ltd.LeaveTypeId,      LeaveType,      LeaveTypeDesc,      cast(isnull(PeriodStart, 0) as nvarchar) + ' - ' + cast(isnull(PeriodEnd, 0) as nvarchar) + (case when isnull(PeriodIndicator, 0) = 1 then ' Months' when isnull(PeriodIndicator, 0) = 2 then ' Years' else '' end) as PeriodDesc,      IsNULL(Balance,0) as OpeningBalance,      IsNULL(Accrued,0) As AcrualLeave,      IsNULL(Taken,0) as TakenLeave,      IsNULL(balance.Forfeit,0) as ForfeitLeave,      IsNULL(Encashed,0) as EncashedLeave,      IsNULL(TotalLeaveDays,0) AS Balance,      @LeaveSchemeId LeaveSchemeId,       IsNULL(Adjusted,0) as AdjustedLeave,      0.00 AS WithoutPlayLeave,      0.00 AS ClosingBalance,      0.00 AS PlannedLeave,      0.00 AS AvailableLEave,      ltd.StartDate,      ltd.EndDate     from(       select * from Const_LeaveType where LeaveType_ID in(         select LeaveTypeID from Payroll_AbsencePriority where AbsenceTypeID in(         select LeaveTypeId from Const_LeaveSchemeTypeDetails where LeaveSchemeId = @LeaveSchemeId and Enabled = 1))          and Enabled = 1     )LeaveType        left join Const_LeaveTypeDetails ltd on ltd.LeaveTypeId = LeaveType.LeaveType_ID          left join Payroll_EmployeeLeaveBalance balance on balance.EmployeeID = @EmpId and balance.LeaveTypeID = ltd.LeaveTypeId             where ltd.Enabled = 1                 AND LeaveClassificationID not in (CASE WHEN @GenderId = 1 THEN 9 ELSE 3 END)          AND (@Encash IS NULL OR LeaveType.Encash = @Encash)          order by LeaveTypeDesc          END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveTransaction
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 12 July 2013  -- Description: Payroll Employee approved leave transaction  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveTransaction]    @EmployeeID INT,   @FinancialYear  NVARCHAR(30)  AS  BEGIN      SET NOCOUNT ON;      -- PLAR.ApprovalStatus = 3 = Approved   -- PLAR.LeaveStatus = 1 = Taken         SELECT PE.IdNo,        PE.FirstName,         PE.Surname,         PLD.LeaveTypeDesc,         CLR.LeaveReasonDesc,     CONVERT(NVARCHAR(12),PLAR.RequestFromDate,106) AS RequestFromDate,     CONVERT(NVARCHAR(12),PLAR.RequestToDate,106) AS RequestToDate,      PLAR.RequestNoOfDays,          CONVERT(NVARCHAR(12),PLAR.ApproveFromDate,106) AS ApproveFromDate,     CONVERT(NVARCHAR(12),PLAR.ApproveToDate,106) AS ApproveToDate,     PLAR.ApproveNoOfDays,          CONVERT(NVARCHAR(12),PLAR.TakenFromDate,106) AS TakenFromDate,     CONVERT(NVARCHAR(12),PLAR.TakenToDate,106) AS TakenToDate,      PLAR.TakenNoOfDays      FROM Payroll_LeaveApproveRequest AS PLAR       LEFT OUTER JOIN Payroll_Employee AS PE ON PLAR.EmployeeID = PE.Employee_ID       LEFT OUTER JOIN Const_LeaveReason AS CLR ON PLAR.LeaveReasonID = CLR.LeaveReason_ID       LEFT OUTER JOIN Payroll_LeaveDefinition AS PLD ON PLAR.LeaveTypeID = PLD.LeaveType_ID       WHERE PLAR.ApprovalStatus = 3 AND PLAR.LeaveStatus = 1 AND PE.Employee_ID = @EmployeeID       AND PLAR.FinancialYear = @FinancialYear  END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveTransactionByDate
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Mehul Panchal  -- Create date: 12 July 2013  -- Description: Payroll Employee approved leave transaction  -- =============================================  --select * from Payroll_LeaveApproveRequest  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveTransactionByDate] ---13,'09/01/2013','09/24/2013', 0   @EmployeeID INT,   @FromDate datetime,   @ToDate Datetime,   @LeaveTypeId INT   --@FinancialYear  NVARCHAR(30)  AS  BEGIN      --SET NOCOUNT ON;      -- PLAR.ApprovalStatus = 3 = Approved   -- PLAR.LeaveStatus = 1 = Taken         SELECT C_LT.LeaveTypeDesc, RequestFromDate, RequestToDate, RequestNoOfDays, ApproveFromDate, ApproveToDate, ApproveNoOfDays FROM Payroll_LeaveApproveRequest AS P_LA   INNER JOIN Const_LeaveType AS C_LT ON C_LT.LeaveType_ID = P_LA.LeaveTypeID   WHERE EmployeeID = @EmployeeID AND P_LA.ApprovalStatus = 3 AND (ApproveFromDate BETWEEN @FromDate AND @ToDate OR ApproveToDate BETWEEN @FromDate AND @ToDate)   AND (LeaveType_ID = @LeaveTypeId OR @LeaveTypeId = 0)     --WHERE PLAR.ApprovalStatus = 3 AND PLAR.LeaveStatus = 1 AND  PE.Employee_ID = @EmployeeID     --  AND PLAR.TakenFromDate BETWEEN @FromDate and @ToDate       --AND PLAR.FinancialYear = @FinancialYear  END  

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveTransactionRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  PRERANA PARMAR  -- Create date:08 JULY 2013  -- Description: EMPLOYEE LEAVE TRANSACTION  -- CALLS : Payroll_EmployeeLeaveTransactionRpt_sp '08/01/2013' ,'08/10/2014', 0, 0, 0  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-04-04 TP32628 Ravindra Jijotia: Added LeaveSchemeId & LeaveTypeId filter  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2020-01-20 Modiri https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/24408  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveTransactionRpt_sp]    @LeaveFromDate DATETIME,    @LeaveToDate DATETIME,    @EmployeeId INT,    @DepartmentId INT,    @CycleId INT,    @LeaveSchemeId INT,    @LeaveTypeId INT  AS  BEGIN   Declare @tblEmpl table(Employeeid INT)     Insert into @tblEmpl      Select P_E.Employee_ID      FROM dbo.Payroll_Employee P_E      JOIN dbo.Const_LeaveScheme AS C_LS ON C_LS.LeaveScheme_ID = P_E.LeaveSchemeId      JOIN [Const_LeaveSchemeTypeDetails] LST ON LST.LeaveSchemeID = P_E.LeaveSchemeId     join Payroll_AbsencePriority PAP on PAP.AbsenceTypeID = LST.LeaveTypeId     JOIN dbo.Const_LeaveType AS C_LT ON C_LT.LeaveType_ID = LST.LeaveTypeId       JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID      JOIN dbo.Const_Department AS C_DEP ON C_DEP.Department_ID = PP.DepartmentID      WHERE     (P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0)     AND (C_DEP.Department_ID = @DepartmentId OR @DepartmentId = 0)    AND (P_E.CycleID = @CycleId OR @CycleId = 0)    AND (P_E.LeaveSchemeId = @LeaveSchemeId OR @LeaveSchemeId = 0)    AND (LST.LeaveTypeId = @LeaveTypeId OR @LeaveTypeId = 0)   ORDER BY Employee_ID        declare @tbl table(idx int identity(1,1), trandate datetime, leavetypeid int,empid int,Accrued decimal(4,2),Taken decimal(4,2),Forfeit decimal(4,2),Encashed decimal(4,2),Accumulated decimal(4,2), Adjusted decimal(4,2), Other decimal(4,2))     --Accrued   insert into @tbl(empid,leavetypeid,Accrued,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),StartDate from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID=2 and employeeid in (select employeeid from @tblEmpl)       --Taken   insert into @tbl(empid,leavetypeid,Taken,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),datecaptured from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID=3 and employeeid in (select employeeid from @tblEmpl)     --Forfeit   insert into @tbl(empid,leavetypeid,Forfeit,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),datecaptured from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID=4 and employeeid in (select employeeid from @tblEmpl)     --Encashed   insert into @tbl(empid,leavetypeid,Encashed,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),datecaptured from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID=5 and employeeid in (select employeeid from @tblEmpl)     --Accumulated   insert into @tbl(empid,leavetypeid,Accumulated,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),datecaptured from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID=6 and employeeid in (select employeeid from @tblEmpl)     --Adjusted/opening balance   insert into @tbl(empid,leavetypeid,Adjusted,trandate)   select employeeid, LeaveTypeID,isnull([Value],0),datecaptured from payroll_EmployeeLeaveTransactions where enabled=1 and LeaveAdjustmentTypeID in(7,1) and employeeid in (select employeeid from @tblEmpl)        SELECT P_E.Employee_ID, P_E.FirstName + ' ' + P_E.Surname AS EmployeeName, TranDate, IdNo, EmpCode, dbo.BufferString_fxn(CONVERT(VARCHAR, ( P_E.Employee_ID )), 8,'0') AS EmpNo, C_LS.LeaveSchemeDesc, C_LT.LeaveType,     isnull(TRA.Accrued,0) as AccrualLeave,isnull(TRA.Taken,0) as TakenLeave,isnull(TRA.Forfeit,0) as ForfeitLeave,    isnull(TRA.Encashed,0) as EncashLeave,isnull(TRA.Adjusted,0) as AdjustedLeave      FROM @tbl TRA      JOIN dbo.Payroll_Employee P_E ON P_E.Employee_ID = TRA.empid     JOIN dbo.Const_LeaveScheme AS C_LS ON C_LS.LeaveScheme_ID = P_E.LeaveSchemeId      JOIN dbo.Const_LeaveType AS C_LT ON C_LT.LeaveType_ID = TRA.LeaveTypeId       JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID      JOIN dbo.Const_Department AS C_DEP ON C_DEP.Department_ID = PP.DepartmentID      WHERE TranDate BETWEEN @LeaveFromDate AND @LeaveToDate       ORDER BY Employee_ID, TranDate, C_LS.LeaveSchemeDesc, LeaveType     END

GO

-- ============================================
-- SP: Payroll_EmployeeLeaveTypeByEmpId
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_EmployeeLeaveTypeByEmpId]   @EmployeeId INT  AS    BEGIN       Select LeaveType_ID,scheme.LeaveSchemeId LeaveScheme_id,LeaveTypeDesc LeaveType,AbsenceTypeID,AbsenceType    from (Select LeaveSchemeId from Payroll_employee where Employee_ID = @EmployeeId)emp    join Const_LeaveSchemeTypeDetails scheme on scheme.LeaveSchemeId = emp.LeaveSchemeID and scheme.Enabled = 1    join Payroll_AbsencePriority labs on labs.AbsenceTypeID = scheme.LeaveTypeId    join Const_AbsenceType abt on abt.AbsenceType_ID = labs.AbsenceTypeID    join Const_LeaveTypeDetails ldet on ldet.LeaveTypeId = labs.LeaveTypeID    join Const_LeaveType lt on lt.LeaveType_ID = ldet.LeaveTypeId    END

GO

-- ============================================
-- SP: Payroll_EmployeeListRpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author: PRERANA PARMAR  -- Create date: <Create Date,,>  -- Description: 08 JULY 2013  -- CALLS : Payroll_EmployeeListRpt_sp '1950/08/01','2014/08/01', 0, 0, NULL, 0  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2021-04-12 TP59871 Myroshnychenko: Fix problem with Reasons  -- 2022-03-16 WI84356 Change report to filter on Enddate instead of Enabled flag  --Payroll_EmployeeListRpt_sp '1950/08/01','2014/08/01', 0, 0, NULL, 0  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeListRpt_sp]   @FromDate DATETIME,   @ToDate DATETIME,   @DepartmentId INT,   @DivisionId INT,   @Status BIT = NULL,   @CycleId INT  AS  BEGIN    SET NOCOUNT ON;      ;WITH ph AS   (     SELECT PositionHistory_ID, PositionID,StartDate,EndDate,           ROW_NUMBER() OVER (PARTITION BY PositionId ORDER BY StartDate asc) AS rn     FROM Payroll_PositionHistory   )     SELECT * into #PositionHistory   FROM ph    WHERE rn = 1      SELECT DISTINCT      EmpCode        ,dbo.BufferString_fxn(CONVERT(VARCHAR, ( P_E.Employee_ID )), 8,'0') AS EmpNo     ,ISNULL(P_E.FirstName,'') + ' ' + ISNULL(P_E.Surname,'')  AS EmployeeName     ,CONVERT(NVARCHAR,ISNULL(P_E.DateOfBirth,''),103) AS DateOfBirth     ,CONVERT(NVARCHAR,ISNULL(P_E.JoiningDate,''),103 ) AS StartDate     ,(CASE       WHEN P_E.EndDate is NULL THEN ''       ELSE CONVERT(NVARCHAR,ISNULL(P_E.EndDate,null),103)      END ) AS EndDate     ,P_E.IdNo     , CASE       WHEN (LEN(TRIM(P_E.NotchChangeReason)) = 0 OR P_E.NotchChangeReason IS NULL) THEN (SELECT TOP 1 ReasonDescription FROM Payroll_ReasonEmployeeChange AS P_REC WHERE P_REC.Reason_ID = P_E.ReasonID)       ELSE P_E.NotchChangeReason      END AS Reason     , DepartmentDesc     , P_JP.JobTitle    FROM Payroll_Employee AS P_E     LEFT OUTER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID    LEFT JOIN #PositionHistory ph on ph.PositionID = pp.Position_ID    LEFT OUTER JOIN dbo.Payroll_JobProfile AS P_JP ON P_JP.JobProfile_ID = PP.JobProfileID    LEFT OUTER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID    LEFT OUTER JOIN dbo.Const_Division AS C_Div ON C_D.Department_ID = C_Div.DepartmentID      WHERE (C_D.Department_ID = @DepartmentId OR @DepartmentId = 0) AND    (C_Div.Division_ID = @DivisionId OR @DivisionId = 0) AND    ((@Status is null AND (P_E.[EndDate] BETWEEN @FromDate AND @ToDate OR P_E.[EndDate] > @ToDate)) OR    (@Status = 1 AND P_E.[EndDate] >= @ToDate) OR    (@Status = 0 AND P_E.[EndDate] BETWEEN @FromDate AND @ToDate))    AND (P_E.CycleID = @CycleId OR @CycleId = 0)    Drop table #PositionHistory    END

GO

-- ============================================
-- SP: Payroll_EmployeeMedicalAid_Detail_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Ivan Myroshnychenko  -- Create date: 28/12/2020  -- Description:   -- CALLS : EXEC [dbo].[Payroll_EmployeeMedicalAid_Detail_sp] '2020/2021',0,'',0,(1-3)  -- '2020/2021' - TaxYear  -- 0 - Cycle ID  -- '' - Medical Aid Scheme name (e.g. 'BONITAS')  -- 0 - Medical Aid Plan ID  -- (1-3) - Status, 1- All employees, 2 - Inactive employees, 3 - Active employees  -- 2023/11/14 Kiran WI96570 - Fixed Dependants count in Reprot Employee Medical Aid  -- 2023/12/01 Kiran WI83386 fixed issue employees not on the detail report   -- 2024/01/10 Kiran WI83386 fixed issue employees not on the detail report  -- 2024/01/23 Kiran WI96570 fixed duplication  -- 2024/01/24 Kiran WI83386 fixed the termination date  -- 2024/03/22 Kiran WI83386 fixed issue Medical Aid Tax Credit  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeMedicalAid_Detail_sp]      @TaxYear NVARCHAR(MAX),      @CycleID INT,      @MedicalAidScheme NVARCHAR(MAX),      @MedicalAidPlan INT,      @Status INT  AS    BEGIN    DECLARE @PurposeTaxYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    DECLARE @IRP5CodeMedicalFringeBenefit INT = 3810  DECLARE @IRP5CodeMedicalEmployerContribution INT = 4474  DECLARE @IRP5CodeMedicalEmployeeContribution INT = 4005    DROP TABLE IF EXISTS #InactiveEmployee  CREATE TABLE #InactiveEmployee  (EmployeeID INT)    INSERT INTO #InactiveEmployee  SELECT DISTINCT P_E.Employee_ID AS EmployeeID   FROM Payroll_Employee AS P_E    LEFT JOIN Payroll_EmployeeTermination AS P_ET     ON P_E.Employee_ID = P_ET.EmployeeID   WHERE P_E.EndDate < GETDATE() OR P_ET.Complete = 1    DROP TABLE IF EXISTS #Result    CREATE TABLE #Result(  EmployeeNumber INT,  Initials NVARCHAR(MAX),  Surname NVARCHAR(MAX),  MedicalAidScheme NVARCHAR(MAX),  MedicalAidPlan NVARCHAR(MAX),  ReferenceNumber NVARCHAR(MAX),  PayPeriod NVARCHAR(MAX),  Dependants INT,  EmployerContribution FLOAT,  EmployerExtra FLOAT,  EmployeeContribution FLOAT,  EmployeeExtra FLOAT,  TotalContribution FLOAT,  TaxCredit FLOAT,  MedicalFringeBenefit FLOAT,  PeriodID INT  )      INSERT INTO #Result(      EmployeeNumber      , Initials      , Surname      , MedicalAidScheme      , MedicalAidPlan      , ReferenceNumber      , PayPeriod      , Dependants      , EmployerContribution      , EmployerExtra      , EmployeeContribution      , EmployeeExtra      , TotalContribution      , TaxCredit      , MedicalFringeBenefit       , PeriodID   )  SELECT DISTINCT P_E.Employee_ID  , P_E.Initials  , P_E.Surname  , C_MS.MedicalSchemeDesc AS MedicalAidScheme  , C_MS.FundName AS MedicalAidPlan  , P_EMD.Reference AS ReferenceNumber  , P_CPR.ProcessingMonth + ' ' + CAST(YEAR(P_CPR.PeriodStartDate) AS NVARCHAR(MAX)) AS PayPeriod  , Dependants.Dependants AS Dependants  , (CASE    WHEN P_PR.IRP5Code = @IRP5CodeMedicalEmployerContribution AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')' ) THEN ISNULL(P_PR.Amount,0)  END )AS EmployerContribution  , CASE   WHEN ExtraAmount.Amount IS NOT NULL THEN (ExtraAmount.Amount * C_MS.EmployerContributionValue)/100  END AS EmployerExtra  , (CASE    WHEN P_PR.IRP5Code = @IRP5CodeMedicalEmployeeContribution AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')' ) THEN ISNULL(P_PR.Amount,0)  END )AS EmployeeContribution  , CASE   WHEN ExtraAmount.Amount IS NOT NULL THEN (ExtraAmount.Amount * C_MS.EmployeeContributionValue)/100  END AS EmployeeExtra  , 0 AS TotalContribution  , P_PR_HE.TaxCredits AS TaxCredit  , (CASE    WHEN P_PR.IRP5Code = @IRP5CodeMedicalFringeBenefit AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')' ) THEN ISNULL(P_PR.Amount,0)  END ) AS MedicalFringeBenefit  , P_CPR.Period_ID AS PeriodToOrder  FROM Payroll_Employee AS P_E  JOIN Payroll_EmployeeMedicalAIDDetail AS P_EMD   ON P_E.Employee_ID = P_EMD.EmployeeID AND P_EMD.[Enable]=1 AND P_EMD.TerminationDate >= GETDATE()  LEFT JOIN Const_MedicalAIDScheme AS C_MS   ON P_EMD.MedicalAidSchmeID = C_MS.MedicalScheme_ID  JOIN Payroll_PayrollResults AS P_PR    ON P_E.Employee_ID = P_PR.EmployeeID AND P_PR.IRP5Code IN (@IRP5CodeMedicalEmployeeContribution,@IRP5CodeMedicalEmployerContribution,@IRP5CodeMedicalFringeBenefit)  LEFT JOIN Payroll_CyclePeriodDetails AS P_CPR   ON P_PR.PeriodID = P_CPR.Period_ID AND P_CPR.TaxYear = @TaxYear  LEFT JOIN (SELECT P_EM.EmployeeID, P_ET.Amount, P_CPD.Period_ID    FROM Payroll_ExtraActiveMedicalAidTransaction AS P_ET    LEFT JOIN Payroll_EmployeeMedicalAIDDetail AS P_EM     ON P_ET.EmployeeMedicalAIDID = P_EM.EmployeeMedicalAID_ID AND P_EM.[Enable]=1 AND P_EM.TerminationDate >= GETDATE()    JOIN Payroll_Employee AS P_E     ON P_EM.EmployeeID = P_E.Employee_ID    JOIN Payroll_CyclePeriodDetails AS P_CPD     ON P_E.CycleID = P_CPD.CycleID    WHERE P_CPD.PeriodStartDate BETWEEN P_ET.PeriodFrom AND P_ET.PeriodTo     AND P_CPD.TaxYear = @TaxYear) AS ExtraAmount   ON P_E.Employee_ID = ExtraAmount.EmployeeID AND P_CPR.Period_ID = ExtraAmount.Period_ID  LEFT JOIN (SELECT P_E.Employee_ID, P_CPD.Period_ID, Count(P_EMADD.EmployeeDependant_ID) AS Dependants      FROM Payroll_EmployeeMedicalAIDDetailDependants AS P_EMADD     JOIN Payroll_EmployeeMedicalAIDDetail AS P_EMAD      ON P_EMADD.EmployeeMedicalAIDID = P_EMAD.EmployeeMedicalAID_ID AND P_EMAD.[Enable]=1 AND P_EMAD.TerminationDate >= GETDATE()     JOIN Payroll_Employee AS P_E      ON P_EMAD.EmployeeID = P_E.Employee_ID     JOIN Payroll_CyclePeriodDetails AS P_CPD      ON P_E.CycleID = P_CPD.CycleID     WHERE P_EMADD.Enable=1 AND P_EMADD.StartDate < (SELECT MAX(EndDate) FROM Const_Payroll_TaxPeriods WHERE TaxYear = @PurposeTaxYear AND (@CycleID = 0 OR @CycleID = cycleID))      AND P_EMADD.EndDate > (SELECT MIN(StartDate) FROM Const_Payroll_TaxPeriods WHERE TaxYear = @PurposeTaxYear AND (@CycleID = 0 OR @CycleID = cycleID))       AND P_CPD.PeriodStartDate BETWEEN P_EMADD.StartDate AND P_EMADD.EndDate      AND P_CPD.TaxYear = @TaxYear     GROUP BY P_E.Employee_ID, P_CPD.Period_ID) AS Dependants   ON P_E.Employee_ID = Dependants.Employee_ID AND P_CPR.Period_ID = Dependants.Period_ID  LEFT JOIN Payroll_PayrollRun_History_Employees AS P_PR_HE   ON P_E.Employee_ID = P_PR_HE.Employee_ID AND P_CPR.Period_ID = P_PR_HE.Period_ID AND @TaxYear = P_PR_HE.TaxYear    WHERE P_PR.TaxYear = @PurposeTaxYear   AND (@CycleID = 0 OR @CycleID = P_PR.CycleID)   AND (@MedicalAidScheme = '' OR @MedicalAidScheme = C_MS.MedicalSchemeDesc)   AND (@MedicalAidPlan = 0 OR @MedicalAidPlan = C_MS.MedicalScheme_ID)    AND (@Status = 1     OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))     OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))    SELECT DISTINCT dbo.BufferString_fxn(EmployeeNumber, 8, '0') AS EmployeeNumber      , Initials      , Surname      , MedicalAidScheme      , MedicalAidPlan      , ReferenceNumber      , PayPeriod      , CASE        WHEN Dependants IS NULL THEN 0       ELSE Dependants      END AS Dependants      , SUM(EmployerContribution) EmployerContribution      , SUM(EmployerExtra) EmployerExtra      , SUM(EmployeeContribution) EmployeeContribution      , SUM(EmployeeExtra) EmployeeExtra      , SUM(ISNULL(EmployerContribution,0) + ISNULL(EmployeeContribution,0) + IIF(EmployerExtra IS NULL, 0, ISNULL(EmployerExtra,0)) + IIF(EmployeeExtra IS NULL, 0, ISNULL(EmployeeExtra,0))) AS TotalContribution      , ISNULL((SELECT SUM(P_PR_HE.TaxCredits) FROM Payroll_PayrollRun_History_Employees AS P_PR_HE WHERE #Result.EmployeeNumber = P_PR_HE.Employee_ID AND #Result.PeriodID = P_PR_HE.Period_ID AND @TaxYear = P_PR_HE.TaxYear), SUM(TaxCredit)) AS TaxCredit      , SUM(MedicalFringeBenefit) MedicalFringeBenefit      , PeriodID  FROM #Result   GROUP BY EmployeeNumber, Initials      , Surname      , MedicalAidScheme      , MedicalAidPlan      , ReferenceNumber      , PayPeriod,CASE        WHEN Dependants IS NULL THEN 0       ELSE Dependants      END, PeriodID  ORDER BY EmployeeNumber, PeriodID     END

GO

-- ============================================
-- SP: Payroll_EmployeeMedicalAid_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Ivan Myroshnychenko  -- Create date: 23/12/2020  -- Description:   -- CALLS : EXEC [dbo].[Payroll_EmployeeMedicalAid_sp] '2020/2021',0,'',0,(1-3)  -- '2020/2021' - TaxYear  -- 0 - Cycle ID  -- '' - Medical Aid Scheme name (e.g. 'BONITAS')  -- 0 - Medical Aid Plan ID  -- (1-3) - Status, 1- All employees, 2 - Inactive employees, 3 - Active employees    -- Modified: Richa M - Exclude disabled Medical Aids from report  -- 2023/11/14 Kiran WI96570 - Fixed Dependants count in Reprot Employee Medical Aid  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeMedicalAid_sp]      @TaxYear NVARCHAR(MAX),      @CycleID INT,      @MedicalAidScheme NVARCHAR(MAX),      @MedicalAidPlan INT,      @Status INT  AS  BEGIN    DECLARE @PurposeTaxYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    DROP TABLE IF EXISTS #InactiveEmployee  CREATE TABLE #InactiveEmployee  (EmployeeID INT)    INSERT INTO #InactiveEmployee  SELECT DISTINCT P_E.Employee_ID AS EmployeeID   FROM Payroll_Employee AS P_E    LEFT JOIN Payroll_EmployeeTermination AS P_ET     ON P_E.Employee_ID = P_ET.EmployeeID   WHERE P_E.EndDate < GETDATE() OR P_ET.Complete = 1    DROP TABLE IF EXISTS #BasicSalary    CREATE TABLE #BasicSalary  (  EmployeeID INT,  MonthlySalary FLOAT  )    INSERT INTO #BasicSalary(EmployeeID, MonthlySalary)  SELECT EmployeeId  , Amount/12  FROM Payroll_EmployeeSalaryTransaction   WHERE SalaryHeadId = 1    INSERT INTO #BasicSalary(EmployeeID, MonthlySalary)  SELECT P_E.Employee_ID  , CASE    WHEN P_N.MonthlySalary < P_N.MinimumSalary THEN P_N.MinimumSalary   ELSE P_N.MonthlySalary  END AS MonthSalary  FROM Payroll_Employee AS P_E  JOIN Payroll_Notch AS P_N   ON P_E.NotchId = P_N.Notch_ID    DROP TABLE IF EXISTS #Result    CREATE TABLE #Result  (  EmployeeID INT,  Initials NVARCHAR(MAX),  Surname NVARCHAR(MAX),  IdNo NVARCHAR(MAX),  EmploymentDate NVARCHAR(MAX),  BasicSalary FlOAT,  MedicalAid NVARCHAR(MAX),  MedicalAidPlan NVARCHAR(MAX),  ReferenceNumber NVARCHAR(MAX),  Dependants INT,  EmployerContribution FLOAT,  EmployerContributionPercentage FLOAT,  EmployeeContribution FLOAT,  EmployeeContributionPercentage FLOAT,  TotalContribution FLOAT  )    INSERT INTO #Result (EmployeeID, Initials, Surname, IdNo, EmploymentDate, BasicSalary, MedicalAid, MedicalAidPlan, ReferenceNumber, Dependants        , EmployerContribution, EmployerContributionPercentage, EmployeeContribution, EmployeeContributionPercentage, TotalContribution)  SELECT P_E.Employee_ID   , P_E.Initials   , P_E.Surname   , P_E.IdNo   , CONVERT(VARCHAR(10), P_E.JoiningDate, 103) AS EmploymentDate   , BasicSalary.MonthlySalary AS BasicSalary   , C_MS.MedicalSchemeDesc AS MedicalAid   , C_MS.FundName AS MedicalAidPlan   , P_EMD.Reference AS ReferenceNumber   , CASE    WHEN Dep.Dependants IS NOT NULL THEN Dep.Dependants    ELSE 0    END AS Dependants   , SUM(CASE      WHEN P_PR.IRP5Code = 4474 AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')' ) THEN P_PR.Amount    END) AS EmployerContribution   , C_MS.EmployerContributionValue AS EmployerContributionPercentage   , SUM(CASE      WHEN P_PR.IRP5Code = 4005 AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')' ) THEN P_PR.Amount    END) AS EmployeeContribution   , C_MS.EmployeeContributionValue AS EmployeeContributionPercentage   , SUM(CASE      WHEN P_PR.IRP5Code IN (4005,4474) AND (P_PR.SalaryTitle LIKE '%' + C_MS.FundName + ')' OR P_PR.SalaryTitle LIKE '%' + C_MS.MedicalSchemeDesc + ')') THEN P_PR.Amount    END) AS TotalContribution  FROM Payroll_Employee AS P_E   JOIN Payroll_EmployeeMedicalAIDDetail AS P_EMD    ON P_E.Employee_ID = P_EMD.EmployeeID AND P_EMD.Enable = 1   LEFT JOIN Const_MedicalAIDScheme AS C_MS    ON P_EMD.MedicalAidSchmeID = C_MS.MedicalScheme_ID   LEFT JOIN (SELECT EmployeeMedicalAIDID, Count(EmployeeDependant_ID) AS Dependants       FROM Payroll_EmployeeMedicalAIDDetailDependants                   WHERE Enable = 1 AND StartDate < (SELECT MAX(EndDate) FROM Const_Payroll_TaxPeriods WHERE TaxYear = @PurposeTaxYear AND (@CycleID = 0 OR @CycleID = cycleID))        AND EndDate > (SELECT MIN(StartDate) FROM Const_Payroll_TaxPeriods WHERE TaxYear = @PurposeTaxYear AND (@CycleID = 0 OR @CycleID = cycleID))       GROUP BY EmployeeMedicalAIDID) AS Dep     ON P_EMD.EmployeeMedicalAID_ID = Dep.EmployeeMedicalAIDID   JOIN Payroll_PayrollResults AS P_PR    ON P_E.Employee_ID = P_PR.EmployeeID   LEFT JOIN #BasicSalary AS BasicSalary    ON P_E.Employee_ID = BasicSalary.EmployeeId  WHERE P_PR.TaxYear = @PurposeTaxYear   AND (@CycleID = 0 OR @CycleID = P_PR.CycleID)   AND (@MedicalAidScheme = '' OR @MedicalAidScheme = C_MS.MedicalSchemeDesc)   AND (@MedicalAidPlan = 0 OR @MedicalAidPlan = C_MS.MedicalScheme_ID)    AND (@Status = 1     OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))     OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))  GROUP BY P_E.Employee_ID, P_E.Initials, P_E.Surname, P_E.IdNo, CONVERT(VARCHAR(10), P_E.JoiningDate, 103), C_MS.MedicalSchemeDesc, C_MS.FundName, P_EMD.Reference    , CASE    WHEN Dep.Dependants IS NOT NULL THEN Dep.Dependants    ELSE 0    END    , C_MS.EmployerContributionValue , C_MS.EmployeeContributionValue, BasicSalary.MonthlySalary   ORDER BY P_E.Employee_ID      SELECT dbo.BufferString_fxn(#Result.EmployeeID, 8, '0') AS EmployeeID  , Initials  , Surname  , IdNo  , EmploymentDate  , BasicSalary  , MedicalAid  , MedicalAidPlan  , ReferenceNumber  , Dependants  , CASE   WHEN Extra.ExtraSum IS NOT NULL THEN EmployerContribution + (Extra.ExtraSum * EmployerContributionPercentage)/100   ELSE EmployerContribution   END AS EmployerContribution   , EmployerContributionPercentage  , CASE   WHEN Extra.ExtraSum IS NOT NULL THEN EmployeeContribution + (Extra.ExtraSum * EmployeeContributionPercentage)/100   ELSE EmployeeContribution  END AS EmployeeContribution  , EmployeeContributionPercentage  , CASE    WHEN Extra.ExtraSum IS NOT NULL THEN TotalContribution + Extra.ExtraSum   ELSE TotalContribution  END AS TotalContribution  FROM #Result  LEFT JOIN(SELECT P_EM.EmployeeID, SUM(P_ET.Amount) as ExtraSum    FROM Payroll_ExtraActiveMedicalAidTransaction AS P_ET    LEFT JOIN Payroll_EmployeeMedicalAIDDetail AS P_EM     ON P_ET.EmployeeMedicalAIDID = P_EM.EmployeeMedicalAID_ID    JOIN Payroll_Employee AS P_E     ON P_EM.EmployeeID = P_E.Employee_ID    JOIN Payroll_CyclePeriodDetails AS P_CPD     ON P_E.CycleID = P_CPD.CycleID    WHERE P_CPD.PeriodStartDate BETWEEN P_ET.PeriodFrom AND P_ET.PeriodTo     AND P_CPD.TaxYear = @TaxYear     GROUP BY P_EM.EmployeeID) AS Extra     ON #Result.EmployeeID = Extra.EmployeeID  WHERE TotalContribution > 0  ORDER BY EmployeeID    DROP TABLE #InactiveEmployee  DROP TABLE #BasicSalary  DROP TABLE #Result    END

GO

-- ============================================
-- SP: Payroll_EmployeeMedicalContribution_Trial_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 07/03/2017   Description : Calculates Employees Medical Aid Deductions   Update date : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination   Update Date :   07/04/2020 - Ilya Skavronskiy => Changed salary head title to be Medical Scheme Descripttion  */  /*   Updated By: Modiri Selao   Reason: Include the employeer extra medical aid calculations   #87058 Mnquma Medical Aid Calculation     Update: 2022/08/29 Richa M - Max Dependant Count not working   Update: 2023/04/19  Richa M - Calculation incorrect if Employee must contribute 100% for Dependants  */  CREATE PROCEDURE [dbo].[Payroll_EmployeeMedicalContribution_Trial_sp]      @EmployeeID int,      @PeriodID int,      @CycleID int,      @CycleModeID int,      @StartDate datetime,      @EndDate datetime,      @Month int,      @SCOAYear nvarchar(10),      @TaxYear nvarchar(10),      @Simulation bit  AS  BEGIN      SET NOCOUNT ON;        BEGIN TRY          IF EXISTS (              SELECT 1              FROM [Payroll_CyclePeriodDetails] [CPD]              WHERE [CPD].[PeriodStartDate] = @StartDate                AND [CPD].[PeriodEndDate]   = @EndDate                AND [CPD].[Enabled]         = 1                AND [CPD].[Processed]       = 0                AND [Period_ID]             = @PeriodID                AND [CycleID]               = @CycleID                AND [CycleModeID]           = @CycleModeID          )          BEGIN              DECLARE @IRP5Code TABLE ([IRP5Code] int NOT NULL);              INSERT INTO @IRP5Code VALUES                (3810),(3813),(3860),(3863),(4005),(4024),(4025),(4474),(4485),(4486),(4487),(4493);                DECLARE @EmployeeMedicalAid TABLE              (                  [Employee_ID]            int           NOT NULL,                  [Salary]                 decimal(18,6) NOT NULL,                  [PayrollDefinationID]    int           NOT NULL,                  [TransactionTypeID]      int           NOT NULL,                  [VendorID]               int           NULL,                  [Fund]                   nvarchar(100) NOT NULL,                  [MembershipNo]           nvarchar(50)  NULL,                  [IsMaxDependantChildEnabled] bit       NOT NULL,                  [MaxDependantCount]      int           NOT NULL,                  [EmployeePercent]        decimal(18,6) NOT NULL,                  [EmployerPercent]        decimal(18,6) NOT NULL,                  [EmployerMaxValue]       decimal(18,6) NOT NULL,      [BasePercent]            decimal(18,6)   NOT NULL,                  [EmployeeMemberCount]    int           NOT NULL,                  [EmployeeMemberValue]    decimal(18,6) NOT NULL,                  [EmployerMemberCount]    int           NOT NULL,                  [EmployerMemberValue]    decimal(18,6) NOT NULL,                  [EmployeeAdultCount]     int           NOT NULL,                  [EmployeeAdultValue]     decimal(18,6) NOT NULL,                  [EmployerAdultCount]     int           NOT NULL,                  [EmployerAdultValue]     decimal(18,6) NOT NULL,                  [EmployeeChildCount]     int           NOT NULL,                  [EmployeeChildValue]     decimal(18,6) NOT NULL,                  [EmployerChildCount]     int           NOT NULL,                  [EmployerChildValue]     decimal(18,6) NOT NULL,                  [EmployeeExtraValue]     decimal(18,6) NOT NULL,                  [EmployerExtraValue]     decimal(18,6) NOT NULL,                  [EmployeeValue]          decimal(18,6) NOT NULL DEFAULT(0),                  [EmployerValue]          decimal(18,6) NOT NULL DEFAULT(0)              );                INSERT INTO @EmployeeMedicalAid              (                  [Employee_ID],[Salary],[PayrollDefinationID],[TransactionTypeID],[VendorID],[Fund],[MembershipNo],                  [IsMaxDependantChildEnabled],[MaxDependantCount],                  [EmployeePercent],[EmployerPercent],[EmployerMaxValue],[BasePercent],                  [EmployeeMemberCount],[EmployeeMemberValue],                  [EmployerMemberCount],[EmployerMemberValue],                  [EmployeeAdultCount],[EmployeeAdultValue],                  [EmployerAdultCount],[EmployerAdultValue],                  [EmployeeChildCount],[EmployeeChildValue],                  [EmployerChildCount],[EmployerChildValue],                  [EmployeeExtraValue],[EmployerExtraValue]              )              SELECT                  em.EmployeeID,                  CAST(emp.FixedSalary AS decimal(18,6)) AS Salary,                         -- FIXED: emp.*                  emp.EmployeePayrollDefinition_ID,                                          -- FIXED: emp.*                  emp.TransactionTypeID,                                                     -- FIXED: emp.*                  ven.Vendor_ID,                  cs.MedicalSchemeDesc,                  em.Reference,                  ISNULL(cd.IsMaxDependantChildEnabled,0),                  ISNULL(cd.MaxDependantCount,0),                  CAST(ISNULL(cs.EmployeeContributionValue, 100 - ISNULL(cs.EmployerContributionValue,0)) AS decimal(18,6)) AS EmployeePercent,      CAST(ISNULL(cs.EmployerContributionValue, 100 - ISNULL(cs.EmployeeContributionValue,0)) AS decimal(18,6)) AS EmployerPercent,      CAST(cs.EmployerMaxContributorValue AS decimal(18,6)) AS EmployerMaxValue,      CAST(ISNULL(emp.Percentage, 100) AS decimal(18,6)) AS BasePercent,                      1 AS EmployeeMemberCount,                  (CAST(cd.MemberAmount AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployeeMemberValue,                  1 AS EmployerMemberCount,                  (CAST(cd.MemberAmount AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployerMemberValue,                    ISNULL(dep.EmployeeAdultCount,0)  AS EmployeeAdultCount,                 (CAST(cd.AdultAmount  AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployeeAdultValue,                  ISNULL(dep.EmployerAdultCount,0)  AS EmployerAdultCount,                 (CAST(cd.AdultAmount  AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployerAdultValue,                    ISNULL(dep.EmployeeChildCount,0)  AS EmployeeChildCount,                 (CAST(cd.ChildAmount  AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployeeChildValue,                  ISNULL(dep.EmployerChildCount,0)  AS EmployerChildCount,                 (CAST(cd.ChildAmount  AS decimal(18,6)) * CAST(ISNULL(emp.Percentage,100) AS decimal(18,6)) / 100.0) AS EmployerChildValue,                    ISNULL(ex.EmployeeExtraValue, 0.0) AS EmployeeExtraValue,                  ISNULL(ex.EmployerExtraValue, 0.0) AS EmployerExtraValue              FROM [Payroll_EmployeeMedicalAIDDetail]      AS em  WITH (NOLOCK)              JOIN [Const_MedicalAIDScheme]                AS cs  WITH (NOLOCK) ON cs.MedicalScheme_ID = em.MedicalAidSchmeID              CROSS APPLY (                  SELECT TOP 1                         d.MedicalSchemeID, d.StartDate, d.EndDate,                         d.IsMaxDependantChildEnabled, d.MaxDependantCount,                         d.MemberAmount, d.AdultAmount, d.ChildAmount                  FROM [Const_MedicalAIDSchemeDetail] d WITH (NOLOCK)                  WHERE d.MedicalSchemeID = cs.MedicalScheme_ID                    AND d.Enabled = 1                    AND (                          (d.StartDate <= @StartDate AND d.EndDate >= @EndDate)                       OR (d.StartDate BETWEEN @StartDate AND @EndDate)                       OR (d.EndDate   BETWEEN @StartDate AND @EndDate)                    )                  ORDER BY d.DateCaptured DESC              ) AS cd              JOIN [Cons_Vendor]                            AS ven WITH (NOLOCK) ON ven.Vendor_ID = cs.VendorID              JOIN (                  SELECT DISTINCT                         EPD.EmployeeID,                         ISNULL(CAST(FixedSalary AS decimal(18,6)), CAST(0 AS decimal(18,6))) AS FixedSalary,                         EPD.EmployeePayrollDefinition_ID,                         TransactionTypeID,                         CAST(EPD.Percentage AS decimal(18,6)) AS Percentage                  FROM [Payroll_EmployeePayrollDefinition] EPD WITH (NOLOCK)                  JOIN [Payroll_SalaryHead]             SH  WITH (NOLOCK) ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID AND SH.Enabled = 1                  JOIN [Payroll_IRP5Code]               IRP WITH (NOLOCK) ON IRP.IRP5Code_ID  = SH.IRP5CodeId AND IRP.Enabled = 1                  JOIN [Payroll_Employee]               PE  WITH (NOLOCK) ON PE.Employee_ID   = EPD.EmployeeID AND PE.CycleID = @CycleID                  JOIN [Payroll_CyclePeriodDetails]     CPD WITH (NOLOCK) ON CPD.CycleID = PE.CycleID AND CPD.Period_ID = @PeriodID AND CPD.Enabled = 1                  JOIN [Payroll_TrialRun_History_Employees] EP WITH (NOLOCK)                       ON EP.Employee_ID = PE.Employee_ID AND EP.Period_ID = CPD.Period_ID AND EP.Cycle_ID = PE.CycleID                  LEFT JOIN [Payroll_CyclePeriodAdhocSalaryHead] ACPD WITH (NOLOCK)                       ON ACPD.PeriodID = CPD.Period_ID AND ACPD.SalaryHeadID = SH.SalaryHead_ID                  WHERE (EPD.EmployeeID = CASE @EmployeeID WHEN 0 THEN EPD.EmployeeID ELSE @EmployeeID END)                    AND EPD.Enabled = 1                    AND TransactionTypeID IN (2,3,4)                    AND ISNULL(IRP.IRP5Code, IRP.IRP5CertCode) IN (SELECT IRP5Code FROM @IRP5Code)                    AND (                          CASE WHEN @CycleModeID = 1 THEN CASE WHEN ISNULL(ACPD.CyclePeriodAdhocPayrollDefinition_ID,0)=0 THEN 1 ELSE 0 END                               WHEN @CycleModeID = 2 THEN CASE WHEN ISNULL(ACPD.CyclePeriodAdhocPayrollDefinition_ID,0)=0 THEN 0 ELSE 1 END                               ELSE 0                          END                        ) = 1              ) AS emp ON emp.EmployeeID = em.EmployeeID                /* FIX A: revised dependants aggregation */              LEFT OUTER JOIN              (                  SELECT                      dep_ed.EmployeeMedicalAIDID,  -- FIXED: take from dependants table                      SUM(CASE WHEN dep_ed.DependantType = 0 THEN 1 ELSE 0 END) AS EmployeeAdultCount,                      SUM(CASE WHEN dep_ed.DependantType = 1 THEN 1 ELSE 0 END) AS EmployeeChildCount,                      SUM(CASE WHEN dep_ed.DependantType = 0 AND dep_ed.EmployerContribute = 1 THEN 1 ELSE 0 END) AS EmployerAdultCount,                      SUM(CASE WHEN dep_ed.DependantType = 1 AND dep_ed.EmployerContribute = 1 THEN 1 ELSE 0 END) AS EmployerChildCount,                      cd.IsMaxDependantChildEnabled                  FROM [Payroll_EmployeeMedicalAIDDetail]            dep_em WITH (NOLOCK)                  JOIN [Payroll_EmployeeMedicalAIDDetailDependants]  dep_ed WITH (NOLOCK)                       ON dep_ed.EmployeeMedicalAIDID = dep_em.EmployeeMedicalAID_ID                      AND dep_ed.Enable  = 1                  JOIN [Const_MedicalAIDScheme] cs WITH (NOLOCK)                       ON cs.MedicalScheme_ID = dep_em.MedicalAidSchmeID                  CROSS APPLY (                      SELECT TOP 1                             d.MedicalSchemeID, d.StartDate, d.EndDate,                             d.IsMaxDependantChildEnabled, d.MaxDependantCount,                             d.MemberAmount, d.AdultAmount, d.ChildAmount                      FROM [Const_MedicalAIDSchemeDetail] d WITH (NOLOCK)                      WHERE d.MedicalSchemeID = cs.MedicalScheme_ID                        AND d.Enabled = 1                        AND (                              (d.StartDate <= @StartDate AND d.EndDate >= @EndDate)                           OR (d.StartDate BETWEEN @StartDate AND @EndDate)                           OR (d.EndDate   BETWEEN @StartDate AND @EndDate)                            )                      ORDER BY d.DateCaptured DESC                  ) AS cd                  WHERE dep_ed.Disabled = 0                    AND dep_ed.StartDate <= @EndDate                    AND ISNULL(dep_ed.EndDate, @StartDate) >= @StartDate                  GROUP BY dep_ed.EmployeeMedicalAIDID, cd.IsMaxDependantChildEnabled              ) AS dep ON dep.EmployeeMedicalAIDID = em.EmployeeMedicalAID_ID              /* end FIX A */                LEFT OUTER JOIN (                  SELECT                      EmployeeMedicalAIDID,                      SUM(CASE WHEN ISNULL(IsEmployerContribute,0) = 0 THEN CAST(Amount AS decimal(18,6)) ELSE CAST(0 AS decimal(18,6)) END) AS EmployeeExtraValue,                      SUM(CASE WHEN ISNULL(IsEmployerContribute,0) = 1 THEN CAST(Amount AS decimal(18,6)) ELSE CAST(0 AS decimal(18,6)) END) AS EmployerExtraValue                  FROM [Payroll_ExtraActiveMedicalAidTransaction] WITH (NOLOCK)                  WHERE [Enabled] = 1                    AND [PeriodFrom] <= @EndDate                    AND ISNULL([PeriodTo], @StartDate) >= @StartDate                  GROUP BY EmployeeMedicalAIDID              ) AS ex ON ex.EmployeeMedicalAIDID = em.EmployeeMedicalAID_ID                WHERE em.Enable = 1                AND cs.Enabled = 1                AND em.JoinDate <= @EndDate                AND ISNULL(em.TerminationDate, @StartDate) >= @StartDate;                /* Max dependant rules (unchanged) */              UPDATE E              SET                  E.EmployerAdultCount =                      CASE                          WHEN E.IsMaxDependantChildEnabled = 1 THEN E.EmployerAdultCount                          ELSE CASE WHEN (E.MaxDependantCount - E.EmployerAdultCount) < 0                                    THEN E.MaxDependantCount                                    ELSE E.EmployerAdultCount                               END                      END,                  E.EmployerChildCount =                      CASE                          WHEN E.IsMaxDependantChildEnabled = 1 AND E.EmployerChildCount > E.MaxDependantCount                              THEN E.MaxDependantCount                          WHEN E.IsMaxDependantChildEnabled = 1 AND E.EmployerChildCount <= E.MaxDependantCount                              THEN E.EmployerChildCount                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) <= 0                              THEN 0                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) >= E.EmployeeChildCount                              THEN E.EmployeeChildCount                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) <  E.EmployeeChildCount                              THEN (E.MaxDependantCount - E.EmployeeAdultCount)                      END,                  E.EmployeeChildCount =                      CASE                          WHEN E.IsMaxDependantChildEnabled = 1 AND E.EmployerChildCount > E.MaxDependantCount                              THEN E.MaxDependantCount                          WHEN E.IsMaxDependantChildEnabled = 1 AND E.EmployerChildCount <= E.MaxDependantCount                              THEN E.EmployerChildCount                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) <= 0                              THEN 0                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) >= E.EmployeeChildCount                              THEN E.EmployeeChildCount                          WHEN E.IsMaxDependantChildEnabled = 0 AND (E.MaxDependantCount - E.EmployeeAdultCount) <  E.EmployeeChildCount                              THEN (E.MaxDependantCount - E.EmployeeAdultCount)                      END              FROM @EmployeeMedicalAid E;                /* FIX B: split payments correctly */              UPDATE E              SET                  E.EmployeeValue =                        (E.EmployeeMemberValue * E.EmployeeMemberCount) * (E.EmployeePercent / 100.0)                      + (E.EmployeeAdultValue  * E.EmployerAdultCount)  * (E.EmployeePercent / 100.0)                      + (E.EmployeeAdultValue  * ISNULL(NULLIF(E.EmployeeAdultCount - E.EmployerAdultCount,0),0)) * 1.0                      + (E.EmployeeChildValue  * E.EmployerChildCount)  * (E.EmployeePercent / 100.0)                      + (E.EmployeeChildValue  * ISNULL(NULLIF(E.EmployeeChildCount - E.EmployerChildCount,0),0)) * 1.0                      + E.EmployeeExtraValue                      + (E.EmployerExtraValue  * (E.EmployeePercent / 100.0)),                    E.EmployerValue =                        (E.EmployerMemberValue * E.EmployerMemberCount) * (E.EmployerPercent / 100.0)                      + (E.EmployerAdultValue  * E.EmployerAdultCount)  * (E.EmployerPercent / 100.0)                      + (E.EmployerChildValue  * E.EmployerChildCount)  * (E.EmployerPercent / 100.0)                      + (E.EmployerExtraValue  * (E.EmployerPercent / 100.0))              FROM @EmployeeMedicalAid E;                /* Cap employer and move excess to employee */              UPDATE E              SET                  E.EmployeeValue = CAST(E.EmployeeValue AS decimal(18,6)) + (CAST(E.EmployerValue AS decimal(18,6)) - CAST(E.EmployerMaxValue AS decimal(18,6))),                  E.EmployerValue = CAST(E.EmployerMaxValue AS decimal(18,6))              FROM @EmployeeMedicalAid E              WHERE CAST(E.EmployerValue AS decimal(18,6)) > CAST(E.EmployerMaxValue AS decimal(18,6));                INSERT INTO [Payroll_EmployeeTrialPayslip]                  ([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [VendorID], [TaxYear], [SalaryHeadTitleAddendum], [ReferenceNo], [Simulation])              SELECT                  [Employee_ID],                  [PayrollDefinationID],                  CASE WHEN [TransactionTypeID] = 2 THEN CAST([EmployeeValue] AS decimal(18,6))                       ELSE CAST([EmployerValue] AS decimal(18,6))                  END,                  @Month, @SCOAYear, @PeriodID, [VendorID], @TaxYear, [Fund], ISNULL([MembershipNo], ''), @Simulation              FROM @EmployeeMedicalAid;          END      END TRY      BEGIN CATCH          INSERT INTO [Payroll_TrialErrors]              ([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])          VALUES              ('System', @PeriodID, '#' + CAST(ERROR_LINE() AS nvarchar(20)) + ' - ' + ERROR_MESSAGE(), ERROR_PROCEDURE(), 1, GETDATE(), @Simulation);      END CATCH        SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_EmployeeMedicalContribution_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employees Medical Aid Deductions (Simulation)   Update Date : 11/04/2019 => Added Employee Medical Aid Deductions (Simulation) @ Terminations   Update Date :   16/09/2019 - Artur Anzorge => Changes for employee termination  */  CREATE procedure [Payroll_EmployeeMedicalContribution_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try    begin    declare @IRP5Code table (       [IRP5Code] int not null      )      /* MEDICAL AID CONTRIBUTIONS PAID ON BEHALF OF AN EMPLOYEE [3810] */    insert into @IRP5Code([IRP5Code]) values(3810)      /* MEDICAL SERVICES COSTS [3813] */    insert into @IRP5Code([IRP5Code]) values(3813)      /* FOREIGN MEDICAL AID CONTRIBUTIONS PAID ON BEHALF OF AN EMPLOYEE [3860] */    insert into @IRP5Code([IRP5Code]) values(3860)      /* FOREIGN MEDICAL SERVICES COSTS [3863] */    insert into @IRP5Code([IRP5Code]) values(3863)      /* MEDICAL AID CONTRIBUTIONS [4005] */    insert into @IRP5Code([IRP5Code]) values(4005)      /* MEDICAL SERVICES COTS DEEMED TO BE PAID BY EMPLOYEE FOR SELF, SPOUSE OR CHILDREN [4024] */    insert into @IRP5Code([IRP5Code]) values(4024)      /* MEDICAL CONTRIBUTIONS PAID BY AN EMPLOYEE ALLOWED AS A DEDUCTION FOR EMPLOYEES' TAX (PAYE) PURPPOSES [4025] */    insert into @IRP5Code([IRP5Code]) values(4025)      /* EMPLOYER'S MEDICAL AID CONTRIBUTIONS [4474] */    insert into @IRP5Code([IRP5Code]) values(4474)      /* MEDICAL SERVICES COTS DEEMED TO BE PAID BY EMPLOYEE FOR OTHER DEPENDANTS & RELATIVE [4485] */    insert into @IRP5Code([IRP5Code]) values(4485)      /* CAPPED AMOUNT (MEDICAL AID CONTRIBUTIONS) [4486] */    insert into @IRP5Code([IRP5Code]) values(4486)      /* NO VALUE BENEFITS IN RESPECT OF MEDICAL SERVICES PROVIDED OR INCURRED BY EMPLOYER [4487] */    insert into @IRP5Code([IRP5Code]) values(4487)      /* EMPLOYER'S MEDICAL AID CONTRIBUTIONS IN RESPECT OF RETIRED EMPLOYEES */    insert into @IRP5Code([IRP5Code]) values(4493)      declare @EmployeeMedicalAid table (       [Employee_ID] int not null,     [Salary] decimal(18, 6) not null,     [SalaryHeadID] int not null,     [SalaryHeadTitle] nvarchar(256) not null,     [PayrollDefinationID] int not null,     [TransactionTypeID] int not null,     [VendorID] int null,     [Fund] nvarchar(100) not null,     [MembershipNo] nvarchar(50) null,     [IsMaxDependantChildEnabled] bit not null,     [MaxDependantCount] int not null,     [EmployeePercent] decimal(18, 6) not null,     [EmployerPercent] decimal(18, 6) not null,     [EmployerMaxValue] decimal(18, 6) not null,     [EmployeeMemberCount] int not null,     [EmployeeMemberValue] decimal(18, 6) not null,     [EmployerMemberCount] int not null,     [EmployerMemberValue] decimal(18, 6) not null,     [EmployeeAdultCount] int not null,     [EmployeeAdultValue] decimal(18, 6) not null,     [EmployerAdultCount] int not null,     [EmployerAdultValue] decimal(18, 6) not null,     [EmployeeChildCount] int not null,     [EmployeeChildValue] decimal(18, 6) not null,     [EmployerChildCount] int not null,     [EmployerChildValue] decimal(18, 6) not null,     [EmployeeExtraValue] decimal(18, 6) not null,     [EmployerExtraValue] decimal(18, 6) not null,     [EmployeeValue] decimal(18, 6) not null default(0),     [EmployerValue] decimal(18, 6) not null default(0)      )      insert into @EmployeeMedicalAid([Employee_ID], [Salary], [SalaryHeadID], [SalaryHeadTitle], [PayrollDefinationID], [TransactionTypeID], [VendorID], [Fund], [MembershipNo], [IsMaxDependantChildEnabled], [MaxDependantCount], [EmployeePercent], [EmployerPercent], [EmployerMaxValue], [EmployeeMemberCount], [EmployeeMemberValue], [EmployerMemberCount], [EmployerMemberValue], [EmployeeAdultCount], [EmployeeAdultValue], [EmployerAdultCount], [EmployerAdultValue], [EmployeeChildCount], [EmployeeChildValue], [EmployerChildCount], [EmployerChildValue], [EmployeeExtraValue], [EmployerExtraValue])       select [em].[EmployeeID], [MonthlySalary], [SalaryHead_ID], [SalaryHeadTitle], [EmployeePayrollDefinition_ID], [TransactionTypeID], [Vendor_ID], [FundName], [Reference], isnull([IsMaxDependantChildEnabled], 0), isnull([MaxDependantCount], 0), cast([EmployeeContributionValue] as decimal(18, 6)), cast([EmployerContributionValue] as decimal(18, 6)), cast([EmployerMaxContributorValue] as decimal(18, 6)), 1, ((cast([MemberAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), 1, ((cast([MemberAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), isnull([EmployeeAdultCount], 0), ((cast([AdultAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), isnull([EmployerAdultCount], 0), ((cast([AdultAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), isnull([EmployeeChildCount], 0), ((cast([ChildAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), isnull([EmployerChildCount], 0), ((cast([ChildAmount] as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), isnull(cast([EmployeeExtraValue] as decimal(18, 6)), cast(0 as decimal(18, 6))), isnull(cast([EmployerExtraValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))        from [Payroll_EmployeeMedicalAIDDetail] as [em] with(nolock)         join [Const_MedicalAIDScheme] as [cs] with(nolock) on [MedicalScheme_ID] = [em].[MedicalAidSchmeID]         cross apply (          select top 1 [MedicalSchemeID], [StartDate], [EndDate], [IsMaxDependantChildEnabled], [MaxDependantCount], [MemberAmount], [AdultAmount], [ChildAmount]           from [Const_MedicalAIDSchemeDetail] with(nolock)           where ([MedicalSchemeID] = [cs].[MedicalScheme_ID] and [Enabled] = 1 and (([StartDate] <= @StartDate and [EndDate] >= @UntilDate) or ([StartDate] between @StartDate and @UntilDate) or ([EndDate] between @StartDate and @UntilDate)))            order by [DateCaptured] desc         ) as [cd]         join [Cons_Vendor] as [ven] with(nolock) on [Vendor_ID] = [cs].[VendorID]         join (          select distinct [EPD].[EmployeeID], isnull(cast((case            when @SimulationType = 1 then (             coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)            )            when @SimulationType = 2 then (             coalesce((select [FixedSalary] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)            )            else 0           end) as decimal(18, 6)), cast(0 as decimal(18, 6))) as [MonthlySalary], [EmployeePayrollDefinition_ID], [TransactionTypeID], cast([Percentage] as decimal(18, 6)) as [Percentage], [SalaryHead_ID], [SalaryHeadTitle]           from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)            join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1            join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1            join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]            join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (             (isnull([TPS].[EmployeeChangeID], 0) = (case              when @SimulationType = 1 then @ParentID              else 0             end))             or             (isnull([TPS].[TerminationID], 0) = (case              when @SimulationType = 2 then @ParentID              else 0             end))            )            where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] in(2, 3, 4) and                     isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code))         ) as [emp] on [emp].[EmployeeID] = [em].[EmployeeID]         left outer join (          select [EmployeeMedicalAIDID], sum(case when [DependantType] = 0 then 1 else 0 end) as [EmployeeAdultCount], sum(case when [DependantType] = 0 and [EmployerContribute] = 1 then 1 else 0 end) as [EmployerAdultCount], sum(case when [DependantType] = 1 then 1 else 0 end) as [EmployeeChildCount], sum(case when [DependantType] = 1 and [EmployerContribute] = 1 then 1 else 0 end) as [EmployerChildCount]           from [Payroll_EmployeeMedicalAIDDetail] as [dep_em] with(nolock)            join [Payroll_EmployeeMedicalAIDDetailDependants] as [dep_ed] with(nolock) on [EmployeeMedicalAIDID] = [dep_em].[EmployeeMedicalAID_ID] and [dep_ed].[Enable] = 1            join [Const_MedicalAIDScheme] as [cs] with(nolock) on [MedicalScheme_ID] = [dep_em].[MedicalAidSchmeID]            cross apply (             select top 1 [MedicalSchemeID], [StartDate], [EndDate], [IsMaxDependantChildEnabled], [MaxDependantCount], [MemberAmount], [AdultAmount], [ChildAmount]              from [Const_MedicalAIDSchemeDetail] with(nolock)              where ([MedicalSchemeID] = [cs].[MedicalScheme_ID] and [Enabled] = 1 and (([StartDate] <= @StartDate and [EndDate] >= @UntilDate) or ([StartDate] between @StartDate and @UntilDate) or ([EndDate] between @StartDate and @UntilDate)))               order by [DateCaptured] desc            ) as [cd]            where ([dep_ed].[StartDate] <= @UntilDate and isnull([dep_ed].[EndDate], @StartDate) >= @StartDate)          group by [EmployeeMedicalAIDID], [IsMaxDependantChildEnabled]         ) as [dep] on [dep].[EmployeeMedicalAIDID] = [em].[EmployeeMedicalAID_ID]         left outer join (          select [EmployeeMedicalAIDID], sum(case when isnull([IsEmployerContribute], 0) = 0 then cast([Amount] as decimal(18, 6)) else cast(0 as decimal(18, 6)) end) as [EmployeeExtraValue], sum(case when isnull([IsEmployerContribute], 0) = 1 then cast([Amount] as decimal(18, 6)) else 0 end) as [EmployerExtraValue]           from [Payroll_ExtraActiveMedicalAidTransaction] with(nolock)            where ([Enabled] = 1 and [PeriodFrom] <= @UntilDate and isnull([PeriodTo], @StartDate) >= @StartDate)          group by [EmployeeMedicalAIDID]         ) as [ex] on [ex].[EmployeeMedicalAIDID] = [em].[EmployeeMedicalAID_ID]         where ([em].[Enable] = 1 and [cs].[Enabled] = 1 and [em].[JoinDate] <= @UntilDate and isnull([em].[TerminationDate], @StartDate) >= @StartDate)      /* Updating the Max Employer Dependant Counts */    update @EmployeeMedicalAid set      [EmployerAdultCount] = (       case        when [IsMaxDependantChildEnabled] = 1 then [EmployerAdultCount]        else         case          when ([MaxDependantCount] - [EmployerAdultCount]) < 0 then [MaxDependantCount]          else [EmployerAdultCount]         end       end      ),      [EmployerChildCount] = (       case        when [IsMaxDependantChildEnabled] = 1 and [EmployerChildCount] > [MaxDependantCount] then [MaxDependantCount]        else         case          when ([MaxDependantCount] - [EmployerAdultCount]) <= 0 then 0          when (([MaxDependantCount] - [EmployerAdultCount]) - [EmployerChildCount]) < 0 then ([MaxDependantCount] - [EmployerAdultCount])          else [EmployerChildCount]         end       end      )      /* Updating Employee and Employer Contributions */    update @EmployeeMedicalAid set [EmployeeValue] = ((((cast([EmployeeMemberValue] as decimal(18, 6)) * cast([EmployeeMemberCount] as decimal(18, 6))) + (cast([EmployeeAdultValue] as decimal(18, 6)) * cast([EmployeeAdultCount] as decimal(18, 6))) + (cast([EmployeeChildValue] as decimal(18, 6)) * cast([EmployeeChildCount] as decimal(18, 6)))) * cast([EmployeePercent] as decimal(18, 6))) / cast(100 as decimal(18, 6))) + cast([EmployeeExtraValue] as decimal(18, 6)), [EmployerValue] = ((((cast([EmployerMemberValue] as decimal(18, 6)) * cast([EmployerMemberCount] as decimal(18, 6))) + (cast([EmployerAdultValue] as decimal(18, 6)) * cast([EmployerAdultCount] as decimal(18, 6))) + (cast([EmployerChildValue] as decimal(18, 6)) * cast([EmployerChildCount] as decimal(18, 6)))) * cast([EmployerPercent] as decimal(18, 6))) / cast(100 as decimal(18, 6))) + cast([EmployerExtraValue] as decimal(18, 6))      /* Updating the Max Employer Contribution */    update @EmployeeMedicalAid set [EmployeeValue] = cast([EmployeeValue] as decimal(18, 6)) + (cast([EmployerValue] as decimal(18, 6)) - cast([EmployerMaxValue] as decimal(18, 6))), [EmployerValue] = cast([EmployerMaxValue] as decimal(18, 6)) where (cast([EmployerValue] as decimal(18, 6)) > cast([EmployerMaxValue] as decimal(18, 6)))      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [TransactionTypeID], [SalaryHeadID], [Employee_ID],         (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),         (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SalaryHeadTitle] + ' (' + [Fund] + ')',         (case         when [TransactionTypeID] = 2 then cast([EmployeeValue] as decimal(18, 6))         else cast([EmployerValue] as decimal(18, 6))        end)        from @EmployeeMedicalAid    end   end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeMentDetails_sp
-- Schema: dbo
-- ============================================
               -- =============================================      -- Author: MEHUL PANCHAL       -- Create date:  24 AUG 2013      -- Description:       -- [Payroll_EmployeeMentDetails_sp]  13,1,1,1,2,'2012/2013','07/22/2012','1','08/24/2013',null,null      -- 2016-10-12 Tshekedi Mogwere - Added No WITH(NOLOCK)  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_EmployeeMentDetails_sp]      @EmployeeID INT ,      @BenefitSchemeID INT ,      @PayrollDefinitionGroupID INT ,      @LeaveSchemeID INT ,      @GenderID INT ,      @FinancialYear NVARCHAR(50) ,      @EmployeeJoinDate DATETIME  AS       BEGIN       --employee payroll defination entry            IF ( @PayrollDefinitionGroupID > 0 )               BEGIN                    EXEC [Payroll_EmployeePayrollDefinition_sp] @PayrollDefinitionGroupID, @EmployeeID                  END                   IF ( @LeaveSchemeID > 0 )               BEGIN                    IF EXISTS ( SELECT  *                              FROM    Payroll_EmployeeLeaveSchemeDetails WITH(NOLOCK)                              WHERE   EmployeeID = @EmployeeID                                      AND LeaveSchemeID <> @LeaveSchemeID                                      AND IsEnabled = 1 )                       BEGIN                            UPDATE  Payroll_EmployeeLeaveSchemeDetails                          SET     IsEnabled = 0                          WHERE   EmployeeId = @EmployeeID                                  AND LeaveSchemeId <> @LeaveSchemeId                                  AND IsEnabled = 1                        END                                        UPDATE  dbo.Payroll_Employee                  SET     LeaveSchemeID = @LeaveSchemeID                  WHERE   Employee_ID = @EmployeeID              DECLARE @UserId INT      SELECT @UserId = ISNULL(ModifierID, CapturerID) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID                        EXEC [Payroll_EmployeeLeave_Calculation] @EmployeeID, @LeaveSchemeID, @UserId              END        END                     

GO

-- ============================================
-- SP: Payroll_EmployeeNetPayListRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 08 JULY 2013  -- Description: <Description,,>  -- Payroll_EmployeeNetPayListRpt_sp  -- 2015-01-12 James Roodt: Updated ISNULL checks at employee name  to conform to other checks on other stored procs  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeNetPayListRpt_sp]     AS  BEGIN    SELECT          ISNULL(PAY_EMP.EmpCode,'') AS EmpCode       ,ISNULL(PAY_EMP.FirstName+ ' ','')  + ISNULL(PAY_EMP.SecondName+ ' ','') + ISNULL(PAY_EMP.Surname,'') AS EmployeeName       ,CONST_PAY.PaymentTypeDesc       ,CONST_BANK.BankDesc       ,ISNULL(PAY_EMP.AccountNumber,'') AS AccountNumber       ,CONST_BANK_BRANCH_CODE.BankBranchCode       ,PAY_EMP.FixedSalary        ,(SELECT SUM(SUB_PAY_EMP.FixedSalary) FROM Payroll_Employee SUB_PAY_EMP       INNER JOIN  Const_PaymentType SUB_CONST_PAY           ON SUB_PAY_EMP.PaymentTypeID = SUB_CONST_PAY.PaymentType_ID) AS TOTAL        FROM Payroll_Employee PAY_EMP        INNER JOIN Const_PaymentType CONST_PAY       ON PAY_EMP.PaymentTypeID = CONST_PAY.PaymentType_ID          INNER JOIN Const_Bank CONST_BANK      ON PAY_EMP.BankID = CONST_BANK.Bank_ID            INNER JOIN Const_BankBranchCode CONST_BANK_BRANCH_CODE        ON PAY_EMP.BranchID= CONST_BANK_BRANCH_CODE.BankBranchCode_ID      END     

GO

-- ============================================
-- SP: Payroll_EmployeeNetPayslipRpt_sp
-- Schema: dbo
-- ============================================
-- =============================================    -- Author:  MEHUL PANCHAL    -- Create date: 23 JUL 2013    -- Description: <Description,,>    -- CALLS : Payroll_EmployeeNetPayslipRpt_sp 0, 0, 0, 1    -- 2015-01-12 James Roodt: Added ISNULL checks at employee name to cater for empty fields.    -- 2016-01-05 TP29885 Ravindra Jijotia: Added EmpCode in the list.    -- 2016-01-14 Suri Kandukuri : Modified Report to Balance with Remuneration Report.    -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling    -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions    -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA    --  Update date : 23/02/2018 - Add PaymentTypeID parameter and AccountHolderName field in the output and set order by CONST_PAY.PaymentTypeDesc - Himil Modi    --  Update date : 2018/04/06 - Richa Mills - Changed SP to return correct details      --  Update date : 2018/09/10 - Himil Modi - Changed SP EmpCode     --  Exec Payroll_EmployeeNetPayslipRpt_sp 0,0,0,304,1    -- Modiri : 2019/08/14 #88774 Karoo Hoogland 2 instead of 1 EFT Payment file  -- Ruan : 2022/04/07 - W80201 - Fix Query and remove Deparment and Division  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeNetPayslipRpt_sp]   @EmployeeID INT,   @PeriodId INT,   @PaymentTypeID INT,   @CycleId INT = 0  AS    BEGIN    DECLARE @LastDayinMonth VARCHAR(50) = (SELECT CONVERT(VARCHAR(50), [PeriodEndDate], 103) FROM Payroll_CyclePeriodDetails WHERE [Period_ID] = @PeriodId);    SELECT   emp.[EmpCode],   dbo.BufferString_fxn(CONVERT(VARCHAR, emp.[Employee_ID]), 8,'0') AS 'EmpNo',   CONCAT(emp.[FirstName], ' ', emp.[Surname]) AS 'EMPLOYEENAME',   emp.[AccountNumber],   pt.[PaymentTypeDesc],   emp.[Employee_ID],   b.[BankDesc],   act.[AccountDesc],   bb.[BankBranchCode],   ISNULL(p.[Earning], 0) - ISNULL(p.[Deduction], 0) AS 'NET',   @LastDayinMonth AS 'LastDayInMonth',   emp.[AccountHolderName]  FROM   Payroll_Employee emp  INNER JOIN   Const_PaymentType pt ON emp.[PaymentTypeID] = pt.[PaymentType_ID]  CROSS APPLY   (    SELECT     *    FROM     (      SELECT       pt.[EmployeeID],       CASE WHEN pt.[TransactionTypeID] = 1 THEN 'Earning' ELSE 'Deduction' END AS 'TransactionType',       SUM(pt.[Amount]) AS 'Amount'      FROM       Payroll_PayrollResults pt      WHERE       pt.[EmployeeID] = emp.[Employee_ID]      AND pt.[TransactionTypeID] IN (1, 2)      AND pt.[TaxSavePurpose] = 0      AND pt.[PeriodID] = @PeriodId      AND (pt.[CycleID] = @CycleId OR @CycleId = 0)      GROUP BY       pt.[EmployeeID],       CASE WHEN pt.[TransactionTypeID] = 1 THEN 'Earning' ELSE 'Deduction' END     ) t     PIVOT     (      SUM([Amount])      FOR [TransactionType] IN ([Earning], [Deduction])     ) pvt   ) p  LEFT JOIN   Const_AccountType act ON emp.[AccountTypeID] = act.[AccountType_ID]  LEFT JOIN   Const_Bank b ON emp.[BankID] = b.[Bank_ID]  LEFT JOIN   Const_BankBranchCode bb ON emp.[BranchID] = bb.[BankBranchCode_ID]  WHERE   (emp.[Employee_ID] = @EmployeeID OR @EmployeeID = 0)  AND (emp.[PaymentTypeID] = @PaymentTypeID OR @PaymentTypeID = 0)  ORDER BY   [EmpNo], pt.[PaymentTypeDesc];      END

GO

-- ============================================
-- SP: Payroll_EmployeeNetPayslipRptTrial_sp
-- Schema: dbo
-- ============================================
    -- =============================================        -- Author:  MarioT 2015/05/28 Same as Payroll_EmployeeNetPayslipRpt_sp but using Trial Run        -- 2015-01-12 James Roodt: Added ISNULL checks at employee name to cater for empty fields.        -- 2015-11-18 : TP28407 : Suri Kandukuri : Modified the Payroll_EmployeePayslip to Payroll_EmployeeTrialPayslip        -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling        -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions        -- Update date : 16/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA      -- Update date : 2018/02/12 - Richa Mills - Changed SP to return correct details    -- Exec Payroll_EmployeeNetPayslipRptTrial_sp 8,0,0,305,17   -- 11/Feb/2019 -- Himil Modi- #84440 Nett Pay list -- Add new paramater of paymenttypeID and pass into where condition.  -- 30 March 2019 - Ferdi Botha - Removed Period retreiving from Payroll_CyclePeriodDetails  -- Ruan : 2022/04/07 - W80201 - Fix Query and remove Deparment and Division  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeNetPayslipRptTrial_sp]   @EmployeeID INT,   @PeriodId INT = 0,   @PaymentTypeID INT,   @CycleId INT = 0  AS          BEGIN       DECLARE @LastDayinMonth VARCHAR(50) = (SELECT CONVERT(VARCHAR(50), [PeriodEndDate], 103) FROM Payroll_CyclePeriodDetails WHERE [Period_ID] = @PeriodId);    SELECT   emp.[EmpCode],   dbo.BufferString_fxn(CONVERT(VARCHAR, emp.[Employee_ID]), 8,'0') AS 'EmpNo',   CONCAT(emp.[FirstName], ' ', emp.[Surname]) AS 'EMPLOYEENAME',   emp.[AccountNumber],   pt.[PaymentTypeDesc],   emp.[Employee_ID],   b.[BankDesc],   act.[AccountDesc],   bb.[BankBranchCode],   ISNULL(p.[Earning], 0) - ISNULL(p.[Deduction], 0) AS 'NET',   @LastDayinMonth AS 'LastDayInMonth',   emp.[AccountHolderName]  FROM   Payroll_Employee emp  INNER JOIN   Const_PaymentType pt ON emp.[PaymentTypeID] = pt.[PaymentType_ID]  CROSS APPLY   (    SELECT     *    FROM     (      SELECT       pt.[EmployeeID],       CASE WHEN pt.[TransactionTypeID] = 1 THEN 'Earning' ELSE 'Deduction' END AS 'TransactionType',       SUM(pt.[Amount]) AS 'Amount'      FROM       Payroll_TrialResults pt      WHERE       pt.[EmployeeID] = emp.[Employee_ID]      AND pt.[TransactionTypeID] IN (1, 2)      AND pt.[TaxSavePurpose] = 0      AND pt.[PeriodID] = @PeriodId      AND (pt.[CycleID] = @CycleId OR @CycleId = 0)      GROUP BY       pt.[EmployeeID],       CASE WHEN pt.[TransactionTypeID] = 1 THEN 'Earning' ELSE 'Deduction' END     ) t     PIVOT     (      SUM([Amount])      FOR [TransactionType] IN ([Earning], [Deduction])     ) pvt   ) p  LEFT JOIN   Const_AccountType act ON emp.[AccountTypeID] = act.[AccountType_ID]  LEFT JOIN   Const_Bank b ON emp.[BankID] = b.[Bank_ID]  LEFT JOIN   Const_BankBranchCode bb ON emp.[BranchID] = bb.[BankBranchCode_ID]  WHERE   (emp.[Employee_ID] = @EmployeeID OR @EmployeeID = 0)  AND (emp.[PaymentTypeID] = @PaymentTypeID OR @PaymentTypeID = 0)  ORDER BY   [EmpNo], pt.[PaymentTypeDesc];    END

GO

-- ============================================
-- SP: Payroll_EmployeeNoLeaveTakenRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL   -- Create date: 05 AUG 2013  -- Description:EMPLOYEE WISE LEAVE TRANSACTION  --call :Payroll_EmployeeNoLeaveTakenRpt_sp '01 Jun 2014', '30 Jun 2014', 0, 0, 0  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling  -- 2016-04-06 TP32628 Ravindra Jijotia: Added LeaveTypeId filter  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2020/01/08 Modiri WI24390  -- 2021/10/25 Ruan WI77848  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeNoLeaveTakenRpt_sp]      @FromDate DATETIME ,      @ToDate DATETIME ,      @DepartmentId INT ,      @CycleId INT,    @LeaveTypeId INT  AS   BEGIN   SELECT    emp.*,    tkn.[StartDate],    tkn.[EndDate],    ISNULL(tkn.[Value], 0) AS 'leaveTaken'   FROM    (     SELECT      dbo.BufferString_fxn(CONVERT(VARCHAR,(e.[Employee_ID])), 8, '0') AS 'EmpNo',      e.[EmpCode],      CONCAT(e.[FirstName], ' ', e.[Surname]) AS 'EmpName',      pap.[LeaveTypeID] AS 'LeaveType_ID',      lt.[LeaveType],      e.[Employee_ID]     FROM      Payroll_Employee e     INNER JOIN        Payroll_PositionHistory ph ON e.[Employee_ID] = ph.[EmployeeID]              AND e.[JobProfileID] = ph.[JobProfileID]              AND @FromDate BETWEEN ph.[StartDate] AND ph.[EndDate]              AND (ISNULL(@DepartmentId, 0) = 0 OR ph.[DepartmentID] = @DepartmentId)     INNER JOIN      Const_LeaveSchemeTypeDetails lstd ON e.[LeaveSchemeID] = lstd.[LeaveSchemeId]               AND lstd.[Enabled] = 1     INNER JOIN      Const_AbsenceType cat ON lstd.[LeaveTypeId] = cat.[AbsenceType_ID]     INNER JOIN      Payroll_AbsencePriority pap ON cat.[AbsenceType_ID] = pap.[AbsenceTypeID]     LEFT JOIN      Const_LeaveTypeDetails ltd ON pap.[LeaveTypeID] = ltd.[LeaveTypeId]     LEFT JOIN      Const_LeaveType lt ON ltd.[LeaveTypeId] = lt.[LeaveType_ID]     LEFT JOIN      Payroll_EmployeeLeaveBalance elb ON e.[Employee_ID] = elb.[EmployeeID]              AND pap.[LeaveTypeId] = elb.[LeaveTypeID]     LEFT JOIN      Payroll_EmployeeTermination et ON e.[Employee_ID] = et.[EmployeeID]     WHERE      (ISNULL(@CycleId, 0) = 0 OR e.[CycleID] = @CycleId)     AND et.[EmployeeTermination_ID] IS NULL     AND (ISNULL(@LeaveTypeId, 0) = 0 OR pap.[LeaveTypeID] = @LeaveTypeId)    ) emp   LEFT JOIN    (     SELECT      *     FROM      Payroll_EmployeeLeaveTransactions elt     WHERE      elt.[LeaveAdjustmentTypeID] = 3     AND elt.[StartDate] >= @FromDate     AND elt.[StartDate] <= @ToDate    ) tkn ON emp.[Employee_ID] = tkn.[EmployeeID]      AND emp.[LeaveType_ID] = tkn.[LeaveTypeID]   WHERE    ISNULL(tkn.[Value], 0) = 0   ORDER BY    emp.[Employee_ID], emp.[LeaveType_ID]  END

GO

-- ============================================
-- SP: Payroll_EmployeeOverTimeCalculation_Trial_sp
-- Schema: dbo
-- ============================================
/*   Author  : Lungisani Khumalo   Create date : 09/03/2017   Description : Calculates Employees Over Time   Update date : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings   Update date :   19/07/2019 - Correctional Transactions for Overtime  */  CREATE procedure [dbo].[Payroll_EmployeeOverTimeCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      declare @IRP5Code table (       [IRP5Code] int not null      )      /* INCOME - TAXABLE [3601] */    insert into @IRP5Code([IRP5Code]) values(3601)      /* OVERTIME [3607] */    insert into @IRP5Code([IRP5Code]) values(3607)      /* FOREIGN INCOME - TAXABLE [3651] */    insert into @IRP5Code([IRP5Code]) values(3651)      /* FOREIGN OVERTIME [3657] */    /*insert into @IRP5Code([IRP5Code]) values(3657)*/      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [TaxYear], [ReferenceNo],[Simulation])       select [PE].[Employee_ID], [EmployeePayrollDefinition_ID], sum(cast(isnull(cast([TotalAmount] as decimal(18, 6)), ((((isnull(cast([OverTimeHour] as decimal(18, 6)), cast(0 as decimal(18, 6))) * isnull(cast([OT].[Rate] as decimal(18, 6)), cast(1 as decimal(18, 6)))) * (isnull(cast([FixedSalary] as decimal(18, 6)), cast(0 as decimal(18, 6))) / isnull(cast([WHPM_Monthly] as decimal(18, 6)), cast(1 as decimal(18, 6))))) * isnull(cast([Percentage] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6)))) as decimal(18, 6))), @Month, @SCOAYear, @PeriodID, [SalaryHeadName], @TaxYear, cast(sum(isnull([OverTimeHour], 0)) as nvarchar) + ' Hour(s)', @Simulation        from [Payroll_EmployeeOverTime] as [OT] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [OT].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SalaryHead_ID] = [OT].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([OT].[EmployeeID] = (case @EmployeeID when 0 then [OT].[EmployeeID] else @EmployeeID end)        and [OT].[Enabled] = 1        and isnull([OT].[ExcludeFromPayment], 0) = 0        and isnull([OT].[Processed], 0) = 0       and [OverTimeDate] <= @EndDate        and (([OverTimeDate] >= @StartDate and [OT].[PeriodID] = @PeriodID)        or ([OverTimeDate] >= datefromparts(year(dateadd(m, -2, @StartDate)), month(dateadd(m, -2, @StartDate)), 1))        or (IsCorrection = 1))       and [TransactionTypeID] = 1        and (case        when isnull([IsApprovalRequired], 0) = 0 then 1        when isnull([IsApprovalRequired], 0) = 1 and isnull([IsApproved], 0) = 1 then 1        else 0 end       ) = 1        and isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code)        and not [SalaryHead_ID] = 1        and (case        when @CycleModeID = 1 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end        when @CycleModeID = 2 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end        else 0 end       ) = 1      )         group by [PE].[Employee_ID], [EmployeePayrollDefinition_ID], [SalaryHeadName], [OT].[SalaryHeadID]   end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeOverTimeCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Create date : 09/03/2017   Description : Calculates Employee Over Time (Simulation)   Update Date : 11/04/2019 => Added Employee Over Time (Simulation) @ Terminations  */  CREATE procedure [Payroll_EmployeeOverTimeCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      declare @IRP5Code table (       [IRP5Code] int not null      )      /* INCOME - TAXABLE [3601] */    insert into @IRP5Code([IRP5Code]) values(3601)      /* OVERTIME [3607] */    /*insert into @IRP5Code([IRP5Code]) values(3607)*/      /* FOREIGN INCOME - TAXABLE [3651] */    insert into @IRP5Code([IRP5Code]) values(3651)      /* FOREIGN OVERTIME [3657] */    /*insert into @IRP5Code([IRP5Code]) values(3657)*/      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle] + ' (' + cast(sum(isnull([OverTimeHour], 0)) as nvarchar) + ' Hour(s))',        sum(cast(isnull(cast([TotalAmount] as decimal(18, 6)), ((((isnull(cast([OverTimeHour] as decimal(18, 6)), cast(0 as decimal(18, 6))) * isnull(cast([OT].[Rate] as decimal(18, 6)), cast(1 as decimal(18, 6)))) * (isnull(cast(cast((case          when @SimulationType = 1 then (           isnull([EC].[RPH_Monthly], isnull([EC].[RPH_Other], 0))          )          when @SimulationType = 2 then (           isnull([PE].[RPH_Monthly], isnull([PE].[RPH_Other], 0))          )          else 0         end) as decimal(18, 6)) as decimal(18, 6)), cast(0 as decimal(18, 6))) / isnull(cast(cast((case          when @SimulationType = 1 then (           isnull([EC].[WHPM_Monthly], 0)          )          when @SimulationType = 2 then (           isnull([PE].[WHPM_Monthly], 0)          )          else 0         end) as decimal(18, 6)) as decimal(18, 6)), cast(1 as decimal(18, 6))))) * isnull(cast([Percentage] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6)))) as decimal(18, 6)))        from [Payroll_EmployeeOverTime] as [OT] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [OT].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SalaryHead_ID] = [OT].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )         left outer join [Payroll_EmployeeChange] as [EC] with(nolock) on [EC].[EmployeeID] = [OT].[EmployeeID] and [EC].[EmployeeChange_ID] = @ParentID        where ([OT].[EmployeeID] = @EmployeeID and [OT].[Enabled] = 1 and isnull([OT].[ExcludeFromPayment], 0) = 0 and [TransactionTypeID] = 1 and [OverTimeDate] >= @StartDate and [OverTimeDate] <= @UntilDate and         (case          when isnull([IsApprovalRequired], 0) = 0 then 1          when isnull([IsApprovalRequired], 0) = 1 and isnull([IsApproved], 0) = 1 then 1          else 0 end) = 1 and         isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code) and not [SalaryHead_ID] = 1)         group by [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID], [SH].[SalaryHeadTitle]         having ((sum((isnull([TotalAmount], isnull([OverTimeHour], 0) * isnull([OT].[Rate], 1)) * isnull([Percentage], 0)) / 100)) > 0)     end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeOverTimeRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 23 JUL 2013  -- Description:  GET EMPLOYEE OVER TIME  -- calls : Payroll_EmployeeOverTimeRpt_sp '06/01/2013','06/30/2013'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeOverTimeRpt_sp]    @FromDate DATETIME,   @ToDate DATETIME     AS  BEGIN       DECLARE @DisplayFields nvarchar(MAX)   DECLARE @TotalDates nvarchar(max)    SET @TotalDates = ''      SET @TotalDates = (SELECT dbo.DaysInMonthYear(@FromDate,@ToDate,2))      SET @DisplayFields= ' with BaseQuery AS(    SELECT     ISNULL(PAY_EMP.FirstName,'' '') + '' '' + ISNULL(PAY_EMP.SecondName,'' '') + '' ''+ ISNULL(PAY_EMP.Surname,'' '') AS EmployeeName      , PAY_EMP_OVR.OverTimeHour,CONVERT(NVARCHAR,PAY_EMP_OVR.OverTimeDate,103) AS OverTimeDate    FROM Payroll_Employee PAY_EMP    INNER JOIN Payroll_EmployeeOverTime PAY_EMP_OVR      ON PAY_EMP_OVR.EmployeeID = PAY_EMP.Employee_ID )        SELECT EmployeeName,'+ @TotalDates + ' FROM BaseQuery    PIVOT (ISNULL(min(OverTimeHour),0) FOR OverTimeDate in    (' + @TotalDates + ')    )AS PVT '  PRINT @DisplayFields  EXECUTE (@DisplayFields)     END     

GO

-- ============================================
-- SP: Payroll_EmployeePayrollDefinition_sp
-- Schema: dbo
-- ============================================
    -- =============================================    -- Author:  MEHUL PANCHAL    -- Create date:  13 AUG 2013    -- Description: <Description,,>    -- [Payroll_EmployeePayrollDefinition_sp] 5,125    -- 2015-02-02 James Roodt: Added IsRFI (Pensinable) flag to be copied as well  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeePayrollDefinition_sp]       @PayrollDefinitionGroupID INT,      @EmployeeID INT    AS    BEGIN         DECLARE @OldPayrollDefinitionGroupID INT     SELECT @OldPayrollDefinitionGroupID = ISNULL(PayrollDefinitionGroupID, 0) FROM Payroll_Employee WHERE Employee_ID = @EmployeeID     PRINT @OldPayrollDefinitionGroupID     IF(@PayrollDefinitionGroupID = @OldPayrollDefinitionGroupID)     BEGIN      DECLARE @cnt INT      -- simply check if at least one of the 25 pre-defined rules have been applied. if so the rest must be fine.    Select @cnt = COUNT(1) FROM dbo.Payroll_EmployeePayrollDefinition WHERE EmployeeID = @EmployeeID AND Enabled = 1 AND CustomAction = 0      IF(@cnt > 0)      BEGIN       RETURN       END     END         IF((SELECT COUNT(1) FROM [Payroll_EmployeePayrollDefinition] WHERE EmployeeID = @EmployeeID AND [Enabled] = 1) > 0)     BEGIN      DECLARE @DATABASENAME NVARCHAR(50)      DECLARE @SQLQuery NVARCHAR(MAX)      SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'          SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_EmployeePayrollDefinition       (        AuditUserID , AuditDate , AuditUser , EmployeePayrollDefinition_ID , PayrollSalaryHeadID ,        FunctionCodeID , SCOACostingID , SCOAFundsID , SCOAProjectID , SCOARegionID,        Percentage, EmployeeID , Enabled , DateCaptured , CapturerID , DateModified ,         ModifierID , CustomAction, IsRFI , RepeateEveryYear, SCOAItemID       )       SELECT         1, GETDATE(), ''Admin User'', EmployeePayrollDefinition_ID, PayrollSalaryHeadID,         FunctionCodeID, SCOACostingID , SCOAFundsID , SCOAProjectID , SCOARegionID,        Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, DateModified,         ModifierID, CustomAction, IsRFI, RepeateEveryYear, SCOAItemID       FROM Payroll_EmployeePayrollDefinition       WHERE CustomAction = 0 AND Enabled = 1 AND EmployeeID = ' + CONVERT(NVARCHAR(50), @EmployeeID)              EXEC(@SQLQuery)            UPDATE [Payroll_EmployeePayrollDefinition] SET [Enabled] = 0 WHERE EmployeeID = @EmployeeID AND CustomAction = 0     END         INSERT INTO [Payroll_EmployeePayrollDefinition](                      [EmployeeID]          ,[PayrollSalaryHeadID]          ,[FunctionCodeID]          ,SCOAItemID          ,SCOACostingID          ,SCOAFundsID          ,SCOAProjectID          ,SCOARegionID       ,IsRFI        ,[Percentage]          ,[CustomAction]          ,[Enabled]          ,[DateCaptured]          ,[CapturerID])            SELECT      @EmployeeID           ,[PayrollSalaryHeadID]           ,[FunctionCodeID]           ,SCOAItemID           ,SCOACostingID           ,SCOAFundsID           ,SCOAProjectID           ,SCOARegionID        ,IsRFI         ,[Percentage]        ,0           ,1           ,GETDATE()           ,1        FROM PAYROLL_PAYROLLDEFINATION        WHERE PayrollDefinitionGroupID = @PayrollDefinitionGroupID            END         

GO

-- ============================================
-- SP: Payroll_EmployeePayrollDefinitions_sp
-- Schema: dbo
-- ============================================
  -- ======================================================================================================  -- Author: MEHUL PANCHAL    -- Create date: 28 JAN 2014    -- Description: GET PAYROLL LIST     -- Execute [Payroll_EmployeePayrollDefinationlst_sp] 00000015    -- 2015-12-22 : Suri Kandukuri : TP29886 Added Enabled Condition for Salary Head.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-04-08 TP34966 James Roodt: Added ActiveTaxYear to where clause  -- 2016-06-14 TP37484 Seipei Mathole: Changed Inner join to Left join on CSS.ScoaID = PAY_DEF.SCOAItemID   -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2016-12-07 TP48989 - remove Commission and VAT on Commission  -- Update date : 12/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings  -- Update date : 08/03/2018 - Updated checks to verify Payslip values if a Trial / Final has been executed  -- Update date : 28/03/2018 - Updated checks to include Definitions not included in Trial / Final mappings  --  Update date : 29/10/2018 - Updated checks to Type : 1 (trial),  2 (final)  --  Update date : 06/12/2018 - Updated checks to default Type to 1 and default the PeriodID to the last processing period, including resolving the procedure - FERDI BOTHA  -- ======================================================================================================  /*     Developer: Modiri Selao   Date: 2019/04/29   Reason :TP #87717 Emalahleni - Retirement Funding Indicator - Calculation of Pension fund Contributions   SP was looking at the incorrect [IsRFI] table column. Changed it to read the Payroll_SalaryHead column is the one that get updated on the payroll settings page.    */  CREATE procedure [dbo].[Payroll_EmployeePayrollDefinitions_sp] @EmployeeID int, @PeriodID int = null, @type int = 1  as    begin     set nocount on;     /*@CommID int = (select [SalaryHead_ID] from [Payroll_SalaryHead] where ([SalaryHeadTitle] = 'Commission Earned')),   @VatCommID int = (select [SalaryHead_ID] from [Payroll_SalaryHead] where ([SalaryHeadTitle] = 'Tax on Commission Earned')),*/     declare @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))      declare @results table (      [EmployeePayrollDefinition_ID] int,    [TransactionType] nvarchar(50),    [SalaryHeadID] INT,    [SalaryHeadTitle] nvarchar(max),    [PayrollSalaryHeadName] nvarchar(max),    [FunctionNumber] nvarchar(50),    [Percentage] decimal(18, 2),    [TransactionTypeID] int,    [Amount] decimal(18, 2),    [Pensionable] nvarchar(10),    [Taxable] nvarchar(10),    [TaxablePercentage] decimal(18, 2),    [IRP5Code] nvarchar(10),    [PeriodID] int,    [Flag] nvarchar(10)     )     if (@Type = 1)   begin      declare @CycleID int = (select [CycleID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))      declare @EmployeeTypeId int = (select [EmployeeTypeID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))      declare @isUpperLimit bit      if @EmployeeTypeId in (2,3,7)     set @isUpperLimit = 1    else      set @isUpperLimit = 0      --set @PeriodID = (select top 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = @CycleID and [TaxYear] = @ActiveTaxYear) order by [Period_ID] asc)      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID],[SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle],            CASE WHEN TransactionTypeID in (1,3) THEN       CASE WHEN @isUpperLimit = 1 THEN [SCOAES].ScoaCode else [SCOA1].[ScoaCode] end     else [SCOA].[ScoaShortDesc] end,          [Percentage], [TransactionType_ID], isnull([TP].[Amount], 0), (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), isnull([PeriodID], @PeriodID), 'Trial'        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA1] with(nolock) on [Scoa1].[ScoaID] = [ScoaItemIDPermanentStaff] and [SCOA1].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         left outer join [Payroll_EmployeeTrialPayslip] as [TP] with(nolock) on [TP].[PayrollDefinationID] = [EPD].[EmployeePayrollDefinition_ID] and [TP].[PeriodID] = @PeriodID         left outer join [Payroll_EmployeeSalaryTransaction] as [ES] with (nolock) on [SH].[SalaryHead_ID] = [ES].[SalaryHeadId] and [ES].[EmployeeId] = @EmployeeID         left outer join [Const_SCOA_Structure] as [SCOAES] with(nolock) on [SCOAES].[ScoaID] = [ES].[GLScoaItem] and [SCOAES].[Enabled] = 1        where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID and [TaxSavePurpose] = 0)      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc],           [SalaryHeadTitle],           CASE WHEN TransactionTypeID in (1,3) THEN SCOA1.ScoaCode else [Scoa].[ScoaShortDesc] end,             [Percentage], [TransactionType_ID], 0, (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Trial'        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA1] with(nolock) on [Scoa1].[ScoaID] = [ScoaItemIDPermanentStaff] and [SCOA1].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID and not [EmployeePayrollDefinition_ID] in (          select [EmployeePayrollDefinition_ID] from @results            )        )     end   else   begin      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle],           CASE WHEN TransactionTypeID in (1,3) THEN [SCOA1].[ScoaCode] else [SCOA].[ScoaShortDesc] end,        [Percentage],           [TransactionType_ID], isnull([Amount], 0), (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), isnull([EPDF].[PeriodID], @PeriodID), 'Final'        from [Payroll_EmployeePayrollDefinitionFinal] as [EPDF] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPDF].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [EPDF].[PeriodID] = @PeriodID         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA1] with(nolock) on [Scoa1].[ScoaID] = [ScoaItemIDPermanentStaff] and [SCOA1].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         left outer join [Payroll_EmployeePayslip] as [TP] with(nolock) on [TP].[PayrollDefinationID] = [EPDF].[EmployeePayrollDefinition_ID] and [TP].[PeriodID] = @PeriodID        where ([EPDF].[Enabled] = 1 and [EPDF].[EmployeeID] = @EmployeeID and [TaxSavePurpose] = 0)      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc],           [SalaryHeadTitle],           CASE WHEN TransactionTypeID in (1,3) THEN [SCOA1].[ScoaCode] else [SCOA].[ScoaShortDesc] end,            [Percentage], [TransactionType_ID], 0, (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Final'        from [Payroll_EmployeePayrollDefinitionFinal] as [EPDF] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPDF].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [EPDF].[PeriodID] = @PeriodID         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA1] with(nolock) on [Scoa1].[ScoaID] = [ScoaItemIDPermanentStaff] and [SCOA1].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        where ([EPDF].[Enabled] = 1 and [EPDF].[EmployeeID] = @EmployeeID and not [EmployeePayrollDefinition_ID] in (          select [EmployeePayrollDefinition_ID] from @results         )        )     end     select [EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], sum([Amount]) as [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag]      from @results     group by [EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag]      order by [IRP5Code]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeePayrollDefinitionsIRP5Code_sp
-- Schema: dbo
-- ============================================
  create procedure [Payroll_EmployeePayrollDefinitionsIRP5Code_sp] @EmployeeID int, @IRP5Code int  as    begin     declare @PayrollDefinitionID int = 0     declare @payrollDefinitions table (      [EmployeePayrollDefinition_ID] int,    [TransactionType] nvarchar(50),    [SalaryHeadTitle] nvarchar(max),    [PayrollSalaryHeadName] nvarchar(max),    [FunctionNumber] nvarchar(50),    [Percentage] decimal(18, 2),    [TransactionTypeID] int,    [Amount] decimal(18, 2),    [Pensionable] nvarchar(10),    [Taxable] nvarchar(10),    [TaxablePercentage] decimal(18, 2),    [IRP5Code] int,    [PeriodID] int,    [Flag] nvarchar(10)     )     insert into @payrollDefinitions exec [Payroll_EmployeePayrollDefinitions_sp] @EmployeeID, null, 1      select top 1 @PayrollDefinitionID = [EmployeePayrollDefinition_ID] from @payrollDefinitions where ([IRP5Code] = @IRP5Code)     select @PayrollDefinitionID as [PayrollDefinitionID]    end  

GO

-- ============================================
-- SP: Payroll_EmployeePayslip_sp
-- Schema: dbo
-- ============================================
   /*   Author  : FERDI BOTHA   Create date : 21/04/2017   Description : Returns the Payslip View (items)   Update date : 12/05/2017 - Changed the mappings for Method of Calculation     Modified : Richa M 2026/01/26 - Fix Units for Overtime     Payroll_EmployeePayslip_sp 815,100,1,'2025/2026','Trial',0    */  CREATE procedure [dbo].[Payroll_EmployeePayslip_sp] @EmployeeId int, @PeriodID int, @CycleID int, @FinancialYear nvarchar(50), @PayslipType nvarchar(50), @Simulation bit  as    begin     set nocount on;     declare @PayslipView table  (      [TransactionTypeDesc] nvarchar(200) not null,    [TransactionTypeDesc1] nvarchar(max) not null,    [Employee] nvarchar(max) not null,    [Month] nvarchar(max) not null,    [Amount] decimal(18,2) not null default(0),    [IRP5Code] nvarchar(50) not null     )     if (@PayslipType = 'Final')   begin      insert into @PayslipView([TransactionTypeDesc], [TransactionTypeDesc1], [Employee], [Month], [Amount], [IRP5Code])       select [CTT].[TransactionTypeDesc], (case         when [SH].[SalaryHeadTitle] = [TP].[SalaryHeadTitleAddendum] and len([TP].[ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [TP].[ReferenceNo] + ')'         when [SH].[SalaryHeadTitle] = [TP].[SalaryHeadTitleAddendum] and len([TP].[ReferenceNo]) = 0 then [SH].[SalaryHeadTitle]         when [IRP5].[IRP5Code] = 3607  and len([TP].[ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [TP].[ReferenceNo] + ')'         else [SH].[SalaryHeadTitle] + isnull(' (' + [TP].[SalaryHeadTitleAddendum] + ')', '')        end) as [TransactionTypeDesc1], min(isnull([PE].[FirstName], '') + ' ' + isnull([PE].[Surname], '')) as [Employee], min([TP].[Month]) as [Month], sum([TP].[Amount]) as [Amount], min([IRP5].[IRP5Code]) as [IRP5Code]       from [Payroll_EmployeePayslip] as [TP] with(nolock)        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID]/* and [EPD].[Enabled] = 1*/        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]/* and [SH].[Enabled] = 1*/        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId]/* and [IRP5].[Enabled] = 1*/        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID]/* and [CTT].[Enabled] = 1*/       where ([TP].[EmployeeID] = @EmployeeId and [TP].[PeriodID] = @PeriodID and [TP].[TaxYear] = @FinancialYear and [TP].[TaxSavePurpose] = 0 and [SH].[IsGroup] = 0)        group by [CTT].[TransactionTypeDesc], [SH].[SalaryHeadTitle], [TP].[SalaryHeadTitleAddendum], [TP].[ReferenceNo],[IRP5].[IRP5Code]      insert into @PayslipView([TransactionTypeDesc], [TransactionTypeDesc1], [Employee], [Month], [Amount], [IRP5Code])       select [CTT].[TransactionTypeDesc], min([IRP5].[IRP5CodeDesc]) as [TransactionTypeDesc1], min(isnull([PE].[FirstName], '') + ' ' + isnull([PE].[Surname], '')) as [Employee], min([TP].[Month]) as [Month], sum([TP].[Amount]) as Amount, [IRP5].[IRP5Code]       from [Payroll_EmployeePayslip] as [TP] with(nolock)        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID]/* and [EPD].[Enabled] = 1*/        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]/* and [SH].[Enabled] = 1*/        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId]/* and [IRP5].[Enabled] = 1*/        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID]/* and [CTT].[Enabled] = 1*/       where ([TP].[EmployeeID] = @EmployeeId and [TP].[PeriodID] = @PeriodID and [TP].[TaxYear] = @FinancialYear and [TP].[TaxSavePurpose] = 0 and [SH].[IsGroup] = 1)        group by [IRP5].[IRP5Code], [CTT].[TransactionTypeDesc]     end   else   begin       insert into @PayslipView([TransactionTypeDesc], [TransactionTypeDesc1], [Employee], [Month], [Amount], [IRP5Code])       select [CTT].[TransactionTypeDesc], (case         when [SH].[SalaryHeadTitle] = [TP].[SalaryHeadTitleAddendum] and len([TP].[ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [TP].[ReferenceNo] + ')'         when [SH].[SalaryHeadTitle] = [TP].[SalaryHeadTitleAddendum] and len([TP].[ReferenceNo]) = 0 then [SH].[SalaryHeadTitle]         when [IRP5].[IRP5Code] = 3607  and len([TP].[ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [TP].[ReferenceNo] + ')'         else [SH].[SalaryHeadTitle] + isnull(' (' + [TP].[ReferenceNo] + ')', '')        end) as [TransactionTypeDesc1], min(isnull([PE].[FirstName], '') + ' ' + isnull([PE].[Surname], '')) as [Employee], min([TP].[Month]) as [Month], sum([TP].[Amount]) as [Amount], min([IRP5].[IRP5Code]) as [IRP5Code]       from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1       where ([TP].[EmployeeID] = @EmployeeId and [TP].[PeriodID] = @PeriodID and [TP].[TaxYear] = @FinancialYear and [TP].[TaxSavePurpose] = 0 and [SH].[IsGroup] = 0 and [TP].[Simulation] = @Simulation)        group by [CTT].[TransactionTypeDesc], [SH].[SalaryHeadTitle], [TP].[SalaryHeadTitleAddendum], [TP].[ReferenceNo],[IRP5].[IRP5Code]      insert into @PayslipView([TransactionTypeDesc], [TransactionTypeDesc1], [Employee], [Month], [Amount], [IRP5Code])       select [CTT].[TransactionTypeDesc], min([IRP5].[IRP5CodeDesc]) as [TransactionTypeDesc1], min(isnull([PE].[FirstName], '') + ' ' + isnull([PE].[Surname], '')) as [Employee], min([TP].[Month]) as [Month], sum([TP].[Amount]) as [Amount], [IRP5].[IRP5Code]       from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1       where ([TP].[EmployeeID] = @EmployeeId and [TP].[PeriodID] = @PeriodID and [TP].[TaxYear] = @FinancialYear and [TP].[TaxSavePurpose] = 0 and [SH].[IsGroup] = 1 and [TP].[Simulation] = @Simulation)        group by [IRP5].[IRP5Code], [CTT].[TransactionTypeDesc]         end     select [TransactionTypeDesc], [TransactionTypeDesc1], [Employee], [Month], [Amount] from @PayslipView /*where ([Amount] >= 0)*/     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeePlainPaperPayslipRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 23 jul 2013  -- Description: <Description,,>  -- CALLS : Payroll_EmployeePlainPaperPayslipRpt_sp 1, 0, 229  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt: Added ISNULL checks at employee name and address to cater for empty fields.  -- 2015-03-30 James Roodt: Removed percentage multiplier on the amount  -- 2015-05-19 TP19714 James Roodt: Added SalaryHeadTitleAddendum to be appended to PayrollSalaryHeadTitle  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_EmployeePlainPaperPayslipRpt_sp]   @EmployeeID INT,   @DepartmentId INT,   @PeriodId INT   AS  BEGIN   DECLARE @FROMDATE DATETIME, @CycleId INT   DECLARE @TODATE DATETIME, @TaxYear NVARCHAR(10)   SELECT  @FROMDATE = PeriodStartDate, @TODATE = PeriodEndDate, @TaxYear = TaxYear, @CycleId = CycleID FROM Payroll_CyclePeriodDetails WHERE Period_ID = @PERIODID     DECLARE @Period TABLE (Period_ID INT)   INSERT INTO @Period   SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE TaxYear = @TaxYear  AND CycleID = @CycleId AND Period_ID <= @PeriodId      SELECT distinct @FROMDATE AS FROMDATE , @TODATE AS TODATE,     PAY_MUN.MunicipalityName    ,ISNULL(PAY_MUN.PhyAddress1 + ' ','') + ISNULL(PAY_MUN.PhyAddress2 + ' ','')+ ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb),'') AS COMPANYADDRESS    ,CONVERT(NVARCHAR,PAY_CYC_PER.PeriodEndDate,103) AS PAYPERIOD    ,PAY_EMP.IdNo as EmpCode, PAY_EMP.Employee_ID,     ISNULL(PAY_EMP.FirstName + ' ','') + ISNULL(PAY_EMP.SecondName + ' ','') + ISNULL(PAY_EMP.Surname,'') AS EMPLOYEENAME,     ISNULL(PAY_EMP.PhysicalAddress1 + ' ','') + ISNULL(PAY_EMP.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_EMP.PhysicalSuburbID),'') AS EMPADDRESS,           CONVERT(NVARCHAR,PAY_EMP.JoiningDate,103) AS STARTDATE    ,CONST_TRAN_TYPE.TransactionTypeDesc, CONST_TRAN_TYPE.TransactionType_ID    ,P_JP.JobTitle    ,PAY_EMP_PAY.Amount    ,PAY_SAL.SalaryHeadTitle + isnull(' (' + PAY_EMP_PAY.SalaryHeadTitleAddendum + ')','') AS TRANSTYPEDESCRIPTION    ,ISNULL((SELECT SUM(AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave) FROM dbo.Payroll_EmployeeLeaveSchemeTransaction AS EL WHERE EmployeeId = PAY_EMP.Employee_ID ), 0) AS TOTALLEAVE    ,PAY_DEF.EmployeePayrollDefinition_ID,     ((SELECT SUM(TRAIL.Amount) FROM Payroll_EmployeePayslip TRAIL       INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID       INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = PAY.PayrollSalaryHeadID      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID  AND TaxSavePurpose = 0      AND TRAIL.PeriodID =@PERIODID AND TRAIL.TaxYear =@TaxYear  AND       Payroll_IRP5Code.TransactionTypeID = 1     )     -         (SELECT SUM(AMOUNT) FROM Payroll_EmployeePayslip TRAIL       INNER JOIN Payroll_EmployeePayrollDefinition PAY  ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID       INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = PAY.PayrollSalaryHeadID      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND      TRAIL.TaxYear =@TaxYear AND      Payroll_IRP5Code.TransactionTypeID = 2)    )AS NETPAY,    ISNULL((    SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TaxableID = 1 AND TransactionType_ID = 1 AND TaxSavePurpose = 0 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableEarnings,    ISNULL((    SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TaxableID = 1 AND TransactionType_ID = 3 AND TaxSavePurpose = 0 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableCompanyContributions,    ISNULL((    SELECT SUM(Amount) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TransactionType_ID = 4 AND TaxSavePurpose = 0 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableFringeBenefits,    --CAST(0 AS DECIMAL(18, 2)) AS BonusTax,    --PAY_EMP.BonusCalculation,    TBC.TaxBonusCalculation AS BonusCalculation,    ISNULL((    SELECT SUM(Amount) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TaxableID = 1 AND SalaryHeadName = 'Pay as you Earn' AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxPaid,    CASE WHEN PAY_SAL.SalaryHeadTitle = 'Loan' THEN ISNULL((SELECT SUM(Balance) FROM dbo.Payroll_InstalmentHistory WHERE EmployeeId = PAY_EMP.Employee_ID AND PeriodID = @PeriodID),0) ELSE 0.00 END AS OpeningBalance     FROM Payroll_Employee PAY_EMP  INNER JOIN Payroll_Municipality PAY_MUN     ON PAY_MUN.Municipality_ID = PAY_EMP.MunicipalityID  INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY     ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID           INNER JOIN dbo.Payroll_EmployeePayrollDefinition PAY_DEF     ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID   INNER JOIN Payroll_SalaryHead PAY_SAL     ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID  INNER JOIN Payroll_IRP5Code IRP5     ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID   INNER JOIN Const_TransactionType CONST_TRAN_TYPE     ON CONST_TRAN_TYPE.TransactionType_ID = IRP5.TransactionTypeID  INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER     ON PAY_CYC_PER.PERIOD_ID = PAY_EMP_PAY.PERIODID AND  PAY_CYC_PER.CYCLEID=PAY_EMP.CYCLEID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID     INNER JOIN dbo.Payroll_JobProfile AS P_JP ON P_JP.JobProfile_ID = PP.JobProfileID  INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID  INNER JOIN dbo.Const_TaxBonusCalculation_sys TBC ON TBC.TaxBonusCalculation_ID= PAY_EMP.BonusCalculation  WHERE (PAY_EMP.Employee_ID =@EmployeeID OR @EmployeeID = 0 ) AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND PAY_EMP_PAY.PERIODID = @PERIODID    AND PAY_EMP_PAY.TaxYear = @TaxYear AND TaxSavePurpose = 0          END  

GO

-- ============================================
-- SP: Payroll_EmployeePlainPaperPayslipT1Rpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 23 jul 2013  -- Description: <Description,,>  -- CALLS : Payroll_EmployeePlainPaperPayslipT1Rpt_sp 0, 0, 1  -- 2014-11-04   Stephan Stephansen: ISNULL checks on name and address fields added.  -- 2015-01-09 James Roodt: Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt: Updated Stephan's ISNULL checks to look identical to other payslip reports  -- 2015-05-19 TP19714 James Roodt: Added SalaryHeadTitleAddendum to be appended to SalaryHeadTitle  -- 2016-01-05 Suri Kandukuri Added employee code.  -- 2016-01-21 Suri Kandukuri Added condition for transaction types only earnings and deductions  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_EmployeePlainPaperPayslipT1Rpt_sp]   @EmployeeID INT,   @DepartmentId INT,   @PeriodId INT  AS  BEGIN   DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME, @TaxYear NVARCHAR(10) =''     SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID      SELECT distinct @FROMDATE AS FROMDATE , @TODATE AS TODATE,     PAY_MUN.MunicipalityName    ,ISNULL(PAY_MUN.PhyAddress1+ ' ','') + ISNULL(PAY_MUN.PhyAddress2+ ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb),'') AS COMPANYADDRESS    ,CONVERT(NVARCHAR,PAY_CYC_PER.PeriodEndDate,103) AS PAYPERIOD    ,PAY_EMP.IdNo as IDNumber, isnull(EmpCode,'') EmpCode, PAY_EMP.Employee_ID,     ISNULL(PAY_EMP.FirstName + ' ','') + ISNULL(PAY_EMP.SecondName + ' ','') + ISNULL(PAY_EMP.Surname,'') AS EMPLOYEENAME,     ISNULL(PAY_EMP.PhysicalAddress1 + ' ','') + ISNULL(PAY_EMP.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_EMP.PhysicalSuburbID),'') AS EMPADDRESS,    CONVERT(NVARCHAR,PAY_EMP.JoiningDate,103) AS STARTDATE    ,CONST_TRAN_TYPE.TransactionTypeDesc    ,PAY_EMP_PAY.Amount    ,PAY_SAL.SalaryHeadTitle  + isnull(' (' + PAY_EMP_PAY.SalaryHeadTitleAddendum + ')','') AS TRANSTYPEDESCRIPTION    ,ISNULL((SELECT SUM(LeaveBalance)FROM Payroll_EmployeeLeave WHERE EmployeeID = PAY_EMP.Employee_ID and FinancialYear = @TaxYear and LeaveTypeID = 1    ),0) AS TOTALLEAVE,    PAY_DEF.EmployeePayrollDefinition_ID,    ((SELECT SUM(TRAIL.Amount) FROM Payroll_EmployeePayslip TRAIL       INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID       INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID =  pay.PayrollSalaryHeadID      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID  AND TaxSavePurpose = 0     AND TRAIL.PeriodID =@PERIODID AND TRAIL.TaxYear =@TaxYear  AND Payroll_IRP5Code.TransactionTypeID = 1     )) as Earnings,     (SELECT SUM(AMOUNT) FROM Payroll_EmployeePayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY  ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID =  pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID       WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND       TRAIL.TaxYear =@TaxYear AND Payroll_IRP5Code.TransactionTypeID  = 2) as Deduction,     PAY_SAL.IRP5CodeId ,     ((SELECT SUM(TRAIL.Amount) FROM Payroll_EmployeePayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY  ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID =  pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID  AND TaxSavePurpose = 0      AND TRAIL.PeriodID =@PERIODID AND TRAIL.TaxYear =@TaxYear  AND Payroll_IRP5Code.TransactionTypeID = 1     )-         (SELECT SUM(AMOUNT) FROM Payroll_EmployeePayslip TRAIL       INNER JOIN Payroll_EmployeePayrollDefinition PAY  ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID       INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID =  pay.PayrollSalaryHeadID      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID      WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND TRAIL.TaxYear =@TaxYear      AND Payroll_IRP5Code.TransactionTypeID = 2)    )AS NETPAY    ,PAY_JOB.JobTitle    , dbo.BufferString_fxn(CONVERT(VARCHAR,(PAY_EMP.Employee_ID)), 12, '0') AS EMPLOYEENO   FROM Payroll_Employee PAY_EMP  INNER JOIN Payroll_Municipality PAY_MUN     ON PAY_MUN.Municipality_ID = PAY_EMP.MunicipalityID  INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY     ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID           INNER JOIN dbo.Payroll_EmployeePayrollDefinition PAY_DEF     ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID   INNER JOIN Payroll_SalaryHead PAY_SAL     ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID   INNER JOIN Payroll_IRP5Code IRP5     ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID   INNER JOIN Const_TransactionType CONST_TRAN_TYPE     ON CONST_TRAN_TYPE.TransactionType_ID = IRP5.TransactionTypeID  INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER     ON PAY_CYC_PER.PERIOD_ID = PAY_EMP_PAY.PERIODID AND  PAY_CYC_PER.CYCLEID=PAY_EMP.CYCLEID      INNER JOIN dbo.Payroll_JobProfile PAY_JOB ON PAY_EMP.JobProfileID = PAY_JOB.JobProfile_ID  INNER JOIN dbo.Const_Department AS C_D ON PAY_JOB.DepartmentID = C_D.Department_ID  WHERE (PAY_EMP.Employee_ID =@EmployeeID OR @EmployeeID = 0 ) AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND PAY_EMP_PAY.PERIODID = @PERIODID    AND PAY_EMP_PAY.TaxYear = @TaxYear AND TaxSavePurpose = 0       and CONST_TRAN_TYPE.TransactionType_ID in (1,2)  order by PAY_SAL.SalaryHeadTitle  + isnull(' (' + PAY_EMP_PAY.SalaryHeadTitleAddendum + ')','')  END  

GO

-- ============================================
-- SP: Payroll_EmployeePresentDaysCount_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 20/07/2013  -- Description: Get Employee's Presant days count  -- [Payroll_EmployeePresentDaysCount_sp] 1,'2013/2014',1,0,0  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeePresentDaysCount_sp]   @EmployeeID INT,   @Financeyear NVARCHAR(10),   @Month INT,   @TotalDays INT OUTPUT,   @WorkedDays INT OUTPUT  AS  BEGIN      SET NOCOUNT ON;        DECLARE @colsUnpivot AS NVARCHAR(MAX), @query  AS NVARCHAR(MAX)   DECLARE @OVERDUEDAYS INT      SELECT @colsUnpivot = stuff((SELECT ',' + quotename(C.name)FROM sys.columns as C       WHERE C.object_id = object_id('Payroll_EmployeeAttendance') AND     C.name != 'EmployeeAttendance_ID' AND  C.name != 'EmployeeID'               AND C.name != 'TaxYear' AND  C.name != 'Month'      FOR XML PATH('')), 1, 1, '')     INSERT INTO Payroll_EmployeeAttendance_Temp   SELECT * FROM Payroll_EmployeeAttendance WHERE EmployeeID = @EmployeeID    AND TaxYear = @Financeyear AND [Month] = @Month     SET @query = 'SELECT PresantDays FROM Payroll_EmployeeAttendance_Temp unpivot      (PresantDays for Days in (' + @colsunpivot + ')) u '           DECLARE @PresantDaysTable TABLE   (    PresantDays NVARCHAR(10)   )     INSERT INTO @PresantDaysTable    EXEC(@query)      SELECT @TotalDays = COUNT(PresantDays) FROM @PresantDaysTable   SELECT @WorkedDays = COUNT(PresantDays) FROM @PresantDaysTable WHERE (PresantDays = 'P' OR PresantDays = 'WO' OR PresantDays = 'H')     DELETE FROM Payroll_EmployeeAttendance_Temp     --SELECT @SalaryDays AS SalaryDays   DELETE @PresantDaysTable      SET NOCOUNT OFF     RETURN @TotalDays   RETURN @WorkedDays   PRINT 'Payroll_EmployeePresentDaysCount_sp  - DONE'   END  

GO

