-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 20/07/2013  -- Description: Get Employee's Presant days count  -- [Payroll_EmployeePresentDaysCount_sp] 1,'2013/2014',1,0,0  -- =============================================  Create PROCEDURE [dbo].[Payroll_EmployeePresentDaysCount_Ver2_sp]   @EmployeeID INT,   @PeriodID Int,   @TotalDays INT OUTPUT,   @WorkedDays INT OUTPUT  AS  BEGIN      SET NOCOUNT ON;        select  @WorkedDays =Count(T1.DayIndicator) , @TotalDays = Max(DatePart(Day,P.PeriodEndDate)) from (   select [1] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [2] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [3] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [4] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [5] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [6] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [7] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [8] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [9] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [10] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [11] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [12] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [13] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [14] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [15] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [16] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [17] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [18] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [19] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [20] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [21] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [22] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [23] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [24] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [25] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [26] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [27] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [28] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [29] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [30] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [31] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate)) as T1       inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where T1.DayIndicator in('H','P','L')       group by T1.EmployeeID   PRINT 'Payroll_EmployeePresentDaysCount_sp  - DONE'   END  

GO

-- ============================================
-- SP: Payroll_EmployeePUKGenerate
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_EmployeePUKGenerate 2, 0  -- 14-10-2016 TP47127 add a try catch     --=============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeePUKGenerate]   @EmployeeId INT,   @Repeat BIT = 0     AS  BEGIN    BEGIN TRY   DECLARE @PukNo VARCHAR(50), @Id INT   declare @AlLChars varchar(100) = 'ABCDEFGHIJK123456789LMNOPQRSTUVWXYZ0123456789ABCDEFGHIJKLMNOP123456789QRSTUVWXYZ'     SELECT @PukNo = RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%34) + 1 ),1) + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%35) + 1 ),1) +   RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%35) + 1 ),1) + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%45) + 1 ),1)    + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%39) + 1 ),1) + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%35) + 1 ),1)    + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%23) + 1 ),1) + RIGHT( LEFT(@AlLChars,ABS(BINARY_CHECKSUM(NEWID())%52) + 1 ),1)         IF EXISTS (SELECT * FROM dbo.Payroll_EmployeePUKDetails WHERE EmployeeId = @EmployeeId) BEGIN    IF @Repeat = 1 BEGIN     SELECT @Id = Id FROM dbo.Payroll_EmployeePUKDetails WHERE EmployeeId = @EmployeeId     UPDATE dbo.Payroll_EmployeePUKDetails SET PUKNo = @PukNo, IsPukVerified = 0 WHERE Id = @Id     EXEC dbo.Payroll_EmployeeSendNewPUK @EmployeeId = @EmployeeId, -- int               @PukId = @Id    END    ELSE BEGIN     EXEC dbo.Payroll_EmployeeSendPaySlip @EmployeeId = @EmployeeId -- int       END   END   ELSE BEGIN    INSERT INTO dbo.Payroll_EmployeePUKDetails ( EmployeeId, PUKNo, IsPukVerified, DateCaptured )    SELECT @EmployeeId, @PukNo, 0, GETDATE()    SET @Id = SCOPE_IDENTITY()    EXEC dbo.Payroll_EmployeeSendNewPUK @EmployeeId = @EmployeeId, @PukId = @Id -- int     END   END TRY   BEGIN CATCH     PRINT'ERROR OCCURED '   END CATCH  END  

GO

-- ============================================
-- SP: Payroll_EmployeeRetirementFundDetailReport_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Ivan Myroshnychenko  -- Create date: 08/01/2021  -- Description:   -- CALLS : EXEC [dbo].[[Payroll_EmployeeRetirementFundDetailReport_sp] '2020/2021',0,0,0,(1-3),'0'  -- '2020/2021' - TaxYear  -- 0 - Cycle ID  -- 0 - Benefit Type ID  -- 0 - Returement Fund ID  -- (1-3) - Status, 1- All employees, 2 - Inactive employees, 3 - Active employees  -- '0' - Transactions SalaryHeadID (e.g. '54' or '54,56') linked to IRP 5 code 4472, 4473, 4001 and 4003.   --      Exclude the system salary transactions for Pension fund (salary transaction ID 15,16 &17),   --      Provident fund (Salary transaction 18,19/20) and Retirement funds (salary transaction 21,22,23).  --      0 - Default value  --2023/12/05 Kiran - WI84602 Fix The detail per month should be in one line and not in three lines  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeRetirementFundDetailReport_sp]      @TaxYear NVARCHAR(MAX),      @CycleID INT,      @RetirementType INT,      @RetirementFund INT,          @Status INT,      @SalaryHeadIDs NVARCHAR(MAX)  AS  BEGIN    DECLARE @PurposeTaxYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    DROP TABLE IF EXISTS #Amount   CREATE TABLE #Amount   (  EmployeeID INT,  SalaryTitle NVARCHAR(MAX),  TaxPeriod INT,  EmployerAmount FLOAT,  EmployerArrear FLOAT,  EmployeeAmount FLOAT,  EmployeeArrear FLOAT,  FringeAmount FLOAT  )    -------------------- Get transactions from Payroll_PayrollResults with SalaryHeadeID(s) from 15 till 23 is and typed by user----------------  INSERT INTO #Amount (EmployeeID, SalaryTitle, TaxPeriod, EmployerAmount, EmployerArrear, EmployeeAmount, EmployeeArrear,FringeAmount)     SELECT      P_E.Employee_ID     , PPR.SalaryTitle     , PPR.PeriodID     , SUM(CASE       WHEN PPR.IRP5Code = 4472 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount      WHEN PPR.IRP5Code = 4473 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount      WHEN PPR.IRP5Code = 4475 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount     END) AS EmployerAmount     , 0 AS EmployerArrear     , SUM(CASE       WHEN PPR.IRP5Code = 4001 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount      WHEN PPR.IRP5Code = 4003 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount      WHEN PPR.IRP5Code = 4006 AND (PPR.SalaryHeadID BETWEEN 15 AND 23) THEN PPR.Amount     END) AS EmployeeAmount     , 0 AS EmployeeArrear     , SUM(CASE       WHEN PPR.IRP5Code = 3817 THEN PPR.Amount      WHEN PPR.IRP5Code = 3825 THEN PPR.Amount      WHEN PPR.IRP5Code = 3828 THEN PPR.Amount     END) AS FringeAmount     FROM Payroll_Employee AS P_E      JOIN (SELECT        P_PR.EmployeeID       , P_PR.VendorID       , P_PR.SalaryTitle       , P_PR.IRP5Code       , P_PR.SalaryHeadID       , P_PR.PeriodID       , P_PR.Amount AS Amount       FROM Payroll_PayrollResults AS P_PR       WHERE (@CycleID = 0 OR @CycleID = P_PR.CycleID)        AND P_PR.IRP5Code IN (4001,4472,3817,4003,4473,3825,4006,4475,3828)        AND P_PR.SalaryHeadID BETWEEN 15 AND 23        AND P_PR.TaxYear =  CAST(@PurposeTaxYear AS NVARCHAR(MAX))       ) AS PPR       ON P_E.Employee_ID = PPR.EmployeeID     GROUP BY P_E.Employee_ID, PPR.SalaryTitle, PPR.PeriodID        DROP TABLE IF EXISTS #ArrearAmount   CREATE TABLE #ArrearAmount   (  EmployeeID INT,  SalaryTitle NVARCHAR(MAX),  TaxPeriod INT,  EmployerArrear FLOAT,  EmployeeArrear FLOAT,  )    INSERT INTO #ArrearAmount (EmployeeID, SalaryTitle, TaxPeriod, EmployerArrear, EmployeeArrear)     SELECT      P_E.Employee_ID     , MAX(PPR.SalaryTitle)     , PPR.PeriodID     , SUM(CASE       WHEN (PPR.IRP5Code = 4472 OR PPR.IRP5Code = 4473) AND (PPR.SalaryHeadID NOT BETWEEN 15 AND 23) THEN PPR.Amount      ELSE NULL     END) AS EmployerArrear     , SUM(CASE       WHEN (PPR.IRP5Code = 4001 OR PPR.IRP5Code = 4003) AND (PPR.SalaryHeadID NOT BETWEEN 15 AND 23) THEN PPR.Amount      ELSE NULL     END) AS EmployeeArrear     FROM Payroll_Employee AS P_E      JOIN (SELECT        P_PR.EmployeeID       , P_PR.VendorID       , P_PR.SalaryTitle       , P_PR.IRP5Code       , P_PR.SalaryHeadID       , P_PR.PeriodID       , P_PR.Amount AS Amount       FROM Payroll_PayrollResults AS P_PR       WHERE (@CycleID = 0 OR @CycleID = P_PR.CycleID)        AND P_PR.IRP5Code IN (4001,4472,3817,4003,4473,3825,4006,4475,3828)        AND P_PR.SalaryHeadID IN (SELECT CAST(value AS INT) FROM STRING_SPLIT(@SalaryHeadIDs, ','))           AND P_PR.TaxYear = @PurposeTaxYear        ) AS PPR       ON P_E.Employee_ID = PPR.EmployeeID     GROUP BY P_E.Employee_ID, PPR.PeriodID, PPR.VendorID       DROP TABLE IF EXISTS #InactiveEmployee  CREATE TABLE #InactiveEmployee  (EmployeeID INT)    INSERT INTO #InactiveEmployee  SELECT DISTINCT P_E.Employee_ID AS EmployeeID   FROM Payroll_Employee AS P_E    LEFT JOIN Payroll_EmployeeTermination AS P_ET     ON P_E.Employee_ID = P_ET.EmployeeID   WHERE P_E.EndDate < GETDATE() OR P_ET.Complete = 1    DROP TABLE IF EXISTS #Results  CREATE TABLE #Results  (  EmployeeID INT  , Initials NVARCHAR(MAX)  , Surname NVARCHAR(MAX)  , PayPeriod NVARCHAR(MAX)  , RetirementType NVARCHAR(MAX)  , ReferenceNumber NVARCHAR(MAX)  , RetirementPlan NVARCHAR(MAX)  , EmployerIRP5Code INT  , EmployerContribution FLOAT  , EmployerArrea FLOAT  , EmployeeIRP5Code INT  , EmployeeContribution FLOAT  , EmployeeArrea FLOAT  , TotalContribution FLOAT  , FringeBenefitIRP5Code INT  , FringeBenefit FLOAT  , PeriodID INT  )    INSERT INTO #Results (EmployeeID, Initials, Surname, PayPeriod, RetirementType, ReferenceNumber, RetirementPlan, EmployerIRP5Code, EmployerContribution     , EmployerArrea, EmployeeIRP5Code, EmployeeContribution, EmployeeArrea, TotalContribution, FringeBenefitIRP5Code, FringeBenefit, PeriodID)  SELECT P_E.Employee_ID AS EmployeNumber  , P_E.Initials AS Initials  , P_E.Surname AS Surname  , P_CPD.ProcessingMonth + ' ' + CAST(YEAR(P_CPD.PeriodStartDate) AS NVARCHAR(4)) AS PayPeriod  , C_BT.BenefitType AS RetirementType  , P_EBD.ReferenceNo AS ReferenceNumber  , P_BD.FundName AS RetirementPlan  , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 4472    WHEN C_BT.BenefitType_ID = 4 THEN 4473    WHEN C_BT.BenefitType_ID = 5 THEN 4475   END AS EmployerIRP5Code   , #Amount.EmployerAmount AS EmployerContribution  , #ArrearAmount.EmployerArrear AS EmplyerArrea  , CASE     WHEN C_BT.BenefitType_ID = 3 THEN 4001    WHEN C_BT.BenefitType_ID = 4 THEN 4003    WHEN C_BT.BenefitType_ID = 5 THEN 4006   END AS EmployeeIRP5Code  , #Amount.EmployeeAmount AS EmployeeContribution  , #ArrearAmount.EmployeeArrear AS EmployeeArrea  , 0 AS TotalContribution  , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 3817    WHEN C_BT.BenefitType_ID = 4 THEN 3825    WHEN C_BT.BenefitType_ID = 5 THEN 3828   END AS FringeBenefitIRP5Code  , #Amount.FringeAmount AS FringeBenefit  , P_CPD.Period_ID  FROM Payroll_Employee AS P_E   JOIN Payroll_EmpBenefitDetail AS P_EBD    ON P_E.Employee_ID = P_EBD.EmployeeId      LEFT JOIN Payroll_BenefitDetail AS P_BD    ON P_EBD.BenefitSchemeID = P_BD.Benefit_ID   LEFT JOIN Const_BenefitType_sys AS C_BT    ON P_BD.BenefitTypeID = C_BT.BenefitType_ID   JOIN #Amount    ON P_E.Employee_ID = #Amount.EmployeeID   JOIN Payroll_CyclePeriodDetails AS P_CPD    ON #Amount.TaxPeriod = P_CPD.Period_ID   LEFT JOIN Cons_Vendor AS C_V    ON P_BD.VendorID = C_V.Vendor_ID   LEFT JOIN #ArrearAmount      ON P_E.Employee_ID = #ArrearAmount.EmployeeID AND #Amount.TaxPeriod = #ArrearAmount.TaxPeriod      AND (P_EBD.IsPrivate = 0 OR (CHARINDEX(P_EBD.ReferenceNo, #ArrearAmount.SalaryTitle collate Latin1_General_CI_AS)) > 0)  WHERE (@Status = 1      OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))      OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))       AND (@RetirementFund = 0 OR @RetirementFund = P_BD.Benefit_ID)    AND (@RetirementType = 0 OR @RetirementType = C_BT.BenefitType_ID)  --------------------Check that current transaction title contains Benefit Plan name in the SalaryTitle (FringeBenefit transaction can be attached to another transactions only by Plan name )---------------    AND ((CHARINDEX(C_V.VendorName, #Amount.SalaryTitle collate Latin1_General_CI_AS)) > 0 )  --------------------Select plans which were active in selected period---------------------------------    AND P_EBD.JoinDate < (SELECT MAX(PeriodEndDate) FROM Payroll_CyclePeriodDetails WHERE (@CycleID = 0 OR @CycleID = CycleID) AND @TaxYear = TaxYear)     AND (P_EBD.Enabled = 1 OR P_EBD.DateModified IS NULL OR P_EBD.DateModified > (SELECT MIN(PeriodStartDate) FROM Payroll_CyclePeriodDetails WHERE (@CycleID = 0 OR @CycleID = CycleID) AND @TaxYear = TaxYear))      ORDER BY P_E.Employee_ID, P_CPD.Period_ID      SELECT dbo.BufferString_fxn(EmployeeID, 8, '0') AS EmployeeNumber  , Initials   , Surname   , PayPeriod   , SUBSTRING(RetirementType, 1, CHARINDEX(' ', RetirementType)-1) AS RetirementType  , ReferenceNumber   , RetirementPlan   , EmployerIRP5Code   , SUM(ISNULL(EmployerContribution,0)) AS EmployerContribution  , SUM(ISNULL(EmployerArrea,0)) AS EmployerArrea  , EmployeeIRP5Code  , SUM(ISNULL(EmployeeContribution,0)) AS EmployeeContribution  , SUM(ISNULL(EmployeeArrea,0)) AS EmployeeArrea  , SUM(ISNULL(EmployerContribution,0) + ISNULL(EmployerArrea,0) + ISNULL(EmployeeContribution,0) + ISNULL(EmployeeArrea,0) + ISNULL(TotalContribution ,0)) AS TotalContribution   , FringeBenefitIRP5Code   , SUM(FringeBenefit) AS FringeBenefit   FROM #Results  --ORDER BY EmployeeID, PeriodID  GROUP BY EmployeeID, Initials, Surname,PayPeriod, SUBSTRING(RetirementType, 1, CHARINDEX(' ', RetirementType)-1),  ReferenceNumber, RetirementPlan, EmployerIRP5Code, EmployeeIRP5Code, FringeBenefitIRP5Code     DROP TABLE IF EXISTS #Amount   DROP TABLE IF EXISTS #ArrearAmount  DROP TABLE IF EXISTS #InactiveEmployee  DROP TABLE IF EXISTS #Results      END

GO

-- ============================================
-- SP: Payroll_EmployeeRetirementFundReport_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Ivan Myroshnychenko  -- Create date: 08/01/2021  -- Description:   -- CALLS : EXEC [dbo].[[Payroll_EmployeeRetirementFundReport_sp] '2020/2021',0,0,0,(1-3),'0'  -- '2020/2021' - TaxYear  -- 0 - Cycle ID  -- 0 - Benefit Type ID  -- 0 - Returement Fund ID  -- (1-3) - Status, 1- All employees, 2 - Inactive employees, 3 - Active employees  -- '0' - Transactions SalaryHeadID (e.g. '54' or '54,56') linked to IRP 5 code 4472, 4473, 4001 and 4003.   --      Exclude the system salary transactions for Pension fund (salary transaction ID 15,16 &17),   --      Provident fund (Salary transaction 18,19/20) and Retirement funds (salary transaction 21,22,23).  --      0 - Default value  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeRetirementFundReport_sp]      @TaxYear NVARCHAR(MAX),      @CycleID INT,      @RetirementType INT,      @RetirementFund INT,          @Status INT,      @SalaryHeadIDs NVARCHAR(MAX)  AS  BEGIN    DECLARE @PurposeTaxYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    DROP TABLE IF EXISTS #Amount   CREATE TABLE #Amount   (  EmployeeID INT,  SalaryTitle NVARCHAR(MAX),  EmployerAmount FLOAT,  EmployeeAmount FLOAT,  FringeAmount FLOAT  )    --------------- Get transactions from Payroll_PayrollResults with SalaryHeadeID from 15 till 23-------------------------  INSERT INTO #Amount (EmployeeID, SalaryTitle, EmployerAmount, EmployeeAmount, FringeAmount)  SELECT   P_E.Employee_ID  , PPR.SalaryTitle  , SUM(CASE    WHEN PPR.IRP5Code = 4472 THEN PPR.Amount   WHEN PPR.IRP5Code = 4473 THEN PPR.Amount   WHEN PPR.IRP5Code = 4475 THEN PPR.Amount  END) AS EmployerAmount  , SUM(CASE    WHEN PPR.IRP5Code = 4001 THEN PPR.Amount   WHEN PPR.IRP5Code = 4003 THEN PPR.Amount   WHEN PPR.IRP5Code = 4006 THEN PPR.Amount  END) AS EmployeeAmount  , SUM(CASE    WHEN PPR.IRP5Code = 3817 THEN PPR.Amount   WHEN PPR.IRP5Code = 3825 THEN PPR.Amount   WHEN PPR.IRP5Code = 3828 THEN PPR.Amount  END) AS FringeAmount  FROM Payroll_Employee AS P_E   JOIN (SELECT     P_PR.EmployeeID    , P_PR.VendorID    , P_PR.SalaryTitle    , P_PR.IRP5Code    , SUM(P_PR.Amount) AS Amount    FROM Payroll_PayrollResults AS P_PR    WHERE (@CycleID = 0 OR @CycleID = P_PR.CycleID)     AND P_PR.SalaryHeadID BETWEEN 15 AND 23      AND P_PR.TaxYear = @PurposeTaxYear    GROUP BY P_PR.EmployeeID, P_PR.IRP5Code, P_PR.VendorID,P_PR.SalaryTitle) AS PPR    ON P_E.Employee_ID = PPR.EmployeeID  GROUP BY   P_E.Employee_ID  , PPR.SalaryTitle    -------------------- Get transactions from Payroll_PayrollResults with SalaryHeadeID(s) which is typed by user----------------  IF(@SalaryHeadIDs!='0')  BEGIN       INSERT INTO #Amount (EmployeeID, SalaryTitle, EmployerAmount, EmployeeAmount, FringeAmount)      SELECT       P_E.Employee_ID      , MAX(PPR.SalaryTitle)      , SUM(CASE        WHEN PPR.IRP5Code = 4472 THEN PPR.Amount       WHEN PPR.IRP5Code = 4473 THEN PPR.Amount       WHEN PPR.IRP5Code = 4475 THEN PPR.Amount      END) AS EmployerAmount      , SUM(CASE        WHEN PPR.IRP5Code = 4001 THEN PPR.Amount       WHEN PPR.IRP5Code = 4003 THEN PPR.Amount       WHEN PPR.IRP5Code = 4006 THEN PPR.Amount      END) AS EmployeeAmount      , SUM(CASE        WHEN PPR.IRP5Code = 3817 THEN PPR.Amount       WHEN PPR.IRP5Code = 3825 THEN PPR.Amount       WHEN PPR.IRP5Code = 3828 THEN PPR.Amount      END) AS FringeAmount      FROM Payroll_Employee AS P_E       JOIN (      SELECT       P_PR.EmployeeID      , P_PR.VendorID      , P_PR.SalaryTitle      , P_PR.IRP5Code      , SUM(P_PR.Amount) AS Amount      FROM Payroll_PayrollResults AS P_PR      WHERE (@CycleID = 0 OR @CycleID = P_PR.CycleID)       AND P_PR.SalaryHeadID IN (SELECT CAST(value AS INT) FROM STRING_SPLIT(@SalaryHeadIDs, ','))       AND P_PR.TaxYear = @PurposeTaxYear       GROUP BY       P_PR.EmployeeID      , P_PR.IRP5Code      , P_PR.VendorID      ,P_PR.SalaryTitle) AS PPR      on P_E.Employee_ID = PPR.EmployeeID      GROUP BY       P_E.Employee_ID      , PPR.VendorID  END      DROP TABLE IF EXISTS #InactiveEmployee  CREATE TABLE #InactiveEmployee  (EmployeeID INT)    INSERT INTO #InactiveEmployee  SELECT DISTINCT P_E.Employee_ID AS EmployeeID   FROM Payroll_Employee AS P_E    LEFT JOIN Payroll_EmployeeTermination AS P_ET     ON P_E.Employee_ID = P_ET.EmployeeID   WHERE P_E.EndDate < GETDATE() OR P_ET.Complete = 1    DROP TABLE IF EXISTS #BasicSalary    CREATE TABLE #BasicSalary  (  EmployeeID INT,  MonthlySalary FLOAT  )    INSERT INTO #BasicSalary(EmployeeID, MonthlySalary)  SELECT EmployeeId  , Amount/12  FROM Payroll_EmployeeSalaryTransaction   WHERE SalaryHeadId = 1    INSERT INTO #BasicSalary(EmployeeID, MonthlySalary)  SELECT P_E.Employee_ID  , CASE    WHEN P_N.MonthlySalary < P_N.MinimumSalary THEN P_N.MinimumSalary   ELSE P_N.MonthlySalary  END AS MonthSalary  FROM Payroll_Employee AS P_E  JOIN Payroll_Notch AS P_N   ON P_E.NotchId = P_N.Notch_ID    DROP TABLE IF EXISTS #Results    CREATE TABLE #Results  (  EmployeeNumber INT  , Initials NVARCHAR(MAX)  , Surname NVARCHAR(MAX)  , IDNumber BIGINT  , EmploymentDate NVARCHAR(MAX)  , BasicSalary FLOAT  , RetirementType NVARCHAR(MAX)  , ReferenceNumber NVARCHAR(MAX)  , RetirementPlan NVARCHAR(MAX)  , FundType NVARCHAR(MAX)  , Private NVARCHAR(MAX)  , EmployerPercent FLOAT  , EmployerIRP5Code INT  , EmployerAmount FLOAT  , EmployeePercent FLOAT  , EmployeeIRP5Code INT  , EmployeeAmount FLOAT  , FringeBenefitPercent FLOAT  , FringeBenefitIRP5Code INT  , FringeBenefitAmount FLOAT  )       INSERT INTO #Results (EmployeeNumber, Initials, Surname, IDNumber, EmploymentDate, BasicSalary, RetirementType, ReferenceNumber, RetirementPlan, FundType, Private,     EmployerPercent, EmployerIRP5Code, EmployerAmount, EmployeePercent, EmployeeIRP5Code, EmployeeAmount, FringeBenefitPercent, FringeBenefitIRP5Code, FringeBenefitAmount)   SELECT    P_E.Employee_ID AS EmployeeNumber   , P_E.Initials AS Initials   , P_E.Surname AS Surname   , P_E.IdNo AS IDNumber   , CAST(CONVERT(VARCHAR(10), P_E.JoiningDate, 103) AS NVARCHAR(MAX)) AS EmploymentDate   , #BasicSalary.MonthlySalary AS BasicSalary   , C_BT.BenefitType AS RetirementType   , P_EBD.ReferenceNo AS ReferenceNumber   , P_BD.FundName AS RetirementPlan   , C_P_RFT.Description AS FundType   , CASE     WHEN P_EBD.IsPrivate = 1 THEN 'Yes'    WHEN P_EBD.IsPrivate = 0 THEN 'No'    END AS Private   , CASE    WHEN P_BD.ContributionType = 1 AND P_EBD.IsPrivate = 0 THEN P_BD.EmplrContributionValue    ELSE NULL   END AS EmployerPercent   , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 4472    WHEN C_BT.BenefitType_ID = 4 THEN 4473    WHEN C_BT.BenefitType_ID = 5 THEN 4475   END AS EmployerIRP5Code    , CASE WHEN P_EBD.IsPrivate = 1 THEN 0 ELSE SUM(#Amount.EmployerAmount) end AS EmployerAmount   , CASE    WHEN P_BD.ContributionType = 1 AND P_EBD.IsPrivate = 0 THEN P_BD.EmpContributionValue    ELSE NULL   END  AS EmployeePercent   , CASE     WHEN C_BT.BenefitType_ID = 3 THEN 4001    WHEN C_BT.BenefitType_ID = 4 THEN 4003    WHEN C_BT.BenefitType_ID = 5 THEN 4006   END AS EmployeeIRP5Code   , CASE WHEN P_EBD.IsPrivate = 1 THEN EmployeeContribution ELSE SUM(#Amount.EmployeeAmount) END AS EmployeeAmount   , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN P_BD.RetirementFundTypeID =1 THEN 100    ELSE P_BD.FundMemberCategoryFactors   END AS FringeBenefitPercent   , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 3817    WHEN C_BT.BenefitType_ID = 4 THEN 3825    WHEN C_BT.BenefitType_ID = 5 THEN 3828   END AS FringeBenefitIRP5Code   , CASE WHEN P_EBD.IsPrivate = 1 THEN 0 else SUM(#Amount.FringeAmount) end AS FringeBenefitAmount     FROM Payroll_Employee AS P_E   JOIN Payroll_EmpBenefitDetail AS P_EBD    ON P_E.Employee_ID = P_EBD.EmployeeId      LEFT JOIN Payroll_BenefitDetail AS P_BD    ON P_EBD.BenefitSchemeID = P_BD.Benefit_ID   LEFT JOIN Const_BenefitType_sys AS C_BT    ON P_BD.BenefitTypeID = C_BT.BenefitType_ID   LEFT JOIN Const_Payroll_RetirementFundType_sys AS C_P_RFT    ON P_BD.RetirementFundTypeID = C_P_RFT.RetirementFundType_ID   LEFT JOIN #BasicSalary     ON P_E.Employee_ID = #BasicSalary.EmployeeID   LEFT JOIN Cons_Vendor AS C_V    ON P_BD.VendorID = C_V.Vendor_ID   JOIN #Amount    ON P_E.Employee_ID = #Amount.EmployeeID AND (CHARINDEX(C_V.VendorName, #Amount.SalaryTitle collate Latin1_General_CI_AS) > 0       OR CHARINDEX(P_EBD.ReferenceNo, #Amount.SalaryTitle collate Latin1_General_CI_AS) > 0)    WHERE  (@Status = 1      OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))      OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))       AND (@RetirementFund = 0 OR @RetirementFund = P_BD.Benefit_ID)    AND (@RetirementType = 0 OR @RetirementType = C_BT.BenefitType_ID)     --------------------Select plans which were active in selected period---------------------------------    AND P_EBD.JoinDate < (SELECT MAX(PeriodEndDate) FROM Payroll_CyclePeriodDetails WHERE (@CycleID = 0 OR @CycleID = CycleID) AND @TaxYear = TaxYear)     AND (P_EBD.Enabled = 1 OR P_EBD.DateModified IS NULL OR P_EBD.DateModified > (SELECT MIN(PeriodStartDate) FROM Payroll_CyclePeriodDetails WHERE (@CycleID = 0 OR @CycleID = CycleID) AND @TaxYear = TaxYear))   GROUP BY P_E.Employee_ID    , P_E.Initials    , P_E.Surname    , P_E.IdNo    , CAST(CONVERT(VARCHAR(10), P_E.JoiningDate, 103) AS NVARCHAR(MAX))    , #BasicSalary.MonthlySalary    , C_BT.BenefitType    , P_EBD.ReferenceNo    , P_BD.FundName    , C_P_RFT.Description    , CASE     WHEN P_EBD.IsPrivate = 1 THEN 'Yes'    WHEN P_EBD.IsPrivate = 0 THEN 'No'    END    , CASE    WHEN P_BD.ContributionType = 1 AND P_EBD.IsPrivate = 0 THEN P_BD.EmplrContributionValue    ELSE NULL   END    , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 4472    WHEN C_BT.BenefitType_ID = 4 THEN 4473    WHEN C_BT.BenefitType_ID = 5 THEN 4475   END     , CASE    WHEN P_BD.ContributionType = 1 AND P_EBD.IsPrivate = 0 THEN P_BD.EmpContributionValue    ELSE NULL   END    , CASE     WHEN C_BT.BenefitType_ID = 3 THEN 4001    WHEN C_BT.BenefitType_ID = 4 THEN 4003    WHEN C_BT.BenefitType_ID = 5 THEN 4006   END    , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN P_BD.RetirementFundTypeID =1 THEN 100    ELSE P_BD.FundMemberCategoryFactors   END    , CASE     WHEN P_EBD.IsPrivate = 1 THEN NULL    WHEN C_BT.BenefitType_ID = 3 THEN 3817    WHEN C_BT.BenefitType_ID = 4 THEN 3825    WHEN C_BT.BenefitType_ID = 5 THEN 3828   END,P_EBD.IsPrivate,EmployeeContribution    ORDER BY P_E.Employee_ID       SELECT dbo.BufferString_fxn(EmployeeNumber, 8, '0') AS EmployeeNumber   , Initials   , Surname   , IDNumber   , EmploymentDate   , BasicSalary   , SUBSTRING(RetirementType, 1, CHARINDEX(' ', RetirementType)-1) AS RetirementType   , ReferenceNumber   , RetirementPlan   , FundType   , Private   , EmployerPercent   , EmployerIRP5Code   , EmployerAmount   , EmployeePercent   , EmployeeIRP5Code   , EmployeeAmount   , FringeBenefitPercent   , FringeBenefitIRP5Code   , FringeBenefitAmount  FROM #Results   WHERE EmployerAmount > 0 OR EmployeeAmount > 0  OR FringeBenefitAmount >0  ORDER BY EmployeeNumber    DROP TABLE IF EXISTS #Amount   DROP TABLE IF EXISTS #InactiveEmployee  DROP TABLE IF EXISTS #BasicSalary  DROP TABLE IF EXISTS #Results           END

GO

-- ============================================
-- SP: Payroll_EmployeeSalaryStructureCalculation_Trail_sp
-- Schema: dbo
-- ============================================
    /*   Author  : FERDI BOTHA   Create date : 24/10/2017   Description : Calculates Employees Salary Structure   Update date :   13/02/2020 - Ilya Skavronskiy => updated bonus calculation   Update date :   24/02/2020 - Ilya Skavronskiy => Added Bonus processing for specific month   Update date :   25/02/2020 - Ilya Skavronskiy => Added filtering to prevent employee to receive a Bonus in his/her first month of employment   Update date :   13/04/2022 - R Mills => Cater for prorata Salary Transactions   Update date : 30/05/2022 - R Mills => Fix SP to save VendorId where applicable  */  CREATE procedure [dbo].[Payroll_EmployeeSalaryStructureCalculation_Trail_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit   as    begin     set nocount on;     begin try      declare @Payroll_EmployeeTrialPayslip table (       [EmployeeID] int not null,     [PayrollDefinationID] int not null,     [Amount] decimal(18, 6) not null,     [Month] nvarchar(10) not null,     [FinancialYear] nvarchar(10) not null,     [SalaryHeadTitleAddendum] nvarchar(200) null,     [PeriodID] int not null,     [TaxYear] nvarchar(10) null,     [VendorId] int,     [Simulation] bit null    )      declare @BonusDateID int = 0,      @BonusMonth int = 0      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @Payroll_EmployeeTrialPayslip([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear],[VendorId], [Simulation])       select       [PE].[Employee_ID],       [EmployeePayrollDefinition_ID],       case when SH.SalaryHead_ID = 2 then        cast(((isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6)))         * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))      else       case when [PET].[TerminationPeriodId] = @PeriodID and [SH].[IsProrata] = 1 then       (       (cast(((isnull(cast(([Amount] / 12) as decimal(18, 6)), cast(0 as decimal(18, 6)))         * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))))       /[PE].[WDPM_Monthly] * [PE].UntilDays      else       case when [PE].[StartDays] > 0 and [SH].[IsProrata] = 1 then       (       (cast(((isnull(cast(([Amount] / 12) as decimal(18, 6)), cast(0 as decimal(18, 6)))         * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))))       /[PE].[WDPM_Monthly] * [PE].StartDays      else        cast(((isnull(cast(([Amount] / 12) as decimal(18, 6)), cast(0 as decimal(18, 6)))        * cast([Percentage] as decimal(18, 6)))/ cast(100 as decimal(18, 6))) as decimal(18, 6))      end      end      end,       @Month,       @SCOAYear,       [SalaryHeadTitle],       @PeriodID,       @TaxYear,       GL.VendorID,      @Simulation        from [Payroll_EmployeeSalaryTransaction] as [ET] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [ET].[EmployeeId] and [PayrollSalaryHeadID] = [ET].[SalaryHeadId] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with (nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID]         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ET].[EmployeeId] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         left outer join [Payroll_EmployeeTermination] as [PET] on [PET].[EmployeeId] = [PE].[Employee_ID] and [PET].[TerminationPeriodId] = @PeriodID and [PET].Complete = 1        where ([ET].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and         not isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) in(4472, 4473, 4474, 4475) and         (        [SH].[SalaryHead_ID] != 2          or [SH].[SalaryHead_ID] = 2        and        (         isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@EndDate))          or isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@EndDate))          or isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@EndDate))         or isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@EndDate))        )        and              --No employee can receive a bonus or a pro-rate bonus in his/her first month of employment.        (         year(@EndDate) > year([PE].[JoiningDate])         or          (year(@EndDate) = year([PE].[JoiningDate]) and month(@EndDate) > month([PE].[JoiningDate]))         )        and        --Only one Bonus payment can be made during the Tax Year        not exists (         select top 1 1         from Payroll_PayrollResults AS PR         where [PR].[EmployeeID] = [EPD].[EmployeeID]          and [PR].[SalaryHeadID] = 2          and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int)        )       ) and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      update [TP] set [TP].[Amount] = [ET].[Amount]       from [Payroll_EmployeeTrialPayslip] as [TP]        join @Payroll_EmployeeTrialPayslip as [ET] on [ET].[EmployeeID] = [TP].[EmployeeID] and [ET].[PayrollDefinationID] = [TP].[PayrollDefinationID] and [ET].[Month] = [TP].[Month] and [ET].[FinancialYear] = [TP].[FinancialYear] and [ET].[PeriodID] = [TP].[PeriodID] and [ET].[TaxYear] = [TP].[TaxYear]       where ([ET].[Amount] > 0)      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear],[VendorId],[Simulation])       select [EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [TaxYear],[VendorId], [Simulation]        from @Payroll_EmployeeTrialPayslip as [ET]        where ([ET].[Amount] > 0 and not exists(          select top 1 [EmployeeID]           from [Payroll_EmployeeTrialPayslip]           where ([EmployeeID] = [ET].[EmployeeID] and [PayrollDefinationID] = [ET].[PayrollDefinationID] and [Month] = [ET].[Month] and [FinancialYear] = [ET].[FinancialYear] and [PeriodID] = [ET].[PeriodID] and [TaxYear] = [ET].[TaxYear] and [Simulation] = [ET].[Simulation] )         )        )     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeSalaryStructureCalculation_TrailSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Create date : 31/01/2019   Description : Calculates Employee Salary Structure (Simulation)   Update Date : 11/04/2019 => Added Employee Salary Structure (Simulation) @ Terminations   Update date :   13/02/2020 - Ilya Skavronskiy => updated bonus calculation   Update date :   24/02/2020 - Ilya Skavronskiy => Added Bonus processing for specific month   Update date :   25/02/2020 - Ilya Skavronskiy => Added filtering to prevent employee to receive a Bonus in his/her first month of employment  */  CREATE procedure [Payroll_EmployeeSalaryStructureCalculation_TrailSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      declare @Payroll_EmployeeTrialPayslip table (       [EmployeeID] int not null,     [TransactionTypeID] int not null,     [SalaryHeadID] int not null,     [Amount] decimal(18, 6) not null,     [SalaryHeadTitle] nvarchar(256) null      )      declare @BonusDateID int = 0,      @BonusMonth int = 0,      @TaxYear int = (case when month(@StartDate) < 3 then year(@StartDate)          else year(@StartDate) + 1 end)      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @Payroll_EmployeeTrialPayslip([EmployeeID], [TransactionTypeID], [SalaryHeadID], [Amount], [SalaryHeadTitle])       select       [PE].[Employee_ID],       [TransactionTypeID],       [SalaryHead_ID],       case when SH.SalaryHead_ID = 2 then        cast(((isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6)))         * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))      else cast(((isnull(cast(([Amount] / 12) as decimal(18, 6)), cast(0 as decimal(18, 6)))        * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) as decimal(18, 6))      end,      [SalaryHeadTitle]        from [Payroll_EmployeeSalaryTransaction] as [ET] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [ET].[EmployeeId] and [PayrollSalaryHeadID] = [ET].[SalaryHeadId] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ET].[EmployeeId]         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([ET].[EmployeeID] = @EmployeeID and not isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) in(4472, 4473, 4474, 4475)) and       (        [SH].[SalaryHead_ID] != 2          or [SH].[SalaryHead_ID] = 2        and        (         isnull([BonusPaymentDateID], @BonusDateID) = 1 and (month([JoiningDate]) = month(@StartDate) or month([JoiningDate]) = month(@UntilDate))          or isnull([BonusPaymentDateID], @BonusDateID) = 2 and (month([DateOfBirth]) = month(@StartDate) or month([DateOfBirth]) = month(@UntilDate))          or isnull([BonusPaymentDateID], @BonusDateID) = 3 and (@BonusMonth = month(@StartDate) or @BonusMonth = month(@UntilDate))          or isnull([BonusPaymentDateID], @BonusDateID) = 4 and [PE].[BonusMonth] is not null and ([PE].[BonusMonth] = month(@StartDate) or [PE].[BonusMonth] = month(@UntilDate))        )        and        --No employee can receive a bonus or a pro-rate bonus in his/her first month of employment.        (         year(@UntilDate) > year([PE].[JoiningDate])         or          (year(@UntilDate) = year([PE].[JoiningDate]) and month(@UntilDate) > month([PE].[JoiningDate]))         )        and        --Only one Bonus payment can be made during the Tax Year        not exists (         select top 1 1         from Payroll_PayrollResults AS PR         where [PR].[EmployeeID] = [EPD].[EmployeeID]          and [PR].[SalaryHeadID] = 2          and [PR].[TaxYear] = @TaxYear        )       )       update [TP] set [TP].[Value] = [ET].[Amount]       from [Payroll_EmployeeTrialPayslipSimulation] as [TP]        join @Payroll_EmployeeTrialPayslip as [ET] on [ET].[EmployeeID] = [TP].[EmployeeID] and [ET].[TransactionTypeID] = [TP].[TransactionTypeID] and [ET].[SalaryHeadID] = [TP].[SalaryHeadID]       where ([ET].[Amount] > 0)      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [TransactionTypeID], [SalaryHeadID], [EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SalaryHeadTitle], [Amount]        from @Payroll_EmployeeTrialPayslip as [ET]        where ([ET].[Amount] > 0 and not exists(          select top 1 [EmployeeID]           from [Payroll_EmployeeTrialPayslipSimulation]           where ([EmployeeID] = [ET].[EmployeeID] and [TransactionTypeID] = [ET].[TransactionTypeID] and [SalaryHeadID] = [ET].[SalaryHeadID])         )        )     end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeSDLCalculation_Trial_sp
-- Schema: dbo
-- ============================================
      /*  Payroll_EmployeeSDLCalculation_Trial_sp   Author  : FERDI BOTHA   Create date : 08/06/2017   Description : Employee SDL Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_EmployeeSDLCalculation_Trial_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin      set nocount on;     begin try      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID))      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @CalculationType int,      @Age int,      @income decimal(18, 6),      @pension decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @ExcludeSDL bit = (select isnull([ExcludeForSDL], 0) from [Payroll_Municipality] with(nolock) where ([Enabled] = 1)),      @SDLPercentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] = 4142 and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @LastEmployeeId int = -1;      declare @IRP5Code table (       [IRP5Code] int not null      )      declare @SDLCalculation table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [EmployeeID] [int] not null,     [CalculationType] int not null,     [Age] int not null,     [PayrollDefinationID] [int] not null,     [Amount] [decimal](18, 6) not null,     [Month] [nvarchar](10) not null,     [FinancialYear] [nvarchar](10) not null,     [PeriodID] [int] not null,     [TaxSavePurpose] [bit] not null default (0),     [SalaryHeadTitleAddendum] [nvarchar](200) null,     [VendorID] [int] null,     [TaxYear] [nvarchar](10) null      )      /* EMPLOYER SKILLS DEVELOPMENT LEVY (SDL) CONTRIBUTION [4142] */    insert into @IRP5Code([IRP5Code]) values(4142)      /* FORCE SDL TO READ FROM EMPLOYEE SUBTYPE CONFIGURATION */    if (not @ExcludeSDL = 0)       set @ExcludeSDL = 0      if (@ExcludeSDL = 0)    begin       insert into @SDLCalculation([Periods], [EmployeeID], [CalculationType], [Age], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [VendorID], [TaxYear])        select (         select isnull(max([PeriodInTaxYear]), @Periods)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)        ), [EPD].[EmployeeID], (case          when [TaxCalculationType] is null then 1          when [TaxCalculationType] > 4 then 1          else [TaxCalculationType]         end), (floor(datediff(day, [DateOfBirth], getdate()) / (365.242199))), [EmployeePayrollDefinition_ID], cast(0 as decimal(18, 6)), @Month, @SCOAYear, @PeriodID, [SalaryHeadTitle], [VendorID], @TaxYear         from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_GLItems] as [GL] with(nolock) on [SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and isnull([PE].[ExcludeSDL], 0) = 0 and [PE].[CycleID] = @CycleID          join [Payroll_EmployeeSubtypes] as [ES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ES].[ExcludeSDL] = 0          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1          join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 3 and          isnull([IRP5CertCode], [IRP5Code]) in(select [IRP5Code] from @IRP5Code) and          (case           when @CycleModeID = 1 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end           when @CycleModeID = 2 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end           else 0 end) = 1         )       select @c = count([ID]) from @SDLCalculation       while (@i <= @c)     begin        select @EmployeeID = [EmployeeID], @CalculationType = [CalculationType], @Age = [Age] from @SDLCalculation where ([ID] = @i)        /* CALCULATE TAXABLE INCOME */        IF (@EmployeeID <> @LastEmployeeId)              BEGIN                  /* 1) BASE TAXABLE INCOME FOR CURRENT PERIOD                        Types 01+02+03, taxable only, TxTypeID 1 & 4 */                  SELECT @income =                      COALESCE(SUM(                          CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *                          (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)                      ), 0.0)                  FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)                  JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)                       ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID                      AND EPD.Enabled = 1                  JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)                       ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID                      AND SH.Enabled = 1                  JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)                       ON IRP5.IRP5Code_ID = SH.IRP5CodeId                      AND IRP5.Enabled = 1                  JOIN @IRP5Income AS ETR                       ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)                      AND ETR.[Type]    IN (1, 2, 3)          -- 01 + 02 + 03                      AND ETR.Taxable   > 0                  -- taxable only                      AND ETR.StartDate <= @EndDate                      AND ETR.UntilDate >= @StartDate                  JOIN Payroll_Employee AS PE                   WITH (NOLOCK)                       ON PE.Employee_ID = ETP.EmployeeID                      AND PE.CycleID = @CycleID                  JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)                       ON CPD.CycleID   = PE.CycleID                      AND CPD.Period_ID = ETP.PeriodID                      AND CPD.Enabled   = 1                  JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)                       ON EP.Period_ID   = ETP.PeriodID                      AND EP.Employee_ID = ETP.EmployeeID                      AND EP.Cycle_ID    = PE.CycleID                  LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)                       ON ACPD.PeriodID    = CPD.Period_ID                      AND ACPD.SalaryHeadID = SH.SalaryHead_ID                  WHERE                      ETP.EmployeeID = @EmployeeID                      AND ETP.PeriodID = @PeriodID                      AND ETP.TaxSavePurpose = 0                      AND (                            CASE                               WHEN @CycleModeID = 1 THEN                                   CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                               WHEN @CycleModeID = 2 THEN                                   CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                               ELSE 0                            END                          ) = 1                      AND IRP5.TransactionTypeID IN (1, 4);          END      /* ANNUALIZE INCOME */      set @income = @income * cast(@Periods as decimal(18, 6))        /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS */      select @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                    from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                     join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                     join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                     join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                    where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)        /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */      if (@pension > 0)      begin         /* ANNUALIZE PENSION */       set @pension = @pension * cast(@Periods as decimal(18, 6))         /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN WE CAPPED THE PENSION TO 27.5% */       if (@pension > (@income * @pension_percentage))          set @pension = (@income * @pension_percentage)         /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN WE CAPPED THE PENSION TO 350, 000 */       if (@pension > @pension_value)          set @pension = @pension_value         set @income = @income - @pension        end        update @SDLCalculation set [Amount] = (@income * cast(@SDLPercentage as decimal(18, 6))) / cast(@Periods as decimal(18, 6)) where ([ID] = @i)        set @i = @i + 1       end       insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [VendorID], [TaxYear], [Simulation])        select [EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [VendorID], [TaxYear], @Simulation from @SDLCalculation         where ([Amount] > 0)      end     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)       end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeSDLCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 08/06/2017   Description : Employee SDL Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update Date : 11/04/2019 => Added Employee SDL Calculation (Simulation) @ Terminations  */  create procedure [Payroll_EmployeeSDLCalculation_TrialSimulation_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin      set nocount on;     begin try      declare @CycleID int = (select isnull([CycleID], 0) from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)),      @CycleModeID int = 1,      @TaxYear varchar(9) = (select [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'TaxYear'))      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID))      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @CalculationType int,      @Age int,      @income decimal(18, 6),      @pension decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @ExcludeSDL bit = (select isnull([ExcludeForSDL], 0) from [Payroll_Municipality] with(nolock) where ([Enabled] = 1)),      @SDLPercentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] = 4142 and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),        /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @XOR int = (1 ^ 8)      declare @IRP5Code table (       [IRP5Code] int not null      )      declare @SDLCalculation table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [EmployeeID] [int] not null,     [CalculationType] int not null,     [Age] int not null,     [PayrollDefinationID] [int] not null,     [Amount] [decimal](18, 6) not null,     [TaxSavePurpose] [bit] not null default (0),     [TransactionTypeID] int null,     [SalaryHeadID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      /* EMPLOYER SKILLS DEVELOPMENT LEVY (SDL) CONTRIBUTION [4142] */    insert into @IRP5Code([IRP5Code]) values(4142)      /* FORCE SDL TO READ FROM EMPLOYEE SUBTYPE CONFIGURATION */    if (not @ExcludeSDL = 0)       set @ExcludeSDL = 0      if (@ExcludeSDL = 0)    begin       insert into @SDLCalculation([Periods], [EmployeeID], [CalculationType], [Age], [PayrollDefinationID], [Amount], [TransactionTypeID], [SalaryHeadID], [SalaryHeadTitle])        select @Periods, [EPD].[EmployeeID], (case          when [TaxCalculationType] is null then 1          when [TaxCalculationType] > 4 then 1          else [TaxCalculationType]         end), (floor(datediff(day, [DateOfBirth], getdate()) / (365.242199))), [EmployeePayrollDefinition_ID], cast(0 as decimal(18, 6)), [IRP5].[TransactionTypeID], [SalaryHead_ID], [SalaryHeadTitle]         from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and isnull([PE].[ExcludeSDL], 0) = 0 and [PE].[CycleID] = @CycleID          join [Payroll_EmployeeSubtypes] as [ES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ES].[ExcludeSDL] = 0          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (           (isnull([TPS].[EmployeeChangeID], 0) = (case            when @SimulationType = 1 then @ParentID            else 0           end))           or           (isnull([TPS].[TerminationID], 0) = (case            when @SimulationType = 2 then @ParentID            else 0           end))          )         where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] = 3 and isnull([IRP5CertCode], [IRP5Code]) in(select [IRP5Code] from @IRP5Code))       select @c = count([ID]) from @SDLCalculation       while (@i <= @c)     begin        select @EmployeeID = [EmployeeID], @CalculationType = [CalculationType], @Age = [Age] from @SDLCalculation where ([ID] = @i)        /* CALCULATE TAXABLE INCOME */      exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] @IRP5Income, '01 + 02 + 03', @EmployeeID, @StartDate, @UntilDate, @CycleID, @CycleModeID, @XOR, @SimulationType, @ParentID, 1, @income out        /* ANNUALIZE INCOME */      set @income = @income * cast(@Periods as decimal(18, 6))        /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS */      select @pension = coalesce((select sum(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))))                    from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)                     join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID]                     join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                    where ([ETP].[EmployeeID] = @EmployeeID and [SimulationType] = @SimulationType and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)        /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */      if (@pension > 0)      begin         /* ANNUALIZE PENSION */       set @pension = @pension * cast(@Periods as decimal(18, 6))         /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN WE CAPPED THE PENSION TO 27.5% */       if (@pension > (@income * @pension_percentage))          set @pension = (@income * @pension_percentage)         /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN WE CAPPED THE PENSION TO 350, 000 */       if (@pension > @pension_value)          set @pension = @pension_value         set @income = @income - @pension        end        update @SDLCalculation set [Amount] = (@income * cast(@SDLPercentage as decimal(18, 6))) / cast(@Periods as decimal(18, 6)) where ([ID] = @i)        set @i = @i + 1       end       insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])        select @SimulationType, [TransactionTypeID], [SalaryHeadID], [EmployeeID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SalaryHeadTitle], [Amount] from @SDLCalculation where ([Amount] > 0)      end     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeSendNewPUK
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_EmployeeSendNewPUK 2  -- 18-10-2016 TP46985 add a table[Payroll_FinalRunFailures] to record if puk failed sending  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeSendNewPUK]      @EmployeeId INT ,      @PukId INT  AS          BEGIN          BEGIN TRY            BEGIN          DECLARE @Msg_Body VARCHAR(MAX) ,              @Schedule_Id INT ,              @EmpName NVARCHAR(105) ,              @PUKNo NVARCHAR(50),              @CycleID INT,     @PeriodID INT,     @Date DATETIME = GETDATE()           SELECT @CycleID=CycleID FROM Payroll_Employee WHERE Employee_ID=@EmployeeId      SELECT @PeriodID = Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE @Date BETWEEN PeriodStartDate AND PeriodEndDate AND CycleID = @CycleId AND CycleModeID = 1                SELECT  @Msg_Body = TemplateText ,                  @Schedule_Id = Schedule_ID          FROM    dbo.Cons_Email_Template                  INNER JOIN dbo.Cons_Email_Schedule ON dbo.Cons_Email_Template.Template_ID = dbo.Cons_Email_Schedule.TemplateID          WHERE   TemplateTitle = 'PUK'                  AND ModuleID = 3                  AND SendingType = 'Email'             SELECT  @EmpName = FirstName + ' ' + Surname          FROM    dbo.Payroll_Employee          WHERE   Employee_ID = @EmployeeId             SELECT  @PUKNo = PUKNo          FROM    dbo.Payroll_EmployeePUKDetails          WHERE   Id = @PukId             SET @Msg_Body = REPLACE(@Msg_Body, '##EmployeeName##', @EmpName)          SET @Msg_Body = REPLACE(@Msg_Body, '##PUK##', @PUKNo)             INSERT  INTO dbo.Cons_Email_Schedule_Details                  ( ScheduleID ,                    SendTo ,                    Subject ,                    Message ,                    IsSent ,                    ReferanceID                  )                  SELECT  @Schedule_Id ,                          @EmployeeId ,                          'PUK Number for Payslip' ,                          @Msg_Body ,                          0 ,                          @PukId      END            END TRY          BEGIN CATCH                    print 'error sending PUK'-- PRINT ERROR_MESSAGE()            ------------RECORD THE FAILURE IN Payroll_FinalRunFailures-----------------------   INSERT INTO [dbo].[Payroll_FinalRunFailures] (PeriodID,CycleID, EmployeeID , SourceOfFailure,CaptureID,DateCaptured)              VALUES (@PeriodID,@CycleID,@EmployeeId,'PUK',1,GETDATE())            END CATCH      END  

GO

-- ============================================
-- SP: Payroll_EmployeeSendPaySlip
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_EmployeeSendPaySlip 682  -- 18-10-2016 TP46985 add a table[Payroll_FinalRunFailures] to record if Email failed sending  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeSendPaySlip] @EmployeeId INT  AS       BEGIN          BEGIN TRY              IF EXISTS ( SELECT  *                          FROM    dbo.Payroll_EmployeePUKDetails                          WHERE   EmployeeId = @EmployeeId                                  AND [Password] IS NOT NULL )                   BEGIN                      DECLARE @Msg_Body NVARCHAR(MAX) ,                          @Schedule_Id INT ,                          @EmpName NVARCHAR(105) ,                          @Msg_Subject NVARCHAR(50) ,                          @PeriodID INT,        @CycleID INT                                            SELECT  @Msg_Body = TemplateText ,                              @Msg_Subject = TemplateTitle ,                              @Schedule_Id = Schedule_ID                      FROM    dbo.Cons_Email_Template                              INNER JOIN dbo.Cons_Email_Schedule ON dbo.Cons_Email_Template.Template_ID = dbo.Cons_Email_Schedule.TemplateID                      WHERE   TemplateTitle = 'Payslip'                              AND ModuleID = 3                              AND SendingType = 'Email'                        SELECT  @EmpName = FirstName + ' ' + Surname                      FROM    dbo.Payroll_Employee                      WHERE   Employee_ID = @EmployeeId                          SET @Msg_Body = REPLACE(@Msg_Body, '##EmployeeName##',                                              @EmpName)                           SELECT TOP 1                              @PeriodID = PeriodID,@CycleID = CycleID                      FROM    dbo.Payroll_EmployeePayslip EP       INNER JOIN Payroll_CyclePeriodDetails CPD ON EP.PeriodID = CPD.Period_ID                      WHERE   EmployeeID = @EmployeeId                      ORDER BY EP.DateCaptured DESC                           INSERT  INTO dbo.Cons_Email_Schedule_Details                              ( ScheduleID ,                                SendTo ,                                Subject ,                                Message ,                                IsSent ,                                ReferanceID                              )                              SELECT  @Schedule_Id ,                                      @EmployeeId ,                                      @Msg_Subject ,                                      @Msg_Body ,                                      0 ,                                      @PeriodID                  END              ELSE                   BEGIN                      DECLARE @Id INT                      SELECT  @Id = Id                      FROM    dbo.Payroll_EmployeePUKDetails                      WHERE   EmployeeId = @EmployeeId                      EXEC dbo.Payroll_EmployeeSendNewPUK @EmployeeId = @EmployeeId, -- int                           @PukId = @Id                  END          END TRY          BEGIN CATCH              PRINT 'Error on Payroll_EmployeeSendPaySlip ' --ERROR_MESSAGE()        ------------RECORD THE FAILURE IN Payroll_FinalRunFailures-----------------------   INSERT INTO [dbo].[Payroll_FinalRunFailures] (PeriodID,CycleID, EmployeeID , SourceOfFailure,CaptureID,DateCaptured)              VALUES (@PeriodID,@CycleID,@EmployeeId,'PUK',1,GETDATE())              END CATCH      END  

GO

-- ============================================
-- SP: Payroll_EmployeeSignoffReport_sp
-- Schema: dbo
-- ============================================
/*-- =============================================      Author: Richa Mills  Create date:  2018/06/25  Description: Generate Signoff Report  [Payroll_EmployeeSignoffReport_sp]  0,'February','2017/2018','Any',false  =============================================  Modified By: Ruan Strydom  Modified Date: 19/01/2021  Description: Bring in line with central data  ============================================= */  CREATE procedure [dbo].[Payroll_EmployeeSignoffReport_sp]      @CycleId INT ,      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN                    SELECT       [EmployeeNumber], [FirstTwoNames] AS [FirstName], [EmployeeSurnameOrTradingName] AS [Surname], [CertificateNumber] AS [IRP5Number], [CycleID] AS [Cycle]      FROM       Payroll_CertificateInformation      WHERE       (@CycleId = 0 OR [CycleId] = @CycleId)      AND [Month] = CASE WHEN @TaxPeriod = 'February' THEN 2 ELSE 8 END      AND [TransactionYear] = CASE WHEN @TaxPeriod = 'August' THEN (CAST(RIGHT(@TaxYear, 4) AS INT) - 1) ELSE CAST(RIGHT(@TaxYear, 4) AS INT) END      AND [IsTerminated] = @IsTerminated   ORDER BY    CASE     WHEN @SortIndex = 'Any' THEN [EmployeeID]     WHEN @SortIndex = 'Employee' THEN [FirstTwoNames]    END;    END;

GO

-- ============================================
-- SP: Payroll_EmployeeSummary_rpt
-- Schema: dbo
-- ============================================
 -- ==========================================================================================================================  -- Author: Seipei Mathole  -- Create date: 27 JUL 2016  -- Description: Returns employee(s) within a selected which match the equired selected date parameters according to Tax Year  -- Call: [Payroll_EmployeeSummary_rpt]'2017-03-01','2018-02-28',0,0,1,'EmployeeCode'  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date: 17/09/18 - Change SP to cater for all processing months - TP62352 - Richa Mills  -- Update date: 2018/04/17 - Change SP - TP69909 - Himil Modi  -- EXEC Payroll_EmployeeSummary_rpt '2017/03/01','2017/03/31',0,0,1  -- E Beetge WI41867 Terminated employees do not display any info    --Payroll_EmployeeSummary_rpt '2021/05/01','2021/05/31',0,0,16  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeSummary_rpt]   @FromDate DATETIME,  @ToDate DATETIME,  @Employee INT,  @Department INT,  @CycleId INT      AS    BEGIN       SELECT   CASE WHEN ctt.TransactionType_ID = 2 THEN 3 ELSE CASE WHEN ctt.TransactionType_ID = 3 THEN 2 ELSE ctt.TransactionType_ID END END AS SORTORDER,    ep.PeriodInTaxYear      ,emp.Employee_ID      ,emp.EmpCode      ,emp.FirstName  AS EmployeeName      ,emp.Surname AS Surname      ,ctt.TransactionType_ID      ,ctt.TransactionTypeDesc      ,sh.SalaryHeadName      ,PI.IRP5Code      ,cpd.ProcessingMonth      ,ep.Amount      ,cc.CycleDesc   FROM (SELECT     payslip.*       ,cyclePeriods.ProcessingMonth       ,cyclePeriods.PeriodInTaxYear    FROM Payroll_PayrollResults payslip    INNER JOIN Payroll_CyclePeriodDetails cyclePeriods     ON cyclePeriods.Period_ID = payslip.PeriodID    WHERE PeriodStartDate >= @FromDate    AND PeriodEndDate <= @ToDate    AND payslip.CycleID = (case when isnull(@Employee, 0) = 0 or @Employee = 0 then @CycleId else payslip.CycleID end)) ep   INNER JOIN Payroll_Employee emp    ON emp.Employee_ID = ep.EmployeeID   INNER JOIN dbo.Payroll_SalaryHead AS sh    ON ep.SalaryHeadID = sh.SalaryHead_ID   INNER JOIN dbo.Payroll_IRP5Code PI    ON sh.IRP5CodeId = PI.IRP5Code_ID   INNER JOIN dbo.Const_TransactionType ctt    ON PI.TransactionTypeID = ctt.TransactionType_ID   INNER JOIN Payroll_CyclePeriodDetails cpd    ON cpd.Period_ID = ep.PeriodID   INNER JOIN dbo.Payroll_Position pp    ON emp.PositionID = pp.Position_ID   INNER JOIN dbo.Const_Division d    ON pp.DivisionID = d.Division_ID   INNER JOIN dbo.Const_Cycle cc    ON emp.CycleID = cc.Cycle_ID   WHERE (emp.Employee_ID = @Employee OR ISNULL(@Employee,0) = 0)   AND (d.DepartmentID = @Department OR ISNULL(@Department,0) = 0)   --AND emp.CycleID = @CycleId  END

GO

-- ============================================
-- SP: Payroll_EmployeeTaxCalculation_Trial_Days_sp
-- Schema: dbo
-- ============================================
   /*    Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation  */  create procedure [dbo].[Payroll_EmployeeTaxCalculation_Trial_Days_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int , @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try            -- 🔸 New: clear explanation rows for this period / tax year          delete from Payroll_PayeCalculationExplain          where PeriodID = @PeriodID            and TaxYear = @TaxYear            and IsTrialRun = 1            and (@EmployeeID = 0 OR EmployeeID = @EmployeeID);      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)),      @TaxYearEndDate datetime = (select EndDate from Const_Payroll_TaxPeriods where TaxYear = right(@TaxYear,4) and cycleID = @CycleID)            ,@TaxYearStartDate date       ,@EmpStartDate     date       ,@EmpEndDate       date       ,@WorkStart        date       ,@WorkEnd          date       ,@DaysWorked       decimal(18,6)       ,@DaysInYear       decimal(18,6);               -- Get tax year start date     SELECT @TaxYearStartDate = CAST(StartDate AS date)     FROM Const_Payroll_TaxPeriods WITH (NOLOCK)     WHERE TaxYear = RIGHT(@TaxYear,4)       AND CycleID = @CycleID;       -- Get employee start/end dates     SELECT       @EmpStartDate = CAST(JoiningDate AS date),      @EmpEndDate   = CAST(EndDate    AS date)     FROM Payroll_Employee WITH (NOLOCK)     WHERE Employee_ID = @EmployeeID;       IF @EmpStartDate IS NULL      SET @EmpStartDate = @TaxYearStartDate;    -- Determine effective work window in this tax year  SET @WorkStart = CASE                       WHEN @EmpStartDate < @TaxYearStartDate THEN @TaxYearStartDate                      ELSE @EmpStartDate                   END;    SET @WorkEnd = CASE                       WHEN @EmpEndDate IS NULL OR @EmpEndDate > CAST(@EndDate AS date)                           THEN CAST(@EndDate AS date)                      ELSE @EmpEndDate                 END;    -- Calculate DaysWorked (inclusive)  SET @DaysWorked = CASE                       WHEN @WorkEnd < @WorkStart THEN 0                      ELSE DATEDIFF(DAY, @WorkStart, @WorkEnd) + 1                    END;    -- Calculate DaysInYear (inclusive)  SET @DaysInYear = DATEDIFF(DAY, @TaxYearStartDate, CAST(@TaxYearEndDate AS date)) + 1;    -- Safety: avoid division by zero  IF @DaysWorked <= 0 SET @DaysWorked = 1;  IF @DaysInYear <= 0 SET @DaysInYear = 365;         declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 0,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6),      @incomeBonusYearToDate decimal(18, 6),      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @payeHistoryType decimal(18, 6),      @payeHistoryPeriod int,      @payeHistoryValue decimal(18, 6),      @payeHistoryBonus decimal(18, 6),      @payeHistoryBalance decimal(18, 6),      /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @LastEmployeeId int = -1;      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [VendorID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [Age], [Amount], [PayrollDefinationID], [VendorID], [SalaryHeadTitle])       select (         select isnull(max([PeriodInTaxYear]), @Periods)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)        ), (         select isnull(max([PeriodInTaxYear]), @Month)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [Processed] = 1 and [TaxYear] = @TaxYear)        ), (         CASE         WHEN @Periods <> 12 THEN         (          SELECT COUNT(DISTINCT [PeriodID])          FROM [Payroll_PayrollResults] AS [PR] WITH (NOLOCK)          JOIN [Payroll_CyclePeriodDetails] AS [CPR] WITH (NOLOCK)            ON [PR].[PeriodID] = [CPR].[Period_ID]             AND ([CPR].[CycleModeID] = 1             OR ([CPR].[CycleModeID] = 2              AND [CPR].[AdhocTypeID] = 1              AND [CPR].[AdhocTerminationTypeID] = 1))             AND [CPR].[Enabled] = 1          WHERE [EmployeeID] = [EPD].[EmployeeID]            AND [PR].[TaxYear] = CAST(RIGHT(@TaxYear, 4) AS INT)         )        ELSE         ISNULL(          (           SELECT SUM(MonthsWorked)           FROM payroll_employeeperiodsworked pew           WHERE pew.EmployeeID = [EPD].[EmployeeID]             AND pew.TaxYear  = @TaxYear          ),          0         )       END        ), [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), (floor(datediff(day, [DateOfBirth], @TaxYearEndDate) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [VendorID], [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and         [SalaryHead_ID] = 3               and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      select @c = count([ID]) from @paye      while (@i <= @c)    begin        DECLARE @ExplainSeq INT;       SET @ExplainSeq = 10;       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @Age = [Age] from @paye where ([ID] = @i)          DECLARE @StartDateInTaxYear DATETIME = (select StartdateInTaxYear from payroll_ClassicPeriods where EmployeeID = @EmployeeID)          SELECT       @EmpStartDate = CAST(JoiningDate AS date),      @EmpEndDate   = CAST(EndDate    AS date)     FROM Payroll_Employee WITH (NOLOCK)     WHERE Employee_ID = @EmployeeID;    IF @StartDateInTaxYear IS NOT NULL      SET @EmpStartDate = @StartDateInTaxYear;     SET @WorkStart = CASE                       WHEN @EmpStartDate < @TaxYearStartDate THEN @TaxYearStartDate                      ELSE @EmpStartDate                   END;    SET @WorkEnd = CASE                       WHEN @EmpEndDate IS NULL OR @EmpEndDate > CAST(@EndDate AS date)                           THEN CAST(@EndDate AS date)                      ELSE @EmpEndDate                 END;    SET @DaysWorked = CASE                       WHEN @WorkEnd < @WorkStart THEN 0                      ELSE DATEDIFF(DAY, @WorkStart, @WorkEnd) + 1                    END;    IF @DaysWorked <= 0 SET @DaysWorked = 1;  -- @DaysInYear can stay global, no need to recompute per employee     select @TaxDirectiveType = 0       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodID as [PeriodID], @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     IF (@EmployeeID <> @LastEmployeeID)  BEGIN      SELECT @income =          COALESCE(SUM(              CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *              (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)          ), 0.0)      FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)      JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)           ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID          AND EPD.Enabled = 1      JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)           ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID          AND SH.Enabled = 1      JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)           ON IRP5.IRP5Code_ID = SH.IRP5CodeId          AND IRP5.Enabled = 1      JOIN @IRP5Income AS ETR           ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)          AND ETR.[Type]    IN (1, 2, 3)            -- 01 + 02 + 03          AND ETR.Taxable   > 0                    -- taxable only (same as @taxable = 1)          AND ETR.StartDate <= @EndDate          AND ETR.UntilDate >= @StartDate      JOIN Payroll_Employee AS PE                   WITH (NOLOCK)           ON PE.Employee_ID = ETP.EmployeeID          AND PE.CycleID = @CycleID      JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)           ON CPD.CycleID   = PE.CycleID          AND CPD.Period_ID = ETP.PeriodID          AND CPD.Enabled   = 1      JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)           ON EP.Period_ID   = ETP.PeriodID          AND EP.Employee_ID = ETP.EmployeeID          AND EP.Cycle_ID    = PE.CycleID      LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)           ON ACPD.PeriodID    = CPD.Period_ID          AND ACPD.SalaryHeadID = SH.SalaryHead_ID      WHERE          ETP.EmployeeID = @EmployeeID          AND ETP.PeriodID = @PeriodID          AND ETP.TaxSavePurpose = 0          AND (                CASE                   WHEN @CycleModeID = 1 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                   WHEN @CycleModeID = 2 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                   ELSE 0                END              ) = 1          AND IRP5.TransactionTypeID IN (1, 4);      -- same Tx types as UIF        SET @LastEmployeeID = @EmployeeID;  END          /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = coalesce((select sum([Amount] * ([TatxablePercentage] / 100))               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1               where ([EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                [PR].[TransactionTypeID] in(1, 4) and not [PR].[SalaryHeadID] in(2) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(                 /* 01 - INCOME RECORD(S) */               3601, 3651, 3602, 3652, 3603, 3653, 3604, 3654, 3606, 3656, 3607, 3657, 3608, 3658, 3609, 3659, 3610, 3660, 3611, 3661, 3612, 3662, 3613, 3663, 3614, 3664, 3615, 3665, 3616, 3666, 3617, 3667, 3619, 3669, 3620, 3670, 3621,                 /* 02 - ALLOWANCE RECORD(S) */               3701, 3722, 3751, 3701, 3751, 3702, 3752, 3703, 3753, 3704, 3754, 3705, 3755, 3706, 3756, 3707, 3757, 3708, 3758, 3709, 3759, 3710, 3760, 3711, 3761, 3712, 3762, 3713, 3763, 3714, 3764, 3715, 3765, 3716, 3766, 3717, 3767, 3718, 3768, 3719, 3769, 3720, 3770, 3721, 3771,                 /* 03 - FRINGE BENEFIT RECORD(S) */               3801, 3851, 3802, 3852, 3803, 3853, 3804, 3854, 3805, 3855, 3806, 3856, 3807, 3857, 3808, 3858, 3809, 3859, 3810, 3860, 3813, 3863, 3815, 3865, 3816, 3866, 3817, 3867, 3820, 3870, 3821, 3871, 3822, 3872, 3825, 3875, 3828, 3878, 3833                )               )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and not [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and not [PR].[SalaryHeadID] in(4, 5) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102 and not [PR].[PeriodID] in(                   select [Period_ID] from [Payroll_PayrollRun_History_Employees] with(nolock) where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)                  ))), 0)          /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS */     set @payeValueYearToDate = @payeValueYearToDate + coalesce((select sum([PAYEBalance] + [PAYEValue])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [CycleModeID] = @CycleModeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = 4 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = coalesce((select sum([TaxCredits])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear)), 0)    -- build ExtraInfo for the explanation row  DECLARE @ExtraInfo_Income VARCHAR(MAX);  DECLARE @CombinedIncome   DECIMAL(18,6);    SET @ExtraInfo_Income =    'IncomeCurrent' + CAST(@income AS VARCHAR(50))   + '; YTDIncome'  + CAST(@incomeYearToDate AS VARCHAR(50))      + '; AnnualCurrent='         + CAST(@incomeAnnual AS VARCHAR(50))      + '; AnnualYTD='      + CAST(@incomeAnnualYearToDate AS VARCHAR(50))      + '; BonusCurrent='          + CAST(@incomeBonus AS VARCHAR(50))      + '; BonusYTD='       + CAST(@incomeBonusYearToDate AS VARCHAR(50))      + '; PAYE_YTD='       + CAST(@payeValueYearToDate AS VARCHAR(50))      + '; PAYE_BonusYTD='  + CAST(@payeValueBonusYearToDate AS VARCHAR(50))      + '; CreditsYTD='     + CAST(@payeCreditsYearToDate AS VARCHAR(50));    SET @CombinedIncome = @income + @incomeYearToDate;    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'INCOME',      @LineCode         = 'RAW_INCOME_YTD',      @LineDescription  = 'Taxable income for PAYE (current + year-to-date, incl. annual/bonus where applicable)',      @SourceAmount     = @income,      @YTDAmount        = @incomeYearToDate,      @CalculatedAmount = @CombinedIncome,      @ExtraInfo        = @ExtraInfo_Income,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;  /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)          /* ANNUALIZE INCOME: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @income = (((@income + @incomeYearToDate) / @DaysWorked) * @DaysInYear)        DECLARE @ExtraInfo_Annualised VARCHAR(MAX);    SET @ExtraInfo_Annualised =    CAST(@DaysWorked AS VARCHAR(10))         EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'INCOME',      @LineCode         = 'ANNUALISED_INCOME',      @LineDescription  = 'Annualised taxable income after removing annual/bonus amounts - CombinedIco/DaysWorked * DaysInYear',      @SourceAmount     = @income,      @YTDAmount        = NULL,      @CalculatedAmount = @income,      @ExtraInfo        = @ExtraInfo_Annualised,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;           /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))               from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]               where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)         /* CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pensionYearToDate = coalesce((select sum([Amount])        from [Payroll_PayrollResults] as [PR] with(nolock)         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]         join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1        where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and         isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878)        )), 0)       /* ANNUALIZE PENSION: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @pension = (((@pension + @pensionYearToDate) / @DaysWorked) * @DaysInYear)       /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */     if (@pension > 0)     begin        /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN PENSION IS CAPPED TO 27.5% */      if (@pension > (@income * @pension_percentage))         set @pension = (@income * @pension_percentage)        /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN PENSION IS CAPPED TO 350, 000 */      if (@pension > @pension_value)         set @pension = @pension_value        set @income = @income - @pension         end       DECLARE @ExtraInfo_Pension VARCHAR(MAX);    SET @ExtraInfo_Pension =        'Pension%Cap=' + CAST(@pension_percentage AS VARCHAR(50))      + '; PensionMax=' + CAST(@pension_value AS VARCHAR(50));    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'DEDUCTIONS',      @LineCode         = 'PENSION_RA',      @LineDescription  = 'Pension / Provident / RA contributions deducted (capped per SARS rules)',      @SourceAmount     = @pension,      @YTDAmount        = @pensionYearToDate,      @CalculatedAmount = @income,      @ExtraInfo        = @ExtraInfo_Pension,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;       /* CALCULATE TAX ACCORDING TO SARS TAX SCALES */     if (@CalculationType % 2 = 1)     begin        select @payeMinValue = cast([TaxThresholdsAmount] as decimal(18, 6)) from [Const_TaxThresholds] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and ([MaxAge] is null or [MaxAge] >= @Age) and [FinancialYear] = @TaxYear)        select @payeRebates = cast(sum(isnull([TaxRebatesAmount], 0)) as decimal(18, 6)) from [Const_TaxRebates] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and [FinancialYear] = @TaxYear)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       DECLARE @ExtraInfo_Threshold VARCHAR(MAX);    SET @ExtraInfo_Threshold = 'Age=' + CAST(@Age AS VARCHAR(10));    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'TAX',      @LineCode         = 'THRESHOLD_REBATES',      @LineDescription  = 'Tax thresholds and annual rebates based on age',      @SourceAmount     = @payeMinValue,      @YTDAmount        = NULL,      @CalculatedAmount = @payeRebates,      @ExtraInfo        = @ExtraInfo_Threshold,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;       /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        if(@income > @payeMinValue)      begin        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */      if (@CalculationType % 2 = 1)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         --@PayeValue1       set @payeValue = (@payeFix

GO

-- ============================================
-- SP: Payroll_EmployeeTaxCalculation_Trial_Periods_sp
-- Schema: dbo
-- ============================================
    /*      Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation   Update Date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update Date : 30/06/2017 - Updated the joins to the correct mappings   Update Date : 12/02/2018 - Updated the PAYE Pension, Provident and Retirement Fund mappings   Update Date : 03/04/2018 - Updated Tax Spread (Bonus)   Update Date :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Update Date :   28/08/2019 - CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS   Update Date :   31/03/2021 - Richa M - IRP5Code 3833 not included in annualized income   Update Date : 2021/08/11 - Richa M Fix Secondary and Tertiary Rebates to calculate if employee reaches the specific age within the YOA   Update Date : 2021/08/22 - Richa M If no bonus tax will be calculated we need to check for negative PAYE amounts   Update Date : 2021/11/10 - Richa M Cater for Secondary MTC for employees over 65   Update Date : 2022/03/14 - Richa M PAYE not calculating for Additional Term run  */  create procedure [dbo].[Payroll_EmployeeTaxCalculation_Trial_Periods_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int , @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      delete from Payroll_PayrollRunLog where PeriodId = @PeriodId and (EmployeeId = @EmployeeId or @EmployeeID = 0) and Source = 'Payroll_EmployeeTaxCalculation_Trial_sp'      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)),      @TaxYearEndDate datetime = (select EndDate from Const_Payroll_TaxPeriods where TaxYear = right(@TaxYear,4) and cycleID = @CycleID)      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 0,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6),      @incomeBonusYearToDate decimal(18, 6),      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @payeHistoryType decimal(18, 6),      @payeHistoryPeriod int,      @payeHistoryValue decimal(18, 6),      @payeHistoryBonus decimal(18, 6),      @payeHistoryBalance decimal(18, 6),      @trialRunLogs varchar(max) = '',      /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @LastEmployeeId int = -1;      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [VendorID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [Age], [Amount], [PayrollDefinationID], [VendorID], [SalaryHeadTitle])       select (         select isnull(max([PeriodInTaxYear]), @Periods)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)        ), (         select isnull(max([PeriodInTaxYear]), @Month)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [Processed] = 1 and [TaxYear] = @TaxYear)        ), (         select count(distinct [PeriodID])          from [Payroll_PayrollResults] as [PR] with(nolock)           join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [PR].[PeriodID] = [CPR].[Period_ID]                   and ([CPR].[CycleModeID] = 1 OR ([CPR].[CycleModeID] = 2 AND [CPR].[AdhocTypeID] = 1 AND [CPR].[AdhocTerminationTypeID] = 1 ))                  and [CPR].[Enabled] = 1          where ([EmployeeID] = [EPD].[EmployeeID] and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int))        ), [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), (floor(datediff(day, [DateOfBirth], @TaxYearEndDate) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [VendorID], [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and         [SalaryHead_ID] = 3               and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      select @c = count([ID]) from @paye      while (@i <= @c)    begin       set @trialRunLogs = ''       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @Age = [Age] from @paye where ([ID] = @i)          select @TaxDirectiveType = 0       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodID as [PeriodID], @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     IF (@EmployeeID <> @LastEmployeeID)  BEGIN      SELECT @income =          COALESCE(SUM(              CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *              (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)          ), 0.0)      FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)      JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)           ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID          AND EPD.Enabled = 1      JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)           ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID          AND SH.Enabled = 1      JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)           ON IRP5.IRP5Code_ID = SH.IRP5CodeId          AND IRP5.Enabled = 1      JOIN @IRP5Income AS ETR           ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)          AND ETR.[Type]    IN (1, 2, 3)            -- 01 + 02 + 03          AND ETR.Taxable   > 0                    -- taxable only (same as @taxable = 1)          AND ETR.StartDate <= @EndDate          AND ETR.UntilDate >= @StartDate      JOIN Payroll_Employee AS PE                   WITH (NOLOCK)           ON PE.Employee_ID = ETP.EmployeeID          AND PE.CycleID = @CycleID      JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)           ON CPD.CycleID   = PE.CycleID          AND CPD.Period_ID = ETP.PeriodID          AND CPD.Enabled   = 1      JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)           ON EP.Period_ID   = ETP.PeriodID          AND EP.Employee_ID = ETP.EmployeeID          AND EP.Cycle_ID    = PE.CycleID      LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)           ON ACPD.PeriodID    = CPD.Period_ID          AND ACPD.SalaryHeadID = SH.SalaryHead_ID      WHERE          ETP.EmployeeID = @EmployeeID          AND ETP.PeriodID = @PeriodID          AND ETP.TaxSavePurpose = 0          AND (                CASE                   WHEN @CycleModeID = 1 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                   WHEN @CycleModeID = 2 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                   ELSE 0                END              ) = 1          AND IRP5.TransactionTypeID IN (1, 4);      -- same Tx types as UIF        SET @LastEmployeeID = @EmployeeID;  END          /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = coalesce((select sum([Amount] * ([TatxablePercentage] / 100))               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1               where ([EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                [PR].[TransactionTypeID] in(1, 4) and not [PR].[SalaryHeadID] in(2) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(                 /* 01 - INCOME RECORD(S) */               3601, 3651, 3602, 3652, 3603, 3653, 3604, 3654, 3606, 3656, 3607, 3657, 3608, 3658, 3609, 3659, 3610, 3660, 3611, 3661, 3612, 3662, 3613, 3663, 3614, 3664, 3615, 3665, 3616, 3666, 3617, 3667, 3619, 3669, 3620, 3670, 3621,                 /* 02 - ALLOWANCE RECORD(S) */               3701, 3722, 3751, 3701, 3751, 3702, 3752, 3703, 3753, 3704, 3754, 3705, 3755, 3706, 3756, 3707, 3757, 3708, 3758, 3709, 3759, 3710, 3760, 3711, 3761, 3712, 3762, 3713, 3763, 3714, 3764, 3715, 3765, 3716, 3766, 3717, 3767, 3718, 3768, 3719, 3769, 3720, 3770, 3721, 3771,                 /* 03 - FRINGE BENEFIT RECORD(S) */               3801, 3851, 3802, 3852, 3803, 3853, 3804, 3854, 3805, 3855, 3806, 3856, 3807, 3857, 3808, 3858, 3809, 3859, 3810, 3860, 3813, 3863, 3815, 3865, 3816, 3866, 3817, 3867, 3820, 3870, 3821, 3871, 3822, 3872, 3825, 3875, 3828, 3878, 3833                )               )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and not [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and not [PR].[SalaryHeadID] in(4, 5) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102 and not [PR].[PeriodID] in(                   select [Period_ID] from [Payroll_PayrollRun_History_Employees] with(nolock) where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)                  ))), 0)          /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS */     set @payeValueYearToDate = @payeValueYearToDate + coalesce((select sum([PAYEBalance] + [PAYEValue])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [CycleModeID] = @CycleModeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = 4 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = coalesce((select sum([TaxCredits])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear)), 0)       set @trialRunLogs = CONCAT(@trialRunLogs, '@YTDTaxableIncome,', @income + @incomeYearToDate, '| @income=', @income, ' | @incomeYearToDate= ', @incomeYearToDate, ' | @incomeAnnual= ', @incomeAnnual, ' | @incomeAnnualYearToDate = ', @incomeAnnualYearToDate,' | @incomeBonus= ',@incomeBonus,' | @incomeBonusYearToDate= ',@incomeBonusYearToDate,' | @payeValueYearToDate= ',@payeValueYearToDate,' | @payeValueBonusYearToDate= ',@payeValueBonusYearToDate,' | @payeCreditsYearToDate= ',@payeCreditsYearToDate)        /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)          /* ANNUALIZE INCOME: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @income = (((@income + @incomeYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       /* DEDUCT ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     /*set @income = @income - (@incomeAnnualYearToDate + @incomeBonusYearToDate)*/       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'DEDUCT ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'       /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))               from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]               where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)         /* CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pensionYearToDate = coalesce((select sum([Amount])        from [Payroll_PayrollResults] as [PR] with(nolock)         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]         join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1        where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and         isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878)        )), 0)       /* ANNUALIZE PENSION: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @pension = (((@pension + @pensionYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */     if (@pension > 0)     begin        /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN PENSION IS CAPPED TO 27.5% */      if (@pension > (@income * @pension_percentage))         set @pension = (@income * @pension_percentage)        /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN PENSION IS CAPPED TO 350, 000 */      if (@pension > @pension_value)         set @pension = @pension_value        set @income = @income - @pension         end       set @trialRunLogs = CONCAT(@trialRunLogs, '| @AnnualisedTaxableIncomeD27=', @income)         /* CALCULATE TAX ACCORDING TO SARS TAX SCALES */     if (@CalculationType % 2 = 1)     begin        select @payeMinValue = cast([TaxThresholdsAmount] as decimal(18, 6)) from [Const_TaxThresholds] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and ([MaxAge] is null or [MaxAge] >= @Age) and [FinancialYear] = @TaxYear)        select @payeRebates = cast(sum(isnull([TaxRebatesAmount], 0)) as decimal(18, 6)) from [Const_TaxRebates] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and [FinancialYear] = @TaxYear)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       set @trialRunLogs = CONCAT(@trialRunLogs, '| @PayeMinValue=', @payeMinValue,'| @payeRebates=', @payeRebates)         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        if(@income > @payeMinValue)      begin        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */      if (@CalculationType % 2 = 1)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         --@PayeValue1       set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))        end        set @trialRunLogs = CONCAT(@trialRunLogs,'| @payeFixedValue=', @payeFixedValue,'| @payeStartValue=', @payeStartValue,'| @payePercentage=', @payePercentage, '| @PayeValue1D28=', @payeValue)          /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 0 and @income > @payeMinValue)      begin         set @payeStartValue = cast(0 as decimal(18, 6))         set @payeFixedValue = cast(0 as decimal(18, 6))         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVE */       if (@CalculationType = 2)       begin          select @payePercentage = coalesce((select sum((case             when [DirectiveTypeId] = 1 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @payeValue = coalesce((select sum((case             when [DirectiveTypeId] = 1 then (@income * (@payePercentage / cast(100 as decimal(18, 6))))             when [DirectiveTypeId] = 2 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @TaxDirectiveType = [DirectiveTypeId] from [Payroll_EmployeeTaxDirectives] with(nolock) where ([Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)         end         /* CALCULATE TAX ACCORDING TO EMPLOYEE PART TIME COUNCILLORS DIRECTIVE */       if (@CalculationType = 4)       begin          set @payePercentage = @payePercentageCouncillors          set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         end        end        set @payeValueBonus = 0           /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */      if (@BonusCalculationType = 2)      begin         set @incomeAnnual = @incomeAnnual + @incomeBonus         set @incomeAnnualYearToDate = @incomeAnnualYearToDate + @incomeBonusYearToDate         set @trialRunLogs = CONCAT(@trialRunLogs, ' new @incomeAnnual=', @incomeAnnual, ' new @incomeAnnualYearToDate=', @incomeAnnualYearToDate)        end        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; INCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 1 and (@incomeAnnual + @incomeAnnualYearToDate) > 0 and (@income + (@incomeAnnual + @incomeAnnualYearToDate)) > @payeMinValue)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= (@income + (@incomeAnnual + @incomeAnnualYearToDate)) and ([MaxSlotAmount] is null or [MaxSlotAmount] >= (@income + (@incomeAnnual + @incomeAnnualYearToDate))) and [FinancialYear] = @TaxYear)         set @payeValueBonus = (@payeFixedValue + (((@income + (@incomeAnnual + @incomeAnnualYearToDate)) - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         set @payeValueBonus = (@payeValueBonus - @payeValue)        end        DECLARE @EmpTerminatedThisMonth int =        (select count(*) from Payroll_Emp

GO

