-- SP: Payroll_EmployeeTaxCalculation_TrialOld_sp
-- Schema: dbo
-- ============================================
 /*    Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation   Update Date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update Date : 30/06/2017 - Updated the joins to the correct mappings   Update Date : 12/02/2018 - Updated the PAYE Pension, Provident and Retirement Fund mappings   Update Date : 03/04/2018 - Updated Tax Spread (Bonus)   Update Date :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Update Date :   28/08/2019 - CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS   Update Date :   31/03/2021 - Richa M - IRP5Code 3833 not included in annualized income   Update Date : 2021/08/11 - Richa M Fix Secondary and Tertiary Rebates to calculate if employee reaches the specific age within the YOA   Update Date : 2021/08/22 - Richa M If no bonus tax will be calculated we need to check for negative PAYE amounts   Update Date : 2021/11/10 - Richa M Cater for Secondary MTC for employees over 65   Update Date : 2022/03/14 - Richa M PAYE not calculating for Additional Term run  */  Create procedure [dbo].[Payroll_EmployeeTaxCalculation_TrialOld_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int , @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      delete from Payroll_PayrollRunLog where PeriodId = @PeriodId and (EmployeeId = @EmployeeId or @EmployeeID = 0) and Source = 'Payroll_EmployeeTaxCalculation_Trial_sp'      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)),      @TaxYearEndDate datetime = (select EndDate from Const_Payroll_TaxPeriods where TaxYear = right(@TaxYear,4) and cycleID = @CycleID)      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 0,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6),      @incomeBonusYearToDate decimal(18, 6),      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @payeHistoryType decimal(18, 6),      @payeHistoryPeriod int,      @payeHistoryValue decimal(18, 6),      @payeHistoryBonus decimal(18, 6),      @payeHistoryBalance decimal(18, 6),      @trialRunLogs varchar(max) = '',      /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @LastEmployeeId int = -1;      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [VendorID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [Age], [Amount], [PayrollDefinationID], [VendorID], [SalaryHeadTitle])       select (         select isnull(max([PeriodInTaxYear]), @Periods)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)        ), (         select isnull(max([PeriodInTaxYear]), @Month)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [Processed] = 1 and [TaxYear] = @TaxYear)        ), (         CASE         WHEN @Periods <> 12 THEN         (          SELECT COUNT(DISTINCT [PeriodID])          FROM [Payroll_PayrollResults] AS [PR] WITH (NOLOCK)          JOIN [Payroll_CyclePeriodDetails] AS [CPR] WITH (NOLOCK)            ON [PR].[PeriodID] = [CPR].[Period_ID]             AND ([CPR].[CycleModeID] = 1             OR ([CPR].[CycleModeID] = 2              AND [CPR].[AdhocTypeID] = 1              AND [CPR].[AdhocTerminationTypeID] = 1))             AND [CPR].[Enabled] = 1          WHERE [EmployeeID] = [EPD].[EmployeeID]            AND [PR].[TaxYear] = CAST(RIGHT(@TaxYear, 4) AS INT)         )        ELSE         ISNULL(          (           SELECT SUM(MonthsWorked)           FROM payroll_employeeperiodsworked pew           WHERE pew.EmployeeID = [EPD].[EmployeeID]             AND pew.TaxYear  = @TaxYear          ),          0         )       END        ), [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), (floor(datediff(day, [DateOfBirth], @TaxYearEndDate) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [VendorID], [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and         [SalaryHead_ID] = 3               and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      select @c = count([ID]) from @paye      while (@i <= @c)    begin       set @trialRunLogs = ''       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @Age = [Age] from @paye where ([ID] = @i)          select @TaxDirectiveType = 0       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodID as [PeriodID], @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     IF (@EmployeeID <> @LastEmployeeID)  BEGIN      SELECT @income =          COALESCE(SUM(              CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *              (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)          ), 0.0)      FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)      JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)           ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID          AND EPD.Enabled = 1      JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)           ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID          AND SH.Enabled = 1      JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)           ON IRP5.IRP5Code_ID = SH.IRP5CodeId          AND IRP5.Enabled = 1      JOIN @IRP5Income AS ETR           ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)          AND ETR.[Type]    IN (1, 2, 3)            -- 01 + 02 + 03          AND ETR.Taxable   > 0                    -- taxable only (same as @taxable = 1)          AND ETR.StartDate <= @EndDate          AND ETR.UntilDate >= @StartDate      JOIN Payroll_Employee AS PE                   WITH (NOLOCK)           ON PE.Employee_ID = ETP.EmployeeID          AND PE.CycleID = @CycleID      JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)           ON CPD.CycleID   = PE.CycleID          AND CPD.Period_ID = ETP.PeriodID          AND CPD.Enabled   = 1      JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)           ON EP.Period_ID   = ETP.PeriodID          AND EP.Employee_ID = ETP.EmployeeID          AND EP.Cycle_ID    = PE.CycleID      LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)           ON ACPD.PeriodID    = CPD.Period_ID          AND ACPD.SalaryHeadID = SH.SalaryHead_ID      WHERE          ETP.EmployeeID = @EmployeeID          AND ETP.PeriodID = @PeriodID          AND ETP.TaxSavePurpose = 0          AND (                CASE                   WHEN @CycleModeID = 1 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                   WHEN @CycleModeID = 2 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                   ELSE 0                END              ) = 1          AND IRP5.TransactionTypeID IN (1, 4);      -- same Tx types as UIF        SET @LastEmployeeID = @EmployeeID;  END          /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = coalesce((select sum([Amount] * ([TatxablePercentage] / 100))               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1               where ([EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                [PR].[TransactionTypeID] in(1, 4) and not [PR].[SalaryHeadID] in(2) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(                 /* 01 - INCOME RECORD(S) */               3601, 3651, 3602, 3652, 3603, 3653, 3604, 3654, 3606, 3656, 3607, 3657, 3608, 3658, 3609, 3659, 3610, 3660, 3611, 3661, 3612, 3662, 3613, 3663, 3614, 3664, 3615, 3665, 3616, 3666, 3617, 3667, 3619, 3669, 3620, 3670, 3621,                 /* 02 - ALLOWANCE RECORD(S) */               3701, 3722, 3751, 3701, 3751, 3702, 3752, 3703, 3753, 3704, 3754, 3705, 3755, 3706, 3756, 3707, 3757, 3708, 3758, 3709, 3759, 3710, 3760, 3711, 3761, 3712, 3762, 3713, 3763, 3714, 3764, 3715, 3765, 3716, 3766, 3717, 3767, 3718, 3768, 3719, 3769, 3720, 3770, 3721, 3771,                 /* 03 - FRINGE BENEFIT RECORD(S) */               3801, 3851, 3802, 3852, 3803, 3853, 3804, 3854, 3805, 3855, 3806, 3856, 3807, 3857, 3808, 3858, 3809, 3859, 3810, 3860, 3813, 3863, 3815, 3865, 3816, 3866, 3817, 3867, 3820, 3870, 3821, 3871, 3822, 3872, 3825, 3875, 3828, 3878, 3833                )               )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and not [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and not [PR].[SalaryHeadID] in(4, 5) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102 and not [PR].[PeriodID] in(                   select [Period_ID] from [Payroll_PayrollRun_History_Employees] with(nolock) where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)                  ))), 0)          /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS */     set @payeValueYearToDate = @payeValueYearToDate + coalesce((select sum([PAYEBalance] + [PAYEValue])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [CycleModeID] = @CycleModeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = 4 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = coalesce((select sum([TaxCredits])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear)), 0)       set @trialRunLogs = CONCAT(@trialRunLogs, '@YTDTaxableIncome,', @income + @incomeYearToDate, '| @income=', @income, ' | @incomeYearToDate= ', @incomeYearToDate, ' | @incomeAnnual= ', @incomeAnnual, ' | @incomeAnnualYearToDate = ', @incomeAnnualYearToDate,' | @incomeBonus= ',@incomeBonus,' | @incomeBonusYearToDate= ',@incomeBonusYearToDate,' | @payeValueYearToDate= ',@payeValueYearToDate,' | @payeValueBonusYearToDate= ',@payeValueBonusYearToDate,' | @payeCreditsYearToDate= ',@payeCreditsYearToDate)        /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)          /* ANNUALIZE INCOME: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @income = (((@income + @incomeYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       /* DEDUCT ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     /*set @income = @income - (@incomeAnnualYearToDate + @incomeBonusYearToDate)*/       --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'DEDUCT ANNUAL YEAR-TO-DATE PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'       /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))               from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]               where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)         /* CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pensionYearToDate = coalesce((select sum([Amount])        from [Payroll_PayrollResults] as [PR] with(nolock)         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]         join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1        where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and         isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878)        )), 0)       /* ANNUALIZE PENSION: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @pension = (((@pension + @pensionYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */     if (@pension > 0)     begin        /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN PENSION IS CAPPED TO 27.5% */      if (@pension > (@income * @pension_percentage))         set @pension = (@income * @pension_percentage)        /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN PENSION IS CAPPED TO 350, 000 */      if (@pension > @pension_value)         set @pension = @pension_value        set @income = @income - @pension         end       set @trialRunLogs = CONCAT(@trialRunLogs, '| @AnnualisedTaxableIncomeD27=', @income)         /* CALCULATE TAX ACCORDING TO SARS TAX SCALES */     if (@CalculationType % 2 = 1)     begin        select @payeMinValue = cast([TaxThresholdsAmount] as decimal(18, 6)) from [Const_TaxThresholds] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and ([MaxAge] is null or [MaxAge] >= @Age) and [FinancialYear] = @TaxYear)        select @payeRebates = cast(sum(isnull([TaxRebatesAmount], 0)) as decimal(18, 6)) from [Const_TaxRebates] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and [FinancialYear] = @TaxYear)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       set @trialRunLogs = CONCAT(@trialRunLogs, '| @PayeMinValue=', @payeMinValue,'| @payeRebates=', @payeRebates)         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        if(@income > @payeMinValue)      begin        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */      if (@CalculationType % 2 = 1)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         --@PayeValue1       set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))        end        set @trialRunLogs = CONCAT(@trialRunLogs,'| @payeFixedValue=', @payeFixedValue,'| @payeStartValue=', @payeStartValue,'| @payePercentage=', @payePercentage, '| @PayeValue1D28=', @payeValue)          /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 0 and @income > @payeMinValue)      begin         set @payeStartValue = cast(0 as decimal(18, 6))         set @payeFixedValue = cast(0 as decimal(18, 6))         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVE */       if (@CalculationType = 2)       begin          select @payePercentage = coalesce((select sum((case             when [DirectiveTypeId] = 1 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @payeValue = coalesce((select sum((case             when [DirectiveTypeId] = 1 then (@income * (@payePercentage / cast(100 as decimal(18, 6))))             when [DirectiveTypeId] = 2 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @TaxDirectiveType = [DirectiveTypeId] from [Payroll_EmployeeTaxDirectives] with(nolock) where ([Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)         end         /* CALCULATE TAX ACCORDING TO EMPLOYEE PART TIME COUNCILLORS DIRECTIVE */       if (@CalculationType = 4)       begin          set @payePercentage = @payePercentageCouncillors          set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         end        end        set @payeValueBonus = 0           /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */      if (@BonusCalculationType = 2)      begin         set @incomeAnnual = @incomeAnnual + @incomeBonus         set @incomeAnnualYearToDate = @incomeAnnualYearToDate + @incomeBonusYearToDate         set @trialRunLogs = CONCAT(@trialRunLogs, ' new @incomeAnnual=', @incomeAnnual, ' new @incomeAnnualYearToDate=', @incomeAnnualYearToDate)        end        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; INCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 1 and (@incomeAnnual + @incomeAnnualYearToDate) > 0 and (@income + (@incomeAnnual + @incomeAnnualYearToDate)) > @payeMinValue)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= (@income + (@incomeAnnual + @incomeAnnualYearToDate)) and ([MaxSlotAmount] is null or [MaxSlotAmount] >= (@income + (@incomeAnnual + @incomeAnnualYearToDate))) and

GO

-- ============================================
-- SP: Payroll_EmployeeTaxCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employee PAYE (Simulation)   Update Date : 11/04/2019 => Added Employee PAYE (Simulation) @ Terminations  */  CREATE procedure [Payroll_EmployeeTaxCalculation_TrialSimulation_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      declare @CycleID int = (select isnull([CycleID], 0) from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)),      @CycleModeID int = 1,      @TaxYear varchar(9) = (select [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'TaxYear'))      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID))      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 0,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6),      @incomeBonusYearToDate decimal(18, 6),      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,        /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @XOR int = (1 ^ 8)      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [TransactionTypeID] int null,     [SalaryHeadID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [Age], [Amount], [PayrollDefinationID], [TransactionTypeID], [SalaryHeadID], [SalaryHeadTitle])       select @Periods, 1, 0, [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), (floor(datediff(day, [DateOfBirth], getdate()) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [TransactionTypeID], [SalaryHead_ID], [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and [SalaryHead_ID] = 3)      select @c = count([ID]) from @paye      while (@i <= @c)    begin       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @Age = [Age] from @paye where ([ID] = @i)       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] @IRP5Income, '01 + 02 + 03', @EmployeeID, @StartDate, @UntilDate, @CycleID, @CycleModeID, @XOR, @SimulationType, @ParentID, 1, @income out       /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = 0       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [ETP].[SimulationType] = @SimulationType and [IRP5].[TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = 0       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [ETP].[SimulationType] = @SimulationType and [IRP5].[TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = 0       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = 0       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = 0       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = 0       select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue]       /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)       select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusY