lationType] = @SimulationType and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)       select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS'       /* CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pensionYearToDate = 0       select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS'       /* ANNUALIZE PENSION: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @pension = (((@pension + @pensionYearToDate) / cast(@PeriodsWorked as decimal(18, 6))) * cast(@Periods as decimal(18, 6)))       select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'ANNUALIZE PENSION'       /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */     if (@pension > 0)     begin        /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN PENSION IS CAPPED TO 27.5% */      if (@pension > (@income * 