ension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 1 and @income > @payeMinValue)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES'' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]'        end        /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 0 and @income > @payeMinValue)      begin         set @payeStartValue = cast(0 as decimal(18, 6))         set @payeFixedValue = cast(0 as decimal(18, 6))         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVE */       if (@CalculationType = 2)       begin          select @payePercentage = coalesce((select sum((case             when [DirectiveTypeId] = 1 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @payeValue = coalesce((select sum((case             when [DirectiveTypeId] = 1 then (@income * (@payePercentage / cast(100 as decimal(18, 6))))             when [DirectiveTypeId] = 2 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @TaxDirectiveType = [DirectiveTypeId] from [Payroll_EmployeeTaxDirectives] with(nolock) where ([Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)         end         /* CALCULATE TAX ACCORDING TO EMPLOYEE PART TIME COUNCILLORS DIRECTIVE */       if (@CalculationType = 4)       begin          set @payePercentage = @payePercentageCouncillors          set @payeValue = (@payeFixedValue + ((@income - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         end        end        set @payeValueBonus = 0        /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */      if (@BonusCalculationType = 2)      begin         set @incomeAnnual = @incomeAnnual + @incomeBonus         set @incomeAnnualYearToDate = @incomeAnnualYearToDate + @incomeBonusYearToDate        end        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; INCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 1 and (@incomeAnnual + @incomeAnnualYearToDate) > 0 and (@income + (@incomeAnnual + @incomeAnnualYearToDate)) > @payeMinValue)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= (@income + (@incomeAnnual + @incomeAnnualYearToDate)) and ([MaxSlotAmount] is null or [MaxSlotAmount] >= (@income + (@incomeAnnual + @incomeAnnualYearToDate))) and [FinancialYear] = @TaxYear)         set @payeValueBonus = (@payeFixedValue + (((@income + (@incomeAnnual + @incomeAnnualYearToDate)) - @payeStartValue) * (@payePercentage / cast(100 as decimal(18, 6)))))         set @payeValueBonus = (@payeValueBonus - @payeValue)        end        /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; INCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */      if (@CalculationType % 2 = 0 and (@incomeAnnual + @incomeAnnualYearToDate) > 0 and (@income + (@incomeAnnual + @incomeAnnualYearToDate)) > @payeMinValue)      begin         set @payeStartValue = cast(0 as decimal(18, 6))         set @payeFixedValue = cast(0 as decimal(18, 6))         /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVE */       if (@CalculationType = 2)       begin          select @payePercentage = coalesce((select sum((case             when [DirectiveTypeId] = 1 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @payeValueBonus = coalesce((select sum((case             when [DirectiveTypeId] = 1 then ((@income + (@incomeAnnual + @incomeAnnualYearToDate)) * (@payePercentage / cast(100 as decimal(18, 6))))             when [DirectiveTypeId] = 2 then cast([TaxDirectiveValue] as decimal(18, 6))             else 0            end))            from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)             join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1           where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)), 0)          select @TaxDirectiveType = [DirectiveTypeId] from [Payroll_EmployeeTaxDirectives] with(nolock) where ([Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)         end         /* CALCULATE TAX ACCORDING TO EMPLOYEE PART TIME COUNCILLORS DIRECTIVE */       if (@CalculationType = 4)       begin          set @payePercentage = @payePercentageCouncillors          set @payeValueBonus = ((@income + (@incomeAnnual + @incomeAnnualYearToDate)) * (@payePercentage / cast(100 as decimal(18, 6))))         end         set @payeValueBonus = (@payeValueBonus - @payeValue)        end        /* CALCULATE PAYE TAX REBATES; EXCEPT FOR TAX DIRECTIVE (FIXED OR PERCENTAGE) AND PART TIME COUNCILLORS */      if (not @TaxDirectiveType in(1, 2) and @CalculationType <> 4)         set @payeValue = @payeValue - @payeRebates        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE PAYE TAX REBATES'        /* DEANNUALIZE INCOME; EXCEPT FOR TAX DIRECTIVE (FIXED AMOUNT) */      if (not @TaxDirectiveType = 2)         set @payeValue = (((@payeValue / @Periods) * @PeriodsWorked) - @payeValueYearToDate)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'DEANNUALIZE INCOME'        /* DEDUCT CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS; EXCEPT FOR PART TIME COUNCILLORS */      if (@payeCreditsYearToDate > 0 and @CalculationType <> 4)         set @payeValue = @payeValue - @payeCreditsYearToDate        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'DEDUCT CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS'        if (@payeValueBonus > 0)         set @payeValue = @payeValue + @payeValueBonus        /* CALCULATE MEDICAL AID TAX CREDITS (NORMAL RUN); EXCEPT FOR TAX DIRECTIVE (FIXED OR PERCENTAGE) AND PART TIME COUNCILLORS */      if (not @TaxDirectiveType in(1, 2) and @CycleModeID = 1 and @CalculationType <> 4)      begin         /* CALCULATE MEDICAL AID TAX CREDITS */       set @medical_count = coalesce((select count([EmployeeMedicalAID_ID])          from [Payroll_EmployeeMedicalAIDDetail] as [EM] with(nolock)          where ([EmployeeID] = @EmployeeID and [EM].[Enable] = 1 and [JoinDate] <= @UntilDate and isnull([TerminationDate], @StartDate) >= @StartDate)), 0)         set @medical_dependants = coalesce((select count([EmployeeDependant_ID])          from [Payroll_EmployeeMedicalAIDDetail] as [EM] with(nolock)           join [Payroll_EmployeeMedicalAIDDetailDependants] as [EMD] with(nolock) on [EmployeeMedicalAIDID] = [EmployeeMedicalAID_ID] and [EMD].[Enable] = 1 and [EMD].[StartDate] <= @UntilDate and isnull([EMD].[EndDate], @StartDate) >= @StartDate          where ([EmployeeID] = @EmployeeID and [EM].[Enable] = 1 and [JoinDate] <= @UntilDate and isnull([TerminationDate], @StartDate) >= @StartDate)), 0)         set @payeCredits = 0         if (@medical_count > 0 and exists(select cast([Value] as decimal(18, 6))            from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)             join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID]             join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]            where ([ETP].[EmployeeID] = @EmployeeID and [SimulationType] = @SimulationType and isnull([IRP5CertCode], [IRP5Code]) in(3810, 3813, 3860, 3863, 4

GO

-- ============================================
-- SP: Payroll_EmployeeTaxCalculationByDaysWorked_Trial_sp
-- Schema: dbo
-- ============================================
 /*    Author  : FERDI BOTHA   Create date : 08/03/2017   Description : Calculates Employee PAYE   Update Date : 10/05/2017 - Changed the mappings for Method of Calculation  */  create procedure [dbo].[Payroll_EmployeeTaxCalculationByDaysWorked_Trial_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @PeriodID int , @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try            -- 🔸 New: clear explanation rows for this period / tax year          delete from Payroll_PayeCalculationExplain          where PeriodID = @PeriodID            and TaxYear = @TaxYear            and IsTrialRun = 1            and (@EmployeeID = 0 OR EmployeeID = @EmployeeID);      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID)),      @AdhocTypeID int = (select isnull([AdhocTypeID], 0) from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)),      @TaxYearEndDate datetime = (select EndDate from Const_Payroll_TaxPeriods where TaxYear = right(@TaxYear,4) and cycleID = @CycleID)            ,@TaxYearStartDate date       ,@EmpStartDate     date       ,@EmpEndDate       date       ,@WorkStart        date       ,@WorkEnd          date       ,@DaysWorked       decimal(18,6)       ,@DaysInYear       decimal(18,6);               -- Get tax year start date     SELECT @TaxYearStartDate = CAST(StartDate AS date)     FROM Const_Payroll_TaxPeriods WITH (NOLOCK)     WHERE TaxYear = RIGHT(@TaxYear,4)       AND CycleID = @CycleID;       -- Get employee start/end dates     SELECT       @EmpStartDate = CAST(JoiningDate AS date),      @EmpEndDate   = CAST(EndDate    AS date)     FROM Payroll_Employee WITH (NOLOCK)     WHERE Employee_ID = @EmployeeID;       IF @EmpStartDate IS NULL      SET @EmpStartDate = @TaxYearStartDate;    -- Determine effective work window in this tax year  SET @WorkStart = CASE                       WHEN @EmpStartDate < @TaxYearStartDate THEN @TaxYearStartDate                      ELSE @EmpStartDate                   END;    SET @WorkEnd = CASE                       WHEN @EmpEndDate IS NULL OR @EmpEndDate > CAST(@EndDate AS date)                           THEN CAST(@EndDate AS date)                      ELSE @EmpEndDate                 END;    -- Calculate DaysWorked (inclusive)  SET @DaysWorked = CASE                       WHEN @WorkEnd < @WorkStart THEN 0                      ELSE DATEDIFF(DAY, @WorkStart, @WorkEnd) + 1                    END;    -- Calculate DaysInYear (inclusive)  SET @DaysInYear = DATEDIFF(DAY, @TaxYearStartDate, CAST(@TaxYearEndDate AS date)) + 1;    -- Safety: avoid division by zero  IF @DaysWorked <= 0 SET @DaysWorked = 1;  IF @DaysInYear <= 0 SET @DaysInYear = 365;         declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @PeriodNo int = 0,      @PeriodsWorked int = 0,      @PeriodsSkipped int = 0,      @CalculationType int,      @TaxDirectiveType int = 0,      @BonusCalculationType int,      @Age int,      @income decimal(18, 6),      @incomeYearToDate decimal(18, 6),      @incomeBonus decimal(18, 6),      @incomeBonusYearToDate decimal(18, 6),      @incomeAnnual decimal(18, 6),      @incomeAnnualYearToDate decimal(18, 6),      @pension decimal(18, 6),      @pensionYearToDate decimal(18, 6),      @pension_percentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @pension_value decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] in(4001, 4003, 4006) and ((@StartDate between [StartDate] and [UntilDate]) or (@EndDate between [StartDate] and [UntilDate])))),      @payeMinValue decimal(18, 6),      @payeRebates decimal(18, 6),      @payeValue decimal(18, 6),      @payeValueYearToDate decimal(18, 6),      @payeValueBonus decimal(18, 6),      @payeValueBonusYearToDate decimal(18, 6),      @payeCredits decimal(18, 6),      @payeCreditsYearToDate decimal(18, 6),      @payeStartValue decimal(18, 6),      @payeFixedValue decimal(18, 6),      @payePercentage decimal(18, 6),      @payePercentageCouncillors decimal(18, 6) = 25,      @BonusDateID int = 0,      @BonusMonth int = 0,      @medical_count int,      @medical_dependants int,      @payeHistoryType decimal(18, 6),      @payeHistoryPeriod int,      @payeHistoryValue decimal(18, 6),      @payeHistoryBonus decimal(18, 6),      @payeHistoryBalance decimal(18, 6),      /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @LastEmployeeId int = -1;      declare @paye table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [PeriodNo] [int] not null,     [PeriodsWorked] [int] not null,     [EmployeeID] int not null,     [CalculationType] int not null,     [BonusCalculationType] int not null,     [Age] int not null,     [Amount] decimal(18, 6) not null,     [PayrollDefinationID] int not null,     [VendorID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      select top 1 @BonusDateID = [BonusPaymentDateID], @BonusMonth = [BonusMonth] from [Payroll_Municipality] where ([Enabled] = 1)      insert into @paye([Periods], [PeriodNo], [PeriodsWorked], [EmployeeID], [CalculationType], [BonusCalculationType], [Age], [Amount], [PayrollDefinationID], [VendorID], [SalaryHeadTitle])       select (         select isnull(max([PeriodInTaxYear]), @Periods)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [TaxYear] = @TaxYear)        ), (         select isnull(max([PeriodInTaxYear]), @Month)          from [Payroll_CyclePeriodDetails] with(nolock)          where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Enabled] = 1 and [Processed] = 1 and [TaxYear] = @TaxYear)        ), (         CASE         WHEN @Periods <> 12 THEN         (          SELECT COUNT(DISTINCT [PeriodID])          FROM [Payroll_PayrollResults] AS [PR] WITH (NOLOCK)          JOIN [Payroll_CyclePeriodDetails] AS [CPR] WITH (NOLOCK)            ON [PR].[PeriodID] = [CPR].[Period_ID]             AND ([CPR].[CycleModeID] = 1             OR ([CPR].[CycleModeID] = 2              AND [CPR].[AdhocTypeID] = 1              AND [CPR].[AdhocTerminationTypeID] = 1))             AND [CPR].[Enabled] = 1          WHERE [EmployeeID] = [EPD].[EmployeeID]            AND [PR].[TaxYear] = CAST(RIGHT(@TaxYear, 4) AS INT)         )        ELSE         ISNULL(          (           SELECT SUM(MonthsWorked)           FROM payroll_employeeperiodsworked pew           WHERE pew.EmployeeID = [EPD].[EmployeeID]             AND pew.TaxYear  = @TaxYear          ),          0         )       END        ), [EPD].[EmployeeID], (case         when [TaxCalculationType] is null then 1         when [TaxCalculationType] > 4 then 1         else [TaxCalculationType]        end), isnull([BonusCalculation], 2), (floor(datediff(day, [DateOfBirth], @TaxYearEndDate) / (365.242199))), 0, [EmployeePayrollDefinition_ID], [VendorID], [SalaryHeadTitle]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and         [SalaryHead_ID] = 3               and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )      select @c = count([ID]) from @paye      while (@i <= @c)    begin        DECLARE @ExplainSeq INT;       SET @ExplainSeq = 10;       select @EmployeeID = [EmployeeID], @Periods = [Periods], @PeriodNo = [PeriodNo], @PeriodsWorked = [PeriodsWorked], @CalculationType = [CalculationType], @BonusCalculationType = [BonusCalculationType], @Age = [Age] from @paye where ([ID] = @i)          DECLARE @StartDateInTaxYear DATETIME = (select StartdateInTaxYear from payroll_ClassicPeriods where EmployeeID = @EmployeeID)          SELECT       @EmpStartDate = CAST(JoiningDate AS date),      @EmpEndDate   = CAST(EndDate    AS date)     FROM Payroll_Employee WITH (NOLOCK)     WHERE Employee_ID = @EmployeeID;    IF @StartDateInTaxYear IS NOT NULL      SET @EmpStartDate = @StartDateInTaxYear;     SET @WorkStart = CASE                       WHEN @EmpStartDate < @TaxYearStartDate THEN @TaxYearStartDate                      ELSE @EmpStartDate                   END;    SET @WorkEnd = CASE                       WHEN @EmpEndDate IS NULL OR @EmpEndDate > CAST(@EndDate AS date)                           THEN CAST(@EndDate AS date)                      ELSE @EmpEndDate                 END;    SET @DaysWorked = CASE                       WHEN @WorkEnd < @WorkStart THEN 0                      ELSE DATEDIFF(DAY, @WorkStart, @WorkEnd) + 1                    END;    IF @DaysWorked <= 0 SET @DaysWorked = 1;  -- @DaysInYear can stay global, no need to recompute per employee     select @TaxDirectiveType = 0       /* CHANGE CALCULATION TO SARS TABLES (IF NO TAX DIRECTIVE IS LINKED) */     if (@CalculationType = 2 and not exists(select [EmpID]         from [Payroll_EmployeeTaxDirectives] as [ETD] with(nolock)          join [Payroll_TaxDirectiveType] as [TD] with(nolock) on [DirectiveType_Id] = [DirectiveTypeId] and [TD].[Enabled] = 1        where ([ETD].[Enabled] = 1 and [EmpID] = @EmployeeID and [TaxYear] = @TaxYear and [ExpiryDate] >= @StartDate)))        set @CalculationType = 1       set @PeriodsSkipped = @PeriodNo - @PeriodsWorked       /* ONLY ADD 1 TO THE CURRENT PERIODS WORKED IF THIS IS A NORMAL RUN (AND/OR) THE PERIODS WORKED IS NONE (IN ORDER TO AVOID DIVISION BY ZERO) */     if (@CycleModeID = 1 or @PeriodsWorked = 0)        set @PeriodsWorked = @PeriodsWorked + 1       --select @PeriodID as [PeriodID], @PeriodNo as [PeriodNo], @Periods as [Periods], @PeriodsWorked as [PeriodsWorked], @PeriodsSkipped as [PeriodsSkipped]       /* CALCULATE TAXABLE INCOME FOR THE CURRENT PROCESSING PERIOD */     IF (@EmployeeID <> @LastEmployeeID)  BEGIN      SELECT @income =          COALESCE(SUM(              CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *              (CAST(ETR.Taxable AS DECIMAL(18, 6)) / 100.0)          ), 0.0)      FROM Payroll_EmployeeTrialPayslip AS ETP       WITH (NOLOCK)      JOIN Payroll_EmployeePayrollDefinition AS EPD  WITH (NOLOCK)           ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID          AND EPD.Enabled = 1      JOIN Payroll_SalaryHead AS SH                  WITH (NOLOCK)           ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID          AND SH.Enabled = 1      JOIN Payroll_IRP5Code AS IRP5                  WITH (NOLOCK)           ON IRP5.IRP5Code_ID = SH.IRP5CodeId          AND IRP5.Enabled = 1      JOIN @IRP5Income AS ETR           ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)          AND ETR.[Type]    IN (1, 2, 3)            -- 01 + 02 + 03          AND ETR.Taxable   > 0                    -- taxable only (same as @taxable = 1)          AND ETR.StartDate <= @EndDate          AND ETR.UntilDate >= @StartDate      JOIN Payroll_Employee AS PE                   WITH (NOLOCK)           ON PE.Employee_ID = ETP.EmployeeID          AND PE.CycleID = @CycleID      JOIN Payroll_CyclePeriodDetails AS CPD        WITH (NOLOCK)           ON CPD.CycleID   = PE.CycleID          AND CPD.Period_ID = ETP.PeriodID          AND CPD.Enabled   = 1      JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)           ON EP.Period_ID   = ETP.PeriodID          AND EP.Employee_ID = ETP.EmployeeID          AND EP.Cycle_ID    = PE.CycleID      LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)           ON ACPD.PeriodID    = CPD.Period_ID          AND ACPD.SalaryHeadID = SH.SalaryHead_ID      WHERE          ETP.EmployeeID = @EmployeeID          AND ETP.PeriodID = @PeriodID          AND ETP.TaxSavePurpose = 0          AND (                CASE                   WHEN @CycleModeID = 1 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END                   WHEN @CycleModeID = 2 THEN                       CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END                   ELSE 0                END              ) = 1          AND IRP5.TransactionTypeID IN (1, 4);      -- same Tx types as UIF        SET @LastEmployeeID = @EmployeeID;  END          /* CALCULATE TAXABLE INCOME: YEAR TO DATE; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @incomeYearToDate = coalesce((select sum([Amount] * ([TatxablePercentage] / 100))               from [Payroll_PayrollResults] as [PR] with(nolock)                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1               where ([EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                [PR].[TransactionTypeID] in(1, 4) and not [PR].[SalaryHeadID] in(2) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(                 /* 01 - INCOME RECORD(S) */               3601, 3651, 3602, 3652, 3603, 3653, 3604, 3654, 3606, 3656, 3607, 3657, 3608, 3658, 3609, 3659, 3610, 3660, 3611, 3661, 3612, 3662, 3613, 3663, 3614, 3664, 3615, 3665, 3616, 3666, 3617, 3667, 3619, 3669, 3620, 3670, 3621,                 /* 02 - ALLOWANCE RECORD(S) */               3701, 3722, 3751, 3701, 3751, 3702, 3752, 3703, 3753, 3704, 3754, 3705, 3755, 3706, 3756, 3707, 3757, 3708, 3758, 3709, 3759, 3710, 3760, 3711, 3761, 3712, 3762, 3713, 3763, 3714, 3764, 3715, 3765, 3716, 3766, 3717, 3767, 3718, 3768, 3719, 3769, 3720, 3770, 3721, 3771,                 /* 03 - FRINGE BENEFIT RECORD(S) */               3801, 3851, 3802, 3852, 3803, 3853, 3804, 3854, 3805, 3855, 3806, 3856, 3807, 3857, 3808, 3858, 3809, 3859, 3810, 3860, 3813, 3863, 3815, 3865, 3816, 3866, 3817, 3867, 3820, 3870, 3821, 3871, 3822, 3872, 3825, 3875, 3828, 3878, 3833                )               )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnual = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and not [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */     set @incomeAnnualYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and not [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonus = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))                from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                 join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                 join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]                where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and [TransactionTypeID] = 1 and [SalaryHead_ID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655))), 0)       /* CALCULATE YEAR-TO-DATE ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; BONUS [2] */     set @incomeBonusYearToDate = coalesce((select sum([Amount])                from [Payroll_PayrollResults] as [PR] with(nolock)                 join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                 join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                 [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = 2 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(3605, 3655)                )), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING (PAY-AS-YOU-EARN (PAYE: BONUS) [4] + PAY-AS-YOU-EARN (PAYE: TAX OVER DEDUCTION) [5]) */     set @payeValueYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and not [PR].[SalaryHeadID] in(4, 5) and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102 and not [PR].[PeriodID] in(                   select [Period_ID] from [Payroll_PayrollRun_History_Employees] with(nolock) where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)                  ))), 0)          /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; RECOVERY OF TAX SPREAD => MONTH OF BONUS */     set @payeValueYearToDate = @payeValueYearToDate + coalesce((select sum([PAYEBalance] + [PAYEValue])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [CycleModeID] = @CycleModeID and [TaxYear] = @TaxYear and [PAYEBalance] > 0)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; PAY-AS-YOU-EARN (PAYE: BONUS) [4] */     set @payeValueBonusYearToDate = coalesce((select sum([Amount])                 from [Payroll_PayrollResults] as [PR] with(nolock)                  join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]                  join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1                 where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and                  [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = 4 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 4102)), 0)       /* CALCULATE YEAR-TO-DATE PAY-AS-YOU-EARN CREDITS */     set @payeCreditsYearToDate = coalesce((select sum([TaxCredits])                 from [Payroll_PayrollRun_History_Employees] with(nolock)                 where ([Employee_ID] = @EmployeeID and [TaxYear] = @TaxYear)), 0)    -- build ExtraInfo for the explanation row  DECLARE @ExtraInfo_Income VARCHAR(MAX);  DECLARE @CombinedIncome   DECIMAL(18,6);    SET @ExtraInfo_Income =    'IncomeCurrent' + CAST(@income AS VARCHAR(50))   + '; YTDIncome'  + CAST(@incomeYearToDate AS VARCHAR(50))      + '; AnnualCurrent='         + CAST(@incomeAnnual AS VARCHAR(50))      + '; AnnualYTD='      + CAST(@incomeAnnualYearToDate AS VARCHAR(50))      + '; BonusCurrent='          + CAST(@incomeBonus AS VARCHAR(50))      + '; BonusYTD='       + CAST(@incomeBonusYearToDate AS VARCHAR(50))      + '; PAYE_YTD='       + CAST(@payeValueYearToDate AS VARCHAR(50))      + '; PAYE_BonusYTD='  + CAST(@payeValueBonusYearToDate AS VARCHAR(50))      + '; CreditsYTD='     + CAST(@payeCreditsYearToDate AS VARCHAR(50));    SET @CombinedIncome = @income + @incomeYearToDate;    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'INCOME',      @LineCode         = 'RAW_INCOME_YTD',      @LineDescription  = 'Taxable income for PAYE (current + year-to-date, incl. annual/bonus where applicable)',      @SourceAmount     = @income,      @YTDAmount        = @incomeYearToDate,      @CalculatedAmount = @CombinedIncome,      @ExtraInfo        = @ExtraInfo_Income,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;  /* DEDUCT ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655] */     set @income = @income - (@incomeAnnual + @incomeBonus)          /* ANNUALIZE INCOME: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @income = (((@income + @incomeYearToDate) / @DaysWorked) * @DaysInYear)        DECLARE @ExtraInfo_Annualised VARCHAR(MAX);    SET @ExtraInfo_Annualised =    CAST(@DaysWorked AS VARCHAR(10))         EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'INCOME',      @LineCode         = 'ANNUALISED_INCOME',      @LineDescription  = 'Annualised taxable income after removing annual/bonus amounts - CombinedIco/DaysWorked * DaysInYear',      @SourceAmount     = @income,      @YTDAmount        = NULL,      @CalculatedAmount = @income,      @ExtraInfo        = @ExtraInfo_Annualised,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;           /* CALCULATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pension = coalesce((select sum(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))))               from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)                join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]               where ([ETP].[EmployeeID] = @EmployeeID and [PeriodID] = @PeriodID and isnull([IRP5CertCode], [IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878))), 0)         /* CALCULATE YEAR-TO-DATE PENSION, PROVIDENT AND RETIREMENT FUND CONTRIBUTIONS:        CURRENT PENSION FUND CONTRIBUTIONS                 [4001] +      ARREAR PENSION FUND CONTRIBUTIONS                 [4002] +      CURRENT PROVIDENT FUND CONTRIBUTIONS                [4003] +      ARREAR PROVIDENT FUND CONTRIBUTIONS (MUST BE INCLUDED IN CODE 4003 FROM 2010 YEAR OF ASSESSMENT) [4004] +      CURRENT RETIREMENT ANNUITY FUND CONTRIBUTIONS              [4006] +      ARREAR (RE-INSTATED) RETIREMENT ANNUITY FUND CONTRIBUTIONS           [4007] +      ARREAR PENSION FUND CONTRIBUTIONS - NON-STATUTORY FORCES (NSF)          [4026] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE)             [3817] +      BENEFIT-EMPLOYER PENSION FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3867] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE)            [3825] +      BENEFIT-EMPLOYER PROVIDENT FUND CONTRIBUTIONS (PAYE) FOR FOREIGN SERVICE INCOME      [3875] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS              [3828] +      EMPLOYER RETIREMENT ANNUITY FUND CONTRIBUTIONS FOR FOREIGN SERVICE INCOME       [3878]       */     set @pensionYearToDate = coalesce((select sum([Amount])        from [Payroll_PayrollResults] as [PR] with(nolock)         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = [PR].[TransactionTypeID]         join [Payroll_CyclePeriodDetails] as [CPR] with(nolock) on [CPR].[Period_ID] = [PR].[PeriodID]/* and [CPR].[CycleModeID] = 1*/ and [CPR].[Enabled] = 1        where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = cast(right(@TaxYear, 4) as int) and         isnull([IRP5CertCode], [IRP5].[IRP5Code]) in(4001, 4002, 4003, 4004, 4006, 4007, 4026, 3817, 3867, 3825, 3875, 3828, 3878)        )), 0)       /* ANNUALIZE PENSION: ADHOC INCOME IS PROCESSED AS PART OF THE PREVIOUS PERIOD */     set @pension = (((@pension + @pensionYearToDate) / @DaysWorked) * @DaysInYear)       /* TAXABLE DEDUCTION FOR THOSE WHO HAVE PENSION, PROVIDENT OR RETIREMENT FUND CONTRIBUTIONS */     if (@pension > 0)     begin        /* IF THE ANNUAL PENSION EXCEEDS 27.5% (OF THE TAXABLE INCOME) - THEN PENSION IS CAPPED TO 27.5% */      if (@pension > (@income * @pension_percentage))         set @pension = (@income * @pension_percentage)        /* IF THE ANNUAL PENSION STILL EXCEEDS THE MAXIMUM OF 350, 000 - THEN PENSION IS CAPPED TO 350, 000 */      if (@pension > @pension_value)         set @pension = @pension_value        set @income = @income - @pension         end       DECLARE @ExtraInfo_Pension VARCHAR(MAX);    SET @ExtraInfo_Pension =        'Pension%Cap=' + CAST(@pension_percentage AS VARCHAR(50))      + '; PensionMax=' + CAST(@pension_value AS VARCHAR(50));    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'DEDUCTIONS',      @LineCode         = 'PENSION_RA',      @LineDescription  = 'Pension / Provident / RA contributions deducted (capped per SARS rules)',      @SourceAmount     = @pension,      @YTDAmount        = @pensionYearToDate,      @CalculatedAmount = @income,      @ExtraInfo        = @ExtraInfo_Pension,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;       /* CALCULATE TAX ACCORDING TO SARS TAX SCALES */     if (@CalculationType % 2 = 1)     begin        select @payeMinValue = cast([TaxThresholdsAmount] as decimal(18, 6)) from [Const_TaxThresholds] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and ([MaxAge] is null or [MaxAge] >= @Age) and [FinancialYear] = @TaxYear)        select @payeRebates = cast(sum(isnull([TaxRebatesAmount], 0)) as decimal(18, 6)) from [Const_TaxRebates] with(nolock) where ([Enabled] = 1 and [MinAge] <= @Age and [FinancialYear] = @TaxYear)        --select @income as [income], @incomeYearToDate as [incomeYearToDate], @incomeAnnual as [incomeAnnual], @incomeAnnualYearToDate as [incomeAnnualYearToDate], @incomeBonus as [incomeBonus], @incomeBonusYearToDate as [incomeBonusYearToDate], @payeValueYearToDate as [payeValueYearToDate], @payeValueBonusYearToDate as [payeValueBonusYearToDate], @payeCreditsYearToDate as [payeCreditsYearToDate], @pension as [pension], @pensionYearToDate as [pensionYearToDate], @payeMinValue as [payeMinValue], @payeRebates as [payeRebates], @payeStartValue as [payeStartValue], @payeFixedValue as [payeFixedValue], @payePercentage as [payePercentage], @payeValue as [payeValue], 'CALCULATE TAX ACCORDING TO SARS TAX SCALES'       end       DECLARE @ExtraInfo_Threshold VARCHAR(MAX);    SET @ExtraInfo_Threshold = 'Age=' + CAST(@Age AS VARCHAR(10));    EXEC Payroll_AddPayeExplainLine      @EmployeeID       = @EmployeeID,      @PeriodID         = @PeriodID,      @TaxYear          = @TaxYear,      @IsTrialRun       = 1,      @SequenceNo       = @ExplainSeq,      @Section          = 'TAX',      @LineCode         = 'THRESHOLD_REBATES',      @LineDescription  = 'Tax thresholds and annual rebates based on age',      @SourceAmount     = @payeMinValue,      @YTDAmount        = NULL,      @CalculatedAmount = @payeRebates,      @ExtraInfo        = @ExtraInfo_Threshold,      @CreatedBy        = NULL;    SET @ExplainSeq = @ExplainSeq + 10;       /* CALCULATE TAX ACCORDING TO EMPLOYEE TAX DIRECTIVES */     if (@CalculationType % 2 = 0)     begin        set @payeMinValue = 0        set @payeRebates = 0       end       begin        set @payeValue = 0        if(@income > @payeMinValue)      begin        /* CALCULATE TAX ACCORDING TO SARS TAX SCALES: CALCULATE PAY-AS-YOU-EARN [PAYE - (EMPLOYEES' TAX)] [4102]; EXCLUDING ANNUAL PAYMENT - TAXABLE [3605] + FOREIGN ANNUAL PAYMENT - TAXABLE [3655]; EXCLUDING BONUS [2] */      if (@CalculationType % 2 = 1)      begin         select @payeStartValue = cast([RatesOfTaxAboveAmount] as decimal(18, 6)), @payeFixedValue = cast([RatesOfTaxFixedAmount] as decimal(18, 6)), @payePercentage = cast([RatesOfTaxPercentage] as decimal(18, 6)) from [Const_StatutoryRates] with(nolock) where ([Enabled] = 1 and [MinSlotAmount] <= @income and ([MaxSlotAmount] is null or [MaxSlotAmount] >= @income) and [FinancialYear] = @TaxYear)         --@PayeValue1       set @payeValue = (@pa

GO

-- ============================================
-- SP: Payroll_EmployeeTaxDirectiveNotify_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  FERDI BOTHA  -- Create date: 05/02/2018  -- =============================================    CREATE procedure [Payroll_EmployeeTaxDirectiveNotify_sp]    as      begin        set nocount on;     select [Employee_ID], [EmpCode], [FirstName] as [Name], [Surname], [TaxDirectives_ID], [DirectiveDesc], min([TD].[ExpiryDate]) as [EndDate]      from [Payroll_Employee] as [PE] with(nolock)       join [Payroll_EmployeeTaxDirectives] as [TD] with(nolock) on [EmpID] = [Employee_ID] and [TD].[Enabled] = 1 and [TD].[ExpiryDate] > getdate()       join [Payroll_TaxDirectiveType] as [TDT] with(nolock) on [TDT].[DirectiveType_Id] = [TD].[DirectiveTypeId]         where ([PE].[Enabled] = 1) AND [TDT].DirectiveType_Id != 4 --IRP3 (a) Gratuities      group by [PE].[Employee_ID], [EmpCode], [FirstName], [Surname], [TaxDirectives_ID], [DirectiveDesc]       having (min([TD].[ExpiryDate]) < dateadd(day, 60, getdate()))     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeTaxOverDeduction_Trial_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 05/07/2017   Description : Calculates Employee PAYE (Tax Over Deduction)   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  create procedure [Payroll_EmployeeTaxOverDeduction_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [SalaryHeadTitleAddendum], [PeriodID], [VendorID], [TaxYear], [Simulation])       select distinct [TOD].[EmployeeID], [EmployeePayrollDefinition_ID], cast([Amount] as decimal(18, 6)), @Month, @SCOAYear, [SalaryHeadTitle], @PeriodID, [VendorID], @TaxYear, @Simulation        from [Payroll_EmployeeTaxOverDeduction] as [TOD] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [TOD].[EmployeeID] and [EPD].[PayrollSalaryHeadID] = [TOD].[SalaryHeadID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [TOD].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([TOD].[EmployeeID] = (case @EmployeeID when 0 then [TOD].[EmployeeID] else @EmployeeID end) and [TOD].[Enabled] = 1 and [TOD].[StartDate] <= @EndDate and [TOD].[EndDate] >= @StartDate and [TransactionTypeID] = 2 and         [SalaryHead_ID] = 5 and [Amount] > 0 and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeTaxOverDeduction_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 05/07/2017   Description : Calculates Employee PAYE (Tax Over Deduction) (Simulation)   Update Date : 11/04/2019 => Added Employee PAYE (Tax Over Deduction) (Simulation) @ Terminations  */  create procedure [Payroll_EmployeeTaxOverDeduction_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select distinct @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [PE].[Employee_ID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SH].[SalaryHeadTitle], cast([Amount] as decimal(18, 6))        from [Payroll_EmployeeTaxOverDeduction] as [TOD] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [TOD].[EmployeeID] and [EPD].[PayrollSalaryHeadID] = [TOD].[SalaryHeadID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [TOD].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where ([TOD].[EmployeeID] = (case @EmployeeID when 0 then [TOD].[EmployeeID] else @EmployeeID end) and [TOD].[Enabled] = 1 and [TOD].[StartDate] <= @UntilDate and [TOD].[EndDate] >= @StartDate and [TransactionTypeID] = 2 and [SalaryHead_ID] = 5 and [Amount] > 0)     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeTaxOverDeductionNotify_sp
-- Schema: dbo
-- ============================================
      -- =============================================    -- Author:  FERDI BOTHA  -- Create date: 05/02/2018  -- =============================================    create procedure [Payroll_EmployeeTaxOverDeductionNotify_sp]    as      begin        set nocount on;       select [Employee_ID], [EmpCode], [FirstName] as [Name], [Surname], [SalaryHead_ID], [SalaryHeadName], min([TOD].[EndDate]) as [EndDate]      from [Payroll_Employee] as [PE] with(nolock)       join [Payroll_EmployeeTaxOverDeduction] as [TOD] with(nolock) on [EmployeeID] = [Employee_ID] and [TOD].[Enabled] = 1 and [TOD].[EndDate] > getdate()       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [SalaryHeadID]      where ([PE].[Enabled] = 1)      group by [PE].[Employee_ID], [EmpCode], [FirstName], [Surname], [SalaryHead_ID], [SalaryHeadName]       having (min([TOD].[EndDate]) < dateadd(day, 60, getdate()))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeTaxPerCodeSummary_Deductions_sp
-- Schema: dbo
-- ============================================
    /*-- =============================================      Author: Richa Mills  Create date:  2022/09/19  Description: Generate IRP5 Recon Report  Payroll_EmployeeTaxPerCodeSummary_Deductions_sp  'August','2022/2023','Any',false  ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxPerCodeSummary_Deductions_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN            DECLARE @ToDate DATETIME     DECLARE @taxYearfrom varchar(4) = left(@TaxYear,4)    DECLARE @taxYearTo varchar(4) = right(@TaxYear,4)            IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearTo, '03', '01'), 120)      SET @ToDate = DATEADD(d,-1,@ToDate)              END;          ELSE              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearfrom, '08', '31'), 120)              END;                    SELECT          irp.[TransactionTypeID], irp.[IRP5Code], irp.[IRP5CodeDesc], SUM(ISNULL(tr.[Amount], 0)) AS 'Amount'          FROM           (select Irp5Code, SUM(Amount)Amount from Payroll_PayrollResults      where TransactionTypeId in (2) and irp5Code not in(4102,4141,4142,4116,4120) and PeriodID in (select Period_Id from Payroll_CyclePeriodDetails where PeriodEndDate <= @ToDate and TaxYear = @TaxYear) group by IRP5Code) tr           LEFT JOIN           Payroll_IRP5Code irp ON tr.[IRP5Code] = irp.[IRP5Code]          WHERE            ISNULL(tr.[Amount], 0) <> 0    AND tr.[IRP5Code] <> 0          GROUP BY           irp.[IRP5Code], irp.[IRP5CodeDesc],irp.[TransactionTypeID]          ORDER BY           irp.[IRP5Code], irp.[IRP5CodeDesc];  END;

GO

-- ============================================
-- SP: Payroll_EmployeeTaxPerCodeSummary_Earnings_sp
-- Schema: dbo
-- ============================================
/*-- =============================================      Author: Richa Mills  Create date:  2022/09/19  Description: Generate IRP5 Recon Report  [Payroll_EmployeeTaxPerCodeSummary_Earnings_sp]  'August','2022/2023','Any',false  ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxPerCodeSummary_Earnings_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN            DECLARE @ToDate DATETIME     DECLARE @taxYearfrom varchar(4) = left(@TaxYear,4)    DECLARE @taxYearTo varchar(4) = right(@TaxYear,4)            IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearTo, '03', '01'), 120)      SET @ToDate = DATEADD(d,-1,@ToDate)              END;          ELSE              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearfrom, '08', '31'), 120)              END;                    SELECT          irp.[TransactionTypeID], irp.[IRP5Code], irp.[IRP5CodeDesc], SUM(ISNULL(tr.[Amount], 0)) AS 'Amount'          FROM           (select Irp5Code, SUM(Amount)Amount from Payroll_PayrollResults      where TransactionTypeId in (1,4) and PeriodID in (select Period_Id from Payroll_CyclePeriodDetails where PeriodEndDate <= @ToDate and TaxYear = @TaxYear) group by IRP5Code) tr           LEFT JOIN           Payroll_IRP5Code irp ON tr.[IRP5Code] = irp.[IRP5Code]          WHERE            ISNULL(tr.[Amount], 0) <> 0    AND tr.[IRP5Code] <> 0          GROUP BY           irp.[IRP5Code], irp.[IRP5CodeDesc],irp.[TransactionTypeID]          ORDER BY           irp.[IRP5Code], irp.[IRP5CodeDesc];    END;

GO

-- ============================================
-- SP: Payroll_EmployeeTaxPerCodeSummary_MTC_sp
-- Schema: dbo
-- ============================================
/*-- =============================================      Author: Richa Mills  Create date:  2022/09/19  Description: Generate IRP5 Recon Report  Payroll_EmployeeTaxPerCodeSummary_Tax_sp  'August','2022/2023','Any',false  ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxPerCodeSummary_MTC_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN     DECLARE @ToDate DATETIME        DECLARE @taxYearfrom varchar(4) = left(@TaxYear,4)    DECLARE @taxYearTo varchar(4) = right(@TaxYear,4)             IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearTo, '03', '01'), 120)      SET @ToDate = DATEADD(d,-1,@ToDate)              END;          ELSE              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearfrom, '08', '31'), 120)              END         SELECT 0 TransactionTypeID,4116 IRP5Code,SUM(TaxCredits)Amount,'MEDICAL SCHEME FEES TAX CREDIT'IRP5Desc FROM Payroll_PayrollRun_History_Employees WHERE Period_ID IN (      SELECT Period_id from Payroll_CyclePeriodDetails where TaxYear = @TaxYear and EndDate <= @ToDate)     UNION     SELECT 0,4120,SUM(SecondaryMTC)Amount,'ADDITIONAL MEDICAL EXPENSES TAX CREDIT EMPLOYEE >= 65' FROM Payroll_PayrollRun_History_Employees WHERE Period_ID IN (      SELECT Period_id from Payroll_CyclePeriodDetails where TaxYear = @TaxYear and EndDate <= @ToDate)  END

GO

-- ============================================
-- SP: Payroll_EmployeeTaxPerCodeSummary_sp
-- Schema: dbo
-- ============================================
/*-- =============================================      Author: Richa Mills  Create date:  2018/06/25  Description: Generate IRP5 Recon Report  [Payroll_EmployeeTaxPerCodeSummary_sp]  17,'August','2017/2018','Any',false  =============================================  Modified By: Ruan Strydom  Modified Date: 19/01/2021  Description: Bring in line with central data  ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxPerCodeSummary_sp]      @CycleId INT ,      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN            DECLARE @Period TABLE ( PeriodID INT );          DECLARE @PayeCode VARCHAR(50);            DECLARE @FromDate DATETIME , @ToDate DATETIME , @TYear NVARCHAR(50) , @Month NVARCHAR(2) , @SumOfCode BIGINT = 0;        SELECT TOP 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE   ( CycleID = @CycleId OR @CycleId = 0 )                  AND FinancialYear = @TaxYear ORDER BY Period_ID;              SELECT TOP 1 @PayeCode = PayeRegistrationNo FROM  dbo.Payroll_Municipality;               IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));                  SET @Month = '02';              END;          ELSE              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));                  SET @Month = '08';              END;                    SELECT           irp.[IRP5Code], irp.[IRP5CodeDesc], SUM(ISNULL(tr.[Amount], 0)) AS 'Amount'          FROM           Payroll_CyclePeriodDetails cyc          LEFT JOIN           Payroll_PayrollResults tr ON cyc.[Period_ID] = tr.[PeriodID]          LEFT JOIN           Payroll_IRP5Code irp ON tr.[IRP5Code] = irp.[IRP5Code]          LEFT JOIN           Const_Cycle c ON cyc.[CycleID] = c.[Cycle_ID]          LEFT JOIN           Payroll_Employee emp ON tr.[EmployeeID] = emp.[Employee_ID]          WHERE           (@CycleId = 0 OR cyc.[CycleId] = @CycleId)          AND cyc.[PeriodEndDate] BETWEEN @FromDate and @ToDate          AND ISNULL(tr.[Amount], 0) <> 0          AND CASE WHEN @IsTerminated = 1 THEN emp.[EndDate] ELSE @FromDate END BETWEEN @FromDate AND @ToDate          GROUP BY           irp.[IRP5Code], irp.[IRP5CodeDesc]          ORDER BY           irp.[IRP5Code], irp.[IRP5CodeDesc];    END;

GO

-- ============================================
-- SP: Payroll_EmployeeTaxPerCodeSummary_Tax_sp
-- Schema: dbo
-- ============================================
    /*-- =============================================      Author: Richa Mills  Create date:  2022/09/19  Description: Generate IRP5 Recon Report  Payroll_EmployeeTaxPerCodeSummary_Tax_sp  'August','2022/2023','Any',false  ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxPerCodeSummary_Tax_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS  BEGIN            DECLARE @ToDate DATETIME        DECLARE @taxYearfrom varchar(4) = left(@TaxYear,4)    DECLARE @taxYearTo varchar(4) = right(@TaxYear,4)             IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearTo, '03', '01'), 120)      SET @ToDate = DATEADD(d,-1,@ToDate)              END;          ELSE              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearfrom, '08', '31'), 120)              END;                    SELECT          tr.IRP5Code,IRP5CodeDesc,Amount          FROM           (select Irp5Code, SUM(Amount)Amount from Payroll_PayrollResults where IRP5Code in (4102,4141,4142) and PeriodID in (select Period_Id from Payroll_CyclePeriodDetails where PeriodEndDate <= @ToDate and TaxYear = @TaxYear) group by IRP5Code) tr           LEFT JOIN           (select distinct IRP5Code,IRP5CodeDesc from Payroll_IRP5Code) irp ON tr.[IRP5Code] = irp.[IRP5Code]          WHERE ISNULL(tr.[Amount], 0) <> 0    END;

GO

-- ============================================
-- SP: Payroll_EmployeeTaxTotalDetail_sp
-- Schema: dbo
-- ============================================
  /*-- =============================================      Author: Richa Mills  Create date:  2022/09/16  Description: Generate IRP5 Recon Report  Exec Payroll_EmployeeTaxTotalDetail_sp 'August','2023/2024',1,false    ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxTotalDetail_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex int,      @IsTerminated BIT  AS  BEGIN    DECLARE @ToDate DATETIME        DECLARE @taxYearfrom varchar(4) = left(@TaxYear,4)    DECLARE @taxYearTo varchar(4) = right(@TaxYear,4)    DECLARE @Month varchar(2) = '02'    DECLARE @PayeCode varchar(50) = (SELECT TOP 1 PayeRegistrationNo FROM  dbo.Payroll_Municipality)               IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearTo, '03', '01'), 120)      SET @ToDate = DATEADD(d,-1,@ToDate)              END;          ELSE              BEGIN                  SET @ToDate = convert(nvarchar(19), datefromparts(@taxYearfrom, '08', '31'), 120)      SET @Month = '08'              END         Select Employee_ID,EmpCode,FirstName,Surname,                dbo.PaddingString_fxn(ISNULL(@PayeCode + CAST(2023 AS VARCHAR(4)) + @Month, ''), 25, 0, 'R') + dbo.PaddingString_fxn(CONVERT(NVARCHAR(50), '0' + cn.Irp5CertificateNumber), 5, 0, 'L') Irp5Number,     IRP5Code,SUM(Amount)Amount from(      Select EmployeeID,IRP5Code,Amount from payroll_payrollresults where IRP5Code <> 0 and PeriodID in       (select Period_Id from Payroll_CyclePeriodDetails where PeriodEndDate <= @ToDate and TaxYear = @TaxYear)      UNION ALL     SELECT Employee_ID,4116 IRP5Code,SUM(TaxCredits)Amount FROM Payroll_PayrollRun_History_Employees WHERE Period_ID IN (      SELECT Period_id from Payroll_CyclePeriodDetails where TaxYear = @TaxYear and EndDate <= @ToDate) group by Employee_ID      UNION ALL     SELECT Employee_ID,4120 IRP5Code,SUM(SecondaryMTC)Amount FROM Payroll_PayrollRun_History_Employees WHERE Period_ID IN (      SELECT Period_id from Payroll_CyclePeriodDetails where TaxYear = @TaxYear and EndDate <= @ToDate) group by Employee_ID)pr       Left Join       Payroll_Employee emp on emp.Employee_ID = pr.EmployeeID           Left Join       Payroll_EmployeeIRP5CertificateNumber cn on cn.EmployeeId = pr.EmployeeID and cn.TaxYear = @taxYearTo       where Amount <> 0       Group by Employee_ID,EmpCode,FirstName,Surname,cn.Irp5CertificateNumber,IRP5Code       Order by Employee_ID,IRP5Code    END;     

GO

-- ============================================
-- SP: Payroll_EmployeeTaxTotalSummary_sp
-- Schema: dbo
-- ============================================
/*-- =============================================      Author: Richa Mills  Create date:  2022/09/16  Description: Generate IRP5 Recon Report  Exec Payroll_EmployeeTaxTotalSummary_sp 'August','2023/2024',1,false  Richa M - 2023/10/26 Fix binding to Payroll_EmployeeIRP5CertificateNumber table    ============================================= */  CREATE PROCEDURE [dbo].[Payroll_EmployeeTaxTotalSummary_sp]      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex int,      @IsTerminated BIT  AS  BEGIN      DECLARE @PAYENumber varchar(20)          DECLARE @Period TABLE ( PeriodID INT );          DECLARE @PayeCode VARCHAR(50);    DECLARE @TaxYearint int = CAST(RIGHT(@Taxyear,4) AS Int)            DECLARE @FromDate DATETIME , @ToDate DATETIME , @TYear NVARCHAR(50) , @Month NVARCHAR(2) , @SumOfCode BIGINT = 0;        SELECT TOP 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails     WHERE TaxYear = @TaxYear ORDER BY Period_ID;              SELECT TOP 1 @PayeCode = PayeRegistrationNo FROM  dbo.Payroll_Municipality;               IF @TaxPeriod = 'February'              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));                  SET @Month = '02';              END;          ELSE              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));                  SET @Month = '08';              END;                    SELECT          tr.[EmployeeID],       emp.[EmpCode],       emp.[FirstName],       emp.[Surname],             dbo.PaddingString_fxn(ISNULL(@PayeCode + CAST(2023 AS VARCHAR(4)) + @Month, ''), 25, 0, 'R') + dbo.PaddingString_fxn(CONVERT(NVARCHAR(50), '0' + cn.Irp5CertificateNumber), 5, 0, 'L') Irp5Number,       irp.[TransactionTypeID],        irp.[IRP5Code],        irp.[IRP5CodeDesc],        SUM(ISNULL(tr.[Amount], 0)) AS 'Amount'          FROM           Payroll_CyclePeriodDetails cyc          LEFT JOIN           Payroll_PayrollResults tr ON cyc.[Period_ID] = tr.[PeriodID]          LEFT JOIN           Payroll_IRP5Code irp ON tr.[IRP5Code] = irp.[IRP5Code]          LEFT JOIN           Const_Cycle c ON cyc.[CycleID] = c.[Cycle_ID]          LEFT JOIN           Payroll_Employee emp ON tr.[EmployeeID] = emp.[Employee_ID]    LEFT JOIN      Payroll_EmployeeIRP5CertificateNumber cn  on cn.[EmployeeId] = emp.[Employee_ID] and cn.TaxYear = @TaxYearint               WHERE            cyc.[PeriodEndDate] BETWEEN @FromDate and @ToDate          AND ISNULL(tr.[Amount], 0) <> 0    AND irp.[IRP5Code] in (4102)          GROUP BY           irp.[IRP5Code], irp.[IRP5CodeDesc],irp.[TransactionTypeID],tr.[EmployeeID], emp.EmpCode,emp.FirstName,emp.Surname,cn.[Irp5CertificateNumber]    END;

GO

-- ============================================
-- SP: Payroll_EmployeeTerminationRpt_sp
-- Schema: dbo
-- ============================================
-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  --2016-10-05 TP46563 James: Additional columns named EndDate caused old EndDate to be come ambigioous. Renamed it to P_E.EndDate  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2023/03/13 Richa M - Fix SP to display correct information  -- 2024/06/06 Kgosi S - Updated SP to allow for Department and Division filters  -- 2024/10/31 Richa M - Fix Department/Division Filters    CREATE PROCEDURE [dbo].[Payroll_EmployeeTerminationRpt_sp]   @TerminationFromDate DATETIME = '',   @TerminationToDate DATETIME='',   @DepartmentId INT = 0,   @DivisionId INT = 0,   @CycleId INT = 0  as  BEGIN     DECLARE @Employee TABLE (Employee_ID INT, EmployeeNo VARCHAR(50), EmployeeCode VARCHAR(10), EmployeeName VARCHAR(200),IDNumber VARCHAR(50), DateJoined VARCHAR(50),DateResigned VARCHAR(50),ResignationReason nvarchar(250),Departement nvarchar(200),Division nvarchar(200),Cycle nvarchar(200),OriginalCycle varchar(200), DepartmentId INT, DivisionId INT)      -- Add Terminated Employees (Employee_Termination)     INSERT INTO @Employee     SELECT         emp.Employee_ID,      dbo.BufferString_fxn(CONVERT(VARCHAR, (emp.Employee_ID )), 8, '0') AS EmployeeNo,       ISNULL(EmpCode, '') AS EmployeeCode,       ISNULL(FirstName + ' ','') + ISNULL(Surname,'') AS EmployeeName,      ISNULL(IDno,'') AS IDNumber,      CONVERT(NVARCHAR(15),emp.JoiningDate ,103) as DateJoined,      CONVERT(NVARCHAR(15),term.TerminationStartDate ,103) as DateResigned,      reason.ReasonDescription as ResignationReason,      dep.DepartmentDesc,      div.DivisionDesc,      cycle.CycleDesc CurrentCycle,      termCycle.CycleDesc OriginalCycle,      Department_ID,      Division_ID        FROM      (SELECT *       FROM Payroll_EmployeeTermination       WHERE TerminationStartDate BETWEEN @TerminationFromDate and @TerminationToDate and Complete = 1) term      LEFT OUTER JOIN Payroll_employee emp      on emp.Employee_ID = term.EmployeeID      LEFT OUTER JOIN       (       SELECT EmployeeId,DepartmentId,DivisionId from Payroll_EmployeeHistory where EmployeeHistory_ID in(     SELECT MAX(EmployeeHistory_ID)EmployeeHistory_ID     FROM Payroll_EmployeeHistory      WHERE EmployeeID in       (SELECT EmployeeID        FROM Payroll_EmployeeTermination               WHERE TerminationStartDate BETWEEN @TerminationFromDate and @TerminationToDate and Complete = 1)       AND EndDate  BETWEEN @TerminationFromDate and @TerminationToDate     GROUP  BY EmployeeId)            )      AS emph ON emph.EmployeeID = emp.Employee_ID       LEFT OUTER JOIN dbo.Payroll_ReasonEmployeeChange AS reason       ON reason.Reason_ID = term.TerminationReasonID     LEFT OUTER JOIN dbo.Const_Department AS dep       ON dep.Department_ID = emph.DepartmentID     LEFT OUTER JOIN dbo.Const_Division AS div       ON div.Division_ID = emph.DivisionID     LEFT OUTER JOIN dbo.Const_Cycle AS cycle       ON cycle.Cycle_ID = emp.CycleID     LEFT OUTER JOIN dbo.Const_Cycle AS termCycle       ON termCycle.Cycle_ID = term.EmployeeCycleId     ORDER BY Employee_ID      -- Add Employees not terminated via Termination process. Contracts ended    INSERT INTO @Employee   SELECT  Employee_ID,   dbo.BufferString_fxn(CONVERT(VARCHAR, (emp.Employee_ID )), 8, '0') AS EmployeeNo,       ISNULL(EmpCode, '') AS EmployeeCode,       ISNULL(FirstName + ' ','') + ISNULL(Surname,'') AS EmployeeName,      ISNULL(IDno,'') AS IDNumber,      CONVERT(NVARCHAR(15),emp.JoiningDate ,103) as DateJoined,      CONVERT(NVARCHAR(15),emp.EndDate ,103) as DateResigned,       'End Of Contract' as ResignationReason,      dep.DepartmentDesc,      div.DivisionDesc,      cycle.CycleDesc CurrentCycle,      cycle.CycleDesc OriginalCycle,      Department_ID,      Division_ID      FROM (SELECT *        FROM payroll_employee        WHERE EndDate BETWEEN @TerminationFromDate AND @TerminationToDate        AND Employee_ID NOT IN (select Employee_ID from @Employee)) emp     LEFT OUTER JOIN       (       SELECT MAX(EmployeeHistory_ID)EmployeeHistory_ID, EmployeeId,DepartmentID,DivisionID      FROM Payroll_EmployeeHistory      WHERE EmployeeID in       (SELECT Employee_ID       FROM payroll_employee        WHERE EndDate BETWEEN @TerminationFromDate AND @TerminationToDate       AND Employee_ID NOT IN (select Employee_ID from @Employee)       ) GROUP  BY EmployeeId,DepartmentID,DivisionID)          AS emph ON emph.EmployeeID = emp.Employee_ID       LEFT OUTER JOIN dbo.Payroll_ReasonEmployeeChange AS reason       ON reason.Reason_ID = emp.ReasonID     LEFT OUTER JOIN dbo.Const_Department AS dep       ON dep.Department_ID = emph.DepartmentID     LEFT OUTER JOIN dbo.Const_Division AS div       ON div.Division_ID = emph.DivisionID     LEFT OUTER JOIN dbo.Const_Cycle AS cycle       ON cycle.Cycle_ID = emp.CycleID          ORDER BY Employee_ID      SELECT * from @Employee where (DepartmentId = @DepartmentId OR  @DepartmentId = 0) AND (DivisionId = @DivisionId OR @DivisionId = 0) order by Employee_ID         END

GO

-- ============================================
-- SP: Payroll_EmployeeTrailPaysilpRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 23 JUL 2013  -- Description:    -- CALLS : Payroll_EmployeeTrailPaysilpRpt_sp 0, 0, 4  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt Added ISNULL checks at employee name and address to cater for empty fields.  -- 2016-01-05 Suri Kandukuri Added employee code.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_EmployeeTrailPaysilpRpt_sp]   @EmployeeID INT,   @DepartmentId INT,   @PeriodId INT  AS  BEGIN   DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME, @TaxYear NVARCHAR(10)   SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID     SELECT @FROMDATE AS FROMDATE,@TODATE AS  TODATE,    PAY_MUN.MunicipalityName,    (SELECT        KeyValue                            FROM            AAAA_ConfigSettings                            WHERE        (KeyName = 'DocViewerRootFolderPath')) + 'Municipality/' +                               PAY_MUN.MunicipalityImagePath                                AS [IMAGE],    ISNULL(PAY_MUN.PhyAddress1 + ' ','')+ ISNULL(PAY_MUN.PhyAddress2 + ' ','')+ ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb),'') AS COMPANYADDRESS,    PAY_MUN.RegistrationNo,    CONVERT(NVARCHAR,PAY_CYC_PER.PeriodEndDate,103) AS PAYPERIOD,    PAY_EMP.Idno as IDNumber,isnull(EmpCode,'') EmpCode, PAY_EMP.Employee_ID,    ISNULL(PAY_EMP.FirstName + ' ','') + ISNULL(PAY_EMP.SecondName + ' ','') + ISNULL(PAY_EMP.Surname,'') AS EMPLOYEENAME,    dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8,'0') AS EmpNo,    ISNULL(PAY_EMP.PhysicalAddress1 + ' ','') + ISNULL(PAY_EMP.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_EMP.PhysicalSuburbID),'') AS EMPADDRESS,      CONVERT(NVARCHAR,PAY_EMP.JoiningDate,103) AS STARTDATE,    CONST_TRAN_TYPE.TransactionTypeDesc, CONST_TRAN_TYPE.TransactionType_ID,    PAY_EMP_TRA_PAY.Amount,    PAY_SAL.SalaryHeadTitle as TransactionTypeDescription,    (SELECT SUM(LeaveBalance)FROM Payroll_EmployeeLeave WHERE EmployeeID =PAY_EMP.Employee_ID) AS TOTALLEAVE,        (     (      SELECT SUM(TRAIL.Amount)       FROM Payroll_EmployeeTrialPayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID       WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND        TRAIL.TaxYear =@TaxYear  AND Payroll_IRP5Code.TransactionTypeID = 1     )     -     (      SELECT SUM(AMOUNT)       FROM Payroll_EmployeeTrialPayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID        WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND         TRAIL.TaxYear =@TaxYear AND Payroll_IRP5Code.TransactionTypeID = 2     )    )AS NETPAY       FROM Payroll_Employee PAY_EMP   INNER JOIN Payroll_Municipality PAY_MUN ON PAY_MUN.Municipality_ID = PAY_EMP.MunicipalityID   INNER JOIN Payroll_EmployeeTrialPayslip PAY_EMP_TRA_PAY ON PAY_EMP_TRA_PAY.EmployeeID = PAY_EMP.Employee_ID   INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_TRA_PAY.PayrollDefinationID   INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID   INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID    INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID   INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER ON PAY_CYC_PER.PERIOD_ID = PAY_EMP_TRA_PAY.PERIODID AND  PAY_CYC_PER.CYCLEID=PAY_EMP.CYCLEID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID  WHERE (PAY_EMP.Employee_ID =@EmployeeID OR @EmployeeID = 0 ) AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND PAY_EMP_TRA_PAY.PeriodId = @PeriodID    AND PAY_EMP_TRA_PAY.TaxYear = @TaxYear AND TaxSavePurpose = 0  END  

GO

-- ============================================
-- SP: Payroll_EmployeeTrailPaysilpT1Rpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 23 JUL 2013  -- Description:    -- CALLS : [Payroll_EmployeeTrailPaysilpT1Rpt_sp] 0, 0, 1  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt Added ISNULL checks at employee name and address to cater for empty fields.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_EmployeeTrailPaysilpT1Rpt_sp]   @EmployeeID INT,   @DepartmentId INT,   @PeriodId INT  AS  BEGIN   DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME, @TaxYear NVARCHAR(10)   SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID     SELECT @FROMDATE AS FROMDATE,@TODATE AS  TODATE,    PAY_MUN.MunicipalityName,    (SELECT        KeyValue                            FROM            AAAA_ConfigSettings                            WHERE        (KeyName = 'DocViewerRootFolderPath')) + 'Municipality/' +                               PAY_MUN.MunicipalityImagePath                                AS [IMAGE],    ISNULL(PAY_MUN.PhyAddress1 + ' ','')+ ISNULL(PAY_MUN.PhyAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb),'') AS COMPANYADDRESS,    PAY_MUN.RegistrationNo,    CONVERT(NVARCHAR,PAY_CYC_PER.PeriodEndDate,103) AS PAYPERIOD,    PAY_EMP.Idno as EmpCode, PAY_EMP.Employee_ID,    ISNULL(PAY_EMP.FirstName + ' ','') + ISNULL(PAY_EMP.SecondName + ' ','') + ISNULL(PAY_EMP.Surname,'') AS EMPLOYEENAME,    dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8,'0') AS EmpNo,    ISNULL(PAY_EMP.PhysicalAddress1 + ' ','') + ISNULL(PAY_EMP.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_EMP.PhysicalSuburbID),'') AS EMPADDRESS,    CONVERT(NVARCHAR,PAY_EMP.JoiningDate,103) AS STARTDATE,    CONST_TRAN_TYPE.TransactionTypeDesc, CONST_TRAN_TYPE.TransactionType_ID,    PAY_EMP_TRA_PAY.Amount,    PAY_SAL.SalaryHeadTitle as TransactionTypeDescription,    (SELECT SUM(LeaveBalance)FROM Payroll_EmployeeLeave WHERE EmployeeID =PAY_EMP.Employee_ID) AS TOTALLEAVE,        (     (      SELECT SUM(TRAIL.Amount)       FROM Payroll_EmployeeTrialPayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID       WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND        TRAIL.TaxYear =@TaxYear  AND Payroll_IRP5Code.TransactionTypeID = 1     )     -     (      SELECT SUM(AMOUNT)       FROM Payroll_EmployeeTrialPayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Pay.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID        WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND         TRAIL.TaxYear =@TaxYear AND Payroll_IRP5Code.TransactionTypeID = 2     )    )AS NETPAY       FROM Payroll_Employee PAY_EMP   INNER JOIN Payroll_Municipality PAY_MUN ON PAY_MUN.Municipality_ID = PAY_EMP.MunicipalityID   INNER JOIN Payroll_EmployeeTrialPayslip PAY_EMP_TRA_PAY ON PAY_EMP_TRA_PAY.EmployeeID = PAY_EMP.Employee_ID   INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_TRA_PAY.PayrollDefinationID   INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID   INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID    INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID   INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER ON PAY_CYC_PER.PERIOD_ID = PAY_EMP_TRA_PAY.PERIODID AND  PAY_CYC_PER.CYCLEID=PAY_EMP.CYCLEID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID  WHERE (PAY_EMP.Employee_ID =@EmployeeID OR @EmployeeID = 0 ) AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND PAY_EMP_TRA_PAY.PeriodId = @PeriodID    AND PAY_EMP_TRA_PAY.TaxYear = @TaxYear AND TaxSavePurpose = 0  END  

GO

-- ============================================
-- SP: Payroll_EmployeeTravelCalculation_Trial_sp
-- Schema: dbo
-- ============================================
   /*   Author  : LUNGISANI KHUMALO   Create date : 09/03/2017   Description : Calculates Employees Travel Claims   Update date : 11/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings   Update date :   21/11/2017 - Richa M Update SP to read claims from Payroll_EmployeeClaims table   Update date : 23/02/2018 - Richa M Change SP to get Salary Head from Const table   Update date : 2018/08/21 - Richa M Add Scoa string details   Update date : 2018/10/22 - Ferdi Botha Added Travel Allowance (taxable distribution)   Update date : 2019/01/18 - Ferdi Botha Updated Travel Allowance to only include values above zero (taxable distribution)   Update date : 2019/10/10 - Modiri Sealo added  [EPD].[Enabled] = 1   Update date : 2019/10/24 - Modiri Sealo 21733 Transactions for previous month do not display on the payslip View after approval   Update date : 2019/11/08 - Artur Anzorge Change query to accept claim with negative values   Update date : 2019/11/14 - Modiri https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/24899   Update date : 2020/02/28 - Ilya Skavronskiy Change query to include claims for valid periods  */  CREATE procedure [dbo].[Payroll_EmployeeTravelCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      declare @Periods table (       [ID] [int] identity(1,1) not null,     [PeriodID] [int] not null      )      insert into @Periods([PeriodID])        select top 3 [Period_ID] from [Payroll_CyclePeriodDetails] where [CycleID] = @CycleID and [CycleModeID] = @CycleModeID     and (PeriodStartDate >= DateAdd(Month,-2,@StartDate) and PeriodEndDate <= @EndDate)    order by [Period_ID] desc      declare @Percentage decimal(18, 6) = 0,      @Value decimal(18, 6) = 0,      @Minimum decimal(18, 6) = 0,      @Maximum decimal(18, 6) = 0      select top 1 @Percentage = [Percentage], @Value = [Value], @Minimum = [Minimum], @Maximum = [Maximum] from [Const_SARSRates] where ([IRP5Code] in(3702, 3703) and [StartDate] <= @EndDate and [UntilDate] >= @StartDate)      /* INSERT CLAIMS + RE-IMBURSIVE TRAVEL ALLOWANCE LESS THAN CLIENT POLICY */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear], [Simulation], [ProjectId], [ScoaItemId], [DivisionId], [FunctionId], [RegionId])       select [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], sum(cast([TE].[CostAmount] as decimal(18, 6))), @Month, @SCOAYear, @PeriodID, [SH].[SalaryHeadTitle], [TE].[ReferenceNo], @TaxYear, @Simulation, ProjectId, [TE].[ScoaItemID], [TE].[DivisionId], [TE].[FunctionId], [TE].[RegionId]        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadId] = [CL].[SalaryHeadId] and [EPD].[EmployeeId] = [TE].[EmployeeId]  and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left join @Periods as [P] on [TE].[PeriodID] = [P].[PeriodID]           left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on  [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ISNULL(TE.Processed,0)=0       and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end)        and [TE].[Enabled] = 1        AND (ISNULL(TE.IsCorrection, 0) = 0 OR (TE.IsCorrection = 1 AND TE.PeriodID = @PeriodID ))       and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null)        and [IsApprovalRequired] = 1 and [IsApproved] = 1        and (not [CL].[Claim_Type] = 'Travel' or ([CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] <= @Value))       and (case        when @CycleModeID = 1 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end        when @CycleModeID = 2 then         case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end        else 0 end) = 1        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast([TE].[CostAmount] as decimal(18, 6))) <> 0      /* INSERT RE-IMBURSIVE TRAVEL ALLOWANCE EXCEEDING CLIENT POLICY; HOWEVER WE CAP THE VALUE TO THE SARS PRESCRIBED RATE */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear], [Simulation], [ProjectId], [ScoaItemId], [DivisionId], [FunctionId], [RegionId])       select [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], sum(cast((@Value * [TE].[Kilometre]) as decimal(18, 6))), @Month, @SCOAYear, @PeriodID, [SH].[SalaryHeadTitle], [TE].[ReferenceNo], @TaxYear, @Simulation, ProjectId, [TE].[ScoaItemID], [TE].[DivisionId], [TE].[FunctionId], [TE].[RegionId]        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadId] = [CL].[SalaryHeadId] and [EPD].[EmployeeId] = [TE].[EmployeeId]  and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left join @Periods as [P] on [TE].[PeriodID] = [P].[PeriodID]           left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on  [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where (ISNULL(TE.Processed,0)=0  and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end) and [TE].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [IsApprovalRequired] = 1 and [IsApproved] = 1 and [CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] > @Value and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast((@Value * [TE].[Kilometre]) as decimal(18, 6))) <> 0      /* INSERT RE-IMBURSIVE TRAVEL ALLOWANCE EXCEEDING CLIENT POLICY; THE DIFFERENCE ABOVE THE CAP OF THE SARS PRESCRIBED RATE */    insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear], [Simulation], [ProjectId], [ScoaItemId], [DivisionId], [FunctionId], [RegionId])       select [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], sum(cast((([CL].[ClientPolicy] * [TE].[Kilometre]) - (@Value * [TE].[Kilometre])) as decimal(18, 6))), @Month, @SCOAYear, @PeriodID, [SH].[SalaryHeadTitle], [TE].[ReferenceNo], @TaxYear, @Simulation, ProjectId, [TE].[ScoaItemID], [TE].[DivisionId], [TE].[FunctionId], [TE].[RegionId]        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_ClaimsHistory] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID] and TE.EffectiveDate >= CL.EffectiveDate and TE.EffectiveDate <= CL.EndDate         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeId] = [TE].[EmployeeId] and ([EPD].[PayrollSalaryHeadId] = (           select top 1 [SH].[SalaryHead_ID]            from [Payroll_IRP5Code] as [IRP5] with(nolock)             join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1            where ([IRP5].[Enabled] = 1 and isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) = 3722)          )         ) and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left join @Periods as [P] on [TE].[PeriodID] = [P].[PeriodID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on  [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where (ISNULL(TE.Processed,0)=0  and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end) and [TE].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [IsApprovalRequired] = 1 and [IsApproved] = 1 and [CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] > @Value and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1        )        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast((([CL].[ClientPolicy] * [TE].[Kilometre]) - (@Value * [TE].[Kilometre])) as decimal(18, 6))) <> 0     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeTravelCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Create date : 31/01/2019   Description : Calculates Employee Travel Claims (Simulation)   Update Date : 11/04/2019 => Added Employee Travel Claims (Simulation) @ Terminations   Modified : Artur Anzorge 08/11/2019 Change query to accept claim with negative values  */  CREATE procedure [Payroll_EmployeeTravelCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      declare @Percentage decimal(18, 6) = 0,      @Value decimal(18, 6) = 0,      @Minimum decimal(18, 6) = 0,      @Maximum decimal(18, 6) = 0      select top 1 @Percentage = [Percentage], @Value = [Value], @Minimum = [Minimum], @Maximum = [Maximum] from [Const_SARSRates] where ([IRP5Code] in(3702, 3703) and [StartDate] <= @UntilDate and [UntilDate] >= @StartDate)      /* INSERT CLAIMS + RE-IMBURSIVE TRAVEL ALLOWANCE LESS THAN CLIENT POLICY */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [TE].[EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle], sum(cast([TE].[CostAmount] as decimal(18, 6)))        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadId] = [CL].[SalaryHeadId] and [EPD].[EmployeeId] = [TE].[EmployeeId]         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where (ISNULL(TE.Processed,0)=0  and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end) and [TE].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [IsApprovalRequired] = 1 and [IsApproved] = 1 and (not [CL].[Claim_Type] = 'Travel' or ([CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] <= @Value)))        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast([TE].[CostAmount] as decimal(18, 6))) <> 0      /* INSERT RE-IMBURSIVE TRAVEL ALLOWANCE EXCEEDING CLIENT POLICY; HOWEVER WE CAP THE VALUE TO THE SARS PRESCRIBED RATE */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [TE].[EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle], sum(cast((@Value * [TE].[Kilometre]) as decimal(18, 6)))        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadId] = [CL].[SalaryHeadId] and [EPD].[EmployeeId] = [TE].[EmployeeId]         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where (ISNULL(TE.Processed,0)=0  and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end) and [TE].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [IsApprovalRequired] = 1 and [IsApproved] = 1 and [CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] > @Value)        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast((@Value * [TE].[Kilometre]) as decimal(18, 6))) <> 0      /* INSERT RE-IMBURSIVE TRAVEL ALLOWANCE EXCEEDING CLIENT POLICY; THE DIFFERENCE ABOVE THE CAP OF THE SARS PRESCRIBED RATE */    insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [TE].[EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [SH].[SalaryHeadTitle], sum(cast((([CL].[ClientPolicy] * [TE].[Kilometre]) - (@Value * [TE].[Kilometre])) as decimal(18, 6)))        from [Payroll_EmployeeClaims] as [TE] with(nolock)         join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [TE].[ClaimID]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeId] = [TE].[EmployeeId] and ([EPD].[PayrollSalaryHeadId] = (           select top 1 [SH].[SalaryHead_ID]            from [Payroll_IRP5Code] as [IRP5] with(nolock)             join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1            where ([IRP5].[Enabled] = 1 and isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) = 3722)          )         ) and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [TE].[EmployeeID]         join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (          (isnull([TPS].[EmployeeChangeID], 0) = (case           when @SimulationType = 1 then @ParentID           else 0          end))          or          (isnull([TPS].[TerminationID], 0) = (case           when @SimulationType = 2 then @ParentID           else 0          end))         )        where (ISNULL(TE.Processed,0)=0  and [TE].[EmployeeID] = (case @EmployeeID when 0 then [TE].[EmployeeID] else @EmployeeID end) and [TE].[Enabled] = 1 and ([ExcludeFromPayment] = 0 or [ExcludeFromPayment] is null) and [IsApprovalRequired] = 1 and [IsApproved] = 1 and [CL].[Claim_Type] = 'Travel' and [CL].[ClientPolicy] > @Value)        group by [TE].[EmployeeID], [EPD].[EmployeePayrollDefinition_ID], [IRP5].[TransactionTypeID], [SH].[SalaryHead_ID], [SH].[SalaryHeadTitle], [TE].[ReferenceNo], [TE].[ProjectId], [TE].[ScoaItemID], [TE].[DivisionId], [TE].[RegionId], [TE].[FunctionId]         having sum(cast((([CL].[ClientPolicy] * [TE].[Kilometre]) - (@Value * [TE].[Kilometre])) as decimal(18, 6))) <> 0     end try     begin catch     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeTrialPayslipErrors_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- author:  <author,,>  -- create date: <create date,,>  -- description: <description,,Copy data from staging table to actual tables>  -- 2019-04-06: FERDI BOTHA, ADDED INSERT TO CREATE TRIAL ERRORS IF THEY DON'T EXIST  -- =============================================  create procedure [dbo].[Payroll_EmployeeTrialPayslipErrors_sp] @type tinyint, @EmployeeID int,  @PeriodID int, @table [Payroll_EmployeeTrialPayslipErrors] readonly  as    begin     set nocount on;     if (@type = 0)      delete from [Payroll_EmployeeTrialPayslipErrors] where ([ID] in(select [ID] from @table))     if (@type = 1)   begin      update [ETP] set [ETP].[PeriodID] = @PeriodID, [ETP].[EmployeeID] = [LTP].[EmployeeID], [ETP].[Reason] = [LTP].[Reason], [ETP].[Enabled] = [LTP].[Enabled], [ETP].[ValidationType] = [LTP].[ValidationType], [ETP].[StoredProcedure] = [LTP].[StoredProcedure],  [ETP].[CapturerID] = [LTP].[CapturerID], [ETP].[DateCaptured] = [LTP].[DateCaptured], [ETP].[ModifierID] = [LTP].[ModifierID], [ETP].[DateModified] = [LTP].[DateModified]       from [Payroll_EmployeeTrialPayslipErrors] as [ETP]        join @table as [LTP] on [LTP].[ID] = [ETP].[ID]        end     if (@type = 2)   begin             if(@EmployeeID = 0)       delete [Payroll_TrialErrors] where ([PeriodID] = @PeriodID)       else         delete [Payroll_TrialErrors] where ([PeriodID] = @PeriodID and ([EmployeeID] in(select [EmployeeID] from @table) or [ValidationType] <> 'Employee Level'))      insert into [Payroll_TrialErrors]([EmployeeID], [PeriodID],[ErrorMessage], [ValidationType], [StoredProcedure], [CapturedBy], [CapturedDate], [Blocking])       select [EmployeeID], [PeriodID], [Reason], [ValidationType] ,[StoredProcedure],[CapturerID], [DateCaptured], [Blocking] from @table where ([Enabled] = 1)      insert into [Payroll_EmployeeTrialPayslipErrors]([ID], [PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified], [Blocking], [Simulation])       select [ID], [PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified], [Blocking], [Simulation]        from @table as [T] where (not exists(          select [ID]           from [Payroll_EmployeeTrialPayslipErrors] as [TPE] with(nolock)           where ([TPE].[PeriodID] = [T].[PeriodID] and [TPE].[EmployeeID] = [T].[EmployeeID] and [TPE].[Reason] = [T].[Reason] and [TPE].[Enabled] = [T].[Enabled] and [T].[Enabled] = 1 and [TPE].[ValidationType] = [T].[ValidationType] and [TPE].[StoredProcedure] = [T].[StoredProcedure] and [TPE].[Blocking] = [T].[Blocking] and [TPE].[Simulation] = [T].[Simulation])         )        )     end     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeType_sp
-- Schema: dbo
-- ============================================
      -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 01 March 2016  -- Description: Returns all Employee Type   -- Call: [Payroll_EmployeeType_sp]  -- 2015-02-12 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeType_sp]  AS   BEGIN       SELECT [EmployeeType_ID]      ,[EmployeeTypeDescription]      ,[Enabled]      ,[CapturerID]      ,[ModifierID]      ,[DateCaptured]      ,[DateModified]     FROM [dbo].[Const_EmployeeType_sys]    END    

GO

-- ============================================
-- SP: Payroll_EmployeeU19Form_sp
-- Schema: dbo
-- ============================================
--SET QUOTED_IDENTIFIER ON|OFF  --SET ANSI_NULLS ON|OFF  --GO  CREATE PROCEDURE [dbo].[Payroll_EmployeeU19Form_sp]   @IsDummy bit, @EmployeeID int = null, @Surname nvarchar(50) = null, @FullName nvarchar(200) = null, @IDNumber nvarchar(13) = null, @PassportNumber nvarchar(20) = null, @EmployeeCode nvarchar(50) = null  as    BEGIN   DECLARE @EmployeeTable  TABLE ( EmployeeID INT);     INSERT INTO @EmployeeTable (EmployeeID)   SELECT EmployeeID FROM dbo.Payroll_EmployeeTermination WHERE TerminationStartDate <= GETDATE()   UNION    SELECT EmployeeID FROM dbo.payroll_EmployeeLeaveTransactions WHERE LeaveTypeID = 31 AND GETDATE() BETWEEN StartDate AND EndDate -- 31 id is Maternity Leave       SELECT [Employee_ID], [IdNo], [Surname], [FirstName], [PassportNumber], isnull([EmailAddress], '') as [EmailAddress], isnull([CellNumber], '') as [CellNumber], isnull([HomeNumber], '') as [HomeNumber], isnull([FaxNumber], '') as [FaxNumber], [JoiningDate], [PE].[EndDate], [PositionDesc],    cast((case when [PE].[EndDate] >= getdate() then 1 else 0 end) as bit) as [Enabled], [PE].[IsMarried], isnull([EmpCode], '') as [EmpCode]    FROM [Payroll_Employee] as [PE] with(nolock)    INNER JOIN @EmployeeTable AS EE ON EE.EmployeeID = PE.Employee_ID     JOIN [Payroll_Position] as [PP] with(nolock) on [Position_ID] = (      (select top 1 [PositionID]         from [Payroll_PositionHistory]         where ([EmployeeID] = [PE].[Employee_ID])          order by [StartDate] desc         )      )    WHERE ([IsDummy] = @IsDummy and     (isnull(@EmployeeID, 0) = 0 or [Employee_ID] = @EmployeeID) and     (isnull(@Surname, '') = '' or [Surname] like '%' + @Surname + '%') and     (isnull(@FullName, '') = '' or [FirstName] like '%' + @FullName + '%') and     (isnull(@IDNumber, '') = '' or [IdNo] like '%' + @IDNumber + '%') and     (isnull(@PassportNumber, '') = '' or [PassportNumber] like '%' + @PassportNumber + '%') and     (isnull(@EmployeeCode, '') = '' or [EmpCode] like '%' + @EmployeeCode + '%')    )ORDER BY  [Employee_ID]    END  

GO

-- ============================================
-- SP: Payroll_EmployeeU19FormDeails_sp
-- Schema: dbo
-- ============================================
--SET QUOTED_IDENTIFIER ON|OFF  --SET ANSI_NULLS ON|OFF  --GO  CREATE PROCEDURE [dbo].[Payroll_EmployeeU19FormDeails_sp]      @EmployeeId AS INT  -- WITH ENCRYPTION, RECOMPILE, EXECUTE AS CALLER|SELF|OWNER| 'user_name'  AS      SELECT  ROW_NUMBER() OVER ( ORDER BY ( SELECT   1 ) ) AS No , 'UIF Claim Form' AS [Description], FORMAT(puc.CaputureDate,'dd/MM/yyyy') AS DateGenerated, (uu.FirstName+ ' '+ uu.LastName) AS GeneratedBy,     UIfClaimformId,PUC.UIFClaimFormCreationReason AS Reason   FROM Payroll_UIFClaimForm AS PUC   INNER JOIN dbo.User_UserDetail AS UU ON UU.User_ID = PUC.CapturerID   WHERE puc.EmployeeId = @EmployeeId   ORDER BY PUC.CaputureDate DESC  

GO

-- ============================================
-- SP: Payroll_EmployeeUIFCalculation_Trial_sp
-- Schema: dbo
-- ============================================
/*      Payroll_EmployeeUIFCalculation_Trial_sp   Author  : FERDI BOTHA   Create date : 08/06/2017   Description : Employee UIF Calculation   Update date : 28/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified :   17/09/2021 - Richa M - Fixed Bugs on UIF calc  */  CREATE PROCEDURE [dbo].[Payroll_EmployeeUIFCalculation_Trial_sp]      @IRP5Income [Payroll_IRP5Income] READONLY,      @EmployeeID     INT,      @PeriodID       INT,      @CycleID        INT,      @CycleModeID    INT,      @StartDate      DATETIME,      @EndDate        DATETIME,      @Month          INT,      @SCOAYear       NVARCHAR(10),      @TaxYear        NVARCHAR(10),      @Simulation     BIT  AS  BEGIN        SET NOCOUNT ON;        BEGIN TRY            DECLARE @CycleTypeID  INT = (SELECT ISNULL(CycleTypeID, 1)                                       FROM  [Const_Cycle] WITH (NOLOCK)                                       WHERE [Cycle_ID] = @CycleID),                  @AdhocTypeID  INT = (SELECT ISNULL(AdhocTypeID, 0)                                       FROM  [Payroll_CyclePeriodDetails] WITH (NOLOCK)                                       WHERE [Period_ID] = @PeriodID),                  @periodInTaxYear INT = (SELECT PeriodInTaxYear                                          FROM  Payroll_CyclePeriodDetails                                          WHERE Period_ID = @PeriodID),                  @TrxTypeId   INT;            DECLARE @i INT = 1,                  @c INT,                  @Periods INT = (CASE @CycleTypeID                                     WHEN 1 THEN 12    -- Months                                     WHEN 2 THEN 52    -- Weekly                                     WHEN 3 THEN 26    -- Bi-weekly                                 END),                  @result       DECIMAL(18, 6),                  @ExcludeUIF   BIT = (SELECT ISNULL(ExcludeForUIF, 0)                                       FROM  [Payroll_Municipality] WITH (NOLOCK)                                       WHERE [Enabled] = 1),                  @UIFPercentage DECIMAL(18, 6) = (SELECT TOP 1 [Percentage]                                                   FROM  [Const_SARSRates] WITH (NOLOCK)                                                   WHERE [IRP5Code] = 4141                                                     AND ((@StartDate BETWEEN [StartDate] AND [UntilDate])                                                       OR (@EndDate   BETWEEN [StartDate] AND [UntilDate]))),                  @UIFMaximum    DECIMAL(18, 6) = (SELECT TOP 1 [Maximum]                                                   FROM  [Const_SARSRates] WITH (NOLOCK)                                                   WHERE [IRP5Code] = 4141                                                     AND ((@StartDate BETWEEN [StartDate] AND [UntilDate])                                                       OR (@EndDate   BETWEEN [StartDate] AND [UntilDate]))),                  @UIFCalcMax    DECIMAL(18, 6);            DECLARE @IRP5Code TABLE          (              [IRP5Code] INT NOT NULL          );            DECLARE @UIFCalculation TABLE          (              [ID]              INT IDENTITY(1, 1) NOT NULL,              [Periods]         INT NOT NULL,              [EmployeeID]      INT NOT NULL,              [PayrollDefinationID] INT NOT NULL,              [Amount]          DECIMAL(18, 6) NOT NULL,              [Month]           NVARCHAR(10) NOT NULL,              [FinancialYear]   NVARCHAR(10) NOT NULL,              [PeriodID]        INT NOT NULL,              [TaxSavePurpose]  BIT NOT NULL DEFAULT (0),              [SalaryHeadTitleAddendum] NVARCHAR(200) NULL,              [VendorID]        INT NULL,              [TaxYear]         NVARCHAR(10) NULL,              [TransactionTypeId] INT          );            -- UIF IRP5 code [4141]          INSERT INTO @IRP5Code ([IRP5Code]) VALUES (4141);            -- Force UIF to read from employee subtype configuration          IF (NOT @ExcludeUIF = 0)              SET @ExcludeUIF = 0;            IF (@ExcludeUIF = 0)          BEGIN                INSERT INTO @UIFCalculation                      ([Periods], [EmployeeID], [PayrollDefinationID], [Amount],                       [Month], [FinancialYear], [PeriodID],                       [SalaryHeadTitleAddendum], [VendorID], [TaxYear], [TransactionTypeId])              SELECT                      (SELECT ISNULL(MAX(PeriodInTaxYear), @Periods)                         FROM [Payroll_CyclePeriodDetails] WITH (NOLOCK)                        WHERE [CycleID]    = @CycleID                          AND [CycleModeID]= 1                          AND [Enabled]    = 1                          AND [TaxYear]    = @TaxYear),                      [PE].[Employee_ID],                      [EmployeePayrollDefinition_ID],                      CAST(0 AS DECIMAL(18, 6)),                      @Month,                      @SCOAYear,                      @PeriodID,                      [SalaryHeadTitle],                      [VendorID],                      @TaxYear,                      [TransactionTypeID]              FROM    [Payroll_EmployeePayrollDefinition] AS [EPD] WITH (NOLOCK)              JOIN    [Payroll_SalaryHead] AS [SH] WITH (NOLOCK)                      ON [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]                     AND [SH].[Enabled] = 1              JOIN    [Payroll_GLItems] AS [GL] WITH (NOLOCK)                      ON [SalaryHeadID] = [SalaryHead_ID]                     AND [GL].[Enabled] = 1                     AND [GL].[FinYear] = @SCOAYear              JOIN    [Payroll_IRP5Code] AS [IRP5] WITH (NOLOCK)                      ON [IRP5Code_ID] = [SH].[IRP5CodeId]                     AND [IRP5].[Enabled] = 1              JOIN    [Payroll_Employee] AS [PE] WITH (NOLOCK)                      ON [Employee_ID] = [EPD].[EmployeeID]                     AND ISNULL([PE].[ExcludeUIF], 0) = 0                     AND [PE].[CycleID] = @CycleID              JOIN    [Payroll_EmployeeSubtypes] AS [ES] WITH (NOLOCK)                      ON [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID]                     AND [ES].[ExcludeUIF] = 0              JOIN    [Payroll_CyclePeriodDetails] AS [CPD] WITH (NOLOCK)                      ON [CPD].[CycleID]   = [PE].[CycleID]                     AND [CPD].[Period_ID] = @PeriodID                     AND [CPD].[Enabled]   = 1              JOIN    [Payroll_TrialRun_History_Employees] AS [EP] WITH (NOLOCK)                      ON [EP].[Employee_ID] = [PE].[Employee_ID]                     AND [EP].[Period_ID]  = [CPD].[Period_ID]                     AND [EP].[Cycle_ID]   = [PE].[CycleID]              LEFT JOIN [Payroll_CyclePeriodAdhocSalaryHead] AS [ACPD] WITH (NOLOCK)                      ON [PeriodID]     = [CPD].[Period_ID]                     AND [ACPD].[SalaryHeadID] = [SalaryHead_ID]              WHERE   [PE].[Employee_ID] = (CASE @EmployeeID WHEN 0 THEN [PE].[Employee_ID] ELSE @EmployeeID END)                AND   [EPD].[Enabled]    = 1                AND   [TransactionTypeID] IN (2, 3)                AND   ISNULL([IRP5CertCode], [IRP5Code]) IN (SELECT [IRP5Code] FROM @IRP5Code)                AND   (CASE                          WHEN @CycleModeID = 1 THEN                              CASE WHEN ISNULL([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 THEN 1 ELSE 0 END                          WHEN @CycleModeID = 2 THEN                              CASE WHEN ISNULL([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 THEN 0 ELSE 1 END                          ELSE 0                       END) = 1;                SELECT @c = COUNT([ID]) FROM @UIFCalculation;                ----------------------------------------------------------------              -- NEW: cache last EmployeeID so we only call the income SP once              ----------------------------------------------------------------              DECLARE @LastEmployeeID INT = -1;                WHILE (@i <= @c)              BEGIN                  SELECT  @EmployeeID = [EmployeeID],                          @TrxTypeId = [TransactionTypeId]                  FROM    @UIFCalculation                  WHERE   [ID] = @i;                    SET @UIFCalcMax = @UIFMaximum;                    -- Only call Payroll_GetTotalIRP5Income_Trial_sp once per employee                  IF (@EmployeeID <> @LastEmployeeID)                  BEGIN                      SELECT @result =         COALESCE(SUM(          CAST(ISNULL(CAST(ETP.Amount AS DECIMAL(18, 6)), 0.0) AS DECIMAL(18, 6)) *          (           CAST(            CASE             WHEN ETR.Taxable = 0 THEN 100.0       -- non-taxable still counts as 100% of the UIF base             ELSE ETR.Taxable                      -- percentage from @IRP5Income            END AS DECIMAL(18, 6)           ) / 100.0          )         ), 0.0)        FROM Payroll_EmployeeTrialPayslip AS ETP   WITH (NOLOCK)        JOIN Payroll_EmployeePayrollDefinition AS EPD WITH (NOLOCK)          ON EPD.EmployeePayrollDefinition_ID = ETP.PayrollDefinationID         AND EPD.Enabled = 1        JOIN Payroll_SalaryHead AS SH            WITH (NOLOCK)          ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID         AND SH.Enabled = 1        JOIN Payroll_IRP5Code AS IRP5            WITH (NOLOCK)          ON IRP5.IRP5Code_ID = SH.IRP5CodeId         AND IRP5.Enabled = 1        JOIN @IRP5Income AS ETR          ON ETR.IRP5Code = ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code)         AND ETR.[Type] IN (1, 2, 3)                  -- 01 + 02 + 03         AND ETR.Taxable > 0                          -- @taxable = 1 (taxable only)         AND ETR.StartDate <= @EndDate         AND ETR.UntilDate >= @StartDate        JOIN Payroll_Employee AS PE           WITH (NOLOCK)          ON PE.Employee_ID = ETP.EmployeeID         AND PE.CycleID = @CycleID        JOIN Payroll_CyclePeriodDetails AS CPD WITH (NOLOCK)          ON CPD.CycleID   = PE.CycleID         AND CPD.Period_ID = ETP.PeriodID         AND CPD.Enabled   = 1        JOIN Payroll_TrialRun_History_Employees AS EP WITH (NOLOCK)          ON EP.Period_ID   = ETP.PeriodID         AND EP.Employee_ID = ETP.EmployeeID         AND EP.Cycle_ID    = PE.CycleID        LEFT JOIN Payroll_CyclePeriodAdhocSalaryHead AS ACPD WITH (NOLOCK)          ON ACPD.PeriodID    = CPD.Period_ID         AND ACPD.SalaryHeadID = SH.SalaryHead_ID        WHERE         ETP.EmployeeID = @EmployeeID         AND ETP.PeriodID = @PeriodID         AND ETP.TaxSavePurpose = 0         AND (            CASE            WHEN @CycleModeID = 1 THEN             CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 1 ELSE 0 END            WHEN @CycleModeID = 2 THEN             CASE WHEN ISNULL(CyclePeriodAdhocPayrollDefinition_ID, 0) = 0 THEN 0 ELSE 1 END            ELSE 0            END          ) = 1         AND IRP5.TransactionTypeID IN (1, 4);                 SET @LastEmployeeID = @EmployeeID;           END             DECLARE @UIFAmount         DECIMAL(18,6) = (CAST(@result AS DECIMAL(18,6)) * CAST(@UIFPercentage AS DECIMAL(18,6)));           DECLARE @UIFAlreadydeducted DECIMAL(18,6) = (             SELECT SUM(Amount)             FROM   Payroll_PayrollResults             WHERE  EmployeeID = @EmployeeID               AND  PeriodId IN (                 SELECT Period_Id                 FROM   Payroll_CyclePeriodDetails                 WHERE  TaxYear        = @TaxYear                AND  CycleID        = @CycleId                AND  PeriodInTaxYear = @periodInTaxYear               )               AND  IRP5Code IN (SELECT IRP5Code FROM @IRP5Code)               AND  TransactionTypeID = @TrxTypeId           );                    SET @UIFCalcMax = @UIFCalcMax - ISNULL(@UIFAlreadydeducted, 0);                    IF (@UIFCalcMax < @UIFAmount)                      SET @UIFAmount = @UIFCalcMax;                    IF (@UIFCalcMax < 0)                      SET @UIFAmount = 0;                    UPDATE @UIFCalculation                     SET [Amount] = @UIFAmount                   WHERE [ID] = @i;                    SET @i = @i + 1;              END                INSERT INTO [Payroll_EmployeeTrialPayslip]                      ([EmployeeID],                       [PayrollDefinationID],                       [Amount],                       [Month],                       [FinancialYear],                       [PeriodID],                       [SalaryHeadTitleAddendum],                       [VendorID],                       [TaxYear],                       [Simulation])              SELECT  [EmployeeID],                      [PayrollDefinationID],                      [Amount],                      [Month],                      [FinancialYear],                      [PeriodID],                      [SalaryHeadTitleAddendum],                      [VendorID],                      [TaxYear],                      @Simulation              FROM    @UIFCalculation;            END        END TRY        BEGIN CATCH            INSERT INTO [Payroll_TrialErrors]                  ([ValidationType],                   [PeriodID],                   [ErrorMessage],                   [StoredProcedure],                   [CapturedBy],                   [CapturedDate],                   [Simulation])          VALUES ('System',                  @PeriodID,                  '#' + CAST(ERROR_LINE() AS NVARCHAR(10)) + ' - ' + ERROR_MESSAGE(),                  ERROR_PROCEDURE(),                  1,                  GETDATE(),                  @Simulation);        END CATCH        SET NOCOUNT OFF;    END

GO

-- ============================================
-- SP: Payroll_EmployeeUIFCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 08/06/2017   Description : Employee UIF Calculation   Update date : 28/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update Date : 11/04/2019 => Added Employee UIF Calculation (Simulation) @ Terminations  */  create procedure [Payroll_EmployeeUIFCalculation_TrialSimulation_sp] @IRP5Income [Payroll_IRP5Income] readonly, @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as     begin     set nocount on;     begin try      declare @CycleID int = (select isnull([CycleID], 0) from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)),      @CycleModeID int = 1,      @TaxYear varchar(9) = (select [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'TaxYear'))      declare @CycleTypeID int = (select isnull([CycleTypeID], 1) from [Const_Cycle] with(nolock) where ([Cycle_ID] = @CycleID))      declare @i int = 1,      @c int,      @Periods int = (case @CycleTypeID         /* MONTHS */       when 1 then 12         /* WEEKLY */       when 2 then 52         /* BI-WEEKLY */       when 3 then 26        end),      @result decimal(18, 6),      @ExcludeUIF bit = (select isnull([ExcludeForUIF], 0) from [Payroll_Municipality] with(nolock) where ([Enabled] = 1)),      @UIFPercentage decimal(18, 6) = (select top 1 [Percentage] from [Const_SARSRates] with(nolock) where ([IRP5Code] = 4141 and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),      @UIFMaximum decimal(18, 6) = (select top 1 [Maximum] from [Const_SARSRates] with(nolock) where ([IRP5Code] = 4141 and ((@StartDate between [StartDate] and [UntilDate]) or (@UntilDate between [StartDate] and [UntilDate])))),        /* SET THE XOR VALUE OF THE TransactionTypeID TO MATCH 1 OR 4 */      @XOR int = (1 ^ 8)      declare @IRP5Code table (       [IRP5Code] int not null      )      declare @UIFCalculation table (       [ID] [int] identity(1, 1) not null,     [Periods] [int] not null,     [EmployeeID] [int] not null,     [PayrollDefinationID] [int] not null,     [Amount] [decimal](18, 6) not null,     [TaxSavePurpose] [bit] not null default (0),     [TransactionTypeID] int null,     [SalaryHeadID] int null,     [SalaryHeadTitle] nvarchar(50) null      )      /* EMPLOYEE & EMPLOYER UNEMPLOYMENT INSURANCE FUND (UIF) CONTRIBUTIONS [4141] */    insert into @IRP5Code([IRP5Code]) values(4141)      /* FORCE UFI TO READ FROM EMPLOYEE SUBTYPE CONFIGURATION */    if (not @ExcludeUIF = 0)       set @ExcludeUIF = 0      if (@ExcludeUIF = 0)    begin       insert into @UIFCalculation([Periods], [EmployeeID], [PayrollDefinationID], [Amount], [TransactionTypeID], [SalaryHeadID], [SalaryHeadTitle])        select @Periods, [PE].[Employee_ID], [EmployeePayrollDefinition_ID], cast(0 as decimal(18, 6)), [IRP5].[TransactionTypeID], [SalaryHead_ID], [SalaryHeadTitle]         from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and isnull([PE].[ExcludeUIF], 0) = 0 and [PE].[CycleID] = @CycleID          join [Payroll_EmployeeSubtypes] as [ES] with(nolock) on [EmployeeSubtype_ID] = [PE].[EmployeeSubtypeID] and [ES].[ExcludeUIF] = 0          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (           (isnull([TPS].[EmployeeChangeID], 0) = (case            when @SimulationType = 1 then @ParentID            else 0           end))           or           (isnull([TPS].[TerminationID], 0) = (case            when @SimulationType = 2 then @ParentID            else 0           end))          )         where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] in(2, 3) and isnull([IRP5CertCode], [IRP5Code]) in(select [IRP5Code] from @IRP5Code))       select @c = count([ID]) from @UIFCalculation       while (@i <= @c)     begin        select @EmployeeID = [EmployeeID] from @UIFCalculation where ([ID] = @i)        exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] @IRP5Income, '01 + 02 + 03', @EmployeeID, @StartDate, @UntilDate, @CycleID, @CycleModeID, @XOR, @SimulationType, @ParentID, 1, @result out        update @UIFCalculation set [Amount] = (cast(@result as decimal(18, 6)) * cast(@UIFPercentage as decimal(18, 6))) where ([ID] = @i)        set @i = @i + 1       end       update @UIFCalculation set [Amount] = cast(@UIFMaximum as decimal(18, 6)) where (cast([Amount] as decimal(18, 6)) > cast(@UIFMaximum as decimal(18, 6)))       insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])        select @SimulationType, [TransactionTypeID], [SalaryHeadID], [EmployeeID],         (case          when @SimulationType = 1 and @ParentID > 0 then @ParentID          else null         end),         (case          when @SimulationType = 2 and @ParentID > 0 then @ParentID          else null         end), 0, [SalaryHeadTitle], [Amount] from @UIFCalculation where ([Amount] > 0)      end     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeUIFDeclartion_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 20/09/2017   Description : Returns Employees UIF Declarations   Update date : 26/02/2018 - Resolved incorrectly calculated Tax Year.   update the salary : 17/8/2018 - 77227 change the salary value.   update the NonContributionReason :17/8/2018 -- 77231 change the NonContributionReason value   update the NonContributionReason :01/10/2018 -- 77231 change the NonContributionReason value   update the Description to UifDefinedNonContributorReason_ID  : 01/Feb/2019 -- #84047 Export File to CSV Date format Change From YYYY/MM/DD to DD/MM/YYYY   2019/08/13 => Removed linkage to Payroll Const_TerminationReason table - Ferdi Botha     exec Payroll_EmployeeUIFDeclartion_sp '2022',9,570   EXECUTE Payroll_EmployeeUIFDeclartion_sp 2022,5,0  */    CREATE PROCEDURE [dbo].[Payroll_EmployeeUIFDeclartion_sp] @TaxYear nvarchar(100), @TaxMonth int, @EmployeeID int  as  begin      set nocount on;       DECLARE @CalendarYear INT = IIF(@TaxMonth > 2,CAST(@TaxYear AS INT)-1,CAST(@TaxYear AS INT));  DECLARE @HistoryDate DATETIME = DATEFROMPARTS(@CalendarYear,@TaxMonth,1);  declare @UifLimit decimal(18,2) = (select top 1 Maximum * 100 from Const_SARSRates where IRP5Code = 4141 and @HistoryDate between [StartDate] and [UntilDate])  DECLARE @Period TABLE (Period_Id INT)         INSERT INTO @Period     SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails   WHERE DATEPART(MONTH,PeriodEndDate) = @TaxMonth      AND DATEPART(YEAR, PeriodEndDate) = @CalendarYear     AND Processed = 1       declare @Employees table  (   PeriodId int,   EmployeeId int,   Amount decimal(18,2)  )    insert into @Employees  Select PeriodID,EmployeeID,SUM(Amount)Amount from Payroll_PayrollResults where PeriodID in (Select Period_Id from @Period) and IRP5CodeID in (select IRP5Code_Id from Payroll_IRP5Code where IRP5Code = 4141)  group by PeriodID,EmployeeID    select cp.PeriodEndDate,   Employee_ID,   @TaxYear TaxYear,   ct.UifDefinedTitleID TitleCode,   Initials,   FirstName,   Surname,   (case when [IdNo] is null then 2 else 1 end) as [IDCode],   IdNo [IDNumber],   DateOfBirth,   (case when isnull(st.[ExcludeUIF], 0) = 1 then 2 else 1 end) as [ContributionCode],   st.UIFReasonID,   ISNULL(gross.Amount,0) [Gross],   (select top 1 IIF(peh.MonthlySalary > @UifLimit, @UifLimit, IsNULL(peh.MonthlySalary,0)) from Payroll_EmployeeHistory peh where peh.employeeid=emp.Employee_ID and Enabled = 1 and    StartDate <= @HistoryDate and EndDate >= @HistoryDate order by StartDate desc) as [UIFSalary],   1 as [FrequencyTypeCode],   WHPM_Monthly MonthlyHours,   JoiningDate CommencementDate,   Case when ISNULL(TerminationReasonID,0) = 0 OR (ISNULL(TerminationReasonID,0) <> 0 and emp.EndDate > PeriodEndDate) Then Null else emp.EndDate end TerminationDate,   CASE WHEN emp.EndDate > PeriodEndDate THEN NULL ELSE TerminationReasonID END TerminationReason,   pr.Amount [UIFContribution]  from  (Select PeriodID,EmployeeID,SUM(Amount)Amount from @Employees  group by PeriodID,EmployeeID  UNION ALL  Select distinct PeriodId,EmployeeID,0 from Payroll_PayrollResults where PeriodID in (Select Period_id from @Period) and EmployeeID not in (Select EmployeeID from @Employees)  )pr  left join payroll_employee emp on emp.Employee_ID = pr.EmployeeID  left join Payroll_EmployeeSubtypes st on st.EmployeeSubtype_ID = emp.EmployeeSubtypeID  left join Payroll_CyclePeriodDetails cp on cp.Period_ID = pr.PeriodID  left join Const_Title ct on ct.Title_ID = emp.TitleID  left join Const_HR_UifDefinedNonContributorReason_sys uif on st.UIFReasonID = uif.UifDefinedNonContributorReason_ID  left join const_UIFTerminationReason term on term.UIFTerminationReason_Id = emp.TerminationReasonID  left join   (  Select PeriodID,EmployeeID,SUM(Amount)Amount from Payroll_PayrollResults where PeriodID in (Select Period_Id from @Period) and TransactionTypeID in (1,4)  group by PeriodID,EmployeeID  )gross on gross.EmployeeID = pr.EmployeeID and gross.PeriodID = pr.PeriodID  where Employee_ID = @EmployeeID OR @EmployeeID = 0  order by Employee_ID      set nocount off;    end

GO

-- ============================================
-- SP: Payroll_EmployeeUnionFeesCalculation_Trial_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 06/03/2017   Description : Calculates Employees Union Deductions   Update date : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs   Update date : 10/05/2017 - Changed the mappings for Method of Calculation   Update date : 27/06/2017 - Updated Parameters & IRP5Code mappings   Update date : 30/06/2017 - Updated the joins to the correct mappings  */  create procedure [Payroll_EmployeeUnionFeesCalculation_Trial_sp] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @Simulation bit  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [PeriodID], [VendorID], [SalaryHeadTitleAddendum], [TaxYear], [ReferenceNo], [Simulation])       select [EmployeeID], [EmployeePayrollDefinition_ID], ((cast(         case when isnull([ContributionType], 0) = 1 then          case when ((cast([FixedSalary] as decimal(18, 6)) * isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) > isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else ((cast([FixedSalary] as decimal(18, 6)) * isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) end         else          case when isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) > isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) end         end        as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))), @Month, @SCOAYear, @PeriodID, [VendorID], [UnionRepresentatives], @TaxYear, [UnionRepresentatives],  @Simulation        from ([Payroll_EmployeeUnion] as [eu] with(nolock)         join [Const_UnionRepresentatives] as [cu] with(nolock) on [UnionRepresentatives_ID] = [eu].[UnionRepresentativesID] and [cu].[Enabled] = 1)         join [Cons_Vendor] as [ven] with(nolock) on [Vendor_ID] = [cu].[VendorID]         join (          select distinct [EPD].[EmployeeID], isnull([FixedSalary], 0) as [FixedSalary], [EmployeePayrollDefinition_ID], [Percentage]           from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)            join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1            join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1            join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID            join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = @PeriodID and [CPD].[Enabled] = 1            join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]            left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]           where ([EPD].[EmployeeID] = (case @EmployeeID when 0 then [EPD].[EmployeeID] else @EmployeeID end) and [EPD].[Enabled] = 1 and [TransactionTypeID] = 2 and            [SalaryHead_ID] = 9 and            (case             when @CycleModeID = 1 then              case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end             when @CycleModeID = 2 then              case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end             else 0 end) = 1           )        ) as [emp] on [emp].[EmployeeID] = [eu].[EmpID]         where ([eu].[Enabled] = 1 and [eu].[StartDate] <= @EndDate and isnull([eu].[EndDate], @StartDate) >= @StartDate and ((cast(         case when isnull([ContributionType], 0) = 1 then          case when ((cast([FixedSalary] as decimal(18, 6)) * isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) > isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else ((cast([FixedSalary] as decimal(18, 6)) * isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) end         else          case when isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) > isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else isnull(cast([ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) end         end        as decimal(18, 6)) * cast([Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) > 0)     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate], [Simulation])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), @Simulation)     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeUnionFeesCalculation_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 31/01/2019   Description : Calculates Employee Union Fees (Simulation)   Update Date : 11/04/2019 => Added Employee Union Fees (Simulation) @ Terminations  */  create procedure [Payroll_EmployeeUnionFeesCalculation_TrialSimulation_sp] @EmployeeID int, @StartDate datetime, @UntilDate datetime, @SimulationType tinyint, @ParentID int  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslipSimulation]([SimulationType], [TransactionTypeID], [SalaryHeadID], [EmployeeID], [EmployeeChangeID], [TerminationID], [TaxPurpose], [Transaction], [Value])       select @SimulationType, [EMP].[TransactionTypeID], [EMP].[SalaryHead_ID], [EMP].[EmployeeID],        (case         when @SimulationType = 1 and @ParentID > 0 then @ParentID         else null        end),        (case         when @SimulationType = 2 and @ParentID > 0 then @ParentID         else null        end), 0, [EMP].[SalaryHeadTitle] + ' (' + [CU].[UnionRepresentatives] + ')', ((cast(         case when isnull([CU].[ContributionType], 0) = 1 then          case when ((cast([EMP].[MonthlySalary] as decimal(18, 6)) * isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) > isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else ((cast([EMP].[MonthlySalary] as decimal(18, 6)) * isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) end         else          case when isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) > isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) end         end        as decimal(18, 6)) * cast([EMP].[Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6)))        from ([Payroll_EmployeeUnion] as [EU] with(nolock)         join [Const_UnionRepresentatives] as [CU] with(nolock) on [UnionRepresentatives_ID] = [EU].[UnionRepresentativesID] and [CU].[Enabled] = 1)         join [Cons_Vendor] as [VEN] with(nolock) on [Vendor_ID] = [CU].[VendorID]         join (          select distinct [EPD].[EmployeeID] as [EmployeeID], cast((case             when @SimulationType = 1 then (              coalesce((select [MonthlySalary] from [Payroll_EmployeeChange] where ([EmployeeChange_ID] = @ParentID)), 0)             )             when @SimulationType = 2 then (              coalesce((select [FixedSalary] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID)), 0)             )             else 0            end) as decimal(18, 6)) as [MonthlySalary], [EPD].[EmployeePayrollDefinition_ID], [EPD].[Percentage], [IRP5].[TransactionTypeID] as [TransactionTypeID], [SH].[SalaryHead_ID] as [SalaryHead_ID], [SH].[SalaryHeadTitle] as [SalaryHeadTitle]           from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)            join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1            join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1            join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [EPD].[EmployeeID]            join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [EPD].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (             (isnull([TPS].[EmployeeChangeID], 0) = (case              when @SimulationType = 1 then @ParentID              else 0             end))             or             (isnull([TPS].[TerminationID], 0) = (case              when @SimulationType = 2 then @ParentID              else 0             end))            )           where ([EPD].[EmployeeID] = @EmployeeID and [EPD].[Enabled] = 1 and [IRP5].[TransactionTypeID] = 2 and [SH].[SalaryHead_ID] = 9)        ) as [EMP] on [EMP].[EmployeeID] = [EU].[EmpID]         where ([EU].[Enabled] = 1 and [EU].[StartDate] <= @UntilDate and isnull([EU].[EndDate], @StartDate) >= @StartDate and ((cast(         case when isnull([CU].[ContributionType], 0) = 1 then          case when ((cast([EMP].[MonthlySalary] as decimal(18, 6)) * isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) > isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else ((cast([EMP].[MonthlySalary] as decimal(18, 6)) * isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6)))) / cast(100 as decimal(18, 6))) end         else          case when isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) > isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) then isnull(cast([CU].[ContributionMaxValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) else isnull(cast([CU].[ContributionValue] as decimal(18, 6)), cast(0 as decimal(18, 6))) end         end        as decimal(18, 6)) * cast([EMP].[Percentage] as decimal(18, 6))) / cast(100 as decimal(18, 6))) > 0)     end try     begin catch     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_EmployeeVarianceRpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================    -- Author:  MEHUL PANCHAL     -- Create date: 08 JULY 2013    -- Description: GET EMPLOYEE PAYLIST    -- CALLS : [Payroll_EmployeeVarianceRpt_sp] 3,'2015/2016', 0, 0, 1    -- 2015-06-26 TP20842 James Roodt: Fixed year value fo LastDayInMonth    -- 2015-10-05 TP25371 Suri Kandukuri : Fixed Variance    -- 2016-01-05 TP29885 Ravindra Jijotia: Added EmpCode in the list.    -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.    -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA    -- Update date: 2017/12/06 - Richa M: changed the stored proc to return correct data - TP62825  -- NB! For this report the taxyear will be passed as 2018 (not 2017/2018)  -- The month will be 0 for Trial report as we can get the month   -- Payroll_EmployeeVarianceRpt_sp 304,2019,0,0,17  -- =============================================    CREATE procedure [dbo].[Payroll_EmployeeVarianceRpt_sp]     @PeriodId INT,     @TaxYear NVARCHAR(50),     @EmployeeId INT,     @DepartmentId INT,     @CycleId INT    AS    BEGIN    DECLARE @PreviousMonth INT,   @Month int = (select PeriodInTaxYear from Payroll_CyclePeriodDetails where Period_Id = @PeriodId),   @EndDate DATE,   @PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1,   @PreviousPreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 2     DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear   DECLARE @PreviousPeriodTaxYear VARCHAR(9) = @CurrentPeriodTaxYear   DECLARE @CycleDesc varchar(50) = (Select CycleDesc from Const_Cycle where Cycle_ID = @CycleID)    SET @PreviousMonth = @Month - 1         IF (@Month = 1)    BEGIN      SET @PreviousMonth = 12    SET @PreviousPeriodTaxYear =  @PreviousPreviousTaxYear + '/' + @PreviousTaxYear    END       DECLARE @CycleMode int = (Select CycleModeId from Payroll_CyclePeriodDetails where Period_Id = @PeriodId)     DECLARE @PreviousPeriodID int = (Select Period_ID from Payroll_CyclePeriodDetails where PeriodInTaxYear = @PreviousMonth AND TaxYear = @PreviousPeriodTaxYear AND CycleID = @CycleId AND CycleModeId = @CycleMode)     Select @EndDate = (Select periodEnddate from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)       SELECT @EndDate AS PeriodEndDate     ,pt.TransactionTypeID     ,ctt.TransactionTypeDesc     ,psh.SalaryHeadName SalaryTitle     ,pt.EmployeeID     ,emp.IdNo     ,Right('00000000' + CAST(isnull(emp.Employee_Id, '') AS VARCHAR(10)),8) + ' ' + isnull(emp.FirstName, '') + ' ' + isnull(emp.Surname, '') AS Fullname     ,pt.TaxPeriod     ,@CycleDesc AS CycleDesc   ,CASE when pt.PeriodID = @PeriodId THEN 'This Period' ELSE 'Previous Period' END As DisplayPeriod     ,ProcessingMonth     ,pt.SalaryHeadId     ,SalaryHeadName     ,pt.Amount AS Amount     ,CASE WHEN Period = @PeriodId Then pt.Amount * -1 ELSE pt.Amount END AS VarianceTotal     ,CASE WHEN ctt.TransactionType_ID = 1 THEN pt.Amount ELSE 0 END AS Earnings     ,CASE WHEN ctt.TransactionType_ID = 2 THEN pt.Amount ELSE 0 END AS Deductions        ,CASE WHEN ctt.TransactionType_ID = 3 THEN pt.Amount ELSE 0 END AS CompanyContribution     ,Case when ctt.TransactionType_ID = 1 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceEarnings     ,Case when ctt.TransactionType_ID = 2 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceDeduction     ,Case when ctt.TransactionType_ID = 3 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceCompanyContribution  FROM (SELECT  @PeriodId AS Period,    *   FROM Payroll_PayrollResults ppr   WHERE periodId = @PeriodId   AND ppr.TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeID, 0)   OR ISNULL(@EmployeeID, 0) = 0)   UNION ALL   SELECT @PreviousPeriodId AS Period,    *   FROM Payroll_PayrollResults ppr   WHERE periodId = @PreviousPeriodId   AND TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeID, 0)   OR ISNULL(@EmployeeID, 0) = 0)   ) pt  LEFT OUTER JOIN Payroll_Employee emp   ON emp.Employee_ID = pt.EmployeeID  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd   ON pt.PeriodId = pcpd.Period_ID    AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt   ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh   ON psh.Salaryhead_ID = pt.SalaryHeadId  WHERE (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)  order by emp.Employee_ID    end

GO

-- ============================================
-- SP: Payroll_EmployeeVarianceRptTrial_sp
-- Schema: dbo
-- ============================================
/*   Author  : Ferdi Botha   Create date : 15/09/2017   Description : Returns Employee Trial Run Variances   Update date: 22/09/2017 - updated the Total Costs Values   Update date: 2017/12/06 - Richa M: changed the stored proc to return correct data - TP62825   NB! For this report the taxyear will be passed as 2018 (not 2017/2018)   The month will be 0 for Trial report as we can get the month    Payroll_EmployeeVarianceRptTrial_sp 0,1,0,1,2018   done chages for the bug #84414 -- resolve the issue by putting isnull() for the fullName field in the query    */  CREATE PROCEDURE [dbo].[Payroll_EmployeeVarianceRptTrial_sp]   @DepartmentID int,   @CycleID int,   @EmployeeID int,   @PeriodId int,   @TaxYear nvarchar(50)  as    BEGIN     DECLARE @PreviousMonth INT,   @Month int = (select PeriodInTaxYear from Payroll_CyclePeriodDetails where Period_Id = @PeriodId),   @EndDate DATE,   @PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1,   @PreviousPreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 2     DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear   DECLARE @PreviousPeriodTaxYear VARCHAR(9) = @CurrentPeriodTaxYear   DECLARE @CycleDesc varchar(50) = (Select CycleDesc from Const_Cycle where Cycle_ID = @CycleID)    SET @PreviousMonth = @Month - 1         IF (@Month = 1)    BEGIN      SET @PreviousMonth = 12    SET @PreviousPeriodTaxYear =  @PreviousPreviousTaxYear + '/' + @PreviousTaxYear    END       DECLARE @CycleMode int = (Select CycleModeId from Payroll_CyclePeriodDetails where Period_Id = @PeriodId)     DECLARE @PreviousPeriodID int = (Select Period_ID from Payroll_CyclePeriodDetails where PeriodInTaxYear = @PreviousMonth AND TaxYear = @PreviousPeriodTaxYear AND CycleID = @CycleId AND CycleModeId = @CycleMode)     Select @EndDate = (Select periodEnddate from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)  SELECT @EndDate AS PeriodEndDate     ,pt.TransactionTypeID     ,ctt.TransactionTypeDesc     ,psh.SalaryHeadName SalaryTitle     ,pt.EmployeeID     ,emp.IdNo      ,Right('00000000' + CAST(isnull(emp.Employee_Id, '') AS VARCHAR(10)),8) + ' ' + isnull(emp.FirstName, '') + ' ' + isnull(emp.Surname, '') AS Fullname     ,pt.TaxPeriod     ,@CycleDesc AS CycleDesc   ,CASE when pt.PeriodID = @PeriodId THEN 'This Period (Trial)' ELSE 'Previous Period' END As DisplayPeriod     ,ProcessingMonth     ,pt.SalaryHeadId     ,SalaryHeadName     ,pt.Amount AS Amount     ,CASE WHEN Period = @PeriodId Then pt.Amount * -1 ELSE pt.Amount END AS VarianceTotal     ,CASE WHEN ctt.TransactionType_ID = 1 THEN pt.Amount ELSE 0 END AS Earnings     ,CASE WHEN ctt.TransactionType_ID = 2 THEN pt.Amount ELSE 0 END AS Deductions        ,CASE WHEN ctt.TransactionType_ID = 3 THEN pt.Amount ELSE 0 END AS CompanyContribution     ,Case when ctt.TransactionType_ID = 1 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceEarnings     ,Case when ctt.TransactionType_ID = 2 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceDeduction     ,Case when ctt.TransactionType_ID = 3 THEN CASE WHEN Period = @PeriodId THEN pt.Amount * -1 ELSE pt.Amount END ELSE 0 END AS VarianceCompanyContribution  FROM (SELECT  @PeriodId AS Period,    ppr.TransactionTypeID,EmployeeId,TaxPeriod,ppr.SalaryHeadID,Amount,PeriodId,ppr.DepartmentID   FROM Payroll_TrialResults ppr   WHERE periodId = @PeriodId   AND TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeID, 0)   OR ISNULL(@EmployeeID, 0) = 0)   UNION ALL   SELECT @PreviousPeriodId AS Period,    ppr.TransactionTypeID,EmployeeId,TaxPeriod,ppr.SalaryHeadID,Amount,PeriodId,ppr.DepartmentID   FROM Payroll_PayrollResults ppr   WHERE periodId = @PreviousPeriodId   AND TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeID, 0)   OR ISNULL(@EmployeeID, 0) = 0)   ) pt  LEFT OUTER JOIN Payroll_Employee emp   ON emp.Employee_ID = pt.EmployeeID  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd   ON pt.PeriodId = pcpd.Period_ID    AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt   ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh   ON psh.Salaryhead_ID = pt.SalaryHeadId  WHERE (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)  order by emp.Employee_ID    end

GO

-- ============================================
-- SP: Payroll_EmployeeWageCalculation_Trial_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Ilya Skavronskiy  -- Create date: 2020-09-16  -- Description: Calculates Employee Wages  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_EmployeeWageCalculation_Trial_sp]      @EmployeeID INT,       @PeriodID INT,       @CycleID INT,       @CycleModeID INT,       @StartDate DATETIME,       @EndDate DATETIME,       @Month INT,       @SCOAYear NVARCHAR(10),       @TaxYear NVARCHAR(10),       @Simulation BIT  AS  BEGIN  SET NOCOUNT ON;    BEGIN TRY   INSERT INTO Payroll_EmployeeTrialPayslip     (EmployeeID, PayrollDefinationID, Amount, [Month], FinancialYear, PeriodID, SalaryHeadTitleAddendum, TaxYear, ReferenceNo, Simulation)   SELECT    E.Employee_ID,    EPD.EmployeePayrollDefinition_ID,    SUM(WT.Amount),    @Month,     @SCOAYear,     @PeriodID,     SH.SalaryHeadName,     @TaxYear,    '',    @Simulation   FROM Payroll_WageTransaction AS WT WITH(NOLOCK)   JOIN Payroll_Employee AS E WITH(NOLOCK) ON WT.EmployeeId = E.Employee_ID AND E.CycleID = @CycleID   JOIN Payroll_EmployeePayrollDefinition AS EPD WITH(NOLOCK) ON WT.EmployeeId = EPD.EmployeeID AND EPD.Enabled = 1   JOIN Payroll_SalaryHead AS SH WITH(NOLOCK) ON EPD.PayrollSalaryHeadID = SH.SalaryHead_ID AND WT.SalaryHeadId = SH.SalaryHead_ID AND SH.Enabled = 1   JOIN Payroll_IRP5Code AS IRPC WITH(NOLOCK) ON SH.IRP5CodeId = IRPC.IRP5Code_ID AND IRPC.Enabled = 1   JOIN Payroll_CyclePeriodDetails AS CPD WITH(NOLOCK) ON WT.CapturedDuringPeriodId = CPD.Period_ID AND CPD.CycleID = @CycleID   JOIN Payroll_TrialRun_History_Employees AS TRHE WITH(NOLOCK) ON WT.EmployeeId = TRHE.Employee_ID AND CPD.Period_ID = TRHE.Period_ID   WHERE    (@EmployeeID = 0 OR WT.EmployeeId = @EmployeeID)    AND WT.Enabled = 1    AND WT.IsApproved = 1    AND WT.Processed = 0    AND WT.CapturedDuringPeriodId = @PeriodID   GROUP BY E.Employee_ID, EPD.EmployeePayrollDefinition_ID, SH.SalaryHeadName, WT.SalaryHeadId  END TRY  BEGIN CATCH   INSERT INTO Payroll_TrialErrors     (ValidationType, PeriodID, ErrorMessage, StoredProcedure, CapturedBy, CapturedDate, Simulation)   VALUES('System', @PeriodID, '#' + CAST(ERROR_LINE() AS NVARCHAR) + ' - ' + ERROR_MESSAGE(), ERROR_PROCEDURE(), 1, GETDATE(), @Simulation)  END CATCH    SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: Payroll_EmployeeWiseLeaveCalculation
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Ghanshyam Dhanani>  -- Create date: <Create Date,,28 Feb 2014>  -- Description: <Description,,Payroll_Employee Wise LeaveCalculation>  -- Call SP    : Payroll_EmployeeWiseLeaveCalculation '2013/2014'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_EmployeeWiseLeaveCalculation]   @FinYear VARCHAR(50)  AS  BEGIN      ----- Variable Declaration   DECLARE @tblEmp TABLE (EmpId INT, Flag BIT)   DECLARE @EmpId INT      ----- Get All Emp List   INSERT INTO @tblEmp ( EmpId, Flag )   SELECT DISTINCT EMPL.EmployeeID, 0 FROM dbo.Payroll_Employee AS EMP   INNER JOIN dbo.Payroll_EmployeeLeaves AS EMPL ON EMP.Employee_ID = EMPL.EmployeeID   INNER JOIN dbo.Const_LeaveSchemeDetail AS LSD ON EMPL.LeaveSchemeID = LSD.LeaveSchemeID AND EMPL.LeaveTypeID = LSD.LeaveTypeID   WHERE EMP.EndDate IS NULL AND EMPL.Enabled = 1 AND [Type] = '1'      ----- Leave Process Start   WHILE EXISTS (SELECT * FROM @tblEmp WHERE Flag = 0) BEGIN    SELECT TOP 1 @EmpId = EmpId FROM @tblEmp WHERE Flag = 0        EXEC dbo.Payroll_EmployeeLeaveCalculation_Periodic @EmployeeID = @EmpId--, -- int        --@FinYear = @FinYear -- nvarchar(10)        UPDATE @tblEmp SET Flag = 1 WHERE EmpId = @EmpId   END     END    

GO

