-- ============================================
-- SP: Payroll_Equity_Disciplinary_rpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_Equity_Disciplinary_rpt '2013/2014'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_Equity_Disciplinary_rpt]   @Financial_Year VARCHAR(50)  AS  BEGIN   DECLARE @Result TABLE (Id INT IDENTITY(1,1), Terminations VARCHAR(500), M_Africa INT, M_Color INT, M_India INT, M_White INT, M_Fo INT,        F_Africa INT, F_Color INT, F_India INT, F_White INT, F_Fo INT, Total INT)           /* Current Financial Year */   DECLARE @C_Year INT, @Fin_StartDate DATETIME, @Fin_EndDate DATETIME, @StartMonth VARCHAR(2)   SELECT TOP 1 @C_Year = Data FROM dbo.Split(@Financial_Year,'/')   SELECT @StartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'FinYearStartMonth'   SET @Fin_StartDate = @StartMonth + '/01/'+ CONVERT(NVARCHAR(10), @C_Year)   SET @Fin_EndDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @Fin_StartDate))      PRINT @Fin_StartDate   PRINT @Fin_EndDate      /* Employee Table */        DECLARE @Employee TABLE(Employee_ID INT, GenderID INT, OccupationLevel VARCHAR(500), EthnicGroupID INT, Isforeigner BIT, EquityDisabled BIT, JoiningDate DATETIME, EndDate DATETIME, IsDummy BIT, TerminationReasonID INT)      INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy, TerminationReasonID )   SELECT Employee_ID, GenderID, '', EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy, TerminationReasonID FROM dbo.Payroll_Employee AS P_E     INNER JOIN dbo.Payroll_Disciplinary AS PD ON PD.EmployeeReceivingID = P_E.Employee_ID     WHERE PD.DisiplinaryEndDate BETWEEN @Fin_StartDate AND @Fin_EndDate        /* Ethnic Table */   DECLARE @African_Id INT, @India_Id INT, @White_Id INT   SELECT @African_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE '%African%'   SELECT @India_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'India%'   SELECT @White_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'White%'      /* Declare Variables*/   DECLARE @C_Count INT, @M_Africa INT, @M_Color INT, @M_India INT, @M_White INT, @M_Fo INT, @F_Africa INT, @F_Color INT, @F_India INT, @F_White INT, @F_Fo INT     /* For Male GenderId = 2 and For Female GenderId = 1*/   DECLARE @M_GenderId INT = 2, @F_GenderId INT = 1      SELECT @M_Africa = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0      SELECT @F_Africa = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0      SELECT @M_Color = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0      SELECT @F_Color = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0      SELECT @M_India = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0      SELECT @F_India = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0      SELECT @M_White = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0      SELECT @F_White = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0      SELECT @M_Fo = COUNT(*) FROM @Employee   WHERE GenderID = @M_GenderId AND Isforeigner = 1      SELECT @F_Fo = COUNT(*) FROM @Employee   WHERE GenderID = @F_GenderId AND Isforeigner = 1      INSERT INTO @Result (Terminations, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )   SELECT '', @M_Africa, @M_Color, @M_India, @M_White, @M_Fo, @F_Africa, @F_Color, @F_India, @F_White, @F_Fo, (@M_Africa+ @M_Color+ @M_India+ @M_White+ @M_Fo+ @F_Africa+ @F_Color+ @F_India+ @F_White+ @F_Fo)     SELECT * FROM @Result      END  

GO

-- ============================================
-- SP: Payroll_Equity_Termination_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,08 May 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_Equity_Termination_rpt '2013/2014'  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2019/08/13 => Removed linkage to Payroll Const_TerminationReason table - Ferdi Botha  -- =============================================  create procedure [Payroll_Equity_Termination_rpt] @Financial_Year varchar(50)  as  begin     DECLARE @Result TABLE (Id INT IDENTITY(1,1), Terminations VARCHAR(500), M_Africa INT, M_Color INT, M_India INT, M_White INT, M_Fo INT,        F_Africa INT, F_Color INT, F_India INT, F_White INT, F_Fo INT, Total INT)      /* Current Financial Year */   DECLARE @C_Year INT, @Fin_StartDate DATETIME, @Fin_EndDate DATETIME, @StartMonth VARCHAR(2)   SELECT TOP 1 @C_Year = Data FROM dbo.Split(@Financial_Year,'/')   SELECT @StartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'FinYearStartMonth'   SET @Fin_StartDate = @StartMonth + '/01/'+ CONVERT(NVARCHAR(10), @C_Year)   SET @Fin_EndDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @Fin_StartDate))      /* Employee Table */        DECLARE @Employee TABLE(Employee_ID INT, GenderID INT, OccupationLevel VARCHAR(500), EthnicGroupID INT, Isforeigner BIT, EquityDisabled BIT, JoiningDate DATETIME, EndDate DATETIME, IsDummy BIT, TerminationReasonID INT)      INSERT INTO @Employee ( Employee_ID, GenderID, OccupationLevel, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, EndDate, IsDummy, TerminationReasonID )   SELECT Employee_ID, GenderID, JobFamily, EthnicGroupID, Isforeigner, EquityDisabled, JoiningDate, P_E.EndDate, IsDummy, TerminationReasonID FROM dbo.Payroll_Employee AS P_E     INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID     INNER JOIN dbo.Payroll_JobProfile AS P_JP ON PP.JobProfileID = P_JP.JobProfile_ID     WHERE P_E.EndDate BETWEEN @Fin_StartDate AND @Fin_EndDate     /* Major Group Table */   /*DECLARE @Level TABLE (TerminationReason_ID INT, TerminationReason NVARCHAR(500), Flag BIT)   DECLARE @TerminationReason_ID INT, @TerminationReason NVARCHAR(500)     INSERT INTO @Level( TerminationReason_ID, TerminationReason, Flag )   SELECT TerminationReason_ID, TerminationReasonDesc, 0 FROM dbo.Const_TerminationReason*/      /* Ethnic Table */   DECLARE @African_Id INT, @India_Id INT, @White_Id INT   SELECT @African_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE '%African%'   SELECT @India_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'India%'   SELECT @White_Id = Ethnic_ID FROM dbo.Const_EthnicGroup WHERE EthnicDesc LIKE 'White%'      /* Declare Variables*/   DECLARE @C_Count INT, @M_Africa INT, @M_Color INT, @M_India INT, @M_White INT, @M_Fo INT, @F_Africa INT, @F_Color INT, @F_India INT, @F_White INT, @F_Fo INT     /* For Male GenderId = 2 and For Female GenderId = 1*/   DECLARE @M_GenderId INT = 2, @F_GenderId INT = 1     /*WHILE EXISTS (SELECT * FROM @Level WHERE Flag = 0) BEGIN    SELECT TOP 1 @TerminationReason_ID = TerminationReason_ID, @TerminationReason = TerminationReason FROM @Level WHERE Flag = 0        SELECT @M_Africa = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @M_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0        SELECT @F_Africa = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @F_GenderId AND EthnicGroupID = @African_Id AND Isforeigner = 0        SELECT @M_Color = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @M_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0        SELECT @F_Color = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @F_GenderId AND EthnicGroupID NOT IN (@African_Id, @India_Id, @White_Id) AND Isforeigner = 0        SELECT @M_India = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @M_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0        SELECT @F_India = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @F_GenderId AND EthnicGroupID = @India_Id AND Isforeigner = 0        SELECT @M_White = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @M_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0        SELECT @F_White = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @F_GenderId AND EthnicGroupID = @White_Id AND Isforeigner = 0        SELECT @M_Fo = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @M_GenderId AND Isforeigner = 1        SELECT @F_Fo = COUNT(*) FROM @Employee    WHERE TerminationReasonID = @TerminationReason_ID AND GenderID = @F_GenderId AND Isforeigner = 1        INSERT INTO @Result (Terminations, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )    SELECT @TerminationReason, @M_Africa, @M_Color, @M_India, @M_White, @M_Fo, @F_Africa, @F_Color, @F_India, @F_White, @F_Fo, (@M_Africa+ @M_Color+ @M_India+ @M_White+ @M_Fo+ @F_Africa+ @F_Color+ @F_India+ @F_White+ @F_Fo)        UPDATE @Level SET Flag = 1 WHERE TerminationReason_ID = @TerminationReason_ID   END*/      /*Grand Total*/   INSERT INTO @Result (Terminations, M_Africa, M_Color, M_India, M_White, M_Fo, F_Africa, F_Color, F_India, F_White, F_Fo, Total )   SELECT 'GRAND Total', SUM(M_Africa), SUM(M_Color), SUM(M_India), SUM(M_White), SUM(M_Fo), SUM(F_Africa), SUM(F_Color), SUM(F_India), SUM(F_White), SUM(F_Fo), SUM(Total)   FROM @Result      SELECT * FROM @Result    END      /****** Object:  StoredProcedure [dbo].[Payroll_SalaryIncrementProcess_sp]    Script Date: 11/10/2016 8:17:57 AM ******/  SET ANSI_NULLS ON  

GO

-- ============================================
-- SP: Payroll_FinalRun_Export_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  James Roodt  -- Create date: 2015-02-19  -- Description: Retrieves data from a final payroll run and returns it to be exported   --              into a CSV file by the webapp  -- Called by: Checklist.aspx.cs (on the Payroll Run Screen)  -- EXEC Payroll_FinalRun_Export_sp 234  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_FinalRun_Export_sp]    -- Add the parameters for the stored procedure here   @PeriodID int = 0     AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     DECLARE @Temp TABLE                  (                    FMS5VoteNumber NVARCHAR(50),                                      [Description] NVARCHAR(200),        Amount DECIMAL(18, 2)                  )      INSERT INTO @Temp   SELECT lv.OldFms56VoteNumber, lv.VoteDesc, CreditAmount*-1 AS Amount   FROM Payroll_TransactionsGroup AS ptg   INNER JOIN led_vote AS lv ON lv.Vote_ID=ptg.VoteID   WHERE ptg.PeriodID=@PeriodID   AND CreditAmount<>0      INSERT INTO @Temp   SELECT lv.OldFms56VoteNumber, lv.VoteDesc, DebitAmount AS Amount   FROM Payroll_TransactionsGroup AS ptg   INNER JOIN led_vote AS lv ON lv.Vote_ID=ptg.VoteID   WHERE ptg.PeriodID=@PeriodID   AND DebitAmount>0    SELECT * FROM @Temp    END  

GO

-- ============================================
-- SP: Payroll_FinalRun_ExportPaymentData_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  James Roodt  -- Create date: 2015-02-20  -- Description: Retrieves Banking information for trnasactions in the form of an ABC file  -- Called by: Checklist.aspx.cs (on the Payroll Run Screen)  -- EXEC Payroll_FinalRun_ExportPaymentData_sp 234  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_FinalRun_ExportPaymentData_sp]    -- Add the parameters for the stored procedure here   @PeriodID int = 0     AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     --Merge data from Employee and Creditors    -- Temp table to emrge the data  DECLARE @Temp TABLE  (   IsSalary BIT,   Name NVARCHAR(200),   PaymentType NVARCHAR(200),   BankName NVARCHAR(200),   BankBranchCode NVARCHAR(200),   BankAccountType NVARCHAR(200),   BankAccountNumber  NVARCHAR(200),   Amount DECIMAL(18,2)  )    ----Employee  -- SELECT   -- FirstName +' '+ Surname,   -- PaymentTypeID,    --*  -- AccountTypeID,    --*  -- AccountHolderName,   --*  -- AccountHolderRelationshipID,  -- BankID,      --*  -- BranchID,     --*  -- AccountNumber,    --*   -- FixedSalary AS Amount  --*  --FROM Payroll_Employee    INSERT INTO @Temp  SELECT 1 AS IsSalary, pe.AccountHolderName AS Name, cpt.PaymentTypeDesc AS PaymentType, cb.BankDesc AS BankName,   bbc.BankBranchCode AS BankBranchCode, cat.BankAccountType AS BankAccountType, pe.AccountNumber AS BankAccountNumber,   SUM(TotalNetAmount) AS Amount  FROM Payroll_TransactionsCashbook as ptcb  LEFT OUTER JOIN Payroll_Employee AS pe ON pe.Employee_ID=ptcb.EmployeeId  LEFT OUTER JOIN Const_PaymentType AS cpt ON cpt.PaymentType_ID=pe.PaymentTypeID  LEFT OUTER JOIN Const_BankAccountType AS cat ON cat.BankAccountTypeID=pe.AccountTypeID  LEFT OUTER JOIN Const_Bank as cb ON cb.Bank_ID=pe.BankID  LEFT OUTER JOIN Const_BankBranchCode as bbc on bbc.BankBranchCode_ID=pe.BranchID  WHERE ptcb.PeriodID=@PeriodID  GROUP BY AccountHolderName, PaymentTypeDesc, BankAccountType, BankDesc,  BankBranchCode, AccountNumber        ----Creditors  --     SELECT   --  VendorName,  --  PaymentMethodID,  --  BankAccountTypeID,  --  BankID,    --  BankBranchCodeID,  --  BankAccountNumber,  --  'Amount' AS Amount  --  FROM Cons_Vendor    INSERT INTO @Temp  SELECT 0 AS IsSalary, cv.VendorName AS Name, cpt.PaymentTypeDesc AS PaymentType, cb.BankDesc AS BankName,   bbc.BankBranchCode AS BankBranchCode, cat.BankAccountType AS BankAccountType, cv.BankAccountNumber AS BankAccountNumber,  SUM(pid.EmployeeAmount+pid.EmployerAmount) AS Amount  FROM SCM_Invoice AS i  LEFT OUTER JOIN SCM_Payroll_InvoiceDetails AS pid ON pid.InvoiceID=i.Invoice_ID  LEFT OUTER JOIN Cons_Vendor AS cv ON cv.Vendor_ID=i.VendorCreditorID  LEFT OUTER JOIN Const_PaymentType AS cpt ON cpt.PaymentType_ID=cv.PaymentMethodID  LEFT OUTER JOIN Const_BankAccountType AS cat ON cat.BankAccountTypeID=cv.BankAccountTypeID  LEFT OUTER JOIN Const_Bank as cb ON cb.Bank_ID=cv.BankID  LEFT OUTER JOIN Const_BankBranchCode as bbc on bbc.BankBranchCode_ID=cv.BankBranchCodeID  WHERE i.PayrollPeriodID=@PeriodID  GROUP BY VendorName, PaymentTypeDesc, BankAccountType, VendorName, BankDesc,  BankBranchCode, BankAccountNumber          --SELECT     --EmailAddress AS Name,     --EmailAddress AS PaymentType,    --EmailAddress AS BankName,    --EmailAddress AS BankBranchCode,    --EmailAddress AS BankAccountType,    --EmailAddress AS BankAccountNumber,    --EmailAddress AS Amount    --FROM Payroll_Employee    SELECT * FROM @Temp           END  

GO

-- ============================================
-- SP: Payroll_FinalRun_ExportReconData_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  James Roodt  -- Create date: 2015-03-02  -- Description: Export Recon data from SCM module  -- Called by: Checklist.aspx.cs (on the Payroll Run Screen)  -- EXEC Payroll_FinalRun_ExportReconData_sp 234  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_FinalRun_ExportReconData_sp]    -- Add the parameters for the stored procedure here   @PeriodID int = 0    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        SELECT v.Vendor_ID, v.VendorName, emp.FirstName+' '+emp.Surname AS Name, sum(employeeAmount+EmployerAmount) AS Amount, ItemDescription, ReferenceNo   FROM SCM_Payroll_InvoiceDetails as pid    INNER JOIN SCM_Invoice AS i ON i.Invoice_ID=pid.InvoiceID    INNER JOIN Cons_Vendor AS v ON v.Vendor_ID=i.VendorCreditorID    INNER JOIN Payroll_Employee AS emp ON emp.Employee_ID=pid.EmployeeID   WHERE pid.PeriondID=@PeriodID   GROUP BY Vendor_ID, VendorName, emp.FirstName+' '+emp.Surname, ItemDescription, ReferenceNo   ORDER BY Vendor_ID  END  

GO

-- ============================================
-- SP: Payroll_FinalRunFailuresByCycles
-- Schema: dbo
-- ============================================
--=================================  -- Author: Lungisani Khumalo  -- Descriptions :gets all Payroll CycleDetails with failures and give summary details  -- TP46985  -- Created on 24/10/2016    --=================================    CREATE PROC [dbo].[Payroll_FinalRunFailuresByCycles]    @PeriodID int    AS  BEGIN    Declare @Results table(    Period_ID int, CycleID int  )     INSERT INTO @Results( Period_ID , CycleID) (SELECT distinct PeriodID , CycleID FROM Payroll_FinalRunFailures where PeriodID =@PeriodID)       SELECT cycledesc as Payroll, processingmonth as Month, EmployeeID , SOURCEOFFAILURE as Source           FROM Payroll_CyclePeriodDetails PCD    INNER JOIN @Results R ON PCD.Period_ID=R.Period_ID   INNER JOIN Const_Cycle CC ON R.CycleID = CC.Cycle_ID   INNER JOIN Payroll_FinalRunFailures PFF ON R.Period_ID =PFF.PeriodID     END  

GO

-- ============================================
-- SP: Payroll_FinalRunFailuresByGroup
-- Schema: dbo
-- ============================================
--=================================  -- Author: Lungisani Khumalo  -- Descriptions :gets all Payroll CycleDetails with failures and give summary details  -- TP43906  -- Created on 24/10/2016    --=================================    CREATE PROC [dbo].[Payroll_FinalRunFailuresByGroup]    AS  BEGIN    Declare @Results table(    Period_ID int, CycleID int  )     INSERT INTO @Results( Period_ID , CycleID) (SELECT distinct PeriodID , CycleID FROM Payroll_FinalRunFailures)       SELECT r.Period_ID, cycledesc as Payroll, processingmonth as Month,EmployeeID, sourceoffailure           FROM Payroll_CyclePeriodDetails PCD    INNER JOIN @Results R ON PCD.Period_ID=R.Period_ID   INNER JOIN Const_Cycle CC ON R.CycleID = CC.Cycle_ID   INNER JOIN Payroll_FinalRunFailures pff on PCD.Period_ID = pff.PeriodID    END  

GO

