-- ============================================
-- SP: Payroll_FutureLeaveForfeit
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-24  -- Description: Used as a dataset for Leave Forfeit report (HR_LeaveForfeit.rdl)  --              Returns future forfeit leave    -- =============================================    CREATE PROCEDURE [dbo].[Payroll_FutureLeaveForfeit]      @LeaveBalanceDate DATETIME      ,@LeaveForfeitWithin INT = 6      ,@EmployeeId INT      ,@LeaveTypeId INT      ,@DepartmentId INT      ,@DivisionId INT      ,@EmployeeTypeId INT      ,@EmployeeSubTypeId INT      ,@LeaveClassificationId INT = 0  AS  BEGIN    DECLARE @CycleStartFixedDate INT = 1  DECLARE @CycleStartJoiningDate INT = 2  DECLARE @CycleStartCalendarYear INT = 3    DECLARE @LeaveStatusApproved INT = 3    DECLARE @ForfeitFilterEndDate DATETIME = DATEADD(MONTH, @LeaveForfeitWithin, @LeaveBalanceDate);    SELECT      PE.Employee_ID AS EmployeeNumber      ,PE.FirstName AS EmployeeName      ,PE.Surname AS EmployeeSurname      ,Department.DepartmentDesc AS Department      ,Division.DivisionDesc AS Division      ,CLT.LeaveTypeDesc AS LeaveType      ,CLTD.ExtentionDays AS ExtentionDays      ,ForfeitDate.EndDate AS CycleEndDate      ,DATEADD(DAY, CLTD.ExtentionDays, ForfeitDate.EndDate) AS LeaveForfeitedDate      ,ForfeitDays.Value AS DaysForfeited  FROM Payroll_Employee AS PE  LEFT JOIN Payroll_Position AS PP ON PE.Employee_ID = PP.EmployeeID AND PE.Enabled = 1  LEFT JOIN Const_Department AS Department ON PP.DepartmentID = Department.Department_ID  LEFT JOIN Const_Division AS Division ON PP.DivisionID = Division.Division_ID  JOIN Const_LeaveScheme AS CLS ON PE.LeaveSchemeID = CLS.LeaveScheme_ID  JOIN Const_LeaveSchemeTypeDetails AS CLSTD ON CLSTD.LeaveSchemeId = CLS.LeaveScheme_ID  JOIN Const_AbsenceType AS CAT ON CAT.AbsenceType_ID = CLSTD.LeaveTypeId  JOIN Payroll_AbsencePriority AS PAP ON PAP.AbsenceTypeID = CAT.AbsenceType_ID  JOIN Const_LeaveTypeDetails AS CLTD ON CLTD.LeaveTypeId = PAP.LeaveTypeID  JOIN Const_LeaveType AS CLT on CLT.LeaveType_ID = CLTD.LeaveTypeId    CROSS APPLY (SELECT       TOP 1 DT.StartDate      ,DT.EndDate       FROM GenerateDateRanges(       CASE CLT.CyclePeriodIDStart          WHEN @CycleStartJoiningDate THEN PE.JoiningDate          WHEN @CycleStartFixedDate THEN CLT.CycleStartDate          WHEN @CycleStartCalendarYear THEN DATEFROMPARTS(YEAR(CLT.StartDate), 1, 1)      END      ,@ForfeitFilterEndDate, CLT.CycleEnd, 'MONTH') AS DT          WHERE @LeaveBalanceDate BETWEEN DT.StartDate AND DT.EndDate          ORDER BY DT.StartDate ASC          ) AS ForfeitDate    CROSS APPLY (SELECT SUM(PELT.Value) AS Value       FROM Payroll_EmployeeLeaveTransactions AS PELT      WHERE PELT.EmployeeID = PE.Employee_ID           AND PELT.LeaveTypeID = CLT.LeaveType_ID           AND PELT.LeaveStatusID = @LeaveStatusApproved      GROUP BY PELT.LeaveTypeID      HAVING SUM(PELT.Value) > 0  ) AS ForfeitDays         WHERE (PE.Employee_ID = @EmployeeId OR ISNULL(@EmployeeId, 0) = 0)      AND CLTD.Forfeit = 1       AND CLTD.Enabled = 1      AND CLSTD.Enabled = 1      AND @LeaveBalanceDate BETWEEN CLTD.StartDate AND CLTD.EndDate      AND ForfeitDate.EndDate IS NOT NULL      AND ForfeitDays.Value IS NOT NULL      AND (Department.Department_ID = @DepartmentId OR ISNULL(@DepartmentId, 0) = 0)      AND (Division.Division_ID = @DivisionId OR ISNULL(@DivisionId, 0) = 0)      AND (PE.EmployeeTypeID = @EmployeeTypeId OR ISNULL(@EmployeeTypeId, 0) = 0)      AND (PE.EmployeeSubtypeID = @EmployeeSubTypeId OR ISNULL(@EmployeeSubTypeId, 0) = 0)      AND (CLT.LeaveType_ID = @LeaveTypeId OR ISNULL(@LeaveTypeId, 0) = 0)      AND (CLT.LeaveClassificationID = @LeaveClassificationId OR @LeaveClassificationId = 0)  ORDER BY      PE.Employee_ID    END

GO

