-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_Generate_EFTS_BankFormatWise_Sp]    @PeriodID INT,   @CashbookID INT,   @BankFormatType INT  AS  BEGIN   BEGIN TRY     IF (@BankFormatType = 1)   BEGIN    EXEC Payroll_Generate_EFTS_CycleWise_STDBank_Best2000_Sp @PeriodID, @CashbookID   END     END TRY      BEGIN CATCH      DECLARE @ErrorMessage NVARCHAR(MAX), @ErrorSeverity INT, @ErrorState INT;      SELECT      @ErrorMessage = ERROR_MESSAGE(),     @ErrorSeverity = ERROR_SEVERITY(),     @ErrorState = ERROR_STATE();        RAISERROR (@ErrorMessage, -- Message text.       @ErrorSeverity, -- Severity.       @ErrorState -- State.      );                --ROLLBACK TRAN - Should only be in parent procedure      END CATCH  END  

GO

-- ============================================
-- SP: Payroll_Generate_EFTS_CycleWise_STDBank_Best2000_Sp
-- Schema: dbo
-- ============================================
      CREATE PROCEDURE [dbo].[Payroll_Generate_EFTS_CycleWise_STDBank_Best2000_Sp]    @PeriodID INT,   @CashbookID INT  AS  BEGIN   BEGIN TRY   --BEGIN TRAN         DELETE FROM Payroll_EFTFileData    DBCC CHECKIDENT ('Payroll_EFTFileData', RESEED, 0)      Declare @DocRootFolderPath nvarchar(200) , @DBName varchar(100)    ,@FolderEFT nvarchar(200)        --@CashbookID INT = 7032      select @DocRootFolderPath = KeyValue from AAAA_ConfigSettings where KeyName  = 'DocRootFolderPath'    select @FolderEFT = KeyValue from AAAA_ConfigSettings where KeyName  = 'FolderEFT'    SELECT @DBName = DB_NAME()       --***RECORD HEADER***    INSERT INTO Payroll_EFTFileData    SELECT       CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'HeaderErrorFlag') as CHAR(1)) --ERROR FLAG    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'CompanyCode') as CHAR(4)) --COMPANY CODE 4??    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'CompanyName') as CHAR(40)) --COMPANY NAME 40 ??    + CONVERT(VARCHAR(8), (select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'ActionDate'), 112)--ACTION DATE (CCYYMMDD) 8    + (select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'Language') --LANGUAGE 1    + CAST(' ' as CHAR(8)) --FILLER SPACES(8)    + CAST(LEFT('               ', 15 - LEN((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'HeaderStatementReference')))      + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'HeaderStatementReference') AS VARCHAR) as CHAR(15)) -- STATEMENT REFERENCE 15    + (select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'Sign') --SIGN 1??    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'EntryClass') as CHAR(2)) -- ENTRY CLASS 2 ??    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TaxCode') as CHAR(1)) -- TAX CODE 1 ??    + CAST(' ' as CHAR(9)) -- FILLER SPACES 9    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'BatchNumber') as CHAR(2)) -- BATCH NUMBER 2 ??    + (select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'SystemType') -- TEST OR LIVE 4??        -- Scripts '*605PSenqu Municipality                      20151125Y                  SENQU+610         01Live'    -- v5.6    '*605PSENQU                                   20151022Y                  SENQU+610         01Live'      --****TRANSACTION RECORD***    INSERT INTO Payroll_EFTFileData    SELECT       CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TransactionMethodOfPayment') as CHAR(1)) -- METHOD OF PAYMENT 1    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'CompanyCode') as CHAR(4)) -- COMPANY CODE 4 ??    + CAST(LEFT('000000', 6 - LEN(ISNULL(PE.BranchID, 0))) + CAST(ISNULL(PE.BranchID, 0) AS VARCHAR) as CHAR(6)) -- BRANCH NUMBER – CREDITOR/ DEBTOR/ SALARY ACCOUNT 6 ??    + CAST(LEFT('0000000', 7 - LEN(ISNULL(PE.Employee_ID, 0))) + CAST(ISNULL(PE.Employee_ID, 0) AS VARCHAR) as CHAR(7)) -- EMPLOYEE NUMBER (THIS FIELD IS NOT MANDATORY) 7    + CAST(LEFT('0000000000000000000', 19 - LEN(ISNULL(PE.AccountNumber, 0))) + CAST(ISNULL(PE.AccountNumber, 0) AS VARCHAR) as CHAR(19)) -- ACCOUNT NUMBER – CREDITOR/ DEBTOR/ SALARY ACCOUNT 19    + CAST(' ' as CHAR(1)) --FILLER SPACES(1)    + CAST(ISNULL(PE.AccountTypeID, 0) as CHAR(1)) -- ACCOUNT TYPE 1 ??    + CAST(LEFT('00000000000', 11 - LEN(ISNULL(LCV.VoteAmount, 0))) + CAST(ISNULL(LCV.VoteAmount, 0) AS VARCHAR) as CHAR(11)) -- AMOUNT (11)     + CAST(ISNULL(PE.AccountHolderName, '') as CHAR(20)) -- ACCOUNT NAME – CREDITOR/ DEBTOR/ SALARY ACCOUNT 20    + CAST(' ' as CHAR(10)) -- FILLER 10    + CAST(LEFT('               ', 15 - LEN((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'HeaderStatementReference')))      + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'HeaderStatementReference') AS VARCHAR) as CHAR(15)) -- STATEMENT REFERENCE 15    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TransactionRTGSIndicator') as CHAR(1)) -- RTGS INDICATOR APPLICABLE FOR CREDITS ONLY.1    FROM Led_CashbookVote LCV       INNER JOIN Payroll_Employee PE ON LCV.EmployeeId = PE.Employee_ID     --INNER JOIN Const_Cycle CC ON PE.CycleID = CC.Cycle_ID     WHERE LCV.CashbookTransactionID = @CashbookID and PE.Enabled = 1      -- Scripts '2605P01000100000110000000010007677969 200001002918AccountName                             SENQU '    -- v5.6    '2605P01000100000110000000010007677969 200001002918PITSO NA                                SENQU '        --***TRAILER RECORD***    INSERT INTO Payroll_EFTFileData    SELECT       CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TrailerErrorFlag') as CHAR(1)) -- ERROR FLAG 1    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'CompanyCode') as CHAR(4)) -- COMPANY CODE 4 ??    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TrailerIndicator') as CHAR(1)) -- TRAILER INDICATOR 1 ??    + CAST(' ' as CHAR(30)) -- FILLER 30    + CAST(LEFT('0000000000000', 13 - LEN(sum(VoteAmount))) + CAST((sum(VoteAmount)) AS VARCHAR) as CHAR(13)) -- AMOUNT (13) ??    + CAST(' ' as CHAR(14)) -- FILLER 14    + CAST((select KeyValue from AAAA_ConfigSettings_EFTSFile where CompanyName = 'SENQU' AND KeyName = 'TrailerNumberOfTransaction') as CHAR(7)) -- NUMBER OF TRANSACTIONS 7    + CAST(' ' as CHAR(26)) -- FILLER 26     FROM Led_CashbookVote LCV       INNER JOIN Payroll_Employee PE ON LCV.EmployeeId = PE.Employee_ID     --INNER JOIN Const_Cycle CC ON PE.CycleID = CC.Cycle_ID     WHERE LCV.CashbookTransactionID = @CashbookID and PE.Enabled = 1     group by LCV.CashbookTransactionID      -- Scripts '2605PT                              0000000012345                        SENQU+'    -- v5.6    '2605PT                              0000372096687                                               '      --SELECT Data FROM [FMS_Senqu_Live].[dbo].[EFTFileData]      --EXEC xp_cmdshell 'bcp "SELECT Data FROM [FMS_Senqu_Live].[dbo].[EFTFileData]" queryout "C:\Data\2015 2016\EFTFiles\EFT_TEST.txt" -T -c -t,'          DECLARE @FilePath varchar(100), @bcpCommand varchar(2000), @FileName varchar(100)      SET @FileName = 'EFT_' + CAST(@PeriodID AS VARCHAR) + '_' + REPLACE(CONVERT(CHAR(19), GETDATE(), 120), ':', '') + '.txt'    --YYYY-MM-DD HHMMSS    --SET @FilePath = REPLACE(@DocRootFolderPath + @FolderEFT + @FileName,'/','-')     --SET @bcpCommand = 'bcp "SELECT Data FROM "' + @DBName + '".dbo.Payroll_EFTFileData" queryout "'     ----SET @bcpCommand = @bcpCommand + @FilePath + '" -U sa -P Imsql321 -c'     --SET @bcpCommand = @bcpCommand + @FilePath + '" -T -c -t'     ----EXEC master..xp_cmdshell @bcpCommand    --EXEC xp_cmdshell @bcpCommand         UPDATE Payroll_CyclePeriodDetails    SET PayrollEFTFileName = @FileName    WHERE Period_ID = @PeriodID      --TODO - Bank format type check    --TODO - Transaction(NR: Already in Final Run sp) and Error Handling   --COMMIT TRAN   END TRY      BEGIN CATCH      DECLARE @ErrorMessage NVARCHAR(MAX), @ErrorSeverity INT, @ErrorState INT;      SELECT      @ErrorMessage = ERROR_MESSAGE(),     @ErrorSeverity = ERROR_SEVERITY(),     @ErrorState = ERROR_STATE();      INSERT  INTO Sys_ErrorLog ( moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName )          VALUES  ( 'Payroll', 'SQL Server', 'Payroll_Generate_EFTS_CycleWise_STDBank_Best2000_Sp', @ErrorMessage, 'SQL', @ErrorMessage, GETDATE(), 'PayrollFinalRunUser' )      RAISERROR (@ErrorMessage, -- Message text.       @ErrorSeverity, -- Severity.       @ErrorState -- State.      );                --ROLLBACK TRAN - Should only be in parent procedure      END CATCH  END  

GO

-- ============================================
-- SP: Payroll_GenerateIrpCsv_sp
-- Schema: dbo
-- ============================================
  /*  =============================================      Author: Richa Mills  Create date:  2018/07/13  Description: Generate CSV file for IRP5s  [Payroll_GenerateIrp5Csv_sp] 'August', '2017/2018',0,0,0,'TEST'  =============================================      */   CREATE PROCEDURE [dbo].[Payroll_GenerateIrpCsv_sp]      @PeriodType NVARCHAR(100) ,      @FinancialYear NVARCHAR(100) ,      @CycleId INT ,      @IsTerminated BIT = 0 ,      @EmployeeID INT = 0,   @SubmissionType varchar(4)  AS      BEGIN     SET NOCOUNT ON  --TODO     --If Income Codes are more than 20 they must be combined  --If Deduction Codes are more than 12 they must be combined    DECLARE @PeriodTable TABLE ( PeriodID INT );  DECLARE @CycleTypeID int   DECLARE @FromPeriod int, @ToPeriod int    DECLARE cycle_cursor CURSOR FOR SELECT Distinct CycleId from Payroll_PayrollResults where ( CycleID = @CycleId OR @CycleId = 0 )      OPEN cycle_Cursor        FETCH NEXT FROM cycle_Cursor INTO @CycleId        WHILE @@FETCH_STATUS = 0      BEGIN         Select @CycleTypeId = CycleTypeID from Const_Cycle where Cycle_Id = @CycleId         IF @CycleTypeID = 1     BEGIN      If @PeriodType = 'August'       Select @FromPeriod = 1, @ToPeriod = 6      else       Select @FromPeriod = 1, @ToPeriod = 12       END       IF @CycleTypeId = 2     BEGIN      If @PeriodType = 'August'       Select @FromPeriod = 1, @ToPeriod = 26      else       Select @FromPeriod = 1, @ToPeriod = 52            END       IF @CycleTypeId = 3     BEGIN      If @PeriodType = 'August'       Select @FromPeriod = 1, @ToPeriod = 13      else       Select @FromPeriod = 1, @ToPeriod = 26     END       Insert into @PeriodTable      select Period_ID from Payroll_CyclePeriodDetails cd where cd.PeriodInTaxYear >= @FromPeriod and cd.PeriodInTaxYear <= @ToPeriod and CycleId = @CycleID    FETCH NEXT FROM cycle_Cursor     INTO @CycleId    END     CLOSE cycle_Cursor  DEALLOCATE cycle_Cursor      DECLARE @FromDate DATETIME , @ToDate DATETIME ,@TYear NVARCHAR(50) , @Month NVARCHAR(2) , @SumOfCode BIGINT = 0;             SELECT TOP 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WITH ( NOLOCK ) WHERE   ( CycleID = @CycleId OR @CycleId = 0 ) AND FinancialYear = @FinancialYear ORDER BY Period_ID;             IF @PeriodType = 'February'              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));                  SET @Month = '02';              END;          ELSE              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));                  SET @Month = '08';              END;            IF OBJECT_ID('tempdb..#TEMPDATA') IS NOT NULL              DROP TABLE #TEMPDATA;            IF OBJECT_ID('tempdb..#IncomeIds') IS NOT NULL              DROP TABLE #IncomeIds;            IF OBJECT_ID('tempdb..#DeductionIds') IS NOT NULL              DROP TABLE #DeductionIds;        --Add all the relevant PeriodId's to a table    insert into @PeriodTable     Select Period_Id from Payroll_CyclePeriodDetails where Period_ID in (301,302,303,304,305,306)      --Select all the employees grouped by Irp5Code into a temp tabe    SELECT  EmployeeId,Irp5Code,SUM(Amount)Amount into #TEMPDATA from Payroll_PayrollResults where PeriodId in (Select * from @PeriodTable)    GROUP BY EmployeeId,Irp5Code    order by EmployeeId    Select EmployeeId into #IncomeIds from (  select distinct EmployeeId, IRP5Code, Amount, count(IRP5Code) over (partition by EmployeeId ) Noofcount       from #tempdata A where (        IRP5Code BETWEEN '3601' and '3617' or         IRP5Code BETWEEN '3619' and '3621' or         IRP5Code BETWEEN '3651' and '3667' or         IRP5Code BETWEEN '3701' and '3723' or         IRP5Code BETWEEN '3751' and '3773' or         IRP5Code BETWEEN '3801' and '3810' or         IRP5Code BETWEEN '3820' and '3822' or        IRP5Code BETWEEN '3828' and '3832' or        IRP5Code BETWEEN '3851' and '3860' or        IRP5Code BETWEEN '3870' and '3872' or        IRP5Code BETWEEN '3878' and '3882' or        IRP5Code BETWEEN '3901' and '3909' or        IRP5Code BETWEEN '3920' and '3924' or        IRP5Code BETWEEN '3951' and '3957' or   IRP5Code in ('3669','3670','3813','3815','3816','3817','3825','3863','3865','3866','3867','3875','3915'))) AS Summary  Where Summary.Noofcount > 20    Select EmployeeId into #DeductionIds from (  select distinct EmployeeId, IRP5Code, Amount, count(IRP5Code) over (partition by EmployeeId ) Noofcount       from #tempdata A where (        IRP5Code BETWEEN '4005' and '4007' or         IRP5Code BETWEEN '4472' and '4475' or           IRP5Code in ('4001','4003','4018','4024','4030','4493','4582','4583'))) AS Summary  Where Summary.Noofcount > 12      DECLARE @Result TABLE(Id INT IDENTITY(1, 1),Code BIGINT,TotalValue Decimal(36,2),Result NVARCHAR(MAX))    --** Header Record start **  Insert Into @Result (Result)  SELECT     '2010'+',"'+CONVERT(NVARCHAR(90), ISNULL(REPLACE(MunicipalityName,',','&&&'),''))+'",'    +'2015,"'+ @SubmissionType +''+'",'    +'2020'+',"'+CONVERT(NVARCHAR(MAX), ISNULL(PayeRegistrationNo,''))+'",'    + CASE WHEN ISNULL(SDLReferenceNo,'') <> '' THEN +'2022'+',"'+ SDLReferenceNo +'",' ELSE '' +'' END    + CASE WHEN ISNULL(UIFReferenceNo,'') <> '' THEN +'2024'+',"'+ UIFReferenceNo +'",' ELSE '' +'' END    +'2025'+',"'+ISNULL(REPLACE(SARSPersonName,',','&&&'), '')+'",'    +'2026'+',"'+ISNULL(replace(REPLACE(SARSContactNo,',','&&&'),' ',''), '')+'",'    + CASE WHEN CONVERT(NVARCHAR(MAX), ISNULL(M.SARSEmailAddress,'')) <> '' THEN '2027'+',"'+CONVERT(NVARCHAR(MAX), ISNULL(REPLACE(SARSEmailAddress,',','&&&'),''))+'",' END     +'2028'+','+'"EMS6"'+','    +'2030'+',"'+CAST(YEAR(@toDate) AS NVARCHAR(4)) +'",'    +'2031'+',"'+CAST(YEAR(@toDate) AS NVARCHAR(4)) + @Month +'",'     +'2082'+',"'+ ISNULL(CONVERT(VARCHAR,(SELECT top 1 SubclassID FROM CONST_SICCodeSubClass CSCS WHERE CSCS.Enabled=1 and CSCS.SubclassID= SICCodeId)),'') + '",'    + CASE WHEN ISNULL(CONVERT(VARCHAR,(SELECT top 1 SezCode FROM Const_SEZCode CSC WHERE CSC.SEZCodeId= SEZCodeId)),'') <> '' THEN +'2083'+',"'+ ISNULL(CONVERT(VARCHAR,(SELECT top 1 SezCode FROM Const_SEZCode CSC WHERE CSC.SEZCodeId= SEZCodeId)),'') +'",' ELSE '' +'' END    +'2035'+',"'+(SELECT KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'EmployerTradeClassification')+'",'    + CASE WHEN ISNULL( CONVERT( VARCHAR, PhyUnitNumber),'') <> '' THEN +'2061'+',"'+  CONVERT( VARCHAR, REPLACE(PhyUnitNumber,',','&&&')) +'",' ELSE '' +'' END    + CASE WHEN ISNULL( CONVERT( VARCHAR, PhyComplex),'') <> '' THEN +'2062'+',"'+  CONVERT( VARCHAR, REPLACE(PhyComplex,',','&&&')) +'",' ELSE '' +'' END    + CASE WHEN ISNULL( CONVERT( VARCHAR, PhyStreetNumber),'') <> '' THEN +'2063'+',"'+  CONVERT( VARCHAR, REPLACE(PhyStreetNumber,',','&&&')) +'",' ELSE '' +'' END    +'2064'+',"'+ + ISNULL((SELECT REPLACE(StreetName,',','&&&') FROM Const_Street WHERE ISNULL(PhyStreetID,0)= Street_ID), '')+'",'    + CASE WHEN ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PhySuburb), '') <> '' THEN +'2065'+',"'+ ISNULL((SELECT REPLACE(SubUrbName,',','&&&') FROM Const_Suburb WHERE Suburb_ID=PhySuburb), '') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(T.Town,'') <> '' THEN +'2066'+',"'+ REPLACE(T.Town,',','&&&') +'",' ELSE '' +'' END    +'2080'+',"'+CONVERT(NVARCHAR(MAX), dbo.AppendString_fxn(ISNULL(PhyPostalCode,''), 4, '0'))+'",'    +'2081'+',"ZA"'+''+','    +'9999,' FROM Payroll_Municipality AS M    LEFT OUTER JOIN dbo.Const_Town AS T ON M.PhyCityID = T.Town_ID    LEFT OUTER JOIN dbo.Const_Province AS P ON M.PhyProvinceID = P.Province_ID  --** Header Record end**     --** Employee Record start**   Insert Into @Result (Result)  SELECT       '3010'+',"'+ISNULL(M.PayeRegistrationNo + @TYear + @Month, '') + dbo.PaddingString_fxn(CONVERT(NVARCHAR(50),EMP.Employee_ID), 14, 0, 'L') +'",'     + '3015'+',"'+ CASE WHEN (SELECT ISNULL(SUM(Amount),0) FROM #TEMPDATA TMD WHERE TMD.IRP5Code in ('4102','4115') AND TMD.EmployeeID=Emp.Employee_Id) > 0     and (SELECT ISNULL(SUM(Amount),0) FROM #TEMPDATA TMD WHERE TMD.IRP5Code =4150 AND TMD.EmployeeID=Emp.Employee_Id)<=0 THEN 'IRP5'     WHEN (SELECT ISNULL(SUM(Amount),0) FROM #TEMPDATA TMD WHERE TMD.IRP5Code in ('4102','4115') AND TMD.EmployeeID=Emp.Employee_Id) <= 0     and (SELECT ISNULL(SUM(Amount),0) FROM #TEMPDATA TMD WHERE TMD.IRP5Code =4150 AND TMD.EmployeeID=Emp.Employee_Id)>0 THEN 'IT3(a)' ELSE '' end +'",'    + '3020'+',"'+(CASE WHEN ISNULL(EMP.NatureOfPersonID,'') <> '' THEN NOP.NatureOfPersonCode END) +'",'    + '3025'+',"'+CAST(YEAR(@toDate) AS NVARCHAR(4))+'",'    --TODO    + '3026,'    + '3030'+',"'+(CASE WHEN ISNULL(EMP.Surname,'') <> '' THEN REPLACE(Emp.Surname,',','&&&') ELSE '' END)+'",'    + CASE WHEN ISNULL(EMP.FirstName,'') <> '' THEN +'3040'+',"'+ REPLACE(RTRIM(EMP.FirstName + ' '+ ISNULL(EMP.SecondName,'')),',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.Initials,'') <> '' THEN +'3050'+',"'+ REPLACE(EMP.Initials,',','&&&') +'",' ELSE '' +'' END       + CASE WHEN ISNULL(EMP.IdNo,'') <> '' THEN +'3060'+',"'+ EMP.IdNo +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.PassportNumber,'') <> '' THEN +'3070'+',"'+ REPLACE(EMP.PassportNumber,',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL((SELECT TOP 1 CountryCode FROM dbo.Const_Country cid where cid.Country_ID= EMP.PassportCountryID),'') <> '' THEN +'3075'+',"'+ (SELECT TOP 1 CountryCode FROM dbo.Const_Country cid where cid.Country_ID= EMP.PassportCountryID) +'",' ELSE '' +'' END       + CASE WHEN AlternateIDType IS NOT NULL THEN +'3065'+',"'+  CASE WHEN EMP.AlternateIDNumber= 1 THEN +'Y' ELSE 'X' END ELSE '' +'' END       + CASE WHEN ISNULL(EMP.AlternateIDNumber,'') <> '' THEN +'3066'+',"'+ EMP.AlternateIDNumber +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.EmailAddress,'') <> '' THEN +'3125'+',"'+ REPLACE(EMP.EmailAddress,',','&&&') +'",' ELSE '' +'' END          + CASE WHEN ISNULL(EMP.HomeNumber,'') <> '' THEN +'3135'+',"'+ REPLACE(EMP.HomeNumber,',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.WorkNumber,'') <> '' THEN +'3136'+',"'+ REPLACE(EMP.WorkNumber,',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.FaxNumber,'') <> '' THEN +'3137'+',"'+ REPLACE(EMP.FaxNumber,',','&&&')+'",' ELSE '' +'' END             + CASE WHEN ISNULL(EMP.CellNumber,'') <> '' THEN +'3138'+',"'+ REPLACE(EMP.CellNumber,',','&&&')+'",' ELSE '' +'' END    + CASE WHEN ISNULL(CONVERT(NVARCHAR(50),Emp.DateOfBirth),'') <> '' THEN +'3080'+',"'+ FORMAT(Emp.DateOfBirth,'yyyyMMdd','en-us') +'",' ELSE '' +'' END    + '3100'+',"'+(CASE WHEN ISNULL(EMP.IncomeTaxNumber,'') <> '' THEN Emp.IncomeTaxNumber ELSE '' END)+'",'    + CASE WHEN ISNULL(CONVERT(VARCHAR,(SELECT top 1  SubclassID FROM CONST_SICCodeSubClass CSCS, Payroll_Municipality PM WHERE CSCS.Enabled=1 and CSCS.SubclassID= PM.SICCodeId)),'') <> '' THEN +'3263'+',"'+ ISNULL(CONVERT(VARCHAR,(SELECT top 1 REPLACE(SubclassID,',','&&&') FROM CONST_SICCodeSubClass CSCS, Payroll_Municipality PM WHERE CSCS.Enabled=1 and CSCS.SubclassID= PM.SICCodeId)),'') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(CONVERT(VARCHAR,(SELECT top 1 SezCode FROM Const_SEZCode CSC, Payroll_Municipality PM WHERE CSC.SEZCodeId= PM.SEZCodeId)),'') <> '' THEN +'3264'+',"'+ ISNULL(CONVERT(VARCHAR,(SELECT top 1 REPLACE(SezCode,',','&&&') FROM Const_SEZCode CSC, Payroll_Municipality PM WHERE CSC.SEZCodeId= PM.SEZCodeId)),'') +'",' ELSE '' +'' END           + CASE WHEN ISNULL(EMP.PhyWorkUnit,'') <> '' THEN +'3144'+',"'+ CONVERT(VARCHAR,REPLACE(EMP.PhyWorkUnit,',','&&&')) +'",' ELSE '' +'' End    + CASE WHEN ISNULL(EMP.PhyWorkComplex,'') <> '' THEN +'3145'+',"'+ REPLACE(EMP.PhyWorkComplex,',','&&&') +'",' ELSE '' +'' End    + CASE WHEN ISNULL(EMP.PhyWorkStreetNo,'') <> '' THEN +'3146'+',"'+ CONVERT(VARCHAR,REPLACE(EMP.PhyWorkStreetNo,',','&&&')) +'",' ELSE '' +'' END    + CASE WHEN ISNULL((SELECT StreetName FROM Const_Street WHERE ISNULL(EMP.PhyWorkStreetId,0)= Street_ID),'') <> '' THEN +'3147'+',"'+ (SELECT REPLACE(StreetName,',','&&&') FROM Const_Street WHERE ISNULL(EMP.PhyWorkStreetId,0)= Street_ID) +'",' ELSE '' +'' END    + CASE WHEN ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=EMP.WorkSuburbID), '') <> '' THEN +'3148'+',"'+ (SELECT REPLACE(SubUrbName,',','&&&') FROM Const_Suburb WHERE Suburb_ID=EMP.WorkSuburbID) +'",' ELSE '' +'' END    + CASE WHEN ISNULL(WA_T.Town,'') <> '' THEN +'3149'+',"'+ REPLACE(WA_T.Town,',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.WorkPostalCode,'') <> '' THEN +'3150'+',"'+ CONVERT(NVARCHAR(20), dbo.AppendString_fxn(ISNULL(EMP.WorkPostalCode,''), 4, '0')) +'",' ELSE '' +'' END    +'3151'+','+'"ZA"'+','        + CASE WHEN ISNULL(EMP.Employee_ID,'') <> '' THEN +'3160'+',"'+ CONVERT(VARCHAR,EMP.Employee_ID) +'",' ELSE '' +'' END    +'3170'+',"'+(CASE WHEN ISNULL(CONVERT(NVARCHAR(50),Emp.joiningdate),'') <> '' then FORMAT(Emp.joiningdate,'yyyyMMdd','en-us') ELSE '' END)+'",'    +'3180'+',"'+(CASE WHEN ISNULL(CONVERT(NVARCHAR(50),Emp.Enddate),'') <> '' then FORMAT(Emp.Enddate,'yyyyMMdd','en-us') ELSE '' END)+'",'    --TODO    +'3190'+',"'    +'3200'+','+CONVERT(NVARCHAR(50), (SELECT CAST(COUNT(1) AS DECIMAL(18, 4)) FROM dbo.Payroll_CyclePeriodDetails WHERE CycleModeID=1 AND CycleID = EMP.CycleID AND FinancialYear = @FinancialYear))+','    +'3210'+','+CONVERT(NVARCHAR(50),(SELECT CAST(COUNT(1) AS DECIMAL(18, 4)) FROM Payroll_CyclePeriodDetails AS cpd WHERE FinancialYear=@FinancialYear AND CycleModeID=1    AND Cycleid =Emp.CycleID AND Processed=1 AND cpd.PeriodStartDate>Emp.joiningdate AND cpd.PeriodEndDate<Emp.EndDate))+','        + CASE WHEN ISNULL(EMP.PhysicalFlatUnitSuiteNo,'') <> '' THEN +'3211'+',"'+ REPLACE(EMP.PhysicalFlatUnitSuiteNo,',','&&&')+'",' ELSE '' +'' End    + CASE WHEN ISNULL(EMP.PhysicalComplexName,'') <> '' THEN +'3212'+',"'+ REPLACE(EMP.PhysicalComplexName,',','&&&')+'",' ELSE '' +'' End    + CASE WHEN ISNULL(EMP.PhysicalStreetNo,'') <> '' THEN +'3213'+',"'+ CONVERT(VARCHAR,REPLACE(EMP.PhysicalStreetNo,',','&&&')) +'",' ELSE '' +'' End    +'3214'+',' + CASE WHEN ISNULL((SELECT StreetName FROM Const_Street WHERE ISNULL(EMP.PhysicalStreetID,0)= Street_ID), '') <> '' THEN (SELECT REPLACE(StreetName,',','&&&') FROM Const_Street WHERE ISNULL(EMP.PhysicalStreetID,0)= Street_ID) + '",' ELSE ISNULL(((SELECT TOP 1 REPLACE(CSF.FarmName,',','&&&') FROM dbo.Const_Farm CSF WHERE CSF.Enabled =1 AND CSF.Farm_ID = EMP.farmID)),'') + '",' END    + CASE WHEN ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PhysicalSuburbID), '') <> '' THEN +'3215'+',"'+ (SELECT REPLACE(SubUrbName,',','&&&') FROM Const_Suburb WHERE Suburb_ID=PhysicalSuburbID) +'",' ELSE '' +'' END    + CASE WHEN ISNULL(PhyA_T.Town,'') <> '' THEN +'3216'+',"'+ REPLACE(PhyA_T.Town,',','&&&') +'",' ELSE '' +'' END    + CASE WHEN ISNULL(EMP.PhysicalPostalCode,'') <> '' THEN +'3217'+',"'+  CONVERT(NVARCHAR(20), dbo.AppendString_fxn(ISNULL(EMP.PhysicalPostalCode,''), 4, '0')) +'",' ELSE '' +'' END    --TODO - check if hardcoding is ok    +'3285'+','+'"ZA"'+','      --TODO - check 3279 and 3283    +'3279'+','+'"N"'+','    + CASE WHEN ISNULL(EMP.CareOfIntermediary,'') <> '' THEN +'3283'+',"'+REPLACE(EMP.CareOfIntermediary,',','&&&') +'",' ELSE '' END    +'3288'+',"'+CONVERT(NVARCHAR(50),dbo.Payroll_PostalAddressStructureIndicator_fxn(ISNULL(Emp.Employee_ID,'')))+'",'        -- for field 3288 is 2    + CASE WHEN  CONVERT(NVARCHAR(50),dbo.Payroll_PostalAddressStructureIndicator_fxn(ISNULL(Emp.Employee_ID,''))) = 2 THEN     + CASE WHEN ISNULL((SELECT AddressType FROM dbo.Const_PostalAddressType_sys CPA WHERE CPA.AddressType_ID = PostalAddressIndId), '') <> '' THEN +'3249'+',"'+ (SELECT REPLACE(AddressType,',','&&&') FROM dbo.Const_PostalAddressType_sys CPA WHERE CPA.AddressType_ID =PostalAddressIndId) +'",' ELSE '' +'' END        + CASE WHEN ISNULL(EMP.PoSpecialService,'') <> '' THEN +'3280'+',"'+ REPLACE(EMP.PoSpecialService,',','&&&') +'",' ELSE '' +'' END        +  CASE WHEN ISNULL(EMP.PostalAddressNo,'') <> '' THEN +'3262'+',"'+ REPLACE(EMP.PostalAddressNo,',','&&&') +'",' ELSE '' +'' END     +  CASE WHEN ISNULL(EMP.PostalFlatUnitSuiteNo,'') <> '' THEN +'3251'+',"'+ REPLACE(EMP.PostalFlatUnitSuiteNo,',','&&&') +'",' ELSE '' +'' END     + '3253'+',"' + ISNULL(EMP.PostalPostOffice,'')  +'",'     + CASE WHEN ISNULL(EMP.PhysicalPostalCode,'') <> '' THEN +'3254'+',"'+ CONVERT(NVARCHAR(MAX), dbo.AppendString_fxn(ISNULL(EMP.PhysicalPostalCode,''), 4, '0')) +'",' ELSE '' +'' END       +  '3286'+',"' + ISNULL(P_PPC.CountryCode,'')  +'",' ELSE '' END      -- for field 3288 is 3    + CASE WHEN  CONVERT(NVARCHAR(50),dbo.Payroll_PostalAddressStructureIndicator_fxn(ISNULL(Emp.Employee_ID,''))) = 3 THEN     CASE WHEN ISNULL(EMP.PostalAddressUnitNumber,'') <> '' THEN +'3255'+',"'+ REPLACE(EMP.PostalAddressUnitNumber,',','&&&') +'",' ELSE '' +'' END       + CASE WHEN ISNULL(EMP.PostalComplexName,'') <> '' THEN +'3256'+',"'+ REPLACE(EMP.PostalComplexName,',','&&&') +'",' ELSE '' +'' END      + CASE WHEN ISNULL(EMP.PostalStreetName,'') <> '' THEN +'3257'+',"'+ REPLACE(EMP.PostalStreetName,',','&&&') +'",' ELSE '' +'' END     + '3258'+',"'+ ISNULL(REPLACE(W_PS.StreetName,',','&&&'),'') +'",'     + CASE WHEN ISNULL(EMP.PostalSuburbID,'') <> '' THEN +'3259'+',"'+ ISNULL(REPLACE(P_Suburb.SuburbName,',','&&&'),'') +'",' ELSE '' +'' END     + CASE WHEN ISNULL(EMP.PostalTownID,'') <> '' THEN +'3260'+',"'+ ISNULL(REPLACE(WA_T.Town,',','&&&'),'') +'",' ELSE '' +'' END     + CASE WHEN ISNULL(EMP.PostalPostalCode,'') <> '' THEN +'3261'+',"'+ CONVERT(NVARCHAR(20), dbo.AppendString_fxn(ISNULL(EMP.PostalPostalCode,''), 4, '0')) +'",' ELSE '' +'' END     + '3287'+',"'+ ISNULL(P_PPC.CountryCode,'') +'",' ELSE '' END          -- for field 3288 is 4    +  CASE WHEN  CONVERT(NVARCHAR(50),dbo.Payroll_PostalAddressStructureIndicator_fxn(ISNULL(Emp.Employee_ID,''))) = 4 THEN     '3289'+',"'+ ISNULL( REPLACE(EMP.PostalAddress1,',','&&&'),'') +'",'     + CASE WHEN ISNULL(EMP.PostalAddress2,'') <> '' THEN +'3290'+',"'+ REPLACE(EMP.PostalAddress2,',','&&&') + '",' ELSE '' END    + CASE WHEN ISNULL(EMP.PostalAddress3,'') <> '' THEN +'3291'+',"'+ CONVERT(VARCHAR,REPLACE(EMP.PostalAddress3,',','&&&')) + '",' ELSE '' END     + CASE WHEN ISNULL(EMP.PostalAddress4,'') <> '' THEN +'3292'+',"'+ REPLACE(EMP.PostalAddress4,',','&&&') + '",' ELSE '' END     + CASE WHEN ISNULL(EMP.PostalPostalCode,'') <> '' THEN +'3293'+',"'+ CONVERT(NVARCHAR(20), dbo.AppendString_fxn(ISNULL(EMP.PostalPostalCode,''), 4, '0')) +'",' ELSE '' END     + '3294'+',"'+ ISNULL(P_PPC.CountryCode,'') +'",' ELSE '' END            + CASE WHEN ISNULL((SELECT TOP 1 PETD.TaxDirectiveNumber FROM dbo.Payroll_EmployeeTaxDirectives PETD WHERE PETD.EmpID = EMP.Employee_ID),'') <> '' THEN +'3230'+',"'+ (SELECT TOP 1 PETD.TaxDirectiveNumber FROM dbo.Payroll_EmployeeTaxDirectives PETD WHERE PETD.EmpID = EMP.Employee_ID) ELSE '' END    +'3240'+',"'+(CASE WHEN BAT.BankAccountType = 'Cheque Account' OR BAT.BankAccountType = 'Cheque/Current Account' OR BAT.BankAccountType = 'Current Account' THEN '1' WHEN BAT.BankAccountType = 'Savings Account' THEN '2' WHEN BAT.BankAccountType = 'Transmission Account' THEN '3' WHEN BAT.BankAccountType = 'Bond Account' THEN '4' WHEN BAT.BankAccountType = 'Credit Card Account' THEN '5' WHEN BAT.BankAccountType = 'Subscription Share Account' THEN '6' WHEN BAT.BankAccountType = 'Foreign Bank Account' THEN '7' ELSE '0' END)+'",'    + CASE WHEN ISNULL(EMP.AccountNumber,'') <> '' THEN +'3241'+',"'+EMP.AccountNumber+'",' ELSE '' END     + CASE WHEN ISNULL(BBC.BankBranchCode,'') <> '' THEN +'3242'+',"'+ REPLACE(BBC.BankBranchCode,',','&&&') +'",' ELSE '' END    + CASE WHEN ISNULL(Bank.BankDesc,'') <> '' THEN +'3243'+',"'+ REPLACE(Bank.BankDesc,',','&&&') +'",' ELSE '' END    + CASE WHEN ISNULL(BBC.BranchCodeDesc,'') <> '' THEN +'3244'+',"'+ REPLACE(BBC.BranchCodeDesc,',','&&&') +'",' ELSE '' END    + CASE WHEN ISNULL(EMP.AccountHolderName,'') <> '' THEN +'3245'+',"'+ REPLACE(EMP.AccountHolderName,',','&&&') +'",' ELSE '' END    + CASE WHEN ISNULL(EMP.AccountHolderRelationshipID,'') <> '' THEN +'3246'+',"'+  CASE WHEN EMP.AccountHolderRelationshipID=1 THEN 'Own' +'",' WHEN EMP.AccountHolderRelationshipID=2 THEN 'Joint' +'",' WHEN EMP.AccountHolderRelationshipID=3 THEN 'Third Party' +'",' ELSE '' END ELSE '' END     --** Header Record start end**         --** Employee Remuneration Information start**     + ',' + ISNULL(stuff (ISNULL((SELECT ',' + IRP5Code + ',' + CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA A     where A.EmployeeID = EMP.Employee_Id      and (IRP5Code BETWEEN '3601' and '3617' or         IRP5Code BETWEEN '3619' and '3621' or         IRP5Code BETWEEN '3651' and '3667' or         IRP5Code BETWEEN '3701' and '3723' or         IRP5Code BETWEEN '3751' and '3773' or         IRP5Code BETWEEN '3801' and '3810' or         IRP5Code BETWEEN '3820' and '3822' or        IRP5Code BETWEEN '3828' and '3832' or        IRP5Code BETWEEN '3851' and '3860' or        IRP5Code BETWEEN '3870' and '3872' or        IRP5Code BETWEEN '3878' and '3882' or        IRP5Code BETWEEN '3901' and '3909' or        IRP5Code BETWEEN '3920' and '3924' or        IRP5Code BETWEEN '3951' and '3957' or      IRP5Code in ('3669','3670','3813','3815','3816','3817','3825','3863','3865','3866','3867','3875','3915') )      and isnull(Amount,0) > 0      FOR XML PATH('') ), ''),1,1,''),0)      + CASE WHEN (select CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3696') > 0    THEN ',3696,' + CASE WHEN  ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922'),0) <= 300000 THEN  (select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922') + ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3696'),'0')    ELSE (select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3696') End ELSE '' END      + CASE WHEN Year(@ToDate) >= 2017 THEN ',3699,' + CASE WHEN  ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922'),0) > 300000 THEN  (select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922') + ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3699'),'0')    ELSE isnull((select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3699'),'0') End ELSE '' END           + CASE WHEN Year(@ToDate) < 2017 THEN ',3697,' + ISNULL((SELECT CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3697'),'0') ELSE '' End        + CASE WHEN Year(@ToDate) < 2017 THEN ',3698,' + CASE WHEN  ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922'),0) > 300000 THEN  (select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3922') + ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3698'),'0')    ELSE ISNULL((select CONVERT(NVARCHAR(50), CAST(ROUND(ABS(amount),0) AS DECIMAL)) FROM #TEMPDATA WHERE IRP5Code = '3698'),'0') End ELSE '' END        + ',' + ISNULL(stuff (ISNULL((SELECT ',' + IRP5Code + ',' + CONVERT(NVARCHAR(50), CAST(ROUND(amount,0) AS DECIMAL)) FROM #TEMPDATA A     where A.EmployeeID = EMP.Employee_Id      and (IRP5Code BETWEEN '4005' and '4007' or         IRP5Code BETWEEN '4472' and '4475' or         IRP5Code in ('4001','4003','4018','4024','4030','4493','4582','4583') )      and isnull(Amount,0) > 0      FOR XML PATH('') ), ''),1,1,''),0)        + CASE WHEN (ISNULL((select SUM(amount) FROM #TEMPDATA T WHERE IRP5Code in ('4001','4003','4005','4006','4007','4018','4024','4030','4472','4473','4475','4493') AND T.EmployeeID= EMP.Employee_Id ),0) > 0 )    THEN ',4497,' + CONVERT(NVARCHAR, (select SUM(amount) FROM #TEMPDATA T WHERE IRP5Code in ('4001','4003','4005','4006','4007','4018','4024','4030','4472','4473','4475','4493') AND T.EmployeeID= EMP.Employee_Id )) ELSE '' END        + CASE WHEN Year(@ToDate) < 2017 THEN  CASE WHEN ISNULL((select SUM(amount) FROM #TEMPDATA T WHERE IRP5Code in ('4102','4115') AND T.EmployeeID= EMP.Employee_Id ),0 ) > 0     THEN ',4102,' + ISNULL((select CONVERT(NVARCHAR(50), CAST(amount AS DECIMAL(11,2))) FROM #TEMPDATA T WHERE IRP5Code = '4102' AND T.EmployeeID= EMP.Employee_Id ),0) ELSE '' END ELSE '' END    + ',4115,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4115' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))     + ',4141,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4141' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))    + ',4142,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4142' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))    + CASE WHEN ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4149' AND T.EmployeeID= EMP.Employee_Id ),0) > 0     THEN ',4149,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4149' AND T.EmployeeID= EMP.Employee_Id ),0) - ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4116' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2))) ELSE '' END      + ',4116,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4116' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))     + CASE WHEN Year(@ToDate) >= 2017 THEN ',4120,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4120' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2))) ELSE '' END      + ',4118,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4118' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))      + ',4150,' + CONVERT(NVARCHAR, CAST(ISNULL((select amount FROM #TEMPDATA T WHERE IRP5Code = '4150' AND T.EmployeeID= EMP.Employee_Id ),0) AS DECIMAL(11,2)))    + ',9999,'     --** Employee Remuneration Information End**         FROM dbo.Payroll_Employee AS EMP        INNER JOIN dbo.Payroll_Municipality AS M ON EMP.MunicipalityID = M.Municipality_ID                          LEFT OUTER JOIN dbo.Const_Province AS WA_P ON EMP.WorkProvinceID = WA_P.Province_ID                          LEFT OUTER JOIN dbo.Const_Province AS PhyA_P ON EMP.PhysicalProvinceID = PhyA_P.Province_ID                          LEFT OUTER JOIN dbo.Const_Town AS WA_T ON EMP.WorkTownID = WA_T.Town_ID                          LEFT OUTER JOIN dbo.Const_Town AS PhyA_T ON EMP.PhysicalTownID = PhyA_T.Town_ID                          LEFT OUTER JOIN dbo.Const_Country AS P_PC ON P_PC.Country_ID = EMP.PhysicalCountryID                          LEFT OUTER JOIN dbo.Const_Country AS P_PPC ON P_PPC.Country_ID = EMP.PostalCountryID                          LEFT OUTER JOIN dbo.Const_Country AS P_C ON P_C.Country_ID = EMP.PassportCountryID                          LEFT OUTER JOIN dbo.Const_BankAccountType AS BAT ON BAT.BankAccountTypeID = EMP.AccountTypeID                          LEFT OUTER JOIN dbo.Const_BankBranchCode AS BBC ON EMP.BranchID = BBC.BankBranchCode_ID                          LEFT OUTER JOIN dbo.Const_Bank AS Bank ON BBC.BankID = Bank.Bank_ID                          LEFT OUTER JOIN dbo.Const_AccountRelationship ARS ON EMP.AccountHolderRelationshipID = ARS.AccountRelationship_ID                          LEFT OUTER JOIN dbo.Const_NatureOfPerson_Sys AS NOP ON EMP.NatureOfPersonID = NOP.NatureOfPerson_ID                          LEFT OUTER JOIN dbo.Const_Street AS W_PS ON EMP.PostalStreetID = W_PS.Street_ID                          LEFT JOIN Const_Suburb AS P_Suburb ON P_Suburb.Suburb_ID = EMP.PostalSuburbID                  WHERE   EMP.Employee_ID in (Select EmployeeID from #TEMPDATA)      --**Trailer record    --6010 - Total of all records    --6020 - Employer total code value. Optional and not validated, so this wont be included    --6020 - Employer total amount. Optional and not validated, so this wont be included      DECLARE @RecordCount int = (Select Count(Id) from @Result)        INSERT INTO @Result( Result )    SELECT '6010,' + CONVERT(VARCHAR, @RecordCount) + '9999'     SELECT REPLACE(Result,'&&&',',') AS Result,'' AS Result1 FROM @Result ORDER BY Id  SET NOCOUNT OFF      END;    

GO

-- ============================================
-- SP: Payroll_GenerateLeave_sp
-- Schema: dbo
-- ============================================
CREATE procedure [dbo].[Payroll_GenerateLeave_sp]  @ToDate DateTime,  @CapturerId int  as  begin    DECLARE   @id int    DECLARE @Step1 TABLE          (     [Id] [int] ,     [EmployeeId] [int] ,     [LeaveSchemeId] [int] ,     [LeaveTypeId] [int] ,     [LeaveTypeDetailId] [int] ,     [IsEnabled] [bit] ,     [DateCaptured] [datetime] ,     [CapturerId] [int] ,     [FollowOrForfietDate] [datetime] ,     [CycleStartDate] [datetime] ,     [CycleEndDate] [datetime] ,     [Entitled] [decimal](18, 2) ,     [Deduction] [decimal](18, 2) ,     [Balance] [decimal](18, 2) ,     [Forfeit] [decimal](18, 2) ,     [Encash] [decimal](18, 2) ,     [NextAccrualDate] [datetime]     )      INSERT INTO @Step1             ([Id]  ,     [EmployeeId]  ,     [LeaveSchemeId]  ,     [LeaveTypeId]  ,     [LeaveTypeDetailId]  ,     [IsEnabled]  ,     [DateCaptured]  ,     [CapturerId]  ,     [FollowOrForfietDate] ,     [CycleStartDate] ,     [CycleEndDate] ,     [Entitled] ,     [Deduction] ,     [Balance]  ,     [Forfeit]  ,     [Encash]  ,     [NextAccrualDate] )  SELECT  EL.[Id]        ,EL.[EmployeeId]        ,EL.[LeaveSchemeId]        ,EL.[LeaveTypeId]        ,EL.[LeaveTypeDetailId]        ,EL.[IsEnabled]        ,EL.[DateCaptured]        ,EL.[CapturerId]        ,EL.[FollowOrForfietDate]        ,EL.[CycleStartDate]        ,EL.[CycleEndDate]        ,EL.[Entitled]        ,EL.[Deduction]        ,EL.[Balance]        ,EL.[Forfeit]        ,EL.[Encash]        ,EL.[NextAccrualDate]    FROM [EMS_Dev].[dbo].[Payroll_EmployeeLeaveSchemeDetails] EL    INNER JOIN Const_LeaveTypeDetails  LTD    ON LTD.LeaveTypeDetailsId = EL.LeaveTypeDetailId    INNER JOIN Const_LeaveType LT    ON LT.LeaveType_ID = LTD.LeaveTypeId    WHERE [NextAccrualDate] <= @ToDate    AND  [NextAccrualDate] BETWEEN LT.StartDate AND LT.EndDate  --Date Validation   ORDER BY LTD.SequenceNo        WHILE exists (select 1 from @Step1)  BEGIN       select top 1 @id = [Id] from @Step1      --select @id      --   INSERT INTO Payroll_EmployeeLeaveSchemeTransaction ([EmployeeId],[LeaveSchemeId],[LeaveTypeId],[LeaveTypeDetailId],[AccrualLeave],[TakenLeave],[ForfeitLeave]   --              ,[EncashLeave],[AdjustedLeave],[WithoutPayLeave],[TranDate],[IsEnabled],[IsAdjustment],[EncashAmount]   --              ,[AdjustmentReason],[LeaveBeforeAdjustment],[IsProcessed],[DateCaptured],[CapturerId],[Remarks])     --SELECT tmp.EmployeeId, tmp.LeaveSchemeId,tmp.LeaveTypeId,tmp.LeaveTypeDetailId,'AccrualLeave','takenleave' , 'forfeitleave',   --  'EncashLeave', 'Adjustedleave', 'witoutpayleave',GetDate(),1,0,'encashamount', 'AdjustedReason', 'LeaveBeforeAdjustment',   --  1,GetDate(), @CapturerId,'Remarks'    --  FROM @Step1 tmp                   delete from @Step1 where [Id] = @id;  END    END  --select * from Const_LeaveTypeDetails  --select * from Payroll_EmployeeLeaveSchemeDetails  

GO

-- ============================================
-- SP: Payroll_GenerateLedPaymentInstructions
-- Schema: dbo
-- ============================================
 /*   Author  : Unknown   Create date : Unknown   Description : Create the Payment Instructions in Ledger when payment instructions in Payroll are approved      NB! For this report the taxyear will be passed as 2018 (not 2017/2018)   The month will be 0 for Trial report as we can get the month    Payroll_EmployeeVarianceRptTrial_sp 0,1,0,1,2018   done chages for the bug #84414 -- resolve the issue by putting isnull() for the fullName field in the query     Update: Richa M - 22/01/2025 - WI118513 - dont terminate employees if a reinstatement was done in the same period as termination     */     CREATE PROCEDURE [dbo].[Payroll_GenerateLedPaymentInstructions]      @BatchID INT,      @CapturerID INT  AS  BEGIN     DECLARE @Success INT       ,@FinYear NVARCHAR(10)       ,@PaymentInstructionId INT     BEGIN TRANSACTION     BEGIN TRY      SELECT     @FinYear = KeyValue    FROM AAAA_ConfigSettings    WHERE KeyName = 'ActiveFinYear'      DECLARE @PeriodId INT = (       SELECT TOP 1 PeriodID FROM Payroll_PaymentInstructions       WHERE BatchID = @BatchID      )     DECLARE @SalaryControlProjectId INT = (SELECT     SalaryProjectID    FROM [Payroll_Municipality])      declare @projectItems table    (     [PlanProjectItem_ID] [int] NOT NULL,     [ProjectID] [int] NOT NULL,     [ProjectItemID] [int] NULL,     [SCOAItemID] [int] NOT NULL,     [FinYear] [nvarchar](9) NOT NULL,     [CapturerID] [int] NOT NULL,     [DateCaptured] [datetime] NOT NULL,     [ModifierID] [int] NULL,     [DateModified] [datetime] NULL,     [ProjectFundYearID] [int] NULL,     [SCOAFundId] [int] NULL,     [BudgetAmount] [decimal](16, 2) NULL,     [BudgetAmountCurP1] [decimal](16, 2) NULL,     [BudgetAmountCurP2] [decimal](16, 2) NULL,     [SCOAFunctionId] [int] NULL,     [SCOARegionId] [int] NULL,     [DivisionId] [int] NULL,     [BudgetSplitID] [int] NULL,     [VirementId] [int] NULL,     [HistoricalProjectCode] [nvarchar](100) NULL,     [AdjustmentId] [int] NULL,     [ModificationNumber] [int] NULL,     [SCOACostingID] [int] NULL,     [IsItemLocked] [bit] NULL,     [CreditDebit] [varchar](6) NULL    );      insert into @projectItems     Select      [PlanProjectItem_ID],     [ProjectID],     [ProjectItemID],     [SCOAItemID],     [FinYear],     [CapturerID],     [DateCaptured],     [ModifierID],     [DateModified],     [ProjectFundYearID],     [SCOAFundId],     [BudgetAmount],     [BudgetAmountCurP1],     [BudgetAmountCurP2],     [SCOAFunctionId],     [SCOARegionId],     [DivisionId],     [BudgetSplitID],     [VirementId],     [HistoricalProjectCode],     [AdjustmentId],     [ModificationNumber],     [SCOACostingID],     [IsItemLocked],     [CreditDebit]           from Plan_ProjectItem where PlanProjectItem_ID in(         Select min(PlanProjectItem_Id)PlanProjectItem_Id from Plan_ProjectItem          group by ProjectId,ScoaItemId,ScoaFunctionId,ScoaRegionId,FinYear,ScoaCostingId,DivisionId)    drop table if exists #incomeTrx      select min(PayrollResult_ID)Id into #incomeTrx      from Payroll_PayrollResults      where PeriodID = @PeriodId      and TransactionTypeID = 1     GROUP by EmployeeID         ---------------------------------- insert into Led_PaymentInstructions and Led_PaymentInstructionsDetail with Payroll_PaymentInstructions -------------------------------------------------------------------------      DECLARE db_cursor CURSOR FOR SELECT     ppi.PaymentInstructions_ID     FROM Payroll_PaymentInstructions ppi    WHERE ppi.BatchID = @BatchId      OPEN db_cursor    FETCH NEXT FROM db_cursor INTO @PaymentInstructionId      WHILE @@fetch_status = 0    BEGIN        INSERT INTO Led_PaymentInstructions ([FinYear], [ProcessingMonth], [TransactionID], [TransactionDate], [CashbookID], [DocTypeCode],    [TransactionTypeID], [BeneficiaryID], [BeneficiaryName], [BeneficiaryBankName],    [BeneficiaryBankAccountNumber], [BeneficiaryBankAccountType], [BeneficiaryBankBranchCode],    [ModuleId], [InvoiceTotalAmount], [CapturerID], [DateCaptured], [IsAuthorised], [IsImmediatePayment],    [PaymentDueDate], [MunicipalityDepositeReference])       SELECT      @FinYear        ,ppi.ProcessingMonth        ,TransactionID        ,TransactionDate        ,ppi.CashbookID        ,ppi.DocTypeCode        ,ppi.TransactionTypeID        ,ppi.EmployeeID        ,ppi.EmployeeName        ,ppi.EmployeeBankName        ,ppi.EmployeeBankAccountNumber        ,ppi.EmployeeBankAccountType        ,ppi.EmployeeBankBranchCode        ,ppi.ModuleId        ,ppi.InvoiceTotalAmount        ,ppi.CapturerID        ,ppi.DateCaptured        ,ppi.IsAuthorised        ,ppi.IsImmediatePayment        ,ppi.PaymentDueDate        ,ppi.MunicipalityDepositeReference     FROM Payroll_PaymentInstructions ppi     WHERE ppi.PaymentInstructions_ID = @PaymentInstructionId      DECLARE @NewId INT = @@identity      UPDATE Payroll_PaymentInstructions    SET Led_PaymentInstructions_ID = @NewId    WHERE PaymentInstructions_ID = @PaymentInstructionId        INSERT INTO Led_PaymentInstructionDetails ([PaymentInstructions_ID], [EmployeeID], [VoteId], [VoteAmount], [VoteVATIndicator], [VoteVATAmount],    [VoteVATClaimable], [DateCaptured], [CapturerID], [ItemDescription], [SCOACostingID], [SCOAFunctionID],    [SCOAFundsID], [SCOAItemID], [SCOAProjectID], [SCOARegionID],[ProjectId],[ProjectItemId],[DivisionId])       SELECT      @NewId        ,ppid.EmployeeID        ,ppid.VoteId        ,ppid.VoteAmount        ,ppid.VoteVATIndicator        ,ppid.VoteVATAmount        ,ppid.VoteVATClaimable        ,ppid.DateCaptured        ,ppid.CapturerID        ,ppid.ItemDescription        ,ppid.SCOACostingID        ,ppid.SCOAFunctionID        ,ppid.SCOAFundsID        ,ppid.SCOAItemID        ,ppid.SCOAProjectID        ,ppid.SCOARegionID        ,ppi.ProjectId        ,ppi.PlanProjectItem_ID        ,ppid.DivisionId     FROM Payroll_PaymentInstructionDetails ppid      LEFT OUTER JOIN @projectItems ppi      ON ppi.ScoaItemId = ppid.ScoaItemId AND ppi.ScoaFunctionId = ppid.ScoaFunctionId  and ppi.DivisionId = ppid.DivisionId and ppi.SCOARegionId = ppid.SCOARegionID and ppi.SCOAFundId = ppid.SCOAFundsID and FinYear = @FinYear      and ppi.ProjectId = @SalaryControlProjectId and ppi.SCOARegionId = ppid.SCOARegionID     WHERE ppid.PaymentInstructions_ID = @PaymentInstructionId          FETCH NEXT FROM db_cursor INTO @PaymentInstructionId      END      CLOSE db_cursor    DEALLOCATE db_cursor        ---------------------------------------------------- update Payroll_PaymentBatches-----------------------------------------------------------------------------------------------      --POST TRANSACTIONS TO LEDGER    DECLARE @UserProcessingMonth INT, -- must be queried for the current user id @CapturerID when required      @COUNT INT,      @START INT = 1,      @SalaryControlDTItem INT,      @SalaryControlCRItem INT,      @SalaryControlVoteId INT = 0,      @EmployeeNetPayBondProjectID INT,      @EmployeeNetPayBondScoaCreditID INT,      @TravelControlProjectId INT,      @TravelScoaDTItem INT,      @TravelScoaCRItem INT,      @TravelVoteID INT,      @ItemDescription nvarchar(20) = 'Total Net Payment',      @DocCount INT = (       SELECT ISNULL(MAX(CAST(RIGHT(DocNumber, LEN(DocNumber) - 4) AS INT)), 0)       FROM Payroll_TransactionsGroup       WHERE DocNumber LIKE '133/%'      )        SELECT      @EmployeeNetPayBondProjectID = EmployeeNetPayBondProjectID,      @EmployeeNetPayBondScoaCreditID = EmployeeNetPayBondScoaCreditID,     @SalaryControlCRItem = SalarySuspenseScoaItemCreditID,     @SalaryControlDTItem = SalarySuspenseScoaItemID,     @TravelControlProjectId = TravelProjectID,     @TravelScoaDTItem = TravelSuspenseScoaItemID,     @TravelScoaCRItem = TravelSuspenseScoaItemCreditID    FROM [Payroll_Municipality] WITH(NOLOCK)      SELECT TOP 1 @SalaryControlVoteId = [Vote_ID] from [Led_Vote] WITH(NOLOCK)     WHERE ([SCOAItemID] = @SalaryControlDTItem AND [FinYear] = @FinYear AND [VoteStatusID] = 1)      SELECT TOP 1 @TravelVoteID = [Vote_ID] FROM [Led_Vote] WITH(NOLOCK)     WHERE ([SCOAItemID] = @TravelScoaDTItem AND [FinYear] = @FinYear AND [VoteStatusID] = 1)      SET @UserProcessingMonth = dbo.[GetProcessingMonthByUserID_fxn](@CapturerID);      BEGIN      DECLARE @Led_GeneralLedger TABLE (       PostingDate DATETIME         ,ProcessingMonth INT         ,VoteID INT         ,FinYear NVARCHAR(130)         ,PayrollLinkID INT         ,TransactionTypeID INT         ,TransactionDetails NVARCHAR(130)         ,DocumentNumber NVARCHAR(130)         ,DocumentTypeId INT         ,Debit DECIMAL(18, 2)         ,Credit DECIMAL(18, 2)         ,DateCaptured DATETIME         ,CapturerID INT         ,MatchTranGuid UNIQUEIDENTIFIER         ,SCOACostingID INT         ,SCOAFunctionID INT         ,SCOAFundsID INT         ,SCOAItemID INT         ,SCOAProjectID INT         ,SCOARegionID INT         ,DivisionID INT         ,ROWNO INT IDENTITY (1, 1)         ,ProjectId INT         ,PlanProjectItemId INT      )      DECLARE @InsertedTransactionGroups TABLE (TransactionGroup_ID INT)     DECLARE @MatchTransactionGuid UNIQUEIDENTIFIER = newid()      -- DT Salary Control SCOA Debit Item    -- CR Net Pay and Bond Payment SCOA Credit Item    INSERT INTO Payroll_TransactionsGroup (TransactionDate, VoteID, CreditAmount, DebitAmount, PeriodID, DocumentTypeID, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID,      SCOAFunctionID, SCOAItemID, Enabled, DateCaptured, CapturerID, DocNumber, SCMInvoiceSalaryHeadName, MatchTranGuid, DivisionID, ContraSCOAProjectID, ContraSCOAItemID,      ContraSCOACostingID, ContraSCOAFunctionID, ContraSCOAFundingID, ContraSCOARegionID, ProjectID, PlanProjectItemID, ContraProjectId, ContraPlanProjectItemId)    OUTPUT INSERTED.TransactionGroup_ID INTO @InsertedTransactionGroups(TransactionGroup_ID)    select      GetDate(),     results.dtScoaitemId,     0.00 CtAmount,     SUM(Amount),     @PeriodID,     133,     results.ScoaFundingId,     results.SCOARegionID,     pidt.SCOACostingID,     dtpr.ScoaProjectID,     results.SCOAFunctionId,     results.dtScoaitemId,     1     ,GETDATE(),     @CapturerID,     '133/' + CAST((ROW_NUMBER() OVER(ORDER BY (SELECT NULL))) + @DocCount AS VARCHAR(15)),     @ItemDescription,     @MatchTransactionGuid,     results.DivisionID,     ctpr.ScoaProjectID,     results.crScoaItemId,     piCt.SCOACostingID,     results.SCOAFunctionID,     piCt.SCOAFundId,     results.SCOARegionID,     results.DtProjectId,     piDt.PlanProjectItem_ID,     results.crProjectId,     piCt.PlanProjectItem_ID    FROM(      SELECT pr.PayrollResult_ID,pr.EmployeeID,pr.TransactionTypeID,CASE WHEN pr.TransactionTypeID = 1 then pr.Amount else pr.Amount * -1 END AS Amount ,        pr.SalaryHeadID,pr.DepartmentID,pr.DivisionID,pr.SCOARegionID,pr.SCOAFunctionID,pr.SCOAFundingID '131Fund', pr1.scoaFundingId '132Fund',        CASE WHEN pr.TransactionTypeID = 1 then pr.SCOAFundingID else pr1.SCOAFundingID end as ScoaFundingId,        IsNULL(eType.SalaryProjectId,@SalaryControlProjectId) DtProjectId,        IsNULL(eType.SalarySuspenseScoaItemId,@SalaryControlDTItem) dtScoaitemId,@EmployeeNetPayBondScoaCreditID crScoaItemId,@EmployeeNetPayBondProjectID crProjectId      FROM(      SELECT  pt.* FROM Payroll_PayrollResults pt      JOIN Payroll_PaymentInstructions AS PPI ON pt.EmployeeID = PPI.EmployeeID AND pt.PeriodID = PPI.PeriodID      WHERE pt.PeriodID = @PeriodId        and ppi.BatchID = @BatchID       and pt.TransactionTypeID in (1,2)         and TaxSavePurpose = 0)pr      LEFT JOIN (SELECT * FROM Payroll_PayrollResults WHERE PayrollResult_ID in (SELECT Id FROM #incomeTrx)) pr1 ON pr1.EmployeeID = pr.EmployeeID      JOIN Payroll_Employee emp on emp.Employee_id = pr.EmployeeId      JOIN const_EmployeeType_sys eType on eType.EmployeeType_id = emp.EmployeeTypeId)results      LEFT JOIN (SELECT Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID FROM Plan_ProjectItem       where FinYear = @Finyear      GROUP BY FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID)piDt ON      piDt.SCOAItemID = results.dtScoaitemId      and piDt.ProjectID = results.DtProjectId      and piDt.SCOARegionId = results.SCOARegionID      and pidt.SCOAFundId = results.ScoaFundingId      and piDt.SCOAFunctionId = results.SCOAFunctionID      and pidt.DivisionId = results.DivisionID  LEFT JOIN (SELECT Min(PlanProjectItem_ID)PlanProjectItem_ID,FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID FROM Plan_ProjectItem       WHERE FinYear = @Finyear      GROUP BY FinYear,ProjectID,SCOAItemID,SCOAFundId,SCOAFunctionId,SCOARegionId,DivisionId,SCOACostingID)piCt ON      piCt.SCOAItemID = results.crScoaItemId      and piCt.ProjectID = results.crProjectId      and piCt.SCOARegionId = results.SCOARegionID      and piCt.SCOAFundId = results.ScoaFundingId      and piCt.SCOAFunctionId = results.SCOAFunctionID      and piCt.DivisionId = results.DivisionID  LEFT JOIN Plan_Project dtpr ON dtpr.Project_ID = results.DtProjectId  LEFT JOIN Plan_Project ctpr ON ctpr.Project_ID = results.crProjectId    GROUP BY results.ScoaFundingId,results.SCOARegionID,piCt.SCOAFunctionId,results.dtScoaitemId,results.DivisionID,results.crScoaItemId,results.SCOAFunctionID,  piCt.SCOAFundId,results.SCOARegionID,results.DtProjectId,piDt.PlanProjectItem_ID,results.crProjectId,piCt.PlanProjectItem_ID,pidt.SCOACostingID,pict.SCOACostingID,dtpr.ScoaProjectID,ctpr.ScoaProjectID      --Create Transaction from Payroll_TransactionsGroup    INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,      DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID,SCOAItemID, SCOAProjectID,      SCOARegionID, DivisionID, ProjectId, PlanProjectItemId)    SELECT     PTG.TransactionDate     ,@UserProcessingMonth     ,PTG.VoteID     ,@FinYear     ,PTG.TransactionGroup_ID     ,PTG.DocumentTypeID     ,PTG.SCMInvoiceSalaryHeadName + ' (' + PCPD.ProcessingMonth + ')'     ,PTG.DocNumber     ,PTG.DocumentTypeID     ,PTG.DebitAmount      ,0     ,GETDATE()     ,@CapturerID     ,PTG.MatchTranGuid     ,PTG.SCOACostingID     ,PTG.SCOAFunctionID     ,PTG.SCOAFundsID     ,PTG.SCOAItemID     ,PTG.SCOAProjectID     ,PTG.SCOARegionID     ,PTG.DivisionID     ,PTG.ProjectID     ,PTG.PlanProjectItemID    FROM Payroll_TransactionsGroup PTG WITH (NOLOCK)    JOIN Payroll_CyclePeriodDetails AS PCPD WITH (NOLOCK) ON PCPD.Period_ID = PTG.PeriodID    WHERE PTG.PeriodID = @PeriodId AND PTG.DocumentTypeID = 133 AND PTG.TransactionGroup_ID IN (SELECT * FROM @InsertedTransactionGroups)      --Insert Contra Entry     INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,     DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID, SCOAItemID, SCOAProjectID,      SCOARegionID, DivisionID, ProjectId, PlanProjectItemId)    SELECT     PTG.TransactionDate     ,@UserProcessingMonth     ,PTG.VoteID     ,@FinYear     ,PTG.TransactionGroup_ID     ,PTG.DocumentTypeID     ,PTG.SCMInvoiceSalaryHeadName + ' (' + PCPD.ProcessingMonth + ')'     ,PTG.DocNumber     ,PTG.DocumentTypeID     ,0     ,PTG.DebitAmount     ,GETDATE()     ,@CapturerID     ,PTG.MatchTranGuid     ,PTG.ContraSCOACostingID     ,PTG.ContraSCOAFunctionID     ,PTG.ContraSCOAFundingID     ,PTG.ContraSCOAItemID     ,PTG.ContraSCOAProjectID     ,PTG.ContraSCOARegionID     ,PTG.DivisionID     ,PTG.ContraProjectID     ,PTG.ContraPlanProjectItemID    FROM Payroll_TransactionsGroup PTG WITH (NOLOCK)    JOIN Payroll_CyclePeriodDetails AS PCPD WITH (NOLOCK) ON PCPD.Period_ID = PTG.PeriodID    WHERE PTG.PeriodID = @PeriodId AND PTG.DocumentTypeID = 133 AND PTG.TransactionGroup_ID IN (SELECT * FROM @InsertedTransactionGroups)      DECLARE @TransactionDate DATETIME      ,@VOTEIDScoa INT      ,@TransactionLinkID INT      ,@TransactionDesc NVARCHAR(MAX)      ,@DocumentNumber NVARCHAR(130)      ,@DocumentTypeId INT      ,@DebitAmt DECIMAL(18, 2)      ,@CreditAmt DECIMAL(18, 2)      ,@MatchTGuid UNIQUEIDENTIFIER      ,@SCOACostingID INT      ,@SCOAFunctionID INT      ,@SCOAFundsID INT      ,@SCOAItemID INT      ,@SCOAProjectID INT      ,@SCOARegionID INT      ,@DivID INT      ,@ProjectId INT      ,@PlanProjectItemId INT         SELECT @COUNT = COUNT(*) FROM @Led_GeneralLedger             SET @START = 1      WHILE (@START <= @COUNT)    BEGIN       SELECT      @TransactionDate = PostingDate      ,@VOTEIDScoa = VoteID      ,@TransactionLinkID = PayrollLinkID      ,@DocumentNumber = DocumentNumber      ,@DocumentTypeID = DocumentTypeID      ,@TransactionDesc = TransactionDetails      ,@DebitAmt = Debit      ,@CreditAmt = Credit      ,@CapturerID = CapturerID      ,@SCOACostingID = SCOACostingID      ,@SCOAFunctionID = SCOAFunctionID      ,@SCOAFundsID = SCOAFundsID      ,@SCOAItemID = SCOAItemID      ,@SCOAProjectID = SCOAProjectID      ,@SCOARegionID = SCOARegionID      ,@MatchTGuid = MatchTranGuid      ,@DivID = DivisionID      ,@ProjectId = ProjectId      ,@PlanProjectItemId = PlanProjectItemId     FROM @Led_GeneralLedger     WHERE ROWNO = @START       IF (@VOTEIDScoa IS NOT NULL)     BEGIN        EXECUTE Led_Posting_Payroll_sp @TransactionDate              ,@UserProcessingMonth              ,@VOTEIDScoa              ,@FinYear              ,@TransactionLinkID              ,@DocumentTypeID              ,@TransactionDesc              ,@DocumentNumber              ,@DebitAmt              ,@CreditAmt              ,@CapturerID              ,@MatchTGuid              ,@SCOACostingID              ,@SCOAFunctionID              ,@SCOAFundsID              ,@SCOAItemID              ,@SCOAProjectID              ,@SCOARegionID              ,@DivID              ,@ProjectId              ,@PlanProjectItemId       END     SET @START = @START + 1    END      END      UPDATE [Payroll_PaymentBatches]    SET [PayrollStatus] = 'Approved'    WHERE ([Batch_ID] = @BatchID)      /* Update Terminated Employee's Cycle */      declare @TerminationCycleId int = (select Cycle_ID from Const_Cycle where CycleDesc = 'Ad Hoc Termination')        Update payroll_employee set CycleID = @TerminationCycleId         where Employee_ID in (     select EmployeeID      from Payroll_EmployeeTermination term      where TerminationPeriodId = @PeriodId      and EmployeeID not in      (select EmployeeID      from Payroll_EmployeeChange      where StartDate >= term.TerminationStartDate))      SET @Success = 1      COMMIT TRANSACTION     END TRY     BEGIN CATCH      ROLLBACK TRANSACTION      SET @Success = 0     END CATCH     SELECT    @Success    END

GO

-- ============================================
-- SP: Payroll_GenericRemunerationSummaryRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Richa M  -- Create date: 2025/08/20  -- Description: SP for Generic Employee Remuneration Report  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GenericRemunerationSummaryRpt_sp]      @StartDate   Datetime ,                  @EndDate   Datetime  ,                 @Cycle    INT             = NULL,      @Department   INT             = NULL,      @Division   INT             = NULL,      @EmployeeType       INT             = NULL,      @EmployeeSubType    INT             = NULL,      @Employee   INT             = NULL,      @TransactionType    INT             = NULL,      @SalaryHeadId       NVARCHAR(MAX)   = NULL  AS  BEGIN      SET NOCOUNT ON;     ;WITH Parsed AS (          SELECT DISTINCT TRY_CONVERT(INT, LTRIM(RTRIM(value))) AS Id          FROM STRING_SPLIT(ISNULL(@SalaryHeadId, ''), ',')          WHERE ISNULL(LTRIM(RTRIM(value)), '') <> ''      ),      FilterIds AS (          SELECT Id FROM Parsed WHERE Id IS NOT NULL      ),      base AS (          SELECT              emp.Employee_ID,              emp.EmpCode,              emp.Initials,              emp.FirstName,              emp.Surname,              pos.PositionDesc,              dep.DepartmentDesc,              div.DivisionDesc,              et.EmployeeTypeDescription,              est.EmployeeSubtypeDesc,     tt.TransactionType_ID,              tt.TransactionTypeDesc,              sh.SalaryHead_ID,              sh.SalaryHeadName,              pr.IRP5Code,              c.Cycle_ID,              c.CycleDesc,              cp.PeriodStartDate,              YEAR(cp.PeriodStartDate)                 AS YearNo,              MONTH(cp.PeriodStartDate)                AS MonthNo,              -- label: e.g. "Jan 2025"              LEFT(DATENAME(MONTH, cp.PeriodStartDate), 3) + ' ' + CAST(YEAR(cp.PeriodStartDate) AS varchar(4)) AS ProcessingMonth,              -- sort key for columns (YYYYMM)              (YEAR(cp.PeriodStartDate) * 100) + MONTH(cp.PeriodStartDate)   AS MonthKey,              pr.Amount          FROM Payroll_PayrollResults       pr          JOIN Payroll_CyclePeriodDetails   cp  ON cp.Period_ID     = pr.PeriodID          JOIN Payroll_Employee             emp ON emp.Employee_ID  = pr.EmployeeID          JOIN Payroll_SalaryHead           sh  ON sh.SalaryHead_ID = pr.SalaryHeadID          JOIN Const_Cycle                  c   ON c.Cycle_ID       = pr.CycleID          JOIN Payroll_Position             pos ON pos.Position_ID  = emp.PositionID          JOIN Const_Department             dep ON dep.Department_ID= pos.DepartmentID          JOIN Const_Division               div ON div.Division_ID  = pos.DivisionID          JOIN Const_EmployeeType_sys       et  ON et.EmployeeType_ID = emp.EmployeeTypeID          JOIN Payroll_EmployeeSubtypes     est ON est.EmployeeSubtype_ID = emp.EmployeeSubtypeID          JOIN Const_TransactionType        tt  ON tt.TransactionType_ID  = pr.TransactionTypeID          WHERE             PeriodID in (select Period_ID from Payroll_CyclePeriodDetails where PeriodStartDate >= @StartDate and PeriodEndDate <= @EndDate)              AND (@Division        = 0 OR div.Division_ID          = @Division)              AND (@Department     = 0 OR dep.Department_ID        = @Department)              AND (@EmployeeType   = 0 OR et.EmployeeType_ID       = @EmployeeType)              AND (@EmployeeSubtype = 0 OR est.EmployeeSubtype_ID   = @EmployeeSubtype)              AND (@Employee      = 0 OR emp.Employee_ID          = @Employee)              AND (@TransactionType = 0 OR tt.TransactionType_ID    = @TransactionType)              AND (@Cycle        = 0 OR c.Cycle_ID               = @Cycle)     AND (       NOT EXISTS (SELECT 1 FROM FilterIds)                     OR EXISTS (SELECT 1 FROM FilterIds WHERE Id = 0)            OR sh.SalaryHead_ID IN (SELECT Id FROM FilterIds)          )      )      SELECT          Employee_ID,          EmpCode,          Initials,          FirstName,          Surname,          PositionDesc,          DepartmentDesc,          DivisionDesc,          EmployeeTypeDescription,          EmployeeSubtypeDesc,          TransactionTypeDesc,    TransactionType_ID,          SalaryHead_ID,          SalaryHeadName,          IRP5Code,          Cycle_ID,          CycleDesc,          PeriodStartDate,          YearNo,          MonthNo,          MonthKey,          ProcessingMonth,          SUM(Amount) AS Amount      FROM base      GROUP BY          Employee_ID, EmpCode, Initials, FirstName, Surname,          PositionDesc, DepartmentDesc, DivisionDesc,          EmployeeTypeDescription, EmployeeSubtypeDesc,          TransactionTypeDesc,TransactionType_ID, SalaryHead_ID, SalaryHeadName, IRP5Code,          Cycle_ID, CycleDesc,          PeriodStartDate, YearNo, MonthNo, MonthKey, ProcessingMonth      ORDER BY Employee_ID,TransactionType_ID, SalaryHead_ID, MonthKey;  END

GO

-- ============================================
-- SP: Payroll_Get3rdPartyPayment
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_Get3rdPartyPayment]  @PartyPayment_ID int  as  begin   select    PayEmp.PartyPayment_ID,    PayEmp.EmployeeID,    PayEmp.VendorID,    PayEmp.TotalAmount,    PayEmp.Periods,    PayEmp.EMI,    PayEmp.Balance,    PayEmp.[Enabled],    cv.VendorName,   emp.FirstName,   emp.Surname,   emp.IdNo   from    Payroll_3rdPartyPayment PayEmp   inner join Payroll_Employee emp on emp.Employee_ID = PayEmp.EmployeeID   inner join Cons_Vendor cv  on cv.Vendor_ID = PayEmp.VendorID   where PayEmp.PartyPayment_ID = @PartyPayment_ID  end

GO

-- ============================================
-- SP: Payroll_Get3rdPartyPaymentList
-- Schema: dbo
-- ============================================
--[dbo].[Payroll_Get3rdPartyPaymentList] 0,3  -- ==============================================================================  -- Author: Suri Kandukuri  -- Create date: 04 JAN 2016  -- Description: Returns all 3rd Party Payments which match the required search parameters  -- Call: [dbo].[Payroll_Get3rdPartyPaymentList] 0,3,''  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  --Modiri 2019/08/06  --#92480 Incorrect Message for Overtime transactions that were included in a Final Run, no message for Claim transactions.  -- ==============================================================================  CREATE procedure [dbo].[Payroll_Get3rdPartyPaymentList]  --'','','',0   @EmployeeID INT,   @VendorID INT,   @EmployeeCode NVARCHAR(50) = null  as  BEGIN   DECLARE @TempTbl TABLE   (    PartyPayment_ID INT ,    EmployeeID NVARCHAR(50),    EmpCode NVARCHAR(50),    VendorID NVARCHAR(50),    TotalAmount NVARCHAR(50),    Periods NVARCHAR(50),    EMI NVARCHAR(500),    Balance NVARCHAR(50),    [Enabled] bit,    VendorName NVARCHAR(50),    FirstName NVARCHAR(50),    Surname NVARCHAR(50),    IdNo NVARCHAR(50),    PartyDate DATETIME,    Processed BIT   )     declare @sql NVARCHAR(MAX)   set @sql = '   select     PayEmp.PartyPayment_ID,    dbo.BufferString_fxn(CONVERT(VARCHAR,(emp.Employee_ID)), 8, ''0'') as Employee_ID,    isnull(emp.EmpCode,'''') EmpCode,    PayEmp.VendorID,    PayEmp.TotalAmount,    PayEmp.Periods,    PayEmp.EMI,    PayEmp.Balance,    PayEmp.[Enabled],    cv.VendorName,    emp.FirstName,    emp.Surname,    emp.IdNo,    PayEmp.PartyPaymentDate,    CASE WHEN History.PartyPaymentHistory_ID IS NULL THEN 0 ELSE 1 END AS Processed   from Payroll_3rdPartyPayment PayEmp   OUTER APPLY (    SELECT TOP (1) PartyPaymentHistory_ID    FROM Payroll_3rdPartyPaymentHistory PPH     WHERE PPH.PartyPayment_ID = PayEmp.PartyPayment_ID AND PPH.Enabled = 1   ) AS History   inner join Payroll_Employee emp on emp.Employee_ID = PayEmp.EmployeeID   left join Cons_Vendor cv  on cv.Vendor_ID = PayEmp.VendorID    Where 1=1'      if(@EmployeeID is not null and LEN(@EmployeeID)>0 AND @EmployeeID > 0)   BEGIN    set @sql = @sql + 'and emp.Employee_ID = ''' + Convert(varchar(50),@EmployeeID) + ''' '   END   if(@VendorID is not null and @VendorID >0)   BEGIN    set @sql = @sql + 'and PayEmp.VendorID = '+ Convert(varchar(50),@VendorID)   END   if(isnull(@EmployeeCode ,'') <> '')   BEGIN       set @sql = @sql + 'and emp.EmpCode = ''' + @EmployeeCode + ''' '   END    SET @sql = @sql +'Order by emp.Employee_ID'   INSERT INTO @TempTbl    EXEC(@sql)      SELECT * FROM @TempTbl  END

GO

-- ============================================
