-- ============================================
-- SP: Payroll_GetActiveEmployees
-- Schema: dbo
-- ============================================
  /*       Author  : Ferdi Botha   Create Date : 2018/11/15     Description : Returns a list of active employees  */      create procedure [dbo].[Payroll_GetActiveEmployees] @DepartmentID int = null, @DivisionID int = null, @EmployeeID int = null, @Date datetime = null, @active bit = 1  as    begin     declare @highDate datetime = '9999-12-31 00:00:00'     if (@Date is null)      set @Date = getdate()     declare @employees as table (      [Employee_ID] int not null     )     insert into @employees([Employee_ID])      select distinct [Employee_ID]       from [Payroll_Employee] as [PE] with(nolock)        join (         select [EmployeeID], [EPR].[Enabled], [StartDate], [EndDate]          from [Payroll_EmployeeHistory] as [EPH] with(nolock)           join [Payroll_ReasonEmployeeChange] as [EPR] with(nolock) on [Reason_ID] = [ReasonID] and [EPR].[Enabled] = 1         where (          [DepartmentID] = (case isnull(@DepartmentID, 0) when 0 then [DepartmentID] else @DepartmentID end) and          [DivisionID] = (case isnull(@DivisionID, 0) when 0 then [DivisionID] else @DivisionID end) and          not [ReasonDescription] = 'Non-Employee' and          not exists(           select [PositionHistory_ID]           from [Payroll_PositionHistory] with(nolock)           where (            [PositionHistory_ID] = [EPH].[PositionHistoryID] and            [IsNonEmployee] = 1           )          )         )          group by [EmployeeID], [ReasonID], [EPR].[Enabled], [StartDate], [EndDate]        ) as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[StartDate] <= @Date and [PEH].[EndDate] >= @Date      where (       (        [Employee_ID] = (case isnull(@EmployeeID, 0) when 0 then [Employee_ID] else @EmployeeID end) and        [IsDummy] = 0 and        [JoiningDate] <= @Date and [PE].[EndDate] >= @Date       ) and       not ([PE].[Enabled] = 0 and [PE].[EndDate] = @highDate)      )     if (@active = 1)   begin      select [Employee_ID] from @employees     end   else if (@active = 0)   begin      select [Employee_ID]       from [Payroll_Employee] with(nolock)      where (not [Employee_ID] in(        select [Employee_ID] from @employees       )      )     end    end  

GO

-- ============================================
-- SP: Payroll_GetAdhocCyclePeriod_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Ravindra Jijotia  -- Create date : 21 APRIL 2016  -- Description: This sp will return adhoc payroll periods for given cycle.  -- calls : Payroll_GetAdhocCyclePeriod_sp  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetAdhocCyclePeriod_sp]     @FinancialYear NVARCHAR(50),    @CycleID INT  AS  BEGIN   DECLARE @PeriodInTaxYear INT   SELECT TOP 1 @PeriodInTaxYear = PeriodInTaxYear   FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear AND CycleID = @CycleID AND Processed = 0 AND CycleModeID = 1 AND Enabled=1     SELECT Period_ID, ProcessingMonth + ' (' + CONVERT(NVARCHAR(15),PeriodStartDate,106) + ' - ' + CONVERT(NVARCHAR(15),PeriodEndDate,106) + ')' AS Period   FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear AND CycleID = @CycleID AND Processed = 0 AND CycleModeID = 2 AND PeriodInTaxYear = @PeriodInTaxYear AND Enabled=1  END        

GO

-- ============================================
-- SP: Payroll_GetAffectedEmployeeTaxReallocate
-- Schema: dbo
-- ============================================
  -- ===============================================================================  -- Author: PHUTI CHOKOE  -- Create date: 01/11/2016  -- Description: GET AFFECTED EMPLOYEES TAX REALOOCAATE  -- calls : [Payroll_GetAffectedEmployeeTaxReallocate] 'loan,basic salary','2016/2017'  -- 2016-11-11 43101 Phuti chokoe   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetAffectedEmployeeTaxReallocate]  @List varchar(MAX),  @TaxYear varchar(20)  AS     select ps.EmployeeID  as Affected_Employee, ps.Amount, HEAD.SalaryHeadName     from Payroll_EmployeePayslip ps     inner join Payroll_EmployeePayrollDefinition  AS DEF ON DEF.EmployeePayrollDefinition_ID = ps.PayrollDefinationID     INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON HEAD.SalaryHead_ID = DEF.PayrollSalaryHeadID      --INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID     INNER JOIN fnSplitString(@List, ',') AS LIST ON HEAD.SalaryHeadName = LIST.splitdata     where ps.TaxYear = @TaxYear      order by  ps.EmployeeID asc        

GO

-- ============================================
-- SP: Payroll_GetAggrivedEmployee
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:Phuti chokoe  -- Create date: 12 July 2016  -- Description: Get Aggrived employees to populate in the Add aggrived table   -- Call : [[Payroll_GetAggrivedEmployee] 71  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetAggrivedEmployee]  @GrievanceID int  AS  BEGIN   SELECT    PET.EmployeeID,    PE.EmpCode,   PE.FirstName,   PE.IdNo,   PE.PassportNumber,   PE.Surname,   PET.GrievanceID   FROM dbo.Payroll_GrievanceEmployeeSubmittedBy PET    INNER JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = PET.EmployeeID    AND PET.GrievanceID = @GrievanceID    ANd PET.Enabled = 1  END    

