-- ============================================
-- SP: Payroll_GetAllEFTPaymentInstructions
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_GetAllEFTPaymentInstructions]    @DueDate Datetime = NULL    AS  BEGIN        SELECT [PB].[PaymentDueDate]            ,[Batch_ID]            ,[PayrollStatus]            ,[LedgerPaymentStatus]            ,COALESCE( (SELECT COUNT([PaymentInstructions_ID])                        FROM [Payroll_PaymentInstructions]                        WHERE [BatchID] = [PB].[Batch_ID]                              AND [Changed] = 1),0) AS            [Updated]            ,[BatchType]            ,[NumberOfEmployees]            ,[NumberOfTransactions]            ,[PB].[InvoiceTotalAmount]            ,[PB].[ProcessedDate]            ,[CC].[CycleDesc] AS                                  [PayrollCycle]            ,COALESCE( (SELECT TOP 1 [IsImmediatePayment]                        FROM [Payroll_PaymentInstructions]                        WHERE [BatchID] = [PB].[Batch_ID]                              AND [IsImmediatePayment] = 1),0) AS [IsImmediatePayment]            , (SELECT TOP 1 CASE                                WHEN [CPD].[AdhocTypeID] IS NULL                                THEN 'Normal'                                WHEN [CPD].[AdhocTypeID] = 1                                THEN 'Ad Hoc Termination'                                WHEN [CPD].[AdhocTypeID] = 2                                THEN 'Ad Hoc Transaction'                            END               FROM [Payroll_CyclePeriodDetails] AS [CPD]               WHERE [CC].[Cycle_ID] = [CPD].[CycleID]) AS        [CycleType]      FROM [Payroll_PaymentBatches] AS [PB] WITH (nolock)           JOIN [Const_Cycle] AS [CC] ON [CC].[Cycle_ID] = [PB].[Payroll_CycleID]                                         AND [CC].[Enabled] = 1      WHERE [NumberOfEmployees] > 0 and (PaymentDueDate = @DueDate OR @DueDate IS NULL)       order by [PB].[PaymentDueDate] desc      END;

GO

-- ============================================
-- SP: Payroll_GetAllEmployeeForPA
-- Schema: dbo
-- ============================================
-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  CREATE PROCEDURE [dbo].[Payroll_GetAllEmployeeForPA]  AS  BEGIN   SELECT    EMP.FirstName,   EMP.Employee_ID,   EMP.IdNo,   EMP.Surname,   EMP.JoiningDate,   JP.JobProfile_ID AS JobProfileID,   JP.JobTitle,   EMP.Enabled,   EMP.IsDummy   FROM Payroll_Employee EMP    INNER JOIN Payroll_Position PP ON PP.Position_ID = EMP.PositionID    INNER JOIN Payroll_JobProfile JP ON JP.JobProfile_ID = PP.JobProfileID   WHERE EMP.Enabled = 1 AND EMP.IsDummy = 0  END    

GO

