-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 06 Jun 2014  -- Call SP    : Payroll_GetAllInovice  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetAllInovice]     AS  BEGIN   SELECT INV.Invoice_ID,    dbo.BufferString_fxn(CONVERT(VARCHAR, ( INV.Invoice_ID )), 8,'0') AS InvoiceNo,   INV.InvoiceDate,    C_V.Vendor_ID,    VendorName,    C_V.FirstName,    C_V.LastName,    C_V.Tel_Mobile,    C_V.EmailAddress    FROM SCM_Invoice AS INV   INNER JOIN Cons_Vendor AS C_V ON INV.VendorCreditorID = C_V.Vendor_ID   WHERE PayrollPeriodID IS NOT NULL   ORDER BY PayrollPeriodID  END  

