-- ============================================
-- SP: Payroll_GetApprovedTrialRunOnLockDown_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 09/05/2017   Description : Get the Trial Runs on lockdown waiting for Final Run  */  create procedure [Payroll_GetApprovedTrialRunOnLockDown_sp]  as    begin     set nocount on;     select [Period_ID], [CycleDesc] as [PayrollCycleDescription], [PeriodStartDate] as [Start_Date], [PeriodEndDate] as [End_Date], sum([Amount]) as [Total_Company_Cost], [CPD].[DateCaptured] as [TrialRunDate], [ApprovedDate], [ApprovedBy], (case when [ApprovedStatus] = 'Yes' then 'Yes' else 'No' end) as [Approved], (select count(distinct [Employee_ID]) from [Payroll_Employee] where ([CycleID] = [CC].[Cycle_ID])) as [Employee_Count]      from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)       join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [PayrollDefinationID]       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]       join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]       join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = [TP].[PeriodID]       join [Const_Cycle] as [CC] with(nolock) on [Cycle_ID] = [CPD].[CycleID]       join [Const_TransactionType] as [CT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID]      where ([EPD].[Enabled] = 1 and [SH].[Enabled] = 1 and [IRP5].[Enabled] = 1 and [GL].[Enabled] = 1 and [CPD].[Enabled] = 1 and [LockedDown] = 1 and [ApprovedStatus] = 'Yes' and [TransactionType_ID] in(1, 3))       group by [Period_ID], [CycleDesc], [PeriodStartDate], [PeriodEndDate], [CPD].[DateCaptured], [ApprovedDate], [ApprovedBy], [ApprovedStatus], [Cycle_ID]     set nocount off;    end  

GO

