  CREATE procedure [dbo].[Payroll_GetAssignedEmployeeSubtypes_sp]  @LeaveClassificationID int =0  as  begin   if (@LeaveClassificationID = 0 )   begin      select b.LeaveClassificationID, c.EmployeeSubtype_ID,c.EmployeeSubtypeDesc,b.LeaveType_ID,b.LeaveType from  Const_LeaveToEmployeeSubtype a     inner join Const_LeaveType  b     on a.LeaveTypeID = b.LeaveType_ID     inner join Payroll_EmployeeSubTypes c     on c.EmployeeSubtype_ID = a.EmployeeSubtypeID          end   else   begin     select b.LeaveClassificationID, c.EmployeeSubtype_ID,c.EmployeeSubtypeDesc,b.LeaveType_ID,b.LeaveType from  Const_LeaveToEmployeeSubtype a     inner join Const_LeaveType  b     on a.LeaveTypeID = b.LeaveType_ID     inner join Payroll_EmployeeSubTypes c     on c.EmployeeSubtype_ID = a.EmployeeSubtypeID     where b.LeaveClassificationID =LeaveClassificationID   end  end      

