CREATE PROCEDURE [dbo].[Payroll_GetBargainingCouncilIncrease]  @BargainingCouncilID INT=0  AS    BEGIN      select     [TG].TaskGradeName,    [SL].Description,    [PN].[Notch],    [PN].Notch_ID,    [TG].TaskGrade_ID,     [PN].MinimumSalary as [MinNotchValue],    [PN].MaximumSalary as [MaxNotchValue]     from [Payroll_Notch] as [PN]   join [Payroll_TaskGrade] as [TG] with(nolock) on [PN].[TaskGradeid] = [TG].[TaskGrade_ID]   join [Payroll_TaskSkillLevel] as [SL] with(nolock) on [SL].[TaskSkillLevel_ID] = [TG].[SkillLevelId]   WHERE [PN].[Enabled]=1 AND ([SL].[IsEnabled] = 1)     order by [TG].[TaskGradeName], [PN].[Notch]  END

