      CREATE PROC [dbo].[Payroll_GetBargainingCouncilIncreaseByTaskGradeID_sp](@TaskGradeId INT = NULL)  AS  BEGIN  SELECT  [BargainingCouncil_ID]        , [TaskGradeID]     , TG.TaskGradeName        , [DecimalRounding]        , [Y1IncreaseDate]        , [Y1IncreasePercentage]        , [EffectiveDate]        , [BackPayMonth]        , [BackPayFromDate]        , [BackPayToDate]        , [Y2IncreaseDate]        , [Y2Increase]        , [Y3IncreaseDate]        , [Y3Increase]    FROM  [dbo].[Payroll_BargainingCouncilIncrease] BC WITH(NOLOCK)    INNER JOIN [dbo].[Payroll_TaskGrade]  TG WITH(NOLOCK) ON TG.TaskGrade_ID = BC.TaskGradeId    WHERE TaskGradeId = ISNULL(@TaskGradeId,TaskGradeId)     order by [TG].[TaskGrade_ID] asc    END

