-- ============================================
-- SP: Payroll_GetBenefitContribution
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 11 03 2014  -- Description:   -- CALLS : --EXEC Payroll_GetBenefitContribution 1,0  -- 2015-03-27 James Roodt: Changed ActiveFinYear to ActivePayrollYear  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =============================================  create procedure [Payroll_GetBenefitContribution] @EmployeeID int, @BenefitContribution decimal(18, 2) output  as    begin     declare @TaxYear nvarchar(50)     select @TaxYear = [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear')     select @BenefitContribution = sum(isnull([Amount], 0))      from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)       join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [PayrollDefinationID]      where ([ETP].[EmployeeID] = @EmployeeID and [TaxYear] = @TaxYear and [IsRFI] = 1)     if (@BenefitContribution is null)       set @BenefitContribution = 0      select isnull(@BenefitContribution, '0.00') as [BenefitContribution]    end  

GO

-- ============================================
-- SP: Payroll_GetBulkApprovalDetails_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 03 SEPT 2016  -- Description: Returns all Bulk upload approvals which match the required search parameters  -- Call: [Payroll_GetBulkApprovalDetails_sp]  -- 2016-09-06 TP:43647 Seipei Mathole: Created  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetBulkApprovalDetails_sp] @HeaderID int  as  begin     declare @statusID int     select @StatusID = [Status_ID] from [Const_Status] where ([StatusDesc] = 'Requested' and [UsedBy] ='BulkUploadApprovals')        SELECT  Distinct BUH.UploadDate,            CC.CycleDesc,      BUT.Description AS UploadTypeDesc,     SH.SalaryHeadName,      (SELECT COUNT(*)        FROM [dbo].[Payroll_BulkUploadTransactionDetails] BTD        WHERE BTD.BulkUploadHeaderID = @HeaderID) AS AmountOFLines,           (SELECT Sum(Value)          FROM  [dbo].[Payroll_BulkUploadTransactionDetails] BTD         WHERE  BTD.BulkUploadHeaderID = @HeaderID) AS CostAmount,        BUH.FileName,       UD.FirstName,       BUH.StatusID,       CS.StatusDesc,       BUH.Reason    FROM         [dbo].[Payroll_BulkUploadHeader] BUH      INNER JOIN [dbo].[Payroll_BulkUploadTransactionDetails] BTD  ON BTD.BulkUploadHeaderID = BUH.BulkUploadHeader_ID     INNER JOIN [dbo].[Payroll_BulkUploadType_sys] BUT ON BUH.BulkUploadTypeID = BUT.BulkUploadType_ID     INNER JOIN [dbo].[User_UserDetail] UD ON UD.User_ID = BUH.UploadByUserID     INNER JOIN [dbo].[Const_Cycle] CC  ON CC.Cycle_ID = BUH.CycleID     INNER JOIN [dbo].[Payroll_SalaryHead] SH ON SH.SalaryHead_ID = BUH.SalaryHeadID     INNER JOIN [dbo].[Const_Status] CS ON CS.Status_ID = BUH.StatusID      WHERE BUH.BulkUploadHeader_ID = @HeaderID   AND BUH.StatusID = Status_ID    END  

GO

-- ============================================
-- SP: Payroll_GetBulkEmployeeDetails_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 03 SEPT 2016  -- Description: Returns all Bulk upload approvals which match the required search parameters  -- Call: [Payroll_GetBulkEmployeeDetails_sp]  -- 2016-09-06 TP:43647 Seipei Mathole: Created  -- ==============================================================================    CREATE PROCEDURE [dbo].[Payroll_GetBulkEmployeeDetails_sp]    @HeaderID INT     AS     BEGIN         Declare @statusID INT      SELECT @StatusID = Status_ID FROM Const_Status WHERE StatusDesc = 'Requested' AND UsedBy ='BulkUploadApprovals'        SELECT  Distinct BUH.UploadDate,            CC.CycleDesc,      BUT.Description AS UploadTypeDesc,     (SELECT COUNT(*)        FROM [dbo].[Payroll_BulkUploadEmployeeDetails] BED        WHERE BED.BulkUploadHeaderID = @HeaderID) AS AmountOFLines,       BUH.FileName,       UD.FirstName,       BUH.StatusID,       CS.StatusDesc      FROM         [dbo].[Payroll_BulkUploadHeader] BUH      INNER JOIN [dbo].[Payroll_BulkUploadEmployeeDetails] BED  ON BED.BulkUploadHeaderID = BUH.BulkUploadHeader_ID     INNER JOIN [dbo].[Payroll_BulkUploadType_sys] BUT ON BUH.BulkUploadTypeID = BUT.BulkUploadType_ID     INNER JOIN [dbo].[User_UserDetail] UD ON UD.User_ID = BUH.UploadByUserID     INNER JOIN [dbo].[Const_Cycle] CC  ON CC.Cycle_ID = BUH.CycleID     INNER JOIN [dbo].[Const_Status] CS ON CS.Status_ID = BUH.StatusID      WHERE BUH.BulkUploadHeader_ID = @HeaderID   AND BUH.StatusID = @StatusID    END  

GO

-- ============================================
-- SP: Payroll_GetBulkEmployees_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 03 SEPT 2016  -- Description: Returns all Bulk upload approvals which match the required search parameters  -- Call: BED.Payroll_GetBulkEmployees_sp  -- 2016-09-06 TP:43647 Seipei Mathole: Created  -- ==============================================================================    CREATE PROCEDURE [dbo].[Payroll_GetBulkEmployees_sp]    @HeaderID INT  AS     BEGIN    SELECT         BED.BulkUploadHeaderID        ,BED.Employee_ID AS EmployeeID        ,BED.EmpCode        ,BED.IdNo        ,BED.FirstName        ,BED.Surname              FROM [dbo].[Payroll_BulkUploadEmployeeDetails] BED           INNER JOIN [dbo].Payroll_BulkUploadHeader BUH ON BED.BulkUploadHeaderID = BUH.BulkUploadHeader_ID           WHERE  BED.BulkUploadHeaderID = @HeaderID            AND BED.Enabled = 1    END    

GO

-- ============================================
-- SP: Payroll_GetBulkHeaders_sp
-- Schema: dbo
-- ============================================
-- =============================================        -- Author  :Varun Parvataneni        -- Create date :12/09/2016        -- Description :Return all the Headers and the editable or not information        -- Calls  :Payroll_GetBulkHeaders_sp 2        -- Changes  :Jaydev on dated 7-Nov-16 (ADD addressIndicator, postalPostOffice, postalStreetID FOR BulkType=2)        -- =============================================     -- =============================================      -- Author:  <ANANTH SAKTHIVEL>      -- Modify date: <10-Jan-2018>      -- Description: modified the Headers as per Spec Document.       -- File : TP-66284  -- =============================================               CREATE PROCEDURE [dbo].[Payroll_GetBulkHeaders_sp]         @BulkType INT                AS        BEGIN                DECLARE @Headerstable  TABLE (Headers nvarchar(50),HeaderEditableInfo nvarchar(100))                If(@BulkType =1)        BEGIN        INSERT INTO @Headerstable VALUES('EmployeeNumber','ONLY EDIT IF NEW')        INSERT INTO @Headerstable VALUES('LastName','ONLY EDIT IF NEW')    INSERT INTO @Headerstable VALUES('FirstName','ONLY EDIT IF NEW')        INSERT INTO @Headerstable VALUES('EntryDate','EDIT')        INSERT INTO @Headerstable VALUES('SalaryHead','ONLY EDIT IF NEW')        INSERT INTO @Headerstable VALUES('Amount/Unit','EDIT')        INSERT INTO @Headerstable VALUES('ReferenceNo','EDIT')     INSERT INTO @Headerstable VALUES('RepeatMonthly','EDIT')       INSERT INTO @Headerstable VALUES('ID','DO NOT EDIT/BLANK IF NEW(NOTE THAT FIRST LINE MUST BE AN EXISTING ENTRY')        END        ELSE IF((@BulkType =2) OR (@BulkType =3))      BEGIN        INSERT INTO @Headerstable VALUES('Employee_ID','ONLY EDIT IF NEW')        INSERT INTO @Headerstable VALUES('EmpCode','EDIT')        INSERT INTO @Headerstable VALUES('IdNo','EDIT')        INSERT INTO @Headerstable VALUES('TitleID','EDIT')        INSERT INTO @Headerstable VALUES('Initials','EDIT')        INSERT INTO @Heade