-- ============================================
-- SP: Payroll_GetColumns_sp
-- Schema: dbo
-- ============================================
    --Payroll_GetColumns_sp 'Payroll_Employee',0  CREATE procedure [dbo].[Payroll_GetColumns_sp]    @table sysname,   @includeAll bit  as  begin    if @includeAll = 0  begin      select 1 as idx, [c].[name] as [name],[cc].[SortOrder],      isnull([p].[is_primary_key], 0) as [is_primary_key],      cast((case when isnull([f].[constraint_object_id], 0) > 0 then 1 else 0 end) as bit) as [is_foreign_key],      isnull([i].[is_identity], 0) as [is_identity],      cast((case when isnull([d].[object_id], 0) > 0 then 1 else 0 end) as bit) as [is_default],      [c].[is_computed] as [is_computed],      isnull([cc].[IsNullable], 1) as [is_nullable]      from [sys].[columns] as [c]       join [sys].[types] as [t] on [t].[user_type_id] = [c].[user_type_id]       left join (        select [ix].[object_id], [ix].[is_primary_key], [ic].[column_id]         from [sys].[indexes] as [ix]          join [sys].[index_columns] as [ic] on [ic].[object_id] = [ix].[object_id] and [ic].[index_id] = [ix].[index_id]       ) as [p] on [p].[object_id] = [c].[object_id] and [p].[column_id] = [c].[column_id] and [p].[is_primary_key] = 1       left join [sys].[foreign_key_columns] as [f] on [f].[parent_object_id] = [c].[object_id] and [f].[parent_column_id] = [c].[column_id]       left join [sys].[identity_columns] as [i] on [i].[object_id] = [c].[object_id] and [i].[column_id] = [c].[column_id] and [i].[is_identity] = 1       left join [sys].[default_constraints] as [d] on [d].[parent_object_id] = [c].[object_id] and [d].[parent_column_id] = [c].[column_id]       inner join [Const_CompulsaryEmployeeBulkImportInfo] as [cc] on [cc].[ColumnName] = [c].[name]       where ([c].[object_id] = object_id('[' + @table + ']') and objectproperty([c].[object_id], 'IsUserTable') = 1)         order by [cc].[SortOrder]  end  else  begin   select 1 as idx, [c].[name] as [name],1 as [SortOrder],      isnull([p].[is_primary_key], 0) as [is_primary_key],      cast((case when isnull([f].[constraint_object_id], 0) > 0 then 1 else 0 end) as bit) as [is_foreign_key],      isnull([i].[is_identity], 0) as [is_identity],      cast((case when isnull([d].[object_id], 0) > 0 then 1 else 0 end) as bit) as [is_default],      [c].[is_computed] as [is_computed],      isnull([c].[is_nullable], 1) as [is_nullable]      from [sys].[columns] as [c]       join [sys].[types] as [t] on [t].[user_type_id] = [c].[user_type_id]       left join (        select [ix].[object_id], [ix].[is_primary_key], [ic].[column_id]         from [sys].[indexes] as [ix]          join [sys].[index_columns] as [ic] on [ic].[object_id] = [ix].[object_id] and [ic].[index_id] = [ix].[index_id]       ) as [p] on [p].[object_id] = [c].[object_id] and [p].[column_id] = [c].[column_id] and [p].[is_primary_key] = 1       left join [sys].[foreign_key_columns] as [f] on [f].[parent_object_id] = [c].[object_id] and [f].[parent_column_id] = [c].[column_id]       left join [sys].[identity_columns] as [i] on [i].[object_id] = [c].[object_id] and [i].[column_id] = [c].[column_id] and [i].[is_identity] = 1       left join [sys].[default_constraints] as [d] on [d].[parent_object_id] = [c].[object_id] and [d].[parent_column_id] = [c].[column_id]      where ([c].[object_id] = object_id('[' + @table + ']') and objectproperty([c].[object_id], 'IsUserTable') = 1)    end  end

GO

-- ============================================
-- SP: Payroll_GetContractEndNotifications_sp
-- Schema: dbo
-- ============================================
--DROP PROCEDURE IF EXISTS [dbo].[Payroll_GetContractEndNotifications_sp]  --GO  -- =============================================  -- Author:  <Varun Parvataneni>  -- Create date: <Create Date,,4 Aug 2016>  -- Description: <Description,,Notification on Contract Ending Employees>  -- Call SP    : Payroll_GetContractEndNotifications_sp   -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  /*  Developer: Modiri  Date: 2019/04/15  Reason :#86719 No Notification of contract worker who's contract will expiere on dashboard  SP was looking at IsContractor instead of ReasonID to check see if employee is contractor or not  Date: 2019/04/23  Fix issues with contractors contracts about to expire was not returning all employees  Fix the date format issue  */  --===========================================================================  -- 2021/10/07 Charl E WI34287 Added additional fields  --===========================================================================  CREATE PROCEDURE [dbo].[Payroll_GetContractEndNotifications_sp]  AS  BEGIN  SELECT DISTINCT [dbo].[BufferString_fxn](CONVERT(NVARCHAR(10), ([Emp].[Employee_ID])), 8, '0') AS [EmpNo]       , [emp].[IdNo] AS [SANumber]       , ([emp].[FirstName] + ' ' + [emp].[Surname]) AS [EmployeeName]       , [Emp].[Employee_ID]       , [dept].[DepartmentDesc] AS [Department]       , [div].[DivisionDesc] AS [Division]       , [Currentpos].[PositionDesc] AS [Position]       , [cc].[CycleDesc] AS PayrollCycle       , [emp].[JoiningDate] AS ContractStartDate       , [emp].[EndDate] AS ContractEndDate       ,ISNULL(emp.RPH_Other,0) AS RatesPerHour  FROM [Payroll_EmployeeHistory] AS [empH] WITH(NOLOCK)       LEFT OUTER JOIN [dbo].[Payroll_Employee] AS [emp] WITH(NOLOCK) ON [emp].[Employee_ID] = [emph].[EmployeeID]       LEFT OUTER JOIN [dbo].[Const_Cycle] AS [CC] ON [CC].[Cycle_ID] = [emp].[CycleID]       LEFT OUTER JOIN [Const_Division] AS [div] WITH(NOLOCK) ON [Division_ID] = [empH].[DivisionID]       LEFT OUTER JOIN [dbo].[Const_Department] AS [dept] WITH(NOLOCK) ON [dept].[Department_ID] = [emph].[DepartmentID]       LEFT OUTER JOIN [Payroll_PositionHistory] AS [posH] WITH(NOLOCK) ON [PositionHistory_ID] = [empH].[PositionHistoryID]                                                                           AND [posH].[Enabled] = 1       LEFT OUTER JOIN [Payroll_Position] AS [pos] WITH(NOLOCK) ON [Position_ID] = [posH].[PositionID]       JOIN [Payroll_ReasonEmployeeChange] AS [res] WITH(NOLOCK) ON [Reason_ID] = [empH].[ReasonID]                                                                    AND ([res].[ReasonDescription] = 'New Contractor'                                                                         OR [res].[ReasonDescription] = 'New Temporary Employee'                                                                         OR [res].[ReasonDescription] = 'New Employee')       LEFT OUTER JOIN [Payroll_Position] AS [Currentpos] WITH(NOLOCK) ON [Currentpos].[Position_ID] = [emp].[PositionID]      WHERE [Emp].[IsDummy] = 0            AND [Emp].[Enabled] = 1            AND (CONVERT(DATE, [emp].[EndDate])) BETWEEN(CONVERT(DATE, GETDATE())) --Current Date            AND(CONVERT(DATE, GETDATE() + 60))--60days later of calender  ----    END

GO

