-- ============================================
-- SP: Payroll_GetCostCenterDetails_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  -- Description : Called from BulkUpload we have to write salaryhead and the into Payroll_BulkHeaders Table  -- Create date: 03/09/2016  -- CALLS : [Payroll_GetCostCenterDetails_sp] 43239  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetCostCenterDetails_sp] @CostCenterID INT    AS    BEGIN     SELECT    PEP.PayrollSalaryHeadID,   PE.CycleID,   PC.EmployeeID,   PC.CostDesc AS PayrollSalaryHeadTitle,   PC.CostCenter_ID,   PE.FirstName+''+PE.Surname AS FullName    FROM Payroll_CostCenter PC  INNER JOIN Payroll_EmployeePayrollDefinition PEP ON PC.PayrollDefinationID = PEP.EmployeePayrollDefinition_ID  INNER JOIN Payroll_SalaryHead PS ON PS.SalaryHead_ID = PEP.PayrollSalaryHeadID  INNER JOIN Payroll_Employee PE ON PC.EmployeeID = PE.Employee_ID  WHERE PC.CostCenter_ID =@CostCenterID    END  

GO

