CREATE PROC [dbo].[Payroll_GetCurrentYearPeriodIDs]  @TaxYear varchar(max)  AS    select  row_number() over (order by (select 0)) as Periods ,Period_ID from Payroll_CyclePeriodDetails where CycleID = 1 and CycleModeID = 1  and TaxYear = '2016/2017'     

GO

-- ============================================
-- SP: Payroll_GetCurrentYearPeriodIDs_sp
-- Schema: dbo
-- ============================================
-- ===============================================================================  -- Author: PHUTI CHOKOE  -- Create date: 01/11/2016  -- Description: GET Totals for the tax total code   -- calls : [Payroll_GetCurrentYearPeriodIDs_sp] '2016/2017',4006  -- 2016-08-23 TP43523 Phuti chokoe   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 2018/03/05 - Changed the periodId to PeriodInTaxYear - TP62769 - RichaM  -- Update date : 2018/11/01 - Added the IsRFI flag - FERDI BOTHA  -- =============================================  CREATE procedure [dbo].[Payroll_GetCurrentYearPeriodIDs_sp] @TaxYear varchar(max), @IsRFI bit, @IRP5Code varchar(10), @EmployeeId int  as  begin    declare @tbl table([SalaryHeadName] varchar(150),[PeriodId] int,[SalaryHeadId] int,[Irp5CodeId] int,[Amount] decimal(18,2))   Insert into @tbl   select [SH].[SalaryHeadName], [CPD].[PeriodInTaxYear] as [PeriodId], [PR].[SalaryHeadId], [PR].[Irp5CodeId], [PR].[Amount]      from      (select [PeriodId], [SalaryHeadId], [PR].[Irp5CodeId], [Amount]       from [Payroll_PayrollResults] as [PR] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PR].[SalaryHeadID] and [SH].[Enabled] = 1       where ([TaxYear] = (case when @TaxYear <> '-1/0' then cast(right(@TaxYear, 4) as int) else 0 end)       and [EmployeeID] = @EmployeeId       --and [PR].[Irp5CodeId] in(      -- select [IRP5Code_ID] from [Payroll_IRP5code] with(nolock) where ([IRP5Code] in(@IRP5Code) and not ([TransactionTypeID] = 2 and [IRP5Code] = 0))      --)      AND (@IsRFI IS NULL OR PR.IsRFI = @IsRFI)     )      ) as [PR]       left outer join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PR].[SalaryHeadID]       left outer join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_Id] = [PR].[PeriodId]      order by [PeriodId], [SalaryHeadId]        --4116    --MEDICAL SCHEME FEES TAX CREDIT    if(@IRP5Code = '4116')    BEGIN     DECLARE @Irp5CodeId int = (select Irp5Code_id from Payroll_IRP5Code where IRP5Code = @IRP5Code)       INSERT INTO @tbl     Select 'MEDICAL SCHEME FEES TAX CREDIT',[Period],0,@Irp5CodeId,TaxCredits from Payroll_PayrollRun_History_Employees WHERE Employee_ID=@EmployeeID AND TaxYear=@TaxYear    END      --4120    --MEDICAL SCHEME FEES TAX CREDIT    if(@IRP5Code = '4120')    BEGIN     SET @Irp5CodeId = (select Irp5Code_id from Payroll_IRP5Code where IRP5Code = @IRP5Code)       INSERT INTO @tbl     Select 'SECONDARY MEDICAL SCHEME FEES TAX CREDIT',[Period],0,@Irp5CodeId,SecondaryMTC from Payroll_PayrollRun_History_Employees WHERE Employee_ID=@EmployeeID AND TaxYear=@TaxYear    END      DECLARE @BenefitTotal decimal(18,2)               IF(@IRP5Code not in ('4005','4003','4001'))    BEGIN     SELECT [SalaryHeadName] ,[PeriodId] ,[SalaryHeadId] ,[Irp5CodeId] ,[Amount]      FROM @tbl     WHERE Irp5CodeId in (select [IRP5Code_ID] from [Payroll_IRP5code] with(nolock) where ([IRP5Code] in(@IRP5Code) and not ([TransactionTypeID] = 2 and [IRP5Code] = 0)))     ORDER BY PeriodId    END    ELSE    IF (@IRP5Code = '4005')     BEGIN     SELECT [SalaryHeadName] ,[PeriodId] ,0, [SalaryHeadId] ,0 [Irp5CodeId] ,[Amount]     FROM @tbl     WHERE Irp5CodeId in (select [IRP5Code_ID] from [Payroll_IRP5code] with(nolock) where ([IRP5Code] in(@IRP5Code,'4474') and not ([TransactionTypeID] = 2 and [IRP5Code] = 0)))     ORDER BY PeriodId    END    IF (@IRP5Code = '4003')     BEGIN     SELECT [SalaryHeadName] ,[PeriodId] ,0, [SalaryHeadId] ,0 [Irp5CodeId] ,[Amount]     FROM @tbl     WHERE Irp5CodeId in (select [IRP5Code_ID] from [Payroll_IRP5code] with(nolock) where ([IRP5Code] in(@IRP5Code,'4473') and not ([TransactionTypeID] = 2 and [IRP5Code] = 0)))     ORDER BY PeriodId    END    IF (@IRP5Code = '4001')     BEGIN     SELECT [SalaryHeadName] ,[PeriodId] ,0, [SalaryHeadId] ,0 [Irp5CodeId] ,[Amount]     FROM @tbl     WHERE Irp5CodeId in (select [IRP5Code_ID] from [Payroll_IRP5code] with(nolock) where ([IRP5Code] in(@IRP5Code,'4472') and not ([TransactionTypeID] = 2 and [IRP5Code] = 0)))     ORDER BY PeriodId    END              end

GO

-- ============================================
-- SP: Payroll_GetCycleByEmployeeId_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- [Payroll_GetCycleByEmployeeId_sp] 83  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetCycleByEmployeeId_sp]   @EmployeeId Int  AS  BEGIN    Select top 1 Cycle_ID, CycleDesc,PeriodStartDate,PeriodEndDate,Period_ID From Const_Cycle   inner join Payroll_employee     on Payroll_employee.CycleID = Const_Cycle.Cycle_ID   join Payroll_CyclePeriodDetails on Payroll_CyclePeriodDetails.CycleID=Const_Cycle.Cycle_ID   where Payroll_employee.Employee_ID=@EmployeeId and Payroll_CyclePeriodDetails.Processed=0 and FinancialYear=(select top 1 KeyValue from AAAA_ConfigSettings where KeyName ='ActiveFinYear')   and CycleModeID=1   order by Payroll_CyclePeriodDetails.Period_ID asc  END

GO

-- ============================================
-- SP: Payroll_GetDataForEmployees_sp
-- Schema: dbo
-- ============================================
/*      -- =============================================      -- Author  :Varun Parvataneni      -- Create date :09/09/2016      -- Description :Return the Transactions from CostCenter table related to SalaryHead      -- Calls  :Payroll_GetDataForEmployees_sp 4      -- Changes  :Jaydev on dated 7-Nov-16 (add AddressIndicator, PostalPostOffice, PostalStreetID & added isnull in NatureOfPersonID)    -- Changes :Pavan on 25-July-17(Modified entire store procedure as per TP59598)      -- =============================================*/    CREATE PROCEDURE [dbo].[Payroll_GetDataForEmployees_sp]         @CycleID INT        AS        BEGIN                Select            [Employee_ID]             ,[EmpCode]                   ,[IdNo]                   ,[TitleID]                   ,[Initials]                   ,[FirstName]                   ,[Surname]             ,[DateOfBirth]                    ,ISNULL([addressIndicator],0) AS AddressIndicator             ,ISNULL([postalPostOffice],'') AS PostalPostOffice             ,ISNULL([postalStreetID],0) AS PostalStreetID             ,ISNULL([PhysicalStreetID],0) AS PhysicalStreetID             ,ISNULL([farmID],0) AS farmID                   ,[GenderID]                   ,[LanguageID]                   ,[PassportNumber]                   ,[PassportCountryID]                   ,[EmailAddress]                   ,[HomeNumber]                   ,[WorkNumber]                   ,[CellNumber]                   ,[FaxNumber]                   ,[JoiningDate]                    --,ISNULL([EndDate],GETDATE()) AS [EndDate]             ,[EndDate]                  ,[WorkOutside]                   ,[IncomeTaxNumber]                   ,[ExcludeUIF]                   ,[ExcludeSDL]                   ,[PhysicalAddress1]                   ,[PhysicalAddress2]                   ,[PhysicalPostalCode]                   ,[PhysicalCountryID]                   ,[PhysicalProvinceID]                   ,[PhysicalTownID]                   ,[PostalSameAsPhysical]                   ,[PostalAddress1]                   ,[PostalAddress2]                   ,[PostalPostalCode]                   ,[PostalCountryID]                   ,[PostalProvinceID]                   ,[PostalTownID]                   ,[WorkSameAsPhysical]                   ,[WorkSameAsCompany]                   ,[WorkAddress1]                   ,[WorkAddress2]                   ,[WorkPostalCode]                   ,[WorkCountryID]                   ,[WorkProvinceID]                   ,[WorkTownID]                   ,[PaymentTypeID]                   ,[AccountTypeID]                   ,[AccountHolderName]                   ,[AccountHolderRelationshipID]                   ,[AccountNumber]                   ,[BankID]                   ,[BranchID]                   ,[WHPM_Monthly]                   ,[WDPM_Monthly]                   ,[FixedSalary]                   ,[Enabled]                   ,[LeaveBased]                   ,[Monday]                   ,[Tuesday]                   ,[Wednesday]                   ,[Thursday]                   ,[Friday]                   ,[Saturday]                   ,[Sunday]                   ,[ShiftID]                   ,[AllowOverTime]                   ,[CycleID]                   ,[PayrollDefinitionGroupID]                   ,[EthnicGroupID]                   ,[IsMarried]                   ,[JobProfileID]                   ,[TerminationReasonID]                   ,[LeaveSchemeID]                   ,[MethodofCommunication]                   ,[EquityDisabled]                   ,[NotchId]                   ,[TaxCalculationType]                   ,[BonusCalculation]                   ,ISNULL([NatureOfPersonID],-1) AS [NatureOfPersonID]                   ,[PhysicalAddressTypeID]                   ,[PostalAddressTypeID]                   ,[QualificationID]                   ,[NewLabour]                   ,[Learners]                   ,[IsContractor]                   ,[BonusAmount]                   ,[PhysicalSuburbID]                   ,[PostalSuburbID]                   ,[WorkSuburbID]                   ,[ExcludeUIFNonContributorReasonID]                   ,[PackageAmount]                   ,[PackageOverriden]                   ,[DisabilityTypeID]                   ,[EmailAddressSecondary]         from Payroll_Employee where CycleID= @CycleID        END 

GO

-- ============================================
-- SP: Payroll_GetDataForInterviewSchedule_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,05/09/2018>  -- Description: <Description,,Get Data for interview Schedule>  -- =============================================  -- 2021/10/07 Charl E WI34880 add filter for shortlis only  -- 2021/10/07 Charl E WI34882 change contact details  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetDataForInterviewSchedule_sp] @ADVERTID   INT  AS  BEGIN      SET NOCOUNT ON;      SELECT DISTINCT             [ProspectiveEmployee_ID]           , (ISNULL([PPE].[FirstName], '') + ' ' + ISNULL([ppe].[SecondName], '') + ' ' + ISNULL([ppe].[Surname], '')) AS [EmployeeName]           , CASE                 WHEN [PPE].[MethodofCommunication] = 3                 THEN ISNULL([ppe].[CellNumber], '')+' - '+ISNULL([ppe].HomeNumber, '') +' - '+ISNULL([ppe].WorkNumber, '')                 ELSE ISNULL([ppe].[EmailAddress], '')+' - '+ISNULL([ppe].EmailAddressSecondary, '')             END AS [ContactDetails]      FROM [Payroll_CandidateShortListPage] AS [CS]           INNER JOIN [Payroll_EmployeeShortListPage] AS [PE] ON [PE].[CandidateShortListId] = [CS].[CandidateShortListID]           INNER JOIN [dbo].[Payroll_ProspectiveEmployee] AS [PPE] ON [PPE].[ProspectiveEmployee_ID] = [PE].[ProspectiveEmployeeId]      WHERE [CS].[AdvertId] = @ADVERTID            AND [PPE].[ProspectiveEmployee_ID] IN         (             SELECT [PISE].[ProspectiveEmployeeId]             FROM [payroll_InterviewSchedule] AS [PIS]                  INNER JOIN [dbo].[Payroll_InterviewScheduledEmployee] AS [PISE] ON [PISE].[InterviewScheduleId] = [PIS].[InterviewScheduleID]             WHERE [pis].[AdvertId] = @ADVERTID                   AND [PISE].[IsAvailable] = 1                   AND ISNULL([pe].[EmployeeShortList], 0) = 1         )  END

GO

-- ============================================
-- SP: Payroll_GetDataForPresentCandidate_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,05/09/2018>  -- Description: <Description,,Get Data for Present Candidate>  -- =============================================  CREATE PROCEDURE dbo.Payroll_GetDataForPresentCandidate_sp    @AdvertId INT  AS  BEGIN   SET NOCOUNT ON;       SELECT DISTINCT    PISE.EmployeeInterviewID,    ProspectiveEmployee_ID,     (ISNULL(PPE.FirstName,'')+ ' '+ ISNULL(ppe.SecondName,'')+ ' ' + ISNULL(ppe.Surname,'')) AS CandidateName,    (ISNULL(ppe.EmailAddress,'') +'-'+ ISNULL(ppe.CellNumber,'')) AS ContactDetails,    (CASE PISE.IsAvailable WHEN 1 THEN 'true' ELSE 'false' END)AS Available,     CAST(PISE.InterviewTime AS TIME) AS InterviewTime    FROM Payroll_CandidateShortListPage AS CS    INNER JOIN payroll_InterviewSchedule AS PIS ON PIS.AdvertId = CS.AdvertId    INNER JOIN dbo.Payroll_InterviewScheduledEmployee AS PISE ON  PISE.InterviewScheduleId = PIS.InterviewScheduleID    INNER JOIN dbo.Payroll_ProspectiveEmployee AS PPE ON PPE.ProspectiveEmployee_ID = PISE.ProspectiveEmployeeId    WHERE CS.AdvertId = @AdvertId AND PISE.IsAvailable = 1 AND  ISNULL(PISE.IsSuccessFul,0) != 1  END  

GO

-- ============================================
-- SP: Payroll_GetDatesofFilledpositionID_sp
-- Schema: dbo
-- ============================================
    -- =================================================================================================            -- Author:Varun Parvataneni       -- Create date: 28/10/2016          -- Description: Returns the least stardate and highestenddate on the filled position from positionhistory table        -- Exec [Payroll_GetDatesofFilledpositionID_sp] 4561  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetDatesofFilledpositionID_sp]    @PositionID INT  AS     BEGIN    Select Min(StartDate) as Startdate,Max(EndDate) as Enddate from Payroll_PositionHistory where PositionID =@PositionID and status=2    END  

