-- ============================================
-- SP: Payroll_GetDecimalColumnNamesFromPayrollEmployee_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: James Roodt  -- Create date:  2015-02-05  -- Description: Gets a dynamic list of all the column names in Payroll_Employee where the column type is Decimal  -- Payroll_GetDecimalColumnNamesFromPayrollEmployee_sp  -- =============================================  create PROCEDURE [dbo].[Payroll_GetDecimalColumnNamesFromPayrollEmployee_sp]    AS  BEGIN   SELECT COLUMN_NAME AS EmployeeFields FROM information_schema.columns   WHERE TABLE_NAME='Payroll_Employee'   AND DATA_TYPE='decimal'   ORDER BY ORDINAL_POSITION DESC  END  

