-- ============================================
-- SP: Payroll_GetDependantCount
-- Schema: dbo
-- ============================================
-- =======================================================================================================================  -- Author:  MEHUL PANCHAL  -- Create date: 04 03 2014  -- Description:   -- CALLS : --EXEC Payroll_GetDependantCount 1,1  -- 2015-01-19 James Roodt: check max child dependants according to @Max3ChildAmount  -- 2015-05-04 James Roodt: TP19167 Changed ActiveFinYear to ActivePayrollYear  -- 2015-06-23 Ravindra Jijotia: TP19741 New flag has been introduced to support maximum dependants feature.  -- 2015-08-14 Ravindra Jijotia: TP19740 Updated to consider termination date.  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- =======================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetDependantCount]   @EmployeeID INT  AS  BEGIN   DECLARE @CycleID INT   SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID      DECLARE @MemberCount INT = 1, @AdultCount INT, @ChildCount INT   DECLARE @AdultCountBefore INT, @ChildCountBefore INT   DECLARE @MaxDependantCount INT      DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)   SELECT @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND TaxYear = @TaxYear      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear     Select @AdultCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_EmployeeDependantDetails   WHERE Enable = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND Dependant = 1   AND CAST(DependedJoinDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND (TerminateDate > @ToDate OR TerminateDate is null)       IF(@AdultCount IS NULL) SET @AdultCount = 0       Select @AdultCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_EmployeeDependantDetails   WHERE Enable = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND Dependant = 1   AND DependedJoinDate < @FromDate AND (TerminateDate > @ToDate OR TerminateDate is null)      IF(@AdultCountBefore IS NULL) SET @AdultCountBefore = 0       SET @AdultCount = @AdultCount + @AdultCountBefore      Select @ChildCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_EmployeeDependantDetails   WHERE Enable = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND Dependant = 0   AND CAST(DependedJoinDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND (TerminateDate > @ToDate OR TerminateDate is null)      IF(@ChildCount IS NULL) SET @ChildCount = 0      Select @ChildCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_EmployeeDependantDetails   WHERE Enable = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND Dependant = 0   AND DependedJoinDate < @FromDate AND (TerminateDate > @ToDate OR TerminateDate is null)      IF(@ChildCountBefore IS NULL) SET @ChildCountBefore = 0       SET @ChildCount = @ChildCount + @ChildCountBefore     DECLARE @IsMaxDependantChildEnabled bit     --Get Max dependants allowed by medical aid   SELECT  @MaxDependantCount = isnull(cmsd.MaxDependantCount, 0), @IsMaxDependantChildEnabled = ISNULL(cmsd.IsMaxDependantChildEnabled, 0)   FROM Payroll_EmployeeMedicalAIDDetail as pemsd   inner join Const_MedicalAIDScheme as cms on cms.MedicalScheme_ID=pemsd.MedicalAidSchmeID   inner join Const_MedicalAIDSchemeDetail as cmsd on cmsd.MedicalSchemeID=cms.MedicalScheme_ID   WHERE pemsd.Enable = 1 AND pemsd.EmployeeID=@EmployeeID     --If IsMaxDependantChildEnabled is true, Child Count will come from saved value as MaxDependantCount in Const_MedicalAIDSchemeDetail table.   IF @IsMaxDependantChildEnabled = 1   BEGIN    IF @ChildCount > @MaxDependantCount     SET @ChildCount = @MaxDependantCount   END   --If IsMaxDependantChildEnabled is false, Adult Count & Child Count will be caluculated based on MaxDependantCount in Const_MedicalAIDSchemeDetail table.   -- Sum of AdultCount & ChildCount will not be more than the MaxDependantCount.   ELSE IF @IsMaxDependantChildEnabled = 0   BEGIN    IF ((@MaxDependantCount - @AdultCount) > 0)    BEGIN     DECLARE @Temp INT       SET @Temp = (@MaxDependantCount - @AdultCount)       IF ((@Temp - @ChildCount) < 0)     BEGIN      SET @ChildCount = @Temp     END    END    ELSE IF ((@MaxDependantCount - @AdultCount) < 0)    BEGIN     SET @AdultCount = @MaxDependantCount     SET @ChildCount = 0    END    ELSE IF ((@MaxDependantCount - @AdultCount) = 0)    BEGIN     SET @ChildCount = 0    END   END        SELECT @AdultCount AS Adult, @ChildCount AS Child  END  

GO

-- ============================================
-- SP: Payroll_GetDependantCountWhereEmployerContribute_sp
-- Schema: dbo
-- ============================================
-- =======================================================================================================================  -- Author  : Ravindra Jijotia - TP19740  -- Create date : 22 July 2015  -- Description : Get total AdultCount & ChildCount where employer contribute regardless of   --     MaxDependantCount & IsMaxDependantChildEnabled values.  -- CALLS  : EXEC [Payroll_GetDependantCountWhereEmployerContribute_sp] 7  -- 23-07-2015 : [Name]: [TPID] [Change Description]  -- 2015-08-14 : Ravindra Jijotia: TP19740 Updated to consider termination date.  -- 2016-08-19 : Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return DependantCount for Adult WHERE IsAdultDependant =1 and count for Child WHERE IsChildDependant=1  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =======================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetDependantCountWhereEmployerContribute_sp]   @EmployeeID INT  AS  BEGIN    DECLARE @CycleID INT   SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID      DECLARE @MemberCount INT = 1, @AdultCountEmployerContribute INT, @ChildCountEmployerContribute INT   DECLARE @AdultCountBefore INT, @ChildCountBefore INT   DECLARE @MaxDependantCount INT      DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)   SELECT  @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND TaxYear = @TaxYear      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear     Select @AdultCountEmployerContribute = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND IsMedAidEmployerContribute = 1 AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)       IF(@AdultCountEmployerContribute IS NULL) SET @AdultCountEmployerContribute = 0       Select @AdultCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND MedAidJoiningDate < @FromDate AND IsMedAidEmployerContribute = 1 AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)      IF(@AdultCountBefore IS NULL) SET @AdultCountBefore = 0       SET @AdultCountEmployerContribute = @AdultCountEmployerContribute + @AdultCountBefore      Select @ChildCountEmployerContribute = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND IsMedAidEmployerContribute = 1 AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)     IF(@ChildCountEmployerContribute IS NULL) SET @ChildCountEmployerContribute = 0      Select @ChildCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND MedAidJoiningDate < @FromDate AND IsMedAidEmployerContribute = 1 AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)      IF(@ChildCountBefore IS NULL) SET @ChildCountBefore = 0       SET @ChildCountEmployerContribute = @ChildCountEmployerContribute + @ChildCountBefore         SELECT @AdultCountEmployerContribute AS Adult, @ChildCountEmployerContribute AS Child  END  

GO

