CREATE PROCEDURE [dbo].[Payroll_GetDisciplinaryRepresetativeDetails]        @DisciplinaryID int  AS     BEGIN   SELECT   PET.FirstName, PET.Employee_ID,PET.EmpCode,PET.Surname,PET.PassportNumber,PET.IdNo   FROM dbo.Payroll_Employee PET   LEFT JOIN Payroll_Disciplinary DIS ON PET.Employee_ID = DIS.RepresentedByEmpID   WHERE  DIS.Disiplinary_ID = @DisciplinaryID     END

