-- ============================================
-- SP: Payroll_GetDisiplinaryDocument
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  GD  -- Create date: 15 Mar 2014  -- Description: Gets a list of all document relating to the specified disciplinary  -- Call SP:  Payroll_GetDisiplinaryDocument 3  -- 2015-03-13 James Roodt: Changed date format from 101 (MMddyyyy) to 103 (ddMMyyyy)  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetDisiplinaryDocument]   @DisiplinaryID INT  AS  BEGIN   SELECT (ROW_NUMBER() OVER (ORDER BY P_D.Document_Id)) - 1 AS Document_Id, DocumentName, CONVERT(nvarchar(50), ISNULL(P_D.DateModified, P_D.DateCaptured), 103) as DocDate, 0 as IsNew, ISNULL(P_E1.FirstName, P_E.FirstName) AS UploadedBy FROM Payroll_DisciplinaryDocumentDetails AS P_D   INNER JOIN User_UserDetail AS P_E ON P_E.User_ID = P_D.CapturerID   LEFT OUTER JOIN User_UserDetail AS P_E1 ON P_E1.User_ID = P_D.ModifierID   WHERE P_D.Enabled = 1 AND DisiplinaryId = @DisiplinaryID  END    

GO

-- ============================================
-- SP: Payroll_GetDivisionTree
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetDivisionTree] @departmentId int = null, @divisionId int = null, @divisionItem varchar(200) = null, @levelId int = null, @levelCount int = null, @excludeDivisionId bit = 0, @excludePostingLevel bit = 0  as    begin     set nocount on;     with [DivisionTree] as (      select 0 as [Index], [Division_ID], [DivisionCode], [DivisionDesc], [DivisionParentID]       from [Const_Division] as [CD] with(nolock)       where ([Enabled] = 1 and [DepartmentID] = (case when @departmentId is null then [DepartmentID] else @departmentId end) and [Division_ID] = (case when @divisionId is null and [DivisionParentID] is null then [Division_ID] else @divisionId end) and [DivisionDesc] = (case when @divisionItem is null then [DivisionDesc] else @divisionItem end))      union all      select [DT].[Index] + 1, [CD].[Division_ID], [CD].[DivisionCode], [CD].[DivisionDesc], [CD].[DivisionParentID]       from [Const_Division] as [CD] with(nolock)        join [DivisionTree] as [DT] on [DT].[Division_ID] = [CD].[DivisionParentID]       where ([CD].[Enabled] = 1 and not [CD].[DivisionParentID] is null)     )     select (dense_rank() over (order by [Index]) - 1) as [Index], [Division_ID], [DivisionCode], [DivisionDesc], [DivisionParentID], [PostingLevel]      from (       select [Index], [Division_ID], [DivisionCode], [DivisionDesc], [DivisionParentID], (case         when coalesce((select count([DivisionParentID])           from [DivisionTree]           where ([DivisionParentID] = [DT].[Division_ID])         ), 0) > 0 then 'No'        else 'Yes' end) as [PostingLevel]        from [DivisionTree] as [DT]      ) as [DT]      where (       (case        when isnull(@excludePostingLevel, 0) = 1 and [PostingLevel] = 'No' then 1        when isnull(@excludePostingLevel, 0) = 0 then 1       else 0 end) = 1 and       (case        when isnull(@excludeDivisionId, 0) = 1 and ([Index] > 0 or ([Index] = 0 and isnull(@excludePostingLevel, 0) = 0 and [PostingLevel] = 'Yes')) then 1        when isnull(@excludeDivisionId, 0) = 0 then 1       else 0 end) = 1 and       (case        when @levelId is null and @levelCount is null then 1        when @levelId is null and not @levelCount is null and [DT].[Index] < (case when @divisionId is null then @levelCount - 1 else @levelCount end) then 1        when not @levelId is null and not @levelCount is null and [DT].[Index] >= @levelId and [DT].[Index] < (@levelID + (case when @divisionId is null then @levelCount - 1 else @levelCount end)) then 1       else 0 end) = 1      )      order by [DivisionParentID], [Index], [Division_ID], [DivisionCode], [DivisionDesc]       option (maxrecursion 99);     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetEFTPaymentInstructions
-- Schema: dbo
-- ============================================
  /*   20211115 - Ruan - WI59291 - Changed the "Changed" column and how value is determined  */  CREATE procedure [dbo].[Payroll_GetEFTPaymentInstructions] @BatchID int  as    begin     declare @CycleID int, @LastPeriodProcessed int, @PeriodID int, @StartDate datetime, @EndDate datetime, @PeriodInTaxYear int      select top 1      @PeriodInTaxYear =[PeriodInTaxYear],     @CycleID = [CycleID] , @PeriodID = [CP].[Period_ID], @EndDate = [CP].PeriodEndDate, @StartDate = [CP].[PeriodStartDate]      from [Payroll_PaymentInstructions] [PP]      Join Payroll_CyclePeriodDetails [CP] on [PP].[PeriodID] = [CP].Period_ID       where [BatchID] = @BatchID           if @PeriodInTaxYear != 1       select top 1  @LastPeriodProcessed = [CP].Period_ID, @StartDate = [CP].PeriodStartDate from Payroll_CyclePeriodDetails [CP] where [CP].[CycleID] = @CycleID AND Period_ID <> @PeriodID and [PeriodInTaxYear] =(@PeriodInTaxYear -1) order by [CP].ProcessedDate desc      SELECT    pi.[PaymentInstructions_ID],    pi.[ApprovalStatus],    CASE WHEN ISNULL(pi.[Include], 1) = 1 THEN 'Approved' else 'Excluded' end AS 'Approved',    pi.[DeclinedReason],    pi.[TransactionID],    CAST(cb.[DocTypeCode] AS VARCHAR(5)) + '/' + cb.[DocNumber] AS 'DocNumber',    pi.[EmployeeID],    pi.[EmployeeName],    CAST(CASE     WHEN pi.[EmployeeName] <> aa.[EmployeeName]      OR pi.[EmployeeBankName] <> aa.[EmployeeBankName]      OR pi.[EmployeeBankAccountNumber] <> aa.[EmployeeBankAccountNumber]      OR pi.[EmployeeBankBranchCode] <> aa.[EmployeeBankBranchCode]      OR pi.[EmployeeBankAccountType] <> aa.[EmployeeBankAccountType]      OR pi.[IsBankDetailChanged] = 1       OR pi.[Changed] = 1 THEN 1     ELSE 0    END AS BIT) AS 'Changed',    pt.[PaymentTypeDesc] AS 'Employee_BankAccountType',    pi.[EmployeeBankName],    pi.[EmployeeBankAccountNumber],    pi.[EmployeeBankBranchCode],    pi.[InvoiceTotalAmount],    ISNULL(pi.[InstructionsStatus], 'New') AS 'InstructionsStatus',    pi.[PeriodID]   FROM    Payroll_PaymentInstructions pi   INNER JOIN    Payroll_Employee e ON pi.[EmployeeID] = e.[Employee_ID]   INNER JOIN    Const_PaymentType pt ON e.[PaymentTypeID] = pt.[PaymentType_ID]   OUTER APPLY    (     SELECT TOP 1      *     FROM      Payroll_PaymentInstructions ipi     WHERE      ipi.[EmployeeID] = pi.[EmployeeID]     AND ipi.[TransactionDate] < pi.[TransactionDate]     ORDER BY      ipi.[TransactionDate] DESC    ) aa   LEFT JOIN    Led_Cashbook cb ON pi.[TransactionID] = cb.[TransactionID]   WHERE    pi.[BatchID] = @BatchID    end

GO

-- ============================================
-- SP: Payroll_GetEmployee3rdPartyList
-- Schema: dbo
-- ============================================
--[dbo].[Payroll_GetEmployee3rdPartyList] '','','',24  CREATE procedure [dbo].[Payroll_GetEmployee3rdPartyList]    @Name NVARCHAR(100),   @Surname NVARCHAR(100),   @IDNo NVARCHAR(30),   @VendorID int  as  BEGIN   DECLARE @TempTbl TABLE   (    Employee3rdPatry_ID INT ,    VendorID NVARCHAR(50),    EmployeeID NVARCHAR(50),    [Enabled] BIT,    VendorName NVARCHAR(50),    IdNo NVARCHAR(50),    Surname NVARCHAR(500),    FirstName NVARCHAR(50)   )     declare @sql NVARCHAR(MAX)   set @sql = 'select epd.Employee3rdPatry_ID, epd.VendorID,dbo.BufferString_fxn(CONVERT(VARCHAR,(epd.EmployeeID)), 8, ''0'') as Employee_ID , epd.Enabled,        const.VendorName, emp.IdNo, emp.Surname, emp.FirstName       from Payroll_Employee3rdPartyDetails epd      inner join Payroll_Employee emp on emp.Employee_ID = epd.EmployeeID      inner join Cons_Vendor const on const.Vendor_ID = epd.VendorID      where 1=1 '      if(@Name is not null and LEN(@Name)>0)   BEGIN    set @sql = @sql + 'and emp.FirstName = '''+@Name+''' '   END   if(@Surname is not null and LEN(@Surname)>0)   BEGIN    set @sql = @sql + 'and emp.Surname = '''+@Surname+''' '   END   if(@IDNo is not null and LEN(@IDNo)>0)   BEGIN    set @sql = @sql + 'and emp.IdNo = '''+@IDNo+''' '   END   if(@VendorID is not null and @VendorID >0)   BEGIN    set @sql = @sql + 'and epd.VendorID = '+ Convert(varchar(50),@VendorID)   END   SET @sql = @sql +'Order by emp.Employee_ID'   INSERT INTO @TempTbl    EXEC(@sql)         SELECT * FROM @TempTbl  END

GO

-- ============================================
-- SP: Payroll_GetEmployeeAccountByEmpID
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,12 Sep 2014>  -- Description: <Description,,Get employee Account By ID>  -- Call SP    : Payroll_GetEmployeeAccountByEmpID 18  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeAccountByEmpID] @EmployeeID INT  AS       BEGIN          SELECT  EAD.ID, EAD.SequenceNo, EAD.Enabled, Emp.FirstName, Emp.Surname, Emp.FirstName + ' ' + Emp.Surname AS EmpName, IdNo, Emp.CellNumber, Emp.FaxNumber, Emp.EmailAddress, ISNULL(Name.Surname_Company, '') + ' ' + ISNULL(Name.FirstNames, '') AS AccountHolderName, dbo.BufferString_fxn(Acc.Account_ID, 12, '0') AS AccountNo, CU.SGNumber, dbo.BufferString_fxn(Cu.Unit_ID, 12, '0') AS PropertId, S.StatusDesc, dbo.GetAddress(CU.Unit_ID) AS [Address]          FROM    dbo.Payroll_EmployeeAccountDetails AS EAD                  INNER JOIN dbo.Payroll_Employee AS Emp ON EAD.EmployeeID = Emp.Employee_ID                  INNER JOIN dbo.Cons_Account AS Acc ON EAD.AccountID = Acc.Account_ID                  INNER JOIN dbo.Cons_Name AS Name ON Acc.NameID = Name.Name_ID                  INNER JOIN dbo.Cons_Unit CU ON CU.Unit_ID = ACC.UnitID                  INNER JOIN dbo.Const_Status S ON S.Status_ID = ACC.AccountStatusID          WHERE   Emp.Employee_ID = @EmployeeID          ORDER BY EAD.SequenceNo      END  

GO

-- ============================================
-- SP: Payroll_GetEmployeeAllowanceDetail_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Ivan Myroshnychenko  -- Create date: 08/01/2021  -- Description:   -- CALLS : EXEC [dbo].[[Payroll_GetEmployeeAllowanceDetail_sp] '2020/2021',0,0,0,(1-3),'0'  -- '2020/2021' - TaxYear  -- 0 - Cycle ID  -- 0 - Department ID  -- 0 - Division ID  -- (1-3) - Status, 1- All employees, 2 - Inactive employees, 3 - Active employees  -- '0' - Transactions SalaryHeadID (e.g. '54' or '54,56') of the selected Company Contributions and Earning Salary Transaction.  --      0 - Default value  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeAllowanceDetail_sp]      @TaxYear NVARCHAR(MAX),      @CycleID INT,      @DepartmentID INT,      @DivisionID INT,          @Status INT,      @SalaryHeadIDs NVARCHAR(MAX)  AS  BEGIN    DECLARE @PurposeTaxYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    DROP TABLE IF EXISTS #Amount   CREATE TABLE #Amount   (  EmployeeID INT,  SalaryTitle NVARCHAR(MAX),  IRP5Code INT,  Amount FLOAT,  CycleID INT  )      INSERT INTO #Amount (EmployeeID, SalaryTitle, IRP5Code, Amount, CycleID)   SELECT P_E.Employee_ID    , P_SH.SalaryHeadName    , P_PR.IRP5Code    , SUM(P_PR.Amount)   , P_PR.CycleID   FROM Payroll_Employee AS P_E   JOIN Payroll_PayrollResults AS P_PR    ON P_E.Employee_ID = P_PR.EmployeeID   JOIN Payroll_SalaryHead AS P_SH    ON P_PR.SalaryHeadID = P_SH.SalaryHead_ID    WHERE P_PR.TaxYear = @PurposeTaxYear    AND P_PR.SalaryHeadID IN (SELECT CAST(value AS INT) FROM STRING_SPLIT(@SalaryHeadIDs, ','))    AND (@CycleID = 0 OR @CycleID = P_PR.CycleID)    AND (@DepartmentID= 0 OR @DepartmentID = P_PR.DepartmentID)    AND (@DivisionID= 0 OR @DivisionID = P_PR.DivisionID)     GROUP BY P_E.Employee_ID, P_SH.SalaryHeadName, P_PR.IRP5Code, P_PR.CycleID   ORDER BY P_E.Employee_ID    DROP TABLE IF EXISTS #Current  CREATE TABLE #Current  (  EmployeeID INT,  SalaryTitle NVARCHAR(MAX),  IRP5Code INT,  Amount FLOAT,  CycleID INT  )        INSERT INTO #Current (EmployeeID, SalaryTitle, IRP5Code, Amount, CycleID)   SELECT P_E.Employee_ID AS EmployeeNumber   , P_SH.SalaryHeadName AS SalaryTitle   , P_TR.IRP5Code AS IRP_5_Code   , P_TR.Amount AS Amount    , P_TR.CycleID   FROM Payroll_Employee AS P_E   JOIN Payroll_TrialResults AS P_TR    ON P_E.Employee_ID = P_TR.EmployeeID   JOIN Payroll_SalaryHead AS P_SH    ON P_TR.SalaryHeadID = P_SH.SalaryHead_ID   WHERE P_TR.SalaryHeadID IN (SELECT CAST(value AS INT) FROM STRING_SPLIT(@SalaryHeadIDs, ','))    AND (@CycleID = 0 OR @CycleID = P_TR.CycleID)    AND (@DepartmentID= 0 OR @DepartmentID = P_TR.DepartmentID)    AND (@DivisionID= 0 OR @DivisionID = P_TR.DivisionID)      DROP TABLE IF EXISTS #InactiveEmployee  CREATE TABLE #InactiveEmployee  (EmployeeID INT)    INSERT INTO #InactiveEmployee  SELECT DISTINCT P_E.Employee_ID AS EmployeeID   FROM Payroll_Employee AS P_E    LEFT JOIN Payroll_EmployeeTermination AS P_ET     ON P_E.Employee_ID = P_ET.EmployeeID   WHERE P_E.EndDate < GETDATE() OR P_ET.Complete = 1    DROP TABLE IF EXISTS #Results  CREATE TABLE #Results  (EmployeeNumber INT  , Initials NVARCHAR(MAX)  , Surname NVARCHAR(MAX)  , Department NVARCHAR(MAX)  , Division NVARCHAR(MAX)  , Position NVARCHAR(MAX)  , SalaryTransaction NVARCHAR(MAX)  , IRP_5_Code INT  , CurrentAmount FLOAT  , YearToDate FLOAT  )    INSERT INTO #Results(EmployeeNumber, Initials, Surname, Department, Division, Position, SalaryTransaction, IRP_5_Code, CurrentAmount, YearToDate)  SELECT P_E.Employee_ID AS EmployeeNumber  , P_E.Initials AS Initials  , P_E.Surname AS Surname  , C_DEP.DepartmentDesc AS Department  , C_DIV.DivisionDesc AS Division  , P_JP.JobTitle AS Position  , #Amount.SalaryTitle AS SalaryTransaction  , #Amount.IRP5Code AS IRP_5_Code  , 0 AS CurrentAmount  , #Amount.Amount AS YearToDate  FROM Payroll_Employee AS P_E  JOIN Payroll_Position AS P_P   ON P_E.PositionID = P_P.Position_ID  JOIN Payroll_JobProfile AS P_JP   ON P_P.JobProfileID = P_JP.JobProfile_ID  JOIN Const_Division AS C_DIV   ON P_P.DivisionID = C_DIV.Division_ID  JOIN Const_Department AS C_DEP   ON P_P.DepartmentID = C_DEP.Department_ID  JOIN #Amount    ON P_E.Employee_ID = #Amount.EmployeeID  WHERE (@Status = 1     OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))     OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))       ORDER BY P_E.Employee_ID    INSERT INTO #Results(EmployeeNumber, Initials, Surname, Department, Division, Position, SalaryTransaction, IRP_5_Code, CurrentAmount, YearToDate)  SELECT P_E.Employee_ID AS EmployeeNumber  , P_E.Initials AS Initials  , P_E.Surname AS Surname  , C_DEP.DepartmentDesc AS Department  , C_DIV.DivisionDesc AS Division  , P_JP.JobTitle AS Position  , #Current.SalaryTitle AS SalaryTransaction  , #Current.IRP5Code AS IRP_5_Code  , #Current.Amount  , 0 AS YearToDate  FROM Payroll_Employee AS P_E  JOIN Payroll_Position AS P_P   ON P_E.PositionID = P_P.Position_ID  JOIN Payroll_JobProfile AS P_JP   ON P_P.JobProfileID = P_JP.JobProfile_ID  JOIN Const_Division AS C_DIV   ON P_P.DivisionID = C_DIV.Division_ID  JOIN Const_Department AS C_DEP   ON P_P.DepartmentID = C_DEP.Department_ID  JOIN #Current    ON P_E.Employee_ID = #Current.EmployeeID  WHERE (@Status = 1     OR (@Status = 2 AND P_E.Employee_ID IN (SELECT * FROM #InactiveEmployee))     OR (@Status = 3 AND P_E.Employee_ID NOT IN (SELECT * FROM #InactiveEmployee)))           SELECT dbo.BufferString_fxn(EmployeeNumber, 8, '0') AS EmployeeNumber   , Initials   , Surname   , Department   , Division   , Position   , SalaryTransaction   , IRP_5_Code   , SUM(CurrentAmount) AS CurrentAmount  , SUM(YearToDate) AS YearToDate  FROM #Results  WHERE CurrentAmount > 0 OR YearToDate > 0  GROUP BY EmployeeNumber   , Initials   , Surname   , Department   , Division   , Position   , SalaryTransaction   , IRP_5_Code   ORDER BY EmployeeNumber      DROP TABLE IF EXISTS #InactiveEmployee  DROP TABLE IF EXISTS #Amount   DROP TABLE IF EXISTS #Current  DROP TABLE IF EXISTS #Results  END

GO

-- ============================================
-- SP: Payroll_GetEmployeeBankDetailHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 25/09/2018   Description : Get a list of bank detail history transactions per employee   Payroll_GetEmployeeBankDetailHistory_sp 1  */  Create procedure [dbo].[Payroll_GetEmployeeBankDetailHistory_sp]    @EmployeeId int  as    begin    select [empHist].[Enabled],[empHist].[IsApproved], [empHist].[AccountDetailHistory_ID], [emp].[Employee_ID], [emp].[EmpCode], [emp].[Surname],[emp].[FirstName] + ' ' + [emp].[SecondName] + ' ' As FullName,[ptype].[PaymentTypeDesc],[acctype].[BankAccountType],[emphist].[AccountNumber],[cbank].[BankDesc],[cbranch].[BankBranchCode],[cbranch].[BranchCodeDesc],[emphist].[AccountHolderName], [accrelation].[AccountHolderRelation],[emphist].[StartDate],[emphist].[EndDate]     from [dbo].[Payroll_EmployeeAccountDetailHistory] emphist     left outer join [dbo].[Payroll_Employee] emp on [emp].[Employee_ID] = [emphist].[EmployeeId]     left outer join [dbo].[Const_PaymentType] ptype on [ptype].[PaymentType_ID] = [emphist].[PaymentTypeID]     left outer join [dbo].[Const_AccountHolderRelation_sys]  accrelation on [accrelation].[AccHolderRelation_ID] = [emphist].[AccountHolderRelationshipID]     left outer join [dbo].[Const_BankAccountType] acctype on [acctype].[BankAccountTypeID] = [emphist].[AccountTypeID]     left outer join [dbo].[Const_Bank] cbank on [cbank].[Bank_ID] = [emphist].[BankID]     left outer join [dbo].[Const_BankBranchCode] cbranch on [cbranch].[BankBranchCode_ID] = [emphist].[BranchID]      where [emphist].[EmployeeId] = @EmployeeId  end     

GO

-- ============================================
-- SP: Payroll_GetEmployeeBenefitDetail_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 10 March 2014  -- Description:   -- Call : [Payroll_GetEmployeeBenefitDetail_sp] 36,5  -- 2016-09-15 TP44504 Lungisani Khumalo : modified all calculating to exclude the 'IsPrivate' column  -- 2021/09/27 - Fix SP for Private Funds  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeBenefitDetail_sp]  @EmployeeID INT   ,@BenegitTypeID INT   AS  BEGIN   SELECT        EMA.EmployeeBenefit_ID,     EMA.BenefitSchemeID,     CONVERT(NVARCHAR(12),EMA.JoinDate, 103) AS JoinDate,    CONVERT(NVARCHAR(12),EMA.TerminationDate, 103) AS TerminationDate,    V.VendorName AS Fund,    MS.FundName AS PLANName,    EMA.ReferenceNo,    'No' AS ISPrivate,    CASE WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  < CAST(GETDATE() AS DATE ) THEN 'Terminated'      WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )  THEN 'Active'       WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  >= CAST(GETDATE() AS DATE ) THEN 'Pending'    ELSE '' END  AS STATUS,    CASE WHEN IsCurrent = 1 THEN 'Yes' ELSE 'No' END AS CurrentStatus,    NULL as Amount   FROM dbo.Payroll_EmpBenefitDetail EMA    LEFT JOIN dbo.Payroll_BenefitDetail MS ON MS.Benefit_ID = EMA.BenefitSchemeID    LEFT JOIN dbo.Cons_Vendor V ON V.Vendor_ID = MS.VendorID   WHERE EMA.EmployeeId = @EmployeeID AND EMA.Enabled=1 AND MS.BenefitTypeID=@BenegitTypeID And IsPrivate = 0   UNION    SELECT        EMA.EmployeeBenefit_ID,     EMA.BenefitSchemeID,     CONVERT(NVARCHAR(12),EMA.JoinDate, 103) AS JoinDate,    CONVERT(NVARCHAR(12),EMA.TerminationDate, 103) AS TerminationDate,    'Private Fund',    '',    EMA.ReferenceNo    ,'Yes' ISPrivate,    CASE WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  < CAST(GETDATE() AS DATE ) THEN 'Terminated'      WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )  THEN 'Active'       WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  >= CAST(GETDATE() AS DATE ) THEN 'Pending'    ELSE '' END  AS STATUS,    CASE WHEN IsCurrent = 1 THEN 'Yes' ELSE 'No' END AS CurrentStatus,    EMA.EmployeeContribution As Amount   FROM dbo.Payroll_EmpBenefitDetail EMA   WHERE EMA.EmployeeId = @EmployeeID AND EMA.Enabled=1 AND EMA.BenefitSchemeID=@BenegitTypeID And IsPrivate = 1  END

GO

-- ============================================
-- SP: Payroll_GetEmployeeBenefitSchemeDetail_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 26 12 2013  -- Description: <Description,,>  -- [dbo].[Payroll_GetEmployeeBenefitSchemeDetail_sp] 18  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeBenefitSchemeDetail_sp]   @EmployeeID INT   AS  BEGIN   SET NOCOUNT ON;      SELECT     PEBD.BenefitSchemeID, PEBD.EmployeeBenefitDetail_ID, PEBD.BenefitTypeID, CBTs.BenefitType,    CASE WHEN PEBD.ContributionType = 1 THEN      '%'     ELSE      'Fixed' END     AS ContributionType,    PEBD.ContributionValue, ISNULL(PEBD.FundName, '') AS FundName    ,PEBD.Amount1 AS 'MinValue'    ,PEBD.Amount2 AS 'MaxValue'   FROM dbo.Payroll_EmployeeBenefitDetail AS PEBD     INNER JOIN Const_BenefitScheme AS CBS ON PEBD.BenefitSchemeID = CBS.BenefitScheme_ID      INNER JOIN dbo.Const_BenefitType_sys AS CBTs ON PEBD.BenefitTypeID = CBTs.BenefitType_ID   WHERE PEBD.EmployeeID = @EmployeeID AND PEBD.BenefitTypeID NOT IN (2,6) AND ContributionFor = 1  END  

GO

-- ============================================
-- SP: Payroll_GetEmployeeCalendarWeeks
-- Schema: dbo
-- ============================================
  /*   Author  : Richa Mills   Create date : 2018/07/31   Description : Get EmployeeCalendar Weeks   exec Payroll_EmployeeCalendarWeeks    */  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeCalendarWeeks]    @Day varchar(50),  @EmployeeId int     as  begin    DECLARE @ShiftRotationId int = (Select ShiftRotationID from Payroll_Employee where Employee_ID = @EmployeeId)  DECLARE @Query varchar(max)    Select @Query = 'select CS.Shift_ID,Cs.ShortDesc,CS.StartDate,Cs.EndDAte,Cs.ShiftHOur,CS.NightHours,WeekNo from Payroll_ShiftRotation SR    join Payroll_ShiftRotationDetail SRD on SRD.ShiftRotationID = SR.ShiftRotation_ID    join Const_Shift CS on CS.Shift_ID = SRD.' + @Day + ' where SR.ShiftRotation_ID = ' + cast(@ShiftRotationID as varchar(10))     Exec (@Query)      end        

GO

-- ============================================
-- SP: Payroll_GetEmployeeDetailsByJobProfile_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- calls : Payroll_GetEmployeeDetailsByJobProfile_sp 1  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  --Payroll_GetEmployeeDetailsByJobProfile_sp 1  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeDetailsByJobProfile_sp]    @JobProfileID INT  AS  BEGIN    DECLARE @Result NVARCHAR(MAX)  DECLARE @NewLineChar AS CHAR(2) = CHAR(13) + CHAR(10)  DECLARE @ID NVARCHAR(max)  --SELECT  @ID =STUFF((SELECT ','+ convert(nvarchar,JobProfile_ID) FROM  Payroll_JobProfile    --WHERE   JobProfile_ID = @JobProfileID or ToWomDoesThisPositionReport = @JobProfileID   FOR XML PATH('')),1,1,'')    --PRINT @id         --Nidhi start       DECLARE @ResultSet TABLE(     [JobProfileID] INT)         ; WITH cte AS    (    SELECT  p.JobProfile_ID,p.ToWomDoesThisPositionReport    FROM Payroll_JobProfile p    WHERE JobProfile_ID = @JobProfileID --or ToWomDoesThisPositionReport = 1     UNION ALL    SELECT  p.JobProfile_ID,p.ToWomDoesThisPositionReport    FROM Payroll_JobProfile p         JOIN cte c ON p.ToWomDoesThisPositionReport =c.JobProfile_ID    ) INSERT INTO @ResultSet SELECT JobProfile_ID FROM cte      --DECLARE @listStr  NVARCHAR(MAX)   --SELECT @ID = COALESCE(@ID + ', ','') + CONVERT(NVARCHAR(50),[JobProfileID])   --        FROM @ResultSet      SELECT  @ID =STUFF((SELECT ','+ convert(nvarchar,JobProfileID) FROM @ResultSet  FOR XML PATH('')),1,1,'')    PRINT @ID         --nidhi end--   SELECT cast((ISNULL(PAY_JOB.ToWomDoesThisPositionReport,0)) as INT) AS SRNO ,PAY_JOB.JobTitle,(Select dbo.GetEmployeeDetails(PAY_EMP.Employee_ID))  AS FirstName, PAY_EMP.Surname,PAY_JOB.JobProfile_ID,PAY_EMP.Employee_ID    ,PAY_EMP.ImagePath ,GenderID   FROM Payroll_Employee PAY_EMP     INNER JOIN Payroll_Position PP ON PAY_EMP.PositionID =PP.Position_ID     INNER JOIN Payroll_JobProfile PAY_JOB ON PP.JobProfileID =PAY_JOB.JobProfile_ID    WHERE (PAY_JOB.JobProfile_ID =@JobProfileID OR @JobProfileID =0)     OR (PAY_JOB.ToWomDoesThisPositionReport IN (SELECT  Value FROM [Split_fxn](@ID,',')))    AND PAY_EMP.IsDummy =0 AND PAY_EMP.Enabled =1    order by SRNo ASC  END    

GO

-- ============================================
-- SP: Payroll_GetEmployeeDetailsForMedicalAidDates
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Phuti Chokoe  -- Create date: 17 - Sep - 2016  -- Description: [Payroll_GetEmployeeDetailsForMedicalAidDates] 15  -- =============================================  CREATE proc [dbo].[Payroll_GetEmployeeDetailsForMedicalAidDates]  @EmployeeID INT  as  select  e.JoiningDate, tp.StartDate, tp.EndDate from Payroll_Employee e  inner join Const_Payroll_TaxPeriods as tp on tp.cycleID = e.CycleID  where e.Employee_ID = @EmployeeID  and tp.Enable = 1  and e.Enabled = 1    

