-- ============================================
-- SP: Payroll_GetEmployeeDisableSalaryHeads_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetEmployeeDisableSalaryHeads_sp]  as    BEGIN  declare @StartCycle int,@CountCyle int  declare @CycleID int  declare @PeriodStartDate datetime,@PeriodEndDate datetime  set @StartCycle = 1      DECLARE @tmpCycleTable TABLE  (    ID INT IDENTITY(1, 1) PRIMARY KEY ,              CycleID int  )    Declare @tmpDisableSalaryHeadDataTable TABLE  (    ID INT IDENTITY(1, 1) PRIMARY KEY ,     Employee_ID INT,    EmpNo nvarchar(50),    EmpCode nvarchar(50),    FirstName nvarchar(500),    SurName nvarchar(500),    IDNumber nvarchar(50),    CycleID INT,    CycleDesc nvarchar(200),    PayrollSalaryHeadTitle nvarchar(200)  )    insert into @tmpCycleTable(CycleID)  select Cycle_ID from Const_Cycle    where Enabled = 1    select  @CountCyle = count(1) from Const_Cycle    where Enabled = 1    while (@StartCycle < (@CountCyle + 1))  begin     select @CycleID = CycleID     from @tmpCycleTable     where id = @StartCycle       select top 1 @PeriodStartDate = PeriodStartDate,@PeriodEndDate = PeriodEndDate        from Payroll_CyclePeriodDetails       where Processed = 0     and CycleID = @CycleID      order by DateCaptured ,Period_ID              insert into @tmpDisableSalaryHeadDataTable      select emp.Employee_ID,dbo.BufferString_fxn(CONVERT(NVARCHAR(10), ( Employee_ID )), 8, '0') AS EmpNo,emp.EmpCode,emp.FirstName ,emp.Surname,emp.IdNo,cyc.Cycle_ID,cyc.CycleDesc,sh.SalaryHeadTitle        from Payroll_CostCenter PC        inner join Payroll_EmployeePayrollDefinition EmpDef on EmpDef.EmployeePayrollDefinition_ID = pc.PayrollDefinationID  and empdef.enabled = 0     inner join Payroll_SalaryHead sh on sh.SalaryHead_ID = EmpDef.PayrollSalaryHeadID and sh.Enabled = 0     inner join Payroll_Employee emp on emp.Employee_ID = EmpDef.EmployeeID and emp.Enabled = 1     inner join Const_Cycle cyc on cyc.Cycle_ID = @CycleID and emp.CycleID = cyc.Cycle_ID      where EntryDate between @PeriodStartDate and @PeriodEndDate       SET @StartCycle = @StartCycle + 1    End    select Employee_ID,EmpNo,EmpCode,FirstName,SurName,IDNumber,CycleID,CycleDesc,PayrollSalaryHeadTitle     from @tmpDisableSalaryHeadDataTable      END  

GO

-- ============================================
-- SP: Payroll_GetEmployeeForRevisedInformation_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- =============================================  /*  Modiri  2019/06/07  #89622  Notification only applicable to positions linked to a task grade    */  Create PROCEDURE [dbo].[Payroll_GetEmployeeForRevisedInformation_sp]   @MunicipalityId int   -- Add the parameters for the stored procedure here  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;      -- Insert statements for procedure here   SELECT DISTINCT  Employee_ID,IDNo,FirstName,SurName FROM dbo.Payroll_Employee AS PE   INNER JOIN dbo.Payroll_JobProfile AS pj ON PE.JobProfileID = pj.JobProfile_ID   INNER JOIN dbo.Payroll_TaskGrade AS PT ON PT.TaskGrade_ID = pj.TaskGradeId   INNER JOIN dbo.Payroll_Notch AS PN ON PN.TaskGradeId = PT.TaskGrade_ID   WHERE pe.Enabled = 1 AND pe.TerminationReasonID IS NULL AND PE.PositionID IS NOT NULL    AND PE.NotchId is null AND MunicipalityID = 1 AND PE.PositionID IS NOT NULL     END  

GO

-- ============================================
-- SP: Payroll_GetEmployeeInformation_sp
-- Schema: dbo
-- ============================================
  CREATE procedure [Payroll_GetEmployeeInformation_sp] @EmpID as int  as  begin     select top 1 [PE].[FixedSalary] as [Basic_salary], [PE].[JoiningDate] as [Join_Date], [D].[DepartmentDesc] as [Department_Name],      [D].[DepartmentCode] as [Department_code], [PCS].[ConditionDesc] as [Condition_description], [PP].[PositionDesc] as [Designation], [DIV].[DivisionDesc] as [Division_Name]      from [Payroll_Employee] as [PE] with(nolock)       join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID]       join [Const_Department] as [D] with(nolock) on [D].[Department_ID] = [PP].[DepartmentID]       join [Const_Division] as [DIV] with(nolock) on [DIV].[Division_ID] = [PP].[DivisionID]       join [Payroll_ConditionOfService] as [PCS] with(nolock) on [PCS].[ConditionOfService_ID] = [PP].[ConditionOfServiceID]       join [Payroll_EmployeeHistory] as [PH] with(nolock) on [PE].[Employee_ID] = [PH].[EmployeeID]      where ([PE].[Employee_ID] = @EmpID)       order by [PE].[JoiningDate]    end  

GO

-- ============================================
-- SP: Payroll_GetEmployeeLeaveBalance
-- Schema: dbo
-- ============================================
  -- =================================================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/08/14>  -- Description: <Get Employee Leave Balances>  -- Call SP    : Payroll_GetEmployeeLeaveBalance 5  --   -- =================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeLeaveBalance]     @EmployeeId int  AS  BEGIN    SELECT cls.LeaveSchemeDesc,clt.LeaveTypeDesc,cat.AbsenceType, LeaveBalance. *     FROM(    SELECT    EmployeeID,   LeaveSchemeID,   LeaveTypeID,   CycleStartDate,   CycleEndDate,   CycleMonths,   Balance,   Accrued,   Taken,   Forfeit,   Encashed,   Accumulated,   Adjusted,   CalcDate,   NextAccrualDate,   ForfeitDate,   AbsenceTypeId ,   TotalLeaveDays  FROM Payroll_EmployeeLeaveBalance    )AS LeaveBalance    LEFT OUTER JOIN Const_LeaveScheme cls   ON cls.LeaveScheme_ID = LeaveBalance.LeaveSchemeID    LEFT OUTER JOIN Const_LeaveType clt   ON clt.LeaveType_ID = LeaveBalance.LeaveTypeID    LEFT OUTER JOIN Const_AbsenceType cat    ON cat.AbsenceType_ID = LeaveBalance.AbsenceTypeId    WHERE LeaveBalance.EmployeeID = @EmployeeID      END    

GO

-- ============================================
-- SP: Payroll_GetEmployeeLeaveDetail
-- Schema: dbo
-- ============================================
-- =============================================        -- Author:  MEHUL PANCHAL        -- Create date: 17/02/2014        -- Description: <Description,,>        -- =============================================        --Payroll_GetEmployeeLeaveDetail 35       CREATE PROCEDURE [dbo].[Payroll_GetEmployeeLeaveDetail]      (        @EmployeeId INT ,        @FinancialYear NVARCHAR(50)      )  AS      BEGIN               --DECLARE @FinancialYear NVARCHAR(50)              --SET @FinancialYear = '2013/2014'              SELECT  PEL.EmployeeLeave_ID ,                  PEL.EmployeeID ,                  PEL.LeaveSchemeID ,                  Pel.LeaveTypeID ,                  ISNULL(PEL.LeaveAcrual, 0.0) AS LeaveAcrual ,                  CLT.LeaveType AS LeaveType ,                  PEL.LeaveBalance AS OpeningBalance ,                  ISNULL(PEL.LeaveAcrual, 0.0) AS Acrual ,                  PEL.UsedLeave AS Taken ,                  ( ISNULL(PEL.LeaveBalance, 0) + ISNULL(PEL.LeaveAcrual, 0)                    - ISNULL(PEL.UsedLeave, 0) ) AS ClosingBalance ,                  ( SELECT    ISNULL(sum(RequestNoOfDays),0)                    FROM      dbo.Payroll_LeaveApproveRequest                    WHERE     LeaveTypeID = Pel.LeaveTypeID                              AND LeaveSchemeID = PEL.LeaveSchemeID                              AND EmployeeID = PEL.EmployeeID                              AND ApprovalStatus = 1                              AND LeaveStatus = 0                              AND TaxYear = PEL.FinancialYear                  ) AS PlannedLeave          FROM    Payroll_EmployeeLeaves AS PEL                  INNER JOIN dbo.Const_LeaveType AS CLT ON CLT.LeaveType_ID = PEL.LeaveTypeID          WHERE   PEL.EmployeeID = @EmployeeId                  AND PEL.FinancialYear = @FinancialYear                        END              

GO

-- ============================================
-- SP: Payroll_GetEmployeeLeaveScheme_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author   : Teboho Mofokeng  -- Create date: 14 March 2017  -- Description: Return Employee leave scheme based on the filters.  -- EXEC Payroll_GetEmployeeLeaveScheme_sp  -- ==============================================================================  CREATE procedure [dbo].[Payroll_GetEmployeeLeaveScheme_sp]      @EmployeeTypeId int =0,   @EmployeeSubtypeId int =0,   @LeaveSchemeId int =0,   @conditionid int =0  as    begin     select a.EmployeeTypeID,a.LeaveScheme_ID, a.LeaveSchemeDesc, a.ConditionOfServiceID,d.ConditionShortDesc,c.EmployeeTypeDescription, b.EmployeeSubtypeDesc,a.StartDate,a.EndDate      from Const_LeaveScheme a      left join Payroll_EmployeeSubtypes b      on b.EmployeeSubtype_ID = a.EmployeeSubtypeID      left join Const_EmployeeType_sys c      on c.EmployeeType_ID = a.EmployeeTypeID      left join Payroll_ConditionOfService d      on d.ConditionOfService_ID = a.ConditionOfServiceID      where ((A.LeaveScheme_ID = @LeaveSchemeId) or (@LeaveSchemeId =0))      --comented out to show the results because curretlt EmployeeTypeID and EmployeeSubtype_ID are not linked      AND ((a.EmployeeTypeID = @EmployeeTypeId) or (@EmployeeTypeId =0))         AND ((B.EmployeeSubtype_ID = @EmployeeSubtypeId) or (@EmployeeSubtypeId =0))     AND ((a.ConditionOfServiceID = @conditionid) or (@conditionid =0))                  end  

GO

-- ============================================
-- SP: Payroll_GetEmployeeLinkedToUpperLimitDetails_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author: Ivan Myroshnychenko  -- Description : Generate Employee list with Upper Limit which are linked with Payroll_Position  -- Create date: 7 December 2020  -- CALLS : [Payroll_GetEmployeeLinkedToUpperLimitDetails_sp] (0-3),0,(1-3)   -- WHERE:  -- 1. 0-3 UpperLimit type - 0- All/Midpoint, 1 - Minimum, 2 - Midpoint, 3- Maximum  -- 2. 0 - Department ID  -- 3. 1-3 Status type - 1 - All, 2 - Inactive, 3 - Active  -- E Beetge 77560 Status filter not working  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeLinkedToUpperLimitDetails_sp]     @UpperLimit INT    ,@Department INT    ,@Status INT    AS    BEGIN     SELECT dbo.BufferString_fxn(P_E.Employee_ID, 8, '0')  AS EmployeeID  , P_E.Initials  , P_E.Surname  , CASE    WHEN P_ET.Complete IS NULL AND P_E.EndDate > GETDATE() THEN 'Active'   ELSE 'Inactive'  END AS Status  , C_DEP.DepartmentDesc AS Department  , C_DIV.DivisionDesc AS Division  , P_JP.JobTitle AS JobProfile  , P_P.PositionDesc AS Position  , C_UL.LimitDesc AS UpperLimit  , CASE     WHEN P_JP.LimitID = 1 THEN P_UL.MinimumValue   WHEN P_JP.LimitID = 2 THEN P_UL.MidpointValue   WHEN P_JP.LimitID = 3 THEN P_UL.MaximumValue  END AS Amount  FROM Payroll_Employee AS P_E  JOIN Payroll_JobProfile AS P_JP   ON P_E.JobProfileID = P_JP.JobProfile_ID AND (P_JP.LimitID IS NOT NULL AND P_JP.LimitID != 0)  LEFT JOIN Payroll_Position AS P_P    ON P_E.JobProfileID = P_P.JobProfileID AND P_E.Employee_ID = P_P.EmployeeID  LEFT JOIN Const_Department AS C_DEP   ON P_P.DepartmentID = C_DEP.Department_ID  LEFT JOIN Const_Division AS C_DIV   ON P_P.DivisionID = C_DIV.Division_ID  CROSS JOIN Payroll_Municipality AS P_M  LEFT JOIN Payroll_UpperLimit AS P_UL   ON P_JP.JobProfile_ID = P_UL.JobProfileId AND P_UL.MunicipalGradingID = P_M.GradingID  JOIN Const_UpperLimits AS C_UL   ON P_JP.LimitID = C_UL.Limit_ID  LEFT JOIN Payroll_EmployeeTermination AS P_ET   ON P_E.Employee_ID = P_ET.EmployeeID  WHERE (@Department = 0 OR @Department = C_DEP.Department_ID)       AND (@Status = 1           OR (@Status = 2 AND (P_ET.Complete IS NOT NULL OR P_E.EndDate < GETDATE()))           OR (@Status = 3 AND (P_ET.Complete IS NULL AND P_E.EndDate > GETDATE())))   AND (@UpperLimit = 0 OR @UpperLimit = P_JP.LimitID)  ORDER BY EmployeeID  END

GO

-- ============================================
-- SP: Payroll_GetEmployeeLinkedToWageDetails_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author: Ivan Myroshnychenko  -- Description : Generate Employee list which not linked with Upper Limit or Task Grade  -- Create date: 9 December 2020  -- CALLS : [Payroll_GetEmployeeLinkedToWageDetails_sp] (0-3),0,(1-3)   -- WHERE:  -- 1. 0-3 Based on Salary - 0- All, 1 - Rate Per Hour, 2 - Rate Per Day, 3 - Captured Value  -- 2. 0 - Department ID or any Department ID  -- 3. 1-3 Status type - 1 - All, 2 - Disabled, 3 - Enabled  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeLinkedToWageDetails_sp]     @SalaryBasedOn INT    ,@Department INT    ,@Status INT    AS    BEGIN     SELECT dbo.BufferString_fxn(P_E.Employee_ID, 8, '0')   AS EmployeeNumber  , P_E.Initials  , P_E.Surname  , IIF(P_ET.Complete IS NOT NULL OR P_E.EndDate < GETDATE(),'Inactive', 'Active') AS Status  , C_DEP.DepartmentDesc AS Department  , C_DIV.DivisionDesc AS Division  , P_JP.JobTitle AS JobProfile  , P_P.PositionDesc AS Position  ,CASE   WHEN P_E.SalaryBasedOn = 1 THEN 'Rate Per Hour'   WHEN P_E.SalaryBasedOn = 2 THEN 'Rate Per Day'   WHEN P_E.SalaryBasedOn = 3 THEN 'Captured Value'  END AS SalaryBased  , P_E.Rate  FROM Payroll_Employee AS P_E  LEFT JOIN Payroll_JobProfile AS P_JP   ON P_E.JobProfileID = P_JP.JobProfile_ID  LEFT JOIN Payroll_Position AS P_P   ON P_E.Employee_ID = P_P.EmployeeID AND P_E.JobProfileID = P_P.JobProfileID  LEFT JOIN Const_Department AS C_DEP   ON P_P.DepartmentID = C_DEP.Department_ID  LEFT JOIN Const_Division AS C_DIV   ON P_P.DivisionID = C_DIV.Division_ID  LEFT JOIN Payroll_EmployeeTermination AS P_ET   on P_E.Employee_ID = P_ET.EmployeeID  WHERE P_E.SalaryBasedOn IS NOT NULL   AND P_JP.TaskGradeId IS NULL   AND P_JP.LimitID IS NULL   AND (@Status = 1           OR (@Status = 2 AND (P_ET.Complete IS NOT NULL OR  P_E.EndDate < GETDATE()))           OR (@Status = 3 AND (P_ET.Complete IS NULL AND P_E.EndDate > GETDATE())))   AND (@Department = 0 OR C_DEP.Department_ID = @Department)   AND (@SalaryBasedOn = 0 OR @SalaryBasedOn = P_E.SalaryBasedOn)   ORDER BY P_E.Employee_ID    END

GO

-- ============================================
-- SP: Payroll_GetEmployeeListForPayslipView_sp
-- Schema: dbo
-- ============================================
    /*   Author   : FERDI BOTHA   Creation Date : 2017/04/03   Description  : Create or Update the Employee Payslip View   Update date  : 12/05/2017 - Changed the mappings for Method of Calculation     modified by  : Modiri   Date   : 2019/05/02   Reason   : TP #86893 After a new Bi-weekly employee was captured, the employee are included in the trial run but there are no Payslip view for the Employee?        Change the Where condition to cater for employees terminationm date is before the period End date.   Update Date  : 14/06/2019 - Changed the Where clause  */  CREATE procedure [dbo].[Payroll_GetEmployeeListForPayslipView_sp] @CycleID int  as  begin     declare @PeriodFromDate datetime,     @PeriodToDate datetime,     @TaxYear nvarchar(50) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))     select top 1 @PeriodFromDate = [PeriodStartDate] from [Payroll_CyclePeriodDetails] where ([CycleID] = @CycleID and [TaxYear] = @TaxYear) order by [PeriodStartDate]     select top 1 @PeriodToDate = [PeriodEndDate] from [Payroll_CyclePeriodDetails] where ([CycleID] = @CycleID and [TaxYear] = @TaxYear) order by [PeriodEndDate] desc     select distinct [Employee_ID], isnull([EmpCode], '') [EmpCode], [IdNo], [Surname], [FirstName], [PassportNumber], [PE].[Enabled], [EmailAddress], [CellNumber], [HomeNumber], [JobTitle], [DIV].[DivisionDesc]      from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)       join [Payroll_Salaryhead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]       join [Payroll_Employee] as [PE] with(nolock) on [EmployeeID] = [PE].[Employee_ID]       join [Payroll_Position] as [PP] with(nolock) on [Position_ID] = [PE].[PositionID]       join [Payroll_JobProfile] as [JP] with(nolock) on [JobProfile_ID] = [PP].[JobProfileID]       join [Const_Division] as [DIV] with(nolock) on [Division_ID] = [PP].[DivisionID]      where ([IsDummy] = 0 and [JoiningDate] <= @PeriodToDate  and not ([PE].[Enabled] = 0 and [PE].[EndDate] = '9999-12-31') and [CycleID] = @CycleID)      order by Employee_Id       end

GO

-- ============================================
-- SP: Payroll_GetEmployeeMedicalAIDScheme_sp
-- Schema: dbo
-- ============================================
  /*   Author   : FERDI BOTHA   Creation Date : 2017/02/24   Description  : Get the Employee Medical Aid Scheme Details   Updated   : 2017/06/03 - Added extra check for Const_MedicalAIDSchemeDetail to also be enabled  */  create procedure [Payroll_GetEmployeeMedicalAIDScheme_sp] @EmployeeID int  as  begin     declare @Today datetime = cast(getdate() as date)     select distinct [EmployeeMedicalAID_ID], [MedicalAidSchmeID], [JoinDate], [TerminationDate], [dScheme].[StartDate], [dScheme].[EndDate],  [VendorName] as [Fund], [FundName] as [PlanName], [Reference], [MemberAmount], [AdultAmount], [ChildAmount], [MaxDependantCount], isnull([IsMaxDependantChildEnabled], 0) as [IsMaxDependantChildEnabled], case when ([JoinDate] <= @Today and ([TerminationDate] is null or [TerminationDate] >= @Today)) then 'Active' else 'Terminated' end as [Status], isnull([AdultCount], 0) as [AdultCount], isnull([AdultContribute], 0) as [AdultContribute], isnull([ChildCount], 0) as [ChildCount], isnull([ChildContribute], 0) as [ChildContribute]      from [Payroll_EmployeeMedicalAIDDetail] as [eScheme] with(nolock)       join [Const_MedicalAIDScheme] as [cScheme] with(nolock) on [MedicalScheme_ID] = [MedicalAidSchmeID] and [cScheme].[Enabled] = 1       join [Const_MedicalAIDSchemeDetail] as [dScheme] with(nolock) on [MedicalSchemeID] = [MedicalScheme_ID] and [dScheme].[Enabled] = 1       join [Cons_Vendor] as [vScheme] with(nolock) on [Vendor_ID] = [VendorID]       left outer join (        select [EmployeeMedicalAIDID], sum(case when [DependantType] = 0 then 1 else 0 end) as [AdultCount], sum(case when [DependantType] = 0 and [EmployerContribute] = 1 then 1 else 0 end) as [AdultContribute], sum(case when [DependantType] = 1 then 1 else 0 end) as [ChildCount], sum(case when [DependantType] = 1 and [EmployerContribute] = 1 then 1 else 0 end) as [ChildContribute]         from [Payroll_EmployeeMedicalAIDDetailDependants] with(nolock)          where ([Enable] = 1)        group by [EmployeeMedicalAIDID]       ) as [dep] on [EmployeeMedicalAIDID] = [eScheme].[EmployeeMedicalAID_ID]       where ([eScheme].[Enable] = 1 and [cScheme].[Enabled] = 1 and [dScheme].[Enabled] = 1 and [EmployeeID] = @EmployeeID)    end  

GO

-- ============================================
-- SP: Payroll_GetEmployeeNotches
-- Schema: dbo
-- ============================================
--DROP PROCEDURE IF EXISTS [dbo].[Payroll_GetEmployeeNotches]  --GO  -- =============================================  -- EXEC [Payroll_GetEmployeeNotches]  -- 2021/10/08 E Beetge    -- =============================================  CREATE PROCEDURE [dbo].Payroll_GetEmployeeNotches  AS  BEGIN  SET NOCOUNT ON;    select Distinct  pe.Employee_ID as Employee_ID ,pe.Surname as Surname,pe.FirstName as FirstName,pe.IdNo AS IdNo,pe.EmailAddress as EmailAddress,                           pe.CellNumber as CellNumber, pe.HomeNumber as HomeNumber,pe.FaxNumber as FaxNumber, pe.Enabled AS Enabled                            from Payroll_Employee as pe left join Payroll_Position pos on pe.PositionID = pos.Position_ID                               inner join Payroll_JobProfile as jp on pos.JobProfileID = jp.JobProfile_ID                                   inner join Const_Cycle as cc on pe.CycleID = cc.Cycle_ID                                         inner join Const_CycleType_sys as css on cc.CycleTypeID = css.CycleType_ID                                    where jp.TaskGradeId is not null and pe.NotchId is null and ISNULL(pe.FixedSalary, 0) = 0 and ISNULL(pe.BonusAmount, 0) = 0 and css.CycleType_ID  = 1    END;

GO

-- ============================================
-- SP: Payroll_GetEmployeeNotInUse_sp
-- Schema: dbo
-- ============================================
        -- =========================================================    -- Author:  Seipei Mathole  -- Create date: 07/03/2016   -- Description: Returns the Payroll_GetEmployeeNotInUse  --  -- ==========================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeNotInUse_sp]        @ProvisionReport_ID int    AS      BEGIN         SELECT E.EmployeeType_ID, E.EmployeeTypeDescription         FROM Const_EmployeeType_sys E         WHERE E.EmployeeType_ID NOT IN            (SELECT ET.EmployeeTypeID             FROM Payroll_ProvisionReportEmployeeTypeLinkTable ET WHERE ET.ProvisionReportID = @ProvisionReport_ID)  END                  

GO

-- ============================================
-- SP: Payroll_GetEmployeePagination_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_GetEmployeePagination_sp]  @EmployeeID INT  AS    BEGIN   Declare @IsDummy BIT = 0           SELECT  n.Employee_ID              FROM    ( SELECT    RecordID, WorkFlowID, COUNT(*) AS WFSACount                    FROM      dbo.Sys_WorkFlowSectionAudit        inner join Payroll_Employee emp ON RecordID = emp.Employee_ID        where case when (emp.IsMarried = 1 or isnull(emp.IsMarried,0) = 0) and WorkFlowSectionID <> 'Spouse details' then 1                   when emp.IsMarried in (2,3)  then 1          else 1  end = 1                    GROUP BY  RecordID, WorkFlowID                  ) WFSA                  INNER JOIN ( SELECT WorkFlowID, COUNT(*) AS WFSCount                               FROM   dbo.Sys_WorkFlowSection WFS                                      INNER JOIN ( SELECT *                                                   FROM   Sys_WorkFlow                                                   WHERE  PageName = 'Employee.aspx'                                                 ) WF ON WFS.WorkFlowID = WF.WorkFlow_ID                                       GROUP BY WorkFlowID                             ) WFCount ON WFSA.WorkFlowID = WFCount.WorkFlowID                  RIGHT JOIN Payroll_Employee n ON RecordID = n.Employee_ID         WHERE   n.Employee_ID = @EmployeeID AND              n.IsDummy = @IsDummy       ORDER BY n.Employee_ID ASC    END    

GO

-- ============================================
-- SP: Payroll_GetEmployeePositionHistory_sp
-- Schema: dbo
-- ============================================
    -- =================================================================================================            -- Author:Varun Parvataneni       -- Create date: 31/10/2016          -- Description: Returns the Result set for the employement history based om Em[loyee_ID        -- Exec [Payroll_GetEmployeePositionHistory_sp]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetEmployeePositionHistory_sp]    @EmployeeID INT  AS     BEGIN    Select pp.PositionHistory_ID,PEH.StartDate,PEH.EndDate,PEH.DivisionID,pp.PositionID,PRC.ReasonDescription from Payroll_EmployeeHistory peh  Inner Join Payroll_PositionHistory pp on peh.PositionHistoryID =pp.PositionHistory_ID  Inner Join Payroll_ReasonEmployeeChange PRC on PRC.Reason_ID = PEH.ReasonID    Where PEH.EmployeeID=@EmployeeID  END  

GO

-- ============================================
-- SP: Payroll_GetEmployeeSalaryTransactions
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetEmployeeSalaryTransactions] @EmployeeID int = 0, @PayrollGroupID int = 0, @prospective bit = 0  as    begin     set nocount on;     declare @CycleID int = (select top 1 [CycleID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))     declare @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))     declare @PeriodID int = (select top 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = @CycleID and [TaxYear] = @ActiveTaxYear) order by [Period_ID] asc)     if (@prospective = 0)   begin      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],       isnull((case        when isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) in(4472, 4473, 4474, 4475) then (isnull([TR].[Amount], 0) * 12)        else [ET].[Amount]        end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        /*when [ET].[SalaryHeadId] is null and not [EPD].[PayrollSalaryHeadID] is null then 'Included (G)'*/        else '' end) as [Package], [GLScoaItem], [ControlScoa]       from [Payroll_EmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[PeriodID] = @PeriodID and [TR].[EmployeeID] = [ET].[EmployeeId] and [TR].[CycleID] = @CycleID and [TR].[SalaryHeadID] = [ET].[SalaryHeadId]        /*join [Payroll_PayrollDefination] as [SG] with(nolock) on [SG].[PayrollSalaryHeadID] = [SalaryHead_ID] and [SG].[Enabled] = 1 and [PayrollDefinitionGroupID] = (case when @PayrollGroupID = 0 then [PayrollDefinitionGroupID] else @PayrollGroupID end)        left outer join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadID] = [SG].[PayrollSalaryHeadID] and [EPD].[Enabled] = 1 and [EPD].[EmployeeID] = (case when @EmployeeID = 0 then [EPD].[EmployeeID] else @EmployeeID end)        left outer join [Payroll_TrialResults] as [TP] with(nolock) on [TP].[SalaryHeadID] = [SG].[PayrollSalaryHeadID] and [TP].[EmployeeID] = (case when @EmployeeID = 0 then [TP].[EmployeeID] else @EmployeeID end)        left outer join  on [ET].[SalaryHeadId] = [SG].[PayrollSalaryHeadID] and [ET].[EmployeeId] = (case when @EmployeeID = 0 then [ET].[EmployeeId] else @EmployeeID end)*/       where ([ET].[EmployeeId] = @EmployeeID)     end   else if (@prospective = 1)   begin      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],       isnull((case         when isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) in(4474, 4472, 4473, 4475) then (isnull([TR].[Amount], 0) * 12)         else [ET].[Amount]         end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        /*when [ET].[SalaryHeadId] is null and not [EPD].[PayrollSalaryHeadID] is null then 'Included (G)'*/        else '' end) as [Package], [GLScoaItem], [ControlScoa]       from [Payroll_ProspectiveEmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[PeriodID] = @PeriodID and [TR].[EmployeeID] = [ET].[ProspectiveEmployeeID] and [TR].[CycleID] = @CycleID and [TR].[SalaryHeadID] = [ET].[SalaryHeadId]        /*join [Payroll_PayrollDefination] as [SG] with(nolock) on [SG].[PayrollSalaryHeadID] = [SalaryHead_ID] and [SG].[Enabled] = 1 and [PayrollDefinitionGroupID] = (case when @PayrollGroupID = 0 then [PayrollDefinitionGroupID] else @PayrollGroupID end)        left outer join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[PayrollSalaryHeadID] = [SG].[PayrollSalaryHeadID] and [EPD].[Enabled] = 1 and [EPD].[EmployeeID] = (case when @EmployeeID = 0 then [EPD].[EmployeeID] else @EmployeeID end)        left outer join [Payroll_TrialResults] as [TP] with(nolock) on [TP].[SalaryHeadID] = [SG].[PayrollSalaryHeadID] and [TP].[EmployeeID] = (case when @EmployeeID = 0 then [TP].[EmployeeID] else @EmployeeID end)        left outer join  on [ET].[SalaryHeadId] = [SG].[PayrollSalaryHeadID] and [ET].[EmployeeId] = (case when @EmployeeID = 0 then [ET].[EmployeeId] else @EmployeeID end)*/       where ([ET].[ProspectiveEmployeeID] = @EmployeeID)     end     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetEmployeeSalaryTransactionsNotification
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,24/04/2018,>  -- Description: <Description,Get Employee affected by upperlimit changes relating to Salary Transactions,>  -- 05/Feb/2019 -- Himil Modi -- #83961 Add gradeID and pass it to Upper limit inner join and also pick the min, mid and max value from the job profile.  -- 03/Jul/2019 -- Himil Modi -- #88960 Add Active tax year and period id in the subquery .  -- =============================================    CREATE PROCEDURE dbo.Payroll_GetEmployeeSalaryTransactionsNotification  AS    BEGIN   set nocount on;     DECLARE @GradingID INT = 0;   SELECT @GradingID = GradingID FROM dbo.Payroll_Municipality     DECLARE @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))   SELECT [Group], [EmployeeID] , (([MaximumValue] - sum(case when [Package] = 'Included' then [Value] else 0 end))) as [Result_Amount]       from (      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],       isnull((case        when [IRP5].[IRP5Code] in(4474, 4472, 4473, 4475) then (isnull([TR].[Amount], 0) * 12)        else [ET].[Amount]        end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        else '' end) as [Package], 'Employee' as [Group], [Employee_ID] as [EmployeeID]      ,CASE jp.LimitID WHEN 1 THEN pu.MinimumValue WHEN 2 THEN pu.MidpointValue ELSE  [PU].[MaximumValue] END  AS [MaximumValue] -- [PU].[MaximumValue] AS [MaximumValue]       from [Payroll_EmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_Employee] as [PE]  with(nolock) on [PE].[Employee_ID] = [ET].[EmployeeId]        join [Payroll_JobProfile] as [JP] with(nolock) on [JobProfile_ID] = [PE].[JobProfileID] and [JP].[Enabled] = 1            join [Payroll_UpperLimit] as [PU] with(nolock) on ISNULL([JP].[LimitID], 0) <> 0 AND [PU].[JobProfileID] = [PE].[JobProfileID] and [PU].[EmployeetypeID] = [PE].[EmployeetypeID] and [PU].[EmployeeSubtypeID] = [PE].[EmployeeSubtypeID]  AND  [PU].MunicipalGradingID = @GradingID        join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID] and [PE].[PayrollDefinitionGroupID] = [PP].[PayrollDefinitionGroupID] and [PP].[JobProfileID] = [PU].[JobProfileId]        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[EmployeeID] = [ET].[EmployeeId] and [TR].[SalaryHeadID] = [ET].[SalaryHeadId]AND TR.CycleID = PE.CycleID AND Tr.PeriodID = (      SELECT  TOP 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = PE.CycleID and [TaxYear] = @ActiveTaxYear) order by [Period_ID] asc)         union      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],       isnull((case         when [IRP5].[IRP5Code] in(4474, 4472, 4473, 4475) then (isnull([TR].[Amount], 0) * 12)         else [ET].[Amount]         end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        else '' end) as [Package],'ProspectiveEmployee' as [Group], [ProspectiveEmployee_ID] as [EmployeeID] , [PU].[MaximumValue] as [MaximumValue]       from [Payroll_ProspectiveEmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_ProspectiveEmployee] as [PPE]  with(nolock) on [PPE].[ProspectiveEmployee_ID] = [ET].[ProspectiveEmployeeID]            join [Payroll_JobProfile] as [JP] with(nolock) on [JobProfile_ID] = [PPE].[JobProfileID] and [JP].[Enabled] = 1            join [Payroll_UpperLimit] as [PU] with(nolock) on ISNULL([JP].[LimitID], 0) <> 0 AND [PU].[JobProfileID] = [PPE].[JobProfileID] and [PU].[EmployeetypeID] = [PPE].[EmployeetypeID] and [PU].[EmployeeSubtypeID] = [PPE].[EmployeeSubtypeID]         join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PPE].[PositionID] and [PPE].[PayrollDefinitionGroupID] = [PP].[PayrollDefinitionGroupID] and [PP].[JobProfileID] = [PU].[JobProfileId]        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[EmployeeID] = [ET].[ProspectiveEmployeeID] and [TR].[SalaryHeadID] = [ET].[SalaryHeadId] AND TR.CycleID = PPE.CycleID AND Tr.PeriodID = (      SELECT  TOP 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = PPE.CycleID and [TaxYear] = @ActiveTaxYear) order by [Period_ID] asc)               ) a            group by [group], [EmployeeID],[MaximumValue]          having ((([MaximumValue] - sum(case when [Package] = 'Included' then [Value] else 0 end)) / 12) > 20)       order by [group], [EmployeeID],[MaximumValue]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetEmployeeScreenItems_sp
-- Schema: dbo
-- ============================================
  create procedure [dbo].[Payroll_GetEmployeeScreenItems_sp]      @TypeId int,   @SubtypeId int    as    begin     select [ScreenSection_ID], [EmployeeScreen_ID], [EmployeeTypeID], [EmployeeSubtypeID], [ScreenSectionID], [ScreenSectionDesc], cast(case [ShowHide] when 1 then 1 else 0 end as bit) as [Show], cast(case [ShowHide] when 0 then 1 else 0 end as bit) as [Hide] from      [Payroll_Const_ScreenSections] as [s] join [Payroll_EmployeeScreen] as [e] on [s].[ScreenSection_ID] = [e].[ScreenSectionID]       where ([EmployeeTypeID] = @TypeId and [EmployeeSubtypeID] = @SubtypeId)     order by [ScreenSectionDesc]    end  

GO

-- ============================================
-- SP: Payroll_GetEmployeesLinkedToMedicalAidScheme
-- Schema: dbo
-- ============================================
--============================================  --Phuti Chokoe  --description: Get employee info linked to medical aid scheme  --TP44910   --============================================  CREATE proc [dbo].[Payroll_GetEmployeesLinkedToMedicalAidScheme]  @medicalSchemeID INT   AS  select a.EmployeeID,a.EmployeeMedicalAID_ID, ads.StartDate,ads.EndDate, e.Employee_ID,a.MedicalAidSchmeID,e.CycleId,a.Enable,e.Enabled from Payroll_EmployeeMedicalAIDDetail a  inner join Const_MedicalAIDScheme as ads on ads.MedicalScheme_ID = a.MedicalAidSchmeID  inner join Payroll_Employee as e on e.Employee_ID = a.EmployeeID  where a.MedicalAidSchmeID = @medicalSchemeID  

GO

-- ============================================
-- SP: Payroll_GetEmployeesSalaryHeads
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 19/05/2017   Description : Calculates Employees Over Time   Update date : 19/05/2017 - Changed the mappings for Method of Calculation  */  create procedure [Payroll_GetEmployeesSalaryHeads] @CycleID int  as    begin     set nocount on;     select [SalaryHead_ID] as [PayrollSalaryHeadID], [SalaryHeadTitle] + ' - ' + cast([IRP5Code] as nvarchar(max)) as [SalaryHeadData]      from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]       join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]      where ([EPD].[Enabled] = 1 and [SH].[Enabled] = 1 and [IRP5].[Enabled] = 1 and [PE].[CycleID] = @CycleID)       group by [SalaryHead_ID], [SalaryHeadTitle], [IRP5Code]     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetEmployeeSubtypes_sp
-- Schema: dbo
-- ============================================
  create procedure [dbo].[Payroll_GetEmployeeSubtypes_sp]      @TypeId int,   @Subtype nvarchar(255)    as    begin     if (@TypeId = 0 and @Subtype = '')   begin      select [EmployeeSubtype_ID], [EmployeeType_ID], [EmployeeTypeDescription], [EmployeeSubtypeDesc] from       [Payroll_EmployeeSubtypes] as [s] join [Const_EmployeeType_sys] as [e] on [s].[EmployeeTypeID] = [e].[EmployeeType_ID]      order by [EmployeeTypeDescription], [EmployeeSubtypeDesc]     end   else   begin      select [EmployeeSubtype_ID], [EmployeeType_ID], [EmployeeTypeDescription], [EmployeeSubtypeDesc] from       [Payroll_EmployeeSubtypes] as [s] join [Const_EmployeeType_sys] as [e] on [s].[EmployeeTypeID] = [e].[EmployeeType_ID]        where ([EmployeeTypeID] = @TypeId and [EmployeeSubtypeDesc] like '%' + isnull(@Subtype, '') + '%')      order by [EmployeeTypeDescription], [EmployeeSubtypeDesc]     end    end  

GO

