GO

-- ============================================
-- SP: Payroll_GetEmployeesWhoseLeavesWillExpire_rpt
-- Schema: dbo
-- ============================================
/*   Modiri   2020/01/21   https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/27092      Modified: Richa M 2021/10/23 Report is not displaying correct info (WI67998)  */  CREATE PROCEDURE [dbo].[Payroll_GetEmployeesWhoseLeavesWillExpire_rpt]     @DepartmentId int =0,  @CycleId int =0,  @EmployeeID int =0,  @LeaveSchemeId int =0,  @LeaveToDate datetime,  @LeaveTypeId int,  @Days int    AS  BEGIN    select dep.DepartmentDesc,cyc.CycleDesc,ls.LeaveSchemeDesc,lt.LeaveType,FirstName + ' ' + Surname as EmployeeName,daysTillExpire,ForfeitDate from(      Select *, Datediff(D,@LeaveToDate,ForfeitDate)daysTillExpire from Payroll_EmployeeLeaveBalance      WHERE (EmployeeID = @EmployeeId OR @EmployeeId = 0)      AND (LeaveSchemeID = @LeaveSchemeId OR @LeaveSchemeId = 0)      AND (LeaveTypeID = @LeaveTypeId OR @LeaveTypeId = 0))empleave      LEFT JOIN Payroll_Employee emp on emp.Employee_ID = empleave.EmployeeID      LEFT JOIN Payroll_Position pos on pos.Position_ID = emp.PositionID      LEFT JOIN Const_Department dep on dep.Department_ID = pos.DepartmentID      LEFT JOIN Const_Cycle cyc on cyc.Cycle_ID = emp.CycleID      LEFT JOIN Const_LeaveScheme ls on ls.LeaveScheme_ID = empleave.LeaveSchemeID      LEFT JOIN Const_LeaveType lt on lt.LeaveType_ID = empleave.LeaveTypeID      WHERE daysTillExpire <= @Days and daysTillExpire > 0      AND (Department_ID = @DepartmentId OR @DepartmentId = 0)      AND (emp.CycleID = @CycleId OR @CycleId = 0)      ORDER BY Employee_ID,LeaveType     END

GO

-- ============================================
-- SP: Payroll_GetEmployeesWhoseLeavesWillExpire_sp
-- Schema: dbo
-- ============================================
  /*   Modiri   2020/01/21   https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/27092  */  CREATE PROCEDURE [dbo].[Payroll_GetEmployeesWhoseLeavesWillExpire_sp]     AS  BEGIN     -- Use this variables for testing purpose   DECLARE @LEAVE_EXPIRE_IN_NEXT_X_MONTHS INT = 2   DECLARE @TODAYSDATE DATETIME = GETDATE() --'2015-06-27 00:00:00.000' --GETDATE()      DECLARE @EMPLIST_LEAVEEXPIRES TABLE   (     EMPID INT,    CYCLESTARTDATE DATETIME,    EMPCODE NVARCHAR(50),    FIRSTNAME NVARCHAR(50),    SURNAME NVARCHAR(50),    DETAILNAME NVARCHAR (200),    LEAVEBALANCE DECIMAL(18, 2)   )      DECLARE @EMPLIST TABLE   (    ID INT IDENTITY(1, 1) ,    EMPID INT ,    JOININGDATE DATETIME,    EMPCODE NVARCHAR(50),    FIRSTNAME NVARCHAR(50),    SURNAME NVARCHAR(50)   )      INSERT INTO @EMPLIST    SELECT EMPLOYEE_ID, JOININGDATE, EMPCODE, FIRSTNAME, SURNAME FROM PAYROLL_EMPLOYEE AS P_EMP    LEFT OUTER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_EMP.PositionID      LEFT OUTER JOIN dbo.Const_Department AS C_DEP ON C_DEP.Department_ID = PP.DepartmentID     WHERE P_EMP.ENABLED = 1     ORDER BY P_EMP.EMPLOYEE_ID      DECLARE @START_EMPLIST INT = 1, @COUNT_EMPLIST INT, @EMPID INT, @JOININGDATE DATETIME, @EMPCODE NVARCHAR(50), @FIRSTNAME NVARCHAR(50), @SURNAME NVARCHAR(50)         DECLARE @EMPLEAVESCHEMETYPE TABLE   (     ID INT ,     LEAVESCHEMEID INT ,     LEAVETYPEID INT ,     LEAVETYPEDETAILID INT,     FOLLOWORFORFIETDATE DATETIME,     CYCLESTARTDATE DATETIME,     CYCLEENDDATE DATETIME,     LEAVETYPE NVARCHAR (200),     SEQUENCENO INT,     ISFIXEDORCALCULATED BIT,     ACCRUALFREQUENCY INT,     ACCRUALDAYS DECIMAL(18, 2),     CYCLEON INT,     FIXEDCYCLESTARTDATE DATETIME,     MAXACCUMULATION INT,     ACCRUALREPEATTIMES INT,     CYCLEREPEATFREQUENCY INT,     NEGATIVEBALANCEALLOWED BIT,     CARRYOVERNEGATIVE BIT,     FORFEIT BIT,     EXTENTIONDAYS INT,     COMPULSORYDAYS INT,     ACCUMULATIVEDAYS INT   )      SELECT  @COUNT_EMPLIST = COUNT(*) FROM @EMPLIST      WHILE ( @START_EMPLIST <= @COUNT_EMPLIST )    BEGIN     SELECT  @EMPID = EMPID, @JOININGDATE = JOININGDATE, @EMPCODE = EMPCODE, @FIRSTNAME = FIRSTNAME, @SURNAME = SURNAME FROM @EMPLIST WHERE ID = @START_EMPLIST       DECLARE @START_EMPLEAVESCHEMETYPE INT = 1 ,  @COUNT_EMPLEAVESCHEMETYPE INT    DECLARE @LEAVESCHEMEID_2 INT, @LEAVETYPEID_2 INT, @LEAVETYPEDETAILID INT,  @FOLLOWORFORFIETDATE DATETIME, @CYCLESTARTDATE DATETIME, @CYCLEENDDATE DATETIME, @LEAVETYPE NVARCHAR (200), @SEQUENCENO INT, @ISFIXEDORCALCULATED BIT,     @ACCRUALFREQUENCY INT, @ACCRUALDAYS DECIMAL(18, 2), @CYCLEON INT, @FIXEDCYCLESTARTDATE DATETIME, @MAXACCUMULATION INT, @ACCRUALREPEATTIMES INT, @CYCLEREPEATFREQUENCY INT, @NEGATIVEBALANCEALLOWED BIT, @CARRYOVERNEGATIVE BIT, @FORFEIT BIT, @EXTENTIONDAYS INT,     @COMPULSORYDAYS INT, @ACCUMULATIVEDAYS INT       -- Get annual leave types for employee    INSERT  INTO @EMPLEAVESCHEMETYPE(ID, LEAVESCHEMEID, LEAVETYPEID, LEAVETYPEDETAILID, FOLLOWORFORFIETDATE, CYCLESTARTDATE, CYCLEENDDATE, LEAVETYPE, SEQUENCENO, ACCRUALDAYS, FIXEDCYCLESTARTDATE, MAXACCUMULATION, NEGATIVEBALANCEALLOWED, CARRYOVERNEGATIVE, FORFEIT, EXTENTIONDAYS, COMPULSORYDAYS, ACCUMULATIVEDAYS)       SELECT ROW_NUMBER() OVER ( ORDER BY P_ELSD.Id ), P_ELSD.LEAVESCHEMEID, P_ELSD.LEAVETYPEID, P_ELSD.LEAVETYPEDETAILID, P_ELSD.FOLLOWORFORFIETDATE, P_ELSD.CYCLESTARTDATE, P_ELSD.CYCLEENDDATE,       C_LT.LEAVETYPE, C_LTD.SEQUENCENO, /*C_LTD.ISFIXEDORCALCULATED, C_LTD.ACCRUALFREQUENCY, */C_LTD.ACCRUALDAYS, /*C_LTD.CYCLEON, */C_LTD.CYCLESTARTDATE AS FIXEDCYCLESTARTDATE, C_LTD.MAXACCUMULATION, /*C_LTD.ACCRUALREPEATTIMES,*/      /*C_LTD.CYCLEREPEATFREQUENCY, */null as [NEGATIVEBALANCEALLOWED], C_LTD.CARRYOVERNEGATIVE, C_LTD.FORFEIT, C_LTD.EXTENTIONDAYS, C_LTD.COMPULSORYDAYS, C_LTD.ACCUMULATIVEDAYS     FROM PAYROLL_EMPLOYEELEAVESCHEMEDETAILS P_ELSD     INNER JOIN CONST_LEAVETYPE C_LT ON P_ELSD.LEAVETYPEID = C_LT.LEAVETYPE_ID AND C_LT.LEAVECLASSIFICATIONID = 1     INNER JOIN CONST_LEAVETYPEDETAILS C_LTD ON P_ELSD.LEAVETYPEDETAILID = C_LTD.LEAVETYPEDETAILSID     WHERE EMPLOYEEID = @EMPID         SELECT  @COUNT_EMPLEAVESCHEMETYPE = COUNT(*) FROM @EMPLEAVESCHEMETYPE       WHILE ( @START_EMPLEAVESCHEMETYPE <= @COUNT_EMPLEAVESCHEMETYPE )    BEGIN     SELECT  @LEAVESCHEMEID_2 = LEAVESCHEMEID,       @LEAVETYPEID_2 = LEAVETYPEID,       @LEAVETYPEDETAILID = LEAVETYPEDETAILID,       @FOLLOWORFORFIETDATE = FOLLOWORFORFIETDATE,       @CYCLESTARTDATE = CYCLESTARTDATE,       @CYCLEENDDATE = CYCLEENDDATE,       @LEAVETYPE = LEAVETYPE,       @SEQUENCENO = SEQUENCENO,       @ISFIXEDORCALCULATED = ISFIXEDORCALCULATED,       @ACCRUALFREQUENCY = ACCRUALFREQUENCY,       @ACCRUALDAYS = ACCRUALDAYS,       @CYCLEON = CYCLEON,       @FIXEDCYCLESTARTDATE = FIXEDCYCLESTARTDATE,       @MAXACCUMULATION = MAXACCUMULATION,       @ACCRUALREPEATTIMES = ACCRUALREPEATTIMES,       @CYCLEREPEATFREQUENCY = CYCLEREPEATFREQUENCY,       @NEGATIVEBALANCEALLOWED = NEGATIVEBALANCEALLOWED,       @CARRYOVERNEGATIVE = CARRYOVERNEGATIVE,       @FORFEIT = FORFEIT,       @EXTENTIONDAYS = EXTENTIONDAYS,       @COMPULSORYDAYS = COMPULSORYDAYS,       @ACCUMULATIVEDAYS = ACCUMULATIVEDAYS            FROM    @EMPLEAVESCHEMETYPE           WHERE   ID = @START_EMPLEAVESCHEMETYPE        DECLARE @MonthDifference INT, @MonthRemainder INT, @CYCLEON_CYCLESTARTDATE DATETIME, @AVAILABLELEAVEBALANCE DECIMAL(18, 2)        IF @IsFixedOrCalculated = 1 AND @CYCLEREPEATFREQUENCY > 0     BEGIN         SELECT  @AVAILABLELEAVEBALANCE = ISNULL(SUM(ACCRUALLEAVE - TAKENLEAVE - FORFEITLEAVE - ENCASHLEAVE + ADJUSTEDLEAVE - WITHOUTPAYLEAVE), 0)        FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMETRANSACTION AS P_ELST        WHERE   EMPLOYEEID = @EMPID                AND LEAVETYPEID = @LEAVETYPEID_2                AND LEAVESCHEMEID = @LEAVESCHEMEID_2                AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID                AND ISENABLED = 1            DECLARE @LASTCYCLESTARTDATE DATETIME, @LASTCYCLEENDDATE DATETIME, @LEAVEBALANCE_LASTCYCLE INT, @ACCRUALLEAVEBALANCE_LASTCYCLE INT,          @TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE INT, @ACCRUALLEAVEBALANCE_CURRENTCYCLE INT, @FORFEITLEAVES INT         IF @CYCLEON = 2 OR @CYCLEON = 3 --EmploymentDate OR EmploymentDate + month      BEGIN       IF (@EXTENTIONDAYS > 0)       BEGIN        IF (@FOLLOWORFORFIETDATE IS NOT NULL) AND ((DATEADD(MONTH, @LEAVE_EXPIRE_IN_NEXT_X_MONTHS, @TODAYSDATE)) >= @FOLLOWORFORFIETDATE)        BEGIN         SET @CYCLEON_CYCLESTARTDATE = @TODAYSDATE         BEGIN         SELECT  @LASTCYCLESTARTDATE = CYCLESTARTDATE, @LASTCYCLEENDDATE = CYCLEENDDATE         FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMEDETAILS         WHERE   EMPLOYEEID = @EMPID          AND LEAVESCHEMEID = @LEAVESCHEMEID_2          AND LEAVETYPEID = @LEAVETYPEID_2          AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID            IF(@LASTCYCLESTARTDATE IS NOT NULL AND @LASTCYCLEENDDATE IS NOT NULL)         BEGIN          SELECT  @TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE = ISNULL(SUM(TAKENLEAVE + FORFEITLEAVE + ENCASHLEAVE + WITHOUTPAYLEAVE), 0)           FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMETRANSACTION AS P_ELST WHERE   EMPLOYEEID = @EMPID AND LEAVETYPEID = @LEAVETYPEID_2 AND LEAVESCHEMEID = @LEAVESCHEMEID_2 AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID AND ISENABLED = 1            AND TRANDATE BETWEEN @LASTCYCLESTARTDATE AND @FOLLOWORFORFIETDATE                    SELECT @ACCRUALLEAVEBALANCE_LASTCYCLE = ISNULL(SUM(ACCRUALLEAVE), 0)           FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMETRANSACTION AS P_ELST WHERE   EMPLOYEEID = @EMPID AND LEAVETYPEID = @LEAVETYPEID_2 AND LEAVESCHEMEID = @LEAVESCHEMEID_2 AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID AND ISENABLED = 1            AND TRANDATE BETWEEN @LASTCYCLESTARTDATE AND DATEADD(DAY, -1, @LASTCYCLEENDDATE)                    IF ((@TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE IS NOT NULL) AND (@ACCRUALLEAVEBALANCE_LASTCYCLE IS NOT NULL))          BEGIN           SET @FORFEITLEAVES = @ACCRUALLEAVEBALANCE_LASTCYCLE - @TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE              IF @FORFEITLEAVES > 0           BEGIN            IF((@ACCUMULATIVEDAYS IS NOT NULL) AND (@ACCUMULATIVEDAYS > 0))            BEGIN             IF (@FORFEITLEAVES > @ACCUMULATIVEDAYS)             BEGIN              SET @FORFEITLEAVES = @FORFEITLEAVES - @ACCUMULATIVEDAYS             END             ELSE             BEGIN              SET @FORFEITLEAVES = 0             END            END                        IF @FORFEITLEAVES > 0            BEGIN             INSERT INTO @EMPLIST_LEAVEEXPIRES              SELECT @EMPID, @LASTCYCLESTARTDATE, @EMPCODE, @FIRSTNAME, @SURNAME, @LEAVETYPE, @FORFEITLEAVES            END           END          END            END        END        END       END       ELSE       BEGIN        SET @CYCLEON_CYCLESTARTDATE = @JOININGDATE       END      END      ELSE -- Fixed Date      BEGIN       IF @FIXEDCYCLESTARTDATE IS NULL       BEGIN        SET @FIXEDCYCLESTARTDATE = @JOININGDATE       END          IF ((@FOLLOWORFORFIETDATE IS NOT NULL) AND ((DATEADD(MONTH, @LEAVE_EXPIRE_IN_NEXT_X_MONTHS, @TODAYSDATE)) >= @FOLLOWORFORFIETDATE))       BEGIN        SET @CYCLEON_CYCLESTARTDATE = @TODAYSDATE        BEGIN         SELECT  @LASTCYCLESTARTDATE = CYCLESTARTDATE, @LASTCYCLEENDDATE = CYCLEENDDATE         FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMEDETAILS         WHERE   EMPLOYEEID = @EMPID          AND LEAVESCHEMEID = @LEAVESCHEMEID_2          AND LEAVETYPEID = @LEAVETYPEID_2          AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID            IF(@LASTCYCLESTARTDATE IS NOT NULL AND @LASTCYCLEENDDATE IS NOT NULL)         BEGIN          SELECT  @TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE = ISNULL(SUM(TAKENLEAVE + FORFEITLEAVE + ENCASHLEAVE + WITHOUTPAYLEAVE), 0)           FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMETRANSACTION AS P_ELST WHERE   EMPLOYEEID = @EMPID AND LEAVETYPEID = @LEAVETYPEID_2 AND LEAVESCHEMEID = @LEAVESCHEMEID_2 AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID AND ISENABLED = 1            AND TRANDATE BETWEEN @LASTCYCLESTARTDATE AND @FOLLOWORFORFIETDATE                    SELECT @ACCRUALLEAVEBALANCE_LASTCYCLE = ISNULL(SUM(ACCRUALLEAVE), 0)           FROM    DBO.PAYROLL_EMPLOYEELEAVESCHEMETRANSACTION AS P_ELST WHERE   EMPLOYEEID = @EMPID AND LEAVETYPEID = @LEAVETYPEID_2 AND LEAVESCHEMEID = @LEAVESCHEMEID_2 AND LEAVETYPEDETAILID = @LEAVETYPEDETAILID AND ISENABLED = 1            AND TRANDATE BETWEEN @LASTCYCLESTARTDATE AND DATEADD(DAY, -1, @LASTCYCLEENDDATE)                    IF ((@TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE IS NOT NULL) AND (@ACCRUALLEAVEBALANCE_LASTCYCLE IS NOT NULL))          BEGIN           SET @FORFEITLEAVES = @ACCRUALLEAVEBALANCE_LASTCYCLE - @TAKENLEAVEBALANCE_LASTCYCLESTARTTOFORFEITDATE              IF @FORFEITLEAVES > 0           BEGIN            IF((@ACCUMULATIVEDAYS IS NOT NULL) AND (@ACCUMULATIVEDAYS > 0))            BEGIN             IF (@FORFEITLEAVES > @ACCUMULATIVEDAYS)             BEGIN              SET @FORFEITLEAVES = @FORFEITLEAVES - @ACCUMULATIVEDAYS             END             ELSE             BEGIN              SET @FORFEITLEAVES = 0             END            END                        IF @FORFEITLEAVES > 0            BEGIN             INSERT INTO @EMPLIST_LEAVEEXPIRES              SELECT @EMPID, @LASTCYCLESTARTDATE, @EMPCODE, @FIRSTNAME, @SURNAME, @LEAVETYPE, @FORFEITLEAVES            END           END          END            END        END       END       ELSE       BEGIN        SET @CYCLEON_CYCLESTARTDATE = @FIXEDCYCLESTARTDATE       END      END         SET @MONTHDIFFERENCE = DATEDIFF(MONTH, @CYCLEON_CYCLESTARTDATE, @TODAYSDATE)      SET @MONTHREMAINDER = @MONTHDIFFERENCE % @CYCLEREPEATFREQUENCY         IF ((@MONTHREMAINDER + @LEAVE_EXPIRE_IN_NEXT_X_MONTHS) >= @CYCLEREPEATFREQUENCY)      BEGIN       --PRINT 'LAPSE'       IF @CARRYOVERNEGATIVE = 0        BEGIN         INSERT  INTO @EMPLIST_LEAVEEXPIRES          SELECT @EMPID, @CYCLEON_CYCLESTARTDATE, @EMPCODE, @FIRSTNAME, @SURNAME, @LEAVETYPE, @AVAILABLELEAVEBALANCE        END      END     END        SET @START_EMPLEAVESCHEMETYPE = @START_EMPLEAVESCHEMETYPE + 1    END       DELETE FROM @EMPLEAVESCHEMETYPE      SET @START_EMPLIST = @START_EMPLIST + 1   END      SELECT EMPID, CYCLESTARTDATE, EMPCODE, FIRSTNAME, SURNAME, DETAILNAME, LEAVEBALANCE FROM @EMPLIST_LEAVEEXPIRES    END

GO

-- ============================================
-- SP: Payroll_GetEmployeesWithNegativeLeaveBalances_Rpt_sp
-- Schema: dbo
-- ============================================
   -- =================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 07 April 2016  -- Request:  TP32628  -- Description: This sp will return all the employees who have negative leave balances  -- Modified: 2025/01/29 Richa M - Updated SP to use correct Leave tables    --Payroll_GetEmployeesWithNegativeLeaveBalances_Rpt_sp '2025/01/31',0,0,0,0,0   -- =================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeesWithNegativeLeaveBalances_Rpt_sp]    @LeaveToDate DATETIME, @EmployeeID INT, @DepartmentId INT, @CycleId INT, @LeaveSchemeId INT, @LeaveTypeId INT  AS  BEGIN   select     dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (emp.Employee_ID)), 8,'0') AS EmployeeId,     ISNULL(emp.EmpCode, '') AS EmpCode, ISNULL(emp.FirstName + ' ','') + ISNULL(emp.Surname,'') AS EmployeeName,    lt.LeaveTypeDesc AS LeaveType,    CAST(Isnull(LeaveBalance,0) AS Decimal(18,2))  LeaveBalance    from(    select EmployeeID,LeaveSchemeID,LeaveTypeID,SUM(Average) LeaveBalance     from(     select EmployeeID,LeaveSchemeID,LeaveTypeID,LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,StartDate CalDate,'None' DayName,0 PublicH,1 Leave,1 Shift,Value as Average      from Payroll_EmployeeLeaveTransactions     where LeaveStatusID = 3    and Enabled = 1    and Enddate <= @LeaveToDate     and (EmployeeID = @EmployeeId OR @EmployeeId = 0)    and StartDate = EndDate   Union ALL     select LeaveTransactions.EmployeeID,LeaveSchemeID,LeaveTransactions.LeaveTypeID,LeaveTransactions.LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,cal.Date,DayName,PublicH,Leave,Shift,(abs(value)/NumberOfDaysRequested)* -1 Average from(     select EmployeeID,LeaveSchemeID,LeaveTypeID,LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,NumberOfDaysRequested from Payroll_EmployeeLeaveTransactions     where LeaveStatusID = 3    and Enabled = 1    and Enddate <= @LeaveToDate     and (EmployeeID = @EmployeeId OR @EmployeeId = 0)    and StartDate <> EndDate)LeaveTransactions   join Payroll_EmployeeCalander cal on cal.Date between LeaveTransactions.StartDate and LeaveTransactions.EndDate and cal.EmployeeID = LeaveTransactions.EmployeeID)EmpCal    where calDate <= @LeaveToDate and Leave = 1    group by EmployeeID,LeaveSchemeID,LeaveTypeID   )LeaveSummary     join Payroll_employee emp on emp.Employee_ID = LeaveSummary.EmployeeID   join Const_LeaveScheme ls on ls.LeaveScheme_ID = LeaveSummary.LeaveSchemeID   join Const_LeaveType lt on lt.LeaveType_ID = LeaveSummary.LeaveTypeID   where LeaveBalance < 0  END

GO

-- ============================================
-- SP: Payroll_GetEmployeesWithNegativeLeaveBalances_sp
-- Schema: dbo
-- ============================================
-- =================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 25 March 2016  -- Request:  TP34150  -- Description: This sp will return all the employees who have negative leave balances  -- =================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeesWithNegativeLeaveBalances_sp]   AS  BEGIN   SELECT  dbo.BufferString_fxn(CONVERT(NVARCHAR(10), (P_ELST.EmployeeId)), 8,'0') AS EmployeeId , P_EMP.EmpCode, P_EMP.FirstName, P_EMP.Surname     , LT.LeaveTypeDesc AS LeaveType, ISNULL(SUM(AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave - WithoutPayLeave), 0) AS LeaveBalance   FROM    dbo.Payroll_EmployeeLeaveSchemeTransaction AS P_ELST   INNER JOIN Const_LeaveTypeDetails AS C_LTD ON P_ELST.LeaveTypeDetailId = C_LTD.LeaveTypeDetailsId   INNER JOIN Const_LeaveType LT ON LT.LeaveType_Id  = C_LTD.LeaveTypeId   INNER JOIN Payroll_Employee P_EMP on P_EMP.Employee_ID = P_ELST.EmployeeId and P_EMP.Enabled = 1   WHERE P_ELST.IsEnabled = 1   GROUP BY P_ELST.EmployeeId, P_EMP.EmpCode, P_EMP.FirstName, P_EMP.Surname , P_ELST.LeaveSchemeId, P_ELST.LeaveTypeId, P_ELST.LeaveTypeDetailId , LT.LeaveTypeDesc   HAVING ISNULL(SUM(AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave - WithoutPayLeave), 0) < 0  END    

GO

-- ============================================
-- SP: Payroll_GetEmployeeTaskGradeAndNotchDetail_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author: Ivan Myroshnychenko  -- Description : Generate Employee list which Notch will be update in future  -- Create date: 03 December 2020  -- CALLS : Payroll_GetEmployeeTaskGradeAndNotchDetail_sp  0,0,0,(1-3)   -- 2023/11/08 Kiran WI96667 Fixed Sorting Selection per Notch increment date not working  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeTaskGradeAndNotchDetail_sp]     @TaskGradeId INT = 0   ,@DepartmentId INT = 0      ,@StatusId INT = 0   ,@SortingSelection INT = 1  AS  BEGIN   SELECT * FROM (   SELECT    e.[Employee_ID] AS 'EmployeeNumber',    e.[Initials],    e.[Surname],    CASE     WHEN et.[EmployeeTermination_ID] IS NULL THEN 'Active'     WHEN et.[Complete] IS NULL AND e.[EndDate] > CURRENT_TIMESTAMP THEN 'Active'     ELSE 'Inactive'    END AS 'Status',    e.[Enabled],    d.[DepartmentDesc] AS 'Department',    p.[DepartmentID] AS 'Department_ID',    div.[DivisionDesc] AS 'Division',    jp.[JobTitle] AS 'JobProfile',    jp.[JobProfile_ID],    p.[PositionDesc] AS 'Position',    tg.[TaskGradeName] AS 'TaskGrade',    tg.[TaskGrade_ID] AS 'TaskGradeID',    n.[Notch],    CASE       WHEN n.[OnAppointment] = 1 THEN 'Appointment Date'     WHEN n.[OnIncreaseDate] = 1 THEN 'Specific Month'     ELSE NULL    END AS 'NotchIncrement',    CASE     WHEN e.[NotchID] IS NULL THEN NULL -- employee not linked to notch     WHEN n.[Notch] = mn.[MaxNotch] THEN NULL -- case when employee has maximum notch in this TaskGrade       WHEN n.[OnIncreaseDate] = 1 AND n.[MonthID] IS NULL THEN NULL -- case when Notch doesn''t have type MonthID, this is issue case       WHEN n.[OnIncreaseDate] = 0 AND (n.[OnAppointment] = 0  OR n.[OnAppointment] IS NULL) THEN NULL -- issue when neither ''On Appointment Date'' no ''On Notch Increase Date'' checkboxes tick       WHEN n.[OnIncreaseDate] = 1 THEN CONCAT(CAST(CASE WHEN n.[MonthID] < MONTH(CURRENT_TIMESTAMP) THEN YEAR(CURRENT_TIMESTAMP) + 1 ELSE YEAR(CURRENT_TIMESTAMP) END AS VARCHAR(4)), '-', RIGHT('00' + CAST(n.[MonthID] AS VARCHAR(2)), 2), '-01')     WHEN n.[OnAppointment] = 1 THEN CONCAT(CAST(YEAR(CASE WHEN MONTH(e.[JoiningDate]) - MONTH(CURRENT_TIMESTAMP) < 0 THEN DATEADD(YEAR, YEAR(CURRENT_TIMESTAMP) - YEAR(e.[JoiningDate]), e.[JoiningDate]) ELSE e.[JoiningDate] END) + CAST(n.[AnnualIncrease] AS INT) AS VARCHAR(4)), '-', FORMAT(e.[JoiningDate], 'MM'), '-01')     ELSE NULL    END AS 'NotchIncrementDay',    CASE        WHEN e.[FixedSalary] > N.[MinimumSalary] THEN E.[FixedSalary]     ELSE n.[MinimumSalary]    END AS 'Amount'   FROM    Payroll_TaskGrade tg   INNER JOIN    Payroll_JobProfile jp ON tg.[TaskGrade_ID] = jp.[TaskGradeId]          AND jp.[Enabled] = 1   INNER JOIN    Payroll_Employee e ON jp.[JobProfile_ID] = e.[JobProfileID]   LEFT JOIN    Payroll_Notch n ON e.[NotchId] = n.[Notch_ID]   LEFT JOIN    Payroll_EmployeeTermination et ON e.[Employee_ID] = et.[EmployeeID]   LEFT JOIN    Payroll_Position p ON e.[JobProfileID] = p.[JobProfileID]          AND e.[Employee_ID] = p.[EmployeeID]          AND e.[Enabled] = 1   LEFT JOIN    Const_Department d ON p.[DepartmentID] = d.[Department_ID]   LEFT JOIN    Const_Division div ON p.[DivisionID] = div.[Division_ID]   OUTER APPLY    (     SELECT      MAX(pn.[Notch]) AS 'MaxNotch'     FROM      Payroll_Notch pn     WHERE      pn.[TaskGradeId] = tg.[TaskGrade_ID]     AND pn.[Enabled] = 1    ) mn   WHERE    (ISNULL(@TaskGradeId, 0) = 0 OR tg.[TaskGrade_ID] = @TaskGradeId)   AND (ISNULL(@DepartmentId, 0) = 0 OR p.[DepartmentId] = @DepartmentId)   AND (ISNULL(@StatusId, 0) = 0    OR (     CASE      WHEN et.[EmployeeTermination_ID] IS NULL THEN 2      WHEN et.[Complete] IS NULL AND e.[EndDate] > CURRENT_TIMESTAMP THEN 2      ELSE 1     END) = @StatusId     )    ) t   ORDER BY        CASE     WHEN @SortingSelection = 1 THEN [EmployeeNumber]      WHEN @SortingSelection = 2 THEN [TaskGradeID]      WHEN @SortingSelection = 3 THEN CAST(NotchIncrementDay AS DATETIME)    END      END

GO

-- ============================================
-- SP: Payroll_GetEmployeeTaxDirectiveDetail_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:Varun Parvataneni  -- Create date: 28 june 2016  -- Description: Display the list of Employee Tax directives on grid in Employee page(Employee section)  -- Call : exec [Payroll_GetEmployeeTaxDirectiveDetail_sp] 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeTaxDirectiveDetail_sp]   @EmployeeID INT , @TaxYear NVARCHAR(12)  AS  BEGIN  DECLARE @TaxDirectiveCount INT  DECLARE @TaxDeductionAmount NUMERIC(18,2)     SELECT   @TaxDirectiveCount = COUNT (EmpId)     FROM dbo.Payroll_EmployeeTaxDirectives PET    INNER JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = PET.EmpID   WHERE PET.EmpID = @EmployeeID    AND PET.Enabled = 1    AND PET.TaxYear = @TaxYear    GROUP BY  PET.TaxYear      SELECT    @TaxDeductionAmount = SUM(ISNULL(ETOD.Amount,0))     FROM dbo.Payroll_EmployeeTaxOverDeduction ETOD    INNER JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = ETOD.EmployeeID   WHERE ETOD.EmployeeID = @EmployeeID    AND ETOD.Enabled = 1    AND ETOD.TaxYear = @TaxYear    GROUP BY  ETOD.TaxYear      SELECT ISNULL(@TaxDirectiveCount,0) TaxDirectiveCount, ISNULL(@TaxDeductionAmount,0) TaxDeductionAmount    END      

GO

-- ============================================
-- SP: Payroll_GetEmployeeTaxTotals
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Richa M  -- Create date: 2023/03/09  -- Name: Payroll_GetEmployeeTaxTotals  -- Description: Create tax totals for IRP5 certificates per employee  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmployeeTaxTotals]        @TaxYear VARCHAR(10),        @TaxPeriod INT  AS  BEGIN  DECLARE @TaxYearInt INT  DECLARE @PeriodEndDate DATETIME    SELECT     @TaxYearInt = TaxYearInt,   @PeriodEndDate = EndDate   FROM Payroll_Irp5SubmissionPeriod   WHERE IsClosed = 0    DELETE FROM Payroll_EmployeeTaxTotals WHERE TaxYear = @TaxYearInt and TaxPeriod = @TaxPeriod    INSERT INTO Payroll_EmployeeTaxTotals    SELECT    @TaxYearInt,   @TaxPeriod,    EmployeeId,   SUM(TaxableIncome),   SUM(NonTaxableIncome),   SUM(MTC),   SUM(secondaryMTC),   SUM(TotalDeductions)   FROM(    SELECT      EmployeeId,     IRP5Code,      CASE WHEN IRP5Code in       (SELECT Irp5Code FROM Const_IRP5DataTypes WHERE id > 111        AND Id < 276        AND IRP5Code NOT IN        (3714,3602,3652,3703,3753,3717,3764,3815,3865,3821,3871,3822,3872,3830,3880,3832,3882,3834,3884,3908))      THEN SUM(Amount)      ELSE 0.00      END AS 'TaxableIncome',       CASE WHEN IRP5Code in (3602,3652,3703,3753,3717,3764,3815,3865,3821,3871,3822,3872,3830,3880,3832,3882,3834,3884,3908)      THEN SUM(Amount)      ELSE 0.00      END AS 'NonTaxableIncome',       CASE WHEN IRP5Code in (4116)      THEN SUM(Amount)      ELSE 0.00      END AS MTC,       CASE WHEN IRP5Code in (4120)      THEN SUM(Amount)      ELSE 0.00      END AS SecondaryMTC,       CASE WHEN IRP5Code in (3701,3802,3816)      THEN SUM(Amount*80/100)      ELSE       CASE WHEN IRP5Code in (3817,3825,3875,3810,3828) OR IRP5Code in (SELECT IRP5Code FROM Payroll_IRP5Code WHERE Left(IRP5Code,2) in (40,44,45))       THEN SUM(Amount)       ELSE 0.00       END      END AS 'TotalDeductions'  FROM(     SELECT     EmployeeID,     Irp5Code,    Cast(Sum(Amount) as int)Amount     FROM Payroll_PayrollResults WHERE PeriodID in     (SELECT Period_id FROM Payroll_CyclePeriodDetails WHERE TaxYear = @TaxYear and PeriodEndDate <= @PeriodEndDate)   GROUP BY EmployeeID, IRP5Code   UNION ALL    SELECT Employee_Id,4116, SUM(TaxCredits) FROM Payroll_PayrollRun_History_Employees WHERE Period_ID in (SELECT Period_id FROM Payroll_CyclePeriodDetails WHERE TaxYear = @TaxYear and PeriodEndDate <= @PeriodEndDate)    group by Employee_ID   UNION ALL    SELECT Employee_Id,4120, SUM(SecondaryMTC) FROM Payroll_PayrollRun_History_Employees WHERE Period_ID in (SELECT Period_id FROM Payroll_CyclePeriodDetails WHERE TaxYear = @TaxYear and PeriodEndDate <= @PeriodEndDate)    group by Employee_ID    )TaxTotals  group by EmployeeID,IRP5Code)result  group by EmployeeID  order by EmployeeID    --Update Certificate Numbers  update Payroll_EmployeeIRP5CertificateNumber set TaxYear = '2023' where ISNULL(TaxYear,0) = 0    DECLARE @LastNumber int = (select Max(Irp5CertificateNumber) from Payroll_EmployeeIRP5CertificateNumber where Taxyear = @TaxYearInt)    Insert into Payroll_EmployeeIRP5CertificateNumber  select EmployeeId,  IsNULL(@LastNumber,0)  + row_number() over (order by tt.EmployeeId),  @TaxYearInt  from  Payroll_EmployeeTaxTotals tt where TaxYear = @TaxYearInt and TaxPeriod = @TaxPeriod and EmployeeId not in   (  select EmployeeId from Payroll_EmployeeIRP5CertificateNumber where TaxYear = @TaxYearInt  )      Select EmployeeTaxTotalId,TaxYear,TaxPeriod,EmployeeId,TaxableIncome3699 AS TaxableIncome,NonTaxableIncome3969 AS NonTaxableIncome,MedicalTaxCredit4116 AS MedicalTaxCredit,  SecondaryMedicalTaxCredit4120 SecondaryMedicalTaxCredit,TotalDeductions4497 AS TotalDeductions from Payroll_EmployeeTaxTotals where TaxYear = @TaxYearInt and TaxPeriod = @TaxPeriod      END;

GO

-- ============================================
-- SP: Payroll_GetEmployeeTrailrunSalaryTransactionsNotification
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Himil Modi  -- Create date: 26 Jun, 2019  -- Description: Check Ledger Trail Run  -- =============================================  CREATE PROCEDURE Payroll_GetEmployeeTrailrunSalaryTransactionsNotification  AS  BEGIN      DECLARE @GradingID INT = 0;   SELECT @GradingID = GradingID FROM dbo.Payroll_Municipality     select ROW_NUMBER() OVER ( ORDER BY EmployeeID  ) AS RowID,  [Group], [EmployeeID] , (([MaximumValue] - sum(case when [Package] = 'Included' then [Value] else 0 end)) / 12) as [Result_Amount]       INTO #tempTable FROM  (      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],     isnull((case        when [IRP5].[IRP5Code] in(4474, 4472, 4473, 4475) then (isnull([TR].[Amount], 0) * 12)        else [ET].[Amount]        end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        else '' end) as [Package], 'Employee' as [Group], [Employee_ID] as [EmployeeID]      ,CASE jp.LimitID WHEN 1 THEN pu.MinimumValue WHEN 2 THEN pu.MidpointValue ELSE  [PU].[MaximumValue] END  AS [MaximumValue] -- [PU].[MaximumValue] AS [MaximumValue]       from [Payroll_EmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_Employee] as [PE]  with(nolock) on [PE].[Employee_ID] = [ET].[EmployeeId]        join [Payroll_JobProfile] as [JP] with(nolock) on [JobProfile_ID] = [PE].[JobProfileID] and [JP].[Enabled] = 1            join [Payroll_UpperLimit] as [PU] with(nolock) on  [PU].[JobProfileID] = [PE].[JobProfileID] and [PU].[EmployeetypeID] = [PE].[EmployeetypeID] and [PU].[EmployeeSubtypeID] = [PE].[EmployeeSubtypeID]  AND  [PU].MunicipalGradingID = @GradingID        join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID] and [PE].[PayrollDefinitionGroupID] = [PP].[PayrollDefinitionGroupID] and [PP].[JobProfileID] = [PU].[JobProfileId]        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[EmployeeID] = [ET].[EmployeeId] and [TR].[SalaryHeadID] = [ET].[SalaryHeadId]         union      select distinct [SalaryHead_ID], replicate('0', 4 - len(cast(isnull([IRP5].[IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5].[IRP5Code], 0) as nvarchar) + ' - ' + isnull([SalaryHeadName], '') as [SalaryHeadName], [SalaryHeadTitle],     isnull((case         when [IRP5].[IRP5Code] in(4474, 4472, 4473, 4475) then (isnull([TR].[Amount], 0) * 12)         else [ET].[Amount]         end), 0) as [Value], (case         when isnull([ET].[IncludeInPackage], 0) = 1 then 'Included'        when isnull([ET].[AdditionalInPackage], 0) = 1 then 'Additional'        else '' end) as [Package],'ProspectiveEmployee' as [Group], [ProspectiveEmployee_ID] as [EmployeeID] , [PU].[MaximumValue] as [MaximumValue]       from [Payroll_ProspectiveEmployeeSalaryTransaction] as [ET] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ET].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_ProspectiveEmployee] as [PPE]  with(nolock) on [PPE].[ProspectiveEmployee_ID] = [ET].[ProspectiveEmployeeID]            join [Payroll_JobProfile] as [JP] with(nolock) on [JobProfile_ID] = [PPE].[JobProfileID] and [JP].[Enabled] = 1            join [Payroll_UpperLimit] as [PU] with(nolock) on  [PU].[JobProfileID] = [PPE].[JobProfileID] and [PU].[EmployeetypeID] = [PPE].[EmployeetypeID] and [PU].[EmployeeSubtypeID] = [PPE].[EmployeeSubtypeID]         join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PPE].[PositionID] and [PPE].[PayrollDefinitionGroupID] = [PP].[PayrollDefinitionGroupID] and [PP].[JobProfileID] = [PU].[JobProfileId]        left outer join [Payroll_TrialResults] as [TR] with(nolock) on [TR].[EmployeeID] = [ET].[ProspectiveEmployeeID] and [TR].[SalaryHeadID] = [ET].[SalaryHeadId]                ) a            group by [group], [EmployeeID],[MaximumValue]          having ((([MaximumValue] - sum(case when [Package] = 'Included' then [Value] else 0 end)) / 12) > 20)       order by [group], [EmployeeID],[MaximumValue]     DECLARE @count INT = 0;     DECLARE @totalCount INT = 0;       SELECT @totalCount = COUNT(1) FROM #tempTable       DECLARE @empId INT,      @CycleId INT,      @PeriodId INT,      @CycleModeId INT,      @StartDate DATETIME,      @EndDate DATETIME,      @period INT,      @TaxYear VARCHAR(10) ,      @ScoaYear varchar(10);          --declare @IRP5Code table (      -- [Type] tinyint not null,      -- [IRP5Code] int not null,      -- [IRP5Description] nvarchar(max) not null,      -- [Taxable] decimal(18, 6) not null,      -- [StartDate] datetime2 not null default('1964-03-01 00:00:00.0000000'),      -- [UntilDate] datetime2 not null default('9999-12-31 00:00:00.0000000')      --)        DECLARE @IRP5Code Payroll_IRP5Income         /* 01 - INCOME RECORD(S) */   begin      insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3601, 'INCOME - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3651, 'FOREIGN INCOME - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3602, 'INCOME - NON TAXABLE', 0)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3652, 'FOREIGN INCOME - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3603, 'PENSION - TAXABLE', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3653, 'FOREIGN PENSION - TAXABLE', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3604, 'PENSION - NON TAXABLE', 0, '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3654, 'FOREIGN PENSION - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000', '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3605, 'ANNUAL PAYMENT - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3655, 'FOREIGN ANNUAL PAYMENT - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3606, 'COMMISSION', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3656, 'FOREIGN COMMISSION', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3607, 'OVERTIME', 100, '2010-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3657, 'FOREIGN OVERTIME', 100, '2002-03-01 00:00:00.0000000', '2010-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3608, 'ARBITRATION AWARDS - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3658, 'FOREIGN ARBITRATION AWARDS - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3609, 'ARBITRATION AWARDS - NON TAXABLE', 0, '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3659, 'FOREIGN ARBITRATION AWARDS - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000', '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3610, 'ANNUITY FROM RETIREMENT FUND', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3660, 'FOREIGN ANNUITY FROM RETIREMENT FUND', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3611, 'PURCHASED ANNUITIES - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3661, 'FOREIGN PURCHASED ANNUITY - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3612, 'PURCHASED ANNUITY - NON TAXABLE', 0, '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3662, 'FOREIGN PURCHASED ANNUITY - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000', '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3613, 'RESTRAINT OF TRADE', 100, '2000-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3663, 'FOREIGN RESTRAINT OF TRADE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3614, 'OTHER RETIREMENT FUNDING LUMP SUM', 100, '2001-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Descript