-- ============================================
-- SP: Payroll_GetEmployeeTypeHistory
-- Schema: dbo
-- ============================================
-- -- ==============================================================================      ---- Author  : RichaM   ---- Create date: 2023/04/26      ---- Description: Return all Employee Type History with Scoa Info      ---- EXEC Payroll_GetEmployeeTypeHistory 1,'2022/2023'     ---- ==============================================================================      CREATE PROCEDURE [dbo].[Payroll_GetEmployeeTypeHistory]     @EmployeeTypeId int,   @Finyear varchar(10)     WITH RECOMPILE  AS          BEGIN       select    eth.finyear,   Startdate,   EndDate,   EmployeeTypeDescription,   SalaryProjectId,   SalarySuspenseScoaITemId,   SalarySuspenseScoaItemCreditId,   cast(proj.ProjectCode as varchar(10)) + ' | ' + proj.ProjectDesc ProjectDesc,   scoaDt.ScoaDesc + ' | ' + scoaDt.ScoaCode DebitItem,   scoaCt.ScoaDesc + ' | ' + scoaCt.ScoaCode CreditItem  from(   select * from Const_EmployeeTypeHistory_sys    where employeetypeId = @EmployeeTypeId    and Finyear = @Finyear   )eth  LEFT join Plan_Project proj on proj.Project_ID = eth.SalaryProjectId and proj.FinYear = eth.finYear    LEFT join Const_SCOA_Structure_Consolidated_vw scoaDt on scoaDt.ScoaID = eth.SalarySuspenseScoaITemId and scoaDt.FinYearText = eth.finYear    LEFT join Const_SCOA_Structure_Consolidated_vw scoaCt on scoaCt.ScoaID = eth.SalarySuspenseScoaItemCreditId and scoaCt.FinYearText = eth.finYear    order by Startdate desc              END

GO

-- ============================================
-- SP: Payroll_GetEmployeeTypes
-- Schema: dbo
-- ============================================
-- -- ==============================================================================      ---- Author  : RichaM   ---- Create date: 2023/04/26      ---- Description: Return all Employee Types with Scoa Info      ---- EXEC Payroll_GetEmployeeTypes 0     ---- ==============================================================================      CREATE PROCEDURE [dbo].[Payroll_GetEmployeeTypes]     @EmployeeTypeId int    AS          BEGIN       select et.EmployeeType_ID,et.EmployeeTypeDescription,et.Enabled,SalaryProjectID,SalarySuspenseScoaItemID,SalarySuspenseScoaItemCreditID,    cast(proj.ProjectCode as varchar(10)) + ' | ' + proj.ProjectDesc ProjectDesc,    scoaDt.ScoaDesc + ' | ' + scoaDt.ScoaCode DebitItem,    scoaCt.ScoaDesc + ' | ' + scoaCt.ScoaCode CreditItem,    et.FinYear from(   select * from Const_EmployeeType_sys where (EmployeeType_ID = @EmployeeTypeId OR @EmployeeTypeId = 0))et   left join plan_Project proj    on et.SalaryProjectID = proj.Project_ID   left join Const_SCOA_Structure scoaDt    on scoaDt.ScoaID = et.SalarySuspenseScoaItemID   left join Const_SCOA_Structure scoaCt    on scoaCt.ScoaID = et.SalarySuspenseScoaItemCreditID              END

GO

-- ============================================
-- SP: Payroll_GetEmployeeUnionDetail_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 27/01/2017   Description : Returns the employee union details for the employee based on Employee_ID  */  CREATE procedure [Payroll_GetEmployeeUnionDetail_sp] @EmployeeID int  as    begin     select [EmployeeUnion_ID], [UnionRepresentatives], [StartDate], [empU].[EndDate]      from [Payroll_EmployeeUnion] as [empU] with(nolock)       join [Const_UnionRepresentatives] as [conU] with(nolock) on [UnionRepresentatives_ID] = [empU].[UnionRepresentativesID]       join [Payroll_Employee] as [emp] with(nolock) on [Employee_ID] = [empU].[EmpID]       where ([empU].[Enabled] = 1 and [EmpID] = @EmployeeID)    end

GO

-- ============================================
-- SP: Payroll_GetEmployeeWiseClaimList_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  lungisani Khumalo  -- Create date: 24/04/2017  -- Description: <Description,,>    --- Modiri  --- 2019/07/02  --- #90970 Incorrect message when processing claims  --- Himil Modi 2019/07/23 #87742 Edit an Approved Transaction (Change sequnce in case statement to get correct output)    -- =============================================  CREATE PROCEDURE dbo.Payroll_GetEmployeeWiseClaimList_sp   @EmployeeId INT,   @PeriodID INT,   @ClaimType varchar(10)  AS  BEGIN   SET NOCOUNT ON;     Select EmployeeClaims_ID, CostAmount, CONVERT(NVARCHAR(12), EntryDate, 103) AS EntryDate, @PeriodID AS PeriodID,      (CASE WHEN IsApproved=1 THEN 'Approved'     WHEN IsApproved=0 and RejectedReason = '' Or RejectedReason is null  THEN 'Awaiting Approval'     WHEN IsApproved=0 and RejectedReason != '' Or RejectedReason is not null  THEN 'Rejected'              END) AS Status, ISNULL(Processed,0) as Processed, SubType      FROM dbo.Payroll_EmployeeClaims      WHERE       EmployeeID = @EmployeeId AND    PeriodID = @PeriodID AND Enabled = 1 AND   ClaimID in (Select Claim_ID from Const_Claims where replace(replace(Claim_Type,'&',''),' ','') = replace(@claimType,' ',''))  END

GO

-- ============================================
-- SP: Payroll_GetEmployeeWiseCostCenterList_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Lungisani Khumalo   Create date : 02/08/2017   Description : Get Cost Centre infomation    */  CREATE procedure [dbo].[Payroll_GetEmployeeWiseCostCenterList_sp] @EmployeeId int, @PayrollDefinationID int, @PeriodID int  as  begin   set nocount on;        declare @Periods table (        ID [int] identity(1,1) not null,    PeriodId [int]        )          insert into @Periods (PeriodId)       select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails] where [CycleID] = (select top 1 [CycleID] from [Payroll_CyclePeriodDetails] where [Period_ID] = @PeriodID)         and [CycleModeID] = 1 and [Period_ID] <= @PeriodID      if(not exists(select [PeriodId] from @Periods where [PeriodId] = @PeriodID))    begin     insert into @Periods (PeriodId) select @PeriodID    end      select distinct [CostCenter_ID], [CostAmount], convert(nvarchar(12), [EntryDate], 103) as [EntryDate] ,       (case when IsApproved = 0 then 'Awaiting Approval'        when IsApproved = 0 and RejectedReason != '' Or RejectedReason is not null  then 'Rejected'        when IsApproved = 1 then 'Approved'        else 'Not Reqiured'      end) as [Status] , (case when [EveryMonth] = 1 then 'Every Month' else 'Once-Off' end) as [Run]       from [dbo].[Payroll_CostCenter] with(nolock)        where [EmployeeID] = @EmployeeId AND [PayrollDefinationID] = @PayrollDefinationID AND          ([EveryMonth] is null or [EveryMonth] = 0) and [Enabled] = 1 and ([Processed] is null or [Processed] = 0) and [PeriodID] in (select [PeriodId] from @Periods)       union        select distinct [CostCenter_ID], [CostAmount], convert(nvarchar(12), [EntryDate], 103) as [EntryDate] ,       (case when IsApproved = 0 then 'Awaiting Approval'        when IsApproved = 0 and RejectedReason != '' Or RejectedReason is not null  then 'Rejected'        when IsApproved = 1 then 'Approved'        else 'Not Reqiured'     end) as [Status], (case when [EveryMonth] = 1 then 'Every Month' else 'Once-Off' end) as [Run]       from [dbo].[Payroll_CostCenter] with(nolock)        where [EmployeeID] = @EmployeeId AND [PayrollDefinationID] = @PayrollDefinationID AND         [Enabled] = 1 and [CostAmount] > 0 and               [EveryMonth] = 1 and ([PeriodID]  >= (select min([PeriodId]) from @Periods))  end

GO

-- ============================================
-- SP: Payroll_GetEmployeeWiseOverTimeList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Lungisani Khumalo  -- Create date: 12/04/2017  -- Description: <Description,,>  -- Modified: (Ferdi Botha) changed the Case order  /*   Modiri   2019/08/08   #92480 Incorrect Message for Overtime transactions that were included in a Final Run, no message for Claim transactions.  */  -- =============================================    CREATE procedure [dbo].[Payroll_GetEmployeeWiseOverTimeList_sp] @PeriodID int, @EmployeeId int, @EmployeeOverTime_ID int=0  as  begin     select employeeovertime_id, overtimehour, convert(nvarchar(12), overtimedate, 103) as overtimedate,       (case       when isapproved = 1 then 'Approved'       when isapproved = 0 and rejectedreason is null then 'Awaiting Approval'       else 'Rejected'      end) as [status], salaryheadid, sh.salaryheadtitle,ISNULL(Processed,0) as Processed     from [payroll_employeeovertime] [ot] with(nolock)      join [payroll_salaryhead][sh] with(nolock) on  [ot].[salaryheadid] = [sh].[salaryhead_id]     where employeeid = @employeeid and ot.[enabled] = 1 and ot.[enabled] = 1 and   periodid = @periodid AND [ot].EmployeeOverTime_ID = (case @EmployeeOverTime_ID when 0 then [ot].EmployeeOverTime_ID else @EmployeeOverTime_ID END)      end

GO

-- ============================================
-- SP: Payroll_GetEmployeeWiseTransactionType_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:    MEHUL PANCHAL  -- Create date:  03 SEP 2013  -- Description:  Get Transaction Type and Transaction Type Description by employee   -- calls : Payroll_GetEmployeeWiseTransactionType_sp 3,2,2547  -- 2015-02-09 James Roodt: Added another Order By paramter to sub order by salaryhead title.  -- 2015-06-11 James Roodt: Changed order of Description - Code; Also orders it alphabetically; Also filters for enabled SalaryHeads  -- 2016-04-28 Varun Parvataneni: An adhoc period only works for certain salary heads TP36052  -- Update date      : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date      : 06/09/2017 - Changed the mappings to IRP5 and clean up - Lungisani Khumalo  -- Update date  : 10/10/2019 - Code clean and format, there was bug with mixed SalaryHead_ID column and PreLinked  -- Update date  : 02/03/2020 - Ilya Skavronskiy => Fixed filtering   -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetEmployeeWiseTransactionType_sp] @EmployeeID        INT,                                                                     @TransactionTypeID INT,                                                                     @PeriodID          INT  AS    BEGIN         DECLARE @tblSalaryHead TABLE         (                 PreLinked INT,  --1=prelinked, 2=divider, 3=not linked      SalaryHead_ID int,               IRP5Code NVARCHAR(10),               TRANSACTIONTYPEIDDESC NVARCHAR(MAX),               TRANSACTIONTYPEDESC NVARCHAR(MAX),               MenuText NVARCHAR(MAX)         )           DECLARE @transactionType_Deduction INT = 2         DECLARE @getPeriodCycleMode INT           Select @getPeriodCycleMode = CycleModeID            from Payroll_CyclePeriodDetails where Period_ID = @PeriodID           IF(@getPeriodCycleMode=1)-- Normal Period for payroll trail and return all IRP5 codes on the Employee           BEGIN           INSERT INTO @tblSalaryHead             SELECT DISTINCT 1, SalaryHead_ID, IRP5.IRP5Code,    CONVERT(NVARCHAR, PAY_DEF.EmployeePayrollDefinition_ID) + ' - ' + PAY_SAL.SalaryHeadName +'|'+ CONVERT(NVARCHAR,  SalaryHead_ID)  AS TRANSACTIONTYPEIDDESC,                                            PAY_SAL.SalaryHeadTitle + case when PAY_DEF.Percentage <100 THEN '(' +CONVERT(NVARCHAR,  PAY_DEF.Percentage)+ ')'  ELSE  '' END  + ' - ' + CONVERT(NVARCHAR, IRP5.IRP5Code) AS TRANSACTIONTYPEDESC,                                     PAY_SAL.SalaryHeadTitle AS MenuText                 FROM PAYROLL_EMPLOYEEPAYROLLDEFINITION PAY_DEF                        INNER JOIN Payroll_SalaryHead PAY_SAL WITH(NOLOCK) ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                        INNER JOIN Payroll_IRP5Code IRP5 WITH(NOLOCK) ON PAY_SAL.IRP5CodeID = IRP5.IRP5Code_ID                        INNER JOIN CONST_TRANSACTIONTYPE CONST_TRANS WITH(NOLOCK) ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                 WHERE PAY_DEF.EMPLOYEEID = @EmployeeID                   AND IRP5.TransactionTypeID = @TransactionTypeID                   AND PAY_DEF.[Enabled] = 1 AND PAY_SAL.[Enabled] = 1                   AND (@TransactionTypeID <> @transactionType_Deduction OR IRP5.[IRP5Code] NOT IN (4472,4473,4475))                 ORDER BY MenuText                        INSERT INTO @tblSalaryHead                  ( PreLinked,SalaryHead_ID, IRP5Code, TRANSACTIONTYPEIDDESC , TRANSACTIONTYPEDESC )         VALUES                 ( 2,0,'','0 - New', '------------------------------------------------' )                                                      INSERT INTO @tblSalaryHead                               SELECT 3, SalaryHead_ID ,IRP5.IRP5Code,                                     '0 - ' + CONVERT(NVARCHAR, SH.SalaryHead_ID) + ' | ' + CONVERT(NVARCHAR, isnull(GL.ScoaItemIDPermanentStaff,'0')) + ' | ' + SH.SalaryHeadName +'|'+ CONVERT(NVARCHAR,  SalaryHead_ID) AS TRANSACTIONTYPEIDDESC,                                                          SH.SalaryHeadTitle + ' - ' + CONVERT(NVARCHAR, IRP5.IRP5Code) AS TRANSACTIONTYPEDESC, SH.SalaryHeadTitle AS MenuText                               FROM Payroll_SalaryHead AS SH                                      INNER JOIN Payroll_GLItems GL WITH(NOLOCK) ON GL.SalaryHeadID = SH.SalaryHead_ID                                     INNER JOIN Payroll_IRP5Code IRP5 WITH(NOLOCK) ON SH.IRP5CodeId = IRP5.IRP5Code_ID                               WHERE IRP5.TransactionTypeID = @TransactionTypeID                                   AND SH.[Enabled] = 1                 AND (@TransactionTypeID <> @transactionType_Deduction OR IRP5.[IRP5Code] NOT IN (4472,4473,4475))                AND SH.SalaryHead_ID NOT IN                                    (                                      Select PayrollSalaryHeadID FROM PAYROLL_EMPLOYEEPAYROLLDEFINITION WHERE EMPLOYEEID = @EmployeeID AND TransactionTypeID =  @TransactionTypeID AND [Enabled] = 1                                  )                             ORDER BY MenuText                        Select  TRANSACTIONTYPEIDDESC , TRANSACTIONTYPEDESC, SalaryHead_ID FROM  @tblSalaryHead ORDER BY PreLinked, TRANSACTIONTYPEDESC               END                 ELSE IF(@getPeriodCycleMode=2)--  Adhoc period to Return all IRP5CODES linked to that period               BEGIN                                     INSERT INTO @tblSalaryHead                               SELECT DISTINCT 1, SalaryHead_ID ,IRP5.IRP5Code, CONVERT(NVARCHAR, PAY_DEF.EmployeePayrollDefinition_ID)+ ' - ' + SH.SalaryHeadName +'|'+ CONVERT(NVARCHAR,  SalaryHead_ID) AS TRANSACTIONTYPEIDDESC,                                                          SH.SalaryHeadTitle + ' - ' + CONVERT(NVARCHAR, IRP5.IRP5Code) AS TRANSACTIONTYPEDESC, SH.SalaryHeadTitle AS MenuText                               FROM Payroll_CyclePeriodAdhocSalaryHead AS PC_AS                                     INNER JOIN Payroll_SalaryHead SH  WITH(NOLOCK) ON PC_AS.SalaryHeadID = SH.SalaryHead_ID                                     INNER JOIN PAYROLL_EMPLOYEEPAYROLLDEFINITION PAY_DEF WITH(NOLOCK) ON SH.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                                      INNER JOIN Payroll_IRP5Code IRP5 WITH(NOLOCK) ON SH.IRP5CodeId = IRP5.IRP5Code_ID                               WHERE IRP5.TransactionTypeID = @TransactionTypeID                                   AND PC_AS.[Enabled] = 1                                   AND PC_AS.PeriodID = @PeriodID                                   AND PAY_DEF.EMPLOYEEID = @EmployeeID                                   AND PAY_DEF.[Enabled] = 1                                   --AND  IRP5.[IRP5Code] not in(3607,3657,3701,3702,3703,3751,3752,3753)                                  AND (@TransactionTypeID <> @transactionType_Deduction OR IRP5.[IRP5Code] NOT IN (4472,4473,4475))                                                            ORDER BY MenuText                                       Select  TRANSACTIONTYPEIDDESC , TRANSACTIONTYPEDESC , SalaryHead_ID FROM  @tblSalaryHead ORDER BY PreLinked, TRANSACTIONTYPEDESC,SalaryHead_ID    END  END

GO

-- ============================================
-- SP: Payroll_GetEmploymentCodeByCategoryId
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,21 Aug 2014>  -- Description: <Description,,Get Employment Code by Employment Category Id>  -- Call SP    : Payroll_GetEmploymentCodeByCategoryId 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEmploymentCodeByCategoryId]   @CategoryId INT  AS  BEGIN   SELECT Code.EmploymentCode_ID, Code.EmploymentCode FROM dbo.Const_EmploymentCategory_Sys AS Cate   INNER JOIN dbo.Const_EmolymentCategoryCode_Sys AS CateCode ON Cate.EmploymentCategory_ID = CateCode.EmploymentCategoryID   INNER JOIN dbo.Const_EmploymentCode_Sys AS Code ON CateCode.EmploymentCodeID = Code.EmploymentCode_ID   WHERE Cate.EmploymentCategory_ID = @CategoryId  END  

GO

-- ============================================
-- SP: Payroll_GetEmploymentHistory_sp
-- Schema: dbo
-- ============================================
 /*   Author  : FERDI BOTHA   Create date : 27/01/2017   Description : Returns the employment history for the employee based on Employee_ID     modified by : Modiri   Date  : 2019/06/20       #90621 Issue Employee history, Position History and Job Profile Position linked to Job Profile information     modified by : Modiri   Date  : 2019/07/08       #90944 Employee History Record for Change of Notch     Modified by : Modiri   Date  : 2019/07/25       #90963 Lephalale: employee transfer      Modified by : Modiri   Date  : 2019/08/20       #93085 QAMulti_HR\Payroll Employee Details History Order not correct.   Modiri   #93089 After Converting a prospective employee, Position History and Employee History not co   2019/08/26     Modiri   2019/10/25   22758 MOC Rollover. According to the spec the Termination Process should update the Employment history and the Position history.      Update date : 04/03/2020 - Ilya Skavronskiy => updated employment change ReasonDescription   Update date : 22/04/2020 - Ilya Skavronskiy => implemented grouping of several employee history records into one        employment history record if position, task grade and notch did not change     Update date : 02/04/2021 - Ivan Myroshnychenko => Add verification that StartDate in the history row equals TerminationStartDate for display Termination row     Update date : 30/04/2021 - R Strydom => Added in the missing column NotchChangeReason     Payroll_GetEmploymentHistory_sp 467    */    CREATE PROCEDURE [dbo].[Payroll_GetEmploymentHistory_sp]    @EmployeeID INT    AS    BEGIN   DECLARE @tbl TABLE(    idx INT identity(1,1),    [EmployeeHistory_ID] INT,     [StartDate] DATETIME,     [EndDate] DATETIME,     [DivisionID] INT,     [DivisionDesc] VARCHAR(200),    Notch INT,     TaskGrade INT,    [PositionHistory_ID] INT,     [Position_ID] INT,     [PositionDesc] VARCHAR(200),     [Reason_ID] INT,    [ReasonTypeID] INT,    [ReasonDescription] VARCHAR(200),    [NotchChangeReason] VARCHAR(200),    MonthlySalary DECIMAL(18, 2),    WorkingHoursPerMonth DECIMAL(18, 2))     DECLARE @results table(    idx INT identity(1,1),    [EmployeeHistory_ID] INT,     [StartDate] DATETIME,     [EndDate] DATETIME,     [DivisionID] INT,     [DivisionDesc] VARCHAR(200),    Notch INT,     TaskGrade INT,    [PositionHistory_ID] INT,     [Position_ID] INT,     [PositionDesc] VARCHAR(200),     [Reason_ID] INT,    [ReasonTypeID] INT,    [ReasonDescription] VARCHAR(200),    [NotchChangeReason] VARCHAR(200),    MonthlySalary DECIMAL(18, 2),    WorkingHoursPerMonth DECIMAL(18, 2))       INSERT INTO @tbl ([EmployeeHistory_ID], [StartDate], [EndDate], [DivisionID], [DivisionDesc],Notch, TaskGrade, [PositionHistory_ID], [Position_ID]         , [PositionDesc], [Reason_ID],[ReasonTypeID],[ReasonDescription], [NotchChangeReason], MonthlySalary, WorkingHoursPerMonth)   SELECT     [EmployeeHistory_ID],    [empH].[StartDate],     [empH].[EndDate],     [empH].[DivisionID],     [div].[DivisionDesc],    [pn].Notch,    [pn].TaskGradeId,     [posH].[PositionHistory_ID],     [Position_ID],     [pos].[PositionDesc],     [res].[Reason_ID],    [res].[ReasonTypeID],    CASE WHEN IsNULL(NotchChangeReason,'') = '' THEN  [res].[ReasonDescription] ELSE NotchChangeReason END AS ReasonDescription,    [empH].[NotchChangeReason],    [empH].MonthlySalary,    [empH].WHPM_Monthly   FROM [Payroll_EmployeeHistory] as [empH] with(nolock)    LEFT OUTER JOIN [Payroll_PositionHistory] as [posH] with(nolock)      ON [PositionHistory_ID] = [empH].[PositionHistoryID] and [posH].[Enabled] = 1 and emph.EmployeeID = posH.EmployeeID    LEFT OUTER JOIN [Const_Division] as [div] with(nolock)      ON [Division_ID] = [posH].[DivisionID]    LEFT JOIN [Payroll_Position] as [pos] with(nolock)      ON [Position_ID] = [posH].[PositionID]    LEFT JOIN [Payroll_ReasonEmployeeChange] as [res] with(nolock)      ON [Reason_ID] = [empH].[ReasonID]    LEFT JOIN  [Payroll_Notch] as [pn]  with(nolock)      ON empH.NotchID=pn.Notch_ID   WHERE ([empH].[EmployeeID] = @EmployeeID     AND NOT [empH].[StartDate] IS NULL    AND NOT [empH].[EndDate] IS NULL    AND [empH].[Enabled] = 1)   ORDER BY [empH].[EndDate]     DECLARE @cnt INT = 1    , @notchid INT = 0    , @positionid INT = 0    , @taskGrade INT = 0    , @recordsTotal INT = 0    , @lastResultId INT = 0    , @monthlySalary DECIMAL(18, 2) = 0    , @workingHoursPerMonth DECIMAL(18, 2) = 0      , @TerminationDate DATE =  ISNULL((SELECT TOP 1 CAST(TerminationStartDate AS DATE)            FROM Payroll_EmployeeTermination            WHERE EmployeeID = @EmployeeID), CAST(CONVERT(SMALLDATETIME,0) AS DATE))     SET @recordsTotal = (SELECT COUNT(*) FROM @tbl)     IF (@recordsTotal > 0)   BEGIN     INSERT INTO @results([EmployeeHistory_ID], [StartDate], [EndDate], [DivisionID], [DivisionDesc],Notch, [PositionHistory_ID], [Position_ID]    , [PositionDesc], [Reason_ID],[ReasonDescription],[ReasonTypeID], TaskGrade, NotchChangeReason, MonthlySalary, WorkingHoursPerMonth)   SELECT TOP 1 [EmployeeHistory_ID], [StartDate], [EndDate], [DivisionID], [DivisionDesc],Notch, [PositionHistory_ID], [Position_ID], [PositionDesc]    , [Reason_ID],[ReasonDescription],[ReasonTypeID], TaskGrade, NotchChangeReason, MonthlySalary, WorkingHoursPerMonth   FROM @tbl   WHERE ([idx] = 1)     WHILE(@cnt < @recordsTotal)   BEGIN    SET @lastResultId = (SELECT MAX([idx]) FROM @results)      SELECT @notchid = ISNULL(notch,0)     , @positionid = ISNULL(Position_ID,0)     , @taskGrade = ISNULL(TaskGrade,0)     , @monthlySalary = ISNULL(MonthlySalary, 0)     , @workingHoursPerMonth = ISNULL(WorkingHoursPerMonth, 0)       FROM @tbl WHERE idx = @cnt;      IF EXISTS(     SELECT TOP 1 1 FROM @tbl     WHERE [idx] = (@cnt + 1)       AND ISNULL(Notch, 0) = @notchid       AND ISNULL(TaskGrade, 0) = @taskGrade       AND ISNULL(Position_ID, 0) = @positionid       AND ISNULL(MonthlySalary, 0) = @monthlySalary       AND ISNULL(WorkingHoursPerMonth, 0) = @workingHoursPerMonth      AND ISNULL(StartDate, CAST(CONVERT(SMALLDATETIME,0) AS DATE)) != DATEADD( DAY, 1, @TerminationDate)    )    BEGIN     UPDATE @results SET EndDate = (SELECT [EndDate] FROM @tbl WHERE [idx] = @cnt + 1)     WHERE [idx] = @lastResultId    END    ELSE IF EXISTS(SELECT TOP 1 1 FROM @tbl WHERE [idx] = @cnt + 1)    BEGIN     INSERT INTO @results([EmployeeHistory_ID], [StartDate], [EndDate], [DivisionID], [DivisionDesc],Notch, [PositionHistory_ID], [Position_ID]      , [PositionDesc], [Reason_ID],[ReasonDescription],[ReasonTypeID], TaskGrade, NotchChangeReason, MonthlySalary, WorkingHoursPerMonth)     SELECT top 1 [EmployeeHistory_ID]        , [StartDate]        , [EndDate]        , [DivisionID]        , [DivisionDesc]        , Notch        , [PositionHistory_ID]        , [Position_ID]        , [PositionDesc]        , [Reason_ID]        , [ReasonDescription]        , [ReasonTypeID]        , TaskGrade        , NotchChangeReason        , MonthlySalary        , WorkingHoursPerMonth     FROM @tbl     WHERE ([idx] = @cnt + 1)    END      SET @cnt = @cnt + 1   END     SET @cnt = 1     WHILE(@cnt < (SELECT COUNT(*) FROM @results))   BEGIN    SELECT @notchid = ISNULL(notch,0), @positionid = ISNULL(Position_ID,0), @taskGrade = ISNULL(TaskGrade,0)    FROM @results WHERE idx=@cnt;      IF((@notchid !=(SELECT notch FROM @results WHERE idx=(@cnt+1))) AND (@positionid = (SELECT Position_ID FROM @results WHERE idx=(@cnt+1))))    BEGIN     UPDATE @results     SET ReasonDescription=       CASE WHEN NotchChangeReason IS NOT NULL AND LOWER(NotchChangeReason) = 'yearly notch increase' THEN NotchChangeReason       ELSE 'Notch Change'      END     WHERE idx=@cnt+1    END      IF((@taskGrade !=(SELECT TaskGrade FROM @results WHERE idx=(@cnt+1))) AND (@positionid = (SELECT Position_ID FROM @results WHERE idx=(@cnt+1))))    BEGIN     UPDATE @results     SET ReasonDescription= 'Task Grade Change'     WHERE idx=@cnt+1    END      SET @cnt=@cnt+1;   END     END     SELECT [EmployeeHistory_ID]    , [StartDate]    , [EndDate]    , [DivisionID]    , [DivisionDesc]    , Notch    , [PositionHistory_ID]    , [Position_ID]    , [PositionDesc]    , [Reason_ID]    , [ReasonDescription]    , [ReasonTypeID]    , MonthlySalary    , WorkingHoursPerMonth    FROM @results   ORDER BY [EmployeeHistory_ID] DESC  END

GO

-- ============================================
-- SP: Payroll_GetEmpSignOffCert_sp
-- Schema: dbo
-- ============================================
/*=============================================      Author: Jaydev Jangid  Create date:  13 Oct 2016   Description: Return list of employees who have tick signoff checkbox in employee screen  [Payroll_GetEmpSignOffCert_sp] 'February','2016/2017',4  =============================================    */  create PROCEDURE [dbo].[Payroll_GetEmpSignOffCert_sp]      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @PayrollCycleId INT  AS      BEGIN                DECLARE @CertId INT;            SELECT  @CertId = EmployeeTaxCertificate_ID FROM Payroll_EmployeeTaxCertificate WHERE TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;             SELECT  EmployeeID FROM Payroll_EmployeeDocumentDetails WHERE   EmpTaxCertId = @CertId AND IsSignOff = 1;      END;  

GO

-- ============================================
-- SP: Payroll_GetEncashLeaveTypeByEmployeeId
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Ghanshyam Dhanani>  -- Create date: <Create Date,,11 Mar 2014>  -- Description: <Description,,Get the Employee Leave Type by Employee>  -- Call SP:  Payroll_GetEncashLeaveTypeByEmployeeId 5  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetEncashLeaveTypeByEmployeeId]   @EmployeeId INT  AS  BEGIN   SELECT DISTINCT C_LT.LeaveType_ID, C_LT.LeaveTypeDesc, 0 AS MaximumRedemption, 0 AS MinimumRedemption    FROM dbo.Payroll_EmployeeLeaveSchemeDetails AS P_EL   INNER JOIN dbo.Const_LeaveTypeDetails AS C_LTD ON P_EL.LeaveTypeDetailId = C_LTD.LeaveTypeDetailsId AND P_EL.EmployeeId = @EmployeeId AND P_EL.IsEnabled = 1   INNER JOIN Const_LeaveType AS C_LT ON C_LTD.LeaveTypeId = C_LT.LeaveType_ID   WHERE P_EL.EnCash = 1   END  

GO

