cription = REPLACE(@LabelDescription,'&amp;', '&')  --    END    --     IF ( @DivisionType = 'DivisionsAll')   --      BEGIN  --      INSERT INTO @tblFilteredDivision (DivisionParentId,DivisionId)  --      SELECT DISTINCT cdh.DivisionParentID, cd.Division_ID  FROM   [Const_DivisionHistory] as [CDH] with(nolock)  --      INNER JOIN [Const_Division] as [CD] with(nolock) on [CD].[Division_ID] = [CDH].[DivisionID] and [CD].[Enabled] = 1  --                        INNER JOIN Const_Department cdp ON cd.DepartmentID = cdp.Department_ID  --      INNER JOIN [Const_DepartmentHistory] as [CDPH] with(nolock) on [CDP].[Department_ID] = [CDPH].[DepartmentID]  --      WHERE   cdp.Enabled = 1 AND cd.Enabled = 1 --AND cdp.Department_ID = @DepartmentId  --      AND [CDH].[StartDate] <= @UntilDate and [CDH].[EndDate] >= @StartDate  --      AND [CDPH].[StartDate] <= @UntilDate and [CDPH].[EndDate] >= @StartDate  --     IF (@DivisionId = 0)  --     BEGIN  --        SELECT DISTINCT cd.Division_ID ,  --      (CONVERT(NVARCHAR(10),cdp.Department_ID) + '-'+ CONVERT(NVARCHAR(10),cd.Division_ID)) AS DeptDivId,  --                        ISNULL((SELECT DivisionParentID FROM dbo.Const_Division WHERE Division_ID = ISNULL(cd.DivisionParentID, 0)),0) AS DivisionParentID ,  --                        cdp.Department_ID ,  --      cdp.DepartmentCode + '-' + CD.DivisionCode + ' / ' + CD.DivisionDesc +  --      CASE WHEN EXISTS (SELECT 1 FROM dbo.Const_Division WHERE DivisionParentID = cd.Division_ID) THEN  ' (No)'  ELSE ' (Yes)' END   --      AS MunicipalClassification ,  --                        DepartmentDesc + ' / ' + DivisionDesc AS DepartDivisionDesc ,  --                        cd.DivisionDesc ,  --                        cd.DivisionCode ,  --                        cdp.DepartmentDesc ,  --                        cdp.DepartmentCode,  --      cdp.DepartmentCode + ' / ' + @LabelDeptDescription AS LabelDesc  --     FROM   [Const_Division] as [CD]   --                        INNER JOIN Const_Departm