tID = cdp.Department_ID  --      INNER JOIN [Const_DepartmentHistory] as [CDPH] with(nolock) on [CDP].[Department_ID] = [CDPH].[DepartmentID]  --      LEFT JOIN dbo.User_UserDivisions uud ON uud.DivisionID = cd.Division_ID  --      WHERE cdp.Enabled = 1  --                        AND cd.Enabled = 1 AND cd.Division_ID = @DivisionId  --      AND [CDH].[StartDate] <= @UntilDate and [CDH].[EndDate] >= @StartDate  --      AND [CDPH].[StartDate] <= @UntilDate and [CDPH].[EndDate] >= @StartDate  --      AND (CASE WHEN @UserId = 0 THEN 0  --      ELSE uud.UserID END = @UserId )  --    END;  --   END    --  --SELECT  cd.Division_ID ,0 AS DivisionParentID ,0 AS Department_ID , DivisionCode  AS MunicipalClassification , DivisionDesc AS DepartDivisionDesc ,  --                      --  cd.DivisionDesc ,cd.DivisionCode ,'DepartmentDesc' AS DepartmentDesc ,'DepartmentCode' AS DepartmentCode,'LabelDesc' AS LabelDesc  --                --FROM    [Const_Division] as [CD] with(nolock)  --    END;  --GO  --IF @@ERROR <> 0 SET NOEXEC ON  --GO  --PRINT N'Altering [dbo].[Payroll_GetExistingIRP5Details]'  --GO    /*=============================================  Create date: 2018/06/25  Name: Richa Mills  Description: Get existing IRP5 details   Call SP: [Payroll_GetExistingIRP5Details]  'August', '2017/2018',5  =============================================*/  CREATE PROCEDURE [dbo].[Payroll_GetExistingIRP5Details]      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @CycleId INT  AS      BEGIN            If ISNULL(@CycleId,0) = 0    BEGIN     SELECT  * FROM  dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear    END    ELSE    BEGIN     SELECT  * FROM    dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @CycleId    END                 END    

GO

-- ============================================
-- SP: Payroll_GetExistingSCOAFunctionIDByEmployee
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  James Roodt  -- Create date: 2015-05-27  -- Description: Returns the SCOA Function code ID by finding the SCOA Functoin code for the selected employee's basic salary  -- EXEC Payroll_GetExistingSCOAFunctionIDByEmployee 1    -- =============================================  create PROCEDURE [dbo].[Payroll_GetExistingSCOAFunctionIDByEmployee]    -- Add the parameters for the stored procedure here   @EmployeeID int    AS  BEGIN    DECLARE @FunctionCodeID int  select @FunctionCodeID=FunctionCodeID  --get and use this value as default in all 5 instances  from Payroll_EmployeePayrollDefinition as epd   left join Payroll_SalaryHead sh on sh.SalaryHead_ID=epd.PayrollSalaryHeadID  where sh.SalaryHead_ID=1   ---hardcoded as 1 equals basic csalary  and EmployeeID=@EmployeeID   --cahgnes per employee       select @FunctionCodeID;  END    

GO

-- ============================================
-- SP: Payroll_GetExtraTransactions_ForActiveMedicalAid_sp
-- Schema: dbo
-- ============================================
  -- =================================================================================================  -- Author:  Ravindra Jijotia  -- Create date: 21 JULY 2015  -- Description: Select all the Extra Medical Aid Transactions for given employee.  -- Call:  Add Employee screen  -- 2016-09-15 TP44504 Lungisani Khumalo : modified all calculating to exclude the 'IsPrivate' column  -- =================================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetExtraTransactions_ForActiveMedicalAid_sp]     @EmployeeID INT  AS  BEGIN    SELECT    EAMAT.ExtraActiveMedicalAidTransaction_ID,   EMA.EmployeeMedicalAID_ID,    EMA.MedicalAidSchmeID,    CONVERT(NVARCHAR(12),EMA.JoinDate, 103) AS JoinDate,   CONVERT(NVARCHAR(12),EMA.TerminationDate, 103) AS TerminationDate,   V.VendorName AS Fund,   MS.FundName AS PlanName,   (select MedicalAidContributionTypeCaption from Const_Payroll_MedicalAidContributionType where MedicalAidContributionType_ID = EAMAT.MedicalAidContributionTypeID) as ContributionType,   CONVERT(NVARCHAR(12),EAMAT.PeriodFrom, 103) AS PeriodFrom,      CONVERT(NVARCHAR(12),EAMAT.PeriodTo, 103) AS PeriodTo,   EAMAT.Amount,   EMA.Reference,   MSD.MemberAmount,   MSD.AdultAmount,   MSD.ChildAmount,   MS.EmployeeContributionValue,   MS.EmployerContributionValue,   MS.EmployerMaxContributorValue,   --MS.Editable AS ISPrivate,   CASE WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  < CAST(GETDATE() AS DATE ) THEN 'Terminated'     WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )  THEN 'Active'      WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  >= CAST(GETDATE() AS DATE ) THEN 'Pending'   ELSE '' END  AS Status,      CASE WHEN EAMAT.IsEmployerContribute = 1 THEN     'Yes'   ELSE     'No'    END AS IsEmployerContribute  FROM Payroll_ExtraActiveMedicalAidTransaction EAMAT       INNER JOIN Payroll_EmployeeMedicalAIDDetail EMA on EMA.EmployeeMedicalAID_ID = EAMAT.EmployeeMedicalAIDID    INNER JOIN dbo.Const_MedicalAIDScheme MS ON MS.MedicalScheme_ID = EMA.MedicalAidSchmeID    INNER JOIN dbo.Const_MedicalAIDSchemeDetail MSD ON MSD.MedicalSchemeID= MS.MedicalScheme_ID    INNER JOIN dbo.Cons_Vendor V ON V.Vendor_ID = MS.VendorID  WHERE EMA.EmployeeID = @EmployeeID AND EMA.Enable=1 AND EAMAT.Enabled = 1    END      

GO

-- ============================================
-- SP: Payroll_GetExtraTransactionsForMedicalAID_sp
-- Schema: dbo
-- ============================================
-- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  CREATE PROCEDURE [dbo].[Payroll_GetExtraTransactionsForMedicalAID_sp]   @EmployeeID INT,   @EmployeeMedicalAIDID INT  AS    BEGIN   DECLARE @CycleID INT   SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID       DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)   SELECT @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND TaxYear = @TaxYear      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear     select Amount, IsEmployerContribute from [Payroll_ExtraActiveMedicalAidTransaction]   where Enabled = 1 and EmployeeMedicalAIDID = @EmployeeMedicalAIDID   AND CAST(@ToDate AS DATE) BETWEEN DATEADD(month, DATEDIFF(month, 0, PeriodFrom), 0) AND DATEADD(s,-1,DATEADD(mm, DATEDIFF(m,0,CAST(PeriodTo AS DATE))+1,0))     --select @ToDate as ToDate, PeriodFrom, DATEADD(s,-1,DATEADD(mm, DATEDIFF(m,0,CAST(PeriodTo AS DATE))+1,0)) as PeriodTo   --from [Payroll_ExtraActiveMedicalAidTransaction]   --where Enabled = 1 and EmployeeMedicalAIDID = @EmployeeMedicalAIDID   --AND CAST(@ToDate AS DATE) BETWEEN CAST(PeriodFrom AS DATE) AND DATEADD(s,-1,DATEADD(mm, DATEDIFF(m,0,CAST(PeriodTo AS DATE))+1,0))     END  

GO

-- ============================================
-- SP: Payroll_GetFinalRunSummary_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 24/03/2017   Description : Get Trial Summary Results from Trial Results   Update date : 09/05/2017 - Changed the mappings for Method of Calculation   Update Date : 04/04/2019 - Changed query to point to Trial Results  */  create procedure [Payroll_GetFinalRunSummary_sp] @PeriodID int  as    begin     set nocount on;     select null as [Reason], [TP].[EmployeeID], min([PE].[EmpCode]) as [EmpCode], min([PE].[FirstName]) as [FirstName], min([PE].[Surname]) as [Surname], min([PE].[FixedSalary]) as [Salary],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 1 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Earnings],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Deductions],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 3 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Contributions],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 4 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Fringe],      (cast(isnull(sum(case when [TP].[TransactionTypeID] = 1 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) -       cast(isnull(sum(case when [TP].[TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2))) as [Total]      from [Payroll_PayrollResults] as [TP] with(nolock)       join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = [TP].[CycleID]      where ([TP].[PeriodID] = @PeriodID)      group by [TP].[EmployeeID]       order by [TP].[EmployeeID]     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetFinanceYearWiseFTDate
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Phuti chokoe  -- Create date: 20 OCT 2016  -- =============================================  CREATE proc [dbo].[Payroll_GetFinanceYearWiseFTDate]  @TaxYear nvarchar(max)  as  SELECT 0 as Period_ID,CycleID,TaxYear,MIN(PeriodStartDate) as PeriodStartDate,MAX(PeriodEndDate) as PeriodEndDate FROM Payroll_CyclePeriodDetails WHERE TaxYear=@TaxYear AND Enabled=1 AND CycleModeID=1 GROUP BY CycleID,TaxYear  

GO

-- ============================================
-- SP: Payroll_GetFringeDetails_By_BenefitID_sp
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetFringeDetails_By_BenefitID_sp] @BenefitID int  as    begin     select row_number() over (order by [FringeBenefit_ID]) as [Sequence], [FringeBenefit_ID], [Description], [Percentage], [BenefitID], [SalaryHeadName] as [PayrollSalaryHeadIDDesc]      from [Payroll_Fringe_BenefitDetail] as [FRI] with(nolock)       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PayrollSalaryHeadID]      where ([BenefitID] = @BenefitID and [FRI].[Enabled] = 1 and [SH].[Enabled] = 1)    end  

GO

-- ============================================
-- SP: Payroll_GetGeneralLedgerHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 06/06/2017   Description : Gets the General Ledger Transaction History   Update  : 2019/05/27 => Updated the SCOA Mappings to include various other SCOA Item lookups while linking the values to the Financial Year lookup functions   Update  : 2019/05/29 => Updated the SCOA lookups to links to a predefined temporary table  */  CREATE procedure [dbo].[Payroll_GetGeneralLedgerHistory_sp] @SalaryHeadID int = null, @Enabled bit = null, @FinYear nvarchar(9) = null  as  begin     set nocount on;     select distinct       [GLH].[GLHistory_ID],     [GLH].[SalaryHeadID],     [GLH].[FinYear],     [CS2].[ScoaShortDesc] as [MunicipalScoa],     [CS3].[ScoaShortDesc] as [SeniorScoa],     [CS4].[ScoaShortDesc] as [CouncillorScoa],     [CS5].[ScoaShortDesc] as [PostScoa],     [GLH].[StartDate],     [GLH].[EndDate],     [GLH].[Enabled],     [GLH].[JournalEntryOnly],     [CS2].[ScoaDesc] + ': ' + [CS2].[ScoaCode] as [ExpenditureItem],     CAST([PPD].[ProjectCode] AS varchar(10)) + ' ' + [PPD].[ProjectName] as [ControlProject],     (case when [GLH].[JournalEntryOnly] = 1 then null else [CS1D].[ScoaDesc] + ': ' + [CS1D].[ScoaCode] end) as [ControlItem],     [CS1C].[ScoaDesc] + ': ' + [CS1C].[ScoaCode] as [ControlItemCredit],     [CV].[VendorName],     CAST([PPD].[ProjectCode] AS varchar(10)) + ' ' + [PPD].[ProjectName] as [CreditorProject],    [CS2C].[ScoaDesc] + ': ' + [CS2C].[ScoaCode] as [CreditorItem],     CAST([PPJ].[Project_ID] AS varchar(10)) + ' ' + [PPJ].[ProjectName] as [JournalProject],     (case when [GLH].[JournalEntryOnly] = 1 then [CS1D].[ScoaDesc] + ': ' + [CS1D].[ScoaCode] else null end) as [JournalItem]      from (Select * from [Payroll_GLHistory]           where  [SalaryHeadID] = @SalaryHeadID             and [Enabled] = (case when @Enabled is null then  [Enabled] else @Enabled end)         and [FinYear] = (case when isnull(@FinYear, '*') = '*' then  [FinYear] else @FinYear end)) as [GLH]         left outer join [Cons_Vendor] as [CV] with(nolock) on [CV].[Vendor_ID] = [GLH].[VendorID]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS1D] on [CS1D].[ScoaID] = [GLH].[SuspenseScoaItemID]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS1C] on [CS1C].[ScoaID] = [GLH].[SuspenseScoaItemCreditID]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS2C] on [CS2C].[ScoaID] = [GLH].[VendorScoaId]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS2] on [CS2].[ScoaID] = [GLH].[ScoaItemIDPermanentStaff]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS3] on [CS3].[ScoaID] = [GLH].[ScoaItemIDSeniorManagers]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS4] on [CS4].[ScoaID] = [GLH].[ScoaItemIDCouncillors]       left outer join (Select * from  [Const_Scoa_Structure_Filtered](@FinYear)) as [CS5] on [CS5].[ScoaID] = [GLH].[ScoaItemIDPostRetirement]       left outer join [Plan_Project] as [PPD] on [PPD].[Project_ID] = [GLH].[SCOAProjectID]       left outer join [Plan_Project] as [PPC] on [PPC].[Project_ID] = [GLH].[VendorScoaProjectId]       left outer join [Plan_Project] as [PPJ] on [PPJ].[Project_ID] = [GLH].[SCOAItemProjectID]        set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetGrievanceDocument
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,15 Mar 2014>  -- Description: <Description,,Payroll_GetDisciplinaryDocument>  -- Call SP:  Payroll_GetGrievanceDocument 3  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetGrievanceDocument]   @GrievanceID INT  AS  BEGIN   SELECT (ROW_NUMBER() OVER (ORDER BY P_D.Document_Id)) - 1 AS Document_Id, DocumentName, CONVERT(nvarchar(50), ISNULL(P_D.DateModified, P_D.DateCaptured), 101) as DocDate, 0 as IsNew, ISNULL(P_E1.FirstName, P_E.FirstName) AS UploadedBy FROM Payroll_GrievanceDocumentDetails AS P_D   INNER JOIN User_UserDetail AS P_E ON P_E.User_ID = P_D.CapturerID   LEFT OUTER JOIN User_UserDetail AS P_E1 ON P_E1.User_ID = P_D.ModifierID   WHERE P_D.Enabled = 1 AND GrievanceId = @GrievanceID  END    

GO

-- ============================================
-- SP: Payroll_GetGrievanceSubmittedEmployee
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:Phuti chokoe  -- Create date: 20 July 2016  -- Description: Get Aggrived employees to populate in the Main grievance search table  -- Call : [[Payroll_GetGrievanceSubmittedEmployee]]   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetGrievanceSubmittedEmployee]  @GrievanceID int  AS  BEGIN   SELECT    PET.EmployeeID as Employee_ID,    PE.EmpCode,   PE.FirstName,   PE.IdNo,   PE.PassportNumber,   PE.Surname,   PET.GrievanceID as Grievance_ID,   G.GrievanceDate,   G.FinalOutcome,   G.Status,   O.GrievanceOffenceType,   S.FirstName AS SubmittedAgainst,   G.EmployeeSubmittedAgainstID    FROM dbo.Payroll_GrievanceEmployeeSubmittedBy PET    INNER JOIN dbo.Payroll_Employee PE ON PE.Employee_ID = PET.EmployeeID    INNER JOIN DBO.Payroll_Grievance G ON G.Grievance_ID = @GrievanceID    INNER JOIN DBO.Const_GrievanceOffenceType O ON O.GrievanceOffenceType_ID = PET.OffenseType    INNER JOIN dbo.Payroll_Employee S ON G.EmployeeSubmittedAgainstID = s.Employee_ID    AND PET.GrievanceID = @GrievanceID    ANd PET.Enabled = 1  END    

GO

