-- SP: Payroll_GetHRPayrollSettings_sp
-- Schema: dbo
-- ============================================
-- -- ==============================================================================      ---- Author  : Teboho Mofokeng      ---- Create date: 08 March 2017      ---- Description: Return all the menu items for HR/Payroll Settings.      ---- EXEC Payroll_GetHRPayrollSettings_sp      --  05 July 2019  #85784 -- Apply logic for the all payroll constant menu.   --  01 Aug 2019 -- #92401 Apply logic for the "Const_LeaveToEmployeeSubtype" for "Assign Employee Subtypes to Leave Types"  ---- ==============================================================================      CREATE PROCEDURE [dbo].[Payroll_GetHRPayrollSettings_sp]  AS              BEGIN       CREATE TABLE #Status  (ID INT IDENTITY(1,1)  ,ConstantMenu_ID INT, TableName NVARCHAR(200), STatusID INT)         INSERT INTO #Status(ConstantMenu_ID,TableName)     SELECT distinct A.[ConstantMenu_ID], B.[TableName]         FROM         [dbo].[Const_ConstantMenu_sys] A      LEFT  JOIN [dbo].[Const_ConstantSetup_sys]  B      ON A.ConstantMenu_ID = B.ConstantMenuId      WHERE A.ModuleID =3                DECLARE @cnt INT = 1;     DECLARE @MaxCount INT = (SELECT Count('x') FROM #Status )     DECLARE @CurrentTable NVARCHAR(200)     DECLARE @DynSQL NVARCHAR(MAX)                 WHILE @cnt <= @MaxCount    BEGIN              SET @CurrentTable = (SELECT TableName FROM #Status WHERE ID = @cnt)       if(@CurrentTable IS NOT NULL)       BEGIN              IF EXISTS (SELECT 'x' FROM sys.tables WHERE NAME = @CurrentTable)       BEGIN       SET @DynSQL = N' IF EXISTS(SELECT ''x'' FROM '+@CurrentTable +') Update  #Status Set StatusID = 1  WHERE ID = '+  CAST(@cnt AS VARCHAR(5)) +        ' ELSE Update  #Status Set StatusID = 3  WHERE ID = '+  CAST(@cnt AS VARCHAR(5))       EXEC sp_executesql @DynSQl       END       END       SET @cnt = @cnt + 1;    END;              UPDATE #Status SET  StatusID = 3 WHERE StatusID IS NULL             DECLARE @Id INT = 0     DECLARE @ActiveFinYear VARCHAR(9)     IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_Municipality')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_Municipality'     SELECT @ActiveFinYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'ActiveFinYear'   IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_Municipality WHERE FinYear= @ActiveFinYear )     BEGIN   UPDATE  #Status SET  StatusID = 2 WHERE ID = @ID     END  END    --Payroll_Notch   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_Notch')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_Notch'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_Notch)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END      ---Payroll_EmployeeSubtypes   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_EmployeeSubtypes')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_EmployeeSubtypes'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_EmployeeSubtypes)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    ---Payroll_ConditionOfService   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_ConditionOfService')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_ConditionOfService'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_ConditionOfService)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END        --Const_EthnicGroup   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_EthnicGroup')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_EthnicGroup'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_EthnicGroup)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END      --Const_Cycle   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Cycle')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Cycle'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Cycle)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Payroll_CyclePeriodDetails   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_CyclePeriodDetails')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_CyclePeriodDetails'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_CyclePeriodDetails)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Const_Payroll_TaxPeriods   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Payroll_TaxPeriods')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Payroll_TaxPeriods'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Payroll_TaxPeriods)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Const_MedicalAIDScheme   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_MedicalAIDScheme')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_MedicalAIDScheme'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_MedicalAIDScheme)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_UnionRepresentatives   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_UnionRepresentatives')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_UnionRepresentatives'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_UnionRepresentatives)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Payroll_BenefitDetail   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_BenefitDetail')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_BenefitDetail'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_BenefitDetail)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Payroll_SalaryHead   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_SalaryHead')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_SalaryHead'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_SalaryHead)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Payroll_PayrollConstants   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_PayrollConstants')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_PayrollConstants'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_PayrollConstants)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Payroll_PayPoint   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_PayPoint')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_PayPoint'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_PayPoint)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Payroll_PayrollDefination   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_PayrollDefination')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_PayrollDefination'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_PayrollDefination)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Const_Claims   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Claims')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Claims'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Claims)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END     --Payroll_ReasonEmployeeChange   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_ReasonEmployeeChange')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_ReasonEmployeeChange'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_ReasonEmployeeChange)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_TaxRebates   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_TaxRebates')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_TaxRebates'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_TaxRebates)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_TaxThresholds   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_TaxThresholds')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_TaxThresholds'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_TaxThresholds)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END        if EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_UpperLimit')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_UpperLimit'     IF NOT EXISTS(SELECT 'x' FROM Const_UpperLimits)     UPDATE  #Status SET  StatusID = 2 WHERE ID = @ID        END          --Const_Holiday   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Holiday')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Holiday'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Holiday)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_Shift   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Shift')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Shift'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Shift)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END      if EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_ShiftRotation')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_ShiftRotation'   IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_ShiftRotation)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END     ELSE IF NOT EXISTS(SELECT 'x' FROM Payroll_ShiftRotationDetail)     UPDATE  #Status SET  StatusID = 2 WHERE ID = @ID    END     --Const_LeaveType   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_LeaveType')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_LeaveType'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_LeaveType)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END     Else IF NOT EXISTS(SELECT 'x' FROM dbo.Const_LeaveTypeDetails)     BEGIN   UPDATE  #Status SET  StatusID = 2 WHERE ID = @ID     END  END     --Const_LeaveToEmployeeSubtype   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_LeaveToEmployeeSubtype')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_LeaveToEmployeeSubtype'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_LeaveToEmployeeSubtype)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_AbsenceType   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_AbsenceType')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_AbsenceType'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_AbsenceType)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_LeaveScheme   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_LeaveScheme')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_LeaveScheme'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_LeaveScheme)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END       --Const_NotApprovedReason   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_NotApprovedReason')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_NotApprovedReason'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_NotApprovedReason)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_PMSCoreCompentencyRequirement_Detail   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_PMSCoreCompentencyRequirement_Detail')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_PMSCoreCompentencyRequirement_Detail'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_PMSCoreCompetencyRequirement)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END      --Const_PMSCoreCompentencyRequirement_Header   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_PMSCoreCompentencyRequirement_Header')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_PMSCoreCompentencyRequirement_Header'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_PMSCoreCompetencyRequirement)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_PMSCoreCompetencyRequirement   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_PMSCoreCompetencyRequirement')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_PMSCoreCompetencyRequirement'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_PMSCoreCompetencyRequirement)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_Qualification_Sys   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Qualification_Sys')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Qualification_Sys'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Qualification_Sys)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_JobProfileArea   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_JobProfileArea')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_JobProfileArea'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_JobProfileArea)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_JobProfileKPI   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_JobProfileKPI')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_JobProfileKPI'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_JobProfileKPI)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Payroll_WSP_SkillsDevelopmentFacilitator   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_WSP_SkillsDevelopmentFacilitator')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_WSP_SkillsDevelopmentFacilitator'     IF NOT EXISTS(SELECT 'x' FROM dbo.Payroll_WSP_SkillsDevelopmentFacilitator)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_DisiplinaryOffenceType   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_DisiplinaryOffenceType')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_DisiplinaryOffenceType'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_DisiplinaryOffenceType)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Const_GrievanceOffenceType   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_GrievanceOffenceType')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_GrievanceOffenceType'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_GrievanceOffenceType)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END      --Const_Document   IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_Document')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Const_Document'     IF NOT EXISTS(SELECT 'x' FROM dbo.Const_Document)     BEGIN   UPDATE  #Status SET  StatusID = 3 WHERE ID = @ID     END  END    --Payroll_EmployeeScreen'  if EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_EmployeeScreen')     BEGIN     Select @Id = ID FROM #Status WHERE TableName = 'Payroll_EmployeeScreen'     IF NOT EXISTS(SELECT 'x' FROM Payroll_Const_ScreenSections)     UPDATE  #Status SET  StatusID = 2 WHERE ID = @ID        END    --Payroll_FieldOfStudy  IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Payroll_FieldOfStudy')    BEGIN     SELECT @Id = ID FROM #Status WHERE TableName = 'Payroll_FieldOfStudy'     IF NOT EXISTS(SELECT 'x' FROM Payroll_FieldOfStudy WHERE [Enabled] = 1)      UPDATE #Status SET StatusID = 3 WHERE ID = @Id  END    --EmployeeType  IF EXISTS (SELECT 'x' FROM #Status WHERE TableName = 'Const_EmployeeType_sys')    BEGIN     SELECT @Id = ID FROM #Status WHERE TableName = 'Const_EmployeeType_sys'          UPDATE #Status SET StatusID = 1 WHERE ID = @Id  END        SELECT   distinct A.[ConstantMenu_ID]           ,A.[Description]           ,A.[PermissionID]           ,A.[ParentID]           ,A.[ConstantMenuURL]           ,A.[SortOrder]           , tmp.StatusId as StatusID           ,B.ConstantMenuId        FROM [dbo].[Const_ConstantMenu_sys] A        LEFT  JOIN [dbo].[Const_ConstantSetup_sys]  B        ON A.ConstantMenu_ID = B.ConstantMenuId        INNER JOIN #Status tmp ON  tmp.ConstantMenu_ID = A.ConstantMenu_ID      WHERE A.ModuleID =3        ORDER BY A.ParentID,A.SORTORDER            --   DROP TABLE  #Status             END

