-- ============================================
-- SP: Payroll_GetInvoices_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_GetInvoices_sp]        @StartDate DATETIME,        @EndDate   DATETIME  AS  BEGIN        DROP TABLE IF EXISTS [#Periods];        SELECT [Period_ID]      INTO [#Periods]      FROM [Payroll_CyclePeriodDetails]      WHERE [PeriodStartDate] >= @StartDate            AND [PeriodEndDate] <= @EndDate;        SELECT [pt].[PeriodId]            ,[pt].[TransactionTypeID]            ,[pt].[SalaryHeadId]            ,[SalaryHeadName]            ,[pt].[Amount]            ,[pt].[PaymentDate]      FROM (SELECT *            FROM [Payroll_PayrollResults] AS [ppr]                 INNER JOIN [#Periods] AS [p] ON [PeriodID] = [p].[Period_ID]            WHERE [TaxSavePurpose] = 0) AS [pt]           LEFT OUTER JOIN [Payroll_CyclePeriodDetails] AS [pcpd] ON [pt].[PeriodId] = [pcpd].[Period_ID]      LEFT OUTER JOIN [Payroll_SalaryHead] AS [psh] ON [psh].[Salaryhead_ID] = [pt].[SalaryHeadId];    END;

GO

-- ============================================
-- SP: Payroll_GetIRP5CodeHierarchy
-- Schema: dbo
-- ============================================
  /*   Author  : Ferd Botha   Create Date : 23/07/2018   Description : Returns all linked Payroll IRP5 Codes matching the Search Criteria  */  create procedure [Payroll_GetIRP5CodeHierarchy] @PeriodID int = null, @IRP5Code int = null, @ParentCode int = null, @SalaryHeadID int = null  as  begin     set nocount on;     declare @IRP5Codes table (      [Index] int not null,    [IRP5Code] int not null,    [ParentCode] int null     );     with [IRP5Tree] as (      select 0 as [Index], [PIH].[IRP5Code], [PIH].[ParentCode]       from [Payroll_IRP5CodeHierarchy] as [PIH] with(nolock)       where ([PIH].[Enabled] = 1 and [PIH].[ParentCode] is null)      union all      select [IT].[Index] + 1, [PIHT].[IRP5Code], [PIHT].[ParentCode]       from [Payroll_IRP5CodeHierarchy] as [PIHT] with(nolock)        join [IRP5Tree] as [IT] on [IT].[IRP5Code] = [PIHT].[ParentCode]       where ([PIHT].[Enabled] = 1 and not [PIHT].[ParentCode] is null)     )     insert into @IRP5Codes([Index], [IRP5Code], [ParentCode])      select [Index], [IRP5Code], [ParentCode] from [IRP5Tree]       where ([IRP5Code] = (case when @IRP5Code is null then [IRP5Code] else @IRP5Code end))       order by [Index], [IRP5Code], [ParentCode]        option (maxrecursion 99);     if (not @PeriodID is null)      select distinct [IC].[IRP5Code], [IC].[ParentCode], [SH].[SalaryHead_ID] as [SalaryHeadID]       from [Payroll_CyclePeriodAdhocSalaryHead] as [PSH] with(nolock)        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = (case when @SalaryHeadID is null then [SH].[SalaryHead_ID] else @SalaryHeadID end) and [SH].[SalaryHead_ID] = [PSH].[SalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join @IRP5Codes as [IC] on [IC].[IRP5Code] = isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code])       where ([PSH].[PeriodID] = @PeriodID and [PSH].[Enabled] = 1 and         isnull([IC].[IRP5Code], -1) = (case when @IRP5Code is null then isnull([IC].[IRP5Code], -1) else @IRP5Code end) and         isnull([IC].[ParentCode], -1) = (case when @ParentCode is null then isnull([IC].[ParentCode], -1) else @ParentCode end)       )        order by [IC].[IRP5Code], [SH].[SalaryHead_ID], [IC].[ParentCode]     else      select distinct [IC].[IRP5Code], [IC].[ParentCode], [SH].[SalaryHead_ID] as [SalaryHeadID]       from @IRP5Codes as [IC]        join [Payroll_IRP5Code] as [IRP5] on isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) = [IC].[IRP5Code] and [IRP5].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = (case when @SalaryHeadID is null then [SH].[SalaryHead_ID] else @SalaryHeadID end) and [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1       where (        isnull([IC].[IRP5Code], -1) = (case when @IRP5Code is null then isnull([IC].[IRP5Code], -1) else @IRP5Code end) and        isnull([IC].[ParentCode], -1) = (case when @ParentCode is null then isnull([IC].[ParentCode], -1) else @ParentCode end)       )        order by [IC].[IRP5Code], [SH].[SalaryHead_ID], [IC].[ParentCode]     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetIRP5Codes_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 02/06/2017   Description : Gets the list of IRP5 Codes   Updated  : 07/06/2017 - added @IRP5CodeID and @SalaryHeadID  */  create procedure [Payroll_GetIRP5Codes_sp] @IRP5CodeID int = null, @SalaryHeadID int = null, @StartDate datetime = '1900-01-01', @EndDate datetime = '9999-12-31', @TransactionTypeID int = null, @Enabled bit = null  as    begin     set nocount on;     if (not @SalaryHeadID is null and @SalaryHeadID > 0)      select @IRP5CodeID = [IRP5CodeId] from [Payroll_SalaryHead] with(nolock) where ([SalaryHead_ID] = @SalaryHeadID)     select [IRP5Code_ID], [TransactionTypeID], [TaxableID], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) as [IRP5Code], replicate('0', 4 - len(cast(isnull([IRP5CertCode], isnull([IRP5Code], 0)) as nvarchar))) + cast(isnull([IRP5CertCode], isnull([IRP5Code], 0)) as nvarchar) as [IRP5CertCode], [IRP5CodeDesc], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) + ' - ' + isnull([IRP5CodeDesc], '') as [IRP5CodeTitle], [Enabled], [TatxablePercentage], [Rules], [Formula], [StartDate], [EndDate]      from [Payroll_IRP5Code] with(nolock)      where ([IRP5Code_ID] = (case when @IRP5CodeID is null then [IRP5Code_ID] else @IRP5CodeID end) and [Enabled] = (case when @Enabled is null then [Enabled] else @Enabled end) and [TransactionTypeID] = (case when @TransactionTypeID is null or @TransactionTypeID = 0 then [TransactionTypeID] else @TransactionTypeID end) and [StartDate] <= @EndDate and [EndDate] >= @StartDate)     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetIRP5History_sp
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATE DATE : 04/09/2017   DESCRIPTION : GETS THE IRP5 TRANSACTION HISTORY  */  create procedure [Payroll_GetIRP5History_sp] @IRP5CodeID int = null, @SalaryHeadID int, @Enabled bit = null  as    begin     set nocount on;     select [IRP5CodeHistory_ID], [SalaryHeadID], [IRP5].[IRP5CodeID], [TransactionTypeID], [TaxableID], [TaxabilityDesc], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) as [IRP5Code], replicate('0', 4 - len(cast(isnull([IRP5CertCode], isnull([IRP5Code], 0)) as nvarchar))) + cast(isnull([IRP5CertCode], isnull([IRP5Code], 0)) as nvarchar) as [IRP5CertCode], [IRP5CodeDesc], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) + ' - ' + isnull([IRP5CodeDesc], '') as [IRP5CodeTitle], [IRP5].[Enabled], [TatxablePercentage], [Rules], [Formula], [IRP5].[StartDate], [IRP5].[EndDate]      from [Payroll_IRP5CodeHistory] as [IRP5] with(nolock)       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [IRP5].[SalaryHeadID] and [SH].[Enabled] = 1       join [Const_Taxability] as [CT] with(nolock) on [Taxability_ID] = [TaxableID]      where ([IRP5].[IRP5CodeID] = (case when @IRP5CodeID is null then [IRP5].[IRP5CodeID] else @IRP5CodeID end) and [SalaryHead_ID] = (case when @SalaryHeadID is null then [SalaryHead_ID] else @SalaryHeadID end) and [IRP5].[Enabled] = (case when @Enabled is null then [IRP5].[Enabled] else @Enabled end))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetIRP5Income_Trial_sp
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATE DATE : 21/06/2017   DESCRIPTION : EMPLOYEE TOTAL INCOME BASED ON IRP5 CODES   UPDATE DATE : 30/06/2017 - UPDATED THE JOINS AND WHERE CLAUSE TO FILTER IRP5 CODES BASED ON VALID FROM AND VALID UNTIL   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Trial_sp] '06 + 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 deduction(s) + EMS deduction(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Trial_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 income(s) + EMS income(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable     @TransactionTypeID - where you want to match Transaction Type ID 1 to 4, then pass 0   @TransactionTypeID - where you want to match only Transaction Type ID 1, then pass 1   @TransactionTypeID - where you want to match only Transaction Type ID 2, then pass 2   @TransactionTypeID - where you want to match only Transaction Type ID 3, then pass 4   @TransactionTypeID - where you want to match only Transaction Type ID 4, then pass 8     if you wish to match multiple Transaction Type ID, then you need to combine them using SQL Bitwise OR, by creating a int variable and combining the ID you wish to compare, example:     declare @XOR int = (1 ^ 3) < this will match where the Transaction Type ID is 1 or 3   declare @XOR int = (1 ^ 2 ^ 3) < this will match where the Transaction Type ID is 1, 2 or 3   declare @XOR int = (2 ^ 3 ^ 4) < this will match where the Transaction Type ID is 2, 3 or 4   declare @XOR int = (1 ^ 4) < this will match where the Transaction Type ID is 1 or 4   declare @XOR int = (2 ^ 3) < this will match where the Transaction Type ID is 2 or 3   declare @XOR int = (2 ^ 4) < this will match where the Transaction Type ID is 2 or 4     exec [Payroll_GetTotalIRP5Income_Trial_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, @XOR, 2    */  CREATE procedure [Payroll_GetIRP5Income_Trial_sp]  as  begin     set nocount on;     declare @IRP5Code table (      [Type] tinyint not null,    [IRP5Code] int not null,    [IRP5Description] nvarchar(max) not null,    [Taxable] decimal(18, 6) not null,    [StartDate] datetime2 not null default('1964-03-01 00:00:00.0000000'),    [UntilDate] datetime2 not null default('9999-12-31 00:00:00.0000000')     )     /* 01 - INCOME RECORD(S) */   begin      insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3601, 'INCOME - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3651, 'FOREIGN INCOME - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3602, 'INCOME - NON TAXABLE', 0)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3652, 'FOREIGN INCOME - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3603, 'PENSION - TAXABLE', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3653, 'FOREIGN PENSION - TAXABLE', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3604, 'PENSION - NON TAXABLE', 0, '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3654, 'FOREIGN PENSION - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000', '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3605, 'ANNUAL PAYMENT - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3655, 'FOREIGN ANNUAL PAYMENT - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3606, 'COMMISSION', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3656, 'FOREIGN COMMISSION', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3607, 'OVERTIME', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3657, 'FOREIGN OVERTIME', 100, '2002-03-01 00:00:00.0000000', '2010-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3608, 'ARBITRATION AWARDS - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3658, 'FOREIGN ARBITRATION AWARDS - TAXABLE', 100, '2002-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [UntilDate]) values(1, 3609, 'ARBITRATION AWARDS - NON TAXABLE', 0, '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate], [UntilDate]) values(1, 3659, 'FOREIGN ARBITRATION AWARDS - NON TAXABLE', 0, '2002-03-01 00:00:00.0000000', '2009-02-28 23:59:59.9999999')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3610, 'ANNUITY FROM RETIREMENT FUND', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable], [StartDate]) values(1, 3660, 'FOREIGN ANNUITY FROM RETIREMENT FUND', 100, '2012-03-01 00:00:00.0000000')    insert into @IRP5Code([Type], [IRP5Code], [IRP5Description], [Taxable]) values(1, 3611, 'PURCHASED ANNUITIES - TAXABLE', 100)    insert into @IRP5Code([Type], [IRP5Code], [IRP5