-- ============================================
-- SP: Payroll_GetIRP5WithSalaryHead
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Mehul Panchal  -- Create date: 07 01 2014  -- Description:   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetIRP5WithSalaryHead]     AS  BEGIN   SET NOCOUNT ON;            Select    IRP5Code_ID AS PayrollSalaryHead_ID,    IRP5Code + ' - ' + IRP5CodeDesc AS IRP5CodeDesc   FROM dbo.Payroll_IRP5Code ORDER BY IRP5Code  END    

GO

-- ============================================
-- SP: Payroll_GetIRPCriteria_sp
-- Schema: dbo
-- ============================================
  /*=============================================   Create date: 07/Oct/2016  Name: Jaydev Jangid  Description:  GET IRP5 generated certificate submitted details  Call SP:  [Payroll_GetIRPCriteria_sp]  'February', '2015/2016',0  =============================================*/  create PROCEDURE [dbo].[Payroll_GetIRPCriteria_sp]      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @PayrollCycleId INT  AS      BEGIN            DECLARE @checkLock BIT;         -- check of All payroll cycle. if Entry done for All then return data for All cycle          SELECT  @checkLock = IsLock FROM dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = 0;            IF ISNULL((SELECT  1 FROM dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId), 0) = 1              BEGIN                  SELECT  * FROM    dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;              END;          ELSE              BEGIN                  SELECT  * FROM    dbo.Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = 0;              END;      END;    

GO

-- ============================================
-- SP: Payroll_GetIRPNoOfEmployee_sp
-- Schema: dbo
-- ============================================
/*=============================================   Create date: 09/Dec/2016  Name: Jaydev Jangid  Description: get no. of employee as per parameter  Payroll_GetIRPNoOfEmployee_sp 4,'February','2016/2017',0  =============================================*/  CREATE PROCEDURE [dbo].[Payroll_GetIRPNoOfEmployee_sp]      @PayrollCycleId INT ,      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @IsTerminated BIT   AS      BEGIN      DECLARE @noOfEmployee INT;    DECLARE @FromDate DATETIME;    DECLARE @ToDate DATETIME;    DECLARE @Month NVARCHAR(2);    DECLARE @TotalCertID NVARCHAR(200);    DECLARE @IsAllDone INT;      SELECT @IsAllDone = EMP.EmployeeTaxCertificate_ID FROM dbo.Payroll_EmployeeTaxCertificate EMP WHERE EMP.PayrollCycleId=0 and isnull(EMP.IsLock,0) = 1 and EMP.TaxPeriod = @TaxPeriod AND EMP.TaxYear = @TaxYear      IF ISNULL(@IsAllDone,0) = 0 --if not generated for ALL payroll cycle     BEGIN       SELECT TOP 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails      WHERE   ( CycleID = @PayrollCycleId OR @PayrollCycleId = 0  ) AND FinancialYear = @TaxYear ORDER BY Period_ID;          IF @TaxPeriod = 'February'       BEGIN        SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));        SET @Month = '02';       END;      ELSE       BEGIN        SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));        SET @Month = '08';       END;          SELECT @TotalCertID = ETC.EmployeeTaxCertificate_ID FROM dbo.Payroll_EmployeeTaxCertificate ETC WHERE ETC.TaxPeriod = @TaxPeriod AND ETC.TaxYear = @TaxYear          DECLARE @TotalCert TABLE (CycleId INT)      INSERT INTO @TotalCert ( CycleId )      SELECT ETC.EmployeeTaxCertificate_ID FROM dbo.Payroll_EmployeeTaxCertificate ETC WHERE ETC.TaxPeriod = @TaxPeriod AND ETC.TaxYear = @TaxYear        SELECT @noOfEmployee = count(vw.Employee_Id) FROM VwEmployeeIRP5CodeValue vw      LEFT JOIN Payroll_EmployeeDocumentDetails EDD ON  EDD.EmployeeID =vw.Employee_Id      WHERE CASE WHEN @IsTerminated = 1 THEN EndDate ELSE @FromDate END BETWEEN @FromDate AND @ToDate  AND PeriodEndDate BETWEEN @FromDate AND @ToDate and          CycleID IN (SELECT CASE WHEN @PayrollCycleId = 0 THEN Cycle_ID ELSE @PayrollCycleId END  FROM Const_Cycle WHERE Cycle_ID NOT IN       (SELECT EMP.PayrollCycleId FROM dbo.Payroll_EmployeeTaxCertificate EMP WHERE isnull(EMP.IsLock,0) = 1 and EMP.TaxPeriod = @TaxPeriod AND EMP.TaxYear = @TaxYear))           SELECT ISNULL(@noOfEmployee,0) AS noOfEmployee     END    ELSE     SELECT -11 AS noOfEmployee -- generated for all                    END  

GO

-- ============================================
-- SP: Payroll_GetJobProfilebyProfileGroup_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- call: [Payroll_GetJobProfilebyProfileGroup_sp] 4,6  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions--No changes was done   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetJobProfilebyProfileGroup_sp]    @ProfileGroup_ID int    ,@ProfileSubGroupId Int     AS  BEGIN       select distinct PSG.JobProfileID,JP.JobTitle from Payroll_Notch P_N    INNER JOIN Const_ProfileSubGroup PSG      ON PSG.ProfileSubGroup_ID =P_N.Notch_ID       INNER JOIN Const_ProfileGroup PG      ON PG.ProfileGroup_ID =PSG.ProfileGroupID      INNER JOIN Payroll_JobProfile JP      ON JP.JobProfile_ID =PSG.JobProfileID      where  P_N.Enabled = 1 and PSG.ProfileGroupID = @ProfileGroup_ID and PSG.ProfileSubGroup_ID=@ProfileSubGroupId  END      

GO

-- ============================================
-- SP: Payroll_GetJobProfileDetails
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Tshekedi Mogwere  -- Create date: 20 March 2017  -- Description: Get the    -- Call SP    : Payroll_GetJobProfileDetails ''  -- =============================================  CREATE procedure [Payroll_GetJobProfileDetails] @JobTitle nvarchar(50)  as    begin     select [JobProfile_ID], [JobTitle], [PTG].[TaskGradeName], [OccupationOFOCODE], [Occupation], [OL].[OccupationLevel], jp.[StartDate], jp.[EndDate]      from [Payroll_JobProfile] as [JP] with(nolock)       left outer join [Const_OccupationLevel_sys] as [OL] with(nolock) on [OL].[OccupationLevel_ID] = [JP].[JobFamily]       left outer join [Payroll_TaskGrade] as [PTG] with(nolock) on [TaskGrade_ID] = [TaskGradeId]      where ([JP].[Enabled] = 1 and [JobTitle] like '%' + @JobTitle + '%')    end

GO

-- ============================================
-- SP: Payroll_GetJobProfileDetailsById
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Tshekedi Mogwere  -- Create date: 20 March 2017  -- Description: Get the    -- Call SP    : Payroll_GetJobProfileDetails ''  -- =============================================  CREATE procedure [Payroll_GetJobProfileDetailsById] @JobProfileId int = null  as    begin     select [JobProfile_ID], [JobTitle], [PTG].[TaskGradeName], [OccupationOFOCODE], [Occupation], [OL].[OccupationLevel], jp.[StartDate], jp.[EndDate]      from [Payroll_JobProfile] as [JP] with(nolock)       left outer join [Const_OccupationLevel_sys] as [OL] with(nolock) on [OL].[OccupationLevel_ID] = [JP].[JobFamily]       join [Payroll_TaskGrade] as [PTG] with(nolock) on [TaskGrade_ID] = [TaskGradeId]      where ([JP].[JobProfile_ID] = isnull(@JobProfileId, [JP].[JobProfile_ID]))    end

GO

-- ============================================
-- SP: Payroll_GetJobProfileHistoryDetailsById
-- Schema: dbo
-- ============================================
-- =============================================    -- Author:  Pavan    -- Create date: 30 August 2017    -- Description: Get the History Details     -- Call SP    : Payroll_JobProfileHistory    -- Modified: richa mills 2017/09/14 - Can't INNER join Task grades because some job profiles are linked to upper limits instead of task grades  -- Modified Himil Modi 2018/10/03 -- add more columns employeeType,subtype ,function and status  -- Modiri 2019/10/05 #93737 Job Profile - History record to display from newest to oldest    -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetJobProfileHistoryDetailsById] @JobProfileId int = null    as        begin         select [JobProfileID], [JobTitle], [PTG].[TaskGradeName], [OccupationOFOCODE], [Occupation], [OL].[OccupationLevel] ,     CES.EmployeeTypeDescription , pes.EmployeeSubtypeDesc ,(CASE  ISNULL(jph.ISActive,1)  WHEN 1 THEN 'Active' ELSE 'InActive' END )AS Status, [JPH].StartDate, [JPH].EndDate        from [Payroll_JobProfileHistory] as [JPH] with(nolock)           LEFT outer join [Const_OccupationLevel_sys] as [OL] with(nolock) on [OL].[OccupationLevel_ID] = [JPH].[JobFamily]           LEFT join [Payroll_TaskGrade] as [PTG] with(nolock) on [TaskGrade_ID] = [TaskGradeId]          LEFT JOIN [dbo].[Const_EmployeeType_sys] AS CES ON CES.EmployeeType_ID = JPH.EmployeeTypeID          LEFT JOIN  dbo.Payroll_EmployeeSubtypes AS PES ON PES.EmployeeSubtype_ID = JPH.EmployeeSubtypeID          where ([JPH].[JobProfileID] = isnull(@JobProfileId, [JPH].[JobProfileID]))     order by [JPH].EndDate desc  end

GO

-- ============================================
-- SP: Payroll_GetJobProfileKPIList
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 08 03 2014  -- Call SP:  [Payroll_GetJobProfileKPIList] 2, 0, ''  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions--No changes  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetJobProfileKPIList] --20      @JobProfileId INT ,      @JobAreaId INT ,      @PerformanceIndicator NVARCHAR(50)  AS       BEGIN                    SELECT  kpi.KPI_Id, kpi.JobProfile_Id, kpi.Input_Activities, kpi.KeyPerformanceIndicators, kpi.Percentage, kpi.Enabled, kpi.DateCaptured, kpi.CapturerID, kpi.DateModified, kpi.ModifierID, jp.JobTitle, kpi.JobProfileArea_Id, JPA.JobProfileArea          FROM    const_jobprofilekpi kpi                  INNER JOIN Payroll_JobProfile jp ON jp.JobProfile_ID = kpi.JobProfile_Id                  INNER JOIN Const_JobProfileArea JPA ON JPA.JobProfileArea_ID = kpi.JobProfileArea_Id          WHERE   ( kpi.JobProfile_Id = @JobProfileId                    OR @JobProfileId = 0                  )                  AND ( kpi.JobProfileArea_Id = @JobAreaId                        OR @JobAreaId = 0                      )                  AND ( kpi.KeyPerformanceIndicators LIKE '%' + @PerformanceIndicator + '%' )      END    

GO

-- ============================================
-- SP: Payroll_GetJobProfileSubGroupWithNotch
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 17 JAN 2014  -- Description: Get Those Job Profile Sub Group Who have Notch  -- 2014-11-06: James Roodt: As notch have moved from Const_ProfileGroupDetails to   --    Payroll_Notches i updated the stored proc to match  -- 2014-12-01: James Roodt: Changed 'NotchDesc' to 'GradeName'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetJobProfileSubGroupWithNotch]     AS  BEGIN   SET NOCOUNT ON;        SELECT     DISTINCT Const_ProfileSubGroup.ProfileSubGroup_ID, Const_ProfileSubGroup.ProfileSubGroupDesc     FROM Const_ProfileSubGroup    WHERE Const_ProfileSubGroup.TaskGradeId!= 0 OR Const_ProfileSubGroup.TaskGradeId is not null    ORDER BY Const_ProfileSubGroup.ProfileSubGroupDesc ASC  END    

GO

-- ============================================
-- SP: Payroll_GetLastRunValidateDate_sp
-- Schema: dbo
-- ============================================
/*  -- =============================================  Create date: 2018/07/06  Name: Richa Mills  Description:  Get certificate last run date and last validate date for Employee Tax Screen by cycleID  Call SP:  [Payroll_GetLastRunValidateDate_sp] 1  =============================================*/    CREATE PROCEDURE [dbo].[Payroll_GetLastRunValidateDate_sp]  @CycleID int  AS      BEGIN          DECLARE @LastCertificateRunDate DATETIME;          DECLARE @LastValidateDate DATETIME;      If IsNull(@CycleId,0) = 0    BEGIN     SELECT  @LastCertificateRunDate = MAX(CertificateRunDate), @LastValidateDate = MAX(ValidateDate) FROM  Payroll_EmployeeTaxCertificate;    END    ELSE    BEGIN     SELECT  @LastCertificateRunDate = MAX(CertificateRunDate), @LastValidateDate = MAX(ValidateDate) FROM  Payroll_EmployeeTaxCertificate where PayrollCycleId = @CycleId    END            SELECT  @LastCertificateRunDate AS LastCertificateRunDate , @LastValidateDate AS LastValidateDate;        END;  

GO

-- ============================================
-- SP: Payroll_GetLeaveDeductionPriority_sp
-- Schema: dbo
-- ============================================
    CREATE procedure [dbo].[Payroll_GetLeaveDeductionPriority_sp]   @AbsenceTypeID int  as  begin        SELECT AP.AbsencePriority_ID, LT.LeaveType, LT.LeaveTypeDesc, AP.DeductionOrder, AP.StartDate, AP.EndDate, LT.LeaveType_ID      FROM [dbo].[Payroll_AbsencePriority] AP    LEFT OUTER JOIN Const_LeaveType LT      ON LT.LeaveType_ID = AP.LeaveTypeID    WHERE AP.AbsenceTypeID = @AbsenceTypeID     end      

GO

-- ============================================
-- SP: Payroll_GetLeaveScheme_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 20/06/2017   Description : Gets the Leave Schemes   -- 2023/11/16 Kiran WI96314 Fixed Leave Scheme search page filters not working 100%  */  CREATE procedure [dbo].[Payroll_GetLeaveScheme_sp]   @LeaveSchemeID int = null,   @TypeID int = null,   @SubtypeID int = null,   @ConditionID int = null,   @Enabled bit = null  as    begin     select [LeaveScheme_ID], [LeaveSchemeDesc], [EmployeeTypeDescription] as [EmployeeType], [EmployeeSubtypeDesc] as [EmployeeSubtype], [ConditionShortDesc] as [Condition], [LS].[StartDate], [LS].[EndDate]      from [Const_LeaveScheme] as [LS] with(nolock)       left join [Const_EmployeeType_sys] as [CE] with(nolock) on [EmployeeType_ID] = [LS].[EmployeeTypeID] and [CE].[Enabled] = [LS].[Enabled]           left join [Payroll_EmployeeSubtypes] as [PST] with(nolock) on [EmployeeSubtype_ID] = [LS].[EmployeeSubtypeID]           left join [Payroll_ConditionOfService] as [CS] with(nolock) on [ConditionOfService_ID] = [LS].[ConditionOfServiceID] and [CS].[Enabled] = [LS].[Enabled]         where    ([LeaveScheme_ID] = (case when @LeaveSchemeID is null or @LeaveSchemeID = 0 then [LeaveScheme_ID] else @LeaveSchemeID end)    and [LS].[Enabled] = (case when @Enabled is null then [LS].[Enabled] else @Enabled end))   and ISNULL([LS].[EmployeeTypeID],0) = (case when @TypeID is null or @TypeID = 0 then ISNULL([LS].[EmployeeTypeID],0) else @TypeID end)    and ISNULL([LS].[EmployeeSubtypeID],0) = (case when @SubtypeID is null or @SubtypeID = 0 then ISNULL([LS].[EmployeeSubtypeID],0) else @SubtypeID end)    and ISNULL([LS].[ConditionOfServiceID],0) = (case when @ConditionID is null or @ConditionID = 0 then ISNULL([LS].[ConditionOfServiceID],0) else @ConditionID end)  end

GO

-- ============================================
-- SP: Payroll_GetLeaveSchemeByEmployeeSubTypeAndConditionOfService_sp
-- Schema: dbo
-- ============================================
    /*   Author  : Richa Mills    Create date : 16/01/2018    Description : Get Leave Schemes for EmployeeSubType and ConditionOfService  */  CREATE PROCEDURE [dbo].[Payroll_GetLeaveSchemeByEmployeeSubTypeAndConditionOfService_sp] @SubtypeID INT = NULL,  @ConditionID INT = NULL  AS    BEGIN   SELECT 0 LeaveScheme_ID, 'No Leave Entitled' LeaveSchemeDesc   UNION ALL   SELECT DISTINCT    Const_LeaveScheme.LeaveScheme_ID      ,Const_LeaveScheme.LeaveSchemeDesc   FROM Const_LeaveScheme   INNER JOIN Const_LeaveSchemeTypeDetails    ON dbo.Const_LeaveScheme.LeaveScheme_ID = dbo.Const_LeaveSchemeTypeDetails.LeaveSchemeId   WHERE EmployeeSubTypeId = @SubtypeID   AND ConditionOfServiceId = @ConditionID    END

GO

-- ============================================
-- SP: Payroll_GetLeaveSchemeDetails_sp
-- Schema: dbo
-- ============================================
    /*   Author  : FERDI BOTHA   Create date : 22/06/2017   Description : Gets the Leave Scheme Details   170720-STRUCTURE-PAYROLL-000-AlterGetLeaveSchemeDetailsSP     Modified 2018/01/05 - Richa Mills - Changed the SP to bind to Absence Types instead of LeaveTypes as Absence Types gets linked to Leave Schemes.   */  CREATE procedure [dbo].[Payroll_GetLeaveSchemeDetails_sp] @LeaveSchemeID int = null, @SubtypeID int = null, @Enabled bit = null  as    begin     select [Detail_ID], AbsenceType as [Type], AbsenceType as [Description], [LS].[StartDate], [LS].[EndDate]      from [Const_LeaveSchemeTypeDetails] as [CLD] with(nolock)       join [Const_LeaveScheme] as [LS] with(nolock) on [LeaveScheme_ID] = [LeaveSchemeId] and [EmployeeSubtypeID] = (case when @SubtypeID is null or @SubtypeID = 0 then [EmployeeSubtypeID] else @SubtypeID end) and [LS].[Enabled] = [CLD].[Enabled]       join [Const_AbsenceType] with(nolock) on [AbsenceType_ID] = CLD.LeaveTypeId       left outer join [Const_LeaveClassification_sys] as [CLS] with(nolock) on [LeaveClassification_ID] = [LeaveClassificationID] and [CLS].[Enabled] = [CLD].[Enabled]     where ([LeaveSchemeId] = (case when @LeaveSchemeID is null or @LeaveSchemeID = 0 then [LeaveSchemeId] else @LeaveSchemeID end) and [CLD].[Enabled] = (case when @Enabled is null then [CLD].[Enabled] else @Enabled end))    end      

GO

