-- ============================================
-- SP: Payroll_GetLeaveSetupDetails_sp
-- Schema: dbo
-- ============================================
CREATE procedure [dbo].[Payroll_GetLeaveSetupDetails_sp]  as  begin  select   LeaveType_ID,LT.LeaveTypeDesc,LTE.EmployeeTypeID,LTE.EmployeeSubtypeID,LT.StartDate as LTStartDate,LT.EndDate as LTEndDate,LC.Description,LeaveType,    LTD.LeaveTypeDetailsId,LTD.StartDate as LTDStartDate, LTD.EndDate as LTDEndDate, PeriodStart,PeriodEnd,PeriodIndicator,AccrualInverval,NoOfDays, AccrualDays,LeaveScheme_ID,     LS.StartDate as LSStartDate,LS.EndDate as LSEndDate, /*LS.EmployeeSubtypeID,*/ ConditionOfServiceID   from    Const_LeaveToEmployeeSubtype LTE  inner join Const_LeaveType LT  on LTE.LeaveTypeID = LT.LeaveType_ID   inner join Const_LeaveClassification_sys LC  on LT.LeaveClassificationID = LC.LeaveClassification_ID   inner join Const_LeaveTypeDetails LTD  on LTD.LeaveTypeId = LT.LeaveType_ID   inner join Const_LeaveScheme LS  on LS.EmployeeTypeID = LTE.EmployeeTypeID  and LS.EmployeeSubtypeID = LTE.EmployeeSubtypeID  and ((LT.StartDate <= GetDate()) OR (LT.StartDate  is null))  and ((LT.EndDate >GetDate()) OR (LT.EndDate is null))    end  

