-- ============================================
-- SP: Payroll_GetLeaveTypeDetails_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 23/06/2017   Description : Gets the Leave Type Details  */  CREATE procedure [dbo].[Payroll_GetLeaveTypeDetails_sp] @LeaveTypeID int = null, @Enabled bit = null  as    begin     select [LeaveTypeDetailsId], [SequenceNo],     cast(isnull([PeriodStart], 0) as nvarchar) + ' - ' + cast(isnull([PeriodEnd], 0) as nvarchar) + (case when isnull([PeriodIndicator], 0) = 1 then ' Months' when isnull([PeriodIndicator], 0) = 2 then ' Years' else '' end) as [PeriodDesc],     (case [AccrualInverval] when 1 then 'Once-off' when 2 then 'Yearly' when 3 then 'Monthly' when 4 then 'Days' else '' end) as [AccrualInterval], [AccrualDays], [MaxAccumulation], [CompulsoryDays], [StartDate], [EndDate]      from [Const_LeaveTypeDetails] as [CLD] with(nolock)     where ([LeaveTypeId] = (case when @LeaveTypeID is null or @LeaveTypeID = 0 then [LeaveTypeId] else @LeaveTypeID end) and [Enabled] = (case when @Enabled is null then [Enabled] else @Enabled end))      order by [SequenceNo]    end  

GO

