-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 19/06/2017   Description : Gets the Leave Types   Modified : Richa Mills: Cater for LeaveClassification parameter TP59619   170720-STRUCTURE-PAYROLL-000-AlterGetLeaveTypesSP  */  CREATE procedure [dbo].[Payroll_GetLeaveTypes_sp] @LeaveTypeID int = null, @Enabled bit = null, @LeaveClassificationID int = null  as    begin     select [LeaveType_ID],  [LeaveType] [Description], [LeaveTypeDesc], [StartDate], [EndDate],[LeaveClassificationID]      from [Const_LeaveType] as [CL] with(nolock)       left outer join [Const_LeaveClassification_sys] as [CLS] with(nolock) on [LeaveClassification_ID] = [LeaveClassificationID] and [CLS].[Enabled] = [CL].[Enabled]     where ([LeaveType_ID] = (case when @LeaveTypeID is null or @LeaveTypeID = 0 then [LeaveType_ID] else @LeaveTypeID end)    and [CL].[LeaveClassificationID] = (case when @LeaveClassificationID is null OR @LeaveClassificationID = 0 then [CL].[LeaveClassificationID] else @LeaveClassificationID end)   and [CL].[Enabled] = (case when @Enabled is null then [CL].[Enabled] else @Enabled end))    end    

