-- ============================================
-- SP: Payroll_GetLeaveTypeToEmployeeSubtype_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 19/06/2017   Description : Gets the Leave Assignment Subtypes   -- Nidhi Desai - 20-07-2017 - Added Classification Changes  */  CREATE PROCEDURE [dbo].[Payroll_GetLeaveTypeToEmployeeSubtype_sp]      @LeaveTypeID INT = NULL ,      @TypeID INT = NULL ,      @SubtypeID INT = NULL ,      @Enabled BIT = NULL ,      @LeaveClassificationID INT = NULL  AS      BEGIN            SELECT  [LeaveEESubtype_ID] ,                  ISNULL([Description], [LeaveType]) AS [LeaveType] ,                  [EmployeeTypeDescription] AS [EmployeeType] ,                  [EmployeeSubtypeDesc] AS [EmployeeSubtype] ,                  [ELS].[StartDate] ,                  [ELS].[EndDate]          FROM    [dbo].[Const_LeaveToEmployeeSubtype] AS [ELS] WITH ( NOLOCK )                  LEFT OUTER JOIN [Const_LeaveType] AS [CL] WITH ( NOLOCK ) ON [LeaveType_ID] = [LeaveTypeID]                                                                AND [CL].[Enabled] = [ELS].[Enabled]                  LEFT OUTER JOIN [Const_EmployeeType_sys] AS [CE] WITH ( NOLOCK ) ON [EmployeeType_ID] = [ELS].[EmployeeTypeID]                                                                AND [CE].[Enabled] = [ELS].[Enabled]                  LEFT OUTER JOIN [Payroll_EmployeeSubtypes] AS [PST] WITH ( NOLOCK ) ON [EmployeeSubtype_ID] = [ELS].[EmployeeSubtypeID]                  LEFT OUTER JOIN [Const_LeaveClassification_sys] AS [CLS] WITH ( NOLOCK ) ON [LeaveClassification_ID] = [LeaveClassificationID]                                                                AND [CLS].[Enabled] = [ELS].[Enabled]          WHERE   ( [LeaveType_ID] = ( CASE WHEN @LeaveTypeID IS NULL                                                 OR @LeaveTypeID = 0                                            THEN [LeaveType_ID]                                            ELSE @LeaveTypeID                                       END )                    AND [ELS].[Enabled] = ( CASE WHEN @Enabled IS NULL                                                 THEN [ELS].[Enabled]                                                 ELSE @Enabled                                            END )                    AND [EmployeeType_ID] = ( CASE WHEN @TypeID IS NULL                                                        OR @TypeID = 0                                                   THEN [EmployeeType_ID]                                                   ELSE @TypeID                                              END )                    AND [EmployeeSubtype_ID] = ( CASE WHEN @SubtypeID IS NULL                                                           OR @SubtypeID = 0                                                      THEN [EmployeeSubtype_ID]                                                      ELSE @SubtypeID                                                 END )                    AND CLS.LeaveClassification_ID = ( CASE WHEN @LeaveClassificationID IS NULL                                                                OR @LeaveClassificationID = 0                                                            THEN CLS.LeaveClassification_ID                                                            ELSE @LeaveClassificationID                                                       END )                  );        END;    

GO

-- ============================================
-- SP: Payroll_GetLeaveTypeToEmployeeSubtypeHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 22/06/2017   Description : Gets the Leave Assignment Subtypes History  */  CREATE procedure [dbo].[Payroll_GetLeaveTypeToEmployeeSubtypeHistory_sp] @LeaveEESubtypeID int = null, @Enabled bit = null  as    begin     select [LeaveEESubtypeHistory_ID], isnull([Description], [LeaveType]) as [LeaveType], [EmployeeTypeDescription] as [EmployeeType], [EmployeeSubtypeDesc] as [EmployeeSubtype], [ELS].[StartDate], [ELS].[EndDate]      from [Const_LeaveToEmployeeSubtypeHistory] as [ELS] with(nolock)       left outer join [Const_LeaveType] as [CL] with(nolock) on [LeaveType_ID] = [LeaveTypeID] and [CL].[Enabled] = [ELS].[Enabled]       left outer join [Const_EmployeeType_sys] as [CE] with(nolock) on [EmployeeType_ID] = [ELS].[EmployeeTypeID] and [CE].[Enabled] = [ELS].[Enabled]       left outer join [Payroll_EmployeeSubtypes] as [PST] with(nolock) on [EmployeeSubtype_ID] = [ELS].[EmployeeSubtypeID]       left outer join [Const_LeaveClassification_sys] as [CLS] with(nolock) on [LeaveClassification_ID] = [LeaveClassificationID] and [CLS].[Enabled] = [ELS].[Enabled]     where ([ELS].[Enabled] = (case when @Enabled is null then [ELS].[Enabled] else @Enabled end) and [LeaveEESubtypeID] = (case when @LeaveEESubtypeID is null or @LeaveEESubtypeID = 0 then [LeaveEESubtypeID] else @LeaveEESubtypeID end))    end  

GO

-- ============================================
-- SP: Payroll_GetLockedTrialRuns_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create Date : 24/03/2017   Description : Get Trial Run Lockdown Results   Update Date : 11/03/2020 - Ilya Skavronskiy => added @PeriodID parameter  */  CREATE procedure [Payroll_GetLockedTrialRuns_sp] @PeriodID INT = NULL   as    begin     set nocount on;     declare @lockedTrialRuns table (      [Period_ID] [int] not null,    [PayrollCycleDescription] varchar(200) not null,    [Start_Date] [datetime] not null,    [End_Date] [datetime] not null,    [Total_Company_Cost] [decimal](18, 2) not null,    [TrialRunDate] [datetime] not null,    [ApprovedDate] [datetime] not null,    [ApprovedBy] [int] not null,    [Approved] [nvarchar](max) null,    [Employee_Count] [int] not null     )     insert into @lockedTrialRuns([Period_ID], [PayrollCycleDescription], [Start_Date], [End_Date], [Total_Company_Cost], [TrialRunDate], [ApprovedDate], [ApprovedBy], [Approved], [Employee_Count])      select [CPD].[Period_ID], [CC].[CycleDesc], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], sum(case       when [TR].[TransactionTypeID] in(1, 3) then [TR].[Amount]       else 0 end), [CPD].[TrialRunDate], isnull([CPD].[ApprovedDate], [CPD].[TrialRunDate]), isnull([CPD].[ApprovedBy], [CPD].[TrialRunBy]), (case       when [CPD].[ApprovedStatus] is null then 'No'       else [CPD].[ApprovedStatus] end), count(distinct [TR].[EmployeeID])       from [Payroll_TrialResults] as [TR] with(nolock)        join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TR].[PeriodID] and [CPD].[Enabled] = 1        join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [CPD].[CycleID] and [CC].[Enabled] = 1       where [CPD].[LockedDown] = 1 and [CPD].[Processed] = 0 and [TR].[TransactionTypeID] in(1, 2, 3) and (@PeriodID IS NULL OR [CPD].[Period_ID] = @PeriodID)        group by [CPD].[Period_ID], [CC].[CycleDesc], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], [CPD].[TrialRunDate], isnull([CPD].[ApprovedDate], [CPD].[TrialRunDate]), isnull([CPD].[ApprovedBy], [CPD].[TrialRunBy]), [CPD].[ApprovedStatus]     insert into @lockedTrialRuns([Period_ID], [PayrollCycleDescription], [Start_Date], [End_Date], [Total_Company_Cost], [TrialRunDate], [ApprovedDate], [ApprovedBy], [Approved], [Employee_Count])      select [CPD].[Period_ID], [CC].[CycleDesc], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], 0, [CPD].[TrialRunDate], isnull([CPD].[ApprovedDate], [CPD].[TrialRunDate]), isnull([CPD].[ApprovedBy], [CPD].[TrialRunBy]), (case       when [CPD].[ApprovedStatus] is null then 'No'       else [CPD].[ApprovedStatus] end), 0       from [Payroll_CyclePeriodDetails] as [CPD] with(nolock)        join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [CPD].[CycleID] and [CC].[Enabled] = 1       where ([CPD].[Enabled] = 1 and [CPD].[LockedDown] = 1 and [CPD].[Processed] = 0 and (@PeriodID IS NULL OR [CPD].[Period_ID] = @PeriodID) and not exists(         select top 1 [Period_ID]          from [Payroll_TrialResults] with(nolock)          where ([PeriodID] = [CPD].[Period_ID] and [CycleID] = [CPD].[CycleID])        )       )        group by [CPD].[Period_ID], [CC].[CycleDesc], [CPD].[PeriodStartDate], [CPD].[PeriodEndDate], [CPD].[TrialRunDate], isnull([CPD].[ApprovedDate], [CPD].[TrialRunDate]), isnull([CPD].[ApprovedBy], [CPD].[TrialRunBy]), [CPD].[ApprovedStatus]     select [Period_ID], [PayrollCycleDescription], [Start_Date], [End_Date], [Total_Company_Cost], [TrialRunDate], [ApprovedDate], [ApprovedBy], [Approved], [Employee_Count]      from @lockedTrialRuns      order by [Period_ID]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetMedicalAidContribution_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 13 02 2014  -- Description:   -- CALLS : --EXEC Payroll_GetMedicalAidCOntribution 1,1,0  -- 2015-01-19 James Roodt: Check max child dependants and use it if count is exceeded. (@Child3MoreAmount)  -- 2015-02-05 James Roodt: Removed Payroll_Employee's MedicalSchemeID column as the link is in link table Payroll_EmployeeMedicalAIDDetail  -- 2015-05-06 James Roodt: Changed ActiveFinYear to ActivePayrollYear  -- 2015-06-23 Ravindra Jijotia: TP19741 New flag has been introduced to support maximum dependants feature.  -- 2016-08-19 Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return DependantCount for Adult WHERE IsAdultDependant =1 and count for Child WHERE IsChildDependant=1  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetMedicalAidContribution_sp]     @EmployeeID INT,   @MedicalSchemeID INT,   @MedicalAIDContribution DECIMAL(18,2) OUTPUT  AS  BEGIN   DECLARE @CycleID INT     IF(@MedicalSchemeID = 0)   BEGIN    SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID    SELECT @MedicalSchemeID = ISNULL(MedicalAidSchmeID, 0) FROM dbo.Payroll_EmployeeMedicalAIDDetail WHERE EmployeeID = @EmployeeID   END   ELSE   BEGIN    SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID   END     IF(@MedicalSchemeID = 0)   BEGIN    SELECT ISNULL(@MedicalAIDContribution, 0.00) AS MedicalAIDContribution    RETURN   END      DECLARE @MemberAmount DECIMAL(18,2) = 0,      @AdultAmount DECIMAL(18,2) = 0,      @ChildAmount DECIMAL(18,2) = 0,     @Child3MoreAmount DECIMAL(18,2) = 0     SELECT TOP 1 @MemberAmount = ISNULL(MemberAmount, 0), @AdultAmount = ISNULL(AdultAmount, 0),    @ChildAmount = ISNULL(ChildAmount, 0), @Child3MoreAmount =  ISNULL(MaxDependantCount, 0)   FROM dbo.Const_MedicalAIDSchemeDetail    WHERE MedicalSchemeID = @MedicalSchemeID     --PRINT @MemberAmount    --PRINT @AdultAmount    --PRINT @ChildAmount    --PRINT @Child3MoreAmount     IF(@MemberAmount = 0 AND @AdultAmount = 0 AND @ChildAmount = 0 AND @Child3MoreAmount = 0)   BEGIN    SELECT ISNULL(@MedicalAIDContribution, 0.00) AS MedicalAIDContribution    RETURN   END      DECLARE @MemberCount INT = 1, @AdultCount INT, @ChildCount INT   DECLARE @AdultCountBefore INT, @ChildCountBefore INT   DECLARE @MedicalAIDAmt DECIMAL(18,2) = 0     SET @MedicalAIDAmt = (@MemberCount * @MemberAmount)     DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)   SELECT  @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND TaxYear = @TaxYear      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear     Select @AdultCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)      IF(@AdultCount IS NULL) SET @AdultCount = 0       Select @AdultCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND MedAidJoiningDate < @FromDate      IF(@AdultCountBefore IS NULL) SET @AdultCountBefore = 0       SET @AdultCount = @AdultCount + @AdultCountBefore      --SET @MedicalAIDAmt = @MedicalAIDAmt + (@AdultAmount * @AdultCount)     Select @ChildCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)     IF(@ChildCount IS NULL) SET @ChildCount = 0      Select @ChildCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND MedAidJoiningDate < @FromDate      IF(@ChildCountBefore IS NULL) SET @ChildCountBefore = 0       SET @ChildCount = @ChildCount + @ChildCountBefore     DECLARE @MaxDependantCount INT   DECLARE @IsMaxDependantChildEnabled bit     --Get Max dependants allowed by medical aid   SELECT  @MaxDependantCount = isnull(cmsd.MaxDependantCount, 0), @IsMaxDependantChildEnabled = ISNULL(cmsd.IsMaxDependantChildEnabled, 0)   FROM Payroll_EmployeeMedicalAIDDetail as pemsd   inner join Const_MedicalAIDScheme as cms on cms.MedicalScheme_ID=pemsd.MedicalAidSchmeID   inner join Const_MedicalAIDSchemeDetail as cmsd on cmsd.MedicalSchemeID=cms.MedicalScheme_ID   WHERE pemsd.EmployeeID=@EmployeeID     --If IsMaxDependantChildEnabled is true, Child Count will come from saved value as MaxDependantCount in Const_MedicalAIDSchemeDetail table.   IF @IsMaxDependantChildEnabled = 1   BEGIN    IF @ChildCount > @MaxDependantCount     SET @ChildCount = @MaxDependantCount   END   --If IsMaxDependantChildEnabled is false, Adult Count & Child Count will be caluculated based on MaxDependantCount in Const_MedicalAIDSchemeDetail table.   -- Sum of AdultCount & ChildCount will not be more than the MaxDependantCount.   ELSE IF @IsMaxDependantChildEnabled = 0   BEGIN    IF ((@MaxDependantCount - @AdultCount) > 0)    BEGIN     DECLARE @Temp INT       SET @Temp = (@MaxDependantCount - @AdultCount)       IF ((@Temp - @ChildCount) < 0)     BEGIN      SET @ChildCount = @Temp     END    END    ELSE IF ((@MaxDependantCount - @AdultCount) < 0)    BEGIN     SET @AdultCount = @MaxDependantCount     SET @ChildCount = 0    END    ELSE IF ((@MaxDependantCount - @AdultCount) = 0)    BEGIN     SET @ChildCount = 0    END   END       SET @MedicalAIDAmt = @MedicalAIDAmt + (@AdultAmount * @AdultCount) + (@ChildCount * @ChildAmount)       SET @MedicalAIDContribution = @MedicalAIDAmt   SELECT ISNULL(@MedicalAIDContribution, '0.00') AS MedicalAIDContribution  END  

GO

-- ============================================
-- SP: Payroll_GetMedicalAidSchemeDetails
-- Schema: dbo
-- ============================================
CREATE procedure [dbo].[Payroll_GetMedicalAidSchemeDetails] @MedicalAidSchemeID int  as        select distinct  mas.MedicalScheme_ID, mas.StartDate,mas.EndDate, mas.EmployerMaxContributorValue, mas.EmployerContributionValue, sd.MemberAmount,    sd.ChildAmount, sd.AdultAmount,sd.MaxDependantCount,sd.Student, sd.StudentValidTo,sd.Disabled, sd.DisableValidTo   from Const_MedicalAIDScheme mas    inner join Const_MedicalAIDSchemeDetail AS sd ON sd.MedicalSchemeID = mas.ParentID    where mas.ParentID = @MedicalAidSchemeID    --WHERE MAS.FundName = (SELECT FundName FROM Const_MedicalAIDScheme WHERE MedicalScheme_ID = @MedicalAidSchemeID)  

GO

