CREATE PROCEDURE [dbo].[Payroll_GetMedicalAidSchemeHistoryDetails]      @MedicalAidSchemeID INT  AS      SELECT DISTINCT              mas.MedicalSchemeID ,              mas.StartDate ,              mas.EndDate ,              mas.EmployerMaxContributionValue ,              mas.EmployerContributionValue ,              mas.MemberAmount ,              mas.ChildAmount ,              mas.AdultAmount ,              mas.MaxDependantCount      FROM    dbo.Const_MedicalAidSchemeHistory mas      WHERE   mas.MedicalSchemeID = @MedicalAidSchemeID;      

