GO

-- ============================================
-- SP: Payroll_GetMedicalSchemeFreeTaxCredit_sp
-- Schema: dbo
-- ============================================
  -- =========================================================    -- Author:  Seipei Mathole  -- Create date: 30/03/2016   -- Description: Returns the Payroll_GetMedicalSchemeFreeTaxCredit_sp  -- EXEC Payroll_GetMedicalSchemeFreeTaxCredit_sp '',''  -- ==========================================================  CREATE PROCEDURE [dbo].[Payroll_GetMedicalSchemeFreeTaxCredit_sp]        @FinancialYear NVARCHAR(9) = null,  @Description VARCHAR(50) = null    AS      BEGIN      SELECT MSTC.MedicalScheme_ID, MSTC.MedicalSchemeDesc, MSTC.MedicalSchemeAmount, MSTC.TaxYear, MSTC.Enabled, MSTC.CapturerID, MSTC.DateCaptured, MSTC.DateModified, MSTC.ModifierID, MSTC.DependantModeID    FROM Const_MedicalSchemeFeeTaxCredits MSTC       INNER JOIN Const_DependantModeType_Sys DMT    ON DMT.DependantMode_ID = MSTC.DependantModeID    WHERE   (isnull(@FinancialYear,'') = '' OR MSTC.TaxYear LIKE '%' + @FinancialYear + '%')        AND (isnull(@Description,'') = '' OR MSTC.MedicalSchemeDesc LIKE '%' + @Description + '%')    END                  

GO

-- ============================================
-- SP: Payroll_GetMissingDocNotification
-- Schema: dbo
-- ============================================
-- =============================================  -- MS - 06-Oct-2021 - #63531 DELTA02: Payroll Notification for Upload of documents incorrect  -- =============================================  CREATE procedure [dbo].[Payroll_GetMissingDocNotification] --1  @MunicipalityId int  AS  BEGIN      WITH EmpDocMiss AS   (    SELECT PayEmpDoc.EmployeeId,Doc.Document_ID,     (SELECT Count(DocumentID) FROM Payroll_EmployeeDocumentDetails       WHERE EmployeeId = PayEmpDoc.EmployeeId AND Doc.Document_ID = DocumentID     ) AS NoofDocs      FROM Payroll_EmployeeDocumentDetails PayEmpDoc       CROSS JOIN Const_Document Doc --on Doc.Document_ID = PayEmpDoc.DocumentID   WHERE Doc.IsRequired = 1   GROUP BY EmployeeID,Doc.Document_ID)   SELECT dbo.BufferString_fxn(CONVERT(VARCHAR, ( Employee_ID )), 8,'0') AS Employee_ID, IDNo, FirstName, SurName, dbo.GetDocumentList(Employee_ID) AS MissDocuments    FROM Payroll_Employee    WHERE ISNULL(dbo.GetDocumentList(Employee_ID),'')<>'' and   Employee_ID in     (SELECT EmployeeId FROM EmpDocMiss WHERE NoofDocs = 0) AND MunicipalityID = @MunicipalityId and [Enabled]= 1   UNION    SELECT dbo.BufferString_fxn(CONVERT(VARCHAR, ( Employee_ID )), 8,'0') AS Employee_ID, IDNo, FirstName, SurName, dbo.GetDocumentList(Employee_ID) AS MissDocuments FROM Payroll_Employee    WHERE ISNULL(dbo.GetDocumentList(Employee_ID),'')<>'' and   Employee_Id not in     (SELECT EmployeeId FROM Payroll_EmployeeDocumentDetails) AND MunicipalityID = @MunicipalityId AND [Enabled]= 1  END

GO

-- ============================================
-- SP: Payroll_GetMissingStringsForAllSalaryHeads_sp
-- Schema: dbo
-- ============================================
-- =====================================================================================================================    -- Author  : Richa M  -- Created  : 2024/11/04  -- Description : Validates the Position SCOA (Items)  -- Payroll_GetMissingStringsForAllSalaryHeads_sp 0,'2024/2025'  -- =====================================================================================================================      create procedure [dbo].[Payroll_GetMissingStringsForAllSalaryHeads_sp](@PositionID int, @FinYear varchar(9))  as  begin      declare @SalaryProjectID int = null,     @SalaryControlID int = null     select @SalaryProjectID = [SalaryProjectID], @SalaryControlID = [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock) where ([FinYear] = @FinYear)         if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]       Select  [PlanProjectItem_ID]PlanProjectItemID, [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID],[SCOAFundId] into  [#Plan_ProjectItem] from Plan_ProjectItem where PlanProjectItem_ID in(     select ppi.PlanProjectItemID from(       select min([PlanProjectItem_ID]) as [PlanProjectItemID], [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID]-- into [#Plan_ProjectItem]          from [Plan_ProjectItem] with(nolock)          where ([FinYear] = @Finyear)           group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID] )ppi)         if (not object_id('tempdb..#Plan_ProjectItemCt') is null)       drop table [#Plan_ProjectItemCt]      select min([PlanProjectItem_ID])PlanProjectItem_ID, [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOAFundId], [SCOACostingID] into [#Plan_ProjectItemCt]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @Finyear)        group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId], [SCOACostingID],[SCOAFundId]        DECLARE @table table    (     PositionId int,     PositionDesc varchar(250),     Status varchar(100),     EmployeeId int,     EmpCode varchar(20),     FirstName varchar(100),     Surname varchar(100),     SalaryHeadTitle varchar(250),     DtDivisionId int,     DtProjectId int,     DtScoaItemId int,     DtFunctionId int,     DtRegionId int,     DtProjectItemId int,     CTDivisionId int,     CtProjectId int,     CtScoaItemId int,     CtFunctionId int,     CtRegionId int,     CtProjectItemId int    )       Insert Into @table   Select v1.*  from(       select [POS].[Position_ID], [POS].[PositionDesc],      (case       when [POS].[Status] = 1 then 'Vacant'       when [POS].[Status] = 2 then 'Occupied'       when [POS].[Status] = 4 then 'Seconded'      end) as [Status],      Employee_ID,    EmpCode,    FirstName,    Surname,      [SH].[SalaryHeadTitle],      [POS].[DivisionID] DtDivisionId,      (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) DtProjectId,        (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 6 then [GL].[ScoaItemIDPostRetirement]          else [ST].[GLScoaItem]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) DtScoaItemId,        [POS].[FunctionID] DtFunctionId,        [POS].[RegionID] DtRegionId,        [PI].[PlanProjectItemID] DtProjectItemID,        (case when TransactionTypeID = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) CtDivisionId,        (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) CtProjectId,        case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemID]          else (case           when [IRP5].[TransactionTypeID] in (1,3) and IsNULL([ET].[SalarySuspenseScoaItemCreditID],0) <> 0 then [ET].[SalarySuspenseScoaItemCreditID]             else [GL].[SuspenseScoaItemCreditID]          end)         end CtScoaItemId,          (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) CtFunctionId,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end) CtRegionId,        [PC].[PlanProjectItem_ID] CtProjectItemId from [Payroll_PayrollDefination] as [PD] with(nolock)       join [Payroll_DefinitionGroup] as [DG] with(nolock) on [DG].[PayrollDefinitionGroup_ID] = [PD].[PayrollDefinitionGroupID] and [DG].[Enabled] = 1       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] in(1, 2, 3) and [IRP5].[Enabled] = 1       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[FinYear] = @FinYear and [GL].[Enabled] = 1       join [Payroll_Position] as [POS] with(nolock) on        [POS].[Position_ID] = (case when @PositionID = 0 then [POS].[Position_ID] else @PositionID end) and        [POS].[Status] in(1, 2) and        [POS].[Enabled] = 1         join [Payroll_employee] as [PE] with(nolock) on [PE].[PositionID] = [POS].[Position_ID]         left join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [PE].[Employee_ID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]          join [Const_EmployeeType_sys] as [ET] with (nolock) on [ET].EmployeeType_ID = [PE].[EmployeeTypeID]         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [POS].[DivisionID] and               [PI].[ProjectID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then[POS].[ProjectID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAProjectID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryProjectID         end) and               [PI].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then (case [PE].[EmployeeTypeID]           when 1 then [GL].[ScoaItemIDPermanentStaff]           when 2 then [ST].[GLScoaItem]           when 3 then  [ST].[GLScoaItem]           when 6 then [GL].[ScoaItemIDPostRetirement]           when 7 then  [ST].[GLScoaItem]          end)          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then IsNULL([ET].[SalarySuspenseScoaItemID],@SalaryControlID)         end) and [PI].[SCOAFunctionId] =  [POS].[FunctionID]              and [PI].[SCOARegionId] = [POS].[RegionID]           /* CREDIT ITEM */                      left outer join #Plan_ProjectItemCt as [PC] with(nolock) on [PC].[ScoaFundId] = [PI].[ScoaFundId]               and [PC].[DivisionId] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId]          else [POS].[DivisionID]         end) and [PC].[ProjectID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]          else [GL].[SCOAProjectID]         end) and [PC].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemID]          else (case           when [IRP5].[TransactionTypeID] in (1,3) and IsNULL([ET].[SalarySuspenseScoaItemCreditID],0) <> 0 then [ET].[SalarySuspenseScoaItemCreditID]             else [GL].[SuspenseScoaItemCreditID]          end)         end) and [PC].[SCOAFunctionId] = (case          when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId]          else [POS].[FunctionID]         end) and [PC].[SCOARegionId] = (case          when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId]          else [POS].[RegionID]         end)              outer apply (        select [ScoaCode] from [Const_Scoa_Structure_Consolidated] where FinyearText = @FinYear and ScoaId = [PD].[ScoaItemID]        ) as [SDC]       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_Consolidated] where FinyearText = @FinYear and ScoaID = [PC].[ScoaItemID]       ) as [SCC]        where [PD].[PayrollDefinitionGroupID] = [POS].[PayrollDefinitionGroupID]             and [PD].[Enabled] = 1             and [IRP5].[TransactionTypeID] in(1, 2, 3)             and PI.PlanProjectItemID is null OR PC.PlanProjectItem_ID is null       )V1      Select    v1.PositionId,   PositionDesc,   Status,   EmployeeId,   EmpCode,   FirstName,   Surname,   SalaryHeadTitle,   Project_ID ProjectId,   ProjectCode,   ProjectName,   scoa.ScoaID ScoaId,   Scoa.ScoaCode,   func.ScoaID FunctionId,   func.ScoaCode FunctionCode,   reg.ScoaID RegionId,   reg.ScoaCode RegionCode,   DivisionId,   DivisionCode,   Leg   from(   Select distinct 'Debit' Leg, PositionId,PositionDesc,Status,EmployeeId,EmpCode,FirstName,Surname,SalaryHeadTitle,DtDivisionId DivisionId,DtProjectId ProjectId,DtScoaItemId ScoaItemid,DtFunctionId FunctionId,DtRegionId RegionId,DtProjectItemId PlanProjectItemId from @table where ISNULL(DtProjectItemId,0) = 0   UNION    Select distinct 'Credit', PositionId,PositionDesc,Status,EmployeeId,EmpCode,FirstName,Surname,SalaryHeadTitle,CtDivisionId ,CtProjectId ,CtScoaItemId ,CtFunctionId ,CtRegionId ,CtProjectItemId  from @table where ISNULL(CtProjectItemId,0) = 0)v1    Left Join Const_Division div on div.Division_ID = v1.DivisionId    Left Join Plan_Project proj on proj.Project_ID = v1.ProjectId    Left Join Const_SCOA_Function_Structure_Consolidated func on func.ScoaID = v1.FunctionId and func.FinYearText = @Finyear    Left Join Const_SCOA_Regional_Structure_Consolidated reg on reg.ScoaID = v1.RegionId and reg.FinYearText = @Finyear    Left Join Const_SCOA_Structure_Consolidated scoa on scoa.ScoaID = v1.ScoaItemid and scoa.FinYearText = @Finyear    order by EmployeeId,SalaryHeadTitle  end

GO

-- ============================================
-- SP: Payroll_GetMOCDetail_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 10/06/2017   Description : Gets the MOC Details  */  create procedure [Payroll_GetMOCDetail_sp] @MOCID int = null, @SalaryHeadID int, @Enabled bit = null  as    begin     set nocount on;     if (not @SalaryHeadID is null and @SalaryHeadID > 0)      select @MOCID = [MOC_ID] from [Const_MOC] with(nolock) where ([SalaryHeadID] = @SalaryHeadID)     select [MOCDetail_ID], [MOC_ID], [MOCD].[StartDate], [MOCD].[EndDate], [ConditionDesc], [EmployeeTypeDescription], [EmployeeSubtypeDesc], [ProRata]      from [Const_MOCDetail] as [MOCD] with(nolock)       join [Const_MOC] as [MOC] with(nolock) on [MOC_ID] = [MOCID] and [MOC].[Enabled] = [MOCD].[Enabled]       left outer join [Payroll_ConditionOfService] as [COS] with(nolock) on [ConditionOfService_ID] = [ConditionOfServiceID] and [COS].[Enabled] = [MOCD].[Enabled]       left outer join [Const_EmployeeType_sys] as [ET] with(nolock) on [EmployeeType_ID] = [EmployeeTypeID] and [ET].[Enabled] = [MOCD].[Enabled]       left outer join [Payroll_EmployeeSubtypes] as [EST] with(nolock) on [EmployeeSubtype_ID] = [EmployeeSubtypeID]      where ([MOC_ID] = (case when @MOCID = 0 then [MOC_ID] else @MOCID end) and [MOCD].[Enabled] = (case when @Enabled is null then [MOCD].[Enabled] else @Enabled end))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetMOCDetailHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 30/11/2017   Description : Gets the MOC History Details  */  create procedure [Payroll_GetMOCDetailHistory_sp] @MOCID int = null, @SalaryHeadID int, @Enabled bit = null  as    begin     set nocount on;     if (not @SalaryHeadID is null and @SalaryHeadID > 0)      select @MOCID = [MOC_ID] from [Const_MOC] with(nolock) where ([SalaryHeadID] = @SalaryHeadID)     select [MOCDetailHistory_ID], [MOCDH].[MOCID], [MOCDH].[StartDate], [MOCDH].[EndDate], [ConditionDesc], [EmployeeTypeDescription], [EmployeeSubtypeDesc], [MOC].[ProRata]      from [Const_MOCDetailHistory] as [MOCDH] with(nolock)       join [Const_MOCDetail] as [MOCD] with(nolock) on [MOCDetail_ID] = [MOCDetailID] and [MOCD].[Enabled] = [MOCDH].[Enabled]       join [Const_MOC] as [MOC] with(nolock) on [MOC_ID] = [MOCD].[MOCID] and [MOC].[Enabled] = [MOCDH].[Enabled]       left outer join [Payroll_ConditionOfService] as [COS] with(nolock) on [ConditionOfService_ID] = [MOCDH].[ConditionOfServiceID] and [COS].[Enabled] = [MOCDH].[Enabled]       left outer join [Const_EmployeeType_sys] as [ET] with(nolock) on [EmployeeType_ID] = [MOCDH].[EmployeeTypeID] and [ET].[Enabled] = [MOCDH].[Enabled]       left outer join [Payroll_EmployeeSubtypes] as [EST] with(nolock) on [EmployeeSubtype_ID] = [MOCDH].[EmployeeSubtypeID]      where ([MOCDH].[MOCID] = (case when @MOCID = 0 then [MOCDH].[MOCID] else @MOCID end) and [MOCDH].[Enabled] = (case when @Enabled is null then [MOCDH].[Enabled] else @Enabled end))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetMonthByPeriod_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- 2015-06-18 TP20681 James Roodt: Add calender year to ProcessingMonth Column  -- EXEC Payroll_GetMonthByPeriod_sp 1, '2014/2015'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetMonthByPeriod_sp]   @CycleId INT,   @FinanceYear NVARCHAR(10)  AS  BEGIN      SELECT Period_ID, PeriodInTaxYear, (ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))) AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  TaxYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, CycleID, ProcessedDate,CycleModeID    FROM Payroll_CyclePeriodDetails WHERE Processed = 1 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 1    UNION ALL    SELECT TOP 1      Period_ID, PeriodInTaxYear, (ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))+' Trial') AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  TaxYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, CycleID, ProcessedDate,CycleModeID    FROM Payroll_CyclePeriodDetails where Processed = 0 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 1    UNION ALL    SELECT Period_ID, PeriodInTaxYear, ('AdHoc:' + ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))) AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  TaxYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, CycleID, ProcessedDate,CycleModeID    FROM Payroll_CyclePeriodDetails WHERE Processed = 1 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 2    UNION ALL    SELECT       Period_ID, PeriodInTaxYear, ('AdHoc:' + ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))+' Trial') AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  TaxYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, CycleID, ProcessedDate,CycleModeID    FROM Payroll_CyclePeriodDetails where Processed = 0 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 2    ORDER BY PeriodInTaxYear,CycleModeID desc,PeriodEndDate desc  END        

GO

-- ============================================
-- SP: Payroll_GetMonthByPeriodforpayslips_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- 2016-04-27 TP36051 varun parvataneni: Return Months list on the payslipdropdown for adhoc   -- EXEC Payroll_GetMonthByPeriodforpayslips_sp 1, '2016/2017',1  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column    -- Update date : 11/07/2019 Modiri => 91423 Deleted Ad Hoc Runs still visable in drop-down on payslip view screen  -- Update date : 28/04/2020 Ilya Skavronskiy => fixed getting month for terminated employees  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetMonthByPeriodforpayslips_sp]   @CycleId INT,   @FinanceYear NVARCHAR(10),   @EmployeeID INT  AS  BEGIN    DECLARE @terminationCycle INT = (select Cycle_ID from Const_Cycle where CycleDesc = 'Ad Hoc Termination')  DECLARE @FinYearStartMonth INT   SELECT  @FinYearStartMonth = [KeyValue] FROM [dbo].[AAAA_ConfigSettings] WHERE KeyName = 'FinYearStartMonth'    DECLARE @result TABLE   (   Period_ID INT,    PeriodInTaxYear INT,   ProcessingMonth NVARCHAR(40),   PeriodStartDate DATETIME,    PeriodEndDate DATETIME,    Processed BIT,   MunicipalityID INT,   FinancialYear NVARCHAR(10),    [Enabled] BIT,    DateCaptured DATETIME,    CapturerID INT,    DateModified DATETIME,    ModifierID INT,    CycleID INT,    ProcessedDate DATETIME,   CycleModeID INT  )    IF (@CycleId = @terminationCycle)  BEGIN   INSERT INTO @result   SELECT PHE.Period_ID, PCD.PeriodInTaxYear, (ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))) AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID, PHE.TaxYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, PHE.Cycle_ID, PCD.ProcessedDate, PHE.CycleModeID   FROM Payroll_PayrollRun_History_Employees AS PHE   JOIN Payroll_CyclePeriodDetails AS PCD ON PHE.Period_ID = PCD.Period_ID   WHERE Employee_ID = @EmployeeID AND PHE.CycleModeID = 1 and PHE.TaxYear = @FinanceYear  END  ELSE  BEGIN   INSERT INTO @result   SELECT Period_ID, PeriodInTaxYear, (ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))) AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  FinancialYear, [Enabled], DateCaptured, CapturerID, DateModified, ModifierID, CycleID, ProcessedDate,CycleModeID   FROM Payroll_CyclePeriodDetails    WHERE Processed = 1 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 1 and Enabled=1     UNION ALL     SELECT TOP 1     Period_ID, PeriodInTaxYear, (ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))+' Trial') AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, PCD.MunicipalityID,  FinancialYear, PCD.[Enabled], PCD.DateCaptured, PCD.CapturerID, PCD.DateModified, PCD.ModifierID, PCD.CycleID, ProcessedDate,CycleModeID   FROM Payroll_CyclePeriodDetails AS PCD   JOIN Payroll_Employee AS PE ON PE.Employee_ID = @EmployeeID   WHERE PCD.Processed = 0 AND PCD.CycleID = @CycleId AND PCD.TaxYear = @FinanceYear AND PCD.CycleModeID = 1 and PCD.Enabled = 1 AND PE.CycleID != @terminationCycle  END    INSERT INTO @result  SELECT Period_ID, PeriodInTaxYear, ('AdHoc:' + ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))) AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  FinancialYear, pcd.[Enabled], pcd.DateCaptured, pcd.CapturerID, pcd.DateModified, pcd.ModifierID, CycleID, ProcessedDate,CycleModeID  FROM Payroll_CyclePeriodDetails AS pcd   INNER JOIN Payroll_CyclePeriodAdhocEmployee AS pce ON pce.PeriodID= pcd.Period_ID   WHERE Processed = 1 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 2 AND pce.EmployeeID=@EmployeeID and pce.Enabled=1 and pcd.Enabled=1    UNION ALL    SELECT  Period_ID, PeriodInTaxYear, ('AdHoc:' + ProcessingMonth + ' ' + convert(nvarchar(10), YEAR(PeriodStartDate))+' Trial') AS ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed, MunicipalityID,  FinancialYear, pcd.[Enabled], pcd.DateCaptured, pcd.CapturerID, pcd.DateModified, pcd.ModifierID, CycleID, ProcessedDate,CycleModeID  FROM Payroll_CyclePeriodDetails AS pcd   INNER JOIN Payroll_CyclePeriodAdhocEmployee AS pce ON pce.PeriodID= pcd.Period_ID  WHERE Processed = 0 AND CycleID = @CycleId AND TaxYear = @FinanceYear AND CycleModeID = 2 AND CycleModeID = 2 AND pce.EmployeeID=@EmployeeID and pce.Enabled=1 and pcd.Enabled=1  ORDER BY PeriodInTaxYear,CycleModeID desc,PeriodEndDate desc      SELECT * FROM @result    END

GO

-- ============================================
-- SP: Payroll_GetMunicipalityHistory_sp
-- Schema: dbo
-- ============================================
  -- =============================================================================  -- Author  : Ferdi Botha  -- Create Date : 22/05/2019  -- Call   : Returns the list of Municipality History    --exec Payroll_GetMunicipalityHistory_sp  -- =============================================================================  CREATE PROCEDURE [dbo].[Payroll_GetMunicipalityHistory_sp]  as  begin     declare @municipalHistory as table (      [ID] [int] identity(1, 1) not null,    [SCOAItem] [varchar] (64) not null,    [FinYear] [varchar] (9) not null,    [StartDate] [datetime] not null,    [UntilDate] [datetime] not null,    [ProjectID] [int] null,    [SCOAItemDebitID] [int] null,    [SCOAItemCodeDebit] [nvarchar](50) null,    [SCOAItemCreditID] [int] null,    [SCOAItemCodeCredit] [nvarchar](50) null     )     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID])      select 'Nett Salary Project' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [NettSalaryProjectID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Salary Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [NettSalaryProjectID], [SalarySuspenseScoaItemID], [SalarySuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Leave Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [LeaveProjectID], [LeaveSuspenseScoaItemID], [LeaveSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'UIF Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [UIFProjectID], [UIFSuspenseScoaItemID], [UIFSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Pension Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [PensionProjectID], [PensionSuspenseScoaItemID], [PensionSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Group Life Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [GroupLifeProjectID], [GroupLifeSuspenseScoaItemID], [GroupLifeSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Union Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [UnionProjectID], [UIFSuspenseScoaItemID], [UnionsSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Travel Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [TravelProjectID], [TravelSuspenseScoaItemID], [TravelSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Tax Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [TaxProjectID], [SARSSuspenseScoaItemID], [SARSSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Skills Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [SkillsProjectID], [SkillsSuspenseScoaItemID], [SkillsSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Medical Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [MedicalProjectID], [MedicalSuspenseScoaItemID], [MedicalSuspenseScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemDebitID], [SCOAItemCreditID])      select 'Employee Deductions FICS Control' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [EmployeeProjectID], [EmployeeDeductionFICSScoaItemID], [EmployeeDeductionFICSScoaItemCreditID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     insert into @municipalHistory([SCOAItem], [FinYear], [StartDate], [UntilDate], [ProjectID], [SCOAItemCreditID])      select 'Commission Earned Item' as [SCOAItem], [FinYear], [StartDate], [UntilDate], [CommissionProjectID], [CommissionScoaItemID]       from [Payroll_MunicipalityHistory] with(nolock)       where ([Enabled] = 1)     update [MH] set [SCOAItemCodeDebit] = [CSD].[ScoaCode]      from @municipalHistory as [MH]       cross apply (        select [ScoaID], [ScoaCode] from  Const_SCOA_Structure_Consolidated where SCOAID = MH.ScoaItemDebitId and FinyearText = MH.Finyear         ) as [CSD]      where (not [MH].[SCOAItemDebitID] is null and [CSD].[ScoaID] = [MH].[SCOAItemDebitID])     update [MH] set [SCOAItemCodeCredit] = [CSD].[ScoaCode]      from @municipalHistory as [MH]       cross apply (        select [ScoaID], [ScoaCode] from  Const_SCOA_Structure_Consolidated where SCOAID = MH.ScoaItemDebitId and FinyearText = MH.Finyear         ) as [CSD]      where (not [MH].[SCOAItemCreditID] is null and [CSD].[ScoaID] = [MH].[SCOAItemCreditID])     select [MH].[SCOAItem], [MH].[FinYear], [MH].[StartDate], [MH].[UntilDate], [MH].[ProjectID], cast([PP].[ProjectCode] as varchar) + ' ' + [PP].[ProjectName] as [ProjectDesc], [MH].[SCOAItemDebitID], [MH].[SCOAItemCodeDebit], [MH].[SCOAItemCreditID], [MH].[SCOAItemCodeCredit]      from @municipalHistory as [MH]       join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [MH].[ProjectID]      order by [MH].[FinYear] desc, [MH].[ID]    end

GO

-- ============================================
-- SP: Payroll_GetNotApprovedTrialRunOnLockDown_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 09/05/2017   Description : Get the Trial Runs on lockdown waiting for Final Run   Eben Beetge WI77623 Dashboard notification needs to appear after lockdown has been cancelled and trial run has been rerun and put into lockdown again  */  CREATE procedure [Payroll_GetNotApprovedTrialRunOnLockDown_sp]  as    begin     set nocount on;     select [Period_ID], [CycleDesc] as [PayrollCycleDescription], [PeriodStartDate] as [Start_Date], [PeriodEndDate] as [End_Date], sum([Amount]) as [Total_Company_Cost], [CPD].[DateCaptured] as [TrialRunDate], [ApprovedDate], [ApprovedBy], (case when [ApprovedStatus] = 'Yes' then 'Yes' else 'No' end) as [Approved], (select count(distinct [Employee_ID]) from [Payroll_Employee] where ([CycleID] = [CC].[Cycle_ID])) as [Employee_Count]      from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)       join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [PayrollDefinationID]       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID]       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId]       join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID]       join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = [TP].[PeriodID]       join [Const_Cycle] as [CC] with(nolock) on [Cycle_ID] = [CPD].[CycleID]       join [Const_TransactionType] as [CT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID]      where ([EPD].[Enabled] = 1 and [SH].[Enabled] = 1 and [IRP5].[Enabled] = 1 and [GL].[Enabled] = 1 and [CPD].[Enabled] = 1 and [LockedDown] = 1 and ([ApprovedStatus] is null or [ApprovedStatus] = 'No') and [TransactionType_ID] in(1, 3))       group by [Period_ID], [CycleDesc], [PeriodStartDate], [PeriodEndDate], [CPD].[DateCaptured], [ApprovedDate], [ApprovedBy], [ApprovedStatus], [Cycle_ID]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetParentScoaIdForTreeselection_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:Varun Parvataneni  -- Create date:  19 SEP 2016  -- Description: <Return the parentscoaId with increasing level fro the user selection in the tree structure>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetParentScoaIdForTreeselection_sp]    @ScoaID int,        @Level int  AS  BEGIN   Select    Isnull(ScoaParentID,0) as ScoaParentID    ,ScoaID    ,ScoaDesc    ,(LevelID +2) as LevelID    ,PostingLevel    ,ScoaShortDesc    ,ScoaCode    FROM dbo.Const_SCOA_Function_Structure Scoa   where ScoaID=@ScoaID   and Enabled = 1 and PostingLevel='No'   Order by ScoaCode  END  

GO

-- ============================================
-- SP: Payroll_GetPayrollCycleDetailsStatus
-- Schema: dbo
-- ============================================
  --=================================  -- Author: Lungisani Khumalo  -- Descriptions :gets all Payroll CycleDetails abd assigns status based on state and give summary details  -- TP43906  -- Created on 26/08/2016  -- Modified on 30/08/2016  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- 2019-Feb-13 Himil Modi -- #84552 make left join with Const_Payroll_TaxPeriods and set the status open and close from it.  -- 2019-03-20 Ferdi Botha Only show Periods in Current Tax Year  --=================================  create procedure [Payroll_GetPayrollCycleDetailsStatus]  as    begin     declare @TaxYear varchar(9) = (select [KeyValue] from [AAAA_Configsettings] where ([KeyName] = 'TaxYear'))     declare @CyclePeriod as table (      [PeriodID] int not null,      [CycleModeID] int not null     )     insert into @CyclePeriod([PeriodID], [CycleModeID])      select min([Period_ID]), [CycleModeID]       from [Payroll_CyclePeriodDetails] with(nolock)       where ([TaxYear] = @TaxYear and [Processed] = 0 and [Enabled] = 1)       group by [CycleID], [CycleModeID]        order by min([Period_ID])     select [CycleDesc] as [Payroll], [CM].[CycleModeDesc] as [CycleType], [CPD].[ProcessingMonth] as [Period], (case       when [CPD].[Processed] = 1 then 'Processed'       when [CPD].[ApprovedStatus] = 'Yes' then 'Approved'       when [CPD].[LockedDown] = 1 then 'LockedDown'       when [TP].[TaxYearOpen] = 1 then 'Open'       else 'Close'      end) as [Status]      from [Payroll_CyclePeriodDetails] as [CPD] with(nolock)       join @CyclePeriod as [CPDT] on [CPDT].[PeriodID] = [CPD].[Period_ID] and [CPDT].[CycleModeID] = [CPD].[CycleModeID]       join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [CPD].[CycleID] and [CC].[Enabled] = 1       left join [Const_Payroll_TaxPeriods] as [TP] with(nolock) on [TP].[cycleID] = [CC].[Cycle_ID] and [TP].[TaxYear] = cast(right(@TaxYear, 4) as int) and [TP].[Enable] = 1       inner join [Const_Payroll_CycleMode_sys] as [CM] with(nolock) on [CM].[CycleMode_ID] = [CPD].[CycleModeID] and [CM].[Enabled] = 1      where ([CPD].[TaxYear] = @TaxYear and [CPD].[Processed] = 0 and [CPD].[Enabled] = 1)       order by [CycleDesc]    end  

GO

-- ============================================
-- SP: Payroll_GetPayrollCycleNotInUse_sp
-- Schema: dbo
-- ============================================
        -- =========================================================    -- Author:  Seipei Mathole  -- Create date: 07/03/2016   -- Description: Returns the Payroll_GetPayrollCycleNotInUse  --  -- ==========================================================  CREATE PROCEDURE [dbo].[Payroll_GetPayrollCycleNotInUse_sp]         --@Cycle_ID int   @ProvisionReport_ID int  AS      BEGIN          SELECT cc.Cycle_ID, cc.CycleDesc        FROM Const_Cycle cc         WHERE cc.Cycle_ID NOT IN        (SELECT pp.CycleID        FROM Payroll_ProvisionReportPayrollCycleLinkTable pp where pp.ProvisionReportID = @ProvisionReport_ID)    END    

GO

-- ============================================
-- SP: Payroll_GetPayrollDefaultSCOACostingID_sp
-- Schema: dbo
-- ============================================
  -- =================================================================================================            -- Author:Varun Parvataneni        -- Create date: 13/06/2016          -- Description: Return default SCOACostingID Linked to the Payroll from  AAAA_ConfigSettings        -- TP: 37912:To show on CostingCode dropdown   -- Call:Exec [Payroll_GetPayrollDefaultSCOACostingID_sp]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetPayrollDefaultSCOACostingID_sp]    AS   BEGIN  Select   ScoaID,  ScoaCode+'-'+ScoaShortDesc as Scoacode  FROM Const_SCOA_Project_Structure where ScoaID =(select KeyValue  FROM AAAA_ConfigSettings where KeyName='PayrollDefaultSCOACostingID')    END  

