-- ============================================
-- SP: Payroll_GetPayrollDefinationByEmployeePayrollDefinationID_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  <Author,,Name>    -- Create date: <Create Date,,>    -- Description: <Description,,>    -- [Payroll_GetPayrollDefinationByEmployeePayrollDefinationID_sp] 6533    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetPayrollDefinationByEmployeePayrollDefinationID_sp]   @EmployeePayrollDefinationID INT    AS    BEGIN     SELECT            PAY_IRP.TransactionTypeID        ,PAY_SAL.IRP5CodeId        ,PAY_DEF.PayrollSalaryHeadID        ,CSS.ScoaCode + ' - ' + CSS.ScoaShortDesc AS Activity        ,PAY_SAL.SalaryHeadTitle AS PayrollSalaryHeadName        ,PAY_IRP.TaxableID        ,PAY_IRP.TatxablePercentage              FROM dbo.Payroll_EmployeePayrollDefinition PAY_DEF        INNER JOIN Payroll_SalaryHead PAY_SAL          ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID        INNER JOIN Payroll_IRP5Code PAY_IRP          ON PAY_IRP.IRP5Code_ID = PAY_SAL.IRP5CodeId        left JOIN Const_SCOA_Structure CSS          ON CSS.ScoaID = PAY_DEF.SCOAItemID        WHERE PAY_DEF.EmployeePayrollDefinition_ID = @EmployeePayrollDefinationID      END    

GO

-- ============================================
-- SP: Payroll_GetPayrollDefinationByID_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  <Author,,Name>    -- Create date: <Create Date,,>    -- Description: <Description,,>    -- [Payroll_GetPayrollDefinationByID_sp] 2    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetPayrollDefinationByID_sp] @PayrollDefinationID INT  AS  BEGIN   SELECT       PAY_DEFGROUP.PayrollDefinitionGroupName      ,PAY_IRP.TransactionTypeID      ,PAY_SAL.IRP5CodeId      ,PAY_DEF.PayrollSalaryHeadID      ,CSS.ScoaCode + ' - ' + CSS.ScoaShortDesc AS Activity      ,PAY_SAL.SalaryHeadTitle AS PayrollSalaryHeadName      ,PAY_IRP.TaxableID      ,PAY_IRP.TatxablePercentage            FROM dbo.Payroll_PayrollDefination PAY_DEF            INNER JOIN dbo.Payroll_DefinitionGroup PAY_DEFGROUP        ON PAY_DEFGROUP.PayrollDefinitionGroup_ID = PAY_DEF.PayrollDefinitionGroupID        INNER JOIN Payroll_SalaryHead PAY_SAL          ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID        INNER JOIN Payroll_IRP5Code PAY_IRP          ON PAY_IRP.IRP5Code_ID = PAY_SAL.IRP5CodeId        --INNER JOIN Const_SCOA_Structure CSS     LEFT OUTER JOIN Const_SCOA_Structure CSS          ON CSS.ScoaID = PAY_DEF.SCOAItemID        WHERE PAY_DEF.PayrollDefination_ID = @PayrollDefinationID      END    

GO

-- ============================================
-- SP: Payroll_GetPayrollDefinationID_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:  28 JUL 2013  -- Description: <Description,,>  -- =============================================  CREATE PROCEDURE [Payroll_GetPayrollDefinationID_sp]  @TransType nvarchar(50),  @TransTypeDesc nvarchar(50)  AS  BEGIN   SELECT PAY_DEF.PayrollDefination_ID   FROM Payroll_PayrollDefination PAY_DEF    INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID= PAY_DEF.PayrollSalaryHeadID    INNER JOIN dbo.Payroll_IRP5Code IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID= IRP5.TransactionTypeID   WHERE CONST_TRANS.TransactionTypeDesc = @TransType AND PAY_SAL.SalaryHeadTitle = @TransTypeDesc  END       

GO

-- ============================================
-- SP: Payroll_GetPayrollDivisionProjects
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetPayrollDivisionProjects] (@DivisionID int, @ScoaID int)  as  begin     select distinct [Project_ID], [PP].[ProjectName], [PP].[ProjectDesc]      from [Plan_Project] as [PP] with(nolock)       join [Plan_ProjectFunctions] as [PPF] with(nolock) on [ProjectID] = [Project_ID]       join [Const_SCOA_Function_Structure] as [CSFS] on [CSFS].[ScoaID] = [PPF].[ScoaFunctionID] and [CSFS].[Enabled] = 1      where ([PostingLevel] = 'Yes' and       exists(        select 1         from [Plan_ProjectItem] as [PPE] with(nolock)          join [Const_SCOA_Structure] as [CSS] with(nolock) on [CSS].[ScoaID] = [PPE].[SCOAItemID] and [CSS].[Enabled] = 1         where ([PPE].[ProjectID] = [PP].[Project_ID] and [DivisionId] = @DivisionID and [ScoaFunctionID] = @ScoaID and ([ScoaCode] like 'IE005%' or [ScoaCode] like 'IE008%'))       )      )    end  

GO

-- ============================================
-- SP: Payroll_GetPayrollDivisionProjectsByFinYear
-- Schema: dbo
-- ============================================
/*   AUTHOR  : FERDI BOTHA   CREATED  : 18 / 04 / 2019   DESCRIPTION : Gets the list of Payroll Division Projects by Financial Year   -- Payroll_GetPayrollDivisionProjectsByFinYear 33,353,'2021/2022'   -- Payroll_GetPayrollDivisionProjectsByFinYear 41,301,'2021/2022'   #87802 Senqu Unable to update/edit a Division record    */  CREATE procedure [dbo].[Payroll_GetPayrollDivisionProjectsByFinYear] (@DivisionID int, @ScoaID int, @FinYear varchar(9))  as  begin     select distinct [PP].[Project_ID], [PP].[ProjectName], [PP].[ProjectDesc], cast(isnull([PP].[ProjectCode],0) as varchar) + ' | ' + isnull([PP].[ProjectName],'') as [ScoaDesc]      from [Plan_Project] as [PP] with(nolock)       join [Plan_ProjectFunctions] as [PPF] with(nolock) on [PPF].[ProjectID] = [PP].[Project_ID]       join Const_SCOA_Function_Structure_Consolidated as [CSFS] on [CSFS].[ScoaID] = [PPF].[ScoaFunctionID] and [CSFS].[Enabled] = 1 and [CSFS].[PostingLevel] = 'Yes' and FinYearText = @Finyear      where ([PP].[FinYear] = @FinYear and       exists(        select 1         from [Plan_ProjectItem] as [PPE] with(nolock)          join Const_SCOA_Structure_Consolidated as [CSS] on [CSS].[ScoaID] = [PPE].[SCOAItemID] and [CSS].[Enabled] = 1 and FinYearText = @Finyear         where ([PPE].[ProjectID] = [PP].[Project_ID] and [DivisionId] = @DivisionID and [ScoaFunctionID] = @ScoaID and ([ScoaCode] like 'IE005%' or [ScoaCode] like 'IE008%'))       )      )    end

GO

-- ============================================
-- SP: Payroll_GetPayrollProjectFund
-- Schema: dbo
-- ============================================
  -- =================================================================================================            -- Author:Varun Parvataneni       -- Create date: 24/09/2016          -- Description: Returns Funds linked to the selected Projects         -- TP: 45471  -- Exec [Payroll_GetPayrollProjectFund]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetPayrollProjectFund]    @ProjectID INT  AS     BEGIN      Select distinct  ppr.ProjectFund_ID AS ScoaID, /*CSRS.ScoaID,*/ CSRS.ScoaShortDesc+(PostingLevel)+CSRS.ScoaCode as ScoaDesc from Const_SCOA_Funds_Structure as CSRS  inner join Plan_ProjectFund as ppr on ppr.ScoaFundID =CSRS.ScoaID  Inner Join Plan_Project as pp on pp.Project_ID = ppr.ProjectID  where ppr.ProjectID = @ProjectID  and CSRS.PostingLevel='Yes'    END  

GO

-- ============================================
-- SP: Payroll_GetPayrollProjectRegions
-- Schema: dbo
-- ============================================
  -- =================================================================================================            -- Author:Varun Parvataneni       -- Create date: 24/09/2016          -- Description: Returns Projects linked to the selected ScoaFunctionID         -- TP: 45471  -- Exec [Payroll_GetPayrollProjectRegions]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetPayrollProjectRegions]    @ProjectID INT  AS     BEGIN    --Select Project_ID,ProjectDesc from Plan_Project  --where Project_ID in(  --Select ProjectID from Plan_ProjectRegions   --where ScoaRegionID in (  --select scoaid from Const_SCOA_Function_Structure  --where SUBSTRING(scoacode,0,9) = (select SUBSTRING(scoacode,0,9) from Const_SCOA_Function_Structure where ScoaID=@ScoaID)  --and PostingLevel='Yes'))    Select distinct  CSRS.ScoaID,CSRS.ScoaShortDesc+'(Yes)'+CSRS.ScoaCode as ScoaDesc from Const_SCOA_Regional_Structure as CSRS  inner join Plan_ProjectRegions as ppr on ppr.ScoaRegionID =CSRS.ScoaID  Inner Join Plan_Project as pp on pp.Project_ID = ppr.ProjectID  where ppr.ProjectID = @ProjectID  and CSRS.PostingLevel='Yes'    END  

GO

-- ============================================
-- SP: Payroll_GetPayrollProjectRegionsByFinYear
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATED  : 18 / 04 / 2019   DESCRIPTION : Gets the list of Payroll Division Regions by Financial Year   --Exec Payroll_GetPayrollProjectRegionsByFinYear 0,'2022/2023'  */  CREATE procedure [Payroll_GetPayrollProjectRegionsByFinYear] (@ProjectID int, @FinYear varchar(9))  as   begin    select distinct [CSRS].[ScoaID], [CSRS].[ScoaShortDesc] + '(Yes)' + [CSRS].[ScoaCode] as [ScoaDesc]     from (select * from Const_SCOA_Regional_Structure_Consolidated where FinYearText = @FinYear) as [CSRS]      join [Plan_ProjectRegions] as [PPR] on [PPR].[ScoaRegionID] = [CSRS].[ScoaID] and [PPR].[ProjectID] = @ProjectID      Join [Plan_Project] as [PP] on [PP].[Project_ID] = [PPR].[ProjectID]     where ([CSRS].[PostingLevel] = 'Yes')     end

GO

-- ============================================
-- SP: Payroll_GetPayrollProjects
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetPayrollProjects] (@ScoaID int)  as   begin     select distinct [Project_ID], [PP].[ProjectName], [PP].[ProjectDesc] from [Plan_Project] as [PP] with(nolock)      join [Plan_ProjectFunctions] as [PPF] with(nolock) on [ProjectID] = [Project_ID]      join [Const_SCOA_Function_Structure] as [CSFS] on [CSFS].[ScoaID] = @ScoaID and [CSFS].[ScoaID] = [PPF].[ScoaFunctionID]     where ([PostingLevel] = 'Yes')    end  

GO

