        -- =========================================================    -- Author:  Seipei Mathole  -- Create date: 07/03/2016   -- Description: Returns the Payroll_GetPayrollCycleNotInUse  --  -- ==========================================================  CREATE PROCEDURE [dbo].[Payroll_GetPayrollReportDetails_sp]       AS      BEGIN          SELECT Empid, Surname, Firstname AS Name, RatePerDay AS CurrentRatePerDay, NewSalary AS SalaryIncrease, LeaveDaysAvailable AS LeaveDaysAsOn30June, ProvisionLeave AS ProvisionForLeave       FROM Payroll_ProvisionReportDetails    END  

