-- ============================================
-- SP: Payroll_GetPayrollSalaryHead_TotalPercentage_sp
-- Schema: dbo
-- ============================================
  -- =================================================================================================  -- Author  : Ravindra Jijotia  -- Create date : 2015-06-29  -- Description : Returns total percentage of salary heads assigned to Employee if it is not 100%.  -- EXEC [Payroll_GetPayrollSalaryHead_TotalPercentage_sp] '2015/2016',0,1030  -- 2015-10-21 TP26456 Suri Kandukuri: Added EmployeeID  -- 2016-05-03 TP32219,32229 Varun parvataneni:Added CycleID as parameterto get check only employees in that cycle  -- 2016-09-01 TP43798, PHUTI CHOKOE:Added ISDUMMY VALIDATION  -- =================================================================================================  CREATE PROCEDURE [Payroll_GetPayrollSalaryHead_TotalPercentage_sp]       @FinancialYear NVARCHAR(50)   ,@EmployeeID INT   ,@CycleID INT  AS  IF ( @EmployeeID > 0 )   BEGIN   SELECT PEPD.PayrollSalaryHeadID    ,psh.SalaryHeadName    ,pepd.EmployeeID    ,sum(PEPD.Percentage) AS TotalPercentage   FROM Payroll_EmployeePayrollDefinition AS PEPD   INNER JOIN Payroll_SalaryHead AS PSH ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID   WHERE PEPD.EmployeeID = @EmployeeID    AND PEPD.Enabled = 1    AND PSH.Enabled = 1   GROUP BY PEPD.PayrollSalaryHeadID    ,psh.SalaryHeadName    ,pepd.EmployeeID  END  ELSE   BEGIN   SELECT PEPD.PayrollSalaryHeadID    ,psh.SalaryHeadName    ,pepd.EmployeeID    ,sum(PEPD.Percentage) AS TotalPercentage   FROM Payroll_EmployeePayrollDefinition AS PEPD   INNER JOIN Payroll_SalaryHead AS PSH ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID   INNER JOIN Payroll_Employee AS PE ON PEPD.EmployeeID = PE.Employee_ID   INNER JOIN Const_Cycle AS CC ON PE.CycleID = CC.Cycle_ID   WHERE PE.CycleID = @CycleID     AND PE.IsDummy = 0    AND PE.Enabled =1    AND PEPD.Enabled = 1    AND PSH.Enabled = 1   GROUP BY PEPD.PayrollSalaryHeadID    ,psh.SalaryHeadName    ,pepd.EmployeeID  END    

GO

-- ============================================
-- SP: Payroll_GetPayrollSalaryHeadlst_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL    -- Create date: 18/11/2013    -- Description: Returns all Salary Heads not configured up to 100% yet for the indicated PayrollDefinition group  -- EXEC Payroll_GetPayrollSalaryHeadlst_sp '2014/2015',0,5    -- 2015-06-11 TP20667 James Roodt: Added filter to only show Enabled Earnings and Deductions (Salary Heads)  -- Update date : 12/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================    create procedure [Payroll_GetPayrollSalaryHeadlst_sp]   @FinancialYear NVARCHAR(50),     @ID int,     @PayrollGroupID INT    AS    BEGIN      IF(@ID =0)      BEGIN      SELECT DISTINCT         CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,        PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN Payroll_PayrollDefination PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE PAY_SAL.Enabled=1    AND ((PAY_DEF.Percentage IS NULL)     OR PAY_DEF.PayrollSalaryHeadID NOT IN        (        SELECT SalaryHead_ID         FROM Payroll_SalaryHead         WHERE SalaryHead_ID IN         (          SELECT PSH.SalaryHead_ID           FROM Payroll_SalaryHead AS PSH           INNER JOIN Payroll_PayrollDefination AS PPD ON PSH.SalaryHead_ID =PPD.PayrollSalaryHeadID          WHERE PSH.Enabled =1 and PPD.PayrollDefinitionGroupID = @PayrollGroupID          GROUP BY PSH.SalaryHead_ID          HAVING SUM(PPD.Percentage)=100)))     END     ELSE     BEGIN      SELECT  DISTINCT        CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,       PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN Payroll_PayrollDefination PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE     PAY_SAL.Enabled=1    AND ((PAY_DEF.Percentage  is null) OR PAY_DEF.PayrollSalaryHeadID NOT IN        (        SELECT SalaryHead_ID         FROM Payroll_SalaryHead         WHERE SalaryHead_ID IN         (          SELECT PSH.SalaryHead_ID           FROM Payroll_SalaryHead AS PSH           INNER JOIN Payroll_PayrollDefination AS PPD ON PSH.SalaryHead_ID =PPD.PayrollSalaryHeadID          WHERE PSH.Enabled =1 and PPD.PayrollDefinitionGroupID = @PayrollGroupID          GROUP BY PSH.SalaryHead_ID          HAVING SUM(PPD.Percentage)=100)))       UNION       SELECT DISTINCT        CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,       PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN Payroll_PayrollDefination PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE  PAY_DEF.PayrollDefination_ID  = @ID     AND PAY_SAL.Enabled=1   END      END    

GO

-- ============================================
-- SP: Payroll_GetPayrollSalaryHeadlstbyEmployeeID_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 03/02/2014  -- Description:     -- 2015-09-16 TP24564 James Roodt: Removed filters to exclude Salaryheads which have been defined 100%   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetPayrollSalaryHeadlstbyEmployeeID_sp]   @FinancialYear NVARCHAR(50),     @ID int,     @PayrollGroupID INT,     @EmployeeId INT    AS    BEGIN      IF(@ID =0)  --Defining a new Payroll Definition     BEGIN      SELECT DISTINCT         CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,        PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN dbo.Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID     INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE  PAY_SAL.Enabled = 1    END     ELSE     BEGIN  --Editing an existing payroll definition    SELECT  DISTINCT        CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,       PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE  PAY_SAL.Enabled = 1      UNION       SELECT DISTINCT        CONVERT(NVARCHAR,IRP5Code.IRP5Code) + ' - ' + PAY_SAL.SalaryHeadTitle AS DESCRIPTIONHEAD,       PAY_SAL.SalaryHead_ID AS IRP5CodeId, IRP5Code.TransactionTypeID      FROM Payroll_SalaryHead PAY_SAL       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.PayrollSalaryHeadID =PAY_SAL.SalaryHead_ID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = PAY_SAL.IRP5CodeId      WHERE  PAY_DEF.EmployeePayrollDefinition_ID  = @ID AND EmployeeID=@EmployeeId AND PAY_SAL.Enabled = 1     END      END         

GO

-- ============================================
-- SP: Payroll_GetPayslipsToSend
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Ilya Skavronskiy  -- Create date: 2020-05-27  -- Description: Returns employees to whom we need to send payslips according to EFT payment date which was selected during payroll final run  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_GetPayslipsToSend]  AS   DECLARE @communicationMethod_Email INT = 1   DECLARE @currentTaxYear NVARCHAR(10) = (SELECT TOP 1 KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear')      DECLARE @dateValue VARCHAR(10) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE [KeyName] = 'PayrollSchedulerDate')   DECLARE @dateYear INT = CAST(RIGHT(@dateValue, 4) AS INT)   DECLARE @dateMonth INT = CAST(RIGHT(LEFT(@dateValue, 5), 2) AS INT)   DECLARE @dateDay INT = CAST(LEFT(@dateValue, 2) AS INT)   DECLARE @schedulerDate VARCHAR(19) = CONVERT(NVARCHAR(19), DATEFROMPARTS(@dateYear, @dateMonth, @dateDay), 120)     SELECT     PE.Employee_ID,    PE.EmailAddress,    PCPD.Period_ID,    PCPD.CycleModeID,    PCPD.CycleID,    PCPD.TaxYear,    PCPD.PeriodInTaxYear   FROM Payroll_Employee AS PE   JOIN Payroll_CyclePeriodDetails AS PCPD ON PE.CycleID = PCPD.CycleID   LEFT JOIN Payroll_SentPayslip AS PSP ON PCPD.Period_ID = PSP.PeriodID AND PE.Employee_ID = PSP.EmployeeID   LEFT JOIN Payroll_TrailRun_History AS PTRH ON PCPD.Period_ID = PTRH.PeriodID    WHERE PCPD.[Enabled] = 1 AND PCPD.Processed = 1 AND PCPD.TaxYear = @currentTaxYear     AND PTRH.PaymentDueDate = @schedulerDate    AND PE.MethodofCommunication = @communicationMethod_Email AND PE.EmailAddress IS NOT NULL    AND PSP.EmployeeID IS NULL

GO

-- ============================================
-- SP: Payroll_GetPerformanceApriasal
-- Schema: dbo
-- ============================================
  --- Calls : [Payroll_GetPerformanceApriasal] '','','','2013/2014'  CREATE procedure [dbo].[Payroll_GetPerformanceApriasal]     @Name NVARCHAR(100),   @Surname NVARCHAR(100),   @IDNo NVARCHAR(30),   @FinancialYear NVARCHAR(50)  as  begin   DECLARE @TempTbl TABLE   (    PerformanceApprisal_ID nvarchar(50),     EmployeeID nvarchar(50),    JobTitle nvarchar(100),    DateAppointed nvarchar(50),    PerformanceApprisalDocURL nvarchar(max),    POEmployeeName nvarchar(50),    PODate1 nvarchar(50),    POManagerName nvarchar(50),    PODate2 nvarchar(50),    DPEmployeeName nvarchar(50),    DPDate1 nvarchar(50),    DPManagerName nvarchar(50),    DPDate2 nvarchar(50),    HalfYearReview nvarchar(50),    FinalReview nvarchar(50),    FinancialYear nvarchar(50),    [Enabled] bit,    FirstName nvarchar(50),    Surname nvarchar(50),    IdNo nvarchar(50),    Steplocation NVARCHAR(50)   )   declare @sql NVARCHAR(MAX)     set @sql = 'select    PA.PerformanceApprisal_ID,     dbo.BufferString_fxn(CONVERT(VARCHAR,(PA.EmployeeID)), 8, ''0'') as Employee_ID,    PA.JobTitle,    PA.DateAppointed,    PA.PerformanceApprisalDocURL,    PA.POEmployeeName,    PA.PODate1,    PA.POManagerName,    PA.PODate2,    PA.DPEmployeeName,    PA.DPDate1,    PA.DPManagerName,    PA.DPDate2,    PA.HalfYearReview,    PA.FinalReview,    PA.FinancialYear,    PA.[Enabled],    emp.FirstName,   emp.Surname,   emp.IdNo,   CASE WHEN ( SELECT COUNT(1) FROM Payroll_PerformanceApprisalKPI       WHERE PerformanceApprisalID = PA.PerformanceApprisal_ID      AND (HalfYearRate <= 2 OR FinalRate <= 2)) > 0    THEN    CONVERT(NVARCHAR, WFSACount) + '' of '' + CONVERT(NVARCHAR, WFSCount)    ELSE     CONVERT(NVARCHAR, WFSACount) + '' of '' + CONVERT(NVARCHAR, WFSCount - 1)   END AS Steplocation     FROM    (SELECT RecordID, WorkFlowID, COUNT(*) AS WFSACount FROM dbo.Sys_WorkFlowSectionAudit     GROUP BY RecordID, WorkFlowID     ) WFSA INNER JOIN     ( SELECT WorkFlowID, COUNT(*) AS WFSCount FROM dbo.Sys_WorkFlowSection WFS     INNER JOIN (SELECT * FROM Sys_WorkFlow WHERE PageName = ''PerformanceApprisal.aspx'') WF     ON WFS.WorkFlowID = WF.WorkFlow_ID GROUP BY WorkFlowID     ) WFCount ON WFSA.WorkFlowID = WFCount.WorkFlowID    inner join Payroll_PerformanceApprisal PA on RecordID = PA.PerformanceApprisal_ID   inner join Payroll_Employee emp on emp.Employee_ID = PA.EmployeeID   where 1=1 '   if(@Name is not null and LEN(@Name)>0)    BEGIN     set @sql = @sql + 'AND emp.FirstName like ''%'+@Name+'%'' '    END    if(@Surname is not null and LEN(@Surname)>0)    BEGIN     set @sql = @sql + 'AND emp.Surname like ''%'+@Surname+'%'' '    END    if(@IDNo is not null and LEN(@IDNo)>0)    BEGIN     set @sql = @sql + 'AND emp.IdNo like ''%'+@IDNo+'%'' '    END    if(@FinancialYear is not null and len(@FinancialYear) >0)    BEGIN     set @sql = @sql + 'AND PA.FinancialYear = '''+ @FinancialYear +''' '    END    SET @sql = @sql +'Order by emp.Employee_ID'    --PRINT @sql    INSERT INTO @TempTbl     EXEC(@sql)            SELECT * FROM @TempTbl  end  

GO

-- ============================================
-- SP: Payroll_GetPeriodDateByEmployeeID_sp
-- Schema: dbo
-- ============================================
-- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  CREATE PROCEDURE [dbo].[Payroll_GetPeriodDateByEmployeeID_sp]    @EmployeeID INT    AS    BEGIN    SELECT TOP 1  cpd.PeriodStartDate, cpd.PeriodEndDate        FROM Payroll_Employee AS emp            LEFT JOIN Payroll_CyclePeriodDetails as cpd on cpd.CycleID = emp.CycleID       WHERE TaxYear = (select keyvalue from AAAA_ConfigSettings where keyname='TaxYear')            AND emp.Employee_id = @EmployeeID AND Processed = 0 AND CycleModeID=1      ORDER BY PeriodEndDate asc    END  

GO

-- ============================================
-- SP: Payroll_GetPeriodDetailsForCycleId
-- Schema: dbo
-- ============================================
  /*   Author  : Richa Mills   Create date : 2018/04/07   Description : PeriodList used for PayrollRunVariance Report   Payroll_GetPeriodDetailsForCycleId 17  */  CREATE procedure [dbo].[Payroll_GetPeriodDetailsForCycleId]  @CycleId int  as    begin  Select Period_Id,PeriodStartDate,PeriodEndDate, ProcessingMonth + ' (' + TaxYear + ')' + CASE WHEN Processed = 1 THEN ' Final Run' ELSE ' TrialRun' END  AS PeriodDesc from payroll_CyclePeriodDetails where CycleId = @CycleId and (Processed = 1 OR LockedDown = 1)    end  

GO

-- ============================================
-- SP: Payroll_GetPeriodIdByEmployeeId
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Ghanshyam Dhanani>  -- Create date: <Create Date,, Mar 2014>  -- Description: <Description,,Get the Period Id from Employee Id and Date>  -- Call SP    : Payroll_GetPeriodIdByEmployeeId 42, '23 Feb 2014'  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetPeriodIdByEmployeeId]   @EmployeeId INT,   @Date DATETIME  AS  BEGIN   DECLARE @CycleId INT   SELECT @CycleId = CycleID FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeId      SELECT Period_ID, PeriodStartDate, PeriodEndDate FROM dbo.Payroll_CyclePeriodDetails WHERE @Date BETWEEN PeriodStartDate AND PeriodEndDate AND CycleID = @CycleId AND CycleModeID = 1  END  

GO

-- ============================================
-- SP: Payroll_GetPersonRelationshipSpouse_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Seipei Mathole>  -- Create date: <Create Date,,20 Oct 2016>  -- Description:   -- Call SP    : [Payroll_GetPersonRelationshipSpouse_sp] 1  -- TP:39027  - Seipei Mathole  -- =============================================================================  /****** Script for SelectTopNRows command from SSMS  ******/    CREATE PROCEDURE [dbo].[Payroll_GetPersonRelationshipSpouse_sp]    @EmployeeID INT     AS    BEGIN     SELECT PPR.PersonRelationshipType_ID, PPR.EmployeeID, PPR.IdNo, PPR.PassportIdNo, PPR.PassportCountryID, PPR.DateOfBirth, PPR.Age, PPR.TitleID, PPR.Initials, PPR.Surname, PPR.FullNames, PPR.KnownAsName, PPR.GenderID, PPR.RelationshipID, PPR.TownID, PPR.StreetNameID, PPR.SuburbID, PPR.StreetNumber, PPR.TelephoneHome, PPR.MobileNumber, CK.KinRelationShip    FROM Payroll_PersonRelationshipType PPR   INNER JOIN Payroll_Employee PE On PPR.EmployeeID=PE.Employee_ID   INNER JOIN Const_KinRelationShip CK ON CK.KinRelation_ID = PPR.RelationshipID     WHERE PE.IsMarried in (2,3)    AND PPR.EmployeeID = @EmployeeID    AND CK.KinRelationShip='Primary Spouse'   AND PPR.Enabled = 1    END  

GO

-- ============================================
-- SP: Payroll_GetPersonRelationshipTypeList_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  <Seipei Mathole>  -- Create date: <Create Date,,20 Oct 2016>  -- Description: <Get List of Payroll_PersonRelationship>  -- Call SP    : [Payroll_GetPersonRelationshipTypeList_sp] 3  -- TP:  - Seipei Mathole  -- =============================================================================  /****** Script for SelectTopNRows command from SSMS  ******/    CREATE PROCEDURE [dbo].[Payroll_GetPersonRelationshipTypeList_sp]    @EmployeeID INT     AS    BEGIN     SELECT PRT.PersonRelationshipType_ID,PRT.EmployeeID,PRT.IdNo ,PRT.PassportIdNo,PRT.PassportCountryID,PRT.DateOfBirth,PRT.Age,TitleID ,PRT.Initials,PRT.Surname,PRT.FullNames,PRT.KnownAsName,PRT.GenderID,         PRT.RelationshipID,K.KinRelationShip,PRT.TownID,PRT.SuburbID,PRT.StreetNameID,PRT.StreetNumber,PRT.TelephoneHome,PRT.MobileNumber,PRT.IsEmergencyContact,PRT.MedAidJoiningDate,            CASE          WHEN IsMedAidEmployerContribute = 1 THEN 'Yes'      ELSE 'No'      END AS EmployerContribution,      MedAidTerminateDate,      CASE          WHEN DependantMode = 1 THEN 'Main'         WHEN DependantMode = 2 THEN 'First'      WHEN DependantMode = 3 THEN 'Additional'      ELSE 'Terminated'       END AS DependantMode,      CASE         WHEN IsAdultDependant = 1 THEN 'Adult'      WHEN IsChildDependant = 1 THEN 'Child'      ELSE 'NONE'       END AS Dependant                 ,PRT.Enabled        ,PRT.CapturerId        ,PRT.DateCaptured        ,PRT.ModifierId        ,PRT.DateModified    FROM dbo.Payroll_PersonRelationshipType PRT         INNER JOIN Const_KinRelationShip K  ON  PRT.RelationshipID = K.KinRelation_ID      WHERE EmployeeID = @EmployeeID AND PRT.Enabled = 1      ORDER BY PersonRelationshipType_ID ASC      END  

GO

-- ============================================
-- SP: Payroll_GetPositionHistory_sp
-- Schema: dbo
-- ============================================
    /*   Author  : Ferdi Botha   Created  : 31/05/2019   Description : Returns a History of (changed) records for the Job Profile, Advert No, Circular No, Employee No, Grade, Status     Modified : Richa M - Add AdvertNo to history table   E Beetge WI59825 Seconded status when its not 1 - Vacant, 2 - Occupied or 3 - Obsolete     Exec Payroll_GetPositionHistory_sp 3016  */  CREATE procedure [dbo].[Payroll_GetPositionHistory_sp] @PositionID int = null  as  begin     declare @i int = 1,     @c int = 0,     @ix int = 1,     @cx int = 0,     @PositionHistory_ID int,     @EmployeeID int,     @DepartmentID int,     @DivisionID int,     @StartDate datetime,     @EndDate datetime,     @StartDateX datetime,     @EndDateX datetime,     @Status int,     @VacancyNo varchar(200),     @AdvertNo nvarchar(50),     @Enabled bit,     @DateCaptured datetime,     @CapturerID int,     @DateModified datetime,     @ModifierID int,     @ParentID int,     @EmployeeTypeID int,     @EmployeeSubtypeID int,     @ConditionOfServiceID int,     @ScoaCostingID int,     @ScoaFundID int,     @JobProfileID int,     @TaskGradeID int,     @IsNonEmployee bit,     @ScoaExpenseID int,     @RegionID int,     @FunctionID int,     @ProjectID int,     @PayrollDefinitionGroupID int,     @LockFields bit,     @lowDate datetime = '1900-01-01 00:00:00',     @highDate datetime = '9999-12-31 00:00:00'     declare @positionHistory as table (      [ix] [int] identity(1, 1) not null,    [PositionHistory_ID] [int] not null,    [PositionID] [int] not null,    [EmployeeID] [int] null,    [DepartmentID] [int] not null,    [DivisionID] [int] not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [Status] [int] not null,    [VacancyNo] [varchar](200) null,    [AdvertNo] [nvarchar](50) null,    [Enabled] [bit] not null,    [DateCaptured] [datetime] not null,    [CapturerID] [int] not null,    [DateModified] [datetime] null,    [ModifierID] [int] null,    [ParentID] [int] null,    [EmployeeTypeID] [int] null,    [EmployeeSubtypeID] [int] null,    [ConditionOfServiceID] [int] null,    [ScoaCostingID] [int] null,    [ScoaFundID] [int] null,    [JobProfileID] [int] null,    [TaskGradeID] [int] null,    [IsNonEmployee] [bit] null,    [ScoaExpenseID] [int] null,    [RegionID] [int] null,    [FunctionID] [int] null,    [ProjectID] [int] null,    [PayrollDefinitionGroupID] [int] null,    [LockFields] [bit] null     )     declare @taskGradeHistory as table (      [ix] [int] not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [TaskGradeID] [int] null     )     declare @results as table (      [ix] [int] identity(1, 1) not null,    [PositionHistory_ID] [int] not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [JobProfileID] [int] null,    [TaskGradeID] [int] null,    [VacancyNo] [varchar](200) null,    [AdvertNo] [varchar](50) null,    [EmployeeID] [int] null,    [Status] [int] not null     )     insert into @positionHistory([PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo],[AdvertNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], [TaskGradeID], [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields])      select [PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo],[AdvertNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], 0, [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields]       from [Payroll_PositionHistory] with(nolock)       where ([PositionID] = @PositionID)      order by [StartDate]     set @c = (select count([ix]) from @positionHistory)     if (@c > 0)   begin      insert into @results([PositionHistory_ID], [StartDate], [EndDate], [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status])       select top 1 [PositionHistory_ID], [StartDate], [EndDate], [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status]        from @positionHistory        where ([ix] = 1)      while (@i <= @c)    begin       select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo], @AdvertNo = [AdvertNo] ,@Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @TaskGradeID = [TaskGradeID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]        from @positionHistory where ([ix] = @i)       if (exists(        select [StartDate], [EndDate], [JobProfileID], [VacancyNo],[AdvertNo], [EmployeeID], [Status]         from @positionHistory          where ([ix] = (@i + 1) and isnull([JobProfileID], 0) = isnull(@JobProfileID, 0) and isnull([VacancyNo], 0) = isnull(@VacancyNo, 0) and isnull([AdvertNo], 0) = isnull(@AdvertNo, 0) and isnull([EmployeeID], 0) = isnull(@EmployeeID, 0) and isnull([Status], 0) = isnull(@Status, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = (@i + 1)))         where ([ix] = @ix)       end     else if (not exists(        select [StartDate], [EndDate], [JobProfileID], [VacancyNo],[AdvertNo] [EmployeeID], [Status]         from @results          where ([ix] = (@i + 1) and isnull([JobProfileID], 0) = isnull(@JobProfileID, 0) and isnull([VacancyNo], 0) = isnull(@VacancyNo, 0) and isnull([AdvertNo], 0) = isnull(@AdvertNo, 0) and isnull([EmployeeID], 0) = isnull(@EmployeeID, 0) and isnull([Status], 0) = isnull(@Status, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))         where ([ix] = @ix)        if (@i < @c)      begin         select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo],@AdvertNo = [AdvertNo], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @TaskGradeID = [TaskGradeID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]          from @positionHistory where ([ix] = (@i + 1))         insert into @results([PositionHistory_ID], [StartDate], [EndDate], [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status])          values(@PositionHistory_ID, @StartDate, @EndDate, @JobProfileID, @TaskGradeID, @VacancyNo,@AdvertNo, @EmployeeID, @Status)        end      else      begin         update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))          where ([ix] = @ix)        end        set @ix = @ix + 1       end       set @i = @i + 1      end     end     set @i = 1     select @c = count([ix]) from @results     while (@i <= @c)   begin      select @StartDate = [StartDate], @EndDate = [EndDate], @JobProfileID = [JobProfileID] from @results where ([ix] = @i)      insert into @taskGradeHistory([ix], [StartDate], [EndDate], [TaskGradeID])       select distinct row_number() over(order by min([StartDate])), min([StartDate]), max([EndDate]), [TaskGradeID]        from [Payroll_JobProfileHistory] as [JPH] with(nolock)        where ([JobProfileID] = @JobProfileID)        group by [TaskGradeID]         order by min([StartDate])      set @ix = 1      select @cx = count([ix]) from @taskGradeHistory      while (@ix <= @cx)    begin       select @StartDateX = [StartDate], @EndDateX = [EndDate], @TaskGradeID = [TaskGradeID] from @taskGradeHistory where ([ix] = @ix)       if (@StartDateX <= @StartDate and @EndDateX >= @EndDate)     begin        update @results set [TaskGradeID] = @TaskGradeID where ([ix] = @i and [TaskGradeID] = 0)       end     else if ((@StartDateX between @StartDate and @EndDate) or (@EndDateX between @StartDate and @EndDate))     begin        if (@EndDateX >= @StartDate and @EndDateX < @EndDate)      begin         if (@EndDateX < @highDate)       begin          set @StartDate = dateadd(day, 1, @EndDateX)          insert into @results([PositionHistory_ID], [StartDate], [EndDate], [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status])           select [PositionHistory_ID], dateadd(day, 1, @EndDateX), @EndDate, [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status]            from @results where ([ix] = @i)          set @c = @c + 1         end         set @EndDate = @EndDateX         update @results set [EndDate] = @EndDateX, [TaskGradeID] = @TaskGradeID where ([ix] = @i)        end      else if (@StartDateX > @lowDate and @StartDateX <= @StartDate)      begin         if (@StartDateX > @lowDate)       begin          set @EndDate = dateadd(day, -1, @StartDateX)          insert into @results([PositionHistory_ID], [StartDate], [EndDate], [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status])           select [PositionHistory_ID], @StartDate, dateadd(day, -1, @StartDateX), [JobProfileID], [TaskGradeID], [VacancyNo],[AdvertNo], [EmployeeID], [Status]            from @results where ([ix] = @i)          set @c = @c + 1         end         set @StartDate = @StartDateX         update @results set [StartDate] = @StartDateX, [TaskGradeID] = @TaskGradeID where ([ix] = @i)        end       end       set @ix = @ix + 1      end      set @i = @i + 1     end      select 1 as PositionHistory_Id,PositionDesc,StartDate,EndDate,JobProfile_ID,JobTitle,VacancyNo,AdvertNo,EmployeeID,Name,TaskGradeName,Status from(     select  [RES].[PositionHistory_ID], [PP].[PositionDesc], [RES].[StartDate], [RES].[EndDate], [JP].[JobProfile_ID], [JP].[JobTitle],[RES].[VacancyNo],IsNULL([RES].[AdvertNo],'')AdvertNo, [RES].[EmployeeID],      (isnull([PE].[Initials] + ' ', '') + isnull([PE].[Surname], '') + case when [PE].[IdNo] is not null then ' (' + cast([PE].[IdNo] as nvarchar(13)) + ')' else '' end) as [Name],      [TG].[TaskGradeName], (case [RES].[Status] when 1 then 'Vacant' when 2 then 'Occupied' when 3 then 'Obsolete' else 'Seconded' end) as [Status]      from @results as [RES]       join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = @PositionID       left outer join [Payroll_JobProfile] as [JP] with(nolock) on [JP].[JobProfile_ID] = [RES].[JobProfileID]       left outer join [Payroll_TaskGrade] as [TG] with(nolock) on [TG].[TaskGrade_ID] = [RES].[TaskGradeID]       left outer join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [RES].[EmployeeID])v1       --group by PositionDesc,JobProfile_ID,JobTitle,VacancyNo,AdvertNo,EmployeeID,Name,TaskGradeName,Status       order by StartDate desc      end

GO

-- ============================================
-- SP: Payroll_GetPositionListByJobProfileId_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,25/Sep/2018>  -- Description: <Description,Get List of position attach to Job profile>  -- update the sp and set the logic of the 8 charctor with EmployeeNumber  -- =============================================  /*     Modified : Modiri   Date  : 2019/05/31   Reason  : #86470 Deduction Priority of Statutory Deduction not to be changed by the user     Modified : Modiri   Date  : 2019/06/11   Reason  : #86470 Deduction Priority of Statutory Deduction not to be changed by the user       Changed the start date to ready from the job profile     Modified : Modiri   Date  : 2019/06/20   Reason  : #90621 Issue Employee history, Position History and Job Profile Position linked to Job Profile information     Modified : Ferdi   Date  : 2019/08/12   Reason  : #92745 => Position history do not update correctly if the Job Profile Task Grade level is changed     Modified : Modiri   Date  : 2019/09/02   Reason  : #90963 Lephalale: employee transfer     Modified : Richa M   Date  : 2022/07/05   Reason  : The SP is not working correctly for Upperlimit employees      */    CREATE procedure [dbo].[Payroll_GetPositionListByJobProfileId_sp] @JobProfileId int  as  begin     set nocount on;     select [PP].[PositionDesc] as [Position], (       select min([StartDate]) from [Payroll_PositionHistory] where ([PositionID] = [PP].[Position_ID])      ) as [StartDate], (       select max([EndDate]) from [Payroll_PositionHistory] where ([PositionID] = [PP].[Position_ID])      ) as [EndDate], [JP].[JobTitle], [PP].[AdvertNo] as [AdvertRefNo], [PP].[VacancyNo] as [CircularNumber],      replace(str([PE].[Employee_ID], 8), ' ', '0') as [EmployeeNumber],      (isnull([PE].[FirstName], '') + ' ' + isnull([PE].[SecondName], '') + ' ' + isnull([PE].[Surname], '')) as [Employee],      [PTG].[TaskGradeName] as [Grade], isnull([PSS].[Status], 'Vacant') as [Status]     from [Payroll_Position] as [PP]      left join [Payroll_Employee] as [PE] on [PE].Employee_ID = [PP].EmployeeID      join [Payroll_JobProfile] as [JP] on [JP].[JobProfile_ID] = [PP].[JobProfileID]      left join [Payroll_TaskGrade] as [PTG] on [PTG].[TaskGrade_ID] = [JP].[TaskGradeId]      join [Payroll_PositionStatus_sys] as [PSS] on [PSS].[PositionStatus_ID] = [PP].[Status]     where ([PP].[JobProfileID] = @JobProfileId)      order by [PP].[PositionDesc] asc    end

GO

-- ============================================
-- SP: Payroll_GetPositionLockForJpNotifcation
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- E Beetge WI77790, locked fields changes  -- =============================================  CREATE PROCEDURE dbo.Payroll_GetPositionLockForJpNotifcation   -- Add the parameters for the stored procedure here  AS  BEGIN     -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;   SELECT     PP.Position_ID,   PP.PositionDesc AS PositionDesc,   PP.StartDate,   PP.EndDate,   PJ.JobTitle,   T.TaskGradeName AS GradeName   from Payroll_Position PP   Left Join dbo.Payroll_JobProfile PJ ON PP.JobProfileID =PJ.JobProfile_ID   LEFT JOIN dbo.Payroll_TaskGrade T ON T.TaskGrade_Id = PJ.TaskGradeId   WHERE LockFields = 1 and LockedDate is not null  END

GO

-- ============================================
-- SP: Payroll_GetPositionRuleHistory_sp
-- Schema: dbo
-- ============================================
/*   Author  : Ferdi Botha   Created  : 31/05/2019   Description : Returns a History of (changed) records for the Job Profile, SCOA Expense Item, Salary Transaction Group, Employee Type, Employee Subtype, Condition of Service, Lock Fields  */  CREATE procedure [dbo].[Payroll_GetPositionRuleHistory_sp] @PositionID int = null  as  begin     set nocount on;     declare @i int = 1,     @c int = 0,     @ix int = 1,     @PositionHistory_ID int,     @EmployeeID int,     @DepartmentID int,     @DivisionID int,     @StartDate datetime,     @EndDate datetime,     @Status int,     @VacancyNo varchar(200),     @Enabled bit,     @DateCaptured datetime,     @CapturerID int,     @DateModified datetime,     @ModifierID int,     @ParentID int,     @EmployeeTypeID int,     @EmployeeSubtypeID int,     @ConditionOfServiceID int,     @ScoaCostingID int,     @ScoaFundID int,     @JobProfileID int,     @IsNonEmployee bit,     @ScoaExpenseID int,     @RegionID int,     @FunctionID int,     @ProjectID int,     @PayrollDefinitionGroupID int,     @LockFields bit     declare @positionHistory as table (      [ix] [int] identity(1, 1) not null,    [PositionHistory_ID] [int] not null,    [PositionID] [int] not null,    [EmployeeID] [int] null,    [DepartmentID] [int] not null,    [DivisionID] [int] not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [Status] [int] not null,    [VacancyNo] [varchar](200) null,    [Enabled] [bit] not null,    [DateCaptured] [datetime] not null,    [CapturerID] [int] not null,    [DateModified] [datetime] null,    [ModifierID] [int] null,    [ParentID] [int] null,    [EmployeeTypeID] [int] null,    [EmployeeSubtypeID] [int] null,    [ConditionOfServiceID] [int] null,    [ScoaCostingID] [int] null,    [ScoaFundID] [int] null,    [JobProfileID] [int] null,    [IsNonEmployee] [bit] null,    [ScoaExpenseID] [int] null,    [RegionID] [int] null,    [FunctionID] [int] null,    [ProjectID] [int] null,    [PayrollDefinitionGroupID] [int] null,    [LockFields] [bit] null     )     declare @results as table (      [ix] [int] identity(1, 1) not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [JobProfileID] [int] null,    [ScoaExpenseID] [int] null,    [PayrollDefinitionGroupID] [int] null,    [EmployeeTypeID] [int] null,    [EmployeeSubtypeID] [int] null,    [ConditionOfServiceID] [int] null,    [LockFields] [bit] null     )     declare @ActiveFinYear varchar(9) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'ActiveFinYear'))     insert into @positionHistory([PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields])      select [PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields]       from [Payroll_PositionHistory]       where ([PositionID] = @PositionID and [Enabled] = 1)        order by [StartDate]     set @c = (select count([ix]) from @positionHistory)     if (@c > 0)   begin      insert into @results([StartDate], [EndDate], [JobProfileID], [ScoaExpenseID], [PayrollDefinitionGroupID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [LockFields])       select top 1 [StartDate], [EndDate], [JobProfileID], [ScoaExpenseID], [PayrollDefinitionGroupID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [LockFields]        from @positionHistory        where ([ix] = @ix)      while (@i <= @c)    begin       select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]        from @positionHistory where ([ix] = @i)       if (exists(        select [StartDate], [EndDate], [JobProfileID], [ScoaExpenseID], [PayrollDefinitionGroupID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [LockFields]         from @positionHistory          where ([ix] = (@i + 1) and isnull([JobProfileID], 0) = isnull(@JobProfileID, 0) and isnull([ScoaExpenseID], 0) = isnull(@ScoaExpenseID, 0) and isnull([PayrollDefinitionGroupID], 0) = isnull(@PayrollDefinitionGroupID, 0) and isnull([EmployeeTypeID], 0) = isnull(@EmployeeTypeID, 0) and isnull([EmployeeSubtypeID], 0) = isnull(@EmployeeSubtypeID, 0) and isnull([ConditionOfServiceID], 0) = isnull(@ConditionOfServiceID, 0) and isnull([LockFields], 0) = isnull(@LockFields, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = (@i + 1)))         where ([ix] = @ix)       end     else if (not exists(        select [StartDate], [EndDate], [JobProfileID], [ScoaExpenseID], [PayrollDefinitionGroupID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [LockFields]         from @results          where ([ix] = (@i + 1) and isnull([JobProfileID], 0) = isnull(@JobProfileID, 0) and isnull([ScoaExpenseID], 0) = isnull(@ScoaExpenseID, 0) and isnull([PayrollDefinitionGroupID], 0) = isnull(@PayrollDefinitionGroupID, 0) and isnull([EmployeeTypeID], 0) = isnull(@EmployeeTypeID, 0) and isnull([EmployeeSubtypeID], 0) = isnull(@EmployeeSubtypeID, 0) and isnull([ConditionOfServiceID], 0) = isnull(@ConditionOfServiceID, 0) and isnull([LockFields], 0) = isnull(@LockFields, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))         where ([ix] = @ix)        if (@i < @c)      begin         select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]          from @positionHistory where ([ix] = (@i + 1))         insert into @results([StartDate], [EndDate], [JobProfileID], [ScoaExpenseID], [PayrollDefinitionGroupID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [LockFields])          values(@StartDate, @EndDate, @JobProfileID, @ScoaExpenseID, @PayrollDefinitionGroupID, @EmployeeTypeID, @EmployeeSubtypeID, @ConditionOfServiceID, @LockFields)        end      else      begin         update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))          where ([ix] = @ix)        end        set @ix = @ix + 1       end       set @i = @i + 1      end     end     select distinct [RES].[StartDate], [RES].[EndDate], [PJ].[JobTitle], [CSS].[ScoaShortDesc], [PDG].[PayrollDefinitionGroupName], [CET].[EmployeeTypeDescription], [EST].[EmployeeSubtypeDesc], [COS].[ConditionDesc]      from @results as [RES]       left outer join [Payroll_JobProfile] as [PJ] with(nolock) on [PJ].[JobProfile_ID] = [RES].[JobProfileID]       outer apply (        select distinct [ScoaID], [ScoaCode], [ScoaShortDesc] from [Const_SCOA_Structure_Consolidated] where FinYearText = @ActiveFinYear and ScoaID = @ScoaExpenseID         ) as [CSS]       left outer join [Payroll_DefinitionGroup] as [PDG] with(nolock) on [PDG].[PayrollDefinitionGroup_ID] = [RES].[PayrollDefinitionGroupID]       left outer join [Const_EmployeeType_sys] as [CET] with(nolock) on [CET].[EmployeeType_ID] = [RES].[EmployeeTypeID]       left outer join [Payroll_EmployeeSubtypes] as [EST] with(nolock) on [EST].[EmployeeSubtype_ID] = [RES].[EmployeeSubtypeID]       left outer join [Payroll_ConditionOfService] as [COS] with(nolock) on [COS].[ConditionOfService_ID] = [RES].[ConditionOfServiceID]       order by [RES].[StartDate] desc     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetPositions_sp
-- Schema: dbo
-- ============================================
  /* =======================================================================================================================================  -- Author  : Varun Parvataneni  -- Create date : 26/10/2016  -- Description : Get the VacantPosition from  Position table based on the datarange selected in employee screen  -- Call SP  : Payroll_GetVacantPositions_sp 8 ,'2017-04-08 00:00:00.000','9999-12-31 00:00:00.000'  -- Updated By : Ferdi Botha  -- Updated Date : 01/02/2017 - return vacant positions, even when the position end date is less than the employee end date          (but the position start date is less than or equal to the employee start date)     ======================================================================================================================================= */  create procedure [Payroll_GetPositions_sp] @DivisionID int, @StartDate datetime, @EndDate datetime  as  begin     select distinct [Position_ID], [PositionDesc]      from [Payroll_Position] as [pos] join [Payroll_PositionHistory] as [posH] on [Position_ID] = [posH].[PositionID]       where ([posH].[DivisionID] = @DivisionID and [Funds] = 1 and [posH].[StartDate] <= @Startdate and [posH].[EndDate] >= @StartDate)     end  

GO

-- ============================================
-- SP: Payroll_GetPositionSCOAHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Created  : 31/05/2019   Description : Returns a History of (changed) records for the Department, Division, SCOA Function, SCOA Project, SCOA Region  */  CREATE procedure [dbo].[Payroll_GetPositionSCOAHistory_sp] @PositionID int = null  as  begin     declare @i int = 1,     @c int = 0,     @ix int = 1,     @PositionHistory_ID int,     @EmployeeID int,     @DepartmentID int,     @DivisionID int,     @StartDate datetime,     @EndDate datetime,     @Status int,     @VacancyNo varchar(200),     @Enabled bit,     @DateCaptured datetime,     @CapturerID int,     @DateModified datetime,     @ModifierID int,     @ParentID int,     @EmployeeTypeID int,     @EmployeeSubtypeID int,     @ConditionOfServiceID int,     @ScoaCostingID int,     @ScoaFundID int,     @JobProfileID int,     @IsNonEmployee bit,     @ScoaExpenseID int,     @RegionID int,     @FunctionID int,     @ProjectID int,     @PayrollDefinitionGroupID int,     @LockFields bit     declare @positionHistory as table (      [ix] [int] identity(1, 1) not null,    [PositionHistory_ID] [int] not null,    [PositionID] [int] not null,    [EmployeeID] [int] null,    [DepartmentID] [int] not null,    [DivisionID] [int] not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [Status] [int] not null,    [VacancyNo] [varchar](200) null,    [Enabled] [bit] not null,    [DateCaptured] [datetime] not null,    [CapturerID] [int] not null,    [DateModified] [datetime] null,    [ModifierID] [int] null,    [ParentID] [int] null,    [EmployeeTypeID] [int] null,    [EmployeeSubtypeID] [int] null,    [ConditionOfServiceID] [int] null,    [ScoaCostingID] [int] null,    [ScoaFundID] [int] null,    [JobProfileID] [int] null,    [IsNonEmployee] [bit] null,    [ScoaExpenseID] [int] null,    [RegionID] [int] null,    [FunctionID] [int] null,    [ProjectID] [int] null,    [PayrollDefinitionGroupID] [int] null,    [LockFields] [bit] null     )     declare @results as table (      [ix] [int] identity(1, 1) not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [DepartmentID] [int] not null,    [DivisionID] [int] not null,    [FunctionID] [int] null,    [ProjectID] [int] null,    [RegionID] [int] null     )     insert into @positionHistory([PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields])      select [PositionHistory_ID], [PositionID], [EmployeeID], [DepartmentID], [DivisionID], [StartDate], [EndDate], [Status], [VacancyNo], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ParentID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [ScoaCostingID], [ScoaFundID], [JobProfileID], [IsNonEmployee], [ScoaExpenseID], [RegionID], [FunctionID], [ProjectID], [PayrollDefinitionGroupID], [LockFields]       from [Payroll_PositionHistory]       where ([PositionID] = @PositionID and [Enabled] = 1)        order by [StartDate]     set @c = (select count([ix]) from @positionHistory)     if (@c > 0)   begin      insert into @results([StartDate], [EndDate], [DepartmentID], [DivisionID], [FunctionID], [ProjectID], [RegionID])       select top 1 [StartDate], [EndDate], [DepartmentID], [DivisionID], [FunctionID], [ProjectID], [RegionID]        from @positionHistory        where ([ix] = 1)      while (@i <= @c)    begin       select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]        from @positionHistory where ([ix] = @i)       if (exists(        select [StartDate], [EndDate], [DepartmentID], [DivisionID], [FunctionID], [ProjectID], [RegionID]         from @positionHistory          where ([ix] = (@i + 1) and isnull([DepartmentID], 0) = isnull(@DepartmentID, 0) and isnull([DivisionID], 0) = isnull(@DivisionID, 0) and isnull([FunctionID], 0) = isnull(@FunctionID, 0) and isnull([ProjectID], 0) = isnull(@ProjectID, 0) and isnull([RegionID], 0) = isnull(@RegionID, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = (@i + 1)))         where ([ix] = @ix)       end     else if (not exists(        select [StartDate], [EndDate], [DepartmentID], [DivisionID], [FunctionID], [ProjectID], [RegionID]         from @results          where ([ix] = (@i + 1) and isnull([DepartmentID], 0) = isnull(@DepartmentID, 0) and isnull([DivisionID], 0) = isnull(@DivisionID, 0) and isnull([FunctionID], 0) = isnull(@FunctionID, 0) and isnull([ProjectID], 0) = isnull(@ProjectID, 0) and isnull([RegionID], 0) = isnull(@RegionID, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))         where ([ix] = @ix)        if (@i < @c)      begin         select @PositionHistory_ID = [PositionHistory_ID], @PositionID = [PositionID], @EmployeeID = [EmployeeID], @DepartmentID = [DepartmentID], @DivisionID = [DivisionID], @StartDate = [StartDate], @EndDate = [EndDate], @Status = [Status], @VacancyNo = [VacancyNo], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @ParentID = [ParentID], @EmployeeTypeID = [EmployeeTypeID], @EmployeeSubtypeID = [EmployeeSubtypeID], @ConditionOfServiceID = [ConditionOfServiceID], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @JobProfileID = [JobProfileID], @IsNonEmployee = [IsNonEmployee], @ScoaExpenseID = [ScoaExpenseID], @RegionID = [RegionID], @FunctionID = [FunctionID], @ProjectID = [ProjectID], @PayrollDefinitionGroupID = [PayrollDefinitionGroupID], @LockFields = [LockFields]          from @positionHistory where ([ix] = (@i + 1))         insert into @results([StartDate], [EndDate], [DepartmentID], [DivisionID], [FunctionID], [ProjectID], [RegionID])          values(@StartDate, @EndDate, @DepartmentID, @DivisionID, @FunctionID, @ProjectID, @RegionID)        end      else      begin         update @results set [EndDate] = (select [EndDate] from @positionHistory where ([ix] = @i))          where ([ix] = @ix)        end        set @ix = @ix + 1       end       set @i = @i + 1      end     end     select distinct [RES].[StartDate], [RES].[EndDate], [CD].[DepartmentDesc], [CDV].[DivisionDesc], [CSF].[ScoaCode], [CSF].[ScoaDesc], [PP].[ProjectName], [CSR].[ScoaShortDesc], cast([PP].[ProjectCode] as varchar) + ' | ' + [PP].[ProjectName] as [ScoaDescription]      from @results as [RES]       left outer join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [RES].[DepartmentID]       left outer join [Const_Division] as [CDV] with(nolock) on [CDV].[Division_ID] = [RES].[DivisionID]       left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [RES].[ProjectID]       outer apply (        select distinct [ScoaID], [ScoaCode], [ScoaDesc] from [Const_SCOA_Function_Structure_Consolidated] where FinYearText = PP.FinYear and ScoaID = RES.FunctionID         ) as [CSF]       outer apply (        select distinct [ScoaID],[ScoaShortDesc] from [Const_SCOA_Regional_Structure_Consolidated] where FinYearText = [PP].[FinYear] and ScoaID = [RES].[RegionID]       ) as [CSR]       order by [RES].[StartDate] desc     select * from @results    end

GO

-- ============================================
-- SP: Payroll_GetPositionSplits_sp
-- Schema: dbo
-- ============================================
    -- =================================================================================================  -- Author:  Ferdi Botha  -- Create date: 11/02/2017  -- Description: Returns the position splitting for the position based on PositionID  -- exec [Payroll_GetPositionSplits_sp] 8  -- =================================================================================================  create procedure [dbo].[Payroll_GetPositionSplits_sp] @PositionID int  as    begin     select [JobProfileExtraDivisionFunctionCode_ID], [DepartmentDesc] + ' - ' + [DivisionDesc] as Division, [ScoaCode], [CostPercentage], [jpc].[StartDate], [jpc].[EndDate], [pp].[ProjectDesc],[ProjectName]      from [Payroll_JobProfileExtraDivisionFunctionCode] as [jpc]       join [Const_Division] as [div] with(nolock) on [Division_ID] = [jpc].[DivisionID]       join [Const_Department] as [dep] with(nolock) on [Department_ID] = [div].[DepartmentID]       join [Const_SCOA_Function_Structure] as [sfs] with(nolock) on [ScoaID] = [div].[SCOAFunctionID]       join [Plan_Project] as [pp] with(nolock) on [Project_ID] = [jpc].[ProjectID]     where ([jpc].[Enabled] = 1 and [div].[Enabled] = 1 and [sfs].[Enabled] = 1 and [PositionID] = @PositionID)      order by [CostPercentage] desc    end  

GO

