-- ============================================
/*   Author  : Ferdi Botha   Created  : 31/05/2019   Description : Returns a History of (changed) records for the Department, Division, SCOA Function, SCOA Project, SCOA Region, Percentage  */  CREATE procedure [dbo].[Payroll_GetPositionSplitsHistory_sp] @PositionID int = null  as  begin     declare @i int = 1,     @c int = 0,     @ix int = 1,     @JobProfileExtraDivisionFunctionCodeHistory_ID int,     @JobProfileExtraDivisionFunctionCode_ID int,     @JobProfileID int,     @DivisionID int,     @CostPercentage decimal(5, 2),     @Enabled bit,     @DateCaptured datetime,     @CapturerID int,     @DateModified datetime,     @ModifierID int,     @ScoaCostingID int,     @ScoaFundID int,     @ProjectID int,     @SCOAFunctionId int,     @SCOARegionId int,     @StartDate datetime,     @EndDate datetime     declare @positionSplittingHistory as table (      [ix] [int] identity(1, 1) not null,    [JobProfileExtraDivisionFunctionCodeHistory_ID] [int] not null,    [JobProfileExtraDivisionFunctionCode_ID] [int] not null,    [JobProfileID] [int] null,    [DivisionID] [int] null,    [CostPercentage] [decimal](5, 2) null,    [Enabled] [bit] null,    [DateCaptured] [datetime] not null,    [CapturerID] [int] not null,    [DateModified] [datetime] null,    [ModifierID] [int] null,    [PositionId] [int] null,    [ScoaCostingID] [int] null,    [ScoaFundID] [int] null,    [ProjectID] [int] null,    [SCOAFunctionId] [int] null,    [SCOARegionId] [int] null,    [StartDate] [datetime] null,    [EndDate] [datetime] null     )     declare @results as table (      [ix] [int] identity(1, 1) not null,    [StartDate] [datetime] not null,    [EndDate] [datetime] not null,    [DivisionID] [int] not null,    [FunctionID] [int] null,    [ProjectID] [int] null,    [RegionID] [int] null,    [CostPercentage] [decimal](5, 2) null     )     insert into @positionSplittingHistory([JobProfileExtraDivisionFunctionCodeHistory_ID], [JobProfileExtraDivisionFunctionCode_ID], [JobProfileID], [DivisionID], [CostPercentage], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [PositionId], [ScoaCostingID], [ScoaFundID], [ProjectID], [SCOAFunctionId], [SCOARegionId], [StartDate], [EndDate])      select [JobProfileExtraDivisionFunctionCodeHistory_ID], [JobProfileExtraDivisionFunctionCode_ID], [JobProfileID], [DivisionID], [CostPercentage], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [PositionId], [ScoaCostingID], [ScoaFundID], [ProjectID], [SCOAFunctionId], [SCOARegionId], [StartDate], [EndDate]       from [Payroll_JobProfileExtraDivisionFunctionCodeHistory]       where ([PositionId] = @PositionID and [Enabled] = 1)        order by [StartDate]     set @c = (select count([ix]) from @positionSplittingHistory)     if (@c > 0)   begin      insert into @results([StartDate], [EndDate], [DivisionID], [FunctionID], [ProjectID], [RegionID], [CostPercentage])       select top 1 [StartDate], [EndDate], [DivisionID], [SCOAFunctionId], [ProjectID], [SCOARegionId], [CostPercentage]        from @positionSplittingHistory        where ([ix] = 1)      while (@i <= @c)    begin       select @JobProfileExtraDivisionFunctionCodeHistory_ID = [JobProfileExtraDivisionFunctionCodeHistory_ID], @JobProfileExtraDivisionFunctionCode_ID = [JobProfileExtraDivisionFunctionCode_ID], @JobProfileID = [JobProfileID], @DivisionID = [DivisionID], @CostPercentage = [CostPercentage], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @PositionID = [PositionId], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @ProjectID = [ProjectID], @SCOAFunctionId = [SCOAFunctionId], @SCOARegionId = [SCOARegionId], @StartDate = [StartDate], @EndDate = [EndDate]        from @positionSplittingHistory where ([ix] = @i)       if (exists(        select [StartDate], [EndDate], [DivisionID], [SCOAFunctionId], [ProjectID], [SCOARegionId], [CostPercentage]         from @positionSplittingHistory          where ([ix] = (@i + 1) and isnull([DivisionID], 0) = isnull(@DivisionID, 0) and isnull([SCOAFunctionId], 0) = isnull(@SCOAFunctionId, 0) and isnull([ProjectID], 0) = isnull(@ProjectID, 0) and isnull([SCOARegionId], 0) = isnull(@SCOARegionId, 0) and isnull([CostPercentage], 0) = isnull(@CostPercentage, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionSplittingHistory where ([ix] = (@i + 1)))         where ([ix] = @ix)       end     else if (not exists(        select [StartDate], [EndDate], [DivisionID], [FunctionID], [ProjectID], [RegionID], [CostPercentage]         from @results          where ([ix] = (@i + 1) and isnull([DivisionID], 0) = isnull(@DivisionID, 0) and isnull([FunctionID], 0) = isnull(@SCOAFunctionId, 0) and isnull([ProjectID], 0) = isnull(@ProjectID, 0) and isnull([RegionID], 0) = isnull(@SCOARegionId, 0) and isnull([CostPercentage], 0) = isnull(@CostPercentage, 0))))       begin        update @results set [EndDate] = (select [EndDate] from @positionSplittingHistory where ([ix] = @i))         where ([ix] = @ix)        if (@i < @c)      begin         select @JobProfileExtraDivisionFunctionCodeHistory_ID = [JobProfileExtraDivisionFunctionCodeHistory_ID], @JobProfileExtraDivisionFunctionCode_ID = [JobProfileExtraDivisionFunctionCode_ID], @JobProfileID = [JobProfileID], @DivisionID = [DivisionID], @CostPercentage = [CostPercentage], @Enabled = [Enabled], @DateCaptured = [DateCaptured], @CapturerID = [CapturerID], @DateModified = [DateModified], @ModifierID = [ModifierID], @PositionID = [PositionId], @ScoaCostingID = [ScoaCostingID], @ScoaFundID = [ScoaFundID], @ProjectID = [ProjectID], @SCOAFunctionId = [SCOAFunctionId], @SCOARegionId = [SCOARegionId], @StartDate = [StartDate], @EndDate = [EndDate]          from @positionSplittingHistory where ([ix] = (@i + 1))         insert into @results([StartDate], [EndDate], [DivisionID], [FunctionID], [ProjectID], [RegionID], [CostPercentage])          values(@StartDate, @EndDate, @DivisionID, @SCOAFunctionId, @ProjectID, @SCOARegionId, @CostPercentage)        end      else      begin         update @results set [EndDate] = (select [EndDate] from @positionSplittingHistory where ([ix] = @i))          where ([ix] = @ix)        end        set @ix = @ix + 1       end       set @i = @i + 1      end     end     select distinct [RES].[StartDate], [RES].[EndDate], [CD].[DepartmentDesc], [CDV].[DivisionDesc], [CSF].[ScoaCode], [CSF].[ScoaDesc], [PP].[ProjectName], [CSR].[ScoaShortDesc], [RES].[CostPercentage], cast([PP].[ProjectCode] as varchar) + ' | ' + [PP].[ProjectName] as [ScoaDescription]      from @results as [RES]       left outer join [Const_Division] as [CDV] with(nolock) on [CDV].[Division_ID] = [RES].[DivisionID]       left outer join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [CDV].[DepartmentID]       left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [RES].[ProjectID]       outer apply (        select distinct [ScoaID], [ScoaCode], [ScoaDesc] from [Const_SCOA_Function_Structure_Consolidated] where FinYearText = [PP].[FinYear] and ScoaID = [RES].[FunctionID]         ) as [CSF]       outer apply (        select distinct [ScoaID],[ScoaShortDesc] from [Const_SCOA_Regional_Structure_Consolidated] where FinYearText = [PP].[FinYear] and ScoaID = [RES].[RegionID]         ) as [CSR]       order by [RES].[StartDate] desc    end

GO

-- ============================================
-- SP: Payroll_GetProfileGroupKPIDetail
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_GetProfileGroupKPIDetail] --1  @ProfileGroupId int  as  begin   select    pgd.ProfileGroupDetail_ID,    pgd.ProfileGroupID,    pgd.KPIGroupDetailID,    pgd.Enabled,    pgd.DateCaptured,    pgd.CapturerID,    pgd.DateModified,    pgd.ModifierID,   pg.ProfileGroupName,   d.KPIGroupName,   kpi.KPIGroupName as KPI   from Payroll_ProfileGroupKPIDetail pgd   inner join Const_KPIGroupDetail d on d.KPIGroupDetail_ID = pgd.KPIGroupDetailID   inner join Payroll_ProfileGroup pg on pg.ProfileGroup_ID = pgd.ProfileGroupID   inner join Const_KPIGroup kpi on kpi.KPIGroup_ID = d.KPIGroupID   where pgd.ProfileGroupID = @ProfileGroupId  end  

GO

-- ============================================
-- SP: Payroll_GetProspectiveEmployeeBenefitDetail_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Tshekedi Mogwere  -- Create date: 23 August 2017  -- Description:   -- Call : [Payroll_GetProspectiveEmployeeBenefitDetail_sp] 36,5  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetProspectiveEmployeeBenefitDetail_sp]  @EmployeeID INT   ,@BenegitTypeID INT   AS  BEGIN   SELECT        EMA.EmployeeBenefit_ID,     EMA.BenefitSchemeID,     CONVERT(NVARCHAR(12),EMA.JoinDate, 103) AS JoinDate,    CONVERT(NVARCHAR(12),EMA.TerminationDate, 103) AS TerminationDate,    V.VendorName AS Fund,    MS.FundName AS PLANName,    EMA.ReferenceNo,     CASE WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  < CAST(GETDATE() AS DATE ) THEN 'Terminated'      WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )  THEN 'Active'       WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  >= CAST(GETDATE() AS DATE ) THEN 'Pending'    ELSE '' END  AS STATUS,    CASE WHEN IsCurrent = 1 THEN 'Yes' ELSE 'No' END AS CurrentStatus   FROM dbo.Payroll_ProspectiveEmpBenefitDetail EMA    INNER JOIN dbo.Payroll_BenefitDetail MS ON MS.Benefit_ID = EMA.BenefitSchemeID    INNER JOIN dbo.Cons_Vendor V ON V.Vendor_ID = MS.VendorID   WHERE EMA.EmployeeId = @EmployeeID AND EMA.Enabled=1 AND MS.BenefitTypeID=@BenegitTypeID  END      

GO

-- ============================================
-- SP: Payroll_GetProspectiveEmployeeInformation_sp
-- Schema: dbo
-- ============================================
  -- Author : Tshekedi Mogwere  -- Description : Get Prospective user information to display on the Edit Prospective employee screen  -- Call : [Payroll_GetProspectiveEmployeeInformation_sp] 1    CREATE PROCEDURE [dbo].[Payroll_GetProspectiveEmployeeInformation_sp] @ProspectiveEmpID AS INT  AS      BEGIN                SELECT TOP 1 EMP.FixedSalary AS Basic_salary ,                  EMP.JoiningDate AS Join_Date ,                      D.DepartmentDesc AS Department_Name ,                  D.DepartmentCode AS Department_code ,                  PCS.ConditionDesc AS Condition_description ,                  PP.PositionDesc AS Designation ,                  Div.DivisionDesc AS Division_Name          FROM    Payroll_ProspectiveEmployee EMP                  INNER JOIN Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID                  INNER JOIN Const_Department AS D ON PP.DepartmentID = D.Department_ID                  INNER JOIN Const_Division AS Div ON PP.DivisionID = Div.Division_ID                  INNER JOIN Payroll_ConditionOfService AS PCS ON PP.ConditionOfServiceID = PCS.ConditionOfService_ID              WHERE   EMP.ProspectiveEmployee_ID = @ProspectiveEmpID    ORDER BY EMP.JoiningDate DESC;            END;        

GO

-- ============================================
-- SP: Payroll_GetProspectiveEmployeeListForShortList_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,4/09/2018>  -- Description: <Description,,Get list of Employee >  -- =============================================  CREATE PROCEDURE dbo.Payroll_GetProspectiveEmployeeListForShortList_sp   @PositionId INT,      @CandidateShortListId INT = 0  AS  BEGIN   SET NOCOUNT ON;   SELECT   ISNULL(FirstName,'')+ ' '+  ISNULL(SecondName,'')+' ' + ISNULL(Surname,'') AS EmployeeName,    STUFF ( ( SELECT ','+PPEQ.Qualification                    FROM dbo.Payroll_ProspectiveEmployeeQualifications AS PPEQ                    WHERE PPEQ.ProspectiveEmployeeID =PPE.ProspectiveEmployee_ID                    ORDER BY PPEQ.Qualification_ID                    FOR XML PATH(''),TYPE                     ).value('.','VARCHAR(MAX)')                    , 1,1,SPACE(0)) AS Qualifications,       ppe.ProspectiveEmployee_ID,PES.ShortListingComments as Comments,ISNULL(PES.EmployeeShortList,0) as Shortlist     FROM dbo.Payroll_ProspectiveEmployee AS PPE      Left join Payroll_EmployeeShortListPage as PES on PPE.ProspectiveEmployee_ID=PES.ProspectiveEmployeeId     WHERE PPE.PositionID = @PositionId  END

GO

-- ============================================
-- SP: Payroll_GetProspectiveEmployeeMedicalAIDScheme_sp
-- Schema: dbo
-- ============================================
  /*   Author   : Ferdi Botha   Creation Date : 30/11/2017   Description  : Get the Prospective Employee Medical Aid Scheme Details  */  create procedure [Payroll_GetProspectiveEmployeeMedicalAIDScheme_sp] @EmployeeID int  as  begin     declare @Today datetime = cast(getdate() as date)     select [ProspectiveEmployeeMedicalAID_ID], [MedicalAidSchmeID], [JoinDate], [TerminationDate], [dScheme].StartDate, [dScheme].EndDate,  [VendorName] as [Fund], [FundName] as [PlanName], [Reference], [MemberAmount], [AdultAmount], [ChildAmount], [MaxDependantCount], isnull([IsMaxDependantChildEnabled], 0) as [IsMaxDependantChildEnabled], case when ([JoinDate] <= @Today and ([TerminationDate] is null or [TerminationDate] >= @Today)) then 'Active' else 'Terminated' end as [Status], isnull([AdultCount], 0) as [AdultCount], isnull([AdultContribute], 0) as [AdultContribute], isnull([ChildCount], 0) as [ChildCount], isnull([ChildContribute], 0) as [ChildContribute]      from [Payroll_ProspectiveEmployeeMedicalAIDDetail] as [eScheme] with(nolock)       join [Const_MedicalAIDScheme] as [cScheme] with(nolock) on [MedicalScheme_ID] = [MedicalAidSchmeID]       join [Const_MedicalAIDSchemeDetail] as [dScheme] with(nolock) on [MedicalSchemeID] = [MedicalScheme_ID]       join [Cons_Vendor] as [vScheme] with(nolock) on [Vendor_ID] = [VendorID]       left outer join (        select [ProspectiveEmployeeMedicalAIDID], sum(case when [DependantType] = 0 then 1 else 0 end) as [AdultCount], sum(case when [DependantType] = 0 and [EmployerContribute] = 1 then 1 else 0 end) as [AdultContribute], sum(case when [DependantType] = 1 then 1 else 0 end) as [ChildCount], sum(case when [DependantType] = 1 and [EmployerContribute] = 1 then 1 else 0 end) as [ChildContribute]         from [Payroll_ProspectiveEmployeeMedicalAIDDetailDependants] with(nolock)          where ([Enable] = 1)        group by [ProspectiveEmployeeMedicalAIDID]       ) as [dep] on [ProspectiveEmployeeMedicalAIDID] = [eScheme].[ProspectiveEmployeeMedicalAID_ID]       where ([eScheme].[Enable] = 1 and [cScheme].[Enabled] = 1 and [dScheme].[Enabled] = 1 and [ProspectiveEmployeeID] = @EmployeeID)    end  

GO

-- ============================================
-- SP: Payroll_GetProspectiveExtraTransactions_ForActiveMedicalAid_sp
-- Schema: dbo
-- ============================================
  /*   Author   : Ferdi Botha   Creation Date : 30/11/2017   Description  : Get the Prospective Employee Medical Aid Scheme Details  */  create procedure [Payroll_GetProspectiveExtraTransactions_ForActiveMedicalAid_sp] @EmployeeID int  as  begin     select    [EAMAT].[ProspectiveExtraActiveMedicalAidTransaction_ID],    [EMA].[ProspectiveEmployeeMedicalAID_ID],    [EMA].[MedicalAidSchmeID],    convert(nvarchar(12), [EMA].[JoinDate], 103) as [JoinDate],    CONVERT(NVARCHAR(12),[EMA].TerminationDate, 103) as [TerminationDate],    [V].[VendorName] as [Fund],    [MS].[FundName] as [PlanName],    (select [MedicalAidContributionTypeCaption] from [Const_Payroll_MedicalAidContributionType] where ([MedicalAidContributionType_ID] = [EAMAT].[MedicalAidContributionTypeID])) as [ContributionType],    convert(nvarchar(12), [EAMAT].[PeriodFrom], 103) as [PeriodFrom],    convert(nvarchar(12), [EAMAT].[PeriodTo], 103) as [PeriodTo],    [EAMAT].[Amount],    [EMA].[Reference],    [MSD].[MemberAmount],    [MSD].[AdultAmount],    [MSD].[ChildAmount],    [MS].[EmployeeContributionValue],    [MS].[EmployerContributionValue],    [MS].[EmployerMaxContributorValue],    --MS.Editable as ISPrivate,    (case when cast(isnull([EMA].[TerminationDate], getdate()) as date) < cast(getdate() as date) then 'Terminated'      when cast(isnull([EMA].[TerminationDate], getdate()) as date) >= cast(getdate() as date) and cast([EMA].[JoinDate] as date) <= cast(getdate() as date) then 'Active'       when cast(isnull([EMA].[TerminationDate], getdate()) as date) >= cast(getdate() as date) then 'Pending'    else '' end) as [Status],    (case when [EAMAT].[IsEmployerContribute] = 1 then 'Yes' else 'No' end) as [IsEmployerContribute]     from [Payroll_ProspectiveExtraActiveMedicalAidTransaction] as [EAMAT]       join [Payroll_ProspectiveEmployeeMedicalAIDDetail] as [EMA] on [EMA].[ProspectiveEmployeeMedicalAID_ID] = [EAMAT].[ProspectiveEmployeeMedicalAIDID]       join [Const_MedicalAIDScheme] as [MS] on [MS].[MedicalScheme_ID] = [EMA].[MedicalAidSchmeID]       join [Const_MedicalAIDSchemeDetail] as [MSD] on [MSD].[MedicalSchemeID] = [MS].[MedicalScheme_ID]       join [Cons_Vendor] as [V] on [V].[Vendor_ID] = [MS].[VendorID]     where ([EMA].[ProspectiveEmployeeID] = @EmployeeID and [EMA].[Enable] = 1 and [EAMAT].[Enabled] = 1)    end  

GO

