-- ============================================
-- SP: Payroll_GetPublicHoliday_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 31 JAN 2014  -- Description:  GET PUBLIC HOLIDAY  -- CALLS : [Payroll_GetPublicHoliday_sp] '01/01/2012','01/29/2014','2013/2014'   -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- =============================================  create PROCEDURE [dbo].[Payroll_GetPublicHoliday_sp]     @LeaveTakenFromDate DATETIME,    @LeaveTakenToDate DATETIME,    @FinancialYear NVARCHAR(50) = ''  AS  BEGIN    SELECT       [Holiday_ID]        ,[HolidayDesc]        ,[HolidayDate]        ,[TaxYear]    FROM Const_Holiday     WHERE     Enabled= 1 AND     (TaxYear = @FinancialYear) AND(HolidayDate BETWEEN @LeaveTakenFromDate AND @LeaveTakenToDate)    ORDER BY [TaxYear] ASC, [HolidayDate] ASC  END     

GO

