/*  =============================================  Create date: 07/Oct/2016  Name: Jaydev Jangid  Description:  GET 16 Recon report list  Call SP:  Payroll_GetReconList_SP  =============================================*/  create PROCEDURE [dbo].[Payroll_GetReconList_sp]  AS      BEGIN              SELECT TOP 8 ReconEmpSummaryRptName , TaxYear , ROW_NUMBER() OVER ( ORDER BY EmployeeTaxCertificate_ID ) AS ROWID          FROM    dbo.Payroll_EmployeeTaxCertificate WHERE   IsRecon = 1            UNION ALL              SELECT TOP 8 ReconTaxCodeSummaryName , TaxYear ,ROW_NUMBER() OVER ( ORDER BY EmployeeTaxCertificate_ID ) AS ROWID          FROM    dbo.Payroll_EmployeeTaxCertificate WHERE   IsRecon = 1          ORDER BY ROWID ,ReconEmpSummaryRptName ,TaxYear DESC;        END;  

