-- ============================================
-- SP: Payroll_GetSalaryHeadDetailsByID_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Mehul Panchal  -- Create date:  02/11/2013  -- Description: <Description,,>   -- cALLS : Payroll_GetSalaryHeadDetailsByID_sp '22'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetSalaryHeadDetailsByID_sp]   @IRP5CodeID NVARCHAR(50)  AS  BEGIN      SELECT     SH.SalaryHead_ID,     IRP5.IRP5Code AS IRP5CodeId,    SH.SalaryHeadTitle AS PayrollSalaryHeadName,     IRP5.IRP5Code + ' - ' + IRP5.IRP5CodeDesc AS DESCRIPTION,    IRP5.Rules,    IRP5.Formula,    CSS.ScoaCode + ' - ' + CSS.ScoaShortDesc AS ACTIVITYCODE,    Tax.TaxabilityDesc AS SalaryHeadTaxable,     CASE WHEN IRP5.TatxablePercentage IS NULL      THEN       0      ELSE       IRP5.TatxablePercentage     END AS TaxablePercentage,    TT.TransactionTypeDesc,    CF.CalculationFlag, --SH.CalculationFlag,     IRP5.TransactionTypeID,    IRP5.TaxableID   FROM PAYROLL_SALARYHEAD SH    INNER JOIN dbo.Payroll_GLItems GL on GL.SalaryHeadID = SH.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code IRP5 ON IRP5.IRP5Code_ID = SH.IRP5CodeId    INNER JOIN dbo.Const_TransactionType TT ON TT.TransactionType_ID = IRP5.TransactionTypeID    INNER JOIN dbo.Const_Taxability Tax ON Tax.Taxability_ID = IRP5.TaxableID    INNER JOIN Const_SCOA_Structure CSS ON CSS.ScoaID = GL.ScoaItemIDPermanentStaff    INNER JOIN dbo.Const_CalculationFlag_sys CF ON CF.CalculationFlag_ID= SH.CalculationFlag       WHERE CONVERT(NVARCHAR,IRP5.IRP5Code_ID) = @IRP5CodeID   ORDER BY IRP5.IRP5Code, IRP5.IRP5CodeDesc  END    

GO

-- ============================================
-- SP: Payroll_GetSalaryHeadDetailsByPHID_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: Mehul Panchal    -- Create date:  02/11/2013    -- Description: <Description,,>     -- cALLS : [Payroll_GetSalaryHeadDetailsByPHID_sp] '536'    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetSalaryHeadDetailsByPHID_sp] @PayrollSalaryHeadID NVARCHAR(50)  AS    BEGIN       SELECT       SH.SalaryHead_ID,       IRP5.IRP5Code AS IRP5CodeId,      SH.SalaryHeadName AS SalaryHeadName,       cast(isnull(IRP5.IRP5Code, 0) as nvarchar) + ' - ' + isnull(IRP5.IRP5CodeDesc, '') AS DESCRIPTION,      IRP5.Rules,      IRP5.Formula,      Isnull(CSS.ScoaCode + ' - ' + CSS.ScoaShortDesc,'') AS ACTIVITYCODE,      Tax.TaxabilityDesc AS SalaryHeadTaxable,       CASE WHEN IRP5.TatxablePercentage IS NULL THEN 0 ELSE IRP5.TatxablePercentage END AS TaxablePercentage,      TT.TransactionTypeDesc,         CF.CalculationFlag, --SH.CalculationFlag,       IRP5.TransactionTypeID,      IRP5.TaxableID AS Taxable,      SH.IsRFI,      Isnull(GL.ScoaItemIDPermanentStaff,0)  AS ActivityID     FROM PAYROLL_SALARYHEAD SH      INNER JOIN dbo.Payroll_GLItems GL ON GL.SalaryHeadID = SH.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code IRP5 ON IRP5.IRP5Code_ID = SH.IRP5CodeId      INNER JOIN dbo.Const_TransactionType TT ON TT.TransactionType_ID = IRP5.TransactionTypeID      INNER JOIN dbo.Const_Taxability Tax ON Tax.Taxability_ID = IRP5.TaxableID      left JOIN Const_SCOA_Structure CSS ON CSS.ScoaID = Isnull(GL.ScoaItemIDPermanentStaff,0)      INNER JOIN dbo.Const_CalculationFlag_sys CF ON CF.CalculationFlag_ID= SH.CalculationFlag     WHERE CONVERT(NVARCHAR,SH.SalaryHead_ID) = @PayrollSalaryHeadID    END    

GO

-- ============================================
-- SP: Payroll_GetSalaryHeadList
-- Schema: dbo
-- ============================================
  -- CALLS : [Payroll_GetSalaryHeadList]  '2016/2017'  -- TP34844 2016-04-07 James Roodt: Changed mapping from Financialyear to applciable year as current salaryhead/payrolldefinition is carried over to the next year and NOT duplciated for the next year  -- TP40772 2016-07-20 James Roodt: Changed where caluse to use left joins instead ofinner joins. We cannot garuantee backend data is validated.  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 19/05/2017 - Changed the IRP5Code mapping from int to string for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetSalaryHeadList]  @FinancialYear NVARCHAR(50)  AS  BEGIN   SELECT     SH.SalaryHead_ID,     IRP5.IRP5Code AS IRP5CodeId,    SH.SalaryHeadTitle AS PayrollSalaryHeadName,     cast(IRP5.IRP5Code as nvarchar(max)) + ' - ' + IRP5.IRP5CodeDesc AS DESCRIPTION,    IRP5.Rules,    IRP5.Formula,    CSS.ScoaCode + ' - ' + CSS.ScoaShortDesc AS ACTIVITYCODE,    Tax.TaxabilityDesc AS SalaryHeadTaxable,     CASE WHEN IRP5.TatxablePercentage IS NULL THEN 0 ELSE IRP5.TatxablePercentage END AS TaxablePercentage,    TT.TransactionTypeDesc,     CF.CalculationFlag, --SH.CalculationFlag,     IRP5.TransactionTypeID,    IRP5.TaxableID AS Taxable,    CASE WHEN (SH.Enabled =1) THEN      'TRUE'      ELSE      'FALSE'      END AS STATUS,      'FALSE' AS FAVOURITES   FROM PAYROLL_SALARYHEAD SH    LEFT JOIN dbo.Payroll_GLItems GL ON GL.SalaryHeadID = SH.SalaryHead_ID    LEFT JOIN dbo.Payroll_IRP5Code IRP5 ON IRP5.IRP5Code_ID = SH.IRP5CodeId    LEFT JOIN dbo.Const_TransactionType TT ON TT.TransactionType_ID = IRP5.TransactionTypeID    LEFT JOIN dbo.Const_Taxability Tax ON Tax.Taxability_ID = IRP5.TaxableID    LEFT JOIN Const_SCOA_Structure CSS ON CSS.ScoaID = GL.ScoaItemIDPermanentStaff    LEFT JOIN dbo.Const_CalculationFlag_sys CF ON CF.CalculationFlag_ID= SH.CalculationFlag   ORDER BY IRP5.IRP5Code, IRP5.IRP5CodeDesc  END  

GO

-- ============================================
-- SP: Payroll_GetSalaryHeadTaxTotals_sp
-- Schema: dbo
-- ============================================
  -- ===============================================================================  -- Author: PHUTI CHOKOE  -- Create date: 01/11/2016  -- Description: GET SALARY HEAD TOTALS  -- calls : [Payroll_GetSalaryHeadTaxTotals_sp] '2016/2017', 1  -- 2016-08-23 TP43523 Phuti chokoe   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 2017/12/08 - changed SP to read from Payroll_PayrollResutls instead of TrialResults and EmployeePaysi  -- Update date : 2019/07/11 - change current and tax columns calculate method - Lukasz Rakowski  -- =============================================  CREATE procedure [dbo].[Payroll_GetSalaryHeadTaxTotals_sp]   @TaxYear varchar(15) ,   @TransactionTypeId int   AS    declare @processed_months int;    declare @PeriodStart_Id INT    declare @PeriodEnd_Id INT  declare @CurrentPeriod_Id INT    SET @processed_months = (SELECT    COUNT(*)   FROM Payroll_CyclePeriodDetails   WHERE CycleModeID = 1   AND TaxYear = @TaxYear   AND Processed = 1);    SELECT   @PeriodStart_Id = MIN(Period_ID)     ,@PeriodEnd_Id = MAX(Period_ID)  FROM Payroll_CyclePeriodDetails  WHERE CycleModeID = 1  AND TaxYear = @TaxYear  AND Processed = 1    SELECT   @CurrentPeriod_Id = MAX(Period_ID)  FROM Payroll_CyclePeriodDetails  WHERE CycleModeID = 1  AND TaxYear = @TaxYear  AND Processed = 1  AND GETDATE() BETWEEN PeriodStartDate AND PeriodEndDate    SELECT   CAST(ps.IRP5Code as int) as IRP5Code     ,HEAD.SalaryHeadName     , ISNULL((SELECT TOP 1 subps.Amount   FROM Payroll_PayrollResults subps  INNER JOIN dbo.Payroll_SalaryHead AS subHEAD   ON subHEAD.SalaryHead_ID = subps.SalaryHeadId  INNER JOIN dbo.Payroll_IRP5Code AS subIRP5   ON subps.IRP5CodeId = subIRP5.IRP5Code_ID  INNER JOIN Const_TransactionType AS subtt   ON subtt.TransactionType_ID = subIRP5.TransactionTypeID  WHERE  subps.PeriodID >= @CurrentPeriod_Id  AND subtt.TransactionType_ID = 1  AND subHEAD.SalaryHead_ID = HEAD.SalaryHead_ID  AND subHEAD.SalaryHeadName = HEAD.SalaryHeadName  AND subIRP5.IRP5Code = ps.IRP5Code     ), 0.00)      AS Amount     ,SUM(ps.Amount) AS Tax  FROM Payroll_PayrollResults ps  INNER JOIN dbo.Payroll_SalaryHead AS HEAD   ON HEAD.SalaryHead_ID = ps.SalaryHeadId  INNER JOIN dbo.Payroll_IRP5Code AS IRP5   ON ps.IRP5CodeId = IRP5.IRP5Code_ID  INNER JOIN Const_TransactionType AS tt   ON tt.TransactionType_ID = IRP5.TransactionTypeID  WHERE  ps.PeriodID >= @PeriodStart_Id  AND ps.PeriodID <= @PeriodEnd_Id  AND tt.TransactionType_ID = @TransactionTypeId  GROUP BY SalaryHead_ID    ,HEAD.SalaryHeadName    ,ps.IRP5Code  ORDER BY ps.IRP5Code ASC

GO

-- ============================================
-- SP: Payroll_GetSalaryTransactionGroups_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 10/07/2017   Description : Gets the list of Salary Transaction Groups  */  create procedure [Payroll_GetSalaryTransactionGroups_sp] @StartDate datetime = '1900-01-01', @EndDate datetime = '9999-12-31', @GroupID int = null, @TransactionTypeID int = null, @SalaryHeadID int = null, @Enabled bit = null  as    begin     set nocount on;     select [PayrollDefination_ID], [PayrollDefinitionGroup_ID] as [SalaryGroup_ID], [PayrollDefinitionGroupName] as [SalaryGroup], [SalaryHead_ID], [TransactionTypeDesc], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) + ' - ' + isnull([IRP5CodeDesc], '') as [IRP5CodeTitle], [SalaryHeadTitle], [TaxabilityDesc], [TatxablePercentage], [CF].[CalculationFlag], [SH].[StartDate], [SH].[EndDate], [SH].[Enabled]      from [Payroll_DefinitionGroup] as [PDG] with(nolock)       join [Payroll_PayrollDefination] as [PPD] with(nolock) on [PayrollDefinitionGroupID] = [PayrollDefinitionGroup_ID] and [PPD].[Enabled] = [PDG].[Enabled]       join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PPD].[PayrollSalaryHeadID] and [SH].[Enabled] = [PDG].[Enabled]       join [Payroll_GLItems] as [GL] with(nolock) on [SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = [PDG].[Enabled]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = [PDG].[Enabled]       join [Const_Taxability] as [CT] with(nolock) on [Taxability_ID] = [TaxableID]       join [Const_TransactionType] as [TT] with(nolock) on [TransactionType_ID] = [TransactionTypeID]       join [Const_CalculationFlag_sys] as [CF] with(nolock) on [CalculationFlag_ID] = [SH].[CalculationFlag]      where ([PDG].[Enabled] = (case when @Enabled is null then [PDG].[Enabled] else @Enabled end) and [PayrollDefinitionGroup_ID] = (case when @GroupID is null or @GroupID = 0 then [PayrollDefinitionGroup_ID] else @GroupID end) and [TransactionTypeID] = (case when @TransactionTypeID is null or @TransactionTypeID = 0 then [TransactionTypeID] else @TransactionTypeID end) and [SalaryHead_ID] = (case when @SalaryHeadID is null or @SalaryHeadID = 0 then [SalaryHead_ID] else @SalaryHeadID end) and [SH].[StartDate] <= (case when @EndDate is null then '9999-12-31' else @EndDate end) and [SH].[EndDate] >= (case when @StartDate is null then '1900-01-01' else @StartDate end))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetSalaryTransactionHistory_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 05/06/2017   Description : Gets the Salary Transaction History  */  create procedure [Payroll_GetSalaryTransactionHistory_sp] @SalaryHeadID int, @Enabled bit = null  as    begin     set nocount on;     select [SalaryHeadHistory_ID], [SalaryHeadID], [SalaryHeadName], [SalaryHeadTitle], [CF].[CalculationFlag], [IsRFI], [IsProRata], [StartDate], [EndDate], [SH].[Enabled]      from [Payroll_SalaryHeadHistory] as [SH] with(nolock)       join [Const_CalculationFlag_sys] as [CF] with(nolock) on [CalculationFlag_ID] = [SH].[CalculationFlag]      where ([SalaryHeadID] = @SalaryHeadID and [SH].[Enabled] = (case when @Enabled is null then [SH].[Enabled] else @Enabled end))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetSalaryTransactions_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 02/06/2017   Description : Gets the list of Salary Transactions     Lukasz Rakowski   TP: 87864   Search Grid of Salary Transaction to be updated  */  CREATE procedure [dbo].[Payroll_GetSalaryTransactions_sp] @StartDate datetime = '1900-01-01', @EndDate datetime = '9999-12-31', @TransactionTypeID int = null, @Enabled bit = null, @IRP5CodeID int = null, @Description nvarchar(max) = ''  as    begin     set nocount on;     select [SalaryHead_ID], [TransactionTypeDesc], replicate('0', 4 - len(cast(isnull([IRP5Code], 0) as nvarchar))) + cast(isnull([IRP5Code], 0) as nvarchar) + ' - ' + isnull([IRP5CodeDesc], '') as [IRP5CodeTitle], [SalaryHeadTitle], [TaxabilityDesc], [TatxablePercentage], [CF].[CalculationFlag], [SH].[StartDate], [SH].[EndDate], [SH].[Enabled], [CSS].[ScoaDesc] + ': ' + [CSS].[ScoaCode] as [ExpenditureItem]      from [Payroll_SalaryHead] as [SH] with(nolock)       left outer join [Payroll_GLItems] as [GL] with(nolock) on [SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = [SH].[Enabled]       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = [SH].[Enabled]       join [Const_Taxability] as [CT] with(nolock) on [Taxability_ID] = [TaxableID]       join [Const_TransactionType] as [TT] with(nolock) on [TransactionType_ID] = [TransactionTypeID]       join [Const_CalculationFlag_sys] as [CF] with(nolock) on [CalculationFlag_ID] = [SH].[CalculationFlag]       left outer join [Const_SCOA_Structure] as [CSS] with(nolock) on [GL].[ScoaItemIDPermanentStaff] = [CSS].[ScoaID]      where ([SH].[Enabled] = (case when @Enabled is null then [SH].[Enabled] else @Enabled end) and [TransactionTypeID] = (case when @TransactionTypeID is null or @TransactionTypeID = 0 then [TransactionTypeID] else @TransactionTypeID end) and [IRP5Code_ID] = (case when @IRP5CodeID is null or @IRP5CodeID = 0 then [IRP5Code_ID] else @IRP5CodeID end) and [SH].[StartDate] <= (case when @EndDate is null then '9999-12-31' else @EndDate end) and [SH].[EndDate] >= (case when @StartDate is null then '1900-01-01' else @StartDate end) and       [SalaryHeadTitle] like case        when @Description is null or @Description = '' then [SalaryHeadTitle]        else '%' + @Description + '%'       end      )     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetSchedulerLastDateTriggered_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 28 June 2016  -- Description: Update [AAAA_ConfigSettings]  -- Exec [Payroll_SchedulerLastDateTriggered_sp]  -- 2016-06-28 TP38894 Seipei Mathole  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_GetSchedulerLastDateTriggered_sp]    AS    BEGIN   DECLARE @ConfigSett_ID INT = (SELECT ConfigSett_ID FROM dbo.AAAA_ConfigSettings  WHERE KeyName = 'SchedulerLastDateTriggered')      SELECT KeyValue FROM AAAA_ConfigSettings      WHERE ConfigSett_ID = @ConfigSett_ID    END  

