-- ============================================
-- SP: Payroll_GetScoaCodeByDivision_sp
-- Schema: dbo
-- ============================================
-- =============================================                -- Author:  Seipei Mathole               -- Create date: 25 August 2016                -- Description: Returns SCOA Function and Funds      -- Call [Payroll_GetScoaCodeByDivision_sp] 1         -- =============================================      CREATE PROCEDURE [dbo].[Payroll_GetScoaCodeByDivision_sp]    @DivisionID INT    AS     BEGIN               SELECT scoaFunction.ScoaCode, scoaFund.ScoaCode     FROM Const_Division CD     INNER JOIN Const_SCOA_Function_Structure scoaFunction ON CD.SCOAFunctionID = scoaFunction.ScoaID     INNER JOIN Const_SCOA_Funds_Structure scoaFund ON CD.SCOAFunctionID = scoaFund.ScoaID   WHERE CD.Division_ID = @DivisionID      AND scoaFunction.Enabled = 1      AND CD.Enabled = 1    END  

GO

-- ============================================
-- SP: Payroll_GetSCOAFunctionIDByDescription
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  James Roodt  -- Create date: 2015-05-26  -- Description: Retunrs the SCOA Function code ID closest macthing the provided Description. If none are found returns -1  -- EXEC Payroll_GetSCOAFunctionIDByDescription 'Housing:  Core Function'  results in -1 (not found)  -- exec Payroll_GetSCOAFunctionIDByDescription 'Community and Social Services:  Core Function - Aged Care, Home Assistance and Transport Facilities'  -- resultsd in 47  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetSCOAFunctionIDByDescription]    -- Add the parameters for the stored procedure here   @Description nvarchar(200) = 0     AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;       Declare @IDFound int   set @IDFound=-1        set @Description = REPLACE(@description, ':',' ')  set @Description = REPLACE(@description, '-',' ')  set @Description = REPLACE(@description, '  ',' ') --multiple times times to cater for 3 or more spaces next to each other  set @Description = REPLACE(@description, '  ',' ')  set @Description = REPLACE(@description, '  ',' ')  print @Description     DECLARE @Functions TABLE              (                [Id] INT ,                [RowNo] INT,       ScoaShortDesc NVARCHAR(200),       ScoaDesc NVARCHAR(200)              )       INSERT INTO @Functions  SELECT  ScoaID, ROW_NUMBER() OVER ( ORDER BY ScoaID ASC ), ScoaShortDesc, ScoaDesc  FROM Const_SCOA_Function_Structure  WHERE PostingLevel='Yes' AND Enabled=1    DECLARE @Start INT,  @TotalCount INT,  @ID INT,  @ScoaShortDesc NVARCHAR(200),  @ScoaDesc NVARCHAR(200)    SET @Start = 1          SELECT  @TotalCount = COUNT(1)          FROM    @Functions                 WHILE ( @Start <= @TotalCount )               BEGIN        SELECT @ID=id, @ScoaShortDesc=ScoaShortDesc, @ScoaDesc=ScoaDesc FROM @Functions      WHERE RowNo=@Start        set @ScoaShortDesc = REPLACE(@ScoaShortDesc, ':',' ')      set @ScoaShortDesc = REPLACE(@ScoaShortDesc, '-',' ')      set @ScoaShortDesc = REPLACE(@ScoaShortDesc, '  ',' ') --multiple times times to cater for 3 or more spaces next to each other      set @ScoaShortDesc = REPLACE(@ScoaShortDesc, '  ',' ')      set @ScoaShortDesc = REPLACE(@ScoaShortDesc, '  ',' ')      --print @ScoaShortDesc        set @ScoaDesc = REPLACE(@ScoaDesc, 'core function:','{placeholder}')  --Try to remove leading 'core function:' but first temporarily rename valid core function in the middle of the names.      set @ScoaDesc = REPLACE(@ScoaDesc, 'function:','')        set @ScoaDesc = REPLACE(@ScoaDesc, '{placeholder}','Core Function:')      set @ScoaDesc = REPLACE(@ScoaDesc, ':',' ')      set @ScoaDesc = REPLACE(@ScoaDesc, '-',' ')      set @ScoaDesc = REPLACE(@ScoaDesc, '  ',' ') --multiple times times to cater for 3 or more spaces next to each other      set @ScoaDesc = REPLACE(@ScoaDesc, '  ',' ')      set @ScoaDesc = REPLACE(@ScoaDesc, '  ',' ')      --print @ScoaDesc        if(@Description=@ScoaShortDesc)      begin       SET @IDFound=@id       SET @Start = @TotalCount + 1         print 'Match Found'       print @id       print @Description      end      if(@Description=@ScoaDesc)      begin       SET @IDFound=@id       SET @Start = @TotalCount + 1         print 'Match Found'       print @id       print @Description      end               SET @Start = @Start + 1                END           SELECT @IDFound  END  

GO

-- ============================================
-- SP: Payroll_GetSCOAFunctionLinkedtoDivision_sp
-- Schema: dbo
-- ============================================
  -- =================================================================================================            -- Author:Varun Parvataneni        -- Create date: 13/06/2016          -- Description: Returns Scoa Functions Linked to the Division          -- TP: 37912:To show scoa functions on Function code dropdown   -- Call:Exec [Payroll_GetSCOAFunctionLinkedtoDivision_sp]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetSCOAFunctionLinkedtoDivision_sp]      AS     BEGIN    Select Distinct   SCOAFunctionID,  CS_FS.ScoaCode+'-'+CS_FS.ScoaShortDesc as ScoaCode  from Const_Division as C_D  inner join Const_SCOA_Function_Structure as CS_FS on C_D.SCOAFunctionID=CS_FS.ScoaID    END  

GO

-- ============================================
-- SP: Payroll_GetSCOAFunctionTree
-- Schema: dbo
-- ============================================
  create procedure [dbo].[Payroll_GetSCOAFunctionTree] @scoaId int = null, @scoaItem nvarchar(600) = null, @levelId int = null, @levelCount int = null, @excludeScoaId bit = 0, @excludePostingLevel bit = 0  as    begin     set nocount on;     with [SCOATree] as (      select 0 as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaDesc], [ScoaShortDesc], [ScoaParentID], [PostingLevel]       from [Const_SCOA_Function_Structure] with(nolock)       where ([Enabled] = 1 and [PostingLevel] = (case when @excludePostingLevel = 1 then 'No' else [PostingLevel] end) and        (case         when @scoaId is null and @scoaItem is null then 1         when not @scoaId is null and @scoaItem is null and [ScoaID] = @scoaId then 1         when @scoaId is null and not @scoaItem is null and [ScoaDesc] = @scoaItem then 1         when not @scoaId is null and not @scoaItem is null and [ScoaID] = @scoaId and [ScoaDesc] = @scoaItem then 1         else 0 end) = 1 and        (case         when @levelId is null and @levelCount is null then (case          when [ScoaParentID] is null then 1          when not [ScoaParentID] is null and ((not @scoaId is null and [ScoaID] = @scoaId) or (not @scoaItem is null and [ScoaDesc] = @scoaItem)) then 1          else 0 end)         when not @levelId is null and [LevelID] = @levelId then 1         when @levelId is null and not @levelCount is null then (case          when [ScoaParentID] is null then 1          when not [ScoaParentID] is null and ((not @scoaId is null and [ScoaID] = @scoaId) or (not @scoaItem is null and [ScoaDesc] = @scoaItem)) and [LevelID] < ([LevelID] + @levelCount) then 1          else 0 end)         else 0 end) = 1            )      union all      select [ST].[Index] + 1, [CS].[ScoaID], [CS].[LevelID], [CS].[ScoaCode], [CS].[ScoaDesc], [CS].[ScoaShortDesc], [CS].[ScoaParentID], [CS].[PostingLevel]       from [Const_SCOA_Function_Structure] as [CS] with(nolock)        join [SCOATree] as [ST] on [ST].[ScoaID] = [CS].[ScoaParentID]       where ([CS].[Enabled] = 1 and not [CS].[ScoaParentID] is null and [CS].[PostingLevel] = (case when @excludePostingLevel = 1 then 'No' else [CS].[PostingLevel] end) and        (case         when @levelId is null and @levelCount is null then 1         when @levelId is null and not @levelCount is null and ([ST].[Index] + 1) < @levelCount then 1         when not @levelId is null and not @levelCount is null and [CS].[LevelID] >= @levelId and [CS].[LevelID] < (@levelID + @levelCount) then 1         else 0 end) = 1       )     )     select (dense_rank() over (order by [LevelID]) - 1) as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaDesc], [ScoaShortDesc], [ScoaParentID], [PostingLevel]      from [SCOATree]      where (       (case        when isnull(@excludeScoaId, 0) = 1 and ([Index] > 0 or ([Index] = 0 and isnull(@excludePostingLevel, 0) = 0 and [PostingLevel] = 'Yes')) then 1        when isnull(@excludeScoaId, 0) = 0 then 1       else 0 end) = 1      )      order by [LevelID], [ScoaID], [ScoaCode], [ScoaDesc]       option (maxrecursion 99);     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetSCOAFunding_sp
-- Schema: dbo
-- ============================================
  -- =================================================================================================            -- Author:  Seipei Mathole        -- Create date: 30/05/2016          -- Description: Returns Scoa Funds per municipality,         -- TP: 37378  -- Exec [Payroll_GetSCOAFunding_sp]  -- =================================================================================================         CREATE PROCEDURE [dbo].[Payroll_GetSCOAFunding_sp]      AS     BEGIN    SELECT ppf.ScoaFundID, sf.ScoaShortDesc+ ' ' + sf.ScoaCode As ScoaCode FROM Const_Division AS pm         INNER JOIN Plan_Project AS pp ON pp.Project_ID=pm.ProjectID         INNER JOIN Plan_ProjectFund AS ppf ON ppf.ProjectID=pp.Project_ID         INNER JOIN Const_SCOA_Funds_Structure as sf ON sf.ScoaID=ppf.ScoaFundID      WHERE pm.ProjectID is not null    END  

GO

