  create procedure [Payroll_GetSCOATree] @scoaId int = null, @scoaItem nvarchar(600) = null, @levelId int = null, @levelCount int = null, @excludeScoaId bit = 0, @excludePostingLevel bit = 0  as    begin     set nocount on;     with [SCOATree] as (      select 0 as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaDesc], [ScoaShortDesc], [ScoaParentID], [PostingLevel]       from [Const_SCOA_Structure] with(nolock)       where ([Enabled] = 1 and [PostingLevel] = (case when @excludePostingLevel = 1 then 'No' else [PostingLevel] end) and        (case         when @scoaId is null and @scoaItem is null then 1         when not @scoaId is null and @scoaItem is null and [ScoaID] = @scoaId then 1         when @scoaId is null and not @scoaItem is null and [ScoaDesc] = @scoaItem then 1         when not @scoaId is null and not @scoaItem is null and [ScoaID] = @scoaId and [ScoaDesc] = @scoaItem then 1         else 0 end) = 1 and        (case         when @levelId is null and @levelCount is null then (case          when [ScoaParentID] is null then 1          when not [ScoaParentID] is null and ((not @scoaId is null and [ScoaID] = @scoaId) or (not @scoaItem is null and [ScoaDesc] = @scoaItem)) then 1          else 0 end)         when not @levelId is null and [LevelID] = @levelId then 1         when @levelId is null and not @levelCount is null then (case          when [ScoaParentID] is null then 1          when not [ScoaParentID] is null and ((not @scoaId is null and [ScoaID] = @scoaId) or (not @scoaItem is null and [ScoaDesc] = @scoaItem)) and [LevelID] < ([LevelID] + @levelCount) then 1          else 0 end)         else 0 end) = 1            )      union all      select [ST].[Index] + 1, [CS].[ScoaID], [CS].[LevelID], [CS].[ScoaCode], [CS].[ScoaDesc], [CS].[ScoaShortDesc], [CS].[ScoaParentID], [CS].[PostingLevel]       from [Const_SCOA_Structure] as [CS] with(nolock)        join [SCOATree] as [ST] on [ST].[ScoaID] = [CS].[ScoaParentID]       where ([CS].[Enabled] = 1 and not [CS].[ScoaParentID] is null and [CS].[PostingLevel] = (case when @excludePostingLevel = 1 then 'No' else [CS].[PostingLevel] end) and        (case         when @levelId is null and @levelCount is null then 1         when @levelId is null and not @levelCount is null and ([ST].[Index] + 1) < @levelCount then 1         when not @levelId is null and not @levelCount is null and [CS].[LevelID] >= @levelId and [CS].[LevelID] < (@levelID + @levelCount) then 1         else 0 end) = 1       )     )     select (dense_rank() over (order by [LevelID]) - 1) as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaDesc], [ScoaShortDesc], [ScoaParentID], [PostingLevel]      from [SCOATree]      where (       (case        when isnull(@excludeScoaId, 0) = 1 and ([Index] > 0 or ([Index] = 0 and isnull(@excludePostingLevel, 0) = 0 and [PostingLevel] = 'Yes')) then 1        when isnull(@excludeScoaId, 0) = 0 then 1       else 0 end) = 1      )      order by [LevelID], [ScoaID], [ScoaCode], [ScoaDesc]       option (maxrecursion 99);     set nocount off;    end  

GO

