-- SP: Payroll_GetSCOATrees
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetSCOATrees] @scoaId [_intArray] readonly, @scoaItem [_stringArray] readonly, @levelId [_intArray] readonly, @levelCount [_intArray] readonly, @excludeScoaId [_boolArray] readonly, @excludePostingLevel [_boolArray] readonly  as    begin     set nocount on;     declare @i int = 1,     @c int = 0,     @scoaIdValue int = null,     @scoaIdT [_intTable],     @scoaItemValue nvarchar(max) = null,     @scoaItemT [_stringTable],     @levelIdValue int = null,     @levelIdT [_intTable],     @levelCountValue int = null,     @levelCountT [_intTable],     @excludeScoaIdValue bit = 0,     @excludeScoaIdT [_boolTable],     @excludePostingLevelValue bit = 0,     @excludePostingLevelT [_boolTable]     declare @SCOATrees table (      [RootID] int not null,    [Index] int not null,    [ScoaID] int not null,    [LevelID] int null,    [ScoaCode] nvarchar(50) null,    [ScoaShortDesc] nvarchar(200) null,    [ScoaDesc] nvarchar(600) null,    [ScoaParentID] int null,    [PostingLevel] nvarchar(3) null     )     if ((select count([v]) from @scoaId) > @c)      select @c = count([v]) from @scoaId     if ((select count([v]) from @scoaItem) > @c)      select @c = count([v]) from @scoaItem     if ((select count([v]) from @levelId) > @c)      select @c = count([v]) from @levelId     if ((select count([v]) from @levelCount) > @c)      select @c = count([v]) from @levelCount     if ((select count([v]) from @excludeScoaId) > @c)      select @c = count([v]) from @excludeScoaId     if ((select count([v]) from @excludePostingLevel) > @c)      select @c = count([v]) from @excludePostingLevel     insert into @scoaIdT([v])      select [v] from @scoaId     insert into @scoaItemT([v])      select [v] from @scoaItem     insert into @levelIdT([v])      select [v] from @levelId     insert into @levelCountT([v])      select [v] from @levelCount     insert into @excludeScoaIdT([v])      select [v] from @excludeScoaId     insert into @excludePostingLevelT([v])      select [v] from @excludePostingLevel     while (@i <= @c)   begin      select @scoaIdValue = [v] from @scoaIdT where ([i] = @i)      select @scoaItemValue = [v] from @scoaItemT where ([i] = @i)      select @levelIdValue = [v] from @levelIdT where ([i] = @i)      select @levelCountValue = [v] from @levelCountT where ([i] = @i)      select @excludeScoaIdValue = isnull([v], 0) from @excludeScoaIdT where ([i] = @i)      select @excludePostingLevelValue = isnull([v], 0) from @excludePostingLevelT where ([i] = @i);      with [SCOATree] as (       select isnull(@scoaIdValue, @i) as [RootID], 0 as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaDesc], [ScoaShortDesc], [ScoaParentID], [PostingLevel]        from [Const_SCOA_Structure] with(nolock)        where ([Enabled] = 1 and [PostingLevel] = (case when @excludePostingLevelValue = 1 then 'No' else [PostingLevel] end) and         (case          when @scoaIdValue is null and @scoaItemValue is null then 1          when not @scoaIdValue is null and @scoaItemValue is null and [ScoaID] = @scoaIdValue then 1          when @scoaIdValue is null and not @scoaItemValue is null and [ScoaDesc] = @scoaItemValue then 1          when not @scoaIdValue is null and not @scoaItemValue is null and [ScoaID] = @scoaIdValue and [ScoaDesc] = @scoaItemValue then 1          else 0 end) = 1 and         (case          when @levelIdValue is null and @levelCountValue is null then (case           when [ScoaParentID] is null then 1           when not [ScoaParentID] is null and ((not @scoaIdValue is null and [ScoaID] = @scoaIdValue) or (not @scoaItemValue is null and [ScoaDesc] = @scoaItemValue)) then 1           else 0 end)          when not @levelIdValue is null and [LevelID] = @levelIdValue then 1          when @levelIdValue is null and not @levelCountValue is null then (case           when [ScoaParentID] is null then 1           when not [ScoaParentID] is null and ((not @scoaIdValue is null and [ScoaID] = @scoaIdValue) or (not @scoaItemValue is null and [ScoaDesc] = @scoaItemValue)) and [LevelID] < ([LevelID] + @levelCountValue) then 1           else 0 end)          else 0 end) = 1        )       union all       select isnull(@scoaIdValue, @i), [ST].[Index] + 1, [CS].[ScoaID], [CS].[LevelID], [CS].[ScoaCode], [CS].[ScoaDesc], [CS].[ScoaShortDesc], [CS].[ScoaParentID], [CS].[PostingLevel]        from [Const_SCOA_Structure] as [CS] with(nolock)         join [SCOATree] as [ST] on [ST].[ScoaID] = [CS].[ScoaParentID]        where ([CS].[Enabled] = 1 and not [CS].[ScoaParentID] is null and [CS].[PostingLevel] = (case when @excludePostingLevelValue = 1 then 'No' else [CS].[PostingLevel] end) and         (case          when @levelIdValue is null and @levelCountValue is null then 1          when @levelIdValue is null and not @levelCountValue is null and ([ST].[Index] + 1) < @levelCountValue then 1          when not @levelIdValue is null and not @levelCountValue is null and [CS].[LevelID] >= @levelIdValue and [CS].[LevelID] < (@levelIdValue + @levelCountValue) then 1          else 0 end) = 1        )      )      insert into @SCOATrees([RootID], [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaShortDesc], [ScoaDesc], [ScoaParentID], [PostingLevel])       select [RootID], (dense_rank() over (order by [LevelID]) - 1) as [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaShortDesc], [ScoaDesc], [ScoaParentID], [PostingLevel]        from [SCOATree]        where (         (case          when isnull(@excludeScoaIdValue, 0) = 1 and ([Index] > 0 or ([Index] = 0 and isnull(@excludePostingLevelValue, 0) = 0 and [PostingLevel] = 'Yes')) then 1          when isnull(@excludeScoaIdValue, 0) = 0 then 1         else 0 end) = 1        )        order by [RootID], [LevelID], [ScoaID], [ScoaCode], [ScoaDesc]         option (maxrecursion 99);      set @i = @i + 1     end     select [RootID], [Index], [ScoaID], [LevelID], [ScoaCode], [ScoaShortDesc], [ScoaDesc], [ScoaParentID], [PostingLevel]      from @SCOATrees       order by [LevelID], [ScoaID], [ScoaCode], [ScoaDesc]     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_GetSuccessfulCandidateList_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,06/09/2018>  -- Description: <Description,,Get Data for Successful Candidate list>  -- =============================================  CREATE PROCEDURE Payroll_GetSuccessfulCandidateList_sp    @AdvertId INT  AS  BEGIN   SET NOCOUNT ON;        SELECT DISTINCT PISE.EmployeeInterviewID, ProspectiveEmployee_ID, (ISNULL(PPE.FirstName,'')+ ' '+ ISNULL(ppe.SecondName,'')+ ' ' + ISNULL(ppe.Surname,'')) AS CandidateName,    InterviewDate,    cd.DepartmentDesc, cdd.DivisionDesc, pp.PositionDesc    FROM Payroll_CandidateShortListPage AS CS    INNER JOIN Payroll_EmployeeShortListPage AS PE ON PE.CandidateShortListId = CS.CandidateShortListID    INNER JOIN dbo.Payroll_ProspectiveEmployee AS PPE ON PPE.ProspectiveEmployee_ID = PE.ProspectiveEmployeeId    LEFT JOIN payroll_InterviewSchedule AS PIS ON PIS.AdvertId = CS.AdvertId    LEFT JOIN dbo.Payroll_InterviewScheduledEmployee AS PISE ON  PISE.InterviewScheduleId = PIS.InterviewScheduleID    LEFT JOIN dbo.Payroll_Advert AS PA ON pa.AdvertId = cs.AdvertId    LEFT OUTER JOIN dbo.Const_Department AS CD ON cd.Department_ID = pa.DepartmentId    LEFT OUTER JOIN dbo.Const_Division AS CDD ON cdd.Division_ID = pa.DivisionId    LEFT OUTER JOIN dbo.Payroll_Position AS PP ON pp.Position_ID = pa.PositionId    WHERE CS.AdvertId = @AdvertId AND PISE.IsSuccessFul = 1  END    

GO

-- ============================================
-- SP: Payroll_GetSumOfPayrollDefinition_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:MEHUL PANCHAL   -- Create date: 20/11/2013  -- Description: <Description,,>  -- cALLS : Payroll_GEtSumofPayrollDefinition_sp 'Basic Salary', 1, 5  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetSumOfPayrollDefinition_sp]   @SalaryHead NVARCHAR(50),   @TransTypeID INT,   @PayrollDefinationGroupID INT  AS  BEGIN    SELECT SUM(Percentage) AS  Percentage      FROM Payroll_PayrollDefination AS PD    INNER JOIN dbo.Payroll_SalaryHead AS SH ON SH.SalaryHead_ID = PD.PayrollSalaryHeadID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = SH.IRP5CodeId    WHERE     PD.PayrollDefinitionGroupID = @PayrollDefinationGroupID AND IRP5Code.TransactionTypeID = @TransTypeID     AND SH.SalaryHeadName = @SalaryHead  END  

GO

-- ============================================
-- SP: Payroll_GetTableDependencies
-- Schema: dbo
-- ============================================
    /*   =============================================         Created by : Lungisani Khumalo   Date     : 26/02/2018   Description: Gets the table dependencies  =============================================        */    CREATE procedure [dbo].[Payroll_GetTableDependencies]   @TableName nvarchar (100)             as        begin          select [cp].[Name] as [ParentColumnName], object_name([fkc].[referenced_object_id]) as [ParentTableName], [cc].[name] as [ChildColumnName], object_name([st].[object_id]) ,[fk].[name] as[FkName]      from   [sys].[foreign_key_columns] [fkc]      join [sys].[columns] [cc] on [cc].[column_id] = [fkc].[parent_column_id] and [cc].[object_id] = [fkc].[parent_object_id]      join [sys].[columns] [cp] on [cp].[column_id] = [fkc].[referenced_column_id] and [cp].[object_id] = [fkc].[referenced_object_id]      join [sys].[foreign_keys] [fk] on [fkc].[constraint_object_id] = [fk].[object_id]      join [sys].[tables] [st] on [st].[object_id] = [cc].[object_id]     where  [fkc].parent_object_id = object_id(@TableName)     end  

GO

-- ============================================
-- SP: Payroll_GetTaskGradeNotches_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 15/08/2018   Description : Get the Task Grade and Notches  */  create procedure [Payroll_GetTaskGradeNotches_sp] @TaskGradeId int = null, @Notch int = null, @MinSalary numeric(18,2) = null, @MaxSalary numeric(18,2) = null, @TaskSkillId int = null  as  begin      select isnull([NotchCount], 0) as [Notch], isnull([MinimumSalary], 0) as [NotchMinSalary], isnull([MaximumSalary], 0) as [NotchMaxSalary], isnull([T].[MinSalary], 0) as [TaskGradeMinSalary], isnull([T].[MaxSalary], 0) as [TaskGradeMaxSalary], [T].[IsSalgaCompliant], [T].[ToPhaseOut], [T].[TaskGradeName], [T].[TaskGrade_ID], [T].[SkillLevelId], [SL].[Description] as [TaskSkillDesc]       from [Payroll_TaskGrade] as [T] with(nolock)      join [Payroll_TaskSkillLevel] as [SL] with(nolock) on [SL].[TaskSkillLevel_ID] = [T].[SkillLevelId]      full outer join (       select [TaskGradeId], count([TaskGradeId]) as [NotchCount], min([MinimumSalary]) as [MinimumSalary], max([MaximumSalary]) as [MaximumSalary]        from [Payroll_Notch] with(nolock)        where ([Enabled] = 1 and [Notch_ID] = isnull(@Notch, [Notch_ID]) and [TaskGradeId] = isnull(@TaskGradeId, [TaskGradeID]) and convert(numeric(18,2), [MinimumSalary]) >= isnull(@MinSalary, [MinimumSalary]) and convert(numeric(18,2), [MaximumSalary]) <= isnull(@MaxSalary, [MaximumSalary]))         group by [TaskGradeId]      ) as [N] on [N].[TaskGradeId] = [T].[TaskGrade_Id]     where ([SL].[IsEnabled] = 1 and [T].[TaskGrade_ID] = isnull(@TaskGradeId, [T].[TaskGrade_ID]) and [T].[SkillLevelId] = isnull(@TaskSkillId, [T].[SkillLevelId]))    end  

GO

-- ============================================
-- SP: Payroll_GetTaxCodes_sp
-- Schema: dbo
-- ============================================
  -- ===============================================================================  -- Author: Richa Mills  -- Create date: 2018/05/04  -- Description: GET IRP5 Codes by TransactionTypeId  -- calls : [Payroll_GetTaxCodes_sp]  1  -- =============================================  CREATE procedure [dbo].[Payroll_GetTaxCodes_sp]   @TransactionTypeId int   AS    SELECT IRP5Code_ID,IRP5Code,IRP5CodeDesc FROM dbo.Payroll_IRP5Code  WHERE TransactionTypeID = @TransactionTypeId   AND Enabled = 1  ORDER BY IRP5Code ASC      

GO

-- ============================================
-- SP: Payroll_GetTaxTotals_sp
-- Schema: dbo
-- ============================================
-- ===============================================================================  -- AUTHOR: PHUTI CHOKOE  -- Create Date: 01/11/2016  -- Description: GET TAX TOTALS  -- calls : [Payroll_GetTaxTotals_sp] 3, 2018  -- 2016-08-23 TP43523 Phuti chokoe   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- 2017/10/17 - Richa Mills. Redo SP to cater for requirements - TP62769  -- Update Date: 15/02/2018 - Ferdi Botha changed the Annual Equivalent  -- Update Date: 08/08/2019 - Lukasz Rakowski Employee tax totals not updated after Tax Total Edit    -- =============================================  CREATE procedure [dbo].[Payroll_GetTaxTotals_sp] @EmployeeID int, @TaxYear int  as    begin     declare @PeriodID int = 0   declare @FinanceYear Varchar(20)   declare @Taxcredits float=0   declare @CurrentTaxcredits float=0     declare @SecondaryMTC float=0   declare @CurrentSecondaryMTC float=0     declare @CycleTypeID INT=0   declare @CycleId int     declare @tblTaxTotals table([IRP5Code] varchar(20),[Value] decimal(18,2),[Tax] decimal(18,2),[IsRFI] bit,[Annual] decimal(18,2))      select @CycleTypeID =CycleTypeID,@CycleId = Cycle_ID FROM Const_Cycle JOIN Payroll_Employee on Cycle_ID=CycleID where Employee_ID=@EmployeeID     select top 1 @PeriodID = [PeriodID], @FinanceYear=FinanceYear from [Payroll_PayrollResults] where ([EmployeeID] = @EmployeeID and [TaxYear] = @TaxYear) order by [PeriodID] desc     declare @payrollyear varchar(10) = (select TaxYear from Payroll_CyclePeriodDetails where Period_ID = @PeriodID)     INSERT INTO @tblTaxTotals   select     [PR].[IRP5Code] as [IRP5Code],     0,     sum([PR].[Amount]) as [Tax],     [PR].[IsRFI],     (min([PRC].[Amount]) *      (case min([CC].[CycleTypeID])      /* MONTHLY */      when 1 then 12      /* WEEKLY */      when 2 then 52      /* Bi-WEEKLY */      when 3 then 26     end)    ) as [Annual]    from [Payroll_PayrollResults] as [PR] with(nolock)       join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PR].[EmployeeID]       join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1       join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [PR].[PeriodID] and [CPD].[Enabled] = 1       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [PR].[IRP5CodeID] and [IRP5].[Enabled] = 1       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PR].[SalaryHeadID] and [SH].[Enabled] = 1       cross apply (        select [CycleID], [PeriodID], [EmployeeID], [PRI].[IRP5CodeID], sum([Amount]) as [Amount]         from [Payroll_PayrollResults] as [PRI] with(nolock)          join [Payroll_SalaryHead] as [SHI] with(nolock) on [SHI].[SalaryHead_ID] = [PRI].[SalaryHeadID]         where ([EmployeeID] = [PR].[EmployeeID] and [TaxYear] = [PR].[TaxYear] and [PeriodID] = [PR].[PeriodID] and [PRI].[IRP5CodeID] = [PR].[IRP5CodeID] and [PRI].[IsRFI] = [PR].[IsRFI])          group by [CycleID], [PeriodID], [EmployeeID], [PRI].[IRP5CodeID], [PRI].[IsRFI]       ) as [PRC]      where ([PR].[EmployeeID] = @EmployeeID and [PR].[TaxYear] = @TaxYear and not ([IRP5].[TransactionTypeID] = 2 and isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) = 0))       group by [PR].[IRP5Code], [PR].[IsRFI]      order by [PR].[IRP5Code]      DECLARE @Code varchar(10)  DECLARE @lastValue decimal(18,2)  DECLARE @lastFinalRunId int = (select top 1 Period_ID from Payroll_CyclePeriodDetails where CycleID = @CycleId and TaxYear = @payrollyear and Processed = 1 Order by ProcessedDate desc)      DECLARE db_cursor CURSOR FOR   SELECT IRP5Code   FROM @tblTaxTotals     OPEN db_cursor    FETCH NEXT FROM db_cursor INTO @Code      WHILE @@FETCH_STATUS = 0    BEGIN             Select @lastValue = (Select Top 1 SUM(Amount) from Payroll_PayrollResults where IRP5Code = @Code and EmployeeID = @EmployeeId and PeriodID = @lastFinalRunId)     Update @tblTaxTotals set Value = @lastValue, Annual = @lastValue * (case @CycleTypeID      /* MONTHLY */      when 1 then 12      /* WEEKLY */      when 2 then 52      /* Bi-WEEKLY */      when 3 then 26     end)   where IRP5Code = @Code        FETCH NEXT FROM db_cursor INTO @Code   END     CLOSE db_cursor    DEALLOCATE db_cursor             Select @Taxcredits = SUM(ISNULL(TaxCredits,0)) from Payroll_PayrollRun_History_Employees WHERE Employee_ID=@EmployeeID AND TaxYear=@payrollyear     Select @CurrentTaxcredits = (select top 1 TaxCredits from Payroll_PayrollRun_History_Employees where Employee_ID = @employeeId and TaxYear = @payrollyear order by Period Desc )        --4116    --MEDICAL SCHEME FEES TAX CREDIT    IF( (select count(*) from @tblTaxTotals) > 0 and (@TaxCredits > 0 OR @CurrentTaxcredits > 0))    BEGIN     INSERT INTO @tblTaxTotals     VALUES(4116,@CurrentTaxcredits,@Taxcredits,0,     (@CurrentTaxcredits * (case @CycleTypeID       /* MONTHLY */     when 1 then 12       /* WEEKLY */     when 2 then 52       /* Bi-WEEKLY */     when 3 then 26       end)))    END      Select @SecondaryMTC = SUM(ISNULL(SecondaryMTC,0)) from Payroll_PayrollRun_History_Employees WHERE Employee_ID=@EmployeeID AND TaxYear=@payrollyear     Select @CurrentSecondaryMTC = (select top 1 SecondaryMTC from Payroll_PayrollRun_History_Employees where Employee_ID = @employeeId and TaxYear = @payrollyear order by Period Desc )      --4120    --Secondary MEDICAL SCHEME FEES TAX CREDIT    IF( (select count(*) from @tblTaxTotals) > 0 and (@SecondaryMTC > 0 OR @CurrentSecondaryMTC > 0))    BEGIN     INSERT INTO @tblTaxTotals     VALUES(4120,@CurrentSecondaryMTC,@CurrentSecondaryMTC,0,     (@CurrentSecondaryMTC * (case @CycleTypeID       /* MONTHLY */     when 1 then 12       /* WEEKLY */     when 2 then 52       /* Bi-WEEKLY */     when 3 then 26       end)))    END      --Code 4005 should display a sum of 4005 and 4474    --Code 4003 should display a sum of 4003 and 4473    --Code 4001 should display a sum of 4001 and 4472      SELECT      [IRP5Code],      [Value],     [Tax],     [IsRFI],     [Annual]     FROM @tblTaxTotals    WHERE IRP5Code NOT IN (4003,4005,4001)    UNION    SELECT      '4001',      SUM([Value])Value,     SUM([Tax])Tax,     [IsRFI],     SUM([Annual])Annual    FROM @tblTaxTotals    WHERE IRP5Code IN (4001,4472)    GROUP BY IsRFI    UNION    SELECT      '4005',      SUM([Value])Value,     SUM([Tax])Tax,     [IsRFI],     SUM([Annual])Annual    FROM @tblTaxTotals    WHERE IRP5Code IN (4005,4474)    GROUP BY IsRFI    UNION    SELECT      '4003',      SUM([Value])Value,     SUM([Tax])Tax,     [IsRFI],     SUM([Annual])Annual    FROM @tblTaxTotals    WHERE IRP5Code IN (4003,4473)    GROUP BY IsRFI       end

GO

-- ============================================
-- SP: Payroll_GetTaxYears
-- Schema: dbo
-- ============================================
  -- ===================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/08>  -- Description: <Get Payroll TaxYears>  -- Call SP    : Payroll_GetTaxYears 0  --====================================================================  CREATE PROCEDURE [dbo].[Payroll_GetTaxYears]  @TaxYearId int  AS  BEGIN  SELECT    TaxPeriodId,   tp.TaxYear,   tp.StartDate,   tp.EndDate,   tp.cycleID,   tp.Enable,   tp.DateCaptured,   tp.CapturerID,   tp.DateModified,   tp.ModifierID,   pc.CycleDesc,   tp.FinalRunDate,   CASE when tp.TaxYearOpen = 1 THEN 'Open' ELSE 'Close' END AS TaxYearOpen  FROM Const_Payroll_TaxPeriods tp  JOIN Const_Cycle pc    ON tp.cycleID = pc.Cycle_ID  WHERE (TaxYear = @TaxYearId OR @TaxYearId = 0)      END  

GO

-- ============================================
-- SP: Payroll_GetTemplateDetailsByTransTypeIdList_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL    -- Create date:  26 JUL 2013    -- Description: <Description,,>    -- calls: Payroll_GetTemplateDetailsByTransTypeIdList_sp 4,0    -- =============================================    CREATE PROCEDURE [Payroll_GetTemplateDetailsByTransTypeIdList_sp]   @TransactionTypeID INT,     @Flag INT         AS    BEGIN            IF(@Flag >0)      BEGIN      SELECT DISTINCT       CONST_TRAN.TransactionTypeDesc AS TransactionType,       PAY_SAL.SalaryHeadTitle as [Description]      FROM Const_TransactionType CONST_TRAN       INNER JOIN dbo.Payroll_IRP5Code IRP5Code ON CONST_TRAN.TransactionType_ID = IRP5Code.TransactionTypeID       INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.IRP5CodeId = IRP5Code.IRP5Code_ID       INNER JOIN Payroll_PayrollDefination PAY_DEF ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID       INNER JOIN Payroll_DefinitionGroup PAY_PRO_GROUP ON PAY_PRO_GROUP.PayrollDefinitionGroup_ID = PAY_DEF.PayrollDefinitionGroupID      WHERE CONST_TRAN.TransactionType_ID = @TransactionTypeID     END     ELSE     BEGIN      SELECT DISTINCT       CONST_TRAN.TransactionTypeDesc AS TransactionType,       PAY_SAL.SalaryHeadTitle as [Description]      FROM Const_TransactionType CONST_TRAN       INNER JOIN dbo.Payroll_IRP5Code IRP5Code ON CONST_TRAN.TransactionType_ID = IRP5Code.TransactionTypeID       INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.IRP5CodeId = IRP5Code.IRP5Code_ID       INNER JOIN Payroll_EmployeePayrollDefinition PAY_EMP_DEF ON PAY_SAL.SalaryHead_ID = PAY_EMP_DEF.PayrollSalaryHeadID  AND PAY_EMP_DEF.Enabled = 1     INNER JOIN Payroll_Employee PAY_EMP ON PAY_EMP.Employee_ID = PAY_EMP_DEF.EmployeeID      WHERE CONST_TRAN.TransactionType_ID = @TransactionTypeID     END         END           

GO

