-- ============================================
-- SP: Payroll_GetTerminatedPayrollEmployeeTrialPayslip_sp
-- Schema: dbo
-- ============================================
-- ======================================================================================================  -- Author: Artur Anzorge  -- Create date: 27/08/2019    -- Description: Get the trial payslip view for different transactions for terminated employee  -- ======================================================================================================  CREATE procedure [dbo].[Payroll_GetTerminatedPayrollEmployeeTrialPayslip_sp] @PeriodId int, @EmployeeId int, @CycleId int, @TransactionType int  as    begin     set nocount on;        select [CTT].[TransactionType_ID] as TransactionTypeID, [SH].[SalaryHeadTitle] as [Transaction], sum(tp.[Value])  as [Value]      from Payroll_EmployeeTrialPayslipSimulation as [TP] with(nolock)       join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleId            join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [PE].[Employee_ID]             and [EPD].[PayrollSalaryHeadID] = [TP].[SalaryHeadID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1            where TP.EmployeeID = @EmployeeId  and [CTT].[TransactionType_ID] = @TransactionType            group by [CTT].[TransactionType_ID], [SH].[SalaryHeadTitle]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetTop1CyclePertiod_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: PRERANA PARMAR  -- Create date:06 JULY 2013  -- Description: <Description,,>  -- calls : [Payroll_GetTop1CyclePertiod_sp]  '2012/2013', 2  -- 2016-04-22 TP35500 Ravindra Jijotia : Added CycleModeID in filter.  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetTop1CyclePertiod_sp]     @FinancialYear NVARCHAR(50),    @CycleID INT  AS  BEGIN    SELECT TOP 1 Period_ID, CONVERT(NVARCHAR(15),PeriodStartDate,106) as StartDate, CONVERT(NVARCHAR(15),PeriodEndDate,106) as EndDate    FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear AND CycleID = @CycleID AND Processed = 0 AND CycleModeID = 1  END        

GO

-- ============================================
-- SP: Payroll_GetTop1FinalProcessCyclePertiod_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:05/08/2013  -- Description: Get Re-Process Period ID  -- calls : [Payroll_GetTop1CyclePertiod_sp]  '2012/2013', 2  -- 2014-10-20 James Roodt Added a filter on the first select as it selects items outside of the range of the second select  -- 2014-10-30 James Roodt: Fixed bug where wrong cycle was filtered.  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  -- 2016-04-26 Saleem Khan: Added CycleModeID to select  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetTop1FinalProcessCyclePertiod_sp]     @FinancialYear NVARCHAR(50),    @CycleID INT  AS  BEGIN   DECLARE @PeriodID INT   DECLARE @CycleModeID INT   SELECT TOP 1 @PeriodID = PeriodID,@CycleModeID=CycleModeID FROM dbo.Payroll_TrailRun_History as TR   INNER JOIN Payroll_CyclePeriodDetails as CPD on CPD.Period_ID=TR.PeriodID   WHERE TR.[Status] = 'InProcess' AND TR.TaxYear = @FinancialYear AND CPD.CycleID= @CycleID      SELECT TOP 1 Period_ID,     CONVERT(NVARCHAR(15),PeriodStartDate,106) as StartDate,     CONVERT(NVARCHAR(15),PeriodEndDate,106) as EndDate   FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear      AND CycleID = @CycleID AND Period_ID = @PeriodID AND CycleModeID = @CycleModeID  END        

GO

-- ============================================
-- SP: Payroll_GetTop1FinalProcessCyclePertiodAdHoc_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:05/08/2013  -- Description: Get Re-Process Period ID  -- calls : [Payroll_GetTop1CyclePertiod_sp]  '2012/2013', 2  -- 2014-10-20 James Roodt Added a filter on the first select as it selects items outside of the range of the second select  -- 2014-10-30 James Roodt: Fixed bug where wrong cycle was filtered.  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  -- 2016-04-26 Saleem Khan: Added CycleModeID to parameters  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetTop1FinalProcessCyclePertiodAdHoc_sp]     @FinancialYear NVARCHAR(50),    @CycleID INT,    @CycleModeID INT  AS  BEGIN   DECLARE @PeriodID INT   SELECT TOP 1 @PeriodID = PeriodID FROM dbo.Payroll_TrailRun_History as TR   INNER JOIN Payroll_CyclePeriodDetails as CPD on CPD.Period_ID=TR.PeriodID   WHERE TR.[Status] = 'InProcess' AND TR.TaxYear = @FinancialYear AND CPD.CycleID= @CycleID      SELECT TOP 1 Period_ID,     CONVERT(NVARCHAR(15),PeriodStartDate,106) as StartDate,     CONVERT(NVARCHAR(15),PeriodEndDate,106) as EndDate   FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear      AND CycleID = @CycleID AND Period_ID = @PeriodID AND CycleModeID = @CycleModeID  END        

GO

-- ============================================
-- SP: Payroll_GetTop1ReProcessCyclePertiod_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:05/08/2013  -- Description: Get Re-Process Period ID  -- calls : [Payroll_GetTop1CyclePertiod_sp]  '2012/2013', 2  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetTop1ReProcessCyclePertiod_sp]     @FinancialYear NVARCHAR(50),    @CycleID INT  AS  BEGIN   DECLARE @PeriodID INT   SELECT TOP 1 @PeriodID = PeriodID FROM dbo.Payroll_TrailRun_History    WHERE [Status] = 'InProcess' AND TaxYear = @FinancialYear      SELECT TOP 1 Period_ID,     CONVERT(NVARCHAR(15),PeriodStartDate,106) as StartDate,     CONVERT(NVARCHAR(15),PeriodEndDate,106) as EndDate   FROM Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear      AND CycleID = @CycleID AND Period_ID = @PeriodID AND CycleModeID = 1  END        

GO

-- ============================================
-- SP: Payroll_GetTotalAmount_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:  03 AUG 2013  -- Description: <Description,,>  -- calls : Payroll_GetTotalAmount_sp '2012/2013',176,37  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetTotalAmount_sp]    @FinnacialYear NVARCHAR(50),    @PeriodID INT,    @EmployeeID INT  AS  BEGIN   SELECT SUM(AMOUNT) AS TOTALAMOUNT    FROM PAYROLL_EMPLOYEEPAYSLIP   WHERE TaxYear = @FINNACIALYEAR AND PERIODID = @PERIODID AND EMPLOYEEID = @EMPLOYEEID and [TaxSavePurpose] = 0   AND PAYROLLDEFINATIONID IN     (     SELECT EmployeePayrollDefinition_ID      FROM Payroll_EmployeePayrollDefinition AS EPD      INNER JOIN dbo.Payroll_SalaryHead AS Sh ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID      INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = Sh.IRP5CodeId     WHERE IRP5Code.TransactionTypeID != 3    )  END  

GO

-- ============================================
-- SP: Payroll_GetTotalIRP5Income_Final_sp
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATE DATE : 27/09/2017   DESCRIPTION : EMPLOYEE TOTAL INCOME BASED ON IRP5 CODES   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Final_sp] '06 + 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 deduction(s) + EMS deduction(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Final_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 income(s) + EMS income(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable     @TransactionTypeID - where you want to match Transaction Type ID 1 to 4, then pass 0   @TransactionTypeID - where you want to match only Transaction Type ID 1, then pass 1   @TransactionTypeID - where you want to match only Transaction Type ID 2, then pass 2   @TransactionTypeID - where you want to match only Transaction Type ID 3, then pass 4   @TransactionTypeID - where you want to match only Transaction Type ID 4, then pass 8     if you wish to match multiple Transaction Type ID, then you need to combine them using SQL Bitwise OR, by creating a int variable and combining the ID you wish to compare, example:     declare @XOR int = (1 ^ 3) < this will match where the Transaction Type ID is 1 or 3   declare @XOR int = (1 ^ 2 ^ 3) < this will match where the Transaction Type ID is 1, 2 or 3   declare @XOR int = (2 ^ 3 ^ 4) < this will match where the Transaction Type ID is 2, 3 or 4   declare @XOR int = (1 ^ 4) < this will match where the Transaction Type ID is 1 or 4   declare @XOR int = (2 ^ 3) < this will match where the Transaction Type ID is 2 or 3   declare @XOR int = (2 ^ 4) < this will match where the Transaction Type ID is 2 or 4     exec [Payroll_GetTotalIRP5Income_Final_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, @XOR, 2    */  create procedure [Payroll_GetTotalIRP5Income_Final_sp] @IRP5Code [Payroll_IRP5Income] readonly, @calc nvarchar(max), @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @TransactionTypeID int, @taxable tinyint, @result decimal(18, 6) out  as  begin     set nocount on;     declare @i tinyint = 1,     @c tinyint = 11,     @StartDate datetime = null,     @UntilDate datetime = null     begin try      /*       @calc =>       01 - INCOME RECORD(S)     02 - ALLOWANCE RECORD(S)     03 - FRINGE BENEFIT RECORD(S)     04 - LUMP SUM RECORD(S)     05 - GROSS RENUMERATION RECORD(S)     06 - DEDUCTION RECORD(S)     07 - EMPLOYEE TAX DEDUCTION CODE     08 - EARNINGS (IRP5 CODE => 0000)     09 - DEDUCTIONS (IRP5 CODE => 0000)     10 - COMPANY CONTRIBUTIONS (IRP5 CODE => 0000)     11 - FRINGE BENEFITS (IRP5 CODE => 0000)       @taxable       0 - NON-TAXABLE     1 - TAXABLE     2 - BOTH      */      while (@i <= @c)    begin       set @calc = replace(@calc, (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)), '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']')       set @i = @i + 1      end      select @StartDate = [PeriodStartDate], @UntilDate = [PeriodEndDate] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)      set @i = 1      while (@i <= @c)    begin       if (@calc like '%[[]' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']%')     begin        set @result = coalesce((select cast(sum(cast(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))) as decimal(18, 6)) * (cast((case         when [ETR].[Taxable] = 0 then cast(100 as decimal(18, 6))         else [ETR].[Taxable] end) as decimal(18, 6)) / cast(100 as decimal(18, 6)))) as decimal(18, 6))         from [Payroll_PayrollResults] as [ETP] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = (case            when @TransactionTypeID > 0 and (power(2, [IRP5].[TransactionTypeID] - 1) & @TransactionTypeID) > 0 then [IRP5].[TransactionTypeID]            when @i > 7 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 0 then @i - 7            else [IRP5].[TransactionTypeID]           end)          join @IRP5Code as [ETR] on [ETR].[IRP5Code] = isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) and [Type] = @i and [Taxable] = (case            when @taxable = 0 then 0            when @taxable = 1 and [Taxable] > 0 then [Taxable]            when @taxable = 2 then [Taxable]           end) and [ETR].[StartDate] <= @UntilDate and [ETR].[UntilDate] >= @StartDate          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ETP].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [ETP].[PeriodID] and [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Enabled] = 1          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         where ([ETP].[EmployeeID] = (case @EmployeeID when 0 then [ETP].[EmployeeID] else @EmployeeID end) and [ETP].[PeriodID] = @PeriodID and [TaxSavePurpose] = 0 and           (case           when @CycleModeID = 1 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end           when @CycleModeID = 2 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end           else 0 end) = 1         )          group by [ETP].[EmployeeID]), 0)        set @calc = replace(@calc, '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']', 'cast(' + cast(@result as nvarchar(max)) + ' as decimal(18, 6))')       end       set @i = @i + 1      end      set @calc = 'select @result = cast(' + @calc + ' as decimal(18, 6))'      exec sp_executesql @calc, N'@result decimal(18, 6) out', @result = @result out     end try     begin catch      insert into [Payroll_FinalErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;     return    end  

GO

-- ============================================
-- SP: Payroll_GetTotalIRP5Income_Trial_sp
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATE DATE : 21/06/2017   DESCRIPTION : EMPLOYEE TOTAL INCOME BASED ON IRP5 CODES   UPDATE DATE : 30/06/2017 - UPDATED THE JOINS AND WHERE CLAUSE TO FILTER IRP5 CODES BASED ON VALID FROM AND VALID UNTIL   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Trial_sp] '06 + 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 deduction(s) + EMS deduction(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable   SAMPLE  : exec [Payroll_GetTotalIRP5Income_Trial_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 income(s) + EMS income(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable     @TransactionTypeID - where you want to match Transaction Type ID 1 to 4, then pass 0   @TransactionTypeID - where you want to match only Transaction Type ID 1, then pass 1   @TransactionTypeID - where you want to match only Transaction Type ID 2, then pass 2   @TransactionTypeID - where you want to match only Transaction Type ID 3, then pass 4   @TransactionTypeID - where you want to match only Transaction Type ID 4, then pass 8     if you wish to match multiple Transaction Type ID, then you need to combine them using SQL Bitwise OR, by creating a int variable and combining the ID you wish to compare, example:     declare @XOR int = (1 ^ 3) < this will match where the Transaction Type ID is 1 or 3   declare @XOR int = (1 ^ 2 ^ 3) < this will match where the Transaction Type ID is 1, 2 or 3   declare @XOR int = (2 ^ 3 ^ 4) < this will match where the Transaction Type ID is 2, 3 or 4   declare @XOR int = (1 ^ 4) < this will match where the Transaction Type ID is 1 or 4   declare @XOR int = (2 ^ 3) < this will match where the Transaction Type ID is 2 or 3   declare @XOR int = (2 ^ 4) < this will match where the Transaction Type ID is 2 or 4     exec [Payroll_GetTotalIRP5Income_Trial_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, @XOR, 2    */  CREATE procedure [Payroll_GetTotalIRP5Income_Trial_sp] @IRP5Code [Payroll_IRP5Income] readonly, @calc nvarchar(max), @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @TransactionTypeID int, @taxable tinyint, @result decimal(18, 6) out  as  begin     set nocount on;     declare @i tinyint = 1,     @c tinyint = 11,     @StartDate datetime = null,     @UntilDate datetime = null     begin try      /*       @calc =>       01 - INCOME RECORD(S)     02 - ALLOWANCE RECORD(S)     03 - FRINGE BENEFIT RECORD(S)     04 - LUMP SUM RECORD(S)     05 - GROSS RENUMERATION RECORD(S)     06 - DEDUCTION RECORD(S)     07 - EMPLOYEE TAX DEDUCTION CODE     08 - EARNINGS (IRP5 CODE => 0000)     09 - DEDUCTIONS (IRP5 CODE => 0000)     10 - COMPANY CONTRIBUTIONS (IRP5 CODE => 0000)     11 - FRINGE BENEFITS (IRP5 CODE => 0000)       @taxable       0 - NON-TAXABLE     1 - TAXABLE     2 - BOTH      */      while (@i <= @c)    begin       set @calc = replace(@calc, (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)), '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']')       set @i = @i + 1      end      select @StartDate = [PeriodStartDate], @UntilDate = [PeriodEndDate] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID)      set @i = 1      while (@i <= @c)    begin       if (@calc like '%[[]' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']%')     begin        set @result = coalesce((select cast(sum(cast(isnull(cast([Amount] as decimal(18, 6)), cast(0 as decimal(18, 6))) as decimal(18, 6)) * (cast((case         when [ETR].[Taxable] = 0 then cast(100 as decimal(18, 6))         else [ETR].[Taxable] end) as decimal(18, 6)) / cast(100 as decimal(18, 6)))) as decimal(18, 6))         from [Payroll_EmployeeTrialPayslip] as [ETP] with(nolock)          join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [ETP].[PayrollDefinationID] and [EPD].[Enabled] = 1          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] = (case            when @TransactionTypeID > 0 and (power(2, [TransactionTypeID] - 1) & @TransactionTypeID) > 0 then [TransactionTypeID]            when @i > 7 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 0 then @i - 7            else [TransactionTypeID]           end)          join @IRP5Code as [ETR] on [ETR].[IRP5Code] = isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) and [Type] = @i and [Taxable] = (case            when @taxable = 0 then 0            when @taxable = 1 and [Taxable] > 0 then [Taxable]            when @taxable = 2 then [Taxable]           end) and [ETR].[StartDate] <= @UntilDate and [ETR].[UntilDate] >= @StartDate          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ETP].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[CycleID] = [PE].[CycleID] and [Period_ID] = [ETP].[PeriodID] and [CPD].[Enabled] = 1          join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Period_ID] = [ETP].[PeriodID] and [EP].[Employee_ID] = [ETP].[EmployeeID] and [EP].[Cycle_ID] = [PE].[CycleID]          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]         where ([ETP].[EmployeeID] = (case @EmployeeID when 0 then [ETP].[EmployeeID] else @EmployeeID end) and [ETP].[PeriodID] = @PeriodID and [TaxSavePurpose] = 0 and          (case           when @CycleModeID = 1 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end           when @CycleModeID = 2 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end           else 0 end) = 1         )          group by [ETP].[EmployeeID]), 0)        set @calc = replace(@calc, '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']', 'cast(' + cast(@result as nvarchar(max)) + ' as decimal(18, 6))')       end       set @i = @i + 1      end      set @calc = 'select @result = cast(' + @calc + ' as decimal(18, 6))'      exec sp_executesql @calc, N'@result decimal(18, 6) out', @result = @result out     end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;     return    end

GO

-- ============================================
-- SP: Payroll_GetTotalIRP5Income_TrialSimulation_sp
-- Schema: dbo
-- ============================================
  /*   AUTHOR  : FERDI BOTHA   CREATE DATE : 21/06/2017   DESCRIPTION : EMPLOYEE TOTAL INCOME BASED ON IRP5 CODES   UPDATE DATE : 30/06/2017 - UPDATED THE JOINS AND WHERE CLAUSE TO FILTER IRP5 CODES BASED ON VALID FROM AND VALID UNTIL   SAMPLE  : exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] '06 + 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 deduction(s) + EMS deduction(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable   SAMPLE  : exec [Payroll_GetTotalIRP5Income_TrialSimulation_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, 1, 2 <= returns the calculated summary for Employee No. 1; includes the SARS IRP5 income(s) + EMS income(s) - where the IRP5Code is '0000', the TransactionTypeID is 1 and it is either non-taxable or taxable     @TransactionTypeID - where you want to match Transaction Type ID 1 to 4, then pass 0   @TransactionTypeID - where you want to match only Transaction Type ID 1, then pass 1   @TransactionTypeID - where you want to match only Transaction Type ID 2, then pass 2   @TransactionTypeID - where you want to match only Transaction Type ID 3, then pass 4   @TransactionTypeID - where you want to match only Transaction Type ID 4, then pass 8     if you wish to match multiple Transaction Type ID, then you need to combine them using SQL Bitwise OR, by creating a int variable and combining the ID you wish to compare, example:     declare @XOR int = (1 ^ 3) < this will match where the Transaction Type ID is 1 or 3   declare @XOR int = (1 ^ 2 ^ 3) < this will match where the Transaction Type ID is 1, 2 or 3   declare @XOR int = (2 ^ 3 ^ 4) < this will match where the Transaction Type ID is 2, 3 or 4   declare @XOR int = (1 ^ 4) < this will match where the Transaction Type ID is 1 or 4   declare @XOR int = (2 ^ 3) < this will match where the Transaction Type ID is 2 or 3   declare @XOR int = (2 ^ 4) < this will match where the Transaction Type ID is 2 or 4     exec [Payroll_GetTotalIRP5Income_Trial_sp] '01 + 02 + 03 + 04 + 08 - 06 - 09', 1, 1, 1, 1, @XOR, 2    */  create procedure [Payroll_GetTotalIRP5Income_TrialSimulation_sp] @IRP5Code [Payroll_IRP5Income] readonly, @calc nvarchar(max), @EmployeeID int, @StartDate datetime, @UntilDate datetime, @CycleID int, @CycleModeID int, @TransactionTypeID int, @SimulationType tinyint, @ParentID int, @taxable tinyint, @result decimal(18, 6) out  as  begin     set nocount on;     declare @i tinyint = 1,     @c tinyint = 11     begin try      /*       @calc =>       01 - INCOME RECORD(S)     02 - ALLOWANCE RECORD(S)     03 - FRINGE BENEFIT RECORD(S)     04 - LUMP SUM RECORD(S)     05 - GROSS RENUMERATION RECORD(S)     06 - DEDUCTION RECORD(S)     07 - EMPLOYEE TAX DEDUCTION CODE     08 - EARNINGS (IRP5 CODE => 0000)     09 - DEDUCTIONS (IRP5 CODE => 0000)     10 - COMPANY CONTRIBUTIONS (IRP5 CODE => 0000)     11 - FRINGE BENEFITS (IRP5 CODE => 0000)       @taxable       0 - NON-TAXABLE     1 - TAXABLE     2 - BOTH      */      while (@i <= @c)    begin       set @calc = replace(@calc, (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)), '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']')       set @i = @i + 1      end      set @i = 1      while (@i <= @c)    begin       if (@calc like '%[[]' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']%')     begin        set @result = coalesce((select cast(sum(cast(isnull(cast([Value] as decimal(18, 6)), cast(0 as decimal(18, 6))) as decimal(18, 6)) * (cast((case         when [ETR].[Taxable] = 0 then cast(100 as decimal(18, 6))         else [ETR].[Taxable] end) as decimal(18, 6)) / cast(100 as decimal(18, 6)))) as decimal(18, 6))         from [Payroll_EmployeeTrialPayslipSimulation] as [ETP] with(nolock)          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [ETP].[SalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] = (case            when @TransactionTypeID > 0 and (power(2, [IRP5].[TransactionTypeID] - 1) & @TransactionTypeID) > 0 then [IRP5].[TransactionTypeID]            when @i > 7 and isnull([IRP5CertCode], [IRP5].[IRP5Code]) = 0 then @i - 7            else [IRP5].[TransactionTypeID]           end)          join @IRP5Code as [ETR] on [ETR].[IRP5Code] = isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) and [Type] = @i and [Taxable] = (case            when @taxable = 0 then 0            when @taxable = 1 and [Taxable] > 0 then [Taxable]            when @taxable = 2 then [Taxable]           end) and [ETR].[StartDate] <= @UntilDate and [ETR].[UntilDate] >= @StartDate          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [ETP].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_TrialRun_History_EmployeeSimulation] as [TPS] with(nolock) on [TPS].[SimulationType] = @SimulationType and [TPS].[EmployeeID] = [ETP].[EmployeeID] and [TPS].[StartDate] = @StartDate and [TPS].[UntilDate] = @UntilDate and (           (isnull([TPS].[EmployeeChangeID], 0) = (case            when @SimulationType = 1 then @ParentID            else 0           end))           or           (isnull([TPS].[TerminationID], 0) = (case            when @SimulationType = 2 then @ParentID            else 0           end))          )         where ([ETP].[EmployeeID] = @EmployeeID and [ETP].[SimulationType] = @SimulationType and [TaxPurpose] = 0)          group by [ETP].[EmployeeID]), 0)        set @calc = replace(@calc, '[' + (case when @i < 10 then '0' else '' end) + cast(@i as nvarchar(2)) + ']', 'cast(' + cast(@result as nvarchar(max)) + ' as decimal(18, 6))')       end       set @i = @i + 1      end      set @calc = 'select @result = cast(' + @calc + ' as decimal(18, 6))'      exec sp_executesql @calc, N'@result decimal(18, 6) out', @result = @result out     end try     begin catch     end catch     set nocount off;     return    end  

GO

-- ============================================
-- SP: Payroll_GetTotalMedicalAIDContribution_Trial_sp
-- Schema: dbo
-- ============================================
  -- =====================================================================================  -- Author:  Ravindra Jijotia - TP19740  -- Create date: 30-07-2015  -- Used In : Payroll_EmployeeMedicalContribution_Trial_sp  -- Description: Get Total MedicalAID Contribution where Employer contribute and not.  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  -- 2016-08-19 Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return DependantCount for Adult WHERE IsAdultDependant =1 and count for Child WHERE IsChildDependant=1  -- 2016-09-22 TP44913 Phuti Chokoe : Added date range for medical aid scheme and enabled flag  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =====================================================================================  CREATE PROCEDURE [dbo].[Payroll_GetTotalMedicalAIDContribution_Trial_sp]   @EmployeeID INT,   @FinancialYear NVARCHAR(10),   @Month INT,   @PeriodID INT,    @totalAmountEmployerContribute DECIMAL(18,2) OUTPUT,   @totalAmountEmployerNotContribute DECIMAL(18,2) OUTPUT  AS  BEGIN     DECLARE @MemberAmount DECIMAL(18,2) = 0, @AdultAmount DECIMAL(18,2) = 0, @ChildAmount DECIMAL(18,2) = 0   DECLARE @EmployeeMedicalAID_ID INT = 0   DECLARE @MedicalAidSchmeID INT = 0     SELECT     @EmployeeMedicalAID_ID = EMA.EmployeeMedicalAID_ID,     @MedicalAidSchmeID = EMA.MedicalAidSchmeID,     --CONVERT(NVARCHAR(12),EMA.JoinDate, 103) AS JoinDate,    --CONVERT(NVARCHAR(12),EMA.TerminationDate, 103) AS TerminationDate,    --V.VendorName AS Fund,    --MS.FundName AS PLANName,    --EMA.Reference,    @MemberAmount = MSD.MemberAmount,    @AdultAmount = MSD.AdultAmount,    @ChildAmount = MSD.ChildAmount    --MS.EmployeeContributionValue,    --MS.EmployerContributionValue,    --MS.EmployerMaxContributorValue,    --MS.Editable AS ISPrivate,    --EMA.JoinDate,    --EMA.TerminationDate,    --CASE WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  < CAST(GETDATE() AS DATE ) THEN 'Terminated'    --  WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )  THEN 'Active'     --  WHEN CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE)  >= CAST(GETDATE() AS DATE ) THEN 'Pending'    --ELSE '' END  AS Status   FROM Payroll_EmployeeMedicalAIDDetail EMA    INNER JOIN dbo.Const_MedicalAIDScheme MS ON MS.MedicalScheme_ID = EMA.MedicalAidSchmeID    INNER JOIN dbo.Const_MedicalAIDSchemeDetail MSD ON MSD.MedicalSchemeID= MS.MedicalScheme_ID    INNER JOIN dbo.Cons_Vendor V ON V.Vendor_ID = MS.VendorID   WHERE EMA.EmployeeID = @EmployeeID AND EMA.Enable=1    AND CAST(ISNULL(EMA.TerminationDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(EMA.JoinDate AS DATE ) <= CAST(GETDATE() AS DATE )   AND MS.Enabled = 1   --AND CAST(ISNULL(MS.StartDate, GETDATE()) AS DATE) >= CAST(GETDATE() AS DATE ) AND CAST(MS.EndDate AS DATE ) <= CAST(GETDATE() AS DATE )     DECLARE @CycleID INT   SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID      DECLARE @MemberCount INT = 1, @AdultCount INT, @ChildCount INT   DECLARE @AdultCountBefore INT, @ChildCountBefore INT   DECLARE @MaxDependantCount INT      DECLARE @ToDate DATE, @FromDate DATE    SELECT @FinancialYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND TaxYear = @FinancialYear and CycleModeID = 1      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @FinancialYear and CycleModeID = 1       Select @AdultCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)      IF(@AdultCount IS NULL) SET @AdultCount = 0       Select @AdultCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND MedAidJoiningDate < @FromDate AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)      IF(@AdultCountBefore IS NULL) SET @AdultCountBefore = 0       SET @AdultCount = @AdultCount + @AdultCountBefore      Select @ChildCount = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND CAST(MedAidJoiningDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)     IF(@ChildCount IS NULL) SET @ChildCount = 0      Select @ChildCountBefore = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND MedAidJoiningDate < @FromDate AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)      IF(@ChildCountBefore IS NULL) SET @ChildCountBefore = 0       SET @ChildCount = @ChildCount + @ChildCountBefore     DECLARE @IsMaxDependantChildEnabled bit     --Get Max dependants allowed by medical aid   SELECT  @MaxDependantCount = isnull(cmsd.MaxDependantCount, 0), @IsMaxDependantChildEnabled = ISNULL(cmsd.IsMaxDependantChildEnabled, 0)   FROM Payroll_EmployeeMedicalAIDDetail as pemsd   inner join Const_MedicalAIDScheme as cms on cms.MedicalScheme_ID=pemsd.MedicalAidSchmeID   inner join Const_MedicalAIDSchemeDetail as cmsd on cmsd.MedicalSchemeID=cms.MedicalScheme_ID   WHERE pemsd.EmployeeID=@EmployeeID     --If IsMaxDependantChildEnabled is true, Child Count will come from saved value as MaxDependantCount in Const_MedicalAIDSchemeDetail table.   IF @IsMaxDependantChildEnabled = 1   BEGIN    IF @ChildCount > @MaxDependantCount     SET @ChildCount = @MaxDependantCount   END   --If IsMaxDependantChildEnabled is false, Adult Count & Child Count will be caluculated based on MaxDependantCount in Const_MedicalAIDSchemeDetail table.   -- Sum of AdultCount & ChildCount will not be more than the MaxDependantCount.   ELSE IF @IsMaxDependantChildEnabled = 0   BEGIN    IF ((@MaxDependantCount - @AdultCount) > 0)    BEGIN     DECLARE @Temp INT       SET @Temp = (@MaxDependantCount - @AdultCount)       IF ((@Temp - @ChildCount) < 0)     BEGIN      SET @ChildCount = @Temp     END    END    ELSE IF ((@MaxDependantCount - @AdultCount) < 0)    BEGIN     SET @AdultCount = @MaxDependantCount     SET @ChildCount = 0    END    ELSE IF ((@MaxDependantCount - @AdultCount) = 0)    BEGIN     SET @ChildCount = 0    END   END        --SELECT @AdultCount AS Adult, @ChildCount AS Child          DECLARE @AdultCountEmployerContribute INT, @ChildCountEmployerContribute INT      Select @AdultCountEmployerContribute = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsAdultDependant = 1   AND MedAidJoiningDate < @ToDate AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)   --AND CAST(DependedJoinDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND IsMedAidEmployerContribute = 1       IF(@AdultCountEmployerContribute IS NULL) SET @AdultCountEmployerContribute = 0       --SET @AdultCountEmployerContribute = @AdultCountEmployerContribute + @AdultCountBefore      Select @ChildCountEmployerContribute = ISNULL(COUNT(1), 0) FROM dbo.Payroll_PersonRelationshipType   WHERE Enabled = 1 AND DependantMode != 4 AND EmployeeID = @EmployeeID AND IsChildDependant = 1   AND MedAidJoiningDate < @ToDate AND (MedAidTerminateDate > @ToDate OR MedAidTerminateDate is null)   --AND CAST(DependedJoinDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)   AND IsMedAidEmployerContribute = 1      IF(@ChildCountEmployerContribute IS NULL) SET @ChildCountEmployerContribute = 0        --SET @ChildCountEmployerContribute = @ChildCountEmployerContribute + @ChildCountBefore         --SELECT @AdultCountEmployerContribute AS AdultCountEmployerContribute, @ChildCountEmployerContribute AS ChildCountEmployerContribute     --IF(@AdultCountEmployerContribute IS NULL) SET @AdultCountEmployerContribute = 0    --IF(@ChildCountEmployerContribute IS NULL) SET @ChildCountEmployerContribute = 0      DECLARE @AdultCountTotalEmployerContribute INT = 0   DECLARE @AdultCountTotalEmployerNotContribute INT = 0   DECLARE @ChildCountTotalEmployerContribute INT = 0   DECLARE @ChildCountTotalEmployerNotContribute INT = 0      IF((@AdultCountEmployerContribute - @AdultCount) >= 0)   BEGIN    SET @AdultCountTotalEmployerContribute = @AdultCount;   END   ELSE   BEGIN    SET @AdultCountTotalEmployerNotContribute = @AdultCount - @AdultCountEmployerContribute;          SET @AdultCountTotalEmployerContribute = @AdultCountEmployerContribute;   END       IF((@ChildCountEmployerContribute - @ChildCount) >= 0)   BEGIN    SET @ChildCountTotalEmployerContribute = @ChildCount;   END   ELSE   BEGIN    SET @ChildCountTotalEmployerNotContribute = @ChildCount - @ChildCountEmployerContribute;          SET @ChildCountTotalEmployerContribute = @ChildCountEmployerContribute;   END       DECLARE @totalAdultAmountEmployerContribute DECIMAL(18,2) = 0, @totalChildAmountEmployerContribute DECIMAL(18,2) = 0, @totalAdultAmountEmployerNotContribute DECIMAL(18,2) = 0,              @totalChildAmountEmployerNotContribute DECIMAL(18,2) = 0,      @totalMedicalAIDAmount DECIMAL(18,2) = 0, @decTotal DECIMAL(18,2) = 0;     SET @decTotal = @MemberAmount + @AdultAmount + @ChildAmount       DECLARE @totalExtraTransactionsAmountEmployerContribute DECIMAL(18,2) = 0, @totalExtraTransactionsAmountEmployerNotContribute DECIMAL(18,2) = 0       DECLARE @Payroll_ExtraActiveMedicalAidTransactionTbl TABLE   (    Amount DECIMAL(18,2),    IsEmployerContribute BIT,      [RowNo] INT   )     DECLARE @Start INT = 1, @TotalCount INT = 0   DECLARE @ExtraActiveAmount DECIMAL(18,2)   DECLARE @IsEmployerContribute BIT     INSERT INTO @Payroll_ExtraActiveMedicalAidTransactionTbl   Select Amount, IsEmployerContribute, ROW_NUMBER()OVER (ORDER BY ExtraActiveMedicalAidTransaction_ID ASC) AS RowNumber from [Payroll_ExtraActiveMedicalAidTransaction]   WHERE Enabled = 1 and EmployeeMedicalAIDID = @EmployeeMedicalAID_ID   AND CAST(@ToDate AS DATE) BETWEEN DATEADD(month, DATEDIFF(month, 0, PeriodFrom), 0) AND DATEADD(s,-1,DATEADD(mm, DATEDIFF(m,0,CAST(PeriodTo AS DATE))+1,0))       SELECT @TotalCount = COUNT(1) FROM @Payroll_ExtraActiveMedicalAidTransactionTbl      WHILE(@Start <= @TotalCount)   BEGIN    SELECT @ExtraActiveAmount =  Amount, @IsEmployerContribute = IsEmployerContribute FROM @Payroll_ExtraActiveMedicalAidTransactionTbl WHERE [RowNo]= @Start      IF (@IsEmployerContribute = 1)    BEGIN     SET @totalExtraTransactionsAmountEmployerContribute = @totalExtraTransactionsAmountEmployerContribute + @ExtraActiveAmount    END    ELSE    BEGIN     SET @totalExtraTransactionsAmountEmployerNotContribute = @totalExtraTransactionsAmountEmployerNotContribute + @ExtraActiveAmount    END      SET @Start = @Start + 1   END     SET @totalAdultAmountEmployerContribute = @AdultAmount * @AdultCountTotalEmployerContribute   SET @totalChildAmountEmployerContribute = @ChildAmount * @ChildCountTotalEmployerContribute     SET @totalAdultAmountEmployerNotContribute = @AdultAmount * @AdultCountTotalEmployerNotContribute   SET @totalChildAmountEmployerNotContribute = @ChildAmount * @ChildCountTotalEmployerNotContribute      SET @totalAmountEmployerContribute = @MemberAmount + @totalAdultAmountEmployerContribute + @totalChildAmountEmployerContribute + @totalExtraTransactionsAmountEmployerContribute   SET @totalAmountEmployerNotContribute = @totalAdultAmountEmployerNotContribute + @totalChildAmountEmployerNotContribute + @totalExtraTransactionsAmountEmployerNotContribute     --Select @totalAmountEmployerContribute as totalAmountEmployerContribute, @totalAmountEmployerNotContribute as totalAmountEmployerNotContribute  END  

GO

-- ============================================
-- SP: Payroll_GetTrailRunSummary_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 24/03/2017   Description : Get Trial Summary Results from Trial Results   Update date : 09/05/2017 - Changed the mappings for Method of Calculation   Update Date : 04/04/2019 - Changed query to point to Trial Results  */  CREATE procedure [Payroll_GetTrailRunSummary_sp] @PeriodID int  as    begin     set nocount on;     select null as [Reason], [TP].[EmployeeID], min([PE].[EmpCode]) as [EmpCode], min([PE].[FirstName]) as [FirstName], min([PE].[Surname]) as [Surname],        cast(isnull(sum(case when [TP].[TransactionTypeID] = 1 and [TP].[SalaryHeadID] = 1 then isnull([PE].[FixedSalary], 0) else 0 end), 0) as decimal(18, 2)) as [Salary],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 1 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Earnings],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Deductions],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 3 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Contributions],      cast(isnull(sum(case when [TP].[TransactionTypeID] = 4 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) as [Fringe],      (cast(isnull(sum(case when [TP].[TransactionTypeID] = 1 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2)) -       cast(isnull(sum(case when [TP].[TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 0 then isnull([TP].[Amount], 0) else 0 end), 0) as decimal(18, 2))) as [Total]      from [Payroll_TrialResults] as [TP] with(nolock)       join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = [TP].[CycleID]      where ([TP].[PeriodID] = @PeriodID)      group by [TP].[EmployeeID]       order by [TP].[EmployeeID]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_GetTransactionsMOCDetail_sp
-- Schema: dbo
-- ============================================
    /*   Author  : Lungisani Khumalo   Create date : 30/11/2017   Description : Gets the MOC History Details  */  create procedure [dbo].[Payroll_GetTransactionsMOCDetail_sp] @EmployeeID int, @SalaryHeadID int, @TransactionDate datetime    as    begin     set nocount on;     declare @MOCID int     if (not @SalaryHeadID is null and @SalaryHeadID > 0)      select @MOCID = [MOC_ID] from [Const_MOC] with(nolock) where ([SalaryHeadID] = @SalaryHeadID)     select [PE].[Employee_ID], [MOCD].[MOCID], [MOCD].[StartDate], [MOCD].[EndDate], [COS].[ConditionOfService_ID], [ET].[EmployeeType_ID], [EST].[EmployeeSubtype_ID]      from [Const_MOCDetail] as [MOCD] with(nolock)          join [Const_MOC] as [MOC] with(nolock) on [MOC_ID] = [MOCD].[MOCID] and [MOC].[Enabled] = [MOCD].[Enabled]       left outer join [Payroll_ConditionOfService] as [COS] with(nolock) on [ConditionOfService_ID] = [MOCD].[ConditionOfServiceID] and [COS].[Enabled] = [MOCD].[Enabled]       left outer join [Const_EmployeeType_sys] as [ET] with(nolock) on [EmployeeType_ID] = [MOCD].[EmployeeTypeID] and [ET].[Enabled] = [MOCD].[Enabled]       left outer join [Payroll_EmployeeSubtypes] as [EST] with(nolock) on [EmployeeSubtype_ID] = [MOCD].[EmployeeSubtypeID]       join [Payroll_Employee] as [PE] with(nolock) on [PE].[EmployeeSubtypeID] = (case when [MOCD].[EmployeeSubtypeID] is null then [PE].[EmployeeSubtypeID] else [EST].[EmployeeSubtype_ID] end)  and [PE].[ConditionOfServiceID] = (case when [MOCD].[ConditionOfServiceID] is null then [PE].[ConditionOfServiceID] else [COS].[ConditionOfService_ID]  end) and  [PE].[EmployeeTypeID] = (case when [MOCD].[EmployeeTypeID] is null then [PE].[EmployeeTypeID] else [ET].[EmployeeType_ID]  end)      where ([PE].[Employee_ID] = @EmployeeID and [MOCD].[MOCID] = (case when @MOCID = 0 then [MOCD].[MOCID] else @MOCID end) and [MOCD].[Enabled] = 1 and ([MOCD].[StartDate] <= @TransactionDate and @TransactionDate <= [MOCD].[EndDate]))     set nocount off;    end    

GO

-- ============================================
-- SP: Payroll_GetTransactionsonSalaryHead_sp
-- Schema: dbo
-- ============================================
-- =============================================    -- Author  :Varun Parvataneni    -- Create date :31/08/2016    -- Description :Return the Transactions from CostCenter table related to SalaryHead    -- Calls  :Payroll_GetTransactionsonSalaryHead_sp 1,0,204,1    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA    -- =============================================    -- =============================================    -- Author  :ANANTH SAKTHIVEL   -- Create date :10-Jan-2018   -- Description :Return the Transactions from CostCenter table related to SalaryHead For Bulk upload  -- File : TP-66284   -- =============================================    create procedure [Payroll_GetTransactionsonSalaryHead_sp]     @CycleID INT,     @PeriodID INT,     @SalaryHead INT,     @Mode INT    AS    BEGIN    IF(@Mode=1)    BEGIN    DECLARE @tmplstPeriodID TABLE(PeriodID INT)         --//Get the list of Normal periods from @CycleID     INSERT INTO @tmplstPeriodID      SELECT Period_ID  FROM Payroll_CyclePeriodDetails WHERE CycleID = @CycleID and CycleModeID=@Mode     --//Get the list of Transactions from CostCenter linked to @salryhead on specificPperiods      SELECT  PAY_COST.EmployeeID,P_E.Surname,P_E.FirstName,PAY_COST.EntryDate,PAY_SAL.SalaryHeadName as CostDesc,PAY_COST.CostAmount,PAY_COST.ReferenceNo,IsNull(PAY_COST.RunEveryMonth,0) as RepeatMonthly,PAY_COST.CostCenter_ID     FROM Payroll_CostCenter AS PAY_COST          inner join        (        select PAY_COST.EmployeeID , Max(PAY_COST.CostCenter_ID) as CostCenter_ID,  Min(DateDiff(day, PAY_COST.EntryDate,CurrentPeriodDate.PeriodStartDate))  as RO from Payroll_CostCenter as PAY_COST        inner Join        (          select top 1 [PeriodStartDate]from Payroll_CyclePeriodDetails          where [CycleID] = @CycleID and           Period_ID not in (select Period_ID from Payroll_CyclePeriodDetails where [CycleID] = @CycleID and [Processed] = 1) and          Enabled = 1          order by [PeriodStartDate] desc            ) as CurrentPeriodDate on 1=1        INNER JOIN Payroll_EmployeePayrollDefinition ON PAY_COST.PayrollDefinationID = Payroll_EmployeePayrollDefinition.EmployeePayrollDefinition_ID         INNER JOIN Payroll_SalaryHead AS PAY_SAL ON Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID        where PAY_SAL.SalaryHead_ID=@SalaryHead         Group by PAY_COST.EmployeeID        ) as DistinctCostCenter on DistinctCostCenter.CostCenter_ID = PAY_COST.CostCenter_ID       INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID       INNER JOIN Payroll_EmployeePayrollDefinition ON PAY_COST.PayrollDefinationID = Payroll_EmployeePayrollDefinition.EmployeePayrollDefinition_ID        INNER JOIN Payroll_SalaryHead AS PAY_SAL ON Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID                WHERE PAY_COST.PeriodID in (SELECT PeriodID FROM @tmplstPeriodID) and PAY_SAL.Enabled=1 and PAY_SAL.SalaryHead_ID=@SalaryHead          END        ELSE IF(@Mode =2)    BEGIN    SELECT  PAY_COST.EmployeeID,P_E.FirstName+' '+P_E.Surname AS FullName,PAY_COST.EntryDate,PAY_SAL.SalaryHeadName as CostDesc,PAY_COST.CostAmount,PAY_COST.ReferenceNo,IsNull(PAY_COST.RunEveryMonth,0) as RepeatMonthly, PAY_COST.CostCenter_ID     FROM Payroll_CostCenter AS PAY_COST          INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID       INNER JOIN Payroll_EmployeePayrollDefinition ON PAY_COST.PayrollDefinationID = Payroll_EmployeePayrollDefinition.EmployeePayrollDefinition_ID        INNER JOIN Payroll_SalaryHead AS PAY_SAL ON Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     WHERE PAY_COST.PeriodID=@PeriodID and PAY_SAL.Enabled=1 and PAY_SAL.SalaryHead_ID=@SalaryHead         END    END  

GO

-- ============================================
-- SP: Payroll_GetTransactionsToBeApproved
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,02/12/2016,>  -- Description: <Description, Gets the Transcations to be approved,>  -- Modified: (Lungisani Khumalo) removed the Approver based EmployeeID record, this will be handled by  Employee types in C#.  -- Modified: (Richa M) changed the claims to only return transactions where the Enabled flag is set to 1  -- Modified: (Ferdi Botha) changed the Overtime to only return transactions where the Enabled flag is set to 1 and RejectedReason is null  -- Modified: (Ferdi Botha) updated both Overtime and Claims to include showing "new records"  --modified : (Modiri Selao, 2019/07/04) #90993 Overtime in approval grid does not dispaly the correct amount.  -- Modified: Richa M 021/02/21 Add Installments  -- E Beetge WI67401 Modify installments section cycle desc and amounts  -- =============================================  CREATE procedure [dbo].[Payroll_GetTransactionsToBeApproved] @UserID int, @IsTerminationRun bit, @EmployeeID int  as  begin     declare @KeyValue nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'DocRootFolderPath'))     select @KeyValue += [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'FolderSupportDocs')     select @KeyValue += [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TransactionsApprovalDocs')        declare @tableValues table (      [ID] int identity (1, 1),    [Cost_ID] int,    [Type] tinyint,    [FirstName] nvarchar(200),    [Surname] nvarchar(200),    [Employee_ID] int,    [TransactionType] nvarchar(200),    [TransactionTypeDesc] nvarchar(200),    [TransactionDesc] nvarchar(200),    [Amount] decimal(18,2),    [Filepath] varchar(max),    [IsBulk] bit,    [IRP5Code] int,    [hours] decimal(18,2),    [Date] datetime,    [EmployeeTypeID] int,    [Escalated] bit,    [Cycle] nvarchar(200)     )        declare @permissions table (       [PermissionID] int,     [PermissionDesc] nvarchar(200),     [ModuleID] int,     [ModuleDesc] nvarchar(200),     [PageName] nvarchar(300),     [ReadOnlyRights] int     )     DECLARE @transType_costCenter INT = 1   DECLARE @transType_overtime INT = 2   DECLARE @transType_claim INT = 3   DECLARE @transType_wage INT = 4   DECLARE @transType_installment INT = 5     insert into @permissions      exec User_Permissions_sp @UserID      /* COST CENTER */   insert into @tableValues      select      [CostCenter_ID] as [Cost_ID],      @transType_costCenter,      [FirstName],      [Surname],      [Employee_ID],      [CostDesc] as [TransactionType],      [CTT].[TransactionTypeDesc],      (cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc]) as [TransactionDesc],     [CostAmount] as [Amount],     (@KeyValue +      (select top 1 [Filename]      from [Sys_SupportingDocs] as [SD] with(nolock)      join [Payroll_CostCenter] as [CC] with(nolock) on [CC].[SupportingDocsID] = [SD].[SupportingDocs_ID])     ) as [Filepath],      [isBulk],      [IRP5].[IRP5Code],      null,      [CC].[EntryDate],      [PE].[EmployeeTypeID],      [CC].[TerminationEscalated],     C.CycleDesc     from [Payroll_Employee] as [PE] with(nolock)        join [Payroll_CostCenter] as [CC] with(nolock) on [CC].[EmployeeID] = [PE].[Employee_ID] and [CC].[IsApproved] = 0 and [CC].[IsApprovalRequired] = 1 and isnull([CC].[ExcludeFromPayment], 0) = 0 and [CC].[Enabled] = 1        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [CC].[PayrollDefinationID] and [EPD].[EmployeeID] = [CC].[EmployeeID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID]        left join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [PP].[DepartmentID] and [CD].[Enabled] = 1        left join [Const_Division] as [CDIV] with(nolock) on [CDIV].[Division_ID] = [PP].[DivisionID] and [CDIV].[Enabled] = 1        JOIN Const_Cycle AS C WITH(NOLOCK) ON PE.CycleID = C.Cycle_ID       where ([CC].[Enabled] = 1)     /* OVERTIME */   insert into @tableValues      select      [EmployeeOverTime_ID] as [Cost_ID],     @transType_overtime,      [FirstName],      [Surname],      [Employee_ID],      [SH].[SalaryHeadTitle] as [TransactionType],      [TransactionTypeDesc],      (cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc]) as [TransactionDesc],     [TotalAmount] as [Amount],     (@KeyValue +      (select top 1 [Filename]      from [Sys_SupportingDocs] as [SD] with(nolock)      join [Payroll_EmployeeOverTime] as [CC] with(nolock) on [CC].[SupportingDocsID] = [SD].[SupportingDocs_ID])     ) as [Filepath],      [isBulk],      [IRP5].[IRP5Code],      [OverTimeHour],      [OverTimeDate],      [PE].[EmployeeTypeID],      [OT].[TerminationEscalated],     C.CycleDesc     from [Payroll_Employee] as [PE] with(nolock)        join [Payroll_EmployeeOverTime] as [OT] with(nolock) on [OT].[EmployeeID] = [PE].[Employee_ID] and [OT].[IsApproved] = 0 and [OT].[IsApprovalRequired] = 1 and isnull([OT].[ExcludeFromPayment], 0) = 0 and [OT].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [OT].[SalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID]        left join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [PP].[DepartmentID] and [CD].[Enabled] = 1        left join [Const_Division] as [CDIV] with(nolock) on [CDIV].[Division_ID] = [PP].[DivisionID] and [CDIV].[Enabled] = 1        JOIN Const_Cycle AS C WITH(NOLOCK) ON PE.CycleID = C.Cycle_ID       where ([OT].[IsApproved] = 0 and [OT].[RejectedReason] is null)     /* CLAIMS */   insert into @tableValues      select      [EmployeeClaims_ID] as [Cost_ID],      @transType_claim,      [FirstName],      [Surname],      [Employee_ID],      [CL].[Claim_Type] + ' ( ' + [CL].[Sub_Type] + ' )' as [TransactionType],      [TransactionTypeDesc],      (cast(isnull([IRP5CertCode], [IRP5].[IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc]) as [TransactionDesc],     [CostAmount] as [Amount],     (@KeyValue +      (select top 1 [Filename]      from [Sys_SupportingDocs] as [SD] with(nolock)      join [Payroll_EmployeeClaims] as [CC] with(nolock) on [CC].[SupportingDocsID] = [SD].[SupportingDocs_ID])     ) as [Filepath],      [isBulk],      [IRP5].[IRP5Code],      [Kilometre],      [EntryDate],      [PE].[EmployeeTypeID],      [EC].[TerminationEscalated],     C.CycleDesc     from [Payroll_Employee] as [PE] with(nolock)        join [Payroll_EmployeeClaims] as [EC] with(nolock) on [EC].[EmployeeID] = [PE].[Employee_ID] and [EC].[IsApproved] = 0 and [EC].[IsApprovalRequired] = 1 and isnull([EC].[ExcludeFromPayment], 0) = 0 and [EC].[Enabled] = 1        join [Const_Claims] as [CL] with(nolock) on [CL].[Claim_ID] = [EC].[ClaimID]        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [CL].[SalaryHeadId] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1        join [Const_TransactionType] as [CTT] with(nolock) on [CTT].[TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        join [Payroll_Position] as [PP] with(nolock) on [PP].[Position_ID] = [PE].[PositionID]        left join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [PP].[DepartmentID] and [CD].[Enabled] = 1        left join [Const_Division] as [CDIV] with(nolock) on [CDIV].[Division_ID] = [PP].[DivisionID] and [CDIV].[Enabled] = 1            JOIN Const_Cycle AS C WITH(NOLOCK) ON PE.CycleID = C.Cycle_ID       where ([EC].[IsApproved] = 0 and [EC].[RejectedReason] is null)     /* Installments */   Insert into @tableValues   SELECT      ThirdP.PartyPayment_ID,     @transType_installment,      FirstName,     Surname,     Employee_ID,      'Installment ' + '(' + sh.SalaryHeadName + ')',     'Installment ' + '(' + sh.SalaryHeadName + ')',     'Installment ' + '(' + sh.SalaryHeadName + ')',     ThirdP.EMI,     '',      0,     irp.IRP5Code,     ThirdP.TotalAmount,     ThirdP.PartyPaymentDate,     emp.EmployeeTypeID,     0,     C.CycleDesc    from   (Select * from Payroll_3rdPartyPayment where IsNULL(Approved,0) = 0 and IsNULL(Rejected,0) = 0) ThirdP   left join Payroll_Employee emp on ThirdP.EmployeeID = emp.Employee_ID   left join Payroll_SalaryHead sh on sh.SalaryHead_ID = ThirdP.SalaryheadID   left join Const_Cycle cycle on cycle.Cycle_ID = emp.CycleID   left join Payroll_IRP5Code irp on irp.IRP5Code_ID = sh.IRP5CodeId   left join Const_TransactionType AS tt  ON tt.TransactionType_ID = irp.TransactionTypeID  and tt.Enabled = 1   JOIN Const_Cycle AS C WITH(NOLOCK) ON emp.CycleID = C.Cycle_ID       /* WAGE */   INSERT INTO @tableValues    SELECT    WT.Id AS Cost_ID,    @transType_wage,    PE.FirstName,    PE.Surname,    PE.Employee_ID,    SH.SalaryHeadTitle AS TransactionType,    TT.TransactionTypeDesc,    (CAST(ISNULL(IRP5.IRP5CertCode, IRP5.IRP5Code) AS NVARCHAR) + ' - ' + IRP5.IRP5CodeDesc) AS [TransactionDesc],    WT.Amount,    NULL AS Filepath,    NULL AS IsBulk,    IRP5.IRP5Code,    WT.Unit,    WT.DateCaptured,    PE.EmployeeTypeID,    0,    C.CycleDesc   FROM Payroll_WageTransaction AS WT WITH(NOLOCK)   JOIN Payroll_Employee AS PE WITH(NOLOCK) ON WT.EmployeeId = PE.Employee_ID AND PE.Enabled = 1   JOIN Payroll_SalaryHead AS SH WITH(NOLOCK) ON WT.SalaryHeadId = SH.SalaryHead_ID AND SH.Enabled = 1   JOIN Payroll_IRP5Code AS IRP5 WITH(NOLOCK) ON IRP5.IRP5Code_ID = SH.IRP5CodeId and IRP5.Enabled = 1   JOIN Const_TransactionType AS TT WITH(NOLOCK) ON TT.TransactionType_ID = IRP5.TransactionTypeID AND TT.Enabled = 1   JOIN Const_Cycle AS C WITH(NOLOCK) ON PE.CycleID = C.Cycle_ID   WHERE WT.IsApproved = 0 AND WT.RejectedReason IS NULL AND WT.Enabled = 1     if (@IsTerminationRun = 0)   begin      select [ID] as [rownumber], [Cost_ID], [Type], [FirstName], [Surname], [Employee_ID], [TransactionType], [TransactionTypeDesc], [TransactionDesc], [Amount], [Filepath], [IsBulk], [IRP5Code], [hours], [Date], [EmployeeTypeID], [Escalated], Cycle       from @tableValues       where ([EmployeeTypeID] in(        select [EmployeeType_ID]         from [Const_EmployeeType_sys] as [C] with(nolock)          join @permissions as [P] on [P].[PermissionDesc] = [C].[EmployeeTypeDescription]         where ([ModuleID] = 3)        )       )     end   else    begin      select [ID] as [rownumber], [Cost_ID], [Type], [FirstName], [Surname], [Employee_ID], [TransactionType], [TransactionTypeDesc], [TransactionDesc], [Amount], [Filepath], [IsBulk], [IRP5Code], [hours], [Date], [EmployeeTypeID], [Escalated], Cycle       from @tableValues       where ([Employee_ID] = @EmployeeID)     end        end

GO

-- ============================================
-- SP: Payroll_GetTransactionTypeByEmployeeID_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL    -- Create date:  03 SEP 2013    -- Description:  Get Transaction Type and Transaction Type Description by employee     -- calls : Payroll_GetTransactionTypeByEmployeeID_sp 116,1    -- Seipei Mathole : TP:36018 added IRP5Code to display on the specific codes  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_GetTransactionTypeByEmployeeID_sp]      @EmployeeID INT ,      @TransactionTypeID INT  AS       BEGIN            IF ( @TransactionTypeID = 0 )               BEGIN                    SELECT DISTINCT                          CONST_TRANS.TRANSACTIONTYPE_ID AS TRANSACTIONTYPE_ID, CONST_TRANS.TRANSACTIONTYPEDESC AS TRANSACTIONTYPEDESC                  FROM    PAYROLL_EMPLOYEEPAYROLLDEFINITION AS PAY_DEF                          INNER JOIN dbo.Payroll_SalaryHead AS SH ON SH.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                          INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = SH.IRP5CodeId                          INNER JOIN dbo.CONST_TRANSACTIONTYPE AS CONST_TRANS ON CONST_TRANS.TRANSACTIONTYPE_ID = IRP5Code.TransactionTypeID                  WHERE   PAY_DEF.EMPLOYEEID = @EmployeeID                          AND PAY_DEF.Enabled = 1              END            ELSE               BEGIN                    SELECT DISTINCT                          PAY_DEF.EmployeePayrollDefinition_ID AS TRANSACTIONTYPE_ID, CONVERT(NVARCHAR, IRP5.IRP5Code) + ' - ' + SH.SalaryHeadTitle AS TRANSACTIONTYPEDESC                  FROM    PAYROLL_EMPLOYEEPAYROLLDEFINITION PAY_DEF                          INNER JOIN dbo.Payroll_SalaryHead AS SH ON SH.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                          INNER JOIN dbo.Payroll_IRP5Code AS IRP5Code ON IRP5Code.IRP5Code_ID = SH.IRP5CodeId                          INNER JOIN dbo.CONST_TRANSACTIONTYPE AS CONST_TRANS ON CONST_TRANS.TRANSACTIONTYPE_ID = IRP5Code.TransactionTypeID                          INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON SH.IRP5CodeId = IRP5.IRP5Code_ID                  WHERE   PAY_DEF.EMPLOYEEID = @EmployeeID                          AND IRP5Code.TransactionTypeID = @TransactionTypeID                          AND PAY_DEF.Enabled = 1        AND IRP5Code.IRP5Code IN (3704,3705,3715,3716)              END        END    

GO

-- ============================================
-- SP: Payroll_GetTrialRunEmployees
-- Schema: dbo
-- ============================================
 /*        Author        :     FERDI BOTHA        Create date   :     07/04/2017        Description   :     Get Trial Run Employees        Update by   :       FERDI BOTHA : 10/04/2017 - added the ability to distinguish between a single (employee payslip), batch trial and adhoc trial runs        Update by   :       FERDI BOTHA : 10/05/2017 - Changed the mappings for Method of Calculation        Update by   :       FERDI BOTHA : 04/07/2017 - Excluded the "hidden" Employee Type     Update by   :       Lungisani Khumalo : 22/08/2017 - Excluded the "Non-Employee" Employee Type     Update by   :       Ferdi Botha : 11/09/2017 - excluded the "Non-Employee" Employee Type based on Employee Type ID     Update by   :       Ferdi Botha : 16/02/2018 - excluded the "Non-Employee" Employee Type based on Position Non-Employee flag     Update by   :       Ferdi Botha : 15/07/2019 - added the Employee ID Number to the results for Payslip Password (Encryption)     Update by   :       Modiri Selao : 07/08/2019 - #88712 Notification if Trial Run fails due to no Earnings or Company Contribution Salary Transactions linked to the employee.(removed the "[TransactionTypeID] = 1" from the where clause */ CREATE procedure [dbo].[Payroll_GetTrialRunEmployees] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int as  begin    set nocount on;    Set @CycleModeID = (Select CycleModeID from Payroll_CyclePeriodDetails where Period_ID = @PeriodID)    delete from [Payroll_TrialRun_History_Employees] where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)    if (@CycleModeID = 1)   begin                insert into [Payroll_TrialRun_History_Employees]([Employee_ID], [Period_ID], [Cycle_ID], [CycleModeID], [EmpCode], [StartDate], [EndDate], [TaxYear], [Period])                       select distinct [Employee_ID], @PeriodID, @CycleID, @CycleModeID, [EmpCode], [PeriodStartDate], [PeriodEndDate], [CPD].[TaxYear], [PeriodInTaxYear]                             from [Payroll_Employee] as [PE] with(nolock)                                    join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeeID] = [PE].[Employee_ID] and [EPD].[Enabled] = 1                                    join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                                    join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1                                    join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = @PeriodID and [CPD].[CycleID] = [PE].[CycleID] and [CPD].[Enabled] = 1                                    left join (                                           select [EmployeeID], [EPR].[Enabled], [StartDate], [EndDate]                                                  from [Payroll_EmployeeHistory] as [EPH] with(nolock)                                                         join [Payroll_ReasonEmployeeChange] as [EPR] with(nolock) on [Reason_ID] = [ReasonID] and [EPR].[Enabled] = 1                                                  where (not [ReasonDescription] = 'Non-Employee' and not exists(                select [PositionHistory_ID]                 from [Payroll_PositionHistory] with(nolock)                 where ([PositionHistory_ID] = [EPH].[PositionHistoryID] and [IsNonEmployee] = 1)               )              )                                                         group by [EmployeeID], [ReasonID], [EPR].[Enabled], [StartDate], [EndDate]                                    ) as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[StartDate] <= [PeriodEndDate] and [PEH].[EndDate] >= [PeriodStartDate]                             where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and not [EmployeeTypeID] = 4 and [CycleModeID] = @CycleModeID and /*[TransactionTypeID] = 1 and*/ [IsDummy] = 0 and [JoiningDate] <= [PeriodEndDate] and [PE].[EndDate] >= [PeriodStartDate]) and not ([PE].[Enabled] = 0 and [PE].[EndDate] = '9999-12-31')    end   else if (@CycleModeID = 2)   begin              DECLARE @AdHocTerminationTypeId INT = 1;             DECLARE @AdHocTransactionTypeId INT = 2;             DECLARE @AdHocTerminationAdditionalId INT = 2;     insert into [Payroll_TrialRun_History_Employees]([Employee_ID], [Period_ID], [Cycle_ID], [CycleModeID], [EmpCode], [StartDate], [EndDate], [TaxYear], [Period])                       select distinct [Employee_ID], @PeriodID, @CycleID, @CycleModeID, [EmpCode], [PeriodStartDate], [PeriodEndDate], [CPD].[TaxYear], [PeriodInTaxYear]                             from [Payroll_CyclePeriodAdhocEmployee] as [AEMP] with(nolock)                                    join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [AEMP].[EmployeeID] and [EPD].[Enabled] = 1                                    join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                                    join [Payroll_CyclePeriodAdhocSalaryHead] as [ASH] with(nolock) on [SalaryHeadID] = [SH].[SalaryHead_ID] and [ASH].[Enabled] = 1                                    join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1                                    join [Payroll_Employee] as [PE] on [Employee_ID] = [AEMP].[EmployeeID]                                    join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = @PeriodID and [CPD].[Enabled] = 1                                    join (                                           select [EmployeeID], [EPR].[Enabled], [StartDate], [EndDate]                                                  from [Payroll_EmployeeHistory] as [EPH] with(nolock)                                                         join [Payroll_ReasonEmployeeChange] as [EPR] with(nolock) on [Reason_ID] = [ReasonID] and [EPR].[Enabled] = 1                                                  where (not [ReasonDescription] = 'Non-Employee' and not exists(                select [PositionHistory_ID]                 from [Payroll_PositionHistory] with(nolock)                 where ([PositionHistory_ID] = [EPH].[PositionHistoryID] and [IsNonEmployee] = 1)               )              )                                                         group by [EmployeeID], [ReasonID], [EPR].[Enabled], [StartDate], [EndDate]                                    ) as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[StartDate] <= [PeriodEndDate] and [PEH].[EndDate] >= [PeriodStartDate]                            where [AEMP].[EmployeeID] = (case @EmployeeID when 0 then [AEMP].[EmployeeID] else @EmployeeID end)                                  and not ISNULL([EmployeeTypeID], 0) = 4                                  and [CPD].[Period_ID] = [AEMP].[PeriodID]                                  and [CPD].[CycleID] = @CycleID                                 and [CPD].[CycleModeID] = @CycleModeID                                  and [AEMP].[Enabled] = 1                                  and [IsDummy] = 0                                  and [JoiningDate] <= [PeriodEndDate]                                  and (([PE].[EndDate] >= [PeriodStartDate] AND AdhocTypeID = @AdHocTransactionTypeId)                                      OR ([PE].[EndDate] BETWEEN [CPD].[PeriodStartDate] AND [CPD].[PeriodEndDate] AND AdhocTypeID = @AdHocTerminationTypeId)                                     OR ([PE].[EndDate] <= [CPD].[PeriodStartDate] AND CPD.AdhocTerminationTypeID = @AdHocTerminationAdditionalId))                                 and not ([AEMP].[Enabled] = 0 and [PE].[EndDate] = '9999-12-31')    end    select [PET].[Employee_ID], [PET].[Period_ID], [PET].[Cycle_ID], [PET].[CycleModeID], [PET].[EmpCode],       CASE WHEN Len([PE].[IdNo]) <> 0 THEN [PE].[IdNo] ELSE [PE].[PassportNumber] END AS [IdNo], [PET].[StartDate], [PET].[EndDate], [PET].[TaxYear], [PET].[Period]     from [Payroll_TrialRun_History_Employees] as [PET] with(nolock)      join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PET].[Employee_ID]     where ([PET].[Employee_ID] = (case @EmployeeID when 0 then [PET].[Employee_ID] else @EmployeeID end) and         [PET].[Period_ID] = @PeriodID and         [PET].[Cycle_ID] = @CycleID and         [PET].[CycleModeID] = @CycleModeID)         set nocount off;  end

GO

-- ============================================
-- SP: Payroll_GetUnSuccessfulCandidateList_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,06/09/2018>  -- Description: <Description,,Get Data for UnSuccessful Candidate list>  -- =============================================  CREATE PROCEDURE Payroll_GetUnSuccessfulCandidateList_sp    @AdvertId INT  AS  BEGIN   SET NOCOUNT ON;        SELECT DISTINCT PISE.EmployeeInterviewID, ProspectiveEmployee_ID, (ISNULL(PPE.FirstName,'')+ ' '+ ISNULL(ppe.SecondName,'')+ ' ' + ISNULL(ppe.Surname,'')) AS CandidateName,    InterviewDate,    cd.DepartmentDesc, cdd.DivisionDesc, pp.PositionDesc    FROM Payroll_CandidateShortListPage AS CS    INNER JOIN Payroll_EmployeeShortListPage AS PE ON PE.CandidateShortListId = CS.CandidateShortListID    INNER JOIN dbo.Payroll_ProspectiveEmployee AS PPE ON PPE.ProspectiveEmployee_ID = PE.ProspectiveEmployeeId    LEFT JOIN payroll_InterviewSchedule AS PIS ON PIS.AdvertId = CS.AdvertId    LEFT JOIN dbo.Payroll_InterviewScheduledEmployee AS PISE ON  PISE.InterviewScheduleId = PIS.InterviewScheduleID    LEFT JOIN dbo.Payroll_Advert AS PA ON pa.AdvertId = cs.AdvertId    LEFT OUTER JOIN dbo.Const_Department AS CD ON cd.Department_ID = pa.DepartmentId    LEFT OUTER JOIN dbo.Const_Division AS CDD ON cdd.Division_ID = pa.DivisionId    LEFT OUTER JOIN dbo.Payroll_Position AS PP ON pp.Position_ID = pa.PositionId    WHERE CS.AdvertId = @AdvertId AND PISE.IsSuccessFul = 0  END    

GO

-- ============================================
-- SP: Payroll_GetUpperLimitsResolve_sp
-- Schema: dbo
-- ============================================
  create procedure [Payroll_GetUpperLimitsResolve_sp]  as    begin     select [JobProfile_ID], [JobTitle], [OccupationLevel], [EmployeeTypeDescription] as [EmployeeType], [EmployeeSubtypeDesc] as [EmployeeSubtype]      from [Payroll_JobProfile] as [PJ] with(nolock)       left outer join [Const_OccupationLevel_sys] as [OL] with(nolock) on [OL].[OccupationLevel_ID] = [PJ].[JobFamily] and [OL].[Enabled] = 1       left outer join [Const_EmployeeType_sys] as [ET] with(nolock) on [ET].[EmployeeType_ID] = [PJ].[EmployeeTypeID] and [ET].[Enabled] = 1       left outer join [Payroll_EmployeeSubtypes] as [EST] with(nolock) on [EST].[EmployeeSubtype_ID] = [PJ].[EmployeeSubtypeID]      where ([PJ].[Enabled] = 1 and [PJ].[EmployeeTypeID] in(2, 3, 7) and (        [PJ].[LimitID] is null or not exists(         select top 1 [UpperLimit_ID] from [Payroll_UpperLimit] with(nolock) where ([UpperLimit_ID] = [PJ].[LimitID])        )       )      )    end  

GO

-- ============================================
-- SP: Payroll_GetVacantPositions_sp
-- Schema: dbo
-- ============================================
/*   -- Author  : Varun Parvataneni  -- Create date : 26/10/2016  -- Description : Get the VacantPosition from  Position table based on the datarange selected in employee screen  -- Call SP  : Payroll_GetVacantPositions_sp 8 ,'2017-04-08 00:00:00.000','9999-12-31 00:00:00.000'  -- Updated By : Ferdi Botha  -- Updated Date : 01/02/2017 - return vacant positions, even when the position end date is less than the employee end date          (but the position start date is less than or equal to the employee start date)  --Upadate Date  :26/01/2018 (By Lungisani Khumalo) - Add [IsNonEmployee]  --Upadate Date  :07/08/2019 (By Himil Modi #89948) - change the in the where condition for divisionid in from position history to position table.  --Upadate Date  :02/04/2020 (By Ilya Skavronskiy #28439) - change the in the where condition for startDate & endDate from position history to position table.  --Update Date   :08/04/2020 (RichaM) - change the where condition for Status from Position History table.  */  CREATE PROCEDURE dbo.Payroll_GetVacantPositions_sp @DivisionID int, @StartDate datetime, @EndDate datetime  AS  BEGIN      SELECT DISTINCT [Position_ID], [PositionDesc],[pos].[IsNonEmployee]          FROM [Payroll_Position] AS [pos] join [Payroll_PositionHistory] AS [posH] ON [Position_ID] = [posH].[PositionID]          WHERE ([pos].[DivisionID] = @DivisionID and [posH].[Status] = 1 and [Funds] = 1 and [posH].[StartDate] <= @Startdate and [posH].[EndDate] >= @StartDate)      END

GO

-- ============================================
-- SP: Payroll_GetVendorbyBenefitTypeId
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul panchal  -- Create date: 11 March 2014  -- Description: <Description,,>  -- call [Payroll_GetVendorbyBenefitTypeId] 3,1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GetVendorbyBenefitTypeId]   @BenefitTypeId INT      AS  BEGIN     SELECT DISTINCT V.VendorName,V.Vendor_ID FROM dbo.Payroll_BenefitDetail BD     INNER JOIN dbo.Cons_Vendor V         ON V.Vendor_ID = BD.VendorID       WHERE BenefitTypeID=@BenefitTypeId  END  

GO

-- ============================================
-- SP: Payroll_GetVendorListForEmployee
-- Schema: dbo
-- ============================================
-- Payroll_GetVendorListForEmployee 13  CREATE procedure [dbo].[Payroll_GetVendorListForEmployee]  @EmployeeId int  AS  BEGIN   SELECT DISTINCT cv.Vendor_ID, cv.VendorName    FROM Cons_Vendor cv     INNER JOIN Payroll_3rdPartyPayment emp on emp.VendorID = cv.Vendor_ID   WHERE emp.EmployeeID = @EmployeeId  END      

GO

