-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,15 Mar 2014>  -- Description: <Description,, Payroll_GrievanceDocumentDelete>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GrievanceDocumentDelete]   @DocumentName varchar(100),   @GrievanceId INT  AS  BEGIN   DELETE FROM Payroll_GrievanceDocumentDetails WHERE GrievanceId = @GrievanceId AND DocumentName = @DocumentName  END      

