-- ============================================
-- SP: Payroll_GrievanceWarningRpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,23 Mar 2014>  -- Description: <Description,,G>  -- Call SP:  Payroll_GrievanceWarningRpt_sp 4  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_GrievanceWarningRpt_sp]   @GrievanceId INT  AS  BEGIN   --SELECT * FROM Payroll_Grievance   SELECT P_E.FirstName + ' ' + P_E.Surname as Name, P_J.JobTitle, P_E.Employee_ID, chairman, (STUFF((SELECT ', ' + WitnessName FROM Payroll_GrievanceWitnessDetails b WHERE b.GrievanceId = P_Dis.Grievance_ID FOR XML PATH('')), 1, 2, '')) as Witness,    C_DOT.DisiplinaryOffenceType, FinalOutcome, --CONVERT(NVARCHAR, SanctionDate, 101) AS Sanction, CONVERT(NVARCHAR, PeriodOfEffect, 101) as PeriodOfEffect,    (STUFF((SELECT ', ' + DocumentName FROM Payroll_GrievanceDocumentDetails b WHERE b.GrievanceId = P_Dis.Grievance_ID FOR XML PATH('')), 1, 2, '')) as DocumentName, GETDATE() AS SystemDate,   P_Dis.Grievance_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Grievance_ID )), 8, '0') as GrievanceNo   FROM Payroll_Grievance as P_Dis   INNER JOIN Const_DisiplinaryOffenceType as C_DOT ON C_DOT.DisiplinaryOffenceType_ID = P_Dis.GrievanceOffenceTypeID   INNER JOIN Payroll_Employee as P_E ON P_E.Employee_ID = P_Dis.EmployeeSubmittedAgainstID   INNER JOIN Payroll_Position as PP ON PP.Position_ID = P_E.PositionID   LEFT OUTER JOIN Payroll_JobProfile AS P_J ON P_J.JobProfile_ID = PP.JobProfileID   WHERE P_Dis.Grievance_ID = @GrievanceId    END        

GO

-- ============================================
-- SP: Payroll_HolidayByMonthRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 08 JULY 2013  -- Description:    -- CALLS : [Payroll_HolidayByMonthRpt_sp] 3,'2015/2016','0', 0, 0, 4  -- 2015-06-15 TP20786 James Roodt: Now Filter according to CycleID, also respaced code to make it more readable  -- 2016-01-06 TP29885 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_HolidayByMonthRpt_sp]      @Month INT ,      @FinancialYear NVARCHAR(50) ,      @LEAVETYPE NVARCHAR(50) ,      @EmployeeId INT ,      @DepartmentId INT ,      @CycleId INT  AS       BEGIN  --DECLARE @MONTHNAME NVARCHAR(50)          DECLARE @FROMDATE DATETIME          DECLARE @TODATE DATETIME  --SET @MONTHNAME = (SELECT dbo.GetMonthNameFromId(@Month))    --PRINT @MONTHNAME          SELECT  @FROMDATE = PeriodStartDate, @TODATE = PeriodEndDate, @Month = PeriodInTaxYear          FROM    Payroll_CyclePeriodDetails          WHERE   TaxYear = @FinancialYear                  AND DATEPART(MONTH, PeriodStartDate) = @Month                  AND CycleID = @CycleId          ORDER BY Period_ID          PRINT @Month          IF ( @LEAVETYPE != '0' )               BEGIN                    SELECT DISTINCT                          @FROMDATE AS FROMDATE,         @TODATE AS TODATE,         ISNULL(PAY_EMP.FirstName, ' ') + ' ' + ISNULL(PAY_EMP.SecondName, ' ') + ' ' + ISNULL(PAY_EMP.Surname, ' ') AS EmployeeName,         dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo,         ISNULL(PAY_EMP.EmpCode, '') AS EmpCode,        ISNULL(( SELECT    PAY_EMP_ATT.[1]            FROM      Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )             AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )             AND ( PAY_EMP_ATT.Month = @Month )             AND PAY_EMP_ATT.[1] IN ( @LEAVETYPE )           ), '') AS '1',         ISNULL(( SELECT  PAY_EMP_ATT.[2]             FROM    Payroll_EmployeeAttendance PAY_EMP_ATT             WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )               AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )               AND ( PAY_EMP_ATT.Month = @Month )               AND PAY_EMP_ATT.[2] IN ( @LEAVETYPE )           ), '') AS '2',         ISNULL(( SELECT    PAY_EMP_ATT.[3]           FROM      Payroll_EmployeeAttendance PAY_EMP_ATT           WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )               AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )               AND ( PAY_EMP_ATT.Month = @Month )               AND PAY_EMP_ATT.[3] IN ( @LEAVETYPE )            ), '') AS '3',         ISNULL(( SELECT  PAY_EMP_ATT.[4]            FROM    Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )              AND ( PAY_EMP_ATT.Month = @Month )              AND PAY_EMP_ATT.[4] IN ( @LEAVETYPE )           ), '') AS '4',          ISNULL(( SELECT    PAY_EMP_ATT.[5]             FROM      Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )             AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )             AND ( PAY_EMP_ATT.Month = @Month )             AND PAY_EMP_ATT.[5] IN ( @LEAVETYPE )           ), '') AS '5',         ISNULL(( SELECT  PAY_EMP_ATT.[6]                                      FROM    Payroll_EmployeeAttendance PAY_EMP_ATT                                      WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[6] IN ( @LEAVETYPE )                                        ), '') AS '6',          ISNULL(( SELECT    PAY_EMP_ATT.[7]                                      FROM      Payroll_EmployeeAttendance PAY_EMP_ATT                                      WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[7] IN ( @LEAVETYPE )                                  ), '') AS '7',         ISNULL(( SELECT  PAY_EMP_ATT.[8]            FROM    Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )              AND ( PAY_EMP_ATT.Month = @Month )              AND PAY_EMP_ATT.[8] IN ( @LEAVETYPE )             ), '') AS '8',         ISNULL(( SELECT    PAY_EMP_ATT.[9]              FROM      Payroll_EmployeeAttendance PAY_EMP_ATT              WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )               AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )               AND ( PAY_EMP_ATT.Month = @Month )               AND PAY_EMP_ATT.[9] IN ( @LEAVETYPE )            ), '') AS '9',         ISNULL(( SELECT  PAY_EMP_ATT.[10]            FROM    Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )              AND ( PAY_EMP_ATT.Month = @Month )              AND PAY_EMP_ATT.[10] IN ( @LEAVETYPE )             ), '') AS '10',         ISNULL(( SELECT   PAY_EMP_ATT.[11]                                      FROM     Payroll_EmployeeAttendance PAY_EMP_ATT                                      WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )             AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )             AND ( PAY_EMP_ATT.Month = @Month )             AND PAY_EMP_ATT.[11] IN ( @LEAVETYPE )           ), '') AS '11',         ISNULL(( SELECT    PAY_EMP_ATT.[12]            FROM      Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )             AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )             AND ( PAY_EMP_ATT.Month = @Month )             AND PAY_EMP_ATT.[12] IN ( @LEAVETYPE )          ), '') AS '12',         ISNULL(( SELECT PAY_EMP_ATT.[13]                                    FROM   Payroll_EmployeeAttendance PAY_EMP_ATT                                    WHERE  ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                           AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                           AND ( PAY_EMP_ATT.Month = @Month )                                           AND PAY_EMP_ATT.[13] IN ( @LEAVETYPE )                                  ), '') AS '13',           ISNULL(( SELECT  PAY_EMP_ATT.[14]                                  FROM    Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[14] IN ( @LEAVETYPE )                              ), '') AS '14',         ISNULL(( SELECT   PAY_EMP_ATT.[15]                                  FROM     Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[15] IN ( @LEAVETYPE )                                  ), '') AS '15',         ISNULL(( SELECT    PAY_EMP_ATT.[16]                                  FROM      Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[16] IN ( @LEAVETYPE )                                     ), '') AS '16',        ISNULL(( SELECT PAY_EMP_ATT.[17]                                  FROM   Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE  ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[17] IN ( @LEAVETYPE )                                  ), '') AS '17',         ISNULL(( SELECT  PAY_EMP_ATT.[18]                                   FROM    Payroll_EmployeeAttendance PAY_EMP_ATT                                   WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )            AND ( PAY_EMP_ATT.Month = @Month )            AND PAY_EMP_ATT.[18] IN ( @LEAVETYPE )          ), '') AS '18',         ISNULL(( SELECT   PAY_EMP_ATT.[19]                                  FROM     Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[19] IN ( @LEAVETYPE )                                  ), '') AS '19',         ISNULL(( SELECT    PAY_EMP_ATT.[20]                                  FROM      Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[20] IN ( @LEAVETYPE )                                  ), '') AS '20',         ISNULL(( SELECT PAY_EMP_ATT.[21]                                  FROM   Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE  ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[21] IN ( @LEAVETYPE )                                  ), '') AS '21',         ISNULL(( SELECT  PAY_EMP_ATT.[22]            FROM    Payroll_EmployeeAttendance PAY_EMP_ATT            WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )              AND ( PAY_EMP_ATT.Month = @Month )              AND PAY_EMP_ATT.[22] IN ( @LEAVETYPE )          ), '') AS '22',         ISNULL(( SELECT   PAY_EMP_ATT.[23]          FROM     Payroll_EmployeeAttendance PAY_EMP_ATT          WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )            AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )            AND ( PAY_EMP_ATT.Month = @Month )            AND PAY_EMP_ATT.[23] IN ( @LEAVETYPE )          ), '') AS '23',         ISNULL(( SELECT    PAY_EMP_ATT.[24]                                  FROM      Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[24] IN ( @LEAVETYPE )                              ), '') AS '24',         ISNULL(( SELECT PAY_EMP_ATT.[25]          FROM   Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE  ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[25] IN ( @LEAVETYPE )                                  ), '') AS '25',         ISNULL(( SELECT  PAY_EMP_ATT.[26]                                  FROM    Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[26] IN ( @LEAVETYPE )          ), '') AS '26',         ISNULL(( SELECT   PAY_EMP_ATT.[27]                                  FROM     Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[27] IN ( @LEAVETYPE )                                  ), '') AS '27',         ISNULL(( SELECT    PAY_EMP_ATT.[28]                                  FROM      Payroll_EmployeeAttendance PAY_EMP_ATT                                  WHERE     ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                              AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                              AND ( PAY_EMP_ATT.Month = @Month )                                              AND PAY_EMP_ATT.[28] IN ( @LEAVETYPE )                                                  ), '') AS '28',         ISNULL(( SELECT PAY_EMP_ATT.[29]                                  FROM   Payroll_EmployeeAttendance PAY_EMP_ATT          WHERE  ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )            AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )            AND ( PAY_EMP_ATT.Month = @Month )            AND PAY_EMP_ATT.[29] IN ( @LEAVETYPE )            ), '') AS '29',           ISNULL(( SELECT  PAY_EMP_ATT.[30]                              FROM    Payroll_EmployeeAttendance PAY_EMP_ATT                              WHERE   ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                      AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                      AND ( PAY_EMP_ATT.Month = @Month )           AND PAY_EMP_ATT.[30] IN ( @LEAVETYPE )                             ), '') AS '30',         ISNULL(( SELECT   PAY_EMP_ATT.[31]                              FROM     Payroll_EmployeeAttendance PAY_EMP_ATT                              WHERE    ( PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID )                                          AND ( PAY_EMP_ATT.TaxYear = @FinancialYear )                                          AND ( PAY_EMP_ATT.Month = @Month )                                          AND PAY_EMP_ATT.[31] IN ( @LEAVETYPE )                                  ), '') AS '31'                  FROM    Payroll_Employee PAY_EMP                          INNER JOIN Payroll_EmployeeAttendance PAY_EMP_ATT ON PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID                          INNER JOIN dbo.Payroll_Position AS PP ON PAY_EMP.PositionID = PP.Position_ID                  WHERE   PAY_EMP_ATT.Month = @Month                          AND PAY_EMP_ATT.TaxYear = @FinancialYear                          AND ( PAY_EMP.Employee_ID = @EmployeeId                                OR @EmployeeId = 0                              )                          AND ( PP.DepartmentID = @DepartmentId                                OR @DepartmentId = 0                              )              END          ELSE               BEGIN                  SELECT  @FROMDATE AS FROMDATE, @TODATE AS TODATE,       ISNULL(PAY_EMP.FirstName, ' ') + ' ' + ISNULL(PAY_EMP.SecondName, ' ') + ' ' + ISNULL(PAY_EMP.Surname, ' ') AS EmployeeName,       dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo,       ISNULL(PAY_EMP.EmpCode, '') AS EmpCode,      PAY_EMP_ATT.[1], PAY_EMP_ATT.[2], PAY_EMP_ATT.[3], PAY_EMP_ATT.[4], PAY_EMP_ATT.[5], PAY_EMP_ATT.[6], PAY_EMP_ATT.[7], PAY_EMP_ATT.[8], PAY_EMP_ATT.[9], PAY_EMP_ATT.[10],       PAY_EMP_ATT.[11], PAY_EMP_ATT.[12], PAY_EMP_ATT.[13], PAY_EMP_ATT.[14], PAY_EMP_ATT.[15], PAY_EMP_ATT.[16], PAY_EMP_ATT.[17], PAY_EMP_ATT.[18], PAY_EMP_ATT.[19],       PAY_EMP_ATT.[20], PAY_EMP_ATT.[21], PAY_EMP_ATT.[22], PAY_EMP_ATT.[23], PAY_EMP_ATT.[24], PAY_EMP_ATT.[25], PAY_EMP_ATT.[26], PAY_EMP_ATT.[27], PAY_EMP_ATT.[28],       PAY_EMP_ATT.[29], PAY_EMP_ATT.[30], PAY_EMP_ATT.[31]                  FROM    Payroll_Employee PAY_EMP                          INNER JOIN Payroll_EmployeeAttendance PAY_EMP_ATT ON PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID                          INNER JOIN dbo.Payroll_Position AS PP ON PAY_EMP.PositionID = PP.Position_ID                  WHERE   PAY_EMP_ATT.Month = @Month                          AND PAY_EMP_ATT.TaxYear = @FinancialYear         AND ( PAY_EMP.CycleID = @CycleId                                OR @CycleId = 0                              )                          AND ( PAY_EMP.Employee_ID = @EmployeeId                                OR @EmployeeId = 0                              )                          AND ( PP.DepartmentID = @DepartmentId                                OR @DepartmentId = 0                              )              END        END       

GO

-- ============================================
-- SP: Payroll_IMP5BiAnnualRunRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 02 DEC 2013  -- Description:  GET IRP5 CODE DETAILS  -- Call SP:  [Payroll_IMP5BiAnnualRunRpt_sp] 'BiAnnual', '2015/2016', 4,0,0,1  -- Call SP:  [Payroll_IMP5BiAnnualRunRpt_sp] 'Annual', '2015/2016', 4, 0, 0, 1   -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-11-17 : suriKandukuri : modified tax report validations.  -- 2016-03-29 :Varun parvataneni modified for the IRP5 Certificate  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  CREATE procedure [Payroll_IMP5BiAnnualRunRpt_sp]   @PeriodType NVARCHAR(50),   @FinancialYear NVARCHAR(50),   @CycleId INT,   @EmployeeID INT,   @Export BIT,   @UserId INT  AS  BEGIN    DECLARE @Period TABLE (PeriodID INT)   DECLARE @CodeTotal TABLE (Total BIGINT)       DECLARE @FromDate DATETIME, @ToDate DATETIME, @TYear NVARCHAR(50), @Month NVARCHAR(2), @SumOfCode BIGINT = 0   SELECT TOP 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE CycleID = 1 AND TaxYear = @FinancialYear ORDER BY Period_ID      IF @PeriodType = 'Annual' BEGIN    SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate))    SET @Month = '02'   END   ELSE BEGIN    SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate))    SET @Month = '08'   END      IF @Export = 0 BEGIN    DELETE FROM dbo.Payroll_TaxCertificateExportHistory WHERE FinYear = @FinancialYear   END      IF NOT EXISTS (SELECT * FROM dbo.Payroll_TaxCertificateExportHistory WHERE FinYear = @FinancialYear AND CycleID = @CycleId) BEGIN    INSERT INTO dbo.Payroll_TaxCertificateExportHistory ( FinYear, CycleID, DateCaptured, CapturerID )    VALUES  ( @FinancialYear, -- FinYear - varchar(50)        @CycleId, -- CycleID - int        GETDATE(), -- DateCaptured - datetime        @UserId -- CapturerID - int        )   END      PRINT @FromDate   PRINT @ToDate      SELECT TOP 1 @TYear = Data FROM dbo.Split(@FinancialYear, '/') ORDER BY Id DESC      DECLARE @History TABLE (Id INT IDENTITY(1, 1), CycleId INT)   DECLARE @Start INT = 1, @End INT, @CertyNo INT = 0      INSERT INTO @History ( CycleId )   SELECT CycleID FROM dbo.Payroll_TaxCertificateExportHistory WHERE FinYear = @FinancialYear   ORDER BY ID      SELECT @End = COUNT(1) FROM @History      /*Employer*/   DECLARE @Result TABLE(Id INT IDENTITY(1, 1),Code BIGINT,TotalValue Decimal(36,2),Result NVARCHAR(MAX))   INSERT INTO @Result(Code,TotalValue,Result)   SELECT (2010+2015+2020+2022+2024+2025+2026+2027+2028+2030+2031+2082+2083+2035+2062 +2063 +2064+2065+2066+2080+9999),0,'2010'+',"'+CONVERT(VARCHAR(MAX), ISNULL(MunicipalityName,''))+'",'   +'2015'+',"LIVE"'+''+','   +'2020'+','+CONVERT(VARCHAR(MAX), ISNULL(PayeRegistrationNo,''))+','   +'2022'+ ',"'+CONVERT(VARCHAR(MAX), ISNULL(SDLReferenceNo,''))+'",'   +'2024'+',"'+CONVERT(VARCHAR(MAX), ISNULL(UIFReferenceNo,''))+'",'   +'2025'+',"'+ISNULL(SARSPersonName, '')+' '+ISNULL(SARSPersonSurname, '')+'",'   +'2026'+',"'+ISNULL(replace(SARSContactNo,' ',''), '')+'",'   +'2027'+',"'+CONVERT(VARCHAR(MAX), ISNULL(SARSEmailAddress,''))+'",'   +'2028'+','+'"SEBATA FMS"'+','   +'2030'+','+@TYear+','   +'2031'+','+CONVERT(VARCHAR(50), (DATEPART(YEAR, @ToDate)))+ @Month+',' -- 201402   +'2082'+',"'+(SELECT KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'EmployerSIC7Code')+'",'   +'2083'+',"'+(SELECT KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'EmployerSEZCode')+'",'   +'2035'+','+(SELECT KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'EmployerTradeClassification')+','   --optional   --+'2061'+',"'+ISNULL(PhyAddress1, '')+'",'   +'2062'+',"'+ISNULL(PhyAddress2, '')+'",'   +'2063'+',"",'   +'2064'+',"'+ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PhySuburb), '')+'",'   +'2065'+',"'+ISNULL(P.ProvinceDesc,'')+'",'   +'2066'+',"'+ISNULL(T.Town,'')+'",'   +'2080'+','+CONVERT(VARCHAR(MAX), ISNULL(PhyPostalCode,''))+','   +'9999' FROM Payroll_Municipality AS M   LEFT OUTER JOIN dbo.Const_Town AS T ON M.PhyCityID = T.Town_ID   LEFT OUTER JOIN dbo.Const_Province AS P ON M.PhyProvinceID = P.Province_ID      WHILE @Start <= @End BEGIN             SELECT @CertyNo = COUNT(1) - 1 FROM @Result        SELECT @CycleId = CycleId FROM @History WHERE Id = @Start        DELETE FROM @Period        INSERT INTO @Period    SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE PeriodEndDate BETWEEN @FromDate AND @ToDate AND CycleID = @CycleId           /*Employee*/    INSERT INTO @Result(code,TotalValue,Result)    SELECT DISTINCT (SELECT 3010+3015+3020+3025+3026+3030+3040+3050+3060 + 3070  + 3075  +3080+3100+3263+3264+ 3125 +3135 + 3136 +      3137 +3138+3144 + 3145 +3146+ 3147  + 3148  + 3149  + 3150  +3160+3170+3180+3200+3210 +3211+ 3212  +3213+ 3214  + 3215+ 3216  +     3217 + 3218 + 3247 + 3249  + 3240 + 3241 + 3242 + 3243 + 3244 + 3245 + 3246 +         3696 + 3697 +3698 +4497 + 4102 + 4141 + 4142 + 4149 +4118+     + case when isnull(EMP.PostalSameAsPhysical,0) = 0 and EMP.PostalAddressTypeID  = 1 then     3258  +3259+3260  +3261     else     0     end     +     ISNULL(    (SELECT SUM(IRP5Code) from (select distinct (CAST(IRP5Code AS BIGINT )) IRP5Code    FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE DEF.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period) AND TransactionTypeID = 1     AND IRP5Code NOT IN ('3696', '3697', '3698', '0000')      group by IRP5Code     )b    ), 0)+         +ISNULL(    (SELECT SUM(IRP5Code)    from (    select distinct CAST(IRP5Code AS BIGINT ) as IRP5Code FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE DEF.EmployeeID = emp.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)     AND TransactionTypeID = 2 AND IRP5Code NOT IN ('4004','0000', '4101','4102','4115','4116','4141','4149','4997')    )a      ), 0)+         (CASE WHEN ISNULL(    (SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    AND HEAD.SalaryHeadName = 'Medical aid'    ), 0) > 0 THEN 4116 ELSE 0 END)+        (CASE WHEN ISNULL(    (SELECT CAST(ROUND(SUM(Amount), 0) AS DECIMAL) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    AND HEAD.SalaryHe