yeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    AND TransactionTypeID IN (2)    and IRP5code not in ('0000','4102','4141')    ), 0)    )+','    --+'4101'+','+''+','    +'4102'+','+CONVERT(VARCHAR(50), ISNULL(    (SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    AND SalaryHeadName = 'Pay as you Earn'    ), 0)    )+','    --+'4115'+','+CONVERT(VARCHAR(50), ISNULL(    --(SELECT CAST(ROUND(SUM(Amount), 0) AS DECIMAL) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    --INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    --INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    --INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    --INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    --WHERE PAY_EMP.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    --AND IRP5.IRP5Code IN ('3901', '3915', '3920', '3921', '3922')    --), 0)    --)+','    --+'4115'+','+''+','    +'4141'+','+CONVERT(VARCHAR(50), ISNULL(    (SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID AND PAY_EMP.PeriodID IN (SELECT PeriodID FROM @Period)    AND HEAD.SalaryHeadName = 'UIF'    ), 0)    )+','    +'4142'+','+CONVERT(VARCHAR(50), ISNULL(    (SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM dbo.Payroll_EmployeePayslip AS PAY_EMP    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN 

