-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,22 Mar 2014>  -- Description: <Description,, Insert Leave Details>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_InsertLeaveApproveDetails]   @LeaveApproveRequestId INT,   @FromDate DATETIME,   @ToDate DATETIME  AS  BEGIN   DECLARE @EmployeeID INT   SELECT @EmployeeID = EmployeeID FROM Payroll_LeaveApproveRequest WHERE LeaveApproveRequest_ID = @LeaveApproveRequestId     IF EXISTS (SELECT * FROM Payroll_LeaveApproveRequestDetails WHERE LeaveApproveRequestId = @LeaveApproveRequestId) BEGIN    DELETE FROM Payroll_LeaveApproveRequestDetails WHERE LeaveApproveRequestId = @LeaveApproveRequestId AND IsTaken = 0   END     INSERT INTO Payroll_LeaveApproveRequestDetails (LeaveApproveRequestId, LeaveDate, IsApproved, IsTaken)   SELECT @LeaveApproveRequestId, WorkingDate, 0, 0 FROM dbo.[GetEmpWorkingDatesByFromAndToDate](@EmployeeID, @FromDate, @ToDate)       END    

GO

-- ============================================
-- SP: Payroll_Instalments_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:Varun Parvataneni  -- Description : To Generate Instalment's reports on employee for selected dates  -- Create date: 7 APR 2016  -- CALLS : Payroll_Instalments_sp  '2015-03-01','2017-02-28',0,0,0,4   -- 2016-04-22 TP#35825 James Roodt: Corrected VendorName  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2021-11-05 WI77992 - Ruan - Correct filter and joins  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_Instalments_sp]    @FromDate DATETIME,   @ToDate DATETIME,   @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT,   @CycleID INT,   @ExcessValue FLOAT  AS  BEGIN   SELECT DISTINCT    pph.[EmployeeID],    dbo.BufferString_fxn(CONVERT(VARCHAR,(pph.[EmployeeID])), 8, '0') AS 'EmployeeNumber',    e.[Surname] AS 'EmployeeSurname',    e.[FirstName],    pph.[TotalAmount] AS 'TotalAmount',    pph.[Periods] AS 'PeriodofIstalment',    pph.[EMI] AS 'InstalmenstsAmount',    pph.[Balance] AS 'Balance',    pph.[ReferenceNo] AS 'ReferenceNumber',    v.[VendorName] AS 'Creditor',    cpd.[PeriodStartDate]   FROM    Payroll_3rdPartyPaymentHistory pph   INNER JOIN    Payroll_CyclePeriodDetails cpd ON pph.[ProcessedOnPeriodId] = cpd.[Period_ID]             AND cpd.[Enabled] = 1             AND cpd.[PeriodStartDate] BETWEEN @FromDate AND @ToDate   INNER JOIN    Payroll_Employee e ON pph.[EmployeeID] = e.[Employee_ID]   CROSS APPLY    (     SELECT TOP 1      peh.[DepartmentID], peh.[DivisionID]     FROM      Payroll_EmployeeHistory peh     WHERE      peh.[Enabled] = 1     AND peh.[EmployeeID] = pph.[EmployeeID]     AND (ISNULL(@CycleID, 0) = 0 OR peh.[CycleID] = @CycleID)     AND (ISNULL(@DepartmentId, 0) = 0 OR peh.[DepartmentID] = @DepartmentId)     AND (ISNULL(@DivisionId, 0) = 0 OR peh.[DivisionID] = @DivisionId)     AND peh.[StartDate] BETWEEN @FromDate AND @ToDate    ) eh   INNER JOIN    Const_Department d ON eh.[DepartmentID] = d.[Department_ID]   INNER JOIN    Const_Division div ON eh.[DepartmentID] = div.[DepartmentID]   INNER JOIN    Cons_Vendor v ON pph.[VendorID] = v.[Vendor_ID]   WHERE    pph.[Enabled] = 1   AND (ISNULL(@EmployeeID, 0) = 0 OR pph.[EmployeeID] = @EmployeeID)   AND (ISNULL(@ExcessValue, 0) = 0 OR pph.[EMI] > @ExcessValue)   ORDER BY    pph.[EmployeeID], cpd.[PeriodStartDate];   END

GO

-- ============================================
-- SP: Payroll_InvoiceDetailsById
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_InvoiceDetailsById 2  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_InvoiceDetailsById]   @InvoiceId INT  AS  BEGIN   SELECT InvoiceDetail_ID, InvoiceID, Amount AS InvoiceAmount, EmpCode, Employee_ID,    dbo.BufferString_fxn(CONVERT(VARCHAR, ( P_E.Employee_ID )), 8,'0') AS EmpNo,    FirstName, Surname, FirstName + ' ' + Surname AS FullName, IdNo, PassportNumber,   ApprovedDate, CancelReason, VS.Status   FROM dbo.SCM_InvoiceDetail AS INV_D   LEFT OUTER JOIN dbo.Payroll_Employee AS P_E ON P_E.Employee_ID = INV_D.ApprovedBy   INNER JOIN dbo.Const_SCMVendorStatus_sys AS VS ON VS.Status_ID = INV_D.StatusID   WHERE InvoiceID = @InvoiceId  END  

GO

-- ============================================
-- SP: Payroll_InvoicePrint_rpt
-- Schema: dbo
-- ============================================
      -- =====================================================================================================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,12 Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_InvoicePrint_rpt 17  -- 2015-11-17 TP28291 Ravindra Jijotia: Added check to display N.A if column value is Null  -- =====================================================================================================================    CREATE PROCEDURE [dbo].[Payroll_InvoicePrint_rpt] @InvoiceId INT  AS       BEGIN          SELECT VendorInvoiceNumber     ,InvoiceDate     ,ISNULL(VendorNumber, 'N.A.') AS VendorNumber     ,ISNULL(VendorName, 'N.A.') AS CompanyName     ,VendorTypeDesc AS VendorClassification     ,ISNULL(CompanyTypeDescription, 'N.A.') AS CompanyTypeName     --,C_V.PhysicalAddress1 + ' ' + C_V.PhysicalAddress2 AS VendorAddress     ,CASE WHEN (DATALENGTH(LTRIM(ISNULL(PhysicalAddress1 + ' ','') + ISNULL(PhysicalAddress1 +' ',''))) = 0) THEN 'N.A.'            ELSE LTRIM(ISNULL(PhysicalAddress1 + ' ','') + ISNULL(PhysicalAddress1 +' ',''))      END AS VendorAddress     ,(      SELECT MunicipalityName      FROM Payroll_Municipality      ) AS MunicipalityName     ,(      SELECT dbo.GetMuncipalityAddress()      ) AS MuncipalityAddress     ,(      SELECT dbo.GetMuncipalityContact()      ) AS ContactDetails    FROM dbo.SCM_Invoice AS INV    INNER JOIN dbo.Cons_Vendor AS C_V ON INV.VendorCreditorID = C_V.Vendor_ID    LEFT OUTER JOIN dbo.Const_CompanyType AS C_CT ON C_CT.CompanyType_ID = C_V.CompanyTypeID    INNER JOIN Const_VendorTypes CT ON C_V.VendorTypeID=CT.VendorType_ID    WHERE Invoice_ID = @InvoiceId      END  

GO

-- ============================================
-- SP: Payroll_IRP5CodeList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 15 JULY 2013  -- Description:    -- CALLS : Payroll_IRP5CodeList_sp '',''  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_IRP5CodeList_sp]    @IRP5Code  NVARCHAR(50),   @IRP5CodeDesc NVARCHAR(50)  AS  BEGIN    SELECT       PAY_IRP.IRP5Code_ID     ,PAY_IRP.IRP5Code     ,PAY_IRP.IRP5CodeDesc     ,PAY_IRP.Formula     ,PAY_IRP.Rules     ,CASE WHEN (PAY_IRP.Enabled =1) THEN       'TRUE'      ELSE       'FALSE'      END AS STATUS     ,PAY_IRP.DateCaptured     ,PAY_IRP.CapturerID     ,PAY_IRP.DateModified     ,PAY_IRP.ModifierID      ,ISNULL(CT.TransactionTypeDesc,'') AS TransactionType         ,     CASE WHEN (PAY_IRP.TaxableID = 1) THEN       'Taxable'      ELSE       'Non Taxable'      END AS TaxSTATUS      ,PAY_IRP.TatxablePercentage     FROM Payroll_IRP5Code PAY_IRP     LEFT OUTER JOIN dbo.Const_TransactionType CT ON CT.TransactionType_ID = PAY_IRP.TransactionTypeID     WHERE      (IRP5CodeDesc = @IRP5CodeDesc OR @IRP5CodeDesc ='' ) AND     ( IRP5Code = @IRP5Code OR @IRP5Code ='')  END  

GO

-- ============================================
-- SP: Payroll_IRP5ReportPerEmployee_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Suri Kandukuri  -- Create date: 18 Dec 2015  -- Description: <Description,,>  -- calls : [Payroll_IRP5ReportPerEmployee_sp] 8,'2014/2015',1,'employee','',''  -- 2016-01-06 Suri Kandukuri : Added Employee Code  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_IRP5ReportPerEmployee_sp]   @CalendarMonth int = 8,   @TaxYear NVARCHAR(50)='2014/2015',   @PayrollCycleId INT=1,    @SortIndex nvarchar(100) = 'employee',   @FromRange nvarchar(250)='',   @ToRange nvarchar(250)=''    as  BEGIN    DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME,@Cycle nvarchar(250)         DECLARE @Period TABLE (Period_Id INT, PeriodEndDate datetime)    INSERT INTO @Period    SELECT Period_ID, cast(PeriodEndDate AS DATE) FROM dbo.Payroll_CyclePeriodDetails     WHERE DATEPART(MONTH, PeriodStartDate) = @CalendarMonth AND TaxYear = @TaxYear AND (CycleID = @PayrollCycleId OR @PayrollCycleId = 0)       SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID in (select Period_Id from @Period)      select @Cycle = CycleDesc from Const_Cycle where Cycle_ID = @PayrollCycleId    /*Employee*/      if(isnull(@FromRange,'') <> '')    begin     set @FromRange = convert(int,@FromRange)       end    else       set @FromRange = convert(int,0)      if(isnull(@ToRange,'') <> '')    begin           set @ToRange = convert(int,@ToRange)    end    else       set @ToRange = convert(int,0)          --INSERT INTO @Result(code,TotalValue,Result)    select distinct dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.EmployeeID )), 8,'0') AS EmpNo,emp.Surname + ''+emp.FirstName EmployeeName,IRP5Code,IRP5CodeDesc    ,isnull(emp.EmpCode,'') EmpCode    ,isnull((select sum(Amount) from  dbo.Payroll_EmployeePayslip AS PAY_EMP1     INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF1 ON PAY_EMP1.PayrollDefinationID = DEF1.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD1 ON DEF1.PayrollSalaryHeadID = HEAD1.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP51 ON HEAD1.IRP5CodeId = IRP51.IRP5Code_ID    where PAY_EMP1.EmployeeID = PAY_EMP.EmployeeID and IRP51.IRP5Code_ID = IRP5.IRP5Code_ID     AND PAY_EMP1.PeriodID IN (select Period_Id from @Period)      and head1.IsRFI = head.IsRFI    ),0) CurrentMonth,    isnull(sum(Amount),0) TotalsToDate,case when head.IsRFI = 1 then 'Yes' else 'No' end RFI    ,@PeriodStartDate PeriodStartDate,@PeriodEndDate PeriodEndDate,@Cycle CycleDesc    FROM dbo.Payroll_Employee AS EMP    inner join dbo.Payroll_EmployeePayslip AS PAY_EMP on emp.Employee_ID = PAY_EMP.EmployeeID    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID --AND PAY_EMP.PeriodID IN (229) --(SELECT PeriodID FROM @Period)       and emp.Enabled = 1 and EMP.IsDummy =0       and(case when upper(@SortIndex) = upper('Employee')  then                  case when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) = 0 then 1              when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) = 0 and  emp.Employee_ID >= convert(int,@FromRange) then 1           when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) <> 0 and emp.Employee_ID <= convert(int,@ToRange) then 1           when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) <> 0 and  emp.Employee_ID >= convert(int,@FromRange) and emp.Employee_ID <= convert(int,@ToRange)  then 1           else 0 end         when upper(@SortIndex) = upper('IRP5 Code')  then       case when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) = 0 then 1              when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) = 0 and CONVERT(int,irp5.IRP5Code) >= isnull(@FromRange,0) then 1           when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) <> 0 and CONVERT(int,irp5.IRP5Code) <= isnull(@ToRange,0)  then 1           when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) <> 0 and CONVERT(int,irp5.IRP5Code) > = isnull(@FromRange,0)  and CONVERT(int,irp5.IRP5Code) <= isnull(@ToRange,0) then 1           else 0 end           else 1           end =1)              and convert(int,IRP5Code) >= 3601 and convert(int,irp5code) <= 4497          and Pay_emp.TaxYear = @TaxYear              group by pay_emp.EmployeeID,emp.EmpCode,emp.Surname + ''+emp.FirstName,IRP5Code_ID ,IRP5Code,IRP5CodeDesc,head.IsRFI       order by dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.EmployeeID )), 8,'0'),IRP5Code           END  

GO

-- ============================================
-- SP: Payroll_IRP5Reports_sp
-- Schema: dbo
-- ============================================
  /*-- =============================================  Create date: 29/03/2016  Name: varun parvataneni  Description:  GET IRP5 CODE DETAILS TO GENERATE IRP5 CERTIFICATE PER EACH EMPLOYEE  Call SP:  [Payroll_IRP5Reports_sp] 'BiAnnual', '2015/2016', 1030, 630, 0, 1   Call SP:  [Payroll_IRP5Reports_sp] 'February', '2016/2017', 3,1  15/10/2016    Maulik Peshavariya        Update sp for report generation  =============================================*/    CREATE PROCEDURE [dbo].[Payroll_IRP5Reports_sp]      @PeriodType NVARCHAR(50) ,      @FinancialYear NVARCHAR(50) ,      @EmployeeID INT,   @CycleID INT  AS      BEGIN           DECLARE @FromDate DATETIME , @ToDate DATETIME ,@Month NVARCHAR(2);              SELECT TOP 1 @FromDate = PeriodStartDate FROM    dbo.Payroll_CyclePeriodDetails WHERE   CycleID = 1 AND FinancialYear = @FinancialYear ORDER BY Period_ID;                  IF @PeriodType = 'February'              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));                  SET @Month = '02';              END;          ELSE              BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));                  SET @Month = '08';              END;              SELECT DISTINCT A.ID ,                  A.Enabled ,                  A.[2010] , A.[2015] , A.[2020] , A.[2022] , A.[2024] , A.[2025] , A.[2026] , A.[2027] , A.[2028] , A.[2030] , A.[2031] , A.[2082] , A.[2083] ,A.[2035] ,                  A.[2061] , A.[2062] , A.[2063] , A.[2064] , A.[2065] , A.[2066] , A.[2080] , A.[3010] , A.[3015] , A.[3020] , A.[3025] , A.[3026] , A.[3030] , A.[3040] ,                  A.[3050] , A.[3060] , A.[3070] , A.[3075] , A.[3080] , A.[3100] , A.[3263] , A.[3264] , A.[3125] , A.[3135] , A.[3136] , A.[3137] , A.[3138] , A.[3144] ,                  A.[3145] , A.[3146] , A.[3147] , A.[3148] , A.[3149] , A.[3150] , A.[3160] , A.[3170] , A.[3180] , A.[3200] , A.[3210] , A.[3279] , A.[3211] , A.[3212] ,                  A.[3213] , A.[3214] , A.[3215] , A.[3216] , A.[3217] , A.[3218] , A.[3247] , A.[3249] , A.[3258] , A.[3259] , A.[3260] , A.[3261] , A.[3230] , A.[3240] ,                  A.[3241] , A.[3242] , A.[3243] , A.[3244] , A.[3245] , A.[3246] , A.[3255] , A.[3256] , A.[3253] , A.[3262] , B.Code , B.CodeName , B.CodeValue , B.TransactionTypeID          FROM    Payroll_IRP5ReportStaging A                  LEFT MERGE JOIN Payroll_IRP5ReportStagingDynamicCodes B ON A.ID = B.ID AND B.TransactionTypeID BETWEEN 1 AND 3          WHERE   ( A.EmployeeId = @EmployeeID OR @EmployeeID = 0 ) AND [2031] = CONVERT(VARCHAR(50), ( DATEPART(YEAR, @ToDate) )) + @Month AND A.CycleId = @CycleID;         END;        

GO

-- ============================================
-- SP: Payroll_IRP5ReportSplitSourceDynamicCodes_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  varun parvataneni  -- Create date: <Create Date,,24 MAR 2016>  -- Description: <Description,,>  -- Call SP    : Payroll_IRP5ReportSplitSourceDynamicCodes_sp  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_IRP5ReportSplitSourceDynamicCodes_sp]   @EmployeeID int,@ID INT,@Source nvarchar (Max)  AS  BEGIN     Declare @RESULT TABLE([Position] INT, [Value] VARCHAR(MAX))   -- Declare  @XML XML    -- SELECT @XML = CONVERT(XML, SQL_TEXT)    -- FROM (    --  SELECT '<root><item>'    --   + REPLACE(@Source, ',', '</item><item>')    --   + '</item></root>' AS SQL_TEXT    --  ) dt      INSERT INTO @RESULT(Position,Value)    Select ID,Value from dbo.Split_fxn(@Source,',')   -- SELECT t.col.query('.').value('.', 'VARCHAR(1000)') AS [Value]    -- FROM @XML.nodes('root/item') t(col)     DECLARE @splitvalues TABLE(Code nvarchar(max),Value NVARCHAR(MAX))    Declare @Start int =1,@End int      Select @End = Count(*) from @RESULT     WHILE (@Start <= @End)    BEGIN   Insert into @splitvalues(Code,Value) Values((Select Value from @RESULT where Position = @Start),(Select Value from @RESULT where Position = @Start +1))   SET @Start =@Start+2;   END   INSERT INTO dbo.Payroll_IRP5ReportStagingDynamicCodes(ID,Code,CodeValue)  Select ALL ID =@ID,Code,Value from @splitvalues Where Code BETWEEN'3601' AND '4150';   Update dbo.Payroll_IRP5ReportStagingDynamicCodes set CodeName =(Select TOP 1 IRP5CodeDesc from Payroll_IRP5Code where IRP5Code = Code)   Update dbo.Payroll_IRP5ReportStagingDynamicCodes set TransactionTypeID=(Select TOP 1 TransactionTypeID from Payroll_IRP5Code where IRP5Code = Code)   Update dbo.Payroll_IRP5ReportStagingDynamicCodes set TransactionTypeID=3 where code between 4102 and 4149   Update dbo.Payroll_IRP5ReportStagingDynamicCodes set IsFlag =(   CASE    WHEN   ((select TOP 1 IsRFI  from Payroll_SalaryHead as sh   left join Payroll_IRP5Code as irp on irp.IRP5Code_ID=sh.IRP5CodeId   Where IRP5Code = Code AND TransactionTypeID =TransactionTypeID) =1   AND   (select COUNT(*) from Payroll_EmpBenefitDetail as ebd   left join Payroll_BenefitDetail as bd on bd.Benefit_ID=ebd.BenefitSchemeID   where  BenefitTypeID in (3,7)   and employeeid=@EmployeeID) >0)   THEN   1    ELSE   0   END)  END    

GO

