-- ============================================
-- SP: Payroll_IRP5ReportSummary_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_IRP5ReportSummary_sp]    @CalendarMonth int = 8,   @TaxYear NVARCHAR(50)='2014/2015',   @PayrollCycleId INT=1,    @SortIndex nvarchar(100) = 'Employee',   @FromRange nvarchar(250)='',   @ToRange nvarchar(250)=''   as  BEGIN    DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME,@Cycle nvarchar(250)         DECLARE @Period TABLE (Period_Id INT, PeriodEndDate datetime)    INSERT INTO @Period    SELECT Period_ID, cast(PeriodEndDate AS DATE) FROM dbo.Payroll_CyclePeriodDetails     WHERE DATEPART(MONTH, PeriodStartDate) = @CalendarMonth AND TaxYear = @TaxYear AND CycleID = @PayrollCycleId       SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID in (select Period_Id from @Period)      select @Cycle = CycleDesc from Const_Cycle where Cycle_ID = @PayrollCycleId    /*Employee*/            if(isnull(@FromRange,'') <> '')    begin     set @FromRange = convert(int,@FromRange)       end    else       set @FromRange = convert(int,0)      if(isnull(@ToRange,'') <> '')    begin           set @ToRange = convert(int,@ToRange)    end    else       set @ToRange = convert(int,0)          --INSERT INTO @Result(code,TotalValue,Result)    select distinct IRP5Code,IRP5CodeDesc    ,isnull((select sum(Amount) from  dbo.Payroll_EmployeePayslip AS PAY_EMP1     INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF1 ON PAY_EMP1.PayrollDefinationID = DEF1.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD1 ON DEF1.PayrollSalaryHeadID = HEAD1.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP51 ON HEAD1.IRP5CodeId = IRP51.IRP5Code_ID    where IRP51.IRP5Code_ID = IRP5.IRP5Code_ID    and head1.IsRFI = head.IsRFI     AND PAY_EMP1.PeriodID IN (select Period_ID from @Period)        ),0) CurrentMonth,    isnull(sum(Amount),0) TotalsToDate,case when head.IsRFI = 1 then 'Yes' else 'No' end RFI    ,@PeriodStartDate PeriodStartDate,@PeriodEndDate PeriodEndDate,@Cycle CycleDesc    FROM dbo.Payroll_Employee AS EMP    inner join dbo.Payroll_EmployeePayslip AS PAY_EMP on emp.Employee_ID = PAY_EMP.EmployeeID    INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON PAY_EMP.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID    INNER JOIN dbo.Payroll_SalaryHead AS HEAD ON DEF.PayrollSalaryHeadID = HEAD.SalaryHead_ID    INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON HEAD.IRP5CodeId = IRP5.IRP5Code_ID    INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON PAY_EMP.PeriodID = Cyc.Period_ID    WHERE PAY_EMP.EmployeeID = EMP.Employee_ID --AND PAY_EMP.PeriodID IN (229) --(SELECT PeriodID FROM @Period)       and emp.Enabled = 1 and EMP.IsDummy =0       and(case when upper(@SortIndex) = upper('Employee')  then                  case when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) = 0 then 1              when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) = 0 and  emp.Employee_ID >= convert(int,@FromRange) then 1           when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) <> 0 and emp.Employee_ID <= convert(int,@ToRange) then 1           when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) <> 0 and  emp.Employee_ID >= convert(int,@FromRange) and emp.Employee_ID <= convert(int,@ToRange)  then 1           else 0 end         when upper(@SortIndex) = upper('IRP5 Code')  then       case when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) = 0 then 1              when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) = 0 and CONVERT(int,irp5.IRP5Code) >= isnull(@FromRange,0) then 1           when isnull(@FromRange,0) = 0 and isnull(@ToRange,0) <> 0 and CONVERT(int,irp5.IRP5Code) <= isnull(@ToRange,0)  then 1           when isnull(@FromRange,0) <> 0 and isnull(@ToRange,0) <> 0 and CONVERT(int,irp5.IRP5Code) > = isnull(@FromRange,0)  and CONVERT(int,irp5.IRP5Code) <= isnull(@ToRange,0) then 1           else 0 end           else 1           end =1)              and convert(int,IRP5Code) >= 3601 and convert(int,irp5code) <= 4497        and Pay_emp.TaxYear = @TaxYear            group by IRP5Code_ID ,IRP5Code,IRP5CodeDesc,head.IsRFI       order by IRP5Code           END  

GO

-- ============================================
-- SP: Payroll_IRP5TaxTotalTransactions
-- Schema: dbo
-- ============================================
/*   Author  : Richa M   Create date : 2023/03/24   Description : IRP5TaxTotalTransactions   EXEC Payroll_IRP5TaxTotalTransactions 1,2024      */  CREATE PROCEDURE [dbo].[Payroll_IRP5TaxTotalTransactions]   @SalaryHeadId int,   @TaxYear int  as  BEGIN       select    Employee_ID,   REPLACE(STR(Employee_ID,8),' ','0') EmployeeNumber,   IsNULL(EmpCode,'')EmpCode,   FirstName,   Surname,   SalaryHeadName,   Amount,   Cast(IRP5Code as varchar(4)) + ' - ' + IRP5CodeDesc IRP5code   from(    select      IRP5CodeID,      EmployeeID,     SUM(Amount)Amount     from dbo.[Payroll_PayrollResults]     where SalaryHeadID = @SalaryHeadId     and TaxYear = @TaxYear    group by  EmployeeID,IRP5CodeID)payrollResults      Left outer join Payroll_SalaryHead sh     on sh.SalaryHead_ID = @SalaryHeadId      Left outer join Payroll_employee emp     on emp.Employee_ID = payrollResults.EmployeeID      Left outer join Payroll_IRP5Code irp5     on irp5.IRP5Code_ID = payrollresults.IRP5CodeID    END

GO

-- ============================================
-- SP: Payroll_IsLeaveRequestExists
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,10 Jul 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_IsLeaveRequestExists 0, 5, '09 Jun 2014', '11 Jun 2014'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_IsLeaveRequestExists]   @RequestId INT,   @EmployeeId INT,   @FromDate DATETIME,   @ToDate DATETIME  AS  BEGIN   SELECT LeaveApproveRequest_ID FROM dbo.Payroll_LeaveApproveRequest AS LR   INNER JOIN dbo.Payroll_LeaveApproveRequestDetails AS LRD ON LR.LeaveApproveRequest_ID = LRD.LeaveApproveRequestId   WHERE EmployeeID = @EmployeeId AND LeaveApproveRequest_ID <> @RequestId AND LeaveDate BETWEEN @FromDate AND @ToDate   AND ApprovalStatus IN (1, 3)  END  

GO

-- ============================================
-- SP: Payroll_IsPayrollCycleCompletedForFinancialYear_fxn
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_IsPayrollCycleCompletedForFinancialYear_fxn]  (  --====================================================================  ---@FinancialYear NVARCHAR(9) = '2014/2015' AN example,   ---In this case Financial year is Tax Year   ---From the parameter passed, take the first 4 characters  --2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  --====================================================================    @FinancialYear NVARCHAR(9),  @PayrollCycleID    INT    )  AS    BEGIN     SELECT Period_Id, PeriodStartDate, PeriodEndDate, ProcessingMonth, Processed, TaxYear, Enabled, CycleID, CapturerID, ProcessedDate, DateModified, ModifierID    FROM Payroll_CyclePeriodDetails    WHERE PeriodStartDate <=  CONVERT(CHAR(4), @FinancialYear, 120)+ '-' + '06' + '-' + '30'       AND PeriodEndDate >= CONVERT(CHAR(4), @FinancialYear, 120)+ '-' + '06' + '-' + '30'       AND CycleID = @PayrollCycleID        AND Processed = 0 AND CycleModeID = 1  END  

GO

-- ============================================
-- SP: Payroll_IsPayrollCycleCompletedForFinancialYear_sp
-- Schema: dbo
-- ============================================
    CREATE PROCEDURE [dbo].[Payroll_IsPayrollCycleCompletedForFinancialYear_sp]  (  --=========================================================================  ---@FinancialYear NVARCHAR(9) = '2014/2015' AN example,   ---In this case Financial year is Tax Year   ---From the parameter passed, take the first 4 characters  --EXEC [Payroll_IsPayrollCycleCompletedForFinancialYear_sp] '2014/2015', 1  --2016-04-13 TP:35027 Seipei Mathole: Added enabled flag  -- 2016-04-22 TP:35000 Ravindra Jijotia: Added CycleModeID filter  --=========================================================================    @FinancialYear NVARCHAR(9),  @PayrollCycleID    INT    )  AS    BEGIN     SELECT Period_Id, PeriodStartDate, PeriodEndDate, ProcessingMonth, Processed, FinancialYear, Enabled, CycleID, CapturerID, ProcessedDate, DateModified, ModifierID    FROM Payroll_CyclePeriodDetails     WHERE PeriodStartDate <=  CONVERT(CHAR(4), @FinancialYear, 120)+ '-' + '06' + '-' + '30'       AND PeriodEndDate >= CONVERT(CHAR(4), @FinancialYear, 120)+ '-' + '06' + '-' + '30'       AND CycleID = @PayrollCycleID        AND Processed = 0 AND Enabled = 1 AND CycleModeID = 1  END  

GO

-- ============================================
-- SP: Payroll_JobProfile_SearchCompetancySkills_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_JobProfile_SearchCompetancySkills_sp]    -- Add the parameters for the stored procedure here    @SkillType varchar(255),    @SkillSubType varchar(255),    @JobEssetial bit,    @JobProfileID int   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT [CompetancySkills_ID]       ,[SkillType]       ,[SkillSubType]       ,[SkillDescription]       ,Case when [IsMinimumRequirement] = 1 then       'True'       else       'False'       end as MinimumRequirement       ,Case when [IsJobEssential] = 1 then       'True'       else       'False'       end as JobEssential       ,[UserForRecruitMent]      FROM [dbo].[Payroll_JobProfile_CompetancySkills]     where (        JobProfileId = @JobProfileID       and        (SkillType = @SkillType or @SkillType = '-1') and       (SkillSubType = @SkillSubType or @SkillSubType = '-1') and       (IsJobEssential = @JobEssetial or @JobEssetial IS NULL)       )     order by [CompetancySkills_ID] desc     END

GO

-- ============================================
-- SP: Payroll_JobProfile_SearchCompetencyQualification
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_JobProfile_SearchCompetencyQualification] @NQFLevel                      VARCHAR(250) = NULL,                                                                             @QualificationTypeID           INT          = NULL,                                                                             @FieldOfStudyID                INT          = NULL,                                                                             @QualificationShORtDescription VARCHAR(255) = NULL,                                                                             @ProfessionalBodyName          VARCHAR(255) = NULL,                                                                             @UseFORRecruitment             VARCHAR(255) = NULL,                                                                             @IsEducation                   BIT          = NULL,                                                                             @IsAccreditation               BIT          = NULL,                                                                             @JobProfileID                  INT          = NULL  AS      BEGIN          SELECT [CQ].[CompetencyQualification_ID],                  (CASE                      WHEN [Q].[IsEducation] = 1                      THEN 'Education'                      ELSE(CASE                               WHEN [Q].[IsProfessionalAccreditation] = 1                               THEN 'Accreditation'                               ELSE 'N/A'                           END)                  END) AS [TypeOfQualification],                  [Q].[Qualification],                  [QT].[QualificationTypeName],                  fos.[Name] AS FieldOfStudy,                  [Q].[QualificationShORtCode],                  [Q].[QualificationShORtDescription],                  [Q].[ProfessionalBodyName],                  [CQ].[UseFORRecruitment]          FROM [Payroll_JobProfile_CompetencyQualification] AS [CQ] WITH(NOLOCK)               JOIN [Const_Qualification_Sys] AS [Q] WITH(NOLOCK) ON [Q].[Qualification_ID] = [CQ].[QualificationID]               LEFT JOIN [Payroll_QualificationTypes] AS [QT] WITH(NOLOCK) ON [Q].[QualificationTypeID] = [QT].[QualificationTypeId]               LEFT JOIN [Payroll_FieldOfStudy] fos ON fos.FieldOfStudy_ID = [Q].FieldOfStudyID          WHERE(([Q].[Qualification] = (CASE                                            WHEN @NQFLevel IS NULL                                                 OR @NQFLevel = ''                                            THEN [Q].[Qualification]                                            ELSE @NQFLevel                                        END))                AND ([Q].[QualificationTypeID] = (CASE                                                      WHEN @QualificationTypeID IS NULL                                                           OR @QualificationTypeID < 1                                                      THEN [Q].[QualificationTypeID]                                                      ELSE @QualificationTypeID                                                  END))                AND ([Q].[FieldOfStudyID] = (CASE                                                      WHEN @FieldOfStudyID IS NULL                                                           OR @FieldOfStudyID < 1                                                      THEN [Q].[FieldOfStudyID]                                                      ELSE @FieldOfStudyID                                                  END))                AND ([Q].[QualificationShORtDescription] = (CASE                                                                WHEN @QualificationShORtDescription IS NULL                                                                     OR @QualificationShORtDescription = ''                                                                THEN [Q].[QualificationShORtDescription]                                                                ELSE @QualificationShORtDescription                                                            END))                AND ([Q].[ProfessionalBodyName] = (CASE                                                       WHEN @ProfessionalBodyName IS NULL                                                            OR @ProfessionalBodyName = ''                                                       THEN [Q].[ProfessionalBodyName]                                                       ELSE @ProfessionalBodyName                                                   END))                AND ([CQ].[UseFORRecruitment] = (CASE                                                     WHEN @UseFORRecruitment IS NULL                                                          OR @UseFORRecruitment = ''                                                     THEN [CQ].[UseFORRecruitment]                                                     ELSE @UseFORRecruitment                                                 END))                AND ([Q].[IsEducation] = (CASE                                              WHEN @IsEducation IS NULL                                              THEN [Q].[IsEducation]                                              ELSE @IsEducation                                          END))                AND ([Q].[IsProfessionalAccreditation] = (CASE                                                              WHEN @IsAccreditation IS NULL                                                              THEN [Q].[IsProfessionalAccreditation]                                                              ELSE @IsAccreditation                                                          END))                AND ([CQ].[JobProfileID] = (CASE                                                WHEN @JobProfileID IS NULL                                                THEN [CQ].[JobProfileID]                                                ELSE @JobProfileID                                            END)))          ORDER BY [CompetencyQualification_ID] DESC;      END;

GO

-- ============================================
-- SP: Payroll_JobProfile_SearchCompetencyRequirements_sp
-- Schema: dbo
-- ============================================
Create PROCEDURE [dbo].[Payroll_JobProfile_SearchCompetencyRequirements_sp]    -- Add the parameters for the stored procedure here    @CompentencyType int,    @CompentencyRequirement varchar(255),    @MinimumProfeciantcy int,    @Mandatory bit,    @JobProfileID int   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT CR.CompetencyRequirements_ID      ,T.CoreCompetencyRequirementTypeDesc      ,D.[CoreCompetencyRequirement]      ,D.[CoreCompetencyRequirementDesc]      ,Case when CR.[Mandatory] = 1 then      'True'      else      'False'      end as IsMandatory      ,P.Name as [MinimumProficiencyLevel]      ,CR.[CascadeScore]      ,0 as EmployeeCount      ,0 as PositionCount         FROM Payroll_JobProfile_CompetencyRequirements as CR     inner join [dbo].[Const_PMSCoreCompetencyRequirement] as D on D.CoreCompetencyRequirement_ID = CR.CoreCompetencyRequirementID     inner join [dbo].Const_PMSCoreCompetencyRequirementType_sys as T on T.CoreCompetencyRequirementType_ID = D.CoreCompetencyRequirementTypeID     inner join Payroll_MinimumProficiencyLevel as P on P.MinimumProficiencyLevel_ID = CR.MinimumProficiencyLevelID     where (        (T.CoreCompetencyRequirementType_ID = @CompentencyType or @CompentencyType = -1) and       (D.[CoreCompetencyRequirement] = @CompentencyRequirement or @CompentencyRequirement = '-1') and        (P.[MinimumProficiencyLevel_ID] = @MinimumProfeciantcy or @MinimumProfeciantcy = -1) and       (CR.[Mandatory] = @Mandatory or @Mandatory is NULL) and CR.JobProfileID = @JobProfileID and D.Enabled = 1            )     order by CR.CompetencyRequirements_ID desc     END

GO

-- ============================================
-- SP: Payroll_JobProfile_SearchJobDutyAndResponsibility
-- Schema: dbo
-- ============================================
   create PROCEDURE [dbo].[Payroll_JobProfile_SearchJobDutyAndResponsibility]    -- Add the parameters for the stored procedure here    @Name varchar(250),    @UseForRecruitement varchar(255),    @PerformanceMesured varchar(255),    @Duty bit,    @Responsibility bit,    @JobProfileID int     AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT [JobDutyAndResponsibility_ID]      ,[Priority]      ,case when [Duty] = 1 then     'Duty'       else     case when [Responsibility] = 1 then      'Responsibility'     else      'N/A'     end       end as DutyOrResponsibility      ,[Name]      ,[Description]      ,[UseForRecrutement]      ,[PerformanceMesured]      FROM [dbo].[Payroll_JobProfile_JobDutyAndResponsibility]      where (         ([Name] = @Name or @Name = '-1') and        ([UseForRecrutement] = @UseForRecruitement or @UseForRecruitement = '-1') and        ([PerformanceMesured] = @PerformanceMesured or @PerformanceMesured = '-1') and        ([Duty] = @Duty or @Duty is NULL ) and        ([Responsibility] = @Responsibility or @Responsibility is NULL) and JobProfileID = @JobProfileID        )      order by [JobDutyAndResponsibility_ID] desc       END

GO

-- ============================================
-- SP: Payroll_JobProfile_SearchQualificationLibraryForCompentency_sp
-- Schema: dbo
-- ============================================
  CREATE procedure [Payroll_JobProfile_SearchQualificationLibraryForCompentency_sp] @IsEducation bit = null, @IsAccreditation bit = null, @NQFLevel varchar(255) = null, @QualificationTypeID int = null, @QualificationDesc varchar(255) = null, @ProfessionalBodyName varchar(255) = null  as  begin     select [Qualification_ID], [Qualification], [QualificationShortDescription], [ProfessionalBodyName]     from [Const_Qualification_Sys] as [Q] with(nolock)   LEFT JOIN [dbo].[Payroll_QualificationTypes] qt on qt.QualificationTypeId = q.QualificationTypeID      where (       ([IsEducation] = (case when @IsEducation is null then [IsEducation] else @IsEducation end)) and       ([IsProfessionalAccreditation] = (case when @IsAccreditation is null then [IsProfessionalAccreditation] else @IsAccreditation end)) and       ([Qualification] = (case when @NQFLevel is null or @NQFLevel = '' then [Qualification] else @NQFLevel end)) and       ((@QualificationTypeID IS NULL OR @QualificationTypeID = -1) OR ([Q].[QualificationTypeID] = @QualificationTypeID)) AND       ([QualificationShortDescription] = (case when @QualificationDesc is null or @QualificationDesc = '' then [QualificationShortDescription] else @QualificationDesc end)) and       ([ProfessionalBodyName] = (case when @ProfessionalBodyName is null or @ProfessionalBodyName = '' then [ProfessionalBodyName] else @ProfessionalBodyName end))      )       order by [Qualification_ID] desc    end

GO

-- ============================================
-- SP: Payroll_JobProfile_ValidatePercentageForCostingAllocation_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Validates that total percentage for costing allocation is not more than 100%.  -- Call: [Payroll_JobProfile_ValidatePercentageForCostingAllocation_sp]  --2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions-- No change  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_JobProfile_ValidatePercentageForCostingAllocation_sp]      @JobProfileID INT  AS    BEGIN      SELECT JobProfileID, SUM(Percentage) TotalPercentage    FROM    (        SELECT JobProfile_ID AS JobProfileID, PercentageForCostingAllocationToSCOAFunction AS Percentage        FROM Payroll_JobProfile WHERE JobProfile_ID = @JobProfileID OR @JobProfileID = 0        UNION ALL        SELECT JobProfileID AS JobProfileID, CostPercentage AS Percentage        FROM Payroll_JobProfileExtraDivisionFunctionCode WHERE (JobProfileID = @JobProfileID OR @JobProfileID = 0) AND Enabled = 1    ) temp    GROUP BY JobProfileID    HAVING SUM(Percentage) != 100.00        END    

GO

-- ============================================
-- SP: Payroll_JobProfileOrganogram
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,26 Mar 2014>  -- Description: <Description,,>  -- Call SP:  Payroll_JobProfileOrganogram  -- 2014-10-20   James Roodt: Added a where clause to only pull jobprofiles in use or booked to be used instead of all of them.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_JobProfileOrganogram]  AS  BEGIN   SELECT JobProfile_ID, P_JP.JobTitle, ToWomDoesThisPositionReport as ReportingTo, (Select dbo.GetEmployeeDetails(P_E.Employee_ID)) AS EmpName, ImagePath, Employee_ID, GenderID,   P_E.IdNo, dbo.BufferString_fxn(CONVERT(VARCHAR, (Employee_ID )), 8, '0') AS EmployeeNo    FROM Payroll_JobProfile AS P_JP   LEFT OUTER JOIN Payroll_Position pp ON pp.JobProfileID =P_JP.JobProfile_ID   INNER JOIN Payroll_Employee AS P_E ON P_E.PositionID = pp.Position_ID   WHERE  pp.JobProfileID IS NOT NULL OR P_JP.NoOfPosition <>''  END      

GO

-- ============================================
-- SP: Payroll_JobProfileOrganogramReport_sp
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create Date : 01/11/2018   Description : Returns a list of Departments and Divisions with their linked Current and Vacant Positions  */  /* 27/11/2018  Himil Modi only get position which is vacant or Occupied  ([pos].Status IN (1,2)) */  CREATE PROCEDURE dbo.Payroll_JobProfileOrganogramReport_sp @DepartmentID int = null, @DivisionID int = null  as  begin     SELECT    p.[JobProfileID], jp.[JobTitle], d.[DepartmentDesc] AS 'Department',    SUM(CASE WHEN p.[Status] = 1 THEN 1 ELSE 0 END) AS 'VacancyNo',    SUM(CASE WHEN p.[Status] = 2 THEN 1 ELSE 0 END) AS 'OccupiedNo',    SUM(CASE WHEN p.[Status] IN (1, 2) THEN 1 ELSE 0 END) AS 'PositionNo'   FROM     Payroll_Position p   INNER JOIN    Payroll_JobProfile jp ON p.[JobProfileID] = jp.[JobProfile_ID]          AND jp.[Enabled] = 1   INNER JOIN    Const_Department d ON p.[DepartmentID] = d.[Department_ID]          AND d.[Enabled] = 1   WHERE    p.[Enabled] = 1   AND p.[Status] IN (1, 2) -- Position must be vacant or Occupied   AND (@DepartmentID IS NULL OR p.[DepartmentID] = @DepartmentID)   AND (@DivisionID IS NULL OR p.[DivisionID] = @DivisionID)   GROUP BY    p.[JobProfileID], jp.[JobTitle], d.[DepartmentDesc]   ORDER BY    jp.[JobTitle], d.[DepartmentDesc]    end

GO

-- ============================================
-- SP: Payroll_LaserPayslipRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 24 JUL 2013  -- Description: <Description,,>  -- calls : [Payroll_LaserPayslipRpt_sp] 0, 0, 2  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2015-01-12 James Roodt: Added ISNULL checks at employee name and address to cater for empty fields.  -- 2015-03-30 James Roodt: Removed percentage multiplier on the amount  -- 2015-05-19 TP19714 James Roodt: Added SalaryHeadTitleAddendum to be appended to SalaryHeadTitle  -- 2015-07-25 : Ravindra Jijotia: TP22932 Added Month Name Field.  -- 2016-01-06 Suri Kandukuri : Added Employee Code  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_LaserPayslipRpt_sp]   @EmployeeID INT,   @DepartmentId INT,   @PeriodId INT  AS  BEGIN   DECLARE @FROMDATE DATETIME, @CycleId INT   DECLARE @TODATE DATETIME, @FinanceYear NVARCHAR(10)   SELECT  @FROMDATE = PeriodStartDate, @TODATE = PeriodEndDate, @FinanceYear = TaxYear, @CycleId = CycleID FROM Payroll_CyclePeriodDetails WHERE Period_ID = @PERIODID     DECLARE @Period TABLE (Period_ID INT)   INSERT INTO @Period   SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE TaxYear = @FinanceYear  AND CycleID = @CycleId AND Period_ID <= @PeriodId   --AND DATEPART(MONTH, PeriodEndDate) <= DATEPART(MONTH, @TODATE) AND DATEPART(YEAR, PeriodEndDate) <= DATEPART(YEAR, @TODATE)      SELECT @FROMDATE AS FROMDATE,@TODATE AS  TODATE, DateName( month , DateAdd( month , DATEPART(mm, @FROMDATE) , 0 ) - 1 ) + ' ' + DateName(YEAR, @FROMDATE) AS MonthName,    PAY_MUN.MunicipalityName,    ISNULL(PAY_MUN.PhyAddress1 + ' ','') + ISNULL(PAY_MUN.PhyAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb),'') AS COMPANYADDRESS,    CONVERT(NVARCHAR,PAY_CYC_PER.PeriodEndDate,103) AS PAYPERIOD,    PAY_EMP.IdNo as IDNumber,isnull(Pay_EMP.EmpCode,'') EmpCode, PAY_EMP.Employee_ID,    ISNULL(PAY_EMP.FirstName + ' ','') + ISNULL(PAY_EMP.SecondName + ' ','') + ISNULL(PAY_EMP.Surname,'') AS EMPLOYEENAME,    ISNULL(PAY_EMP.PhysicalAddress1 + ' ','') + ISNULL(PAY_EMP.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_EMP.PhysicalSuburbID),'') AS EMPADDRESS,    CONVERT(NVARCHAR,PAY_EMP.JoiningDate,103) AS STARTDATE,    CONST_TRAN_TYPE.TransactionTypeDesc, CONST_TRAN_TYPE.TransactionType_ID,    P_JP.JobTitle,    PAY_EMP_PAY.Amount,    PAY_SAL.SalaryHeadTitle + isnull(' (' + PAY_EMP_PAY.SalaryHeadTitleAddendum + ')','') as TransactionTypeDescription,    ISNULL((SELECT SUM(AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave) FROM dbo.Payroll_EmployeeLeaveSchemeTransaction AS EL WHERE EmployeeId = PAY_EMP.Employee_ID ), 0) AS TOTALLEAVE,    (     (      SELECT SUM(TRAIL.Amount) FROM Payroll_EmployeePayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead SH ON SH.SalaryHead_ID = PAY.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON SH.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID       WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID AND       TRAIL.TaxYear =@FinanceYear  AND Payroll_IRP5Code.TransactionTypeID = 1     )     -     (      SELECT SUM(AMOUNT) FROM Payroll_EmployeePayslip TRAIL        INNER JOIN Payroll_EmployeePayrollDefinition PAY ON PAY.EmployeePayrollDefinition_ID =TRAIL.PayrollDefinationID        INNER JOIN dbo.Payroll_SalaryHead SH ON SH.SalaryHead_ID = PAY.PayrollSalaryHeadID       INNER JOIN Payroll_IRP5Code ON SH.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID       WHERE TRAIL.EmployeeID =PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND TRAIL.PeriodID =@PERIODID       AND TRAIL.TaxYear =@FinanceYear AND Payroll_IRP5Code.TransactionTypeID = 2     )    )AS NETPAY,    ISNULL((    SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TaxableID = 1 AND TransactionType_ID = 1 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableEarnings,    ISNULL((    SELECT CAST(SUM(Amount) AS DECIMAL(18, 2)) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TaxableID = 1 AND TransactionType_ID = 3 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableCompanyContributions,    ISNULL((    SELECT SUM(Amount) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE TransactionType_ID = 4 AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxableFringeBenefits,    --CAST(0 AS DECIMAL(18, 2)) AS BonusTax,    --PAY_EMP.BonusCalculation,    TBC.TaxBonusCalculation AS BonusCalculation,    ISNULL((    SELECT SUM(Amount) FROM Payroll_EmployeePayslip PAY_EMP_PAY --ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Const_Taxability AS C_T ON dbo.Payroll_IRP5Code.TaxableID = C_T.Taxability_ID    WHERE SalaryHeadName = 'Pay as you Earn' AND PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID AND TaxSavePurpose = 0 AND PeriodID IN (SELECT Period_ID FROM @Period)    ), 0) AS TaxPaid,    CASE WHEN PAY_SAL.SalaryHeadTitle = 'Loan' THEN ISNULL((SELECT SUM(Balance) FROM dbo.Payroll_InstalmentHistory WHERE EmployeeId = PAY_EMP.Employee_ID AND PeriodID = @PeriodID),0) ELSE 0.00 END AS OpeningBalance   FROM Payroll_Employee PAY_EMP    INNER JOIN Payroll_Municipality PAY_MUN ON PAY_MUN.Municipality_ID = PAY_EMP.MunicipalityID    INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID             INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID     INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID     INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID     INNER JOIN Const_TransactionType CONST_TRAN_TYPE ON CONST_TRAN_TYPE.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID    INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER ON PAY_CYC_PER.PERIOD_ID = PAY_EMP_PAY.PERIODID AND  PAY_CYC_PER.CYCLEID = PAY_EMP.CYCLEID     INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID      INNER JOIN dbo.Payroll_JobProfile AS P_JP ON P_JP.JobProfile_ID = PP.JobProfileID    INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID    INNER JOIN dbo.Const_TaxBonusCalculation_sys TBC ON TBC.TaxBonusCalculation_ID= PAY_EMP.BonusCalculation   WHERE (PAY_EMP.Employee_ID =@EmployeeID OR @EmployeeID = 0 ) AND (Department_ID = @DepartmentId OR @DepartmentId = 0)   AND (PAY_EMP_PAY.PERIODID = @PERIODID) AND TaxSavePurpose = 0    --AND(PAY_EMP_PAY.FinancialYear=@FinanceYear)    order by  CONST_TRAN_TYPE.TransactionTypeDesc asc       END  

GO

-- ============================================
-- SP: Payroll_Leave_Adjustment_Search
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/18>  -- Description: <Description,,>  -- Call SP    : Payroll_Leave_Adjustment_Search 1  -- Modiri #93954: 2019/09/20 HR_Payroll_Leave Adjustments No Edit / Delete function on Grid  -- ===========================================  CREATE PROCEDURE [dbo].[Payroll_Leave_Adjustment_Search]   @AdjustmentType INT  AS  BEGIN     SELECT Employee_ID,EmpCode, dbo.BufferString_fxn(CONVERT(VARCHAR, ( [PE].Employee_Id )), 8,'0') AS EmployeeId, IdNo, Surname, FirstName,LT.LeaveTypeDesc,0.00 AS LeaveBeforeAdjustment,   Lt.LeaveType AS DetailName, Lt.LeaveTypeDesc AS DetailDesc,   [ET].[Value] AS AdjustedDays,   [ET].Notes AS AdjustmentReason,0.00 AS EncashAmount,   [ET].Transaction_ID,   [ET].LeaveSchemeID    from [Const_LeaveType] as [LT] with(nolock)     join [Payroll_AbsencePriority] as [AP] with(nolock) on [AP].[LeaveTypeID] = [LT].[LeaveType_ID]     join [Const_AbsenceType] as [CA] with(nolock) on [CA].[AbsenceType_ID] = [AP].[AbsenceTypeID]     join [Const_LeaveSchemeTypeDetails] as [LSD] with(nolock) on [LSD].[LeaveTypeId] = [CA].[AbsenceType_ID] and [LSD].[Enabled] = 1     join [Const_LeaveScheme] as [LS] with(nolock) on [LS].[LeaveScheme_ID] = [LSD].[LeaveSchemeId] and [LS].[Enabled] = 1      JOIN [Payroll_Employee] as [PE] with(nolock) on [PE].[LeaveSchemeID] = [LSD].[LeaveSchemeId] AND [PE].[Enabled] =1     JOIN [Payroll_EmployeeLeaveTransactions] as  [ET]  with(nolock) on  [ET].LeaveTypeID = [LT].[LeaveType_ID]       AND [ET].[EmployeeID] = [PE].[Employee_ID] AND [ET].[LeaveSchemeID] = [PE].[LeaveSchemeID]     WHERE @AdjustmentType = [ET].[LeaveAdjustmentTypeID] and LeaveStatusID in (1,2,3,6)    END

GO

-- ============================================
-- SP: Payroll_Leave_Approve_Search_sp
-- Schema: dbo
-- ============================================
         --==============================================================================       --Author:  Mehul Panchal       --Create date: 06 JUNE 2013       --call [Payroll_Leave_Approve_Search_sp] 'nirav','','',0,'2012/2013'       --==============================================================================       CREATE PROCEDURE [dbo].[Payroll_Leave_Approve_Search_sp]      @Name NVARCHAR(100) ,      @Surname NVARCHAR(100) ,      @IDNo NVARCHAR(30) ,      @ApprovalStatus INT ,      @FinancialYear NVARCHAR(30)   AS      BEGIN                          SELECT  P_LAR.LeaveApproveRequest_ID ,                  P_E.IdNo ,                  P_E.Surname ,                  P_E.FirstName ,                  LT.LeaveTypeDesc ,                  CONVERT(DATE, P_LAR.RequestFromDate) AS RequestFromDate ,                  CONVERT(DATE, P_LAR.RequestToDate) AS RequestToDate ,                  P_LAR.RequestNoOfDays AS RequestNoOfDays ,                  PEL.LeaveBalance AS CurrentBalance ,                  0.0 AS DaysTakenCycle ,                  GETDATE() AS DateLastTaken ,                  1 AS DaysLastTaken ,                  0 AS AccrualsDuePerCycle ,                  0 AS AverageTakenPerCycle ,                  CASE WHEN P_LAR.ApprovalStatus = 1 THEN 'Requested'                       WHEN P_LAR.ApprovalStatus = 2 THEN 'Declined'                       ELSE 'Approved'                  END AS ApprovalStatus ,                  ISNULL(C_NAR.NotApprovedReasonDesc, '') AS NotApprovedReasonDesc ,                  P_LAR.[Enabled] ,                  ApproveFromDate ,                  ApproveToDate ,                  ApproveNoOfDays ,                  CONVERT(DATE, P_LAR.TakenFromDate) AS TakenFromDate ,                  CONVERT(DATE, P_LAR.TakenToDate) AS TakenToDate ,                  P_LAR.TakenNoOfDays AS TakenNoOfDays ,                  dbo.BufferString_fxn(CONVERT(VARCHAR, ( P_E.Employee_ID )), 8,                                       '0') AS Employee_ID ,                  P_LAR.LeaveTypeID          FROM    Payroll_LeaveApproveRequest AS P_LAR                  INNER JOIN Payroll_Employee AS P_E ON P_LAR.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_EmployeeLeaves AS PEL ON P_E.Employee_ID = PEL.EmployeeID                                                                AND P_LAR.LeaveTypeID = PEL.LeaveTypeID                  INNER JOIN Payroll_EmployeeLeaves AS P_LT ON P_LAR.LeaveTypeID = P_LT.LeaveTypeID AND P_LT.EmployeeID = P_E.Employee_ID      INNER JOIN Const_LeaveType AS LT ON LT.LeaveType_ID = P_LT.LeaveTypeID                  LEFT JOIN Const_NotApprovedReason AS C_NAR ON P_LAR.NotApprovedReasonID = C_NAR.NotApprovedReason_ID          WHERE   ( P_E.FirstName = @Name                    OR @Name = ''                  )                  AND ( P_E.Surname = @Surname                        OR @Surname = ''                      )                  AND ( P_E.IdNo = @IDNo                        OR @IDNo = ''                      )                  AND ( P_LAR.ApprovalStatus = @ApprovalStatus                        OR @ApprovalStatus = 0                      )                  AND ( P_LAR.FinancialYear = @FinancialYear                        OR @FinancialYear = ''                      )          ORDER BY P_E.Employee_ID          END  

GO

-- ============================================
-- SP: Payroll_Leave_Approve_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 5 June 2013  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_Leave_Approve_sp]   @FinancialYear NVARCHAR(30)  AS    BEGIN      SELECT     P_LAR.LeaveApproveRequest_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,     P_LT.LeaveTypeDesc, CONVERT(DATE,P_LAR.TakenFromDate) AS FromDate,     CONVERT(DATE,P_LAR.TakenToDate) AS TakenToDate, P_LAR.TakenNoOfDays AS NoOfDays,     CASE      WHEN P_LAR.ApprovalStatus = 1 THEN 'Requested'     WHEN P_LAR.ApprovalStatus = 2 THEN 'Declined'     ELSE 'Approved' END AS ApprovalStatus,     ISNULL(C_NAR.NotApprovedReasonDesc,'') AS NotApprovedReasonDesc, P_LAR.[Enabled]    ,ApproveFromDate    ,ApproveToDate    ,ApproveNoOfDays   FROM Payroll_LeaveApproveRequest AS P_LAR    INNER JOIN Payroll_Employee AS P_E ON P_LAR.EmployeeID = P_E.Employee_ID    INNER JOIN Payroll_LeaveDefinition AS P_LT ON P_LAR.LeaveTypeID = P_LT.LeaveType_ID   LEFT OUTER JOIN Const_NotApprovedReason AS C_NAR ON P_LAR.NotApprovedReasonID = C_NAR.NotApprovedReason_ID    WHERE P_LAR.FinancialYear = @FinancialYear   ORDER BY P_E.Surname  END  

GO

