  INNER JOIN Const_LeaveType AS LT ON LT.LeaveType_ID = P_LT.LeaveTypeID                  --LEFT OUTER JOIN Const_LeaveReason AS C_LR ON P_LAR.LeaveReasonID = C_LR.LeaveReason_ID            WHERE   ( P_E.FirstName = @Name                      OR @Name = ''                    )                    AND ( P_E.Surname = @Surname                          OR @Surname = ''                        )                    AND ( P_E.IdNo = @IDNo                          OR @IDNo = ''                        )                    AND ( P_LAR.FinancialYear = @FinancialYear                          OR @FinancialYear = ''                        )            ORDER BY P_E.Employee_ID        --END        --ELSE        --BEGIN        --    SELECT         --     P_LAR.LeaveApproveRequest_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,         --     P_LT.LeaveTypeDesc, CONVERT(DATE,P_LAR.TakenFromDate) AS FromDate,         --     CONVERT(DATE,P_LAR.TakenToDate) AS TakenToDate, P_LAR.NoOfDays,         --     CASE WHEN P_LAR.LeaveStatus = 0 THEN 'Not Taken' ELSE 'Taken' END AS LeaveStatus,         --     C_LR.LeaveReasonDesc, P_LAR.[Enabled]        --     ,ApproveFromDate        --     ,ApproveToDate        --     ,ApproveNoOfDays        --     ,dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID        --    FROM Payroll_LeaveApproveRequest AS P_LAR         --    INNER JOIN Payroll_Employee AS P_E ON P_LAR.EmployeeID = P_E.Employee_ID         --    INNER JOIN Payroll_LeaveDefinition AS P_LT ON P_LAR.LeaveTypeID = P_LT.LeaveType_ID         --    INNER JOIN Const_LeaveReason AS C_LR ON P_LAR.LeaveReasonID = C_LR.LeaveReason_ID        --    WHERE P_E.FirstName = @Name          --       or P_E.Surname = @Surname         --       and  P_E.IdNo = @IDNo         --       AND P_LAR.FinancialYear =@FinancialYear         --    ORDER BY P_E.Surname        --END             END       

