-- ============================================
-- SP: Payroll_Leave_Request_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 31 May 2013  -- calls : Payroll_Leave_Request_sp '2012/2013'  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_Leave_Request_sp]    @FinancialYear NVARCHAR(30)  AS    BEGIN   SELECT      P_LAR.LeaveApproveRequest_ID,     P_E.IdNo,     P_E.Surname,     P_E.FirstName,     P_LT.LeaveTypeDesc,     CONVERT(NVARCHAR(12),P_LAR.TakenFromDate, 106) AS FromDate,    CONVERT(NVARCHAR(12),P_LAR.TakenToDate, 106) AS TakenToDate,    P_LAR.TakenNoOfDays AS NoOfDays,     CASE WHEN P_LAR.LeaveStatus = 0 THEN 'Not Taken' ELSE 'Taken' END AS LeaveStatus,     C_LR.LeaveReasonDesc, P_LAR.[Enabled],    ISNULL(CONVERT(NVARCHAR(12),ApproveFromDate, 106), '') AS ApproveFromDate,    ISNULL(CONVERT(NVARCHAR(12),ApproveToDate, 106), '') AS ApproveToDate,    ISNULL(ApproveNoOfDays,'') AS ApproveNoOfDays   FROM Payroll_LeaveApproveRequest AS P_LAR     INNER JOIN Payroll_Employee AS P_E ON P_LAR.EmployeeID = P_E.Employee_ID     INNER JOIN Payroll_LeaveDefinition AS P_LT ON P_LAR.LeaveTypeID = P_LT.LeaveType_ID     INNER JOIN Const_LeaveReason AS C_LR ON P_LAR.LeaveReasonID = C_LR.LeaveReason_ID   WHERE P_LAR.FinancialYear = @FinancialYear   ORDER BY P_E.Surname  END  

GO

-- ============================================
-- SP: Payroll_LeaveApproveRequestList_sp
-- Schema: dbo
-- ============================================
      -- =============================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/23>  -- Description: <Description,,>  -- Call SP    : Payroll_LeaveApproveRequestList_sp 33, '', '', '', 0  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveApproveRequestList_sp]   @UserId INT,  @Name NVARCHAR(100),  @Surname NVARCHAR(100),  @IDNo NVARCHAR(30),  @ApprovalStatus INT  AS  BEGIN    DECLARE @HOD int  DECLARE @DepartmentId int  DECLARE @DivisionId int     select @HOD = HOD,@DepartmentId = DepartmentID,@DivisionId = DivisionID from Payroll_Position where Position_ID in (select PositionID from Payroll_Employee where Employee_ID in (Select empId from User_UserDetail where User_ID = @UserId))    DECLARE @Employees table  (   EmployeeId int  )    if(@HOD = 1)--Department Manager  Begin    Insert Into @Employees    Select Employee_ID from payroll_Employee where PositionID in (select Position_ID from Payroll_Position where DepartmentID = @DepartmentId and (HOD = 0 OR HOD = 2))    end  if(@HOD = 2)--Division Manager  begin   Insert Into @Employees    Select Employee_ID from payroll_Employee where PositionID in (select Position_ID from Payroll_Position where DivisionID = @DivisionId and HOD = 0)  end    --Add employees with no Division or Department head  if(@HOD in (1,2))  begin   Insert Into @Employees    select Employee_ID from (      select v1.*,      HODep.Position_ID DepartmentHeadPosId,HODep.PositionDesc DepartmentHeadPosDescription,       HODiv.Position_ID DivisionHeadPosId,HODiv.PositionDesc DivisionHeadPosDescription      from(      select Employee_ID,EmpCode,FirstName,Surname,IdNo,Position_ID,PositionDesc,HOD,DepartmentID,DivisionID from(      select * from payroll_employee where isnull(leaveschemeId,0) <> 0 and CycleID <> 3 ) emp      join Payroll_Position pos on pos.Position_ID = emp.PositionID)v1      Left join Payroll_Position HODiv  on HODiv.DivisionID = v1.DivisionID and HODiv.HOD =  2      Left join Payroll_Position HODep  on HODep.DepartmentID = v1.DepartmentID and HODep.HOD =  1)v1       where DepartmentHeadPosId is null and DivisionHeadPosId is null  end     select pelt.Transaction_ID      ,dbo.BufferString_fxn(CONVERT(VARCHAR, (pelt.EmployeeID)), 8, '0') AS Employee_ID      ,ISNULL(EmpCode, '') EmpCode      ,IdNo      ,Surname      ,FirstName      ,DepartmentCode + ' - ' + DepartmentDesc Department       ,DivisionCode  + ' - ' + DivisionDesc Division       ,lt.LeaveType      ,lt.LeaveTypeDesc      ,pelt.StartDate      ,pelt.Value      ,pelt.EndDate      ,CASE pelt.LeaveStatusID     WHEN 1 THEN 'New'     WHEN 2 THEN 'Pending'     WHEN 3 THEN 'Approved'     WHEN 4 THEN 'Declined'     WHEN 5 THEN 'Cancelled'     ELSE ''    END AS LeaveStatus FROM (select * from Payroll_EmployeeLeaveTransactions where EmployeeID in (select EmployeeID from @Employees) and LeaveStatusID in (1,2) and Enabled = 1) pelt   INNER JOIN dbo.Payroll_Employee AS pe    ON pelt.EmployeeID = pe.Employee_ID   INNER JOIN dbo.Payroll_Position AS pp    ON pe.PositionID = pp.Position_ID   INNER JOIN dbo.Const_Division AS cd    ON cd.Division_ID = pp.DivisionID   INNER JOIN dbo.Const_Department AS cdep    on cdep.Department_ID = cd.DepartmentID   INNER JOIN dbo.Const_LeaveType AS lt    ON pelt.LeaveTypeID = lt.LeaveType_ID        END

GO

-- ============================================
-- SP: Payroll_LeaveBalance
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-21  -- Description: Used as a dataset for Leave Register report (HR_LeaveBalance.rdl)  --              Returns Employee Leave Balance for given date  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_LeaveBalance]      @Date DATETIME2,      @DepartmentId INT,      @DivisionId INT,      @EmployeeSubtypeId INT,      @LeaveTypeId INT,      @EmployeeTypeId INT,      @EmployeeId INT  AS  BEGIN       DECLARE @StartDate datetime = (SELECT DATEFROMPARTS(YEAR(@date), 1, 1))     DECLARE @LeaveTable table   (    EmployeeId int,    EmpCode varchar(10),    FirstName varchar(100),    Surname varchar(100),    JoiningDate datetime,    LeaveSchemeId int,    LeaveSchemeDesc varchar(250),    LeaveTypeId int,    LeaveTypeDesc varchar(250),    LeaveAdjustmentType varchar(100),    DocumentNumber varchar(100),    Startdate datetime,    Enddate datetime,    Datecaptured datetime,    Status varchar(20),    Days decimal(18,2)   )     insert into @LeaveTable   exec Payroll_LeaveRegister  @StartDate,@Date,@DepartmentId,@DivisionId,0,0,0,@EmployeeID     select * from(     select leave.EmployeeId AS EmployeeId,     leave.FirstName,      leave.Surname,      dep.DepartmentDesc,      div.DivisionDesc,     LeaveTypeDesc,     SUM(leave.Days) AS LeaveBalance from @LeaveTable leave     Left Join Payroll_Employee emp on emp.Employee_ID = leave.EmployeeId     join Payroll_Position pos on emp.PositionID = pos.Position_ID     join Const_Department dep on dep.Department_ID = pos.DepartmentID     join Const_Division div on div.Division_ID = pos.DivisionID     GROUP BY leave.EmployeeId ,     leave.FirstName,      leave.Surname,      dep.DepartmentDesc,      div.DivisionDesc,     LeaveTypeDesc    )LeaveBalances where LeaveBalance <> 0      END

GO

-- ============================================
-- SP: Payroll_LeaveByMonthRpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Jun 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_LeaveByMonthRpt 0, 0, 0, 3, '2013/2014'  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-04-06 TP32628 Ravindra Jijotia: Added LeaveSchemeId & LeaveTypeId filter  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveByMonthRpt]   @EmployeeID INT,   @DepartmentId INT,   @CycleId INT,   @Month INT,   @FinYear VARCHAR(50),   @LeaveSchemeId INT,   @LeaveTypeId INT  AS  BEGIN  ;WITH Cycles  AS  (   SELECT    cpd.[CycleID],    c.[CycleDesc],    MIN(cpd.[PeriodStartDate]) AS 'PeriodStartDate',    MAX(cpd.[PeriodEndDate]) AS 'PeriodEndDate'   FROM    Payroll_CyclePeriodDetails cpd   INNER JOIN    Const_Cycle c ON cpd.[CycleID] = c.[Cycle_ID]   WHERE    cpd.[FinancialYear] = @FinYear   AND (ISNULL(@CycleId, 0) = 0 OR cpd.[CycleID] = @CycleId)   AND DATEPART(MONTH, cpd.[PeriodEndDate]) = @Month   GROUP BY    cpd.[CycleID], c.[CycleDesc]  )    SELECT   YEAR(c.[PeriodEndDate]) AS 'TaxYear',   DATENAME(MONTH, c.[PeriodEndDate]) AS 'Month',   CONCAT(e.[FirstName], ' ', e.[Surname]) AS 'Employee',   dep.[DepartmentDesc] AS 'Department',   c.[CycleDesc] AS 'Cycle',   ls.[LeaveSchemeDesc] AS 'LeaveScheme',   lt.[LeaveTypeDesc] AS 'LeaveType',   SUM(elt.[Value]) AS 'DaysTaken'  FROM   Cycles c  INNER JOIN   Payroll_Employee e ON c.[CycleID] = e.[CycleID]         AND (ISNULL(@LeaveSchemeID, 0) = 0 OR e.[LeaveSchemeID] = @LeaveSchemeID)         AND (ISNULL(@EmployeeID, 0) = 0 OR e.[Employee_ID] = @EmployeeID)  INNER JOIN   Payroll_EmployeeLeaveTransactions elt ON e.[Employee_ID] = elt.[EmployeeID]             AND elt.[Enabled] = 1             AND elt.[LeaveAdjustmentTypeID] = 3             AND elt.[LeaveStatusID] = 3             AND elt.[EndDate] BETWEEN c.[PeriodStartDate] AND c.[PeriodEndDate]             AND (ISNULL(@LeaveTypeId, 0) = 0 OR elt.[LeaveTypeID] = @LeaveTypeId)  INNER JOIN   Payroll_PositionHistory ph ON e.[Employee_ID] = ph.[EmployeeID]           AND e.[JobProfileID] = ph.[JobProfileID]           AND elt.[StartDate] BETWEEN ph.[StartDate] AND ph.[EndDate]           AND (ISNULL(@DepartmentId, 0) = 0 OR ph.[DepartmentID] = @DepartmentId)  INNER JOIN   Const_Department dep ON ph.[DepartmentID] = dep.[Department_ID]  INNER JOIN   Const_Division div ON ph.[DivisionID] = div.[Division_ID]  LEFT JOIN   Const_LeaveType lt ON elt.[LeaveTypeID] = lt.[LeaveType_ID]  LEFT JOIN   Const_LeaveScheme ls ON elt.[LeaveSchemeID] = ls.[LeaveScheme_ID]  GROUP BY   c.[PeriodEndDate],   e.[FirstName], e.[Surname],   dep.[DepartmentDesc],   c.[CycleDesc],   ls.[LeaveSchemeDesc],   lt.[LeaveTypeDesc];  END

GO

-- ============================================
-- SP: Payroll_LeaveByMonthRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 08 JULY 2013  -- Description:    -- CALLS : Payroll_LeaveByMonthRpt_sp  9,'2012/2013','0'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveByMonthRpt_sp]   --@StartDate DATETIME,   --@EndDate DATETIME   @Month INT,   @FinancialYear NVARCHAR(50),   @LEAVETYPE NVARCHAR(50)  AS  BEGIN  DECLARE @MONTHNAME NVARCHAR(50)  DECLARE @FROMDATE DATETIME  DECLARE @TODATE DATETIME  SET @MONTHNAME =(SELECT dbo.GetMonthNameFromId(@Month))    SELECT @FROMDATE= PeriodStartDate, @TODATE=PeriodEndDate FROM Payroll_CyclePeriodDetails WHERE FinancialYear =@FinancialYear AND ProcessingMonth =@MONTHNAME  DECLARE @DisplayFields nvarchar(MAX)  if(@LEAVETYPE != '0')  BEGIN  SELECT  distinct @FROMDATE AS FROMDATE ,@TODATE AS TODATE,  ISNULL (PAY_EMP.FirstName,' ') + ' ' + ISNULL(PAY_EMP.SecondName,' ') + ' '+ ISNULL(PAY_EMP.Surname,' ') AS EmployeeName,    ISNULL((SELECT       PAY_EMP_ATT.[1]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT          WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[1] IN (@LEAVETYPE)),'') AS '1',    ISNULL((SELECT       PAY_EMP_ATT.[2]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear   ) AND  PAY_EMP_ATT.[2] IN (@LEAVETYPE) ),'')AS '2'    ,    ISNULL((SELECT       PAY_EMP_ATT.[3]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[3] IN (@LEAVETYPE)),'') AS '3'    ,    ISNULL((SELECT       PAY_EMP_ATT.[4]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[4] IN (@LEAVETYPE)),'') AS '4'    ,    ISNULL((SELECT       PAY_EMP_ATT.[5]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[5] IN (@LEAVETYPE)),'') AS '5'         ,    ISNULL((SELECT       PAY_EMP_ATT.[6]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[6] IN (@LEAVETYPE)),'') AS '6'    ,    ISNULL((SELECT       PAY_EMP_ATT.[7]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[7] IN (@LEAVETYPE)),'') AS '7'    ,    ISNULL((SELECT       PAY_EMP_ATT.[8]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[8] IN (@LEAVETYPE)),'') AS '8'    ,    ISNULL((SELECT       PAY_EMP_ATT.[9]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[9] IN (@LEAVETYPE)),'') AS '9'    ,    ISNULL((SELECT       PAY_EMP_ATT.[10]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[10] IN (@LEAVETYPE)),'') AS '10'    ,    ISNULL((SELECT       PAY_EMP_ATT.[11]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[11] IN (@LEAVETYPE)),'') AS '11'    ,    ISNULL((SELECT       PAY_EMP_ATT.[12]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[12] IN (@LEAVETYPE)),'') AS '12'    ,    ISNULL((SELECT       PAY_EMP_ATT.[13]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear   ) AND  PAY_EMP_ATT.[13] IN (@LEAVETYPE)),'') AS '13'    ,    ISNULL((SELECT       PAY_EMP_ATT.[14]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[14] IN (@LEAVETYPE)),'') AS '14'    ,    ISNULL((SELECT       PAY_EMP_ATT.[15]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[15] IN (@LEAVETYPE)),'') AS '15'    ,    ISNULL((SELECT       PAY_EMP_ATT.[16]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[16] IN (@LEAVETYPE)),'') AS '16'    ,    ISNULL((SELECT       PAY_EMP_ATT.[17]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[17] IN (@LEAVETYPE)),'') AS '17'    ,    ISNULL((SELECT       PAY_EMP_ATT.[18]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[18] IN (@LEAVETYPE)),'') AS '18'    ,    ISNULL((SELECT       PAY_EMP_ATT.[19]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[19] IN (@LEAVETYPE)),'') AS '19'    ,    ISNULL((SELECT       PAY_EMP_ATT.[20]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[20] IN (@LEAVETYPE)),'') AS '20'    ,    ISNULL((SELECT       PAY_EMP_ATT.[21]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[21] IN (@LEAVETYPE)),'') AS '21'    ,    ISNULL((SELECT       PAY_EMP_ATT.[22]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[22] IN (@LEAVETYPE)),'') AS '22'    ,    ISNULL((SELECT       PAY_EMP_ATT.[23]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[23] IN (@LEAVETYPE)),'') AS '23'    ,    ISNULL((SELECT       PAY_EMP_ATT.[24]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[24] IN (@LEAVETYPE)),'') AS '24'    ,    ISNULL((SELECT       PAY_EMP_ATT.[25]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[25] IN (@LEAVETYPE)),'') AS '25'    ,    ISNULL((SELECT       PAY_EMP_ATT.[26]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[26] IN (@LEAVETYPE)),'') AS '26'    ,    ISNULL((SELECT       PAY_EMP_ATT.[27]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[27] IN (@LEAVETYPE)),'') AS '27'    ,    ISNULL((SELECT       PAY_EMP_ATT.[28]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID  AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear ) AND  PAY_EMP_ATT.[28] IN (@LEAVETYPE)),'') AS '28'    ,    ISNULL((SELECT       PAY_EMP_ATT.[29]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[29] IN (@LEAVETYPE)),'') AS '29'    ,    ISNULL((SELECT       PAY_EMP_ATT.[30]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT    WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[30] IN (@LEAVETYPE)),'') AS '30'    ,    ISNULL((SELECT       PAY_EMP_ATT.[31]    FROM       Payroll_EmployeeAttendance PAY_EMP_ATT     WHERE (PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID AND  UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  ) AND  PAY_EMP_ATT.[31] IN (@LEAVETYPE)),'') AS '31'                           FROM Payroll_Employee PAY_EMP    INNER JOIN Payroll_EmployeeAttendance PAY_EMP_ATT      ON PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID        WHERE UPPER(PAY_EMP_ATT.Month) = UPPER(@Month) and PAY_EMP_ATT.FinancialYear  = @FinancialYear  END  ELSE  BEGIN     SELECT   distinct @FROMDATE AS FROMDATE ,@TODATE AS TODATE,     ISNULL (PAY_EMP.FirstName,' ') + ' ' + ISNULL(PAY_EMP.SecondName,' ') + ' '+ ISNULL(PAY_EMP.Surname,' ') AS EmployeeName,     PAY_EMP_ATT.[1],PAY_EMP_ATT.[2],PAY_EMP_ATT.[3],PAY_EMP_ATT.[4],     PAY_EMP_ATT.[5],PAY_EMP_ATT.[6],PAY_EMP_ATT.[7],     PAY_EMP_ATT.[8],PAY_EMP_ATT.[9],PAY_EMP_ATT.[10],PAY_EMP_ATT.[11],     PAY_EMP_ATT.[12],PAY_EMP_ATT.[13],PAY_EMP_ATT.[14],PAY_EMP_ATT.[15],     PAY_EMP_ATT.[16],PAY_EMP_ATT.[17],PAY_EMP_ATT.[18],PAY_EMP_ATT.[19],     PAY_EMP_ATT.[20],PAY_EMP_ATT.[21],PAY_EMP_ATT.[22],PAY_EMP_ATT.[23],     PAY_EMP_ATT.[24],PAY_EMP_ATT.[25],PAY_EMP_ATT.[26],PAY_EMP_ATT.[27],     PAY_EMP_ATT.[28],PAY_EMP_ATT.[29],PAY_EMP_ATT.[30],PAY_EMP_ATT.[31]                FROM Payroll_Employee PAY_EMP    INNER JOIN Payroll_EmployeeAttendance PAY_EMP_ATT      ON PAY_EMP_ATT.EmployeeID = PAY_EMP.Employee_ID        WHERE PAY_EMP_ATT.Month = @Month and PAY_EMP_ATT.FinancialYear  = @FinancialYear  END      END     

GO

-- ============================================
-- SP: Payroll_LeaveCarryForward_Yearly_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 07 AUG 2013  -- Description: CARRY FOWWARD LEAVE EVERY YEAR  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveCarryForward_Yearly_sp]    AS  BEGIN    DECLARE @DateCaptured DATETIME  DECLARE @CapturerID INT  DECLARE @GENDERID INT  DECLARE @EmployeeID INT  DECLARE @EmployeeJoinDate DATETIME  DECLARE @TotalDays INT  DECLARE @TotalYear Decimal(18,2)  DECLARE @COUNT INT  DECLARE @START INT    SET @DateCaptured =GETDATE()  SET @CapturerID =1  SET @START =1    DECLARE @TEMPEMPLOYEE TABLE(         [EMPLOYEEID] INT,         [JoiningDate] DATETIME,         [ROWNO] INT,         [GENDERID] INT)     DECLARE @EMPLOYEELEAVE TABLE([Employee_Id] INT,          [LeaveType_ID] INT,          [LEAVE] NVARCHAR(50),          [UsedLeave] NVARCHAR(50),          [Enable] BIT,          [DateCaptured] DATETIME,          [CapturerID] INT,          [EntitledLeave] NVARCHAR(50))       INSERT INTO @TEMPEMPLOYEE     SELECT EMPLOYEE_ID,JoiningDate,ROW_NUMBER()OVER (ORDER BY Employee_ID ASC),GENDERID  FROM PAYROLL_EMPLOYEE WHERE ISDUMMY =0 AND EnableD =1    SELECT @COUNT = COUNT(1)   FROM @TEMPEMPLOYEE    WHILE(@START <=@COUNT)    BEGIN   SELECT @EmployeeJoinDate= JoiningDate,@EmployeeID=EmployeeID,@GENDERID = GENDERID FROM  @TEMPEMPLOYEE WHERE ROWNO = @START     SET @TotalDays = DATEDIFF(DAY,@EmployeeJoinDate,GETDATE())   SET @TotalYear = CAST ((@TotalDays/365) AS DECIMAL(18,2))         INSERT INTO @EMPLOYEELEAVE (Employee_Id,LeaveType_ID,LEAVE,UsedLeave,Enable,DateCaptured,CapturerID,EntitledLeave)      SELECT @EmployeeID as EmployeeId,* FROM     ((SELECT        LeaveType_ID,CASE WHEN FALSuspendYear < @TotalYear THEN        '0.0'  ELSE FixedLeaveDays END AS LEAVE,        '0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =1)       UNION               (SELECT        LeaveType_ID,InCrementalLeaveDays as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =2)           UNION               (SELECT        LeaveType_ID,CASE WHEN SLSuspendYear < @TotalYear THEN        '0.0' ELSE SickLeaveDays  END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =3)        UNION               (SELECT        LeaveType_ID,FullSickLeaveDays as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =4)       UNION               (SELECT        LeaveType_ID,HalfSickLeaveDays as LEAVE ,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =5)       UNION               (SELECT        LeaveType_ID,CompanyAccidentLeaveDays as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =6)       UNION               (SELECT        LeaveType_ID,AccidentLeaveDays as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =7)                   UNION               (SELECT        LeaveType_ID,SpecialLeaveDays as LEAVE ,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =8)       UNION               (SELECT        LeaveType_ID,FamilyLeaveDays as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =9)                     UNION               (SELECT        LeaveType_ID,CASE WHEN  @GenderID =1 THEN        MaternityLeaveDays       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =10)     UNION               (SELECT        LeaveType_ID,CASE WHEN   @GenderID =1 THEN        AdditionalMLeaveDays       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =11)      UNION               (SELECT        LeaveType_ID,CASE WHEN @GenderID =1 THEN         AdoptionLeaveDays       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave         FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =12)              UNION               (SELECT        LeaveType_ID,CASE WHEN  @GenderID =1 THEN        AdditionalALeaveDays        ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =13)                                UNION               (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =14)      UNION           (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =15)         UNION           (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave         FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =16)              UNION           (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave         FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =17)        UNION           (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave         FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =18)              UNION           (SELECT        LeaveType_ID,CASE WHEN  @TotalYear > YearRange THEN        BonusLeave       ELSE        '0'         END as LEAVE,'0.0' as UsedLeave,        1 as Enable,@DateCaptured as DateCaptured,        @CapturerID as CapturerID,        '0.0' as EntitledLeave        FROM Payroll_LeaveDefinition        WHERE LeaveType_ID =19) ) AS TEMP            SET @START =@START +1              END    SELECT * FROM @EMPLOYEELEAVE    UPDATE Payroll_EmployeeLeave SET LeaveBalance=EMP.Leave,UsedLeave=EMP.UsedLeave, EntitledLeave =  EMP.EntitledLeave  FROM @EMPLOYEELEAVE AS EMP  WHERE EmployeeId=EMP.Employee_Id AND LeaveTypeID=EMP.LeaveType_ID  END     

GO

