-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,09 Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_LeaveEscalationReassignEmail 7  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveEscalationReassignEmail] @History_Id INT  AS       BEGIN          DECLARE @IsReassigned BIT ,              @IsEscalation BIT ,              @LeaveApproveRequestId INT ,              @EmployeeId INT ,              @JobProfileId INT ,              @IsApproved BIT ,              @Msg_Body VARCHAR(MAX) ,              @Schedule_Id INT ,              @Subject NVARCHAR(50) ,              @URL NVARCHAR(50)      --       SELECT  @Msg_Body = TemplateText ,   --               @Schedule_Id = Schedule_ID   --       FROM    dbo.Cons_Email_Template   --               INNER JOIN dbo.Cons_Email_Schedule ON dbo.Cons_Email_Template.Template_ID = dbo.Cons_Email_Schedule.TemplateID   --       WHERE   TemplateTitle = 'Leave Request / Approve / Escalate / Reassigned'   --               AND ModuleID = 3   --               AND SendingType = 'Email'       --       SELECT  @URL = KeyValue   --       FROM    dbo.AAAA_ConfigSettings   --       WHERE   KeyName = 'SchedulerPageUrl'     --       SELECT  @IsReassigned = IsReassigned ,   --               @IsEscalation = IsEscalation ,   --               @LeaveApproveRequestId = LeaveApproveRequestId ,   --               @EmployeeId = EmployeeId ,   --               @JobProfileId = JobProfileId ,   --               @IsApproved = IsApproved   --       FROM    Payroll_LeaveEscalationReassigneHistory   --       WHERE   History_Id = @History_Id      -------------- Request Detail --------------   --       DECLARE @RequestDetail NVARCHAR(MAX)   --       SET @RequestDetail = '<table align="left" border="0" cellpadding="0" cellspacing="0" style="width:100%"><tbody><tr><td width="20%">Employee :</td><td>##EmployeeName##</td></tr>   -- <tr><td>Company :</td><td>##Municipality##</td></tr><tr><td>Employee Code :</td><td>##EmployeeNo##</td></tr><tr><td>Submitted :</td><td>##SubmittedOn##</td></tr>   -- <tr><td>From Date :</td><td>##FromDate##</td></tr><tr><td>To Date :</td><td>##ToDate##</td></tr><tr><td>Day(s) Requested :</td><td>##RequstedDays##</td></tr>   -- <tr><td>Reason :</td><td>##Reason##</td></tr></tbody></table>'   -- --<tr><td>Submitter Comment :</td><td>##SubmitterComment##</td></tr>   --       DECLARE @EmpName NVARCHAR(50) ,   --           @Municipality NVARCHAR(50) ,   --           @EmployeeNo NVARCHAR(50) ,   --           @SubmittedOn DATETIME ,   --           @FromDate DATETIME ,   --           @ToDate DATETIME ,   --           @TotalDays INT ,   --           @Reason NVARCHAR(500) ,   --           @LeaveType VARCHAR(500)      --       SELECT TOP 1   --               @Municipality = MunicipalityName   --       FROM    dbo.Payroll_Municipality   --       SELECT  @EmpName = FirstName + ' ' + Surname ,   --               @EmployeeNo = Employee_ID ,   --               @FromDate = RequestFromDate ,   --               @ToDate = RequestToDate ,   --               @TotalDays = RequestNoOfDays ,   --               @Reason = RequestReason ,   --               @SubmittedOn = P_LA.DateCaptured ,   --               @LeaveType = LeaveType   --       FROM    dbo.Payroll_LeaveApproveRequest AS P_LA   --               INNER JOIN dbo.Payroll_Employee AS P_E ON P_LA.EmployeeID = P_E.Employee_ID   --               INNER JOIN dbo.Const_LeaveType AS C_LT ON P_LA.LeaveTypeID = C_LT.LeaveType_ID   --       WHERE   LeaveApproveRequest_ID = @LeaveApproveRequestId      --       SET @RequestDetail = REPLACE(@RequestDetail, '##EmployeeName##',   --                                    @EmpName)   --       SET @RequestDetail = REPLACE(@RequestDetail, '##Municipality##',   --                                    @Municipality)   --       SET @RequestDetail = REPLACE(@RequestDetail, '##EmployeeNo##',   --                                    dbo.BufferString_fxn(@EmployeeNo, 8, '0'))   --       SET @RequestDetail = REPLACE(@RequestDetail, '##SubmittedOn##',   --                                    CONVERT(VARCHAR(50), @SubmittedOn, 103))   --       SET @RequestDetail = REPLACE(@RequestDetail, '##FromDate##',   --                                    CONVERT(VARCHAR(50), @FromDate, 103))   --       SET @RequestDetail = REPLACE(@RequestDetail, '##ToDate##',   --                                    CONVERT(VARCHAR(50), @ToDate, 103))   --       SET @RequestDetail = REPLACE(@RequestDetail, '##RequstedDays##',   --                                    @TotalDays)   --       SET @RequestDetail = REPLACE(@RequestDetail, '##Reason##', @Reason)   ----SET @RequestDetail = REPLACE(@RequestDetail, '##EmployeeName##', @EmpName)   --       PRINT @RequestDetail   --------------- Request History --------------   --       DECLARE @TblEmp TABLE   --           (   --             Id INT IDENTITY(1, 1) ,   --             EmpName VARCHAR(50) ,   --             Email VARCHAR(50) ,   --             EmployeeId INT   --           )   --       DECLARE @RequestHistory NVARCHAR(MAX) ,   --           @Flag NVARCHAR(MAX) ,   --           @Count INT ,   --           @Start INT = 1 ,   --           @EmailId NVARCHAR(50) ,   --           @Co INT   --       DECLARE @Emp1 NVARCHAR(50) ,   --           @EmpId1 NVARCHAR(50) ,   --           @CapturerId INT ,   --           @Capturer NVARCHAR(100)      --       DECLARE @History TABLE   --           (   --             Id INT IDENTITY(1, 1) ,   --             EmployeeId INT ,   --             JobProfileId INT ,   --             IsEsacalation BIT ,   --             IsReassigned BIT ,   --             DateCap DATETIME ,   --             CapturerId INT ,   --             IsApproved BIT   --           )      --       INSERT  INTO @History   --               ( EmployeeId ,   --                 JobProfileId ,   --                 IsEsacalation ,   --                 IsReassigned ,   --                 DateCap ,   --                 CapturerId ,   --                 IsApproved    --               )   --               SELECT  EmployeeId ,   --                       JobProfileId ,   --                       IsEscalation ,   --                       IsReassigned ,   --                       DateCaptured ,   --                       CapturerId ,   --                       IsApproved   --               FROM    Payroll_LeaveEscalationReassigneHistory   --               WHERE   LeaveApproveRequestId = @LeaveApproveRequestId      --       SELECT  @Co = COUNT(*)   --       FROM    @History      --       IF @IsReassigned = 0   --           AND @IsApproved = 0    --           BEGIN   --               INSERT  INTO @TblEmp   --                       SELECT  FirstName + ' ' + Surname ,   --                               EmailAddress ,   --                               Employee_ID   --                       FROM    dbo.Payroll_JobProfile AS P_JP   --                               INNER JOIN dbo.Payroll_Employee AS P_E ON P_JP.JobProfile_ID  = P_E.JobProfileID   --                       WHERE   JobProfile_ID = @JobProfileId   --                               AND P_E.EmailAddress IS NOT NULL   --                               AND P_E.EmailAddress <> ''   --           END   --       ELSE    --           BEGIN   --               INSERT  INTO @TblEmp   --                       SELECT  FirstName + ' ' + Surname ,   --                               EmailAddress ,   --                               Employee_ID   --                       FROM    Payroll_Employee   --                       WHERE   Employee_ID = @EmployeeId   --           END      --       SELECT  @Count = COUNT(*)   --       FROM    @TblEmp   --       IF @IsApproved = 1    --           BEGIN   --               PRINT 'APPROVED'   --               SET @Subject = 'Leave Approved'     --               SET @Flag = '<p>APPROVED: ' + @LeaveType + ' Request for '   --                   + @EmpName + '</p>'   --               SET @Flag = @Flag   --                   + '<p>You are the submitter for this request. This is a notification and no action is required by you. </p>'   --               SET @RequestHistory = '<p><span style="color:#0066cc"><u><strong>Current Status Of Request</strong></u></span></p><p>This Annual Leave Request is approved by approver</p>'   --               SET @RequestHistory = @RequestHistory   --                   + '<p><span style="color:#0066cc"><u><strong>History Of Request</strong></u></span></p>'   --               SET @RequestHistory = @RequestHistory + '1. CREATED: '   --                   + @LeaveType + ' Requested on '   --                   + CONVERT(VARCHAR(50), @SubmittedOn) + ' by Applicant '   --                   + @EmpName   --               SET @Start = 2   --               WHILE ( @Start < @Co )    --                   BEGIN   --                       SELECT  @IsEscalation = IsEsacalation ,   --                               @IsReassigned = IsReassigned ,   --                               @SubmittedOn = DateCap ,   --                               @EmpId1 = EmployeeId ,   --                               @JobProfileId = JobProfileId ,   --                               @CapturerId = CapturerId ,   --                               @IsApproved = IsApproved   --                       FROM    @History   --                       WHERE   Id = @Start   --                       IF @IsEscalation = 1    --                           BEGIN   --                               SET @RequestHistory = @RequestHistory   --                                   + CONVERT(VARCHAR(10), @Start)   --                                   + '. ESCALATED: ' + @LeaveType   --                                   + ' Requested on '   --                                   + CONVERT(VARCHAR(50), @SubmittedOn)   --                                   + ' to ##EmployeeName## by Work flow system '   --                           END   --                       ELSE    --                           IF @IsReassigned = 1    --                               BEGIN   --                                   SELECT  @Emp1 = FirstName + ' ' + Surname   --                                   FROM    dbo.Payroll_Employee   --                                   WHERE   Employee_ID = @EmpId1   --                                   SELECT  @Capturer = FirstName + ' '   --                                           + Surname   --                                   FROM    dbo.Payroll_Employee   --                                   WHERE   Employee_ID = @CapturerId   --                                   SET @RequestHistory = @RequestHistory   --                                       + CONVERT(VARCHAR(10), @Start)   --                                       + '. REASSIGNED: ' + @LeaveType   --                                       + ' Requested on '   --                                       + CONVERT(VARCHAR(50), @SubmittedOn)   --                                       + ' from ' + @Capturer + ' To '   --                                       + @Emp1 + ' By Approver ' + @Capturer   --                               END   --                           ELSE    --                               IF @IsApproved = 1    --                                   BEGIN   --                                       SELECT  @Emp1 = FirstName + ' '   --                                               + Surname   --                                       FROM    dbo.Payroll_Employee   --                                       WHERE   Employee_ID = @EmpId1   --                                       SELECT  @Capturer = FirstName + ' '   --                                               + Surname   --                                       FROM    dbo.Payroll_Employee   --                                       WHERE   Employee_ID = @CapturerId   --                                       SET @RequestHistory = @RequestHistory   --                                           + CONVERT(VARCHAR(10), @Start)   --                                           + '. APPROVED: ' + @LeaveType   --                                           + ' Requested on '   --                                           + CONVERT(VARCHAR(50), @SubmittedOn)   --                                           + ' by Approver ' + @Capturer   --                                   END   --                       SET @Start = @Start + 1     --                   END       --               PRINT @RequestHistory   --               SET @Msg_Body = REPLACE(@Msg_Body, '##URL##', @URL)   --               SET @Msg_Body = REPLACE(@Msg_Body, '##FLAG##', @Flag)   --               SET @Msg_Body = REPLACE(@Msg_Body, '##RequestDetail##',   --                                       @RequestDetail)   --               SET @Msg_Body = REPLACE(@Msg_Body, '##RequestHistory##',   --                                       @RequestHistory)       --               SET @Start = 1   --               WHILE ( @Start <= @Count )    --                   BEGIN   --                       SELECT  @EmpName = EmpName ,   --                               @EmployeeId = EmployeeId   --                       FROM    @TblEmp   --                       WHERE   Id = @Start   --                       INSERT  INTO dbo.Cons_Email_Schedule_Details   --                               ( ScheduleID ,   --                                 SendTo ,   --                                 Subject ,   --                                 Message ,   --                                 IsSent ,   --                                 ReferanceID   --                               )   --                               SELECT  @Schedule_Id ,   --                                       @EmployeeId ,   --                                       @Subject ,   --                                       REPLACE(@Msg_Body, '##EmployeeName##',   --                                               @EmpName) ,   --                                       0 ,   --                                       @History_Id     --                       SET @Start = @Start + 1   --                   END   --           END   --       ELSE    --           IF @IsReassigned = 1    --               BEGIN   --                   PRINT 'Reassign'     --                   SET @Subject = 'Leave Reassign'   --                   SET @Flag = '<p>REASSIGNED: ' + @LeaveType   --                       + ' Requested for ' + @EmpName + '</p>'   --                   SET @Flag = @Flag   --                       + '<p>You are the approver for this request, but this request has now been reassigned to another approver. This is a notification and no action is required by you. </p>'   --                   SET @RequestHistory = '<p><span style="color:#0066cc"><u><strong>Current Status Of Request</strong></u></span></p><p>This '   --                       + @LeaveType   --                       + ' Request is waiting to be approved by the next approver</p>'   --                   SET @RequestHistory = @RequestHistory   --                       + '<p><span style="color:#0066cc"><u><strong>History Of Request</strong></u></span></p>'   --                   SET @RequestHistory = @RequestHistory + '1. CREATED: '   --                       + @LeaveType + ' Requested on '   --                       + CONVERT(VARCHAR(50), @SubmittedOn)   --                       + ' by Applicant ' + @EmpName   --                   SET @Start = 2   --                   WHILE ( @Start < @Co )    --                       BEGIN   --                           SELECT  @IsEscalation = IsEsacalation ,   --                                   @IsReassigned = IsReassigned ,   --                                   @SubmittedOn = DateCap ,   --                                   @EmpId1 = EmployeeId ,   --                                   @JobProfileId = JobProfileId ,   --                                   @CapturerId = CapturerId   --                           FROM    @History   --                           WHERE   Id = @Start   --                           IF @IsEscalation = 1    --                               BEGIN   --                                   SET @RequestHistory = @RequestHistory   --                                       + CONVERT(VARCHAR(10), @Start)   --                                       + '. ESCALATED: ' + @LeaveType   --                                       + ' Requested on '   --                                       + CONVERT(VARCHAR(50), @SubmittedOn)   --                                       + ' to ##EmployeeName## by Work flow system '   --                               END   --                           ELSE    --                               IF @IsReassigned = 1    --                                   BEGIN   --                                       SELECT  @Emp1 = FirstName + ' '   --                                               + Surname   --                                       FROM    dbo.Payroll_Employee   --                                       WHERE   Employee_ID = @EmpId1   --                                       SELECT  @Capturer = FirstName + ' '   --                                               + Surname   --                                       FROM    dbo.Payroll_Employee   --                                       WHERE   Employee_ID = @CapturerId   --                                       SET @RequestHistory = @RequestHistory   --                                           + CONVERT(VARCHAR(10), @Start)   --                                           + '. REASSIGNED: ' + @LeaveType   --                                           + ' Requested on '   --                                           + CONVERT(VARCHAR(50), @SubmittedOn)   --                                           + ' from ' + @Capturer + ' To '   --                                           + @Emp1 + ' By Approver '   --                                           + @Capturer   --                                   END        --                           SET @Start = @Start + 1     --                       END   --                   SET @Start = 1    --                   SET @RequestHistory = @RequestHistory   --                       + '<p><span style="color:#0066cc"><u><strong>Remaining Approvers</strong></u></span></p>'   --                   WHILE ( @Start <= @Count )    --                       BEGIN   --                           SELECT  @EmpName = EmpName   --                           FROM    @TblEmp   --                           WHERE   Id = @Start   --                           SET @RequestHistory = @RequestHistory + '<p>'   --                               + CONVERT(VARCHAR(10), @Start) + '. User: '   --                               + @EmpName + '</p>'   --                           SET @Start = @Start + 1   --                       END   --                   PRINT @RequestHistory   --                   SET @Msg_Body = REPLACE(@Msg_Body, '##URL##', @URL)   --                   SET @Msg_Body = REPLACE(@Msg_Body, '##FLAG##', @Flag)   --                   SET @Msg_Body = REPLACE(@Msg_Body, '##RequestDetail##',   --                                           @RequestDetail)   --                   SET @Msg_Body = REPLACE(@Msg_Body, '##RequestHistory##',   --                                           @RequestHistory)       --                   SET @Start = 1   --                   WHILE ( @Start <= @Count )    --                       BEGIN   --                           SELECT  @EmpName = EmpName ,   --                                   @EmployeeId = EmployeeId   --                           FROM    @TblEmp   --                           WHERE   Id = @Start   --                           INSERT  INTO dbo.Cons_Email_Schedule_Details   --                                   ( ScheduleID ,   --                                     SendTo ,   --                                     Subject ,   --                                     Message ,   --                                     IsSent ,   --                                     ReferanceID   --                                   )   --                                   SELECT  @Schedule_Id ,   --                                           @EmployeeId ,   --                                           @Subject ,   --                                           REPLACE(@Msg_Body,   --                                                   '##EmployeeName##',   --                                                   @EmpName) ,   --                                           0 ,   --                                           @History_Id     --                           SET @Start = @Start + 1   --                       END   --               END   --           ELSE    --               IF @IsEscalation = 1    --                   BEGIN   --                       PRINT 'Escalation'   --                       SET @Subject = 'Leave Escalation'   --                       SET @Flag = '<p>ESCALATED: ' + @LeaveType   --                           + ' Requested for ' + @EmpName + '</p>'   --                       SET @Flag = @Flag   --                           + '<p>You are the new approver for this request. You are required to action this request. </p>'   --                       SET @RequestHistory = '<p><span style="color:#0066cc"><u><strong>Current Status Of Request</strong></u></span></p><p>This '   --                           + @LeaveType   --                           + ' Request is waiting to be approved by the next approver</p>'   --                       SET @RequestHistory = @RequestHistory   --                           + '<p><span style="color:#0066cc"><u><strong>History Of Request</strong></u></span></p>'   --                       SET @RequestHistory = @RequestHistory + '1. CREATED: '   --                           + @LeaveType + ' Requested on '   --                           + CONVERT(VARCHAR(50), @SubmittedOn)   --                           + ' by Applicant ' + @EmpName   --                       SET @Start = 2   --                       WHILE ( @Start < @Co )    --                           BEGIN   --                               SELECT  @IsEscalation = IsEsacalation ,   --                                       @IsReassigned = IsReassigned ,   --                                       @SubmittedOn = DateCap ,   --                                       @EmpId1 = EmployeeId ,   --                                       @JobProfileId = JobProfileId ,   --                                       @CapturerId = CapturerId   --                               FROM    @History   --                               WHERE   Id = @Start   --                               IF @IsEscalation = 1    --                                   BEGIN   --                                       SET @RequestHistory = @RequestHistory   --                                           + CONVERT(VARCHAR(10), @Start)   --                                           + '. ESCALATED: ' + @LeaveType   --                                           + ' Requested on '   --                                           + CONVERT(VARCHAR(50), @SubmittedOn)   --                                           + ' to ##EmployeeName## by Work flow system '   --                                   END   --                               ELSE    --                                   IF @IsReassigned = 1    --                                       BEGIN   --                                           SELECT  @Emp1 = FirstName + ' '   --                                                   + Surname   --                                           FROM    dbo.Payroll_Employee   --                                           WHERE   Employee_ID = @EmpId1   --                                           SELECT  @Capturer = FirstName   --                                                   + ' ' + Surname   --                                           FROM    dbo.Payroll_Employee   --                                           WHERE   Employee_ID = @CapturerId   --                                           SET @RequestHistory = @RequestHistory   --                                               + CONVERT(VARCHAR(10), @Start)   --                                               + '. REASSIGNED: '   --                                               + @LeaveType   --                                               + ' Requested on '   --                                               + CONVERT(VARCHAR(50), @SubmittedOn)   --                                               + ' from ' + @Capturer   --                                               + ' To ' + @Emp1   --                                               + ' By Approver ' + @Capturer   --                                       END        --                               SET @Start = @Start + 1     --                           END   --                       SET @Start = 1    --                       SET @RequestHistory = @RequestHistory   --                           + '<p><span style="color:#0066cc"><u><strong>Remaining Approvers</strong></u></span></p>'   --                       WHILE ( @Start <= @Count )    --                           BEGIN   --                               SELECT  @EmpName = EmpName   --                               FROM    @TblEmp   --                               WHERE   Id = @Start   --                               SET @RequestHistory = @RequestHistory + '<p>'   --                                   + CONVERT(VARCHAR(10), @Start)   --                                   + '. User: ' + @EmpName + '</p>'   --                               SET @Start = @Start + 1   --                           END   --                       PRINT @RequestHistory   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##URL##', @URL)   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##FLAG##', @Flag)   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##RequestDetail##',   --                                               @RequestDetail)   --                       SET @Msg_Body = REPLACE(@Msg_Body,   --                                               '##RequestHistory##',   --                                               @RequestHistory)       --                       SET @Start = 1   --                       WHILE ( @Start <= @Count )    --                           BEGIN   --                               SELECT  @EmpName = EmpName ,   --                                       @EmployeeId = EmployeeId   --                               FROM    @TblEmp   --                               WHERE   Id = @Start   --                               INSERT  INTO dbo.Cons_Email_Schedule_Details   --                                       ( ScheduleID ,   --                                         SendTo ,   --                                         Subject ,   --                                         Message ,   --                                         IsSent ,   --                                         ReferanceID   --                                       )   --                                       SELECT  @Schedule_Id ,   --                                               @EmployeeId ,   --                                               @Subject ,   --                                               REPLACE(@Msg_Body,   --                                                       '##EmployeeName##',   --                                                       @EmpName) ,   --                                               0 ,   --                                               @History_Id     --                               SET @Start = @Start + 1   --                           END   --                   END   --               ELSE    --                   BEGIN   --                       PRINT 'Created'           --                       SET @Subject = 'Leave Created'   --                       SET @Flag = '<p>CREATED: ' + @LeaveType   --                           + ' Requested for ' + @EmpName + '</p>'   --                       SET @Flag = @Flag   --                           + '<p>You are the new approver for this request. You are required to action this request.</p>'   --                       SET @RequestHistory = '<p><span style="color:#0066cc"><u><strong>Current Status Of Request</strong></u></span></p><p>This '   --                           + @LeaveType   --                           + ' Request is waiting to be approved by the next approver</p>'   --                       SET @RequestHistory = @RequestHistory   --                           + '<p><span style="color:#0066cc"><u><strong>History Of Request</strong></u></span></p>'   --                       SET @RequestHistory = @RequestHistory + '1. CREATED: '   --                           + @LeaveType + ' Requested on '   --                           + CONVERT(VARCHAR(50), @SubmittedOn)   --                           + ' by Applicant ' + @EmpName   --                       SET @RequestHistory = @RequestHistory   --                           + '<p><span style="color:#0066cc"><u><strong>Remaining Approvers</strong></u></span></p>'   --                       WHILE ( @Start <= @Count )    --                           BEGIN   --                               SELECT  @EmpName = EmpName   --                               FROM    @TblEmp   --                               WHERE   Id = @Start   --                               SET @RequestHistory = @RequestHistory + '<p>'   --                                   + CONVERT(VARCHAR(10), @Start)   --                                   + '. User: ' + @EmpName + '</p>'   --                               SET @Start = @Start + 1   --                           END   --                       PRINT @RequestHistory   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##URL##', @URL)   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##FLAG##', @Flag)   --                       SET @Msg_Body = REPLACE(@Msg_Body, '##RequestDetail##',   --                                               @RequestDetail)   --                       SET @Msg_Body = REPLACE(@Msg_Body,   --                                               '##RequestHistory##',   --                                               @RequestHistory)       --                       SET @Start = 1   --                       WHILE ( @Start <= @Count )    --                           BEGIN   --                               SELECT  @EmpName = EmpName ,   --                                       @EmployeeId = EmployeeId   --                               FROM    @TblEmp   --                               WHERE   Id = @Start        --                               INSERT  INTO dbo.Cons_Email_Schedule_Details   --                                       ( ScheduleID ,   --                                         SendTo ,   --                                         Subject ,   --                                         Message ,   --                                         IsSent ,   --                                         ReferanceID   --                                       )   --                                       SELECT  @Schedule_Id ,   --                                               @EmployeeId ,   --                                               @Subject ,   --                                               REPLACE(@Msg_Body,   --                                                       '##EmployeeName##',   --                                                       @EmpName) ,   --                                               0 ,   --                                               @History_Id     --                               SET @Start = @Start + 1   --                           END   --                   END      END    

