-- ============================================
-- SP: Payroll_LeaveRegister
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-18  -- Description: Used as a dataset for Leave Register report (Payroll_LeaveRegister.rdl)  --              Returns all Leave Transactions captured during specific period    --Exec Payroll_LeaveRegister '2022/08/01','2023/06/30',0,0,0,0,0,0    -- Richa M - 2023/10/26 - Include Report Opening Balances  -- Richa M - 2025/01/30 - Leave Register to give the actual leave balance on end date of report (WI113669)     --Exec Payroll_LeaveRegister '2024/07/01','2025/01/31',0,0,0,0,24,0  -- =============================================     CREATE PROCEDURE [dbo].[Payroll_LeaveRegister]      @StartDate DATETIME2,      @EndDate DATETIME2,      @DepartmentId INT,      @DivisionId INT,      @CycleId INT,      @LeaveTypeId INT,      @LeaveSchemeId INT,      @EmployeeId INT  AS  BEGIN    DECLARE    @TermCycle INT = (select Cycle_ID from Const_Cycle where CycleDesc = 'Ad Hoc Termination')   --Cursor 2 - update Leave Days   declare @EmpId int   declare @lstartDate datetime   declare @lenddate datetime         DECLARE db_cursor1 CURSOR FOR      select EmployeeID,StartDate,EndDate from Payroll_EmployeeLeaveTransactions where LeaveAdjustmentTypeID = 3 and Enabled = 1 and LeaveStatusID in (1,3) and (EmployeeID = @EmployeeId OR @EmployeeId = 0)       OPEN db_cursor1     FETCH NEXT FROM db_cursor1 INTO @EmpId,@lstartDate,@lEndDate       WHILE @@FETCH_STATUS = 0     BEGIN       update Payroll_EmployeeCalander set Leave = 1 where EmployeeID = @EmpId and date >= @lstartDate and Date <= @lenddate and Shift = 1 and PublicH = 0      FETCH NEXT FROM db_cursor1 INTO @EmpId,@lstartDate,@lEndDate     END      CLOSE db_cursor1     DEALLOCATE db_cursor1          Select LeaveScheme_ID, Leaveschemedesc,LeaveType_ID,LeaveTypeDesc, Leave.* Into #temp from(    select * from(       select EmployeeID,LeaveSchemeID,LeaveTypeID,LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,StartDate CalDate,'None' DayName,0 PublicH,1 Leave,1 Shift,Value as Average,DateCaptured       from Payroll_EmployeeLeaveTransactions       where LeaveStatusID = 3      and Enabled = 1      and StartDate <= @EndDate       and (EmployeeID = @EmployeeId OR @EmployeeId = 0)      and (LeaveTypeID = @LeaveTypeId OR @LeaveTypeId = 0)      and StartDate = EndDate   Union ALL    select LeaveTransactions.EmployeeID,LeaveSchemeID,LeaveTransactions.LeaveTypeID,LeaveTransactions.LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,cal.Date,DayName,PublicH,Leave,Shift,Round((abs(value)/NumberOfDaysRequested)* -1,2) Average,LeaveTransactions.DateCaptured     from(      select EmployeeID,LeaveSchemeID,LeaveTypeID,LeaveAdjustmentTypeID,StartDate,EndDate,Value,Notes,DocumentNumber,NumberOfDaysRequested,DateCaptured      from Payroll_EmployeeLeaveTransactions       where LeaveStatusID = 3      and Enabled = 1      and StartDate <= @EndDate       AND (EmployeeID = @EmployeeId OR @EmployeeId = 0)      AND (LeaveTypeID = @LeaveTypeId OR @LeaveTypeId = 0)      AND StartDate <> EndDate)LeaveTransactions      join Payroll_EmployeeCalander cal on cal.Date between LeaveTransactions.StartDate and LeaveTransactions.EndDate and cal.EmployeeID = LeaveTransactions.EmployeeID)EmpCal    where calDate <= @EndDate     and Leave = 1     and PublicH = 0 and Shift = 1)Leave     join Payroll_employee emp on emp.Employee_ID = Leave.EmployeeID   join Const_LeaveScheme ls on ls.LeaveScheme_ID = Leave.LeaveSchemeID   join Const_LeaveType lt on lt.LeaveType_ID = Leave.LeaveTypeID          ----OpeningBalance   Select Employee_ID EmployeeId,EmpCode,FirstName,Surname,JoiningDate,lt.LeaveScheme_ID,ls.LeaveSchemeDesc,LeaveType_ID,lt.LeaveTypeDesc,ladj.LeaveAdjustmentType LeaveAdjustmentType,   DocumentNumber,lt.StartDate,lt.EndDate,lt.DateCaptured,'Approved' Status,Cast(Balance as decimal(18,2)) Days   from(    select EmployeeId,LeaveTypeID,LeaveScheme_ID,LeaveSchemeDesc,LeaveTypeDesc, 'Opening Balance' DocumentNumber,Min(CalDate)StartDate,@StartDAte EndDate,@StartDAte DateCaptured,Sum(Average)Balance,1 LeaveAdjustmentTypeId     from #temp     where CalDate < @StartDAte    group by EmployeeId,LeaveTypeID,LeaveScheme_ID,LeaveSchemeDesc,LeaveTypeDesc   Union All   ----Transactions    select EmployeeID ,LeaveTypeID,LeaveScheme_ID,LeaveSchemeDesc,LeaveTypeDesc,DocumentNumber,StartDate,EndDate,DateCaptured,SUM(Average) ,LeaveAdjustmentTypeID    from #temp     where CalDate >= @StartDAte and CalDate <= @EndDate    group by EmployeeID ,LeaveTypeID,LeaveScheme_ID,LeaveSchemeDesc,LeaveTypeDesc,DocumentNumber,StartDate,EndDate,DateCaptured,LeaveAdjustmentTypeID    )lt    left join Payroll_employee emp on emp.Employee_ID = lt.EmployeeID  left join Payroll_Position AS P   ON P.Position_ID = emp.PositionID  left join Const_Department AS DEP   ON P.DepartmentID = DEP.Department_ID  left join Const_Division AS DIV   ON P.DivisionID = DIV.Division_ID  join Const_LeaveScheme ls on ls.LeaveScheme_ID = emp.LeaveSchemeID  join Const_LeaveType clt on clt.LeaveType_ID = lt.LeaveTypeID  join Const_LeaveAdjustmentType_sys ladj on ladj.LeaveAdjustmentType_ID = lt.LeaveAdjustmentTypeId    where    (ISNULL(@DepartmentId, 0) = 0 OR DEP.Department_ID = @DepartmentId)      and (ISNULL(@DivisionId, 0) = 0 OR DIV.Division_ID = @DivisionId)      and (ISNULL(@CycleId, 0) = 0 OR emp.CycleID = @CycleId)   and (ISNULL(@LeaveSchemeId, 0) = 0 OR emp.LeaveSchemeID = @LeaveSchemeId)   and LeaveClassificationID not in (case when emp.GenderID = 1 THEN 9 ELSE 3 END )   order by StartDate   drop table #temp      END

GO

-- ============================================
-- SP: Payroll_LeaveRequestList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Richa Mills>  -- Create date: <2018/01/18>  -- Description: <Description,,>  -- Call SP    : Payroll_LeaveRequestList_sp '', '', 0,0  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_LeaveRequestList_sp]   @Name NVARCHAR(100),        @Surname NVARCHAR(100),        @EmployeeId INT,   @AbsenceTypeId INT  AS  BEGIN      SELECT Transaction_Id,dbo.BufferString_fxn(CONVERT(VARCHAR, ( LeaveRequest.EmployeeId )), 8,'0') AS Employee_ID,EmpCode, IdNo, Surname, FirstName,lat.AbsenceType LeaveType,    LeaveRequest.StartDate RequestFromDate,LeaveRequest.EndDate RequestToDate,Value RequestNoOfDays,Notes,stat.StatusDesc LeaveStatus   from   (SELECT * FROM Payroll_EmployeeLeaveTransactions WHERE LeaveAdjustmentTypeId = 3)LeaveRequest   LEFT OUTER JOIN Payroll_Employee Emp     ON Emp.Employee_ID = LeaveRequest.EmployeeId   LEFT OUTER JOIN Const_LeaveType Lt     ON lt.LeaveType_ID = LeaveRequest.LeaveTypeId   LEFT OUTER JOIN Const_AbsenceType lat    ON lat.AbsenceType_ID = LeaveRequest.AbsenceTypeId   LEFT OUTER JOIN Const_LeaveStatus_sys stat    ON stat.Status_Id = LeaveRequest.LeaveStatusID   WHERE (EmployeeId = @EmployeeId OR ISNULL(@EmployeeId,0) = 0) AND (lat.AbsenceType_ID = @AbsenceTypeId OR @AbsenceTypeId = 0)      END

GO

-- ============================================
-- SP: Payroll_LeaveSummary
-- Schema: dbo
-- ============================================
 -- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-18  -- Description: Used as a dataset for Captured Leave Transactions report (Payroll_LeaveSummary.rdl)  --              Returns summary Leave Transactions    -- Edit:  Richa M 2023/05/16 - Remove the Start and End Date validation as it doesn't make sense on this report  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_LeaveSummary]      @TaxYear VARCHAR(10),      @EmployeeID INT,      @DepartmentId INT,      @DivisionId INT,      @CycleId INT,      @LeaveSchemeId INT,      @LeaveTypeId INT  AS  BEGIN    DECLARE @TaxYearStartDate DATETIME = SUBSTRING(@TaxYear, 1, 4) + '-03-01'  DECLARE @TaxYearEndDate DATETIME = DATEADD(DAY, -1, DATEADD(YEAR, 1, @TaxYearStartDate))  DECLARE @DefaultWDPM DECIMAL = 21.67    DECLARE @leaveStatus_new INT = 1  DECLARE @leaveStatus_approved INT = 3    DECLARE @adjustmentType_accrued INT = 2  DECLARE @adjustmentType_taken INT = 3  DECLARE @adjustmentType_forfeit INT = 4  DECLARE @adjustmentType_encashed INT = 5  DECLARE @adjustmentType_accumulated INT = 6  DECLARE @adjustmentType_adjusted INT = 7  DECLARE @adjustmentType_opening INT = 1      DECLARE @cycleStart_fixedDate INT = 1  DECLARE @cycleStart_joiningDate INT = 2  DECLARE @cycleStart_calendarYear INT = 3  DECLARE @LeaveTable table   (    EmployeeId int,    EmpCode varchar(10),    FirstName varchar(100),    Surname varchar(100),    JoiningDate datetime,    LeaveSchemeId int,    LeaveSchemeDesc varchar(250),    LeaveTypeId int,    LeaveTypeDesc varchar(250),    LeaveAdjustmentType varchar(100),    DocumentNumber varchar(100),    Startdate datetime,    Enddate datetime,    Datecaptured datetime,    Status varchar(20),    Days decimal(18,2)   )     insert into @LeaveTable   exec Payroll_LeaveRegister  @taxyearStartDate,@TaxYearEndDate,@DepartmentId,@DivisionId,@cycleId,@LeaveTypeId,@LeaveSchemeId,@EmployeeID     Select Leave.*,CycleStartDate.Dt as CycleStartDate,NewCycleStartDate.Dt as NewCycleStartDate,LeaveDaysPerCycle.LeaveDays,IsNULL(PlannedLeave.Value,0) PlannedLeave from(   select EmployeeId,LeaveSchemeDesc,LeaveSchemeId LeaveSchemeID,LeaveTypeId LeaveTypeID,LeaveTypeDesc LeaveType,FirstName + ' ' + Surname EmployeeName,EmpCode,JoiningDate,   SUM(CASE          WHEN LeaveAdjustmentType = 'Opening Balance' THEN Days          ELSE 0      END) AS 'OpeningBalance',   SUM(CASE          WHEN LeaveAdjustmentType = 'Accrued' THEN Days          ELSE 0      END) AS 'Accrued'      ,SUM(CASE          WHEN LeaveAdjustmentType = 'Taken' THEN Days          ELSE 0      END) AS 'Taken'      ,SUM(CASE          WHEN LeaveAdjustmentType = 'Forfeit' THEN Days          ELSE 0      END) AS 'Forfeit'      ,SUM(CASE          WHEN LeaveAdjustmentType = 'Encashed' THEN Days          ELSE 0      END) AS 'Encashed'      ,SUM(CASE          WHEN LeaveAdjustmentType = 'Adjusted' THEN Days          ELSE 0      END) AS 'Adjusted',   SUM(Days) AS 'Balance'   from @LeaveTable   Group by EmployeeId,LeaveSchemeDesc,LeaveSchemeId,LeaveTypeId,LeaveTypeDesc,FirstName, Surname,EmpCode,JoiningDate)Leave   CROSS APPLY (      SELECT CASE          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_fixedDate            THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, @TaxYearStartDate, SubCLT.CycleStartDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, SubCLT.CycleStartDate)          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_joiningDate            THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, @TaxYearStartDate, Leave.JoiningDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, Leave.JoiningDate)          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_calendarYear            THEN DATEFROMPARTS(YEAR(@TaxYearStartDate), 1, 1)          ELSE NULL      END AS Dt      FROM Const_LeaveType AS SubCLT      WHERE SubCLT.LeaveType_ID = Leave.LeaveTypeID  ) AS CycleStartDate    CROSS APPLY (      SELECT CASE          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_fixedDate            THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, @TaxYearStartDate, SubCLT.CycleStartDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd + SubCLT.CycleEnd, SubCLT.CycleStartDate)          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_joiningDate            THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, @TaxYearStartDate, Leave.JoiningDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd + SubCLT.CycleEnd, Leave.JoiningDate)          WHEN SubCLT.CyclePeriodIDStart = @cycleStart_calendarYear            THEN DATEFROMPARTS(YEAR(@TaxYearStartDate) + 1, 1, 1)          ELSE NULL      END AS Dt      FROM Const_LeaveType AS SubCLT      WHERE SubCLT.LeaveType_ID = Leave.LeaveTypeID    ) AS NewCycleStartDate  CROSS APPLY(SELECT         SUM(        CASE           WHEN SubCLTD.AccrualInverval = 3 AND SubCLTD.PeriodIndicator = 1 -- Monthly, Month Periods            THEN            (CASE WHEN SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1 > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd * SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * SubCLTD.AccrualDays              END)            WHEN SubCLTD.AccrualInverval = 3 AND SubCLTD.PeriodIndicator = 2 -- Monthly, Year Periods            THEN            (CASE WHEN (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * 12 > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd * SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * 12 * SubCLTD.AccrualDays              END)            WHEN SubCLTD.AccrualInverval = 2 AND SubCLTD.PeriodIndicator = 1 -- Yearly, Month Periods            THEN            (CASE WHEN SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1 > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd / 12 * SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) / 12 * SubCLTD.AccrualDays              END)            WHEN SubCLTD.AccrualInverval = 2 AND SubCLTD.PeriodIndicator = 2 -- Yearly, Year Periods            THEN            (CASE WHEN (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * 12 > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd / 12 * SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * SubCLTD.AccrualDays              END)            WHEN SubCLTD.AccrualInverval = 1 AND SubCLTD.PeriodIndicator = 1 -- Once-off, Month Periods            THEN            (SubCLTD.AccrualDays)            WHEN SubCLTD.AccrualInverval = 1 AND SubCLTD.PeriodIndicator = 2 -- Once-off, Year Periods            THEN            (SubCLTD.AccrualDays)            WHEN SubCLTD.AccrualInverval = 4 AND SubCLTD.PeriodIndicator = 1 -- days, Month Periods            THEN            (CASE WHEN (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1)  > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd * @DefaultWDPM / SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * @DefaultWDPM / SubCLTD.AccrualDays              END)            WHEN SubCLTD.AccrualInverval = 4 AND SubCLTD.PeriodIndicator = 2 -- days, Year Periods            THEN            (CASE WHEN (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * 12 > SubCLT.CycleEnd              THEN               SubCLT.CycleEnd * @DefaultWDPM / SubCLTD.AccrualDays            ELSE              (SubCLTD.PeriodEnd - SubCLTD.PeriodStart + 1) * 12 * @DefaultWDPM / SubCLTD.AccrualDays              END)            ELSE 0        END        ) AS LeaveDays        FROM Const_LeaveTypeDetails AS SubCLTD        JOIN Const_LeaveType AS SubCLT ON SubCLTD.LeaveTypeId = SubCLT.LeaveType_ID         WHERE SubCLTD.LeaveTypeId = Leave.LeaveTypeID          AND SubCLTD.StartDate <= DATEADD(DAY, -1, NewCycleStartDate.Dt) AND SubCLTD.EndDate >= CycleStartDate.Dt          AND SubCLTD.Enabled = 1        GROUP BY SubCLTD.LeaveTypeId) AS LeaveDaysPerCycle    OUTER APPLY(      SELECT SUM(SubELT.Value) AS Value      FROM Payroll_EmployeeLeaveTransactions AS SubELT       WHERE Leave.EmployeeID = SubELT.EmployeeID          AND SubELT.StartDate >= DATEADD(YEAR, +1, @TaxYearStartDate)          AND (SubELT.LeaveStatusID = @leaveStatus_new OR SubELT.LeaveStatusID = @leaveStatus_approved)          AND SubELT.LeaveAdjustmentTypeID = @adjustmentType_taken           AND SubELT.Enabled = 1      GROUP BY SubELT.LeaveTypeID  ) AS PlannedLeave  END

GO

-- ============================================
-- SP: Payroll_LeaveTaken
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-29  -- Description: Used as a dataset for Leave Taken report (HR_LeaveTaken.rdl)  --              Returns leaves that were taken during specific period  -- 2023/12/12 Kiran - WI96558 Fix Leave Take Report not all leave on the report for the selected Start and End Date  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_LeaveTaken]      @FromDate DATETIME2,      @ToDate DATETIME2,      @DepartmentId INT,      @DivisionId INT,      @EmployeeSubtypeId INT,      @LeaveTypeId INT,      @EmployeeTypeId INT,      @EmployeeId INT  AS  BEGIN    DECLARE @leaveStatus_approved INT = 3  DECLARE @adjustmentType_taken INT = 3    SELECT       emp.Employee_ID,      emp.FirstName,      emp.Surname,      dep.DepartmentDesc,      div.DivisionDesc,      leave.LeaveTypeDesc,      FORMAT(leave.StartDate, 'dd/MM/yyyy') AS StartDate,      FORMAT(leave.EndDate, 'dd/MM/yyyy') AS EndDate,      leave.Value,      leave.LeaveTypeId,      leave.Notes  FROM (      SELECT           EmployeeId,          Value,          leave.StartDate,          leave.EndDate,          Notes,          leaveT.LeaveTypeDesc,          leave.LeaveTypeId      FROM Payroll_EmployeeLeaveTransactions leave          LEFT OUTER JOIN Const_LeaveType leaveT ON leaveT.LeaveType_ID = leave.LeaveTypeId      WHERE leave.StartDate >= @FromDate          AND leave.EndDate <= @ToDate          AND leave.LeaveAdjustmentTypeID = @adjustmentType_taken          AND leave.LeaveStatusID = @leaveStatus_approved          AND (leave.LeaveTypeId = @LeaveTypeId OR ISNULL(@LeaveTypeId, 0) = 0)  ) AS leave      LEFT JOIN Payroll_Employee emp ON emp.Employee_ID = leave.EmployeeId      LEFT JOIN Payroll_Position pos ON emp.Employee_ID = pos.EmployeeId AND emp.[JobProfileID] = pos.[JobProfileID]      LEFT JOIN Const_Department dep ON dep.Department_ID = pos.DepartmentID      LEFT JOIN Const_Division div ON div.Division_ID = pos.DivisionID  WHERE (dep.Department_ID = @DepartmentId OR @DepartmentId = 0)      AND (div.Division_ID = @DivisionId OR @DivisionId = 0)      AND (emp.EmployeeTypeID = @EmployeeTypeId OR @EmployeeTypeId = 0)      AND (emp.EmployeeSubtypeID = @EmployeeSubTypeId OR @EmployeeSubTypeId = 0)      AND (emp.Employee_ID = @EmployeeID OR @EmployeeID = 0)    END

GO

-- ============================================
-- SP: Payroll_LeaveTakenMonday
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-11  -- Description: Used as a dataset for Leave Taken on Monday report (Payroll_LeaveTakenMonday.rdl)  --              Returns all “one” day leave transactions that falls on a Monday for leave type   --              Annual Leave and Sick Leave where this leave does not form part of a leave transaction   --              for leave taken for periods of two days or longer  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_LeaveTakenMonday]      @StartDate DATETIME,      @EndDate DATETIME,      @DepartmentId INT,      @DivisionId INT,      @LeaveSchemeId INT,      @LeaveTypeId INT,      @CycleId INT  AS  BEGIN    SELECT   e.[Employee_ID] AS 'EmployeeId',   e.[Initials],   e.[Surname],   d.[DepartmentDesc] AS 'Department',   di.[DivisionDesc] AS 'Division',   elt.[StartDate],   elt.[EndDate],   clt.[LeaveTypeDesc] AS 'LeaveType',   elt.[DocumentNumber],   Mondays.[Dates] AS 'Monday'  FROM   Payroll_EmployeeLeaveTransactions elt  INNER JOIN   Const_AbsenceType cat ON elt.[AbsenceTypeId] = cat.[AbsenceType_ID]         AND cat.[LeaveClassificationID] IN (1, 2) -- 1 - Annual Leave, 2 - Sick Leave  INNER JOIN   Const_LeaveType clt ON elt.[LeaveTypeID] = clt.[LeaveType_ID]  INNER JOIN   Payroll_Employee e ON elt.[EmployeeID] = e.[Employee_ID]         AND e.[EndDate] > @StartDate  CROSS APPLY   (    SELECT [Dt] AS 'Dates' FROM [dbo].[GetDatesDayOfWeekInDateRange](elt.[StartDate], elt.[EndDate], 'Monday')   ) Mondays  OUTER APPLY   (    SELECT DISTINCT     ph.[DepartmentID], ph.[DivisionID]    FROM     Payroll_PositionHistory ph    WHERE     ph.[EmployeeID] = elt.[EmployeeID]    AND ph.[JobProfileID] = e.[JobProfileID]    AND ph.[Enabled] = 1    AND elt.[StartDate] BETWEEN ph.[StartDate] AND ph.[EndDate]   ) dd  LEFT JOIN   Const_Department d ON dd.[DepartmentID] = d.[Department_ID]  LEFT JOIN   Const_Division di ON dd.[DivisionID] = di.[Division_ID]  WHERE   elt.[Enabled] = 1  AND elt.[NumberOfDaysRequested] = 1  AND elt.[LeaveAdjustmentTypeID] = 3 -- Adjustment Type Taken  AND elt.[StartDate] >= @StartDate  AND (@EndDate IS NULL OR elt.[EndDate] <= @EndDate)  AND (ISNULL(@LeaveSchemeId, 0) = 0 OR elt.[LeaveSchemeID] = @LeaveSchemeId)  AND (ISNULL(@LeaveTypeId, 0) = 0 OR elt.[LeaveTypeID] = @LeaveTypeId)  AND (ISNULL(@DepartmentId, 0) = 0 OR dd.[DepartmentID] = @DepartmentId)  AND (ISNULL(@DivisionId, 0) = 0 OR dd.[DivisionID] = @DivisionId)  AND (ISNULL(@CycleId, 0) = 0 OR e.[CycleID] = @CycleId);    END

GO

-- ============================================
-- SP: Payroll_LeaveTransactionsStatus
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-11  -- Description: Used as a dataset for Leave Transactions Status report (Payroll_LeaveTransactionsStatus.rdl)  --              Returns all Leave Transactions with the employee who approved it or should approve it  -- Modified: Richa M Add Status Description   --    2025/04/08 - Add Approved Date to Report (WI119918)    --exec Payroll_LeaveTransactionsStatus '2023/11/01','2023/11/15',0,0,0    -- =============================================   CREATE PROCEDURE [dbo].[Payroll_LeaveTransactionsStatus]      @StartDate DATETIME,      @EndDate DATETIME,      @DepartmentId INT,      @DivisionId INT,      @StatusId INT  AS  BEGIN    ;WITH Employees  AS  (   SELECT    [Employee_ID], [Initials], CONCAT([FirstName], ' ', [Surname]) AS 'FullName', [Surname], [JobProfileID], [Enabled]   FROM    Payroll_Employee  ),  Positions  AS  (   SELECT    [EmployeeID], [JobProfileID], [DepartmentID], [DivisionID], [HOD], [StartDate], [EndDate], [Enabled]   FROM    Payroll_Position  )    SELECT   e.[Employee_ID] AS 'EmployeeId',   e.[Initials],   e.[Surname],   elt.[StartDate],   elt.[EndDate],   clt.[LeaveTypeDesc] AS 'LeaveType',   elt.[DocumentNumber],   ABS(elt.[Value]) AS 'Days',   uu.FirstName + ' ' + uu.LastName + ' ( ' + CONVERT(VARCHAR(20), elt.ApproveDate, 120) + ' )' AS 'Approver' ,   StatusDesc as 'Status'  FROM   Payroll_EmployeeLeaveTransactions elt  INNER JOIN   Const_LeaveType clt ON elt.[LeaveTypeID] = clt.[LeaveType_ID]  INNER JOIN   Const_LeaveStatus_sys cls ON elt.[LeaveStatusID] = cls.[Status_ID]  LEFT JOIN User_UserDetail uu on uu.User_ID = elt.ApprovedById  INNER JOIN   Employees e ON elt.[EmployeeID] = e.[Employee_ID]        AND e.[Enabled] = 1  OUTER APPLY   (    SELECT DISTINCT     ph.[DepartmentID], ph.[DivisionID], ph.[HOD]    FROM     Positions ph    WHERE     ph.[EmployeeID] = elt.[EmployeeID]    AND ph.[JobProfileID] = e.[JobProfileID]    AND ph.[Enabled] = 1    AND elt.[StartDate] BETWEEN ph.[StartDate] AND ph.[EndDate]   ) dd  WHERE   elt.[Enabled] = 1  AND elt.[LeaveAdjustmentTypeID] IN (3, 7) -- 3 - Adjustment Type Taken, 7 - Adjustment Type Adjust  AND elt.[StartDate] >= @StartDate  AND elt.[EndDate] <= @EndDate  AND (ISNULL(@DepartmentId, 0) = 0 OR dd.[DepartmentID] = @DepartmentId)  AND (ISNULL(@DivisionId, 0) = 0 OR dd.[DivisionID] = @DivisionId)  AND (ISNULL(@StatusId, 0) = 0 OR elt.[LeaveStatusID] = @StatusId);    END

GO

-- ============================================
-- SP: Payroll_LoadAdditionalDivisionSplitByJobProfileId_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Ravindra Jijotia  -- Create date: 08 JUN 2016  -- Description: Loads Additional Division Split By JobProfileId  -- Call: [Payroll_LoadAdditionalDivisionSplitByJobProfileId_sp]  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions--No changes on this  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_LoadAdditionalDivisionSplitByJobProfileId_sp]      @JobProfileID INT, @PositionId INT  AS    BEGIN      SELECT P_JPED.JobProfileExtraDivisionFunctionCode_ID, C_DEP.DepartmentDesc + ' - ' + C_D.DivisionDesc AS Division, C_SFS.ScoaCode AS FunctionCode, P_JPED.CostPercentage AS Percentage from Payroll_JobProfileExtraDivisionFunctionCode P_JPED    INNER JOIN Const_Division C_D ON P_JPED.DivisionID = C_D.Division_ID    INNER JOIN Const_Department C_DEP ON C_DEP.Department_ID = C_D.DepartmentID    INNER JOIN Const_SCOA_Function_Structure C_SFS ON C_D.SCOAFunctionID = C_SFS.ScoaID    WHERE P_JPED.JobProfileID = @JobProfileID AND P_JPED.Enabled = 1 AND C_D.Enabled = 1 AND C_SFS.Enabled = 1 AND P_JPED.PositionId= @PositionId        END    

GO

-- ============================================
-- SP: Payroll_LockDownTrialRun_sp
-- Schema: dbo
-- ============================================
-- Description: Lock down Trial run of period  -- Author: Phuti Chokoe  -- TP43233    CREATE proc [dbo].[Payroll_LockDownTrialRun_sp]  @PeriodId int,  @LockDownBy int  As  update Payroll_CyclePeriodDetails  set LockedDown = 1, LockedDownBy = @LockDownBy, LockDownDate = Getdate()  where Period_ID = @PeriodId    

GO

-- ============================================
-- SP: Payroll_MedicalAIDSchemeList_sp
-- Schema: dbo
-- ============================================
  /*   Author   : Mehul Panchal   Creation Date : 2014/04/16   Description  : List all ID's and Fundnames(with min and max values) associated with the supplied Vendor ID   Updated   : 2015/02/05 James Roodt: Reordered the text to make it readable   Updated   : 2017/06/03 - Added extra check for Const_MedicalAIDSchemeDetail to also be enabled   Updated   : 2018/04/09 - Resolved Duplicate Schemes  */  create procedure [Payroll_MedicalAIDSchemeList_sp] @VendorID int = 0  as    begin     select distinct [MedicalScheme_ID], (case       when [MonthlyMinAmount] is null or [MonthlyMaxAmount] is null then [FundName]       else [FundName] + ' (' + cast(isnull([MonthlyMinAmount], 0.00) as nvarchar(50)) + '-' + cast(isnull([MonthlyMaxAmount], 0.00) as nvarchar(50)) + ')'      end) as [FundName]      from [Const_MedicalAIDScheme] as [MS] with(nolock)       join [Const_MedicalAIDSchemeDetail] as [MD] with(nolock) on [MD].[MedicalSchemeID] = [MS].[MedicalScheme_ID]     where ([VendorID] = @VendorID and [MD].[Enabled] = 1 and [MS].[Enabled] = 1)    end  

GO

-- ============================================
-- SP: Payroll_MedicalYearly_sp
-- Schema: dbo
-- ============================================
-- =====================================================================================================================  -- Author:  Mehul Panchal  -- Create date: 24-7-2013  -- Description: Medical Scheme Tax break benefit Constant Re-Create with new Finance Year  -- 2015-03-27 James Roodt: Changed ActiveFinYear to ActivePayrollYear  -- 2015-03-30 James Roodt: Added check to continue  -- 2015-08-11 Ravindra Jijotia TP19740: Added new column DependantModeID  --          Renamed Const_MedicalScheme to Const_MedicalSchemeFeeTaxCredits  -- 2016-06-22 TP:38352-Seipei Mathole : Updated the function GetLastYearTaxYear  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_MedicalYearly_sp]    AS  BEGIN   SET NOCOUNT ON;     DECLARE @PayrollYear NVARCHAR(10)   DECLARE @OldPayrollYear NVARCHAR(10)   SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'   SET @OldPayrollYear = (SELECT [dbo].[GetLastYearTaxYear]())     IF NOT EXISTS(SELECT  * FROM Const_MedicalSchemeFeeTaxCredits WHERE TaxYear =@PayrollYear )   BEGIN    INSERT INTO dbo.Const_MedicalSchemeFeeTaxCredits      ( MedicalSchemeDesc , MedicalSchemeAmount , FinancialYear , [Enabled] , DateCaptured , CapturerID, DependantModeID ,TaxYear      )      (    SELECT MedicalSchemeDesc , MedicalSchemeAmount , @PayrollYear , [Enabled] , GETDATE() , 1 , DependantModeID , @PayrollYear    FROM dbo.Const_MedicalSchemeFeeTaxCredits WHERE FinancialYear = @OldPayrollYear AND [Enabled] = 1      )   END  END  

GO

-- ============================================
-- SP: Payroll_MissingStringsByPeriod
-- Schema: dbo
-- ============================================
  -- =============================================              -- Author:  Richa M              -- Create date: 2025/04/13             -- Description: Returns missing strings for the Payroll Module  --Payroll_MissingStringsByPeriod 384  -- =============================================        CREATE PROCEDURE [dbo].[Payroll_MissingStringsByPeriod]            @PeriodId int    AS  BEGIN        DECLARE @FinYear VARCHAR(10) = (      SELECT FinancialYear       FROM Payroll_CyclePeriodDetails       WHERE Period_ID = @PeriodId  );    SELECT       trx.EmployeeId,      emp.EmpCode,      emp.FirstName,      emp.Surname,      trx.SalaryHeadId,      sh.SalaryHeadName,      Getdate() TrialRunDate,      trx.ScoaItemId,      scoa.ScoaCode,      scoa.ScoaDesc,      proj.Project_ID,      proj.ProjectCode,      proj.ProjectDesc,      trx.DivisionId,      div.DivisionCode,      div.DivisionDesc,      func.ScoaID AS FunctionId,      func.ScoaCode AS FunctionCode,      func.ScoaDesc AS FunctionDesc,      fund.ScoaID AS FundId,      fund.ScoaCode AS FundCode,      fund.ScoaDesc AS FundDesc,      trx.ScoaRegionId AS RegionId,      reg.ScoaID AS RegionCode,      reg.ScoaDesc AS RegionDesc  FROM Payroll_MissingStrings trx  LEFT JOIN Payroll_Employee emp ON trx.EmployeeId = emp.Employee_ID  LEFT JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = trx.SalaryHeadId  LEFT JOIN Const_SCOA_Structure_Consolidated scoa       ON scoa.FinYearText = @FinYear AND scoa.ScoaID = trx.ScoaItemId  LEFT JOIN Const_SCOA_Funds_Structure_Consolidated fund       ON fund.FinYearText = @FinYear AND fund.ScoaID = trx.ScoaFundId  LEFT JOIN Const_SCOA_Function_Structure_Consolidated func       ON func.FinYearText = @FinYear AND func.ScoaID = trx.ScoaFunctionID  LEFT JOIN Const_SCOA_Regional_Structure_Consolidated reg       ON reg.FinYearText = @FinYear AND reg.ScoaID = trx.ScoaRegionID  LEFT JOIN Const_SCOA_Costing_Structure_Consolidated cost       ON cost.FinYearText = @FinYear AND cost.ScoaID = 20  LEFT JOIN Plan_Project proj ON trx.ProjectId = proj.Project_ID  LEFT JOIN Const_Division div ON trx.DivisionID = div.Division_ID  WHERE       trx.PeriodId = @PeriodId AND      trx.DocumentType = 131 AND   isnull(trx.PlanProjectItemID,0) = 0 ;     END

GO

