  /*   Author  : FERDI BOTHA   Create date : 23/03/2017   Description : Gets the list of MOC Column mappings  */  create procedure [Payroll_MOCColumns_sp]  as    begin     set nocount on;     select [table], [c].[name], [where], [trans]      from [Payroll_MOCItems] as [o] with(nolock)       join [sys].[columns] as [c] with(nolock) on [object_id] = object_id([o].[table])       order by [o].[table], [c].[name]     set nocount off;    end  

