-- ============================================
-- SP: Payroll_MonthEndProcess_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 24-07-2013  -- Description: Month End Process  -- 2015-12-04 TP19147 Suri Kandukuri: Rename CycleTypeID to CycleID.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_MonthEndProcess_sp]   @FinancialYear NVARCHAR(10),   @CycleID INT  AS  BEGIN   SET NOCOUNT ON;     --Older one Cycle Period Details update Processed = 1 it mean all employees salary calculated   DECLARE @Period_ID INT   SELECT TOP 1 @Period_ID = Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear AND Processed = 0 AND CycleID = @CycleID   UPDATE dbo.Payroll_CyclePeriodDetails SET Processed = 1 WHERE Period_ID = @Period_ID      --Next period's End Date take from Payroll_CyclePeriodDetails and update in Payroll_Municipality_CycleDetails based on FinancialYear and Cycle   DECLARE @PeriodEndDate DATETIME    SELECT TOP 1 @PeriodEndDate = PeriodEndDate FROM dbo.Payroll_CyclePeriodDetails WHERE TaxYear = @FinancialYear AND Processed = 0 AND CycleID = @CycleID   UPDATE dbo.Payroll_Municipality_CycleDetails SET PeriodEndDate = @PeriodEndDate WHERE CycleID = @CycleID AND TaxYear = @FinancialYear    END  

GO

-- ============================================
-- SP: Payroll_MonthlyCyclePeriodPopulate_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:Varun Parvataneni  -- Create date: 2016-08-22  -- Description: #43519:Generate Periods For Payroll run Cycles  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- 2019-07-22 Modiri Selao : JoGEDA: No records to display on the Payroll Run Periods on both sites (Live + Test)  -- 2020-02-20 Donald Asante: Added start date and capturer ID. link payroll cycle to payroll tax periods.   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_MonthlyCyclePeriodPopulate_sp]   @FromDate DATETIME,   @CapturerID INT,   @CycleID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     --DECLARE VARIABLES   DECLARE  @CYCLEENTRY TABLE   (    [CapturerID] INT,    [DateCaptured] DATETIME,    [Enabled] BIT,    [Processed] BIT,    [FinancialYear] NVARCHAR(50),    [ProcessingMonth] NVARCHAR(25),    [PeriodStartDate] DATETIME,    [PeriodEndDate] DATETIME,    [PeriodInTaxYear] INT   )     DECLARE @FYSTARTDATE DATETIME   DECLARE @FYENDDATE DATETIME   DECLARE @1stENDDATE DATETIME   DECLARE @PayrollYear NVARCHAR(10)   DECLARE @STARTDATE DATETIME   DECLARE @ENDDATE DATETIME   DECLARE @DateCapture DATETIME = GETDATE()   DECLARE @COUNT INT   DECLARE @APPROVEDSTATUS NVARCHAR(10) = 'No'   DECLARE @PAYROLLYEARSTARTDATE DATETIME   DECLARE @PAYROLLYEARENDDATE DATETIME   DECLARE @MunicipalityID INT   DECLARE @TaxYearOpen INT   DECLARE @TAXYEARENDDATE INT      DECLARE @MONTH INT     --Initialize variables   SET @COUNT = 0      -- Get municipality Id   SELECT TOP 1 @MunicipalityID = Municipality_ID FROM dbo.Payroll_Municipality      --Get payroll end month   SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'     SET @PAYROLLYEARSTARTDATE = '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)), 0, 5);      SET @PAYROLLYEARENDDATE = DATEADD(d,-1, '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9));   SET @TAXYEARENDDATE = CAST(SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9) as INT);     IF(@FromDate BETWEEN @PAYROLLYEARSTARTDATE AND @PAYROLLYEARENDDATE)   BEGIN    SET @TaxYearOpen = 1   END    ELSE   BEGIN    SET @TaxYearOpen = 0   END     SET @STARTDATE = DATEADD(m,@COUNT,@FromDate)   SET @ENDDATE = DATEADD(d,-1,(DATEADD(M,1,@STARTDATE)))     WHILE(@COUNT < 12 AND @ENDDATE < @PAYROLLYEARENDDATE)   BEGIN     SET @STARTDATE = DATEADD(m,@COUNT,@FromDate)    SET @ENDDATE = DATEADD(d,-1,(DATEADD(M,1,@STARTDATE)))    SET @MONTH = MONTH(@STARTDATE)      IF @COUNT = 0    BEGIN     SET @FYSTARTDATE = @STARTDATE     SET @1stENDDATE = @ENDDATE    END    ELSE IF @COUNT = 11 OR DATEADD(M, 1, @ENDDATE) >= @PAYROLLYEARENDDATE    BEGIN     SET @FYENDDATE = @ENDDATE    END        INSERT INTO @CYCLEENTRY     SELECT @CapturerID, @DateCapture, 1, 0, @PayrollYear, *           FROM     (     SELECT       DATENAME(month, @STARTDATE) AS ProcessingMonth,       @STARTDATE AS PeriodStartDate,       @ENDDATE AS PeriodEndDate,      IIF(@MONTH < 3, @MONTH + 10, @MONTH - 2) AS PeriodInTaxYear    ) AS TEMP                 SET  @COUNT = @COUNT + 1    END     IF NOT EXISTS (SELECT Period_ID FROM Payroll_CyclePeriodDetails  WHERE TaxYear = @PayrollYear and CycleID = @CycleID)   BEGIN    INSERT INTO Payroll_CyclePeriodDetails (PeriodInTaxYear, ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed ,              MunicipalityID , FinancialYear , Enabled , DateCaptured ,              CapturerID , CycleID, CycleModeID,ApprovedStatus, TaxYear)    SELECT [PeriodInTaxYear], [ProcessingMonth], [PeriodStartDate] ,[PeriodEndDate], [Processed], @MunicipalityID,      [FinancialYear], [Enabled], [DateCaptured], [CapturerID], @CycleID, 1, @APPROVEDSTATUS,[FinancialYear]  FROM @CYCLEENTRY   END      IF NOT EXISTS (SELECT CycleDetail_ID FROM Payroll_Municipality_CycleDetails  WHERE TaxYear = @PayrollYear and CycleID = @CycleID)   BEGIN    INSERT INTO dbo.Payroll_Municipality_CycleDetails    (      MunicipalityID , CycleID , FinancialYear , TaxYearStartDate , TaxYearEndDate ,     PeriodEndDate , [Enabled] , DateCaptured , CapturerID, TaxYear    )    VALUES      (      @MunicipalityID, @CycleID, @PayrollYear, @FYSTARTDATE, @FYENDDATE, @1stENDDATE, 1, @DateCapture, 1, @PayrollYear    )   END     IF NOT EXISTS (SELECT TaxPeriodID from dbo.Const_Payroll_TaxPeriods where cycleID = @CycleID)   BEGIN    INSERT INTO dbo.Const_Payroll_TaxPeriods    (     TaxYear,StartDate,EndDate,cycleID,Enable,DateCaptured,CapturerID,DateModified,ModifierID,FinalRunDate,TaxYearOpen    )    VALUES    (     @TAXYEARENDDATE,@FYSTARTDATE,@FYENDDATE,@CycleID,1,@DateCapture,@CapturerID,null,null,null,@TaxYearOpen    )   END   END

GO

-- ============================================
-- SP: Payroll_Municipality_CycleDetailsList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 06 JULY 2013  -- Description: <Description,,>  -- CALLS: [Payroll_Municipality_CycleDetailsList_sp]  -- 2015-12-04 TP19147 Suri Kandukuri: Rename CycleTypeID to CycleID.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_Municipality_CycleDetailsList_sp]  AS       BEGIN          SELECT  PAY_MUN_CYC.CycleDetail_ID, CONST_CYC.Cycle_ID, PAY_MUN.MunicipalityName, CONST_CYC.CycleDesc, PAY_MUN_CYC.FinancialYear, CONVERT(NVARCHAR, PAY_MUN_CYC.TaxYearStartDate, 103) AS TaxYearStartDate, CONVERT(NVARCHAR, PAY_MUN_CYC.TaxYearEndDate, 103) AS TaxYearEndDate, CONVERT(NVARCHAR, PAY_MUN_CYC.PeriodEndDate, 103) AS PeriodEndDate, CASE WHEN PAY_MUN_CYC.Enabled = 1 THEN 'ACTIVE'                                                                                                                                                                                                                                                                                                                                                                     ELSE 'IN ACTIVE'                                                                                                                                                                                                                                                                                                                                                                END AS STATUS, PAY_MUN_CYC.DateCaptured, PAY_MUN_CYC.CapturerID          FROM    Payroll_Municipality_CycleDetails PAY_MUN_CYC                  LEFT OUTER JOIN Payroll_Municipality PAY_MUN ON PAY_MUN.Municipality_ID = PAY_MUN_CYC.MunicipalityID                  INNER JOIN Const_Cycle CONST_CYC ON CONST_CYC.Cycle_ID = PAY_MUN_CYC.CycleID      END    

GO

