-- ============================================
-- SP: Payroll_MunicipalityCycle_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 12 JULY 2013  -- Description: <Description,,>  -- 2015-12-04 TP19147 Suri Kandukuri: Rename CycleTypeID to CycleID.  -- =============================================  CREATE PROCEDURE  [dbo].[Payroll_MunicipalityCycle_sp]   @FinancialYear NVARCHAR(50),   @CycleID INT,   @DateCaptured DATETIME,   @CapturerID INT,   @IsMonthly BIT  AS  DECLARE @MunicipalityID INT  DECLARE @CurrentEndDate NVARCHAR(50)  SELECT top 1 @MunicipalityID = Municipality_ID FROM Payroll_Municipality ORDER BY Municipality_ID DESC   BEGIN  IF NOT EXISTS (SELECT CycleDetail_ID FROM Payroll_Municipality_CycleDetails WHERE (MunicipalityID = @MunicipalityID) AND (CycleID= @CycleID) AND (TaxYear= @FinancialYear))  BEGIN    IF (@IsMonthly =0)    BEGIN    DECLARE @FinancialStartDate DATETIME    DECLARE @FinancialEndDate DATETIME    DECLARE @FinancialStartMonth  NVARCHAR(50)    DECLARE @FinancialEndMonth  NVARCHAR(50)            SELECT @FinancialStartMonth= SUBSTRING(@FinancialYear,0,5),  @FinancialEndMonth=SUBSTRING(@FinancialYear,6,8)         SET @FinancialStartDate =  @FinancialStartMonth +'/03/01'     SET @FinancialEndDate =  @FinancialEndMonth + '02/01'         SELECT @FinancialEndDate = DATEADD(d,-1,(DATEADD(M,1,cast(@FinancialEndDate aS DATETIME))))    SELECT @CurrentEndDate = DATEADD(d,-1,(DATEADD(M,1,cast(@FinancialStartDate aS DATETIME))))        INSERT INTO Payroll_Municipality_CycleDetails (MunicipalityID,CycleID,FinancialYear,TaxYearStartDate,TaxYearEndDate,PeriodEndDate,Enabled,DateCaptured,CapturerID, TaxYear)    SELECT @MunicipalityID,@CycleID,@FinancialYear,@FinancialStartDate,@FinancialEndDate ,@CurrentEndDate ,1,@DateCaptured,@CapturerID, @FinancialYear        END  END   ELSE  BEGIN   IF (@IsMonthly =1)    BEGIN          DECLARE @CurrentDay INT             SELECT @CurrentDay =DAY(GETDATE())         IF (@CurrentDay > 1)     BEGIN      SELECT   @CurrentEndDate =DATEADD(M,1,DATEADD(MONTH, DATEDIFF(MONTH, -1, GETDATE())-1, -1) )     END     ELSE     BEGIN     SELECT @CurrentEndDate = DATEADD(D,1,DATEADD(M,1,GETDATE()))           END         UPDATE Payroll_Municipality_CycleDetails SET PeriodEndDate =@CurrentEndDate               ,DateModified=  @DateCaptured               ,ModifierID=@CapturerID                                 WHERE (MunicipalityID = @MunicipalityID) AND (CycleID= @CycleID) AND (FinancialYear= @FinancialYear)       END    END     END     

GO

-- ============================================
-- SP: Payroll_MunicipalityDetailsRpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  prerana parmar  -- Create date: 06 july 2013  -- Description:   -- CALLS : [Payroll_MunicipalityDetailsRpt_sp]  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_MunicipalityDetailsRpt_sp]  AS       BEGIN          SELECT  DISTINCT                  PAY_MUN.MunicipalityName, PAY_MUN.MunicipalityNo, PAY_MUN.RegistrationNo, PAY_MUN.TaxRegistrationNo, CONST_COUNT.CountryDesc AS Country, PAY_MUN.SDLReferenceNo, PAY_MUN.UIFReferenceNo, PAY_MUN.UIFRegistrationNo, PAY_MUN.PhyAddress1 + ' ' + PAY_MUN.PhyAddress2 + ' ' + (SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PhySuburb) AS PhysicalAddress, PAY_MUN.PosAddress1 + '' + PAY_MUN.PosAddress2 + ' ' + (SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PAY_MUN.PosSuburb) AS PostalAddress, PAY_MUN.SARSContactNo AS SARSContactNo, ISNULL(PAY_MUN.SARSPersonName, '') + ' ' + ISNULL(PAY_MUN.SARSPersonSurname, '') AS SARSPersonName, PAY_MUN.SARSEmailAddress AS SARSEmailAddress, PAY_MUN.UIFContactNo AS UIFContactNo, PAY_MUN.UIFEmailAddress AS UIFEmailAddress, ISNULL(PAY_MUN.UIFPersonName, '') + ' ' + ISNULL(PAY_MUN.UIFPersonSurname, '') AS UIFPersonName, CONST_CYC.CycleDesc AS CycleName, CASE WHEN PAY_MUN.ExcludeForUIF = 0 THEN 'NO'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ELSE 'YES'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               END AS ExcludeForUIF, CASE WHEN PAY_MUN.ExcludeForSDL = 0 THEN 'NO'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ELSE 'YES'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     END AS ExcludeForSDL, PAY_CYC_PER.PeriodInTaxYear AS PeriodNo, PAY_CYC_PER.ProcessingMonth, CONVERT(NVARCHAR, PAY_CYC_PER.PeriodStartDate, 103) AS PeriodStartDate, CONVERT(NVARCHAR, PAY_CYC_PER.PeriodEndDate, 103) AS PeriodEndDate, CASE WHEN PAY_CYC_PER.Processed = 1 THEN 'YES'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ELSE 'NO'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             END AS Completed, CASE WHEN PAY_MUN_CYC.ProRataAnnualBonus = 0 THEN 'YES'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ELSE 'NO'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               END AS ProRataAnnualBonus, ( SELECT    KeyValue                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            FROM      AAAA_ConfigSettings                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            WHERE     ( KeyName = 'DocViewerRootFolderPath' )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ) + 'Municipality/' + ( SELECT  MunicipalityImagePath                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  FROM    Payroll_Municipality                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ) AS IMAGE          FROM    Payroll_Municipality PAY_MUN                  INNER JOIN Payroll_Municipality_CycleDetails PAY_MUN_CYC ON PAY_MUN.Municipality_ID = PAY_MUN_CYC.MunicipalityID                  INNER JOIN Payroll_CyclePeriodDetails PAY_CYC_PER ON PAY_MUN.Municipality_ID = PAY_CYC_PER.MunicipalityID                  INNER JOIN Const_Cycle CONST_CYC ON CONST_CYC.Cycle_ID = PAY_CYC_PER.CycleID                  INNER JOIN Const_Country CONST_COUNT ON CONST_COUNT.Country_ID = PAY_MUN.CountryID       END

GO

