-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  prerana parmar  -- Create date: 06 july 2013  -- Description: <Description,,>  --- CALLS : Payroll_MunicipalityList_sp  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_MunicipalityList_sp]      AS  BEGIN    SELECT Municipality_ID       ,MunicipalityNo        ,MunicipalityName        ,RegistrationNo       ,TaxRegistrationNo        ,TradeClassificationID        ,SDLReferenceNo        ,UIFRegistrationNo        ,UIFReferenceNo        ,PrintOnPayslip       ,MunicipalityImagePath       ,CASE WHEN (Enabled  =1)        THEN      'ACTIVE'        ELSE      'IN ACTIVE'     END AS STATUS     ,ExcludeForSDL     ,ExcludeForUIF        FROM Payroll_Municipality      END     

