-- ============================================
-- SP: Payroll_NotchChanges
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_NotchChanges]  AS  BEGIN     DECLARE @CurrentDate DATETIME = CAST(CURRENT_TIMESTAMP AS DATE);   DECLARE @DateValue VARCHAR(10) = (SELECT [KeyValue] FROM AAAA_ConfigSettings WHERE [KeyName] = 'PayrollSchedulerDate');   DECLARE @UseCustomDate VARCHAR(6) = (SELECT [KeyValue] FROM AAAA_ConfigSettings WHERE [KeyName] = 'UseCustomPayrollSchedulerDate');     IF @UseCustomDate = 'true'   BEGIN    DECLARE @dateYear INT = CAST(RIGHT(@dateValue, 4) AS INT),      @dateMonth INT = CAST(RIGHT(LEFT(@dateValue, 5), 2) AS INT),      @dateDay INT = CAST(LEFT(@dateValue, 2) AS INT)      SELECT @CurrentDate = CONVERT(NVARCHAR(19), DATEFROMPARTS(@dateYear, @dateMonth, @dateDay), 120)   END     SELECT    nh.[ID], nh.[NotchID], nh.[TaskGradeId], nh.[Notch], nh.[StartDate], nh.[EndDate], nh.[MinimumSalary], nh.[MaximumSalary]   INTO #Notches   FROM    Payroll_NotchHistory nh   WHERE    nh.[Enabled] = 1   AND CAST(ISNULL(nh.[DateModified], nh.[DateCaptured]) AS DATE) BETWEEN DATEADD(MONTH, -1, @CurrentDate) AND @CurrentDate;     DECLARE @CurrentNotchId INT = 0,     @CurrentNotchHistoryId INT = 0,     @CurrentNotchStartDate DATE = '',     @CurrentNotchEndDate DATE = '',     @CurrentNotchMinimumSalary DECIMAL(18, 4) = 0;     -- Iterate through each Notch   WHILE (@CurrentNotchId < (SELECT MAX([NotchID]) FROM #Notches))   BEGIN      SELECT TOP 1 @CurrentNotchId = [NotchID] FROM #Notches WHERE [NotchID] > @CurrentNotchId ORDER BY [NotchID], [ID];      -- Get all Employee history records for notch    SELECT     *    INTO #Employees    FROM     Payroll_EmployeeHistory eh             WHERE     eh.[Enabled] = 1;      DECLARE @CurrentEmployeeId INT = 0,     @CurrentEmployeeHistoryId INT = 0,     @CurrentEmployeeStartDate DATE = '',     @CurrentEmployeeEndDate DATE = '',     @CurrentEmployeeMonthlySalary DECIMAL(18, 2) = 0;      -- Iterate through each employee    WHILE (@CurrentEmployeeId < (SELECT MAX([EmployeeID]) FROM #Employees WHERE [NotchID] = @CurrentNotchId))    BEGIN       SELECT TOP 1 @CurrentEmployeeId = [EmployeeID] FROM #Employees WHERE [NotchID] = @CurrentNotchId AND [EmployeeID] > @CurrentEmployeeId ORDER BY [EmployeeID];       -- Iterate through each notch history     WHILE (@CurrentNotchStartDate < (SELECT MAX([StartDate]) FROM #Notches WHERE [NotchID] = @CurrentNotchId))     BEGIN          SELECT TOP 1 @CurrentNotchHistoryId = [ID], @CurrentNotchStartDate = [StartDate], @CurrentNotchEndDate = [EndDate], @CurrentNotchMinimumSalary = [MinimumSalary] FROM #Notches WHERE [NotchID] = @CurrentNotchId AND [StartDate] > @CurrentNotchStartDate ORDER BY [NotchID], [StartDate];        -- Iterate through each employee history      WHILE (@CurrentEmployeeStartDate < (SELECT MAX([StartDate]) FROM #Employees WHERE [EmployeeID] = @CurrentEmployeeId))      BEGIN         SELECT TOP 1 @CurrentEmployeeHistoryId = [EmployeeHistory_ID], @CurrentEmployeeStartDate = [StartDate], @CurrentEmployeeEndDate = [EndDate], @CurrentEmployeeMonthlySalary = [MonthlySalary]       FROM #Employees       WHERE [EmployeeID] = @CurrentEmployeeId AND [StartDate] > @CurrentEmployeeStartDate       ORDER BY [EmployeeID], [StartDate];         -- Only update where the History Start and End Dates are overlapping the Main Start and End Dates       IF (@CurrentEmployeeStartDate <= @CurrentNotchEndDate AND @CurrentEmployeeEndDate >= @CurrentNotchStartDate)       BEGIN          -- Only Create Splitting where the Main Start Date or End Date <=> History Start Date or End Date        IF (@CurrentEmployeeStartDate <> @CurrentNotchStartDate OR @CurrentEmployeeEndDate <> @CurrentNotchEndDate)        BEGIN           -- Do not split if the History Start Date is greater than of equal to the Main Start Date and the History End Date is less than of equal to the Main End Date         IF NOT (@CurrentEmployeeStartDate >= @CurrentNotchStartDate AND @CurrentEmployeeEndDate <= @CurrentNotchEndDate)         BEGIN            IF (@CurrentEmployeeStartDate < @CurrentNotchStartDate AND @CurrentEmployeeEndDate > @CurrentNotchEndDate)          BEGIN             MERGE INTO #Employees AS targetTable           USING           (            -- To Be Updated            SELECT             [EmployeeHistory_ID], [EmployeeID], [DepartmentID], [DivisionID], [PositionHistoryID], [StartDate], DATEADD(DAY, -1, @CurrentNotchStartDate) AS 'EndDate', [ReasonID], [VacancyNo], [Enabled],             [DateCaptured], [CapturerID], [DateModified], [ModifierID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [CycleID], [NotchID], [ShiftRotationID], [RotationID],             [BonusPaymentDateID], [BonusMonth], [ExcludeUIFNonContributorReasonID], [RPD_Other], [RPW_Other], [WHPD_Monthly], [WHPD_Other], [WHPM_Monthly], [RPD_Monthly], [WDPW_Other], [WDPM_Monthly],             [RPH_Monthly], [RPH_Other], [MonthlySalary], [BonusSalary], [AnnualSalary], [BonusCalculation], [AllowOverTime], [TaxCalculationType], [ExcludeUIF], [ExcludeSDL], [NotchChangeReason]            FROM             #Employees            WHERE             [EmployeeID] = @CurrentEmployeeId            AND CAST([StartDate] AS DATE) = @CurrentEmployeeStartDate           UNION            -- To Be Created created[0]            SELECT             0 AS 'EmployeeHistory_ID', [EmployeeID], [DepartmentID], [DivisionID], [PositionHistoryID], @CurrentNotchStartDate AS 'StartDate', @CurrentNotchEndDate AS 'EndDate', [ReasonID], [VacancyNo], eh.[Enabled],             eh.[DateCaptured], eh.[CapturerID], eh.[DateModified], eh.[ModifierID], eh.[EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [CycleID], [NotchID], [ShiftRotationID], [RotationID],             [BonusPaymentDateID], [BonusMonth], [ExcludeUIFNonContributorReasonID], [RPD_Other], [RPW_Other], [WHPD_Monthly], [WHPD_Other], [WHPM_Monthly],              IIF([WDPM_Monthly] > 0, @CurrentNotchMinimumSalary / [WDPM_Monthly], @CurrentNotchMinimumSalary) AS 'RPD_Monthly', [WDPW_Other], [WDPM_Monthly],             IIF([WHPM_Monthly] > 0, @Curr