HED THEN          UPDATE SET           targetTable.[StartDate] = sourceTable.[StartDate],           targetTable.[EndDate] = sourceTable.[EndDate],           targetTable.[RPD_Monthly] = sourceTable.[RPD_Monthly],           targetTable.[RPH_Monthly] = sourceTable.[RPH_Monthly],           targetTable.[MonthlySalary] = sourceTable.[MonthlySalary],           targetTable.[BonusSalary] = sourceTable.[BonusSalary],           targetTable.[AnnualSalary] = sourceTable.[AnnualSalary],           targetTable.[ModifierID] = 0,           targetTable.[DateModified] = CURRENT_TIMESTAMP;          END;         END;        END;       END;       SET @CurrentNotchHistoryId = 0     SET @CurrentNotchStartDate = '';     SET @CurrentNotchEndDate = '';     SET @CurrentNotchMinimumSalary = 0;     SET @CurrentEmployeeHistoryId = 0;     SET @CurrentEmployeeStartDate = '';     SET @CurrentEmployeeEndDate = '';     SET @CurrentEmployeeMonthlySalary = 0;      END;      -- Insert into Payroll_EmployeeHistory    MERGE INTO Payroll_EmployeeHistory AS targetTable    USING    (     -- To Be Updated     SELECT      [EmployeeHistory_ID], [EmployeeID], [DepartmentID], [DivisionID], [PositionHistoryID], eh.[StartDate], eh.[EndDate], [ReasonID], [VacancyNo], eh.[Enabled],      eh.[DateCaptured], eh.[CapturerID], eh.[DateModified], eh.[ModifierID], eh.[EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [CycleID], [NotchID], [ShiftRotationID], [RotationID],      [BonusPaymentDateID], [BonusMonth], [ExcludeUIFNonContributorReasonID], [RPD_Other], [RPW_Other], [WHPD_Monthly], [WHPD_Other], [WHPM_Monthly],       IIF([WDPM_Monthly] > 0, ISNULL([MinimumSalary], [MonthlySalary])  / [WDPM_Monthly], ISNULL([MinimumSalary], [MonthlySalary])) AS 'RPD_Monthly', [WDPW_Other], [WDPM_Monthly],      IIF([WHPM_Monthly] > 0, ISNULL([MinimumSalary], [MonthlySalary]) / [WHPM_Monthly], ISNULL([MinimumSalary], [MonthlySalary])) AS 'RPH_Monthly', [RPH_Other],      ISNULL([MinimumSalary], [MonthlySalary]) AS 'MonthlySalary',      IIF(est.[ApplyBonus] = 1, ISNULL([MinimumSalary], [MonthlySalary]), NULL) AS 'BonusSalary',       (ISNULL([MinimumSalary], [MonthlySalary]) * 12) AS 'AnnualSalary', [BonusCalculation], [AllowOverTime], [TaxCalculationType], eh.[ExcludeUIF], eh.[ExcludeSDL], [NotchChangeReason]     FROM      #Employees eh     LEFT JOIN      Payroll_EmployeeSubtypes est ON eh.[EmployeeSubtypeID] = est.[EmployeeSubtype_ID]             AND est.[Enabled] = 1     OUTER APPLY      (       SELECT [MinimumSalary] FROM #Notches WHERE [NotchID] = eh.[NotchID] AND [StartDate] = eh.[StartDate]      ) aa     WHERE      [NotchID] = @CurrentNotchId    ) AS sourceTable    ON    (     targetTable.[EmployeeHistory_ID] = sourceTable.[EmployeeHistory_ID]    )    WHEN MATCHED THEN     UPDATE SET      targetTable.[StartDate] = sourceTable.[StartDate],      targetTable.[EndDate] = sourceTable.[EndDate],      targetTable.[Enabled] = sourceTable.[Enabled],      targetTable.[RPD_Monthly] = sourceTable.[RPD_Monthly],      targetTable.[RPH_Monthly] = sourceTable.[RPH_Monthly],      targetTable.[MonthlySalary] = sourceTable.[MonthlySalary],      targetTable.[BonusSalary] = sourceTable.[BonusSalary],      targetTable.[AnnualSalary] = sourceTable.[AnnualSalary],      targetTable.[ModifierID] = sourceTable.[ModifierID],      targetTable.[DateModified] = sourceTable.[DateModified]    WHEN NOT MATCHED THEN     INSERT ([EmployeeID], [DepartmentID], [DivisionID], [PositionHistoryID], [StartDate], [EndDate], [ReasonID], [VacancyNo], [Enabled],      [DateCaptured], [CapturerID], [EmployeeTypeID], [EmployeeSubtypeID], [ConditionOfServiceID], [CycleID], [NotchID], [ShiftRotationID], [RotationID],      [BonusPaymentDateID], [BonusMonth], [ExcludeUIFNonContributorReasonID], [RPD_Other], [RPW_Other], [WHPD_Monthly], [WHPD_Other], [WHPM_Monthly], [RPD_Monthly], [WDPW_Other], [WDPM_Monthly],      [RPH_Monthly], [RPH_Other], [MonthlySalary], [BonusSalary], [AnnualSalary], [BonusCalculation], [AllowOverTime], [TaxCalculationType], [ExcludeUIF], [ExcludeSDL], [NotchChangeReason])     VALUES (sourceTable.[EmployeeID], sourceTable.[DepartmentID], sourceTable.[DivisionID], sourceTable.[PositionHistoryID], sourceTable.[StartDate], sourceTable.[EndDate], sourceTable.[ReasonID], sourceTable.[VacancyNo], sourceTable.[Enabled],      CURRENT_TIMESTAMP, 0, sourceTable.[EmployeeTypeID], sourceTable.[EmployeeSubtypeID], sourceTable.[ConditionOfServiceID], sourceTable.[CycleID], sourceTable.[NotchID], sourceTable.[ShiftRotationID], sourceTable.[RotationID],      sourceTable.[BonusPaymentDateID], sourceTable.[BonusMonth], sourceTable.[ExcludeUIFNonContributorReasonID], sourceTable.[RPD_Other], sourceTable.[RPW_Other], sourceTable.[WHPD_Monthly], sourceTable.[WHPD_Other], sourceTable.[WHPM_Monthly], sourceTable.[RPD_Monthly], sourceTable.[WDPW_Other], sourceTable.[WDPM_Monthly],      sourceTable.[RPH_Monthly], sourceTable.[RPH_Other], sourceTable.[MonthlySalary], sourceTable.[BonusSalary], sourceTable.[AnnualSalary], sourceTable.[BonusCalculation], sourceTable.[AllowOverTime], sourceTable.[TaxCalculationType], sourceTable.[ExcludeUIF], sourceTable.[ExcludeSDL], sourceTable.[NotchChangeReason]);        DROP TABLE #Employees;     END;     DROP TABLE #Notches;    END;

GO

-- ============================================
-- SP: Payroll_NotchesUpdateEmployeeTable
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,04/04/2018,>  -- Description: <Description, Notches Update Employee Table,>  -- Modified  :Richa M - Update Bonus amount as well TP74094    -- =============================================  CREATE procedure [dbo].[Payroll_NotchesUpdateEmployeeTable]  @NotchID int    as   begin       begin try      /*This is hardcoded for now. These values were originally in the old Const_ProfileGroupDetails (notches) table but it was removed as these values are NOT the same per notch or jobgrading e.g. janitor doing night shift vs janitor doing normal office hours    This is also similar to the employee screen*/        /* Default Working Hours per Month.*/    declare @DefaultWHPM decimal(18,2) = 173.33,       /* Default Working Days per Month*/      @DefaultWDPM decimal(18,2) = 21.67             update [pe]        set [pe].[FixedSalary] = [MonthlySalary],       [pe].[AnnualSalary] = ([MonthlySalary] * 12),       [pe].[BonusAmount] = [MonthlySalary],       [pe].[WHPM_Monthly] = (case when [pe].[WDPM_Monthly] > 0 then [pe].[WHPM_Monthly]  else @DefaultWHPM end),       [pe].[RPD_Other] = (case when [WDPM_Monthly] > 0 then [MonthlySalary] / [WDPM_Monthly] else [MonthlySalary]/ @DefaultWHPM end ),       [pe].[WHPD_Other] = (case when [WDPM_Monthly] > 0 then [WHPM_Monthly] / [WDPM_Monthly] else [WHPM_Monthly]/ @DefaultWDPM end ),       [pe].[RPH_Monthly] = (case when [WHPD_Other] > 0 then [RPD_Other] / [WHPD_Other] else [RPD_Other]/ @DefaultWDPM end )       from [Payroll_Employee] [pe]        join [Payroll_Notch] [pn] on [pe].[NotchId] = [pn].[Notch_ID]       join [Const_Cycle] [cc] on [pe].[CycleID] = [cc].[Cycle_ID]       join [Const_CycleType_sys] [cs] on [cc].[CycleTypeID] = [cs].[CycleType_ID]       where [pn].[Notch_ID] = @NotchID      end try      begin catch        end catch  end

GO

-- ============================================
-- SP: Payroll_NotchOnAppointment
-- Schema: dbo
-- ============================================
/*   Modiri   2020/01/24   Scheduler will execute this SP to check if there any nothc increases for that specific date     Ruan Strydom   2021/04/06   Fix stored procedure, removing duplicates etc     Richa M   2021/05/17 - Notch increase should only apply after employee completed first year of service WI64347   2022/03/16 - Exclude Terminated employees    */      CREATE procedure [dbo].[Payroll_NotchOnAppointment]  AS  BEGIN      DECLARE @Date NVARCHAR(19) = CONVERT(NVARCHAR(19), CURRENT_TIMESTAMP, 111);   DECLARE @DateValue NVARCHAR(10) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE [KeyName] = 'PayrollSchedulerDate');   DECLARE @UseCustomDate NVARCHAR(6) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE [KeyName] = 'UseCustomPayrollSchedulerDate');     IF @UseCustomDate = 'true'   BEGIN    DECLARE @DateYear INT = CAST(RIGHT(@DateValue, 4) AS INT),      @DateMonth INT = CAST(RIGHT(LEFT(@DateValue, 5), 2) AS INT),      @DateDay INT = CAST(LEFT(@DateValue, 2) AS INT);      SELECT @Date = CONVERT(NVARCHAR(19), DATEFROMPARTS(@DateYear, @DateMonth, @DateDay), 120);   END     -- Get the different Cycles   SELECT    *   INTO #Cycles   FROM    Const_Cycle c   WHERE    c.[Enabled] = 1   AND c.[CycleTypeID] = 1;     DECLARE @CurrentTaxYear NVARCHAR(10);     -- Current Tax Year   SELECT    @CurrentTaxYear = cs.[KeyValue]   FROM    AAAA_ConfigSettings cs   WHERE    cs.[KeyName] = 'TaxYear'       DECLARE @CurrentCycleId INT = 0,     @CurrentCycleName NVARCHAR(100) = '',     @CurrentMonth INT = 0,     @CurrentYear INT = 0;     -- Foreach cycle iterate through   WHILE (@CurrentCycleId < (SELECT MAX([Cycle_ID]) FROM #Cycles))   BEGIN       SELECT TOP 1 @CurrentCycleId = [Cycle_ID], @CurrentCycleName = [CycleDesc] FROM #Cycles WHERE [Cycle_ID] > @CurrentCycleId ORDER BY [Cycle_ID];      SELECT TOP 1     @CurrentMonth = MONTH([PeriodStartDate]), @CurrentYear = YEAR([PeriodStartDate])    FROM     Payroll_CyclePeriodDetails    WHERE     [CycleID] = @CurrentCycleId    AND [TaxYear] = @CurrentTaxYear    AND [Processed] = 0    ORDER BY     [PeriodInTaxYear];      -- Check Employees per Cycle    SELECT * INTO #CurrentEmployees from(    SELECT DISTINCT     DATEDIFF(MONTH,e.JoiningDate, @Date) PeriodsWorked,       e.[Employee_ID], nh.[TaskGradeId], nh.[Notch_ID], nh.[Notch], e.[FixedSalary], nnh.[Notch_ID] AS 'NewNotchID', nnh.[Notch] AS 'NewNotch', nnh.[MinimumSalary] AS 'NewMinimumSalary', ISNULL(nnh.[MinimumSalary], 0) - ISNULL([FixedSalary], 0) AS 'IncreaseAmount'        FROM     Payroll_Employee e    INNER JOIN     Payroll_JobProfile jp ON e.[JobProfileID] = jp.[JobProfile_ID]    INNER JOIN     Payroll_Notch nh ON e.[NotchId] = nh.[Notch_ID]           AND jp.[TaskGradeId] = nh.[TaskGradeId]           AND OnAppointment = 1           AND nh.[Enabled] = 1    INNER JOIN     Payroll_Notch nnh ON nh.[TaskGradeId] = nnh.[TaskGradeId]           AND (nh.[Notch] + 1) = nnh.[Notch]           AND nnh.[Enabled] = 1    LEFT JOIN     (      SELECT DISTINCT       nid.[EmployeeId]      FROM       Payroll_Notch_Increase_Detail nid      INNER JOIN       Payroll_Notch_Increase_Header nih ON nid.[NotchIncreaseHeaderID] = nih.[NotchIncreaseHeader_ID]      WHERE       nid.[iYear] = @CurrentYear      AND nid.[MonthID] = @CurrentMonth      AND nih.[OnAppointment] = 1     ) aa ON e.[Employee_ID] = aa.[EmployeeId]    WHERE     e.[Enabled] = 1    AND e.[CycleID] = @CurrentCycleId    AND MONTH(e.[JoiningDate]) = @CurrentMonth    AND e.EndDate > @Date    AND aa.[EmployeeId] IS NULL    )Employees Where PeriodsWorked >= 12      IF (SELECT COUNT(*) FROM #CurrentEmployees) > 0    BEGIN       -- Insert Notch Increase Header     INSERT INTO Payroll_Notch_Increase_Header ([ReportName], [NumOfEmployees], [OnAppointment], [OnIncreaseDate], [DateCaptured], [CapturerID], [MonthID], [iYear])     SELECT      'OnAppointment_' + @CurrentCycleName + '_' + RIGHT('0' + CAST(@CurrentMonth AS VARCHAR(2)), 2) + CAST(@CurrentYear AS VARCHAR(4)),      COUNT(DISTINCT [Employee_ID]),      1,      0,      CURRENT_TIMESTAMP,      1,      @CurrentMonth,      @CurrentYear     FROM      #CurrentEmployees;       DECLARE @NewHeaderID INT = SCOPE_IDENTITY();       INSERT INTO Payroll_Notch_Increase_Detail ([NotchIncreaseHeaderID], [EmployeeId], [CurrentTaskGradeId], [NotchId], [CurrentSalary], [NewNotchId], [IncreaseAmount], [NewBasicSalary], [BudgetIncreaseEffect], [MonthID], [iYear], [Approved])     SELECT      @NewHeaderID, [Employee_ID], [TaskGradeId], [Notch_ID], [FixedSalary], [NewNotchID], [IncreaseAmount], [NewMinimumSalary], [IncreaseAmount], @CurrentMonth, @CurrentYear, NULL     FROM      #CurrentEmployees;       UPDATE      h     SET      h.[TotalBudgetEffect] = aa.[TotalIncreaseEffect]     FROM      Payroll_Notch_Increase_Header h     INNER JOIN      (       SELECT        d.[NotchIncreaseHeaderID], SUM(d.[BudgetIncreaseEffect]) AS 'TotalIncreaseEffect'       FROM        Payroll_Notch_Increase_Detail d       GROUP BY        d.[NotchIncreaseHeaderID]      ) aa ON h.[NotchIncreaseHeader_ID] = aa.[NotchIncreaseHeaderID]     WHERE      h.[NotchIncreaseHeader_ID] = @NewHeaderID;    END;      DROP TABLE #CurrentEmployees;   END;     DROP TABLE #Cycles;    END

GO

-- ============================================
-- SP: Payroll_NotchOnIncreaseDate
-- Schema: dbo
-- ============================================
  /*   Modiri   2019/12/04   Scheduler will execute this SP to check if there any nothc increases for that specific date      2021/01/11 - RichaM - Fix SP to correctly create transactions for Notch Increases - WI49257     2021/04/06 - Ruan Strydom - Fix sp and standardize with OnAppointment sp     2022/03/16 - Richa M - Exclude Terminated employees     2022/03/18 - Richa M  - The increase should only happen after an employee completed a full year service    */    CREATE procedure [dbo].[Payroll_NotchOnIncreaseDate]    @EmployeeID INT = 0  AS    BEGIN     -- Get the different Cycles   SELECT    *   INTO #Cycles   FROM    Const_Cycle c   WHERE    c.[Enabled] = 1   AND c.[CycleTypeID] = 1;     DECLARE @CurrentCycleId INT = 0,     @CurrentCycleName NVARCHAR(100) = '',     @CurrentMonth INT = 0,     @CurrentYear INT = 0,     @Date NVARCHAR(19) = CONVERT(NVARCHAR(19), CURRENT_TIMESTAMP, 111);   DECLARE @DateValue NVARCHAR(10) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE [KeyName] = 'PayrollSchedulerDate');   DECLARE @UseCustomDate NVARCHAR(6) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE [KeyName] = 'UseCustomPayrollSchedulerDate');     IF @UseCustomDate = 'true'   BEGIN    DECLARE @DateYear INT = CAST(RIGHT(@DateValue, 4) AS INT),      @DateMonth INT = CAST(RIGHT(LEFT(@DateValue, 5), 2) AS INT),      @DateDay INT = CAST(LEFT(@DateValue, 2) AS INT);      SELECT @Date = CONVERT(NVARCHAR(19), DATEFROMPARTS(@DateYear, @DateMonth, @DateDay), 120);   END      SET @CurrentMonth = DATEPART(MM, @Date);   SET @CurrentYear = DATEPART(YYYY, @Date);     -- Foreach cycle iterate through   WHILE (@CurrentCycleId < (SELECT MAX([Cycle_ID]) FROM #Cycles))   BEGIN       SELECT TOP 1 @CurrentCycleId = [Cycle_ID], @CurrentCycleName = [CycleDesc] FROM #Cycles WHERE [Cycle_ID] > @CurrentCycleId ORDER BY [Cycle_ID];       -- Check Employees per Cycle    SELECT * INTO #CurrentEmployees    from (    SELECT DISTINCT     e.[Employee_ID], nh.[TaskGradeId], nh.[Notch_ID], nh.[Notch], e.[FixedSalary], nnh.[Notch_ID] AS 'NewNotchID', nnh.[Notch] AS 'NewNotch', nnh.[MinimumSalary] AS 'NewMinimumSalary', ISNULL(nnh.[MinimumSalary], 0) - ISNULL([FixedSalary], 0) AS 'IncreaseAmount',     ( select Max(Notch) from Payroll_Notch where TaskGradeId = nh.[TaskGradeId] ) MaxNotch,      DATEDIFF(MONTH,e.JoiningDate, @Date) PeriodsWorked    FROM     Payroll_Employee e    INNER JOIN     Payroll_JobProfile jp ON e.[JobProfileID] = jp.[JobProfile_ID]    INNER JOIN     Payroll_Notch nh ON e.[NotchId] = nh.[Notch_ID]           AND jp.[TaskGradeId] = nh.[TaskGradeId]           AND OnIncreaseDate = 1           AND nh.[MonthID] = @CurrentMonth           AND nh.[Enabled] = 1    INNER JOIN     Payroll_Notch nnh ON nh.[TaskGradeId] = nnh.[TaskGradeId]           AND (nh.[Notch] + nh.[AnnualIncrease]) = nnh.[Notch]           AND nnh.[Enabled] = 1    LEFT JOIN     (      SELECT DISTINCT       nid.[EmployeeId]      FROM       Payroll_Notch_Increase_Detail nid      INNER JOIN       Payroll_Notch_Increase_Header nih ON nid.[NotchIncreaseHeaderID] = nih.[NotchIncreaseHeader_ID]      WHERE       nid.[iYear] = @CurrentYear      AND nid.[MonthID] = @CurrentMonth      AND nih.[OnIncreaseDate] = 1     ) aa ON e.[Employee_ID] = aa.[EmployeeId]    WHERE     e.[Enabled] = 1    AND e.[CycleID] = @CurrentCycleId    AND e.[EndDate] > @Date    AND aa.[EmployeeId] IS NULL    )Employees    Where PeriodsWorked > 12      IF (SELECT COUNT(*) FROM #CurrentEmployees) > 0    BEGIN       -- Insert Notch Increase Header     INSERT INTO Payroll_Notch_Increase_Header ([ReportName], [NumOfEmployees], [OnAppointment], [OnIncreaseDate], [DateCaptured], [CapturerID], [MonthID], [iYear])     SELECT      'OnDateIncrease_' + @CurrentCycleName + '_' + RIGHT('0' + CAST(@CurrentMonth AS VARCHAR(2)), 2) + CAST(@CurrentYear AS VARCHAR(4)),      COUNT(DISTINCT [Employee_ID]),      0,      1,      CURRENT_TIMESTAMP,      1,      @CurrentMonth,      @CurrentYear     FROM      #CurrentEmployees where Notch <> MaxNotch       DECLARE @NewHeaderID INT = SCOPE_IDENTITY();       INSERT INTO Payroll_Notch_Increase_Detail ([NotchIncreaseHeaderID], [EmployeeId], [CurrentTaskGradeId], [NotchId], [CurrentSalary], [NewNotchId], [IncreaseAmount], [NewBasicSalary], [BudgetIncreaseEffect], [MonthID], [iYear], [Approved])     SELECT      @NewHeaderID, [Employee_ID], [TaskGradeId], [Notch_ID], [FixedSalary], [NewNotchID], [IncreaseAmount], [NewMinimumSalary], [IncreaseAmount], @CurrentMonth, @CurrentYear, NULL     FROM      #CurrentEmployees where Notch <> MaxNotch;       UPDATE      h     SET      h.[TotalBudgetEffect] = aa.[TotalIncreaseEffect]     FROM      Payroll_Notch_Increase_Header h     INNER JOIN      (       SELECT        d.[NotchIncreaseHeaderID], SUM(d.[BudgetIncreaseEffect]) AS 'TotalIncreaseEffect'       FROM        Payroll_Notch_Increase_Detail d       GROUP BY        d.[NotchIncreaseHeaderID]      ) aa ON h.[NotchIncreaseHeader_ID] = aa.[NotchIncreaseHeaderID]     WHERE      h.[NotchIncreaseHeader_ID] = @NewHeaderID;    END;      DROP TABLE #CurrentEmployees;   END;     DROP TABLE #Cycles;    END

GO

-- ============================================
-- SP: Payroll_OIDReportRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:  01 JULY 2013  -- Description:    -- Payroll_OIDReportRpt_sp '2013/2014', 2, 0  -- 2015-12-08 Suri Kandukuri: Function changed from  GetYearFromFinanceYearAndMonth to GetYearFromPayrollYearAndMonth  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_OIDReportRpt_sp]      @FinancialYear NVARCHAR(50) ,      @DepartmentId INT ,      @CycleId INT  AS       BEGIN  /* CREATE A TABLE*/          DECLARE @OIDREPORT TABLE              (                [MONTH] NVARCHAR(20) ,                [COUNT] INT ,                [EARNING] DECIMAL(18, 2)              )           /*END TABLE*/            DECLARE @FinancialStartYear NVARCHAR(50)          DECLARE @STARTDATE DATETIME          DECLARE @ENDDATE DATETIME          DECLARE @FinYearStartMonth INT          DECLARE @MONTH INT          DECLARE @COUNT INT          DECLARE @Earning DECIMAL(18, 2) ,              @EmpCount INT ,              @PeriodId INT                  SET @COUNT = 1          SELECT  @FinYearStartMonth = KeyValue          FROM    dbo.AAAA_ConfigSettings          WHERE   KeyName = 'TaxFinYearEndMonth' --TaxFinYearEndMonth             DECLARE @PayrollCycle TABLE ( Period_Id INT )             SET @MONTH = @FinYearStartMonth + 1          SELECT  @FinancialStartYear = dbo.GetYearFromPayrollYearAndMonth(@FinancialYear, @MONTH)             WHILE ( @COUNT <= 12 )               BEGIN                  DELETE  FROM @PayrollCycle                  INSERT  INTO @PayrollCycle                          SELECT  Period_ID                          FROM    Payroll_CyclePeriodDetails                          WHERE   DATEPART(MONTH, PeriodEndDate) = @Month                                  AND TaxYear = @FinancialYear                                  AND ( CycleId = @CycleId                                        OR @CycleId = 0                                      )                      SELECT  @EmpCount = COUNT(DISTINCT PAY_EMP.Employee_ID), @Earning = SUM(PAY_EMP_PAY.AMOUNT)                  FROM    Payroll_Employee PAY_EMP                          LEFT OUTER JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP.Employee_ID = PAY_EMP_PAY.EmployeeID                          LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PAYROLLDEFINATIONID                          LEFT OUTER JOIN dbo.Payroll_SalaryHead PAY_SH ON PAY_DEF.PayrollSalaryHeadID = PAY_SH.SalaryHead_ID                          LEFT OUTER JOIN Payroll_IRP5Code ON PAY_SH.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                          LEFT OUTER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID                          LEFT OUTER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TRANSACTIONTYPE_ID = Payroll_IRP5Code.TransactionTypeID                  WHERE   UPPER(PAY_EMP_PAY.PeriodID) IN ( SELECT Period_Id                                                           FROM   @PayrollCycle )                          AND ( PAY_EMP_PAY.TaxYear = @FinancialYear )                          AND LOWER(CONST_TRANS.TransactionType_ID) = 1                          AND ( PP.DepartmentID = @DepartmentId                                OR @DepartmentId = 0                              )                  GROUP BY PAY_EMP_PAY.Month                            INSERT  INTO @OIDREPORT                          SELECT  DATENAME(MONTH, CAST(( @FinancialStartYear + '/' + CAST(@MONTH AS NVARCHAR(10)) + '/' + '01' ) AS DATETIME)) AS MONTH, ISNULL(@EmpCount, 0), ISNULL(@Earning, 0)                       SET @EmpCount = NULL                  SET @Earning = NULL                         SET @COUNT = @COUNT + 1                      SET @MONTH = @MONTH + 1                      IF @MONTH > 12                       BEGIN                          SET @MONTH = @MONTH - 12                      END              END             SELECT  *, ( SELECT KeyValue                       FROM   AAAA_ConfigSettings                       WHERE  KeyName = 'TaxYear'                     ) AS FinYear          FROM    @OIDREPORT           END  

GO

-- ============================================
-- SP: Payroll_OverTime_Search_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 06 JUNE 2013  -- call [Payroll_OverTime_Search_sp] '' ,'','',1  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- 2018-20-03 Himil Modi : change the FinancialYear to TaxYear in sp  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_OverTime_Search_sp]    @Name NVARCHAR(100),   @Surname NVARCHAR(100),   @IDNo NVARCHAR(30),   @Flag BIT   AS    BEGIN   IF(@Flag = 0)   BEGIN    SELECT      PAY_EMP_OVR.EmployeeOverTime_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      CONVERT(NVARCHAR,PAY_EMP_OVR.OverTimeDate,103) AS OverTimeDate,     PAY_EMP_OVR.OverTimeHour,PAY_EMP_OVR.OverTimeFlag,PAY_EMP_OVR.FinancialYear,     PAY_EMP_OVR.TaxYear,CASE WHEN PAY_EMP_OVR.Enabled = 1 THEN     ' ACTIVE'     ELSE     'IN ACTIVE'     END AS STATUS,     PAY_EMP_OVR.CapturerID,     PAY_EMP_OVR.DateCaptured,     PAY_EMP_OVR.ModifierID,     PAY_EMP_OVR.DateModified,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_EmployeeOverTime AS PAY_EMP_OVR     INNER JOIN Payroll_Employee AS P_E ON PAY_EMP_OVR.EmployeeID = P_E.Employee_ID     WHERE (P_E.FirstName = @Name or @Name='' ) and  (P_E.Surname = @Surname or @Surname='') and  (P_E.IdNo = @IDNo or @IDNo='')    AND PAY_EMP_OVR.Enabled = 1    ORDER BY P_E.Employee_ID   END   ELSE   BEGIN    SELECT     PAY_EMP_OVR.EmployeeOverTime_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,     CONVERT(NVARCHAR,PAY_EMP_OVR.OverTimeDate,103) AS OverTimeDate,    PAY_EMP_OVR.OverTimeHour,PAY_EMP_OVR.OverTimeFlag,PAY_EMP_OVR.FinancialYear,    PAY_EMP_OVR.TaxYear,CASE WHEN PAY_EMP_OVR.Enabled = 1 THEN    ' ACTIVE'    ELSE    'IN ACTIVE'    END AS STATUS,    PAY_EMP_OVR.CapturerID,    PAY_EMP_OVR.DateCaptured,    PAY_EMP_OVR.ModifierID,    PAY_EMP_OVR.DateModified,    dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,    isnull(P_E.EmpCode,'') EmpCode   FROM Payroll_EmployeeOverTime AS PAY_EMP_OVR    INNER JOIN Payroll_Employee AS P_E ON PAY_EMP_OVR.EmployeeID = P_E.Employee_ID    WHERE PAY_EMP_OVR.Enabled = 1   ORDER BY P_E.Employee_ID   END  END  

GO

-- ============================================
-- SP: Payroll_OverTime_SearchList_sp
-- Schema: dbo
-- ============================================
-- 2021/17/03 49392 Change returned data of the OverTimeDate from String to DateTime    CREATE PROCEDURE [dbo].[Payroll_OverTime_SearchList_sp]    @Name NVARCHAR(100),   @Surname NVARCHAR(100),   @IDNo NVARCHAR(30),   @Flag BIT   AS    BEGIN   SELECT    Min(PAY_EMP_OVR.EmployeeOverTime_ID) EmployeeOverTime_ID,    P_E.IdNo,    P_E.Surname,    P_E.FirstName,    Sum(PAY_EMP_OVR.OverTimeHour) AS OverTimeHour,    Min(PayrollCyclePeriodDetails.PeriodStartDate) AS OverTimeDate,    PAY_EMP_OVR.FinancialYear,    PAY_EMP_OVR.TaxYear,    MAX(PAY_EMP_OVR.DateCaptured) LastDateCaptured,    dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,    isnull(P_E.EmpCode,'') EmpCode,    PayrollCyclePeriodDetails.PeriodInTaxYear,    PayrollCyclePeriodDetails.PeriodEndDate   FROM Payroll_EmployeeOverTime AS PAY_EMP_OVR    LEFT JOIN Payroll_Employee AS P_E ON PAY_EMP_OVR.EmployeeID = P_E.Employee_ID    LEFT JOIN Payroll_CyclePeriodDetails AS PayrollCyclePeriodDetails ON PayrollCyclePeriodDetails.Period_ID = PAY_EMP_OVR.PeriodID   WHERE (P_E.FirstName = @Name or @Name='' ) and  (P_E.Surname = @Surname or @Surname='') and  (P_E.IdNo = @IDNo or @IDNo='')    AND PAY_EMP_OVR.Enabled = 1   GROUP BY    P_E.IdNo,    PayrollCyclePeriodDetails.PeriodInTaxYear,    P_E.Surname,    P_E.FirstName,    P_E.Employee_ID,    PAY_EMP_OVR.FinancialYear,    PAY_EMP_OVR.TaxYear,    P_E.EmpCode,    PayrollCyclePeriodDetails.PeriodInTaxYear,    PayrollCyclePeriodDetails.PeriodEndDate   ORDER BY P_E.Employee_ID  END

GO

-- ============================================
-- SP: Payroll_Overtime_sp
-- Schema: dbo
-- ============================================
     -- ==============================================================================  -- Author:Varun Parvataneni  -- Description : To Generate OverTime reports on employee for selected dates  -- Create date: 7 APR 2016  -- CALLS : Payroll_Overtime_sp  '2015-03-01','2016-02-29',0,0,0,3   -- -- 14/Jun/2019 -- 86707 -- Add condition   "PAY_EMP_OVR.ExcludeFromPayment = 0"  -- 2020-10-20 US42239 Myroshnychenko: Remove 'ReportType' parameter, add CycleID and ExcessValue parameters, change call for getting more information  -- Modified - Richa M - 2025/01/28 - Exclude disabled overtime transactions    -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_Overtime_sp]       @FromDate DATETIME,   @ToDate DATETIME,   @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT,   @CycleID INT,   @ExcessValue FLOAT  AS     BEGIN       Select * from(    SELECT DISTINCT         dbo.BufferString_fxn(CONVERT(VARCHAR,(PE.EmployeeID)), 8, '0') as EmployeeNumber,       P_E.Surname as EmployeeSurname,       P_E.FirstName,        C_D.DepartmentDesc as Department,       C_Div.DivisionDesc as Division,       PAY_EMP_OVR.CostDesc as SalaryTransaction,       Convert(varchar,PAY_EMP_OVR.OverTimeDate,103) as Date,       PAY_EMP_OVR.OverTimeHour as OvertimeHours,       PAY_EMP_OVR.TotalAmount,       PAY_EMP_OVR.OverTimeDate    FROM Payroll_EmployeeOverTime AS PAY_EMP_OVR        JOIN Payroll_Employee AS P_E      ON PAY_EMP_OVR.EmployeeId = P_E.Employee_ID     CROSS APPLY (SELECT TOP 1 P_EH.EmployeeID, P_EH.CycleID, P_EH.DepartmentID, P_EH.DivisionID        FROM Payroll_EmployeeHistory as P_EH              WHERE P_E.Employee_ID = P_EH.EmployeeID         AND (@CycleID = 0 OR P_EH.CycleID = @CycleID)        AND (P_EH.StartDate < @ToDate AND P_EH.EndDate >@FromDate)        AND P_EH.Enabled = 1) AS PE               INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID     INNER JOIN dbo.Const_Department AS C_D ON PE.DepartmentID = C_D.Department_ID     INNER JOIN dbo.Const_Division AS C_Div ON C_D.Department_ID = C_Div.DepartmentID AND C_Div.Division_ID=PE.DivisionID      WHERE (PAY_EMP_OVR.OverTimeDate between @FromDate and @ToDate)      AND (ISNULL(@DepartmentId,0) = 0 OR Department_ID = @DepartmentId)      AND (ISNULL(@DivisionId,0) = 0 OR Division_ID = @DivisionId)      AND PAY_EMP_OVR.ExcludeFromPayment = 0      AND (ISNULL(@CycleID,0) =0 OR @CycleID=P_E.CycleID )      AND (ISNULL(@EmployeeID,0) = 0 OR P_E.Employee_ID=@EmployeeID)      AND (ISNULL(@ExcessValue,0) = 0 OR PAY_EMP_OVR.OverTimeHour > @ExcessValue)      AND PAY_EMP_OVR.Processed = 1      AND PAY_EMP_OVR.Enabled = 1      )v1      order by EmployeeNumber,OverTimeDate      END

GO

-- ============================================
-- SP: Payroll_PastLeaveForfeit
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-24  -- Description: Used as a dataset for Leave Forfeit report (HR_LeaveForfeit.rdl)  --              Returns past forfeit leave  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_PastLeaveForfeit]      @FromDate DATETIME      ,@ToDate DATETIME      ,@EmployeeId INT      ,@LeaveTypeId INT      ,@DepartmentId INT      ,@DivisionId INT      ,@EmployeeTypeId INT      ,@EmployeeSubTypeId INT  AS  BEGIN    DECLARE @leaveStatus_approved INT = 3  DECLARE @adjustmentType_forfeit INT = 4  DECLARE @cycleStart_fixedDate INT = 1  DECLARE @cycleStart_joiningDate INT = 2  DECLARE @cycleStart_calendarYear INT = 3    SELECT      PE.Employee_ID AS EmployeeNumber      ,PE.FirstName AS EmployeeName      ,PE.Surname AS EmployeeSurname      ,Department.DepartmentDesc AS Department      ,Division.DivisionDesc AS Division      ,CLT.LeaveTypeDesc AS LeaveType      ,DATEADD(DAY, -1, CycleStartDate.Dt) AS CycleEndDate      ,DATEADD(DAY, CLTD.ExtentionDays, DATEADD(DAY, -1, CycleStartDate.Dt)) AS LeaveForfeitedDate      ,CLTD.ExtentionDays AS ExtentionDays      ,PELT.Value AS DaysForfeited  FROM Payroll_EmployeeLeaveTransactions AS PELT      JOIN Payroll_Employee AS PE ON PELT.EmployeeID = PE.Employee_ID      LEFT JOIN Payroll_Position AS PP ON PE.Employee_ID = PP.EmployeeID      LEFT JOIN Const_Department AS Department ON PP.DepartmentID = Department.Department_ID      LEFT JOIN Const_Division AS Division ON PP.DivisionID = Division.Division_ID      JOIN Const_LeaveType AS CLT ON PELT.LeaveTypeID = CLT.LeaveType_ID      CROSS APPLY (          SELECT CASE              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_fixedDate                  THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, PELT.StartDate, SubCLT.CycleStartDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, SubCLT.CycleStartDate)              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_joiningDate                  THEN DATEADD(MONTH, (ABS(DATEDIFF(MONTH, PELT.StartDate, PE.JoiningDate)) / SubCLT.CycleEnd) * SubCLT.CycleEnd, PE.JoiningDate)              WHEN SubCLT.CyclePeriodIDStart = @cycleStart_calendarYear                  THEN DATEFROMPARTS(YEAR(PELT.StartDate), 1, 1)              ELSE NULL          END AS Dt          FROM Const_LeaveType AS SubCLT          WHERE SubCLT.LeaveType_ID = CLT.LeaveType_ID) AS CycleStartDate      LEFT JOIN Const_LeaveTypeDetails AS CLTD ON CLT.LeaveType_ID = CLTD.LeaveTypeId AND (DATEADD(DAY, -1, CycleStartDate.Dt) BETWEEN CLTD.StartDate AND CLTD.EndDate)  WHERE PELT.StartDate >= @FromDate      AND PELT.EndDate <= @ToDate      AND PELT.LeaveAdjustmentTypeID = @adjustmentType_forfeit      AND PELT.LeaveStatusID = @leaveStatus_approved      AND PELT.Enabled = 1      AND (Department.Department_ID = @DepartmentId OR ISNULL(@DepartmentId, 0) = 0)      AND (Division.Division_ID = @DivisionId OR ISNULL(@DivisionId, 0) = 0)      AND (PE.EmployeeTypeID = @EmployeeTypeId OR ISNULL(@EmployeeTypeId, 0) = 0)      AND (PE.EmployeeSubtypeID = @EmployeeSubTypeId OR ISNULL(@EmployeeSubTypeId, 0) = 0)      AND (CLT.LeaveType_ID = @LeaveTypeId OR ISNULL(@LeaveTypeId, 0) = 0)      AND (PE.Employee_ID = @EmployeeId OR ISNULL(@EmployeeId, 0) = 0)  ORDER BY      PE.Employee_ID    END

GO

-- ============================================
-- SP: Payroll_PaymentAudit_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create 21/11/2016,,>  -- Description: <Description, generate the payroll payment audit report  ,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PaymentAudit_rpt]  @BatchID int  AS  BEGIN   select EmployeeID, pe.FirstName, pe.Surname, ppi.ModifierID,ppi.DateModified, 'Bank'   from dbo.Payroll_PaymentInstructions ppi   inner join dbo.Payroll_employee pe on pe.Employee_ID=ppi.EmployeeID   where Changed = 1 and ppi.BatchID= @BatchID    END    

GO

-- ============================================
-- SP: Payroll_PayPointEmployee_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Yevhen Boiko  -- Create date: 07/04/2021  -- Description: Get active employees by Pay Point id  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PayPointEmployee_sp]          @PayrollPayPointId INT  AS  BEGIN      SELECT RIGHT(CONCAT('00000000',[Employee_ID]),8) AS [EmpID]            ,[EmpCode]            ,[IdNo]            ,[FirstName]            ,[Surname]            ,[CD].[DepartmentDesc]      FROM [Payroll_Employee] AS [PE]           LEFT JOIN [Payroll_Position] AS [PP] ON [PE].[PositionID] = [PP].[Position_ID]      LEFT JOIN [Const_Department] AS [CD] ON [PP].[DepartmentID] = [CD].[Department_ID]      WHERE [PE].[Enabled] = 1            AND [PayPointID] = @PayrollPayPointId            AND [PE].[EndDate] < GETDATE();  END;

GO

-- ============================================
-- SP: Payroll_PayRegisterRtp_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL   -- Create date: 05 AUG 2013   -- Description:   -- CALLS : Payroll_PayRegisterRtp_sp 0,0,229  -- 2015-06-01 TP20330 James Roodt: Reordered text to make it more readable  -- 2016-01-05 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_PayRegisterRtp_sp]      @EmployeeID INT ,      @DepartmentId INT ,      @PeriodId INT  AS       BEGIN            DECLARE @FROMDATE DATETIME          DECLARE @TODATE DATETIME          SELECT  @FROMDATE = PeriodStartDate, @TODATE = PeriodEndDate          FROM    Payroll_CyclePeriodDetails          WHERE   Period_ID = @PERIODID             SELECT  @FROMDATE AS FROMDATE, @TODATE AS TODATE    , ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)) AS EmpID, PAY_EMP.Employee_ID, PAY_EMP.EmpCode AS EmpCode    , ( SELECT   CONVERT(VARCHAR, PeriodEndDate, 103) FROM     dbo.Payroll_CyclePeriodDetails WHERE    Period_ID = @PeriodID ) AS PayPeriod       , PAY_EMP.FirstName + ' ' + PAY_EMP.Surname AS EMPNAME       , CONVERT(NVARCHAR, PAY_EMP.JoiningDate, 103) AS JoiningDate    , PAY_EMP.RPD_Other, PAY_EMP.RPH_Other, PAY_EMP.RPD_Monthly, PAY_EMP.RPH_Monthly    , dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo    , CONST_PAY.PaymentTypeDesc, CONST_TRANS.TransactionType_ID, CONST_TRANS.TransactionTypeDesc AS TRANSTYPE, PAY_SAL.SalaryHeadTitle AS TRANSDESC    , CASE WHEN PAY_SAL.SalaryHead_ID IN (10, 11)       THEN ( SELECT    SUM(OverTimeHour)                              FROM      dbo.Payroll_EmployeeOverTime                              WHERE     OverTimeDate BETWEEN @FROMDATE AND @TODATE                                      AND Enabled = 1                                      AND EmployeeID = PAY_EMP.Employee_ID)                  WHEN PAY_SAL.SalaryHead_ID in(24, 25, 26)      THEN ( SELECT   SUM(Kilometer)                              FROM     dbo.Payroll_TravelEntry                              WHERE    EntryDate BETWEEN @FROMDATE AND @TODATE                                      AND Enabled = 1                                      AND EmployeeID = PAY_EMP.Employee_ID )                  ELSE '0.00'             END AS Input, PAY_EMP_PAY.AMOUNT   , ( SELECT   SUM(AMOUNT)              FROM     Payroll_EmployeePayslip              WHERE    PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                  FROM   dbo.Payroll_EmployeePayrollDefinition                                                      INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                  WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )                      AND EMPLOYEEID = PAY_EMP.Employee_ID                      AND TaxSavePurpose = 0                      AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear     ) AS TotalEarning   , ( SELECT    SUM(AMOUNT)              FROM      Payroll_EmployeePayslip              WHERE     PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                  FROM   dbo.Payroll_EmployeePayrollDefinition                                                      INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                  WHERE  Payroll_IRP5Code.TransactionTypeID = 2 )                      AND EMPLOYEEID = PAY_EMP.Employee_ID                      AND TaxSavePurpose = 0                      AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                    ) AS TotalDeduction   , ( SELECT   SUM(AMOUNT)              FROM     Payroll_EmployeePayslip              WHERE    PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                  FROM   dbo.Payroll_EmployeePayrollDefinition                                                      INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                  WHERE  Payroll_IRP5Code.TransactionTypeID = 3 )                      AND EMPLOYEEID = PAY_EMP.Employee_ID                      AND TaxSavePurpose = 0                      AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                        ) AS COMPANYCONTRIBUTION   , ( SELECT SUM(AMOUNT)                  FROM   Payroll_EmployeePayslip                  WHERE  PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                  FROM   dbo.Payroll_EmployeePayrollDefinition                                                      INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                  WHERE  Payroll_IRP5Code.TransactionTypeID = 4 )                      AND EMPLOYEEID = PAY_EMP.Employee_ID                      AND TaxSavePurpose = 0                      AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                       ) AS FRINGEBENEFITS   , ( ( SELECT  ISNULL(SUM(AMOUNT), 0.0)                  FROM    Payroll_EmployeePayslip                  WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                   FROM   dbo.Payroll_EmployeePayrollDefinition                                                          INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                          INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                   WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )                          AND EMPLOYEEID = PAY_EMP.Employee_ID                          AND TaxSavePurpose = 0                          AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                ) - ( SELECT  ISNULL(SUM(AMOUNT), 0.0)                      FROM    Payroll_EmployeePayslip                      WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                       FROM   dbo.Payroll_EmployeePayrollDefinition                                                              INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                              INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                       WHERE  Payroll_IRP5Code.TransactionTypeID = 2 )                              AND EMPLOYEEID = PAY_EMP.Employee_ID                              AND TaxSavePurpose = 0                              AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                              ) ) AS NETPAY     , ( ( SELECT SUM(AMOUNT)                    FROM   Payroll_EmployeePayslip                    WHERE  PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                    FROM   dbo.Payroll_EmployeePayrollDefinition                                                           INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                           INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                    WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )                           AND EMPLOYEEID = PAY_EMP.Employee_ID                           AND TaxSavePurpose = 0                           AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear              ) + ISNULL(( SELECT  SUM(AMOUNT)                              FROM    Payroll_EmployeePayslip                              WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                      FROM   dbo.Payroll_EmployeePayrollDefinition                                                              INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                              INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                      WHERE  Payroll_IRP5Code.TransactionTypeID = 3 )                              AND EMPLOYEEID = PAY_EMP.Employee_ID                              AND TaxSavePurpose = 0                              AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                ), 0.00) ) AS COSTPAY   , PAY_EMP.CycleID   , CASE WHEN PAY_SAL.SalaryHeadName = 'Loan'      THEN ISNULL(( SELECT SUM(Balance)         FROM   dbo.Payroll_InstalmentHistory         WHERE  EmployeeId = PAY_EMP.Employee_ID           AND PeriodID = @PeriodID ), 0)            ELSE 0.00       END AS OpeningBalance   , CASE WHEN TBC.TaxBonusCalculation = 'Monthly Bonus'      THEN ( ISNULL(( SELECT ( TaxWithBonus - TaxWithoutBonus )                                  FROM   dbo.Payroll_EmployeeFinalRunHistory                                  WHERE  EmployeeId = PAY_EMP.Employee_ID                                          AND PeriodId = @PeriodID ), 0) )              ELSE 0.00      END AS TaxOnBonus   , ISNULL(( SELECT SUM(TaxWithBonus - TaxWithoutBonus)                      FROM   dbo.Payroll_EmployeeFinalRunHistory                      WHERE  PeriodId = @PeriodID ), 0) AS TotalTax   , ISNULL(( SELECT   SUM(Balance)                      FROM     dbo.Payroll_InstalmentHistory                      WHERE    PeriodID = @PeriodID ), 0) AS TotalOpeningBalance           FROM    Payroll_Employee PAY_EMP                  INNER JOIN Const_PaymentType CONST_PAY ON PAY_EMP.PaymentTypeID = CONST_PAY.PaymentType_ID                  INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                  INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = PAY_EMP_PAY.PayrollDefinationID                  INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                  INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                  INNER JOIN CONST_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID                  INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID                  INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID                  INNER JOIN dbo.Const_TaxBonusCalculation_sys TBC ON TBC.TaxBonusCalculation_ID = PAY_EMP.BonusCalculation          WHERE   PAY_EMP_PAY.PeriodID = @PeriodID                  AND --PAY_EMP_PAY.FinancialYear = @FinancialYear AND                   ( PAY_EMP.Employee_ID = @EmployeeID                    OR @EmployeeID = 0                  )                  AND ( Department_ID = @DepartmentId                        OR @DepartmentId = 0                      )                  AND TaxSavePurpose = 0          GROUP BY PAY_EMP.Employee_ID, PAY_EMP.EMPCODE, PAY_EMP.FirstName, PAY_EMP.Surname, PAY_EMP.JoiningDate, PAY_EMP.RPD_Other, PAY_EMP.RPH_Other, PAY_EMP.RPD_Monthly, PAY_EMP.RPH_Monthly, CONST_PAY.PaymentTypeDesc, CONST_TRANS.TransactionTypeDesc, PAY_SAL.SalaryHead_ID, PAY_SAL.SalaryHeadName, PAY_SAL.SalaryHeadTitle,     --PAY_EMP.BonusCalculation,                  TBC.TaxBonusCalculation, PAY_EMP_PAY.AMOUNT, PAY_EMP.CycleID, CONST_TRANS.TransactionType_ID, PAY_EMP.Employee_ID      END  

GO

-- ============================================
-- SP: Payroll_PayRegisterRtpTrialRun_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MarioT 2015/05/28 Same as Payroll_PayRegisterRtp_sp but using Trial Run Payroll_EmployeeTrialPayslip instead  -- Payroll_PayRegisterRtp_sp 533,0,3  -- TP20647 : Suri Kandukuri : 2015/11/04 Added From Date and To Date.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_PayRegisterRtpTrialRun_sp]      @EmployeeID INT ,      @DepartmentId INT = 0      ,@PeriodId INT = 0   AS       BEGIN       select distinct @PeriodId = periodid from Payroll_EmployeeTrialPayslip               DECLARE @FROMDATE DATETIME          DECLARE @TODATE DATETIME          SELECT  @FROMDATE = PeriodStartDate, @TODATE = PeriodEndDate          FROM    Payroll_CyclePeriodDetails          WHERE   Period_ID = @PERIODID          /*          SELECT  @FROMDATE AS FROMDATE,             @TODATE AS TODATE,       ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)                                                            ) AS EmpCode,              ( SELECT   CONVERT(VARCHAR, PeriodEndDate, 103)                      FROM     dbo.Payroll_CyclePeriodDetails                      WHERE    Period_ID = @PeriodID                      ) AS PayPeriod,        */    select         @FROMDATE AS FROMDATE,         @TODATE AS TODATE,         ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)                                                            ) AS EmpCode,         PAY_EMP.Employee_ID,        '' as [PayPeriod]        ,PAY_EMP.FirstName + ' ' + PAY_EMP.Surname AS EMPNAME,      CONVERT(NVARCHAR, PAY_EMP.JoiningDate, 103) AS JoiningDate,      PAY_EMP.RPD_Other,      PAY_EMP.RPH_Other,      PAY_EMP.RPD_Monthly,      PAY_EMP.RPH_Monthly,      dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo,      CONST_PAY.PaymentTypeDesc,      CONST_TRANS.TransactionType_ID,      CONST_TRANS.TransactionTypeDesc AS TRANSTYPE,      PAY_SAL.SalaryHeadTitle AS TRANSDESC,      CASE WHEN PAY_SAL.SalaryHead_ID in(10, 11) THEN ( SELECT top 1 SUM(OverTimeHour)                           FROM      dbo.Payroll_EmployeeOverTime                           WHERE     --OverTimeDate BETWEEN @FROMDATE AND @TODATE                             Enabled = 1                             AND EmployeeID = PAY_EMP.Employee_ID                           --order by EmployeeOverTime_ID desc                           )              WHEN PAY_SAL.SalaryHead_ID in(24, 25, 26) THEN ( SELECT top 1  SUM(Kilometer)                                                                              FROM     dbo.Payroll_TravelEntry                                                                              WHERE    --EntryDate BETWEEN @FROMDATE AND @TODATE                                                                                       Enabled = 1                                                                                      AND EmployeeID = PAY_EMP.Employee_ID                       --Order by TravelEntry_ID desc                                                                              )              ELSE '0.00'              END AS Input,      petp.AMOUNT,      ( SELECT   SUM(AMOUNT)      FROM     Payroll_EmployeePayslip      WHERE    PayrollDefinationID IN ( SELECT top 1 EmployeePayrollDefinition_ID               FROM   dbo.Payroll_EmployeePayrollDefinition                INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID               WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )                AND EMPLOYEEID = PAY_EMP.Employee_ID                AND TaxSavePurpose = 0                --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                --Order by EmployeePayrollDefinition_ID desc                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           ) AS TotalEarning,      ( SELECT    SUM(AMOUNT)                                  FROM      Payroll_EmployeePayslip                                  WHERE     PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                                      FROM   dbo.Payroll_EmployeePayrollDefinition                                                                          INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                                          INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                                      WHERE  Payroll_IRP5Code.TransactionTypeID = 2 )                                          AND EMPLOYEEID = PAY_EMP.Employee_ID                                          AND TaxSavePurpose = 0                                          --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ) AS TotalDeduction,      ( SELECT   SUM(AMOUNT)                                      FROM     Payroll_EmployeePayslip                                      WHERE    PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                                          FROM   dbo.Payroll_EmployeePayrollDefinition                                                                              INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                                              INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                                          WHERE  Payroll_IRP5Code.TransactionTypeID = 3 )                                              AND EMPLOYEEID = PAY_EMP.Employee_ID                                              AND TaxSavePurpose = 0                                              --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           ) AS COMPANYCONTRIBUTION,      ( SELECT SUM(AMOUNT)                                          FROM   Payroll_EmployeePayslip                                          WHERE  PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                                          FROM   dbo.Payroll_EmployeePayrollDefinition                                                                              INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                                              INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                                          WHERE  Payroll_IRP5Code.TransactionTypeID = 4 )                                              AND EMPLOYEEID = PAY_EMP.Employee_ID                                              AND TaxSavePurpose = 0                                              --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     ) AS FRINGEBENEFITS,      ( ( SELECT  ISNULL(SUM(AMOUNT), 0.0)                                      FROM    Payroll_EmployeePayslip                                      WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                                          FROM   dbo.Payroll_EmployeePayrollDefinition                                                                              INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                                              INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                                          WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )                                              AND EMPLOYEEID = PAY_EMP.Employee_ID                                              AND TaxSavePurpose = 0                                              --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ) - ( SELECT  ISNULL(SUM(AMOUNT), 0.0)                                          FROM    Payroll_EmployeePayslip                                          WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                                                                              FROM   dbo.Payroll_EmployeePayrollDefinition                                                                                  INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                                                                                  INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                                                                              WHERE  Payroll_IRP5Code.TransactionTypeID = 2 )                                                  AND EMPLOYEEID = PAY_EMP.Employee_ID                                                  AND TaxSavePurpose = 0                                                  --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ) ) AS NETPAY,      ( ( SELECT SUM(AMOUNT)          FROM   Payroll_EmployeePayslip          WHERE  PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                  FROM   dbo.Payroll_EmployeePayrollDefinition                   INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                   INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                  WHERE  Payroll_IRP5Code.TransactionTypeID = 1 )           AND EMPLOYEEID = PAY_EMP.Employee_ID           AND TaxSavePurpose = 0           --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ) + ISNULL(( SELECT  SUM(AMOUNT)            FROM    Payroll_EmployeePayslip            WHERE   PayrollDefinationID IN ( SELECT EmployeePayrollDefinition_ID                     FROM   dbo.Payroll_EmployeePayrollDefinition                      INNER JOIN dbo.Payroll_SalaryHead ON Payroll_SalaryHead.SalaryHead_ID = Payroll_EmployeePayrollDefinition.PayrollSalaryHeadID                      INNER JOIN Payroll_IRP5Code ON Payroll_SalaryHead.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                     WHERE  Payroll_IRP5Code.TransactionTypeID = 3 )              AND EMPLOYEEID = PAY_EMP.Employee_ID              AND TaxSavePurpose = 0              --AND PeriodID = @PeriodID --AND FinancialYear=@FinancialYear                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   ), 0.00) ) AS COSTPAY,      PAY_EMP.CycleID,      CASE WHEN PAY_SAL.SalaryHeadName = 'Loan' THEN ISNULL(( SELECT SUM(Balance)                                                                              FROM   dbo.Payroll_InstalmentHistory                                                                              WHERE  EmployeeId = PAY_EMP.Employee_ID                                                                                  --AND PeriodID = @PeriodID                                                                                                                  ), 0)                                                          ELSE 0.00                                                      END AS OpeningBalance,      CASE WHEN TBC.TaxBonusCalculation = 'Monthly Bonus' THEN ( ISNULL(( SELECT top 1 ( TaxWithBonus - TaxWithoutBonus )                                                                                                          FROM   dbo.Payroll_EmployeeFinalRunHistory                                                                                                          WHERE  EmployeeId = PAY_EMP.Employee_ID                                                                                                              --AND PeriodId = @PeriodID                             order by Payroll_EmployeeFinalRunHistory.ID desc                                                                                                      ), 0) )                                          ELSE 0.00                                      END AS TaxOnBonus,      ISNULL(( SELECT SUM(TaxWithBonus - TaxWithoutBonus)                                          FROM   dbo.Payroll_EmployeeFinalRunHistory                                          --WHERE  PeriodId = @PeriodID                                      ), 0) AS TotalTax,      ISNULL(( SELECT   SUM(Balance)                                          FROM     dbo.Payroll_InstalmentHistory                                          --WHERE    PeriodID = @PeriodID                                          ), 0) AS TotalOpeningBalance          FROM    Payroll_EmployeeTrialPayslip  petp     Inner join Payroll_Employee PAY_EMP on PAY_EMP.Employee_ID = petp.EmployeeID              INNER JOIN Const_PaymentType CONST_PAY ON PAY_EMP.PaymentTypeID = CONST_PAY.PaymentType_ID             -- INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID              INNER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_DEF.EmployeePayrollDefinition_ID = petp.PayrollDefinationID              INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID              INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID              INNER JOIN CONST_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID              INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID              INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID              INNER JOIN dbo.Const_TaxBonusCalculation_sys TBC ON TBC.TaxBonusCalculation_ID = PAY_EMP.BonusCalculation          WHERE   --PAY_EMP_PAY.PeriodID = @PeriodID                  --AND --PAY_EMP_PAY.FinancialYear = @FinancialYear AND                   ( PAY_EMP.Employee_ID = @EmployeeID OR @EmployeeID = 0 )                  AND ( Department_ID = @DepartmentId OR @DepartmentId = 0 )                  AND petp.TaxSavePurpose = 0          GROUP BY PAY_EMP.Employee_ID, PAY_EMP.EMPCODE, PAY_EMP.FirstName, PAY_EMP.Surname, PAY_EMP.JoiningDate, PAY_EMP.RPD_Other, PAY_EMP.RPH_Other, PAY_EMP.RPD_Monthly, PAY_EMP.RPH_Monthly, CONST_PAY.PaymentTypeDesc, CONST_TRANS.TransactionTypeDesc, PAY_SAL.SalaryHead_ID, PAY_SAL.SalaryHeadName, PAY_SAL.SalaryHeadTitle,     --PAY_EMP.BonusCalculation,                  TBC.TaxBonusCalculation, petp.AMOUNT, PAY_EMP.CycleID, CONST_TRANS.TransactionType_ID, PAY_EMP.Employee_ID      END  

GO

-- ============================================
-- SP: Payroll_PayrollDefinationList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL    -- Create date: 06 JULY 2013    -- Description: <Description,,>    -- CALLS : [Payroll_PayrollDefinationList_sp] '2012/2013',0,5,0    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_PayrollDefinationList_sp]   @FinancialYear NVARCHAR(50),     @TransactionTypeID INT,     @TransactionTypeDescID INT,     @SalaryHead INT    AS    BEGIN      SELECT        PAY_PAYDEF.PayrollDefination_ID,        PAY_PRO_GROUP.PayrollDefinitionGroupName as ProfileGroupName,        PAY_ROLL_SAL.SalaryHeadTitle AS PayrollSalaryHeadName,        CONST_TRANS.TRANSACTIONTYPEDESC as TransactionType,        ISNULL(PAY_ROLL_SAL.SalaryHeadTitle,'') as TransactionTypeDesc,        CONVERT(NVARCHAR,IRP5.IRP5Code) + ' - ' + IRP5.IRP5CodeDesc AS IRP5CodeDesc,        CONST_TAX.TaxabilityDesc,        PAY_PAYDEF.Percentage AS TaxablePercentage,        CASE WHEN  PAY_PAYDEF.Enabled = 1        THEN        'True'        ELSE        'False'        END AS [STATUS],        CASE WHEN  PAY_PAYDEF.IsRFI = 1        THEN        'True'        ELSE        'False'        END AS IsRFI,       '' AS ActivityNumber,       '' AS FunctionNumber      FROM Payroll_PayrollDefination PAY_PAYDEF       INNER JOIN Payroll_SalaryHead PAY_ROLL_SAL ON PAY_ROLL_SAL.SalaryHead_ID =PAY_PAYDEF.PayrollSalaryHeadID       INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON IRP5.IRP5Code_ID = PAY_ROLL_SAL.IRP5CodeId       INNER JOIN CONST_TRANSACTIONTYPE CONST_TRANS ON CONST_TRANS.TRANSACTIONTYPE_ID = IRP5.TransactionTypeID       INNER JOIN Const_Taxability CONST_TAX ON CONST_TAX.Taxability_ID = IRP5.TaxableID       INNER JOIN Payroll_DefinitionGroup PAY_PRO_GROUP ON PAY_PRO_GROUP.PayrollDefinitionGroup_ID =PAY_PAYDEF.PayrollDefinitionGroupID      WHERE (IRP5.TransactionTypeID = @TransactionTypeID or @TransactionTypeID = 0)      AND (PAY_PAYDEF.PayrollDefinitionGroupID = @TransactionTypeDescID or @TransactionTypeDescID = 0)      AND (PAY_PAYDEF.PayrollSalaryHeadID = @SalaryHead or @SalaryHead = 0)      ORDER BY CONST_TRANS.TRANSACTIONTYPEDESC    END    

GO

-- ============================================
-- SP: Payroll_PayrollDefinitionChanged_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,05 Sep 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_PayrollDefinitionChanged_sp  -- 2015-10-07 TP25665 Ravindra Jijotia: Commented @FromEmployeeScreen = 1 part which was being called from Add Employee screen when we update job grading group.  --     It was updating the payroll definition group then all the employees belongs to that group, found during % split.  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_PayrollDefinitionChanged_sp]      @FromEmployeeScreen BIT ,      @EmployeePayrollDefinitionID INT ,      @PayrollDefinitionID INT ,      @IsNewRecord BIT ,      @UserId INT ,      @UserName NVARCHAR(50)  AS       BEGIN          DECLARE @PayrollDefinitionGroupID INT ,              @PayrollSalaryHeadID INT ,              @FunctionCodeID INT ,              @Percentage DECIMAL(18, 2) ,              @Enabled BIT ,              @IsRFI BIT ,              @SCOAFundsID INT ,              @SCOARegionID INT ,              @SCOACostingID INT ,              @SCOAProjectID INT ,              @SCOAItemID INT ,              @SqlQuery NVARCHAR(MAX) ,              @DatabaseName NVARCHAR(100)                        SELECT  @DatabaseName = KeyValue          FROM    dbo.AAAA_ConfigSettings          WHERE   KeyName = 'FMSAuditDatabaseName'                            IF @FromEmployeeScreen = 1               BEGIN      PRINT '@FromEmployeeScreen = 1'              --    IF ( SELECT CustomAction              --         FROM   dbo.Payroll_EmployeePayrollDefinition              --         WHERE  EmployeePayrollDefinition_ID = @EmployeePayrollDefinitionID              --       ) = 0               --        BEGIN              --            SELECT  @PayrollDefinitionGroupID = PayrollDefinitionGroupID, @PayrollSalaryHeadID = EPD.PayrollSalaryHeadID, @FunctionCodeID = EPD.FunctionCodeID, @Percentage = EPD.Percentage, @Enabled = EPD.Enabled, @IsRFI = EPD.IsRFI, @SCOAFundsID = EPD.SCOAFundsID, @SCOARegionID = EPD.SCOARegionID, @SCOACostingID = EPD.SCOACostingID, @SCOAProjectID = EPD.SCOAProjectID, @SCOAItemID = EPD.SCOAItemID              --            FROM    dbo.Payroll_EmployeePayrollDefinition AS EPD              --                    INNER JOIN dbo.Payroll_Employee AS Emp ON EPD.EmployeeID = Emp.Employee_ID              --            WHERE   EmployeePayrollDefinition_ID = @EmployeePayrollDefinitionID                                        --            SET @SqlQuery = 'INSERT INTO ' + @DatabaseName + '.dbo.aPayroll_PayrollDefination ( AuditUserID, AuditDate, AuditUser, PayrollDefination_ID, PayrollDefinitionGroupID, PayrollSalaryHeadID, FunctionCodeID, Percentage, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, IsRFI, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID ) '              --            SET @SqlQuery = @SqlQuery + 'SELECT  ' + CONVERT(VARCHAR(50), @UserId) + ', GETDATE(), ''' + @UserName + ''', PayrollDefination_ID, PayrollDefinitionGroupID, PayrollSalaryHeadID, FunctionCodeID, Percentage, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, IsRFI, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID              --  FROM    dbo.Payroll_PayrollDefination WHERE PayrollDefinitionGroupID = ' + CONVERT(VARCHAR(50), @PayrollDefinitionGroupID) + '              --  AND PayrollSalaryHeadID = ' + CONVERT(VARCHAR(50), @PayrollSalaryHeadID) + ''              --            EXEC(@SqlQuery)              --            SET @SqlQuery = ''                                        --            UPDATE  dbo.Payroll_PayrollDefination              --            SET     FunctionCodeID = @FunctionCodeID, Percentage = @Percentage, Enabled = @Enabled, IsRFI = @IsRFI, SCOAFundsID = @SCOAFundsID, SCOARegionID = @SCOARegionID, SCOACostingID = @SCOACostingID, SCOAProjectID = @SCOAProjectID, SCOAItemID = @SCOAItemID, DateModified = GETDATE(), ModifierID = @UserId              --            WHERE   PayrollDefinitionGroupID = @PayrollDefinitionGroupID              --                    AND PayrollSalaryHeadID = @PayrollSalaryHeadID                                        --            SET @SqlQuery = N'INSERT  INTO ' + @DatabaseName + '.dbo.aPayroll_EmployeePayrollDefinition ( AuditUserID, AuditDate, AuditUser, EmployeePayrollDefinition_ID, PayrollSalaryHeadID, FunctionCodeID, Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, CustomAction, RepeateEveryYear, IsRFI, PayrollSalaryHeadEmployeeTitle, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID )'              --            SET @SqlQuery = @SqlQuery + 'SELECT  ' + CONVERT(VARCHAR(50), @UserId) + ', GETDATE(), ''' + @UserName + ''', EmployeePayrollDefinition_ID, PayrollSalaryHeadID, FunctionCodeID, Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, CustomAction, RepeateEveryYear, IsRFI, PayrollSalaryHeadEmployeeTitle, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID              --  FROM dbo.Payroll_EmployeePayrollDefinition WHERE PayrollSalaryHeadID = ' + CONVERT(VARCHAR(50), @PayrollSalaryHeadID) + '              --  AND EmployeeID IN ( SELECT  Employee_ID              --                                         FROM    dbo.Payroll_Employee              --                                         WHERE   PayrollDefinitionGroupID = ' + CONVERT(VARCHAR(50), @PayrollDefinitionGroupID) + ' )              --                                         AND dbo.Payroll_EmployeePayrollDefinition.Enabled = 1'                                        --            EXEC(@SqlQuery)              --            SET @SqlQuery = ''                                                --            UPDATE  dbo.Payroll_EmployeePayrollDefinition              --            SET     FunctionCodeID = @FunctionCodeID, Percentage = @Percentage, Enabled = @Enabled, IsRFI = @IsRFI, SCOAFundsID = @SCOAFundsID, SCOARegionID = @SCOARegionID, SCOACostingID = @SCOACostingID, SCOAProjectID = @SCOAProjectID, SCOAItemID = @SCOAItemID, DateModified = GETDATE(), ModifierID = @UserId              --            WHERE   PayrollSalaryHeadID = @PayrollSalaryHeadID              --                    AND EmployeeID IN ( SELECT  Employee_ID              --                                        FROM    dbo.Payroll_Employee              --                                        WHERE   PayrollDefinitionGroupID = @PayrollDefinitionGroupID )              --                    AND dbo.Payroll_EmployeePayrollDefinition.Enabled = 1                                        --        END              END          ELSE               BEGIN                  SELECT  @PayrollDefinitionGroupID = PayrollDefinitionGroupID, @PayrollSalaryHeadID = PayrollSalaryHeadID, @FunctionCodeID = FunctionCodeID, @Percentage = Percentage, @Enabled = Enabled, @IsRFI = IsRFI, @SCOAFundsID = SCOAFundsID, @SCOARegionID = SCOARegionID, @SCOACostingID = SCOACostingID, @SCOAProjectID = SCOAProjectID, @SCOAItemID = SCOAItemID                  FROM    Payroll_PayrollDefination                  WHERE   PayrollDefination_ID = @PayrollDefinitionID                                    IF @IsNewRecord = 1                       BEGIN                          INSERT  INTO dbo.Payroll_EmployeePayrollDefinition ( PayrollSalaryHeadID, FunctionCodeID, Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, CustomAction, RepeateEveryYear, IsRFI, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID )                                  SELECT  @PayrollSalaryHeadID, @FunctionCodeID, @Percentage, Employee_ID, @Enabled, GETDATE(), @UserId, 0, 0, @IsRFI, @SCOAFundsID, @SCOARegionID, @SCOACostingID, @SCOAProjectID, @SCOAItemID                                  FROM    dbo.Payroll_Employee                                  WHERE   PayrollDefinitionGroupID = @PayrollDefinitionGroupID                      END                  ELSE                       BEGIN        SET @SqlQuery = N'INSERT  INTO ' + @DatabaseName + '.dbo.aPayroll_EmployeePayrollDefinition ( AuditUserID, AuditDate, AuditUser, EmployeePayrollDefinition_ID, PayrollSalaryHeadID, FunctionCodeID, Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, CustomAction, RepeateEveryYear, IsRFI, PayrollSalaryHeadEmployeeTitle, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID )'                          SET @SqlQuery = @SqlQuery + 'SELECT  ' + CONVERT(VARCHAR(50), @UserId) + ', GETDATE(), ''' + @UserName + ''', EmployeePayrollDefinition_ID, PayrollSalaryHeadID, FunctionCodeID, Percentage, EmployeeID, Enabled, DateCaptured, CapturerID, DateModified, ModifierID, CustomAction, RepeateEveryYear, IsRFI, PayrollSalaryHeadEmployeeTitle, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAItemID                FROM dbo.Payroll_EmployeePayrollDefinition                 WHERE PayrollSalaryHeadID = ' + CONVERT(VARCHAR(50), @PayrollSalaryHeadID) + '                AND EmployeeID IN ( SELECT  Employee_ID                                                       FROM    dbo.Payroll_Employee                                                       WHERE   PayrollDefinitionGroupID = ' + CONVERT(VARCHAR(50), @PayrollDefinitionGroupID) + ' )                                                       AND dbo.Payroll_EmployeePayrollDefinition.Enabled = 1'                                                    EXEC(@SqlQuery)                          SET @SqlQuery = ''                                                    UPDATE  dbo.Payroll_EmployeePayrollDefinition                          SET     FunctionCodeID = @FunctionCodeID, Percentage = @Percentage, Enabled = @Enabled, IsRFI = @IsRFI, SCOAFundsID = @SCOAFundsID, SCOARegionID = @SCOARegionID, SCOACostingID = @SCOACostingID, SCOAProjectID = @SCOAProjectID, SCOAItemID = @SCOAItemID, DateModified = GETDATE(), ModifierID = @UserId                          WHERE   PayrollSalaryHeadID = @PayrollSalaryHeadID                                  AND EmployeeID IN ( SELECT  Employee_ID                                                      FROM    dbo.Payroll_Employee                                                      WHERE   PayrollDefinitionGroupID = @PayrollDefinitionGroupID )                                  AND dbo.Payroll_EmployeePayrollDefinition.Enabled = 1                      END              END      END  

GO

-- ============================================
-- SP: Payroll_PayrollJournalrpt_sp
-- Schema: dbo
-- ============================================
      /*       Author  : Richa Mills     Create date : 2017/12/01      Description : Generates Payroll Journal for final Run        Exec Payroll_PayrollJournalrpt_sp 3,'2019',3,null,null,null,null,null,null,null,17      16/02/2021 Modified by Ivan Myroshychenko - fix problem with TaxY    21/02/2021 Richa M: Above fix caused a blank report. The Tax year param is sent from the front end as 2021 not 2020/2021 WI58600    02/11/2023 Richa M: Exclude transactions that were not posted to the GL due to the SalaryControl Id being the same as the main salary control  */         CREATE procedure [dbo].[Payroll_PayrollJournalrpt_sp]              @PeriodId int = 0,      @TaxYear nvarchar(50) = '',      @CalendarMonth INT = 0,       @SCOAFundsFilterID int = 0,      @SCOARegionFilterID int = 0,      @SCOACostingFilterID int = 0,            @SCOAProjectFilterID int = 0,     @SCOAFunctionFilterID int = 0,      @SCOAItemFilterID int = 0,      @SalaryHeadFilterID int = 0,    @CycleId int                  as            BEGIN    DECLARE @StartDate DATETIME, @EndDate DATETIME  DECLARE @PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1   DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear        SELECT @StartDate =  (Select top 1 PeriodStartDate from Payroll_CyclePeriodDetails where TaxYear = @CurrentPeriodTaxYear and PeriodInTaxYear = @PeriodId and CycleID = @CycleId order by PeriodStartDate asc)  SELECT @EndDate =  (Select top 1 PeriodEndDate from Payroll_CyclePeriodDetails where TaxYear = @CurrentPeriodTaxYear and PeriodInTaxYear = @PeriodId and CycleID = @CycleId order by PeriodStartDate desc)     SELECT   @StartDate PeriodStart,   @EndDate PeriodEnd   ,PayrollResults.*     ,emp.EmpCode     ,tt.TransactionTypeDesc     ,ScoaItemValue.ScoaCode dtCode     ,SCOAItemValue.ScoaShortDesc dtDesc     ,ContraItemValue.ScoaCode ctCode     ,ContraItemValue.ScoaShortDesc ctDesc     ,SCOAFunds.ScoaCode AS ScoaFund     ,SCOAFunction.ScoaCode AS ScoaFunction     ,SCOAProject.ScoaCode AS ScoaProject     ,SCOACosting.ScoaCode AS ScoaCosting     ,SCOARegion.ScoaCode AS ScoaREgion     ,tg.DocNumber     ,tg.SCMInvoiceSalaryHeadName SalaryTitle     ,DepartmentCode + '/' + DivisionCode AS MunicipalClass       FROM (SELECT    EmployeeID      ,TransactionTypeID      ,DebitAmount AS Amount      ,SalaryHeadID      ,SCOAItemID      ,VoteID      ,SCOAProjectID      ,SCOAFunctionID      ,SCOAFundsID      ,SCOARegionID      ,SCOACostingID      ,TransactionsGroupID      ,DivisionID      ,ContraVoteId      ,vendorId   FROM Payroll_Transactions   WHERE PeriodID in(Select Period_ID from Payroll_CyclePeriodDetails where TaxYear = @CurrentPeriodTaxYear and ProcessingMonth = (select DATENAME(m, str(@PeriodId) + '/1/2011')) and CycleID = @CycleId)    AND TransactionTypeID IN (1,2, 3) AND (DebitAmount <> 0 OR (SalaryHeadId = 30 AND DebitAmount <> 0 ))   AND DocNumber like ('131/%') and TransactionsGroupID in (select PayrollLinkID from Led_GeneralLedger)    ) AS PayrollResults    JOIN Const_Division div    ON div.Division_ID = PayrollResults.DivisionID    JOIN Const_Department dep   ON dep.Department_ID = div.DepartmentID    JOIN Payroll_TransactionsGroup tg   ON tg.TransactionGroup_ID = PayrollResults.TransactionsGroupID     JOIN Const_SCOA_Structure SCOAItemValue   ON SCOAItemValue.ScoaID = PayrollResults.SCOAItemID  JOIN Const_SCOA_Structure ContraItemValue   ON ContraItemValue.ScoaID = PayrollResults.ContraVoteID  LEFT OUTER JOIN Payroll_Employee emp   ON emp.Employee_ID = PayrollResults.EmployeeId    LEFT OUTER JOIN Const_TransactionType tt   ON tt.TransactionType_ID = PayrollResults.TransactionTypeID    JOIN Const_SCOA_Funds_Structure SCOAFunds    ON SCOAFunds.ScoaID = PayrollResults.SCOAFundsID    JOIN Const_SCOA_Regional_Structure SCOARegion    ON SCOAregion.ScoaID = PayrollResults.SCOARegionID    JOIN Const_SCOA_Costing_Structure SCOACosting    ON SCOACosting.ScoaID = PayrollResults.SCOACostingID    JOIN Const_SCOA_Project_Structure SCOAProject    ON SCOAProject.ScoaID = PayrollResults.SCOAProjectID    JOIN Const_SCOA_Function_Structure SCOAFunction    ON SCOAFunction.ScoaID = PayrollResults.SCOAFunctionID    WHERE (PayrollResults.SCOAFundsID = @SCOAFundsFilterID OR ISnull(@SCOAFundsFilterID,0) = 0)  AND (PayrollResults.SCOARegionID = @SCOARegionFilterID OR ISNULL(@SCOARegionFilterID,0) = 0)  AND (PayrollResults.SCOACostingID = @SCOACostingFilterID OR ISNULL(@SCOACostingFilterID,0) = 0)  AND (PayrollResults.SCOAProjectID = @SCOAProjectFilterID OR ISNULL(@SCOAProjectFilterID,0) = 0)  AND (PayrollResults.SCOAFunctionID = @SCOAFunctionFilterID OR ISNULL(@SCOAFunctionFilterID,0) = 0)  AND (PayrollResults.SCOAItemID = @SCOAItemFilterID OR ISNULL(@SCOAItemFilterID,0) = 0)  AND (PayrollResults.SalaryHeadID = @SalaryHeadFilterID OR ISNULL(@SalaryHeadFilterID,0) = 0)  order by CAST(Substring(DocNumber,5,Len(DocNumber)) AS INT)        end

GO

-- ============================================
-- SP: Payroll_PayrollJournalTrialrpt_sp
-- Schema: dbo
-- ============================================
    /*   Author  : Lungisani Khumalo   Create date : 29/08/2017   Description : Generates Payroll Journal for Trial Run  */    create procedure [dbo].[Payroll_PayrollJournalTrialrpt_sp]      @PayrollCycleId int = 0,  @TaxYear nvarchar(50) = '',  @CalendarMonth INT = 0,    @SCOAFundsFilterID int = 0,  @SCOARegionFilterID int = 0,  @SCOACostingFilterID int = 0,         @SCOAProjectFilterID int = 0,  @SCOAFunctionFilterID int = 0,  @SCOAItemFilterID int = 0,  @SalaryHeadFilterID int = 0         as     begin       set nocount on;     begin try       declare @PeriodEndDate datetime, @PeriodStartDate datetime,@Cycle nvarchar(250)        select @CalendarMonth  = month(PeriodStartDate), @PayrollCycleId = cpd.CycleID, @TaxYear = cpd.TaxYear, @PeriodEndDate = PeriodEndDate        from Payroll_TrailRun_History trh with(nolock)        left join Payroll_CyclePeriodDetails cpd ON cpd.Period_ID = trh.PeriodID        where trh.[Status] = 'InProcess' and trh.Porcessed = 0           declare @Period table (Period_Id int)        insert into @Period       select Period_ID FROM dbo.Payroll_CyclePeriodDetails where datepart(month, PeriodStartDate) = @CalendarMonth AND TaxYear = @TaxYear AND (CycleID = @PayrollCycleId OR @PayrollCycleId = 0)          select @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails where Period_ID in (select Period_Id from @Period)          select @Cycle = CycleDesc from Const_Cycle where Cycle_ID = @PayrollCycleId             select dbo.BufferString_fxn(convert(varchar, ( TrialResults.EmployeeID )), 8,'0')  AS EmpNo,isnull(emp.empcode,'') as EmpCode,tt.TransactionType_ID,          tt.TransactionTypeDesc ,'' as ScoaCode,'' as ScoaShortDesc ,'' as ControlScoaCode,'' as ControlScoaShortDesc  ,salhead.SalaryHeadTitle, TrialResults.Amount DebitAmount,              '' DocumentNumber,0 TotalLedgerAmount, @PeriodEndDate AS PeriodEndDate, @PeriodStartDate AS PeriodStartDate , @Cycle as CycleDesc ,SCOAFunds.ScoaCode SCOAFundCode,SCOAFunds.ScoaShortDesc SCOAFundDesc              ,SCOARegion.ScoaCode SCOARegionCode,SCOARegion.ScoaShortDesc SCOARegionDesc ,SCOACosting.ScoaCode SCOACostingCode,SCOACosting.ScoaShortDesc SCOACostingDesc ,SCOAProject.ScoaCode SCOAProjectCode,SCOAProject.ScoaShortDesc SCOAProjectDesc         ,SCOAFunction.ScoaCode SCOAFunctionCode,SCOAFunction.ScoaShortDesc SCOAFunctionDesc,SCOAItemValue.ScoaCode SCOAItemCode,SCOAItemValue.ScoaShortDesc SCOAItemDesc            from  Payroll_TrialResults TrialResults with(nolock)           join Payroll_SalaryHead salhead  with(nolock) on salhead.SalaryHead_ID = TrialResults.SalaryHeadID         join Payroll_IRP5Code irp5  with(nolock) on irp5.IRP5Code_ID = salhead.IRP5CodeId         join Const_TransactionType tt  with(nolock) on tt.TransactionType_ID = irp5.TransactionTypeID         join Const_SCOA_Funds_Structure SCOAFunds  with(nolock) on SCOAFunds.ScoaID = TrialResults.SCOAFundingID         join Const_SCOA_Regional_Structure SCOARegion  with(nolock) on SCOAregion.ScoaID = TrialResults.SCOARegionID         join Const_SCOA_Costing_Structure SCOACosting  with(nolock) on SCOACosting.ScoaID = TrialResults.SCOACostingID         join Const_SCOA_Project_Structure  SCOAProject  with(nolock) on SCOAProject.ScoaID = TrialResults.SCOAProjectID         join Const_SCOA_Function_Structure SCOAFunction  with(nolock) on SCOAFunction.ScoaID = TrialResults.SCOAFunctionID         join Const_SCOA_Structure SCOAItemValue  with(nolock) on SCOAItemValue.ScoaID = TrialResults.SCOAItemID         join Payroll_Employee emp  with(nolock) on emp.Employee_ID = TrialResults.EmployeeId         where PeriodID in (select Period_Id from @Period)         and TransactionType_ID in (1,3)          and (case when @SCOAFundsFilterID = 0 then 1  when @SCOAFundsFilterID = TrialResults.SCOAFundingID then 1  else 0 end ) = 1         and (case when @SCOARegionFilterID = 0 then 1 when @SCOARegionFilterID = TrialResults.SCOARegionID then 1 else 0 end ) = 1         and (case when @SCOACostingFilterID = 0 then 1 when @SCOACostingFilterID = TrialResults.SCOACostingID then 1 else 0 end ) = 1         and (case when @SCOAProjectFilterID = 0 then 1  when @SCOAProjectFilterID = TrialResults.SCOAProjectID then 1 else 0 end ) = 1         and (case when @SCOAFunctionFilterID = 0 then 1  when @SCOAFunctionFilterID = TrialResults.SCOAFunctionID then 1 else 0 end ) = 1         and (case when @SCOAItemFilterID = 0 then 1 when @SCOAItemFilterID = TrialResults.SCOAItemID then 1 else 0 end ) = 1         and (case when @SalaryHeadFilterID = 0 then 1 when salhead.SalaryHead_ID=@SalaryHeadFilterID then 1  else 0 end = 1 )         order by TransactionTypeDesc,SalaryHeadTitle      end try     begin catch      print error_message();     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_PayrollLeavePaid_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_PayrollLeavePaid_sp]     --(@Employee_ID int)     AS    BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.  SET NOCOUNT ON;    SELECT emp.Employee_ID, emp.Surname, emp.FirstName, emp.FixedSalary,          (emp.FixedSalary * 12) AS        Annualy, ((emp.FixedSalary * 5.5) / 100 + emp.FixedSalary) AS NewSalary    FROM Payroll_Employee emp      ORDER BY Employee_ID    END    --EXEC [dbo].[Payroll_PayrollLeavePaid_sp]  

GO

-- ============================================
-- SP: Payroll_PayrollRunDetails
-- Schema: dbo
-- ============================================
   -- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-11-26  -- Description: Used as a dataset for Payroll Run Schedule report (rptEarningDeduction.rdl)  --              Returns Payroll Trial or Final Run results for @PeriodId  --Payroll_PayrollRunDetails 2,0,1185,1634,0  --Modified : Richa M 2022/03/15 Fix Report to handle Positional Split correctly  --2022/04/11 M Van Wyk WI85441 Added Payroll_EmployeeMedicalAIDDetail for MedicalAid Reference if exists  --2022/04/18 Richa M - The above changes caused duplicates on the report.   --2022/05/25 Richa M - Fix Commission amount  --2022/06/22 Richa M - Replace SalaryTitle with ReferenceNo   --2023/04/03 Richa M - WI96618 Fix duplications on report   --2023/12/05 Kiran - WI79649 report only the reference number should be in the column, if no reference number exists the column should be blank   --2024/01/14 Richa M - Above change caused duplicates on Report. Fixed duplicates and added reference   -- =============================================    CREATE PROCEDURE [dbo].[Payroll_PayrollRunDetails]      @TransactionTypeId INT,      @SalaryHeadId INT,      @PeriodId INT,      @VendorId INT,      @IsTrialRun BIT  AS  BEGIN    DECLARE       @transactionType_earnings INT = 1,      @transactionType_deductions INT = 2,      @transactionType_companyContrib INT = 3,      @transactionType_fringeBen INT = 4      DROP TABLE IF EXISTS #PayrollResults    -- Select from Trial Run tables or Final Run tables depending on @IsTrialRun  Select  PR.EmployeeID, PR.SalaryHeadID, PR.Amount, PR.DepartmentID, PR.Calculation ReferenceNo, PR.VendorID, PR.TransactionTypeID INTO #PayrollResults from(  SELECT ppr.*  from Payroll_TrialResults ppr   WHERE ppr.PeriodID = @PeriodId AND ppr.TaxSavePurpose = 0      AND (ISNULL(@SalaryHeadId, 0) = 0 OR ppr.SalaryHeadID = @SalaryHeadId)      AND (ISNULL(@TransactionTypeId, 0) = 0 OR TransactionTypeID = @TransactionTypeId)      AND (ISNULL(@VendorId, 0) = 0 OR PPR.VendorID = @VendorId))PR  UNION ALL  Select   PR.EmployeeID, PR.SalaryHeadID, PR.Amount, PR.DepartmentID, PR.Calculation ReferenceNo, PR.VendorID, PR.TransactionTypeID from(  SELECT ppr.* from Payroll_PayrollResults ppr   WHERE ppr.PeriodID = @PeriodId AND ppr.TaxSavePurpose = 0      AND (ISNULL(@SalaryHeadId, 0) = 0 OR ppr.SalaryHeadID = @SalaryHeadId)      AND (ISNULL(@TransactionTypeId, 0) = 0 OR TransactionTypeID = @TransactionTypeId)      AND (ISNULL(@VendorId, 0) = 0 OR VendorID = @VendorId))PR    SELECT      E.Employee_ID,      E.EmpCode,      E.Initials,      E.Surname,      PR.SalaryHeadID,      SH.SalaryHeadName,      PR.VendorID,      V.VendorName,      PR.Amount,      ISNULL(PR.ReferenceNo,'') AS ReferenceNo,      CASE          WHEN GLH.JournalEntryOnly = 1 AND PR.TransactionTypeID IN (@transactionType_deductions, @transactionType_companyContrib)               THEN 'Journal'          WHEN PR.TransactionTypeID IN (@transactionType_deductions, @transactionType_companyContrib)              THEN ISNULL(CTT.TransactionDesc, '')          ELSE ''      END AS PaymentMethod,      Inv.VendorInvoiceNumberCustom,      IIF(PR.TransactionTypeID = @transactionType_deductions AND ISNULL(V.bPayrollCommission, 0) = 1, 1, 0) AS HasCommision,      IIF(PR.TransactionTypeID <> @transactionType_deductions OR ISNULL(V.bPayrollCommission, 0) = 0, NULL, V.CommissionPercentage) AS CommissionPercentage,       InvoiceDetails.CommissionAmount,      PR.TransactionTypeID,      TT.TransactionTypeDesc AS TransactionTypeName  FROM #PayrollResults AS PR  JOIN Payroll_Employee AS E WITH (NOLOCK) ON PR.EmployeeID = E.Employee_ID  JOIN Payroll_SalaryHead AS SH WITH (NOLOCK) ON PR.SalaryHeadID = SH.SalaryHead_ID   JOIN Payroll_CyclePeriodDetails AS CPD WITH (NOLOCK) ON @PeriodId = CPD.Period_ID  JOIN Const_TransactionType AS TT WITH (NOLOCK) ON PR.TransactionTypeID = TT.TransactionType_ID  OUTER APPLY (       SELECT TOP 1 JournalEntryOnly      FROM Payroll_GLHistory AS GLH_Inner WITH (NOLOCK)      WHERE GLH_Inner.Enabled = 1 AND GLH_Inner.SalaryHeadID = PR.SalaryHeadID AND CPD.PeriodStartDate BETWEEN GLH_Inner.StartDate AND GLH_Inner.EndDate      ORDER BY GLH_Inner.GLHistory_ID DESC  ) AS GLH  LEFT JOIN Cons_Vendor AS V WITH (NOLOCK) ON PR.VendorID = V.Vendor_ID  LEFT JOIN Cons_VendorBankingDetails AS VBD WITH (NOLOCK) ON PR.VendorID = VBD.VendorID  LEFT JOIN Const_CashbookTransactionType AS CTT WITH (NOLOCK) ON VBD.TransactionTypeID = CTT.TransactionType_ID  OUTER APPLY (      SELECT TOP 1 I.Invoice_ID, I.VendorInvoiceNumberCustom       FROM SCM_Invoice AS I       JOIN SCM_InvoiceDetail AS ID ON ID.InvoiceID = I.Invoice_ID      WHERE @PeriodID = I.PayrollPeriodID AND PR.VendorID = I.VendorCreditorID   ) AS Inv  OUTER APPLY (    select sum(Amount) * (CommissionPercentage/100) CommissionAmount from Payroll_PayrollResults where PeriodID = @PeriodId and Isnull(VendorID,0) = @VendorId and SalaryHeadID = @SalaryHeadId  ) AS InvoiceDetails    END

GO

-- ============================================
-- SP: Payroll_PayrollRunSummary
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-11-26  -- Description: Used as a dataset for Payroll Run Schedule report (rptEarningDeduction.rdl)  --              Returns Summary of Payroll Trial or Final Run results for @PeriodId grouped by Salary Head and Vendor  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_PayrollRunSummary]      @TransactionTypeId INT,      @SalaryHeadId INT,      @PeriodId INT,      @VendorId INT,      @IsTrialRun BIT  AS  BEGIN    DROP TABLE IF EXISTS #PayrollResult    CREATE TABLE #PayrollResult  (      Employee_ID INT,      EmpCode NVARCHAR(50),      Initials NVARCHAR(50),      Surname NVARCHAR(50),      SalaryHeadID INT,      SalaryHeadName NVARCHAR(50),      VendorID INT,      VendorName NVARCHAR(200),      Amount DECIMAL(18,2),      ReferenceNo NVARCHAR(500),      PaymentMethod NVARCHAR(200),      VendorInvoiceNumberCustom NVARCHAR(50),      HasCommision BIT,      CommissionAmount DECIMAL(18,2),      CommissionPercentage DECIMAL(18,2),      TransactionTypeID INT,      TransactionTypeName NVARCHAR(200)  )    INSERT INTO #PayrollResult  EXECUTE Payroll_PayrollRunDetails @TransactionTypeId, @SalaryHeadId, @PeriodId, @VendorId, @IsTrialRun    SELECT       PR.SalaryHeadID,      PR.SalaryHeadName,      PR.VendorName,      PR.PaymentMethod,      PR.TransactionTypeID,      PR.TransactionTypeName,      IRP.IRP5Code,      SUM(PR.Amount) AS Total  FROM #PayrollResult AS PR WITH (NOLOCK)  JOIN Payroll_SalaryHead AS SH WITH (NOLOCK) ON PR.SalaryHeadID = SH.SalaryHead_ID  JOIN Payroll_IRP5Code AS IRP WITH (NOLOCK) ON SH.IRP5CodeId = IRP.IRP5Code_ID  GROUP BY PR.SalaryHeadID, PR.SalaryHeadName, PR.PaymentMethod, IRP.IRP5Code, PR.VendorID, PR.VendorName, PR.TransactionTypeID, PR.TransactionTypeName    END

GO

-- ============================================
-- SP: Payroll_PayrollTotalsEmpAndMunicipal_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,Lungisani khumalo>  -- Create date: <Create Date,17/06/2017>  -- Description: <Description,>  -- 11/04/2018 Himil Modi -- Add parameter for the CycleID to get the cycle name from sp.  -- 27/05/2018 Richa M -- Fix Period End Date  -- ============================================  create procedure [dbo].[Payroll_PayrollTotalsEmpAndMunicipal_sp]    @EmployeeID INT,    @PeriodID INT,   @CycleID INT  AS  BEGIN      SELECT distinct Top 1 [PM].MunicipalityName,(SELECT KeyValue FROM AAAA_ConfigSettings WHERE (KeyName = 'DocViewerRootFolderPath')) + '/Municipality/' + [PM].MunicipalityImagePath AS [IMAGE],        (SELECT CycleDesc FROM dbo.Const_Cycle WHERE Cycle_ID = @CycleID ) AS CycleName,      ISNULL([PM].PhyAddress1 + ' ','')+ ISNULL([PM].PhyAddress2 + ' ','')+ ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID = [PM].PhySuburb),'') AS COMPANYADDRESS,        [PM].RegistrationNo, [CPD].PeriodEndDate AS PAYPERIOD,      case when @EmployeeID > 0 then isnull(EmpCode,'') else '' end as [EmpCode], case when @EmployeeID > 0 then right('0000'+convert(varchar(4), [PE].Employee_ID), 4) else '' end as [EmployeeID] ,      case when @EmployeeID > 0 then ISNULL([PE].FirstName + ' ','') + ISNULL([PE].SecondName + ' ','') + ISNULL([PE].Surname,'') else '' end as [EmployeeName],      case when @EmployeeID > 0 then dbo.BufferString_fxn(CONVERT(VARCHAR, ( [PE].Employee_ID )), 8,'0') else '' end as [EmpNo]     FROM [Payroll_Employee] [PE] with(nolock)     join [Payroll_Municipality] [PM] with(nolock) on [PM].Municipality_ID = [PE].MunicipalityID     join [Payroll_TrialResults] [TR] with(nolock) on [PE].Employee_ID = [TR].EmployeeID and [TR].PERIODID = @PeriodID and ([PE].Employee_ID = @EmployeeID OR @EmployeeID = 0 )     join [Payroll_CyclePeriodDetails] [CPD] with(nolock) on [CPD].PERIOD_ID = [TR].PERIODID AND  [CPD].PERIOD_ID = @PeriodID    WHERE         ([PE].Employee_ID = @EmployeeID OR @EmployeeID = 0 )    END    

GO

-- ============================================
-- SP: Payroll_PayrollTotalsRpt_sp
-- Schema: dbo
-- ============================================
   -- =============================================  -- Author:  <Author,,Lungisani>  -- Create date: <Create Date, 10/11/2017,>  -- Description: <Description,Calculates Payroll Totals for each salary head>  -- Modified: Richa M - Changed report to return correct totals 2017/12/07   -- Modified: Ivan M - Changed report to return correct overtimes and kilometers 14 Apr 2021  -- Exec Payroll_PayrollTotalsRpt_sp 1,17,0,'2018',0  -- =============================================    CREATE procedure [dbo].[Payroll_PayrollTotalsRpt_sp]     @Month INT,   @CycleId INT,   @EmployeeId INT,   @TaxYear VARCHAR(10),   @DepartmentId INT    AS   BEGIN     DECLARE @EndDate DATE      ,@PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS INT) - 1         DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear    DECLARE @PeriodId int = @Month  SELECT @EndDate = (SELECT periodEnddate FROM Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)    DROP TABLE IF EXISTS #Input  CREATE TABLE #Input(  EmployeeID INT  , Flag INT  , Amount FLOAT  )    -- Add overtimes to table  INSERT INTO #Input (EmployeeID, Flag, Amount)  SELECT OT.EmployeeID, OT.SalaryHeadID, SUM(OverTimeHour)         FROM dbo.Payroll_EmployeeOverTime AS OT   INNER JOIN dbo.Payroll_Employee Pay_EMp    ON OT.EmployeeID = Pay_EMp.Employee_ID   INNER JOIN dbo.Payroll_Position AS PP    ON Pay_EMp.PositionID = PP.Position_ID   WHERE (Pay_EMp.Employee_ID = @EmployeeId OR @EmployeeId = 0)    AND (PP.DepartmentID = @DepartmentId OR @DepartmentId = 0)   AND OT.ProcessedOnPeriodId = @PeriodId  GROUP BY OT.EmployeeID, OT.SalaryHeadID    -- Add kilometers to table  INSERT INTO #Input (EmployeeID,Flag, Amount)  SELECT P_EC.EmployeeID, C_C.SalaryHeadId, SUM(P_EC.Kilometre )  FROM Payroll_EmployeeClaims AS P_EC  INNER JOIN dbo.Payroll_Employee Pay_EMp    ON P_EC.EmployeeID = Pay_EMp.Employee_ID   INNER JOIN dbo.Payroll_Position AS PP    ON Pay_EMp.PositionID = PP.Position_ID   JOIN Const_Claims AS C_C   ON P_EC.ClaimID = C_C.Claim_ID  WHERE (Pay_EMp.Employee_ID = @EmployeeId OR @EmployeeId = 0)    AND (PP.DepartmentID = @DepartmentId OR @DepartmentId = 0)   AND P_EC.ProcessedOnPeriodId = @PeriodId    AND C_C.Claim_Type = 'Travel'  GROUP BY P_EC.EmployeeID, C_C.SalaryHeadId      SELECT pt.Period   , @EndDate AS PeriodEndDate   , ProcessingMonth   , pt.TransactionTypeID   , ctt.TransactionTypeDesc   , pt.SalaryHeadId   , SalaryHeadName   , pt.Amount   , CASE WHEN pt.TransactionTypeID = 1 THEN pt.Amount END AS Earnings   , CASE WHEN pt.TransactionTypeID = 2 THEN pt.Amount END AS Deductions   , CASE WHEN pt.TransactionTypeID = 3 THEN pt.Amount END AS CompanyContributions     , IIF(#Input.Amount IS NOT NULL,#Input.Amount,0) AS Input  FROM (SELECT  'Amount' As Period,    *   FROM Payroll_PayrollResults ppr   WHERE periodId = @PeriodId AND TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeId , 0)   OR ISNULL(@EmployeeId, 0) = 0)   ) pt  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd   ON pt.PeriodId = pcpd.Period_ID    AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt   ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh   ON psh.Salaryhead_ID = pt.SalaryHeadId  LEFT JOIN #Input   ON pt.EmployeeID = #Input.EmployeeID     AND psh.SalaryHead_ID = Flag  WHERE (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)        DROP TABLE #Input      END

GO

-- ============================================
-- SP: Payroll_PayrollTotalsRptTrial_sp
-- Schema: dbo
-- ============================================
   -- =============================================        -- Author: MarioT 2015/05/28 Same as Payroll_PayrollTotalsRpt_sp but use trial run details        -- Calls : Payroll_PayrollTotalsRptTrial_sp 5, '2014', 0, 0, 0        -- TP20344 2015/12/03 : Suri Kandukuri : Modified the query for getting amount and year to date values correctly.        -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.        -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions        -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA   -- Update date : 29/03/2019 - Added PeriodID as Parameter - FERDI BOTHA   -- Modified: Ivan M - Changed report to return correct overtimes and kilometers 14 Apr 2021  --EXEC Payroll_PayrollTotalsRptTrial_sp 2018,0,0,17  -- =============================================          CREATE procedure [dbo].[Payroll_PayrollTotalsRptTrial_sp]           @TaxYear VARCHAR(50) = ''         ,@EmployeeId INT         ,@DepartmentId INT         ,@CycleId INT = 0   ,@PeriodId INT = 0  AS        BEGIN                       DECLARE @EndDate DATE      ,@PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1         DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear    SELECT @EndDate = (SELECT periodEnddate FROM Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)    DROP TABLE IF EXISTS #Input  CREATE TABLE #Input(  EmployeeID INT  , Flag INT  , Amount FLOAT  )    -- Add overtimes to table  INSERT INTO #Input (EmployeeID, Flag, Amount)  SELECT OT.EmployeeID, OT.SalaryHeadID, SUM(OverTimeHour)         FROM dbo.Payroll_EmployeeOverTime AS OT   INNER JOIN dbo.Payroll_Employee Pay_EMp    ON OT.EmployeeID = Pay_EMp.Employee_ID   INNER JOIN dbo.Payroll_Position AS PP    ON Pay_EMp.PositionID = PP.Position_ID   WHERE (Pay_EMp.Employee_ID = @EmployeeId OR @EmployeeId = 0)    AND (PP.DepartmentID = @DepartmentId OR @DepartmentId = 0)   AND OT.PeriodID = @PeriodId OR OT.CapturedDuringPeriodId = @PeriodId  GROUP BY OT.EmployeeID, OT.SalaryHeadID    -- Add kilometers to table  INSERT INTO #Input (EmployeeID,Flag, Amount)  SELECT P_EC.EmployeeID, C_C.SalaryHeadId, SUM(P_EC.Kilometre )  FROM Payroll_EmployeeClaims AS P_EC  INNER JOIN dbo.Payroll_Employee Pay_EMp    ON P_EC.EmployeeID = Pay_EMp.Employee_ID   INNER JOIN dbo.Payroll_Position AS PP    ON Pay_EMp.PositionID = PP.Position_ID   JOIN Const_Claims AS C_C   ON P_EC.ClaimID = C_C.Claim_ID  WHERE (Pay_EMp.Employee_ID = @EmployeeId OR @EmployeeId = 0)    AND (PP.DepartmentID = @DepartmentId OR @DepartmentId = 0)   AND P_EC.PeriodID = @PeriodId    AND C_C.Claim_Type = 'Travel'  GROUP BY P_EC.EmployeeID, C_C.SalaryHeadId      SELECT pt.Period   , @EndDate AS PeriodEndDate   , ProcessingMonth   , pt.TransactionTypeID   , ctt.TransactionTypeDesc   , pt.SalaryHeadId   , SalaryHeadName   , pt.Amount   , CASE WHEN pt.TransactionTypeID = 1 THEN pt.Amount END AS Earnings   , CASE WHEN pt.TransactionTypeID = 2 THEN pt.Amount END AS Deductions   , CASE WHEN pt.TransactionTypeID = 3 THEN pt.Amount END AS CompanyContributions     , IIF(#Input.Amount IS NOT NULL,#Input.Amount,0) AS Input  FROM (SELECT  'Amount' As Period,    *   FROM Payroll_TrialResults ppr   WHERE periodId = @PeriodId AND TaxSavePurpose = 0   AND (ppr.EmployeeID = ISNULL(@EmployeeId , 0)   OR ISNULL(@EmployeeId, 0) = 0 )    ) pt  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd   ON pt.PeriodId = pcpd.Period_ID    AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt   ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh   ON psh.Salaryhead_ID = pt.SalaryHeadId  LEFT JOIN #Input   ON pt.EmployeeID = #Input.EmployeeID     AND psh.SalaryHead_ID = Flag  WHERE (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)    ORDER BY psh.SalaryHead_ID    DROP TABLE #Input     END

GO

-- ============================================
-- SP: Payroll_PayrollTrialVariance_rpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Richa Mills  -- Create date: 13 October 2017  -- Description: Payroll Trial Variance Report  -- exec Payroll_PayrollTrialVariance_rpt 17,0,2018,0,0  -- NB! For this report the taxyear will be passed as 2018 (not 2017/2018)  -- The month will be the Month in the tax year - eg March = 1  -- 2023/11/23 Kiran WI95515 Fixed Department display issue  -- 2024/01/15 Kiran WI95515 Fixed error it is clear that fields mismatch in select list of union  -- =============================================  CREATE procedure [dbo].[Payroll_PayrollTrialVariance_rpt]  @CycleId INT,   @TransactionType INT,   @TaxYear VARCHAR(10),   @SalaryHeadId int,   @DepartmentId int,   @PeriodId int  AS   BEGIN    DECLARE @Month int = (select PeriodInTaxYear from Payroll_CyclePeriodDetails where Period_Id = @PeriodId)  DECLARE @CycleMode int = (select CycleModeId from Payroll_CyclePeriodDetails where Period_Id = @PeriodId)      DECLARE @PreviousMonth INT      ,@EndDate DATE       ,@PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1     ,@PreviousPreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 2          DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear      DECLARE @PreviousPeriodTaxYear VARCHAR(9) = @CurrentPeriodTaxYear         SET @PreviousMonth = @Month - 1     IF (@Month = 1)    BEGIN      SET @PreviousMonth = 12    SET @PreviousPeriodTaxYear =  @PreviousPreviousTaxYear + '/' + @PreviousTaxYear    END       DECLARE @PreviousPeriodID int = (Select Period_ID from Payroll_CyclePeriodDetails where PeriodInTaxYear = @PreviousMonth AND TaxYear = @PreviousPeriodTaxYear AND CycleID = @CycleId AND CycleModeId = @CycleMode)     Select @EndDate = (Select periodEnddate from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)    SELECT @EndDate AS CurrentPeriodEndDate   ,CASE when pt.PeriodID = @PeriodId THEN 'This Period' ELSE 'Previous Period' END As DisplayPeriod     ,ProcessingMonth     ,pt.TransactionTypeID     ,ctt.TransactionTypeDesc     ,pt.SalaryHeadId     ,SalaryHeadName     ,pt.Amount AS Amount     ,CASE WHEN Period = @PeriodId THEN pt.Amount ELSE pt.Amount * -1 END AS VarianceTotal,      pemp.FirstName + ' ' + pemp.Surname as FullName ,     pemp.EmpCode     ,pt.DepartmentDesc  FROM (SELECT  @PeriodId AS Period,   PeriodId,ppr.TransactionTypeID,ppr.SalaryHeadID,Amount,ppr.DepartmentID,EmployeeId,ppr.DepartmentDesc   FROM Payroll_TrialResults ppr   WHERE periodId = @PeriodId   AND TaxSavePurpose = 0   AND (TransactionTypeID = ISNULL(@TransactionType, 0)   OR ISNULL(@TransactionType, 0) = 0)   UNION ALL   SELECT @PreviousPeriodId AS Period,   PeriodId,ppr.TransactionTypeID,ppr.SalaryHeadID,Amount,ppr.DepartmentID,ppr.EmployeeID,ppr.DepartmentDesc   FROM Payroll_PayrollResults ppr   WHERE periodId = @PreviousPeriodId   AND TaxSavePurpose = 0   AND (TransactionTypeID = ISNULL(@TransactionType, 0)   OR ISNULL(@TransactionType, 0) = 0)   ) pt  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd   ON pt.PeriodId = pcpd.Period_ID    AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt   ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh   ON psh.Salaryhead_ID = pt.SalaryHeadId   inner join Payroll_Employee pemp on pt.EmployeeID = pemp.Employee_ID  WHERE (pt.SalaryHeadId = ISNULL(@SalaryHeadId,0) OR ISNULL(@SalaryHeadId,0) = 0)  AND (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)             END

GO

-- ============================================
-- SP: Payroll_PayrollVariance_rpt
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Richa Mills  -- Create date: 13 October 2017  -- Description: Payroll Variance Report  -- exec Payroll_PayrollVariance_rpt 301,17,0,2018,0,0  -- NB! For this report the taxyear will be passed as 2018 (not 2017/2018)  -- The month will be the Month in the tax year - eg March = 1  -- 2018/03/02 - Someone changed the front end to now pass a PeriodId, not the month  -- 2023/11/23 Kiran WI95515 Fixed Department display issue   -- 2024/01/15 Kiran WI95515 Fixed error it is clear that fields mismatch in select list of union  -- =============================================    CREATE procedure [dbo].[Payroll_PayrollVariance_rpt]    @Month INT, --Payroll PeriodId   @CycleId INT,   @TransactionType INT,   @TaxYear VARCHAR(10),   @SalaryHeadId INT,   @DepartmentId INT  AS  BEGIN    DECLARE @PeriodId int = @Month  DECLARE @ActualMonth int  DECLARE @CycleMode INT    SELECT  @ActualMonth = PeriodInTaxYear,  @CycleMode = CycleModeID  FROM Payroll_CyclePeriodDetails where Period_Id = @PeriodId    DECLARE @PreviousMonth INT    ,@EndDate DATE    ,@PreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 1    ,@PreviousPreviousTaxYear VARCHAR(10) = CAST(@TaxYear AS int) - 2    DECLARE @CurrentPeriodTaxYear VARCHAR(9) = @PreviousTaxYear + '/' + @TaxYear  DECLARE @PreviousPeriodTaxYear VARCHAR(9) = @CurrentPeriodTaxYear     SET @PreviousMonth = @ActualMonth - 1    IF (@ActualMonth = 1)  BEGIN     SET @PreviousMonth = 12   SET @PreviousPeriodTaxYear =  @PreviousPreviousTaxYear + '/' + @PreviousTaxYear  END      DECLARE @PreviousPeriodID int = (Select Period_ID from Payroll_CyclePeriodDetails where PeriodInTaxYear = @PreviousMonth AND TaxYear = @PreviousPeriodTaxYear AND CycleID = @CycleId AND CycleModeID = @CycleMode)    SELECT @EndDate = (Select periodEnddate from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)    SELECT @EndDate AS CurrentPeriodEndDate     ,CASE when pt.PeriodID = @PeriodId THEN 'This Period' ELSE 'Previous Period' END As DisplayPeriod     ,ProcessingMonth     ,pt.TransactionTypeID     ,ctt.TransactionTypeDesc     ,pt.SalaryHeadId     ,SalaryHeadName     ,pt.Amount AS Amount     ,CASE WHEN Period = @PeriodId THEN pt.Amount ELSE pt.Amount * -1 END AS VarianceTotal,     pemp.FirstName + ' ' + pemp.Surname as FullName ,     pemp.EmpCode     ,pt.DepartmentDesc  FROM (SELECT  @PeriodId AS Period,  PeriodId,ppr.TransactionTypeID,ppr.SalaryHeadID,Amount,ppr.DepartmentID,EmployeeId,ppr.DepartmentDesc  FROM Payroll_PayrollResults ppr  WHERE periodId = @PeriodId  AND TaxSavePurpose = 0  AND (TransactionTypeID = ISNULL(@TransactionType, 0)  OR ISNULL(@TransactionType, 0) = 0)  UNION ALL  SELECT @PreviousPeriodId AS Period,  PeriodId,ppr.TransactionTypeID,ppr.SalaryHeadID,Amount,ppr.DepartmentID,ppr.EmployeeID,ppr.DepartmentDesc  FROM Payroll_PayrollResults ppr  WHERE periodId = @PreviousPeriodId  AND TaxSavePurpose = 0  AND (TransactionTypeID = ISNULL(@TransactionType, 0)  OR ISNULL(@TransactionType, 0) = 0)  ) pt  LEFT OUTER JOIN Payroll_CyclePeriodDetails pcpd  ON pt.PeriodId = pcpd.Period_ID  AND pcpd.CycleID = @CycleId  LEFT OUTER JOIN Const_TransactionType ctt  ON ctt.TransactionType_Id = pt.TransactionTypeID  LEFT OUTER JOIN Payroll_SalaryHead psh  ON psh.Salaryhead_ID = pt.SalaryHeadId    inner join Payroll_Employee pemp on pt.EmployeeID = pemp.Employee_ID    WHERE (pt.SalaryHeadId = ISNULL(@SalaryHeadId,0) OR ISNULL(@SalaryHeadId,0) = 0)  AND (pt.DepartmentId = ISNULL(@DepartmentId,0) OR ISNULL(@DepartmentId,0) = 0)    END

GO

