-- SP: Payroll_PayrollVarianceRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL   -- Create date: 08 JULY 2013  -- Description: GET EMPLOYEE PAYLIST  -- CALLS : [Payroll_PayrollVarianceRpt_sp] 10,'2016/2017', 0, 0, 0, 4  -- 2015-06-25 James Roodt: Reordered text to make it more readable  -- 2015-06-26 TP20843 James Roodt: Fixed year value fo LastDayInMonth  -- 2015-10-05 TP25371 Suri Kandukuri : Fixed Variance  -- 2016-01-05 TP29885 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  CREATE procedure [dbo].[Payroll_PayrollVarianceRpt_sp]      @Month INT ,      @FinancialYear NVARCHAR(50) ,      @TransactionTypeId INT ,      @EmployeeId INT ,      @DepartmentId INT ,      @CycleId INT  AS     BEGIN          DECLARE @PREVIOUSMONTH INT ,    @PeriodEndDate Date,          @PreviousFinYear VARCHAR(50)                SET @PREVIOUSMONTH = @Month - 1          IF ( @Month = 1 )               BEGIN                  SET @PREVIOUSMONTH = 12               END                       SET @PreviousFinYear = @FinancialYear          IF ( SELECT KeyValue               FROM   dbo.AAAA_ConfigSettings               WHERE  KeyName = 'TaxFinYearEndMonth'             ) = ( @Month - 1 )               BEGIN                  DECLARE @Year INT                  SELECT TOP 1                          @Year = Data                  FROM    dbo.Split(@FinancialYear, '/')                      SET @PreviousFinYear = CONVERT(VARCHAR(50), ( @Year - 1 )) + '/' + CONVERT(VARCHAR(50), ( @Year ))              END                            DECLARE @Period TABLE ( Period_Id INT, PeriodEndDate Date )          INSERT  INTO @Period                  SELECT  Period_ID, cast(PeriodEndDate AS DATE)                  FROM    dbo.Payroll_CyclePeriodDetails                  WHERE   DATEPART(MONTH, PeriodStartDate) = @Month                          AND TaxYear = @FinancialYear                          AND ( CycleID = @CycleId                                OR @CycleId = 0                              )                          AND Processed = 1    Select @PeriodEndDate=Max(PeriodEndDate) FROM @Period             DECLARE @PPeriod TABLE ( Period_Id INT )          INSERT  INTO @PPeriod                  SELECT  Period_ID                  FROM    dbo.Payroll_CyclePeriodDetails                  WHERE   DATEPART(MONTH, PeriodStartDate) = @PREVIOUSMONTH                          AND TaxYear = @PreviousFinYear                          AND ( CycleID = @CycleId                                OR @CycleId = 0                              )                          AND Processed = 1                   SELECT  CONST_TRANS.TransactionType_ID,        CONST_TRANS.TransactionTypeDesc,     PAY_SAL.SalaryHeadTitle AS SalarHead,                                PAY_SAL.SalaryHead_ID,                 MIN(ISNULL(PAY_EMP.FirstName, '') + ' ' + ISNULL(PAY_EMP.Surname, '')) AS EMPLOYEE,                 PAY_EMP.Employee_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo, ISNULL(PAY_EMP.EmpCode, '') AS EmpCode,                min(PAY_EMP_PAY.[Month]) AS [Month], isnull(SUM(PAY_EMP_PAY.Amount),0) AS Amount       ,isnull((Previous.Amount),0) AS Previous       ,isnull(SUM(PAY_EMP_PAY.Amount),0) - isnull((previous.amount),0) as Variance ,            ( SELECT   dbo.GetLastDateOfMonth(DATEPART(yyyy,@PeriodEndDate),@Month)                                ) AS LastDayinMonth,       ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)                                                     ) AS EmployeeId,         ( ISNULL(( SELECT    SUM(PAY_EMP_PAY.Amount)                FROM      Payroll_EmployeePayslip PAY_EMP_PAY                          INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                          INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                          INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                WHERE     PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                          AND TaxSavePurpose = 0                          AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                        FROM      @Period )                          AND CONST_TRANS.TransactionType_ID = 1              ), 0) - ISNULL(( SELECT SUM(PAY_EMP_PAY.Amount)                               FROM   Payroll_EmployeePayslip PAY_EMP_PAY                                      INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID           INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                      INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                 WHERE  PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                                        AND TaxSavePurpose = 0                                        AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @Period )                                        AND CONST_TRANS.TransactionType_ID = 2                  ), 0) ) AS CurNettpay,     ( ISNULL(( SELECT SUM(PAY_EMP_PAY.Amount)                                    FROM   Payroll_EmployeePayslip PAY_EMP_PAY                                           INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                           INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                           INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                    WHERE  PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                                           AND TaxSavePurpose = 0                                           AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                         FROM      @PPeriod )                                           AND CONST_TRANS.TransactionType_ID = 1                                  ), 0) - ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                    FROM    Payroll_EmployeePayslip PAY_EMP_PAY                            INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                              INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                      WHERE   PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                                   AND TaxSavePurpose = 0                                   AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                 FROM      @PPeriod )                                   AND CONST_TRANS.TransactionType_ID = 2                         ), 0) ) AS PreNettpay,      ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                          FROM    Payroll_EmployeePayslip PAY_EMP_PAY                               INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                               INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                               INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                               INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                       WHERE   PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                           AND TaxSavePurpose = 0                           AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                         FROM      @Period )                           AND CONST_TRANS.TransactionType_ID = 1                 ), 0) + ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                                  FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                           INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                          INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                     INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                            WHERE    PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                    AND TaxSavePurpose = 0                     AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                   FROM      @Period )                                     AND CONST_TRANS.TransactionType_ID = 3                          ), 0) ) AS CurCost,      ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                               FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                       INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                       INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                       INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                       INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                               WHERE   PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                                       AND TaxSavePurpose = 0                                       AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @PPeriod )             AND CONST_TRANS.TransactionType_ID = 1             ), 0) + ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                              FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                       INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                       INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                       INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                       INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                              WHERE    PAY_EMP_PAY.EmployeeID = PAY_EMP.Employee_ID                                       AND TaxSavePurpose = 0                                       AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                     FROM      @PPeriod )                                       AND CONST_TRANS.TransactionType_ID = 3                            ), 0) ) AS PreCost,      ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                           FROM    Payroll_EmployeePayslip PAY_EMP_PAY                            INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                            INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                            INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                            INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                            INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                            INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                    WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                              OR @EmployeeId = 0                            )                            AND TaxSavePurpose = 0                            AND ( PP.DepartmentID = @DepartmentId                                  OR @DepartmentId = 0                                )                            AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                           FROM      @Period )                                                           AND CONST_TRANS.TransactionType_ID = 1                                                 ), 0) - ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                                                FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                                         INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                                         INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                                         INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                                         INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                                         INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                                         INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                                WHERE    ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                                           OR @EmployeeId = 0                                                         )                                                         AND TaxSavePurpose = 0                                                         AND ( PP.DepartmentID = @DepartmentId                                                               OR @DepartmentId = 0                                                             )                                                         AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                                       FROM      @Period )                                                         AND CONST_TRANS.TransactionType_ID = 2                                              ), 0) ) AS CurNettPayTotal,     ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                         FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                 INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                 INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                 INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                 INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                 INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                 INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                         WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                   OR @EmployeeId = 0                                 )                                 AND TaxSavePurpose = 0                                 AND ( PP.DepartmentID = @DepartmentId                                       OR @DepartmentId = 0                                     )                                 AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                               FROM      @PPeriod )                                 AND CONST_TRANS.TransactionType_ID = 1                       ), 0) - ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                                        FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                                 INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                                 INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                                INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                                 INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                                 INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                                 INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                        WHERE    ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                                   OR @EmployeeId = 0                                                 )                                                 AND TaxSavePurpose = 0                                AND ( PP.DepartmentID = @DepartmentId                                      OR @DepartmentId = 0                                    )                                AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                              FROM      @PPeriod )                                AND CONST_TRANS.TransactionType_ID = 2                     ), 0) ) AS PreNettPayTotal,       ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                           FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                   INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                   INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                   INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                   INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                   INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                   INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                           WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                     OR @EmployeeId = 0                                   )                                   AND TaxSavePurpose = 0                                  AND ( PP.DepartmentID = @DepartmentId                                        OR @DepartmentId = 0   )                                          AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                        FROM      @Period )                                          AND CONST_TRANS.TransactionType_ID = 1                                ), 0) + ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                                                 FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                                          INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                                          INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                                         INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                                          INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                                          INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                                 WHERE    ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                                            OR @EmployeeId = 0                                                          )                                                          AND TaxSavePurpose = 0                                                          AND ( PP.DepartmentID = @DepartmentId                                                                OR @DepartmentId = 0                                                              )                                                          AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                                        FROM      @Period )                                                          AND CONST_TRANS.TransactionType_ID = 3                                               ), 0) ) AS CurCostTotal,      ( ISNULL(( SELECT SUM(PAY_EMP_PAY.Amount)                 FROM   Payroll_EmployeePayslip PAY_EMP_PAY                        INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                        INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                        INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                        INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                 WHERE  ( PAY_EMP_PAY.EmployeeID = @EmployeeId                          OR @EmployeeId = 0                        )                        AND TaxSavePurpose = 0                        AND ( PP.DepartmentID = @DepartmentId                              OR @DepartmentId = 0                            )                        AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                      FROM      @PPeriod )                        AND CONST_TRANS.TransactionType_ID = 1               ), 0) + ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                                FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                        INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                        INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                        INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                        INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                          OR @EmployeeId = 0                                        )                                        AND TaxSavePurpose = 0                                        AND ( PP.DepartmentID = @DepartmentId                                              OR @DepartmentId = 0                                            )                                        AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @PPeriod )                                        AND CONST_TRANS.TransactionType_ID = 3                              ), 0) ) AS PreCostTotal          FROM    Payroll_Employee PAY_EMP                  INNER JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP.Employee_ID = PAY_EMP_PAY.EmployeeID                  INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                  INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                  INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                  INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID 