  -- =============================================  -- Author:  MarioT 2015/05/28 Same as Payroll_PayrollVarianceRpt_sp but uses Trial Run Details  -- EXEC Payroll_PayrollVarianceRptTrial_sp 0,'0',0,0,0,0  -- 2015-06-25 TP20843 James Roodt: Changed report to use trial run data  -- 2015-06-26 TP20843 James Roodt: Fixed year value fo LastDayInMonth  -- 2015-07-03 TP20843 James Roodt: Added employee active filter  -- 2015-10-05 TP25371 Suri Kandukuri : Fixed Variance  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-08-09 TP:41842 Varun,Lungisani,phuti:Previous Amount gives zeros was fixed.  -- 016-11-04 TP46156 Varun:Organogram: Job Profile and Positions   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_PayrollVarianceRptTrial_sp]        @Month INT       ,@FinancialYear NVARCHAR(50)       ,@TransactionTypeId INT       ,@EmployeeId INT       ,@DepartmentId INT       ,@CycleId INT   AS     BEGIN     --First we need to establish the @Month Value     DECLARE @PeriodEndDate Datetime   SELECT @Month=MONTH(PeriodStartDate), @CycleId=cpd.CycleID, @FinancialYear=cpd.TaxYear, @PeriodEndDate=PeriodEndDate   FROM Payroll_TrailRun_History trh   LEFT JOIN Payroll_CyclePeriodDetails cpd ON cpd.Period_ID=trh.PeriodID   WHERE 1=1   AND trh.Status='InProcess' AND trh.Porcessed=0 AND CycleModeID = 1              DECLARE @PREVIOUSMONTH INT ,              @PreviousFinYear VARCHAR(50)     --DECLARE @PreviousPeriodID INT          SET @PREVIOUSMONTH = @Month - 1          IF ( @Month = 1 )               BEGIN                  SET @PREVIOUSMONTH = 12               END          PRINT @PREVIOUSMONTH             SET @PreviousFinYear = @FinancialYear          IF ( SELECT KeyValue               FROM   dbo.AAAA_ConfigSettings               WHERE  KeyName = 'TaxFinYearEndMonth'             ) = ( @Month - 1 )               BEGIN                  DECLARE @Year INT                  SELECT TOP 1                          @Year = Data                  FROM    dbo.Split(@FinancialYear, '/')                      SET @PreviousFinYear = CONVERT(VARCHAR(50), ( @Year - 1 )) + '/' + CONVERT(VARCHAR(50), ( @Year ))              END              PRINT @PreviousFinYear             DECLARE @Period TABLE ( Period_Id INT )          INSERT  INTO @Period                  SELECT  Period_ID                  FROM    dbo.Payroll_CyclePeriodDetails                  WHERE   DATEPART(MONTH, PeriodStartDate) = @Month                          AND TaxYear = @FinancialYear                          AND ( CycleID = @CycleId                                OR @CycleId = 0                              )                       --   AND Processed = 1                 DECLARE @PPeriod TABLE ( Period_Id INT )          INSERT  INTO @PPeriod                  SELECT  Period_ID                  FROM    dbo.Payroll_CyclePeriodDetails                  WHERE   DATEPART(MONTH, PeriodStartDate) = @PREVIOUSMONTH                          AND TaxYear = @PreviousFinYear                          AND ( CycleID = @CycleId                                OR @CycleId = 0                              )                          AND Processed = 1            --SELECT @PreviousPeriodID=max(Period_ID) FROM dbo.Payroll_CyclePeriodDetails WHERE DATEPART(MONTH, PeriodStartDate) = @PREVIOUSMONTH AND FinancialYear = @PreviousFinYear AND (CycleID = @CycleId OR @CycleId = 0)             SELECT      CONST_TRANS.TransactionType_ID,     CONST_TRANS.TransactionTypeDesc,     PAY_SAL.SalaryHeadTitle AS SalarHead,     PAY_SAL.SalaryHead_ID,     MIN(ISNULL(PAY_EMP.FirstName, '') + ' ' + ISNULL(PAY_EMP.Surname, '')) AS EMPLOYEE,     PAY_EMP.Employee_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo,     MIN(PAY_EMP_PAY.[Month]+1) AS [Month],     isnull(SUM(etp.Amount),0) AS Amount    ,isnull((Previous.Amount),0) AS Previous    ,isnull(SUM(etp.Amount),0) - isnull((previous.amount),0) as Variance ,       --( SELECT   dbo.GetLastDateOfMonth(SUBSTRING(@FinancialYear, CHARINDEX('/', @FinancialYear) + LEN('/'), LEN(@FinancialYear)), @Month)     ( SELECT   dbo.GetLastDateOfMonth(YEAR(@PeriodEndDate), @Month)                                   ) AS LastDayinMonth,        ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)                                ) AS EmployeeId,           ( ISNULL(( SELECT    SUM(etp.Amount)                FROM      Payroll_EmployeeTrialPayslip  etp                          INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                          INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                          INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                WHERE     etp.EmployeeID = PAY_EMP.Employee_ID                          AND TaxSavePurpose = 0                          AND etp.PeriodID IN ( SELECT    Period_Id                                                        FROM      @Period )                          AND CONST_TRANS.TransactionType_ID = 1              ), 0) - ISNULL(( SELECT SUM(etp.Amount)                               FROM   Payroll_EmployeeTrialPayslip etp                                      INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID           INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                      INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                 WHERE  etp.EmployeeID = PA