                            AND CONST_TRANS.TransactionType_ID = 2                                              ), 0) ) AS CurNettPayTotal,     ( ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                         FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                 INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                 INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                 INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                 INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                 INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                 INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                         WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                   OR @EmployeeId = 0                                 )                                 AND TaxSavePurpose = 0                                 AND ( PP.DepartmentID = @DepartmentId                                       OR @DepartmentId = 0                                     )                                 AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                               FROM      @PPeriod )                                 AND CONST_TRANS.TransactionType_ID = 1                       ), 0) - ISNULL(( SELECT   SUM(PAY_EMP_PAY.Amount)                                        FROM     Payroll_EmployeePayslip PAY_EMP_PAY                                                 INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                                 INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                                 INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                                 INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                                 INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                                 INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                        WHERE    ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                                   OR @EmployeeId = 0                                                 )                                                 AND TaxSavePurpose = 0                                AND ( PP.DepartmentID = @DepartmentId                                      OR @DepartmentId = 0                                    )                                AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                              FROM      @PPeriod )                                AND CONST_TRANS.TransactionType_ID = 2                     ), 0) ) AS PreNettPayTotal,         ( ISNULL(( SELECT  SUM(etp.Amount)                    FROM    Payroll_EmployeeTrialPayslip etp                            INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                            INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                            INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                            INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                            INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                            INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                    WHERE   ( etp.EmployeeID = @EmployeeId                              OR @EmployeeId = 0                            )                            AND TaxSavePurpose = 0                           AND ( PP.DepartmentID = @DepartmentId                                 OR @DepartmentId = 0   )                                   AND etp.PeriodID IN ( SELECT    Period_Id                                                                 FROM      @Period )                                   AND CONST_TRANS.TransactionType_ID = 1                         ), 0)        + ISNULL(( SELECT   SUM(etp.Amount)                               FROM     Payroll_EmployeeTrialPayslip etp                                        INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                        INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                        INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                        INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                               WHERE    ( etp.EmployeeID = @EmployeeId                                          OR @EmployeeId = 0                                        )                                        AND TaxSavePurpose = 0                                        AND ( PP.DepartmentID = @DepartmentId                                              OR @DepartmentId = 0                                            )                                        AND etp.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @Period )                                        AND CONST_TRANS.TransactionType_ID = 3                             ), 0) ) AS CurCostTotal,          ( ISNULL(( SELECT SUM(PAY_EMP_PAY.Amount)                 FROM   Payroll_EmployeePayslip PAY_EMP_PAY                        INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                        INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                        INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                        INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                 WHERE  ( PAY_EMP_PAY.EmployeeID = @EmployeeId                          OR @EmployeeId = 0                        )                        AND TaxSavePurpose = 0                        AND ( PP.DepartmentID = @DepartmentId                              OR @DepartmentId = 0                            )                        AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                      FROM      @PPeriod )                        AND CONST_TRANS.TransactionType_ID = 1               ), 0) + ISNULL(( SELECT  SUM(PAY_EMP_PAY.Amount)                                FROM    Payroll_EmployeePayslip PAY_EMP_PAY                                        INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                        INNER JOIN dbo.Payroll_Employee AS P_E ON PAY_EDEF.EmployeeID = P_E.Employee_ID                                        INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                        INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                                        INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                        INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                WHERE   ( PAY_EMP_PAY.EmployeeID = @EmployeeId                                          OR @EmployeeId = 0                                        )                                        AND TaxSavePurpose = 0                                        AND ( PP.DepartmentID = @DepartmentId                                              OR @DepartmentId = 0                                            )                                        AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @PPeriod )                                        AND CONST_TRANS.TransactionType_ID = 3                              ), 0) ) AS PreCostTotal             FROM    Payroll_Employee PAY_EMP    right JOIN Payroll_EmployeeTrialPayslip AS etp ON etp.EmployeeID=PAY_EMP.Employee_ID                  left JOIN Payroll_EmployeePayslip PAY_EMP_PAY ON PAY_EMP.Employee_ID = PAY_EMP_PAY.EmployeeID AND PAY_EMP_PAY.PayrollDefinationID=etp.PayrollDefinationID  AND pay_emp_pay.PeriodID = ( SELECT    Period_Id      FROM      @PPeriod )                  INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                  INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                  INNER JOIN Payroll_IRP5Code ON PAY_SAL.IRP5CodeId = Payroll_IRP5Code.IRP5Code_ID                  INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = Payroll_IRP5Code.TransactionTypeID                  INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID      INNER JOIN Payroll_Employee AS emp ON emp.Employee_ID=etp.EmployeeID      outer apply(select   CONST_TRANS_pre.TransactionType_ID                           ,PAY_SAL_pre.SalaryHead_ID                             ,PAY_EMP_pre.Employee_ID            ,SUM(PAY_EMP_PAY_pre.Amount) AS Amount          FROM    Payroll_Employee PAY_EMP_pre         right JOIN Payroll_EmployeeTrialPayslip AS etp_pre ON etp_pre.EmployeeID=PAY_EMP_pre.Employee_ID         left JOIN Payroll_EmployeePayslip PAY_EMP_PAY_pre ON PAY_EMP_pre.Employee_ID = PAY_EMP_PAY_pre.EmployeeID AND PAY_EMP_PAY_pre.PayrollDefinationID=etp_pre.PayrollDefinationID  AND pay_emp_pay_pre.PeriodID = ( SELECT    Period_Id      FROM      @PPeriod )         INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF_pre ON etp_pre.PayrollDefinationID = PAY_EDEF_pre.EmployeePayrollDefinition_ID         INNER JOIN Payroll_SalaryHead PAY_SAL_pre ON PAY_EDEF_pre.payrollsalaryHeadId = PAY_SAL_pre.SalaryHead_ID         INNER JOIN Payroll_IRP5Code IRP5 ON PAY_SAL_pre.IRP5CodeId = IRP5.IRP5Code_ID         INNER JOIN Const_TransactionType CONST_TRANS_pre ON CONST_TRANS_pre.TransactionType_ID = IRP5.TransactionTypeID         INNER JOIN dbo.Payroll_Position  AS PP ON PP.Position_ID = PAY_EMP_pre.PositionID         INNER JOIN Payroll_Employee AS emp_pre ON emp_pre.Employee_ID=etp_pre.EmployeeID         WHERE   PAY_EMP_PAY_pre.PeriodID in ( SELECT    Period_Id      FROM      @PPeriod )           AND            PAY_EMP_PAY_pre.TaxSavePurpose = 0           AND PAY_EMP_PAY_pre.TaxYear = @PreviousFinYear                     AND ( PAY_EMP_PAY_pre.EmployeeID = @EmployeeId              OR @EmployeeId = 0            )           AND ( PP.DepartmentID = @DepartmentId              OR @DepartmentId = 0            )              and  SalaryHead_ID =  PAY_SAL.SalaryHead_ID             and transactiontype_id = CONST_TRANS.TransactionType_ID             and PAY_EMP_pre.Employee_ID = PAY_EMP_PAY.EmployeeID             GROUP BY PAY_EMP_PRe.Employee_ID, CONST_TRANS_pre.TransactionType_ID, PAY_SAL_pre.SalaryHead_ID     ) Previous             WHERE   1=1          and  etp.PeriodID IN ( SELECT    Period_Id                                            FROM      @Period )    --AND PAY_EMP_PAY.PeriodID IN ( SELECT    Period_Id      FROM      @PPeriod )                  AND etp.TaxSavePurpose = 0                  AND etp.TaxYear = @FinancialYear      AND emp.[Enabled]=1                  AND ( CONST_TRANS.TransactionType_ID = @TransactionTypeId                        OR @TransactionTypeId = 0                      )                  AND ( etp.EmployeeID = @EmployeeId                        OR @EmployeeId = 0                      )                  AND ( PP.DepartmentID = @DepartmentId                        OR @DepartmentId = 0                      )       --and PAY_EMP_PAY.[Month]+1 is not null          GROUP BY     CONST_TRANS.TransactionType_ID,     CONST_TRANS.TransactionTypeDesc,     PAY_SAL.SalaryHeadTitle,     PAY_SAL.SalaryHead_ID,     Previous.Amount,    etp.Amount,     --PAY_EDEF.EmployeePayrollDefinition_ID,     PAY_EMP.Employee_ID--,     ----CONST_TRANS.TransactionType_ID,     --PAY_EMP.Employee_ID                   union     SELECT      CONST_TRANS.TransactionType_ID,     CONST_TRANS.TransactionTypeDesc,     PAY_SAL.SalaryHeadTitle AS SalarHead,     PAY_SAL.SalaryHead_ID,     MIN(ISNULL(PAY_EMP.FirstName, '') + ' ' + ISNULL(PAY_EMP.Surname, '')) AS EMPLOYEE,     PAY_EMP.Employee_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8, '0') AS EmpNo,     MIN(PAY_EMP_PAY.[Month]+1) AS [Month],     isnull(SUM(etp.Amount),0) AS Amount    ,isnull((Previous.Amount),0) AS Previous    ,isnull(SUM(etp.Amount),0) - isnull((previous.amount),0) as Variance ,       --( SELECT   dbo.GetLastDateOfMonth(SUBSTRING(@FinancialYear, CHARINDEX('/', @FinancialYear) + LEN('/'), LEN(@FinancialYear)), @Month)     ( SELECT   dbo.GetLastDateOfMonth(YEAR(@PeriodEndDate), @Month)                                   ) AS LastDayinMonth,        ( SELECT  dbo.AutoGenerateEmployeeId(PAY_EMP.Employee_ID)                                ) AS EmployeeId,           ( ISNULL(( SELECT    SUM(etp.Amount)                FROM      Payroll_EmployeeTrialPayslip  etp                          INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID                          INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                          INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                WHERE     etp.EmployeeID = PAY_EMP.Employee_ID                          AND TaxSavePurpose = 0                          AND etp.PeriodID IN ( SELECT    Period_Id                                                        FROM      @Period )                          AND CONST_TRANS.TransactionType_ID = 1              ), 0) - ISNULL(( SELECT SUM(etp.Amount)                               FROM   Payroll_EmployeeTrialPayslip etp                                      INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON etp.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.payrollsalaryHeadId = PAY_SAL.SalaryHead_ID           INNER JOIN Payroll_IRP5Code AS IRP5 ON PAY_SAL.IRP5CodeId = IRP5.IRP5Code_ID                                      INNER JOIN Const_TransactionType CONST_TRANS ON CONST_TRANS.TransactionType_ID = IRP5.TransactionTypeID                                 WHERE  etp.EmployeeID = PAY_EMP.Employee_ID                                        AND TaxSavePurpose = 0                                        AND etp.PeriodID IN ( SELECT    Period_Id                                                                      FROM      @Period )                                        AND CONST_TRANS.TransactionType_ID = 2                  ), 0) ) AS CurNettpay,     ( ISNULL(( SELECT SUM(PAY_EMP_PAY.Amount)                                    FROM   Payroll_EmployeePayslip PAY_EMP_PAY                                           INNER JOIN Payroll_EmployeePayrollDefinition PAY_EDEF ON PAY_EMP_PAY.PayrollDefinationID = PAY_EDEF.EmployeePayrollDefinition_ID                                           INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_EDEF.

GO

-- ============================================
-- SP: Payroll_PayslipDetails
-- Schema: dbo
-- ============================================
   /*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetails 301,1     Modified : Artur Anzorge 06/11/2019 => Add Paypoint location description      : Richa M 2025/09/15 - Cater for free text address fields        */  CREATE PROCEDURE [dbo].[Payroll_PayslipDetails]   @PeriodID int,   @EmployeeId int  as  begin  DECLARE @FROMDATE DATETIME  DECLARE @TODATE DATETIME  DECLARE @PeriodInTaxYear int  DECLARE @TaxYear nvarchar(10)  DECLARE @MonthlyCycleTypeId INT = 1      SELECT  @FROMDATE = PeriodStartDate       ,@TODATE = PeriodEndDate      ,@PeriodInTaxYear = PeriodInTaxYear      ,@TaxYear = TaxYear  FROM Payroll_CyclePeriodDetails   WHERE Period_ID = @PERIODID      Select CONVERT(VARCHAR(8), @FromDate, 3) FromDate   ,CONVERT(VARCHAR(8), @ToDate, 3) ToDate  ,CAST(@PeriodInTaxYear AS varchar(5)) + '/' + Right(@TaxYear,4) AS Period  ,emp.IdNo  ,emp.Empcode  ,emp.Employee_ID  ,emp.FirstName + ' ' + Emp.Surname AS EmployeeName  ,emp.Initials AS EmploeeInitials  ,emp.Surname AS EmployeeSurname  ,case when PhysicalAddressTypeID = 1 then IIF(emp.PhysicalStreetNo IS NULL, '', emp.PhysicalStreetNo + ', ') + csPhysical.StreetName else PhysicalAddress1 end AS EmployeePhysicalStreet  ,case when PhysicalAddressTypeID = 1 then ctPhysical.Town else PhysicalAddress2 end AS EmployeePhysicalTown  ,case when PhysicalAddressTypeID = 1 then emp.PhysicalPostalCode else PhysicalAddress4 end AS PhysicalPostalCode  ,IIF(PCPD.CycleModeID = @MonthlyCycleTypeId      ,PCPD.ProcessingMonth + ' ' + CONVERT(VARCHAR, YEAR(PCPD.PeriodEndDate))      ,convert(varchar, PCPD.PeriodStartDate, 103) + '-' + convert(varchar, PCPD.PeriodEndDate, 103)) AS PayPeriod  ,pos.PositionDesc AS PositionDescription  ,ISNULL(emp.PhysicalAddress1 + ' ','') + ISNULL(emp.PhysicalAddress2 + ' ','') + ISNULL((SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=emp.PhysicalSuburbID),'') AS EMPADDRESS  ,CONVERT(NVARCHAR,emp.JoiningDate,103) AS STARTDATE  ,0 AS TotalLeave  ,dbo.BufferString_fxn(CONVERT(VARCHAR,(emp.Employee_ID)), 12, '0') AS EMPLOYEENO  ,pj.JobTitle  ,pd.DepartmentDesc  ,emp.IncomeTaxNumber  ,emp.PaypointId  ,Cast(pp.PayPointDesc as Varchar(25)) as PayPointLocation  ,PCPD.PeriodEndDate   from Payroll_Employee emp  INNER JOIN dbo.Payroll_JobProfile pj      ON emp.JobProfileID = pj.JobProfile_ID  INNER JOIN dbo.Payroll_Position pos     ON emp.PositionId = pos.Position_ID  INNER JOIN dbo.Const_Department pd     ON pd.Department_ID = pos.DepartmentID  LEFT JOIN dbo.Payroll_PayPoint pp      ON emp.PayPointID = pp.PayPoint_ID  LEFT JOIN dbo.Const_Street csPhysical              ON csPhysical.Street_ID = emp.PhysicalStreetID  LEFT JOIN dbo.Const_Town ctPhysical              ON ctPhysical.Town_ID = emp.PhysicalTownID  INNER JOIN dbo.Payroll_CyclePeriodDetails PCPD              ON PCPD.Period_ID = @PeriodID  WHERE Employee_Id = @EmployeeId    END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsArrearDeductions
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsArrearDeductions]   @PeriodID int,   @EmployeeId int,   @IsTrial bit,      @IgnoreRowCount BIT = 0  as  begin  DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME   DECLARE @TaxYear NVARCHAR(10) =''     SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID    IF @IsTrial = 1  BEGIN  --This is important for spacing on the payslip      DECLARE @RowCount int = (SELECT Count(1) FROM Payroll_DeductionsCarriedOverTrial WHERE (EmployeeId = @EmployeeId OR @EmployeeId = 0) AND PeriodId = @PeriodId)            SELECT 1,PSH.SalaryHeadTitle AS Description,Amount AS Balance FROM Payroll_DeductionsCarriedOverTrial AS PDCOT      JOIN Payroll_EmployeePayrollDefinition AS PEPD ON PDCOT.EmployeePayrollDefinitionId = PEPD.EmployeePayrollDefinition_ID      JOIN Payroll_SalaryHead AS PSH ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID      WHERE (PDCOT.EmployeeId = @EmployeeId OR @EmployeeId = 0) AND PDCOT.PeriodId = @PeriodId            UNION ALL      SELECT       NumberOfRows.RowNum,       NULL AS Description,       NULL AS Balance       FROM (SELECT TOP (3)        ROW_NUMBER() OVER (ORDER BY id) AS RowNum       FROM sys.syscolumns) AS NumberOfRows      WHERE NumberOfRows.RowNum > @RowCount       AND @IgnoreRowCount = 0    END  ELSE  BEGIN      DECLARE @RowCountFinal int = (SELECT Count(1) FROM Payroll_DeductionsCarriedOverFinal WHERE (EmployeeId = @EmployeeId OR @EmployeeId = 0) AND PeriodId = @PeriodId)            SELECT 1,PSH.SalaryHeadTitle AS Description,Amount AS Balance FROM Payroll_DeductionsCarriedOverFinal AS PDCOT      JOIN Payroll_EmployeePayrollDefinition AS PEPD ON PDCOT.EmployeePayrollDefinitionId = PEPD.EmployeePayrollDefinition_ID      JOIN Payroll_SalaryHead AS PSH ON PEPD.PayrollSalaryHeadID = PSH.SalaryHead_ID      WHERE (PDCOT.EmployeeId = @EmployeeId OR @EmployeeId = 0) AND PDCOT.PeriodId = @PeriodId            UNION ALL      SELECT       NumberOfRows.RowNum,       NULL AS Description,       NULL AS Balance       FROM (SELECT TOP (3)        ROW_NUMBER() OVER (ORDER BY id) AS RowNum       FROM sys.syscolumns) AS NumberOfRows      WHERE NumberOfRows.RowNum > @RowCountFinal       AND @IgnoreRowCount = 0  END  END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsCompanyContributions
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetailsCompanyContributions 301,1   Update Date : 07/04/2020 - Ilya Skavronskiy => Changed Salary Head Title for Medical Aid and Persion Fund  */  CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsCompanyContributions]   @PeriodID INT,   @EmployeeId INT  AS  BEGIN    DECLARE @transactionType_companyContrib INT = 3     DECLARE @SalaryHead_MedicalAidPensionFund   TABLE ([SalaryHeadID] [int] not null)    INSERT INTO @SalaryHead_MedicalAidPensionFund([SalaryHeadID])  VALUES (12), -- Medical Aid (Employee)    (13), -- Medical Aid (Employer)    (14), -- Medical Aid (Fringe)    (15), -- Pension Fund (Employee)    (16), -- Pension Fund (Employer)    (17) -- Pension Fund (Fringe)    DECLARE @SalaryHead_ProvidentFund  TABLE ([SalaryHeadID] [int] not null)    INSERT INTO @SalaryHead_ProvidentFund([SalaryHeadID])  VALUES (18), -- Provident Fund (Employee)    (19), -- Provident Fund (Employer)    (20) -- Provident Fund (Fringe)        Select SalaryTitle,SUM(Amount)Amount,ReferenceNo from(   SELECT DISTINCT     0 as PayrollResult_ID,    (CASE      WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN ps.SalaryHeadTitleAddendum     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PBD.FundName     ELSE tr.SalaryTitle    END) AS SalaryTitle,    tr.Amount,    (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PEBD.ReferenceNo     ELSE ps.ReferenceNo    END) AS ReferenceNo   FROM   (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle   FROM Payroll_PayrollResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = @transactionType_companyContrib And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr   LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID   Left outer join Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = tr.SalaryHeadID and def.EmployeeID = tr.EmployeeID  and def.Enabled = 1    join Payroll_EmployeePayslip ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID and Ps.Amount = tr.Amount    JOIN Payroll_CyclePeriodDetails AS PCPD ON ps.PeriodID = PCPD.Period_ID   LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId     AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0    LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID   )ps   GROUP BY SalaryTitle,ReferenceNo  END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsCompanyContributionsTrial
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetailsCompanyContributions 301,1   Update Date : 12/08/2019 (By Himil Modi #86913) - Done changes in the selected field and get the reference number.   Update Date : 07/04/2020 - Ilya Skavronskiy => Changed Salary Head Title for Medical Aid and Persion Fund     Payroll_PayslipDetailsCompanyContributionsTrial 280,735  */  CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsCompanyContributionsTrial]   @PeriodID INT,   @EmployeeId INT   AS  BEGIN    DECLARE @transactionType_companyContrib INT = 3       DECLARE @SalaryHead_MedicalAidPensionFund   TABLE ([SalaryHeadID] [INT] not null)    INSERT INTO @SalaryHead_MedicalAidPensionFund([SalaryHeadID])  VALUES (12), -- Medical Aid (Employee)    (13), -- Medical Aid (Employer)    (14), -- Medical Aid (Fringe)    (15), -- Pension Fund (Employee)    (16), -- Pension Fund (Employer)    (17) -- Pension Fund (Fringe)    DECLARE @SalaryHead_ProvidentFund  TABLE ([SalaryHeadID] [INT] not null)    INSERT INTO @SalaryHead_ProvidentFund([SalaryHeadID])  VALUES (18), -- Provident Fund (Employee)    (19), -- Provident Fund (Employer)    (20) -- Provident Fund (Fringe)      Select SalaryTitle,SUM(Amount)Amount,ReferenceNo from(   SELECT DISTINCT     0 AS TrialResult_ID,    (CASE      WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN ps.SalaryHeadTitleAddendum     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PBD.FundName     ELSE tr.SalaryTitle    END) AS SalaryTitle,    tr.Amount,    (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PEBD.ReferenceNo     ELSE ps.ReferenceNo    END) AS ReferenceNo   FROM   (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle   FROM Payroll_TrialResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = @transactionType_companyContrib And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr   LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID   Left outer join Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = tr.SalaryHeadID and def.EmployeeID = tr.EmployeeID  and def.Enabled = 1    join Payroll_EmployeeTrialPayslip ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID and Ps.Amount = tr.Amount    JOIN Payroll_CyclePeriodDetails AS PCPD ON ps.PeriodID = PCPD.Period_ID   LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId     AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0    LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID   )ps   GROUP BY SalaryTitle,ReferenceNo  END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsDeductions
-- Schema: dbo
-- ============================================
/*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetailsDeductions 301,1      Modiri  : 2019/07/01   Reason  : #90611 Payslip blank on Final run view     RichaM  : 2019/11/09   Reason  : Add NumberOfRows as Paramater in order to use proc for multiple templates     Update Date : 07/04/2020 - Ilya Skavronskiy => Changed Salary Head Title for Medical Aid and Persion Fund     select * from payroll_cyclePerioddetails where taxyear = '2024/2025'   Payroll_PayslipDetailsDeductions 148,143  */      CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsDeductions]   @PeriodID int,   @EmployeeId int     as  begin    declare @groupTransactions bit = (select GroupTransactionsOnPayslip from Payroll_Municipality)      DECLARE @SalaryHead_MedicalAidPensionFund   TABLE ([SalaryHeadID] [int] not null)    INSERT INTO @SalaryHead_MedicalAidPensionFund([SalaryHeadID])  VALUES (12), -- Medical Aid (Employee)    (13), -- Medical Aid (Employer)    (14), -- Medical Aid (Fringe)    (15), -- Pension Fund (Employee)    (16), -- Pension Fund (Employer)    (17) -- Pension Fund (Fringe)    DECLARE @SalaryHead_ProvidentFund  TABLE ([SalaryHeadID] [INT] not null)    INSERT INTO @SalaryHead_ProvidentFund([SalaryHeadID])  VALUES (18), -- Provident Fund (Employee)    (19), -- Provident Fund (Employer)    (20) -- Provident Fund (Fringe)      if @groupTransactions = 1   BEGIN  DECLARE @SalaryHeadTitle TABLE (   [SalaryHeadID] [int] not null,   [Description] nvarchar(200)  )    Insert into @SalaryHeadTitle  select Distinct PayrollSalaryHeadID,SalaryHeadTitleAddendum   from(   select distinct PayrollDefinationID,SalaryHeadTitleAddendum    from payroll_employeepayslip    where EmployeeID = @EmployeeId and PeriodID = @PeriodID and TaxsavePurpose = 0  and PayrollDefinationID in    (select EmployeePayrollDefinition_ID from Payroll_EmployeePayrollDefinition where EmployeeID = @EmployeeId and PayrollSalaryHeadID in (select SalaryHeadID from @SalaryHead_MedicalAidPensionFund UNION ALL select * from @SalaryHead_ProvidentFund)))ep   join Payroll_EmployeePayrollDefinition pd on pd.EmployeePayrollDefinition_ID = ep.PayrollDefinationID        Select ID,Grouped.SalaryHeadTitle,SUM(Amount)Amount,Grouped.ReferenceNo from(  SELECT   0 ID,   (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN st.Description          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN st.Description    ELSE sh.SalaryHeadTitle   END) AS SalaryHeadTitle,   tr.Amount,    '' AS ReferenceNo  FROM  (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle  FROM Payroll_PayrollResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = 2 And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr  LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID    JOIN Payroll_CyclePeriodDetails AS PCPD ON @PeriodId = PCPD.Period_ID  LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId    AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0   LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID  LEFT JOIN @SalaryHeadTitle st on st.SalaryHeadID = SalaryHead_ID    )Grouped Group BY ID,Grouped.SalaryHeadTitle,Grouped.ReferenceNo  END  ELSE  BEGIN  SELECT DISTINCT  0,   (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN ps.SalaryHeadTitleAddendum          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PBD.FundName    ELSE sh.SalaryHeadTitle   END) AS SalaryHeadTitle,   tr.Amount,    (CASE          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PEBD.ReferenceNo          ELSE ps.ReferenceNo      END) AS ReferenceNo  FROM  (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle  FROM Payroll_PayrollResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = 2 And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr  LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID  Left outer join Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = tr.SalaryHeadID and def.EmployeeID = tr.EmployeeID  and def.Enabled = 1   join (select PayrollDefinationID,SUM(Amount)Amount,PeriodID,SalaryHeadTitleAddendum,ReferenceNo from Payroll_EmployeePayslip group by PayrollDefinationID,PeriodID,SalaryHeadTitleAddendum,ReferenceNo)ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID and Ps.Amount = tr.Amount   JOIN Payroll_CyclePeriodDetails AS PCPD ON ps.PeriodID = PCPD.Period_ID  LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId    AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0   LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID  END  END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsDeductionsTrial
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetailsDeductions 301,1      Modiri  : 2019/07/01   Reason  : #90611 Payslip blank on Final run view     RichaM  : 2019/11/09   Reason  : Add NumberOfRows as Paramater in order to use proc for multiple templates      Update Date : 07/04/2020 - Ilya Skavronskiy => Changed Salary Head Title for Medical Aid and Persion Fund  */    CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsDeductionsTrial]   @PeriodID int,   @EmployeeId int   as  begin    declare @groupTransactions bit = (select GroupTransactionsOnPayslip from Payroll_Municipality)    DECLARE @SalaryHead_MedicalAidPensionFund   TABLE ([SalaryHeadID] [int] not null)    INSERT INTO @SalaryHead_MedicalAidPensionFund([SalaryHeadID])  VALUES (12), -- Medical Aid (Employee)    (13), -- Medical Aid (Employer)    (14), -- Medical Aid (Fringe)    (15), -- Pension Fund (Employee)    (16), -- Pension Fund (Employer)    (17) -- Pension Fund (Fringe)    DECLARE @SalaryHead_ProvidentFund  TABLE ([SalaryHeadID] [INT] not null)    INSERT INTO @SalaryHead_ProvidentFund([SalaryHeadID])  VALUES (18), -- Provident Fund (Employee)    (19), -- Provident Fund (Employer)    (20) -- Provident Fund (Fringe)    if @groupTransactions = 1   BEGIN    DECLARE @SalaryHeadTitle TABLE (   [SalaryHeadID] [int] not null,   [Description] nvarchar(200)  )    Insert into @SalaryHeadTitle  select Distinct PayrollSalaryHeadID,SalaryHeadTitleAddendum   from(   select distinct PayrollDefinationID,SalaryHeadTitleAddendum    from Payroll_EmployeeTrialPayslip    where EmployeeID = @EmployeeId and PeriodID = @PeriodID and TaxsavePurpose = 0  and PayrollDefinationID in    (select EmployeePayrollDefinition_ID from Payroll_EmployeePayrollDefinition where EmployeeID = @EmployeeId and PayrollSalaryHeadID in (select SalaryHeadID from @SalaryHead_MedicalAidPensionFund UNION ALL select * from @SalaryHead_ProvidentFund)))ep   join Payroll_EmployeePayrollDefinition pd on pd.EmployeePayrollDefinition_ID = ep.PayrollDefinationID    Select ID,SalaryHeadTitle,SuM(Amount)Amount,ReferenceNo from(  SELECT   0 ID,   (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN st.Description          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN st.Description    ELSE sh.SalaryHeadTitle   END) AS SalaryHeadTitle,   tr.Amount,    '' AS ReferenceNo  FROM  (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle  FROM Payroll_TrialResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = 2 And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr  LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID   JOIN Payroll_CyclePeriodDetails AS PCPD ON @PeriodID = PCPD.Period_ID  LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId    AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0   LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID  LEFT JOIN @SalaryHeadTitle st on st.SalaryHeadID = SalaryHead_ID    )grouped GROUP BY ID,SalaryHeadTitle,ReferenceNo  END  ELSE  BEGIN  SELECT DISTINCT  0,   (CASE     WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_MedicalAidPensionFund) THEN ps.SalaryHeadTitleAddendum          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PBD.FundName    ELSE sh.SalaryHeadTitle   END) AS SalaryHeadTitle,   tr.Amount,    (CASE          WHEN tr.SalaryHeadID IN (SELECT * FROM @SalaryHead_ProvidentFund) THEN PEBD.ReferenceNo          ELSE ps.ReferenceNo      END) AS ReferenceNo  FROM  (SELECT SalaryHeadId, EmployeeId, SUM(Amount)Amount, VendorID ,SalaryTitle  FROM Payroll_TrialResults where Employeeid = @EmployeeId and PeriodId = @PeriodID and Transactiontypeid = 2 And TaxSavePurpose = 0 group by SalaryHeadID,EmployeeID,VendorID,SalaryTitle) tr  LEFT OUTER JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = tr.SalaryHeadID  Left outer join Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = tr.SalaryHeadID and def.EmployeeID = tr.EmployeeID  and def.Enabled = 1   join (select PayrollDefinationID,SUM(Amount)Amount,PeriodID,SalaryHeadTitleAddendum,ReferenceNo from Payroll_EmployeeTrialPayslip group by PayrollDefinationID,PeriodID,SalaryHeadTitleAddendum,ReferenceNo)ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID and Ps.Amount = tr.Amount   JOIN Payroll_CyclePeriodDetails AS PCPD ON ps.PeriodID = PCPD.Period_ID  LEFT JOIN Payroll_EmpBenefitDetail AS PEBD ON tr.EmployeeID = PEBD.EmployeeId    AND PEBD.JoinDate <= PCPD.PeriodEndDate AND ISNULL(PEBD.TerminationDate, PCPD.PeriodStartDate) >= PCPD.PeriodStartDate and pebd.Enabled = 1 and PEBD.IsPrivate = 0   LEFT JOIN Payroll_BenefitDetail AS PBD ON PEBD.BenefitSchemeID = PBD.Benefit_ID AND tr.VendorID = PBD.VendorID     END  END

GO

-- ============================================
-- SP: Payroll_PayslipDetailsIncome
-- Schema: dbo
-- ============================================
      /* =======================================================================================================================================  -- Author  :   -- Create date :      exec Payroll_PayslipDetailsIncome 302,328    select * from payroll_cycleperioddetails where taxyear = '2024/2025'    Modified - RichaM 2025/02/05 WI118708 - Fix division by 0 error       ======================================================================================================================================= */    CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsIncome]   @PeriodID int,   @EmployeeId int   as  begin  DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME   DECLARE @TaxYear NVARCHAR(10) =''     SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID       declare @tbl table(   PayrollResult_id int null   ,SalaryTitle varchar(200) null   ,Amount float   ,OvertimeHour float   ,Rate float   ,ReferenceNo NVARCHAR(50) NULL      ,SalaryHeadTitle NVARCHAR(50))       insert into @tbl    SELECT    PayrollResult_id   ,SalaryTitle   ,pr.Amount,   sum(OvertimeHour)   ,SUM(pr.Amount)/SUM(OvertimeHour) AS Rate      ,IIF(MIN(ISNULL(ov.OverTimeHour, 0)) <> 0, NULL, ps.ReferenceNo)      ,sh.SalaryHeadTitle   FROM Payroll_PayrollResults pr  LEFt JOIN Payroll_EmployeeOvertime ov on ov.ProcessedOnPeriodId = pr.PeriodID and ov.employeeId = pr.EmployeeId and ov.SalaryHeadId = pr.salaryHeadId and Enabled = 1 and IsNULL(IsApproved,0) = 1    JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = pr.SalaryHeadID  LEFT JOIN Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = pr.SalaryHeadID and def.EmployeeID = pr.EmployeeID and def.Enabled = 1  LEFT JOIN Payroll_EmployeeTrialPayslip ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID AND ps.Amount = pr.Amount    WHERE (pr.EmployeeId = @EmployeeId OR @EmployeeId = 0) AND pr.PeriodId = @PeriodId AND TransactionTypeId in (1)  and pr.Amount <> 0  group by PayrollResult_id,SalaryTitle, pr.amount, ps.ReferenceNo, sh.SalaryHeadTitle  END      select * from   (select SalaryTitle,SUM(Amount)Amount,SUM(OvertimeHour)OvertimeHour,SUM(Rate)Rate,ReferenceNo,SalaryHeadTitle from @tbl    group by SalaryTitle,ReferenceNo,SalaryHeadTitle)tbl

GO

-- ============================================
-- SP: Payroll_PayslipDetailsIncomeTrial
-- Schema: dbo
-- ============================================
/* =======================================================================================================================================  -- Author  :   -- Create date :   --Upadate Date  :12/08/2019 (By Himil Modi #86913) - Change in the join with the over time user periodId instead of ProcessedOnPeriodId    Modified - RichaM 2025/02/05 WI118708 - Fix division by 0 error    exec Payroll_PayslipDetailsIncomeTrial 295,3       ======================================================================================================================================= */  CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsIncomeTrial]   @PeriodID int,   @EmployeeId int   as  begin  DECLARE @FROMDATE DATETIME   DECLARE @TODATE DATETIME   DECLARE @TaxYear NVARCHAR(10) =''     SELECT  @FROMDATE =PeriodStartDate ,@TODATE =PeriodEndDate, @TaxYear = TaxYear FROM Payroll_CyclePeriodDetails WHERE Period_ID =@PERIODID     --This is important for spacing on the payslip     declare @tbl table(   PayrollResult_id int null   ,SalaryTitle varchar(200) null   ,Amount float   ,OvertimeHour float   ,Rate float   ,ReferenceNo NVARCHAR(50) NULL      ,SalaryHeadTitle NVARCHAR(50))   insert into @tbl    SELECT    TrialResult_ID   ,SalaryTitle   ,pr.Amount   ,sum(OvertimeHour)   ,SUM(pr.Amount)/SUM(OvertimeHour) AS Rate     ,IIF(MIN(ISNULL(ov.OverTimeHour, 0)) <> 0, NULL, ps.ReferenceNo)      ,sh.SalaryHeadTitle  FROM Payroll_TrialResults pr  LEFT JOIN Payroll_EmployeeOvertime ov on ov.employeeId = pr.EmployeeId and ov.SalaryHeadId = pr.salaryHeadId and Ov.Enabled = 1 and IsNULL(IsApproved,0) = 1  JOIN Payroll_SalaryHead sh ON sh.SalaryHead_ID = pr.SalaryHeadID  LEFT JOIN Payroll_EmployeePayrollDefinition def on def.PayrollSalaryHeadID = pr.SalaryHeadID and def.EmployeeID = pr.EmployeeID and def.Enabled = 1  LEFT JOIN Payroll_EmployeeTrialPayslip ps on ps.PayrollDefinationID = def.EmployeePayrollDefinition_ID and ps.PeriodID = @PeriodID AND ps.Amount = pr.Amount  WHERE (pr.EmployeeId = @EmployeeId OR @EmployeeId = 0) AND pr.PeriodId = @PeriodId AND TransactionTypeId in (1) AND IsNULL(ov.Processed,0) = 0 AND  pr.Amount <> 0  group by TrialResult_ID,SalaryTitle, pr.amount, ps.ReferenceNo, sh.SalaryHeadTitle  END    select * from   (select SalaryTitle,SUM(Amount)Amount,SUM(OvertimeHour)OvertimeHour,SUM(Rate)Rate,ReferenceNo,SalaryHeadTitle from @tbl    group by SalaryTitle,ReferenceNo,SalaryHeadTitle)tbl

GO

-- ============================================
-- SP: Payroll_PayslipDetailsLeaveBalance
-- Schema: dbo
-- ============================================
/*   Author  : RICHA MILLS   Create date : 2018/03/06   Description : Payslips   EXEC Payroll_PayslipDetailsLeaveBalance,1     Modiri   2019/10/23   21756 Only Leave types marked for printing on payslip should display on the Payslip.     Artur Anzorge   2019/11/05   Changed top(5) to top(6) for report payslip view      2019/02/09   Modiri   https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/21756    */  CREATE PROCEDURE [dbo].[Payroll_PayslipDetailsLeaveBalance]   @EmployeeId int  as  BEGIN    declare @SubtypeID int, @Encash bit =null,     @LeaveSchemeID int     SELECT @SubtypeID=EmployeeSubtypeID, @LeaveSchemeID=LeaveSchemeID FROM Payroll_Employee where Employee_ID=@EmployeeId      declare @tbl table(idx int identity(1,1),LeaveScheme_ID int,[AbsenceType_ID] int, LeaveTypeId int,Description varchar(100),OpeningBalance decimal(18,2), Acrrued decimal(18,2),Taken decimal(18,2),Forfeited decimal(18,2),Encashed decimal(18,2),LeaveBalance decimal(18,2))     Insert into @tbl([AbsenceType_ID],LeaveTypeId, LeaveScheme_ID, Description)      select [CA].[AbsenceType_ID],[LT].[LeaveType_ID], [LS].[LeaveScheme_ID], [LT].[LeaveTypeDesc]       from [Const_LeaveType] as [LT] with(nolock)        join [Payroll_AbsencePriority] as [AP] with(nolock) on [AP].[LeaveTypeID] = [LT].[LeaveType_ID]        join [Const_AbsenceType] as [CA] with(nolock) on [CA].[AbsenceType_ID] = [AP].[AbsenceTypeID]        join [Const_LeaveSchemeTypeDetails] as [LSD] with(nolock) on [LSD].[LeaveTypeId] = [CA].[AbsenceType_ID] and [LSD].[Enabled] = 1        join [Const_LeaveScheme] as [LS] with(nolock) on [LS].[LeaveScheme_ID] = [LSD].[LeaveSchemeId] and [LS].[Enabled] = 1        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = @EmployeeId and [PE].[EmployeeTypeID] = [LS].[EmployeeTypeID] and [PE].[EmployeeSubtypeID] = [LS].[EmployeeSubtypeID] and [PE].[ConditionOfServiceID] = [LS].[ConditionOfServiceID] and [PE].[Enabled] = 1       where ([LT].[Enabled] = 1 and (@Encash is null or isnull([LT].[Encash], 0) = @Encash)) AND BalanceOnPayslip=1       UPDATE TB     SET OpeningBalance = [OPB].[Total],      Acrrued = [ACC].[Total],      Taken = [TKN].[Total],      Forfeited = [FFD].[Total],      Encashed = [ECH].[Total]          FROM @tbl TB    LEFT JOIN ( select ISNULL(SUM(value),0)  as Total,LeaveTypeId from [Payroll_EmployeeLeaveTransactions] as [ET]      WHERE [LeaveAdjustmentTypeID] in(1,7) AND [EmployeeID] = @EmployeeId GROUP BY LeaveTypeId       ) as [OPB]       ON TB.[LeaveTypeId] = [OPB].LeaveTypeID     LEFT JOIN ( select ISNULL(SUM(value),0)  as Total,LeaveTypeId from [Payroll_EmployeeLeaveTransactions] as [ET]       WHERE [LeaveAdjustmentTypeID] in(2,6) AND [EmployeeID] = @EmployeeId GROUP BY LeaveTypeId        ) as [ACC]        ON TB.[LeaveTypeId] = [ACC].LeaveTypeID      LEFT JOIN ( select ISNULL(SUM(value),0)  as Total,LeaveTypeId from [Payroll_EmployeeLeaveTransactions] as [ET]        WHERE [LeaveAdjustmentTypeID] in(3) AND [EmployeeID] = @EmployeeId GROUP BY LeaveTypeId         ) as [TKN]         ON TB.[LeaveTypeId] = [TKN].LeaveTypeID       LEFT JOIN ( select ISNULL(SUM(value),0)  as Total,LeaveTypeId from [Payroll_EmployeeLeaveTransactions] as [ET]         WHERE [LeaveAdjustmentTypeID] in(4) AND [EmployeeID] = @EmployeeId GROUP BY LeaveTypeId          ) as [FFD]          ON TB.[LeaveTypeId] = [FFD].LeaveTypeID        LEFT JOIN ( select ISNULL(SUM(value),0) as Total,LeaveTypeId from [Payroll_EmployeeLeaveTransactions] as [ET]          WHERE [LeaveAdjustmentTypeID] in(5) AND [EmployeeID] = @EmployeeId GROUP BY LeaveTypeId           ) as [ECH]           ON TB.[LeaveTypeId] = [ECH].LeaveTypeID      DECLARE @RowCount int = (Select count(LeaveTypeId) from @tbl)     Select     [TB].LeaveTypeId,          [Description] as LeaveTypeDesc          ,( ISNULL(Encashed,0) + ISNULL(Taken,00) +ISNULL(Forfeited,0) + ISNULL(Acrrued,0)+ ISNULL(OpeningBalance,0)) AS  Balance      ,null as cBalanceOnPayslip   from @tbl TB       join [Const_AbsenceType] as [AT] with(nolock) on [AT].[AbsenceType_ID] = [TB].[AbsenceType_ID]       UNION ALL   SELECT    NumberOfRows.RowNum,    NULL AS LeaveTypeDesc,    NULL AS Balancce,    null AS BalanceOnPayslip      FROM (SELECT TOP (10)     ROW_NUMBER() OVER (ORDER BY id) AS RowNum    FROM sys.syscolumns) AS NumberOfRows   WHERE NumberOfRows.RowNum > @RowCount            END

GO

-- ============================================
-- SP: Payroll_PayslipEmployeeDetails
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 2025/09/01   Description : Payslips   EXEC Payroll_PayslipEmployeeDetails 103,1555     */  CREATE PROCEDURE [dbo].[Payroll_PayslipEmployeeDetails]   @PeriodID int,   @EmployeeId int  as  begin  DECLARE @FROMDATE DATETIME  DECLARE @TODATE DATETIME  DECLARE @PeriodInTaxYear int  DECLARE @TaxYear nvarchar(10)  DECLARE @MonthlyCycleTypeId INT = 1      SELECT  @FROMDATE = PeriodStartDate       ,@TODATE = PeriodEndDate      ,@PeriodInTaxYear = PeriodInTaxYear      ,@TaxYear = TaxYear  FROM Payroll_CyclePeriodDetails   WHERE Period_ID = @PERIODID      Select CONVERT(VARCHAR(8), @FromDate, 3) FromDate   ,CONVERT(VARCHAR(8), @ToDate, 3) ToDate  ,CAST(@PeriodInTaxYear AS varchar(5)) + '/' + Right(@TaxYear,4) AS Period  ,emp.IdNo  ,emp.Empcode  ,emp.Employee_ID   ,emp.FirstName + ' ' + Emp.Surname AS EmployeeName  ,emp.Initials AS EmploeeInitials  ,emp.Surname AS EmployeeSurname  , LTRIM(RTRIM(CONCAT_WS(' ',          NULLIF(emp.Initials, ''),          NULLIF(emp.FirstName, ''),          NULLIF(emp.SecondName, ''),          NULLIF(emp.Surname, '')      ))) AS FullName  ,cb.BankDesc + ' / ' + BBR.BankBranchCode Bank  ,emp.AccountNumber  ,emp.IncomeTaxNumber  ,emp.AnnualSalary  ,CASE WHEN PhysicalAddressTypeID = 1 THEN IIF(emp.PhysicalStreetNo IS NULL, '', emp.PhysicalStreetNo + ', ') + csPhysical.StreetName ELSE emp.PhysicalAddress1 end AS Address1  ,CASE WHEN PhysicalAddressTypeID = 1 THEN ctPhysical.Town ELSE PhysicalAddress2 END AS Address2  ,CASE WHEN PhysicalAddressTypeID = 1 THEN sub.SuburbName ELSE PhysicalAddress3 END AS Address3  ,CASE WHEN PhysicalAddressTypeID = 1 THEN emp.PhysicalPostalCode ELSE PhysicalAddress4 END AS Address4  ,IIF(PCPD.CycleModeID = @MonthlyCycleTypeId      ,PCPD.ProcessingMonth + ' ' + CONVERT(VARCHAR, YEAR(PCPD.PeriodEndDate))      ,convert(varchar, PCPD.PeriodStartDate, 103) + '-' + convert(varchar, PCPD.PeriodEndDate, 103)) AS PayPeriod  ,pos.PositionDesc AS PositionDescription  ,CONVERT(NVARCHAR,emp.JoiningDate,103) AS JoiningDate  ,CONVERT(NVARCHAR,emp.DateOfBirth,103) AS DateOfBirth  ,0 AS TotalLeave  ,dbo.BufferString_fxn(CONVERT(VARCHAR,(emp.Employee_ID)), 12, '0') AS EMPLOYEENO  ,pd.DepartmentDesc  ,emp.PaypointId  ,Cast(pp.PayPointDesc as Varchar(25)) as PayPointLocation  ,PCPD.PeriodEndDate   from Payroll_Employee emp  LEFT JOIN dbo.Payroll_Position pos     ON emp.PositionId = pos.Position_ID  LEFT JOIN dbo.Const_Department pd     ON pd.Department_ID = pos.DepartmentID  LEFT JOIN dbo.Payroll_PayPoint pp      ON emp.PayPointID = pp.PayPoint_ID  LEFT JOIN dbo.Const_Street csPhysical              ON csPhysical.Street_ID = emp.PhysicalStreetID  LEFT JOIN Const_Suburb sub     ON sub.Suburb_ID = emp.PhysicalSuburbID  LEFT JOIN dbo.Const_Town ctPhysical              ON ctPhysical.Town_ID = emp.PhysicalTownID  LEFT JOIN dbo.Payroll_CyclePeriodDetails PCPD              ON PCPD.Period_ID = @PeriodID  LEFT JOIN Const_Bank CB     ON CB.Bank_ID = emp.BankID  LEFT JOIN Const_BankBranchCode BBR     ON BBR.BankBranchCode_ID = emp.BranchID  WHERE Employee_Id = @EmployeeId        END

GO

-- ============================================
-- SP: Payroll_PayslipLeaveDays
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_PayslipLeaveDays]   @EmployeeId int      ,@PeriodEndDate DATETIME  AS  BEGIN            DECLARE @AnnualClassificationId INT = 1     SELECT           SUM(PELB.Balance) + SUM(PELB.Accrued) + SUM(PELB.Forfeit) + SUM(PELB.Taken) + SUM(PELB.Encashed) AS LeaveBalance          ,MIN(PELB.ForfeitDate) AS [ExpireDate]           FROM Payroll_EmployeeLeaveBalance AS PELB      JOIN Const_LeaveType AS CLT ON PELB.LeaveTypeID = CLT.LeaveType_ID AND CLT.LeaveClassificationID = @AnnualClassificationId      WHERE PELB.EmployeeID = @EmployeeId      AND PELB.Enabled = 1    END

GO

-- ============================================
-- SP: Payroll_PayslipMessage
-- Schema: dbo
-- ============================================
/*   Author  : RICHA MILLS   Create date : 2019/02/07   Description : Payslips   Payroll_PayslipMessage     modified by : Modiri Selao   Date  : 2019/05/02   Description : #86750 Wrong message print on the Payslip.       Modified the where clause condition to look at the record with high end date and record is enabled.  */  CREATE PROCEDURE [dbo].[Payroll_PayslipMessage]   @PeriodID INT    AS  BEGIN    DECLARE @PeriodStartDate DATETIME  DECLARE @PeriodEndDate DATETIME    SELECT @PeriodStartDate = PeriodStartDate     ,@PeriodEndDate = PeriodEndDate  FROM Payroll_CyclePeriodDetails  WHERE Period_ID = @PeriodId    SELECT TOP 1 [Message]  FROM Payroll_PayslipMessages  WHERE (StartDate <= @PeriodEndDate AND EndDate >= @PeriodStartDate)   AND [Enabled] = 1  ORDER BY EndDate DESC    END

GO

-- ============================================
-- SP: Payroll_PayslipSpaceRows
-- Schema: dbo
-- ============================================
--Author: Ilya Skavronskiy  --Create date: 2021/02/12  --Description Helper dataset to format PayslipPlainPaper (PayslipPlainPaperWithLogo.rdl)    CREATE PROCEDURE [dbo].[Payroll_PayslipSpaceRows]      @IncomeRowCount INT      ,@CompanyContributionsRowCount INT      ,@DeductionsRowCount INT      ,@ArrearDeductionsRowCount INT      ,@PageSize INT  AS  BEGIN        SET @ArrearDeductionsRowCount = (@ArrearDeductionsRowCount / 2) + (@ArrearDeductionsRowCount % 2)        DECLARE @FillRows INT = 0;        IF @PageSize % (@IncomeRowCount + 2) < @PageSize      BEGIN          SET @FillRows = 2 + @IncomeRowCount      END      ELSE      BEGIN          WHILE @PageSize % (@IncomeRowCount + 2) = @PageSize           BEGIN              SET @IncomeRowCount = @IncomeRowCount - @PageSize + 1              SET @FillRows = @FillRows + @PageSize          END          SET @FillRows = @FillRows + @IncomeRowCount + 2      END          IF @CompanyContributionsRowCount <> 0           BEGIN          IF (@PageSize - (@FillRows % @PageSize)) % (@CompanyContributionsRowCount + 2) < @PageSize - (@FillRows % @PageSize)          BEGIN              SET @FillRows = @FillRows + 2 + @CompanyContributionsRowCount          END          ELSE          BEGIN              IF @PageSize - (@FillRows % @PageSize) < @CompanyContributionsRowCount + 1              BEGIN                  SET @CompanyContributionsRowCount = @CompanyContributionsRowCount - (@PageSize - (@FillRows % @PageSize)) + 1                  SET @FillRows = @FillRows + @PageSize - (@FillRows % @PageSize)              END                WHILE @PageSize % (@CompanyContributionsRowCount + 2) = @PageSize               BEGIN                  SET @CompanyContributionsRowCount = @CompanyContributionsRowCount - @PageSize + 2                  SET @FillRows = @FillRows + @PageSize              END              SET @FillRows = @FillRows + @CompanyContributionsRowCount + 2          END      END          IF (@PageSize - (@FillRows % @PageSize)) % (@DeductionsRowCount + 1) < @PageSize - (@FillRows % @PageSize)      BEGIN          SET @FillRows = @FillRows + 1 + @DeductionsRowCount      END      ELSE      BEGIN          IF @PageSize - (@FillRows % @PageSize) < @DeductionsRowCount + 1          BEGIN              SET @DeductionsRowCount = @DeductionsRowCount - (@PageSize - (@FillRows % @PageSize)) + 1              SET @FillRows = @FillRows + @PageSize - (@FillRows % @PageSize)          END            WHILE @PageSize % (@DeductionsRowCount + 1) = @PageSize           BEGIN              SET @DeductionsRowCount = @DeductionsRowCount - @PageSize + 1              SET @FillRows = @FillRows + @PageSize          END          SET @FillRows = @FillRows + @DeductionsRowCount + 1      END          DECLARE @SpaceRowCount INT = 0      IF (@PageSize - @ArrearDeductionsRowCount - 3) - (@FillRows % @PageSize) <= 0          SET @SpaceRowCount = (@PageSize - (@FillRows % @PageSize)) + @PageSize - @ArrearDeductionsRowCount - 3;      ELSE           SET @SpaceRowCount = @PageSize - ((@FillRows % @PageSize) + 3 + @ArrearDeductionsRowCount);        SELECT TOP(@SpaceRowCount)          '' AS [Row]      FROM sys.syscolumns    END

GO

-- ============================================
-- SP: Payroll_PerformanceAppraisalrpt_sp
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:Varun Parvataneni  -- Create date: 4 April 2016  -- Description: <Description,,>  -- CALLS : Payroll_PerformanceAppraisalrpt_sp '2015/2016',5550,0,0  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PerformanceAppraisalrpt_sp]   @Financial_Year VARCHAR(50),   @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT  AS  BEGIN      SELECT DISTINCT       dbo.BufferString_fxn(CONVERT(VARCHAR, ( PAY_EMP.Employee_ID )), 8,'0') AS EmployeeNumber,       PAY_EMP.Surname as EmployeeSurname,       P_PA.POEmployeeName as EmployeeFullName,       P_PA.JobTitle as JobTitle,       P_PA.IsInterventionRequired as InterventionRequired,       PA_KPI.Weight as Weight,       JPKPI.KeyPerformanceIndicators as KeyPerformanceIndicators,       P_PA.HalfYearReview as HalfYearReview,       P_PA.FinalReview  as FullYearReview,       PA_KPI.HalfYearScore as HalfYearReviewResult,       PA_KPI.FinalScore as FinalYearReviewResult,       JPA.JobProfileArea  as KeyPerformanceArea,       JPA.Percentage as Percentage             FROM Payroll_Employee PAY_EMP    INNER JOIN  Payroll_PerformanceApprisal P_PA       ON PAY_EMP.Employee_ID = P_PA.EmployeeID   LEFT OUTER JOIN Payroll_PerformanceApprisalKPI PA_KPI      ON PA_KPI.PerformanceApprisalID= P_PA.PerformanceApprisal_ID   LEFT OUTER JOIN dbo.Const_JobProfileKPI as JPKPI      ON JPKPI.KPI_Id= PA_KPI.KPIID   LEFT OUTER JOIN Const_JobProfileArea  as JPA      ON JPA.JobProfileArea_ID =JPKPI.JobProfileArea_Id   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = PAY_EMP.PositionID   INNER JOIN dbo.Payroll_JobProfile AS P_JP ON P_JP.JobProfile_ID = PP.JobProfileID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID   LEFT OUTER JOIN dbo.Const_Division AS C_Div ON C_D.Department_ID = C_Div.DepartmentID   WHERE  (PAY_EMP.Employee_ID = @EmployeeID or @EmployeeID =0)--AND PAY_EMP.IsDummy = 0 AND PAY_EMP.Enabled = 1   AND P_PA.TaxYear = @Financial_Year   AND (Department_ID = @DepartmentId OR @DepartmentId = 0)   AND (Division_ID = @DivisionId OR @DivisionId = 0)      END      

GO

-- ============================================
-- SP: Payroll_PerformanceApprisalKPIList
-- Schema: dbo
-- ============================================
-- Call SP:  [Payroll_PerformanceApprisalKPIList] 1  CREATE PROCEDURE [dbo].[Payroll_PerformanceApprisalKPIList]      @PerformanceApprisalID INT  AS       BEGIN          SELECT  PA_KPI.PerformanceApprisalKPI_ID, PA_KPI.PerformanceApprisalID, PA_KPI.KPIID, JPA.JobProfileArea,                   PA_KPI.Weight, PA_KPI.HalfYearRate, PA_KPI.FinalRate, PA_KPI.HalfYearScore, PA_KPI.FinalScore, PA_KPI.Comments, PA_KPI.Enabled, PA_KPI.DateCaptured, PA_KPI.CapturerID, PA_KPI.DateModified, PA_KPI.ModifierID          FROM    Payroll_PerformanceApprisalKPI AS PA_KPI          INNER JOIN dbo.Const_JobProfileKPI AS JPKPI ON PA_KPI.KPIID = JPKPI.KPI_Id                  INNER JOIN Const_JobProfileArea AS JPA ON JPKPI.JobProfileArea_Id = JPA.JobProfileArea_ID          WHERE   PA_KPI.PerformanceApprisalID = @PerformanceApprisalID      END  

GO

-- ============================================
-- SP: Payroll_PerformanceApprisalKPIList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date:  04 SEP 2013  -- Description:    -- Payroll_PerformanceApprisalKPIList_sp 17  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PerformanceApprisalKPIList_sp]   @PerformanceApprisalID INT  AS  BEGIN   SELECT PAY_PER_APP.PerformanceApprisalKPI_ID,       JPKPI.KeyPerformanceIndicators AS KeyPerformanceAreas,       CONST_JOB_AREA.JobProfileArea          FROM Payroll_PerformanceApprisalKPI AS PAY_PER_APP   INNER JOIN dbo.Const_JobProfileKPI AS JPKPI ON PAY_PER_APP.KPIID = JPKPI.KPI_Id   INNER JOIN Const_JobProfileArea CONST_JOB_AREA       ON JPKPI.JobProfileArea_Id = CONST_JOB_AREA.JobProfileArea_ID   WHERE  PAY_PER_APP.PerformanceApprisalID = @PerformanceApprisalID     group by   CONST_JOB_AREA.JobProfileArea,PAY_PER_APP.PerformanceApprisalKPI_ID,       JPKPI.KeyPerformanceIndicators   order by  CONST_JOB_AREA.JobProfileArea      END    

GO

-- ============================================
-- SP: Payroll_PeriodIDfromDate_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Phuti Chokoe  -- Create date: 2016/08/11  -- Description: Get The period_Id from Payroll_cyclePerioddetails for payroll claims  -- =============================================  -- =============================================  -- Author:  Artur Anzorge  -- Create date: 2019/10/09  -- Description: Changes for CycleModeId = 2 for terminated employees  -- =============================================    CREATE proc [dbo].[Payroll_PeriodIDfromDate_sp]  @OverTimeDate datetime, --Declare The EntryDate(The user selects)  @CycleID INT,  @CycleModeID int = 1,  @EmployeeId int = 0  AS  BEGIN  declare @currentPeriodStartDate datetime, --Get The current start and end month(The month we are processing)  @currentPeriodEndDate datetime,  @Period_ID INT   --Temp table so store the period ID  Declare @Results table  (   PeriodID INt  )    if(@CycleModeID = 1)  Begin    select TOP 1 @currentPeriodStartDate=PeriodStartDate, @currentPeriodEndDate=PeriodEndDate, @Period_ID = Period_ID from Payroll_CyclePeriodDetails where CycleID=@CycleID AND CycleModeID=@CycleModeID AND Processed=0  and CycleID is not null-- Get Current Period ID for the unproccesed month    IF (@OverTimeDate >= @currentPeriodStartDate AND @OverTimeDate <= @currentPeriodEndDate) --Date entry is in current month, so return the current Period_ID   Begin    INsert into @Results     select @Period_ID   End   Else if (@OverTimeDate < @currentPeriodStartDate) -- ITs a past date so save the transaction with the current period ID we are currenting proccessing      Begin       INsert into @Results        select @Period_ID    End   ELSe if(@OverTimeDate > @currentPeriodEndDate ) -- ITS a future date so get the future period_ID     Begin     Select @Period_ID=Period_ID from Payroll_CyclePeriodDetails         where @OverTimeDate >= PeriodStartDate AND @OverTimeDate <= PeriodEndDate and CycleID=@CycleID AND CycleModeID=@CycleModeID AND Processed=0 and CycleID is not null     END  End  else if(@CycleModeID = 2)  Begin   select TOP 1 @currentPeriodStartDate= cp.PeriodStartDate, @currentPeriodEndDate= cp.PeriodEndDate, @Period_ID = cp.Period_ID from Payroll_CyclePeriodDetails cp join Payroll_CyclePeriodAdhocEmployee ah on cp.Period_ID = ah.PeriodID    where ah.EmployeeID = @EmployeeId and cp.Enabled = 1 and ah.Enabled = 1 and cp.CycleModeID = @CycleModeID and cp.CycleID = @CycleID  AND cp.Processed=0      IF (@OverTimeDate >= @currentPeriodStartDate AND @OverTimeDate <= @currentPeriodEndDate) --Date entry is in current month, so return the current Period_ID   Begin    INsert into @Results     select @Period_ID   End   Else if (@OverTimeDate < @currentPeriodStartDate) -- ITs a past date so save the transaction with the current period ID we are currenting proccessing      Begin       INsert into @Results        select @Period_ID    End   ELSe if(@OverTimeDate > @currentPeriodEndDate ) -- ITS a future date so get the future period_ID     Begin     Select @Period_ID=Period_ID from Payroll_CyclePeriodDetails         where @OverTimeDate >= PeriodStartDate AND @OverTimeDate <= PeriodEndDate and CycleID=@CycleID AND CycleModeID=@CycleModeID AND Processed=0 and CycleID is not null     END  End      END    select @Period_ID as Period_ID  return

GO

-- ============================================
-- SP: Payroll_Position_SearchCompetency_sp
-- Schema: dbo
-- ============================================
Create PROCEDURE [dbo].[Payroll_Position_SearchCompetency_sp]    -- Add the parameters for the stored procedure here    @CompentencyType int,    @CompentencyRequirement varchar(255),    @CompetencySubType varchar(250),    @MinimumProfeciantcy int,    @Mandatory bit,    @PositionID int   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT CR.PositionCompetency_ID      ,T.CoreCompetencyRequirementTypeDesc      ,D.[CoreCompetencyRequirement]      ,D.[CoreCompetencyRequirementDesc]      ,Case when CR.[Mandatory] = 1 then      'True'      else      'False'      end as IsMandatory      ,P.Name as [MinimumProficiencyLevel]      ,CR.Weighting      ,CR.[CascadeScore]      ,0 as EmployeeCount      ,0 as PositionCount         FROM Payroll_Position_Competency as CR     inner join [dbo].[Const_PMSCoreCompetencyRequirement] as D on D.CoreCompetencyRequirement_ID = CR.CoreCompetencyRequirementID     inner join [dbo].Const_PMSCoreCompetencyRequirementType_sys as T on T.CoreCompetencyRequirementType_ID = D.CoreCompetencyRequirementTypeID     inner join Payroll_MinimumProficiencyLevel as P on P.MinimumProficiencyLevel_ID = CR.MinimumProficiencyLevelID     where (        (T.CoreCompetencyRequirementType_ID = @CompentencyType or @CompentencyType = -1) and       (D.[CoreCompetencyRequirement] = @CompentencyRequirement or @CompentencyRequirement = '-1') and        (P.[MinimumProficiencyLevel_ID] = @MinimumProfeciantcy or @MinimumProfeciantcy = -1) and          (CR.CompetencySubType = @CompetencySubType or @CompetencySubType = '-1') and          (CR.[Mandatory] = @Mandatory or @Mandatory is NULL) and CR.PositionID = @PositionID and D.Enabled = 1            )     order by CR.PositionCompetency_ID desc     END

GO

-- ============================================
-- SP: Payroll_Position_SearchSkills_sp
-- Schema: dbo
-- ============================================
create PROCEDURE [dbo].[Payroll_Position_SearchSkills_sp]    -- Add the parameters for the stored procedure here    @SkillType varchar(255),    @SkillSubType varchar(255),    @JobEssetial bit,    @PositionID int   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT [PositionSkill_ID]       ,[SkillType]       ,[SkillSubType]       ,[Description]       ,Case when [IsMinimumRequirement] = 1 then       'True'       else       'False'       end as MinimumRequirement       ,Case when [IsJobEssential] = 1 then       'True'       else       'False'       end as JobEssential       ,[UseForRecruitement]      FROM [dbo].[Payroll_Position_Skill]     where (        ([SkillType] = @SkillType or @SkillType = '-1') and       ([SkillSubType] = @SkillSubType or @SkillSubType = '-1') and       ([IsJobEssential] = @JobEssetial or @JobEssetial is null) and PositionID = @PositionID     )     order by [PositionSkill_ID] desc     END

GO

-- ============================================
-- SP: Payroll_Position_SearchyQualification
-- Schema: dbo
-- ============================================
CREATE procedure [Payroll_Position_SearchyQualification] @NQFLevel      VARCHAR(250) = null,                 @QualificationTypeID   INT = null,                 @FieldOfStudyID    INT = null,                 @QualificationShortDescription VARCHAR(255) = null,                 @ProfessionalBodyName   VARCHAR(255) = null,                 @UseForRecruitment    VARCHAR(255) = null,                 @IsEducation     BIT = null,                 @IsAccreditation    BIT = null,                 @PositionID     INT = null  as  begin   select [PQ].[QualificationDefinition_ID], (case    when [Q].[IsEducation] = 1 then 'Education'    else (case     when [Q].[IsProfessionalAccreditation] = 1 then 'Accreditation'     else 'N/A' end)    end) as [TypeOfQualification], [Q].[Qualification], [QT].[QualificationTypeName], fos.[Name] as FieldOfStudy, [Q].[QualificationShortCode], [Q].[QualificationShortDescription], [Q].[ProfessionalBodyName], [PQ].[UseForRecruitment]    from [Payroll_Position_QualificationDefinition] as [PQ] with(nolock)     JOIN [Const_Qualification_Sys] as [Q] with(nolock) on [Q].[Qualification_ID] = [PQ].[QualificationID]     LEFT JOIN [dbo].[Payroll_QualificationTypes] qt on qt.QualificationTypeId = q.QualificationTypeID     LEFT JOIN [Payroll_FieldOfStudy] fos ON fos.FieldOfStudy_ID = [Q].FieldOfStudyID    where (     ([Q].[Qualification] = (case when @NQFLevel is null or @NQFLevel = '' then [Q].[Qualification] else @NQFLevel end)) and     ([Q].[QualificationTypeID] = @QualificationTypeID OR @QualificationTypeID < 1) AND     ([Q].[FieldOfStudyID] = @FieldOfStudyID OR @FieldOfStudyID < 1) AND     ([Q].[QualificationShortDescription] = (case when @QualificationShortDescription is null or @QualificationShortDescription = '' then [Q].[QualificationShortDescription] else @QualificationShortDescription end)) and     ([Q].[ProfessionalBodyName] = (case when @ProfessionalBodyName is null or @ProfessionalBodyName = '' then [Q].[ProfessionalBodyName] else @ProfessionalBodyName end)) and     ([PQ].[UseForRecruitment] = (case when @UseForRecruitment is null or @UseForRecruitment = '' then [PQ].[UseForRecruitment] else @UseForRecruitment end)) and     ([Q].[IsEducation] = (case when @IsEducation is null then [Q].[IsEducation] else @IsEducation end)) and     ([Q].[IsProfessionalAccreditation] = (case when @IsAccreditation is null then [Q].[IsProfessionalAccreditation] else @IsAccreditation end)) and     ([PQ].[PositionID] = (case when @PositionID is null then [PQ].[PositionID] else @PositionID end))    )     order by [PQ].[QualificationDefinition_ID] desc  end

GO

-- ============================================
-- SP: Payroll_PositionParentRecords_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author   : Varun Parvataneni  -- Create date: 14/10/2016  -- Description: Records on the Positions baed on ParentID  -- Call SP    : Payroll_PositionParentRecords_sp   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PositionParentRecords_sp]  @ParentID INT   AS  BEGIN     SELECT Position_ID,PositionDesc,pph.StartDate,pph.EndDate,pp.JobProfileID,pph.EmployeeID, t.TaskGradeName gradename,   CASE PPh.Status      WHEN 1 THEN 'Vacant'      WHEN 2 THEN 'Occupied'       WHEN 3 THEN 'Obsolete'    END as Status    from dbo.Payroll_Position as pp   inner join Payroll_PositionHistory pph on pph.PositionID=pp.Position_ID   inner join Payroll_JobProfile pj on pj.JobProfile_ID =pp.JobProfileID   INNER JOIN Payroll_TaskGrade T on T.TaskGrade_ID = pj.TaskGradeId   WHERE PPh.PositionID = @ParentID      END    

GO

-- ============================================
-- SP: Payroll_PreloadedPayrollDefinitionDetailAddByGroupId
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Mehul Panchal  -- Create date: 17 Jan 2014  -- Description: Payroll Definition Details Preloaded insert when Payroll Definition Group Create  -- 2015-05-13 James Roodt: TP19577: Changed flag used for checking from CalculationFlag=2 to IsPredefine=1  -- 2015-05-13 James Rodot: TP19577: Changed stored proc completely to actually add/update the built in rules  -- 2016-01-29 Suri Kandukuri: TP30237 : Modified SCOAFunctionCodeID from Default to Selection in Screen.  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_PreloadedPayrollDefinitionDetailAddByGroupId]      @PayrollDefinitionGroupID INT ,      @UserId INT   --@SCOAFunctionCodeIDForGroup INT  AS       BEGIN    DECLARE @COUNT INT ,          @START INT      DECLARE @SalaryHead_ID int,      @IsRFI bit,      --@ActivityID int,      @DefinitionExists int,      @DefinitionIdentical int      --@SCOACostingCode int,      --@SCOAFundCode int,      --@SCOAProjectCode int,      --@SCOARegionCode int,      --@SCOAFunctionCode int      DECLARE @PredefinedSH TABLE    (     ID INT IDENTITY(1, 1) PRIMARY KEY ,     SalaryHead_ID int,     IsRFI bit    )      INSERT INTO @PredefinedSH (SalaryHead_ID, IsRFI)    SELECT  SalaryHead_ID, IsRFI          FROM    dbo.Payroll_SalaryHead SH      SET @START = 1    SELECT @COUNT=count(*) FROM @PredefinedSH      WHILE ( @START < ( @COUNT + 1 ) )     BEGIN       SELECT  @SalaryHead_ID = SalaryHead_ID, @IsRFI=IsRFI        FROM    @PredefinedSH        WHERE   ID = @START         SELECT @DefinitionIdentical=count(*) FROM Payroll_PayrollDefination     WHERE PayrollSalaryHeadID=@SalaryHead_ID     AND PayrollDefinitionGroupID =@PayrollDefinitionGroupID     AND IsRFI=@IsRFI       IF(@DefinitionIdentical>0)     BEGIN      --Nothing need sot be done as it is already Correct      set @START=@START     END     ELSE     BEGIN      SELECT @DefinitionExists=count(*) FROM Payroll_PayrollDefination      WHERE PayrollSalaryHeadID=@SalaryHead_ID      AND PayrollDefinitionGroupID =@PayrollDefinitionGroupID        IF(@DefinitionExists>0)      BEGIN       UPDATE Payroll_PayrollDefination       SET IsRFI=@IsRFI,        [Enabled]=1,        Percentage=100.00,        DateModified=GETDATE(),        ModifierID=@UserId       WHERE PayrollSalaryHeadID=@SalaryHead_ID       AND PayrollDefinitionGroupID =@PayrollDefinitionGroupID      END      ELSE      BEGIN       INSERT INTO dbo.Payroll_PayrollDefination ( PayrollDefinitionGroupID, PayrollSalaryHeadID, Percentage, IsRFI, Enabled, DateCaptured, CapturerID)       VALUES(@PayrollDefinitionGroupID, @SalaryHead_ID, 100.00, @IsRFI, 1, GETDATE(), @UserId)      END     END       SET @START = @START + 1      END        END  

GO

-- ============================================
-- SP: Payroll_PresentDaysCountOtherCycle_Trial_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 20/07/2013  -- Description: Employee Present Days Count in Other Cycle  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_PresentDaysCountOtherCycle_Trial_sp]   @EmployeeID INT,   @FinanceYear NVARCHAR(10),   @FromDate DATETIME,   @ToDate DATETIME,   @Month INT,   @TotalDays INT OUTPUT,   @WorkedDays INT OUTPUT  AS  BEGIN   SET NOCOUNT ON;      DECLARE @Day NVARCHAR(10)      DECLARE @TotalNoTotal INT   SET @TotalNoTotal = 0   DECLARE @QueryTotal NVARCHAR(MAX)   DECLARE @SQLQueryTotal NVARCHAR(MAX)      DECLARE @TotalNoWorked INT   SET @TotalNoWorked = 0   DECLARE @QueryWorked NVARCHAR(MAX)   DECLARE @SQLQueryWorked NVARCHAR(MAX)      While(@FromDate < DATEADD(DAY,1,@ToDate))   BEGIN     SET @Day = DAY(@FromDate)    SET @FromDate = DATEADD(DAY, 1, @FromDate)        SET @QueryWorked = N' @RowCountWorked nvarchar(50) OUTPUT '    SET @SQLQueryWorked = 'SELECT  @RowCountWorked = ISNULL(COUNT(1),0) FROM Payroll_EmployeeAttendance WHERE ([' + @DAY + '] = ''P'' OR [' + @DAY + '] = ''WO'' OR [' + @DAY + '] = ''H'')        AND MONTH =' + CONVERT(NVARCHAR,@Month) + ' AND EMPLOYEEID = ' + CONVERT(NVARCHAR,@EmployeeID ) + ' AND TaxYear = ''' + @FinanceYear + ''''      EXEC SP_EXECUTESQL @SQLQueryWorked, @QueryWorked, @RowCountWorked = @TotalNoWorked OUTPUT        IF @TotalNoWorked > 0    BEGIN     SET @WorkedDays = @WorkedDays + 1    END        SET @QueryTotal = N' @RowCountTotal nvarchar(50) OUTPUT '    SET @SQLQueryTotal = 'SELECT  @RowCountTotal = ISNULL(COUNT(1),0) FROM Payroll_EmployeeAttendance WHERE ([' + @DAY + '] = ''P'' OR [' + @DAY + '] = ''WO'' OR [' + @DAY + '] = ''H'')        AND MONTH =' + CONVERT(NVARCHAR,@Month) + ' AND EMPLOYEEID = ' + CONVERT(NVARCHAR,@EmployeeID ) + ' AND TaxYear = ''' + @FinanceYear + ''''      EXEC SP_EXECUTESQL @SQLQueryTotal, @QueryTotal, @RowCountTotal = @TotalNoTotal OUTPUT        IF @TotalNoTotal > 0    BEGIN     SET @TotalDays = @TotalDays + 1    END   END      --SELECT @SalaryDays AS SalaryDays   RETURN @TotalDays   RETURN @WorkedDays   SET NOCOUNT OFF      PRINT 'Payroll_PresentDaysCountOtherCycle_Trial_sp  - DONE'   END  

GO

-- ============================================
-- SP: Payroll_PresentDaysCountOtherCycle_Ver2_Trial_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 20/07/2013  -- Description: Employee Present Days Count in Other Cycle  -- =============================================  Create PROCEDURE [dbo].[Payroll_PresentDaysCountOtherCycle_Ver2_Trial_sp]   @EmployeeID INT,   @PeriodID Int,   @TotalDays INT OUTPUT,   @WorkedDays INT OUTPUT  AS  BEGIN   SET NOCOUNT ON;      select  @WorkedDays =Count(T1.DayIndicator) , @TotalDays = Max(DatePart(Day,P.PeriodEndDate)) from (   select [1] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [2] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [3] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [4] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [5] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [6] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [7] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [8] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [9] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [10] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [11] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [12] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [13] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [14] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [15] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [16] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [17] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [18] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [19] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [20] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [21] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [22] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [23] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [24] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [25] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [26] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [27] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [28] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [29] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [30] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       Inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate) Union All    select [31] as DayIndicator ,EmployeeID  from Payroll_EmployeeAttendance as EA       inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where (EA.EmployeeID = @EmployeeID ) and EA.TaxYear = P.TaxYear and EA.[Month] = DatePart(Month, P.PeriodStartDate)) as T1       inner join Payroll_CyclePeriodDetails as P on P.Period_ID = @PeriodID       where T1.DayIndicator in('H','P','L')       group by T1.EmployeeID      --SELECT @SalaryDays AS SalaryDays     SET NOCOUNT OFF      PRINT 'Payroll_PresentDaysCountOtherCycle_Trial_sp  - DONE'   END  

GO

-- ============================================
-- SP: Payroll_PreTerminationEmployeeAdHocPayrollDefinitions_sp
-- Schema: dbo
-- ============================================
-- ======================================================================================================  -- Author: Lukasz Rakowski  -- Create date: 19/08/2019      -- dodanie left join zamiast join do tabeli [Payroll_EmployeeTrialPayslipSimulation]  -- ======================================================================================================  CREATE procedure [dbo].[Payroll_PreTerminationEmployeeAdHocPayrollDefinitions_sp] @PeriodId int, @EmployeeId int, @TerminationId int  as    begin     set nocount on;     declare @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))      declare @results table (      [EmployeePayrollDefinition_ID] int,    [TransactionType] nvarchar(50),    [SalaryHeadID] INT,    [SalaryHeadTitle] nvarchar(max),    [PayrollSalaryHeadName] nvarchar(max),    [FunctionNumber] nvarchar(50),    [Percentage] decimal(18, 2),    [TransactionTypeID] int,    [Amount] decimal(18, 2),    [Pensionable] nvarchar(10),    [Taxable] nvarchar(10),    [TaxablePercentage] decimal(18, 2),    [IRP5Code] nvarchar(10),    [PeriodID] int,    [Flag] nvarchar(10),    [IRP5CodeDesc] nvarchar(max),    [IRP5CodeId] int   )        declare @CycleID int = (select [CycleID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle],  [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc], [IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], isnull([Value], 0), (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Trial', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         left outer join [Payroll_EmployeeTrialPayslipSimulation] as [TP] with(nolock) on [TP].[SalaryHeadID] = [SH].[SalaryHead_ID] and [TP].[EmployeeID] = @EmployeeId        where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID )      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle],  [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc], [IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], 0, (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Trial', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1          where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID and not [EmployeePayrollDefinition_ID] in (          select [EmployeePayrollDefinition_ID] from @results            )        )        select [EmployeePayrollDefinition_ID], [TransactionType] as TransactionTypeDesc, res.SalaryHeadID, res.[SalaryHeadTitle], res.[PayrollSalaryHeadName], res.[IRP5CodeId], res.[IRP5CodeDesc], res.[SalaryHeadTitle] as SalaryHeadName, [TransactionTypeID] as TransactionType_ID, sum(cast(isnull([res].[Amount], 0) as decimal(18,2))) as [Amount], res.[IRP5Code], cast(isnull(tab.CyclePeriodAdhocPayrollDefinition_ID, 0) as int) as CyclePeriodAdhocPayrollDefinition_ID      from @results as res left join     (      SELECT [AHSH].CyclePeriodAdhocPayrollDefinition_ID,        [AHSH].[SalaryHeadID],        [SH].[SalaryHeadName],        [SH].[SalaryHeadTitle],        [SH].[IRP5CodeId],        [IRP5].[IRP5CodeDesc],        cast(isnull([IRP5CertCode],        [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc] as [PayrollSalaryHeadName],        [TransactionType_ID],        [TransactionTypeDesc],        cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) as [IRP5Code],       [AHSH].[PeriodID]         FROM Payroll_CyclePeriodAdhocSalaryHead [AHSH] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [AHSH].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         where [AHSH].[PeriodID] = @PeriodID and [AHSH].[Enabled] = 1      ) as tab on tab.PeriodID = res.PeriodID and tab.SalaryHeadID = res.SalaryHeadID     group by [EmployeePayrollDefinition_ID], [TransactionType], res.SalaryHeadID,res.[SalaryHeadTitle], res.[PayrollSalaryHeadName], res.[IRP5CodeId], res.[IRP5CodeDesc], [TransactionTypeID], res.[IRP5Code], tab.CyclePeriodAdhocPayrollDefinition_ID      order by [IRP5Code]       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_ProcessAA88TransactionDetail_SP
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Tshekedi Mogwere  -- Create date: 23/05/2017  -- Description: Create a stub Proc till all the logic is written - Process the AATransaction Details into Payroll_CostCenter tables  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_ProcessAA88TransactionDetail_SP]   @TransactionId INT,   @CapturedId INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here     UPDATE Payroll_AA88TransactionDetail   set EmployeeID = E.Employee_Id   FROM Payroll_AA88TransactionDetail AA WITH(NOLOCK)   INNER JOIN Payroll_Employee E WITH(NOLOCK) ON E.IdNo = AA.IdentityNumber   WHERE AA.EmployeeID = 0 OR AA.EmployeeID IS NULL     -- Now Update Cost Centre Table     DECLARE @UnProcessedAA88Deductions TABLE   (    TransactionDetailId INT,    EmployeeId INT,    StartDate DATETIME,    EndDate DateTime,    MonthlyDeduction DECIMAL   )     INSERT INTO @UnProcessedAA88Deductions   SELECT AA.TransactionDetailId, AA.EmployeeId, AA.AA88StartDate,  AA.AA88EndDate, AA.AA88MonthlyDeduction    FROM Payroll_AA88TransactionDetail AA WITH(NOLOCK)      LEFT JOIN Payroll_CostCenter C WITH(NOLOCK) ON C.EmployeeID = AA.EmployeeId AND AA.AA88StartDate != C.EffectiveDate AND AA.AA88EndDate != C.EndDate    WHERE AA88MonthlyDeduction > 0        DECLARE @DefinationId INT   DECLARE @municipalityId INT   declare @TaxYear NVARCHAR(13)   declare @FinancialYear NVARCHAR(13)     SELECT @municipalityId = Municipality_Id FROM Payroll_Municipality     SELECT @TaxYear = KeyValue from AAAA_ConfigSettings where KeyName  = 'TaxYear'   SELECT @FinancialYear = KeyValue from AAAA_ConfigSettings where KeyName  = 'TaxYear'     SELECT @DefinationId = 1 FROM Payroll_PayrollDefination D WITH(NOLOCK)   INNER JOIN Payroll_SalaryHead S WITH(NOLOCK) ON S.SalaryHead_ID = D.PayrollSalaryHeadID   WHERE S.SalaryHeadName = 'Pay-as-you-earn (PAYE: Tax Over Deduction)'    INSERT INTO [dbo].[Payroll_CostCenter]             ([PayrollDefinationID]             ,[EmployeeID]             ,[CostAmount]             ,[CostDesc]             ,[EntryDate]             ,[MunicipalityID]             ,[FinancialYear]             ,[Enabled]             ,[DateCaptured]             ,[CapturerID]                      ,[EarDedTypeId]                       ,[PeriodID]             ,[TaxYear]             ,[IsApproved]                        ,[IsApprovalRequired]                       ,[RunEveryMonth]           ,[TaxableAmount]       ,[Rate]                  ,[EffectiveDate]             ,[EndDate]             )      SELECT  @DefinationId   ,EmployeeID             ,MonthlyDeduction             ,'AA88 Deductions'             ,GETDATE()             ,@municipalityId             ,@FinancialYear             ,1             ,GETDATE()             ,@CapturedId                       ,2             ,2 -- Period             ,@TaxYear             ,1                       ,0                        ,0                       ,MonthlyDeduction             , MonthlyDeduction             ,StartDate             ,EndDate               FROM @UnProcessedAA88Deductions  END

GO

-- ============================================
-- SP: Payroll_ProcessBargainingCouncilAgreementIncrease
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Ilya Skavronskiy  -- Create date: 2020-07-09  -- Description: Updates MinSalary and MaxSalary of task grades and notches according to Bargaining Council Agreement Increase  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_ProcessBargainingCouncilAgreementIncrease]  AS  BEGIN     DECLARE @dateValue VARCHAR(10) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] WHERE ([KeyName] = 'PayrollSchedulerDate'))     DECLARE @dateYear INT = CAST(RIGHT(@dateValue, 4) AS INT),     @dateMonth INT = CAST(RIGHT(LEFT(@dateValue, 5), 2) AS INT),     @dateDay INT = CAST(LEFT(@dateValue, 2) AS INT)     DECLARE @date VARCHAR(19) = CONVERT(NVARCHAR(19), DATEFROMPARTS(@dateYear, @dateMonth, @dateDay), 120)     -- update task grades    UPDATE TG   SET    MinSalary = UpdatedSalary.NewMinSalary,    MaxSalary = UpdatedSalary.NewMaxSalary,    DateModified = GETDATE(),     ModifierID = 1   FROM Payroll_TaskGrade AS TG WITH(NOLOCK)   CROSS JOIN (SELECT TOP 1 * FROM Payroll_BargainingCouncil) AS BC   CROSS APPLY (    SELECT     ROUND((TG.MinSalary * (BC.Y1IncreasePerc / 100 + 1)) / BC.RoundAmount, 0) * BC.RoundAmount AS NewMinSalary,     ROUND((TG.MaxSalary * (BC.Y1IncreasePerc / 100 + 1)) / BC.RoundAmount, 0) * BC.RoundAmount AS NewMaxSalary   ) UpdatedSalary   WHERE BC.Y1IncreaseDate <= @date    AND TG.MinSalary < UpdatedSalary.NewMinSalary    AND TG.MaxSalary < UpdatedSalary.NewMaxSalary     --update notches   UPDATE N   SET     MinimumSalary = BCI.Y1IncreaseAmount,     MaximumSalary = BCI.Y1IncreaseMaxAmount,     FixedSalary_Monthly = BCI.Y1IncreaseAmount,     DateModified = GETDATE(),     ModifierID = 1   FROM Payroll_BargainingCouncilIncrease AS BCI WITH(NOLOCK)   JOIN Payroll_TaskGrade AS TG WITH(NOLOCK) ON [BCI].[TaskGradeid] = [TG].[TaskGrade_ID]   JOIN Payroll_Notch AS N WITH(NOLOCK) ON BCI.Notch = N.Notch AND BCI.TaskGradeID = N.TaskGradeId   WHERE BCI.[Enable] = 1 AND N.[Enabled] = 1     AND BCI.Y1IncreaseDate <= @date    AND N.MinimumSalary < BCI.Y1IncreaseAmount     AND N.MaximumSalary < BCI.Y1IncreaseMaxAmount    END

GO

-- ============================================
-- SP: Payroll_ProfileGroupDetailsByProfile_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- call: exec [Payroll_ProfileGroupDetailsByProfile_sp] 1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_ProfileGroupDetailsByProfile_sp]    @ProfileGroup_ID int   AS  BEGIN   SELECT      PG.ProfileGroup_ID,PG.ProfileGroupDesc, PSG.ProfileSubGroupDesc, PSG.ProfileSubGroup_ID,     CS.ShifName, PSG.OfficeBound, PSG.AllowOverTime, PSG.ExcludeTDSDeduction, JP.JobTitle,     /*     PGD.Grade,     PGD.WHPD_Other ,PGD.WDPW_Other ,PGD.RPD_Other ,PGD.RPH_Other ,PGD.RPW_Other ,PGD.WHPM_Monthly,     PGD.WDPM_Monthly ,PGD.WHPD_Monthly ,PGD.RPD_Monthly ,PGD.RPH_Monthly ,      */P_N.MonthlySalary,     P_N.Notch_ID, P_N.Enabled    FROM Const_ProfileGroup PG    INNER JOIN Const_ProfileSubGroup PSG ON PSG.ProfileGroup_ID =PG.ProfileGroup_ID    INNER JOIN Payroll_Notch P_N ON P_N.Notch_ID =PSG.ProfileSubGroup_ID    INNER JOIN Const_Shift CS ON CS.Shift_ID =PSG.ShiftID     INNER JOIN Payroll_JobProfile JP ON JP.JobProfile_ID =PSG.JobProfileID   WHERE P_N.Enabled = 1 and PG.ProfileGroup_ID = @ProfileGroup_ID   END

GO

-- ============================================
-- SP: Payroll_ProfileGroupDetailslst_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- call: [Payroll_ProfileGroupDetailslst_sp] 29,0,0    -- call: [Payroll_ProfileGroupDetailslst_sp] 0,0,0    -- call: [Payroll_ProfileGroupDetailslst_sp] 4,1,1  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_ProfileGroupDetailslst_sp]    @ProfileGroup_ID int    ,@ProfileSubGroup_ID int    ,@JobTitleID int   AS  BEGIN         SELECT DISTINCT      PG.ProfileGroup_ID,      CASE WHEN PG.ProfileGroupDesc IS NULL THEN '' ELSE PG.ProfileGroupDesc END AS ProfileGroupDesc,      CASE WHEN PSG.ProfileSubGroupDesc IS NULL THEN '' ELSE PSG.ProfileSubGroupDesc END AS ProfileSubGroupDesc,      CASE WHEN JP.JobTitle IS NULL THEN '' ELSE JP.JobTitle END AS JobTitle          FROM Const_ProfileGroup PG     LEFT OUTER JOIN Const_ProfileSubGroup PSG      ON PSG.ProfileGroup_ID =PG.ProfileGroup_ID     --LEFT OUTER JOIN Const_ProfileGroupDetails PGD     -- ON PGD.ProfileSubGroupID =PSG.ProfileSubGroup_ID     LEFT OUTER JOIN Payroll_JobProfile JP      ON JP.JobProfile_ID =PSG.JobProfileID    WHERE     --PGD.Enabled = 1 and     (PG.ProfileGroup_ID = @ProfileGroup_ID OR @ProfileGroup_ID =0)  and     (PSG.ProfileSubGroup_ID=@ProfileSubGroup_ID OR @ProfileSubGroup_ID =0)    and (PSG.JobProfileID =@JobTitleID OR @JobTitleID =0)  END    

GO

-- ============================================
-- SP: Payroll_ProfileSubGroupDetailsByProfile_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- call: [Payroll_ProfileSubGroupDetailsByProfile_sp] 16  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_ProfileSubGroupDetailsByProfile_sp]   @ProfileGroup_ID int      AS  BEGIN   SELECT      PG.ProfileGroup_ID,PG.ProfileGroupDesc    ,PSG.ProfileSubGroupDesc,PSG.ProfileSubGroup_ID,CS.ShifName,PSG.OfficeBound    ,PSG.AllowOverTime,PSG.ExcludeTDSDeduction,    PSG.Enabled    ,JP.JobTitle    ,'' as CycleDesc --Cycle.CycleDesc    ,Department.DepartmentDesc AS DepartmentDesc    ,Division.DivisionDesc AS DivisionDesc    ,DefinitionGroup.PayrollDefinitionGroupName    FROM  Const_ProfileSubGroup  PSG    INNER JOIN Const_ProfileGroup  PG ON PSG.ProfileGroup_ID =PG.ProfileGroup_ID    INNER JOIN Const_Shift CS ON CS.Shift_ID =PSG.ShiftID     INNER JOIN Payroll_JobProfile JP ON JP.JobProfile_ID = PSG.JobProfileID    --INNER JOIN dbo.Const_Cycle Cycle ON Cycle.Cycle_ID =  PSG.CycleID    INNER JOIN dbo.Const_Department Department ON Department.Department_ID = PSG.DepartmentID    INNER JOIN dbo.Const_Division Division ON Division.Division_ID = PSG.DivisionID    INNER JOIN dbo.Payroll_DefinitionGroup DefinitionGroup ON DefinitionGroup.PayrollDefinitionGroup_ID =  PSG.ProfileGroupID   WHERE  PSG.ProfileGroup_ID = @ProfileGroup_ID   END    select * from Const_ProfileSubGroup  

