-- ============================================
-- SP: Payroll_ProspectiveEmployeePayrollDefinitions_sp
-- Schema: dbo
-- ============================================
  -- ======================================================================================================  -- Author: MEHUL PANCHAL    -- Create date: 28 JAN 2014    -- Description: GET PAYROLL LIST     -- Execute [Payroll_EmployeePayrollDefinationlst_sp] 00000015    -- 2015-12-22 : Suri Kandukuri : TP29886 Added Enabled Condition for Salary Head.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-04-08 TP34966 James Roodt: Added ActiveTaxYear to where clause  -- 2016-06-14 TP37484 Seipei Mathole: Changed Inner join to Left join on CSS.ScoaID = PAY_DEF.SCOAItemID   -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2016-12-07 TP48989 - remove Commission and VAT on Commission  -- Update date : 12/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings  -- ======================================================================================================  create procedure [Payroll_ProspectiveEmployeePayrollDefinitions_sp] @EmployeeID int  as    begin     set nocount on;     declare @TrailRunCount int = 0,     /*@CommID int = (select [SalaryHead_ID] from [Payroll_SalaryHead] where ([SalaryHeadTitle] = 'Commission Earned')),     @VatCommID int = (select [SalaryHead_ID] from [Payroll_SalaryHead] where ([SalaryHeadTitle] = 'Tax on Commission Earned')),*/     @CycleID int = (select [CycleID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))     declare @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))     declare @PeriodID int = (select top 1 [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = @CycleID and [TaxYear] = @ActiveTaxYear) order by [Period_ID] asc)     select @TrailRunCount = 1 from [Payroll_EmployeeTrialPayslip] where ([PeriodID] = @PeriodID and [EmployeeID] = @EmployeeID)     declare @results table (        [EmployeePayrollDefinition_ID] int,    [TransactionType] nvarchar(50),    [SalaryHeadID] INT,    [SalaryHeadTitle] nvarchar(max),    [PayrollSalaryHeadName] nvarchar(max),    [FunctionNumber] nvarchar(50),    [Percentage] decimal(18, 2),    [TransactionTypeID] int,    [Amount] decimal(18, 2),    [Pensionable] nvarchar(10),    [Taxable] nvarchar(10),    [TaxablePercentage] decimal(18, 2),    [IRP5Code] nvarchar(10),    [PeriodID] int,    [Flag] nvarchar(10)     )     if (@TrailRunCount > 0)   begin      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID],[SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], 0/*isnull([Amount], 0)*/, (case when [EPD].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), 0/*isnull([PeriodID], @PeriodID)*/, 'Trial'        from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1/* and not [SalaryHead_ID] in(@CommID, @VatCommID)*/         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         /*left outer join [Payroll_EmployeeTrialPayslip] as [TP] with(nolock) on [TP].[PayrollDefinationID] = [EPD].[EmployeePayrollDefinition_ID] and [TP].[PeriodID] = @PeriodID*/        where ([EPD].[Enabled] = 1 and [EPD].[ProspectiveEmployeeID] = @EmployeeID/* and [TaxSavePurpose] = 0*/)     end   else   begin      select top 1 @PeriodID = [Period_ID] from [Payroll_CyclePeriodDetails] where ([Processed] = 0 and [ProcessedDate] is null and [CycleID] = @CycleID) order by [Period_ID] desc      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], 0/*isnull([Amount], 0)*/, (case when [EPD].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), 0/*isnull([PeriodID], @PeriodID)*/, 'Final'        from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1/* and not [SalaryHead_ID] in(@CommID, @VatCommID)*/         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         /*left outer join [Payroll_EmployeePayslip] as [TP] with(nolock) on [TP].[PayrollDefinationID] = [EPD].[EmployeePayrollDefinition_ID] and [TP].[PeriodID] = @PeriodID*/        where ([EPD].[Enabled] = 1 and [EPD].[ProspectiveEmployeeID] = @EmployeeID/* and [TaxSavePurpose] = 0*/)     end       select [EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], sum([Amount]) as [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag]      from @results     group by [EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadTitle], [PayrollSalaryHeadName], [FunctionNumber], [Percentage], [TransactionTypeID], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag]      order by [IRP5Code]     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_Provision_Leave_Calculate_Rpt_Results_sp
-- Schema: dbo
-- ============================================
--EXEC Payroll_Provision_Leave_Calculate_Rpt_Results_sp '2016/2017', 1    CREATE PROCEDURE [dbo].[Payroll_Provision_Leave_Calculate_Rpt_Results_sp]  (    @FinYearEnd VARCHAR(50),  @PercentageIncrease DECIMAL(18,2)    )  AS    BEGIN            DECLARE @TBL AS TABLE    (    EmployeeId INT,      Surname NVARCHAR(50),    FirstName NVARCHAR(50),     RPD_Monthly DECIMAL(18,2),    SalaryIncrease DECIMAL(18,2),    NewRatePerDay DECIMAL(18,2),    PercentageIncrease DECIMAL(18,2),    FinancialYear NVARCHAR(9),    LeaveDays DECIMAL(18,2),    Provision DECIMAL(18,2)    )    INSERT INTO @TBL  SELECT            e.Employee_ID,      e.Surname,     e.FirstName,      e.RPD_Monthly AS CurrentRatePerDay,     ROUND(((e.FixedSalary * @PercentageIncrease) / cast(100 as float) + e.FixedSalary),2) AS SalaryIncrease,      ROUND((e.RPD_Monthly * @PercentageIncrease / cast(100 as float) + e.RPD_Monthly),2) AS NewRatePerDay,         @PercentageIncrease AS PercentageIncrease, @FinYearEnd AS FinancialYear,              ISNULL((AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave), 0.0)  AS 'Leave Days',                  CASE               WHEN  ISNULL((AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave), 0)  > 48 THEN                                  ROUND((e.RPD_Monthly * @PercentageIncrease / cast(100 as float) + e.RPD_Monthly),2) * 48                ELSE                                           ROUND((e.RPD_Monthly * @PercentageIncrease / cast(100 as float) + e.RPD_Monthly),2) * ISNULL((AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave), 0)                      END AS Provision               FROM                   [dbo].[Payroll_EmployeeLeaveSchemeTransaction] p                  INNER JOIN payroll_employee e on p.EmployeeId =e.Employee_ID                   INNER JOIN Const_LeaveScheme AS ls ON e.LeaveSchemeID=ls.LeaveScheme_ID and ls.enabled=1                  INNER JOIN Const_LeaveSchemeTypeDetails AS stlt on stlt.LeaveSchemeId=ls.LeaveScheme_ID                  INNER JOIN Const_LeaveType AS lt on lt.LeaveType_ID=p.LeaveTypeId and lt.enabled=1                  INNER JOIN Const_LeaveClassification_sys AS lc on lt.LeaveClassificationID = lc.LeaveClassification_ID                  INNER join const_leavetypedetails as ltd on ltd.LeaveTypeId=lt.LeaveType_ID and ltd.enabled=1       WHERE               lt.LeaveClassificationID in (1)      AND e.Enabled=1      AND ltd.commitment=1         AND p.TranDate <= SUBSTRING(@FinYearEnd,charindex('/', @FinYearEnd)+1,4)+ '-' + '06' + '-' + '30'                     GROUP BY                   e.Employee_ID,e.Surname,e.FirstName,e.RPD_Monthly,FixedSalary,AccrualLeave,TakenLeave,ForfeitLeave,EncashLeave,AdjustedLeave         HAVING                 ISNULL((AccrualLeave - TakenLeave - ForfeitLeave - EncashLeave + AdjustedLeave), 0) > 0    ORDER BY e.Employee_ID       SELECT EmployeeId AS Employee_ID, Surname, FirstName, RPD_Monthly AS CurrentRatePerDay,SalaryIncrease,NewRatePerDay,@PercentageIncrease AS PercentageIncrease,SUM(ISNULL(LeaveDays,0)) as 'Leave Days', @FinYearEnd AS FinancialYear, SUM(ISNULL(Provision,0)) As Provision        FROM @TBL     GROUP BY EmployeeId,Surname,FirstName,RPD_Monthly,SalaryIncrease,NewRatePerDay,PercentageIncrease,FinancialYear      END  

GO

-- ============================================
-- SP: Payroll_ProvisionReportEmployeeTypeLink_sp
-- Schema: dbo
-- ============================================
        -- =============================================    -- Author:  Seipei Mathole  -- Create date: 02 March 2016  -- Description: Returns the Provision Report Employee Types for a given Employee  --  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_ProvisionReportEmployeeTypeLink_sp]     @ProvisionReport_ID int    AS    BEGIN        SELECT            ET.ProvisionReportEmployeeType_ID,      ET.Enabled,      E.EmployeeType_ID,     E.EmployeeTypeDescription,     ET.DateCaptured,      ET.CapturerID,      ET.DateModified,      ET.ModifierID         FROM  Payroll_ProvisionReportEmployeeTypeLinkTable ET         INNER JOIN Const_EmployeeType_sys E         ON ET.EmployeeTypeID = E.EmployeeType_ID     WHERE ET.ProvisionReportID = @ProvisionReport_ID    END  

GO

-- ============================================
-- SP: Payroll_ProvisionReportPayrollCycleTypeLink_sp
-- Schema: dbo
-- ============================================
        -- =============================================    -- Author:  Seipei Mathole  -- Create date: 03 March 2016  -- Description: Returns the Provision Report Payroll Cycle  --  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_ProvisionReportPayrollCycleTypeLink_sp]     @ProvisionReport_ID int    AS    BEGIN         SELECT     PP.ProvisionReportPayrollCycle_ID,     PP.Enabled,     CC.Cycle_ID,     CC.CycleDesc,     PP.DateCreated,     PP.CapturerID,     PP.DateModified,     PP.ModifierID              FROM Payroll_ProvisionReportPayrollCycleLinkTable PP     INNER JOIN Const_Cycle CC     ON PP.CycleID = CC.Cycle_ID     WHERE PP.ProvisionReportID = @ProvisionReport_ID    END    

GO

-- ============================================
-- SP: Payroll_Remuneration_cash_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_Remuneration_cash_rpt 0, 0, 0, 99  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  --  Update date : 17/09/19 - SP did not cater for R100 notes - Richa Mills  -- =============================================  CREATE procedure [dbo].[Payroll_Remuneration_cash_rpt]   @EmployeeId INT,   @DepartmentId INT,   @PaymentId INT,   @PeriodId INT  AS  BEGIN     DECLARE @Amount DECIMAL(18, 2), @Total DECIMAL(18, 2)   DECLARE @Result TABLE(R200 INT, R100 INT, R50 INT, R20 INT, R10 INT, R5 INT, R2 INT, R1 INT, C50 INT, C20 INT, C10 INT, Total DECIMAL(18, 2))   DECLARE @Final_Result TABLE (Currency VARCHAR(50), NoOfNote INT, Total DECIMAL(18, 2))   DECLARE @Emp TABLE (EmployeeId INT, Amount DECIMAL(18, 2), Flag BIT)   INSERT INTO @Emp ( EmployeeId, Amount, Flag )   SELECT Employee_Id, SUM(CASE WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1 ELSE P_EPS.Amount END) AS NetPay, 0--, P_IRP5.TransactionTypeID    FROM dbo.Payroll_EmployeePayslip AS P_EPS   INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS P_EPD ON P_EPS.PayrollDefinationID = P_EPD.EmployeePayrollDefinition_ID   INNER JOIN dbo.Payroll_SalaryHead AS P_SH ON P_EPD.PayrollSalaryHeadID = P_SH.SalaryHead_ID   INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID   INNER JOIN dbo.Payroll_Employee AS P_E ON P_E.Employee_ID = P_EPS.EmployeeID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID   WHERE P_IRP5.TransactionTypeID IN (1,2) AND P_EPS.PeriodID = @PeriodId AND (P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0)   AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND (PaymentTypeID = 3) AND TaxSavePurpose = 0   GROUP BY P_E.Employee_ID      DECLARE @R200 INT = 0, @R100 INT = 0, @R50 INT = 0, @R20 INT = 0, @R10 INT = 0, @R5 INT = 0, @R2 INT = 0, @R1 INT = 0   DECLARE @C50 INT = 0, @C20 INT = 0, @C10 INT = 0      WHILE EXISTS (SELECT * FROM @Emp WHERE Flag = 0) BEGIN    SELECT TOP 1 @EmployeeId = EmployeeId, @Amount = Amount, @Total = Amount FROM @Emp WHERE Flag = 0        SELECT @R200 = @Amount / 200, @Amount = @Amount % 200    SELECT @R100 = @Amount / 100, @Amount = @Amount % 100    SELECT @R50 = @Amount / 50, @Amount = @Amount % 50    SELECT @R20 = @Amount / 20, @Amount = @Amount % 20    SELECT @R10 = @Amount / 10, @Amount = @Amount % 10    SELECT @R5 = @Amount / 5, @Amount = @Amount % 5    SELECT @R2 = @Amount / 2, @Amount = @Amount % 2    SELECT @R1 = @Amount / 1, @Amount = @Amount % 1    SELECT @C50 = @Amount / 0.50, @Amount = @Amount % 0.50    SELECT @C20 = @Amount / 0.20, @Amount = @Amount % 0.20    SELECT @C10 = @Amount / 0.10, @Amount = @Amount % 0.10        INSERT INTO @Result    SELECT @R200 AS R200, @R100 AS R100, @R50 AS R50, @R20 AS R20, @R10 AS R10, @R5 AS R5, @R2 AS R2, @R1 AS R1,    @C50 AS C50, @C20 AS C20, @C10 AS C10, @Total AS Amount        UPDATE @Emp SET Flag = 1 WHERE EmployeeId = @EmployeeId   END      IF NOT EXISTS(SELECT * FROM @Result WHERE Total > 0) BEGIN    INSERT INTO @Result    SELECT 0 AS R200, 0 AS R100, 0 AS R50, 0 AS R20, 0 AS R10, 0 AS R5, 0 AS R2, 0 AS R1,    0 AS C50, 0 AS C20, 0 AS C10, 0 AS Amount   END   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R200', SUM(R200), SUM(R200) * 200 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R100', SUM(R100), SUM(R100) * 100 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R50', SUM(R50), SUM(R50) * 50 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R20', SUM(R20), SUM(R20) * 20 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R10', SUM(R10), SUM(R10) * 10 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R5', SUM(R5), SUM(R5) * 5 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R2', SUM(R2), SUM(R2) * 2 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R1', SUM(R1), SUM(R1) * 1 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '50C', SUM(C50), SUM(C50) * 0.5 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '20C', SUM(C20), SUM(C20) * 0.2 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '10C', SUM(C10), SUM(C10) * 0.1 FROM @Result     SELECT * FROM @Final_Result  END  

GO

-- ============================================
-- SP: Payroll_Remuneration_cashByEmployee_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Richa Mills>  -- Create date: <2017/0919>  -- Description: <Remuneration List Report>    -- =============================================    CREATE PROCEDURE [dbo].[Payroll_Remuneration_cashByEmployee_rpt]  @EmployeeId INT,  @DepartmentId INT,  @PaymentId INT,  @PeriodId INT  AS  BEGIN   SELECT    *      ,CONVERT(DECIMAL(18, 4), FLOOR((Cents - (C50 * 0.50) - (C20 * 0.20)) / 0.10)) AS C10   FROM (SELECT     *       ,CONVERT(DECIMAL(18, 4), FLOOR((Cents - (C50 * 0.50)) / 0.20)) AS C20    FROM (SELECT      *        ,CONVERT(DECIMAL(18, 2), FLOOR(Cents.Cents / 0.50)) AS C50     FROM (SELECT       *         ,RANDS.NetPay - ((RANDS.R200 * 200) + (R100 * 100) + (R50 * 50) + (R20 * 20) + (R10 * 10) + (RANDS.R5 * 5) + (R2 * 2) + (R1 * 1)) AS Cents      FROM (SELECT        *          ,CONVERT(DECIMAL(18, 2), FLOOR((R2.NetPay - (R2.R200 * 200) - (R2.R100 * 100) - (R2.R50 * 50) - (R2.R20 * 20) - (R2.R10 * 10) - (R2.R5 * 5) - (R2.R2 * 2) / 1))) AS R1       FROM (SELECT         *           ,CONVERT(DECIMAL(18, 2), FLOOR((R5.NetPay - (R5.R200 * 200) - (R5.R100 * 100) - (R5.R50 * 50) - (R5.R20 * 20) - (R5.R10 * 10) - (R5 * 5)) / 2)) AS R2        FROM (SELECT          *            ,CONVERT(DECIMAL(18, 2), FLOOR((R10.NetPay - (R10.R200 * 200) - (R10.R100 * 100) - (R10.R50 * 50) - (R10.R20 * 20) - (R10 * 10)) / 5)) AS R5         FROM (SELECT           *             ,CONVERT(DECIMAL(18, 2), FLOOR((R20.NetPay - (R20.R200 * 200) - (R20.R100 * 100) - (R20.R50 * 50) - (R20 * 20)) / 10)) AS R10          FROM (SELECT            *              ,CONVERT(DECIMAL(18, 2), FLOOR((R50.NetPay - (R50.R200 * 200) - (R50.R100 * 100) - (R50 * 50)) / 20)) AS R20           FROM (SELECT             *               ,CONVERT(DECIMAL(18, 2), FLOOR((R100.NetPay - (R100.R200 * 200) - (R100.R100 * 100)) / 50)) AS R50            FROM (SELECT              *                ,CONVERT(DECIMAL(18, 2), FLOOR((R200.NetPay - (R200.R200 * 200)) / 100)) AS R100             FROM (SELECT               *                 ,CONVERT(DECIMAL(18, 2), FLOOR(V1.NetPay / 200)) AS R200              FROM (SELECT                Emp.Employee_ID                  ,Emp.EmpCode                  ,Emp.FirstName                  ,Emp.Surname                  ,Emp.DepartmentDesc                  ,SUM(Emp.NetPay) AS NetPay               FROM (SELECT                 Employee_ID                   ,P_E.EmpCode                   ,P_E.FirstName                   ,P_E.Surname                   ,C_D.DepartmentDesc                   ,P_EPS.SalaryHeadTitleAddendum                   ,CASE                  WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1                  ELSE P_EPS.Amount                 END AS NetPay                  FROM dbo.Payroll_EmployeePayslip AS P_EPS                INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS P_EPD                 ON P_EPS.PayrollDefinationID = P_EPD.EmployeePayrollDefinition_ID                INNER JOIN dbo.Payroll_SalaryHead AS P_SH                 ON P_EPD.PayrollSalaryHeadID = P_SH.SalaryHead_ID                INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5                 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID                INNER JOIN dbo.Payroll_Employee AS P_E                 ON P_E.Employee_ID = P_EPS.EmployeeID                INNER JOIN dbo.Payroll_Position AS PP                 ON PP.Position_ID = P_E.PositionID                INNER JOIN dbo.Const_Department AS C_D                 ON PP.DepartmentID = C_D.Department_ID                WHERE P_IRP5.TransactionTypeID IN (1, 2)                AND P_EPS.PeriodID = @PeriodId                AND (P_E.Employee_ID = @EmployeeId                OR @EmployeeId = 0)                AND (Department_ID = @DepartmentId                OR @DepartmentId = 0)                AND (PaymentTypeID = 3)                AND TaxSavePurpose = 0) Emp               GROUP BY Emp.Employee_ID                 ,Emp.EmpCode                 ,Emp.FirstName                 ,Emp.Surname                 ,Emp.DepartmentDesc) V1) R200) R100) R50) R20) R10) R5) R2) RANDS) Cents) C50) C20      END      --EXEC Payroll_Remuneration_cash_rpt 0, 0, 0, 6    

GO

-- ============================================
-- SP: Payroll_Remuneration_cashByEmployeeTrial_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Richa Mills>  -- Create date: <2017/0919>  -- Description: <Remuneration List Report>    -- =============================================    CREATE PROCEDURE [dbo].[Payroll_Remuneration_cashByEmployeeTrial_rpt]  @EmployeeId INT,  @DepartmentId INT,  @PaymentId INT,  @CycleID int  AS  BEGIN    DECLARE @PeriodId INT  SELECT @PeriodID = (Select Top 1 PeriodId from Payroll_TrialResults where CycleID = @CycleId )   SELECT    *      ,CONVERT(DECIMAL(18, 4), FLOOR((Cents - (C50 * 0.50) - (C20 * 0.20)) / 0.10)) AS C10   FROM (SELECT     *       ,CONVERT(DECIMAL(18, 4), FLOOR((Cents - (C50 * 0.50)) / 0.20)) AS C20    FROM (SELECT      *        ,CONVERT(DECIMAL(18, 2), FLOOR(Cents.Cents / 0.50)) AS C50     FROM (SELECT       *         ,RANDS.NetPay - ((RANDS.R200 * 200) + (R100 * 100) + (R50 * 50) + (R20 * 20) + (R10 * 10) + (RANDS.R5 * 5) + (R2 * 2) + (R1 * 1)) AS Cents      FROM (SELECT        *          ,CONVERT(DECIMAL(18, 2), FLOOR((R2.NetPay - (R2.R200 * 200) - (R2.R100 * 100) - (R2.R50 * 50) - (R2.R20 * 20) - (R2.R10 * 10) - (R2.R5 * 5) - (R2.R2 * 2) / 1))) AS R1       FROM (SELECT         *           ,CONVERT(DECIMAL(18, 2), FLOOR((R5.NetPay - (R5.R200 * 200) - (R5.R100 * 100) - (R5.R50 * 50) - (R5.R20 * 20) - (R5.R10 * 10) - (R5 * 5)) / 2)) AS R2        FROM (SELECT          *            ,CONVERT(DECIMAL(18, 2), FLOOR((R10.NetPay - (R10.R200 * 200) - (R10.R100 * 100) - (R10.R50 * 50) - (R10.R20 * 20) - (R10 * 10)) / 5)) AS R5         FROM (SELECT           *             ,CONVERT(DECIMAL(18, 2), FLOOR((R20.NetPay - (R20.R200 * 200) - (R20.R100 * 100) - (R20.R50 * 50) - (R20 * 20)) / 10)) AS R10          FROM (SELECT            *              ,CONVERT(DECIMAL(18, 2), FLOOR((R50.NetPay - (R50.R200 * 200) - (R50.R100 * 100) - (R50 * 50)) / 20)) AS R20           FROM (SELECT             *               ,CONVERT(DECIMAL(18, 2), FLOOR((R100.NetPay - (R100.R200 * 200) - (R100.R100 * 100)) / 50)) AS R50            FROM (SELECT              *                ,CONVERT(DECIMAL(18, 2), FLOOR((R200.NetPay - (R200.R200 * 200)) / 100)) AS R100             FROM (SELECT               *                 ,CONVERT(DECIMAL(18, 2), FLOOR(V1.NetPay / 200)) AS R200              FROM (SELECT                Emp.Employee_ID                  ,Emp.EmpCode                  ,Emp.FirstName                  ,Emp.Surname                  ,Emp.DepartmentDesc                  ,SUM(Emp.NetPay) AS NetPay               FROM (SELECT                 Employee_ID                   ,P_E.EmpCode                   ,P_E.FirstName                   ,P_E.Surname                   ,C_D.DepartmentDesc                   ,P_EPS.SalaryTitle                   ,CASE                  WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1                  ELSE P_EPS.Amount                 END AS NetPay                  FROM dbo.Payroll_TrialResults AS P_EPS                                INNER JOIN dbo.Payroll_SalaryHead AS P_SH                 ON P_EPS.SalaryHeadID = P_SH.SalaryHead_ID                INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5                 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID                INNER JOIN dbo.Payroll_Employee AS P_E                 ON P_E.Employee_ID = P_EPS.EmployeeID                INNER JOIN dbo.Payroll_Position AS PP                 ON PP.Position_ID = P_E.PositionID                INNER JOIN dbo.Const_Department AS C_D                 ON PP.DepartmentID = C_D.Department_ID                WHERE TaxSavePurpose = 0 AND P_IRP5.TransactionTypeID IN (1, 2)                AND P_EPS.PeriodID = @PeriodId                AND (P_E.Employee_ID = @EmployeeId                OR @EmployeeId = 0)                AND (Department_ID = @DepartmentId                OR @DepartmentId = 0)                AND (P_EPS.PaymentTypeID = 3)                ) Emp               GROUP BY Emp.Employee_ID                 ,Emp.EmpCode                 ,Emp.FirstName                 ,Emp.Surname                 ,Emp.DepartmentDesc) V1) R200) R100) R50) R20) R10) R5) R2) RANDS) Cents) C50) C20      END      --EXEC Payroll_Remuneration_cash_rpt 0, 0, 0, 6    

GO

-- ============================================
-- SP: Payroll_Remuneration_cashTrial_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MarioT 2015/05/28 Same as Payroll_Remuneration_cash_rpt but uses Trial run  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  CREATE procedure [dbo].[Payroll_Remuneration_cashTrial_rpt]   @EmployeeId INT,   @DepartmentId INT   ,@PaymentId INT   ,@CycleId INT  AS  BEGIN    DECLARE @PeriodId INT  SELECT @PeriodID = (Select Top 1 PeriodId from Payroll_TrialResults where CycleID = @CycleId)     DECLARE @Amount DECIMAL(18, 2), @Total DECIMAL(18, 2)   DECLARE @Result TABLE(R200 INT, R100 INT, R50 INT, R20 INT, R10 INT, R5 INT, R2 INT, R1 INT, C50 INT, C20 INT, C10 INT, Total DECIMAL(18, 2))   DECLARE @Final_Result TABLE (Currency VARCHAR(50), NoOfNote INT, Total DECIMAL(18, 2))   DECLARE @Emp TABLE (EmployeeId INT, Amount DECIMAL(18, 2), Flag BIT)   INSERT INTO @Emp ( EmployeeId, Amount, Flag )   SELECT Employee_Id, SUM(CASE WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1 ELSE P_EPS.Amount END) AS NetPay, 0--, P_IRP5.TransactionTypeID    FROM dbo.Payroll_TrialResults AS P_EPS   INNER JOIN dbo.Payroll_SalaryHead AS P_SH ON P_EPS.SalaryHeadID = P_SH.SalaryHead_ID   INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID   INNER JOIN dbo.Payroll_Employee AS P_E ON P_E.Employee_ID = P_EPS.EmployeeID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID   WHERE P_IRP5.TransactionTypeID IN (1,2) AND P_EPS.PeriodID = @PeriodId AND (P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0)   AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND (P_EPS.PaymentTypeID = 3) AND TaXsavePurpose = 0   GROUP BY P_E.Employee_ID      DECLARE @R200 INT = 0, @R100 INT = 0, @R50 INT = 0, @R20 INT = 0, @R10 INT = 0, @R5 INT = 0, @R2 INT = 0, @R1 INT = 0   DECLARE @C50 INT = 0, @C20 INT = 0, @C10 INT = 0      WHILE EXISTS (SELECT * FROM @Emp WHERE Flag = 0) BEGIN    SELECT TOP 1 @EmployeeId = EmployeeId, @Amount = Amount, @Total = Amount FROM @Emp WHERE Flag = 0        SELECT @R200 = @Amount / 200, @Amount = @Amount % 200    SELECT @R100 = @Amount / 100, @Amount = @Amount % 100    SELECT @R50 = @Amount / 50, @Amount = @Amount % 50    SELECT @R20 = @Amount / 20, @Amount = @Amount % 20    SELECT @R10 = @Amount / 10, @Amount = @Amount % 10    SELECT @R5 = @Amount / 5, @Amount = @Amount % 5    SELECT @R2 = @Amount / 2, @Amount = @Amount % 2    SELECT @R1 = @Amount / 1, @Amount = @Amount % 1    SELECT @C50 = @Amount / 0.50, @Amount = @Amount % 0.50    SELECT @C20 = @Amount / 0.20, @Amount = @Amount % 0.20    SELECT @C10 = @Amount / 0.10, @Amount = @Amount % 0.10        INSERT INTO @Result    SELECT @R200 AS R200, @R100 AS R100, @R50 AS R50, @R20 AS R20, @R10 AS R10, @R5 AS R5, @R2 AS R2, @R1 AS R1,    @C50 AS C50, @C20 AS C20, @C10 AS C10, @Total AS Amount        UPDATE @Emp SET Flag = 1 WHERE EmployeeId = @EmployeeId   END      IF NOT EXISTS(SELECT * FROM @Result WHERE Total > 0) BEGIN    INSERT INTO @Result    SELECT 0 AS R200, 0 AS R100, 0 AS R50, 0 AS R20, 0 AS R10, 0 AS R5, 0 AS R2, 0 AS R1,    0 AS C50, 0 AS C20, 0 AS C10, 0 AS Amount   END   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R200', SUM(R200), SUM(R200) * 200 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R100', SUM(R100), SUM(R100) * 100 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R50', SUM(R50), SUM(R50) * 50 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R20', SUM(R20), SUM(R20) * 20 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R10', SUM(R10), SUM(R10) * 10 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R5', SUM(R5), SUM(R5) * 5 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R2', SUM(R2), SUM(R2) * 2 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT 'R1', SUM(R1), SUM(R1) * 1 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '50C', SUM(C50), SUM(C50) * 0.5 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '20C', SUM(C20), SUM(C20) * 0.2 FROM @Result   INSERT INTO @Final_Result ( Currency, NoOfNote, Total )   SELECT '10C', SUM(C10), SUM(C10) * 0.1 FROM @Result     SELECT * FROM @Final_Result  END  

GO

-- ============================================
-- SP: Payroll_Remuneration_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,, Apr 2014>  -- Description: <Description,,>  -- Call SP    : Payroll_Remuneration_rpt 0, 0, 0, 301, ''  -- 2016-01-06 TP29885 Ravindra Jijotia: Added EmpCode in the list.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 24/06/2019 - Changed the condition for the BankDescription for bug #86657  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_Remuneration_rpt]   @EmployeeId INT,   @DepartmentId INT,   @PaymentId INT,   @PeriodId INT,   @UserName NVARCHAR(100),   @ZeroOnly BIT  AS  BEGIN   DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME   SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId     DECLARE @NettPay TABLE   (    EmployeeId int,    EmpNo varchar(50),    EmpCode varchar(50),    Name varchar(250),    DepartmentDesc varchar(50),    PaymentTypeDesc varchar(20),    BankDesc varchar(100),    AccountNumber varchar(50),    BankBranchCode varchar(20),    NetPay Decimal(18,2),    PeriodEndDate datetime,    PeriodStartDate datetime   )     Insert into @NettPay   SELECT Employee_Id, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Employee_ID )), 8,'0') AS EmpNo, ISNULL(P_E.EmpCode, '') AS EmpCode, P_E.FirstName + ' ' + P_E.Surname AS Name, C_D.DepartmentDesc, C_PT.PaymentTypeDesc, C_Bank.BankDesc, P_E.AccountNumber, C_BBC.BankBranchCode,   SUM(CASE WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1 ELSE P_EPS.Amount END) AS NetPay, @PeriodEndDate AS PeriodEndDate, @PeriodStartDate AS PeriodStartDate--, P_IRP5.TransactionTypeID    FROM dbo.Payroll_PayrollResults AS P_EPS   INNER JOIN dbo.Payroll_SalaryHead AS P_SH ON P_EPS.SalaryHeadId = P_SH.SalaryHead_ID   INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID   INNER JOIN dbo.Payroll_Employee AS P_E ON P_E.Employee_ID = P_EPS.EmployeeID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID   INNER JOIN dbo.Const_PaymentType AS C_PT ON C_PT.PaymentType_ID = P_E.PaymentTypeID   LEFT OUTER JOIN dbo.Const_Bank AS C_Bank ON P_E.BankID = C_Bank.Bank_ID   LEFT OUTER JOIN dbo.Const_BankBranchCode AS C_BBC ON C_Bank.Bank_ID = C_BBC.BankID AND P_E.BranchID = C_BBC.BankBranchCode_ID   WHERE P_EPS.TaxSavePurpose = 0 AND P_IRP5.TransactionTypeID IN (1,2) AND P_EPS.PeriodID = @PeriodId AND (P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0)   AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND (PaymentType_ID = @PaymentId OR @PaymentId = 0) AND TaxSavePurpose = 0   AND ((C_PT.PaymentTypeDesc ='EFT' AND  C_Bank.BankDesc IS NOT NULL) OR (C_PT.PaymentTypeDesc ='Cheque'))   GROUP BY P_E.Employee_ID, P_E.EmpCode, P_E.FirstName, P_E.Surname, C_D.DepartmentDesc, C_PT.PaymentTypeDesc, C_Bank.BankDesc, P_E.AccountNumber, C_BBC.BankBranchCode       if @ZeroOnly = 1    Select * from @NettPay where NetPay = 0   ELSE    Select * from @NettPay      END

GO

-- ============================================
-- SP: Payroll_RemunerationTrial_rpt
-- Schema: dbo
-- ============================================
   -- =============================================  -- Author:  MarioT 2015/05/28 Same as Payroll_Remuneration_rpt but using Trial Run detils  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  --- 13/Feb/2019 -Himil Modi - #84441 -- put the case statement for bank related data  when it is EFT at that time data will come otherwise it will be display blank.  --Exec Payroll_RemunerationTrial_rpt 2,0,0,17,'1'  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_RemunerationTrial_rpt]   @EmployeeId INT,   @DepartmentId INT,   @PaymentId INT = 0,   @CycleId INT,   @UserName NVARCHAR(100),   @PeriodId int,   @ZeroOnly bit  AS  BEGIN     DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME   SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId     DECLARE @NettPay TABLE   (    EmployeeId int,    EmpNo varchar(50),    EmpCode varchar(50),    Name varchar(250),    DepartmentDesc varchar(50),    PaymentTypeDesc varchar(20),    BankDesc varchar(100),    AccountNumber varchar(50),    BankBranchCode varchar(20),    NetPay Decimal(18,2),    PeriodEndDate datetime,    PeriodStartDate datetime   )     Insert into @NettPay  SELECT Employee_Id, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Employee_ID )), 8,'0') AS EmpNo, ISNULL(P_E.EmpCode, '') AS EmpCode, P_E.FirstName + ' ' + P_E.Surname AS Name, C_D.DepartmentDesc, C_PT.PaymentTypeDesc,     (CASE @PaymentId WHEN 1 then C_Bank.BankDesc ELSE NULL  END) AS BankDesc,     (CASE @PaymentId WHEN 1 THEN P_E.AccountNumber ELSE NULL END) AS AccountNumber ,      (CASE @PaymentId WHEN 1 THEN  C_BBC.BankBranchCode ELSE NULL END) AS BankBranchCode,   SUM(CASE WHEN P_IRP5.TransactionTypeID = 2 THEN P_EPS.Amount * -1 ELSE P_EPS.Amount END) AS NetPay, @PeriodEndDate AS PeriodEndDate, @PeriodStartDate AS PeriodStartDate--, P_IRP5.TransactionTypeID   FROM dbo.Payroll_TrialResults AS P_EPS   INNER JOIN dbo.Payroll_SalaryHead AS P_SH ON P_EPS.SalaryHeadID = P_SH.SalaryHead_ID   INNER JOIN dbo.Payroll_IRP5Code AS P_IRP5 ON P_SH.IRP5CodeId = P_IRP5.IRP5Code_ID   INNER JOIN dbo.Payroll_Employee AS P_E ON P_E.Employee_ID = P_EPS.EmployeeID   INNER JOIN dbo.Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID   INNER JOIN dbo.Const_Department AS C_D ON PP.DepartmentID = C_D.Department_ID   INNER JOIN dbo.Const_PaymentType AS C_PT ON C_PT.PaymentType_ID = P_E.PaymentTypeID   LEFT OUTER JOIN dbo.Const_Bank AS C_Bank ON P_E.BankID = C_Bank.Bank_ID   LEFT OUTER JOIN dbo.Const_BankBranchCode AS C_BBC ON C_Bank.Bank_ID = C_BBC.BankID AND P_E.BranchID = C_BBC.BankBranchCode_ID   WHERE    PeriodId = @PeriodId AND TaxSavePurpose = 0 AND P_IRP5.TransactionTypeID IN (1,2) AND P_E.CycleID = @CycleId AND (P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0)   AND (Department_ID = @DepartmentId OR @DepartmentId = 0) AND (PaymentType_ID = @PaymentId OR @PaymentId = 0)    GROUP BY P_E.Employee_ID, P_E.EmpCode, P_E.FirstName, P_E.Surname, C_D.DepartmentDesc, C_PT.PaymentTypeDesc, C_Bank.BankDesc, P_E.AccountNumber, C_BBC.BankBranchCode      if @ZeroOnly = 1    Select * from @NettPay where NetPay = 0   ELSE    Select * from @NettPay      END

GO

-- ============================================
-- SP: Payroll_ReProcess_Trail_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 05/08/2013  -- Description: Trail reprocess functionality  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_ReProcess_Trail_sp]   @FinancialYear NVARCHAR(50),   @PeriodID INT  AS  BEGIN      SET NOCOUNT ON;     DELETE FROM dbo.Payroll_EmployeeTrialPayslip WHERE TaxYear = @FinancialYear AND PeriodID = @PeriodID      DECLARE @TrailRunID INT   SELECT TOP 1 @TrailRunID = TrailRun_ID FROM dbo.Payroll_TrailRun_History WHERE [Status] = 'InProcess' AND TaxYear = @FinancialYear AND PeriodID = @PeriodID   UPDATE dbo.Payroll_TrailRun_History SET [Status] = 'Requested' WHERE TaxYear = @FinancialYear AND TrailRun_ID = @TrailRunID  END  

GO

-- ============================================
-- SP: Payroll_Rollover
-- Schema: dbo
-- ============================================
  /* ================================================================================================    Author   : Ferdi Botha    Created Date : 18/05/2019    Descirption  : Performs a MultiYear Rollover for Payroll   ================================================================================================    Author   : Ruan Strydom    Created Date : 28/08/2020    Descirption  : Add additional columns for sars columns and trade classification activity   ================================================================================================ */  CREATE procedure [Payroll_Rollover] @SCOAYearFrom nvarchar(9) = null, @SCOAYearTo nvarchar(9) = null  as    begin     declare @error_line int = null,     @error_message nvarchar(2048) = null,     @error_procedure nvarchar(2048) = null     set xact_abort on;     set nocount on;     begin transaction      begin try       declare @StartDateFrom datetime = null,       @UntilDateFrom datetime = null,       @StartDateTo datetime = null,       @UntilDateTo datetime = null,       @lowDate datetime = '1900-01-01 00:00:00',       @highDate datetime = '9999-12-31 00:00:00'       if (@SCOAYearFrom is null)        select @SCOAYearFrom = cast([KeyValue] as nvarchar(9)) from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'ActiveFinYear')       if (@SCOAYearTo is null)        set @SCOAYearTo = cast((cast(left(@SCOAYearFrom, 4) as int) + 1) as nvarchar(4)) + '/' + cast((cast(right(@SCOAYearFrom, 4) as int) + 1) as nvarchar(4))       set @StartDateFrom = cast((left(@SCOAYearFrom, 4) + '-07-01 00:00:00') as datetime)     set @UntilDateFrom = cast((right(@SCOAYearFrom, 4) + '-06-30 00:00:00') as datetime)     set @StartDateTo = cast((left(@SCOAYearTo, 4) + '-07-01 00:00:00') as datetime)     set @UntilDateTo = cast((right(@SCOAYearTo, 4) + '-06-30 00:00:00') as datetime)       /* PROCESS MUNICIPALITY */       /* Create a copy of the Financial Year (@SCOAYearFrom => @SCOAYearTo) */     insert into [Payroll_MunicipalityHistory]([MunicipalityID], [MunicipalityNo], [MunicipalityName], [RegistrationNo], [TaxRegistrationNo], [TradeClassificationID], [SDLReferenceNo], [UIFRegistrationNo], [UIFReferenceNo], [PrintOnPayslip], [MunicipalityImagePath], [LeaveBased], [GradingID], [PhyAddress1], [PhyAddress2], [PhyPostalCode], [City], [SameAsPhysical], [PosAddress1], [PosAddress2], [PosPostalCode], [SARSPersonName], [SARSEmailAddress], [SARSContactNo], [SameAsSARS], [UIFPersonName], [UIFEmailAddress], [UIFContactNo], [Monday], [Tuesday], [Wednesday], [Thursday], [Friday], [Saturday], [Sunday], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ExcludeForUIF], [ExcludeForSDL], [CountryID], [AppraisalPeriod], [AppraisalNotificationDays], [UnionFee], [SARSFaxNo], [UIFFaxNo], [SendRouteFileReminderDays], [SendRouteFileReminderFlag], [WebServiceRequestedFlag], [WebServiceRequestedDate], [WebServiceRetrivedFlag], [WebServiceRetrivedDate], [BillingRunReminderDays], [BillingRunReminderFlag], [PayrollRunReminderDays], [PayrollRunReminderFlag], [EmailAddress], [FirstName], [LastName], [GUID], [ContactName], [ContactPhone], [ContactEmail], [ContactFax], [VatPercentage], [WorkingDaysOverTimeRate], [HolidayDaysOverTimeRate], [EasyPayCode], [PostOfficeCode], [TemplateType], [BillingTemplateType], [ProRatingPrinciple], [PhyProvinceID], [PhyCityID], [VendorPrefix], [MunicipalityAddress1], [MunicipalityAddress2], [MunicipalityAddress3], [ManagerSignature], [VATRegistrationNumber], [BonusMonth], [WebSite], [PayeRegistrationNo], [EscalationDuration], [MetermanWebSite], [IsSalaryIndicatorDefault], [IsPensionIndicatorDefault], [IsMedicalIndicatorDefault], [IsThirdPartyIndicatorDefault], [IsSARSIndicatorDefault], [IsAdvanceIndicatorDefault], [BillingBankID], [BillingBankBranchCodeID], [BillingAccountType], [BillingAccountNo], [AdvanceSuspenseScoaItemID], [MedicalSuspenseScoaItemID], [PensionSuspenseScoaItemID], [SalarySuspenseScoaItemID], [SARSSuspenseScoaItemID], [ThirdpartySuspenseScoaItemID], [TransferScoaItemID], [DemarcationCode], [MunicipalityType], [PhySuburb], [PosSuburb], [PosProvinceID], [PosCityID], [PosStreetID], [PosBoxBagNo], [PosFlatUnitSuiteNo], [PhyStreetID], [BonusPaymentDateID], [CommissionScoaItemID], [AllowChequeSalaries], [AllowCashSalaries], [HideExcludeUIFSDL], [PhyUnitNumber], [IsTravelIndicatorDefault], [IsLeaveIndicatorDefault], [IsUIFIndicatorDefault], [IsSkillsIndicatorDefault], [IsGroupLifeIndicatorDefault], [IsUnionsIndicatorDefault], [TravelSuspenseScoaItemID], [LeaveSuspenseScoaItemID], [UIFSuspenseScoaItemID], [SkillsSuspenseScoaItemID], [GroupLifeSuspenseScoaItemID], [UnionsSuspenseScoaItemID], [AllowPrimaryCostSplitting], [PhyComplex], [PhyStreetNumber], [SEZCodeId], [SICCodeId], [CashBookID], [EmployeeDeductionFICSScoaItemID], [CommissionProjectID], [NettSalaryProjectID], [SalaryProjectID], [TravelProjectID], [LeaveProjectID], [TaxProjectID], [UIFProjectID], [SkillsProjectID], [PensionProjectID], [MedicalProjectID], [GroupLifeProjectID], [UnionProjectID], [EmployeeProjectID], [SalarySuspenseScoaItemCreditID], [TravelSuspenseScoaItemCreditID], [LeaveSuspenseScoaItemCreditID], [SARSSuspenseScoaItemCreditID], [UIFSuspenseScoaItemCreditID], [SkillsSuspenseScoaItemCreditID], [PensionSuspenseScoaItemCreditID], [MedicalSuspenseScoaItemCreditID], [GroupLifeSuspenseScoaItemCreditID], [UnionsSuspenseScoaItemCreditID], [EmployeeDeductionFICSScoaItemCreditID], [CommDepartmentId], [CommDivisionId], [CommFunctionId], [CommRegionId], [FinYear], [StartDate], [UntilDate], [SARSPersonSurname], [SARSPersonCellNo],[SARSPersonPositionId], [UIFPersonSurname], [UIFPersonCellNo],[UIFPersonPositionId], [TradeClassificationActivityId])        select [Municipality_ID], [MunicipalityNo], [MunicipalityName], [RegistrationNo], [TaxRegistrationNo], [TradeClassificationID], [SDLReferenceNo], [UIFRegistrationNo], [UIFReferenceNo], [PrintOnPayslip], [MunicipalityImagePath], [LeaveBased], [GradingID], [PhyAddress1], [PhyAddress2], [PhyPostalCode], [City], [SameAsPhysical], [PosAddress1], [PosAddress2], [PosPostalCode], [SARSPersonName], [SARSEmailAddress], [SARSContactNo], [SameAsSARS], [UIFPersonName], [UIFEmailAddress], [UIFContactNo], [Monday], [Tuesday], [Wednesday], [Thursday], [Friday], [Saturday], [Sunday], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [ExcludeForUIF], [ExcludeForSDL], [CountryID], [AppraisalPeriod], [AppraisalNotificationDays], [UnionFee], [SARSFaxNo], [UIFFaxNo], [SendRouteFileReminderDays], [SendRouteFileReminderFlag], [WebServiceRequestedFlag], [WebServiceRequestedDate], [WebServiceRetrivedFlag], [WebServiceRetrivedDate], [BillingRunReminderDays], [BillingRunReminderFlag], [PayrollRunReminderDays], [PayrollRunReminderFlag], [EmailAddress], [FirstName], [LastName], [GUID], [ContactName], [ContactPhone], [ContactEmail], [ContactFax], [VatPercentage], [WorkingDaysOverTimeRate], [HolidayDaysOverTimeRate], [EasyPayCode], [PostOfficeCode], [TemplateType], [BillingTemplateType], [ProRatingPrinciple], [PhyProvinceID], [PhyCityID], [VendorPrefix], [MunicipalityAddress1], [MunicipalityAddress2], [MunicipalityAddress3], [ManagerSignature], [VATRegistrationNumber], [BonusMonth], [WebSite], [PayeRegistrationNo], [EscalationDuration], [MetermanWebSite], [IsSalaryIndicatorDefault], [IsPensionIndicatorDefault], [IsMedicalIndicatorDefault], [IsThirdPartyIndicatorDefault], [IsSARSIndicatorDefault], [IsAdvanceIndicatorDefault], [BillingBankID], [BillingBankBranchCodeID], [BillingAccountType], [BillingAccountNo], [AdvanceSuspenseScoaItemID], [MedicalSuspenseScoaItemID], [PensionSuspenseScoaItemID], [SalarySuspenseScoaItemID], [SARSSuspenseScoaItemID], [ThirdpartySuspenseScoaItemID], [TransferScoaItemID], [DemarcationCode], [MunicipalityType], [PhySuburb], [PosSuburb], [PosProvinceID], [PosCityID], [PosStreetID], [PosBoxBagNo], [PosFlatUnitSuiteNo], [PhyStreetID], [BonusPaymentDateID], [CommissionScoaItemID], [AllowChequeSalaries], [AllowCashSalaries], [HideExcludeUIFSDL], [PhyUnitNumber], [IsTravelIndicatorDefault], [IsLeaveIndicatorDefault], [IsUIFIndicatorDefault], [IsSkillsIndicatorDefault], [IsGroupLifeIndicatorDefault], [IsUnionsIndicatorDefault], [TravelSuspenseScoaItemID], [LeaveSuspenseScoaItemID], [UIFSuspenseScoaItemID], [SkillsSuspenseScoaItemID], [GroupLifeSuspenseScoaItemID], [UnionsSuspenseScoaItemID], [AllowPrimaryCostSplitting], [PhyComplex], [PhyStreetNumber], [SEZCodeId], [SICCodeId], [CashBookID], [EmployeeDeductionFICSScoaItemID], [CommissionProjectID], [NettSalaryProjectID], [SalaryProjectID], [TravelProjectID], [LeaveProjectID], [TaxProjectID], [UIFProjectID], [SkillsProjectID], [PensionProjectID], [MedicalProjectID], [GroupLifeProjectID], [UnionProjectID], [EmployeeProjectID], [SalarySuspenseScoaItemCreditID], [TravelSuspenseScoaItemCreditID], [LeaveSuspenseScoaItemCreditID], [SARSSuspenseScoaItemCreditID], [UIFSuspenseScoaItemCreditID], [SkillsSuspenseScoaItemCreditID], [PensionSuspenseScoaItemCreditID], [MedicalSuspenseScoaItemCreditID], [GroupLifeSuspenseScoaItemCreditID], [UnionsSuspenseScoaItemCreditID], [EmployeeDeductionFICSScoaItemCreditID], [CommDepartmentId], [CommDivisionId], [CommFunctionId], [CommRegionId], @SCOAYearTo, @StartDateTo, @highDate, [SARSPersonSurname], [SARSPersonCellNo],[SARSPersonPositionId], [UIFPersonSurname], [UIFPersonCellNo],[UIFPersonPositionId], [TradeClassificationActivityId]         from [Payroll_Municipality] as [PM] with(nolock)         where ([FinYear] = @SCOAYearFrom and not exists(           select top 1 [MunicipalityID] from [Payroll_MunicipalityHistory] where ([FinYear] = @SCOAYearTo and [MunicipalityID] = [PM].[Municipality_ID])          )         )       /* Update EndDate for the Financial Year (@SCOAYearFrom) */     update [Payroll_MunicipalityHistory] set [UntilDate] = @UntilDateFrom where ([FinYear] = @SCOAYearFrom and [UntilDate] > @UntilDateFrom)       /* PROCESS DEPARTMENTS */       /* Create a copy of the Financial Year (@SCOAYearFrom => @SCOAYearTo) */     insert into [Const_DepartmentHistory]([DepartmentID], [StartDate], [EndDate], [ManagerPositionID], [ManagerStartDate], [ManagerEndDate], [Enabled], [CapturerID], [DateCaptured], [ModifierID], [DateModified], [FinYear], [DepartmentDesc], [DepartmentCode])        select [DepartmentID], [StartDate], [EndDate], [ManagerPositionID], [ManagerStartDate], [ManagerEndDate], [Enabled], [CapturerID], [DateCaptured], [ModifierID], [DateModified], @SCOAYearTo, [DepartmentDesc], [DepartmentCode]         from [Const_DepartmentHistory] as [CDH] with(nolock)         where ([FinYear] = @SCOAYearFrom and [StartDate] = (select max([StartDate]) from [Const_DepartmentHistory] where ([FinYear] = @SCOAYearFrom and [DepartmentID] = [CDH].[DepartmentID])) and [EndDate] > @UntilDateFrom and not exists(           select top 1 [DepartmentID] from [Const_DepartmentHistory] where ([FinYear] = @SCOAYearTo and [DepartmentID] = [CDH].[DepartmentID])          )         )       /* Update EndDate for the Financial Year (@SCOAYearFrom) */     update [Const_DepartmentHistory] set [EndDate] = @UntilDateFrom where ([FinYear] = @SCOAYearFrom and [EndDate] > @UntilDateFrom)       /* Update StartDate for the Financial Year (@SCOAYearTo) */     update [Const_DepartmentHistory] set [StartDate] = @StartDateTo where ([FinYear] = @SCOAYearTo and [StartDate] < @StartDateTo)       /* PROCESS DIVISIONS */       /* Create a copy of the Financial Year (@SCOAYearFrom => @SCOAYearTo) */     insert into [Const_DivisionHistory]([DivisionID], [DepartmentID], [DivisionParentID], [ConditionOfServiceID], [SCOAFunctionID], [SCOAProjectID], [SCOARegionID], [SCOAFundID], [StartDate], [EndDate], [ManagerPositionID], [ManagerStartDate], [ManagerEndDate], [Enabled], [CapturerID], [DateCaptured], [ModifierID], [DateModified], [FinYear], [DivisionCode], [DivisionDesc], [DirectorateLevel])        select [DivisionID], [DepartmentID], [DivisionParentID], [ConditionOfServiceID], [SCOAFunctionID], [SCOAProjectID], [SCOARegionID], [SCOAFundID], [StartDate], [EndDate], [ManagerPositionID], [ManagerStartDate], [ManagerEndDate], [Enabled], [CapturerID], [DateCaptured], [ModifierID], [DateModified], @SCOAYearTo, [DivisionCode], [DivisionDesc], [DirectorateLevel]         from [Const_DivisionHistory] as [CDH] with(nolock)         where ([FinYear] = @SCOAYearFrom and [StartDate] = (select max([StartDate]) from [Const_DivisionHistory] where ([FinYear] = @SCOAYearFrom and [DivisionID] = [CDH].[DivisionID])) and [EndDate] > @UntilDateFrom and not exists(           select top 1 [DivisionID] from [Const_DivisionHistory] where ([FinYear] = @SCOAYearTo and [DivisionID] = [CDH].[DivisionID])          )         )       /* Update EndDate for the Financial Year (@SCOAYearFrom) */     update [Const_DivisionHistory] set [EndDate] = @UntilDateFrom where ([FinYear] = @SCOAYearFrom and [EndDate] > @UntilDateFrom)       /* Update StartDate for the Financial Year (@SCOAYearTo) */     update [Const_DivisionHistory] set [StartDate] = @StartDateTo where ([FinYear] = @SCOAYearTo and [StartDate] < @StartDateTo)       /* PROCESS SALARY HEAD LEDGER ENTRIES */       /* Create a copy of the Financial Year (@SCOAYearFrom => @SCOAYearTo) */     insert into [Payroll_GLHistory]([GLItemsID], [SalaryHeadID], [JournalEntryOnly], [VendorID], [SuspenseScoaItemID], [ScoaItemIDPermanentStaff], [ScoaItemIDSeniorManagers], [ScoaItemIDCouncillors], [ScoaItemIDPostRetirement], [StartDate], [EndDate], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [SCOAProjectID], [SCOAItemID], [SCOAItemProjectID], [VendorScoaId], [VendorScoaProjectId], [SuspenseScoaItemCreditID], [SCOAItemCreditID], [PostRetirementApplicable], [ScoaDepartmentId], [ScoaDivisionId], [ScoaFunctionId], [ScoaRegionId], [FinYear])        select [GLItemsID], [SalaryHeadID], [JournalEntryOnly], [VendorID], [SuspenseScoaItemID], [ScoaItemIDPermanentStaff], [ScoaItemIDSeniorManagers], [ScoaItemIDCouncillors], [ScoaItemIDPostRetirement], [StartDate], [EndDate], [Enabled], [DateCaptured], [CapturerID], [DateModified], [ModifierID], [SCOAProjectID], [SCOAItemID], [SCOAItemProjectID], [VendorScoaId], [VendorScoaProjectId], [SuspenseScoaItemCreditID], [SCOAItemCreditID], [PostRetirementApplicable], [ScoaDepartmentId], [ScoaDivisionId], [ScoaFunctionId], [ScoaRegionId], @SCOAYearTo         from [Payroll_GLHistory] as [GLH] with(nolock)         where ([FinYear] = @SCOAYearFrom and [StartDate] = (select max([StartDate]) from [Payroll_GLHistory] where ([FinYear] = @SCOAYearFrom and [GLItemsID] = [GLH].[GLItemsID])) and [EndDate] > @UntilDateFrom and not exists(           select top 1 [GLItemsID] from [Payroll_GLHistory] where ([FinYear] = @SCOAYearTo and [GLItemsID] = [GLH].[GLItemsID])          )         )       /* Update EndDate for the Financial Year (@SCOAYearFrom) */     update [Payroll_GLHistory] set [EndDate] = @UntilDateFrom where ([FinYear] = @SCOAYearFrom and [EndDate] > @UntilDateFrom)       /* Update StartDate for the Financial Year (@SCOAYearTo) */     update [Payroll_GLHistory] set [StartDate] = @StartDateTo where ([FinYear] = @SCOAYearTo and [StartDate] < @StartDateTo)       if (xact_state() = 1)        commit transaction      end try      begin catch       select @error_line = error_line(), @error_message = error_message(), @error_procedure = error_procedure()       if (xact_state() = -1)        rollback transaction      end catch     set xact_abort off;     set nocount off;     if (not @error_line is null)      throw 50000, @error_message, 16    end

GO

-- ============================================
-- SP: Payroll_RunSummary_rpt
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  <Author,,GD>    -- Create date: <Create Date,,28 Apr 2014>    -- Description: <Description,,>    -- Call SP    : Payroll_RunSummary_rpt 1, 'Admin', 0, 0    -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 2017/11/22 - Changed the SP to read from Payroll_PayrollResults instead of Payroll_EmployeePayslip table  -- =============================================  CREATE procedure [dbo].[Payroll_RunSummary_rpt]   @PeriodId INT,     @UserName NVARCHAR(100),     @EmployeeId INT,     @DepartmentId INT    AS    BEGIN     DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME     SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId          SELECT      CSS.ScoaCode AS VoteNo,      CSS.ScoaCode AS ItemCode, CSCS.ScoaCode AS CostingCode, CSFS.ScoaCode AS FunctionCode,       CSRS.ScoaCode AS ReginalCode, CSFundS.ScoaCode AS FundCode, CSPS.ScoaCode AS ProjectCode,       CASE WHEN IRP5.TransactionTypeID IN (1, 3) THEN EPS.Amount ELSE 0 END AS Employeer,       CASE WHEN IRP5.TransactionTypeID IN (2, 4) THEN EPS.Amount ELSE 0 END AS Employee,      Emp.FirstName, Emp.Surname, TT.TransactionTypeDesc, SH.SalaryHeadTitle AS PayrollSalaryHeadName,    dbo.GetMonthNameFromId(MONTH(@PeriodEndDate)) AS ProcessingMonth, TransactionType_ID     FROM dbo.Payroll_PayrollResults AS EPS      --INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS EPD ON EPS.PayrollDefinationID = EPD.EmployeePayrollDefinition_ID      INNER JOIN dbo.Payroll_SalaryHead AS SH ON EPS.SalaryHeadID = SH.SalaryHead_ID      INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON SH.IRP5CodeId = IRP5.IRP5Code_ID      INNER JOIN dbo.Const_TransactionType AS TT ON IRP5.TransactionTypeID = TT.TransactionType_ID      INNER JOIN dbo.Payroll_Employee AS Emp ON Emp.Employee_ID = EPS.EmployeeID      INNER JOIN dbo.Payroll_Position AS PP ON Emp.PositionID = PP.Position_ID      INNER JOIN dbo.Const_Department AS Dep ON Dep.Department_ID = PP.DepartmentID      INNER JOIN dbo.Const_SCOA_Structure AS CSS ON EPS.SCOAItemID =  CSS.ScoaID      INNER JOIN dbo.Const_SCOA_Costing_Structure AS CSCS ON CSCS.ScoaID = EPS.SCOACostingID      INNER JOIN dbo.Const_SCOA_Function_Structure AS CSFS ON CSFS.ScoaID = EPS.SCOAFunctionID      INNER JOIN dbo.Const_SCOA_Regional_Structure AS CSRS ON CSRS.ScoaID = EPS.SCOARegionID      INNER JOIN dbo.Const_SCOA_Funds_Structure AS CSFundS ON CSFundS.ScoaID = EPS.SCOAFundingID      INNER JOIN dbo.Const_SCOA_Project_Structure AS CSPS ON CSPS.ScoaID = EPS.SCOAProjectID     WHERE PeriodID = @PeriodId     AND EPS.TaxSavePurpose = 0   AND (Emp.Employee_ID = @EmployeeId OR @EmployeeId = 0)     AND (Dep.Department_ID = @DepartmentId OR @DepartmentId = 0)     ORDER BY FirstName    END    

GO

-- ============================================
-- SP: Payroll_RunSummaryCount_rpt
-- Schema: dbo
-- ============================================
-- =============================================    -- Author:  <RichaM>    -- Create date: <2020/11/03>    -- Description: <Description,,>    -- Call SP    : Payroll_RunSummaryCount_rpt 1063,0,0    -- =============================================      CREATE PROCEDURE [dbo].[Payroll_RunSummaryCount_rpt]        @PeriodId INT ,        @EmployeeId INT ,        @DepartmentId INT    AS         BEGIN           DECLARE @PeriodEndDate DATETIME ,            @PeriodStartDate DATETIME ,            @CycleId INT ,            @FinYear VARCHAR(50) ,            @PreFinYear VARCHAR(50)      SELECT  @PeriodEndDate = PeriodEndDate,     @PeriodStartDate = PeriodStartDate,     @CycleId = CycleID,     @FinYear = TaxYear    FROM    dbo.Payroll_CyclePeriodDetails    WHERE   Period_ID = @PeriodId      DECLARE @EmployeeTable TABLE    (     EmployeeId int,     JoiningDate datetime,     EndDate datetime,     TerminationDate datetime,     TermReasonID int,     TermComplete bit,     TermReason varchar(50),     PeriodStart datetime,     PeriodEnd datetime    )    INSERT INTO @EmployeeTable       SELECT pe.Employee_ID,        pe.JoiningDate,        pe.EndDate,        pt.TerminationStartDate,        pt.TerminationReasonID,        Complete,        ec.ReasonDescription,        @PeriodStartDate,@PeriodStartDate       FROM(       SELECT DISTINCT EmployeeId        FROM Payroll_PayrollResults        WHERE PeriodID = @PeriodId)pr         LEFT JOIN Payroll_Employee pe ON pe.Employee_ID = pr.EmployeeID       LEFT JOIN Payroll_EmployeeTermination pt ON pt.EmployeeID = pe.Employee_ID       LEFT JOIN Payroll_ReasonEmployeeChange ec ON ec.Reason_ID = pt.TerminationReasonID      DECLARE @OldEmployees int   DECLARE @NewEmp int  DECLARE @Terminated int  DECLARE @TotalEmployees int    --Employees in previous period  Select @OldEmployees = Count(EmployeeId) from @EmployeeTable   WHERE JoiningDate < @PeriodStartDate    --Total employees included  Select @TotalEmployees = Count(EmployeeId) from @EmployeeTable    Select @OldEmployees OldEmployees,@TotalEmployees TotalEmployees        END

GO

-- ============================================
-- SP: Payroll_RunSummaryCountTrial_rpt
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  MarioT 2015/05/28 Same as Payroll_RunSummaryCount_rpt but using Trial Run  -- TP30318 : Suri Kandukuri : updated stored procedure for trial run.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  create procedure [Payroll_RunSummaryCountTrial_rpt]      @PeriodId INT ,      @EmployeeId INT ,      @DepartmentId INT  AS       BEGIN       /*          DECLARE @PeriodEndDate DATETIME ,              @PeriodStartDate DATETIME ,              @CycleId INT ,              @FinYear VARCHAR(50) ,              @PreFinYear VARCHAR(50)          SELECT  @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate, @CycleId = CycleID, @FinYear = FinancialYear          FROM    dbo.Payroll_CyclePeriodDetails          WHERE   Period_ID = @PeriodId    */   /*          SET @PreFinYear = CONVERT(VARCHAR(50), ( SELECT Data - 1                                                   FROM   dbo.Split(@FinYear, '/')                                                   WHERE  Id = 1                                                 )) + '/' + CONVERT(VARCHAR(50), ( SELECT ( Data )                                                                                   FROM   dbo.Split(@FinYear, '/')                                                                                   WHERE  Id = 1                                                                                 ))          PRINT @PreFinYear   */          DECLARE @NormalPaye INT ,              @NewPay INT ,              @NewTerminated INT ,              @Terminated INT ,              @OldTerminated INT          DECLARE @NNormalPaye INT ,              @NNewPay INT ,              @NNewTerminated INT ,              @NTerminated INT ,              @NOldTerminated INT          DECLARE @BroughForward INT ,              @NewJoin INT ,              @TransferedInYTD INT ,              @TransferedIn INT = 0 ,              @Reinstead INT = 0 ,              @LessTermination INT = 0 ,              @TransferedOutYTD INT = 0 ,              @TransferedOut INT = 0            SELECT  @NormalPaye = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                  INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  -- ( P_E.EndDate IS NULL OR P_E.EndDate > @PeriodEndDate )                  --AND P_E.JoiningDate < @PeriodStartDate                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 ) and [TaxSavePurpose] = 0                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 )              SELECT  @NewPay = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                   INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  --AND ( P_E.EndDate IS NULL OR P_E.EndDate > @PeriodEndDate )                  --AND P_E.JoiningDate > @PeriodStartDate                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0            SELECT  @NewTerminated = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                  INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  --AND P_E.EndDate < @PeriodEndDate                  --AND P_E.JoiningDate > @PeriodStartDate                    ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0            SELECT  @Terminated = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                  INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  --AND P_E.EndDate BETWEEN @PeriodStartDate AND @PeriodEndDate                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0            SELECT  @OldTerminated = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                   INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  --AND P_E.EndDate < @PeriodStartDate                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0      /*Not received payment*/          SELECT  @NNormalPaye = COUNT(DISTINCT Employee_ID)          FROM    Payroll_EmployeeTrialPayslip as petp      Inner Join dbo.Payroll_Employee AS EMP on emp.Employee_ID = petp.EmployeeID                   INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID          WHERE   Employee_ID NOT IN ( SELECT DISTINCT                                              petp.EmployeeID                                       FROM   Payroll_EmployeeTrialPayslip as petp              --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                                              INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                                                  AND petp.PeriodID = Cyc.Period_ID                                              INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                       WHERE  --eps.PeriodID = @PeriodId                                              --AND ( P_E.EndDate IS NULL OR P_E.EndDate > @PeriodEndDate )                                              ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                                              AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) )                  AND ( EMP.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0                  --AND EMP.JoiningDate < @PeriodStartDate                  --AND EMP.CycleID = @CycleId             SELECT  @NNewPay = COUNT(DISTINCT Employee_ID)          FROM    Payroll_EmployeeTrialPayslip as petp      Inner Join dbo.Payroll_Employee AS EMP on emp.Employee_ID = petp.EmployeeID                   INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID          WHERE   Employee_ID NOT IN ( SELECT DISTINCT                                              petp.EmployeeID                                       FROM   Payroll_EmployeeTrialPayslip as petp              --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                                              INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                                                  AND petp.PeriodID = Cyc.Period_ID                                               INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                       WHERE  --eps.PeriodID = @PeriodId                                              --AND ( P_E.EndDate IS NULL OR P_E.EndDate > @PeriodEndDate )                                              --AND P_E.JoiningDate > @PeriodStartDate                                                ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                                              AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) )             AND ( EMP.Employee_ID = @EmployeeId OR @EmployeeId = 0 )             AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0             --AND EMP.JoiningDate > @PeriodStartDate             --AND EMP.CycleID = @CycleId            SELECT  @NNewTerminated = COUNT(DISTINCT Employee_ID)          FROM    Payroll_EmployeeTrialPayslip as petp      Inner Join dbo.Payroll_Employee AS EMP on emp.Employee_ID = petp.EmployeeID                   INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID          WHERE   Employee_ID NOT IN ( SELECT DISTINCT                                              petp.EmployeeID                                       FROM   Payroll_EmployeeTrialPayslip as petp              --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                                              INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                                                  AND petp.PeriodID = Cyc.Period_ID                                               INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                       WHERE  --eps.PeriodID = @PeriodId                                              --AND P_E.EndDate < @PeriodEndDate                                              --AND P_E.JoiningDate > @PeriodStartDate                                               ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                                              AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) )             AND ( EMP.Employee_ID = @EmployeeId OR @EmployeeId = 0 )             AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0             --AND EMP.EndDate < @PeriodEndDate             --AND EMP.JoiningDate > @PeriodStartDate             --AND EMP.CycleID = @CycleId            SELECT  @NTerminated = COUNT(DISTINCT Employee_ID)          FROM    Payroll_EmployeeTrialPayslip as petp      Inner Join dbo.Payroll_Employee AS EMP on emp.Employee_ID = petp.EmployeeID                   INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID          WHERE   Employee_ID NOT IN ( SELECT DISTINCT                                              petp.EmployeeID                                       FROM   Payroll_EmployeeTrialPayslip as petp              --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                                              INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                                                  AND petp.PeriodID = Cyc.Period_ID                                              INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                       WHERE  --eps.PeriodID = @PeriodId                                              --AND P_E.EndDate BETWEEN @PeriodStartDate AND @PeriodEndDate                                               ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                                              AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) )             AND ( EMP.Employee_ID = @EmployeeId OR @EmployeeId = 0 )             AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0             --AND EMP.EndDate BETWEEN @PeriodStartDate AND @PeriodEndDate             --AND EMP.CycleID = @CycleId            SELECT  @NOldTerminated = COUNT(DISTINCT Employee_ID)          FROM    Payroll_EmployeeTrialPayslip as petp      Inner Join dbo.Payroll_Employee AS EMP on emp.Employee_ID = petp.EmployeeID                   INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID          WHERE   Employee_ID NOT IN ( SELECT DISTINCT                                              petp.EmployeeID                                       FROM   Payroll_EmployeeTrialPayslip as petp              --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                                              INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                                                  AND petp.PeriodID = Cyc.Period_ID                                              INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID                                       WHERE  --eps.PeriodID = @PeriodId                                              --AND P_E.EndDate < @PeriodStartDate                                               ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                                              AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) )             AND ( EMP.Employee_ID = @EmployeeId OR @EmployeeId = 0 )             AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0             --AND EMP.EndDate < @PeriodStartDate              --AND EMP.CycleID = @CycleId     /*Brought Forward*/          SELECT  @BroughForward = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                   INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --Cyc.FinancialYear = @PreFinYear                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0                  --AND Cyc.CycleID = @CycleId             SELECT  @NewJoin = COUNT(DISTINCT petp.EmployeeID)          FROM    Payroll_EmployeeTrialPayslip as petp       --Inner Join dbo.Payroll_EmployeePayslip AS EPS on eps.EmployeeID = petp.EmployeeID                  INNER JOIN dbo.Payroll_Employee AS P_E ON petp.EmployeeID = P_E.Employee_ID                  INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON P_E.CycleID = Cyc.CycleID                                                                      AND petp.PeriodID = Cyc.Period_ID                   INNER JOIN dbo.Payroll_Position AS PP ON P_E.PositionID = PP.Position_ID          WHERE   --eps.PeriodID = @PeriodId                  --AND P_E.JoiningDate BETWEEN @PeriodStartDate AND @PeriodEndDate                   ( P_E.Employee_ID = @EmployeeId OR @EmployeeId = 0 )                  AND ( PP.DepartmentID = @DepartmentId OR @DepartmentId = 0 ) and [TaxSavePurpose] = 0        /* SURI - Commented because trial run doesn't need to go to final run history table          DECLARE @Tbl TABLE              (                Id INT IDENTITY(1, 1) ,                EmployeeId INT              )          --INSERT  INTO @Tbl          --        SELECT DISTINCT          --                EmployeeId          --        FROM    Payroll_EmployeeFinalRunHistory AS H          --                INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                  --WHERE FinancialYear = @FinYear                          --AND PeriodEndDate <= @PeriodEndDate                          --AND H.CycleId = @CycleId            DECLARE @Start INT = 1 ,              @End INT ,              @Top1 INT ,              @Last1 INT          SELECT  @End = COUNT(1)          FROM    @Tbl              WHILE @Start < @End               BEGIN                  SELECT  @EmployeeId = EmployeeId                  FROM    @Tbl                  WHERE   Id = @Start                  SET @Start += 1                    IF ( SELECT COUNT(EmployeeId)                       FROM   Payroll_EmployeeFinalRunHistory AS H                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                       WHERE  --FinancialYear = @FinYear                               EmployeeId = @EmployeeId                              --AND PeriodEndDate <= @PeriodEndDate                       GROUP BY EmployeeId, H.CycleId                     ) > 1                       BEGIN           /*                          IF ( SELECT TOP 1                                      H.CycleID                               FROM   Payroll_EmployeeFinalRunHistory AS H                                      INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                               WHERE  --FinancialYear = @FinYear                                       EmployeeId = @EmployeeId                                      --AND PeriodEndDate <= @PeriodEndDate                               ORDER BY ID DESC                             ) = @CycleId                               BEGIN                                  SET @TransferedInYTD += 1                              END                          ELSE                               BEGIN                                  SET @TransferedOutYTD += 1                              END         */         /*                          IF ( SELECT COUNT(*)                               FROM   Payroll_EmployeeFinalRunHistory AS H                                      INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                               WHERE  --FinancialYear = @FinYear                                       EmployeeId = @EmployeeId                                      --AND PeriodEndDate <= @PeriodEndDate                             ) > 2                              AND ( SELECT TOP 1                                              H.CycleID                                    FROM      Payroll_EmployeeFinalRunHistory AS H                                              INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                                    WHERE     --FinancialYear = @FinYear                                               EmployeeId = @EmployeeId                                              --AND PeriodEndDate <= @PeriodEndDate                                    ORDER BY  ID DESC                                  ) = @CycleId           */                              BEGIN                                  SELECT TOP 1                                          @Last1 = H.ID                                  FROM    Payroll_EmployeeFinalRunHistory AS H                                          INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                                  WHERE   --FinancialYear = @FinYear                                           EmployeeId = @EmployeeId                                          --AND PeriodEndDate <= @PeriodEndDate                                  ORDER BY ID DESC                                        SELECT TOP 1                                          @Top1 = H.ID                                  FROM    Payroll_EmployeeFinalRunHistory AS H                                          INNER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON H.PeriodId = Cyc.Period_ID                                  WHERE   --FinancialYear = @FinYear                                           EmployeeId = @EmployeeId                                          --AND PeriodEndDate <= @PeriodEndDate                                          --AND H.CycleId = @CycleId                                  ORDER BY ID DESC                                  IF ( SELECT COUNT(*)                                       FROM   Payroll_EmployeeFinalRunHistory AS H                                       WHERE  EmployeeId = @EmployeeId                                              AND ID BETWEEN @Top1 AND @Last1                                              --AND CycleId <> @CycleId                                     ) = 1                                       BEGIN                                          SET @Reinstead += 1                                      END                              END                      END                  END     */          SELECT  ISNULL(@NormalPaye, 0) AS NormalPaye, ISNULL(@NewPay, 0) AS NewPaye, ISNULL(@NewTerminated, 0) AS NewTerminated, ISNULL(@Terminated, 0) AS Terminated, ISNULL(@OldTerminated, 0) AS OldTerminated, ISNULL(@NNormalPaye, 0) AS NNormalPaye, ISNULL(@NNewPay, 0) AS NNewPaye, ISNULL(@NNewTerminated, 0) AS NNewTerminated, ISNULL(@NTerminated, 0) AS NTerminated, ISNULL(@NOldTerminated, 0) AS NOldTerminated, ISNULL(@BroughForward, 0) AS BroughForward, ISNULL(@NewJoin, 0) AS NewJoin, ISNULL(@TransferedInYTD, 0) AS TransferedInYTD, @TransferedIn AS TransferedIn, @Reinstead AS Reinstead, @LessTermination AS LessTermination, @TransferedOutYTD AS TransferedOutYTD, @TransferedOut AS TransferedOut        END    

GO

-- ============================================
-- SP: Payroll_RunSummaryTrial_rpt
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  MarioT 2015/05/28 Same as Payroll_RunSummary_rpt but using Trial Run  -- TP30318 : Suri Kandukuri : updated stored procedure for trial run.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_RunSummaryTrial_rpt]   @PeriodId INT = 0,     @UserName NVARCHAR(100),     @EmployeeId INT,     @DepartmentId INT    AS    BEGIN     DECLARE @PeriodEndDate DATETIME, @PeriodStartDate DATETIME     --SELECT @PeriodEndDate = PeriodEndDate, @PeriodStartDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId             SELECT   @PeriodEndDate=PeriodEndDate   FROM Payroll_TrailRun_History trh   LEFT JOIN Payroll_CyclePeriodDetails cpd ON cpd.Period_ID=trh.PeriodID   WHERE 1=1   AND trh.Status='InProcess' AND trh.Porcessed=0       SELECT      CSS.ScoaCode AS VoteNo,      CSS.ScoaCode AS ItemCode, CSCS.ScoaCode AS CostingCode, CSFS.ScoaCode AS FunctionCode,       CSRS.ScoaCode AS ReginalCode, CSFundS.ScoaCode AS FundCode, CSPS.ScoaCode AS ProjectCode,       CASE WHEN IRP5.TransactionTypeID IN (1, 3) and [TaxSavePurpose] = 0 THEN petpp.Amount ELSE 0 END AS Employeer,       CASE WHEN IRP5.TransactionTypeID IN (2, 4) and [TaxSavePurpose] = 0 THEN petpp.Amount ELSE 0 END AS Employee,      Emp.FirstName, Emp.Surname, TT.TransactionTypeDesc, SH.SalaryHeadTitle AS PayrollSalaryHeadName,    dbo.GetMonthNameFromId(MONTH(@PeriodEndDate)) AS ProcessingMonth, TransactionType_ID     FROM Payroll_EmployeeTrialPayslip  petpp  --  inner join Payroll_EmployeePayslip EPS on EPS.EmployeeID = petpp.EmployeeID       --dbo.Payroll_EmployeePayslip AS EPS      INNER JOIN dbo.Payroll_EmployeePayrollDefinition AS EPD ON petpp.PayrollDefinationID = EPD.EmployeePayrollDefinition_ID      INNER JOIN dbo.Payroll_SalaryHead AS SH ON EPD.PayrollSalaryHeadID = SH.SalaryHead_ID      INNER JOIN dbo.Payroll_IRP5Code AS IRP5 ON SH.IRP5CodeId = IRP5.IRP5Code_ID      INNER JOIN dbo.Const_TransactionType AS TT ON IRP5.TransactionTypeID = TT.TransactionType_ID      INNER JOIN dbo.Payroll_Employee AS Emp ON Emp.Employee_ID = petpp.EmployeeID      INNER JOIN dbo.Payroll_Position AS PP ON Emp.PositionID = PP.Position_ID      INNER JOIN dbo.Const_Department AS Dep ON Dep.Department_ID = PP.DepartmentID      INNER JOIN dbo.Const_SCOA_Structure AS CSS ON EPD.SCOAItemID =  CSS.ScoaID      INNER JOIN dbo.Const_SCOA_Costing_Structure AS CSCS ON CSCS.ScoaID = EPD.SCOACostingID      INNER JOIN dbo.Const_SCOA_Function_Structure AS CSFS ON CSFS.ScoaID = EPD.FunctionCodeID      INNER JOIN dbo.Const_SCOA_Regional_Structure AS CSRS ON CSRS.ScoaID = EPD.SCOARegionID      INNER JOIN dbo.Const_SCOA_Funds_Structure AS CSFundS ON CSFundS.ScoaID = EPD.SCOAFundsID      INNER JOIN dbo.Const_SCOA_Project_Structure AS CSPS ON CSPS.ScoaID = EPD.SCOAProjectID     WHERE --PeriodID = @PeriodId     (Emp.Employee_ID = @EmployeeId OR @EmployeeId = 0)     AND (Dep.Department_ID = @DepartmentId OR @DepartmentId = 0) and [TaxSavePurpose] = 0   ORDER BY FirstName    END      

GO

-- ============================================
-- SP: Payroll_SalaryHeadlstByTransType_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL    -- Create date: 28 JAN 2014    -- Description: FILL SALARY HEAD DROP DOWN    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_SalaryHeadlstByTransType_sp]   @TransactionTypeID INT    AS    BEGIN     SELECT PH.SalaryHead_ID , PH.SalaryHeadTitle AS PayrollSalaryHeadName from Payroll_IRP5Code IRP     INNER JOIN Payroll_SalaryHead PH on PH.IRP5CodeId= IRP.IRP5Code_ID     where IRP.TransactionTypeID=@TransactionTypeID    END    

GO

-- ============================================
-- SP: Payroll_SalaryIncreaseList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date:  03/04/2014  -- Description: <Description,,>  -- Payroll_SalaryIncreaseList_sp 32  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryIncreaseList_sp]      @JobProfileID INT  AS       BEGIN          SELECT  SalaryIncrement_ID, Payroll_JobProfile.JobTitle, Grade, IncreasePerncentage, CONVERT(NVARCHAR(12), EffectiveDate, 103) AS EffectiveDate, Payroll_SalaryIncrease.Enabled          FROM    dbo.Payroll_SalaryIncrease                  INNER JOIN dbo.Payroll_JobProfile ON JobProfile_ID = JobProfileID          WHERE   ( JobProfileID = @JobProfileID                    OR @JobProfileID = 0                  )      END  

GO

-- ============================================
-- SP: Payroll_SalaryIncrementProcess_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 03/04/2014  -- Description: Salary increment process  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-08-17 - Seipei Mathole: commented the update line for due to the fact that Const_ProfileGroupDetails does not exist  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryIncrementProcess_sp]   @PeriodToDate DATETIME  AS  BEGIN   SET NOCOUNT ON;     DECLARE @SalaryIncreaseTbl TABLE   (    SalaryIncrementID INT,    IncreasePerncentage  DECIMAL(18,2),    ProfileSubGroupID INT,    Grade INT,    [RowNo]  INT   )     DECLARE @ProfileGroupTbl TABLE   (    ProfileGroupDetailsID INT,    FixedSalary  DECIMAL(18,2),    WDPM DECIMAL(18,2),    WHPM DECIMAL(18,2),    [RowNo]  INT   )     DECLARE @Count1 INT, @Start1 INT   DECLARE @Count2 INT, @Start2 INT   DECLARE @ProfileSubGroupID INT, @Grade INT, @ProfileGroupDetailsID INT, @SalaryIncrementID INT   DECLARE @FixedSalary DECIMAL(18,2), @WDPM DECIMAL(18,2), @WHPM DECIMAL(18,2), @RPD DECIMAL(18,2),      @WHPD DECIMAL(18,2), @RPH DECIMAL(18,2), @AfterIncrementFixedSalary DECIMAL(18,2),     @IncreasePerncentage DECIMAL(18,2)   DECLARE @DATABASENAME NVARCHAR(50)   DECLARE @SQLQuery NVARCHAR(MAX)     SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'     DELETE FROM @SalaryIncreaseTbl      INSERT INTO @SalaryIncreaseTbl   SELECT SalaryIncrement_ID, IncreasePerncentage, JobProfileID, Grade, ROW_NUMBER()OVER (ORDER BY SalaryIncrement_ID ASC)    FROM dbo.Payroll_SalaryIncrease    WHERE Enabled = 1 AND IsApplied = 0 AND CAST(EffectiveDate AS DATE) < @PeriodToDate     SELECT @Count1 = COUNT(1) FROM @SalaryIncreaseTbl   SET @Start1 = 1      WHILE(@Start1 <= @Count1)   BEGIN    SELECT @SalaryIncrementID = SalaryIncrementID, @IncreasePerncentage = IncreasePerncentage,       @ProfileSubGroupID = ProfileSubGroupID, @Grade = Grade     FROM @SalaryIncreaseTbl WHERE [RowNo]= @Start1        DELETE FROM @ProfileGroupTbl        --INSERT INTO @ProfileGroupTbl    --Select ProfileGroupDetails_ID, FixedSalary_Monthly, WDPM_Monthly, WHPM_Monthly,    --ROW_NUMBER()OVER (ORDER BY ProfileGroupDetails_ID ASC)     --FROM dbo.Const_ProfileGroupDetails WHERE ProfileSubGroupID = @ProfileSubGroupID AND Grade = @Grade        SELECT @Count2 = COUNT(1) FROM @ProfileGroupTbl    SET @Start2 = 1        WHILE(@Start2 <= @Count2)    BEGIN     Select @ProfileGroupDetailsID = ProfileGroupDetailsID, @FixedSalary = FixedSalary,        @WDPM = WDPM, @WHPM = WHPM     FROM @ProfileGroupTbl WHERE [RowNo]= @Start2          SET @AfterIncrementFixedSalary = CAST((@FixedSalary * @IncreasePerncentage) / 100.00 AS DECIMAL(18,2))     IF(@AfterIncrementFixedSalary IS NULL) SET @AfterIncrementFixedSalary = 0          SET @FixedSalary = (@FixedSalary + @AfterIncrementFixedSalary)     SET @RPD = CAST((@FixedSalary / @WDPM) AS DECIMAL(18,2))     SET @WHPD = CAST((@WHPM / @WDPM) AS DECIMAL(18,2))     SET @RPH = CAST((@RPD / @WHPD) AS DECIMAL(18,2))          SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aConst_ProfileGroupDetails      (        AuditUserID , AuditDate , AuditUser , ProfileGroupDetails_ID , ProfileGroupID ,        ProfileSubGroupID , Grade , WHPD_Other , WDPW_Other , RPD_Other , RPH_Other , RPW_Other ,        WHPM_Monthly , WDPM_Monthly , Enabled , DateCaptured , CapturerID , DateModified ,        ModifierID , WHPD_Monthly , RPD_Monthly , RPH_Monthly , FixedSalary_Monthly       )            SELECT        1, GETDATE(), ''Admin User'', ProfileGroupDetails_ID , ProfileGroupID ,        ProfileSubGroupID , Grade , WHPD_Other , WDPW_Other , RPD_Other , RPH_Other , RPW_Other ,        WHPM_Monthly , WDPM_Monthly , Enabled , DateCaptured , CapturerID , DateModified ,        ModifierID , WHPD_Monthly , RPD_Monthly , RPH_Monthly , FixedSalary_Monthly      FROM Const_ProfileGroupDetails      WHERE ProfileGroupDetails_ID = ' + CONVERT(NVARCHAR(50), @ProfileGroupDetailsID)            EXEC(@SQLQuery)          --UPDATE Const_ProfileGroupDetails SET FixedSalary_Monthly = @FixedSalary, RPD_Monthly = @RPD,     --WHPD_Monthly = @WHPD, RPH_Monthly = @RPH WHERE ProfileGroupDetails_ID = @ProfileGroupDetailsID          SET @Start2 = @Start2 + 1    END        SET @SQLQuery = ''    SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_SalaryIncrease      (        AuditUserID , AuditDate , AuditUser , SalaryIncrement_ID , ProfileSubGroupID , Grade ,       IncreasePerncentage , EffectiveDate , IsApplied , Enabled , DateCaptured , CapturerID ,       DateModified , ModifierID      )            SELECT        1, GETDATE(), ''Admin User'', SalaryIncrement_ID , ProfileSubGroupID , Grade ,       IncreasePerncentage , EffectiveDate , IsApplied , Enabled , DateCaptured , CapturerID ,       DateModified , ModifierID      FROM Const_ProfileGroupDetails      WHERE SalaryIncrement_ID = ' + CONVERT(NVARCHAR(50), @SalaryIncrementID)           EXEC(@SQLQuery)        UPDATE dbo.Payroll_SalaryIncrease SET IsApplied = 1 WHERE SalaryIncrement_ID = @SalaryIncrementID        SET @Start1 = @Start1 + 1   END  END  

GO

-- ============================================
-- SP: Payroll_SalaryTransactionDetail_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Myroshnychenko Ivan  -- Create date: 10/11/2020  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_SalaryTransactionDetail_sp]   @TaxYear NVARCHAR(MAX),   @Cycle INT,   @Period INT,   @TransactionType  INT ,   @SalaryTransaction NVARCHAR(MAX)  ,   @Department INT,   @ExcessValue FLOAT,      @TrialRun BIT    AS   BEGIN    DECLARE @Periods NVARCHAR(MAX) =''    DECLARE @PurpuseYear INT = CAST(LEFT(@TaxYear,4) AS INT) + 1    IF(@Cycle !=0)   SELECT @Periods = CAST(@Period AS NVARCHAR(MAX)) + ','  ELSE   SELECT @Periods = @Periods + CAST(Period_ID AS NVARCHAR(MAX)) + ','    FROM Payroll_CyclePeriodDetails    WHERE TaxYear = @TaxYear     AND Processed != @TrialRun     AND Enabled = 1     AND PeriodEndDate BETWEEN (SELECT PCPD.PeriodStartDate FROM Payroll_CyclePeriodDetails AS PCPD WHERE PCPD.Period_ID = @Period)      AND (SELECT PCPD.PeriodEndDate FROM Payroll_CyclePeriodDetails AS PCPD WHERE PCPD.Period_ID = @Period)    DROP TABLE IF EXISTS #Results  CREATE TABLE #Results  (  EmployeeID INT,  Amount FLOAT,  TransactionTypeID INT,  PeriodID INT,  SalaryHeadID INT  )    IF (@TrialRun = 0)   BEGIN    INSERT INTO #Results(EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID)    SELECT EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID    FROM Payroll_PayrollResults     WHERE (CycleID = @Cycle OR @Cycle = 0)      AND (@TransactionType = 0 OR TransactionTypeID = @TransactionType )     AND SalaryHeadID IN (SELECT VALUE FROM  STRING_SPLIT(@SalaryTransaction,','))     AND Amount> @ExcessValue      AND TaxYear = @PurpuseYear     AND PeriodID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))     AND (DepartmentID = @Department OR @Department=0)   END  ELSE   BEGIN    INSERT INTO #Results(EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID)    SELECT EmployeeID, Amount, TransactionTypeID, PeriodID, SalaryHeadID    FROM Payroll_TrialResults     WHERE (CycleID = @Cycle OR @Cycle = 0)      AND (@TransactionType = 0 OR TransactionTypeID = @TransactionType )     AND SalaryHeadID IN (SELECT VALUE FROM  STRING_SPLIT(@SalaryTransaction,','))     AND Amount> @ExcessValue      AND TaxYear = @PurpuseYear     AND PeriodID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))     AND (DepartmentID = @Department OR @Department=0)   END    SELECT P_PR.EmployeeId AS EmployeeNumber     ,PE.FirstName AS EmployeeName     ,PE.Surname AS EmployeeSurname    ,C_Dep.DepartmentDesc AS Department    ,C_Div.DivisionDesc AS Division     ,C_C.CycleDesc AS PayrollCycle     ,C_TT.TransactionTypeDesc AS TransactionType        , P_SH.SalaryHeadName AS SalaryTranaction    , SUM(P_PR.Amount) AS Amount    FROM #Results AS P_PR  JOIN Payroll_Employee AS PE     ON P_PR.EmployeeID = PE.Employee_ID  CROSS APPLY (SELECT TOP 1 P_EH.EmployeeID, P_EH.CycleID, P_EH.DepartmentID, P_EH.DivisionID    FROM Payroll_EmployeeHistory as P_EH       JOIN Payroll_CyclePeriodDetails AS P_CPD     ON P_CPD.Period_ID IN (SELECT VALUE FROM  STRING_SPLIT(@Periods,','))    WHERE P_EH.EmployeeID = PE.Employee_ID     AND (P_EH.StartDate < P_CPD.PeriodEndDate AND P_EH.EndDate >P_CPD.PeriodStartDate)     AND P_EH.Enabled = 1) AS P_E  JOIN Const_Cycle AS C_C   ON P_E.CycleID = C_C.Cycle_ID  JOIN Const_Department AS C_Dep   ON P_E.DepartmentID = C_Dep.Department_ID  JOIN Const_Division AS C_Div    ON P_E.DivisionID = C_Div.Division_ID  JOIN Const_TransactionType AS C_TT   ON P_PR.TransactionTypeID = C_TT.TransactionType_ID   JOIN Payroll_CyclePeriodDetails AS P_CPD   ON P_PR.PeriodID=P_CPD.Period_ID  JOIN Payroll_SalaryHead AS P_SH   ON P_PR.SalaryHeadID=P_SH.SalaryHead_ID  GROUP BY P_PR.EmployeeId   , P_PR.PeriodID   , P_SH.SalaryHeadName   , PE.FirstName   , PE.Surname   , P_CPD.Period_ID   , C_Dep.DepartmentDesc    , C_Div.DivisionDesc    , C_C.CycleDesc    , C_TT.TransactionTypeDesc   ORDER BY P_SH.SalaryHeadName    DROP TABLE IF EXISTS #Results    END

GO

-- ============================================
-- SP: Payroll_SalaryTransactionPerRaceAndGenderDetailedNoTransaction
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2021-01-06  -- Description: Used as a dataset for SalaryTransactionPerRaceAndGenderDetailedNoTransaction report   --              (Payroll_SalaryTransactionPerRaceAndGenderDetailedNoTransaction.rdl)  --              Returns Detailed Employees which are not linked to selected Salary Heads or linked but without transactions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryTransactionPerRaceAndGenderDetailedNoTransaction]   @TaxYear VARCHAR(9) = ''      ,@CycleId INT = 0   ,@Period VARCHAR(500) = ''       ,@SalaryHeadIds VARCHAR(MAX)        ,@DepartmentId INT = 0        ,@DivisionId INT = 0        ,@RemunerationType INT = 0    AS    BEGIN        DECLARE        @RemunerationTypeAll INT = 0        ,@RemunerationTypeTaskGrade INT = 1        ,@RemunerationTypeUpperLimit INT = 2        ,@RemunerationTypeWage INT = 3;      ;WITH CyclePeriods  AS  (   SELECT DISTINCT    [Period_ID],    [CycleID],    [TaxYear]   FROM    Payroll_CyclePeriodDetails   WHERE    [Enabled] = 1   AND (ISNULL(@TaxYear, '') = '' OR [TaxYear] = @TaxYear)   AND (ISNULL(@Period, '') = '' OR [ProcessingMonth] = @Period)   AND (ISNULL(@CycleId, 0) = 0 OR [CycleID] = @CycleId)  ),  TaxYearEmployees  AS  (        SELECT DISTINCT PE.*, PEPDF.[PeriodID] FROM Payroll_Employee AS PE        JOIN Payroll_EmployeePayrollDefinitionFinal AS PEPDF             ON PE.Employee_ID = PEPDF.EmployeeID   INNER JOIN    CyclePeriods cp ON PEPDF.[PeriodID] = cp.[Period_ID]  )    SELECT DISTINCT      PSH.SalaryHead_ID AS SalaryHeadId       ,PSH.SalaryHeadName AS SalaryHeadName        ,PE.Employee_ID AS EmployeeNumber       ,PE.Initials AS Initials       ,PE.Surname AS Surname       ,Department.DepartmentDesc AS Department       ,Division.DivisionDesc AS Division       ,PE.IsYough AS Youth       ,PE.Isforeigner AS Foreigner       ,PE.EquityDisabled AS Disability       ,CEG.Ethnic_ID AS RaceId       ,CEG.EthnicDesc AS Race       ,CG.Gender_ID AS GenderId       ,CG.GenderDesc AS Gender       ,(CASE            WHEN PJP.TaskGradeId IS NOT NULL               THEN @RemunerationTypeTaskGrade           WHEN PJP.TaskGradeId IS NULL AND ISNULL(PJP.LimitID, 0) > 0               THEN @RemunerationTypeUpperLimit           WHEN PJP.TaskGradeId IS NULL AND PJP.LimitID IS NULL               THEN @RemunerationTypeWage       END) AS RemunerationType     FROM TaxYearEmployees AS PE    LEFT JOIN Payroll_EmployeeTermination AS PET ON PET.EmployeeID = PE.Employee_ID AND PET.Complete = 1    JOIN Const_EthnicGroup AS CEG        ON PE.EthnicGroupID = CEG.Ethnic_ID    JOIN Const_Gender AS CG        ON PE.GenderID = CG.Gender_ID    JOIN Payroll_Position AS PP        ON PE.PositionID = PP.Position_ID    JOIN Const_Department AS Department        ON PP.DepartmentID = Department.Department_ID    JOIN Const_Division AS Division        ON PP.DivisionID = Division.Division_ID    JOIN Payroll_JobProfile AS PJP        ON PP.JobProfileID = PJP.JobProfile_ID    JOIN Payroll_SalaryHead AS PSH        ON PSH.SalaryHead_ID IN (SELECT * FROM STRING_SPLIT(@SalaryHeadIds, ','))    OUTER APPLY(        SELECT TOP 1 ep.* FROM Payroll_EmployeePayrollDefinitionFinal ep      WHERE EmployeeID = PE.Employee_ID            AND PayrollSalaryHeadID = PSH.SalaryHead_ID    AND ep.[PeriodID] = pe.[PeriodID]  ) AS PEPDF    OUTER APPLY(        SELECT TOP 1 * FROM Payroll_PayrollResults        WHERE PeriodID = pe.[PeriodID]          AND PE.Employee_ID = EmployeeID             AND SalaryHeadID = PSH.SalaryHead_ID    ) AS PPR        JOIN Payroll_CyclePeriodDetails AS PCPD ON PCPD.Period_ID = pe.[PeriodID]    CROSS APPLY (        SELECT TOP 1 PPHI.JobProfileID         FROM Payroll_PositionHistory AS PPHI         WHERE PPHI.EmployeeID = PEPDF.EmployeeID            AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PPHI.StartDate AND PPHI.EndDate)            AND PPHI.Enabled = 1    ) AS PPH    JOIN Payroll_JobProfileHistory AS PJPH ON PJPH.JobProfileID = PPH.JobProfileID        AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PJPH.StartDate AND PJPH.EndDate)        AND PJPH.Enabled = 1    WHERE ((PEPDF.EmployeePayrollDefinitionFinal_ID IS NULL) OR (PEPDF.EmployeePayrollDefinitionFinal_ID IS NOT NULL AND PPR.PayrollResult_ID IS NULL))        AND PEPDF.Enabled = 1        AND (Department.Department_ID = @DepartmentId OR @DepartmentId = 0)        AND (Division.Division_ID = @DivisionId OR @DivisionId = 0)        AND (@RemunerationType = @RemunerationTypeAll            OR (                (@RemunerationType = @RemunerationTypeTaskGrade AND PJPH.TaskGradeId IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeUpperLimit AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeWage AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NULL))        )        END

GO

-- ============================================
-- SP: Payroll_SalaryTransactionPerRaceAndGenderDetailedTransaction
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-31  -- Description: Used as a dataset for SalaryTransactionPerRaceAndGenderDetailedTransaction report   --              (Payroll_SalaryTransactionPerRaceAndGenderDetailedTransaction.rdl)  --              Returns Detailed Salary Transactions Per Race And Gender   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryTransactionPerRaceAndGenderDetailedTransaction]   @TaxYear VARCHAR(9) = ''      ,@CycleId INT = 0   ,@Period VARCHAR(500) = ''       ,@SalaryHeadIds VARCHAR(MAX)        ,@DepartmentId INT = 0        ,@DivisionId INT = 0        ,@RemunerationType INT = 0    AS    BEGIN        DECLARE @RemunerationTypeAll INT = 0    ,@RemunerationTypeTaskGrade INT = 1    ,@RemunerationTypeUpperLimit INT = 2    ,@RemunerationTypeWage INT = 3;    ;WITH CyclePeriods  AS  (   SELECT DISTINCT    [Period_ID],    [CycleID],    [TaxYear]   FROM    Payroll_CyclePeriodDetails   WHERE          (ISNULL(@TaxYear, '') = '' OR [TaxYear] = @TaxYear)   AND (ISNULL(@Period, '') = '' OR [ProcessingMonth] = @Period)   AND (ISNULL(@CycleId, 0) = 0 OR [CycleID] = @CycleId)  )      SELECT        PSH.SalaryHead_ID AS SalaryHeadId       ,PSH.SalaryHeadName AS SalaryHeadName       ,PE.Employee_ID AS EmployeeNumber       ,PE.Initials AS Initials       ,PE.Surname AS Surname       ,Department.DepartmentDesc AS Department       ,Division.DivisionDesc AS Division       ,IIF(PE.IsYough = 1, 'Yes', 'No') AS Youth       ,IIF(PE.Isforeigner = 1, 'Yes', 'No') AS Foreigner       ,IIF(PE.EquityDisabled = 1, 'Yes', 'No') AS Disability       ,CEG.Ethnic_ID AS RaceId       ,CEG.EthnicDesc AS Race       ,CG.Gender_ID AS GenderId       ,CG.GenderDesc AS Gender       ,(CASE            WHEN PJP.TaskGradeId IS NOT NULL               THEN 'Task Grade'           WHEN PJP.TaskGradeId IS NULL AND ISNULL(PJP.LimitID, 0) > 0               THEN 'Upper Limit'           WHEN PJP.TaskGradeId IS NULL AND PJP.LimitID IS NULL               THEN 'Wage'       END) AS RemunerationType       ,ISNULL(PPR.Amount, 0) AS CurrentAmount       ,ISNULL(YearAmount.Amount, 0) AS YearToDate    FROM Payroll_EmployeePayrollDefinitionFinal AS PEPDF    INNER JOIN   CyclePeriods cp ON PEPDF.[PeriodID] = cp.[Period_ID]  JOIN Payroll_SalaryHead AS PSH        ON PEPDF.PayrollSalaryHeadID = PSH.SalaryHead_ID    LEFT JOIN Payroll_PayrollResults AS PPR        ON PEPDF.EmployeeID = PPR.EmployeeID            AND PSH.SalaryHead_ID = PPR.SalaryHeadID            AND PEPDF.PeriodID = PPR.PeriodID    JOIN Payroll_Employee AS PE        ON PEPDF.EmployeeID = PE.Employee_ID    LEFT JOIN Payroll_EmployeeTermination AS PET ON PET.EmployeeID = PE.Employee_ID AND PET.Complete = 1    JOIN Const_EthnicGroup AS CEG        ON PE.EthnicGroupID = CEG.Ethnic_ID    JOIN Const_Gender AS CG        ON PE.GenderID = CG.Gender_ID    JOIN Payroll_Position AS PP        ON PE.PositionID = PP.Position_ID    JOIN Const_Department AS Department        ON PP.DepartmentID = Department.Department_ID    JOIN Const_Division AS Division        ON PP.DivisionID = Division.Division_ID    JOIN Payroll_JobProfile AS PJP        ON PP.JobProfileID = PJP.JobProfile_ID    CROSS APPLY (        SELECT            SUM(SubPPR.Amount) AS Amount        FROM Payroll_CyclePeriodDetails AS SubCPD        JOIN Payroll_PayrollResults AS SubPPR            ON SubPPR.CycleID = @CycleId            AND SubPPR.TaxYear = CAST(SUBSTRING(SubCPD.TaxYear, 6, 9) AS INT)            AND SubPPR.EmployeeID = PEPDF.EmployeeID            AND SubPPR.SalaryHeadID = PEPDF.PayrollSalaryHeadID            AND SubPPR.PeriodID = SubCPD.Period_ID        WHERE SubCPD.PeriodEndDate <= (            SELECT PeriodEndDate            FROM Payroll_CyclePeriodDetails            WHERE Period_ID = cp.[Period_ID]        )        AND SubCPD.CycleID = cp.[CycleID]        AND SubCPD.TaxYear = cp.[TaxYear]        AND SubCPD.Enabled = 1    ) AS YearAmount    JOIN Payroll_CyclePeriodDetails AS PCPD ON PCPD.Period_ID = cp.[Period_ID]    CROSS APPLY (        SELECT TOP 1 PPHI.JobProfileID         FROM Payroll_PositionHistory AS PPHI         WHERE PPHI.EmployeeID = PEPDF.EmployeeID            AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PPHI.StartDate AND PPHI.EndDate)            AND PPHI.Enabled = 1    ) AS PPH    JOIN Payroll_JobProfileHistory AS PJPH ON PJPH.JobProfileID = PPH.JobProfileID        AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PJPH.StartDate AND PJPH.EndDate)        AND PJPH.Enabled = 1    WHERE PSH.SalaryHead_ID IN (SELECT * FROM STRING_SPLIT(@SalaryHeadIds, ','))        AND PEPDF.Enabled = 1        AND (Department.Department_ID = @DepartmentId OR @DepartmentId = 0)        AND (Division.Division_ID = @DivisionId OR @DivisionId = 0)        AND (@RemunerationType = @RemunerationTypeAll            OR (                (@RemunerationType = @RemunerationTypeTaskGrade AND PJPH.TaskGradeId IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeUpperLimit AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeWage AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NULL))        )        END

GO

-- ============================================
-- SP: Payroll_SalaryTransactionPerRaceAndGenderSummaryNoTransaction
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2021-01-06  -- Description: Used as a dataset for SalaryTransactionPerRaceAndGenderSummaryNoTransaction report   --              (Payroll_SalaryTransactionPerRaceAndGenderSummaryNoTransaction.rdl)  --              Returns Summary Employees which are not linked to selected Salary Heads or linked but without transactions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryTransactionPerRaceAndGenderSummaryNoTransaction]    @TaxYear VARCHAR(9) = ''      ,@CycleId INT = 0   ,@Period VARCHAR(500)      ,@SalaryHeadIds VARCHAR(MAX)        ,@DepartmentId INT = 0        ,@DivisionId INT = 0        ,@RemunerationType INT = 0    AS    BEGIN        DECLARE @RemunerationTypeAll INT = 0    ,@RemunerationTypeTaskGrade INT = 1    ,@RemunerationTypeUpperLimit INT = 2    ,@RemunerationTypeWage INT = 3;    ;WITH CyclePeriods  AS  (   SELECT DISTINCT    [Period_ID],    [CycleID],    [TaxYear]   FROM    Payroll_CyclePeriodDetails   WHERE    [Enabled] = 1      AND (ISNULL(@TaxYear, '') = '' OR [TaxYear] = @TaxYear)   AND (ISNULL(@Period, '') = '' OR [ProcessingMonth] = @Period)   AND (ISNULL(@CycleId, 0) = 0 OR [CycleID] = @CycleId)  ),  TaxYearEmployees  AS  (        SELECT DISTINCT PE.*, cp.[Period_ID] FROM Payroll_Employee AS PE        JOIN Payroll_EmployeePayrollDefinitionFinal AS PEPDF             ON PE.Employee_ID = PEPDF.EmployeeID   INNER JOIN    CyclePeriods cp ON PEPDF.[PeriodID] = cp.[Period_ID]  )    SELECT DISTINCT       PSH.SalaryHead_ID AS SalaryHeadId       ,PSH.SalaryHeadName AS SalaryHeadName       ,SUM(IIF(PE.IsYough = 1, 1, 0)) AS Youth       ,SUM(IIF(PE.Isforeigner = 1, 1, 0)) AS Foreigner       ,SUM(IIF(PE.EquityDisabled = 1, 1, 0)) AS Disability       ,CEG.Ethnic_ID AS RaceId       ,CEG.EthnicDesc AS Race       ,CG.Gender_ID AS GenderId       ,CG.GenderDesc AS Gender       ,COUNT(PE.Employee_ID) AS TotalEmployees    FROM TaxYearEmployees AS PE    LEFT JOIN Payroll_EmployeeTermination AS PET ON PET.EmployeeID = PE.Employee_ID AND PET.Complete = 1    JOIN Const_EthnicGroup AS CEG ON PE.EthnicGroupID = CEG.Ethnic_ID    JOIN Const_Gender AS CG ON PE.GenderID = CG.Gender_ID    JOIN Payroll_SalaryHead AS PSH        ON PSH.SalaryHead_ID IN (SELECT * FROM STRING_SPLIT(@SalaryHeadIds, ','))    OUTER APPLY(        SELECT TOP 1 * FROM Payroll_EmployeePayrollDefinitionFinal  ep   INNER JOIN    CyclePeriods cp ON ep.[PeriodID] = cp.[Period_ID]      WHERE ep.[EmployeeID] = PE.Employee_ID            AND ep.[PayrollSalaryHeadID] = PSH.SalaryHead_ID    ) AS PEPDF    OUTER APPLY(        SELECT TOP 1 pr.* FROM Payroll_PayrollResults pr   INNER JOIN    CyclePeriods cp ON pr.[PeriodID] = cp.[Period_ID]      WHERE PE.Employee_ID = EmployeeID             AND SalaryHeadID = PSH.SalaryHead_ID    ) AS PPR    JOIN Payroll_CyclePeriodDetails AS PCPD ON PCPD.Period_ID = pe.[Period_ID]    CROSS APPLY (        SELECT TOP 1 PPHI.JobProfileID, PPHI.DepartmentID, PPHI.DivisionID        FROM Payroll_PositionHistory AS PPHI         WHERE PPHI.EmployeeID = PEPDF.EmployeeID            AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PPHI.StartDate AND PPHI.EndDate)            AND PPHI.Enabled = 1    ) AS PPH    JOIN Payroll_JobProfileHistory AS PJPH ON PJPH.JobProfileID = PPH.JobProfileID        AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PJPH.StartDate AND PJPH.EndDate)        AND PJPH.Enabled = 1    WHERE ((PEPDF.EmployeePayrollDefinitionFinal_ID IS NULL) OR (PEPDF.EmployeePayrollDefinitionFinal_ID IS NOT NULL AND PPR.PayrollResult_ID IS NULL))        AND PEPDF.Enabled = 1        AND (PPH.DepartmentID = @DepartmentId OR @DepartmentId = 0)        AND (PPH.DivisionID = @DivisionId OR @DivisionId = 0)        AND (@RemunerationType = @RemunerationTypeAll            OR (                (@RemunerationType = @RemunerationTypeTaskGrade AND PJPH.TaskGradeId IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeUpperLimit AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeWage AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NULL))        )    GROUP BY PSH.SalaryHead_ID            ,PSH.SalaryHeadName            ,CEG.Ethnic_ID            ,CEG.EthnicDesc            ,CG.Gender_ID            ,CG.GenderDesc        END

GO

-- ============================================
-- SP: Payroll_SalaryTransactionPerRaceAndGenderSummaryTransaction
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:      Ilya Skavronskiy  -- Create date: 2020-12-31  -- Description: Used as a dataset for SalaryTransactionPerRaceAndGenderSummaryTransaction report   --              (Payroll_SalaryTransactionPerRaceAndGenderSummaryTransaction.rdl)  --              Returns Summary Salary Transactions Per Race And Gender   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SalaryTransactionPerRaceAndGenderSummaryTransaction]      @TaxYear VARCHAR(9) = ''   ,@CycleId INT = 0   ,@Period VARCHAR(500) = ''       ,@SalaryHeadIds VARCHAR(MAX)        ,@DepartmentId INT = 0        ,@DivisionId INT = 0        ,@RemunerationType INT = 0    AS    BEGIN        DECLARE @RemunerationTypeAll INT = 0    ,@RemunerationTypeTaskGrade INT = 1    ,@RemunerationTypeUpperLimit INT = 2    ,@RemunerationTypeWage INT = 3;    ;WITH CyclePeriods  AS  (   SELECT DISTINCT    [Period_ID],    [CycleID],    [TaxYear]   FROM    Payroll_CyclePeriodDetails   WHERE    (ISNULL(@TaxYear, '') = '' OR [TaxYear] = @TaxYear)   AND (ISNULL(@Period, '') = '' OR [ProcessingMonth] = @Period)   AND (ISNULL(@CycleId, 0) = 0 OR [CycleID] = @CycleId)  )    SELECT        PSH.SalaryHead_ID AS SalaryHeadId       ,PSH.SalaryHeadName AS SalaryHeadName       ,SUM(IIF(PE.IsYough = 1, 1, 0)) AS Youth       ,SUM(IIF(PE.Isforeigner = 1, 1, 0)) AS Foreigner       ,SUM(IIF(PE.EquityDisabled = 1, 1, 0)) AS Disability       ,CEG.Ethnic_ID AS RaceId       ,CEG.EthnicDesc AS Race       ,CG.Gender_ID AS GenderId       ,CG.GenderDesc AS Gender       ,COUNT(PE.Employee_ID) AS TotalEmployees       ,SUM(ISNULL(PPR.Amount, 0)) AS CurrentAmount       ,SUM(ISNULL(YearAmount.Amount, 0)) AS YearToDate    FROM Payroll_EmployeePayrollDefinitionFinal AS PEPDF    INNER JOIN   CyclePeriods cp ON PEPDF.[PeriodID] = cp.[Period_ID]  JOIN Payroll_SalaryHead AS PSH        ON PEPDF.PayrollSalaryHeadID = PSH.SalaryHead_ID    LEFT JOIN Payroll_PayrollResults AS PPR        ON PSH.SalaryHead_ID = PPR.SalaryHeadID            AND PEPDF.PeriodID = PPR.PeriodID            AND PEPDF.EmployeeID = PPR.EmployeeID    JOIN Payroll_Employee AS PE ON PEPDF.EmployeeID = PE.Employee_ID    LEFT JOIN Payroll_EmployeeTermination AS PET ON PET.EmployeeID = PE.Employee_ID AND PET.Complete = 1    JOIN Const_EthnicGroup AS CEG ON PE.EthnicGroupID = CEG.Ethnic_ID    JOIN Const_Gender AS CG ON PE.GenderID = CG.Gender_ID    CROSS APPLY (        SELECT            SUM(SubPPR.Amount) AS Amount        FROM Payroll_CyclePeriodDetails AS SubCPD        JOIN Payroll_PayrollResults AS SubPPR            ON SubPPR.CycleID = @CycleId            AND SubPPR.TaxYear = CAST(SUBSTRING(SubCPD.TaxYear, 6, 9) AS INT)            AND SubPPR.EmployeeID = PEPDF.EmployeeID            AND SubPPR.SalaryHeadID = PEPDF.PayrollSalaryHeadID            AND SubPPR.PeriodID = SubCPD.Period_ID        WHERE SubCPD.PeriodEndDate <= (            SELECT PeriodEndDate            FROM Payroll_CyclePeriodDetails            WHERE Period_ID = cp.[Period_ID]      )            AND SubCPD.CycleID = cp.[CycleID]            AND SubCPD.TaxYear = cp.[TaxYear]            AND SubCPD.Enabled = 1    ) AS YearAmount    JOIN Payroll_CyclePeriodDetails AS PCPD ON PCPD.Period_ID = cp.[Period_ID]  CROSS APPLY (        SELECT TOP 1 PPHI.JobProfileID, PPHI.DepartmentID, PPHI.DivisionID        FROM Payroll_PositionHistory AS PPHI         WHERE PPHI.EmployeeID = PEPDF.EmployeeID            AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PPHI.StartDate AND PPHI.EndDate)            AND PPHI.Enabled = 1    ) AS PPH    JOIN Payroll_JobProfileHistory AS PJPH ON PJPH.JobProfileID = PPH.JobProfileID        AND (COALESCE(PET.TerminationStartDate, PCPD.PeriodStartDate) BETWEEN PJPH.StartDate AND PJPH.EndDate)        AND PJPH.Enabled = 1    WHERE PSH.SalaryHead_ID IN (SELECT * FROM STRING_SPLIT(@SalaryHeadIds, ','))        AND PEPDF.Enabled = 1        AND (PPH.DepartmentID = @DepartmentId OR @DepartmentId = 0)        AND (PPH.DivisionID = @DivisionId OR @DivisionId = 0)        AND (@RemunerationType = @RemunerationTypeAll            OR (                (@RemunerationType = @RemunerationTypeTaskGrade AND PJPH.TaskGradeId IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeUpperLimit AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NOT NULL)                OR (@RemunerationType = @RemunerationTypeWage AND PJPH.TaskGradeId IS NULL AND PJPH.LimitID IS NULL))        )    GROUP BY PSH.SalaryHead_ID            ,PSH.SalaryHeadName            ,CEG.Ethnic_ID            ,CEG.EthnicDesc            ,CG.Gender_ID            ,CG.GenderDesc        END

GO

-- ============================================
-- SP: Payroll_SchedulerNotchIncreases
-- Schema: dbo
-- ============================================
/*   Modiri   2019/12/04   Scheduler will execute this SP to check if there any nothc increases for that specific date  */      CREATE procedure dbo.Payroll_SchedulerNotchIncreases  AS  --Runs the Notch Changes base on the timeline changes  --EXEC dbo.Payroll_NotchChanges    /*Runs the Notch increases based on the appointment date*/  EXEC dbo.Payroll_NotchOnAppointment    /*Runs the Notch increases based on the Increase date*/  EXEC dbo. Payroll_NotchOnIncreaseDate

GO

-- ============================================
-- SP: Payroll_SearchAdhocPayrollRunEarningsAndDeductions_sp
-- Schema: dbo
-- ============================================
  -- =========================================================================================================  -- Author:  Saleem Khan  -- Create date: 18 APR 2016  -- Description: Returns all common earnings and deductions linked to a Adhoc payroll run  -- Call: EXECUTE [dbo].[Payroll_SearchAdhocPayrollRunEarningsAndDeductions_sp] 2525  -- 2015-02-17 TP32108 Saleem Khan: Created  -- Author:  Phuti Chokoe  -- Modified: Changed the predifined parameter, to select both predifined and not predifined from SalaryHead  -- 2016-08-09 TP42590  -- 2016-08-27 TP43521 Seipei Mathole : Modify the stored procedure as it was not returning any results  -- Original Stored rocedure in the UserStory TP43521  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  CREATE procedure [dbo].[Payroll_SearchAdhocPayrollRunEarningsAndDeductions_sp]      @PeriodID INT  AS    BEGIN     DECLARE @lstsalaryHeads Table(PayrollSalaryHeadID int)  DECLARE @EmployeeID int  DECLARE @lstEmployee CURSOR   SET @lstEmployee = CURSOR FAST_FORWARD   FOR    SELECT DISTINCT EmployeeID FROM Payroll_CyclePeriodAdhocEmployee WHERE PeriodID=@PeriodID AND Enabled=1     OPEN @lstEmployee    FETCH NEXT FROM @lstEmployee    INTO @EmployeeID      WHILE @@FETCH_STATUS = 0    BEGIN         INSERT INTO @lstsalaryHeads     SELECT DISTINCT S.SalaryHead_ID       FROM   dbo.Payroll_EmployeePayrollDefinition AS C                                      INNER JOIN dbo.Payroll_CyclePeriodAdhocEmployee AS E ON E.EmployeeID = C.EmployeeID                                      INNER JOIN dbo.Payroll_SalaryHead AS S ON C.PayrollSalaryHeadID = S.SalaryHead_ID           INNER JOIN dbo.Payroll_IRP5Code AS I ON S.IRP5CodeId = I.IRP5Code_ID           INNER JOIN dbo.Const_TransactionType AS T ON T.TransactionType_ID = I.TransactionTypeID      WHERE C.Enabled = 1 AND E.Enabled = 1 AND       C.EmployeeID=@EmployeeID AND PeriodID=@PeriodID AND       C.PayrollSalaryHeadID NOT IN(12,18,19,25) AND       C.PayrollSalaryHeadID = S.SalaryHead_ID AND (S.SalaryHeadName = 'Commission' OR S.SalaryHeadName = 'CommissionTax') AND       S.Enabled = 1 AND       S.IRP5CodeId = I.IRP5Code_ID AND           I.Enabled = 1 AND       I.TransactionTypeID != 4 AND       I.TransactionTypeID = T.TransactionType_ID      GROUP BY S.SalaryHead_ID, E.EmployeeID          FETCH NEXT FROM @lstEmployee     INTO @EmployeeID    END    CLOSE @lstEmployee    DEALLOCATE @lstEmployee        -- SELECT DISTINCT PayrollSalaryHeadID FROM @lstsalaryHeads       SELECT DISTINCT T.TransactionTypeDesc, S.SalaryHeadName,I.TransactionTypeID,S.SalaryHead_ID     FROM  [dbo].[Payroll_SalaryHead] S       LEFT JOIN [Payroll_IRP5Code] I ON S.IRP5CodeId = I.IRP5Code_ID       LEFT JOIN [Const_TransactionType] T ON T.TransactionType_ID = I.TransactionTypeID       LEFT JOIN @lstsalaryHeads as commonSalaryHeads ON commonSalaryHeads.PayrollSalaryHeadID = S.SalaryHead_ID      WHERE  S.Enabled = 1 AND        S.IRP5CodeId = I.IRP5Code_ID AND       I.Enabled = 1 AND       I.TransactionTypeID = T.TransactionType_ID       ORDER BY I.TransactionTypeID      END

GO

-- ============================================
-- SP: Payroll_SearchAdhocPayrollRunEmployee_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 17 APR 2016  -- Description: Returns all employees linked to a Adhoc payroll run  -- Call: [Payroll_SearchAdhocPayrollRunEmployee_sp]  -- 2015-02-17 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchAdhocPayrollRunEmployee_sp]      @PeriodID INT  AS    BEGIN        SELECT CPAE.CyclePeriodAdhocEmployee_ID,      CPAE.PeriodID,      CPAE.EmployeeID,      E.EmpCode,      E.FirstName,      E.Surname,      E.IdNo,      E.PassportNumber,      E.EmailAddress,      E.CellNumber,      E.HomeNumber    FROM [dbo].Payroll_CyclePeriodAdhocEmployee CPAE       LEFT JOIN [dbo].Payroll_Employee E ON E.Employee_ID = CPAE.EmployeeID    WHERE CPAE.PeriodID = @PeriodID AND CPAE.Enabled=1        END

GO

-- ============================================
-- SP: Payroll_SearchAdhocPayrollRuns_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferd Botha   Create Date : 05/03/2018   Description : Returns all Adhoc Payroll Runs matching the Search Criteria  */  create procedure [Payroll_SearchAdhocPayrollRuns_sp] @CycleID int = null, @TaxYear int = null, @TaxMonth int = null, @Description nvarchar(100) = null, @Processed bit = null  as    begin     select [Period_ID], [CycleDesc], [AdHocType], [ProcessingMonth] as [Description], cast(right([TaxYear], 4) as int) as [TaxYear], [PeriodInTaxYear] as [TaxMonth], datename(month, [PeriodEndDate]) as [Month], [PeriodStartDate], [PeriodEndDate], [Processed], [ProcessedDate]      from [Payroll_CyclePeriodDetails] as [CPD] with(nolock)         join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [CPD].[CycleID] and [CC].[Enabled] = 1       left join [Const_Payroll_AdhocType_sys] as [CPA] with(nolock) on [CPA].[AdhocType_ID] = [CPD].[AdhocTypeID] and [CPA].[Enabled] = 1      where ([CPD].[Enabled] = 1 and [CycleModeID] = 2 and [CPD].[CycleID] = (case when @CycleID is null then [CPD].[CycleID] else @CycleID end) and       cast(right([TaxYear], 4) as int) = (case when @TaxYear is null then cast(right([TaxYear], 4) as int) else @TaxYear end) and       [PeriodInTaxYear] = (case when @TaxMonth is null then [PeriodInTaxYear] else @TaxMonth end) and       [ProcessingMonth] like (case when @Description is null then [ProcessingMonth] else '%' + @Description + '%' end) and       [Processed] = (case when @Processed is null then [Processed] else @Processed end)      )       order by [PeriodEndDate], [PeriodStartDate], [Processed]    end  

GO

-- ============================================
-- SP: Payroll_SearchAdvert_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author   : Himil Modi  -- Create date: 20/07/2018  -- Description: Display the Grid basaed on the Department/Division Criteria  -- Call SP    : Payroll_SearchAdvert_sp 5,0, NULL  -- =============================================  CREATE PROCEDURE dbo.Payroll_SearchAdvert_sp  @DepartmentID INT,  @DivisionID INT,  @AdvertRefNo nVARCHAR(50)=NULL  AS  BEGIN     SELECT    PA.AdvertId,   PA.AdvertRefNo,   cnstDep.DepartmentDesc,   cnstDiv.DivisionDesc,   Experience,   PP.PositionDesc,   PA.AdvertisementDate,   PA.ClosingDate,  STUFF ( ( SELECT ','+x.QualificationShortDescription                    FROM (select ppq.PositionID,cqs.QualificationShortDescription from Payroll_Position_QualificationDefinition ppq   LEFT JOIN  Const_Qualification_Sys cqs on ppq.QualificationID=cqs.Qualification_ID )x                    WHERE x.PositionID=PA.PositionId                     ORDER BY PositionId                    FOR XML PATH(''),TYPE                     ).value('.','VARCHAR(MAX)')                    , 1,1,SPACE(0)) AS Qualification   from dbo.Payroll_Advert AS PA   LEFT join Payroll_Position PP ON pa.PositionId = pp.Position_ID   LEFT JOIN Const_Department cnstDep ON PP.DepartmentID=cnstDep.Department_ID   LEFT JOIN Const_Division cnstDiv on PP.DivisionID = cnstDiv.Division_ID   WHERE (isnull(@DepartmentID,0) = 0 OR PP.DepartmentID = @DepartmentID)  and (isnull(@DivisionID,0) = 0 OR PP.DivisionID = @DivisionID)  AND (@AdvertRefNo IS NULL or  pa.AdvertRefNo = @AdvertRefNo)      group by AdvertId,Experience,AdvertRefNo,DepartmentDesc,DivisionDesc,PositionDesc,AdvertisementDate,ClosingDate ,PositionId  order by AdvertId asc  END

GO

-- ============================================
-- SP: Payroll_SearchAdvertByAdvertRefNo_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,24/08/2018>  -- Description: <Description,,Get data for advert Id>  -- =============================================  CREATE PROCEDURE dbo.Payroll_SearchAdvertByAdvertRefNo_sp   -- Add the parameters for the stored procedure here   @AdvertRefNo NVARCHAR(50)  AS  BEGIN   SET NOCOUNT ON;        -- Insert statements for procedure here        SELECT PA.*, cd.DepartmentDesc, cdd.DivisionDesc, pp.PositionDesc FROM dbo.Payroll_Advert AS PA    LEFT OUTER JOIN dbo.Const_Department AS CD ON cd.Department_ID = pa.DepartmentId    LEFT OUTER JOIN dbo.Const_Division AS CDD ON cdd.Division_ID = pa.DivisionId    LEFT OUTER JOIN dbo.Payroll_Position AS PP ON pp.Position_ID = pa.PositionId    WHERE AdvertRefNo like '%'+@AdvertRefNo+'%'  END  

GO

-- ============================================
-- SP: Payroll_SearchBudgetReport_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 22 FEB 2016  -- Description: Returns all Budget reports which match the required search parameters  -- Call: [Payroll_SearchBudgetReport_sp]  -- 2015-02-12 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchBudgetReport_sp]      @BudgetDescription NVARCHAR(200) =null,   @BudgetTypeID INT= null,   @BudgetFinancialYear NVARCHAR(9)= null        AS    BEGIN        SELECT br.[BudgetReport_ID]       ,br.[BudgetDescription]       ,br.[FinancialYear]       ,br.[BudgetTypeID]       ,c1.[StatusDesc] as BudgetType       --,c2.[StatusDesc] as ReportLayout       ,br.[Y1IncreasePercentage]       ,br.[Y1IncreaseMinimumAmount]       ,br.[Y2IncreasePercentage]       ,br.[Y2IncreaseMinimumAmount]       ,br.[Y3IncreasePercentage]       ,br.[Y3IncreaseMinimumAmount]       ,br.[Enabled]       ,br.[DateCaptured]       ,br.[CapturerID]       ,br.[DateModified]       ,br.[ModifiedID]      FROM [dbo].[Payroll_BudgetReport] br      LEFT JOIN [dbo].[Const_Status] c1 ON c1.Status_ID = br.BudgetTypeID       WHERE  (isnull(@BudgetTypeID,0) = 0 OR BudgetTypeID = @BudgetTypeID)      AND (isnull(@BudgetDescription,'') = '' OR BudgetDescription LIKE '%' + @BudgetDescription + '%')      AND (isnull(@BudgetFinancialYear,'') = '' OR FinancialYear LIKE '%' + @BudgetFinancialYear + '%')      AND br.Enabled=1        END

GO

-- ============================================
-- SP: Payroll_SearchBudgetReportEmployeeType_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 22 FEB 2016  -- Description: Returns all Budget reports which match the required search parameters  -- Call: [Payroll_SearchBudgetReport_sp]  -- 2015-02-12 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchBudgetReportEmployeeType_sp]  @BudgetReportID INT= null  AS   BEGIN       SELECT e.[BudgetReportEmployeeTypeLink_ID]       ,e.[BudgetReportID]      ,e.[EmployeeTypeID]      ,c.EmployeeTypeDescription      ,e.[Enabled]      ,e.[DateCaptured]      ,e.[CapturerID]      ,e.[DateModified]      ,e.[ModifierID]   FROM [dbo].[Payroll_BudgetReportEmployeeTypeLinkTable] e   LEFT JOIN [dbo].[Const_EmployeeType_sys] c ON c.EmployeeType_ID = e.EmployeeTypeID   WHERE (isnull(@BudgetReportID,0) = 0 OR e.BudgetReportID = @BudgetReportID) AND e.Enabled=1      END

GO

-- ============================================
-- SP: Payroll_SearchBudgetReportPayrollCycle_sp
-- Schema: dbo
-- ============================================
      -- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 22 FEB 2016  -- Description: Returns all Budget reports which match the required search parameters  -- Call: [Payroll_SearchBudgetReport_sp]  -- 2015-02-12 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchBudgetReportPayrollCycle_sp]  @BudgetReportID INT= null  AS   BEGIN       SELECT p.[BudgetReportPayrollCycleLink_ID]       ,p.[BudgetReportID]      ,p.[PayrollCycleID]      ,c.[CycleDesc]      ,p.[Enabled]      ,p.[DateCaptured]      ,p.[CapturedID]      ,p.[DateModified]      ,p.[ModifierID]   FROM [dbo].[Payroll_BudgetReportPayrollCycleLinkTable] p   LEFT JOIN [dbo].[Const_Cycle] c ON p.PayrollCycleID = c.Cycle_ID   WHERE (isnull(@BudgetReportID,0) = 0 OR BudgetReportID = @BudgetReportID) AND p.Enabled=1    END

GO

-- ============================================
-- SP: Payroll_SearchBudgetReportVacancies_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 22 FEB 2016  -- Description: Returns all Budget reports which match the required search parameters  -- Call: [[Payroll_SearchBudgetReportVacancies_sp]]  -- 2015-03-03 TP32108 Saleem Khan: Created  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchBudgetReportVacancies_sp]  @BudgetReportID INT= null  AS   BEGIN      SELECT [BudgetReportVacancy_ID]        ,brv.[BudgetReportID]        ,brv.[DivisionID]     ,cd.[DivisionDesc]     ,cdep.DepartmentDesc        ,brv.[JobProfileID]     ,jp.JobTitle        ,brv.[NoVacancies]        ,brv.[DateVacancyActiveID]     ,c1.[StatusDesc] as DateVacancyActive        ,brv.[Enabled]        ,brv.[DateCaptured]        ,brv.[CapturerID]        ,brv.[DateModified]        ,brv.[ModifierID]    FROM [dbo].[Payroll_BudgetReportVacancies] brv     LEFT JOIN [dbo].Const_Division cd ON brv.DivisionID = cd.Division_ID    LEFT JOIN [dbo].Const_Department cdep ON cd.DepartmentID = cdep.Department_ID    LEFT JOIN [dbo].Payroll_JobProfile jp ON jp.JobProfile_ID = brv.JobProfileID    LEFT JOIN [dbo].[Const_Status] c1 ON c1.Status_ID = brv.DateVacancyActiveID    WHERE (isnull(@BudgetReportID,0) = 0 OR brv.BudgetReportID = @BudgetReportID) AND brv.Enabled=1    END

GO

-- ============================================
-- SP: Payroll_SearchCertEmployee_sp
-- Schema: dbo
-- ============================================
  /*  =============================================      Author: Richa Mills  Create date:  2018/06/28   Description: Search employees included in selected IRP5 run  [Payroll_SearchCertEmployee_sp]  17,'February','2017/2018','Any','0'  */  CREATE procedure [dbo].[Payroll_SearchCertEmployee_sp]      @CycleId INT ,      @TaxPeriod VARCHAR(50) ,      @TaxYear VARCHAR(20) ,      @SortIndex VARCHAR(50) ,      @IsTerminated BIT  AS      begin                  declare @Result table(     EmployeeNumber varchar(20),     EmployeeId int,     EmployeeCode varchar(100),     EmployeeName varchar(250),     DepartmentDesc varchar(250),     PaypointDesc varchar(250),     PayrollCycle varchar(250),      TaxPeriod varchar(10),     TaxYear varchar(10),     EmpStartDate varchar(20),     EmpEndDate varchar(20),     IsSignOff varchar(20),     SignOffDate datetime)      declare @CertId int, @FromDate DateTime, @ToDate Datetime,@FromPeriod int,@ToPeriod int, @CycleTypeId int            select @CertId = EmployeeTaxCertificate_ID from Payroll_EmployeeTaxCertificate where TaxPeriod = @TaxPeriod and TaxYear = @TaxYear AND PayrollCycleId = @CycleId;              DECLARE cycle_cursor CURSOR FOR       SELECT Distinct CycleId from Payroll_PayrollResults where ( CycleID = @CycleId OR @CycleId = 0 )      OPEN cycle_Cursor        FETCH NEXT FROM cycle_Cursor INTO @CycleId        WHILE @@FETCH_STATUS = 0      BEGIN         Select @CycleTypeId = CycleTypeID from Const_Cycle where Cycle_Id = @CycleId         IF @CycleTypeID = 1     BEGIN      If @TaxPeriod = 'August'       Select @FromPeriod = 1, @ToPeriod = 6      else       Select @FromPeriod = 1, @ToPeriod = 12       select @FromDate = Min(PeriodStartDate),@ToDate = Max(PeriodEndDate) from Payroll_CyclePeriodDetails cd      join Const_Cycle cy on cy.Cycle_ID = cd.CycleID      join Const_CycleType_sys cs on cs.CycleType_ID = cy.CycleTypeID     where cd.PeriodInTaxYear in (@FromPeriod,@ToPeriod) and CycleId = @CycleID     END       IF @CycleTypeId = 2     BEGIN      If @TaxPeriod = 'August'       Select @FromPeriod = 1, @ToPeriod = 26      else       Select @FromPeriod = 1, @ToPeriod = 52       select @FromDate = Min(PeriodStartDate),@ToDate = Max(PeriodEndDate) from Payroll_CyclePeriodDetails cd      join Const_Cycle cy on cy.Cycle_ID = cd.CycleID      join Const_CycleType_sys cs on cs.CycleType_ID = cy.CycleTypeID     where cd.PeriodInTaxYear in (1,6) and CycleId = @CycleID     END       IF @CycleTypeId = 3     BEGIN      If @TaxPeriod = 'August'       Select @FromPeriod = 1, @ToPeriod = 13      else       Select @FromPeriod = 1, @ToPeriod = 26       select @FromDate = Min(PeriodStartDate),@ToDate = Max(PeriodEndDate) from Payroll_CyclePeriodDetails cd      join Const_Cycle cy on cy.Cycle_ID = cd.CycleID      join Const_CycleType_sys cs on cs.CycleType_ID = cy.CycleTypeID     where cd.PeriodInTaxYear in (@FromPeriod,@ToPeriod) and CycleId = @CycleID  END      Insert Into @Result  select                 dbo.AppendString_fxn(EMP.Employee_ID, 8, '0') as EmployeeNumber ,       Employee_ID as EmployeeID ,       EMP.EmpCode as EmployeeCode,       EMP.Surname + ' ' + EMP.FirstName AS EmployeeName,      dep.DepartmentDesc,      pp.PayPointDesc,                  (select top 1 CycleDesc from  dbo.Const_Cycle where Cycle_ID = cp.CycleID ) as PayrollCycle ,                  case when @TaxPeriod = 'February' then 'Annual' else 'Bi-Annual' end as TaxPeriod ,       @TaxYear AS TaxYear ,       convert(varchar(20), EMP.JoiningDate, 103) as EmpStartDate ,                  convert(varchar(20), EMP.EndDate, 103) as EmpEndDate ,       case when EDD.IsSignOff = 1 then 'Yes' else 'No'end as IsSignOff ,       convert(varchar(20), EDD.SignOffDate, 103) as SignOffDate       from       (select * from Payroll_PayrollResults where (CycleId = @CycleId OR @CycleId = 0 and TaxYear = Right(@TaxYear,4))) as tr      join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID      join Payroll_CyclePeriodDetails cp       on cp.Period_ID = tr.PeriodId      left outer join Payroll_EmployeeDocumentDetails edd        on edd.EmployeeID = emp.Employee_ID and edd.EmpTaxCertId = @CertId      join Payroll_Position as pos        ON pos.Position_ID = emp.PositionID      join Const_Department dep       ON dep.Department_ID = pos.DepartmentID      join Payroll_PayPoint pp       on pp.PayPoint_ID = emp.PayPointID      where (cp.PeriodEndDate BETWEEN @FromDate AND @ToDate)       and case when @IsTerminated = 1 then emp.EndDate else @FromDate end between @FromDate and  @ToDate      group by dbo.AppendString_fxn(EMP.Employee_ID, 8, '0') , EMP.Employee_ID , EMP.EmpCode , EMP.FirstName , EMP.Surname ,  EMP.JoiningDate ,EMP.EndDate ,cp.CycleID ,IsSignOff , SignOffDate,dep.DepartmentDesc,pp.PayPointDesc      order by case          when @SortIndex = 'Any' then cast(emp.Employee_ID as varchar(20))         when @SortIndex = 'Employee' then emp.FirstName          when @SortIndex = 'Department' then dep.DepartmentDesc         when @SortIndex = 'PayPoint' then pp.PayPointDesc end    FETCH NEXT FROM cycle_Cursor     INTO @CycleId    END     CLOSE cycle_Cursor;    DEALLOCATE cycle_Cursor;            Select * from @Result                end  

GO

-- ============================================
-- SP: Payroll_SearchCoreCompentenceRequirement_sp
-- Schema: dbo
-- ============================================
  --------------------------------------------------------------------    -- 20220427 - Ruan - WI78329 - Correct Enabled Column to adhere to standards    --------------------------------------------------------------------    CREATE PROCEDURE [dbo].[Payroll_SearchCoreCompentenceRequirement_sp]    -- Add the parameters for the stored procedure here    @CompentanceType int,    @ConpentenceRequirement varchar(255)   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT D.[CoreCompetencyRequirement_ID]      ,T.CoreCompetencyRequirementTypeDesc      ,D.[CoreCompetencyRequirementDesc]      ,Case when D.[Enabled] = 1 then      'Yes'      else      'No'      end as Enabled      ,D.[CoreCompetencyRequirement]      ,count(PJC.CompetencyRequirements_ID) as JobProfile      ,count(PPC.CoreCompetencyRequirementID) as Position      ,count(PE.Employee_ID) as Employees     FROM [dbo].[Const_PMSCoreCompetencyRequirement] as D     inner join [dbo].Const_PMSCoreCompetencyRequirementType_sys as T on T.CoreCompetencyRequirementType_ID = D.CoreCompetencyRequirementTypeID     left join Payroll_Position_Competency as PPC on PPC.CoreCompetencyRequirementID = T.CoreCompetencyRequirementType_ID     left join Payroll_JobProfile_CompetencyRequirements as PJC on PJC.CoreCompetencyRequirementID = PPC.CoreCompetencyRequirementID     left join Payroll_Employee as PE on PE.JobProfileID = PJC.JobProfileID     where (        (T.CoreCompetencyRequirementType_ID = @CompentanceType or @CompentanceType = -1) and       (D.[CoreCompetencyRequirement] = @ConpentenceRequirement or @ConpentenceRequirement = '-1')        and D.Enabled = 1     )     group by D.CoreCompetencyRequirement_ID, T.CoreCompetencyRequirementTypeDesc, D.[CoreCompetencyRequirementDesc], D.[Enabled], D.[CoreCompetencyRequirement], PJC.CompetencyRequirements_ID, PPC.CoreCompetencyRequirementID, PE.Employee_ID     END

GO

-- ============================================
-- SP: Payroll_SearchDepartments
-- Schema: dbo
-- ============================================
  /*   Author:   Ferdi Botha   Create Date: Dec. 03, 2018   Description: Returns all Departments that falls within a specific SCOA Year  */  create procedure [Payroll_SearchDepartments] @SCOAYear nvarchar(9) = null  as    begin     declare @StartDate datetime = null,     @UntilDate datetime = null     set @StartDate = cast(left(@SCOAYear, 4) + '-07-01 00:00:00' as datetime)   set @UntilDate = cast(right(@SCOAYear, 4) + '-06-30 00:00:00' as datetime)     select [CDH].[DepartmentHistory_ID], [CDH].[DepartmentID], [CD].[DepartmentCode], [CD].[DepartmentDesc], [CDH].[StartDate], [CDH].[EndDate], [CDH].[ManagerPositionID], [CDH].[ManagerStartDate], [CDH].[ManagerEndDate], [CD].[VatApportionment], [CDH].[CapturerID], [CDH].[DateCaptured], [CDH].[ModifierID], [CDH].[DateModified]      from [Const_DepartmentHistory] as [CDH] with(nolock)       join [Const_Department] as [CD] with(nolock) on [CD].[Department_ID] = [CDH].[DepartmentID] and [CD].[Enabled] = 1      where ([CDH].[Enabled] = 1 and [CDH].[StartDate] <= @UntilDate and [CDH].[EndDate] >= @StartDate)       order by [CDH].[StartDate]    end  

GO

-- ============================================
-- SP: Payroll_SearchDivisions
-- Schema: dbo
-- ============================================
  /*   Author:   Ferdi Botha   Create Date: Dec. 03, 2018   Description: Returns all Divisions that falls within a specific SCOA Year  */  create procedure [Payroll_SearchDivisions] @SCOAYear nvarchar(9) = null  as    begin     declare @StartDate datetime = null,     @UntilDate datetime = null     set @StartDate = cast(left(@SCOAYear, 4) + '-07-01 00:00:00' as datetime)   set @UntilDate = cast(right(@SCOAYear, 4) + '-06-30 00:00:00' as datetime)     select [CDH].[DivisionHistory_ID], [CDH].[DepartmentID], [CDH].[DivisionID], [CDH].[DivisionParentID], [CD].[DivisionCode], [CD].[DivisionDesc], [CDH].[StartDate], [CDH].[EndDate], [CDH].[ManagerPositionID], [CDH].[ManagerStartDate], [CDH].[ManagerEndDate], [CDH].[ConditionOfServiceID], [CDH].[SCOAProjectID], [CDH].[SCOAFunctionID], [CDH].[SCOARegionID], [CDH].[SCOAFundID], [CD].[DirectorateLevel], [CDH].[CapturerID], [CDH].[DateCaptured], [CDH].[ModifierID], [CDH].[DateModified]      from [Const_DivisionHistory] as [CDH] with(nolock)       join [Const_Division] as [CD] with(nolock) on [CD].[Division_ID] = [CDH].[DivisionID] and [CD].[Enabled] = 1      where ([CDH].[Enabled] = 1 and [CDH].[StartDate] <= @UntilDate and [CDH].[EndDate] >= @StartDate)       order by [CDH].[StartDate]    end  

GO

-- ============================================
-- SP: Payroll_SearchEmployee_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 13 FEB 2014  -- Description: Returns all employees which match the required search parameters  -- Call: [Payroll_SearchEmployee_sp] 0, 641   -- 2015-02-12 James Roodt: Added more search paramters instead of just employee ID  -- 2015-02-12 James Roodt: Changed search criteria to be exclusive instead of inclusive (or becomes and)  -- 2015-11-25 Suri Kandukuri : Modified the StepLocation Calculation for Biometrics.  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- 2016-04-23 TP#32072 James Roodt: Fixed some step calculations  -- 2017-07-13 Richa Mills TP#59323 - Add Employee Start and End Date  -- 2019-07-01 Modiri #87612 If I click on the Convert to Employee the detail is not converted to the Employee detail    -- ==============================================================================    CREATE procedure [dbo].[Payroll_SearchEmployee_sp] @IsDummy bit, @EmployeeID int = null, @Surname nvarchar(50) = null, @FullName nvarchar(200) = null, @IDNumber nvarchar(13) = null, @PassportNumber nvarchar(20) = null, @EmployeeCode nvarchar(50) = null  as    begin     select [Employee_ID], [IdNo], [Surname], [FirstName], [PassportNumber], isnull([EmailAddress], '') as [EmailAddress], isnull([CellNumber], '') as [CellNumber], isnull([HomeNumber], '') as [HomeNumber], isnull([FaxNumber], '') as [FaxNumber], [JoiningDate], [PE].[EndDate], [PositionDesc],      cast((case when [PE].[EndDate] >= getdate() then 1 else 0 end) as bit) as [Enabled], [PE].[IsMarried], isnull([EmpCode], '') as [EmpCode]      from [Payroll_Employee] as [PE] with(nolock)       left join [Payroll_Position] as [PP] with(nolock) on [Position_ID] = (        (select top 1 [PositionID]           from [Payroll_PositionHistory]           where ([EmployeeID] = [PE].[Employee_ID])            order by [StartDate] desc           )        )      where ([IsDummy] = @IsDummy and       (isnull(@EmployeeID, 0) = 0 or [Employee_ID] = @EmployeeID) and       (isnull(@Surname, '') = '' or [Surname] like '%' + @Surname + '%') and       (isnull(@FullName, '') = '' or [FirstName] like '%' + @FullName + '%') and       (isnull(@IDNumber, '') = '' or [IdNo] like '%' + @IDNumber + '%') and       (isnull(@PassportNumber, '') = '' or [PassportNumber] like '%' + @PassportNumber + '%') and       (isnull(@EmployeeCode, '') = '' or [EmpCode] like '%' + @EmployeeCode + '%')      )       order by [Employee_ID]    end  

GO

-- ============================================
-- SP: Payroll_SearchEmployeeByEmployeeType_sp
-- Schema: dbo
-- ============================================
    -- ==============================================================================  -- Author   :Varun Parvataneni    -- Create date: 13 AUG 2016  -- Description: Returns all employees which match the required search parameters with their EmployeeType  -- Call: [Payroll_SearchEmployeeByEmployeeType_sp] 0,0,'','','','',0  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions   -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchEmployeeByEmployeeType_sp]   @IsDummy BIT,      @EmployeeID INT =null,   @Surname NVARCHAR(50)= null,   @FullName NVARCHAR(200)= null,   @IDNumber NVARCHAR(13)= null,   @EmployeeCode NVARCHAR(50) = null,   @EmployeeTypeID INT        AS    BEGIN             SELECT  n.Employee_ID,dbo.BufferString_fxn(CONVERT(VARCHAR,(n.Employee_ID)), 8, '0') as EmployeeNumber,isnull(n.EmpCode,'') as EmpCode,n.Enabled as CurrentlyEmployeed,n.FirstName,n.Surname,n.IdNo,CETS.EmployeeTypeDescription       FROM Payroll_Employee n    INNER JOIN Payroll_Position PP on n.PositionID=PP.Position_ID    INNER JOIN Payroll_JobProfile PJ on PP.JobProfileID=PJ.JobProfile_ID    INNER JOIN Const_EmployeeType_sys CETS on CETS.EmployeeType_ID =PJ.EmployeeTypeID         WHERE   n.IsDummy = @IsDummy      AND  (isnull(@EmployeeID,0) = 0 OR n.Employee_ID = @EmployeeID)     AND (isnull(@Surname,'') = '' OR n.Surname LIKE '%' + @Surname + '%')     AND (isnull(@FullName,'') = '' OR n.FirstName LIKE '%' + @FullName + '%')     AND (isnull(@IDNumber,'') = '' OR n.IdNo LIKE '%' + @IDNumber + '%')      AND (isnull(@EmployeeCode,'') = '' OR n.EmpCode LIKE '%' + @EmployeeCode + '%')     AND (isnull(@EmployeeTypeID,0) = 0 OR PJ.EmployeeTypeID =@EmployeeTypeID)             ORDER BY n.Employee_ID ASC      END      

GO

-- ============================================
-- SP: Payroll_SearchEmployeeChanges
-- Schema: dbo
-- ============================================
  /*   Author:   Ferdi Botha   Create Date: Nov. 07, 2018   Description: Returns all employee changes which match the required search parameters     Modiri   2019-08-26   #93242 QAMulti_HR\Payroll No Employment Change Entry     Modiri   2019/12/10   https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/22237  */  CREATE procedure [Payroll_SearchEmployeeChanges] @EmployeeID int = null, @ReasonSubtypeID int = null, @DepartmentID int = null, @DivisionID int = null, @Status varchar(64) = null  as    begin     declare @tbl table (idx int identity(1,1), [EmployeeChange_ID] int,[EmployeeID]int, [Description] varchar(200), [Name] varchar(200), [CurrentPosition] varchar(200), [UpdatePosition] varchar(200), [StartDate] datetime, [UntilDate] datetime, [Status] varchar(150), [PositionID] int)   Insert into @tbl   select [PEC].[EmployeeChange_ID], [PEC].[EmployeeID], [RST].[Description], [PE].[FirstName] + ' ' + [PE].[Surname] as [Name], [PPC].[PositionDesc] as [CurrentPosition], [PPT].[PositionDesc] as [UpdatePosition], [PEC].[StartDate], [PEC].[UntilDate], [PEC].[Status], [PEC].[PositionID]      from [Payroll_EmployeeChange] as [PEC] with(nolock)       join [Payroll_ReasonSubtype_sys] as [RST] with(nolock) on [RST].[ReasonSubtype_ID] = [PEC].[ReasonSubtypeID] and [RST].[Enabled] = 1       join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PEC].[EmployeeID] and [PE].[Enabled] = 1       join [Payroll_Position] as [PPC] with(nolock) on [PPC].[Position_ID] = (        (select top 1 [PositionID]           from [Payroll_PositionHistory]           where ([EmployeeID] = [PEC].[EmployeeID] and [StartDate] <= [PEC].[UntilDate] and [EndDate] >= [PEC].[StartDate])            order by [StartDate] asc           )        ) and [PPC].[Enabled] = 1       join [Payroll_Position] as [PPT] with(nolock) on [PPT].[Position_ID] = [PEC].[PositionID] and [PPT].[Enabled] = 1      where (       [PEC].[Enabled] = 1 and       [PEC].[EmployeeID] = (case when @EmployeeID is null then [PEC].[EmployeeID] else @EmployeeID end) and       [PEC].[ReasonSubtypeID] = (case when @ReasonSubtypeID is null then [PEC].[ReasonSubtypeID] else @ReasonSubtypeID end) and       (        [PPC].[DepartmentID] = (case when @DepartmentID is null then [PPC].[DepartmentID] else @DepartmentID end) or        [PPT].[DepartmentID] = (case when @DepartmentID is null then [PPT].[DepartmentID] else @DepartmentID end)       ) and       (        [PPC].[DivisionID] = (case when @DivisionID is null then [PPC].[DivisionID] else @DivisionID end) or        [PPT].[DivisionID] = (case when @DivisionID is null then [PPT].[DivisionID] else @DivisionID end)       ) and       [PEC].[Status] = (case when @Status is null then [PEC].[Status] else @Status end)      )       order by [PEC].[EmployeeChange_ID] desc      Declare @cnt int =1    while @cnt <= (select count(*) from @tbl)    Begin     declare @empd int     declare @startdate datetime     declare @changeid int     declare @posid int     set @status =''          select @startdate=StartDate, @status=[Status], @empd=EmployeeID,@changeid=EmployeeChange_ID,@posid=PositionID  from @tbl where idx=@cnt       If(@status= 'Completed')     Begin      Update @tbl      SET [CurrentPosition] =       (select PositionDesc from Payroll_Position where Position_ID=(       select positionid from Payroll_PositionHistory        where PositionHistory_ID=       (select top 1  max(PositionHistory_ID) from Payroll_PositionHistory        where EmployeeID=@empd and PositionID <>@posid)))      Where idx=@cnt       End     set @cnt = @cnt+1    End      Select     [EmployeeChange_ID],[EmployeeID],[Description], [Name],[CurrentPosition],[UpdatePosition],[StartDate],[UntilDate],[Status]    from @tbl    end

GO

-- ============================================
-- SP: Payroll_SearchEmployeeQualifications_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [Payroll_SearchEmployeeQualifications_sp] @EmployeeID             INT,                    @Education              BIT,                    @Accreditation          BIT,                    @Qualification          VARCHAR(50),                    @QualificationTypeID    INT,                    @FieldOfStudyID         INT,                   @QualificationShortCode VARCHAR(255),                    @ProfessionalBodyCode   VARCHAR(255)  AS   BEGIN    SET NOCOUNT ON;    SELECT [Qualification_ID],         (CASE       WHEN [IsEducation] = 1       THEN 'Education'       ELSE(CASE          WHEN [IsProfessionalAccreditation] = 1          THEN 'Accreditation'          ELSE 'N/A'         END)      END) AS [TypeOfQualification],         [Qualification],         qt.[QualificationTypeName],         fos.[Name] as FieldOfStudy,        [QualificationShortCode],         [QualificationShortDescription],         [ProfessionalBodyCode],         [ProfessionalBodyName],        [StartDate],        [IsCompleted],        [CompletionYear]    FROM [Payroll_EmployeeQualifications] eq WITH(NOLOCK)      LEFT JOIN [Payroll_QualificationTypes] qt ON qt.QualificationTypeId = eq.QualificationTypeID      LEFT JOIN [Payroll_FieldOfStudy] fos ON fos.FieldOfStudy_ID = eq.FieldOfStudyID    WHERE([EmployeeID] = @EmployeeID       AND (([Qualification] = @Qualification       OR @Qualification = '-1')         AND ([EQ].[QualificationTypeID] = @QualificationTypeID        OR @QualificationTypeID < 1)         AND ([EQ].[FieldOfStudyID] = @FieldOfStudyID        OR @FieldOfStudyID < 1)         AND ([QualificationShortCode] = @QualificationShortCode        OR @QualificationShortCode = '-1')         AND ([ProfessionalBodyCode] = @ProfessionalBodyCode        OR @ProfessionalBodyCode = '-1')         AND ([IsEducation] = @Education        OR @Education IS NULL)         AND ([IsProfessionalAccreditation] = @Accreditation        OR @Accreditation IS NULL)))    ORDER BY [Qualification_ID] DESC;    SET NOCOUNT OFF;   END;

GO

-- ============================================
-- SP: Payroll_SearchFieldOfStudy_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author: Adrian Pietka  -- Create date: 23 OCT 2019  -- Description: Returns all field of study which match the required search parameters  -- Call: [Payroll_FieldOfStudySearch_sp] 'name'  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchFieldOfStudy_sp] @Name nvarchar(150) = null  AS    BEGIN       SELECT [FieldOfStudy_ID], [Name], [Enabled]     FROM [Payroll_FieldOfStudy] WITH(NOLOCK)     WHERE        (ISNULL(@Name, '') = '' OR [Name] LIKE '%' + @Name + '%')     ORDER BY [Name]    END

GO

-- ============================================
-- SP: Payroll_SearchInterviewScheduleItem_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,09/11/2018>  -- Description: <Description,,Get Interview Schedule list>  -- =============================================  Create PROCEDURE Payroll_SearchInterviewScheduleItem_sp   @DepartmentID INT,   @DivisionID INT,   @AdvertRefNo nVARCHAR(50)=NULL  AS  BEGIN   SET NOCOUNT ON;   SELECT    pcs.InterviewScheduleID,   Pa.AdvertId,   pp.Position_ID,   PA.AdvertRefNo,   PP.PositionDesc,   PA.AdvertisementDate,   PA.ClosingDate,   pcs.InterviewDate   from dbo.Payroll_Advert AS PA   INNER JOIN dbo.payroll_InterviewSchedule AS pcs ON pcs.AdvertId = PA.AdvertId   LEFT join Payroll_Position PP ON pa.PositionId = pp.Position_ID   WHERE (isnull(@DepartmentID,0) = 0 OR PP.DepartmentID = @DepartmentID)   AND (isnull(@DivisionID,0) = 0 OR PP.DivisionID = @DivisionID)   AND (@AdvertRefNo IS NULL or  pa.AdvertRefNo = @AdvertRefNo)    END    

GO

-- ============================================
-- SP: Payroll_SearchListByOvertimeID
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SearchListByOvertimeID]    @OvertimeID int   AS  BEGIN   SELECT     PAY_EMP_OVR.EmployeeOverTime_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,     CONVERT(NVARCHAR,PAY_EMP_OVR.OverTimeDate,103) AS OverTimeDate,    PAY_EMP_OVR.OverTimeHour,PAY_EMP_OVR.OverTimeFlag,    PAY_EMP_OVR.CostDesc as CostDesc,CASE WHEN PAY_EMP_OVR.Enabled = 1 THEN    ' ACTIVE'    ELSE    'IN ACTIVE'    END AS STATUS,    PAY_EMP_OVR.CapturerID,    PAY_EMP_OVR.DateCaptured,    PAY_EMP_OVR.ModifierID,    PAY_EMP_OVR.DateModified,    dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,    isnull(P_E.EmpCode,'') EmpCode   FROM Payroll_EmployeeOverTime AS PAY_EMP_OVR    INNER JOIN Payroll_Employee AS P_E ON PAY_EMP_OVR.EmployeeID = P_E.Employee_ID    WHERE PAY_EMP_OVR.Enabled = 1 and PAY_EMP_OVR.EmployeeOverTime_ID = @OvertimeID   ORDER BY P_E.Employee_ID  END      

GO

-- ============================================
-- SP: Payroll_SearchListByTravelEntryID
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Lungisani>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_SearchListByTravelEntryID]   @TravelEntry_ID int   AS  BEGIN   SELECT PAY_COST.TravelEntry_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      Isnull(CONST_TRAN.TransactionTypeDesc + '  '+ PAY_SAL.SalaryHeadTitle,0) AS 'PayDefination',     PAY_COST.CostAmount,PAY_COST.CostDesc, PAY_COST.FinancialYear,     CASE WHEN PAY_COST.[Enabled] = 1 THEN ' True' ELSE 'False' END AS [STATUS],     PAY_COST.EntryDate, PAY_COST.CapturerID, PAY_COST.DateCaptured, PAY_COST.ModifierID,     PAY_COST.DateModified,PAY_COST.Kilometer,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_TravelEntry AS PAY_COST        INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID     LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_COST.PayrollDefinationID = PAY_DEF.EmployeePayrollDefinition_ID        LEFT OUTER JOIN Payroll_SalaryHead PAY_SAL ON PAY_DEF.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     LEFT OUTER JOIN Payroll_IRP5Code PAY_IRP ON PAY_IRP.IRP5Code_ID = PAY_SAL.IRP5CodeId     LEFT OUTER JOIN Const_TransactionType CONST_TRAN ON PAY_IRP.TransactionTypeID = CONST_TRAN.TransactionType_ID       WHERE PAY_COST.TravelEntry_ID = @TravelEntry_ID and PAY_COST.Enabled=1    ORDER BY P_E.Employee_ID  END  

GO

-- ============================================
-- SP: Payroll_SearchPayslip_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 13 FEB 2014  -- Description: Returns all employees which match the required search parameters  -- Call: [Payroll_SearchEmployee_sp] 0, 641   -- 2015-02-12 James Roodt: Added more search paramters instead of just employee ID  -- 2015-02-12 James Roodt: Changed search criteria to be exclusive instead of inclusive (or becomes and)  -- 2015-11-25 Suri Kandukuri : Modified the StepLocation Calculation for Biometrics.  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- 2016-04-23 TP#32072 James Roodt: Fixed some step calculations  -- 2017-07-13 Richa Mills TP#59323 - Add Employee Start and End Date  -- 2020/11/04 Richa M : Remove Terminated Employees  -- 2021/10/18 Eben Beetge If Empcode is null then display blank, not 99999  -- 2022/03/21 Richa M : The payslip printing process do not work correctly for changed cycles  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchPayslip_sp]      @IsDummy        bit,      @EmployeeID     int            = NULL,      @Surname        nvarchar(50)   = NULL,      @FullName       nvarchar(200)  = NULL,      @IDNumber       nvarchar(13)   = NULL,      @PassportNumber nvarchar(20)   = NULL,      @EmployeeCode   nvarchar(50)   = NULL,      @DepartmentID   int            = NULL,      @PayPointID     int            = NULL,      @CycleID        int            = NULL,      @PeriodID       int            = NULL,      @GenerateAll    bit            = 0       -- kept for compatibility; not used for filtering  AS  BEGIN      SET NOCOUNT ON;        DECLARE @Processed bit = (SELECT Processed FROM Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodID);        IF @Processed = 1      BEGIN          /* FINAL (Processed) */          SELECT DISTINCT              PE.CycleID                                AS CycleID,              PP.DepartmentID                           AS DepartmentID,              PE.PayPointID                             AS PayPointID,              PE.Employee_ID                            AS Employee_ID,              PE.IdNo                                   AS IdNo,              PE.Surname                                AS Surname,              PE.FirstName                              AS FirstName,              PE.PassportNumber                         AS PassportNumber,              ISNULL(PE.EmailAddress, '')               AS EmailAddress,              ISNULL(PE.CellNumber, '')                 AS CellNumber,              ISNULL(PE.HomeNumber, '')                 AS HomeNumber,              ISNULL(PE.FaxNumber, '')                  AS FaxNumber,              PE.JoiningDate                            AS JoiningDate,              PE.EndDate                                AS EndDate,              PP.PositionDesc                           AS PositionDesc,              CAST(CASE WHEN PE.EndDate >= GETDATE() THEN 1 ELSE 0 END AS bit) AS [Enabled],              PE.IsMarried                              AS IsMarried,              ISNULL(PE.EmpCode, '')                    AS EmpCode          FROM (SELECT DISTINCT EmployeeID FROM Payroll_PayrollResults WHERE PeriodID = @PeriodID and Amount <> 0) PR          JOIN Payroll_Employee  AS PE ON PR.EmployeeID = PE.Employee_ID          JOIN Payroll_Position  AS PP WITH (NOLOCK) ON PP.Position_ID = PE.PositionID          LEFT JOIN Payroll_PayPointDetails AS PPD WITH (NOLOCK)              ON PPD.DepartmentID = PP.DepartmentID             AND PPD.PayPointID   = (CASE WHEN ISNULL(@PayPointID,0)=0 THEN PPD.PayPointID ELSE @PayPointID END)             AND PPD.Enabled = 1          WHERE              PE.IsDummy = @IsDummy              AND (ISNULL(@EmployeeID,0)     = 0 OR PE.Employee_ID   = @EmployeeID)              AND (ISNULL(@Surname,'')       = '' OR PE.Surname      LIKE '%' + @Surname + '%')              AND (ISNULL(@FullName,'')      = '' OR PE.FirstName    LIKE '%' + @FullName + '%')              AND (ISNULL(@IDNumber,'')      = '' OR PE.IdNo         LIKE '%' + @IDNumber + '%')              AND (ISNULL(@PassportNumber,'')= '' OR PE.PassportNumber LIKE '%' + @PassportNumber + '%')              AND (ISNULL(@EmployeeCode,'')  = '' OR PE.EmpCode      LIKE '%' + @EmployeeCode + '%')          ORDER BY PE.Employee_ID;      END      ELSE      BEGIN          /* TRIAL (Unprocessed) */          SELECT DISTINCT              PE.CycleID                                AS CycleID,              PP.DepartmentID                           AS DepartmentID,              PE.PayPointID                             AS PayPointID,              PE.Employee_ID                            AS Employee_ID,              PE.IdNo                                   AS IdNo,              PE.Surname                                AS Surname,              PE.FirstName                              AS FirstName,              PE.PassportNumber                         AS PassportNumber,              ISNULL(PE.EmailAddress, '')               AS EmailAddress,              ISNULL(PE.CellNumber, '')                 AS CellNumber,              ISNULL(PE.HomeNumber, '')                 AS HomeNumber,              ISNULL(PE.FaxNumber, '')                  AS FaxNumber,              PE.JoiningDate                            AS JoiningDate,              PE.EndDate                                AS EndDate,              PP.PositionDesc                           AS PositionDesc,              CAST(CASE WHEN PE.EndDate >= GETDATE() THEN 1 ELSE 0 END AS bit) AS [Enabled],              PE.IsMarried                              AS IsMarried,              ISNULL(PE.EmpCode, '')                    AS EmpCode          FROM (SELECT DISTINCT EmployeeID FROM Payroll_TrialResults WHERE PeriodID = @PeriodID) PR          JOIN Payroll_Employee AS PE ON PR.EmployeeID = PE.Employee_ID          JOIN Payroll_Position AS PP WITH (NOLOCK)               ON PP.Position_ID =                  (                      SELECT TOP 1 PH.PositionID                      FROM Payroll_PositionHistory PH                      WHERE PH.EmployeeID = PE.Employee_ID                      ORDER BY PH.StartDate DESC                  )              AND PP.DepartmentID = (CASE WHEN ISNULL(@DepartmentID,0)=0 THEN PP.DepartmentID ELSE @DepartmentID END)              AND PP.Enabled = 1          LEFT JOIN Payroll_PayPointDetails AS PPD WITH (NOLOCK)              ON PPD.DepartmentID = PP.DepartmentID             AND PPD.PayPointID   = (CASE WHEN ISNULL(@PayPointID,0)=0 THEN PPD.PayPointID ELSE @PayPointID END)             AND PPD.Enabled = 1          WHERE              PE.IsDummy = @IsDummy              AND (ISNULL(@EmployeeID,0)     = 0 OR PE.Employee_ID   = @EmployeeID)              AND (ISNULL(@Surname,'')       = '' OR PE.Surname      LIKE '%' + @Surname + '%')              AND (ISNULL(@FullName,'')      = '' OR PE.FirstName    LIKE '%' + @FullName + '%')              AND (ISNULL(@IDNumber,'')      = '' OR PE.IdNo         LIKE '%' + @IDNumber + '%')              AND (ISNULL(@PassportNumber,'')= '' OR PE.PassportNumber LIKE '%' + @PassportNumber + '%')              AND (ISNULL(@EmployeeCode,'')  = '' OR PE.EmpCode      LIKE '%' + @EmployeeCode + '%')          ORDER BY PE.Employee_ID;      END  END

GO

-- ============================================
-- SP: Payroll_SearchPayslipMessage_sp
-- Schema: dbo
-- ============================================
  /*   Author:   Ferdi Botha   Create Date: Dec. 11, 2018   Description: Returns all Payslip Messages filtered by the Message parameter  */  create procedure [Payroll_SearchPayslipMessage_sp] @Message nvarchar(256) = null  as  begin     select [Message_ID], [Message], [StartDate], [EndDate], [Enabled]      from [Payroll_PayslipMessages] with(nolock)     where ([Message] like (case when @Message is null then [Message] else '%' + @Message + '%' end))    end  

GO

-- ============================================
-- SP: Payroll_SearchPositions_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author   : Varun Parvataneni  -- Create date: 30/09/2016  -- Description: Display the Grid basaed on the Department/Division Criteria  -- Call SP    : Payroll_SearchPositions_sp 5,0     -- Modiri : 20190814 #92741 Position: Incorrect information relating to the Start Date of a position in the Search Grid    -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SearchPositions_sp]  @DepartmentID INT,  @DivisionID INT   AS  BEGIN     SELECT PP.Position_ID,    PP.PositionDesc as PositionDesc,     Min(PH.StartDate) as StartDate,     MAX(PH.EndDate) as EndDate,     PJ.JobTitle,    T.TaskGradeName AS GradeName    from Payroll_Position  PP       JOIN Payroll_PositionHistory PH on PH.PositionID=PP.Position_ID       Left Join dbo.Payroll_JobProfile PJ ON PP.JobProfileID =PJ.JobProfile_ID       LEFT JOIN dbo.Payroll_TaskGrade T ON T.TaskGrade_Id = PJ.TaskGradeId   WHERE    (isnull(@DepartmentID,0) = 0 OR PP.DepartmentID = @DepartmentID)      AND (isnull(@DivisionID,0) = 0 OR PP.DivisionID = @DivisionID)      --AND PositionID=128   group by PP.Position_ID,     PP.PositionDesc,     PJ.JobTitle,    T.TaskGradeName  END  

GO

-- ============================================
-- SP: Payroll_SearchProspectiveEmployee_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 13 FEB 2014  -- Description: Returns all employees which match the required search parameters  -- Call: [Payroll_SearchEmployee_sp] 0, 641   -- 2015-02-12 James Roodt: Added more search paramters instead of just employee ID  -- 2015-02-12 James Roodt: Changed search criteria to be exclusive instead of inclusive (or becomes and)  -- 2015-11-25 Suri Kandukuri : Modified the StepLocation Calculation for Biometrics.  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- 2016-04-23 TP#32072 James Roodt: Fixed some step calculations  -- 2017-07-13 Richa Mills TP#59323 - Add Employee Start and End Date  -- ==============================================================================  /*   Modified by :  Modiri   DATE  : 20190529   Reason  : #89160 Unable to Create a new Prospective employee done Still to test on QA, SP was not returning because the prospective employee can be created with a a postion.  */  CREATE procedure [dbo].[Payroll_SearchProspectiveEmployee_sp] @IsDummy bit, @EmployeeID int = null, @Surname nvarchar(50) = null, @FullName nvarchar(200) = null, @IDNumber nvarchar(13) = null, @PassportNumber nvarchar(20) = null, @EmployeeCode nvarchar(50) = null  as    begin       select [ProspectiveEmployee_ID], [IdNo], [Surname], [FirstName], [PassportNumber], isnull([EmailAddress], '') as [EmailAddress], isnull([CellNumber], '') as [CellNumber], isnull([HomeNumber], '') as [HomeNumber], isnull([FaxNumber], '') as [FaxNumber], [JoiningDate], [PE].[EndDate], [PositionDesc],      cast((case when [PE].[EndDate] >= getdate() then 1 else 0 end) as bit) as [Enabled], [PE].[IsMarried], isnull([EmpCode], '') as [EmpCode]      from [Payroll_ProspectiveEmployee] as [PE] with(nolock)       LEFT join [Payroll_Position] as [PP] with(nolock) on [Position_ID] = [PositionID]      where (       (isnull(@EmployeeID, 0) = 0 or [ProspectiveEmployee_ID] = @EmployeeID) and       (isnull(@Surname, '') = '' or [Surname] like '%' + @Surname + '%') and       (isnull(@FullName, '') = '' or [FirstName] like '%' + @FullName + '%') and       (isnull(@IDNumber, '') = '' or [IdNo] like '%' + @IDNumber + '%') and       (isnull(@PassportNumber, '') = '' or [PassportNumber] like '%' + @PassportNumber + '%') and       (isnull(@EmployeeCode, '') = '' or [EmpCode] like '%' + @EmployeeCode + '%')      )    and [PE].Enabled = 1    order by [ProspectiveEmployee_ID]    end

GO

-- ============================================
-- SP: Payroll_SearchProspectiveEmployeeQualifications_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [Payroll_SearchProspectiveEmployeeQualifications_sp] @EmployeeID             INT,                      @Education              BIT,                      @Accreditation          BIT,                      @Qualification          VARCHAR(50),                      @QualificationTypeID    INT,                      @FieldOfStudyID    INT,                     @QualificationShortCode VARCHAR(255),                      @ProfessionalBodyCode   VARCHAR(255)  AS   BEGIN    SET NOCOUNT ON;    SELECT [Qualification_ID],         (CASE       WHEN [IsEducation] = 1       THEN 'Education'       ELSE(CASE          WHEN [IsProfessionalAccreditation] = 1          THEN 'Accreditation'          ELSE 'N/A'         END)      END) AS [TypeOfQualification],         [Qualification],         [QT].[QualificationTypeName],         [FOS].[Name] as [FieldOfStudy],        [QualificationShortCode],         [QualificationShortDescription],         [ProfessionalBodyCode],         [ProfessionalBodyName],        [StartDate],        [IsCompleted],        [CompletionYear]    FROM [Payroll_ProspectiveEmployeeQualifications] AS [Q] WITH(NOLOCK)      LEFT JOIN [Payroll_QualificationTypes] AS [QT] WITH(NOLOCK) ON [Q].[QualificationTypeID] = [QT].[QualificationTypeId]      LEFT JOIN [Payroll_FieldOfStudy] AS [FOS] WITH(NOLOCK) ON [FOS].[FieldOfStudy_ID] = [Q].FieldOfStudyID    WHERE([ProspectiveEmployeeID] = @EmployeeID       AND (([Qualification] = @Qualification       OR @Qualification = '-1')         AND ([Q].[QualificationTypeId] = @QualificationTypeID        OR @QualificationTypeID < 1)         AND ([Q].[FieldOfStudyID] = @FieldOfStudyID        OR @FieldOfStudyID < 1)         AND ([QualificationShortCode] = @QualificationShortCode        OR @QualificationShortCode = '-1')         AND ([ProfessionalBodyCode] = @ProfessionalBodyCode        OR @ProfessionalBodyCode = '-1')         AND ([IsEducation] = @Education        OR @Education IS NULL)         AND ([IsProfessionalAccreditation] = @Accreditation        OR @Accreditation IS NULL)))    ORDER BY [Qualification_ID] DESC;    SET NOCOUNT OFF;   END;

GO

-- ============================================
-- SP: Payroll_SearchProvisionReport_sp
-- Schema: dbo
-- ============================================
  CREATE PROCEDURE [dbo].[Payroll_SearchProvisionReport_sp]      @Description NVARCHAR(200) =null,   @ProvisionTypeID INT= null,   @ProvisionFinancialYear NVARCHAR(9)= null        AS    BEGIN        SELECT h.[ProvisionReport_ID]           ,t.ProvisionReportType_ID       ,h.[FinancialYear]       ,t.Description AS ProvisionType       ,h.ProvisionDescription        ,h.[Enabled]       ,h.[CapturerId]        ,h.[ModifierId]       ,h.[DateCaptured]       ,h.[DateModified]                    FROM [dbo].Payroll_ProvisionReportHeader h           LEFT JOIN [dbo].[Payroll_ProvisionReportTypes_sys] t        ON h.ProvisionReportTypeId = t.ProvisionReportType_ID            WHERE  (isnull(@ProvisionTypeID,0) = 0 OR ProvisionReportType_ID = @ProvisionTypeID)      AND (isnull(@Description,'') = '' OR Description LIKE '%' + @Description + '%')      AND (isnull(@ProvisionFinancialYear,'') = '' OR TaxYear LIKE '%' + @ProvisionFinancialYear + '%')                                  END    

GO

-- ============================================
-- SP: Payroll_SearchProvisionReportPayrollCycle_sp
-- Schema: dbo
-- ============================================
      -- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 02 March 2016  -- Description: Return all the payroll cycle  which match the required search parameters  -- Call: [Payroll_SearchProvisionReportPayrollCycle_sp]    -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_SearchProvisionReportPayrollCycle_sp]  @Cycle_ID INT= null  AS   BEGIN       SELECT [Cycle_ID]      ,[CycleDesc]      ,[Enabled]      ,[DateCaptured]      ,[CapturerID]      ,[DateModified]      ,[ModifierID]   FROM   [dbo].[Const_cycle]        WHERE  (isnull(@Cycle_ID,0) = 0 OR Cycle_ID = @Cycle_ID)    END    

GO

-- ============================================
-- SP: Payroll_SearchQualificationLibrary_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_SearchQualificationLibrary_sp]    -- Add the parameters for the stored procedure here    @Eductaion Bit,    @Accreditation Bit,    @Qualification varchar(50),    @QualificationTypeID int,    @FieldOfStudyID int,    @QualificationShortCode varchar(255),    @ProfessionalBodyCode varchar(255)   AS   BEGIN    -- SET NOCOUNT ON added to prevent extra result sets from        SET NOCOUNT ON;    SELECT [Qualification_ID]      ,case when [IsEducation] = 1 then     'Education'       else     case when [IsProfessionalAccreditation] = 1 then      'Accreditation'     else      'N/A'     end       end as TypeOfQualification      ,[Qualification]      ,[qt].[QualificationTypeName] as QualificationType      ,[fos].[Name] as FieldOfStudy      ,[QualificationShortCode]       ,[QualificationShortDescription] as [QualificationDescription]      ,[ProfessionalBodyCode]      ,[ProfessionalBodyName]     FROM [dbo].[Const_Qualification_Sys] q     LEFT JOIN [dbo].[Payroll_QualificationTypes] qt on qt.QualificationTypeId = q.QualificationTypeID     LEFT JOIN [dbo].[Payroll_FieldOfStudy] fos on fos.FieldOfStudy_ID = q.FieldOfStudyID     where (        ([Qualification] = @Qualification or @Qualification = '-1') and       ((@QualificationTypeID IS NULL OR @QualificationTypeID < 1) OR ([Q].[QualificationTypeID] = @QualificationTypeID)) AND       ((@FieldOfStudyID IS NULL OR @FieldOfStudyID < 1) OR ([Q].[FieldOfStudyID] = @FieldOfStudyID)) AND       ([QualificationShortCode] = @QualificationShortCode or @QualificationShortCode = '-1') and       ([ProfessionalBodyCode] = @ProfessionalBodyCode or @ProfessionalBodyCode = '-1') and        ([IsEducation] = @Eductaion   or  @Eductaion is NULL) and       ([IsProfessionalAccreditation] = @Accreditation or @Accreditation is NULL)      )     order by [Qualification_ID] desc       END

GO

-- ============================================
-- SP: Payroll_SearchShortlistingItem_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Himil Modi>  -- Create date: <Create Date,,09/11/2018>  -- Description: <Description,,Get Shortlisting list>  -- =============================================  CREATE PROCEDURE Payroll_SearchShortlistingItem_sp   @DepartmentID INT,   @DivisionID INT,   @AdvertRefNo nVARCHAR(50)=NULL  AS  BEGIN   SET NOCOUNT ON;   SELECT    pcs.CandidateShortListID,   pp.Position_ID,   PA.AdvertRefNo,   PP.PositionDesc,   PA.AdvertisementDate,   PA.ClosingDate,   pcs.DateofShortlisting   from dbo.Payroll_Advert AS PA   INNER JOIN dbo.Payroll_CandidateShortListPage AS pcs ON pcs.AdvertId = PA.AdvertId   LEFT join Payroll_Position PP ON pa.PositionId = pp.Position_ID   WHERE (isnull(@DepartmentID,0) = 0 OR PP.DepartmentID = @DepartmentID)   AND (isnull(@DivisionID,0) = 0 OR PP.DivisionID = @DivisionID)   AND (@AdvertRefNo IS NULL or  pa.AdvertRefNo = @AdvertRefNo)  END    

GO

-- ============================================
-- SP: Payroll_SearchTaxDirective_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_SearchTaxDirective_sp]   -- Add the parameters for the stored procedure here   @EmployeeID int,   @TaxNumber varchar(25),   @IDNumber varchar(13),   @PassPortNumber varchar(25),   @TaxYear varchar(9),   @TaxDirectiveNumber varchar(100),   @TaxDirectiveType int    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;       select D.TaxDirectives_ID,     D.ExpiryDate,     E.Employee_ID,    E.IncomeTaxNumber,    E.IdNo,    E.PassportNumber,    E.FirstName,     E.Surname,    E.EmpCode,    D.TaxDirectiveNumber,    T.DirectiveDesc,    D.TaxYear,     D.TaxDirectiveFilePath,    IIF(D.DirectiveTypeId = 1, TaxDirectiveValue, NULL) AS FixedPercentage, --IRP3 (b) Fixed Percentage    IIF(D.DirectiveTypeId = 2, TaxDirectiveValue, NULL) AS FixedAmount, --IRP3 (c) Fixed Amount    IIF(D.DirectiveTypeId = 4, TaxDirectiveValue, NULL) AS TaxOnGratuity, --IRP3 (a) Gratuities    IIF(D.DirectiveTypeId = 4, GratuityAmount, NULL) AS GratuityAmount --IRP3 (a) Gratuities    from Payroll_EmployeeTaxDirectives as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmpID    left join Payroll_TaxDirectiveType as T on T.DirectiveType_Id = D.DirectiveTypeId    where (E.Employee_ID = @EmployeeID or @EmployeeID = -1) and D.[Enabled] = 1 and    D.TaxYear in (select distinct FinancialYear from Const_StatutoryRates where @TaxYear = '-1' or @TaxYear = FinancialYear) and    T.DirectiveType_Id in  (select distinct DirectiveType_Id from Payroll_TaxDirectiveType where @TaxDirectiveType = -1 or @TaxDirectiveType = DirectiveType_Id) and    (       (E.IncomeTaxNumber = @TaxNumber or @TaxNumber = '') and      (E.IdNo = @IDNumber or @IDNumber = '') and      (E.PassportNumber = @PassPortNumber or @PassPortNumber = '') and      (D.TaxDirectiveNumber = @TaxDirectiveNumber or @TaxDirectiveNumber = '')         )          END

GO

-- ============================================
-- SP: Payroll_SearchTaxOverDeduction_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_SearchTaxOverDeduction_sp]   -- Add the parameters for the stored procedure here   @EmployeeID int,   @SalaryHeadID int,   @TaxNumber varchar(25),   @IDNumber varchar(13),   @PassPortNumber varchar(25),   @TaxYear varchar(9),   @TaxPeriods int,   @StartDate DateTime,   @EndDate DateTime    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;       select D.TaxOverDeduction_ID,     E.Employee_ID,    H.SalaryHeadName,    D.PeriodNo,    D.Amount,    D.TaxYear,    D.StartDate,    D.EndDate,    D.FilePath,    E.IncomeTaxNumber,    E.IdNo,    E.PassportNumber,    E.FirstName,     E.Surname    from Payroll_EmployeeTaxOverDeduction as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmployeeID    left join Payroll_SalaryHead as H on H.SalaryHead_ID = D.SalaryHeadID    where E.Employee_ID = @EmployeeID and D.[Enabled] = 1 and     D.TaxYear in (select distinct TaxYear from Payroll_EmployeeTaxOverDeduction where @TaxYear = '-1' or @TaxYear = TaxYear) and    H.SalaryHead_ID in  (select distinct SalaryHead_ID from Payroll_SalaryHead where @SalaryHeadID = -1 or @SalaryHeadID = SalaryHead_ID) and    D.PeriodNo in (select distinct PeriodNo from Payroll_EmployeeTaxOverDeduction where @TaxPeriods = '-1' or @TaxPeriods = PeriodNo) and    (       (E.IncomeTaxNumber = @TaxNumber or @TaxNumber = '') and      (E.IdNo = @IDNumber or @IDNumber = '') and      (E.PassportNumber = @PassPortNumber or @PassPortNumber = '') and      (D.StartDate between @StartDate and @EndDate or @EndDate is Null or @StartDate is NULL ) and      (D.EndDate between @StartDate and @EndDate or @EndDate is Null or @StartDate is NULL )    )          END  

GO

