-- ============================================
-- SP: Payroll_Stats0271_01_sp
-- Schema: dbo
-- ============================================
-- =================================================  -- author:  <author,,Lungisani>  -- create date: <create date,,20/08/2018>  -- description: <description,Stats0271_01 report>  -- =================================================    create procedure [dbo].[Payroll_Stats0271_01_sp] @startDate datetime, @endDate datetime, @FinYear nvarchar(10), @StatsId int    as  begin      select(convert(varchar(10),@startDate, 103) + ' - ' + convert(varchar(10),@endDate, 103)) as [Period], @FinYear as [FinYear],            count((case when ([PE].[IsContractor] is null or [PE].[IsContractor] = 0) then [PE].[Employee_ID] end)) as [FullTime],                count((case when ([PE].[IsContractor] = 1) then [PE].[Employee_ID] end)) as [PartTime],             count((case when ([PE].[EndDate] <= @endDate) then [PE].[Employee_ID] end)) as [All],         count((case when ([PE].[JoiningDate] >= @startDate and [PE].[JoiningDate] <= @endDate) then [PE].[Employee_ID] end)) as [Joined],         count((case when ([PE].[EndDate] >= @startDate  and [PE].[EndDate] <= @endDate) then [PE].[Employee_ID] end)) as [Left],         sum((case when ([CC].[CycleTypeID] = 1 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                                                  else 0 end) end)) as [Monthly],      sum((case when ([CC].[CycleTypeID] = 2 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                             else 0 end) end)) as [Weekly],             sum((case when ([CC].[CycleTypeID] = 3 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                             else 0 end) end)) as [Bi-weekly],        sum((case when ([CPD].[CycleModeID] = 2) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                           when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                      else 0 end) end)) as [Other],        sum((case when ([SD].[ScoaFunctionTypesID] = 1) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                          when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                        else 0 end) end)) as [Housing],      sum((case when ([SD].[ScoaFunctionTypesID] = 2) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                         else 0 end) end)) as [EnergySources],             sum((case when ([SD].[ScoaFunctionTypesID] = 3) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID]  then [PR].[Amount]                           when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                      else 0 end) end)) as [WaterManagement],        sum((case when ([SD].[ScoaFunctionTypesID] = 4) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                             else 0 end) end)) as [GeneralServices],        sum((case when ([SD].[ScoaFunctionTypesID] = 5 or [SD].[ScoaFunctionTypesID] = 6 or [SD].[ScoaFunctionTypesID] = 8) then                         (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID]  then [PR].[Amount]                                     when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                               else 0 end) end)) as [Transport],      sum((case when ([SD].[ScoaFunctionTypesID] = 7) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                             else 0 end) end)) as [OtherCost],       sum((case when ([ET].[Complete] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                          when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                     else 0 end) end)) as [Termination]         from [Payroll_StatisticsSA] [ST] with(nolock)      join [Payroll_StatisticsSADetails] [SD] with(nolock) on [ST].[StatisticsReportTypeID] = [SD].[StatisticsReportTypeID]      join [Payroll_StatisticsSASections] [SS] with(nolock) on [SD].[StatisticsSADetails_ID] = [SS].[StatisticsSASections_ID] and  [SD].[Enabled] = 1      left join [Payroll_ScoaFunctionTypes] [SF] with(nolock) on [SD].[ScoaID] = [SF].[ScoaFunctionTypes_ID]      left join [Payroll_PayrollResults][PR] with(nolock) on [SD].[SalaryHeadID] = [PR].[SalaryHeadID]      left join [Payroll_CyclePeriodDetails][CPD] with(nolock) on [PR].[PeriodID] = [CPD].[Period_ID]      left join [Const_Cycle][CC] with(nolock) on [CPD].[CycleID] = [CC].[Cycle_ID]      left join [Payroll_Employee][PE] with(nolock) on [PE].[Employee_ID] = [PR].[EmployeeID]      left join [Const_SCOA_Structure][CSS] with(nolock) on [SF].[NTScoaID] = [CSS].[NTScoaID] or [CSS].[NTParentScoaId] = [SF].[NTScoaID]      left join [Payroll_GLItems] [GL] with(nolock) on [SD].[SalaryHeadID] = [GL].[SalaryHeadID]      left join [Payroll_EmployeeTermination] [ET] with(nolock) on [PR].[EmployeeID] = [ET].[EmployeeID] and [ET].[Enabled] = 1 and [ET].[TerminationStartDate] <= @endDate      where ([PE].[IsDummy] is null or [PE].[IsDummy] = 0) and [PE].[JoiningDate] <= @startDate and [PE].[EndDate] >= @endDate and [PE].[Enabled] = 1         and [ST].[StatisticsSA_ID] = @StatsId          end      

GO

-- ============================================
-- SP: Payroll_Stats0275_sp
-- Schema: dbo
-- ============================================
-- =================================================  -- author:  <author,,Lungisani>  -- create date: <create date,,20/08/2018>  -- description: <description,Stats0275 report>  -- =================================================    create procedure [dbo].[Payroll_Stats0275_sp] @startDate datetime, @endDate datetime, @FinYear nvarchar(10), @StatsId int    as  begin      declare @table table (     [ID][int] identity(1,1),     [Year][int] null      )      declare @YearStart int = datepart(year,@startDate), @YearEnd int =  datepart(year,@endDate), @count int = 1      while(((select max([ID]) from @table) is null) or ((select max([ID]) from @table) < 3))    begin        if((select min([Year]) from @table) is null)             insert into @table values(@YearStart)     else       insert into @table values((select max([Year]) from @table) + 1)      end        while(@count < 4)    begin          select @YearStart = [Year] from @table where [ID] = @count        select (@YearStart) as [Year],                count((case when ([PE].[IsContractor] is null or [PE].[IsContractor] = 0) then [PE].[Employee_ID] end)) as [FullTime],                count((case when ([PE].[IsContractor] = 1) then [PE].[Employee_ID] end)) as [PartTime],             count((case when (datepart(year,[PE].[EndDate]) = @YearStart) then [PE].[Employee_ID] end)) as [All],         count((case when (datepart(year,[PE].[JoiningDate]) = @YearStart) then [PE].[Employee_ID] end)) as [Joined],         count((case when (datepart(year,[PE].[EndDate]) = @YearStart) then [PE].[Employee_ID] end)) as [Left],         sum((case when ([CC].[CycleTypeID] = 1 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                                                  else 0 end) end)) as [Monthly],            sum((case when ([CC].[CycleTypeID] = 2 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                     when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                                else 0 end) end)) as [Weekly],                sum((case when ([CC].[CycleTypeID] = 3 and [CPD].[CycleModeID] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                                     when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                                else 0 end) end)) as [Bi-weekly],             sum((case when ([CPD].[CycleModeID] = 2) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                           when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                      else 0 end) end)) as [Other],              sum((case when ([SD].[ScoaFunctionTypesID] = 1) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                          when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                        else 0 end) end)) as [Housing],            sum((case when ([SD].[ScoaFunctionTypesID] = 2) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                         else 0 end) end)) as [EnergySources],                sum((case when ([SD].[ScoaFunctionTypesID] = 3) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID]  then [PR].[Amount]                           when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                      else 0 end) end)) as [WaterManagement],            sum((case when ([SD].[ScoaFunctionTypesID] = 4) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                             else 0 end) end)) as [GeneralServices],            sum((case when ([SD].[ScoaFunctionTypesID] = 5 or [SD].[ScoaFunctionTypesID] = 6 or [SD].[ScoaFunctionTypesID] = 8) then                         (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID]  then [PR].[Amount]                                     when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                               else 0 end) end)) as [Transport],           sum((case when ([SD].[ScoaFunctionTypesID] = 7) then (case when [PR].[TransactionTypeID] = 1 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then [PR].[Amount]                                  when [PR].[TransactionTypeID] = 2 and [PR].[SalaryHeadID] = [SD].[SalaryHeadID] then ([PR].[Amount] * -1)                                             else 0 end) end)) as [OtherCost],          sum((case when ([ET].[Complete] = 1) then (case when [PR].[TransactionTypeID] = 1 then [PR].[Amount]                          when [PR].[TransactionTypeID] = 2 then ([PR].[Amount] * -1)                                     else 0 end) end)) as [Termination]          from [Payroll_StatisticsSA] [ST] with(nolock)      join [Payroll_StatisticsSADetails] [SD] with(nolock) on [ST].[StatisticsReportTypeID] = [SD].[StatisticsReportTypeID]      join [Payroll_StatisticsSASections] [SS] with(nolock) on [SD].[StatisticsSADetails_ID] = [SS].[StatisticsSASections_ID] and  [SD].[Enabled] = 1      left join [Payroll_ScoaFunctionTypes] [SF] with(nolock) on [SD].[ScoaID] = [SF].[ScoaFunctionTypes_ID]      left join [Payroll_PayrollResults][PR] with(nolock) on [SD].[SalaryHeadID] = [PR].[SalaryHeadID]      left join [Payroll_CyclePeriodDetails][CPD] with(nolock) on [PR].[PeriodID] = [CPD].[Period_ID] and [CPD].[TaxYear] = @FinYear      left join [Const_Cycle][CC] with(nolock) on [CPD].[CycleID] = [CC].[Cycle_ID]      left join [Payroll_Employee][PE] with(nolock) on [PE].[Employee_ID] = [PR].[EmployeeID]      left join [Const_SCOA_Structure][CSS] with(nolock) on [SF].[NTScoaID] = [CSS].[NTScoaID] or [CSS].[NTParentScoaId] = [SF].[NTScoaID]      left join [Payroll_GLItems] [GL] with(nolock) on [SD].[SalaryHeadID] = [GL].[SalaryHeadID]      left join [Payroll_EmployeeTermination] [ET] with(nolock) on [PR].[EmployeeID] = [ET].[EmployeeID] and [ET].[Enabled] = 1 and (datepart(year,[ET].[TerminationStartDate]) = @YearStart)      where ([PE].[IsDummy] is null or [PE].[IsDummy] = 0) and ((datepart(year,[PE].[JoiningDate]) = @YearStart) or (datepart(year,[PE].[EndDate]) = @YearStart)) and [PE].[Enabled] = 1         and [ST].[StatisticsSA_ID] = @StatsId         set @count = @count + 1      end    end      

GO

-- ============================================
-- SP: Payroll_StatutoryRatesYearly_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 31/07/2013  -- Description: Duplicates the Statuotory tax rates for the new tax year. The values are identical and needs ot be edited afterwards by a user.  -- 2015-03-27 James Roodt: Changed ActiveFinYear to ActivePayrollYear  -- 2015-03-30 James Roodt: Added check to continue  -- 2016-08-17 Seipei Mathole raplaced GetLastYearPayrollYear with [GetLastYearTaxYear]()  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_StatutoryRatesYearly_sp]     AS  BEGIN   SET NOCOUNT ON;     DECLARE @PayrollYear NVARCHAR(10)   DECLARE @OldPayrollYear NVARCHAR(10)   SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SET @OldPayrollYear = (SELECT [dbo].[GetLastYearTaxYear]())      IF NOT EXISTS(SELECT  * FROM Const_StatutoryRates WHERE FinancialYear =@PayrollYear )   BEGIN    INSERT INTO dbo.Const_StatutoryRates    (      TaxableIncomeSlot , MinSlotAmount , MaxSlotAmount , RatesOfTaxFixedAmount , RatesOfTaxPercentage ,      RatesOfTaxAboveAmount , FinancialYear , [Enabled] , DateCaptured , CapturerID    )    (     SELECT TaxableIncomeSlot , MinSlotAmount , MaxSlotAmount , RatesOfTaxFixedAmount , RatesOfTaxPercentage ,      RatesOfTaxAboveAmount , @PayrollYear , 1 , GETDATE() , 1     FROM dbo.Const_StatutoryRates     WHERE FinancialYear = @OldPayrollYear    )   END  END  

GO

-- ============================================
-- SP: Payroll_SubmitDefaultAdhocPayrollRunEarningsAndDeductions_sp
-- Schema: dbo
-- ============================================
    -- ==============================================================================  -- Author:  Saleem Khan  -- Create date: 23 APR 2016  -- Description: a hack to insert some default salaryheads  -- Call: [Payroll_SubmitDefaultAdhocPayrollRunEarningsAndDeductions_sp]  -- 2015-02-17 TP32108 Saleem Khan: Created  -- 2016-04-28 TP#36093 James Roodt: Added UIF CC to the default list as well. Also removed the modified fields as they are created here, not edited  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  CREATE procedure [dbo].[Payroll_SubmitDefaultAdhocPayrollRunEarningsAndDeductions_sp]      @PeriodID INT  AS    BEGIN       IF NOT EXISTS ( SELECT * FROM [dbo].[Payroll_CyclePeriodAdhocSalaryHead]   left join Payroll_salaryhead as SH on SH.SalaryHead_ID=[Payroll_CyclePeriodAdhocSalaryHead].SalaryHeadID    WHERE PeriodID=@PeriodID AND SalaryHeadName IN('UIF','SDL','Pay as you Earn') )   BEGIN      INSERT INTO [dbo].[Payroll_CyclePeriodAdhocSalaryHead]         ([PeriodID]         ,[SalaryHeadID]         ,[Enabled]         ,[DateCaptured]         ,[CapturerID])    SELECT @PeriodID,SalaryHead_ID,1,getdate(),2     FROM PAYROLL_SALARYHEAD SH    LEFT JOIN Payroll_IRP5Code irp ON SH.IRP5CodeId = irp.IRP5Code_ID    where irp.TransactionTypeID=4 OR SalaryHeadName IN('UIF','SDL','Pay as you Earn')     order by SalaryHead_ID   END      END

GO

-- ============================================
-- SP: Payroll_SubmitIRPCriteria_sp
-- Schema: dbo
-- ============================================
/*=============================================   Create date: 07/Oct/2016  Name: Jaydev Jangid  Description:  Insert IRP5 generated certificate details  =============================================*/    create PROCEDURE [dbo].[Payroll_SubmitIRPCriteria_sp]      @PayrollCycleId INT ,      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @IsTerminated BIT ,      @IsLock BIT ,      @LockBy INT ,      @LockDateTime DATETIME ,      @UnlockDateTime DATETIME ,      @IsSignOff BIT ,      @SignoffDocName NVARCHAR(255) ,      @CertificateName NVARCHAR(255) ,      @IsRecon BIT ,      @ReconEmployeeSummary NVARCHAR(255) ,      @ReconTaxCodeSummary NVARCHAR(255) ,      @CertificateRunDate DATETIME ,      @ValidateDate DATETIME ,      @CapturerID INT ,      @ModifierID INT  AS      BEGIN            DECLARE @EmployeeTaxCertificate_ID INT;          DECLARE @payrollModuleId INT;          DECLARE @docGroupId INT;          DECLARE @signOffId INT;          DECLARE @docName NVARCHAR(255);            SELECT  @EmployeeTaxCertificate_ID = EmployeeTaxCertificate_ID FROM dbo.Payroll_EmployeeTaxCertificate WHERE TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;             SET @SignoffDocName = @SignoffDocName + '.pdf';      -- if no record found then insert          IF ( ISNULL(@EmployeeTaxCertificate_ID, 0) = 0 )              BEGIN                        INSERT  INTO dbo.Payroll_EmployeeTaxCertificate                          ( PayrollCycleId ,TaxPeriod ,TaxYear ,IsTerminated ,IsLock ,LockBy ,LockDateTime ,UnlockDateTime ,IsSignOff ,SignoffDocName ,                            CertificateName ,IsRecon ,ReconEmpSummaryRptName ,ReconTaxCodeSummaryName ,CertificateRunDate ,ValidateDate ,CapturerID ,DateCaptured)                  VALUES  ( @PayrollCycleId ,@TaxPeriod ,@TaxYear ,@IsTerminated ,@IsLock ,@LockBy ,@LockDateTime ,@UnlockDateTime ,@IsSignOff ,@SignoffDocName ,                            @CertificateName ,@IsRecon ,@ReconEmployeeSummary ,@ReconTaxCodeSummary ,@CertificateRunDate ,@ValidateDate ,@CapturerID ,GETDATE());              END;                ELSE              IF ( ISNULL(@EmployeeTaxCertificate_ID, 0) > 0 )                  BEGIN                         UPDATE  dbo.Payroll_EmployeeTaxCertificate SET     IsTerminated = @IsTerminated , IsLock = @IsLock , LockBy = @LockBy , LockDateTime = @LockDateTime ,                              UnlockDateTime = @UnlockDateTime ,IsSignOff = @IsSignOff ,SignoffDocName = @SignoffDocName ,CertificateName = @CertificateName ,IsRecon = @IsRecon ,                              ReconEmpSummaryRptName = @ReconEmployeeSummary ,ReconTaxCodeSummaryName = @ReconTaxCodeSummary ,CertificateRunDate = @CertificateRunDate ,                              ValidateDate = @ValidateDate ,ModifierID = @ModifierID ,DateModified = GETDATE()WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;         -- insert & update signoff document                      IF @IsSignOff = 1 AND @TaxPeriod = 'February'                          BEGIN         -- check if sign off document is already exists                              SELECT  @docName = SignoffDocName FROM Payroll_EmployeeTaxCertificate WHERE   TaxPeriod = @TaxPeriod AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;                                SELECT  @payrollModuleId = Module_ID FROM dbo.User_Module WHERE   ModuleDesc = 'Payroll';                                SELECT  @docGroupId = SupportingDocsGroup_ID FROM dbo.Const_SupportingDocsGroup WHERE   GroupDesc = 'IRP5';           -- check for record exists                               SELECT  @signOffId = SupportingDocs_ID FROM dbo.Sys_SupportingDocs WHERE   ModuleID = @payrollModuleId AND SupportingDocsGroupID = @docGroupId AND [Filename] = @docName;                                IF ISNULL(@signOffId, 0) = 0  --if not exists then insert new record                                  BEGIN                                      INSERT  dbo.Sys_SupportingDocs ( [Filename] ,SuppDocDesc ,DocumentAuthor ,DocumentDate ,ModuleID ,SupportingDocsGroupID ,TableLinkedName ,TableLinkedID ,DateImported ,                                                ImportedByID ,DateCaptured ,CapturerID ,DateModified ,ModifierID) VALUES  ( @SignoffDocName ,'Payroll Signoff' ,NULL ,GETDATE() ,@payrollModuleId ,@docGroupId ,NULL ,0 ,GETDATE() ,                                                0 ,GETDATE() ,@CapturerID ,NULL ,0);                                  END;                              ELSE                                  IF ISNULL(@signOffId, 0) > 0   -- update                                      BEGIN                                          UPDATE  Sys_SupportingDocs SET DateModified = GETDATE() ,ModifierID = @CapturerID , [Filename] = @SignoffDocName WHERE   SupportingDocsGroupID = @signOffId;                                      END;                          END;                                    END;            END;  

GO

-- ============================================
-- SP: Payroll_SubmitIRPUnlock_sp
-- Schema: dbo
-- ============================================
/*=============================================   Create date: 07/Oct/2016  Name: Jaydev Jangid  Description: set Lock value false ( set unlock )  =============================================*/  CREATE PROCEDURE [dbo].[Payroll_SubmitIRPUnlock_sp]      @TaxPeriod NVARCHAR(10) ,      @TaxYear NVARCHAR(10) ,      @PayrollCycleId INT  AS      BEGIN          DELETE FROM  Payroll_EmployeeTaxCertificate  WHERE TaxPeriod = @TaxPeriod    AND TaxYear = @TaxYear AND PayrollCycleId = @PayrollCycleId;      END;

GO

-- ============================================
-- SP: Payroll_TaxCertificateRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 01 AUG 2013  -- Description:    -- CALLS : Payroll_TaxCertificateRpt_sp 2014, 'Annual', 1, 0, 0  -- 2014-11-03   Stephan Stephansen: added isnull check on first and second names and add surname to empname.  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_TaxCertificateRpt_sp]      @Year INT ,      @Period NVARCHAR(50) ,      @CycleId INT ,      @EmployeeID INT ,      @DepartmentId INT  AS       BEGIN             DECLARE @FinYear NVARCHAR(50) ,              @PeriodId INT ,              @TaxStartMonth INT ,              @FromDate DATETIME ,              @ToDate DATETIME          DECLARE @Start INT = 1 ,              @End INT          SET @FinYear = CONVERT(NVARCHAR(5), @Year - 1) + '/' + CONVERT(NVARCHAR(5), @Year)          PRINT @FinYear             DECLARE @Result TABLE              (                IRP5Code NVARCHAR(50) ,                PayrollSalaryHeadTitle NVARCHAR(50) ,                IRP5CodeDesc NVARCHAR(MAX) ,                Employee_ID INT ,                EmpNo NVARCHAR(50) ,                EmpName NVARCHAR(105) ,                ProcessingMonth NVARCHAR(50) ,                Period_ID INT ,                Amount DECIMAL(18, 2) ,                MonthId INT              )             SELECT TOP 1                  @FromDate = PeriodStartDate          FROM    dbo.Payroll_CyclePeriodDetails          WHERE   TaxYear = @FinYear                  AND CycleID = 1          ORDER BY Period_ID      --SET @FromDate = CONVERT(NVARCHAR(5), @TaxStartMonth)+'/01/'+CONVERT(NVARCHAR(5), @Year - 1)          PRINT @FromDate             IF @Period = 'Annual'               BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate))                  SET @End = 12              END          ELSE               BEGIN                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate))                  SET @End = 6              END          SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 1, @FromDate))          PRINT @ToDate             WHILE @Start <= @End               BEGIN                  INSERT  INTO @Result ( IRP5Code, PayrollSalaryHeadTitle, IRP5CodeDesc, Employee_ID, EmpNo, EmpName, ProcessingMonth, Period_ID, Amount, MonthId )                          SELECT  IRP.IRP5Code, Head.SalaryHeadTitle, IRP.IRP5CodeDesc, EMP.Employee_ID, dbo.BufferString_fxn(CONVERT(NVARCHAR(10), ( EMP.Employee_ID )), 8, '0'), isnull(EMP.FirstName, '') + ' ' + isnull(EMP.SecondName,'') + ' ' + EMP.Surname, DATENAME(MONTH, @FromDate), Cyc.Period_ID, ISNULL(Amount, 0) AS Amount, @Start                          FROM    dbo.Payroll_IRP5Code AS IRP                                  FULL OUTER JOIN dbo.Payroll_SalaryHead AS Head ON IRP.IRP5Code_ID = Head.IRP5CodeId                                  FULL OUTER JOIN dbo.Payroll_EmployeePayrollDefinition AS DEF ON Head.SalaryHead_ID = DEF.PayrollSalaryHeadID                                  FULL OUTER JOIN dbo.Payroll_Employee AS Emp ON DEF.EmployeeID = Emp.Employee_ID                                  FULL OUTER JOIN dbo.Payroll_EmployeePayslip AS EMP_PAY ON EMP_PAY.PayrollDefinationID = DEF.EmployeePayrollDefinition_ID                                  FULL OUTER JOIN dbo.Payroll_CyclePeriodDetails AS Cyc ON EMP_PAY.PeriodID = Cyc.Period_ID                          WHERE   ( IsDummy = 0                                    OR IsDummy IS NULL                                  )                                  AND ( Cyc.CycleID = @CycleId                                        OR Cyc.CycleID IS NULL                                        OR @CycleId = 0                                      )                                  AND ( Emp.Employee_ID = @EmployeeID                                        OR @EmployeeID = 0                                        OR Emp.Employee_ID IS NULL                                      )                                  AND ( Cyc.PeriodEndDate BETWEEN @FromDate AND @ToDate                                        OR Cyc.CycleID IS NULL                                      )                  SET @FromDate = DATEADD(MONTH, 1, @FromDate)                  SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 1, @FromDate))                  SET @Start += 1              END          SELECT  *          FROM    @Result      END  

GO

-- ============================================
-- SP: Payroll_TaxRebatesYearly_sp
-- Schema: dbo
-- ============================================
-- =============================================================================  -- Author:  MEHUL PANCHAL  -- Create date: 31/07/2013  -- Description:  Duplicates the tax rebates for the new tax year.  -- 2015-03-27 James Roodt: Changed ActiveFinYear to ActivePayrollYear  -- 2015-03-30 James Roodt: Added check to continue  -- 2016-06-22 TP:38352-Seipei Mathole : Updated the function GetLastYearTaxYear  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- =============================================================================  CREATE PROCEDURE [dbo].[Payroll_TaxRebatesYearly_sp]     AS  BEGIN   SET NOCOUNT ON;     DECLARE @PayrollYear NVARCHAR(10)   DECLARE @OldPayrollYear NVARCHAR(10)   SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'   SET @OldPayrollYear = (SELECT [dbo].[GetLastYearTaxYear]())     IF NOT EXISTS(SELECT  * FROM Const_TaxRebates WHERE FinancialYear =@PayrollYear )   BEGIN    INSERT INTO dbo.Const_TaxRebates    (     TaxRebatesDesc , MinAge , MaxAge , TaxRebatesAmount , FinancialYear , [Enabled] ,      DateCaptured , CapturerID                  )    (      SELECT TaxRebatesDesc , MinAge , MaxAge , TaxRebatesAmount , @PayrollYear , 1 , GETDATE() , 1     FROM dbo.Const_TaxRebates     WHERE FinancialYear = @OldPayrollYear    )   END  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_BackUpDataNotify_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_BackUpDataNotify_sp]    AS  BEGIN    SET NOCOUNT ON;      select '(Back up the EMS and EMS Audit databases for tax Year End)' + Comments from Payroll_TaxYearEndRun     where TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and ProcessNo = 10 and ClearNotification =0 -- This is the manage 10. Back-Up Tax Year Data Tax Year End run Process      SET NOCOUNT OFF;  END    

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeIRP5CesrtAndSignOffNotify_Ver2_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeIRP5CesrtAndSignOffNotify_Ver2_sp]    AS  BEGIN    SET NOCOUNT ON;       select E.EmpCode,E.FirstName,E.Surname,E.IdNo, TotalEmployeeCount.EmployeeTotalCount, TotalIRP5CertSignOff.TotalIRP5CertSignOff from Payroll_Employee as E    inner join      (select Count(E.Employee_ID) as EmployeeTotalCount from Payroll_Employee as E    inner join Payroll_EmployeeHistory as H on H.EmployeeID = E.Employee_ID     where H.EndDate >=  DateAdd(Year ,-1, DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103)))    and E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)    ) as TotalEmployeeCount on 1=1    inner join     (  select Count(EmployeeTaxCertificate_ID) as TotalIRP5CertSignOff from Payroll_EmployeeTaxCertificate    where TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and isSignOff = 1    ) as TotalIRP5CertSignOff on 1=1    inner join Payroll_TaxYearEndRun as TR on TR.TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and TR.ProcessNo = 8 and TR.ClearNotification =0 -- This is the manage 8. Employee Tax Certificates & Sign Off Tax Year End run Process    where E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)          SET NOCOUNT OFF;  END    

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeIRP5CesrtAndSignOffRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      Create PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeIRP5CesrtAndSignOffRpt_sp]    AS  BEGIN    SET NOCOUNT ON;       select E.EmpCode,E.FirstName,E.Surname,E.IdNo, TotalEmployeeCount.EmployeeTotalCount, TotalIRP5CertSignOff.TotalIRP5CertSignOff from Payroll_Employee as E    inner join      (select Count(E.Employee_ID) as EmployeeTotalCount from Payroll_Employee as E    inner join Payroll_EmployeeHistory as H on H.EmployeeID = E.Employee_ID     where H.EndDate >=  DateAdd(Year ,-1, DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103)))    and E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)    ) as TotalEmployeeCount on 1=1    inner join     (  select Count(EmployeeTaxCertificate_ID) as TotalIRP5CertSignOff from Payroll_EmployeeTaxCertificate    where TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and isSignOff = 1    ) as TotalIRP5CertSignOff on 1=1    where E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)          SET NOCOUNT OFF;  END    

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTaxDirectiveNotify_Ver2_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeTaxDirectiveNotify_Ver2_sp]    AS  BEGIN    SET NOCOUNT ON;      select  D.TaxDirectives_ID, E.EmpCode,E.FirstName ,E.Surname,D.ExpiryDate,T.DirectiveDesc as TaxDirectiveDescription , E.EmailAddress, D.TaxDirectiveNumber from     (select E.Employee_ID ,E.EmpCode as EmployeeCode ,E.FirstName as Name, E.Surname as Surname,     Max(D.ExpiryDate) as Expiry, E.EmailAddress from Payroll_EmployeeTaxDirectives as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmpID    where D.Enabled = 1    Group By E.EmpCode,E.FirstName,E.Surname,E.Employee_ID, E.EmailAddress    Having (Max(Convert(int,SubString(D.TaxYear,0,5))) <> DatePart(Year,GetDate()))) as T1    inner join Payroll_EmployeeTaxDirectives as D on Convert(int,SubString(D.TaxYear,0,5)) = (convert(int,DatePart(Year,GetDate())) - 1) and D.EmpID = T1.Employee_ID    Inner join Payroll_TaxDirectiveType as T on T.DirectiveType_Id = D.DirectiveTypeId    inner join Payroll_Employee as E on E.Employee_ID = T1.Employee_ID    inner join Payroll_TaxYearEndRun as TR on TR.TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and TR.ProcessNo = 5 and TR.ClearNotification =0 -- This is the manage tax Agreement Tax Year End run Process    where D.Enabled = 1     SET NOCOUNT OFF;  END    

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTaxDirectiveRpt_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      Create PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeTaxDirectiveRpt_sp]    AS  BEGIN    SET NOCOUNT ON;      select  D.TaxDirectives_ID, E.EmpCode,E.FirstName ,E.Surname,D.ExpiryDate,T.DirectiveDesc as TaxDirectiveDescription , E.EmailAddress, D.TaxDirectiveNumber from     (select E.Employee_ID ,E.EmpCode as EmployeeCode ,E.FirstName as Name, E.Surname as Surname,     Max(D.ExpiryDate) as Expiry, E.EmailAddress from Payroll_EmployeeTaxDirectives as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmpID    where D.Enabled = 1    Group By E.EmpCode,E.FirstName,E.Surname,E.Employee_ID, E.EmailAddress    Having (Max(Convert(int,SubString(D.TaxYear,0,5))) <> DatePart(Year,GetDate()))) as T1    inner join Payroll_EmployeeTaxDirectives as D on Convert(int,SubString(D.TaxYear,0,5)) = (convert(int,DatePart(Year,GetDate())) - 1) and D.EmpID = T1.Employee_ID    Inner join Payroll_TaxDirectiveType as T on T.DirectiveType_Id = D.DirectiveTypeId    inner join Payroll_Employee as E on E.Employee_ID = T1.Employee_ID    where D.Enabled = 1     SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTaxOverDeductionNotify_sp
-- Schema: dbo
-- ============================================
CREATE procedure [Payroll_TaxYearEnd_EmployeeTaxOverDeductionNotify_sp]    AS  BEGIN    SET NOCOUNT ON;      DECLARE @taxYear CHAR(9) = (SELECT KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear')    select D.TaxOverDeduction_ID, E.EmpCode,E.FirstName ,E.Surname,H.SalaryHeadName as SalaryHeadDescription,E.EmailAddress, D.Amount,D.TaxYear,D.StartDate,D.EndDate, D.PeriodNo  from     (select E.Employee_ID ,E.EmpCode as EmployeeCode ,E.FirstName as Name, E.Surname as Surname,     Max(D.EndDate) as Expiry, E.EmailAddress, Max(Convert(int,SubString(D.TaxYear,0,5))) as TaxYearStart from Payroll_EmployeeTaxOverDeduction as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmployeeID    where D.Enabled = 1    Group By E.EmpCode,E.FirstName,E.Surname, E.EmailAddress, E.Employee_ID    Having (Max(Convert(int,SubString(D.TaxYear,0,5))) >= Convert(int,SubString(@taxYear,0,5)) - 1)) as T1 -- Changing <> into =    inner join Payroll_EmployeeTaxOverDeduction as D on D.EmployeeID = T1.Employee_ID    Inner join Payroll_SalaryHead as H on H.SalaryHead_ID = D.SalaryHeadID    inner join Payroll_Employee as E on E.Employee_ID = T1.Employee_ID    Left Outer join Payroll_TaxYearEndRun as TR on TR.TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate())))     and TR.ProcessNo = 5 and TR.ClearNotification =0 -- Changing inner Join to Left Outer Join    -- This is the manage tax Agreement Tax Year End run Process    Where D.Enabled = 1    and D.EndDate != '31 Dec 9999'    and (D.EndDate < DATEFROMPARTS(Convert(int,SubString(@taxYear,0,5)), 3, 1)    or D.EndDate < GetDate())     SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTaxOverDeductionNotify_Ver2_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE dbo.Payroll_TaxYearEnd_EmployeeTaxOverDeductionNotify_Ver2_sp  AS  BEGIN    SET NOCOUNT ON;      select D.TaxOverDeduction_ID, E.EmpCode,E.FirstName ,E.Surname,H.SalaryHeadName as SalaryHeadDescription,E.EmailAddress, D.Amount,D.TaxYear,D.StartDate,D.EndDate, D.PeriodNo  from     (select E.Employee_ID ,E.EmpCode as EmployeeCode ,E.FirstName as Name, E.Surname as Surname,     Max(D.EndDate) as Expiry, E.EmailAddress, Max(Convert(int,SubString(D.TaxYear,0,5))) as TaxYearStart from Payroll_EmployeeTaxOverDeduction as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmployeeID    where D.Enabled = 1    Group By E.EmpCode,E.FirstName,E.Surname, E.EmailAddress, E.Employee_ID    Having (Max(Convert(int,SubString(D.TaxYear,0,5))) = DatePart(Year,GetDate()))) as T1 -- Changing <> into =    inner join Payroll_EmployeeTaxOverDeduction as D on Convert(int,SubString(D.TaxYear,0,5)) = (convert(int,DatePart(Year,GetDate()))) and D.EmployeeID = T1.Employee_ID    Inner join Payroll_SalaryHead as H on H.SalaryHead_ID = D.SalaryHeadID    inner join Payroll_Employee as E on E.Employee_ID = T1.Employee_ID    Left Outer join Payroll_TaxYearEndRun as TR on TR.TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate())))     and TR.ProcessNo = 6 and TR.ClearNotification =0 -- Changing inner Join to Left Outer Join    -- This is the manage tax Agreement Tax Year End run Process    Where D.Enabled = 1         SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTaxOverDeductionRpt_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_TaxYearEnd_EmployeeTaxOverDeductionRpt_sp]    AS  BEGIN    SET NOCOUNT ON;      select D.TaxOverDeduction_ID, E.EmpCode,E.FirstName ,E.Surname,H.SalaryHeadName as SalaryHeadDescription,E.EmailAddress, D.Amount,D.TaxYear,D.StartDate,D.EndDate, D.PeriodNo  from     (select E.Employee_ID ,E.EmpCode as EmployeeCode ,E.FirstName as Name, E.Surname as Surname,     Max(D.EndDate) as Expiry, E.EmailAddress, Max(Convert(int,SubString(D.TaxYear,0,5))) as TaxYearStart from Payroll_EmployeeTaxOverDeduction as D    inner join Payroll_Employee as E on E.Employee_ID = D.EmployeeID    where D.Enabled = 1    Group By E.EmpCode,E.FirstName,E.Surname, E.EmailAddress, E.Employee_ID    Having (Max(Convert(int,SubString(D.TaxYear,0,5))) <> DatePart(Year,GetDate()))) as T1    inner join Payroll_EmployeeTaxOverDeduction as D on Convert(int,SubString(D.TaxYear,0,5)) = (convert(int,DatePart(Year,GetDate())) - 1) and D.EmployeeID = T1.Employee_ID    Inner join Payroll_SalaryHead as H on H.SalaryHead_ID = D.SalaryHeadID    inner join Payroll_Employee as E on E.Employee_ID = T1.Employee_ID    Where D.Enabled = 1     SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTerminationsNotify_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeTerminationsNotify_sp]    AS  BEGIN    SET NOCOUNT ON;           select distinct E.EmpCode,E.FirstName,E.Surname,E.IdNo from Payroll_Employee as E    inner join Payroll_Employee as H on H.Employee_ID = E.Employee_ID     inner join Payroll_TaxYearEndRun as TR on TR.TaxYear = Convert(varchar,(convert(int,DatePart(Year,GetDate())) -1))+ '/' + (convert(varchar,DatePart(Year,GetDate()))) and TR.ProcessNo = 3 and TR.ClearNotification =0 -- This is the manage 3. Manage Employee Terminations. Tax Year End run Process    where H.EndDate >=  DateAdd(Year ,-1, DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103)))     and H.EndDate <=  DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))    and E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)     SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_EmployeeTerminationsRpt_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      Create PROCEDURE [dbo].[Payroll_TaxYearEnd_EmployeeTerminationsRpt_sp]    AS  BEGIN    SET NOCOUNT ON;           select E.EmpCode,E.FirstName,E.Surname,E.IdNo from Payroll_Employee as E    inner join Payroll_EmployeeHistory as H on H.EmployeeID = E.Employee_ID     where H.EndDate >=  DateAdd(Year ,-1, DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103)))     and H.EndDate <=  DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))    and E.Employee_ID in (select distinct EmployeeID from Payroll_EmployeePayrollDefinition where Enabled = 1)     SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_ExpireTaxDirectiveInBulk
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_ExpireTaxDirectiveInBulk]   @ClosingTaxYear varchar(10)  AS  BEGIN    SET NOCOUNT ON;      update Payroll_EmployeeTaxDirectives    set ExpiryDate = DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))    where TaxYear = @ClosingTaxYear and ExpiryDate > DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))       SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_ExpireTaxOverDeductionInBulk
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Petrus Jacobs  -- Create date: 08/03/2017  -- =============================================      Create PROCEDURE [dbo].[Payroll_TaxYearEnd_ExpireTaxOverDeductionInBulk]   @ClosingTaxYear varchar(10)  AS  BEGIN    SET NOCOUNT ON;      update Payroll_EmployeeTaxOverDeduction    set EndDate = DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))    where TaxYear = @ClosingTaxYear and EndDate > DateAdd(day,-1,Convert(DateTime,convert(varchar,'01/03/'+ convert(varchar,DatePart(year,GETDATE()),103)),103))       SET NOCOUNT OFF;  END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_GetConst_MedicalSchemeFeeTaxCredits
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Petrus Jacobs  -- Create date: 08 March 2017  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_GetConst_MedicalSchemeFeeTaxCredits]   @TaxYear nvarchar(10)  AS  BEGIN      SET NOCOUNT ON;   select    MedicalScheme_ID,   CapturerID,   ModifierID,   DependantModeID,   DateCaptured,   DateModified,   Enabled,   MedicalSchemeAmount,   MedicalSchemeDesc,   FinancialYear,   TaxYear   from dbo.Const_MedicalSchemeFeeTaxCredits   where TaxYear = @TaxYear           Set NoCount OFF;   END  

