-- ============================================
-- SP: Payroll_TaxYearEnd_GetCostCenterEveryMonth
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Petrus Jacobs  -- Create date: 08 March 2017  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_GetCostCenterEveryMonth]          AS  BEGIN      SET NOCOUNT ON;     select E.Amount, E.PayrollDefinitionID,E.EmployeeID,E.Description,E.MunicipalityID,Period.FinancialYear,   E.CapturedBy,E.CostCenterEveryMonth_ID, Period.PeriodID , Period.TaxYear   from Payroll_CostCenter_EveryMonth as E   inner join Payroll_EmployeeHistory as h on H.EmployeeID = E.EmployeeID   inner join Payroll_Employee as Emp on Emp.Employee_ID = E.EmployeeID   inner join    (select Max(P.PeriodEndDate) as EndDate, Max(P.Period_ID) as PeriodID ,P.CycleID,P.FinancialYear,P.TaxYear from Payroll_CyclePeriodDetails as P   inner join (select distinct CycleID from Payroll_Employee) as T1 on T1.CycleID = P.CycleID   where DateDiff(Day,DateAdd(day, -1, DateAdd(Month,1, Convert(DateTime,  '01/' + Convert(Varchar,DatePart(Month,GetDate()))  + '/' + Convert(Varchar,DatePart(Year,GetDate())),103))), P.PeriodEndDate) <= 31 and    DateDiff(Day,DateAdd(day, -1, DateAdd(Month,1, Convert(DateTime,  '01/' + Convert(Varchar,DatePart(Month,GetDate()))  + '/' + Convert(Varchar,DatePart(Year,GetDate())),103))), P.PeriodEndDate) >= 0 and    P.[Enabled] = 1   Group by P.CycleID, P.FinancialYear, P.TaxYear) as Period on Period.CycleID = Emp.CycleID   left join Payroll_CostCenter as CC on CC.EmployeeID = Emp.Employee_ID and CC.CostCenterEveryMonthID = E.CostCenterEveryMonth_ID and CC.PeriodID = Period.PeriodID   where CC.CostCenter_ID is Null and    E.Amount is not Null and    E.EmployeeID is NOt Null and    E.MunicipalityID is not NULL and    E.PayrollDefinitionID is not null and   1 = 2       Set NoCount OFF;   END

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_GetCostCenterEveryMonth_InsertedData
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Petrus Jacobs  -- Create date: 08 March 2017  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_GetCostCenterEveryMonth_InsertedData]          AS  BEGIN      SET NOCOUNT ON;     select E.Amount, E.Description,Period.TaxYear,Period.EndDate as PeriodEndDate,Emp.EmpCode,Emp.FirstName,Emp.Surname,Emp.IdNo    from Payroll_CostCenter_EveryMonth as E   inner join Payroll_EmployeeHistory as h on H.EmployeeID = E.EmployeeID   inner join Payroll_Employee as Emp on Emp.Employee_ID = E.EmployeeID   inner join    (select Max(P.PeriodEndDate) as EndDate, Max(P.Period_ID) as PeriodID ,P.CycleID,P.FinancialYear,P.TaxYear from Payroll_CyclePeriodDetails as P   inner join (select distinct CycleID from Payroll_Employee) as T1 on T1.CycleID = P.CycleID   where DateDiff(Day,DateAdd(day, -1, DateAdd(Month,1, Convert(DateTime,  '01/' + Convert(Varchar,DatePart(Month,GetDate()))  + '/' + Convert(Varchar,DatePart(Year,GetDate())),103))), P.PeriodEndDate) <= 31 and    DateDiff(Day,DateAdd(day, -1, DateAdd(Month,1, Convert(DateTime,  '01/' + Convert(Varchar,DatePart(Month,GetDate()))  + '/' + Convert(Varchar,DatePart(Year,GetDate())),103))), P.PeriodEndDate) >= 0 and    P.[Enabled] = 1   Group by P.CycleID, P.FinancialYear, P.TaxYear) as Period on Period.CycleID = Emp.CycleID   left join Payroll_CostCenter as CC on CC.EmployeeID = Emp.Employee_ID and CC.CostCenterEveryMonthID = E.CostCenterEveryMonth_ID and CC.PeriodID = Period.PeriodID   where CC.CostCenter_ID is Not Null and    E.Amount is not Null and    E.EmployeeID is NOt Null and    E.MunicipalityID is not NULL and    E.PayrollDefinitionID is not null       Set NoCount OFF;   END  

GO

-- ============================================
-- SP: Payroll_TaxYearEnd_GetExceptionReport
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_GetExceptionReport]  AS  BEGIN      DECLARE @taxYear CHAR(9) = (SELECT KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear')   SELECT [TaxYearEndRunException_ID]            ,[tyee].[Employee_ID]            ,[Exception]            ,[IgnoreException]            ,[IgnoreExceptionReason]            ,[FirstName]            ,[Surname]            ,[EmpCode]            ,[IdNo]            ,[TaxYearEndProcessDescr]      FROM [Payroll_TaxYearEndRun] AS [tyer]           INNER JOIN [Payroll_TaxYearEnd_Exception] AS [tyee] ON [tyer].[TaxYearEndRun_ID] = [tyee].[TaxYearEndRun_ID]      LEFT JOIN [Payroll_Employee] AS [pe] ON [tyee].[Employee_ID] = [pe].[Employee_ID]      WHERE( [tyer].[TaxYear] = @taxYear             OR [tyer].[TaxYear] = 'Daily'           )           AND [tyee].[IgnoreException] = 0;  END;

GO

