-- ============================================
-- SP: Payroll_TaxYearEnd_Process1
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Petrus Jacobs  -- Create date: 08 March 2017  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearEnd_Process1]   @OldTaxYear nvarchar(10),   @NewTaxYear nvarchar(10)    AS  BEGIN      SET NOCOUNT ON;   Declare @ErrorMessage Varchar(400)     set @ErrorMessage = ''     BEGIN TRY    IF NOT EXISTS (SELECT top 1 MedicalScheme_ID from dbo.Const_MedicalSchemeFeeTaxCredits where TaxYear = @NewTaxYear)    BEGIN     insert into dbo.Const_MedicalSchemeFeeTaxCredits(     CapturerID,     ModifierID,     DependantModeID,     DateCaptured,     DateModified,     Enabled,     MedicalSchemeAmount,     MedicalSchemeDesc,     FinancialYear,     TaxYear)       (select       CapturerID,      ModifierID,      DependantModeID,      DateCaptured,      DateModified,      Enabled,      MedicalSchemeAmount,      MedicalSchemeDesc,      @NewTaxYear,      @NewTaxYear from dbo.Const_MedicalSchemeFeeTaxCredits      where TaxYear = @OldTaxYear      )    end      IF NOT EXISTS (SELECT top 1 TaxRebates_ID from dbo.Const_TaxRebates where FinancialYear = @NewTaxYear)    BEGIN     insert into dbo.Const_TaxRebates(       MinAge,     MaxAge,     CapturerID,     ModifierID,     DateCaptured,     DateModified,     Enabled,     TaxRebatesAmount,     TaxRebatesDesc,     FinancialYear)       (select         MinAge,        MaxAge,        CapturerID,        ModifierID,        DateCaptured,        DateModified,        Enabled,        TaxRebatesAmount,        TaxRebatesDesc,        @NewTaxYear from dbo.Const_TaxRebates        where FinancialYear = @OldTaxYear      )    end      IF NOT EXISTS (SELECT top 1 StatutoryRates_ID from dbo.Const_StatutoryRates where FinancialYear = @NewTaxYear)    BEGIN     insert into dbo.Const_StatutoryRates(       RatesOfTaxPercentage,     CapturerID,     ModifierID,     DateCaptured,     DateModified,     Enabled,     MinSlotAmount,     MaxSlotAmount,     RatesOfTaxFixedAmount,     RatesOfTaxAboveAmount,     TaxableIncomeSlot,     FinancialYear,     TaxIncomeDesc,     IsCopied)     (select         RatesOfTaxPercentage,        CapturerID,        ModifierID,        DateCaptured,        DateModified,        Enabled,        MinSlotAmount,        MaxSlotAmount,        RatesOfTaxFixedAmount,        RatesOfTaxAboveAmount,        TaxableIncomeSlot,        @NewTaxYear,        TaxIncomeDesc,        1         from dbo.Const_StatutoryRates        where FinancialYear = @OldTaxYear      )    end      IF NOT EXISTS (SELECT top 1 TaxThresholds_ID from dbo.Const_TaxThresholds where FinancialYear = @NewTaxYear)    BEGIN     insert into dbo.Const_TaxThresholds(        TaxThresholdsDesc,      MinAge,      MaxAge,      TaxThresholdsAmount,      CapturerID,      DateCaptured,      [Enabled],        FinancialYear)       (select       TaxThresholdsDesc,      MinAge,      MaxAge,      TaxThresholdsAmount,      CapturerID,      getdate(),      [Enabled],      @NewTaxYear       from dbo.Const_TaxThresholds      where FinancialYear = @OldTaxYear     )    end     END TRY   BEGIN CATCH    set @ErrorMessage = ERROR_MESSAGE()   END CATCH;     select @ErrorMessage     Set NoCount OFF;   END

GO

