-- ============================================
-- SP: Payroll_TaxYearEndProcess_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PNACHAL   -- Create date:  22/11/2013  -- Description:   -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearEndProcess_sp]     AS  BEGIN   DECLARE @FINYEAR NVARCHAR(50)   DECLARE @NEXTFINYEAR NVARCHAR(50)   DECLARE @TaxEndMonth INT   SELECT  @FINYEAR=KeyValue FROM AAAA_ConfigSettings WHERE KeyName ='ActiveFinYear'   SELECT  @TaxEndMonth=KeyValue FROM AAAA_ConfigSettings WHERE KeyName ='TaxFinYearEndMonth'   SET @NEXTFINYEAR = (SELECT dbo.GetNextYearFinanceYearBySelectedFinancialYear(@FINYEAR))   SET @TaxEndMonth = @TaxEndMonth +1    IF(@TaxEndMonth = MONTH(getdate() +1))   BEGIN      /* TAX REBATES ENTRY*/    INSERT INTO dbo.Const_TaxRebates      (    TaxRebatesDesc , MinAge , MaxAge , TaxRebatesAmount , FinancialYear , [Enabled] ,     DateCaptured , CapturerID                    )   (     SELECT TaxRebatesDesc , MinAge , MaxAge , TaxRebatesAmount , @NEXTFINYEAR , 1 , GETDATE() , 1    FROM dbo.Const_TaxRebates    WHERE FinancialYear = @FINYEAR      )   /* END*/   /* SATUTARY RATES ENTRY*/     INSERT INTO dbo.Const_StatutoryRates      (     TaxableIncomeSlot , MinSlotAmount , MaxSlotAmount , RatesOfTaxFixedAmount , RatesOfTaxPercentage ,     RatesOfTaxAboveAmount , FinancialYear , [Enabled] , DateCaptured , CapturerID      )   (    SELECT TaxableIncomeSlot , MinSlotAmount , MaxSlotAmount , RatesOfTaxFixedAmount , RatesOfTaxPercentage ,     RatesOfTaxAboveAmount , @NEXTFINYEAR , 1 , GETDATE() , 1    FROM dbo.Const_StatutoryRates    WHERE FinancialYear = @FINYEAR      )   /* END*/   END  END     

GO

-- ============================================
-- SP: Payroll_TaxYearWiseDependant_sp
-- Schema: dbo
-- ============================================
-- =====================================================================================================================  -- Author:  MEHUL PNACHLA  -- Create date: 13 12 2013  -- Description: <Description,,>  -- Payroll_TaxYearWiseDependant_sp  16  -- 2015-01-20 James Roodt: Removed date type manipulation as it didn't work and was needed. i.e. "CONVERT(NVARCHAR(12), DependedJoinDate, 103)"  becomes "DependedJoinDate"  -- 2015-08-14 Ravindra Jijotia: Updated logic for calculation of month Wise Dependant count.  -- 2016-08-19:Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return Dependant result WHERE IsAdultDependant =1 or IsChildDependant=1  -- =====================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_TaxYearWiseDependant_sp]    @EmployeeID int  AS  BEGIN   SET NOCOUNT ON;        DECLARE @TaxYearStartMonth INT   SELECT @TaxYearStartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxFinYearEndMonth'   SET @TaxYearStartMonth = @TaxYearStartMonth + 1     DECLARE @FYear NVARCHAR(10)   SELECT @FYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'ActivePayrollYear'     DECLARE @Year1 INT, @Year2 INT   SELECT TOP 1 @Year1 = Value FROM dbo.Split_fxn(@FYear,'/')      DECLARE @Month int   DECLARE @Year INT     DECLARE @OgFirstDate DATETIME   DECLARE @FirstDate DATETIME   DECLARE @LastDate DATETIME     DECLARE @MonthName NVARCHAR(10)     set @Month = @TaxYearStartMonth   set @Year = @Year1   select @FirstDate = DATEADD(month,@Month-1,DATEADD(year,@Year-1900,0))   select @LastDate = DATEADD(day,-1,DATEADD(month,@Month,DATEADD(year,@Year-1900,0)))   SET @OgFirstDate = @FirstDate     DECLARE @tbl TABLE   (    Month_Name NVARCHAR(10),    DependantCnt INT   )     DECLARE @cnt INT = 0   DECLARE @DependantCnt INT   --DECLARE @DependantCnt1 INT      --Select @DependantCnt1 = COUNT(1) FROM dbo.Payroll_EmployeeDependantDetails    ----WHERE CONVERT(NVARCHAR(12), DependedJoinDate, 103) < CONVERT(NVARCHAR(12), @FirstDate, 103) AND Enable = 1   ----WHERE DependedJoinDate < @FirstDate AND Enable = 1   ----AND EmployeeID = @EmployeeID   --WHERE Enable = 1 AND EmployeeID = @EmployeeID      WHILE(@FirstDate < @LastDate AND @cnt < 12)    BEGIN    --SET @MonthName = DATENAME(month, @FirstDate)    SET @MonthName = DATENAME(month, @LastDate)        --Select @DependantCnt = COUNT(1) FROM dbo.Payroll_EmployeeDependantDetails WHERE     --DependedJoinDate BETWEEN @OgFirstDate AND @LastDate AND EmployeeID = @EmployeeID AND Enable = 1 AND DependantMode <> 4        Select @DependantCnt = COUNT(1) FROM dbo.Payroll_PersonRelationshipType WHERE       MedAidJoiningDate < @LastDate AND EmployeeID = @EmployeeID AND Enabled = 1    AND (MedAidTerminateDate > @FirstDate OR MedAidTerminateDate is null)    AND (IsAdultDependant=1 or IsChildDependant=1)        --SET @DependantCnt = (@DependantCnt + @DependantCnt1)        INSERT @tbl ( Month_Name , DependantCnt )    VALUES  ( @MonthName, @DependantCnt )         --SET @FirstDate = DATEADD(MONTH,1,@FirstDate)    --SET @LastDate =  DATEADD(MONTH,1,@LastDate)    --SET @LastDate = DATEADD(s,-1,DATEADD(mm, DATEDIFF(m,0,@LastDate) + 1,0))      SET @Month = @Month + 1        IF (@Month = 13)    BEGIN     SET @Month = 1     SET @Year = @Year + 1    END         select @FirstDate = DATEADD(month, @Month-1, DATEADD(year, @Year-1900, 0))    select @LastDate = DATEADD(day, -1, DATEADD(month, @Month, DATEADD(year, @Year-1900, 0)))       SET @cnt = @cnt + 1   END       SELECT Month_Name, DependantCnt FROM @tbl  END  

GO

-- ============================================
-- SP: Payroll_TemplateDetails_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 08 JULY 2013  -- Description:    -- CALLS :  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_TemplateDetails_sp]    @TemplateID INT,    @PayrollDefinationID INT,   @Mode TINYINT   AS  BEGIN   IF(@Mode =1) --- 'INSERT'   BEGIN     INSERT INTO [Payroll_TemplateDetails]          ([TemplateID]          ,[PayrollDefinationID])       VALUES          (@TemplateID          ,@PayrollDefinationID)                          SELECT @PayrollDefinationID AS PayrollDefinationID   END    ELSE IF(@Mode =2) --- 'DELETE'   BEGIN     Delete from [Payroll_TemplateDetails]        WHERE PayrollDefinationID = @PayrollDefinationID;                         END      SELECT @PayrollDefinationID AS PayrollDefinationID  END  

GO

-- ============================================
-- SP: Payroll_TemplateDetailsList_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author: MEHUL PANCHAL    -- Create date:  26 JUL 2013    -- Description:  GET PAYROLL TEMPLATE MASTER DETAILS     -- CALLS : Payroll_TemplateDetailsList_sp 1,0    -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_TemplateDetailsList_sp]      @TemplateId INT ,      @Group INT  AS       BEGIN            IF ( @Group > 0 )               BEGIN                    SELECT DISTINCT                          PAY_IRP.TransactionTypeID AS Template_ID ,                          PAY_IRP.TransactionTypeID ,                          PAY_DEF.PayrollDefination_ID                  FROM    Payroll_PayrollDefination PAY_DEF                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_DEF.PayrollSalaryHeadID                          INNER JOIN dbo.Payroll_IRP5Code PAY_IRP ON PAY_SAL.IRP5CodeId = PAY_IRP.IRP5Code_ID                          INNER JOIN Payroll_DefinitionGroup PAY_PRO_GROUP ON PAY_PRO_GROUP.PayrollDefinitionGroup_ID = PAY_DEF.PayrollDefinitionGroupID                  WHERE   PAY_PRO_GROUP.PayrollDefinitionGroup_ID = @TemplateId                          AND PAY_DEF.Enabled = 1                          AND PAY_IRP.Enabled = 1                          AND PAY_PRO_GROUP.Enabled = 1                          AND PAY_SAL.Enabled = 1              END             ELSE               BEGIN                    SELECT DISTINCT                          PAY_IRP.TransactionTypeID AS Template_ID ,                          PAY_IRP.TransactionTypeID ,                          PAY_EMP_DEF.PayrollSalaryHeadID AS PayrollDefination_ID                  FROM    Payroll_Employee PAY_EMP                          INNER JOIN Payroll_EmployeePayrollDefinition PAY_EMP_DEF ON PAY_EMP_DEF.EmployeeID = PAY_EMP.Employee_ID                          INNER JOIN Payroll_SalaryHead PAY_SAL ON PAY_SAL.SalaryHead_ID = PAY_EMP_DEF.PayrollSalaryHeadID                          INNER JOIN dbo.Payroll_IRP5Code PAY_IRP ON PAY_SAL.IRP5CodeId = PAY_IRP.IRP5Code_ID                  WHERE   PAY_EMP.Employee_ID = @TemplateId                          AND PAY_EMP_DEF.Enabled = 1                          AND PAY_IRP.Enabled = 1                          AND PAY_SAL.Enabled = 1              END        END    

GO

-- ============================================
-- SP: Payroll_TemplateList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: <Create Date,,>  -- Description: <Description,,>  -- CALLS : [Payroll_TemplateList_sp]  -- =============================================  CREATE PROCEDURE  [dbo].[Payroll_TemplateList_sp]      AS  BEGIN    SELECT       PAY_TEMP.TemplateName     ,CONST_CYC.CycleDesc     ,PAY_MUN.MunicipalityName     ,CASE WHEN  PAY_TEMP.Enabled =1      THEN        'ACTIVE'      ELSE        'IN ACTIVE'      END AS STATUS      ,PAY_TEMP.Template_Id              ,IsDefault     FROM Payroll_Template PAY_TEMP    LEFT OUTER JOIN Const_Cycle CONST_CYC        ON CONST_CYC.Cycle_ID = PAY_TEMP.CycleTypeID      LEFT OUTER JOIN Payroll_Municipality PAY_MUN       ON PAY_MUN.Municipality_ID= PAY_TEMP.MunicipalityID    END     

GO

-- ============================================
-- SP: Payroll_TerminatedEmployeeLeaveBalance
-- Schema: dbo
-- ============================================
  /*   Author  : RICHA MILLS   Create date : 18/11/2018   Description : Get Leave Balances for terminated Employees   20211027 - Ruan - WI31868  */  CREATE procedure [dbo].[Payroll_TerminatedEmployeeLeaveBalance]     @EmployeeID int,   @TermDateFrom datetime,   @TermDateTo datetime,   @DepartmentId int,  @DivisionId int  as    begin     Select EmployeeLeaveBalanceID, Employee_Id,emp.Firstname,Surname,LeaveTypeId,lt.LeaveType, TotalLeaveDays, IsNULL(IsLeaveCertified,0)IsLeaveCertified,   CertifiedById,IsNULL(IsLeaveApproved,0)IsLeaveApproved,ApprovedById,IsNull(certUser.UserName,'') CertifiedBy,IsNull(approveUser.UserName,'') ApprovedBy, emp.EndDate TerminationDate from     (select EmployeeId,TerminationStartDate from payroll_EmployeeTermination where TerminationStartDate >= @TermDateFrom and TerminationStartDate <= @TermDateTo) empterm     join payroll_EmployeeLeaveBalance empb on empb.EmployeeID = empterm.EmployeeID     join payroll_employee emp on emp.Employee_Id = empb.EmployeeId     join Const_LeaveType lt on lt.LeaveType_Id = empb.LeaveTypeId      left join Payroll_Position pos on pos.EmployeeId = emp.Employee_id and pos.Position_ID = emp.PositionID     left join User_UserDetail certUser on certUser.User_ID = empb.CertifiedById      left join User_UserDetail approveUser on approveUser.User_ID = empb.ApprovedById      where lt.Encash = 1       and (pos.DepartmentID = @DepartmentId OR IsNULL(@DepartmentId,0) = 0)      and (pos.DivisionID = @DivisionId OR IsNULL(@DivisionId,0) = 0)       and (emp.Employee_ID = @EmployeeId OR IsNULL(@EmployeeId,0) = 0)      end

GO

-- ============================================
-- SP: Payroll_TerminationEmployeeAdHocPayrollDefinitions_sp
-- Schema: dbo
-- ============================================
-- ======================================================================================================  -- Author: Artur Anzorge  -- Create date: 19/08/2019    -- Get Payroll Definitions for terminated employee  -- 15 Mar 2021 : Ivan Myroshnychenko : 49340 Add filtering result with 'CyclePeriodAdhocPayrollDefinition_ID IS NOT NULL' for remove from result deleted row.  -- ======================================================================================================  CREATE procedure [dbo].[Payroll_TerminationEmployeeAdHocPayrollDefinitions_sp] @PeriodId int, @EmployeeId int, @TerminationId int, @Type int = 1  as    begin     set nocount on;    declare @ActiveTaxYear nvarchar(200) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'TaxYear'))      declare @results table (      [EmployeePayrollDefinition_ID] int,    [TransactionType] nvarchar(50),    [SalaryHeadID] INT,    [SalaryHeadTitle] nvarchar(max),    [PayrollSalaryHeadName] nvarchar(max),    [FunctionNumber] nvarchar(50),    [Percentage] decimal(18, 2),    [TransactionTypeID] int,    [Amount] decimal(18, 2),    [Pensionable] nvarchar(10),    [Taxable] nvarchar(10),    [TaxablePercentage] decimal(18, 2),    [IRP5Code] nvarchar(10),    [PeriodID] int,    [Flag] nvarchar(10),    [IRP5CodeDesc] nvarchar(max),    [IRP5CodeId] int   )     if (@Type = 1)   begin      declare @CycleID int = (select [CycleID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle],  [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc], [IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], isnull([Value], 0), (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Trial', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         join [Payroll_EmployeeTrialPayslipSimulation] as [TP] with(nolock) on [TP].[SalaryHeadID] = [SH].[SalaryHead_ID] AND [TP].[EmployeeID]= @EmployeeId        where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID)      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle],  [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc], [IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], 0, (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Trial', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1          where ([EPD].[Enabled] = 1 and [EPD].[EmployeeID] = @EmployeeID and not [EmployeePayrollDefinition_ID] in (          select [EmployeePayrollDefinition_ID] from @results            )        )     end   else   begin      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle],  [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc], [IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], isnull([Amount], 0), (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), isnull([EPDF].[PeriodID], @PeriodID), 'Final', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinitionFinal] as [EPDF] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPDF].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [EPDF].[PeriodID] = @PeriodID         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         left outer join [Payroll_EmployeePayslip] as [TP] with(nolock) on [TP].[PayrollDefinationID] = [EPDF].[EmployeePayrollDefinition_ID] and [TP].[PeriodID] = @PeriodID        where ([EPDF].[Enabled] = 1 and [EPDF].[EmployeeID] = @EmployeeID and [TaxSavePurpose] = 0)      insert into @results([EmployeePayrollDefinition_ID], [TransactionType], [SalaryHeadID], [PayrollSalaryHeadName], [SalaryHeadTitle], [FunctionNumber], [Percentage], [TransactionTypeID], [Amount], [Pensionable], [Taxable], [TaxablePercentage], [IRP5Code], [PeriodID], [Flag], [IRP5CodeDesc],[IRP5CodeId])       select [EmployeePayrollDefinition_ID], [TransactionTypeDesc], [SH].[SalaryHead_ID], cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc], [SalaryHeadTitle], [ScoaShortDesc], [Percentage], [TransactionType_ID], 0, (case when [SH].[IsRFI] = 1 then 'Yes' else 'No' end), (case when [TaxableID] = 1 then 'Yes' else 'No' end), [TatxablePercentage], isnull([IRP5CertCode], [IRP5Code]), @PeriodID, 'Final', [IRP5].[IRP5CodeDesc], [IRP5].[IRP5Code_ID]        from [Payroll_EmployeePayrollDefinitionFinal] as [EPDF] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPDF].[PayrollSalaryHeadID] and [SH].[Enabled] = 1 and [EPDF].[PeriodID] = @PeriodID         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         left outer join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1         left outer join [Const_SCOA_Structure] as [SCOA] with(nolock) on [ScoaID] = [SuspenseScoaItemID] and [SCOA].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1        where ([EPDF].[Enabled] = 1 and [EPDF].[EmployeeID] = @EmployeeID and not [EmployeePayrollDefinition_ID] in (          select [EmployeePayrollDefinition_ID] from @results         )        )     end     select [EmployeePayrollDefinition_ID], [TransactionType] as TransactionTypeDesc, res.SalaryHeadID, res.[SalaryHeadTitle], res.[PayrollSalaryHeadName], res.[IRP5CodeId], res.[IRP5CodeDesc], res.[SalaryHeadTitle] as SalaryHeadName, [TransactionTypeID] as TransactionType_ID, sum(cast(isnull([res].[Amount], 0) as decimal(18,2))) as [Amount], res.[IRP5Code], cast(isnull(tab.CyclePeriodAdhocPayrollDefinition_ID, 0) as int) as CyclePeriodAdhocPayrollDefinition_ID      from @results as res left join     (      SELECT [AHSH].CyclePeriodAdhocPayrollDefinition_ID,        [AHSH].[SalaryHeadID],        [SH].[SalaryHeadName],        [SH].[SalaryHeadTitle],        [SH].[IRP5CodeId],        [IRP5].[IRP5CodeDesc],        cast(isnull([IRP5CertCode],        [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc] as [PayrollSalaryHeadName],        [TransactionType_ID],        [TransactionTypeDesc],        cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) as [IRP5Code],       [AHSH].[PeriodID]         FROM Payroll_CyclePeriodAdhocSalaryHead [AHSH] with(nolock)         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [AHSH].[SalaryHeadID] and [SH].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1         where [AHSH].[PeriodID] = @PeriodID and [AHSH].[Enabled] = 1      ) as tab on tab.PeriodID = res.PeriodID and tab.SalaryHeadID = res.SalaryHeadID      WHERE tab.CyclePeriodAdhocPayrollDefinition_ID IS NOT NULL   group by [EmployeePayrollDefinition_ID], [TransactionType], res.SalaryHeadID,res.[SalaryHeadTitle], res.[PayrollSalaryHeadName], res.[IRP5CodeId], res.[IRP5CodeDesc], [TransactionTypeID], res.[IRP5Code], tab.CyclePeriodAdhocPayrollDefinition_ID      order by [IRP5Code]     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TerminationEmployeePayrollDefinitions_sp
-- Schema: dbo
-- ============================================
  -- ======================================================================================================  -- Author: MEHUL PANCHAL    -- Create date: 28 JAN 2014    -- Description: GET PAYROLL LIST     -- Execute [Payroll_EmployeePayrollDefinationlst_sp] 00000015    -- 2015-12-22 : Suri Kandukuri : TP29886 Added Enabled Condition for Salary Head.  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-04-08 TP34966 James Roodt: Added ActiveTaxYear to where clause  -- 2016-06-14 TP37484 Seipei Mathole: Changed Inner join to Left join on CSS.ScoaID = PAY_DEF.SCOAItemID   -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- Phuti Chokoe TP46878 - Changed financial year to use new tax year column  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- 2016-12-07 TP48989 - remove Commission and VAT on Commission  -- Update date : 12/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings  -- Update date : 08/03/2018 - Updated checks to verify Payslip values if a Trial / Final has been executed  -- Update date : 28/03/2018 - Updated checks to include Definitions not included in Trial / Final mappings  -- Update date : 09/10/2019 - Artur Anzorge => Changes to get [PayrollSalaryHeadID]  -- ======================================================================================================  CREATE procedure [Payroll_TerminationEmployeePayrollDefinitions_sp] @EmployeeID int  as    begin     set nocount on;     SELECT [AHSH].[EmployeePayrollDefinition_ID],    [AHSH].[PayrollSalaryHeadID],    [SH].[SalaryHeadName],    [SH].[SalaryHeadTitle],    [SH].[IRP5CodeId],    [IRP5].[IRP5CodeDesc],    cast(isnull([IRP5CertCode],    [IRP5Code]) as nvarchar) + ' - ' + [IRP5].[IRP5CodeDesc] as [PayrollSalaryHeadName],    [TransactionType_ID],    [TransactionTypeDesc],    cast(isnull([IRP5CertCode], [IRP5Code]) as nvarchar) as [IRP5Code]     FROM Payroll_EmployeePayrollDefinition [AHSH] with(nolock)     join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = ahsh.PayrollSalaryHeadID and [SH].[Enabled] = 1     join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1     join [Const_TransactionType] as [CTT] with(nolock) on [TransactionType_ID] = [IRP5].[TransactionTypeID] and [CTT].[Enabled] = 1     WHERE EmployeeID = @EmployeeID AND [AHSH].[Enabled] = 1     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TestLeaveAccruals
-- Schema: dbo
-- ============================================
  -- =================================================================================================  -- Author:  <Richa Mills>  -- Create date: <2018/12/03>  -- Description: <Leave Accruals - This SP was added purely to test the leave accruals>  -- =================================================================================================    /*   Modiri   2019/07/30   #91463 Accumulatation of leave tool to indicate the days as setup on the leave type.  */      CREATE PROCEDURE [dbo].[Payroll_TestLeaveAccruals]   @EmployeeID INT    AS  BEGIN   Select Leavetype.LeaveTypeDesc,adj.LeaveAdjustmentType, [Value] as NumberOfDaysRequested,LeaveTransactions.StartDate,LeaveTransactions.EndDate,LeaveTransactions.DateCaptured    from    (select * from payroll_employeeleavetransactions where employeeid = @EmployeeID)LeaveTransactions       join Const_LeaveType leavetype on leaveType.LeaveType_ID = LeaveTransactions.LeaveTypeId       join Const_LeaveAdjustmentType_sys adj on adj.LeaveAdjustmentType_ID = LeaveTransactions.LeaveAdjustmentTypeID       join Const_LeaveStatus_sys stat on stat.Status_ID = LeaveTransactions.LeaveStatusID    END

GO

-- ============================================
-- SP: Payroll_ThirdParty_Invoice_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 16 June 2014  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_ThirdParty_Invoice_sp]      @VendorID INT ,      @PeriodID INT  AS       BEGIN             DECLARE @StartDate VARCHAR(50) ,              @EndDate VARCHAR(50) ,              @CycleType VARCHAR(50)          SELECT  @StartDate = CONVERT(VARCHAR(50), PeriodStartDate, 103), @EndDate = CONVERT(VARCHAR(50), PeriodEndDate, 103), @CycleType = CycleDesc          FROM    dbo.Payroll_CyclePeriodDetails AS P_C                  INNER JOIN dbo.Const_Cycle AS C_C ON P_C.CycleID = C_C.Cycle_ID          WHERE   Period_ID = @PeriodID             SELECT  dbo.BufferString_fxn(CONVERT(VARCHAR, ( INV.Invoice_ID )), 8, '0') AS InvoiceID, EMP.Employee_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( EMP.Employee_ID )), 8, '0') AS EmployeeNo, dbo.BufferString_fxn(CONVERT(VARCHAR, ( VEN.Vendor_ID )), 8, '0') AS VendorID, EMP.FirstName + ' ' + EMP.Surname AS EmployeeName, INVD.ItemDescription, SUM(INVD.EmployeeAmount) AS EmployeeAmount, SUM(INVD.EmployerAmount) AS EmployerAmount, INV.VendorInvoiceNumber, CONVERT(NVARCHAR(12), INV.InvoiceDate, 103) AS InvoiceDate, VEN.VendorName, INVD.ReferenceNo, INV.Invoice_ID, @StartDate AS FromDate, @EndDate AS ToDate, @CycleType AS CycleType          FROM    SCM_Invoice AS INV                  INNER JOIN dbo.SCM_Payroll_InvoiceDetails AS INVD ON INV.Invoice_ID = INVD.InvoiceID                  INNER JOIN Payroll_Employee AS EMP ON INVD.EmployeeID = EMP.Employee_ID                  INNER JOIN Cons_Vendor AS VEN ON VEN.Vendor_ID = INV.VendorCreditorID          WHERE   ( VEN.Vendor_ID = @VendorID                    OR @VendorID = 0                  )                  AND ( INV.PayrollPeriodID = @PeriodID )          GROUP BY INV.Invoice_ID, EMP.Employee_ID, VEN.Vendor_ID, INV.InvoiceDate, INVD.ItemDescription, EMP.FirstName, EMP.Surname, VEN.VendorName, INV.VendorInvoiceNumber, INVD.ReferenceNo      END  

GO

-- ============================================
-- SP: Payroll_ThridPartyScheduleRpt_sp
-- Schema: dbo
-- ============================================
   -- 2016-08-19 : Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return Dependant Count result WHERE IsAdultDependant =1 or IsChildDependant=1  -- 2017-08-01 : Richa Mills - Fixed stored procedure to cater for "order by" as per Template TP#51378  -- 2017-03-17 : Richa Mills - Fix a few bugs on the report TP69669  -- 2025-01-07 : Richa M  - Add Id Number to the report    --Payroll_ThridPartyScheduleRpt_sp 1,'2024/2025',3,0,'TestNew'       CREATE procedure [dbo].[Payroll_ThridPartyScheduleRpt_sp]  @PayrollCycleId int,  @TaxYear nvarchar(50),  @CalendarMonth INT,  @CreditorFilterID INT,  @TemplateName nvarchar(2000)      as  BEGIN  DECLARE @TemplateID INT = (SELECT Top 1 RptThirdPartyScheduleTemplate_ID FROM Payroll_RptThirdPartySchedule_Template WHERE TemplateName = @TemplateName);  DECLARE @SqlOrderBy NVARCHAR(2000), @SqlStatement NVARCHAR(MAX);    IF (ISNULL(@TemplateID, 0) <> 0)  BEGIN     SET @SqlOrderBy =    (     SELECT      s.[SQLInjection] + ', ' AS 'data()'     FROM      Payroll_RptThirdPartySchedule_LinkTableTemplateSortSelection lt     INNER JOIN      Payroll_RptThirdPartySchedule_SortSelection s ON lt.[SortSelectionID] = s.[SortSelection_ID]     WHERE      lt.[RptThirdPartyScheduleTemplateID] = @TemplateID     ORDER BY      lt.[SortSequence]     FOR XML PATH('')    )         SET @SqlOrderBy = (SELECT LEFT(@SqlOrderBy, LEN(@SqlOrderBy) - 1));  END  ELSE  BEGIN   SET @SqlOrderBy = 'VendorID, Employee_ID';  END;    SET @SqlStatement = '  ;WITH PeriodDetails  AS  (   SELECT    [Period_ID],    CAST([PeriodStartDate] AS DATE) AS [PeriodStartDate],    CAST([PeriodEndDate] AS DATE) AS [PeriodEndDate],    c.[CycleDesc]   FROM    Payroll_CyclePeriodDetails cpd   INNER JOIN    Const_Cycle c ON cpd.[CycleID] = c.[Cycle_ID]   WHERE    [TaxYear] = ''' + @TaxYear + '''   AND DATEPART(MONTH, [PeriodStartDate]) = ' + CAST(@CalendarMonth AS VARCHAR) + '   AND (' + CAST(@PayrollCycleId AS VARCHAR) + ' = 0 OR [CycleID] = ' + CAST(@PayrollCycleId AS VARCHAR) + ')  )    SELECT   a.*,   b.[FundName] AS [plans]  FROM   (    SELECT     id.[PeriondID],     e.[Employee_ID],     dbo.BufferString_fxn(CONVERT(VARCHAR, (e.[Employee_ID])), 8, ''0'') AS [EmpNo],     ISNULL(e.[EmpCode], '''') AS [EmpCode],     e.[Initials],     CONCAT(e.[FirstName], '' '', e.[Surname]) AS [Name],     CONVERT(NVARCHAR(20), e.[DateOfBirth], 106) AS [BirthDate],     CONVERT(NVARCHAR(20), e.[JoiningDate], 106) AS [EngageDate],     g.[GenderDesc] AS [Sex],     e.[FixedSalary] AS [Salary],     SUM(0) AS [FactorAmnt],     id.[ReferenceNo] AS [ReferenceCode],     e.[DateOfBirth],     e.[IdNo],     e.[JoiningDate],     ISNULL(aa.[NumberofDependants], 0) AS [dependants],     SUM(id.[EmployerAmount]) AS [EmployerNormalAmount],     SUM(0) AS [Employeroverunder],     SUM(id.[EmployerAmount] + 0) AS [EmployerTotal],     '''' AS [notUsed2],     SUM(id.[EmployeeAmount]) AS [MemberNormalAmount],     SUM(0) AS [Memberoverunder],     SUM(id.[EmployeeAmount] + 0) AS [MemberTotal],     SUM(id.[CommissionAmount]) AS [Commission],     SUM(id.[EmployeeAmount] - id.[CommissionAmount]) AS [TotalPayment],     '''' AS [notused3],     SUM(id.[EmployeeAmount] + id.[EmployerAmount]) AS [EmployerplusMember],     CONVERT(NVARCHAR(20), pd.[PeriodEndDate], 103) AS [PeriodEndDate],     CONVERT(NVARCHAR(20), pd.[PeriodStartDate], 103) AS [PeriodStartDate],     pd.[CycleDesc],     v.[VendorName],     v.[Vendor_ID] AS [VendorID]    FROM     PeriodDetails pd    INNER JOIN     SCM_Payroll_InvoiceDetails id ON pd.[Period_ID] = id.[PeriondID]    INNER JOIN     SCM_Invoice i ON id.[InvoiceID] = i.[Invoice_ID]    INNER JOIN     Cons_Vendor v ON i.[VendorCreditorID] = v.[Vendor_ID]    INNER JOIN     Payroll_Employee e ON id.[EmployeeID] = e.[Employee_ID]    INNER JOIN     Const_Gender g ON e.[GenderID] = g.[Gender_ID]    OUTER APPLY     (      SELECT       COUNT(prt.[PersonRelationshipType_ID]) AS [NumberofDependants]      FROM       Payroll_PersonRelationshipType prt      WHERE       prt.[EmployeeID] = id.[EmployeeID]      AND prt.[Enabled] = 1      AND (prt.[IsAdultDependant] = 1 OR prt.[IsChildDependant] = 1)     ) aa    GROUP BY     id.[PeriondID], pd.[CycleDesc],     CONVERT(NVARCHAR(20), pd.[PeriodEndDate], 103),     CONVERT(NVARCHAR(20), pd.[PeriodStartDate], 103),     v.[Vendor_ID], v.[VendorName],     e.[Employee_ID], e.[EmpCode], e.[Initials], e.[FirstName], e.[Surname], e.[DateOfBirth], e.[JoiningDate], e.[FixedSalary],     g.[GenderDesc], id.[ReferenceNo],     aa.[NumberofDependants],e.[IdNo]   ) a  LEFT JOIN   (    SELECT     emd.[EmployeeId], ms.[VendorId], ms.[FundName]    FROM     Payroll_EmployeeMedicalAidDetail emd    LEFT JOIN     Const_MedicalAIDScheme ms ON emd.[MedicalAidSchmeID] = ms.[MedicalScheme_ID]    WHERE emd.Enable = 1   UNION       SELECT     ebd.[EmployeeId], bd.[VendorId], bd.[FundName]    FROM     Payroll_EmpBenefitDetail ebd    LEFT JOIN     Payroll_BenefitDetail bd ON ebd.[BenefitSchemeID] = bd.[Benefit_ID]   ) b ON a.[Employee_ID] = b.[EmployeeID] AND a.[VendorID] = b.VendorID  WHERE   (' + CAST(@CreditorFilterID AS VARCHAR) + ' = 0 OR a.[VendorID] = ' + CAST(@CreditorFilterID AS VARCHAR) + ')';    EXECUTE (@SqlStatement + ' ORDER BY ' + @SqlOrderBy);       --SELECT ADDED IN ORDER FOR SSRS DATASET TO POPULATE CORRECT FIELDS. DO NOT DELETE     --   Select '' AS EmployeeId,      --'' AS EmpNo,      --'' AS EmpCode,      --'' AS Initials,      --'' AS Name,      --GetDate() AS BirthDate,     --GetDate() AS EngageDate,     --'F' AS Sex,     --10000.00 AS Salary,     --0 AS FactorAmnt,     --'' AS ReferenceCode,     --GetDate() AS DateOfBirth,     --'' IdNo,     --GETDATE() AS JoiningDate,     --1 AS dependants,     --'' AS plans,     --159000.00 AS EmployerNormalAmount,     --12000.00 AS EmployerTotal,     --0 AS Employeroverunder,     --11 AS notUsed2,     --0 AS MemberNormalAmount,     --0 AS Memberoverunder,     --0 AS MemberTotal,     --'' AS notused3,     --0 AS EmployerplusMember,     --Getdate() AS PeriodEndDate,     --Getdate() AS PeriodStartDate,     --'' AS CycelDesc,     --'' AS VendorName,     --1 AS VendorID,     --0 AS Commission,     --0 AS TotalPayment       END

GO

-- ============================================
-- SP: Payroll_TrailRun_rpt_sp
-- Schema: dbo
-- ============================================
   /*   Modiri   Date : 2019/07/02   #91071 SCOA Credit item for deduction incorrect on the Report   Date : Updated SCOA Descriptions    */  -- ========================================================================  -- 2021/10/07 Charl E WI69049 Fixed @VENDORID Filter  -- 2023/05/18 Richa M Add SalaryHead_id   -- 2025/01/16 Richa M - Fix duplications on report    --Payroll_TrailRun_rpt_sp 0,0,0,4,129,0     -- ========================================================================  CREATE PROCEDURE [dbo].[Payroll_TrailRun_rpt_sp] @TRANSACTIONTYPEID   INT                                                , @SALARYHEADID        INT                                                , @VENDORID            INT                                                , @EMPLOYEEID          INT                                                , @PERIODID            INT                                                , @DEPARTMENTID        INT  AS  BEGIN        SELECT DISTINCT             [PeriodID]           , [EmployeeID]           , [SalaryHead_ID]           , [Vendor_ID]           , [ControlVoteID]           , [TransactionTypeID]           , [IRP5Code]     --, [SalaryTitle]           , CAST(SalaryHeadId as varchar(10)) + ' - ' + [SalaryTitle] AS SalaryTitle           , [DepartmentDesc]           , [DivisionDesc]           , [PlanProjectItem]           , [Amount]           , [TransactionTypeDesc]           , [VendorName]           , [FirstName]           , [Surname]           , [EmpCode]           , [SCOAFundCode]           , [SCOARegionCode]           , [SCOACostingCode]           , [SCOAProjectCode]           , [SCOAFunctionCode]           , [DebitSCOAItem]           , [CreditSCOAItem]      FROM(            SELECT DISTINCT                 1 AS [index]               , [TR].[TrialResult_ID]               , [TR].[PeriodID] AS [PeriodID]               , [PE].[Employee_ID] AS [EmployeeID]               , [SalaryHead_ID] AS [SalaryHead_ID]               , [Vendor_ID] AS [Vendor_ID]               , [ControlVoteID] AS [ControlVoteID]               , [TR].[TransactionTypeID] AS [TransactionTypeID]               , [TR].[IRP5Code] AS [IRP5Code]               , [TR].[SalaryTitle] AS [SalaryTitle]      , [TR].[SalaryHeadID] AS [SalaryHeadId]               , [TR].[DepartmentDesc] AS [DepartmentDesc]               , [TR].[DivisionDesc] AS [DivisionDesc]               , (CAST([PPP].[ProjectCode] AS VARCHAR) + ' | ' + [PPP].[ProjectName]) AS [PlanProjectItem]               , [TR].[Amount] AS [Amount]               , [CTT].[TransactionTypeDesc] AS [TransactionTypeDesc]               , [CV].[VendorName] AS [VendorName]               , [PE].[FirstName] AS [FirstName]               , [PE].[Surname] AS [Surname]               , [PE].[EmpCode] AS [EmpCode]               , [SCOAFunds].[ScoaShortDesc] AS [SCOAFundCode]               , [SCOARegion].[ScoaShortDesc] AS [SCOARegionCode]               , [SCOACosting].[ScoaShortDesc] AS [SCOACostingCode]               , [SCOAProject].[ScoaShortDesc] AS [SCOAProjectCode]               , [SCOAFunction].[ScoaShortDesc] AS [SCOAFunctionCode]               , (CAST([Debit].[ScoaCode] AS VARCHAR(100)) + ' ' + [Debit].[ScoaDesc]) AS [DebitSCOAItem]                 --(CASE [CTT].[TransactionTypeDesc] WHEN 'Deductions'  THEN (CAST([CreditForDeduction].[ScoaCode] as varchar(100)) + ' ' + [CreditForDeduction].[ScoaDesc])  ELSE  (CAST([Credit].[ScoaCode] as varchar(100)) + ' ' + [Credit].[ScoaDesc]) END) as [CreditSCOAItem]               , (CAST([Credit].[ScoaCode] AS VARCHAR(100)) + ' ' + [Credit].[ScoaDesc]) AS [CreditSCOAItem]          FROM [Payroll_TrialResults] AS [TR] WITH(NOLOCK)               JOIN [Payroll_Employee] AS [PE] WITH(NOLOCK) ON [TR].[EmployeeID] = [PE].[Employee_ID]               JOIN [Payroll_SalaryHead] AS [SH] WITH(NOLOCK) ON [SalaryHead_ID] = [TR].[SalaryHeadID]                                                                 AND [SH].[Enabled] = 1               JOIN [Payroll_IRP5Code] AS [IRP5] WITH(NOLOCK) ON [IRP5Code_ID] = [SH].[IRP5CodeId]                                                                 AND [IRP5].[Enabled] = 1               JOIN [Const_TransactionType] AS [CTT] WITH(NOLOCK) ON [TransactionType_ID] = [IRP5].[TransactionTypeID]                                                                     AND [IRP5].[Enabled] = 1               JOIN [Payroll_Position] AS [PP] WITH(NOLOCK) ON [PP].[EmployeeID] = [TR].[EmployeeID]                                                               AND [PP].[Enabled] = 1               JOIN [Const_Division] AS [CD] WITH(NOLOCK) ON [PP].[DivisionID] = [CD].[Division_ID]                                                             AND [CD].[Enabled] = 1               LEFT OUTER JOIN [Cons_Vendor] AS [CV] WITH(NOLOCK) ON [CV].[Vendor_ID] = [TR].[VendorID]                                                                     AND [CV].[VendorCreditor] = 'C'                                                                     AND [CV].[bActivatedForPayroll] = 1                                                                     AND [CV].[bActivatedForLedger] = 1               LEFT OUTER JOIN [Payroll_GLItems] AS [GL] WITH(NOLOCK) ON [TR].[VendorID] = [GL].[VendorID] AND [TR].[SalaryHeadID] = [GL].SalaryHeadID               LEFT OUTER JOIN [Const_SCOA_Funds_Structure] AS [SCOAFunds] WITH(NOLOCK) ON [SCOAFunds].[ScoaID] = [TR].[SCOAFundingID]               LEFT OUTER JOIN [Const_SCOA_Regional_Structure] AS [SCOARegion] WITH(NOLOCK) ON [SCOAregion].[ScoaID] = [TR].[SCOARegionID]               LEFT OUTER JOIN [Const_SCOA_Costing_Structure] AS [SCOACosting] WITH(NOLOCK) ON [SCOACosting].[ScoaID] = [TR].[SCOACostingID]               LEFT OUTER JOIN [Const_SCOA_Project_Structure] AS [SCOAProject] WITH(NOLOCK) ON [SCOAProject].[ScoaID] = [TR].[SCOAProjectID]               LEFT OUTER JOIN [Const_SCOA_Function_Structure] AS [SCOAFunction] WITH(NOLOCK) ON [SCOAFunction].[ScoaID] = [TR].[SCOAFunctionID]               LEFT OUTER JOIN [Const_SCOA_Structure] AS [Debit] WITH(NOLOCK) ON [Debit].[ScoaID] = [TR].[SCOAItemID]               LEFT OUTER JOIN(               SELECT *               FROM [Const_SCOA_Structure] WITH(NOLOCK)) AS [Credit] ON [Credit].[ScoaID] = (CASE                                                                                                 WHEN [GL].[JournalEntryOnly] = 0                                                                                                      AND [TR].[TransactionTypeID] = 2                                                                                                 THEN [GL].[VendorScoaId]                                                                                                 ELSE [TR].[ContraSCOAItemID]                                                                                             END)                 --left outer join (select * from [Const_SCOA_Structure] with(nolock)) as [CreditForDeduction] on [CreditForDeduction].[ScoaID] = [GL].[VendorScoaId]               LEFT OUTER JOIN [Plan_ProjectItem] AS [PI] WITH(NOLOCK) ON [PI].[PlanProjectItem_ID] = [TR].[PlanProjectItemID]               LEFT OUTER JOIN [Plan_Project] AS [PPP] WITH(NOLOCK) ON [PPP].[Project_ID] = [PI].[ProjectID]          WHERE(([PE].[Employee_ID] = @EMPLOYEEID                 OR @EMPLOYEEID = 0)                AND [CTT].[TransactionType_ID] IN                                                 (         1, 2, 3, 4                                                 )                AND ([CTT].[TransactionType_ID] = @TRANSACTIONTYPEID                     OR @TRANSACTIONTYPEID = 0)                AND ([SH].[SalaryHead_ID] = @SALARYHEADID                     OR @SALARYHEADID = 0)                AND [TR].[PeriodID] = @PERIODID                AND ([PP].[DepartmentID] = @DEPARTMENTID                     OR @DEPARTMENTID = 0))               AND (ISNULL([CV].[Vendor_ID], 0) = @VENDORID                    OR @VENDORID = 0)          GROUP BY [TR].[TrialResult_ID]                 , [TR].[PeriodID]                 , [PE].[Employee_ID]                 , [SalaryHead_ID]                 , [Vendor_ID]                 , [ControlVoteID]                 , [TR].[TransactionTypeID]                 , [TR].[IRP5Code]        , [TR].[SalaryHeadID]                 , [TR].[SalaryTitle]                 , [TR].[DepartmentDesc]                 , [TR].[DivisionDesc]                 , [TR].[SCOAItemID]                 , [TR].[ContraSCOAItemID]                 , [PPP].[Project_ID]                 , [PPP].[ProjectCode]                 , [PPP].[ProjectName]                 , [Credit].[ScoaCode]                 , [Credit].[DefinitionDescription]                 , [PI].[PlanProjectItem_ID]                 , [SCOAFunds].[ScoaShortDesc]                 , [SCOARegion].[ScoaShortDesc]                 , [SCOACosting].[ScoaShortDesc]                 , [SCOAProject].[ScoaShortDesc]                 , [SCOAFunction].[ScoaShortDesc]                 , [Debit].[ScoaShortDesc]                 , [Debit].[ScoaCode]                 , [TR].[Amount]                 , [CTT].[TransactionTypeDesc]                 , [CV].[VendorName]                 , [PE].[FirstName]                 , [PE].[Surname]                 , [PE].[EmpCode]                 , [Debit].[ScoaDesc]                 , [Credit].[ScoaDesc]          --, [CreditForDeduction].[ScoaCode], [CreditForDeduction].[ScoaDesc]          ) AS [List]      ORDER BY [EmployeeID]             , [TransactionTypeID]  END

GO

-- ============================================
-- SP: Payroll_TransactionAuditList_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Ivan Myroshnychenko  -- Create date: 18/11/2020  -- Richa M - Fix Units for Overtime  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_TransactionAuditList_sp]   @CycleID INT,      @PeriodID INT ,   @TrialRun BIT  AS     DECLARE @db sysname = (select [KeyValue] from [AAAA_ConfigSettings] with (nolock) where ([KeyName] = 'FMSAuditDatabaseName'))  DECLARE @sql NVARCHAR(MAX)    IF OBJECT_ID('tempdb..#result') IS NOT NULL   DROP TABLE #result    CREATE TABLE #result  (   EmployeeID INT NOT NULL   , EmployeeFirstName NVARCHAR(MAX)   , EmployeeSurname NVARCHAR(MAX)   , TransactionType NVARCHAR(MAX)   , SalaryTranaction NVARCHAR(MAX)   , RepeatMonthly NVARCHAR(MAX)   , ReferenceNumber NVARCHAR(MAX)   , Units INT   , Amount FLOAT   , Action NVARCHAR(MAX)  )      IF OBJECT_ID('tempdb..#CycleEmployees') IS NOT NULL   DROP TABLE #CycleEmployees    CREATE TABLE #CycleEmployees  (    EmployeeID INT  )  INSERT INTO #CycleEmployees(EmployeeID)  SELECT P_E.Employee_ID FROM Payroll_Employee P_E  WHERE P_E.CycleID=@CycleID    DECLARE @StartDate DATETIME2 = (SELECT TOP 1 PeriodStartDate FROM Payroll_CyclePeriodDetails WHERE CycleID=@CycleID AND Period_ID=@PeriodID)  DECLARE @EndDate DATETIME2 = (SELECT TOP 1 PeriodEndDate FROM Payroll_CyclePeriodDetails WHERE CycleID=@CycleID AND Period_ID=@PeriodID)      ---------------------------------Travel and S&T Claims-----------------------  IF OBJECT_ID('tempdb..#claimsView') IS NOT NULL   DROP TABLE #claimsView    CREATE TABLE #claimsView  (   EmployeeClaims_ID INT NOT NULL   , EmployeeID NVARCHAR(MAX)   , DateCaptured DATETIME   , DateModified DATETIME   , Enabled INT  )    SET @sql = 'INSERT INTO #claimsView (EmployeeClaims_ID, EmployeeID, DateCaptured, DateModified, Enabled)   SELECT pec.EmployeeClaims_ID   , pec.EmployeeID   , pec.DateCaptured   , pec.DateModified   , pec.Enabled    FROM ['+@db+'].[dbo].[aPayroll_EmployeeClaims] pec   WHERE    pec.EmployeeClaims_ID IN    (     SELECT EmployeeClaims_ID     FROM Payroll_EmployeeClaims     WHERE ('+CAST(@TrialRun AS VARCHAR)+'=0 AND ProcessedOnPeriodId = '+CAST(@PeriodID AS Varchar)+')      OR ('+CAST(@TrialRun AS Varchar)+'=1 AND (Processed IS NULL OR Processed=0) AND PeriodID='+CAST(@PeriodID AS Varchar)+')     AND ExcludeFromPayment = 0    )'    EXEC sp_executesql @sql    IF (SELECT COUNT(EmployeeClaims_ID) FROM #claimsView) = 0   BEGIN    INSERT INTO #claimsView (EmployeeClaims_ID , EmployeeID , DateCaptured , DateModified , Enabled)     SELECT EmployeeClaims_ID    , EmployeeID    , DateCaptured    , DateModified    , Enabled    FROM Payroll_EmployeeClaims      WHERE (ProcessedOnPeriodId = @PeriodID AND @TrialRun=0)       OR (@TrialRun=1 AND (Processed IS NULL OR Processed=0) AND PeriodID=@PeriodID)      AND ExcludeFromPayment = 0   END      DECLARE @EmployeeClaims_ID INT  DECLARE @Employee_ID INT    DECLARE Claim_Cursor CURSOR FOR   SELECT EmployeeClaims_ID, EmployeeID    FROM Payroll_EmployeeClaims WHERE    EmployeeClaims_ID IN (SELECT EmployeeClaims_ID FROM #claimsView)    OPEN Claim_Cursor;   FETCH NEXT FROM Claim_Cursor INTO @EmployeeClaims_ID, @Employee_ID  WHILE @@FETCH_STATUS = 0    BEGIN    DECLARE @count INT = (SELECT COUNT(EmployeeClaims_ID) FROM #claimsView WHERE EmployeeClaims_ID=@EmployeeClaims_ID AND EmployeeID=@Employee_ID )    DECLARE @action NVARCHAR(MAX)    IF @count = 1   BEGIN    IF ((SELECT DateModified FROM #claimsView WHERE EmployeeClaims_ID=@EmployeeClaims_ID AND EmployeeID=@Employee_ID ) IS NULL)    SET @action = 'Add'    ELSE IF (SELECT Enabled FROM #claimsView WHERE EmployeeClaims_ID=@EmployeeClaims_ID AND EmployeeID=@Employee_ID )=0    SET @action = 'Delete'    ELSE IF ((SELECT DATEDIFF(SECOND, DateCaptured, DateModified) FROM #claimsView WHERE EmployeeClaims_ID=@EmployeeClaims_ID AND EmployeeID=@Employee_ID) > 1)    SET @action = 'EDIT'    ELSE IF((SELECT DATEDIFF(MILLISECOND, DateCaptured, DateModified) FROM #claimsView WHERE EmployeeClaims_ID=@EmployeeClaims_ID AND EmployeeID=@Employee_ID) > 100000)    SET @action = 'Edit'   END  ELSE   BEGIN    IF (SELECT COUNT(d.difftime)      FROM (SELECT EmployeeID, DateCaptured, DateModified,DATEDIFF(MILLISECOND,DateCaptured, DateModified) AS difftime       FROM #claimsView       WHERE EmployeeClaims_ID=@EmployeeClaims_ID) AS d      WHERE d.difftime>100000)=0     SET @action = 'Add'    ELSE     SET @action = 'Edit'   END    INSERT INTO #result   SELECT TOP 1   P_EC.EmployeeID -- EmployeeID   , P_E.FirstName -- Employee Name   , P_E.Surname -- Employee Surname   , C_TT.TransactionTypeDesc --Transaction Type    , P_SH.SalaryHeadName --Salary Name   , 'No' -- Monthly   , '' --   ,0 --   , P_EC.CostAmount -- Amount   , @action --Action Type   FROM Payroll_EmployeeClaims AS P_EC    JOIN Payroll_Employee AS P_E     ON P_E.Employee_ID = @Employee_ID    JOIN Const_Claims AS C_C     ON C_C.Claim_ID = P_EC.ClaimID    JOIN Payroll_SalaryHead AS P_SH      ON P_SH.SalaryHead_ID = C_C.SalaryHeadId    JOIN Payroll_IRP5Code AS P_IRP5      ON P_IRP5.IRP5Code_ID = P_SH.IRP5CodeId    JOIN Const_TransactionType AS C_TT      ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID   WHERE P_EC.EmployeeClaims_ID = @EmployeeClaims_ID AND P_EC.EmployeeID IN (Select * FROM #CycleEmployees)    FETCH NEXT FROM Claim_Cursor INTO @EmployeeClaims_ID, @Employee_ID  END;  CLOSE Claim_Cursor;  DEALLOCATE Claim_Cursor;        ------------OverTime ----------------------------  IF OBJECT_ID('tempdb..#overtimeView') IS NOT NULL   DROP TABLE #overtimeView    CREATE TABLE #overtimeView  (   Audit_ID INT   ,EmployeeOverTime_ID INT NOT NULL   , EmployeeID NVARCHAR(MAX)   , DateCaptured DATETIME   , DateModified DATETIME   , Enabled INT  )    SET @sql = 'INSERT INTO #overtimeView (Audit_ID, EmployeeOverTime_ID, EmployeeID, DateCaptured, DateModified, Enabled)  SELECT Audit_ID, EmployeeOverTime_ID, EmployeeID, DateCaptured, DateModified, Enabled   FROM ['+@db+'].[dbo].[aPayroll_EmployeeOverTime] peot   WHERE   peot.EmployeeOverTime_ID IN   (    SELECT EmployeeOverTime_ID    FROM Payroll_EmployeeOverTime    WHERE ('+CAST(@TrialRun AS VARCHAR)+'=0 AND ProcessedOnPeriodId = '+CAST(@PeriodID AS VARCHAR)+')     OR ('+CAST(@TrialRun AS VARCHAR)+' = 1 AND (Processed IS NULL OR Processed=0) AND PeriodID='+CAST(@PeriodID AS VARCHAR)+')    AND ExcludeFromPayment = 0   )'    EXEC sp_executesql @sql    DECLARE @EmployeeOver_ID INT    DECLARE Overtime_Cursor CURSOR FOR   SELECT EmployeeOverTime_ID, EmployeeID    FROM Payroll_EmployeeOverTime    WHERE EmployeeOverTime_ID IN (SELECT EmployeeOverTime_ID FROM #overtimeView)    OPEN Overtime_Cursor;  FETCH NEXT FROM Overtime_Cursor INTO @EmployeeOver_ID, @Employee_ID  WHILE @@FETCH_STATUS = 0  BEGIN   SET @count = (SELECT COUNT(EmployeeOverTime_ID) FROM #overtimeView WHERE EmployeeOverTime_ID=@EmployeeOver_ID AND EmployeeID=@Employee_ID )     IF @count = 1   BEGIN    IF ((SELECT DateModified FROM #overtimeView WHERE EmployeeOverTime_ID=@EmployeeOver_ID AND EmployeeID=@Employee_ID ) IS NULL)     SET @action = 'Add'    ELSE IF (SELECT Enabled FROM #overtimeView WHERE EmployeeOverTime_ID=@EmployeeOver_ID AND EmployeeID=@Employee_ID )=0     SET @action = 'Delete'    ELSE IF((SELECT DATEDIFF(SECOND, DateCaptured, DateModified) FROM #overtimeView WHERE EmployeeOverTime_ID=@EmployeeOver_ID AND EmployeeID=@Employee_ID) > 1)     SET @action = 'Edit'    ELSE IF((SELECT DATEDIFF(MILLISECOND, DateCaptured, DateModified) FROM #overtimeView WHERE EmployeeOverTime_ID=@EmployeeOver_ID AND EmployeeID=@Employee_ID) > 100000)     SET @action = 'Edit'   END  ELSE   BEGIN    IF (SELECT COUNT(d.difftime) FROM (SELECT Audit_ID, DateCaptured, DateModified,DATEDIFF(MILLISECOND,DateCaptured, DateModified) AS difftime FROM #overtimeView WHERE EmployeeOverTime_ID =@EmployeeOver_ID ) AS d WHERE d.difftime>100000)=0     SET @action = 'Add'    ELSE     SET @action = 'Edit'   END    INSERT INTO #result  SELECT TOP 1  P_EOT.EmployeeID  , P_E.FirstName  , P_E.Surname  , C_TT.TransactionTypeDesc  , P_SH.SalaryHeadName  , 'No'  , ''  ,P_EOT.OverTimeHour  , P_EOT.TotalAmount  , @action  FROM Payroll_EmployeeOverTime AS P_EOT  JOIN Payroll_Employee AS P_E ON P_E.Employee_ID = @Employee_ID  JOIN Payroll_SalaryHead AS P_SH ON P_SH.SalaryHead_ID = P_EOT.SalaryHeadID  JOIN Payroll_IRP5Code AS P_IRP5 ON P_IRP5.IRP5Code_ID = P_SH.IRP5CodeId  JOIN Const_TransactionType AS C_TT ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID  WHERE EmployeeOverTime_ID = @EmployeeOver_ID AND P_EOT.EmployeeID IN (Select * FROM #CycleEmployees)    FETCH NEXT FROM Overtime_Cursor into @EmployeeOver_ID, @Employee_ID  END;  CLOSE Overtime_Cursor;  DEALLOCATE Overtime_Cursor;        --------------------------------- Instalment -----------------------  IF OBJECT_ID('tempdb..#instalmentView') IS NOT NULL   DROP TABLE #instalmentView      CREATE TABLE #instalmentView  (   PartyPayment_ID INT NOT NULL   , EmployeeID NVARCHAR(MAX)   , DateCaptured DATETIME   , DateModified DATETIME   , Enabled INT  )    SET @sql = 'INSERT INTO #instalmentView (PartyPayment_ID, EmployeeID, DateCaptured, DateModified, Enabled)  SELECT aPPR.PartyPayment_ID   , aPPR.EmployeeID   , aPPR.DateCaptured   , aPPR.DateModified   , aPPR.Enabled    FROM ['+@db+'].[dbo].[aPayroll_3rdPartyPayment] aPPR   WHERE    aPPR.PartyPayment_ID IN    (     SELECT PartyPayment_ID     FROM Payroll_3rdPartyPayment     WHERE ('+CAST(@TrialRun as VARCHAR)+' = 0 AND Period_ID = '+CAST(@PeriodID as VARCHAR)+' AND Processed=1)      OR ('+CAST(@TrialRun as VARCHAR)+' = 1 AND (Processed IS NULL OR Processed=0) AND Period_ID='+CAST(@PeriodID as VARCHAR)+')     AND ExcludeFromPayment = 0    )'  EXEC sp_executesql @sql    IF (SELECT COUNT(PartyPayment_ID) FROM #instalmentView) = 0   BEGIN    INSERT INTO #instalmentView (PartyPayment_ID, EmployeeID, DateCaptured, DateModified, Enabled)     SELECT PartyPayment_ID    , EmployeeID    , DateCaptured    , DateModified    , Enabled    FROM Payroll_3rdPartyPayment     WHERE (@TrialRun = 0 AND Period_ID = @PeriodID AND Processed=1)      OR (@TrialRun = 1 AND (Processed IS NULL OR Processed=0) AND Period_ID=@PeriodID)     AND ExcludeFromPayment = 0   END      DECLARE @PartyPayment_ID INT    DECLARE Instalment_Cursor CURSOR FOR   SELECT PartyPayment_ID, EmployeeID    FROM Payroll_3rdPartyPayment WHERE    PartyPayment_ID IN (SELECT PartyPayment_ID FROM #instalmentView)    OPEN Instalment_Cursor;   FETCH NEXT FROM Instalment_Cursor INTO @PartyPayment_ID, @Employee_ID  WHILE @@FETCH_STATUS = 0    BEGIN    SET @count = (SELECT COUNT(PartyPayment_ID) FROM #instalmentView WHERE PartyPayment_ID=@PartyPayment_ID AND EmployeeID=@Employee_ID )    IF @count = 1   BEGIN    IF ((SELECT DateModified FROM #instalmentView WHERE PartyPayment_ID=@PartyPayment_ID AND EmployeeID=@Employee_ID ) IS NULL)    SET @action = 'Add'    ELSE IF (SELECT Enabled FROM #instalmentView WHERE PartyPayment_ID=@PartyPayment_ID AND EmployeeID=@Employee_ID )=0    SET @action = 'Delete'    ELSE IF((SELECT DATEDIFF(MILLISECOND, DateCaptured, DateModified) FROM #instalmentView WHERE PartyPayment_ID=@PartyPayment_ID AND EmployeeID=@Employee_ID) > 1)    SET @action = 'Edit'    ELSE IF((SELECT DATEDIFF(MILLISECOND, DateCaptured, DateModified) FROM #instalmentView WHERE PartyPayment_ID=@PartyPayment_ID AND EmployeeID=@Employee_ID) > 100000)    SET @action = 'Edit'   END  ELSE   BEGIN    IF (SELECT COUNT(d.difftime)      FROM (SELECT EmployeeID, DateCaptured, DateModified,DATEDIFF(MILLISECOND,DateCaptured, DateModified) AS difftime       FROM #instalmentView       WHERE PartyPayment_ID=@PartyPayment_ID ) AS d      WHERE d.difftime>100000)=0     SET @action = 'Add'    ELSE     SET @action = 'Edit'   END    INSERT INTO #result   SELECT TOP 1   PPR.EmployeeID -- EmployeeID   , P_E.FirstName -- Employee Name   , P_E.Surname -- Employee Surname   , C_TT.TransactionTypeDesc --Transaction Type    , P_SH.SalaryHeadName --Salary Name   , 'No' -- Monthly   , PPR.ReferenceNo -- ReferenveNo   ,0 -- Units   , PPR.TotalAmount -- Amount   , @action --Action Type   FROM Payroll_3rdPartyPayment AS PPR    JOIN Payroll_Employee AS P_E     ON P_E.Employee_ID = @Employee_ID      JOIN Payroll_SalaryHead AS P_SH      ON P_SH.SalaryHead_ID = PPR.SalaryHeadId    JOIN Payroll_IRP5Code AS P_IRP5      ON P_IRP5.IRP5Code_ID = P_SH.IRP5CodeId    JOIN Const_TransactionType AS C_TT      ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID   WHERE PPR.PartyPayment_ID=@PartyPayment_ID  AND PPR.EmployeeID IN (Select * FROM #CycleEmployees)    FETCH NEXT FROM Instalment_Cursor INTO @PartyPayment_ID, @Employee_ID  END;  CLOSE Instalment_Cursor;  DEALLOCATE Instalment_Cursor;        --------------------------------- Wage -----------------------  IF OBJECT_ID('tempdb..#wageView') IS NOT NULL   DROP TABLE #wageView    CREATE TABLE #wageView  (   Id INT NOT NULL   , EmployeeID NVARCHAR(MAX)   , DateCaptured DATETIME   , DateModified DATETIME   , Enabled INT  )    SET @sql = 'INSERT INTO #wageView (Id, EmployeeID, DateCaptured, DateModified, Enabled)   SELECT aPWT.Id   , aPWT.EmployeeID   , aPWT.DateCaptured   , aPWT.DateModified   , aPWT.Enabled     FROM [' + @db +'].[dbo].[aPayroll_WageTransaction] aPWT   WHERE    aPWT.Id IN    (     SELECT Id     FROM Payroll_WageTransaction     WHERE ('+ CAST(@TrialRun AS NVARCHAR) +'= 0 AND ProcessedOnPeriodId = '+ CAST(@PeriodID AS NVARCHAR) +' AND Processed=1)      OR ('+ CAST(@TrialRun AS VARCHAR)+' = 1 AND (Processed IS NULL OR Processed=0) AND CapturedDuringPeriodId = '+CAST(@PeriodID AS VARCHAR)+')       )'    EXEC sp_executesql @sql    IF (SELECT COUNT(Id) FROM #wageView) = 0   BEGIN    INSERT INTO #wageView (Id, EmployeeID, DateCaptured, DateModified, Enabled)     SELECT Id    , EmployeeID    , DateCaptured    , DateModified    , Enabled    FROM [Payroll_WageTransaction]     WHERE (@TrialRun = 0 AND ProcessedOnPeriodId= @PeriodID AND Processed=1)      OR (@TrialRun = 1 AND (Processed IS NULL OR Processed=0) AND CapturedDuringPeriodId=@PeriodID)   END      DECLARE @Wage_ID INT    DECLARE Wage_Cursor CURSOR FOR   SELECT Id, EmployeeID    FROM Payroll_WageTransaction pwt WHERE    Id IN (SELECT Id FROM #wageView)    OPEN Wage_Cursor;   FETCH NEXT FROM Wage_Cursor INTO @Wage_ID, @Employee_ID  WHILE @@FETCH_STATUS = 0    BEGIN    SET @count = (SELECT COUNT(Id) FROM #wageView WHERE Id=@Wage_ID AND EmployeeID=@Employee_ID )    IF @count = 1   BEGIN    IF ((SELECT DateModified FROM #wageView WHERE Id=@Wage_ID AND EmployeeID=@Employee_ID ) IS NULL)    SET @action = 'Add'    ELSE IF (SELECT Enabled FROM #wageView WHERE Id=@Wage_ID AND EmployeeID=@Employee_ID )=0    SET @action = 'Delete'    ELSE IF((SELECT DATEDIFF(SECOND, DateCaptured, DateModified) FROM #wageView WHERE Id=@Wage_ID AND EmployeeID=@Employee_ID) > 1)    SET @action = 'Edit'    ELSE IF((SELECT DATEDIFF(MILLISECOND, DateCaptured, DateModified) FROM #wageView WHERE Id=@Wage_ID AND EmployeeID=@Employee_ID) > 100000)    SET @action = 'Edit'   END  ELSE   BEGIN    IF (SELECT COUNT(d.difftime)      FROM (SELECT EmployeeID, DateCaptured, DateModified,DATEDIFF(MILLISECOND,DateCaptured, DateModified) AS difftime       FROM #wageView       WHERE Id=@Wage_ID) AS d      WHERE d.difftime>100000)=0     SET @action = 'Add'    ELSE     SET @action = 'Edit'   END    INSERT INTO #result   SELECT TOP 1   P_WT.EmployeeId -- EmployeeID   , P_E.FirstName -- Employee Name   , P_E.Surname -- Employee Surname   , C_TT.TransactionTypeDesc --Transaction Type    , P_SH.SalaryHeadName --Salary Name   , 'No' -- Monthly   , '' -- ReferenveNo   , P_WT.Unit -- Units   , P_WT.Amount -- Amount   , @action --Action Type   FROM Payroll_WageTransaction AS P_WT    JOIN Payroll_Employee AS P_E     ON P_E.Employee_ID = @Employee_ID      JOIN Payroll_SalaryHead AS P_SH      ON P_SH.SalaryHead_ID = P_WT.SalaryHeadId    JOIN Payroll_IRP5Code AS P_IRP5      ON P_IRP5.IRP5Code_ID = P_SH.IRP5CodeId    JOIN Const_TransactionType AS C_TT      ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID   WHERE P_WT.Id=@Wage_ID AND P_WT.EmployeeID IN (SELECT * FROM #CycleEmployees)    FETCH NEXT FROM Wage_Cursor into @Wage_ID, @Employee_ID  END;  CLOSE Wage_Cursor;  DEALLOCATE Wage_Cursor;    ---------------------------------Payslips-----------------------  IF OBJECT_ID('tempdb..#payslipsView') IS NOT NULL   DROP TABLE #payslipsView    CREATE TABLE #payslipsView  (   PayrollDefinationID INT NOT NULL   , EmployeeID NVARCHAR(MAX)   , DateCaptured DATETIME   , DateModified DATETIME   , Enabled INT   , Amount FLOAT   ,TransactionType NVARCHAR(MAX)   , SalaryName NVARCHAR(MAX)   , ReferenceNo NVARCHAR(MAX)   , EveryMonth INT  )      IF @TrialRun =1  BEGIN   INSERT INTO #payslipsView (PayrollDefinationID, EmployeeID , DateCaptured , DateModified , Enabled, Amount,TransactionType, SalaryName, ReferenceNo, EveryMonth)     SELECT     P_ETP.PayrollDefinationID    ,P_CC.EmployeeID    , P_CC.DateCaptured    , P_CC.DateModified    ,P_CC.Enabled    , P_ETP.Amount    , C_TT.TransactionTypeDesc    ,PSH.SalaryHeadName    ,P_ETP.ReferenceNo    , P_CC.EveryMonth     FROM Payroll_CostCenter AS P_CC    JOIN Payroll_EmployeeTrialPayslip AS P_ETP     ON P_CC.EmployeeID = P_ETP.EmployeeID AND P_CC.ReferenceNo=P_ETP.ReferenceNo    JOIN Payroll_EmployeePayrollDefinition AS P_EPD      ON P_ETP.PayrollDefinationID=P_EPD.EmployeePayrollDefinition_ID    JOIN Payroll_SalaryHead AS PSH     ON P_EPD.PayrollSalaryHeadID = PSH.SalaryHead_ID    JOIN Payroll_IRP5Code AS P_IRP5      ON P_IRP5.IRP5Code_ID = PSH.IRP5CodeId    JOIN Const_TransactionType AS C_TT      ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID    WHERE P_CC.PeriodID=@PeriodID  END  ELSE   BEGIN     INSERT INTO #payslipsView (PayrollDefinationID, EmployeeID , DateCaptured , DateModified , Enabled, Amount,TransactionType, SalaryName, ReferenceNo, EveryMonth)     select PS.PayrollDefinationID,PS.EmployeeID,CC.DateCaptured,CC.DateModified,CC.Enabled,PS.Amount, C_TT.TransactionTypeDesc    ,PSH.SalaryHeadName    ,PS.ReferenceNo    , cc.EveryMonth  from    (select * from Payroll_CostCenter where ProcessedOnPeriodId = @PeriodId)CC    Join Payroll_EmployeePayslip PS on PS.PayrollDefinationID = CC.PayrollDefinationID and CC.EmployeeID = PS.EmployeeID and PS.PeriodID = @PeriodId     JOIN Payroll_EmployeePayrollDefinition AS P_EPD      ON PS.PayrollDefinationID=P_EPD.EmployeePayrollDefinition_ID    JOIN Payroll_SalaryHead AS PSH     ON P_EPD.PayrollSalaryHeadID = PSH.SalaryHead_ID    JOIN Payroll_IRP5Code AS P_IRP5      ON P_IRP5.IRP5Code_ID = PSH.IRP5CodeId    JOIN Const_TransactionType AS C_TT      ON C_TT.TransactionType_ID=P_IRP5.TransactionTypeID     END      DECLARE @PayrollDefinationID INT  DECLARE @Amount FLOAT  DECLARE @Reference NVARCHAR(MAX)    DECLARE Payroll_Cursor CURSOR FOR   SELECT PayrollDefinationID, EmployeeID , Amount,ReferenceNo   FROM #payslipsView    OPEN Payroll_Cursor;   FETCH NEXT FROM Payroll_Cursor INTO @PayrollDefinationID, @Employee_ID, @Amount, @Reference  WHILE @@FETCH_STATUS = 0    BEGIN    SET @count  = (SELECT COUNT(PayrollDefinationID) FROM #payslipsView WHERE PayrollDefinationID=@PayrollDefinationID AND EmployeeID=@Employee_ID AND @Reference = ReferenceNo)    IF @count = 1   BEGIN    IF ((SELECT TOP 1 DateModified FROM #payslipsView WHERE PayrollDefinationID=@PayrollDefinationID AND EmployeeID=@Employee_ID ) IS NULL)     SET @action = 'Add'    ELSE IF (SELECT TOP 1 Enabled FROM #payslipsView WHERE PayrollDefinationID=@PayrollDefinationID AND EmployeeID=@Employee_ID )=0     SET @action = 'Delete'    ELSE    BEGIN      DECLARE @DateCapture DATETIME2 = (SELECT DateCaptured FROM #payslipsView WHERE PayrollDefinationID=@PayrollDefinationID AND EmployeeID=@Employee_ID AND @Reference=ReferenceNo)     DECLARE @DateModify DATETIME2 = (SELECT DateModified FROM #payslipsView WHERE PayrollDefinationID=@PayrollDefinationID AND EmployeeID=@Employee_ID AND @Reference=ReferenceNo)     IF(DATEDIFF(SECOND,@DateCapture, @DateModify) > 1)      SET @action = 'Edit'     ELSE IF( DATEDIFF(MILLISECOND,@DateCapture, @DateModify) > 1000)      SET @action = 'Edit'           ELSE        SET @action = 'Add'    END   END  ELSE   BEGIN    IF (SELECT COUNT(d.difftime)      FROM (SELECT EmployeeID, DateCaptured, DateModified,DATEDIFF(MILLISECOND,DateCaptured, IsNULL(DateModified,DateCaptured)) AS difftime       FROM #payslipsView       WHERE PayrollDefinationID=@PayrollDefinationID) AS d      WHERE d.difftime>100000)=0     SET @action = 'Add'    ELSE     SET @action = 'Edit'   END    INSERT INTO #result   SELECT TOP 1   P_V.EmployeeID -- EmployeeID   , P_E.FirstName -- Employee Name   , P_E.Surname -- Employee Surname   , P_V.TransactionType--Transaction Type    , P_V.SalaryName --Salary Name   , CASE -- Monthly    WHEN P_V.EveryMonth =1 THEN 'Yes'    ELSE 'No'   END   , P_V.ReferenceNo --Reference   ,0 -- Unit   , P_V.Amount-- Amount   , @action --Action Type   FROM #payslipsView AS P_V    JOIN Payroll_Employee AS P_E     ON P_E.Employee_ID = @Employee_ID     WHERE P_V.PayrollDefinationID = @PayrollDefinationID     AND P_V.Amount=@Amount     AND P_V.ReferenceNo=@Reference     AND P_V.EmployeeID IN (Select * FROM #CycleEmployees)    AND NOT EXISTS (SELECT *         FROM #result        WHERE P_E.Employee_ID = @Employee_ID         AND TransactionType = P_V.TransactionType         AND SalaryTranaction = P_V.SalaryName         AND Amount = P_V.Amount         AND ReferenceNumber = P_V.ReferenceNo)    FETCH NEXT FROM Payroll_Cursor INTO @PayrollDefinationID, @Employee_ID, @Amount, @Reference  END;  CLOSE Payroll_Cursor;  DEALLOCATE Payroll_Cursor;    ---------Show result------------------------  SELECT  * FROM #result r ORDER BY r.EmployeeID

GO

