-- ============================================
-- SP: Payroll_TransactionsWithPeriodException
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Lungisani khumalo>  -- Create date: <Create Date,15/05/2018,>  -- Description: <Description, Gets the Transcations that are captured two months before the active period,>  -- #10/July/2019 Himil Modi :#91379 Put or condition with the period id and rejected reason text.  -- #25/July/2019 Himil Modi :#91379 Put or condition with the rected reason text.  -- 21/April/2020 Ilya Skavronskiy: excluded installments from the result  -- =============================================  CREATE PROCEDURE dbo.Payroll_TransactionsWithPeriodException  @cycleId int, @EmployeeId int, @PeriodID int     as  begin     begin try        declare @Results table   ( [rownumber] int identity (1,1),    [Cost_ID]int,    [Employee_ID] int,    [EmpCode]nvarchar(200),    [FirstName]nvarchar(200),    [Surname] nvarchar(200),      [SalaryHeadTitle] nvarchar(200),      [Amount] decimal,    [Date] nvarchar(100)    )        /* 2 months old periods that must be processed */      begin      declare @Periods table (        [ID] [int] identity(2,1) not null,    [PeriodId] [int]      )      insert into @Periods (PeriodId) select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails] where [CycleID] = @CycleID and [CycleModeID] = 1 and [Processed] = 1 and [Period_ID] < @PeriodID  order by [Period_ID] desc      if(not exists(select [PeriodId] from @Periods where [PeriodId] = @PeriodID))    begin     insert into @Periods (PeriodId) select @PeriodID    end     end         /*Employee Over Time*/      insert into @Results( [Cost_ID], [FirstName], [Surname] , [Employee_ID],[EmpCode], [SalaryHeadTitle],[Amount] ,[Date])       select [EmployeeOverTime_ID] as [Cost_ID], [PE].[FirstName], [PE].[Surname],[PE].[Employee_ID], [PE].[EmpCode],[SH].[SalaryHeadTitle],       [OT].[TotalAmount] as [Amount], convert(varchar(10), [OT].[OverTimeDate] , 103) as [Date]                  from  [Payroll_Employee] [PE] with(nolock)       join [Payroll_EmployeeOverTime] [OT] with(nolock) on [PE].[Employee_ID] = [OT].[EmployeeID] and [OT].[Enabled] = 1        join [Payroll_SalaryHead] [SH] with(nolock) on [OT].[SalaryHeadID] = [SH].[SalaryHead_ID] and [SH].[Enabled] = 1             where [OT].[EmployeeID] = (case @EmployeeID when 0 then [OT].[EmployeeID] else @EmployeeID end) and [OT].[Enabled] = 1                    and ([OT].[Processed] is null or [OT].[Processed] = 0)             and [PE].[CycleID] = (case @cycleId when 0 then [PE].[CycleID] else @cycleId end)         and [OT].[PeriodID] < (select min([PeriodId]) from @Periods)            AND [OT].CapturedDuringPeriodId = @PeriodID         /*Employee Claims*/      insert into @Results( [Cost_ID], [FirstName], [Surname] , [Employee_ID],[EmpCode], [SalaryHeadTitle],[Amount] ,[Date])         select [EC].[EmployeeClaims_ID] as [Cost_ID], [PE].[FirstName], [PE].[Surname],[PE].[Employee_ID], [PE].[EmpCode],[SH].[SalaryHeadTitle],       [EC].[CostAmount] as [Amount], convert(varchar(10), [EC].[EffectiveDate] , 103) as [Date]                  from  [Payroll_Employee] [PE] with(nolock)       join [Payroll_EmployeeClaims] [EC] with(nolock) on [PE].[Employee_ID] = [EC].[EmployeeID] and [EC].[Enabled] = 1        join [Const_Claims] [CL] with(nolock) on [EC].[ClaimID] = [CL].[Claim_ID]       join [Payroll_SalaryHead] [SH] with(nolock) on [CL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [SH].[Enabled] = 1        where [EC].[EmployeeID] = (case @EmployeeID when 0 then [EC].[EmployeeID] else @EmployeeID end) and [EC].[Enabled] = 1                    and ([EC].[Processed] is null or [EC].[Processed] = 0)             and [PE].[CycleID] = (case @cycleId when 0 then [PE].[CycleID] else @cycleId end)         and (       ([EC].[PeriodID] < (select min([PeriodId]) from @Periods))        OR (EC.RejectedReason='Transaction exceeding 2 months')      )        AND [EC].CapturedDuringPeriodId = @PeriodID        select * from @Results      end try      begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate],[Blocking]/*,[Simulation]*/)       values('System', @PeriodID, 'Report' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate(), 1/*, @Simulation*/)      end catch           end

GO

-- ============================================
-- SP: Payroll_TravelClaims_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:Varun Parvataneni  -- Description : To Generate TravelClaims reports on employee for selected dates  -- Create date: 7 APR 2016  -- CALLS : Payroll_TravelClaims_sp  '2015-03-01','2016-02-29',0,0,0,1  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions   -- 2020-10-20 US42239 Myroshnychenko: Remove 'ReportType' parameter, add CycleID and ExcessValue parameters, change call for getting more information  -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_TravelClaims_sp]    @FromDate DATETIME,   @ToDate DATETIME,   @CycleID INT,   @ExcessValue FLOAT,   @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT  AS    BEGIN    SELECT DISTINCT    dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as EmployeeNumber,    P_E.FirstName,    P_E.Surname as EmployeeSurname,    IIF(P_EC.ProjectID IS NOT NULL,'Yes', 'No') as OverrideProject,    C_D.DepartmentDesc as Department,    C_DIV.DivisionDesc as Division,    P_EC.SubType as ClaimSubType,    P_EC.ReferenceNo as ReferenceNumber,    P_EC.CostDesc as ReasonForTrip,    P_EC.EntryDate as Date,      P_EC.Kilometre as Kilometersclaimed,    P_EC.CostAmount as AmountClaimed     FROM (SELECT * from Payroll_EmployeeClaims where  EntryDate BETWEEN @FromDate and @ToDate      AND ClaimID in (select Claim_ID from Const_Claims where Claim_Type = 'Travel')      AND (ISNULL(@EmployeeID,0) = 0 OR EmployeeID = @EmployeeID)     AND (ISNULL(@ExcessValue,0) = 0 OR Kilometre > @ExcessValue )      AND Enabled = 1     ) AS P_EC    JOIN Payroll_Employee AS P_E     ON P_EC.EmployeeId = P_E.Employee_ID    INNER JOIN Payroll_Position AS P_P ON P_P.Position_ID = P_E.PositionID    INNER JOIn Const_Division C_DIV on C_DIV.Division_ID = P_P.DivisionId    Inner JOIN Const_Department C_D on C_D.Department_ID = C_DIV.DepartmentID     INNER JOIN Const_Claims C_C ON C_C.Claim_ID = P_EC.ClaimID        WHERE (ISNULL(@DepartmentId,0) = 0 OR Department_ID = @DepartmentId)     AND (ISNULL(@DivisionId,0) = 0 OR Division_ID = @DivisionId)      AND (ISNULL(@CycleID,0) = 0 OR P_E.CycleID = @CycleID)     AND P_EC.Processed = 1   ORDER BY C_D.DepartmentDesc, C_DIV.DivisionDesc , dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0'), P_EC.EntryDate ASC     END

GO

-- ============================================
-- SP: Payroll_TravelEntry_Search_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Mehul Panchal  -- Create date: 1 Nov 2013  -- CALLS : Payroll_TravelEntry_Search_sp  'mehul','','','2012/2013',1    -- CALLS : Payroll_TravelEntry_Search_sp  'nirav','','','2012/2013',0  -- 2016-01-04 Suri Kandukuri : Added Employee Code to Search List  -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_TravelEntry_Search_sp]   @EmployeeID INT,   @FinancialYear NVARCHAR(50),   @Flag BIT   AS    BEGIN   IF(@Flag = 0)   BEGIN    SELECT PAY_COST.TravelEntry_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      Isnull(CONST_TRAN.TransactionTypeDesc + '  '+ PAY_SAL.SalaryHeadTitle,0) AS 'PayDefination',     PAY_COST.CostAmount,PAY_COST.CostDesc, PAY_COST.FinancialYear,     CASE WHEN PAY_COST.[Enabled] = 1 THEN ' True' ELSE 'False' END AS [STATUS],     PAY_COST.EntryDate, PAY_COST.CapturerID, PAY_COST.DateCaptured, PAY_COST.ModifierID,     PAY_COST.DateModified,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_TravelEntry AS PAY_COST        INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID     LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_COST.PayrollDefinationID = PAY_DEF.EmployeePayrollDefinition_ID        LEFT OUTER JOIN Payroll_SalaryHead PAY_SAL ON PAY_DEF.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     LEFT OUTER JOIN Payroll_IRP5Code PAY_IRP ON PAY_IRP.IRP5Code_ID = PAY_SAL.IRP5CodeId     LEFT OUTER JOIN Const_TransactionType CONST_TRAN ON PAY_IRP.TransactionTypeID = CONST_TRAN.TransactionType_ID       WHERE (P_E.Employee_ID = @EmployeeID or @EmployeeID = 0) AND PAY_COST.TaxYear =@FinancialYear    ORDER BY P_E.Employee_ID   END   ELSE   BEGIN    SELECT PAY_COST.TravelEntry_ID, P_E.IdNo, P_E.Surname, P_E.FirstName,      Isnull(CONST_TRAN.TransactionTypeDesc + '  '+ PAY_SAL.SalaryHeadTitle,0) AS 'PayDefination',     PAY_COST.CostAmount,PAY_COST.CostDesc, PAY_COST.FinancialYear,     CASE WHEN PAY_COST.[Enabled] = 1 THEN ' True' ELSE 'False' END AS [STATUS],     PAY_COST.EntryDate, PAY_COST.CapturerID, PAY_COST.DateCaptured, PAY_COST.ModifierID,     PAY_COST.DateModified,     dbo.BufferString_fxn(CONVERT(VARCHAR,(P_E.Employee_ID)), 8, '0') as Employee_ID,     isnull(P_E.EmpCode,'') EmpCode    FROM Payroll_TravelEntry AS PAY_COST        INNER JOIN Payroll_Employee AS P_E ON PAY_COST.EmployeeID = P_E.Employee_ID     LEFT OUTER JOIN Payroll_EmployeePayrollDefinition PAY_DEF ON PAY_COST.PayrollDefinationID = PAY_DEF.EmployeePayrollDefinition_ID        LEFT OUTER JOIN Payroll_SalaryHead PAY_SAL ON PAY_DEF.PayrollSalaryHeadID = PAY_SAL.SalaryHead_ID     LEFT OUTER JOIN Payroll_IRP5Code PAY_IRP ON PAY_IRP.IRP5Code_ID = PAY_SAL.IRP5CodeId     LEFT OUTER JOIN Const_TransactionType CONST_TRAN ON PAY_IRP.TransactionTypeID = CONST_TRAN.TransactionType_ID       WHERE PAY_COST.TaxYear =@FinancialYear    ORDER BY P_E.Employee_ID   END  END  

GO

-- ============================================
-- SP: Payroll_TrialBudget
-- Schema: dbo
-- ============================================
-- =============================================  -- author:  <author,,Lungisani>  -- create date: <create date,,>  -- description: <description,,Validate Municipal Project Budget>  --  Himil Modi #79091 -- give cycleId in where condition to correct the total number of process period and get all process period id in the @period table and put inner join with the all table to get the correct amount in respective fields.  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_TrialBudget] @PeriodID int   as    begin           begin try       Declare @FinYear nvarchar(20), @ProcessedPeriods int , @PeriodEndDate DATETIME ,@CycleID INT, @StartPeriod int      select @FinYear = [KeyValue] from [AAAA_ConfigSettings] where [KeyName] like 'ActiveFinYear'      select @StartPeriod = PeriodInTaxYear , @PeriodEndDate = [PeriodEndDate],@CycleID= CycleID from [Payroll_CyclePeriodDetails] where [Period_ID] = @PeriodID       SET @StartPeriod = @StartPeriod - 4                    select [ID],[ProjectName], [Item], [BudgetAmount], @FinYear as [FinYear], sum([Amount]) as [ActualBudget], ([BudgetAmount] - sum([Amount])) as [RemainingBudget], @ProcessedPeriods as [ProcessedPeriods] ,cast((sum([Amount])/ (case when @ProcessedPeriods = 0 then 1 else @ProcessedPeriods end)) as decimal(18,2)) as [Average],               [SCOAFundCode], [SCOARegionCode], [SCOACostingCode], [SCOAProjectCode], [SCOAFunctionCode], [SCOAItemCode], cast(@PeriodEndDate as date) as [PeriodEndDate], [MuniClassification]           from (      select [PlanProjectItem_ID] as [ID],(cast([PP].[Project_ID] as varchar(10)) + ' ' + [PP].[ProjectName]) as [ProjectName], (cast([PI].[PlanProjectItem_ID] as nvarchar(100)) + ' - ' + [PP].[ProjectDesc] + ' - ' + [PP].[ProjectName]) as Item, sum([TR].[amount]) as [Amount],        ([SCOAFunds].[ScoaShortDesc] + ' ' + [SCOAFunds].[ScoaCode]) as [SCOAFundCode],  ([SCOARegion].[ScoaShortDesc] + ' ' +  [SCOARegion].[ScoaCode]) as [SCOARegionCode], ([SCOACosting].[ScoaShortDesc] + ' ' + [SCOACosting].[ScoaCode]) as [SCOACostingCode] ,              ([SCOAProject].[ScoaShortDesc] + ' ' + [SCOAProject].[ScoaCode]) as [SCOAProjectCode], ([SCOAFunction].[ScoaShortDesc] + ' ' + [SCOAFunction].[ScoaCode]) as [SCOAFunctionCode], ([SCOAItemStructure].[ScoaShortDesc] + ' ' + [SCOAItemStructure].[ScoaCode]) as [SCOAItemCode],        (cast([CD].[Division_ID] as varchar(10)) + ' ' + [CD].[DivisionDesc] + ' / ' + [CD].[DivisionCode]) as [MuniClassification]        ,[TR].[PeriodID]      from  (select * from [Payroll_TrialResults] where PeriodID = @PeriodId) [TR]         join [Plan_ProjectItem] [PI] with(nolock) on [PI].[PlanProjectItem_ID] = [TR].[PlanProjectItemID] and [PI].[SCOAItemID] =  [TR].[SCOAItemID]        join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [PI].[ProjectID]        join [Const_Division] [CD] with(nolock) on [CD].[Division_ID] = [PI].[DivisionId]                    join [Const_Department] [CED] with(nolock) on [CD].[DepartmentID] = [CED].[Department_ID]                 join [Const_SCOA_Funds_Structure] [SCOAFunds]  with(nolock) on [SCOAFunds].[ScoaID] = [TR].[SCOAFundingID]                join [Const_SCOA_Regional_Structure] [SCOARegion]  with(nolock) on [SCOAregion].[ScoaID] = [TR].[SCOARegionID]                join [Const_SCOA_Costing_Structure] [SCOACosting]  with(nolock) on [SCOACosting].[ScoaID] = [TR].[SCOACostingID]                join [Const_SCOA_Project_Structure] [SCOAProject]  with(nolock) on [SCOAProject].[ScoaID] = [TR].[SCOAProjectID]                join [Const_SCOA_Function_Structure] [SCOAFunction]  with(nolock) on [SCOAFunction].[ScoaID] = [TR].[SCOAFunctionID]                join [Const_SCOA_Structure] [SCOAItemStructure]  with(nolock) on [SCOAItemStructure].[ScoaID] = [TR].[SCOAItemID]          where ([TransactionTypeID] in(1,3) and [PI].[FinYear] = @FinYear )         group by [PI].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName],[PP].[Project_ID],                        [SCOAFunds].[ScoaShortDesc] ,[SCOAFunds].[ScoaCode], [SCOARegion].[ScoaShortDesc], [SCOARegion].[ScoaCode], [SCOACosting].[ScoaShortDesc], [SCOACosting].[ScoaCode],                 [SCOAProject].[ScoaShortDesc], [SCOAProject].[ScoaCode], [SCOAFunction].[ScoaShortDesc], [SCOAFunction].[ScoaCode], [SCOAItemStructure].[ScoaShortDesc],[SCOAItemStructure].[ScoaCode], [CD].[Division_ID],[CD].[DivisionDesc],[CD].[DivisionCode]         ,[TR].[PeriodID]      union         select [PlanProjectItem_ID] as [ID],(cast([PP].[Project_ID] as varchar(10)) + ' ' + [PP].[ProjectName]) as [ProjectName],(cast([contraProject].[PlanProjectItem_ID] as nvarchar(100)) + ' - ' + [PP].[ProjectDesc] + ' - ' + [PP].[ProjectName]) as Item, sum([TR].[amount]) as [Amount],              ([SCOAFunds].[ScoaShortDesc] + ' ' + [SCOAFunds].[ScoaCode]) as [SCOAFundCode],  ([SCOARegion].[ScoaShortDesc] + ' ' +  [SCOARegion].[ScoaCode]) as [SCOARegionCode], ([SCOACosting].[ScoaShortDesc] + ' ' + [SCOACosting].[ScoaCode]) as [SCOACostingCode] ,              ([SCOAProject].[ScoaShortDesc] + ' ' + [SCOAProject].[ScoaCode]) as [SCOAProjectCode], ([SCOAFunction].[ScoaShortDesc] + ' ' + [SCOAFunction].[ScoaCode]) as [SCOAFunctionCode], ([SCOAItemStructure].[ScoaShortDesc] + ' ' + [SCOAItemStructure].[ScoaCode]) as [SCOAItemCode],          (cast([CD].[Division_ID] as varchar(10)) + ' ' + [CD].[DivisionDesc] + ' / ' + [CD].[DivisionCode]) as [MuniClassification]  ,[TR].[PeriodID]            from  (Select * from [Payroll_TrialResults] where PeriodID = @PeriodID) [TR]          join (select * from [Plan_ProjectItem] with(nolock)) [contraProject] on [contraProject].[PlanProjectItem_ID] = [TR].[PlanProjectItemID] and  [contraProject].[SCOAItemID] =  [TR].[ControlVoteID]        join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [contraProject].[ProjectID]        join [Const_Division] [CD] with(nolock) on [CD].[Division_ID] = [contraProject].[DivisionId]                    join [Const_Department] [CED] with(nolock) on [CD].[DepartmentID] = [CED].[Department_ID]        join [Const_SCOA_Funds_Structure] [SCOAFunds]  with(nolock) on [SCOAFunds].[ScoaID] = [TR].[ContraSCOAFundingID]             join [Const_SCOA_Regional_Structure] [SCOARegion]  with(nolock) on [SCOAregion].[ScoaID] = [TR].[ContraSCOARegionID]            join [Const_SCOA_Costing_Structure] [SCOACosting]  with(nolock) on [SCOACosting].[ScoaID] = [TR].[ContraSCOACostingID]               join [Const_SCOA_Project_Structure] [SCOAProject]  with(nolock) on [SCOAProject].[ScoaID] = [TR].[ContraSCOAProjectID]               join [Const_SCOA_Function_Structure] [SCOAFunction]  with(nolock) on [SCOAFunction].[ScoaID] = [TR].[ContraSCOAFunctionID]               join [Const_SCOA_Structure] [SCOAItemStructure]  with(nolock) on [SCOAItemStructure].[ScoaID] = [TR].[ContraSCOAItemID]         where ([TransactionTypeID] in(1,3) and [contraProject].[FinYear] = @FinYear )         group by [contraProject].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName],[PP].[Project_ID],                        [SCOAFunds].[ScoaShortDesc] ,[SCOAFunds].[ScoaCode], [SCOARegion].[ScoaShortDesc], [SCOARegion].[ScoaCode], [SCOACosting].[ScoaShortDesc], [SCOACosting].[ScoaCode],                 [SCOAProject].[ScoaShortDesc], [SCOAProject].[ScoaCode], [SCOAFunction].[ScoaShortDesc], [SCOAFunction].[ScoaCode], [SCOAItemStructure].[ScoaShortDesc],[SCOAItemStructure].[ScoaCode], [CD].[Division_ID],[CD].[DivisionDesc],[CD].[DivisionCode]         ,[TR].[PeriodID]        union              select [PlanProjectItem_ID] as [ID],(cast([PP].[Project_ID] as varchar(10)) + ' ' + [PP].[ProjectName]) as [ProjectName], (cast([PI].[PlanProjectItem_ID] as nvarchar(100)) + ' - ' + [PP].[ProjectDesc] + ' - ' + [PP].[ProjectName]) as Item, sum([PPR].[amount]) as [Amount],        ([SCOAFunds].[ScoaShortDesc] + ' ' + [SCOAFunds].[ScoaCode]) as [SCOAFundCode],  ([SCOARegion].[ScoaShortDesc] + ' ' +  [SCOARegion].[ScoaCode]) as [SCOARegionCode], ([SCOACosting].[ScoaShortDesc] + ' ' + [SCOACosting].[ScoaCode]) as [SCOACostingCode] ,              ([SCOAProject].[ScoaShortDesc] + ' ' + [SCOAProject].[ScoaCode]) as [SCOAProjectCode], ([SCOAFunction].[ScoaShortDesc] + ' ' + [SCOAFunction].[ScoaCode]) as [SCOAFunctionCode], ([SCOAItemStructure].[ScoaShortDesc] + ' ' + [SCOAItemStructure].[ScoaCode]) as [SCOAItemCode],          (cast([CD].[Division_ID] as varchar(10)) + ' ' + [CD].[DivisionDesc] + ' / ' + [CD].[DivisionCode]) as [MuniClassification]  ,[PPR].[PeriodID]        from  (select * from [Payroll_PayrollResults] where PeriodID = @PeriodId) [PPR]          join [Plan_ProjectItem] [PI] with(nolock) on [PI].[PlanProjectItem_ID] = [PPR].[PlanProjectItemID] and [PI].[SCOAItemID] =  [PPR].[SCOAItemID]        join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [PI].[ProjectID]        join [Const_Division] [CD] with(nolock) on [CD].[Division_ID] = [PI].[DivisionId]                    join [Const_Department] [CED] with(nolock) on [CD].[DepartmentID] = [CED].[Department_ID]                 join [Const_SCOA_Funds_Structure] [SCOAFunds]  with(nolock) on [SCOAFunds].[ScoaID] = [PPR].[SCOAFundingID]                join [Const_SCOA_Regional_Structure] [SCOARegion]  with(nolock) on [SCOAregion].[ScoaID] = [PPR].[SCOARegionID]                join [Const_SCOA_Costing_Structure] [SCOACosting]  with(nolock) on [SCOACosting].[ScoaID] = [PPR].[SCOACostingID]                join [Const_SCOA_Project_Structure] [SCOAProject]  with(nolock) on [SCOAProject].[ScoaID] = [PPR].[SCOAProjectID]                join [Const_SCOA_Function_Structure] [SCOAFunction]  with(nolock) on [SCOAFunction].[ScoaID] = [PPR].[SCOAFunctionID]                join [Const_SCOA_Structure] [SCOAItemStructure]  with(nolock) on [SCOAItemStructure].[ScoaID] = [PPR].[SCOAItemID]           where ([TransactionTypeID] in(1,3) and [PI].[FinYear] = @FinYear )        group by [PI].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName],[PP].[Project_ID],                        [SCOAFunds].[ScoaShortDesc] ,[SCOAFunds].[ScoaCode], [SCOARegion].[ScoaShortDesc], [SCOARegion].[ScoaCode], [SCOACosting].[ScoaShortDesc], [SCOACosting].[ScoaCode],                 [SCOAProject].[ScoaShortDesc], [SCOAProject].[ScoaCode], [SCOAFunction].[ScoaShortDesc], [SCOAFunction].[ScoaCode], [SCOAItemStructure].[ScoaShortDesc],[SCOAItemStructure].[ScoaCode], [CD].[Division_ID],[CD].[DivisionDesc],[CD].[DivisionCode]         ,[PPR].[PeriodID]      union         select [PlanProjectItem_ID] as [ID],(cast([PP].[Project_ID] as varchar(10)) + ' ' + [PP].[ProjectName]) as [ProjectName],(cast([contraProject].[PlanProjectItem_ID] as nvarchar(100)) + ' - ' + [PP].[ProjectDesc] + ' - ' + [PP].[ProjectName]) as Item, sum([PPR].[amount]) as [Amount],              ([SCOAFunds].[ScoaShortDesc] + ' ' + [SCOAFunds].[ScoaCode]) as [SCOAFundCode],  ([SCOARegion].[ScoaShortDesc] + ' ' +  [SCOARegion].[ScoaCode]) as [SCOARegionCode], ([SCOACosting].[ScoaShortDesc] + ' ' + [SCOACosting].[ScoaCode]) as [SCOACostingCode] ,              ([SCOAProject].[ScoaShortDesc] + ' ' + [SCOAProject].[ScoaCode]) as [SCOAProjectCode], ([SCOAFunction].[ScoaShortDesc] + ' ' + [SCOAFunction].[ScoaCode]) as [SCOAFunctionCode], ([SCOAItemStructure].[ScoaShortDesc] + ' ' + [SCOAItemStructure].[ScoaCode]) as [SCOAItemCode] ,         (cast([CD].[Division_ID] as varchar(10)) + ' ' + [CD].[DivisionDesc] + ' / ' + [CD].[DivisionCode]) as [MuniClassification]  ,[PPR].[PeriodID]        from  (select * from [Payroll_PayrollResults] where PeriodID = @PeriodId) [PPR]          join (select * from [Plan_ProjectItem] with(nolock)) [contraProject] on [contraProject].[PlanProjectItem_ID] = [PPR].[PlanProjectItemID] and  [contraProject].[SCOAItemID] =  [PPR].[ControlVoteID]        join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [contraProject].[ProjectID]        join [Const_Division] [CD] with(nolock) on [CD].[Division_ID] = [contraProject].[DivisionId]                    join [Const_Department] [CED] with(nolock) on [CD].[DepartmentID] = [CED].[Department_ID]        join [Const_SCOA_Funds_Structure] [SCOAFunds]  with(nolock) on [SCOAFunds].[ScoaID] = [PPR].[ContraSCOAFundingID]             join [Const_SCOA_Regional_Structure] [SCOARegion]  with(nolock) on [SCOAregion].[ScoaID] = [PPR].[ContraSCOARegionID]            join [Const_SCOA_Costing_Structure] [SCOACosting]  with(nolock) on [SCOACosting].[ScoaID] = [PPR].[ContraSCOACostingID]               join [Const_SCOA_Project_Structure] [SCOAProject]  with(nolock) on [SCOAProject].[ScoaID] = [PPR].[ContraSCOAProjectID]               join [Const_SCOA_Function_Structure] [SCOAFunction]  with(nolock) on [SCOAFunction].[ScoaID] = [PPR].[ContraSCOAFunctionID]               join [Const_SCOA_Structure] [SCOAItemStructure]  with(nolock) on [SCOAItemStructure].[ScoaID] = [PPR].[ContraSCOAItemID]         where ([TransactionTypeID] in(1,3) and [contraProject].[FinYear] = @FinYear)        group by [contraProject].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName],[PP].[Project_ID],                            [SCOAFunds].[ScoaShortDesc] ,[SCOAFunds].[ScoaCode], [SCOARegion].[ScoaShortDesc], [SCOARegion].[ScoaCode], [SCOACosting].[ScoaShortDesc], [SCOACosting].[ScoaCode],                 [SCOAProject].[ScoaShortDesc], [SCOAProject].[ScoaCode], [SCOAFunction].[ScoaShortDesc], [SCOAFunction].[ScoaCode], [SCOAItemStructure].[ScoaShortDesc],[SCOAItemStructure].[ScoaCode], [CD].[Division_ID],[CD].[DivisionDesc],[CD].[DivisionCode]        ,[PPR].[PeriodID]     ) [Results]       join [Plan_ProjectItem] [PPI] with(nolock) on [PPI].[PlanProjectItem_ID] = [Results].[ID]             group by [ID],[ProjectName], [Item], [BudgetAmount], [SCOAFundCode], [SCOARegionCode], [SCOACostingCode], [SCOAProjectCode], [SCOAFunctionCode], [SCOAItemCode] ,[MuniClassification]               end try          begin catch       insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])               values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())    end catch        set nocount off;  end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateAllSuspenseScoaItemsActiveForPayroll
-- Schema: dbo
-- ============================================
  -- =============================================  -- author:  <author,,Lungisani>  -- create date: <create date,,>  -- description: <description,,Validate all Suspense Scoa Item Active For Payroll>  -- =============================================  /*  Modified by: Modiri  Date: 2019/04/19  Reason: #86658 Spelling error in trial run Notification  Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateAllSuspenseScoaItemsActiveForPayroll] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as  begin     set nocount on;     begin try    DECLARE @voteStasus_active INT = 1        declare @list table(     [ID] int identity(1,1),     [Item] nvarchar(100),     [Error] nvarchar(max)    )      declare @FinYear nvarchar(20)      select @FinYear = KeyValue from AAAA_ConfigSettings where ([KeyName] like 'ActiveFinYear')      /*[SalarySuspenseScoaItemID]*/    DECLARE @SalarySuspenseScoaItemID INT;    DECLARE @SalarySuspenseScoaCode NVARCHAR(50);        SELECT      @SalarySuspenseScoaItemID = [SalarySuspenseScoaItemID],      @SalarySuspenseScoaCode = CSS.ScoaCode    FROM [Payroll_Municipality] AS PM    LEFT JOIN Const_SCOA_Structure AS CSS ON PM.SalarySuspenseScoaItemID = CSS.ScoaID    WHERE PM.[FinYear] = @FinYear        if(@SalarySuspenseScoaItemID is null)    begin     insert into @list values( 'Salary Suspense ScoaItem'  , 'Salary Suspense SCOA Item is not set up - see municipal settings - HR')        end    else if(not exists (select [Vote_ID] from [Led_Vote] where [SCOAItemID] = @SalarySuspenseScoaItemID AND FinYear = @FinYear))    begin     insert into @list values( 'Salary Suspense ScoaItem'  , 'The current municipal settings for the Salary Suspense SCOA Item do not match the vote settings for the year ' + @FinYear )       end    else if(not exists (select [Vote_ID] from [Led_Vote] where [SCOAItemID] = @SalarySuspenseScoaItemID AND FinYear = @FinYear and [VoteStatusID] = @voteStasus_active))    begin     insert into @list values( 'Salary Suspense ScoaItem'  , 'Salary Control SCOA Item is linked to Inactive SCOA Item ' + @SalarySuspenseScoaCode + ' - fix  SCOA<Manage Item in Ledger')        end    else if(EXISTS (     SELECT 1     FROM (      SELECT VoteID, [3] AS Led_CSB_Mod, [4] AS Led_CRD_Mod, [5] AS Led_FIN_Mod, [7] AS Payroll_Mod      FROM (       SELECT * FROM Led_VoteSection AS LVS WITH(NOLOCK)       JOIN Led_Vote AS LV WITH(NOLOCK) ON LVS.VoteID = LV.Vote_ID       WHERE LV.SCOAItemID = @SalarySuspenseScoaItemID AND LV.FinYear = @FinYear AND LV.VoteStatusID = @voteStasus_active      ) AS VoteSections      PIVOT (max(VoteSectionID) FOR VoteSectionID IN ([3], [4], [5], [7])) AS piv     ) AS EnabledSections     WHERE Led_CSB_Mod IS NULL OR Led_CRD_Mod IS NULL OR Led_FIN_Mod IS NULL OR Payroll_Mod IS NULL    ))    begin     insert into @list values( 'Salary Suspense ScoaItem'  , 'Salary Suspense SCOA Item ' + @SalarySuspenseScoaCode + ' is not Active for Payroll/Ledger transations - see Vote settings - Ledger')     end      /*[SalarySuspenseScoaCreditItemID]*/    DECLARE @SalarySuspenseScoaItemCreditID INT;    DECLARE @SalarySuspenseScoaItemCreditCode NVARCHAR(50);        SELECT      @SalarySuspenseScoaItemCreditID = [SalarySuspenseScoaItemCreditID],      @SalarySuspenseScoaItemCreditCode = CSS.ScoaCode    FROM [Payroll_Municipality] AS PM    LEFT JOIN Const_SCOA_Structure AS CSS ON PM.[SalarySuspenseScoaItemCreditID] = CSS.ScoaID    WHERE PM.[FinYear] = @FinYear      if(@SalarySuspenseScoaItemCreditID is null)    begin        insert into @list values( 'Credit Salary Suspense ScoaItem'  , 'Credit Salary Suspense SCOA Item is not set up - see municipal settings - HR')        end    else if(not exists (select [Vote_ID] from [Led_Vote] where [SCOAItemID] = @SalarySuspenseScoaItemCreditID AND FinYear = @FinYear))    begin             insert into @list values( 'Credit Salary Suspense ScoaItem'  , 'The current municipal settings for the Cr