-- ============================================
-- SP: Payroll_TrialRunPostValidateBasicSalary
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 02/07/2019   Description : Get Trial Run Employees where no Basic Salary is assigned  */  CREATE procedure [Payroll_TrialRunPostValidateBasicSalary] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     declare @employeeType_postRetirement int = 6     begin try      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], 'This Employee has no Basic Salary Transaction linked', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)      join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID]      left join Const_EmployeeType_sys as ET with(nolock) on PE.EmployeeTypeID = ET.EmployeeType_ID      JOIN Payroll_Position AS PP WITH(NOLOCK) ON PE.PositionID = PP.Position_ID      JOIN Payroll_JobProfile AS JP WITH(NOLOCK) ON PP.JobProfileID = JP.JobProfile_ID      where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end)        and [EP].[Period_ID] = @PeriodID        and [PE].[CycleID] = @CycleID        and not exists(        select [EmployeePayrollDefinition_ID]         from [Payroll_EmployeePayrollDefinition] as [EPD]         where ([EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[Enabled] = 1 and [EPD].[PayrollSalaryHeadID] = 1)       )       -- skip validation for post-retirement employees, because they do not receive basic salary       and (ET.EmployeeType_ID is not null and ET.EmployeeType_ID != @employeeType_postRetirement)       AND (JP.LimitID IS NOT NULL OR JP.TaskGradeId IS NOT NULL)      )       end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])            values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateBonusTrans
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 02/07/2019   Description : Get Trial Run Employees where no PAYE is assigned     Modified : Modiri   Date  : 2019/07/03      : #86784 No Validation and notification when adding a new employee that the Employee Salary transaction group are linked to the PAYE Salary transactions     Modified : Modiri   Date  : 2019/07/22      : #91863Update Validation message for PAYE to be clearer to user     Modified : Himil Modi   Date  : 2019/07/25      : #91771 Check if bonus filter is applied for the Salary head 4 or not. (if so then validation comes otherwise no validation come from bonus part)    */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateBonusTrans] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin       set nocount on;     begin try      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], 'The Employee has no PAYE Salary Transaction Linked.', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID]        where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end) and [EP].[Period_ID] = @PeriodID and [PE].[CycleID] = @CycleID and         (not exists(          select [EmployeePayrollDefinition_ID]           from [Payroll_EmployeePayrollDefinition] as [EPD]           where ([EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[Enabled] = 1 and [EPD].[PayrollSalaryHeadID] = 3)          )      ))          insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], 'The Employee has no PAYE: Bonus Salary Transaction Linked.', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)       join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID]       LEFT JOIN [dbo].[Payroll_EmployeeSubtypes] AS PES with(nolock) ON PES.EmployeeSubtype_ID = PE.EmployeeSubtypeID      where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end) and [EP].[Period_ID] = @PeriodID and [PE].[CycleID] = @CycleID and       PES.ApplyBonus = 1  AND        (not exists(          select [EmployeePayrollDefinition_ID]           from [Payroll_EmployeePayrollDefinition] as [EPD]           where ([EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[Enabled] = 1 and [EPD].[PayrollSalaryHeadID] = 4)        )      ))     end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])            values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateCreditors
-- Schema: dbo
-- ============================================
  /*         AUTHOR        :   FERDI BOTHA         CREATE DATE   :   28/11/2018           DESCRIPTION   :   Check SCM Creditors Setup for Payroll transactional processing      Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year      E Beetge WI69655 Inactive Creditors not generating Trial Run errors  */  CREATE procedure [Payroll_TrialRunPostValidateCreditors] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as  begin     set nocount on;     begin try      declare @date datetime = getdate()      declare @FinYear varchar(9) = (select [FinancialYear] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID))      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])         select distinct [PeriodID], [EmployeeID], [ErrorReason], 1, 'Employee Level', object_name(@@procid), 1, @date, null, null        from (         select distinct @PeriodID as [PeriodID], [TP].[EmployeeID] as [EmployeeID], (case           when [CV].[bActivatedForPayroll] = 0 or [CV].[bActivatedForPayroll] is null then 'Creditor ' + isnull([CV].[VendorName], '') + ' is not Activated for Payroll'           when [CV].[bActivatedForPayroll] = 1 and not [CV].[StatusID] in (1, 7) then 'Creditor ' + isnull([CV].[VendorName], '') + ' is not active in SCM'          end) as [ErrorReason]         from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)          join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1          join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1          join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]          left outer join [Cons_Vendor] as [CV] with(nolock) on [CV].[Vendor_ID] = [GL].[VendorID]          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID] and [ACPD].[Enabled] = 1         where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and [TaxSavePurpose] = 0 and          (case           when @CycleModeID = 1 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end           when @CycleModeID = 2 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1 and ([IRP5].[TransactionTypeID] = 3 or ([IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0))         )       ) as [t]       where (not [ErrorReason] is null)     end try     begin catch      insert into [Payroll_TrialErrors]([EmployeeID], [PeriodID], [ErrorGroup], [ValidationType], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values(null, @PeriodID, 'System', 'System', error_message(), error_procedure(), 1, getdate())     end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateDepartment
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Trial Run Employees with no Department ID >   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no Department ID   Modified    :   Added validation for terminated employee  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateDepartment] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [DepartmentID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid Department assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]       left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]      where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and         ([Position_ID] is null or [DepartmentID] is null) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))               declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and PH.[DepartmentID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid Department assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or P.[DepartmentID] is null) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate            end try     begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])       values(null, @PeriodID, 'System', 'System', error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateDisabledDivision
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with Disabled Divisions  */  create procedure [Payroll_TrialRunPostValidateDisabledDivision] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     select [Employee_ID], [Position_ID], [PositionDesc], [DivisionDesc]      from [Payroll_Employee] as [PE] with(nolock)       left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]       left outer join [Const_Division] as [DIV] with(nolock) on [Division_ID] = [DivisionID]      where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and       not [Position_ID] is null and ([Division_ID] is null or [DIV].[Enabled] = 0))     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateDivision
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no Division ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no Division ID   Modified    :   Added validation for terminated employee  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateDivision] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [DepartmentID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid Division assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]      left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]     where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        ([Position_ID] is null or [DivisionID] is null) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))      )             declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and PH.[DepartmentID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid Division assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or P.[DivisionID] is null) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate                  end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateEmployeeCalendar
-- Schema: dbo
-- ============================================
-- =============================================  -- author:  <author,,Lungisani>  -- create date: <create date,,>  -- description: <description,,Validate Employee Calendar>  -- =============================================  create procedure [dbo].[Payroll_TrialRunPostValidateEmployeeCalendar] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int     as    begin           begin try     if(exists(select 1 from [Const_Cycle] [CC] with(nolock) join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1 and [CC].[Cycle_ID] = @CycleID and [CT].[CycleType_ID] in (2,3)))   begin      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])      select distinct @PeriodID, [HE].[Employee_ID], ( 'An active calendar is required for Employee Number :'+ [HE].[Employee_ID] +'.The pay run has failed due to the calendar not yet been created for this employee. Retry the pay run for this employee in 30 min '), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null           from (       select distinct [PE].[Employee_ID] from [Payroll_TrialRun_History_Employees] as [HE] with(nolock)       join [Payroll_EmployeeCalander] as [EC] with(nolock) on [EC].[EmployeeID] = [HE].[Employee_ID]        join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [HE].[Employee_ID] and [PE].[CycleID] = @CycleID       join [Const_Cycle] as [CC] with(nolock) on [CC].[Cycle_ID] = [PE].[CycleID] and [CC].[Enabled] = 1       join [Const_CycleType_sys] as [CT] with(nolock) on [CT].[CycleType_ID] = [CC].[CycleTypeID] and [CT].[Enabled] = 1       join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [HE].[Period_ID]       where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end)) and [HE].[Period_ID] = @PeriodID       and ([EC].[Date] between [CPD].[PeriodStartDate] and [CPD].[PeriodEndDate]) and [CT].[CycleType_ID] in (2,3)       ) [List]        right join [Payroll_TrialRun_History_Employees] as [HE] with(nolock) on [HE].[Employee_ID] = [List].[Employee_ID] and [HE].[Period_ID] = @PeriodID    end     end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())   end catch       set nocount off;  end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateInvalidSCOAFunction
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with Invalid SCOA Function ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateInvalidSCOAFunction] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as  begin     set nocount on;     begin try      declare @FinYear varchar(9) = (select [FinancialYear] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID))         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and not [FunctionID] is null and not [FunctionID] in (select [ScoaID] from Const_SCOA_Function_Structure_Consolidated where FinYearText = @FinYear) then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] is assigned to an invalid SCOA Function'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]       where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        not [Position_ID] is null and not [FunctionID] is null and not [FunctionID] in (select [ScoaID] from Const_SCOA_Function_Structure_Consolidated where FinYearText = @FinYear))    )          end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateInvalidSCOAFund
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no SCOA Fund ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */    CREATE procedure [dbo].[Payroll_TrialRunPostValidateInvalidSCOAFund] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try      declare @FinYear varchar(9) = (select [FinancialYear] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID))         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (      select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and not [ScoaFundID] is null and not [ScoaFundID] in (select [ScoaID] from Const_SCOA_Funds_Structure_Consolidated where FinYearText = @FinYear) then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] is assigned to an invalid SCOA Fund'        end), 1 , 'Global Level', object_name(@@procid) , 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]        where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and         not [Position_ID] is null and not [ScoaFundID] is null and not [ScoaFundID] in (select [ScoaID] from Const_SCOA_Funds_Structure_Consolidated where FinYearText = @FinYear))    )          end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

