-- SP: Payroll_TrialRunPostValidateInvalidSCOAProject
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with Invalid SCOA Project ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateInvalidSCOAProject] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try      declare @FinYear varchar(9) = (select [FinancialYear] from [Payroll_CyclePeriodDetails] with(nolock) where ([Period_ID] = @PeriodID))         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and not [ProjectID] is null and not [ProjectID] in (select [ScoaID] from [Const_Scoa_Project_Structure_Consolidated] where FinYearText = @FinYear) then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] is assigned to an invalid SCOA Project'        end), 1, 'Global Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]        left outer join [Plan_Project] as [PP] with(nolock) on [Project_ID] = [ProjectID] and [PP].[FinYear] = @FinYear       where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        not [Position_ID] is null and not [ProjectID] is null and not [ScoaProjectID] is null and not [ScoaProjectID] in (select [ScoaID] from [Const_Scoa_Project_Structure_Consolidated] where FinYearText = @FinYear)       )      )          end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateJobProfile
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no Job Profile ID   Update date : 27/06/2017 - updated to only check Job Profile ID if   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no Job Profile ID   Modified    :   Added validation for terminated employee  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateJobProfile] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [DepartmentID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid Job Profile assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null             from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]      left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]     where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        ([Position_ID] is null or ([POS].[Funds] = 1 and [POS].[JobProfileID] is null)) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))      )         declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and PH.[DepartmentID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid Job Profile assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or ([P].[Funds] = 1 and [P].[JobProfileID] is null)) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate                  end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
