-- Schema: dbo
-- ============================================
-- =============================================  -- author:  <author,,Lungisani>  -- create date: <create date,,>  -- description: <description,,Validate Municipal Project Scoa Item Active For Payroll>  --Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  -- =============================================  create procedure [dbo].[Payroll_TrialRunPostValidateMunicipalProjectItems] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int     as    begin     set nocount on;     begin try           declare @list table(     ID int identity(1,1),     Item nvarchar(100),     Error nvarchar(max)      )      Declare @FinYear nvarchar(20)      select @FinYear = KeyValue from AAAA_ConfigSettings where KeyName like 'ActiveFinYear'                                  /*[SalaryProjectID]*/        if(not exists (select [SalaryProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Salary Control Project Item '  , 'Salary Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[SalaryProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Salary Control Project Item '  , 'Salary Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[SalaryProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'Salary Control Project Item '  , 'Salary Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end        /*[TravelProjectID]*/        if(not exists (select [TravelProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Travel Control Project Item '  , 'Travel Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[TravelProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Travel Control Project Item '  , 'Travel Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[TravelProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'Travel Control Project Item '  , 'Travel Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end        /*[LeaveProjectID]*/      if(not exists (select [LeaveProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Leave Control Project Item '  , 'Leave Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[LeaveProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Leave Control Project Item '  , 'Leave Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[LeaveProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'Leave Control Project Item '  , 'Leave Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end        /*[TaxProjectID]*/      if(not exists (select [TaxProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Tax Control Project Item '  , 'Tax Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[TaxProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Tax Control Project Item '  , 'Tax Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[TaxProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin        