th(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[GroupLifeProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'GroupLife Control Project Item '  , 'GroupLife Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[GroupLifeProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'GroupLife Control Project Item '  , 'GroupLife Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end        /*[UnionsProjectID]*/      if(not exists (select [UnionProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Unions Control Project Item '  , 'Unions Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[UnionProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Unions Control Project Item '  , 'Unions Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[UnionProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'Unions Control Project Item '  , 'Unions Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end       /*[CommissionProjectID]*/         if(not exists (select [CommissionProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Commission Control Project Item '  , 'Commission Control Project Item  is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[CommissionProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Commission Control Project Item '  , 'Commission Control Project Item  set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[CommissionProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 2)    begin          insert into @list values( 'Commission Control Project Item '  , 'Commission Control Project Item  in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end          /*[EmployeeDeductionFICSProjectID]*/      if(not exists (select [EmployeeProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'Employee Deductions FICS Control Project Item'  , 'Employee Deductions FICS Control Project Item is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[EmployeeProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'Employee Deductions FICS Control Project Item'  , 'Employee Deductions FICS  ControlProject Item set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[EmployeeProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'Employee Deductions FICS Control Project Item'  , 'Employee Deductions FICS Control Project Item in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end              /*[NettSalaryProjectID]*/      if(not exists (select [NettSalaryProjectID] from [Payroll_Municipality]))    begin          insert into @list values( 'NettSalary Control Project Item'  , 'NettSalary Control Project Item is not set up - see municipal settings - HR')          end    if(not exists(select [PP].[Project_ID] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[NettSalaryProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ))    begin          insert into @list values( 'NettSalary Control Project Item'  , 'NettSalary  ControlProject Item set up is not Valid - see municipal settings - HR')          end    else if((select [CapitalOperation] from [Plan_Project] [PP] with(nolock) join [Const_PlanCapitalOperationalTypes_sys] [CPO] with(nolock) on [PP].[CapitalOperation]  = [CPO].[TypeValue] join [Payroll_Municipality] [PM] with(nolock) on [PM].[NettSalaryProjectID] = [PP].[Project_ID] where [PM].FinYear = @FinYear and [PP].FinYear = @FinYear ) <> 3)    begin          insert into @list values( 'NettSalary Control Project Item'  , 'NettSalary Control Project Item in municipal settings is not linked to a valid financial project - see Plan Project settings - Planning')          end            insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, null, Error , 1 , 'Global Level', object_name(@@procid), 1, getdate(), null ,null from @list      )          end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())      end catch       set nocount off;    end    

