-- ============================================
-- SP: Payroll_TrialRunPostValidateNegativeDeduction
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with Negative Deductions   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 12/05/2017 - Changed the mappings for Method of Calculation      Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateNegativeDeduction] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [TP].[EmployeeID], 'This Employee has a negative deduction amount', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1        join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]        left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]       where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and [TransactionTypeID] = 2 and [TaxSavePurpose] <> 1 and         (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0 end) = 1       )       group by [TP].[EmployeeID]        having (sum([Amount]) < 0)         )        end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateNegativeSalary
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with Negative Salary   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateNegativeSalary] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try   if @CycleModeID <> 2   begin    insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified],[Blocking])    (     select @PeriodID, [TP].[EmployeeID], 'This Employee has a negative salary', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null,0       from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1        join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]        left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]       where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and [TransactionTypeID] in(1, 2) and [TP].[TaxSavePurpose] = 0 and        (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0 end) = 1       )       group by [TP].[EmployeeID]        having (sum(case [TransactionTypeID] when 1 then [Amount] else [Amount] * -1 end) <= 0)    )    end            --select count([Reason]) from [Payroll_EmployeeTrialPayslipErrors] where [StoredProcedure] = object_name(@@procid) and [PeriodID] = @PeriodID       end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateNettSalaries
-- Schema: dbo
-- ============================================
 /*   Author  : Richa M   Create date : 30/01/2023   Description : Validate Budget Strings for Nett Salaries      */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateNettSalaries] @EmployeeID int, @PeriodID int   as    begin     set nocount on;    begin try    DECLARE @NettPayBondProjectID int = 0, @NettPayBondScoaItemID int = 0    SELECT  @NettPayBondProjectID =[EmployeeNetPayBondProjectID] ,     @NettPayBondScoaItemID =[EmployeeNetPayBondScoaItemID]  FROM [dbo].[Payroll_Municipality]    IF OBJECT_ID('tempdb..#projectItems') IS NOT NULL      DROP TABLE #projectItems     Select * into #projectItems from Plan_ProjectItem where PlanProjectItem_ID in(         Select min(PlanProjectItem_Id)PlanProjectItem_Id from Plan_ProjectItem          group by ProjectId,DivisionId,ScoaItemId,ScoaFunctionId,ScoaRegionId,FinYear)    CREATE INDEX IDX_ProjectItems ON #projectItems(ScoaItemId,ProjectId,DivisionId,ScoaRegionId,ScoaFunctionId)      Insert into Payroll_EmployeeTrialPayslipErrors  SELECT newid(),  @PeriodId,NettSalaries.EmployeeID,'Invalid Scoa String for NettSalaries: ProjectId = ' + CAST(IsNULL(NettSalaries.ProjectId,0) as varchar(10))   + ' ScoaItemId = ' + Cast(IsNULL(@NettPayBondScoaItemID,0) as varchar(10))   + ' FunctionId = ' + CAST(IsNULL(NettSalaries.SCOAFunctionId,0) as varchar(10))  + ' RegionId = ' + CAST(IsNULL(NettSalaries.SCOARegionId,0) AS varchar(10))  + ' DivisionId = ' + CAST(IsNULL(NettSalaries.DivisionID,0) as varchar(10)),  1,'EmployeeLevel','Payroll_TrialRunPostValidateNettSalaries',1,GetDate(),NULL,NULL,1,0   FROM (  SELECT    p.*      ,@NettPayBondProjectID ProjectId   FROM (SELECT     EmployeeID       ,CASE      WHEN TransactionTypeID = 1 THEN 'Earning'      ELSE 'Deduction'     END AS TransactionType       ,pt.Amount       ,pt.DivisionID       ,pt.ScoaRegionID       ,pt.ScoaFunctionID    FROM Payroll_TrialResults pt    WHERE TransactionTypeID IN (1, 2)    AND pt.PeriodID = @PeriodId AND TaxSavePurpose = 0    AND (@EmployeeID = 0 OR EmployeeID = @EmployeeID)    ) t   PIVOT (   SUM(Amount)   FOR TransactionType IN (Earning, Deduction)   ) p      )NettSalaries  LEFT OUTER JOIN Plan_Project pp ON pp.Project_ID = @NettPayBondProjectID    LEFT OUTER JOIN #projectItems ppi      ON ppi.ProjectID = pp.Project_ID               and ppi.SCOAItemID = @NettPayBondScoaItemID      and NettSalaries.divisionID = ppi.divisionId      AND NettSalaries.ScoaRegionID = ppi.ScoaRegionId AND NettSalaries.ScoaFunctionId = ppi.ScoaFunctionId      group by EmployeeId,     ppi.SCOAFundId ,   NettSalaries.SCOARegionId,    NettSalaries.ProjectId,   NettSalaries.SCOAFunctionId,    NettSalaries.DivisionID,   PlanProjectItem_ID  Having (SUM(ISNULL(NettSalaries.Earning,0) - ISNULL(NettSalaries.Deduction,0)) <> 0) and ISNULL(PlanProjectItem_id,0) = 0  order by EmployeeID      if (not object_id('tempdb..#Plan_ProjectItem') is null)   drop table [#Plan_ProjectItem]    end try    begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])     values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())    end catch    set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateNettSalaryJnls
-- Schema: dbo
-- ============================================
  /*   Author  : Richa M   Create date : 30/01/2023   Description : Validate Budget Strings for Nett Salary GL transactions created by Payroll_GenerateLedPaymentInstructions       */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateNettSalaryJnls] @EmployeeID int, @PeriodID int   as    begin     set nocount on;    begin try    DECLARE @SalaryControlDTItem INT  DECLARE @EmployeeNetPayBondScoaCreditID INT  DECLARE @SalaryControlProjectId INT  DECLARE @EmployeeNetPayBondProjectID INT  DECLARE @TravelControlProjectId INT    DECLARE @TravelScoaDTItem INT    DECLARE @TravelScoaCRItem INT    SELECT      @EmployeeNetPayBondProjectID = EmployeeNetPayBondProjectID,      @EmployeeNetPayBondScoaCreditID = EmployeeNetPayBondScoaCreditID,     @SalaryControlDTItem = SalarySuspenseScoaItemID,     @SalaryControlProjectId = SalaryProjectID,     @TravelControlProjectId = TravelProjectID,     @TravelScoaDTItem = TravelSuspenseScoaItemID,     @TravelScoaCRItem = TravelSuspenseScoaItemCreditID  FROM [Payroll_Municipality] WITH(NOLOCK)        IF OBJECT_ID('tempdb..#projectItems') IS NOT NULL      DROP TABLE #projectItems     Select * into #projectItems from Plan_ProjectItem where PlanProjectItem_ID in(         Select min(PlanProjectItem_Id)PlanProjectItem_Id from Plan_ProjectItem          group by ProjectId,DivisionId,ScoaItemId,ScoaFunctionId,ScoaRegionId,FinYear)    CREATE INDEX IDX_ProjectItems ON #projectItems(ScoaItemId,ProjectId,DivisionId,ScoaRegionId,ScoaFunctionId)           Insert into Payroll_TrialErrors  SELECT newid(),NULL, @PeriodId,NULL,'Invalid Scoa String for NettSalaries: ProjectId = ' + CAST(IsNULL(ProjectId,0) as varchar(10))   + ' ScoaItemId = ' + Cast(IsNULL(ScoaId,0) as varchar(10))   + ' FunctionId = ' + CAST(IsNULL(FunctionId,0) as varchar(10))  + ' RegionId = ' + CAST(IsNULL(RegionId,0) AS varchar(10))  + ' DivisionId = ' + CAST(IsNULL(DivisionId,0) as varchar(10)),   'Payroll_TrialRunPostValidateNettSalaryJnls',1,GetDate(),'System',1,0  from(   SELECT 'Debit' leg,     @SalaryControlProjectId ProjectId,@SalaryControlDTItem ScoaId,NettSalaries.divisionID DivisionId,     NettSalaries.ScoaRegionID RegionId,     NettSalaries.ScoaFunctionId FunctionId,     ppiDt.PlanProjectItem_ID ProjectItemId    FROM (     SELECT       ROW_NUMBER() OVER(ORDER BY (SELECT NULL)) AS Rownum,      SUM(ISNULL(Salaries.Earning,0) - ISNULL(Salaries.Deduction,0)) AS NettAmount,      Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     FROM (      SELECT p.*      FROM (       SELECT        CASE         WHEN pt.TransactionTypeID = 1 THEN 'Earning'         ELSE 'Deduction'        END AS TransactionType        ,pt.Amount        ,pt.DivisionID        ,pt.ScoaRegionID        ,pt.ScoaFunctionID        ,pt.ScoaFundingId        ,pt.SCOACostingID        ,pt.SCOAItemID        ,pt.ContraSCOAItemID        ,pt.SCOAProjectID       FROM Payroll_TrialResults pt        WHERE pt.TransactionTypeID IN (1, 2)        AND pt.PeriodID = @PeriodId AND TaxSavePurpose = 0        AND ContraSCOAItemID <> @TravelScoaCRItem      ) t      PIVOT (       SUM(Amount)       FOR TransactionType IN (Earning, Deduction)      ) p     ) Salaries       GROUP BY       Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     HAVING SUM(ISNULL(Salaries.Earning,0) - ISNULL(Salaries.Deduction,0)) <> 0    ) AS NettSalaries     LEFT JOIN #projectItems ppiDt ON ppiDt.ProjectID = @SalaryControlProjectId     AND ppiDt.SCOAItemID = @SalaryControlDTItem      AND NettSalaries.divisionID = ppiDt.divisionId      AND NettSalaries.ScoaRegionID = ppiDt.ScoaRegionId      AND NettSalaries.ScoaFunctionId = ppiDt.ScoaFunctionId        UNION ALL   SELECT 'Credit',     @EmployeeNetPayBondProjectID,@EmployeeNetPayBondScoaCreditID,     NettSalaries.divisionID,     NettSalaries.ScoaRegionID,     NettSalaries.ScoaFunctionId,     ppiCr.PlanProjectItem_ID    FROM (     SELECT       ROW_NUMBER() OVER(ORDER BY (SELECT NULL)) AS Rownum,      SUM(ISNULL(Salaries.Earning,0) - ISNULL(Salaries.Deduction,0)) AS NettAmount,      Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     FROM (      SELECT p.*      FROM (       SELECT        CASE         WHEN pt.TransactionTypeID = 1 THEN 'Earning'         ELSE 'Deduction'        END AS TransactionType        ,pt.Amount        ,pt.DivisionID        ,pt.ScoaRegionID        ,pt.ScoaFunctionID        ,pt.ScoaFundingId        ,pt.SCOACostingID        ,pt.SCOAItemID        ,pt.ContraSCOAItemID        ,pt.SCOAProjectID       FROM Payroll_TrialResults pt        WHERE pt.TransactionTypeID IN (1, 2)        AND pt.PeriodID = @PeriodId AND TaxSavePurpose = 0        --AND (ContraSCOAItemID = @SalaryControlCRItem OR pt.SCOAItemID = @SalaryControlDTItem)      ) t      PIVOT (       SUM(Amount)       FOR TransactionType IN (Earning, Deduction)      ) p     ) Salaries       GROUP BY       Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     HAVING SUM(ISNULL(Salaries.Earning,0) - ISNULL(Salaries.Deduction,0)) <> 0    ) AS NettSalaries     LEFT JOIN #projectItems ppiCr ON ppiCr.ProjectID = @EmployeeNetPayBondProjectID      AND ppiCr.SCOAItemID = @EmployeeNetPayBondScoaCreditID      AND NettSalaries.divisionID = ppiCr.divisionId      AND NettSalaries.ScoaRegionID = ppiCr.ScoaRegionId AND NettSalaries.ScoaFunctionId = ppiCr.ScoaFunctionId  UNION ALL  --Travel  select 'Debit Travel',     @TravelControlProjectId,@TravelScoaDTItem,     NettSalaries.divisionID,     NettSalaries.ScoaRegionID,     NettSalaries.ScoaFunctionId,     ppiDt.PlanProjectItem_ID    FROM (     SELECT       ROW_NUMBER() OVER(ORDER BY (SELECT NULL)) AS Rownum,      SUM(Salaries.Amount) AS NettAmount,      Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     FROM (      SELECT       pt.Amount       ,pt.DivisionID       ,pt.ScoaRegionID       ,pt.ScoaFunctionID       ,pt.ScoaFundingId       ,pt.SCOACostingID       ,pt.SCOAItemID       ,pt.ContraSCOAItemID       ,pt.SCOAProjectID      FROM Payroll_TrialResults pt       WHERE pt.TransactionTypeID = 1        AND pt.PeriodID = @PeriodId AND TaxSavePurpose = 0       AND ContraSCOAItemID = @TravelScoaCRItem     ) Salaries     GROUP BY       Salaries.SCOAFundingID,      Salaries.SCOARegionId,      Salaries.SCOACostingID,      Salaries.SCOAFunctionId,      Salaries.DivisionID     ) AS NettSalaries     LEFT JOIN #projectItems ppiDt ON ppiDt.ProjectID = @TravelControlProjectId      and ppiDt.SCOAItemID = @TravelScoaDTItem      and NettSalaries.divisionID = ppiDt.divisionId      AND NettSalaries.ScoaRegionID = ppiDt.ScoaRegionId AND NettSalaries.ScoaFunctionId = ppiDt.ScoaFunctionId)V1  where IsNULL(ProjectItemId,0) = 0        if (not object_id('tempdb..#Plan_ProjectItem') is null)   drop table [#Plan_ProjectItem]    end try    begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])     values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())    end catch    set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidatePositionPercentage
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Trial Run Employees where the Position Percentages and Functional Splits does not equal 100%   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]  */  create procedure [dbo].[Payroll_TrialRunPostValidatePositionPercentage] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], ( 'Employee'''+'s linked Position: (' + cast([Position_ID] as nvarchar(20)) + ') Primary & Secondary Division Percentage :(' + cast(sum([Percentage]) as nvarchar(20)) + ')'), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null       from (        select distinct [PE].[Employee_ID], [Position_ID], [CostPercentage] as [Percentage]         from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)          join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1          join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1          join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1          join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID          join [Payroll_Position] as [PP] with(nolock) on [Position_ID] = [PositionID] and [PP].[Enabled] = 1          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1          join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]          left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]          join [Payroll_JobProfileExtraDivisionFunctionCode] as [PJF] with(nolock) on [PJF].[PositionId] = [Position_ID] and [PJF].[Enabled] = 1         where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and (not ([TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 1)) and          (case           when @CycleModeID = 1 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end           when @CycleModeID = 2 then            case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end           else 0 end) = 1         )       ) as [Percentage]       group by [Employee_ID], [Position_ID]        having (sum([Percentage]) > 100)       )        end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectBudget
-- Schema: dbo
-- ============================================
-- =============================================  -- author:  <author,,Lungisani>  -- create date: <create date,,>  -- description: <description,,Validate Municipal Project Budget>  --Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year    --Payroll_TrialRunPostValidateProjectBudget 0,1184,1,1   -- =============================================  CREATE procedure [dbo].[Payroll_TrialRunPostValidateProjectBudget] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int     as    begin           begin try      declare @list table(     [ID] int identity(1,1),     [Item] nvarchar(max),     [TotalPercent]decimal(18,2)    )      Declare @FinYear nvarchar(20)      select @FinYear = KeyValue from AAAA_ConfigSettings where KeyName like 'ActiveFinYear'                   insert  into @list ([Item],  [TotalPercent])             select Item,(case when [BudgetAmount] = 0 then 0                                  when [BudgetAmount] >= [TrailAmount] then (100 - (([TrailAmount]/[BudgetAmount]) * 100))                                      when [TrailAmount] > [BudgetAmount]  then ((([BudgetAmount]/[TrailAmount]) * 100) - 100)                           end) [TotalPercent]                                from (          select ('ProjectItemID :' +cast([PI].[PlanProjectItem_ID] as nvarchar(100)) + ' - ProjectDesc :' + [PP].[ProjectDesc] + ' - ProjectName: ' + [PP].[ProjectName]) as Item, sum([TR].[amount]) as [TrailAmount], [PI].[BudgetAmount] as [BudgetAmount]          from  [Payroll_TrialResults] [TR] with(nolock)          join [Plan_ProjectItem] [PI] with(nolock) on [PI].[PlanProjectItem_ID] = [TR].[PlanProjectItemID] and [PI].[SCOAItemID] =  [TR].[SCOAItemID] and [PI].[FinYear] = @FinYear          join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [PI].[ProjectID] and [PP].[FinYear] = @FinYear          where ([TransactionTypeID] in(1,3) and ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end)) and [PeriodID] = @PeriodID)          group by [PI].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName], [PI].[BudgetAmount]          union           select (cast([contraProject].[PlanProjectItem_ID] as nvarchar(100)) + ' - ' + [PP].[ProjectDesc] + ' - ' + [PP].[ProjectName]) as Item, sum([TR].[amount]) as [TrailAmount], [contraProject].[BudgetAmount] as [BudgetAmount]          from  [Payroll_TrialResults] [TR] with(nolock)          join (select * from [Plan_ProjectItem] with(nolock)) [contraProject] on [contraProject].[PlanProjectItem_ID] = [TR].[PlanProjectItemID] and  [contraProject].[SCOAItemID] =  [TR].[ControlVoteID] and [contraProject].[FinYear] = @FinYear          join [Plan_Project] [PP] with(nolock) on [PP].[Project_ID] = [contraProject].[ProjectID] and [PP].[FinYear] = @FinYear          where ([TransactionTypeID] in(1,3) and ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end)) and [PeriodID] = @PeriodID)          group by [contraProject].[PlanProjectItem_ID],[PP].[ProjectDesc],[PP].[ProjectName], [contraProject].[BudgetAmount]) [Results]               Insert Into Payroll_EmployeeTrialPayslipErrors       ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified],[Blocking])         select          @PeriodID,          null,          Item + (case when [TotalPercent] = 0 then '' else cast([TotalPercent] as nvarchar(1000)) end) + ' ' + ( case when [TotalPercent] <= 0 then 'Employee Related Cost & Remuneration Cost budget is depleted.' when [TotalPercent] <= 10 then '% or less of Employee Related Cost & Remuneration Cost budget remains.' end),            1 ,         'Global Level',          object_name(@@procid),          1,         getdate(),          null ,         null,         0         from @list where [TotalPercent] <= 10              end try            begin catch         insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])                 values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())      end catch          set nocount off;  end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectItemDivision
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swopped SCOA Debit and Credit legs for JournalEntryOnly flag    */  create procedure [Payroll_TrialRunPostValidateProjectItemDivision] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try      declare @payrollTrialResults table (       [PeriodID] int null,     [EmployeeID] int null,     [PositionID] int null,     [TransactionTypeID] int null,     [DivisionID_DT] int null,     [DivisionID_CT] int null,     [PositionDesc] varchar(200) null      )      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]      select [DivisionId] into [#Plan_ProjectItem]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @SCOAYear)        group by [DivisionId]      /* DIVISION */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [PositionDesc])       select @PeriodID, [TP].[EmployeeID], [PE].[PositionID], [IRP5].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [POS].[PositionDesc]        from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] < 4 and [IRP5].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID] and [EP].[Cycle_ID] = @CycleID         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = isnull([TP].[DivisionId], [POS].[DivisionID])         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId]          else [POS].[DivisionID]         end)         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[PeriodID] = @PeriodID and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]        where ([TP].[EmployeeID] = (case @EmployeeID          when 0 then [TP].[EmployeeID]          else @EmployeeID         end) and [TP].[PeriodID] = @PeriodID and (case          when @CycleModeID = 1 then (case           when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1           else 0          end)          when @CycleModeID = 2 then (case           when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0           else 1          end)          else 0         end) = 1)      /* DIVISION SPLITS */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [PositionDesc])       select [TR].[PeriodID], [TR].[EmployeeID], [JPD].[PositionID], [TR].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [TR].[PositionDesc]        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)         join @payrollTrialResults as [TR] on [TR].[PositionID] = [JPD].[PositionId]         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [JPD].[DivisionID]         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = [TR].[DivisionID_CT]        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate)      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       select distinct [TR].[PeriodID], [TR].[EmployeeID], 'The Division linked to the Employee, Position (' + [TR].[PositionDesc] + ') is not setup according to the SCOA Segment string in the Budgets', 1, 'Employee Level', 'Payroll_TrialRunPostValidateProjectItemDivision', 1, getdate(), 1        from @payrollTrialResults as [TR]        where ([TR].[DivisionID_DT] is null or [TR].[DivisionID_CT] is null)         group by [TR].[PeriodID], [TR].[EmployeeID], [TR].[PositionDesc]      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectItemFunction
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swopped SCOA Debit and Credit legs for JournalEntryOnly flag    */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateProjectItemFunction] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try      declare @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality] with(nolock)),      @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock))      declare @payrollTrialResults table (       [PeriodID] int null,     [EmployeeID] int null,     [PositionID] int null,     [TransactionTypeID] int null,     [DivisionID_DT] int null,     [DivisionID_CT] int null,     [ProjectID_DT] int null,     [ProjectID_CT] int null,     [SCOAItemID_DT] int null,     [SCOAItemID_CT] int null,     [SCOAFunctionID_DT] int null,     [SCOAFunctionID_CT] int null,     [JournalEntryOnly] bit not null default(0),     [SCOAProjectID] int null,     [PositionDesc] varchar(200) null,     [ProjectID] int null      )      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]      select [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId] into [#Plan_ProjectItem]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @SCOAYear)        group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId]      /* DIVISION */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [SCOAItemID_DT], [SCOAItemID_CT], [SCOAFunctionID_DT], [SCOAFunctionID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select @PeriodID, [TP].[EmployeeID], [PE].[PositionID], [IRP5].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [PI].[SCOAItemID], [PC].[SCOAItemID], [PI].[SCOAFunctionId], [PC].[SCOAFunctionId], [GL].[JournalEntryOnly], [GL].[SCOAProjectID], [POS].[PositionDesc], [PP].[Project_ID]        from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] < 4 and [IRP5].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID] and [EP].[Cycle_ID] = @CycleID         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = isnull([TP].[DivisionId], [POS].[DivisionID]) and [PI].[ProjectID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then isnull([TP].[ProjectId], [POS].[ProjectID])          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAProjectID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then (case [PE].[EmployeeTypeID]           when 1 then isnull([TP].[ScoaItemId], [GL].[ScoaItemIDPermanentStaff])           when 2 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])           when 3 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])           when 6 then isnull([TP].[ScoaItemId], [GL].[ScoaItemIDPostRetirement])           when 7 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])          end)          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryControlID         end) and [PI].[SCOAFunctionId] = isnull([TP].[FunctionId], [POS].[FunctionID])         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId]          else [POS].[DivisionID]         end) and [PC].[ProjectID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]          else [GL].[SCOAProjectID]         end) and [PC].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then (case [PE].[EmployeeTypeID]            when 1 then [GL].[SCOAItemID]            when 2 then [GL].[SCOAItemID]            when 3 then [GL].[SCOAItemID]            when 6 then [GL].[SCOAItemID]            when 7 then [GL].[SCOAItemID]           end)          else (case           when [TP].[Amount] > 0 then [GL].[SuspenseScoaItemCreditID]           else [GL].[SuspenseScoaItemID]          end)         end) and [PC].[SCOAFunctionId] = (case          when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId]          else [POS].[FunctionID]         end)         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[PeriodID] = @PeriodID and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]              LEFT JOIN [Plan_Project] AS [PP] WITH(NOLOCK) ON [GL].[SCOAProjectID] = [PP].[Project_ID] AND [PP].[FinYear] = @SCOAYear        where ([TP].[EmployeeID] = (case @EmployeeID          when 0 then [TP].[EmployeeID]          else @EmployeeID         end) and [TP].[PeriodID] = @PeriodID and (case          when @CycleModeID = 1 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1           else 0          end)          when @CycleModeID = 2 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0           else 1          end)          else 0         end) = 1)      /* DIVISION SPLITS */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [SCOAItemID_DT], [SCOAItemID_CT], [SCOAFunctionID_DT], [SCOAFunctionID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select [TR].[PeriodID], [TR].[EmployeeID], [JPD].[PositionID], [TR].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [PI].[SCOAItemID], [PC].[SCOAItemID], [PI].[SCOAFunctionId], [PC].[SCOAFunctionId], [TR].[JournalEntryOnly], [TR].[SCOAProjectID], [TR].[PositionDesc], [TR].[ProjectID]        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)         join @payrollTrialResults as [TR] on [TR].[PositionID] = [JPD].[PositionId]         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [JPD].[DivisionID] and [PI].[ProjectID] = (case          when [TR].[TransactionTypeID] in(1, 3) then [JPD].[ProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1 then [TR].[SCOAProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = [TR].[SCOAItemID_DT] and [PI].[SCOAFunctionId] = [JPD].[SCOAFunctionId]        /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] =              (case when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1 then [TR].[DivisionID_CT] else [JPD].[DivisionID] end)               and [PC].[ProjectID] = [TR].[ProjectID_CT] and [PC].[SCOAItemID] = [TR].[SCOAItemID_CT] and [PC].[SCOAFunctionId] = (case          when [TR].[JournalEntryOnly] = 1 then [TR].[SCOAFunctionID_CT]          else [JPD].[SCOAFunctionId]         end)        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate)      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       select distinct [TR].[PeriodID], [TR].[EmployeeID], 'The Function linked to the Employee, Position (' + [TR].[PositionDesc] + ') is not setup according to the SCOA Segment string in the Budgets', 1, 'Employee Level', 'Payroll_TrialRunPostValidateProjectItemFunction', 1, getdate(), 1        from @payrollTrialResults as [TR]        where [TR].[ProjectID] IS NOT NULL AND ([TR].[SCOAFunctionID_DT] is null or [TR].[SCOAFunctionID_CT] is null)         group by [TR].[PeriodID], [TR].[EmployeeID], [TR].[PositionDesc]      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectItemProject
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swopped SCOA Debit and Credit legs for JournalEntryOnly flag    */  CREATE procedure [Payroll_TrialRunPostValidateProjectItemProject] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try      declare @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality] with(nolock))      declare @payrollTrialResults table (       [PeriodID] int null,     [EmployeeID] int null,     [PositionID] int null,     [TransactionTypeID] int null,     [DivisionID_DT] int null,     [DivisionID_CT] int null,     [ProjectID_DT] int null,     [ProjectID_CT] int null,     [JournalEntryOnly] bit not null default(0),     [SCOAProjectID] int null,     [PositionDesc] varchar(200) null,     [ProjectID] int null    )      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]      select [DivisionId], [ProjectID] into [#Plan_ProjectItem]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @SCOAYear)        group by [DivisionId], [ProjectID]      /* DIVISION */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select @PeriodID, [TP].[EmployeeID], [PE].[PositionID], [IRP5].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [GL].[JournalEntryOnly], [GL].[SCOAProjectID], [POS].[PositionDesc], [PP].[Project_ID]        from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] < 4 and [IRP5].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID] and [EP].[Cycle_ID] = @CycleID         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = isnull([TP].[DivisionId], [POS].[DivisionID]) and [PI].[ProjectID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then isnull([TP].[ProjectId], [POS].[ProjectID])          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID         end)         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId]          else [POS].[DivisionID]         end) and [PC].[ProjectID] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]          else [GL].[SCOAProjectID]         end)         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[PeriodID] = @PeriodID and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]              LEFT JOIN [Plan_Project] AS [PP] WITH(NOLOCK) ON [GL].[SCOAProjectID] = [PP].[Project_ID] AND [PP].[FinYear] = @SCOAYear        where ([TP].[EmployeeID] = (case @EmployeeID          when 0 then [TP].[EmployeeID]          else @EmployeeID         end) and [TP].[PeriodID] = @PeriodID and (case          when @CycleModeID = 1 then (case           when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1           else 0          end)          when @CycleModeID = 2 then (case           when isnull([ACPD].[CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0           else 1          end)          else 0         end) = 1)      /* DIVISION SPLITS */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select [TR].[PeriodID], [TR].[EmployeeID], [JPD].[PositionID], [TR].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [TR].[JournalEntryOnly], [TR].[SCOAProjectID], [TR].[PositionDesc], TR.[ProjectID]        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)         join @payrollTrialResults as [TR] on [TR].[PositionID] = [JPD].[PositionId]         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [JPD].[DivisionID] and [PI].[ProjectID] = (case          when [TR].[TransactionTypeID] in(1, 3) then [JPD].[ProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1 then [TR].[SCOAProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 0 then @SalaryProjectID         end)         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = [TR].[DivisionID_CT] and [PC].[ProjectID] = [TR].[ProjectID_CT]        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate)      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       select distinct [TR].[PeriodID], [TR].[EmployeeID], 'The Project linked to the Employee, Position (' + [TR].[PositionDesc] + ') is not setup according to the SCOA Segment string in the Budgets', 1, 'Employee Level', 'Payroll_TrialRunPostValidateProjectItemProject', 1, getdate(), 1        from @payrollTrialResults as [TR]        where [TR].ProjectID IS NOT NULL AND ([TR].[ProjectID_DT] is null or [TR].[ProjectID_CT] is null)         group by [TR].[PeriodID], [TR].[EmployeeID], [TR].[PositionDesc]      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectItemRegion
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swopped SCOA Debit and Credit legs for JournalEntryOnly flag    */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateProjectItemRegion] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try      declare @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality] with(nolock)),      @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock))      declare @payrollTrialResults table (       [PeriodID] int null,     [EmployeeID] int null,     [PositionID] int null,     [TransactionTypeID] int null,     [DivisionID_DT] int null,     [DivisionID_CT] int null,     [ProjectID_DT] int null,     [ProjectID_CT] int null,     [SCOAItemID_DT] int null,     [SCOAItemID_CT] int null,     [SCOAFunctionID_DT] int null,     [SCOAFunctionID_CT] int null,     [SCOARegionID_DT] int null,     [SCOARegionID_CT] int null,     [JournalEntryOnly] bit not null default(0),     [SCOAProjectID] int null,     [PositionDesc] varchar(200) null,     [ProjectID] int null      )      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]      select [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId] into [#Plan_ProjectItem]       from [Plan_ProjectItem] with(nolock)       where ([FinYear] = @SCOAYear)        group by [DivisionId], [ProjectID], [SCOAItemID], [SCOAFunctionId], [SCOARegionId]      /* DIVISION */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [SCOAItemID_DT], [SCOAItemID_CT], [SCOAFunctionID_DT], [SCOAFunctionID_CT], [SCOARegionID_DT], [SCOARegionID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select @PeriodID, [TP].[EmployeeID], [PE].[PositionID], [IRP5].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [PI].[SCOAItemID], [PC].[SCOAItemID], [PI].[SCOAFunctionId], [PC].[SCOAFunctionId], [PI].[SCOARegionId], [PC].[SCOARegionId], [GL].[JournalEntryOnly], [GL].[SCOAProjectID], [POS].[PositionDesc], [PP].[Project_ID]        from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[Enabled] = 1 and [GL].[FinYear] = @SCOAYear         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] < 4 and [IRP5].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID] and [EP].[Cycle_ID] = @CycleID         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = isnull([TP].[DivisionId], [POS].[DivisionID]) and [PI].[ProjectID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then isnull([TP].[ProjectId], [POS].[ProjectID])          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAProjectID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then (case [PE].[EmployeeTypeID]           when 1 then isnull([TP].[ScoaItemId], [GL].[ScoaItemIDPermanentStaff])           when 2 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])           when 3 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])           when 6 then isnull([TP].[ScoaItemId], [GL].[ScoaItemIDPostRetirement])           when 7 then isnull([TP].[ScoaItemId], [ST].[GLScoaItem])          end)          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryControlID         end) and [PI].[SCOAFunctionId] = isnull([TP].[FunctionId], [POS].[FunctionID]) and [PI].[SCOARegionId] = isnull([TP].[RegionId], [POS].[RegionID])         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId]          else [POS].[DivisionID]         end) and [PC].[ProjectID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]          else [GL].[SCOAProjectID]         end) and [PC].[SCOAItemID] = (case          when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then (case [PE].[EmployeeTypeID]            when 1 then [GL].[SCOAItemID]            when 2 then [GL].[SCOAItemID]            when 3 then [GL].[SCOAItemID]            when 6 then [GL].[SCOAItemID]            when 7 then [GL].[SCOAItemID]           end)          else (case           when [TP].[Amount] > 0 then [GL].[SuspenseScoaItemCreditID]           else [GL].[SuspenseScoaItemID]          end)         end) and [PC].[SCOAFunctionId] = (case          when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId]          else [POS].[FunctionID]         end) and [PC].[SCOARegionId] = (case          when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId]          else [POS].[RegionID]         end)         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[PeriodID] = @PeriodID and [ACPD].[SalaryHeadID] = [SH].[SalaryHead_ID]              LEFT JOIN [Plan_Project] AS [PP] WITH(NOLOCK) ON [GL].[SCOAProjectID] = [PP].[Project_ID] AND [PP].[FinYear] = @SCOAYear        where ([TP].[EmployeeID] = (case @EmployeeID          when 0 then [TP].[EmployeeID]          else @EmployeeID         end) and [TP].[PeriodID] = @PeriodID and (case          when @CycleModeID = 1 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1           else 0          end)          when @CycleModeID = 2 then (case           when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0           else 1          end)          else 0         end) = 1)      /* DIVISION SPLITS */    insert into @payrollTrialResults([PeriodID], [EmployeeID], [PositionID], [TransactionTypeID], [DivisionID_DT], [DivisionID_CT], [ProjectID_DT], [ProjectID_CT], [SCOAItemID_DT], [SCOAItemID_CT], [SCOAFunctionID_DT], [SCOAFunctionID_CT], [SCOARegionID_DT], [SCOARegionID_CT], [JournalEntryOnly], [SCOAProjectID], [PositionDesc], [ProjectID])       select [TR].[PeriodID], [TR].[EmployeeID], [JPD].[PositionID], [TR].[TransactionTypeID], [PI].[DivisionId], [PC].[DivisionId], [PI].[ProjectID], [PC].[ProjectID], [PI].[SCOAItemID], [PC].[SCOAItemID], [PI].[SCOAFunctionId], [PC].[SCOAFunctionId], [PI].[SCOARegionId], [PC].[SCOARegionId], [TR].[JournalEntryOnly], [TR].[SCOAProjectID], [TR].[PositionDesc], [TR].[ProjectID]        from [Payroll_JobProfileExtraDivisionFunctionCode] as [JPD] with(nolock)         join @payrollTrialResults as [TR] on [TR].[PositionID] = [JPD].[PositionId]         /* DEBIT ITEM */       left outer join [#Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionId] = [JPD].[DivisionID] and [PI].[ProjectID] = (case          when [TR].[TransactionTypeID] in(1, 3) then [JPD].[ProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 1 then [TR].[SCOAProjectID]          when [TR].[TransactionTypeID] = 2 and [TR].[JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = [TR].[SCOAItemID_DT] and [PI].[SCOAFunctionId] = [JPD].[SCOAFunctionId] and [PI].[SCOARegionId] = [JPD].[SCOARegionId]         /* CREDIT ITEM */                      left outer join [#Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionId] = ( case when [TR].[TransactionTypeID] = 1 and [TR] .[JournalEntryOnly] = 1 then [TR].[DivisionID_CT] else [JPD].[DivisionID] end)               and [PC].[ProjectID] = [TR].[ProjectID_CT] and [PC].[SCOAItemID] = [TR].[SCOAItemID_CT] and [PC].[SCOAFunctionId] = (case          when [TR].[JournalEntryOnly] = 1 then [TR].[SCOAFunctionID_CT]          else [JPD].[SCOAFunctionId]         end) and [PC].[SCOARegionId] = (case          when [TR].[JournalEntryOnly] = 1 then [TR].[SCOAFunctionID_CT]          else [JPD].[SCOARegionId]         end)        where ([JPD].[Enabled] = 1 and [JPD].[StartDate] <= @EndDate and [JPD].[EndDate] >= @StartDate)      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       select distinct [TR].[PeriodID], [TR].[EmployeeID], 'The Region linked to the Employee, Position (' + [TR].[PositionDesc] + ') is not setup according to the SCOA Segment string in the Budgets', 1, 'Employee Level', 'Payroll_TrialRunPostValidateProjectItemRegion', 1, getdate(), 1        from @payrollTrialResults as [TR]        where [TR].[ProjectID] IS NOT NULL AND ([TR].[SCOARegionID_DT] is null or [TR].[SCOARegionID_CT] is null)         group by [TR].[PeriodID], [TR].[EmployeeID], [TR].[PositionDesc]      if (not object_id('tempdb..#Plan_ProjectItem') is null)       drop table [#Plan_ProjectItem]        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateProjectItemSCOAItem
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 14/03/2017   Description : Execute Writing to Trial Results   Update date : 20/04/2017 - update the SCOA 7 segments from various sources only if there is no linked project plan item   Update date : 22/04/2017 - updated the Financial Year to store the value as 2016/2017   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 03/07/2017 - Updated Parameters & IRP5Code mappings & Updated the joins to the correct mappings   Update date : 24/10/2017 - Updated division costing splits [Modified By: Lungisani khumalo]   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - Ferdi Botha   Update date : 28/11/2017 - Updated Fringe Benifits to exclude the SCOA Item ID binding to projects - Ferdi Botha   Update date : 2017/12/06 - Updated the Tax Year in Payroll_TrialResults   Update date : 2017/12/12 - Updated the TaxSavePurpose in Payroll_TrialResults   Update date : 2018/01/11 - Added Contra Project Items both normal Transactions and on divisional cost splitting   Update date : 2018/02/01 - Changes to CR TP 65234   Update date : 2018/02/14 - TP 74256   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year   Modified    :   22/07/2019 - Ferdi Botha => Swopped SCOA Debit and Credit legs for JournalEntryOnly flag   Modified :   2024/01/30 - Richa M = Change SP to be inline with fundId changes (WI106438)    */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateProjectItemSCOAItem] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try         insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       Select PeriodId,EmployeeID,'Missing Debit Budget String - ( ' + SalaryTitle + ' )',1,'Employee Level', 'Payroll_TrialRunPostValidateProjectItemSCOAItem', 1, getdate(), 1 from Payroll_TrialResults where PeriodID = @PeriodID and TransactionTypeID <> 4 and isnull(PlanProjectItemID,0)=0     union ALL        Select PeriodId,EmployeeID,'Missing Credit Budget String - ( ' + SalaryTitle + ' )',1,'Employee Level', 'Payroll_TrialRunPostValidateProjectItemSCOAItem', 1, getdate(), 1 from Payroll_TrialResults where PeriodID = @PeriodID and TransactionTypeID <> 4 and isnull(ContraPlanProjectItemID,0)=0      Delete from Payroll_MissingStrings where isnull(PlanprojectItemId,0) = 0 and PeriodId = @PeriodID      Insert into Payroll_missingStrings      select @PeriodID,getdate(),131,SCOAItemID,ProjectId,DivisionID,SCOAFunctionID,SCOAFundingID,SCOARegionID,1,EmployeeID,SalaryHeadID,PlanProjectItemID from Payroll_TrialResults where  PeriodID = @PeriodID and TransactionTypeID <> 4 and isnull(PlanProjectItemID,0)=0     union all    select @PeriodID,getdate(),131,ContraSCOAItemID,ContraProjectId,ContraDivisionId,ContraSCOAFunctionID,ContraSCOAFundingID,ContraSCOARegionID,0,EmployeeID,SalaryHeadID,ContraPlanProjectItemID from Payroll_TrialResults where PeriodID = @PeriodID and TransactionTypeID <> 4 and isnull(ContraPlanProjectItemID,0)=0          end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSalaryControlSCOAItem
-- Schema: dbo
-- ============================================
  -- =============================================  -- author:  Lukasz Rakowski  -- create date: 29/07/2019  -- description: #81335 MOCRollover: Validation SCOA expenditure item setup on Salary Transaction active in Ledger  -- =============================================    CREATE procedure [dbo].[Payroll_TrialRunPostValidateSalaryControlSCOAItem] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @StartDate datetime, @EndDate datetime, @Month int, @SCOAYear nvarchar(10), @TaxYear nvarchar(10), @PaymentDate datetime  as    begin     set nocount on;     begin try    DECLARE @voteStasus_active INT = 1    DECLARE @voteStasus_inactive INT = 2      declare @SCOAMonth tinyint = (select cast([KeyValue] as tinyint) from [AAAA_ConfigSettings] where ([KeyName] = 'FinYearStartMonth')),      @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality]),      @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality])      declare @Payroll_TrialResults table (       [TrialResult_ID] [int] identity(1, 1) not null,     [PayrollDefinationID] [int] null,     [CycleID] [int] not null,     [PeriodID] [int] not null,     [EmployeeID] [int] not null,     [DepartmentID] [int] not null,     [DivisionID] [int] not null,     [IRP5CodeID] [int] not null,     [SalaryHeadID] [int] not null,     [VendorID] [int] null,     [ControlVoteID] [int] null,     [TransactionTypeID] [int] not null,     [PaymentTypeID] [int] not null,     [Processed] [bit] not null default(0),     [EmpRecCount] [int] not null,     [IRP5Code] [nvarchar](50) not null,     [SalaryTitle] [nvarchar](256) not null,     [TaxPeriod] [tinyint] not null,     [TaxYear] [int] not null,     [TaxSavePurpose] [bit] not null default(0),     [PaymentDate] [datetime] not null,     [FinancePeriod] [tinyint] not null,     [FinanceYear] [nvarchar](10) not null,     [DepartmentDesc] [nvarchar](200) not null,     [DivisionDesc] [nvarchar](200) not null,     [PlanProjectItemID] [int] null,     [SCOAProjectID] [int] null,     [SCOAItemID] [int] null,     [SCOACostingID] [int] null,     [SCOAFunctionID] [int] null,     [SCOAFundingID] [int] null,     [SCOARegionID] [int] null,     [ContraPlanProjectItemID] [int] null,     [ContraSCOAProjectID] [int] null,     [ContraSCOAItemID] [int] null,     [ContraSCOACostingID] [int] null,     [ContraSCOAFunctionID] [int] null,     [ContraSCOAFundingID] [int] null,     [ContraSCOARegionID] [int] null,     [Amount] [decimal](18, 2) not null,     [Calculation] [ntext] null,     [Enabled] [bit] null default(1),     [SalaryHeadDesc] [nvarchar](256) not null      )      insert into @Payroll_TrialResults([PayrollDefinationID], [CycleID], [PeriodID], [EmployeeID], [DepartmentID], [DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID], [TransactionTypeID], [PaymentTypeID], [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [TaxSavePurpose], [PaymentDate], [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc], [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID], [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [ContraPlanProjectItemID], [ContraSCOAProjectID], [ContraSCOAItemID], [ContraSCOACostingID], [ContraSCOAFunctionID], [ContraSCOAFundingID], [ContraSCOARegionID], [Amount], [SalaryHeadDesc])       select       [PayrollDefinationID],       [PE].[CycleID],       @PeriodID,       [PE].[Employee_ID],       [Department_ID],       [Division_ID],       [IRP5Code_ID],       [SalaryHead_ID],       (case when [IRP5].[TransactionTypeID] = 1 or [IRP5].[TransactionTypeID] = 4 then null else [TP].[VendorID] end),      (case [PE].[EmployeeTypeID]       when 1 then [GL].[SuspenseScoaItemID]       when 2 then [ST].[ControlScoa]       when 3 then [ST].[ControlScoa]       when 6 then [GL].[SuspenseScoaItemID]       when 7 then [ST].[ControlScoa]      end),       [IRP5].[TransactionTypeID],       [PaymentTypeID],       0,      row_number() over (partition by [PE].[Employee_ID] order by [PE].[Employee_ID], [IRP5].[TransactionTypeID], [SalaryHead_ID]),      [IRP5].[IRP5Code],       (case        when [SH].[SalaryHeadTitle] = [SalaryHeadTitleAddendum] and len([ReferenceNo]) > 0 then [SH].[SalaryHeadTitle] + ' (' + [ReferenceNo] + ')'       when [SH].[SalaryHeadTitle] = [SalaryHeadTitleAddendum] and len([ReferenceNo]) = 0 then [SH].[SalaryHeadTitle]       else [SH].[SalaryHeadTitle] + isnull(' (' + [SalaryHeadTitleAddendum] + ')', '')      end),       cast([Month] as tinyint),       right(@TaxYear, 4),       [TP].[TaxSavePurpose],       @PaymentDate,       @SCOAMonth,       @SCOAYear,      [DepartmentDesc],       [DivisionDesc],       [PI].[PlanProjectItem_ID],       [PPI].[ScoaProjectID],       (case        when [IRP5].[TransactionTypeID] in(1, 3) then        case [PE].[EmployeeTypeID]         when 1 then [GL].[ScoaItemIDPermanentStaff]         when 2 then [ST].[GLScoaItem]         when 3 then [ST].[GLScoaItem]         when 6 then [GL].[ScoaItemIDPostRetirement]         when 7 then [ST].[GLScoaItem]        end       when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1) then        case [PE].[EmployeeTypeID]         when 1 then [GL].[SCOAItemID]         when 2 then [ST].[GLScoaItem]         when 3 then [ST].[GLScoaItem]         when 6 then [GL].[SCOAItemID]         when 7 then [ST].[GLScoaItem]        end       when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0) then @SalaryControlID      end),       [PI].[SCOACostingID],       [PI].[SCOAFunctionId],       [PI].[SCOAFundId],       [PI].[SCOARegionId],      [PC].[PlanProjectItem_ID],       [PPC].[ScoaProjectID],       [PC].[SCOAItemID],       [PC].[SCOACostingID],       [PC].[SCOAFunctionId],       [PC].[SCOAFundId],       [PC].[SCOARegionId],       [TP].[Amount],      [SH].SalaryHeadTitle      from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TP].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Const_Department] as [DEP] with(nolock) on [Department_ID] = [POS].[DepartmentID] and [DEP].[Enabled] = 1         join [Const_Division] as [DIV] with(nolock) on [Division_ID] = [POS].[DivisionID] and [DIV].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionID] = [POS].[DivisionID] and [PI].[ProjectID] = (          case           when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]           when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]           when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = (          case when [IRP5].[TransactionTypeID] in(1, 3) then           case [PE].[EmployeeTypeID]            when 1 then [GL].[ScoaItemIDPermanentStaff]            when 2 then [ST].[GLScoaItem]            when 3 then [ST].[GLScoaItem]            when 6 then [GL].[ScoaItemIDPostRetirement]            when 7 then [ST].[GLScoaItem]           end            when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemID]            when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryControlID         end) and [PI].[SCOAFunctionId] = [POS].[FunctionID] and [PI].[SCOARegionId] = [POS].[RegionID]         left outer join [Plan_Project] as [PPI] with(nolock) on [PPI].[Project_ID] = [PI].[ProjectID]                        left outer join [Plan_ProjectItem] as [PC] with(nolock) on [PC].[DivisionID] = [POS].[DivisionID] and [PC].[ProjectID] = [GL].[SCOAProjectID] and [PC].[SCOAItemID] = (          case [PE].[EmployeeTypeID]           when 1 then [GL].[SuspenseScoaItemID]           when 2 then [ST].[ControlScoa]           when 3 then [ST].[ControlScoa]           when 6 then [GL].[SuspenseScoaItemID]           when 7 then [ST].[ControlScoa]          end) and [PC].[SCOAFunctionId] = [POS].[FunctionID] and [PC].[SCOARegionId] = [POS].[RegionID]         left outer join [Plan_Project] as [PPC] with(nolock) on [PPC].[Project_ID] = [PC].[ProjectID]         left outer join [Led_Vote] as [LV] with(nolock) on [LV].[SCOAItemID] = [PI].[SCOAItemID] or [LV].[SCOAItemID] = [PC].[SCOAItemID]             left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]       where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and        (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0 end) = 1 and [TaxSavePurpose] = 0 and [IRP5].[TransactionTypeID] <> 4 and [LV].[FinYear] = @SCOAYear       )        order by [PE].[Employee_ID], [TransactionTypeID], [SalaryHead_ID]      /* CREATE DIVISIONAL COSTS SPLITTING */    declare @DivisionEmployeeCostsSplitting table (       [ID] [int] identity(1,1) not null,     [TrialResult_ID] [int] not null,     [EmployeeID] [int] not null,     [PositionID] [int] not null,     [DepartmentID] [int] not null,     [DivisionID] [int] not null,     [PlanProjectItemID] [int] null,     [SCOAProjectID] [int] null,     [SCOAItemID] [int] null,     [SCOACostingID] [int] null,     [SCOAFunctionID] [int] null,     [SCOAFundingID] [int] null,     [SCOARegionID] [int] null,     [ContraPlanProjectItemID] [int] null,     [ContraSCOAProjectID] [int] null,     [ContraSCOAItemID] [int] null,     [ContraSCOACostingID] [int] null,     [ContraSCOAFunctionID] [int] null,     [ContraSCOAFundingID] [int] null,     [ContraSCOARegionID] [int] null,     [Amount] [decimal](18,2) null,     [AmountOriginal] [decimal](18,2) null,     [Perc] [decimal](18,2) null           )      declare @DivisionCostsSplitting table (       [ID] [int] identity(1,1) not null,     [TotalPerc] [decimal](18,2) null,     [PositionID] [int] not null      )      insert into @DivisionCostsSplitting([TotalPerc], [PositionID])       select sum([CostPercentage]), [PositionId]        from [Payroll_JobProfileExtraDivisionFunctionCode]        where ([Enabled] = 1 and [PositionId] is not null)         group by [PositionId]      insert into @DivisionEmployeeCostsSplitting([TrialResult_ID], [EmployeeID], [PositionID], [DepartmentID], [DivisionID], [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID], [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [ContraPlanProjectItemID], [ContraSCOAProjectID], [ContraSCOAItemID], [ContraSCOACostingID], [ContraSCOAFunctionID], [ContraSCOAFundingID], [ContraSCOARegionID], [Amount], [AmountOriginal], [Perc])       select [TrialResult_ID], [TR].[EmployeeID], [POS].[Position_ID], [POS].[DepartmentID], [POS].[DivisionID],        [TR].[PlanProjectItemID], [TR].[SCOAProjectID], [TR].[SCOAItemID], [TR].[SCOACostingID], [TR].[SCOAFunctionID], [TR].[SCOAFundingID], [TR].[SCOARegionID],        [TR].[ContraPlanProjectItemID], [TR].[ContraSCOAProjectID], [TR].[ContraSCOAItemID], [TR].[ContraSCOACostingID], [TR].[ContraSCOAFunctionID], [TR].[ContraSCOAFundingID], [TR].[ContraSCOARegionID],            ([TR].[Amount] * ((100 - (isnull([DS].[Perc], 0))) / 100)), [TR].[Amount], ((100 - (isnull([DS].[Perc], 0))) / 100)        from @Payroll_TrialResults as [TR]         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TR].[EmployeeID] and [PE].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join (          select [DivisionID], sum([CostPercentage]) as [Perc]           from [Payroll_JobProfileExtraDivisionFunctionCode] as [JD] with(nolock)           where ([Enabled] = 1)            group by [DivisionID]         ) as [DS] on [DS].[DivisionID] = [POS].[DivisionID] and [PositionId] = [Position_ID]        where ([PeriodID] = @PeriodID and [TaxSavePurpose] = 0)       union all       select [TrialResult_ID], [TR].[EmployeeID], [POS].[Position_ID], [POS].[DepartmentID], [POS].[DivisionID],        [PI].[PlanProjectItem_ID], [PP].[ScoaProjectID], [PI].[SCOAItemID], [PI].[SCOACostingID], [PI].[SCOAFunctionID], [PI].[SCOAFundId], [PI].[SCOARegionID],        [TR].[ContraPlanProjectItemID], [TR].[ContraSCOAProjectID], [TR].[ContraSCOAItemID], [TR].[ContraSCOACostingID], [TR].[ContraSCOAFunctionID], [TR].[ContraSCOAFundingID], [TR].[ContraSCOARegionID],            ([TR].[Amount] * ([CostPercentage] / 100)), [TR].[Amount], [CostPercentage]        from @Payroll_TrialResults as [TR]         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TR].[PayrollDefinationID] and [EPD].[EmployeeID] = [TR].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TR].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TR].[EmployeeID] and [ST].[SalaryHeadId] = [SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[Enabled] = 1         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Position] as [POS] with(nolock) on [Position_ID] = [PE].[PositionID] and [POS].[Enabled] = 1         join [Payroll_JobProfileExtraDivisionFunctionCode] as [JD] on [JD].[DivisionID] = [POS].[DivisionID] and [JD].[PositionId] = [Position_ID] and [JD].[Enabled] = 1         left outer join [Plan_ProjectItem] as [PI] with(nolock) on [PI].[DivisionID] = [POS].[DivisionID] and [PI].[ProjectID] = (          case           when [IRP5].[TransactionTypeID] in(1, 3) then [JD].[ProjectID]           when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]           when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryProjectID         end) and [PI].[SCOAItemID] = (          case when [IRP5].[TransactionTypeID] in(1, 3) then           case [PE].[EmployeeTypeID]            when 1 then [GL].[ScoaItemIDPermanentStaff]            when 2 then [ST].[GLScoaItem]            when 3 then [ST].[GLScoaItem]            when 6 then [GL].[ScoaItemIDPostRetirement]            when 7 then [ST].[GLScoaItem]           end            when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 then [GL].[SCOAItemID]            when [IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 then @SalaryControlID         end) and [PI].[SCOAFunctionId] = [JD].[SCOAFunctionId] and [PI].[SCOARegionId] = [JD].[SCOARegionId]         left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [PI].[ProjectID]         left outer join [Led_Vote] as [LV] with(nolock) on [LV].[SCOAItemID] = [PI].[SCOAItemID]         where ([PeriodID] = @PeriodID and [TaxSavePurpose] = 0)       /* DISABLE ALL EXISTING EMPLOYEE COST SPLITTING RECORDS */    update @Payroll_TrialResults set [Enabled] = 0 where ([EmployeeID] in(select [EmployeeID] from @DivisionEmployeeCostsSplitting))      insert into @Payroll_TrialResults([CycleID], [PeriodID], [EmployeeID], [DepartmentID], [DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID], [TransactionTypeID], [PaymentTypeID], [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [PaymentDate], [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc], [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID], [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [ContraPlanProjectItemID], [ContraSCOAProjectID], [ContraSCOAItemID], [ContraSCOACostingID], [ContraSCOAFunctionID], [ContraSCOAFundingID], [ContraSCOARegionID], [Amount], [SalaryHeadDesc])       select [CycleID], [PeriodID], [ECS].[EmployeeID], [ECS].[DepartmentID], [ECS].[DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID], [TransactionTypeID], [PaymentTypeID], [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [PaymentDate], [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc], [ECS].[PlanProjectItemID], [ECS].[SCOAProjectID], [ETR].[SCOAItemID], [ECS].[SCOACostingID], [ECS].[SCOAFunctionID], [ECS].[SCOAFundingID], [ECS].[SCOARegionID], [ECS].[ContraPlanProjectItemID], [ECS].[ContraSCOAProjectID], [ECS].[ContraSCOAItemID], [ECS].[ContraSCOACostingID], [ECS].[ContraSCOAFunctionID], [ECS].[ContraSCOAFundingID], [ECS].[ContraSCOARegionID], [ECS].[Amount], [ETR].[SalaryHeadDesc]        from @Payroll_TrialResults as [ETR]         join @DivisionEmployeeCostsSplitting [ECS] on [ECS].[TrialResult_ID] = [ETR].[TrialResult_ID]      insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])       select distinct [PeriodID], [TR].[EmployeeID],        [Reason], 1, 'Employee Level', object_name(@@procid), 1, getdate(), 1        from @Payroll_TrialResults as [TR]         join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [TR].[EmployeeID]         join [Payroll_Position] as [POS] with(nolock) on [POS].[Position_ID] = [PE].[PositionID]         left outer join [Const_SCOA_Structure] as [CSS] with(nolock) on [CSS].[ScoaID] = [TR].[SCOAItemID]  or [CSS].[ScoaID] = [TR].[ContraSCOAItemID]         left outer join [Led_Vote] as [LV] with(nolock) on [LV].[SCOAItemID] = [CSS].[ScoaID]        Cross Apply (        Select Reason =       (case        when not [TR].[SCOAItemID] is null and not [CSS].[ScoaID] is null and [LV].[SCOAItemID] is null          then 'Salary Item ' + [CSS].[ScoaCode] + ' do not exist in the Ledger'        when [VoteStatusID] in (0, @voteStasus_inactive)           then 'Salary Transaction for ' + [TR].[SalaryHeadDesc] + ' is linked to inactive SCOA Item '+ [CSS].[ScoaCode]        WHEN [VoteStatusID] = @voteStasus_active AND EXISTS (         SELECT TOP 1 1          FROM (          SELECT VoteID, [3] AS Led_CSB_Mod, [4] AS Led_CRD_Mod, [5] AS Led_FIN_Mod, [7] AS Payroll_Mod          FROM (SELECT * FROM Led_VoteSection AS LVS WHERE LVS.VoteID = LV.Vote_ID) AS LVS          PIVOT (max(VoteSectionID) FOR VoteSectionID IN ([3], [4], [5], [7])) AS piv         ) AS EnabledSections         WHERE Led_CSB_Mod IS NULL OR Led_CRD_Mod IS NULL OR Led_FIN_Mod IS NULL OR Payroll_Mod IS NULL        )         THEN 'Salary Transaction for ' + [TR].[SalaryHeadDesc] + ' linked to SCOA Item ' + [CSS].[ScoaCode] + ' that is not manage for the applicable modules'       end)      ) ReasonQuery        where ([TR].[Enabled] = 1 and [TransactionTypeID] <> 4 and [FinYear] = @SCOAYear and Reason not like '')        group by [PeriodID], [TR].[EmployeeID], [PositionDesc], [CSS].[ScoaCode],[TR].[SCOAItemID],[CSS].[ScoaID],[LV].[SCOAItemID],[VoteStatusID], Reason        end try     begin catch      insert into [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values('System', @PeriodID, '#' + cast(error_line() as nvarchar) + ' - ' + error_message(), error_procedure(), 1, getdate())     end catch     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSalaryHeadPercentage
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Trial Run Employees where the Total Salary Head Percentages does not equal 100%   Update date : 19/04/2017 - changed the grouping to include the TransactionTypeID column   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   23/05/2018 - Updated the groupings to return exact duplicate Salary Heads  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateSalaryHeadPercentage] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [TP].[EmployeeID], 'Salary Head Assigned <> 100% : ' + [SalaryHeadTitleAddendum] + ' ( ' + cast(sum([Percentage])as nvarchar(20)) + '% )', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)        join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1        join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1        join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID        join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1        join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]        left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]       where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and (not ([TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 1)) and        (case         when @CycleModeID = 1 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end         when @CycleModeID = 2 then          case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end         else 0 end) = 1       )       group by [TP].[EmployeeID], [SalaryHeadTitleAddendum], [SalaryHeadTitleAddendum] + '|' + [ReferenceNo], [TransactionTypeID], [Amount]        having (sum([Percentage]) > 0 and avg([Percentage]) <> 100)      )          end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSalaryTransactionSetup
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Ilya Skavronskiy  -- Create date: 2020-06-04  -- Description: Validates that the project for the current Fin Year is set on Salary Transaction -> General Ledger tab  --  -- 2021/01/25 Richa M: Validation should not be done for Fringe Benefits  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_TrialRunPostValidateSalaryTransactionSetup]   @EmployeeID INT,    @PeriodID INT,   @CycleID INT,   @CycleModeID INT,   @SCOAYear nvarchar(10)  AS  BEGIN   SET NOCOUNT ON;     BEGIN TRY    INSERT INTO [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [Blocking])    SELECT      TP.PeriodID,     TP.EmployeeID,     'Salary Transaction for '+ SH.SalaryHeadTitle + ' is not setup correctly',     1,     'Employee Level',      'Payroll_TrialRunPostValidateSalaryTransactionSetup',      1,      getdate(),      1    FROM [Payroll_EmployeeTrialPayslip] AS [TP] WITH(NOLOCK)    JOIN [Payroll_EmployeePayrollDefinition] AS [EPD] WITH(NOLOCK) ON [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] AND [EPD].[EmployeeID] = [TP].[EmployeeID] AND [EPD].[Enabled] = 1    JOIN [Payroll_SalaryHead] AS [SH] WITH(NOLOCK) ON [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] AND [SH].[Enabled] = 1    JOIN [Payroll_IRP5Code] AS [IRP5] WITH(NOLOCK) ON [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID]    JOIN [Payroll_GLItems] AS [GL] WITH(NOLOCK) ON [GL].[SalaryHeadID] = [SalaryHead_ID] AND [GL].[FinYear] = @SCOAYear    LEFT JOIN Plan_Project AS PP WITH(NOLOCK) ON [GL].SCOAProjectID = PP.Project_ID AND [PP].FinYear = @SCOAYear    WHERE [TP].[EmployeeID] = (CASE @EmployeeID WHEN 0 THEN [TP].[EmployeeID] ELSE @EmployeeID END)     AND [TP].[PeriodID] = @PeriodID      AND [TaxSavePurpose] = 0      AND [PP].[Project_ID] IS NULL     AND [IRP5].[TransactionTypeID] <> 4   END TRY     BEGIN CATCH    INSERT INTO [Payroll_TrialErrors]([ValidationType], [PeriodID], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])    VALUES('System', @PeriodID, '#' + CAST(ERROR_LINE() AS NVARCHAR) + ' - ' + ERROR_MESSAGE(), ERROR_PROCEDURE(), 1, GETDATE())   END CATCH     SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSCOAFunction
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no SCOA Function ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no SCOA Function ID   Modified    :   Added validation for terminated employee  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateSCOAFunction] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [FunctionID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid SCOA Function assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null         from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]      left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]     where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        ([Position_ID] is null or [FunctionID] is null) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))    )       declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and P.[FunctionID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid SCOA Function assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or P.[FunctionID] is null) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate                  end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSCOAFund
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no SCOA Fund ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no SCOA Fund ID   Modified    :   Added validation for terminated employee  */    CREATE procedure [dbo].[Payroll_TrialRunPostValidateSCOAFund] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;        begin try      insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [ScoaFundID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid SCOA Fund assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]       left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]      where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and         ([Position_ID] is null or [ScoaFundID] is null) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))    )       declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and P.[ScoaFundID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid SCOA Fund assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or P.[ScoaFundID] is null) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate         end try     begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())      end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateScoaItems
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Trial Run Employees with Salary Heads not linked to valid Creditors   Update date : 21/04/2017 - added the @Year parameter   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 03/05/2017 - changed the in checks to exists in the where clause   Update date : 04/05/2017 - changed the where clause to match the conditional checks based on TransactionTypeID   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - FERDI BOTHA   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateScoaItems] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @Year nvarchar(10)  as    begin     set nocount on;     begin try            declare @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality])      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [TP].[EmployeeID], 'This Employee (' + [SalaryHeadName] + ') Scoa ID is not correctly linked to a Vote ID', 1, 'Employee Level', object_name(@@procid), 1, getdate(), null ,null           from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[FinYear] = @Year         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and [TaxSavePurpose] = 0 and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1 and         (          ([IRP5].[TransactionTypeID] in(1, 3) and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = (case [PE].[EmployeeTypeID] when 1 then [ScoaItemIDPermanentStaff] when 2 then [ST].[GLScoaItem] when 3 then [ST].[GLScoaItem] when 6 then [ScoaItemIDPostRetirement] when 7 then [ST].[GLScoaItem] end))))          or ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 and not @SalaryControlID is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = @SalaryControlID)) and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 and not [GL].[SCOAItemID] is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = [GL].[SCOAItemID])) and not [GL].[VendorID] is null)          or ([IRP5].[TransactionTypeID] = 3 and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([IRP5].[TransactionTypeID] in(1, 2, 3) and (case            when [IRP5].[TransactionTypeID] in(1, 3) then             (case [PE].[EmployeeTypeID]              when 1 then [ScoaItemIDPermanentStaff]              when 2 then [ST].[GLScoaItem]              when 3 then [ST].[GLScoaItem]              when 6 then [ScoaItemIDPostRetirement]              when 7 then [ST].[GLScoaItem]             end)            when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1) then [GL].[SCOAItemID]            when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0) then @SalaryControlID           end) is null)         )        )        end try     begin catch      insert into [Payroll_TrialErrors]([EmployeeID], [PeriodID], [ErrorGroup], [ValidationType], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values(null, @PeriodID, 'System', 'System', error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSCOAProject
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 11/04/2017   Description : Get Trial Run Employees with no SCOA Project ID   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]     Author  : ARTUR ANZORGE   Create date : 09/10/2019   Description : Get Trial Run Employees with no SCOA Project ID   Modified    :   Added validation for terminated employee  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateSCOAProject] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as  begin     set nocount on;     begin try         insert into Payroll_EmployeeTrialPayslipErrors ([PeriodID],[EmployeeID],[Reason],[Enabled],[ValidationType],[StoredProcedure],[CapturerID],[DateCaptured],[ModifierID],[DateModified])    (     select @PeriodID, [Employee_ID], (case          when [Position_ID] is null then 'This Employee does not have a valid Position assigned'         when not [Position_ID] is null and [DepartmentID] is null then 'This Position - ' + [PositionDesc] + ' [' + cast([Position_ID] as nvarchar(20)) + '] does not have a valid SCOA Project assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null          from [Payroll_Employee] as [PE] with(nolock)        left outer join [Payroll_Position] as [POS] with(nolock) on [EmployeeID] = [Employee_ID]      left outer join [Payroll_EmployeeTermination] as TS on TS.EmployeeID = [Employee_ID]     where ([Employee_ID] in(select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)) and        ([Position_ID] is null or [ProjectID] is null) and (TS.EmployeeTermination_ID is null or TS.Complete = 0))      )        declare @results table (      [Empl_ID] int   )     insert into @results(Empl_ID)   select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)     insert into [Payroll_EmployeeTrialPayslipErrors]([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])   select @PeriodID, R.[Empl_ID], (case          when PH.[PositionID] is null then 'This Employee does not have a valid Position assigned'         when not PH.[PositionID] is null and PH.[DepartmentID] is null then 'This Position - ' + P.[PositionDesc] + ' [' + cast(PH.[PositionID] as nvarchar(20)) + '] does not have a valid SCOA Project assigned'        end), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null   from @results R    left join Payroll_EmployeeTermination ET on ET.EmployeeID = R.Empl_ID    left join Payroll_EmployeeHistory EH on EH.EmployeeID = R.Empl_ID and ReasonID not in (10, 9,8,7,21)       left join Payroll_PositionHistory as PH on PH.EmployeeID = R.Empl_ID and PH.PositionHistory_ID = EH.PositionHistoryID    left join Payroll_Position as P on P.Position_ID = PH.PositionID    where ( (P.[Position_ID] is null or P.[ProjectID] is null) and (not ET.EmployeeTermination_ID is null and ET.Complete = 1)) and ET.TerminationStartDate >= PH.StartDate and PH.EndDate <= ET.TerminationStartDate                  end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])              values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateScoaSetup
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 12/04/2017   Description : Get Trial Run Employees with Salary Heads not linked to valid Const_SCOA_Structure Vendors   Update date : 18/04/2017 - changed the SCOA item logic to properly include and exclude certain items   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 03/05/2017 - changed the in checks to exists in the where clause   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - FERDI BOTHA   Update date :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateScoaSetup] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @Year nvarchar(10)  as    begin     set nocount on;     begin try      declare @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality])      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [TP].[EmployeeID], 'This Employee Earnings and Deduction (' + [SalaryHeadName] + ') SCOA Code is not correctly configured', 1, 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[FinYear] = @Year         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and [TP].[TaxSavePurpose] = 0 and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1 and         (          ([IRP5].[TransactionTypeID] in(1, 3) and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = (case [PE].[EmployeeTypeID] when 1 then [ScoaItemIDPermanentStaff] when 2 then [ST].[GLScoaItem] when 3 then [ST].[GLScoaItem] when 6 then [ScoaItemIDPostRetirement] when 7 then [ST].[GLScoaItem] end))))          or ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0 and not @SalaryControlID is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = @SalaryControlID)) and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1 and not [GL].[ScoaItemID] is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = [GL].[SCOAItemID])) and not [GL].[VendorID] is null)          or ([IRP5].[TransactionTypeID] = 3 and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([IRP5].[TransactionTypeID] in(1, 2, 3) and (case             when [IRP5].[TransactionTypeID] in(1, 3) then              (case [PE].[EmployeeTypeID]               when 1 then [ScoaItemIDPermanentStaff]               when 2 then [ST].[GLScoaItem]               when 3 then [ST].[GLScoaItem]               when 6 then [ScoaItemIDPostRetirement]               when 7 then [ST].[GLScoaItem]              end)             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1) then [GL].[SCOAItemID]             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0) then @SalaryControlID            end) is null)         )        )        end try     begin catch      insert into [Payroll_TrialErrors]([EmployeeID], [PeriodID], [ErrorGroup], [ValidationType], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values(null, @PeriodID, 'System', 'System', error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateSDL
-- Schema: dbo
-- ============================================
     /*   Author  : FERDI BOTHA   Create date : 02/07/2019   Description : Get Trial Run Employees where no SDL is assigned     Modified : Himil Modi   Date  : 2019/07/25      : #91771 Check if sdl is excluded or not       (Ferdi had already put this condition at his old sp but that things needs to run at Emalahleni and EMS_KarooHoogland needs to run over there, that why i am including that sp (no change done))    */  CREATE PROCEDURE [dbo].[Payroll_TrialRunPostValidateSDL] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], 'This Employee has no SDL Transaction linked', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID]       LEFT JOIN dbo.Payroll_EmployeeSubtypes AS PES ON PES.EmployeeSubtype_ID = PE.EmployeeSubtypeID      where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end) and [EP].[Period_ID] = @PeriodID and [PE].[CycleID] = @CycleID and      (PES.ExcludeSDL !=  1 OR  PE.ExcludeSDL != 1) AND        not exists(          select [EmployeePayrollDefinition_ID]           from [Payroll_EmployeePayrollDefinition] as [EPD]           where ([EPD].[EmployeeID] = [PE].[Employee_ID] and [EPD].[Enabled] = 1 and [EPD].[PayrollSalaryHeadID] in (select SalaryHead_ID from Payroll_SalaryHead where IRP5CodeId in (         Select IRP5Code_Id from Payroll_IRP5Code where IRP5Code = 4142          )))         )        )       end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])            values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateVotes
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA     Create date : 12/04/2017   Description : Get Trial Run Employees with no Valid Vote ID   Update date : 18/04/2017 - changed the SCOA item logic to properly include and exclude certain items   Update date : 24/04/2017 - changed the joins to include the PeriodID column   Update date : 03/05/2017 - changed the in checks to exists in the where clause   Update date : 12/05/2017 - Changed the mappings for Method of Calculation   Update date : 15/11/2017 - Updated SCOA Item ID to cater for Salary Structuring - FERDI BOTHA   Modified    :   Added Payroll_EmployeeTrialPayslipErrors [Lungisani khumalo : 27/11/2017]   Modified : Change validation to read Vendor ScoaItemId from Payroll_GLItems instead of Cons_Vendor - Richa M TP73112   Modified    :   06/05/2019 - Ferdi Botha => Changed linkage to SCOA Financial Year  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateVotes] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int, @Year nvarchar(10)  as    begin     set nocount on;     begin try      declare @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality])      insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], ( 'This Employee Salary Head [' + [SalaryHeadTitleAddendum] + '] is not linked to a Scoa Item for the current Financial Year of ' + @Year), 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null         from [Payroll_EmployeeTrialPayslip] as [TP] with(nolock)         join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EmployeePayrollDefinition_ID] = [TP].[PayrollDefinationID] and [EPD].[EmployeeID] = [TP].[EmployeeID] and [EPD].[Enabled] = 1         join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1         left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [TP].[EmployeeID] and [ST].[SalaryHeadId] = [SalaryHead_ID]         join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SalaryHead_ID] and [GL].[FinYear] = @Year         join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [IRP5CodeId] and [IRP5].[Enabled] = 1         join [Payroll_Employee] as [PE] with(nolock) on [Employee_ID] = [EPD].[EmployeeID] and [PE].[CycleID] = @CycleID         join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [Period_ID] = [TP].[PeriodID] and [CPD].[Period_ID] = @PeriodID and [CPD].[Enabled] = 1         join [Payroll_Position] as [PP] with(nolock) on [PP].[EmployeeID] = [PE].[Employee_ID]         join [Const_Department] as [DEP] with(nolock) on [Department_ID] = [PP].[DepartmentID] and [DEP].[Enabled] = 1         join [Const_Division] as [DIV] with(nolock) on [Division_ID] = [PP].[DivisionID] and [DIV].[Enabled] = 1         left outer join [Const_Scoa_Structure_ByYear](@Year) as [CSS] on [ScoaID] = (case when [EPD].[ScoaItemID] is null then (             case when [IRP5].[TransactionTypeID] in(1, 3) then              case [PE].[EmployeeTypeID]               when 1 then [ScoaItemIDPermanentStaff]               when 2 then [ST].[GLScoaItem]               when 3 then [ST].[GLScoaItem]               when 6 then [ScoaItemIDPostRetirement]               when 7 then [ST].[GLScoaItem]              end             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1) then              case [PE].[EmployeeTypeID]               when 1 then [ScoaItemIDPermanentStaff]               when 2 then [ScoaItemIDPermanentStaff]               when 3 then [ScoaItemIDPermanentStaff]               when 6 then [ScoaItemIDPostRetirement]               when 7 then [ScoaItemIDPermanentStaff]              end             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0) then @SalaryControlID            end) else [EPD].[ScoaItemID] end)         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = [CPD].[Period_ID] and [EP].[Cycle_ID] = [PE].[CycleID]         left outer join [Payroll_CyclePeriodAdhocSalaryHead] as [ACPD] with(nolock) on [ACPD].[PeriodID] = [CPD].[Period_ID] and [ACPD].[SalaryHeadID] = [SalaryHead_ID]        where ([TP].[EmployeeID] = (case @EmployeeID when 0 then [TP].[EmployeeID] else @EmployeeID end) and [TP].[PeriodID] = @PeriodID and (not ([TransactionTypeID] = 2 and [TP].[TaxSavePurpose] = 1)) and         (case          when @CycleModeID = 1 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 1 else 0 end          when @CycleModeID = 2 then           case when isnull([CyclePeriodAdhocPayrollDefinition_ID], 0) = 0 then 0 else 1 end          else 0 end) = 1 and         (          ([TransactionTypeID] in(1, 3) and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = (case [PE].[EmployeeTypeID] when 1 then [ScoaItemIDPermanentStaff] when 2 then [ST].[GLScoaItem] when 3 then [ST].[GLScoaItem] when 6 then [ScoaItemIDPostRetirement] when 7 then [ST].[GLScoaItem] end))))          or ([TransactionTypeID] = 2 and [JournalEntryOnly] = 0 and not @SalaryControlID is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = @SalaryControlID)) and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([TransactionTypeID] = 2 and [JournalEntryOnly] = 1 and not [GL].[ScoaItemID] is null and not exists(select top 1 [ScoaID] from [Const_Scoa_Structure_ByYear](@Year) join [Led_Vote] with(nolock) on [ScoaID] = [SCOAItemID] where ([FinYear] = @Year and [ScoaID] = [GL].[ScoaItemID])) and not [GL].[VendorID] is null)          or ([TransactionTypeID] = 3 and not exists(select [ScoaId] from [Const_Scoa_Structure_ByYear](@Year) where ([ScoaId] = [GL].[VendorScoaId])))          or ([TransactionTypeID] in(1, 2, 3) and (case when [IRP5].[TransactionTypeID] in(1, 3) then              (case [PE].[EmployeeTypeID]               when 1 then [ScoaItemIDPermanentStaff]               when 2 then [ST].[GLScoaItem]               when 3 then [ST].[GLScoaItem]               when 6 then [ScoaItemIDPostRetirement]               when 7 then [ST].[GLScoaItem]              end)             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 1) then [GL].[SCOAItemID]             when ([IRP5].[TransactionTypeID] = 2 and [JournalEntryOnly] = 0) then @SalaryControlID            end) is null)          )         )        end try     begin catch      insert into [Payroll_TrialErrors]([EmployeeID], [PeriodID], [ErrorGroup], [ValidationType], [ErrorMessage], [StoredProcedure], [CapturedBy], [CapturedDate])       values(null, @PeriodID, 'System', 'System', error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunPostValidateYearlyNotchIncrease
-- Schema: dbo
-- ============================================
    /*   Author  : Modiri   Create date : 2020/02/03   Description : Get Trial Run Employees where no Basic Salary is assigned  */  CREATE procedure [dbo].[Payroll_TrialRunPostValidateYearlyNotchIncrease] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     begin try      Exec Payroll_NotchOnIncreaseDate @EmployeeID      declare @Month int =(select  MONTH(PeriodStartDate) from Payroll_CyclePeriodDetails where Period_ID=@PeriodID)        insert into Payroll_EmployeeTrialPayslipErrors([PeriodID], [EmployeeID], [Reason], [Enabled], [ValidationType], [StoredProcedure], [CapturerID], [DateCaptured], [ModifierID], [DateModified])       select @PeriodID, [PE].[Employee_ID], 'Notch Increase approvals are outstanding. Employee salary is not adjusted yet.', 1 , 'Employee Level', object_name(@@procid), 1, getdate(), null ,null        from [Payroll_Employee] as [PE] with(nolock)         join [Payroll_TrialRun_History_Employees] as [EP] with(nolock) on [EP].[Employee_ID] = [PE].[Employee_ID] and [EP].[Period_ID] = @PeriodID and [EP].[Cycle_ID] = [PE].[CycleID]       join Payroll_Notch_Increase_Detail as [NI] with(nolock) on [NI].EmployeeId = [PE].[Employee_ID] and [NI].[MonthID] = @Month        where ([PE].[Employee_ID] = (case @EmployeeID when 0 then [PE].[Employee_ID] else @EmployeeID end) and [NI].[MonthID] = @Month and [PE].[CycleID] = @CycleID          AND ([NI].[Approved] IS NULL AND [NI].[ApprovedDate] IS NULL)        )       end try         begin catch      insert into [Payroll_TrialErrors] ([EmployeeID],[PeriodID],[ErrorGroup],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate])            values(null, @PeriodID, 'System', 'System' ,error_message(), error_procedure(), 1, getdate())        end catch       set nocount off;    end

GO

-- ============================================
-- SP: Payroll_TrialRunValidateDuplicateID
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 07/04/2017   Description : Get Trial Run Employees with Duplicate ID Numbers  */  create procedure [Payroll_TrialRunValidateDuplicateID] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     select [Employee_ID], [EmpCode]      from [Payroll_Employee] with(nolock)      where (not [IdNo] = 'NA' and not [IdNo] = '' and not [IdNo] is null and [IdNo] in(        select [IdNo] from         [Payroll_Employee] where ([Employee_ID] in(          select [Employee_ID]           from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)         )        ) group by [IdNo] having (count([IdNo]) > 2)         )      )     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunValidateDuplicateVendor
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 07/04/2017   Description : Get Trial Run Employees with Duplicate Vendor Account Numbers  */  create procedure [Payroll_TrialRunValidateDuplicateVendor] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     select [Employee_ID], [EmpCode]      from [Payroll_Employee] as [EMP] with(nolock)       join [Cons_Vendor] as [VEN] with(nolock) on [BankAccountNumber] = [AccountNumber]      where ([Employee_ID] in(        select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)       ) and not [AccountNumber] = 'NA' and not [AccountNumber] = '' and not [AccountNumber] is null)     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunValidatePayrollGroupDefinition
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 24/10/2017   Description : Get Trial Run Employees without configured Payroll Group Definitions  */  create procedure [Payroll_TrialRunValidatePayrollGroupDefinition] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     select [Employee_ID], [EmpCode]      from [Payroll_Employee] as [EMP] with(nolock)      where ([Employee_ID] in(        select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)       ) and (         select count([EmployeePayrollDefinition_ID])          from [Payroll_EmployeePayrollDefinition] with(nolock)          where ([EmployeeID] = (case @EmployeeID when 0 then [EmployeeID] else @EmployeeID end) and [Enabled] = 1)        ) = 0       )     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_TrialRunValidatePayrollPendingBankDetails
-- Schema: dbo
-- ============================================
    /*   Created by : Modiri   Date  : 2019/07/08   Reason  : Validate pending banking details approval        #86527 Workflow not as specification  */    CREATE PROCEDURE [dbo].[Payroll_TrialRunValidatePayrollPendingBankDetails] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  AS    BEGIN   select [emp].[Employee_ID], [emp].[EmpCode]     from [dbo].[Payroll_EmployeeAccountDetailHistory] emphist     left outer join [dbo].[Payroll_Employee] emp on [emp].[Employee_ID] = [emphist].[EmployeeId]     left outer join [dbo].[Const_PaymentType] ptype on [ptype].[PaymentType_ID] = [emphist].[PaymentTypeID]     left outer join [dbo].[Const_AccountHolderRelation_sys]  accrelation on [accrelation].[AccHolderRelation_ID] = [emphist].[AccountHolderRelationshipID]     left outer join [dbo].[Const_BankAccountType] acctype on [acctype].[BankAccountTypeID] = [emphist].[AccountTypeID]     left outer join [dbo].[Const_Bank] cbank on [cbank].[Bank_ID] = [emphist].[BankID]     left outer join [dbo].[Const_BankBranchCode] cbranch on [cbranch].[BankBranchCode_ID] = [emphist].[BranchID]     where [emphist].[IsApproved] is null AND      EMP.Employee_ID IN(      select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)      )        END  

GO

-- ============================================
-- SP: Payroll_TrialRunValidatePayrollPendingTransactions
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 06/04/2019   Description : Get Trial Run Employees with Pending Transactions  */  CREATE procedure [dbo].[Payroll_TrialRunValidatePayrollPendingTransactions] @EmployeeID int, @PeriodID int, @CycleID int, @CycleModeID int  as    begin     set nocount on;     declare @CyclePeriods table (      [PeriodID] int not null     )     declare @IRP5Code table (      [IRP5Code] int not null     )     /* INCOME - TAXABLE [3601] */   insert into @IRP5Code([IRP5Code]) values(3601)     /* OVERTIME [3607] */   insert into @IRP5Code([IRP5Code]) values(3607)     /* FOREIGN INCOME - TAXABLE [3651] */   insert into @IRP5Code([IRP5Code]) values(3651)     /* FOREIGN OVERTIME [3657] */   /*insert into @IRP5Code([IRP5Code]) values(3657)*/     declare @StartDate datetime,     @UntilDate datetime,     @MinPeriodID int     select @StartDate = [PeriodStartDate], @UntilDate = [PeriodEndDate] from [Payroll_CyclePeriodDetails] where ([Period_ID] = @PeriodID)     insert into @CyclePeriods([PeriodID])      select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails] where ([CycleID] = @CycleID and [CycleModeID] = 1 and [Period_ID] <= @PeriodID) order by Period_ID desc     if(not exists(select [PeriodID] from @CyclePeriods where ([PeriodID] = @PeriodID)))      insert into @CyclePeriods([PeriodID])       values (@PeriodID)     select @MinPeriodID = min([PeriodID]) from @CyclePeriods     select [Employee_ID], [EmpCode]      from [Payroll_Employee] as [EMP] with(nolock)      where ([Employee_ID] in(        select [Employee_ID] from [Payroll_TrialRun_History_Employees] with(nolock) where ([Employee_ID] = (case @EmployeeID when 0 then [Employee_ID] else @EmployeeID end) and [Period_ID] = @PeriodID and [Cycle_ID] = @CycleID and [CycleModeID] = @CycleModeID)       ) and (        (         select count([CC].[CostCenter_ID])          from [Payroll_CostCenter] as [CC] with(nolock)          where ([CC].[EmployeeID] = [EMP].[Employee_ID] and [CC].[IsApproved] = 0 and [CC].[IsApprovalRequired] = 1 and isnull([CC].[ExcludeFromPayment], 0) = 0 and [CC].[Enabled] = 1 and [CC].[CostAmount] > 0 and (            (isnull([CC].[EveryMonth], 0) = 0 and isnull([CC].[Processed], 0) = 0) or            (isnull([CC].[ExcludeFromPayment], 0) = 0 and isnull([CC].[EveryMonth], 0) = 1 and [CC].[PeriodID] >= @MinPeriodID)           )          )        ) > 0 or        (         select count([OT].[EmployeeOverTime_ID])          from [Payroll_EmployeeOverTime] as [OT] with(nolock)           join [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock) on [EPD].[EmployeeID] = [OT].[EmployeeID] and [EPD].[Enabled] = 1           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [EPD].[PayrollSalaryHeadID] and [SalaryHead_ID] = [OT].[SalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1          where ([OT].[EmployeeID] = [EMP].[Employee_ID] and isnull([OT].[ExcludeFromPayment], 0) = 0 and isnull([OT].[Processed], 0) = 0 and [OT].[Enabled] = 1 and [OT].[RejectedReason] is null and [OT].[OverTimeDate] <= @UntilDate and (            (             ([OverTimeDate] >= @StartDate and [OT].[PeriodID] = @PeriodID) or             ([OverTimeDate] >= datefromparts(year(dateadd(m, -2, @StartDate)), month(dateadd(m, -2, @StartDate)), 1))            ) and [IRP5].[TransactionTypeID] = 1 and            (case             when isnull([OT].[IsApprovalRequired], 0) = 0 then 1             when isnull([OT].[IsApprovalRequired], 0) = 1 and isnull([OT].[IsApproved], 0) = 0 then 1             else 0            end) = 1 and isnull([IRP5].[IRP5Code], [IRP5].[IRP5CertCode]) in(select [IRP5Code] from @IRP5Code) and not [SalaryHead_ID] = 1           )          )        ) > 0 or        (         select count([EC].[EmployeeClaims_ID])          from [Payroll_EmployeeClaims] as [EC] with(nolock)           join @CyclePeriods as [CP] on [CP].[PeriodID] = [EC].[PeriodID]          where ([EC].[EmployeeID] = [EMP].[Employee_ID] and isnull([EC].[ExcludeFromPayment], 0) = 0 and [EC].[Enabled] = 1 and [EC].[RejectedReason] is null and (            (case             when isnull([EC].[IsApprovalRequired], 0) = 0 then 1             when isnull([EC].[IsApprovalRequired], 0) = 1 and isnull([EC].[IsApproved], 0) = 0 then 1             else 0            end) = 1           )          )        ) > 0        OR EXISTS      (       SELECT TOP (1) 1       FROM Payroll_WageTransaction WT       JOIN @CyclePeriods AS CP ON CP.PeriodID = WT.CapturedDuringPeriodId       WHERE WT.EmployeeId = EMP.Employee_ID AND WT.RejectedReason IS NULL AND WT.IsApproved = 0 AND WT.Enabled = 1      )      OR       (       Select Count(*) from Payroll_3rdPartyPayment TP       JOIN @CyclePeriods CP on CP.PeriodID = TP.Period_ID       where Period_ID = @PeriodID and IsNULL(Approved,0) = 0 and ISNULL(Rejected,0) = 0 and IsNULL(Processed,0) = 0       and TP.EmployeeID = EMP.Employee_ID      ) > 0       )      )     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_UI19GrossTaxableRemuneration
-- Schema: dbo
-- ============================================
--Description: Dataset for Payroll_UI19Information report (Payroll_UI19Information.rdl)    CREATE PROCEDURE [dbo].[Payroll_UI19GrossTaxableRemuneration]   @EmployeeId int  AS  BEGIN        DECLARE @TaxableId INT = 1              ,@EarningsId INT = 1              ,@FringeId INT = 4        DROP TABLE IF EXISTS #Periods        SELECT          PeriodID         ,SUM(Amount) AS UIF INTO #Periods      FROM [Payroll_PayrollResults]      WHERE EmployeeID = @EmployeeId          AND (SalaryHeadID = 7 OR SalaryHeadID = 8)      GROUP BY PeriodID        SELECT          pcpd.PeriodStartDate         ,IIF(pcpd.PeriodEndDate > pet.TerminationStartDate, pet.TerminationStartDate, pcpd.PeriodEndDate) AS PeriodEndDate         ,(SELECT SUM(PPR.Amount) FROM Payroll_PayrollResults AS PPR              JOIN Payroll_SalaryHead AS PSH                  ON PPR.SalaryHeadID = PSH.SalaryHead_ID              JOIN Payroll_IRP5Code AS IRP5                  ON PSH.IRP5CodeId = IRP5.IRP5Code_ID                       AND IRP5.TaxableID = @TaxableId                       AND (IRP5.TransactionTypeID = @EarningsId OR IRP5.TransactionTypeID = @FringeId)                      AND ((IRP5.IRP5Code NOT BETWEEN 3602 AND 3617)                           OR (IRP5.IRP5Code NOT BETWEEN 3619 AND 3620)                           OR (IRP5.IRP5Code NOT BETWEEN 3652 AND 3667))              WHERE pcpd.Period_ID = PPR.PeriodID AND PPR.EmployeeID = @EmployeeId          ) AS TotalGrossTaxableRemuneration         ,(SELECT TOP 1                  pem.WHPM_Monthly              FROM Payroll_EmployeeHistory pem              WHERE EmployeeId = @EmployeeId                  AND pcpd.PeriodEndDate >= StartDate                  AND pcpd.PeriodStartDate <= EndDate              ORDER BY EmployeeHistory_ID DESC)          AS WHPM_Monthly         ,(SELECT TOP 1                  CAST(tr.UifCode AS VARCHAR) + ' - ' + tr.Description              FROM Payroll_EmployeeUifStatusHistory eus              JOIN Const_HR_UifDefinedTeminationReason_sys tr                  ON eus.UifDefinedTerminationReasonID = tr.UifDefinedTerminationReason_ID              WHERE EmployeeId = @EmployeeId                  AND pcpd.PeriodEndDate >= StartDate                  AND pcpd.PeriodStartDate <= EndDate              ORDER BY EmployeeUifStatusHistory_ID DESC)          AS TerminationReason         ,(SELECT TOP 1                  IIF(eus.UifDefinedNonContributorReasonID IS NULL, 'Yes', 'No')              FROM Payroll_EmployeeUifStatusHistory eus              WHERE EmployeeId = @EmployeeId              AND pcpd.PeriodEndDate >= StartDate              AND pcpd.PeriodStartDate <= EndDate              ORDER BY EmployeeUifStatusHistory_ID DESC)          AS Contributor         ,(SELECT TOP 1                  CAST(tr.UifCode AS VARCHAR) + ' - ' + tr.Description              FROM Payroll_EmployeeUifStatusHistory eus              LEFT JOIN Const_HR_UifDefinedNonContributorReason_sys tr                  ON eus.UifDefinedNonContributorReasonID = tr.UifDefinedNonContributorReason_ID              WHERE EmployeeId = @EmployeeId              AND pcpd.PeriodEndDate >= StartDate              AND pcpd.PeriodStartDate <= EndDate              ORDER BY EmployeeUifStatusHistory_ID DESC)          AS NonContributorReason         ,ppr.[UIF] AS UIFContribution      FROM Payroll_Employee pe      JOIN Payroll_EmployeeHistory AS PEH          ON PE.Employee_ID = PEH.EmployeeID AND PEH.Enabled = 1      CROSS APPLY(SELECT DISTINCT PeriodID FROM Payroll_PayrollResults WHERE EmployeeID = @EmployeeId) AS payrollPeriods      JOIN Payroll_CyclePeriodDetails pcpd          ON PEH.CycleID = pcpd.CycleID AND pcpd.Enabled = 1 AND pcpd.Processed = 1 AND pcpd.Period_ID = payrollPeriods.PeriodID      LEFT JOIN Payroll_CyclePeriodAdhocEmployee AS PCPAE          ON pe.Employee_ID = PCPAE.EmployeeID AND PCPAE.PeriodID = pcpd.Period_ID      LEFT JOIN Payroll_EmployeeTermination pet          ON pe.Employee_ID = pet.EmployeeID      LEFT JOIN #Periods ppr          ON pcpd.Period_ID = ppr.PeriodID      WHERE Employee_ID = @EmployeeId      AND pcpd.PeriodEndDate > DATEADD(YEAR, -5, GETDATE())      AND pcpd.PeriodEndDate > pe.JoiningDate      AND ((PEH.StartDate <= pcpd.PeriodEndDate AND PEH.EndDate >= pcpd.PeriodStartDate)           OR (pcpd.AdhocTypeID IS NOT NULL AND PCPAE.CyclePeriodAdhocEmployee_ID IS NOT NULL))    END

GO

-- ============================================
-- SP: Payroll_UI27EmployeeInfo
-- Schema: dbo
-- ============================================
--Description: Dataset for Payroll_UI27Information report (Payroll_UI27Information.rdl)    CREATE PROCEDURE [dbo].[Payroll_UI27EmployeeInfo]   @EmployeeId INT  AS  BEGIN        DECLARE @TaxableId INT = 1              ,@EarningsId INT = 1              ,@FringeId INT = 4         SELECT           ISNULL(FirstName, '') + ' ' + ISNULL(SecondName, '') AS Name          ,SurName          ,IdNo          ,(SELECT SUM(PPR.Amount) FROM Payroll_PayrollResults AS PPR                  JOIN Payroll_SalaryHead AS PSH                      ON PPR.SalaryHeadID = PSH.SalaryHead_ID                  JOIN Payroll_IRP5Code AS IRP5                      ON PSH.IRP5CodeId = IRP5.IRP5Code_ID                           AND IRP5.TaxableID = @TaxableId                           AND (IRP5.TransactionTypeID = @EarningsId OR IRP5.TransactionTypeID = @FringeId)                          AND ((IRP5.IRP5Code NOT BETWEEN 3602 AND 3617)                               OR (IRP5.IRP5Code NOT BETWEEN 3619 AND 3620)                               OR (IRP5.IRP5Code NOT BETWEEN 3652 AND 3667))                  WHERE pcpd.Period_ID = PPR.PeriodID AND PPR.EmployeeID = @EmployeeId              ) AS GrossTaxableRemuneration          ,pcpd.ProcessingMonth + ' (' + FORMAT(pcpd.PeriodStartDate, 'd', 'en-gb') + '-' + FORMAT(pcpd.PeriodEndDate, 'd', 'en-gb') + ')' AS Period       FROM Payroll_Employee pe       CROSS APPLY(SELECT           TOP 1 PCPD.PeriodStartDate, PCPD.PeriodEndDate, PCPD.ProcessingMonth, PCPD.Period_ID           FROM Payroll_CyclePeriodDetails AS PCPD          JOIN Payroll_PayrollResults AS PPR ON PPR.PeriodID = PCPD.Period_ID AND PPR.EmployeeID = @EmployeeId          WHERE PCPD.Enabled = 1 AND PCPD.Processed = 1 ORDER BY PCPD.ProcessedDate DESC) AS pcpd       WHERE Employee_ID = @EmployeeId    END

GO

-- ============================================
-- SP: Payroll_UnLockDownTrialRun_sp
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 23/03/2017   Description : Unlock the Trial Run  */  create procedure [Payroll_UnLockDownTrialRun_sp] @PeriodID int, @Reason nvarchar(max), @CancelBy int  as    begin     set nocount on;     update [Payroll_TrailRun_History] set [Status] = 'InProcess', [Porcessed] = 0, [FInalUserId] = null where ([PeriodID] = @PeriodID)     update [Payroll_CyclePeriodDetails] set [Processed] = 0, [ProcessedDate] = null, [Reason] = @Reason, [LockdownCancelledBy] = @CancelBy, [LockDownCancelledDate] = getdate(), [ApprovedStatus] = 'No', [TrialRunDate] = null, [TrialRunBy] = null, [LockedDown] = null, [LockDownDate] = null, [LockedDownBy] = null where ([Period_ID] = @PeriodID)     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_UpdateAppeal
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul PANCHAL  -- Create date: 30 Aug 2013  -- Description: Update Appeal Dae , status and Grounds of appeal for Disiplinary, Grievnace Apprisal  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_UpdateAppeal]   @AppealDate DATETIME,   @Grounds NVARCHAR(200),   @Status NVARCHAR(50),   @ID INT,   @Mode NVARCHAR(20)  AS  BEGIN   SET NOCOUNT ON;      IF(@Mode = 'Disciplinary')   BEGIN    UPDATE Payroll_Disciplinary SET AppealDate = @AppealDate ,GroundsOfAppeal=@Grounds,Status =@Status WHERE Disiplinary_ID = @ID       END   ELSE IF(@Mode = 'Grievance')   BEGIN    UPDATE Payroll_Grievance SET AppealDate = @AppealDate ,GroundsOfAppeal=@Grounds,Status =@Status WHERE Grievance_ID = @ID   END     END  

GO

