-- ============================================
-- SP: Payroll_UpdateCurrentData
-- Schema: dbo
-- ============================================
  /*   Author  : Richa Mills   Create date : 2018/07/31   Description : Update Current data with relevant History data   Update  : 29/05/2019 => Added flag to check current date from AAAA_ConfigSettings   Update  : 26/08/2019 => Resovled Grouping flag to get top 1 from Start Date desc within the same period   Update  : 05/09/2019 => Resovled Grouping flag to get top 1 from Start Date desc within the same period   exec Payroll_UpdateCurrentData   Select * from Payroll_SchedulerErrors order by errormessage     */  CREATE procedure [dbo].[Payroll_UpdateCurrentData]  as  begin    DECLARE @HistoryTable varchar(250)  DECLARE @MainTable varchar(250)  DECLARE @ColumnName varchar(250)   DECLARE @HistoryColumnName varchar(250)  DECLARE @PrimaryKey varchar(250)  DECLARE @HirstoryPrimaryKey varchar(250)  DECLARE @LinkIdName varchar(250)  DECLARE @StartDate varchar(250)  DECLARE @EndDate varchar(250)  DECLARE @UseColumnMapping bit  DECLARE @ID int  DECLARE @AutoUpdate bit  DECLARE @CustomSP varchar(500)    DECLARE @UpdateQuery varchar(max)  DECLARE @SetStatement varchar(max) = ' Set '    DECLARE @date varchar(19) = convert(nvarchar(19), getdate(), 111)    DECLARE @dateValue varchar(10) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'PayrollSchedulerDate'))  DECLARE @useCustomDate varchar(6) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'UseCustomPayrollSchedulerDate'))    IF @useCustomDate = 'true'  BEGIN   DECLARE @dateYear int = cast(right(@dateValue, 4) as int),     @dateMonth int = cast(right(left(@dateValue, 5), 2) as int),     @dateDay int = cast(left(@dateValue, 2) as int)     Select @date = convert(nvarchar(19), datefromparts(@dateYear, @dateMonth, @dateDay), 120)  END    declare @TEMPCOL table (HistoryCol varchar(250), MainCol varchar(250))    DECLARE historyTable_cursor CURSOR FOR    select ID, MainTableName,HistoryTable,MainTablePrimaryKey,HistoryTablePrimaryKey,LinkIdName,ConditionStartDesc,ConditionEndDesc,UseColumnMapping,AutoUpdate,CustomSPName    from payroll_scheduledhistorytables ht   where IsNULL(ht.enable,0) = 1   order by [Sequence]    OPEN historyTable_cursor    FETCH NEXT FROM historyTable_cursor INTO @ID,@MainTable,@HistoryTable,@PrimaryKey,@HirstoryPrimaryKey,@LinkIdName,@StartDate,@EndDate,@UseColumnMapping,@AutoUpdate,@CustomSP    WHILE @@FETCH_STATUS = 0    BEGIN     --Check if a customSP must be executed  IF not @CustomSP is null    exec (@CustomSP)       IF @UseColumnMapping = 1   BEGIN   INSERT INTO @TEMPCOL    SELECT HistoryColumnName,MainColumnName from Payroll_SchedulerColumnMapping    WHERE ScheduledTableID = @ID   END   ELSE   BEGIN   INSERT INTO @TEMPCOL    SELECT quotename(c.name), quotename(c.name)    FROM sys.columns c    WHERE c.object_id = OBJECT_ID(@HistoryTable)    AND c.name not in (@HirstoryPrimaryKey,@LinkIdName)    AND c.is_computed = 0     END       DECLARE db_cursor CURSOR FOR    SELECT HistoryCol,MainCol from @TEMPCOL     OPEN db_cursor     FETCH NEXT FROM db_cursor INTO @HistoryColumnName, @ColumnName       WHILE @@FETCH_STATUS = 0     BEGIN              if @ColumnName != @PrimaryKey OR @ColumnName != Replace(@PrimaryKey,'_','' ) OR @ColumnName != @HirstoryPrimaryKey     BEGIN     set @SetStatement = @SetStatement +  quotename(@MainTable) + '.' + @ColumnName + ' = ' + quotename(@HistoryTable) + '.' + @HistoryColumnName + ' , '     END     FETCH NEXT FROM db_cursor INTO @HistoryColumnName, @ColumnName     END      CLOSE db_cursor     DEALLOCATE db_cursor          SELECT @UpdateQuery = 'merge into ' + quotename(@MainTable) + ' using ' + quotename(@HistoryTable) +          ' on ' + quotename(@mainTable) + '.' + quotename(@PrimaryKey) + ' = ' + quotename(@HistoryTable) + '.' + quotename(@LinkIdName) +           ' and ''' + @date + ''' between ' + quotename(@HistoryTable) + '.' + quotename(@StartDate) + ' and ' + quotename(@HistoryTable) + '.' + quotename(@EndDate) +           ' and ' + quotename(@HirstoryPrimaryKey) + ' in(select top 1 ' + quotename(@HirstoryPrimaryKey) + ' from ' + quotename(@HistoryTable) + ' where (' + quotename(@linkIDName) + ' = ' + quotename(@MainTable) + '.' + quotename(@PrimaryKey) + ' and ''' + @date + ''' between ' + quotename(@StartDate) + ' and ' + quotename(@EndDate) + ') order by ' + quotename(@StartDate) + ' desc)          when matched then          update ' + @SetStatement        select @UpdateQuery = Left(@UpdateQuery,len(@UpdateQuery) -1) + ';'        BEGIN TRY     IF @AutoUpdate = 1         exec (@UpdateQuery)       Insert into Payroll_SchedulerErrors      values      (@Id,'Successful',@UpdateQuery,'none',getdate())            END TRY      BEGIN CATCH        If @UpdateQuery is NULL       Select @UpdateQuery = 'Query = NULL'           Insert into Payroll_SchedulerErrors      values      (@Id,'Payroll_UpdateCurrentData',@UpdateQuery,error_message(),getdate())        END CATCH   Set @SetStatement = 'Set '   Set @UpdateQuery = ''   Delete from @TEMPCOL     FETCH NEXT FROM historyTable_cursor INTO @ID,@MainTable,@HistoryTable,@PrimaryKey,@HirstoryPrimaryKey,@LinkIdName,@StartDate,@EndDate,@UseColumnMapping,@AutoUpdate,@CustomSP   END       CLOSE historyTable_cursor     DEALLOCATE historyTable_cursor     end

GO

-- ============================================
-- SP: Payroll_UpdateCurrentEmployeeData
-- Schema: dbo
-- ============================================
/*     Author  : Richa Mills   Create Date : 2018/07/31   Description : Update Current data with relevant History data for EmployeeHistoryOnly   Update Date : 2019/07/09 => Ferdi Botha -> Added all sections, to allow proper updating to master records, instead of just updating the Position ID     Modiri   2019/07/23   #91594 Business rule 8 not fully achieved THe Monthly Fixe Salary Field and the Bonus Amount should be cleared if the Task Grade of the Job profile change.      Artur   2019/08/09   Comment on NotchID = null in update      Modiri   2019/09/03   #93628 New employees linked to a Task Grade and Notch, no Basic salary      Ferdi Botha   2019/09/09   #93352 => Clear Notch ID when Task Grade ID changed     Ilya Skavronskiy   2020/04/02   #30451 => Fixed creating new Employee History record after changing Notch for new Task Grade     Ruan Strydom   2021/03/30   #60719 => Fixed creating new Employee History record after changing Notch for new Task Grade     Richa M   2021/04/15   #60068 => Update the positionHisotryId in the EmployeeHistory table      Ruan Strydom   2021/05/26   #67484 => Fixed creating new Employee History record after changing Notch for new Task Grade     Richa Mills   2021/09/20   History records will be created via the front end.    Scheduler should only update the main tables     exec Payroll_UpdateCurrentEmployeeData  */  CREATE PROCEDURE [dbo].[Payroll_UpdateCurrentEmployeeData]  as  begin       DECLARE @CurrentDate DATETIME = CAST(CURRENT_TIMESTAMP AS DATE);  DECLARE @DateValue VARCHAR(10) = (SELECT [KeyValue] FROM AAAA_ConfigSettings WHERE [KeyName] = 'PayrollSchedulerDate');  DECLARE @UseCustomDate VARCHAR(6) = (SELECT [KeyValue] FROM AAAA_ConfigSettings WHERE [KeyName] = 'UseCustomPayrollSchedulerDate');    DECLARE @TerminationCycleId int = (select Cycle_ID from Const_Cycle where CycleDesc = 'Ad Hoc Termination')    IF @UseCustomDate = 'true'  BEGIN   DECLARE @dateYear int = cast(right(@dateValue, 4) as int),     @dateMonth int = cast(right(left(@dateValue, 5), 2) as int),     @dateDay int = cast(left(@dateValue, 2) as int)     Select @CurrentDate = convert(nvarchar(19), datefromparts(@dateYear, @dateMonth, @dateDay), 120)  END      --/*Update Employee (Position) Records */  --UPDATE  -- e  --SET  -- e.[PositionID] = ph.[PositionID],  -- e.[JobProfileID] = ph.[JobProfileID],  -- e.[PayrollDefinitionGroupID] = ph.[PayrollDefinitionGroupID]  --FROM  -- Payroll_Employee e  --INNER JOIN  -- Payroll_EmployeeHistory eh ON e.[Employee_ID] = eh.[EmployeeID]  --         AND eh.[Enabled] = 1  --         AND @CurrentDate BETWEEN eh.[StartDate] AND eh.[EndDate]  --INNER JOIN  -- Payroll_PositionHistory ph ON eh.[PositionHistoryID] = ph.[PositionHistory_ID]  --         AND ph.[Enabled] = 1  --WHERE  -- e.[Enabled] = 1;    /* Employee (History) Records */  UPDATE   e  SET   e.[ReasonID] = eh.[ReasonID],   e.[Enabled] = eh.[Enabled],   e.[EmployeeTypeID] = eh.[EmployeeTypeID],   e.[EmployeeSubtypeID] = eh.[EmployeeSubtypeID],   e.[ConditionOfServiceID] = eh.[ConditionOfServiceID],   e.[CycleID] = eh.[CycleID],   e.[NotchId] = eh.[NotchID],   e.[ShiftRotationID] = eh.[ShiftRotationID],   e.[RotationID] = eh.[RotationID],   e.[BonusPaymentDateID] = eh.[BonusPaymentDateID],   e.[ExcludeUIFNonContributorReasonID] = eh.[ExcludeUIFNonContributorReasonID],   e.[RPD_Other] = eh.[RPD_Other],   e.[RPW_Other] = eh.[RPW_Other],   e.[WHPD_Monthly] = eh.[WHPD_Monthly],   e.[WHPD_Other] = eh.[WHPD_Other],   e.[WHPM_Monthly] = eh.[WHPM_Monthly],   e.[RPD_Monthly] = eh.[RPD_Monthly],   e.[WDPW_Other] = eh.[WDPW_Other],   e.[WDPM_Monthly] = eh.[WDPM_Monthly],   e.[RPH_Monthly] = eh.[RPH_Monthly],   e.[RPH_Other] = eh.[RPH_Other],   e.[FixedSalary] = eh.[MonthlySalary],   e.[BonusAmount] = eh.[BonusSalary],   e.[AnnualSalary] = eh.[AnnualSalary],   e.[BonusCalculation] = eh.[BonusCalculation],   e.[AllowOverTime] = eh.[AllowOverTime],   e.[TaxCalculationType] = eh.[TaxCalculationType],   e.[ExcludeUIF] = eh.[ExcludeUIF],   e.[ExcludeSDL] = eh.[ExcludeSDL],   e.[NotchChangeReason] = eh.[NotchChangeReason]  FROM   Payroll_Employee e  INNER JOIN   Payroll_EmployeeHistory eh ON e.[Employee_ID] = eh.[EmployeeID]           AND eh.[Enabled] = 1           AND @CurrentDate BETWEEN eh.[StartDate] AND eh.[EndDate]  WHERE e.CycleID <> @TerminationCycleId;        end

GO

-- ============================================
-- SP: Payroll_UpdateDivisionIDonHistoricData_sp
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:Varun Parvataneni  -- Description : Some Historical Journal Entries Not Linked To DivisionID.Force Linking Them to First Enable DivisionID  -- Create date: 12 Aug 2016  -- CALLS : Payroll_UpdateDivisionIDonHistoricData_sp 977371  -- TP:42536 CR: Add Municipal classification to ledger entries from HR/Payroll   -- ==============================================================================  CREATE PROCEDURE [dbo].[Payroll_UpdateDivisionIDonHistoricData_sp]    @TransactionID int  AS   BEGIN    UPDATE Payroll_Transactions set DivisionID=(SELECT TOP 1 Division_ID FROM Const_Division WHERE ENABLED=1 AND DivisionParentID IS NULL)    WHERE Transaction_ID= @TransactionID    END  

GO

-- ============================================
-- SP: Payroll_UpdateDocumentURL
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Nirav Parikh  -- Create date: 30 Aug 2013  -- Description: Update document url for Disiplinary, Grievnace, Performance Apprisal  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_UpdateDocumentURL]   @DocUrl NVARCHAR(500),   @ID INT,   @Mode NVARCHAR(20)  AS  BEGIN   SET NOCOUNT ON;      IF(@Mode = 'Disciplinary')   BEGIN    UPDATE Payroll_Disciplinary SET DisciplinaryDocUrl = @DocUrl WHERE Disiplinary_ID = @ID   END   ELSE IF(@Mode = 'Grievance')   BEGIN    UPDATE Payroll_Grievance SET GrievanceDocUrl = @DocUrl WHERE Grievance_ID = @ID   END   ELSE IF(@Mode = 'PerformanceAppraisal')   BEGIN    UPDATE Payroll_PerformanceApprisal SET PerformanceApprisalDocURL = @DocUrl WHERE PerformanceApprisal_ID = @ID   END    ELSE IF(@Mode = 'DisWitnessDelete')   BEGIN    UPDATE Payroll_DisciplinaryWitnessDetails SET [Enabled] = 0 WHERE DisiplinaryWitness_ID = @ID   END    ELSE IF(@Mode = 'GreWitnessDelete')   BEGIN    UPDATE Payroll_GrievanceWitnessDetails SET Enabled = 0 WHERE GrievanceWitness_ID = @ID   END   ELSE IF(@Mode = 'Employee')   BEGIN    UPDATE dbo.Payroll_Employee SET ImagePath = @DocUrl WHERE Employee_ID = @ID   END  END  

GO

