  -- =============================================  -- Author:  MEHUL PANCHAL  -- Create date:  19/11/2013  -- Description: UPDATE EMPLOYEE AGE AND YOUTH ALSO  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_UpdateEmployeeAge_sp]     AS  BEGIN     DECLARE @START INT   DECLARE @COUNT INT   DECLARE @DATEOFBIRTH DATETIME   DECLARE @EMPID INT     DECLARE @EMPLOYEE TABLE   (     ID INT IDENTITY(1,1),    EMPLOYEEID INT,    DATEOFBIRTH DATETIME   )            SET @START = 1       INSERT INTO @EMPLOYEE   SELECT Employee_ID,DateOfBirth from Payroll_Employee where Enabled = 1 AND IsDummy = 0       SELECT @COUNT = COUNT(ID) FROM @EMPLOYEE   SET @COUNT = @COUNT + 1     --WHILE(@START < @COUNT)   --BEGIN   -- SELECT @DATEOFBIRTH = DATEOFBIRTH, @EMPID = EMPLOYEEID FROM @EMPLOYEE WHERE ID = @START   -- IF(MONTH(GETDATE())= MONTH(@DATEOFBIRTH) AND DAY(GETDATE()) = DAY(@DATEOFBIRTH))   -- BEGIN   --  UPDATE Payroll_Employee SET Age = Age + 1 WHERE Employee_ID = @EMPID   -- END   -- SET @START = @START + 1    --END     --UPDATE Payroll_Employee SET IsYough = 0 WHERE AGE >= 36   PRINT 'Age Columns removed so this update query commnetted'  END    

