-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_UpdateEmployeeBargainingCouncilIncrease]  AS  BEGIN     UPDATE Notch    SET     Notch.MinimumSalary = bc.Y1IncreaseAmount,    Notch.MaximumSalary = bc.Y1IncreaseMaxAmount   FROM    (     SELECT *      FROM Payroll_Notch    ) Notch   LEFT JOIN Payroll_BargainingCouncilIncrease bc    ON bc.TaskGradeID = Notch.TaskGradeId and bc.Notch = Notch.Notch and bc.Enable = 0   where bc.Enable = 0     Update Payroll_BargainingCouncilIncrease set Enable = 1 where Enable = 0     Exec Payroll_UpdateCurrentEmployeeData      END

GO

-- ============================================
-- SP: Payroll_UpdateEmployeeCalendar_sp
-- Schema: dbo
-- ============================================
/*   Author  : Richa Mills   Create Date : 2018/09/03   Description : Adds a Year to the Employee Calendar   Update Date : 12/09/2019 => Ferdi Botha: Create temp table to avoid table "locking"  */  CREATE procedure [Payroll_UpdateEmployeeCalendar_sp]  as  begin     set nocount on;     declare @i int = 1,     @c int = 0,     @EmployeeID int = null,     @systemDate datetime = getdate()     declare @employees table (      [ID] int identity(1, 1) not null,    [EmployeeID] int not null,    [Days] int not null     )     insert into @employees([EmployeeID], [Days])      select [EmployeeID], count([Date])       from [Payroll_EmployeeCalander] with(nolock)       where ([Date] >= @systemDate)       group by [EmployeeID]        having (count([Date]) < 365)     select @c = count([ID]) from @employees     while (@i <= @c)   begin      select @EmployeeID = [EmployeeID] from @employees where ([ID] = @i)      exec [Payroll_CreateEmployeeCalendar_sp] @EmployeeID, 0      set @i = @i + 1     end     set nocount off;    end

GO

-- ============================================
-- SP: Payroll_UpdateEmployeeCycle
-- Schema: dbo
-- ============================================
  /*  Modiri  2019/10/24  https://dev.azure.com/Sebata-Dev/Sebata.EMS/_workitems/edit/21656  */    CREATE PROCEDURE dbo.Payroll_UpdateEmployeeCycle   @EmployeeID int  AS    BEGIN   DECLARE @CycleID int     SELECT @CycleID =PE.CycleID FROM Payroll_Employee PE WHERE PE.Employee_ID =@EmployeeID     IF EXISTS(select 1 from Payroll_Employeehistory where EmployeeID =@EmployeeID and Cycleid <>@CycleID)   BEGIN    UPDATE Payroll_Employeehistory     SET Cycleid =@CycleID    WHERE  EmployeeID =@EmployeeID   END     IF EXISTS(select 1 from Payroll_TrialRun_History_Employees where Employee_ID =@EmployeeID and Cycle_id <>@CycleID)   BEGIN    UPDATE Payroll_TrialRun_History_Employees     SET Cycle_id =@CycleID    WHERE  Employee_ID =@EmployeeID   END     IF EXISTS(select 1 from Payroll_TrialResults where EmployeeID =@EmployeeID and cycleid <>@CycleID)   BEGIN    UPDATE Payroll_TrialResults     SET cycleid =@CycleID    WHERE  EmployeeID =@EmployeeID   END     IF EXISTS(select 1 from Payroll_TrialRun_History_Employees where Employee_ID =@EmployeeID and cycle_id <>@CycleID)   BEGIN    UPDATE Payroll_TrialRun_History_Employees     SET cycle_id =@CycleID    WHERE  Employee_ID =@EmployeeID   END      IF EXISTS(select 1 from Payroll_EmployeeFinalRunHistory where EmployeeID =@EmployeeID and cycleid <>@CycleID)   BEGIN    UPDATE Payroll_EmployeeFinalRunHistory     SET cycleid =@CycleID    WHERE  EmployeeID =@EmployeeID   END    END

GO

-- ============================================
-- SP: Payroll_UpdateEmployeeEmploymentChange
-- Schema: dbo
-- ============================================
  /*   Modiri   2019/09/02   #90963 Lephalale: employee transfer  */    CREATE procedure [dbo].[Payroll_UpdateEmployeeEmploymentChange] @EmployeeID INT  as  begin         declare @dateYear int = YEAR(GETDATE()), --cast(right(@dateValue, 4) as int),     @dateMonth int =MONTH(GETDATE()),-- cast(right(left(@dateValue, 5), 2) as int),     @dateDay int = DAY(GETDATE()) --cast(left(@dateValue, 2) as int)     declare @date varchar(19) = convert(nvarchar(19), datefromparts(@dateYear, @dateMonth, @dateDay), 120)     declare @tbl table   (    idx int identity(1,1),    EmployeeID int,    PositionID int,    JobProfileID int,    TaskGradeID int   )   INSERT INTO @tbl(EmployeeID,PositionID,JobProfileID,TaskGradeID)   SELECT distinct [PE].Employee_ID, [PE].[PositionID],[PE].[JobProfileID],[TaskGradeId]   from [Payroll_Employee] as [PE]    join [Payroll_EmployeeHistory] as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[Enabled] = 1        join [Payroll_JobProfile] as [JB] on [JB].[JobProfile_ID] = [PE].[JobProfileID]   where (@date >= [PEH].[StartDate] and @date <= [PEH].[EndDate] and [PE].[Enabled] = 1 AND [PE].Employee_ID=@EmployeeID)       /* Employee (Position) Records */   update [PE] set [PE].[PositionID] = [PPH].[PositionID], [PE].[JobProfileID] = [PPH].[JobProfileID]      from [Payroll_Employee] as [PE]       join [Payroll_EmployeeHistory] as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID] and [PEH].[Enabled] = 1       join [Payroll_PositionHistory] as [PPH] on [PPH].[PositionHistory_ID] = [PEH].[PositionHistoryID] and [PPH].[Enabled] = 1      where (@date >= [PEH].[StartDate] and @date <= [PEH].[EndDate] and [PE].[Enabled] = 1  AND [PEH].EmployeeID=@EmployeeID)     /* Employee History (DepartmentID, DivisionID) Records */   update [PEH] set [PEH].[DepartmentID] = [PPH].[DepartmentID], [PEH].[DivisionID] = [PPH].[DivisionID]      from [Payroll_EmployeeHistory] as [PEH]       join [Payroll_PositionHistory] as [PPH] on [PPH].[PositionHistory_ID] = [PEH].[PositionHistoryID] and [PPH].[Enabled] = 1      where (@date >= [PEH].[StartDate] and @date <= [PEH].[EndDate] and [PEH].[Enabled] = 1  AND [PEH].EmployeeID=@EmployeeID)     /* Employee (History) Records */    update [PE] set [PE].[ReasonID] = [PEH].[ReasonID],       [PE].[Enabled] = [PEH].[Enabled],       [PE].[EmployeeTypeID] = [PEH].[EmployeeTypeID],       [PE].[EmployeeSubtypeID] = [PEH].[EmployeeSubtypeID],       [PE].[ConditionOfServiceID] = [PEH].[ConditionOfServiceID],       [PE].[CycleID] = [PEH].[CycleID],       [PE].[NotchId] = [PEH].[NotchID],       [PE].[ShiftRotationID] = [PEH].[ShiftRotationID],       [PE].[RotationID] = [PEH].[RotationID],       [PE].[BonusPaymentDateID] = [PEH].[BonusPaymentDateID],       [PE].[ExcludeUIFNonContributorReasonID] = [PEH].[ExcludeUIFNonContributorReasonID],       [PE].[RPD_Other] = [PEH].[RPD_Other],       [PE].[RPW_Other] = [PEH].[RPW_Other],       [PE].[WHPD_Monthly] = [PEH].[WHPD_Monthly],       [PE].[WHPD_Other] = [PEH].[WHPD_Other],       [PE].[WHPM_Monthly] = [PEH].[WHPM_Monthly],       [PE].[RPD_Monthly] = [PEH].[RPD_Monthly],       [PE].[WDPW_Other] = [PEH].[WDPW_Other],       [PE].[WDPM_Monthly] = [PEH].[WDPM_Monthly],       [PE].[RPH_Monthly] = [PEH].[RPH_Monthly],       [PE].[RPH_Other] = [PEH].[RPH_Other],       [PE].[FixedSalary] = [PEH].[MonthlySalary],       [PE].[BonusAmount] = [PEH].[BonusSalary],       [PE].[AnnualSalary] = [PEH].[AnnualSalary],       [PE].[BonusCalculation] = [PEH].[BonusCalculation],       [PE].[AllowOverTime] = [PEH].[AllowOverTime],       [PE].[TaxCalculationType] = [PEH].[TaxCalculationType],       [PE].[ExcludeUIF] = [PEH].[ExcludeUIF],       [PE].[ExcludeSDL] = [PEH].[ExcludeSDL],       [PE].[NotchChangeReason] = [PEH].[NotchChangeReason]      from [Payroll_Employee] as [PE]       join [Payroll_EmployeeHistory] as [PEH] on [PEH].[EmployeeID] = [PE].[Employee_ID]      where (@date >= [PEH].[StartDate] and @date <= [PEH].[EndDate]  AND [PE].Employee_ID=@EmployeeID)     /* Employee (TaskGradeID) Records */   update [PE] set /*[PE].[NotchId] = null,*/ [PE].[FixedSalary] = null, [PE].[BonusAmount] = null, [PE].[AnnualSalary] = null      from [Payroll_Employee] as [PE]       join [Payroll_Position] as [PP] on [PP].[EmployeeID] = [PE].[Employee_ID] and [PP].[Enabled] = 1       join [Payroll_JobProfile] as [JP] on [JP].[JobProfile_ID] = [PP].[JobProfileID] and [JP].[Enabled] = 1       join [Payroll_JobProfileHistory] as [JPH] on [JPH].[JobProfileID] = [JP].[JobProfile_ID] and [JPH].[Enabled] = 1       Join @tbl as [TBL] on [TBL].[EmployeeID] = [PE].[Employee_ID]      where (@date >= [JPH].[StartDate] and @date <= [JPH].[EndDate] and [PE].[Enabled] = 1  AND [PE].Employee_ID=@EmployeeID) and (isnull([TBL].TaskGradeID,0) <> ISNULL([JP].TaskGradeId,0) /*OR ([TBL].JobProfileID  <> [JP].JobProfile_ID)*/)    end  

GO

-- ============================================
-- SP: Payroll_UpdateEmployeeIsYouth_sp
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Seipei Mathole  -- Create date: 28 June 2016  -- Description: Update Payroll_Employee: set IsYough to 0 or 1 depending on age  -- 2016-06-28 TP38895 Seipei Mathole -   -- ==============================================================================    CREATE PROCEDURE [dbo].[Payroll_UpdateEmployeeIsYouth_sp]   @employeeID INT,   @dob datetime     AS     BEGIN      IF DATEDIFF(YEAR, @dob, getdate()) >= 36     BEGIN       UPDATE Payroll_Employee      SET IsYough = 0      WHERE Employee_ID = @employeeID     END      ELSE      BEGIN      UPDATE Payroll_Employee      SET IsYough = 1      WHERE Employee_ID = @employeeID     END  END  

GO

-- ============================================
-- SP: Payroll_UpdateEmployeeLeaveBalances
-- Schema: dbo
-- ============================================
      -- =============================================  -- Richa M 2021/01/22   -- Payroll_UpdateEmployeeLeaveBalances 454, 34  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_UpdateEmployeeLeaveBalances]   @EmployeeID INT,  @LeaveTypeId INT  AS    BEGIN      DECLARE @OpenBalance decimal(18,4)  DECLARE @AccruedBalance decimal(18,4)  DECLARE @Taken decimal(18,4)  DECLARE @Forfeit decimal(18,4)  DECLARE @Encashed decimal(18,4)  DECLARE @Accumulated decimal(18,4)  DECLARE @Adjusted decimal(18,4)  DECLARE @Balance decimal(18,4)       SELECT         @OpenBalance = ISNULL(SUM(LeaveTrx.OpeningBalance),0),        @AccruedBalance = ISNULL(SUM(LeaveTrx.Accrued),0),        @Taken = ISNULL(SUM(LeaveTrx.Taken),0),        @Forfeit = ISNULL(SUM(LeaveTrx.Forfeit),0),        @Encashed = ISNULL(SUM(LeaveTrx.Encashed),0),        @Accumulated = ISNULL(SUM(LeaveTrx.Accumulated),0),        @Adjusted = ISNULL(SUM(LeaveTrx.Adjusted),0),         @Balance = (ISNULL(SUM(LeaveTrx.OpeningBalance),0) + ISNULL(SUM(LeaveTrx.Accrued),0) + ISNULL(SUM(LeaveTrx.Accumulated),0) + ISNULL(SUM(LeaveTrx.Adjusted),0))         +          (ISNULL(SUM(LeaveTrx.Taken),0) + ISNULL(SUM(LeaveTrx.Forfeit),0) + ISNULL(SUM(LeaveTrx.Encashed),0))       FROM (SELECT       pelt.StartDate         ,pelt.EndDate         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 1 THEN pelt.Value        ELSE 0       END AS 'OpeningBalance'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 2 THEN pelt.Value        ELSE 0       END AS 'Accrued'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 3 THEN pelt.Value        ELSE 0       END AS 'Taken'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 4 THEN pelt.Value        ELSE 0       END AS 'Forfeit'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 5 THEN pelt.Value        ELSE 0       END AS 'Encashed'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 6 THEN pelt.Value        ELSE 0       END AS 'Accumulated'         ,CASE        WHEN pelt.LeaveAdjustmentTypeID = 7 THEN pelt.Value        ELSE 0       END AS 'Adjusted'         ,pelt.Value AS Balance      FROM Payroll_EmployeeLeaveTransactions pelt      WHERE pelt.EmployeeID = @EmployeeID      AND pelt.LeaveTypeID = @LeaveTypeId      AND pelt.LeaveStatusID = 3      AND pelt.Enabled = 1      AND pelt.LeaveStatusID <> (select Status_ID from Const_LeaveStatus_sys where StatusDesc = 'Cancelled' )      ) LeaveTrx    Update Payroll_EmployeeLeaveBalance set Balance = @OpenBalance,Accrued = @AccruedBalance,   Taken = @Taken,Forfeit = @Forfeit, Encashed = @Encashed,Adjusted = @Adjusted + @Accumulated, TotalLeaveDays = @Balance where EmployeeID = @EmployeeID and LeaveTypeID = @LeaveTypeId    --Update Leave Calendar   declare @EmpId int   declare @lstartDate datetime   declare @lenddate datetime         DECLARE db_cursor1 CURSOR FOR      select EmployeeID,StartDate,EndDate from Payroll_EmployeeLeaveTransactions where LeaveAdjustmentTypeID = 3 and Enabled = 1 and LeaveStatusID in (1,3) and (EmployeeID = @EmployeeId OR @EmployeeId = 0)       OPEN db_cursor1     FETCH NEXT FROM db_cursor1 INTO @EmpId,@lstartDate,@lEndDate       WHILE @@FETCH_STATUS = 0     BEGIN       update Payroll_EmployeeCalander set Leave = 1 where EmployeeID = @EmpId and date >= @lstartDate and Date <= @lenddate and Shift = 1 and PublicH = 0      FETCH NEXT FROM db_cursor1 INTO @EmpId,@lstartDate,@lEndDate     END      CLOSE db_cursor1     DEALLOCATE db_cursor1       END

GO

-- ============================================
-- SP: Payroll_UpdateEmployeePaymentDetails
-- Schema: dbo
-- ============================================
  /*     Author  : Richa Mills   Create Date : 07/11/2019   Description : Update Employee Payments Details => History    */  CREATE procedure [Payroll_UpdateEmployeePaymentDetails]  as  begin     declare @dateValue varchar(10) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'PayrollSchedulerDate'))     declare @dateYear int = cast(right(@dateValue, 4) as int),     @dateMonth int = cast(right(left(@dateValue, 5), 2) as int),     @dateDay int = cast(left(@dateValue, 2) as int)     declare @date varchar(19) = convert(nvarchar(19), datefromparts(@dateYear, @dateMonth, @dateDay), 120)     update [PE] set [PE].[PaymentTypeID] = CASE WHEN [PEH].[PaymentTypeID] = 0 THEN NULL ELSE [PEH].[PaymentTypeID] END,       [PE].[AccountTypeID] = CASE WHEN [PEH].[AccountTypeID] = 0 THEN NULL ELSE [PEH].[AccountTypeID] END,       [PE].[AccountHolderName] = [PEH].[AccountHolderName] ,       [PE].[AccountHolderRelationshipID] = CASE WHEN [PEH].[AccountHolderRelationshipID]= 0 THEN NULL ELSE [PEH].[AccountHolderRelationshipID] END,       [PE].[AccountNumber] = [PEH].[AccountNumber],       [PE].[BankID] = CASE WHEN [PEH].[BankID]= 0 THEN NULL ELSE [PEH].[BankID] END,       [PE].[BranchID] = CASE WHEN [PEH].[BranchID] = 0 THEN NULL ELSE [PEH].[BranchID] END,       [PE].[JointAccountEmployeeId] = [PEH].[JoinedAccountEmployeeId]      from [Payroll_Employee] as [PE]       join [Payroll_EmployeeAccountDetailHistory] as [PEH] on [PEH].[EmployeeId] = [PE].[Employee_ID] and [PEH].[Enabled] = 1      where (@date between [PEH].[StartDate] and [PEH].[EndDate] and [PE].[Enabled] = 1)    end

GO

