-- ============================================
-- SP: Payroll_UpdateEmployeeStatusOnTermination_sp
-- Schema: dbo
-- ============================================
  -- =======================================================================================================================  -- 2016-04-22 TP35500 Ravindra Jijotia : Added CycleModeID in filter.  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- ========================================================================================================================    CREATE PROCEDURE [dbo].[Payroll_UpdateEmployeeStatusOnTermination_sp]   @CycleID INT   AS  BEGIN     --DECLARE @CycleID INT = 0   DECLARE @COUNT INT = 0   DECLARE @Start INT = 0   DECLARE @PeriodEndDate datetime   DECLARE @EmployeeEndDate datetime   DECLARE @EmployeeID INT = 0      DECLARE @TerminatedEmployees TABLE (    Employee_ID INT,    EndDate datetime,    ROWNR INT    );       BEGIN TRAN      --DECLARE @CycleIDsCursor CURSOR SET @CycleIDsCursor = CURSOR FAST_FORWARD    --FOR    --SELECT Cycle_ID FROM Const_Cycle      --OPEN @CycleIDsCursor      --FETCH NEXT FROM @CycleIDsCursor INTO @CycleID      --WHILE @@FETCH_STATUS = 0    --BEGIN         --DELETE FROM @TerminatedEmployees       INSERT INTO @TerminatedEmployees      SELECT Employee_ID, EndDate, ROW_NUMBER() OVER (ORDER BY Employee_ID ASC) AS ROWNR       from payroll_employee where EndDate is not null and CycleID = @CycleID and Enabled = 1       IF (@@ERROR <> 0) GOTO ERR_HANDLER       SELECT top 1 @PeriodEndDate = PeriodEndDate from Payroll_CyclePeriodDetails       where CycleID = @CycleID and TaxYear = (select KeyValue from AAAA_ConfigSettings where KeyName= 'TaxYear') and Processed = 0 and CycleModeID = 1       IF (@@ERROR <> 0) GOTO ERR_HANDLER       SET @Start = 1     SELECT @COUNT = ISNULL(COUNT(1), 0) FROM @TerminatedEmployees       WHILE(@Start <= @COUNT)     BEGIN      SELECT @EmployeeID = Employee_ID, @EmployeeEndDate = EndDate from @TerminatedEmployees WHERE ROWNR = @Start        IF (@@ERROR <> 0) GOTO ERR_HANDLER        IF(@EmployeeEndDate < @PeriodEndDate)      BEGIN       UPDATE payroll_employee       SET Enabled = 0       WHERE Employee_ID = @EmployeeID         IF (@@ERROR <> 0) GOTO ERR_HANDLER      END        SET @Start = @Start + 1       END      -- FETCH NEXT FROM @CycleIDsCursor INTO @CycleID    --END      --CLOSE @CycleIDsCursor      --DEALLOCATE @CycleIDsCursor      IF (@@ERROR <> 0) GOTO ERR_HANDLER     COMMIT TRAN        ERR_HANDLER:     IF (@@ERROR <> 0)   BEGIN      PRINT 'Unexpected error occurred  in Payroll_UpdateEmployeeStatusOnTermination_sp!'    --ROLLBACK TRAN    RETURN 1   END      END  

GO

