-- ============================================
-- SP: Payroll_UpdateIRP5CodeHierarchy
-- Schema: dbo
-- ============================================
  /*   Author  : Ferd Botha   Create Date : 24/07/2018   Description : Adds all missing Payroll IRP5 Codes for the Period which have not been linked  */  create procedure [Payroll_UpdateIRP5CodeHierarchy] @PeriodID int  as  begin     set nocount on;     declare @IRP5Codes table (      [IRP5Code] int not null,    [ParentCode] int null,    [SalaryHeadID] int not null     )     declare @CyclePeriodAdhocSalaryHead table (      [SalaryHeadID] int not null,    [DateCaptured] datetime not null,    [CapturerID] int null     )     insert into @IRP5Codes exec [Payroll_GetIRP5CodeHierarchy] @PeriodID, null, null, null     insert into @CyclePeriodAdhocSalaryHead([SalaryHeadID], [DateCaptured], [CapturerID])      select [SalaryHeadID], [DateCaptured], [CapturerID]       from [Payroll_CyclePeriodAdhocSalaryHead] with(nolock)       where ([PeriodID] = @PeriodID and [Enabled] = 1)     insert into [Payroll_CyclePeriodAdhocSalaryHead]([PeriodID], [SalaryHeadID], [Enabled], [DateCaptured], [CapturerID])      select distinct @PeriodID, [SH].[SalaryHead_ID], 1, [CPD].[DateCaptured], [CPD].[CapturerID]       from @IRP5Codes as [IC]        join [Payroll_IRP5Code] as [IRP5] with(nolock) on isnull([IRP5].[IRP5CertCode], [IRP5].[IRP5Code]) = [IC].[ParentCode] and [IRP5].[Enabled] = 1        join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[IRP5CodeId] = [IRP5].[IRP5Code_ID] and [SH].[Enabled] = 1        cross apply (         select min([DateCaptured]) as [DateCaptured], min([CapturerID]) as [CapturerID]          from @CyclePeriodAdhocSalaryHead        ) as [CPD]       where (not [SH].[SalaryHead_ID] in(4, 5) and not exists(         select [CyclePeriodAdhocPayrollDefinition_ID]          from [Payroll_CyclePeriodAdhocSalaryHead]          where ([PeriodID] = @PeriodID and [Enabled] = 1 and [SalaryHeadID] = [SH].[SalaryHead_ID])        )       )     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_UpdateIRP5TaxTotalTransactions
-- Schema: dbo
-- ============================================
/*   Author  : Richa M   Create date : 2023/03/24   Description : Update IRP5TaxTotalTransactions   EXEC Payroll_IRP5TaxTotalTransactions 1,2024      */  CREATE PROCEDURE [dbo].[Payroll_UpdateIRP5TaxTotalTransactions]   @SalaryHeadId int,   @TaxYear int,   @EmployeeId varchar(max),   @Irp5CodeId int,   @UserId int  as  BEGIN    declare @Irp5Code int  declare @TransactionTypeId int    Select @Irp5Code = IRP5Code, @TransactionTypeId = TransactionTypeID from Payroll_IRP5Code where IRP5Code_ID = @Irp5CodeId    declare @RecordId int    Insert Into Payroll_IRP5CodeChange_Header     Select @TaxYear,@TransactionTypeId,@SalaryHeadId,@UserId,GETDATE()      Select @RecordId = @@IDENTITY    Insert Into Payroll_IRP5CodeChange_Detail   Select @RecordId,PayrollResult_ID,EmployeeID,IRP5CodeID,IRP5Code,@Irp5CodeId,@Irp5Code from Payroll_PayrollResults    where TaxYear = @TaxYear   and SalaryHeadID = @SalaryHeadId   and (@EmployeeId = '' OR EmployeeID in (select TRIM(value) from string_split(@EmployeeId,',')))    Update Payroll_PayrollResults    set IRP5Code = @Irp5Code,   IRP5CodeID = @Irp5CodeId   where TaxYear = @TaxYear   and SalaryHeadID = @SalaryHeadId   and (@EmployeeId = '' OR EmployeeID in (select TRIM(value) from string_split(@EmployeeId,',')))    select count(*)affectedRows from Payroll_PayrollResults    where TaxYear = @TaxYear   and SalaryHeadID = @SalaryHeadId   and (@EmployeeId = '' OR EmployeeID in (select TRIM(value) from string_split(@EmployeeId,',')))    END

GO

-- ============================================
-- SP: Payroll_UpdateMedicalAIDDependantModeToTerminated_sp
-- Schema: dbo
-- ============================================
-- =======================================================================================================================  -- Author  : Ravindra Jijotia TP19740  -- Create date : 14 AUG 2015  -- Description : Auto update dependant mode to Terminated on payroll run based on termination date.  -- Exec   : Payroll_UpdateMedicalAIDDependantModeToTerminated_sp 21  -- Call   : [Payroll_EmployeeSalaryGenerate_sp]  -- 2016-04-22 TP35500 Ravindra Jijotia : Added CycleModeID in filter.  -- 2016-08-19 : Varun Parvataneni:TP43204 Replacing the table Payroll_EmployeeDependantDetails with Payroll_PersonRelationshipType and return Dependant result WHERE IsAdultDependant =1 or IsChildDependant=1  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- ========================================================================================================================  CREATE PROCEDURE [dbo].[Payroll_UpdateMedicalAIDDependantModeToTerminated_sp]   @CycleID INT   AS  BEGIN   SET NOCOUNT ON;     DECLARE @COUNTEmp INT = 0   DECLARE @StartEmp INT = 0    DECLARE @EmployeeID INT = 0      DECLARE @EmployeesList TABLE (    Employee_ID INT,      ROWNR INT    );        DECLARE @TotalCount INT    DECLARE @Start INT   SET @Start = 1     DECLARE @DependantTbl TABLE   (    DependantID INT,    DependantMode INT,    [RowNo] INT   )            DECLARE @DependantID INT, @DependantMode INT     --DECLARE @CycleID INT   --SELECT @CycleID = ISNULL(CycleID, 0) FROM dbo.Payroll_Employee WHERE Employee_ID = @EmployeeID      DECLARE @ToDate DATE, @FromDate DATE   DECLARE @TaxYear nvarchar(50)       INSERT INTO @EmployeesList     SELECT Employee_ID, ROW_NUMBER() OVER (ORDER BY Employee_ID ASC) AS ROWNR      from payroll_employee where CycleID = @CycleID and Enabled = 1     SELECT @TaxYear = KEYVALUE FROM AAAA_ConfigSettings WHERE KeyName = 'TaxYear'       DECLARE @DATABASENAME NVARCHAR(50)      SELECT  @DATABASENAME = KeyValue FROM AAAA_ConfigSettings WHERE KeyName = 'FMSAuditDatabaseName'      SELECT TOP 1 @FromDate = CAST(PeriodStartDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear AND CycleModeID = 1      SELECT TOP 1 @ToDate = CAST(PeriodEndDate AS DATE)    FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND Processed = 0 AND TaxYear = @TaxYear AND CycleModeID = 1       SET @StartEmp = 1   SELECT @COUNTEmp = ISNULL(COUNT(1), 0) FROM @EmployeesList     IF (@@ERROR <> 0) GOTO ERR_HANDLER     WHILE(@StartEmp <= @COUNTEmp)   BEGIN    SELECT @EmployeeID = Employee_ID from @EmployeesList WHERE ROWNR = @StartEmp      INSERT INTO @DependantTbl    SELECT PersonRelationshipType_ID, DependantMode, ROW_NUMBER()OVER (ORDER BY DateOfBirth ASC) AS [RowNo]    FROM dbo.Payroll_PersonRelationshipType     WHERE EmployeeID = @EmployeeID AND Enabled = 1 AND DependantMode <> 4     AND (MedAidTerminateDate < @ToDate AND MedAidTerminateDate is not null)     AND (IsAdultDependant =1 or IsChildDependant=1)           SELECT @TotalCount = COUNT(1) FROM @DependantTbl             DECLARE @SQLQuery NVARCHAR(MAX)      WHILE(@Start <= @TotalCount)    BEGIN        SELECT @DependantID =  DependantID, @DependantMode = DependantMode        FROM @DependantTbl WHERE [RowNo]= @Start              IF(@DependantMode <> 4)        BEGIN         SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPayroll_PersonRelationshipType         (          AuditUserID , AuditDate , AuditUser , PersonRelationshipType_ID , EmployeeID , FullNames, Enabled, DateCaptured , CapturerID , DateModified , ModifierID , Surname , DateOfBirth , MedAidJoiningDate ,DependantMode , MedAidTerminateDate , IsAdultDependant,IsChildDependant         )         SELECT 1, GETDATE(), ''Admin User'', PersonRelationshipType_ID, EmployeeID, FullNames,Enabled, DateCaptured, CapturerID, DateModified, ModifierID, Surname, DateOfBirth,  MedAidJoiningDate, DependantMode,MedAidTerminateDate,IsAdultDependant,IsChildDependant FROM Payroll_PersonRelationshipType WHERE PersonRelationshipType_ID = ' + CONVERT(NVARCHAR(50), @DependantID)     EXEC(@SQLQuery)             UPDATE Payroll_PersonRelationshipType SET DependantMode = 4 WHERE PersonRelationshipType_ID = @DependantID          END            SET @Start = @Start + 1    END        SET @StartEmp = @StartEmp + 1   END        ERR_HANDLER:     IF (@@ERROR <> 0)   BEGIN      PRINT 'Unexpected error occurred  in Payroll_UpdateMedicalAIDDependantModeToTerminated_sp!'    --ROLLBACK TRAN    RETURN 1   END        END  

GO

-- ============================================
-- SP: Payroll_UpdateOtherFinalRunTables
-- Schema: dbo
-- ============================================
  /*   Author  : FERDI BOTHA   Create date : 02/08/2017   Description : Updates Final Run Tables   Update  : 28/05/2019 - Added MOCDetailID     Modified by   Modiri Selao   Reason: included the claims table to be updated with the processed and processed period     22304 Incorrect Message for Overtime transactions that were included in a Final Run, no message for Claim transactions.   date: 2019/11/06   2023/03/16 - Richa M - Make start days 0 after first Final run    2025/10/01 - Richa M - Write Billing Transactions back to billing tables.    2025/10/20 - Richa M - Update PrevSalary in Payroll_Employee  */  CREATE procedure [dbo].[Payroll_UpdateOtherFinalRunTables] @PeriodID int, @UserID int,@PaymentdueDate Datetime  as    begin      begin try           set nocount on;          declare @TaxYear varchar(10), @FinYear varchar(10), @CycleID int, @StartDate datetime,@CycleModeId int       select @TaxYear = [TaxYear], @FinYear = [FinancialYear] , @CycleID = [CycleID], @StartDate = PeriodStartDate,@CycleModeId = CycleModeID      from [Payroll_CyclePeriodDetails] with(nolock) where [Period_ID] = @PeriodID       declare @rounding_reminder decimal(18, 2) = 0.01       declare @Employees table(      [EmployeeId] int     )       insert into @Employees     Select distinct EmployeeId from Payroll_TrialResults where PeriodID = @PeriodID and @CycleModeId = 1        Update payroll_Employee set PrevSalary = FixedSalary where Employee_ID in (select Employee_ID from @Employees)        /* 2 months old periods that must be processed */      begin      declare @Periods table (        [ID] [int] identity(2,1) not null,    [PeriodId] [int]      )      insert into @Periods (PeriodId)     select distinct top 2 [Period_ID] from [Payroll_CyclePeriodDetails]     where [CycleID] = @CycleID and [CycleModeID] = 1 and [Processed] = 1 and [Period_ID] < @PeriodID      order by [Period_ID] desc      INSERT INTO @Periods (PeriodId)     SELECT TOP 1 Period_ID     FROM Payroll_CyclePeriodDetails    WHERE CycleID = @CycleID AND CycleModeID = 1 AND Processed = 0 AND TaxYear = @TaxYear AND @StartDate >= PeriodStartDate    ORDER BY Period_ID ASC      if(not exists(select [PeriodId] from @Periods where [PeriodId] = @PeriodID))    begin     insert into @Periods (PeriodId) select @PeriodID    end     end       /* Third Party Payment */      begin      insert into [dbo].[Payroll_3rdPartyPaymentHistory]               ([PartyPayment_ID],[EmployeeID],[VendorID],[TotalAmount],[Periods],[EMI],[Balance],[Enabled],[DateCaptured],[CapturerID],[DateModified]               ,[ModifierID],[PartyPaymentDate],[MOCID],[ReferenceNo],[EarDedTypeId],[Period_ID],[MOC_Value],[SalaryheadID],[ProcessedOnPeriodId],[Processed])           select [PartyPayment_ID],[EmployeeID] , [VendorID] ,[TotalAmount],[Periods],[EMI],[Balance],[Enabled] ,[DateCaptured],[CapturerID],[DateModified],              [ModifierID] ,[PartyPaymentDate],[MOCID],[ReferenceNo],[EarDedTypeId],[Period_ID], [MOC_Value], [SalaryheadID], @PeriodID ,(case when [Balance] = 0 then 1 else 0 end) as [Processed]              from (            select [PP].[PartyPayment_ID] as [PartyPayment_ID],[PP].[EmployeeID] as [EmployeeID] ,[PP].[VendorID] as [VendorID] ,[PP].[TotalAmount] as [TotalAmount], [PP].[Periods] as [Periods],[PP].[EMI] as [EMI],            (case when ([PP].[Balance] - ([PP].[EMI] * [P].[ID])) >= 0 then ([PP].[Balance] - ([PP].[EMI] * [P].[ID])) else [PP].[Balance] end) as [Balance],                 [PP].[Enabled] as [Enabled] ,[PP].[DateCaptured] as [DateCaptured],[PP].[CapturerID] as [CapturerID],[PP].[DateModified] as [DateModified],            [PP].[ModifierID] as [ModifierID] ,[PP].[PartyPaymentDate] as [PartyPaymentDate],[PP].[MOCID] as [MOCID], [PP].[ReferenceNo] as [ReferenceNo],[PP].[EarDedTypeId] as [EarDedTypeId],            [PP].[Period_ID] as [Period_ID],[PP].[MOC_Value] as [MOC_Value],[PP].[SalaryheadID] as [SalaryheadID]              from [Payroll_3rdPartyPayment] [PP] with(nolock)              join [Payroll_TrialRun_History_Employees][HE] with(nolock) on [PP].EmployeeID = [HE].[Employee_ID] and [HE].[Period_ID] = @PeriodID         join @Periods [P] on [P].[PeriodId] = [PP].[Period_ID] and [P].[PeriodId] <> @PeriodID         where [PP].[PartyPayment_ID] not in (select[PartyPayment_ID] from [Payroll_3rdPartyPaymentHistory] with(nolock))        and [PP].[Balance] > 0 and ([PP].[Processed] = 0  or [PP].[Processed] is null)            group by [PartyPayment_ID],[EmployeeID] , [VendorID] ,[TotalAmount],[Periods],[EMI],[Balance],[Enabled] ,[DateCaptured],[CapturerID],[DateModified],              [ModifierID] ,[PartyPaymentDate],[MOCID],[ReferenceNo],[EarDedTypeId],[PP].[Period_ID], [MOC_Value], [SalaryheadID], [P].[ID]          union             select [PP].[PartyPayment_ID] as [PartyPayment_ID],[PP].[EmployeeID] as [EmployeeID] ,[PP].[VendorID] as [VendorID] ,[PP].[TotalAmount] as [TotalAmount], [PP].[Periods] as [Periods],        (case        when abs([PP].[Balance] - [PP].[EMI]) = @rounding_reminder or ([PP].[Balance] - [PP].[EMI]) < 0         then [PP].[Balance]       else [PP].[EMI]       end) as [EMI],            (case        when abs([PP].[Balance] - [PP].[EMI]) = @rounding_reminder or ([PP].[Balance] - [PP].[EMI]) < 0         then 0       else [PP].[Balance] - [PP].[EMI]      end) as [Balance],          [PP].[Enabled] as [Enabled] ,[PP].[DateCaptured] as [DateCaptured],[PP].[CapturerID] as [CapturerID],[PP].[DateModified] as [DateModified],              [PP].[ModifierID] as [ModifierID] ,[PP].[PartyPaymentDate] as [PartyPaymentDate],[PP].[MOCID] as [MOCID], [PP].[ReferenceNo] as [ReferenceNo],[PP].[EarDedTypeId] as [EarDedTypeId],              [PP].[Period_ID] as [Period_ID],[PP].[MOC_Value] as [MOC_Value],[PP].[SalaryheadID] as [SalaryheadID]           from [Payroll_3rdPartyPayment] [PP] with(nolock)            join [Payroll_TrialRun_History_Employees] [HE] with(nolock) on [PP].EmployeeID = [HE].[Employee_ID] and [HE].[Period_ID] = @PeriodID              where ([PP].[EmployeeID] = [HE].[Employee_ID] and [PP].[Enabled] = 1 and [PP].[Balance] > 0             and ([PP].[Processed] = 0  or [PP].[Processed] is null) and [PP].[Balance] > 0 and ([PP].[Period_ID] <= @PeriodID                 and [PP].[PartyPayment_ID] not in (                 select [PartyPayment_ID] from [Payroll_3rdPartyPayment] as [PP] with(nolock)                         join @Periods [P] on [P].[PeriodId] = [PP].[Period_ID] and [P].[PeriodId] <> @PeriodID             where [PP].[Enabled] = 1 and [PP].[Balance] > 0                 and ([PP].[Processed] = 0  or [PP].[Processed] is null) and [PP].[PartyPayment_ID] not in (select[PartyPayment_ID] from [Payroll_3rdPartyPaymentHistory] with(nolock))                       )))          ) [List] order by [Balance] desc                       update [PP] set [Balance] = [PH].[Balance], [PP].[Processed] = [PH].[Processed]         from [Payroll_3rdPartyPayment] as [PP]         join [Payroll_3rdPartyPaymentHistory] as [PH] with(nolock) on [PP].[PartyPayment_ID] = [PH].[PartyPayment_ID] and  [PH].[ProcessedOnPeriodId] = @PeriodID               end           /* Cost Center */      begin          update [CC] set [CC].[Processed] = 1 , [CC].[ProcessedOnPeriodId] = @PeriodID          from [dbo].[Payroll_CostCenter] [CC] with(nolock)                  join [Payroll_TrialRun_History_Employees] [HE] with(nolock) on [CC].[EmployeeID] = [HE].[Employee_ID] and [HE].[Period_ID] = @PeriodID         where ([CC].[EveryMonth] is null or [CC].[EveryMonth] = 0)  and ([CC].[Processed] is null or [CC].[Processed] = 0) and [CC].[Enabled] = 1 and [CC].[PeriodID] in (select [PeriodId] from @Periods)       insert into [dbo].[Payroll_CostCenter_EveryMonth]         ([PayrollCostCenterID],[EmployeeID],[PayrollDefinitionID],[Description],[Amount],[PeriodID],[Enabled],[MunicipalityID]         ,[DateCaptured],[CapturedBy],[DateModified],[ModifierID],[SalaryheadID])            select distinct [CC].[CostCenter_ID],[CC].[EmployeeID],[CC].[PayrollDefinationID],[CC].[CostDesc],[CC].[CostAmount],@PeriodID,[CC].[Enabled],[CC].[MunicipalityID]             ,[CC].[DateCaptured] ,[CC].[CapturerID],[CC].[DateModified],[CC].[ModifierID],[CC].[SalaryheadID] from [dbo].[Payroll_CostCenter] [CC] with(nolock)                   join [Payroll_TrialRun_History_Employees] [HE] with(nolock) on [CC].[EmployeeID] = [HE].[Employee_ID] and [HE].[Period_ID] = @PeriodID               where [CC].[EveryMonth] = 1 and [CC].[Enabled] = 1 and ([CC].[Processed] is null or [CC].[Processed] = 0)                   and  [CC].[PeriodID] >= (select min(PeriodID) from @Periods) and [CC].[PeriodID] <= (select max(PeriodID) from @Periods)              end          /* Overtime */      begin         update [OT] set [OT].[Processed] = 1 , [OT].[ProcessedOnPeriodId] = @PeriodID          from [dbo].[Payroll_EmployeeOverTime] [OT] with(nolock)              join [Payroll_Employee] [PE] with(nolock) on [OT].[EmployeeID] = [PE].[Employee_ID]                  join [Payroll_TrialRun_History_Employees] [HE] with(nolock) on [OT].[EmployeeID] = [HE].[Employee_ID]          where ([OT].[Processed] is null or [OT].[Processed] = 0)               and [PE].[CycleID] = @CycleID               and [OT].[PeriodID] in (select [PeriodId] from @Periods)               and EmployeeID in (select distinct EmployeeId from Payroll_TrialResults where PeriodID = @PeriodID )            end        /* Claims */      begin         update [EC] set [EC].[Processed] = 1 , [EC].[ProcessedOnPeriodId] = @PeriodID          from [dbo].[Payroll_EmployeeClaims] [EC] with(nolock)              join [Payroll_Employee] [PE] with(nolock) on [EC].[EmployeeID] = [PE].[Employee_ID]                  join [Payroll_TrialRun_History_Employees] [HE] with(nolock) on [EC].[EmployeeID] = [HE].[Employee_ID]          where ([EC].[Processed] is null or [EC].[Processed] = 0) and [PE].[CycleID] = @CycleID and [EC].[PeriodID] in (select [PeriodId] from @Periods)          and EmployeeID in (select distinct EmployeeId from Payroll_TrialResults where PeriodID = @PeriodID )            end        /* Wages */    UPDATE WT     SET Processed = 1, ProcessedOnPeriodId = @PeriodID    FROM Payroll_WageTransaction AS WT    JOIN Payroll_TrialRun_History_Employees AS TRHE WITH(NOLOCK) ON WT.EmployeeId = TRHE.Employee_ID     WHERE      WT.IsApproved = 1     AND WT.Processed = 0     AND WT.CapturedDuringPeriodId = @PeriodID     AND WT.Enabled = 1     AND EmployeeID in (select distinct EmployeeId from Payroll_TrialResults where PeriodID = @PeriodID )       /* Billing Transactions */   DECLARE @BillingSalaryHeadID INT;   SELECT TOP (1)        @BillingSalaryHeadID = sh.SalaryHead_ID   FROM dbo.Payroll_SalaryHead sh   WHERE sh.BillingTransaction = 1     AND ISNULL(sh.Enabled,1) = 1;    WITH CostLines AS  (      SELECT          pc.TrialResult_ID,          pc.EmployeeID,          pc.PeriodID,          pc.PaymentDate       AS InstalmentDate,          pc.Amount            AS InstalmentAmount,          CAST(pc.Calculation AS NVARCHAR(200)) AS ReferenceNo,          TRY_CONVERT(INT, SUBSTRING(ref, p1 + 1, p2 - p1 - 1))          AS AccountId,          TRY_CONVERT(INT, SUBSTRING(ref, p2 + 1, LEN(ref) - p2))         AS PropertyId      FROM dbo.Payroll_TrialResults pc WITH (NOLOCK)      CROSS APPLY (SELECT ref = CAST(pc.Calculation AS NVARCHAR(200))) r      CROSS APPLY (SELECT p1 = CHARINDEX(':', r.ref),                          p2 = CHARINDEX(':', r.ref, CHARINDEX(':', r.ref) + 1)) pos      WHERE pc.PeriodID     = @PeriodID        AND pc.SalaryheadID = @BillingSalaryHeadID        AND pc.Amount <> 0        AND r.ref LIKE N'BILL:%:%'          -- guard broken values        AND pos.p1 > 0 AND pos.p2 > pos.p1  -- guard malformed splits  ),  Resolved AS  (      SELECT          cl.TrialResult_ID,          cl.EmployeeID,          cl.PeriodID,          cl.InstalmentDate,          cl.InstalmentAmount,          cl.AccountId,          cl.PropertyId,          d.EmployeeDeduction_ID AS EmployeeDeductionID      FROM CostLines cl      INNER JOIN dbo.Billing_EmployeeDeduction d WITH (NOLOCK)          ON d.EmployeeId  = cl.EmployeeID         AND d.AccountId   = cl.AccountId         AND d.PropertyId  = cl.PropertyId         AND d.CommencementDate <= ISNULL(cl.InstalmentDate, '19000101')         AND (d.TerminationDate IS NULL OR d.TerminationDate >= ISNULL(cl.InstalmentDate, '19000101'))  )  INSERT INTO dbo.Billing_EmployeeDeductionDetails  (        EmployeeDeductionID, InstalmentDate, InstalmentAmount,        PaymentDate, PaymentAmount, Reason, FinancialYear, PeriodId,        CurrentOutStanding, ReceiptNo, Enabled, DateCaptured, CapturerID, DateModified, ModifierID  )  SELECT        r.EmployeeDeductionID      , NULL      , NULL      , r.InstalmentDate      , r.InstalmentAmount      , N'Payroll deduction - ' + CAST(r.TrialResult_ID AS NVARCHAR(20))  -- <-- fixed      , @FinYear      , r.PeriodID      , NULL      , NULL      , 1      , SYSUTCDATETIME()      , @UserID      , NULL      , NULL  FROM Resolved r  WHERE NOT EXISTS  (      SELECT 1      FROM dbo.Billing_EmployeeDeductionDetails b WITH (NOLOCK)      WHERE b.EmployeeDeductionID = r.EmployeeDeductionID        AND b.PeriodId            = r.PeriodID        AND b.InstalmentDate      = r.InstalmentDate        AND b.InstalmentAmount    = r.InstalmentAmount        AND ISNULL(b.Enabled,1)   = 1  );                /* Payroll Results */      begin       insert into [Payroll_PayrollRun_History_Employees]([Employee_ID],[Period_ID],[Cycle_ID],[CycleModeID],[EmpCode],[StartDate],[EndDate],[TaxYear],[Period],[TaxCredits], [PAYEType], [PAYEValue], [PAYEBonus], [PAYEBalance],[SecondaryMTC])      select [Employee_ID],[Period_ID],[Cycle_ID],[CycleModeID],[EmpCode],[StartDate],[EndDate],[TaxYear],[Period],[TaxCredits], [PAYEType], [PAYEValue], [PAYEBonus], [PAYEBalance],[SecondaryMTC]       from Payroll_TrialRun_History_Employees with (nolock)  where ([Period_ID] = @PeriodID)        insert into [Payroll_PayrollResults]([CycleID], [PeriodID], [EmployeeID], [DepartmentID], [DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID],              [TransactionTypeID], [PaymentTypeID], [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [PaymentDate],              [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc], [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID],              [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [Amount], [Calculation],[TaxSavePurpose],[ContraSCOAProjectId], [ContraSCOAItemId],[ContraSCOACostingID],[ContraSCOAFunctionID],[ContraSCOAFundingId],[ContraSCOARegionID],[ContraPlanProjectItemId], [MOCDetailID], [IsRFI],[ProjectId],[ContraProjectId],[ContraDivisionId],[TrialResultId])      select [CycleID], [PeriodID], [EmployeeID], [DepartmentID], [DivisionID], [IRP5CodeID], [SalaryHeadID], [VendorID], [ControlVoteID], [TransactionTypeID], [PaymentTypeID],        [Processed], [EmpRecCount], [IRP5Code], [SalaryTitle], [TaxPeriod], [TaxYear], [PaymentDate], [FinancePeriod], [FinanceYear], [DepartmentDesc], [DivisionDesc],        [PlanProjectItemID], [SCOAProjectID], [SCOAItemID], [SCOACostingID], [SCOAFunctionID], [SCOAFundingID], [SCOARegionID], [Amount], [Calculation],[TaxSavePurpose],[ContraSCOAProjectId], [ContraSCOAItemId],[ContraSCOACostingID],[ContraSCOAFunctionID],[ContraSCOAFundingId],[ContraSCOARegionID],[ContraPlanProjectItemId], [MOCDetailID], [IsRFI],[ProjectId],[ContraProjectId],[ContraDivisionId],[TrialResult_Id]       from [Payroll_TrialResults] with(nolock)       where ([PeriodID] = @PeriodID)       order by TrialResult_ID           end          /* Employee Payslip */      begin    insert into [Payroll_EmployeePayslip]([EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], [Enabled], [DateCaptured], [CapturerID], [PeriodID],               [TaxSavePurpose], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear])      select [EmployeeID], [PayrollDefinationID], [Amount], [Month], [FinancialYear], 1, getdate(), @UserID, [PeriodID], [TaxSavePurpose], [SalaryHeadTitleAddendum], [ReferenceNo], [TaxYear]       from [Payroll_EmployeeTrialPayslip] with(nolock)       where ([PeriodID] = @PeriodID)    end        /* Clear staging tables */     begin    delete from [Payroll_TrialResults] where ([PeriodID] = @PeriodID)      delete from [Payroll_EmployeeTrialPayslip] where ([PeriodID] = @PeriodID)      delete from [Payroll_TrialErrors] where ([PeriodID] = @PeriodID)      delete from [Payroll_FinalErrors] where ([PeriodID] = @PeriodID)       end       /* Cycle Period Details */        begin    update [Payroll_CyclePeriodDetails] set [Processed] = 1, [ProcessedDate] = getdate() where ([Period_ID] = @PeriodID)        end       /* Trail Run History */     begin    if exists(Select PeriodId from [Payroll_TrailRun_History] with(nolock) where [PeriodId] = @PeriodID)      begin       update [Payroll_TrailRun_History] set [Status] = 'Completed', [Porcessed] = 1, [FinalUserId] = @UserID,PaymentdueDate = @PaymentdueDate where ([PeriodID] = @PeriodID)      end    else    begin         insert into [Payroll_TrailRun_History] ([FinancialYear], [PeriodId], [Status], [Porcessed], [TrialUserId], [FinalUserId], [TaxYear], [PaymentDueDate])          values (@FinYear, @PeriodId, 'Completed', 1, @UserID, @UserId, @TaxYear, @PaymentdueDate)      end      end       /* Deduction Priorities */      begin    IF EXISTS (SELECT TOP 1 1 FROM Payroll_DeductionsCarriedOverTrial WHERE PeriodId = @PeriodID)              INSERT INTO Payroll_DeductionsCarriedOverFinal                    (PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID)              SELECT PeriodId, EmployeeId, EmployeePayrollDefinitionId, Amount, Month, FinancialYear, SalaryHeadTitleAddendum, VendorID, ReferenceNo, TaxYear, ProjectID, DivisionId, ScoaItemID, FunctionId, RegionId, Simulation, MOCDetailID              FROM Payroll_DeductionsCarriedOverTrial WHERE PeriodId = @PeriodID    end      /*Defination History*/     begin          insert into [Payroll_EmployeePayrollDefinitionFinal]([EmployeePayrollDefinition_ID],[PayrollSalaryHeadID],[FunctionCodeID],[Percentage],[EmployeeID],[Enabled],[DateCaptured],[CapturerID],[DateModified],[ModifierID],      [CustomAction],[RepeateEveryYear],[IsRFI],[PayrollSalaryHeadEmployeeTitle],[SCOAFundsID],[SCOARegionID],[SCOACostingID],[SCOAProjectID],[SCOAItemID],[PeriodID])        select distinct [EmployeePayrollDefinition_ID],[PayrollSalaryHeadID],[FunctionCodeID],[Percentage],[EPD].[EmployeeID],[Enabled],[DateCaptured],[CapturerID],[DateModified],[ModifierID],      [CustomAction],[RepeateEveryYear],EPD.[IsRFI],[PayrollSalaryHeadEmployeeTitle],[SCOAFundsID],[EPD].[SCOARegionID],[EPD].[SCOACostingID],[EPD].[SCOAProjectID],[EPD].[SCOAItemID],@PeriodID      from  [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)      join [Payroll_PayrollRun_History_Employees] as [PHE] with(nolock) on [EPD].[EmployeeID] = [PHE].[Employee_ID] and [EPD].[Enabled] = 1 and [PHE].[Period_ID] = @PeriodID      join [Payroll_PayrollResults] as [PP] with(nolock) on [PP].[EmployeeID] = [EPD].[EmployeeID] and [PP].[PeriodID] = @PeriodID        insert into [dbo].[Payroll_PayrollDefinationFinal]     ([PayrollDefinationID] ,[PayrollDefinitionGroupID] ,[PayrollSalaryHeadID] ,[FunctionCodeID]     ,[Percentage],[Enabled],[DateCaptured],[CapturerID],[DateModified],[ModifierID],[IsRFI],[SCOAFundsID] ,[SCOARegionID]     ,[SCOACostingID],[SCOAProjectID],[SCOAItemID],[PeriodID])      select distinct [PayrollDefination_ID], [PPD].[PayrollDefinitionGroupID] ,[PPD].[PayrollSalaryHeadID], [PPD].[FunctionCodeID], [PPD].[Percentage], [PPD].[Enabled], [PPD].[DateCaptured],         [PPD].[CapturerID], [PPD].[DateModified], [PPD].[ModifierID], [PPD].[IsRFI], [PPD].[SCOAFundsID] ,[PPD].[SCOARegionID], [PPD].[SCOACostingID] ,[PPD].[SCOAProjectID],[PPD].[SCOAItemID],@PeriodID        from [Payroll_EmployeePayrollDefinitionFinal] as [EPDF] with(nolock)      join [Payroll_Employee] as [PE] with(nolock) on [EPDF].[EmployeeID] = [PE].[Employee_ID]       join [Payroll_PayrollDefination] as [PPD] with(nolock) on [PPD].[PayrollSalaryHeadID] = [EPDF].[PayrollSalaryHeadID] and [PPD].[Enabled] = 1        where [EPDF].[PeriodID] = @PeriodID  and [PPD].[PayrollDefinitionGroupID] = [PE].[PayrollDefinitionGroupID]            end      /*Start days*/    update Payroll_employee set StartDays = 0 where Employee_ID in (select EmployeeId from @Employees)     select cast(1 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(null as tinyint) as [ErrorGroup], cast(null as nvarchar(max)) as [ErrorMessage], cast(null as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast(null as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]    end try        begin catch     select cast(0 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(1 as tinyint) as [ErrorGroup], cast(error_message() as nvarchar(max)) as [ErrorMessage], cast(error_procedure() as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast('Global' as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]    end catch    set nocount off;    end

GO

-- ============================================
-- SP: Payroll_UpdatePaymentInstructionBankingDetails
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_UpdatePaymentInstructionBankingDetails]   @BatchID INT  AS  BEGIN   UPDATE pi   SET  pi.[EmployeeName] = eadh.[AccountHolderName],     pi.[EmployeeBankName] = b.[BankDesc],     pi.[EmployeeBankAccountNumber] = eadh.[AccountNumber],     pi.[EmployeeBankBranchCode] = bbc.[BankBranchCode],     pi.[EmployeeBankAccountType] = eadh.[AccountTypeID],     pi.IsBankDetailChanged = 1   FROM    Payroll_EmployeeAccountDetailHistory eadh   INNER JOIN    Payroll_PaymentInstructions pi ON eadh.[EmployeeId] = pi.[EmployeeID]             AND pi.[BatchID] = @BatchID             AND pi.[InstructionsStatus] IS NULL -- Status New   LEFT JOIN    Const_Bank b ON eadh.[BankID] = b.[Bank_ID]   LEFT JOIN    Const_BankBranchCode bbc ON eadh.[BranchID] = bbc.[BankBranchCode_ID]   WHERE    (     pi.[PaymentDueDate] BETWEEN eadh.[StartDate] AND eadh.[EndDate]    OR (eadh.[StartDate] <= pi.[PaymentDueDate] AND eadh.[EndDate] >= pi.[PaymentDueDate])    )   AND (     pi.[EmployeeName] <> eadh.[AccountHolderName]    OR pi.[EmployeeBankName] <> b.[BankDesc]    OR pi.[EmployeeBankAccountNumber] <> eadh.[AccountNumber]    OR pi.[EmployeeBankBranchCode] <> bbc.[BankBranchCode]    OR pi.[EmployeeBankAccountType] <> eadh.[AccountTypeID]    );  END;

GO

-- ============================================
-- SP: Payroll_UpdatePayroll_Transactions
-- Schema: dbo
-- ============================================
    /*   Author  : LUNGISANI KHUMALO   Create date : 18/08/2017   Description : Writes transactions and posts to ledger     */  CREATE procedure [dbo].[Payroll_UpdatePayroll_Transactions]   @DefaultSalaryCashBookVoteID int, @PeriodID int, @Group int     as  begin     if(@Group = 1)    begin                update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.DebitAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))                 update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.CreditAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))       end     if(@Group = 2)    begin                update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.DebitAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))                 update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.CreditAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))       end     if(@Group = 3)    begin                       update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.DebitAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))                 update pt set TransactionsGroupID = ptg.TransactionGroup_ID               from Payroll_Transactions pt          inner join Payroll_TransactionsGroup ptg on  ptg.PeriodID = pt.PeriodID and  ptg.VoteID = pt.VoteID and pt.VendorID = ptg.VendorID and  pt.SCOACostingID = ptg.SCOACostingID and pt.SCOAFunctionID = ptg.SCOAFunctionID and pt.SCOAFundsID = ptg.SCOAFundsID and pt.SCOAItemID = ptg.SCOAItemID and pt.SCOAProjectID = ptg.SCOAProjectID and  pt.SCOARegionID =ptg.SCOARegionID and pt.DivisionID = ptg.DivisionID            where   ptg.PeriodID  =  @PeriodID  and pt.PeriodID = @PeriodID and ptg.CreditAmount =  0 and pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID             and ((TransactionTypeID  =  2 and (pt.VoteID <> @DefaultSalaryCashBookVoteID and pt.SCOAItemID <> @DefaultSalaryCashBookVoteID) and (isnull(pt.EntryGoesDirectlyToLedger,0) <> 1) and (isnull(EntryGoesDirectlyToLedger,0) <> 1))                 OR  (TransactionTypeID  =  3 and (isnull(pt.EntryGoesDirectlyToLedger, 0) <> 1)))       end    end    

