-- ============================================
  /*   Author   : FERDI BOTHA   Creation Date : 2017/11/08   Description  : Create or Update the Employee and Prospective Employee Payroll Definitions, based on the linked Payroll Definition Group Salary Heads  */  create procedure [Payroll_UpdatePayrollDefinitionGroup_sp] @EmployeeID int, @DefinitionGroupID int, @UserID int, @disable bit, @prospective bit  as    begin     declare @db sysname = (select [KeyValue] from [AAAA_ConfigSettings] with (nolock) where ([KeyName] = 'FMSAuditDatabaseName')),     @Username nvarchar(50) = (select [UserName] from [User_UserDetail] where ([User_ID] = @UserID)),     @result int,     @sql nvarchar(max),     @DateCaptured datetime = getdate(),     @UserFinancialYear nvarchar(50) = (select [FinYearSelected] from [User_FinYearSelection] where ([UserID] = @UserID)),     @EmployeeTypeID int = 0     set nocount on;     begin transaction;      begin try       if (@prospective = 0)     begin        set @EmployeeTypeID = (select [EmployeeTypeID] from [Payroll_Employee] where ([Employee_ID] = @EmployeeID))        if (@EmployeeTypeID in(2, 3, 7))      begin         /* disable [if any] Employee Payroll Definitions has been assigned */       if (@disable = 1 and exists(select [EmployeePayrollDefinition_ID] from [Payroll_EmployeePayrollDefinition] with (nolock) where ([EmployeeID] = @EmployeeID and [Enabled] = 1)))       begin          set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])           select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]            from [Payroll_EmployeePayrollDefinition] as [EPD1] with(nolock)            where ([EmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and (not exists(              select top 1 1               from [Payroll_EmployeePayrollDefinition] as [EPD2] with(nolock)                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)               where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              ) or exists(              select top 1 1               from [Payroll_EmployeePayrollDefinition] as [EPD2]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)                join [Payroll_PayrollDefination] as [PD2] with(nolock) on [PD2].[PayrollDefinitionGroupID] = ' + cast(@DefinitionGroupID as varchar) + ' and [PD2].[PayrollSalaryHeadID] = [SH].[SalaryHead_ID] and [PD2].[Enabled] = 0               where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              )             )            )'          exec @result = sp_executesql @sql          if (@result = 0)           update [Payroll_EmployeePayrollDefinition] set [Enabled] = 0 where ([EmployeeID] = @EmployeeID and [Enabled] = 1 and (not exists(              select top 1 1               from [Payroll_EmployeePayrollDefinition] as [EPD2] with(nolock)                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)               where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_EmployeePayrollDefinition].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              ) or exists(              select top 1 1               from [Payroll_EmployeePayrollDefinition] as [EPD2]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)                join [Payroll_PayrollDefination] as [PD2] with(nolock) on [PD2].[PayrollDefinitionGroupID] = @DefinitionGroupID and [PD2].[PayrollSalaryHeadID] = [SH].[SalaryHead_ID] and [PD2].[Enabled] = 0               where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_EmployeePayrollDefinition].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              )             )            )         end         insert into [Payroll_EmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], @EmployeeID, 1, @DateCaptured, @UserID, [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_PayrollDefination] as [PD1] with (nolock)           where ([PayrollDefinitionGroupID] = @DefinitionGroupID and [Enabled] = 1 and not exists(             select top 1 1 from [Payroll_EmployeePayrollDefinition] with(nolock) where ([EmployeeID] = @EmployeeID and [Enabled] = 1 and [PayrollSalaryHeadID] = [PD1].[PayrollSalaryHeadID])            ) and not exists(             select top 1 1              from [Payroll_PayrollDefination] as [PD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([PD2].[PayrollDefination_ID] = [PD1].[PayrollDefination_ID] and [PD2].[Enabled] = 1)             )            )            order by [PayrollSalaryHeadID]         set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_EmployeePayrollDefinition] as [EPD1] with(nolock)           where ([EmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and [DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''' and not exists(             select top 1 1              from [Payroll_EmployeePayrollDefinition] as [EPD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID])             )            )'         exec @result = sp_executesql @sql        end      else      begin         /* disable [if any] Employee Payroll Definitions has been assigned */       if (@disable = 1 and exists(select [EmployeePayrollDefinition_ID] from [Payroll_EmployeePayrollDefinition] with (nolock) where ([EmployeeID] = @EmployeeID and [Enabled] = 1)))       begin          set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])           select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]            from [Payroll_EmployeePayrollDefinition] with(nolock)            where ([EmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1)'          exec @result = sp_executesql @sql          if (@result = 0)           update [Payroll_EmployeePayrollDefinition] set [Enabled] = 0 where ([EmployeeID] = @EmployeeID and [Enabled] = 1)         end         insert into [Payroll_EmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], @EmployeeID, 1, @DateCaptured, @UserID, [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_PayrollDefination] as [EPD] with (nolock)           where ([PayrollDefinitionGroupID] = @DefinitionGroupID and [Enabled] = 1 and not exists(             select top 1 1 from [Payroll_EmployeePayrollDefinition] with(nolock) where ([EmployeeID] = @EmployeeID and [Enabled] = 1 and [PayrollSalaryHeadID] = [EPD].[PayrollSalaryHeadID])            )           )            order by [PayrollSalaryHeadID]         set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_EmployeePayrollDefinition] with(nolock)           where ([EmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and [DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''')'         exec @result = sp_executesql @sql        end       end     else if (@prospective = 1)     begin        set @EmployeeTypeID = (select [EmployeeTypeID] from [Payroll_ProspectiveEmployee] where ([ProspectiveEmployee_ID] = @EmployeeID))        if (@EmployeeTypeID in(2, 3, 7))      begin         /* disable [if any] Prospective Employee Payroll Definitions has been assigned */       if (@disable = 1 and exists(select [EmployeePayrollDefinition_ID] from [Payroll_ProspectiveEmployeePayrollDefinition] with (nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1)))       begin          set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])           select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]            from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD1] with(nolock)            where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and (not exists(             select top 1 1              from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)             ) or exists(              select top 1 1               from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)                join [Payroll_PayrollDefination] as [PD2] with(nolock) on [PD2].[PayrollDefinitionGroupID] = ' + cast(@DefinitionGroupID as varchar) + ' and [PD2].[PayrollSalaryHeadID] = [SH].[SalaryHead_ID] and [PD2].[Enabled] = 0               where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              )             )            )'          exec @result = sp_executesql @sql          if (@result = 0)           update [Payroll_ProspectiveEmployeePayrollDefinition] set [Enabled] = 0 where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1 and (not exists(             select top 1 1              from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_ProspectiveEmployeePayrollDefinition].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)             ) or exists(              select top 1 1               from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2]                join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [EPD2].[PayrollSalaryHeadID] and [SH].[Enabled] = 1                join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [IRP5].[TransactionTypeID] in(1, 3)                join [Payroll_PayrollDefination] as [PD2] with(nolock) on [PD2].[PayrollDefinitionGroupID] = @DefinitionGroupID and [PD2].[PayrollSalaryHeadID] = [SH].[SalaryHead_ID] and [PD2].[Enabled] = 0               where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_ProspectiveEmployeePayrollDefinition].[EmployeePayrollDefinition_ID] and [EPD2].[Enabled] = 1)              )             )            )         end         insert into [Payroll_ProspectiveEmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], @EmployeeID, 1, @DateCaptured, @UserID, [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_PayrollDefination] as [PD1] with (nolock)           where ([PayrollDefinitionGroupID] = @DefinitionGroupID and [Enabled] = 1 and not exists(             select top 1 1 from [Payroll_ProspectiveEmployeePayrollDefinition] with(nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1 and [PayrollSalaryHeadID] = [PD1].[PayrollSalaryHeadID])            ) and not exists(             select top 1 1              from [Payroll_PayrollDefination] as [PD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([PD2].[PayrollDefination_ID] = [PD1].[PayrollDefination_ID] and [PD2].[Enabled] = 1)            )           )            order by [PayrollSalaryHeadID]         set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD1] with(nolock)           where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and [DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''' and not exists(             select top 1 1              from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2] with(nolock)               join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1               join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)              where ([EPD2].[EmployeePayrollDefinition_ID] = [EPD1].[EmployeePayrollDefinition_ID])             )            )'         exec @result = sp_executesql @sql        end      else      begin         /* disable [if any] Prospective Employee Payroll Definitions has been assigned */       if (@disable = 1 and exists(select [EmployeePayrollDefinition_ID] from [Payroll_ProspectiveEmployeePayrollDefinition] with (nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1)))       begin          set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])           select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]            from [Payroll_ProspectiveEmployeePayrollDefinition] with(nolock)            where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1)'          exec @result = sp_executesql @sql          if (@result = 0)           update [Payroll_ProspectiveEmployeePayrollDefinition] set [Enabled] = 0 where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1)         end         insert into [Payroll_ProspectiveEmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], @EmployeeID, 1, @DateCaptured, @UserID, [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_PayrollDefination] as [EPD] with (nolock)           where ([PayrollDefinitionGroupID] = @DefinitionGroupID and [Enabled] = 1 and not exists(             select top 1 1 from [Payroll_ProspectiveEmployeePayrollDefinition] with(nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1 and [PayrollSalaryHeadID] = [EPD].[PayrollSalaryHeadID])            )           )            order by [PayrollSalaryHeadID]         set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])          select ' + cast(@UserID as varchar) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]           from [Payroll_ProspectiveEmployeePayrollDefinition] with(nolock)           where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as varchar) + ' and [Enabled] = 1 and [DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''')'         exec @result = sp_executesql @sql        end       end      end try      begin catch       print error_line() + ' - ' + error_message()       rollback transaction;      end catch     if (@@trancount > 0)      commit transaction;     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_UpdatePrintHistory_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  MEHUL PANCHAL  -- Create date: 14 AUGUST 2014  -- Description: UPDATE PRINT HISTORY TABLE   -- Calls: [Payroll_UpdatePrintHistory_sp] 13,2  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_UpdatePrintHistory_sp]      @ID INT ,      @PrintUserId INT  AS       BEGIN            IF ( ( SELECT   COUNT(1)                 FROM     dbo.Const_PrintEXEHistory                 WHERE    ID = @ID               ) > 0 )               BEGIN                  DECLARE @DATABASENAME NVARCHAR(50)                  DECLARE @SQLQuery NVARCHAR(MAX)                  SELECT  @DATABASENAME = KeyValue                  FROM    AAAA_ConfigSettings                  WHERE   KeyName = 'FMSAuditDatabaseName'                    SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME                      + '.dbo.aConst_PrintEXEHistory          (          [AuditUserID],[AuditDate],[AuditUser], PrintExeID ,[ID],[EmployeeID], AccountID,[FinancialYear],[PeriodID],[MonthID],[WebUserId]            ,[PrintUserId],[PrintDate],[DateCaptured],[CapturerID],[DateModified],[ModifierID]          )          SELECT            1, GETDATE(), ''Admin User'',PrintExeID, [ID], [EmployeeID],AccountID,            [FinancialYear], [PeriodID] , [MonthID] , [WebUserId] , [PrintUserId] ,           [PrintDate], [DateCaptured], [CapturerID], [DateModified], [ModifierID]          FROM Const_PrintEXEHistory            WHERE  ID = ' + CONVERT(NVARCHAR(50), @ID)                      EXEC(@SQLQuery)                      UPDATE  Const_PrintEXEHistory                  SET     PrintDate = GETDATE() ,                          PrintUserId = @PrintUserId                  WHERE   ID = @ID               END      END  

GO

