-- ============================================
-- SP: Payroll_UpdateRotationAndShiftInEmployeeCalendar_sp
-- Schema: dbo
-- ============================================
/*   Author  : Ivan Myroshnychenko   Create Date : 2021/04/19   Description : Modify the employee calendar when changed Rotation or Shift for employee   E Beetge WI77581 - Joining date overwrites substitution start date  */    CREATE PROCEDURE [dbo].[Payroll_UpdateRotationAndShiftInEmployeeCalendar_sp]     @EmployeeID INT   , @ShiftRotationID INT    , @RotationID INT  , @StartDate DATETIME   , @UntilDate DATETIME = NULL    AS  BEGIN          SET nocount on;     DECLARE @IsSubstitute BIT = IIF(@UntilDate IS NULL, 1, 0)   DECLARE @TaxYear VARCHAR(10) = (SELECT [KeyValue] FROM [AAAA_ConfigSettings] with(nolock) WHERE ([KeyName] = 'TaxYear')),     @CycleId INT = NULL,     @JoiningDate DATETIME = NULL,     @StartWeek DATETIME = NULL,     @WeekNo INT = NULL,     @NoOfWeeks INT = NULL     DECLARE @leaveDays AS TABLE (      [Date] DATETIME  NOT NULL     )     DECLARE @days AS TABLE (      [Date] DATETIME  NOT NULL,    [Name] VARCHAR(9)  NOT NULL,    [DayNo] tinyint  NOT NULL     )     DECLARE @calendarDays AS TABLE (      [Date] DATETIME  NOT NULL,    [Name] VARCHAR(9)  NOT NULL,    [DayNo] tinyint  NOT NULL,    [WeekNo] INT  NOT NULL,    [WeekNoPerMnth] INT NULL,    [ShiftID] INT  NULL   )     SELECT @CycleId = [CycleID]    , @JoiningDate = [JoiningDate]    FROM [Payroll_Employee] with(nolock)    WHERE ([Employee_ID] = @EmployeeID)     SELECT @WeekNo = [WeekNo]    FROM [Payroll_ShiftRotationDetail]    WHERE ([Rotation_ID] = @RotationID)     SELECT @NoOfWeeks = count([Rotation_ID])    FROM [Payroll_ShiftRotationDetail]    WHERE ([ShiftRotationID] = @ShiftRotationID)     DECLARE @TaxYearStartDate DATETIME = (SELECT top 1 [PeriodStartDate] FROM [Payroll_CyclePeriodDetails] with(nolock) WHERE ([CycleID] = @CycleID and [PeriodInTaxYear] = 1 and [TaxYear] = @TaxYear and CycleModeID=1))     --IF (@JoiningDate > @TaxYearStartDate)   -- SET @StartDate = @JoiningDate     IF (@UntilDate IS NULL)   BEGIN     SET @UntilDate = dateadd(year, 2, @StartDate)    SET @UntilDate = dateadd(day, -1, @UntilDate);   END     IF (@StartDate IS  NOT NULL)   BEGIN      SET @StartWeek = @StartDate      WHILE((datepart(weekday, @StartWeek) - 1) > 1)    BEGIN     SET @StartWeek = dateadd(day, -1, @StartWeek)    END        INSERT INTO @days([Date], [Name], [DayNo])    SELECT [Date]     , datename(weekday, [Date])     , datepart(weekday, [Date])    FROM [Payroll_CreateCalendarDates] (@StartWeek, @UntilDate)    ORDER BY [Date]        DECLARE @oldrows INT = (SELECT COUNT(Date) FROM Payroll_EmployeeCalander WHERE EmployeeID=@employeeID AND DATE <@StartDate)      INSERT INTO @calendarDays([Date], [Name], [DayNo], [WeekNo],WeekNoPerMnth)    SELECT D.[Date]     , D.[Name]     , D.[DayNo]     , IIF(P_EC.WeekNo IS NOT NULL, P_EC.WeekNo, (((row_number() OVER(ORDER BY D.[Date]) - 1  + @oldrows)/ 7) + 1)) AS WeekNo     , datediff(week, dateadd(week, datediff(week, 0, dateadd(month, datediff(month, 0, D.[Date]), 0)), 0), D.[Date] - 1) + 1    FROM @days AS D    LEFT JOIN Payroll_EmployeeCalander AS P_EC     ON P_EC.EmployeeID = @employeeID AND D.Date = P_EC.Date      DELETE FROM @calendarDays WHERE ([Date] < @StartDate)          INSERT INTO @leaveDays([Date])    SELECT [Date] FROM [Payroll_EmployeeCalander] with(nolock) WHERE ([EmployeeID] = @EmployeeID and [Leave] = 1)        /*Work on shift rotation*/    IF(SELECT count(*) FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID) =1    BEGIN     UPDATE @calendarDays     SET ShiftID = (SELECT dbo.Payroll_ShiftRotationDetail.WeekNo FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID)    END    ELSE    BEGIN     UPDATE @calendarDays     SET ShiftID =1     WHERE WeekNoPerMnth=0          UPDATE c     SET c.ShiftID =ps.WeekNo     FROM @calendarDays c     JOIN [Payroll_ShiftRotationDetail] PS on PS.WeekNo = c.WeekNoPerMnth AND ps.ShiftRotationID=@ShiftRotationID              /*Deal with what is left as NULL on WeekNoPerMnth*/     IF(SELECT count(*) FROM [Payroll_ShiftRotationDetail] WHERE dbo.Payroll_ShiftRotationDetail.ShiftRotationID=@ShiftRotationID) =2     BEGIN      UPDATE @calendarDays      SET ShiftID =1      WHERE (WeekNoPerMnth % 2) =0            UPDATE @calendarDays      SET ShiftID =2      WHERE (WeekNoPerMnth % 2) <> 0     END    END         DELETE FROM @calendarDays WHERE ([Date] < @StartDate)        IF(@IsSubstitute = 1)     SET @UntilDate = (SELECT MAX(Date) FROM Payroll_EmployeeCalander WHERE EmployeeID=@EmployeeID)        DELETE FROM @calendarDays WHERE ([Date] > @UntilDate)          INSERT INTO @leaveDays([Date])    SELECT [Date] FROM [Payroll_EmployeeCalander] with(nolock) WHERE ([EmployeeID] = @EmployeeID and [Leave] = 1)            DROP TABLE IF EXISTS #Temp    CREATE TABLE #Temp (    ShiftRotationID INT    , Date DATETIME    , ShiftId INT    , ShiftHour INT     , NightHours INT    , Shift INT     , DateModified DATETIME    , ModifierID INT    , TotalHoursWorked INT)       INSERT INTO #Temp (ShiftRotationID , Date , ShiftId , ShiftHour, NightHours, Shift , DateModified, ModifierID, TotalHoursWorked )     SELECT [RT].[ShiftRotationID]        , [CAL].[Date]     , [RT].[ShiftId]      , [CS].[ShiftHour]     , [CS].[NightHours]        , IIF([CS].[TotalHoursWorked] > 0, 1, 0) AS Shift     , getdate()  AS DateModified     , 1 AS ModifierID     , [CS].[TotalHoursWorked]     FROM @calendarDays as [CAL]        join (         SELECT [ShiftRotationID], 'Monday' as [WeekDay], [Monday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)        WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Tuesday' as [WeekDay], [Tuesday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)        WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Wednesday' as [WeekDay], [Wednesday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)       WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Thursday' as [WeekDay], [Thursday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)        WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Friday' as [WeekDay], [Friday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)        WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Saturday' as [WeekDay], [Saturday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)       WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1          union all         SELECT [ShiftRotationID],'Sunday' as [WeekDay], [Sunday] as [ShiftId], [WeekNo] FROM [Payroll_ShiftRotationDetail] with(nolock)       WHERE ([ShiftRotationID] = @ShiftRotationID) AND Enabled =1         ) AS [RT]        ON [RT].[WeekDay] = [CAL].[Name]         AND [CAL].ShiftID = IIF((SELECT COUNT(WeekNo) FROM Payroll_ShiftRotationDetail WHERE ShiftRotationID = @ShiftRotationID AND Enabled=1 ) = 1             , CAL.ShiftID, RT.WeekNo)      JOIN [Const_Shift] AS [CS] with(nolock)        ON [CS].[Shift_ID] = [RT].[ShiftId]                  UPDATE P_EC      SET P_EC.RotationID = #Temp.ShiftRotationID      , P_EC.ShiftID = #Temp.ShiftId      , P_EC.NoOfHrs = #Temp.ShiftHour      , P_EC.NightHrs = #Temp.NightHours      , P_EC.Shift = #Temp.Shift      , P_EC.DateModified = #Temp.DateModified      , P_EC.ModifierID = #Temp.ModifierID      , P_EC.NoOfWorkingHrs= #Temp.TotalHoursWorked      FROM Payroll_EmployeeCalander AS P_EC      INNER JOIN #Temp       ON P_EC.Date = #Temp.Date AND P_EC.EmployeeID = @EmployeeID          UPDATE pc      SET pc.publich =1      FROM [Payroll_EmployeeCalander] pc      JOIN [Const_Holiday] ch                       ON MONTH(ch.HolidayDate) = MONTH(PC.Date)                       AND DAY(ch.HolidayDate) = DAY(PC.Date)                       AND (YEAR(PC.Date) BETWEEN YEAR(ch.CalendarYearFROM) AND YEAR(ch.CalendarYearTo))                      AND [EmployeeID]= @EmployeeID                       AND [Date] > @Startdate      --Add public holiday on Monday when public holiday on Sunday                  DROP TABLE IF EXISTS #Days                  CREATE TABLE #Days                  (                  EmployeeID INT      , Date DATETIME      )        INSERT INTO #Days (EmployeeID, Date)      SELECT EmployeeID, Date      FROM Payroll_EmployeeCalander       WHERE PublicH = 1       AND WeekDay = 1       AND EmployeeID = @EmployeeID        UPDATE P_EC      SET P_EC.PublicH = 1      FROM Payroll_EmployeeCalander AS P_EC      JOIN #Days        ON P_EC.Date IN (SELECT DATEADD(DAY,1,Date) FROM #Days) AND P_EC.EmployeeID = #Days.EmployeeID        update [Payroll_EmployeeCalander] SET [Leave] = 1 WHERE ([EmployeeID] = @EmployeeID and [Date] in(SELECT [Date] FROM @leaveDays))                    DROP TABLE #Days      DROP TABLE #Temp   END   SET nocount off;    END

GO

-- ============================================
-- SP: Payroll_UpdateSalaryStructureDefinitions_sp
-- Schema: dbo
-- ============================================
  /*   Author   : Ferdi Botha   Creation Date : 2017 - 11 - 09   Description  : Create or Update the Salary Structure Payroll Definitions, based on the linked Definitions   Modiri   2019/08/07   #92590 Salary Transaction not linked to employee once the Salary Structuring are completed and the user click the apply to Payslip button.   Update date     :   11/02/2020 - Ilya Skavronskiy - changed Bonus Amount calculation   Update date     :   22/02/2020 - Ilya Skavronskiy - fixed setting BonusCalculation for Prospective Employees  */  CREATE procedure [dbo].[Payroll_UpdateSalaryStructureDefinitions_sp] @EmployeeID int, @GroupID int, @UserID int, @prospective bit  as    begin     declare @db sysname = (select [KeyValue] from [AAAA_ConfigSettings] with (nolock) where ([KeyName] = 'FMSAuditDatabaseName')),     @Username nvarchar(50) = (select [UserName] from [User_UserDetail] where ([User_ID] = @UserID)),     @result int,     @sql nvarchar(max),     @DateCaptured datetime = getdate(),     @UserFinancialYear nvarchar(50) = (select [FinYearSelected] from [User_FinYearSelection] where ([UserID] = @UserID)),     @Days decimal(18, 6) = 21.67,     @Hours decimal(18, 6) = 8     set nocount on;     begin transaction;      begin try       if (@prospective = 0)     begin        set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select ' + cast(@UserID as nvarchar(16)) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], EPD.[EmployeeID], [EPD].[Enabled], [EPD].[DateCaptured], [EPD].[CapturerID], [SH].[IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]          from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)                  LEFT JOIN Payroll_CostCenter AS CC WITH(NOLOCK) ON EPD.EmployeePayrollDefinition_ID = CC.PayrollDefinationID and EPD.EmployeeID = CC.EmployeeID        where (EPD.[EmployeeID] = ' + cast(@EmployeeID as nvarchar(16)) + ' and [EPD].[Enabled] = 1) AND CC.CostCenter_ID IS NULL'        exec @result = sp_executesql @sql        if (@result = 0)         update [Payroll_EmployeePayrollDefinition] set [Enabled] = 0 where ([EmployeeID] = @EmployeeID and [Enabled] = 1 and exists(          select top 1 1           from [Payroll_EmployeePayrollDefinition] as [EPD2] with(nolock)            join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1            join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)          LEFT JOIN Payroll_CostCenter AS CC WITH(NOLOCK) ON EPD2.EmployeePayrollDefinition_ID = CC.PayrollDefinationID and EPD2.EmployeeID = CC.EmployeeID         where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_EmployeePayrollDefinition].[EmployeePayrollDefinition_ID])          AND CC.CostCenter_ID IS NULL          )         )        insert into [Payroll_EmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select PD.[PayrollSalaryHeadID], PD.[FunctionCodeID], PD.[Percentage], @EmployeeID, 1, @DateCaptured, @UserID, PD.[IsRFI], PD.[SCOAFundsID], PD.[SCOARegionID], PD.[SCOACostingID], PD.[SCOAProjectID], PD.[SCOAItemID]          from [Payroll_EmployeeSalaryTransaction] as [ET] with (nolock)           join [Payroll_PayrollDefination] as [PD] with (nolock) on [PayrollDefinitionGroupID] = @GroupID and [PayrollSalaryHeadID] = [SalaryHeadId] and [Enabled] = 1         LEFT JOIN Payroll_EmployeePayrollDefinition AS EPD WITH(NOLOCK) ON PD.PayrollSalaryHeadID = EPD.PayrollSalaryHeadID  AND ET.EmployeeId = EPD.EmployeeID AND EPD.Enabled = 1         LEFT JOIN Payroll_CostCenter AS CC WITH(NOLOCK) ON EPD.EmployeePayrollDefinition_ID = CC.PayrollDefinationID and ET.EmployeeID = CC.EmployeeID        WHERE ET.[EmployeeId] = @EmployeeID and PD.[Enabled] = 1         AND CC.CostCenter_ID IS NULL          order by PD.[PayrollSalaryHeadID]        set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_EmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select ' + cast(@UserID as nvarchar(16)) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [EmployeeID], [EPD].[Enabled], [EPD].[DateCaptured], [EPD].[CapturerID], [SH].[IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]          from [Payroll_EmployeePayrollDefinition] as [EPD] with(nolock)           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)          where ([EmployeeID] = ' + cast(@EmployeeID as nvarchar(16)) + ' and [EPD].[Enabled] = 1 and [EPD].[DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''' and [TransactionTypeID] in(1, 3))'        exec @result = sp_executesql @sql        if (exists(select top 1 1 from [Payroll_EmployeeSalaryTransaction] with(nolock) where ([EmployeeId] = @EmployeeID and [SalaryHeadId] = 1)))         update [PE] set [FixedSalary] = ([Amount] / 12), [AnnualSalary] = [Amount], [RPH_Monthly] = (([Amount] / 12) / isnull([WHPM_Monthly], @Hours * @Days)), [RPD_Monthly] = (([Amount] / 12) / isnull([WDPM_Monthly], @Days))          from [Payroll_Employee] as [PE]           join [Payroll_EmployeeSalaryTransaction] as [PET] on [EmployeeId] = [Employee_ID] and [SalaryHeadId] = 1          where ([Employee_ID] = @EmployeeID)        if (exists(select top 1 1 from [Payroll_EmployeeSalaryTransaction] with(nolock) where ([EmployeeId] = @EmployeeID and [SalaryHeadId] = 2)))         update [PE] set [BonusAmount] = [Amount]          from [Payroll_Employee] as [PE]           join [Payroll_EmployeeSalaryTransaction] as [PET] on [EmployeeId] = [Employee_ID] and [SalaryHeadId] = 2          where ([Employee_ID] = @EmployeeID)        else         update [Payroll_Employee] set [BonusCalculation] = NULL, [BonusAmount] = 0          where ([Employee_ID] = @EmployeeID)       end     else if (@prospective = 1)     begin        set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select ' + cast(@UserID as nvarchar(16)) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [EPD].[Enabled], [EPD].[DateCaptured], [EPD].[CapturerID], [SH].[IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]          from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD] with(nolock)           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)          where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as nvarchar(16)) + ' and [EPD].[Enabled] = 1)'        exec @result = sp_executesql @sql        if (@result = 0)         update [Payroll_ProspectiveEmployeePayrollDefinition] set [Enabled] = 0 where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1 and exists(          select top 1 1           from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD2] with(nolock)            join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1            join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)           where ([EPD2].[EmployeePayrollDefinition_ID] = [Payroll_ProspectiveEmployeePayrollDefinition].[EmployeePayrollDefinition_ID])          )         )        insert into [Payroll_ProspectiveEmployeePayrollDefinition]([PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], @EmployeeID, 1, @DateCaptured, @UserID, [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]          from [Payroll_ProspectiveEmployeeSalaryTransaction] as [ET] with (nolock)           join [Payroll_PayrollDefination] as [PD] with (nolock) on [PayrollDefinitionGroupID] = @GroupID and [PayrollSalaryHeadID] = [SalaryHeadID] and [PD].[Enabled] = 1          where ([ProspectiveEmployeeID] = @EmployeeID and [Enabled] = 1)           order by [PayrollSalaryHeadID]        set @sql = 'insert into [' + @db + '].[dbo].[aPayroll_ProspectiveEmployeePayrollDefinition]([AuditUserID], [AuditDate], [AuditUser], [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [Enabled], [DateCaptured], [CapturerID], [IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID])         select ' + cast(@UserID as nvarchar(16)) + ', ''' + convert(nvarchar(19), @DateCaptured, 120) + ''', ''' + @Username + ''', [EmployeePayrollDefinition_ID], [PayrollSalaryHeadID], [FunctionCodeID], [Percentage], [ProspectiveEmployeeID], [EPD].[Enabled], [EPD].[DateCaptured], [EPD].[CapturerID], [SH].[IsRFI], [SCOAFundsID], [SCOARegionID], [SCOACostingID], [SCOAProjectID], [SCOAItemID]          from [Payroll_ProspectiveEmployeePayrollDefinition] as [EPD] with(nolock)           join [Payroll_SalaryHead] as [SH] with(nolock) on [SalaryHead_ID] = [PayrollSalaryHeadID] and [SH].[Enabled] = 1           join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[Enabled] = 1 and [TransactionTypeID] in(1, 3)          where ([ProspectiveEmployeeID] = ' + cast(@EmployeeID as nvarchar(16)) + ' and [EPD].[Enabled] = 1 and [EPD].[DateCaptured] = ''' + convert(nvarchar(19), @DateCaptured, 120) + ''' and [TransactionTypeID] in(1, 3))'        exec @result = sp_executesql @sql        if (exists(select top 1 1 from [Payroll_ProspectiveEmployeeSalaryTransaction] with(nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [SalaryHeadID] = 1)))         update [PE] set [FixedSalary] = ([Amount] / 12), [AnnualSalary] = [Amount], [RPH_Monthly] = (([Amount] / 12) / isnull([WHPM_Monthly], @Hours * @Days)), [RPD_Monthly] = (([Amount] / 12) / isnull([WDPM_Monthly], @Days))          from [Payroll_ProspectiveEmployee] as [PE]           join [Payroll_EmployeeSalaryTransaction] as [PET] on [EmployeeId] = [ProspectiveEmployee_ID] and [SalaryHeadID] = 1          where ([ProspectiveEmployee_ID] = @EmployeeID)        if (exists(select top 1 1 from [Payroll_ProspectiveEmployeeSalaryTransaction] with(nolock) where ([ProspectiveEmployeeID] = @EmployeeID and [SalaryHeadId] = 2)))         update [PE] set [BonusAmount] = [Amount]           from [Payroll_ProspectiveEmployee] as [PE]           join [Payroll_ProspectiveEmployeeSalaryTransaction] as [PET] on [ProspectiveEmployeeID] = [ProspectiveEmployee_ID] and [SalaryHeadId] = 2          where ([ProspectiveEmployee_ID] = @EmployeeID)        else         update [Payroll_ProspectiveEmployee] set [BonusCalculation] = NULL, [BonusAmount] = 0          where ([ProspectiveEmployee_ID] = @EmployeeID)       end      end try      begin catch       rollback transaction;      end catch     if (@@trancount > 0)      commit transaction;     set nocount off;    end

GO

