-- ============================================
-- SP: Payroll_UpdateTransactionGroupID_in_Payroll_Transactions_sp
-- Schema: dbo
-- ============================================
  -- ==========================================================================================================================================================================  -- Author:  Ravindra Jijotia   -- Create date: 01/04/2016    -- Description: This sp helps to update TransactionGroup ID in Payroll_Transactions Table.  -- Called by: Payroll_FinalRunCycleSalaryProcessing_sp (called by Final Payroll Run button)  -- TP34356 : Enable Ledger to trace a transaction back to the individual source items   -- Update date : 17/05/2017 - Changed the mappings for Method of Calculation - FERDI BOTHA  -- =============================================  create procedure [Payroll_UpdateTransactionGroupID_in_Payroll_Transactions_sp]   @Case INT,   @CashBookVoteID INT,   @PeriodID INT,   @IsDebit BIT   AS   BEGIN     DECLARE @Payroll_TransactionsGroup TABLE      (        ID INT IDENTITY(1, 1) ,     TransactionGroupID INT,        VoteID INT ,        CreditAmount DECIMAL(18, 2) ,     DebitAmount DECIMAL(18, 2) ,        PeriodID INT,     SCOACostingID INT,     SCOAFunctionID INT,     SCOAFundsID INT,     SCOAItemID INT,     SCOAProjectID INT,     SCOARegionID INT,     VendorID INT,     SalaryHeadID INT,     DocNumber NVARCHAR(20),     MatchTranGuid UNIQUEIDENTIFIER,     SCMInvoiceSalaryHeadName NVARCHAR(500)      )     DECLARE @TransactionGroupID INT,     @VoteID INT ,     @CreditAmount DECIMAL(18, 2) ,     @DebitAmount DECIMAL(18, 2) ,           @SCOACostingID INT,     @SCOAFunctionID INT,     @SCOAFundsID INT,     @SCOAItemID INT,     @SCOAProjectID INT,     @SCOARegionID INT,     @VendorID INT,     @SalaryHeadID INT,     @DocNumber NVARCHAR(20),     @MatchTranGuid UNIQUEIDENTIFIER,     @SCMInvoiceSalaryHeadName NVARCHAR(500)     SET NOCOUNT ON;       INSERT INTO @Payroll_TransactionsGroup     SELECT TransactionGroup_ID, VoteID, CreditAmount, DebitAmount, PeriodID, SCOACostingID, SCOAFunctionID, SCOAFundsID, SCOAItemID, SCOAProjectID, SCOARegionID, VendorID, SalaryHeadID, DocNumber, MatchTranGuid, SCMInvoiceSalaryHeadName     FROM Payroll_TransactionsGroup WHERE FlagToSetTranGroupIdInPayrollTrans = 0      DECLARE @Start INT = 1 ,  @Count INT   SELECT  @Count = COUNT(*) FROM @Payroll_TransactionsGroup     IF @Case = 1   BEGIN    WHILE ( @Start <= @Count )    BEGIN     SELECT @TransactionGroupID = TransactionGroupID, @VoteID = VoteID, @CreditAmount = CreditAmount, @DebitAmount = DebitAmount, @SCOACostingID = SCOACostingID, @SCOAFunctionID = SCOAFunctionID, @SCOAFundsID = SCOAFundsID,       @SCOAItemID = SCOAItemID, @SCOAItemID = SCOAItemID, @SCOAProjectID = SCOAProjectID, @SCOARegionID = SCOARegionID, @VendorID = VendorID, @SalaryHeadID = SalaryHeadID, @DocNumber = DocNumber, @MatchTranGuid = MatchTranGuid,       @SCMInvoiceSalaryHeadName = SCMInvoiceSalaryHeadName     FROM @Payroll_TransactionsGroup WHERE ID = @Start       IF @IsDebit = 0     BEGIN      UPDATE Payroll_Transactions SET TransactionsGroupID = @TransactionGroupID      WHERE PeriodID = @PeriodID AND DebitAmount = 0 AND (TransactionTypeID = 2 AND (VoteID = @CashBookVoteID OR ContraVoteID = @CashBookVoteID))        AND (SalaryHeadID IS NULL OR SalaryHeadID = @SalaryHeadID) AND (VendorID IS NULL OR VendorID = @VendorID) AND SCOACostingID = @SCOACostingID AND SCOAFunctionID = @SCOAFunctionID AND SCOAFundsID = @SCOAFundsID         AND SCOAItemID = @SCOAItemID AND SCOAProjectID = @SCOAProjectID AND SCOARegionID = @SCOARegionID AND DocNumber like @DocNumber AND MatchTranGuid = @MatchTranGuid     END       IF @IsDebit = 1     BEGIN      UPDATE Payroll_Transactions SET TransactionsGroupID = @TransactionGroupID      WHERE PeriodID = @PeriodID AND CreditAmount = 0 AND (TransactionTypeID = 2 AND (VoteID = @CashBookVoteID OR ContraVoteID = @CashBookVoteID))        AND (SalaryHeadID IS NULL OR SalaryHeadID = @SalaryHeadID) AND (VendorID IS NULL OR VendorID = @VendorID) AND SCOACostingID = @SCOACostingID AND SCOAFunctionID = @SCOAFunctionID AND SCOAFundsID = @SCOAFundsID         AND SCOAItemID = @SCOAItemID AND SCOAProjectID = @SCOAProjectID AND SCOARegionID = @SCOARegionID AND DocNumber like @DocNumber AND MatchTranGuid = @MatchTranGuid     END       SET @Start = @Start + 1    END   END   ELSE IF @Case = 2   BEGIN    WHILE ( @Start <= @Count )    BEGIN     SELECT @TransactionGroupID = TransactionGroupID, @VoteID = VoteID, @CreditAmount = CreditAmount, @DebitAmount = DebitAmount, @SCOACostingID = SCOACostingID, @SCOAFunctionID = SCOAFunctionID, @SCOAFundsID = SCOAFundsID,       @SCOAItemID = SCOAItemID, @SCOAItemID = SCOAItemID, @SCOAProjectID = SCOAProjectID, @SCOARegionID = SCOARegionID, @VendorID = VendorID, @SalaryHeadID = SalaryHeadID, @DocNumber = DocNumber, @MatchTranGuid = MatchTranGuid,       @SCMInvoiceSalaryHeadName = SCMInvoiceSalaryHeadName     FROM @Payroll_TransactionsGroup WHERE ID = @Start       IF @IsDebit = 0     BEGIN      UPDATE PT       SET PT.TransactionsGroupID = @TransactionGroupID      FROM Payroll_Transactions PT       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition as epd on epd.EmployeePayrollDefinition_ID = PT.EmployeePayrollDefinitionID  AND EPD.Enabled = 1       LEFT OUTER JOIN Payroll_SalaryHead as sh on sh.SalaryHead_ID = epd.PayrollSalaryHeadID AND SH.Enabled = 1       LEFT OUTER JOIN Payroll_GLItems as GL on GL.SalaryHeadID = SH.SalaryHead_ID AND GL.Enabled = 1      WHERE   PT.PeriodID = @PeriodID AND PT.DebitAmount = 0       AND ((PT.TransactionTypeID = 2 AND (PT.VoteID <> @CashBookVoteID AND PT.ContraVoteID <> @CashBookVoteID) AND (ISNULL(PT.EntryGoesDirectlyToLedger,0) <> 1) AND (ISNULL(Gl.JournalEntryOnly,0) <> 1))       OR  (PT.TransactionTypeID = 3 AND (ISNULL(PT.EntryGoesDirectlyToLedger, 0) <> 1)))        AND sh.SalaryHeadName = @SCMInvoiceSalaryHeadName AND (PT.VendorID IS NULL OR PT.VendorID = @VendorID) AND PT.SCOACostingID = @SCOACostingID AND PT.SCOAFunctionID = @SCOAFunctionID AND PT.SCOAFundsID = @SCOAFundsID        AND PT.SCOAItemID = @SCOAItemID AND PT.SCOAProjectID = @SCOAProjectID AND PT.SCOARegionID = @SCOARegionID AND PT.DocNumber like @DocNumber AND PT.MatchTranGuid = @MatchTranGuid     END       IF @IsDebit = 1     BEGIN      UPDATE PT       SET PT.TransactionsGroupID = @TransactionGroupID      FROM Payroll_Transactions PT       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition as epd on epd.EmployeePayrollDefinition_ID = PT.EmployeePayrollDefinitionID  AND EPD.Enabled = 1       LEFT OUTER JOIN Payroll_SalaryHead as sh on sh.SalaryHead_ID = epd.PayrollSalaryHeadID AND SH.Enabled = 1       LEFT OUTER JOIN Payroll_GLItems as GL on GL.SalaryHeadID = SH.SalaryHead_ID AND GL.Enabled = 1      WHERE   PT.PeriodID = @PeriodID AND PT.CreditAmount = 0       AND ((PT.TransactionTypeID = 2 AND (PT.VoteID <> @CashBookVoteID AND PT.ContraVoteID <> @CashBookVoteID) AND (ISNULL(PT.EntryGoesDirectlyToLedger,0) <> 1) AND (ISNULL(GL.JournalEntryOnly,0) <> 1))       OR  (PT.TransactionTypeID = 3 AND (ISNULL(PT.EntryGoesDirectlyToLedger, 0) <> 1)))        AND sh.SalaryHeadName = @SCMInvoiceSalaryHeadName AND (PT.VendorID IS NULL OR PT.VendorID = @VendorID) AND PT.SCOACostingID = @SCOACostingID AND PT.SCOAFunctionID = @SCOAFunctionID AND PT.SCOAFundsID = @SCOAFundsID        AND PT.SCOAItemID = @SCOAItemID AND PT.SCOAProjectID = @SCOAProjectID AND PT.SCOARegionID = @SCOARegionID AND PT.DocNumber like @DocNumber AND PT.MatchTranGuid = @MatchTranGuid     END       SET @Start = @Start + 1    END   END   ELSE IF @Case = 3   BEGIN    WHILE ( @Start <= @Count )    BEGIN     SELECT @TransactionGroupID = TransactionGroupID, @VoteID = VoteID, @CreditAmount = CreditAmount, @DebitAmount = DebitAmount, @SCOACostingID = SCOACostingID, @SCOAFunctionID = SCOAFunctionID, @SCOAFundsID = SCOAFundsID,       @SCOAItemID = SCOAItemID, @SCOAItemID = SCOAItemID, @SCOAProjectID = SCOAProjectID, @SCOARegionID = SCOARegionID, @VendorID = VendorID, @SalaryHeadID = SalaryHeadID, @DocNumber = DocNumber, @MatchTranGuid = MatchTranGuid,       @SCMInvoiceSalaryHeadName = SCMInvoiceSalaryHeadName     FROM @Payroll_TransactionsGroup WHERE ID = @Start       IF @IsDebit = 0     BEGIN      UPDATE PT       SET PT.TransactionsGroupID = @TransactionGroupID      FROM Payroll_Transactions PT       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition as epd on epd.EmployeePayrollDefinition_ID=pt.EmployeePayrollDefinitionID AND EPD.Enabled=1        LEFT OUTER JOIN Payroll_SalaryHead as sh on sh.SalaryHead_ID=epd.PayrollSalaryHeadID AND SH.Enabled=1                  WHERE   PeriodID = @PeriodID AND DebitAmount = 0        and DocNumber like '131/%'        AND (TransactionTypeID = 2 AND (((VoteID <> @CashBookVoteID AND ContraVoteID <> @CashBookVoteID) AND ISNULL(pt.EntryGoesDirectlyToLedger,0) = 1))       OR  TransactionTypeID = 1        OR  (TransactionTypeID = 3 AND (ISNULL(pt.EntryGoesDirectlyToLedger,0) = 1)))       AND (PT.SalaryHeadID IS NULL OR PT.SalaryHeadID = @SalaryHeadID) AND (PT.VendorID IS NULL OR PT.VendorID = @VendorID) AND PT.SCOACostingID = @SCOACostingID AND PT.SCOAFunctionID = @SCOAFunctionID AND PT.SCOAFundsID = @SCOAFundsID        AND PT.SCOAItemID = @SCOAItemID AND PT.SCOAProjectID = @SCOAProjectID AND PT.SCOARegionID = @SCOARegionID AND PT.DocNumber like @DocNumber AND PT.MatchTranGuid = @MatchTranGuid     END       IF @IsDebit = 1     BEGIN      UPDATE PT       SET PT.TransactionsGroupID = @TransactionGroupID      FROM Payroll_Transactions PT       LEFT OUTER JOIN Payroll_EmployeePayrollDefinition as epd on epd.EmployeePayrollDefinition_ID=pt.EmployeePayrollDefinitionID AND EPD.Enabled=1        LEFT OUTER JOIN Payroll_SalaryHead as sh on sh.SalaryHead_ID=epd.PayrollSalaryHeadID AND SH.Enabled=1                  WHERE   PeriodID = @PeriodID AND CreditAmount = 0        and DocNumber like '131/%'        AND (TransactionTypeID = 2 AND (((VoteID <> @CashBookVoteID AND ContraVoteID <> @CashBookVoteID) AND ISNULL(pt.EntryGoesDirectlyToLedger,0) = 1))       OR  TransactionTypeID = 1        OR  (TransactionTypeID = 3 AND (ISNULL(pt.EntryGoesDirectlyToLedger,0) = 1)))       AND (PT.SalaryHeadID IS NULL OR PT.SalaryHeadID = @SalaryHeadID) AND (PT.VendorID IS NULL OR PT.VendorID = @VendorID) AND PT.SCOACostingID = @SCOACostingID AND PT.SCOAFunctionID = @SCOAFunctionID AND PT.SCOAFundsID = @SCOAFundsID        AND PT.SCOAItemID = @SCOAItemID AND PT.SCOAProjectID = @SCOAProjectID AND PT.SCOARegionID = @SCOARegionID AND PT.DocNumber like @DocNumber AND PT.MatchTranGuid = @MatchTranGuid     END       SET @Start = @Start + 1    END     END     UPDATE Payroll_TransactionsGroup SET FlagToSetTranGroupIdInPayrollTrans = 1 WHERE FlagToSetTranGroupIdInPayrollTrans = 0  END  

GO

-- ============================================
-- SP: Payroll_UpdateUpperLimitDetails_sp
-- Schema: dbo
-- ============================================
    /*     Author  : Richa Mills     Create date : 2017/06/26     Description : Update Const Tables     170626-STRUCTURE-Payroll-000-AlterUpdateUpperLimitDetails    */        CREATE PROCEDURE [dbo].[Payroll_UpdateUpperLimitDetails_sp]    @UpperLimit_ID INT,    --@EmployeetypeID INT,    --@EmployeeSubtypeID INT,    @MunicipalGradingID INT,    --@PositionID INT,    @MinimumValue decimal(8,2),    @MidpointValue decimal(8,2),    @MaximumValue decimal(8,2),    @StartDate DateTime,    @EndDate DateTime,    @IncreaseStartDate DateTime,    @IncreaseEndDate DateTime,    @EstimatedIncrease decimal(8,2)    AS    BEGIN    update Payroll_UpperLimit    set     -- EmployeetypeID =  @EmployeetypeID,    -- EmployeeSubtypeID =@EmployeeSubtypeID,     -- PositionID =@PositionID,        MunicipalGradingID =@MunicipalGradingID ,     MinimumValue =@MinimumValue,     MidpointValue =@MidpointValue ,     MaximumValue =@MaximumValue ,     StartDate =@StartDate,     EndDate =@EndDate,       EstimatedIncrease =@EstimatedIncrease ,       IncreaseStartDate =@IncreaseStartDate,       IncreaseEndDate =@IncreaseEndDate       --PostIncreaseMinimum ,       --PostIncreaseMidpoint ,       --PostIncreaseMaximum ,       --PackageValue      WHERE UpperLimit_ID =@UpperLimit_ID    END  

GO

-- ============================================
-- SP: Payroll_UpperLimitDetails_sp
-- Schema: dbo
-- ============================================
  -- =============================================    -- Author:  Pavan    -- Alter date: 01 September 2017    -- Description: Added Position Column 70793  -- Update - Richa M - Added JobProfileId Column  -- Update - Himil Modi - Added Id Column on 12 June 2018.  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_UpperLimitDetails_sp]    @PackageValue DECIMAL(8,2),    @EmployeetypeID INT,    @EmployeeSubtypeID INT,    @JobProfileId int     AS    BEGIN     SELECT       UpperLimit_ID  ,       LMT.EmployeetypeID ,       EMPTYPE.EmployeeTypeDescription,       LMT.EmployeeSubtypeID ,        EMPSUB.EmployeeSubtypeDesc,       LMT.PositionID ,       ISNULL(JobTitle,'') AS JobProfileDesc,       MunicipalGradingID ,       MinimumValue ,       MidpointValue ,       MaximumValue ,       PostIncreaseMinimum ,       PostIncreaseMidpoint ,       PostIncreaseMaximum ,       PackageValue       FROM Payroll_UpperLimit LMT     INNER JOIN Const_EmployeeType_sys EMPTYPE ON EMPTYPE.EmployeeType_ID = LMT.EmployeetypeID      INNER JOIN Payroll_EmployeeSubtypes EMPSUB ON EMPSUB.EmployeeSubtype_ID = LMT.EmployeeSubtypeID      Left JOIN Payroll_JobProfile JP ON JP.JobProfile_ID = LMT.JobProfileId      WHERE ((LMT.EmployeetypeID =@EmployeetypeID) OR (@EmployeetypeID =0))   AND ((LMT.EmployeeSubtypeID = @EmployeeSubtypeID) OR (@EmployeeSubtypeID =0))    AND ((LMT.JobProfileId = @JobProfileId) OR (@JobProfileId =0))     AND ((LMT.PackageValue = @PackageValue) OR (@PackageValue =0))    -- AND (PackageValue = ISNULL(@PackageValue, PackageValue) )   END

GO

-- ============================================
-- SP: Payroll_UpperLimitHistoryDetails_sp
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[Payroll_UpperLimitHistoryDetails_sp]    @UpperLimitId INT  AS    BEGIN     SELECT        LMT.StartDate  ,     LMT.EndDate  ,     EMPTYPE.EmployeeTypeDescription,       EMPSUB.EmployeeSubtypeDesc,       ISNULL(JobTitle,'') AS JobProfileDesc,       LMT.MinimumValue ,       LMT.MidpointValue ,       LMT.MaximumValue       FROM Payroll_UpperLimitHistory LMT     INNER JOIN Const_EmployeeType_sys EMPTYPE ON EMPTYPE.EmployeeType_ID = LMT.EmployeetypeID      INNER JOIN Payroll_EmployeeSubtypes EMPSUB ON EMPSUB.EmployeeSubtype_ID = LMT.EmployeeSubtypeID      Left JOIN Payroll_JobProfile JP ON JP.JobProfile_ID = LMT.JobProfileId      WHERE LMT.UpperLimit_ID =@UpperLimitId  END

GO

-- ============================================
-- SP: Payroll_ValidateBudgetCheck
-- Schema: dbo
-- ============================================
/*   Author  : Richa M   Created  : 2021/02/10   Description : Validates the Position SCOA (Items)   Payroll_ValidatePositionScoa_sp 0,'2021/2022'    */  CREATE procedure [dbo].[Payroll_ValidateBudgetCheck](@PositionID int = null, @FinYear varchar(9) = null)  as  begin     declare @SalaryProjectID int = null,     @SalaryControlID int = null     declare @projectItems as table (      [DivisionID] int null,    [ProjectID] int null,    [ScoaItemID] int null,    [ScoaFunctionID] int null,    [ScoaRegionID] int null,    [PlanProjectItemId] int null     )     if (@FinYear is null)      select @FinYear = [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'ActiveFinYear')     select @SalaryProjectID = [SalaryProjectID], @SalaryControlID = [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock) where ([FinYear] = @FinYear)     insert into @projectItems([DivisionID], [ProjectID], [ScoaItemID], [ScoaFunctionID], [ScoaRegionID],[PlanProjectItemId])      select [PPI].[DivisionId], [PP].[Project_ID], [PPI].[SCOAItemID], [PPI].[SCOAFunctionId], [PPI].[SCOARegionId],[PPI].[PlanProjectItem_ID]       from [Plan_ProjectItem] as [PPI] with(nolock)        join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [PPI].[ProjectID]       where ([PP].[FinYear] = @FinYear)     Select v1.*,    --dt legs    dtDivision.DivisionCode DtDivisionCode,     dtDivision.DivisionDesc dtDivisionDesc,    dtProj.ProjectName dtProjectName,    dtProj.ProjectCode dtProjectCode,    dtstruc.ScoaCode dtScoaCode,    dtstruc.ScoaDesc dtScoaDesc,    dtfunc.ScoaCode dtScoaFunctionCode,    dtfunc.ScoaDesc dtScoaFunctionDesc,    dtRegion.ScoaCode dtScoaRegionCode,    dtRegion.ScoaDesc dtScoaRegionDesc,   --ct legs   dtDivision.DivisionCode ctDivisionCode,     ctDivision.DivisionDesc ctDivisionDesc,    ctProj.ProjectName ctProjectName,    ctProj.ProjectCode ctProjectCode,    ctstruc.ScoaCode ctScoaCode,    ctstruc.ScoaDesc ctScoaDesc,    ctfunc.ScoaCode ctScoaFunctionCode,    ctfunc.ScoaDesc ctScoaFunctionDesc,    ctRegion.ScoaCode ctScoaRegionCode,    ctRegion.ScoaDesc ctScoaRegionDesc       from (   select [POS].[Position_ID], [POS].[PositionDesc],      (case       when [POS].[Status] = 1 then 'Vacant'       when [POS].[Status] = 2 then 'Occupied'       when [POS].[Status] = 4 then 'Seconded'      end) as [Status],      [SH].[SalaryHeadTitle],      [POS].[DivisionID] DtDivisionId,      (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) DtProjectId,        (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 6 then [GL].[ScoaItemIDPostRetirement]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) DtScoaItemId,        [POS].[FunctionID] DtFunctionId,        [POS].[RegionID] DtRegionId,        [PDI].PlanProjectItemId DtProjectItemID,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) CtDivisionId,        (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) CtProjectId,        (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]          when 1 then [GL].[SCOAItemID]          when 6 then [GL].[SCOAItemID]         end)         else [GL].[SuspenseScoaItemCreditID]        end) CtScoaItemId,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) CtFunctionId,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end) CtRegionId,        [PCI].[PlanProjectItemId] CtProjectItemId      from [Payroll_PayrollDefination] as [PD] with(nolock)       join [Payroll_DefinitionGroup] as [DG] with(nolock) on [DG].[PayrollDefinitionGroup_ID] = [PD].[PayrollDefinitionGroupID] and [DG].[Enabled] = 1       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] in(1, 2, 3) and [IRP5].[Enabled] = 1       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[FinYear] = @FinYear and [GL].[Enabled] = 1       join [Payroll_Position] as [POS] with(nolock) on        [POS].[Position_ID] = (case when @PositionID is null then [POS].[Position_ID] else @PositionID end) and        [POS].[Status] in(1, 2, 4) and        [POS].[Enabled] = 1       left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [POS].[ProjectID]       /* DEBIT */     left outer join @projectItems as [PDI] on        [PDI].[DivisionID] = [POS].[DivisionID] and        [PDI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) and        [PDI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 6 then [GL].[ScoaItemIDPostRetirement]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) and        [PDI].[ScoaFunctionID] = [POS].[FunctionID] and        [PDI].[ScoaRegionID] = [POS].[RegionID]       /* CREDIT */     left outer join @projectItems as [PCI] on        [PCI].[DivisionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) and        [PCI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) and        [PCI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]          when 1 then [GL].[SCOAItemID]          when 6 then [GL].[SCOAItemID]         end)         else [GL].[SuspenseScoaItemCreditID]        end) and        [PCI].[ScoaFunctionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) and        [PCI].[ScoaRegionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end)       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, [PDI].[ScoaItemID])       ) as [SDC]       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, [PCI].[ScoaItemID])       ) as [SCC]      where ([PD].[PayrollDefinitionGroupID] = [POS].[PayrollDefinitionGroupID] and [PD].[Enabled] = 1 and [POS].[EmployeeTypeID] in(1, 6) and       [IRP5].[TransactionTypeID] in(1, 2, 3) )       )V1     Left Join Const_Division dtDivision on dtDivision.Division_ID = DtDivisionId       Left Join Const_Division ctDivision on ctDivision.Division_ID = CtDivisionId        left join Plan_Project dtProj on dtProj.Project_ID = DtProjectId       left join Plan_Project ctProj on ctProj.Project_ID = CtProjectId       left join Const_SCOA_Function_Structure dtfunc on dtfunc.ScoaID = DtFunctionId       left join Const_SCOA_Function_Structure ctfunc on ctfunc.ScoaID = CtFunctionId       left join Const_SCOA_Regional_Structure dtRegion on dtRegion.ScoaID = DtRegionId       left join Const_SCOA_Regional_Structure ctRegion on ctRegion.ScoaID = CtRegionId       Left Join Const_Scoa_Structure dtstruc ON dtstruc.ScoaID = DtScoaItemId       Left Join Const_Scoa_Structure ctstruc ON ctstruc.ScoaID = CtScoaItemId       order by [V1].[Position_ID], [V1].[SalaryHeadTitle]  end

GO

