-- SP: Payroll_ValidateBulkUpload_sp
-- Schema: dbo
-- ============================================
    CREATE PROCEDURE [dbo].[Payroll_ValidateBulkUpload_sp]   @dtValidateBulkUpload Payroll_ValidateBulkUpload_ut READONLY  AS      BEGIN         SET NOCOUNT ON          DECLARE @SQLQuery NVARCHAR(MAX);          -- Create employee temporary table and insert all fields     IF OBJECT_ID('tempdb..#tempEmployee') IS NOT NULL              DROP TABLE #tempEmployee;            CREATE TABLE #tempEmployee              (FirstName nvarchar(200),              NatureOfPersonID nvarchar(10),  --3020     Surname nvarchar(200),    --3030     IncomeTaxNumber nvarchar(200),  --3100     WorkCountryID nvarchar(200),  --3151     JoiningDate DATE,     --3170     EndDate DATE,      --3180     PhysicalAddress1 nvarchar(200),       PhysicalCountryID nvarchar(50),  --3285      PostalPostOffice nvarchar(200),  --3253     postalcountryid nvarchar(50),  --3286     PostalStreetID nvarchar(50),  --3258     --@postalcountryid nvarchar(10), --3287     PostalAddress1 nvarchar(200),  --3289     --@postalcountryid nvarchar(10), --3294     PhysicalStreetID nvarchar(50),  --3214     AddressIndicator INT,    --3279     AccountTypeID nvarchar(50),   --3240     farmID nvarchar(50),    --3214              );            INSERT  INTO #tempEmployee          SELECT * FROM @dtValidateBulkUpload      /*  Starting validation rules here */    /*    INSERT  INTO  Payroll_ValidationRules     (Enable, ExceptionType, CodeName, TaxYear ,CodeValue,CodeCount, Mandatory, TableName, FieldName, Formula, ErrorDescription )    VALUES         (1,'BulkUpload', 'Nature of person', 'Not Applicabale',  3020,1,'Mandatory','#tempEmployee','NatureOfPersonID', 'LEN (ISNULL(CONVERT(VARCHAR,(SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID)),'''')) = 0','Nature of person is mandatory')    ,( 1,'BulkUpload', 'Employee surname or trading name', 'Not Applicabale', 3030,1,'Mandatory','#tempEmployee','Surname', 'Surname like  N''%[0-9]%'' and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'')','Numeric characters are not allowed ')    ,( 1,'BulkUpload', 'Employee surname or trading name', 'Not Applicabale', 3030,2,'Mandatory','#tempEmployee','Surname', 'len(isnull(Surname,'''')) = 0 or len(Surname) > 120 ','Mandatory field')    ,( 1,'BulkUpload', 'Income Tax Reference Number', 'Not Applicabale', 3100,1,'Mandatory','#tempEmployee','IncomeTaxNumber', 'Substring(IncomeTaxNumber,1,1) not in (''0'',''1'',''2'',''3'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''D'',''M'',''N'',''R'')','If Nature of Person A, B, C, D, M, N or R; the number may only start with either 0, 1, 2, or 3 ')    ,( 1,'BulkUpload', 'Income Tax Reference Number', 'Not Applicabale', 3100,2,'Mandatory','#tempEmployee','IncomeTaxNumber', 'Substring(IncomeTaxNumber,1,1) not in (''9'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''E'',''G'',''H'')','If Nature of Person E, G, H ; the number may only start with 9 ')    ,( 1,'BulkUpload', 'Income Tax Reference Number', 'Not Applicabale', 3100,3,'Mandatory','#tempEmployee','IncomeTaxNumber', 'len(IncomeTaxNumber) > 0  and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''F'')','This field may not be completed if Nature of Person F ')    ,( 1,'BulkUpload', 'Income Tax Reference Number', 'Not Applicabale', 3100,4,'Mandatory','#tempEmployee','IncomeTaxNumber', '(len(IncomeTaxNumber) <> 10 or dbo.Payroll_ValidateIRPIncomeTax_Fxn(IncomeTaxNumber) <> 1) and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) not IN (''F'')','Modulus is failed or length not proper')    --,( 1,'BulkUpload', 'Employee Physical Work Address Details - : Country Code ', 'Not Applicabale', 3151,1,'Conditional','#tempEmployee','PhyWorkCountryId', 'len(isnull(PhyWorkCountryId,0)) = 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) not IN (''N'')','Employee Physical Work Address Details - : Country Code is Mandatory if Nature of Person is not N')     ,( 1,'BulkUpload', 'Period employed from', 'Not Applicabale', 3170,1,'Mandatory','#tempEmployee','JoiningDate', 'JoiningDate > getdate() or LEN(CONVERT(VARCHAR,JoiningDate,112)) <> 8 or JoiningDate > EndDate ','Cannot be later than current date or length issue')     ,( 1,'BulkUpload', 'Period Employed To', 'Not Applicabale', 3180,1,'Mandatory','#tempEmployee','EndDate', 'EndDate > (getdate() + 30 ) or EndDate < JoiningDate or LEN(CONVERT(VARCHAR,EndDate,112)) <> 8','Cannot be later than current date plus 30 ')     --,( 1,'BulkUpload', 'Employee residential address: Street / Farm Name', 'Not Applicabale', 3214,1,'Mandatory','#tempEmployee','PhysicalStreetID', 'LEN(ISNULL((SELECT top 1 StreetName FROM dbo.Const_Street CST where CST.Enabled =1 and CST.Street_ID = D.PhysicalStreetID),'''')) > 26 or LEN(ISNULL((SELECT top 1 StreetName FROM dbo.Const_Street CST where CST.Enabled =1 and CST.Street_ID = D.PhysicalStreetID),'''')) =0 ','Mandatory or Length is not proper')        ,( 1,'BulkUpload', 'Employee residential address: Street / Farm Name', 'Not Applicabale', 3214,1,'Mandatory','#tempEmployee','PhysicalStreetID', 'LEN(ISNULL((SELECT top 1 StreetName FROM dbo.Const_Street CST where CST.Enabled =1 and CST.Street_ID = D.PhysicalStreetID),'''')) > 26     or ( LEN(ISNULL((SELECT top 1 StreetName FROM dbo.Const_Street CST where CST.Enabled =1 and CST.Street_ID = D.PhysicalStreetID),'''')) =0 and LEN(ISNULL((SELECT TOP 1 CSF.FarmName FROM dbo.Const_Farm CSF WHERE CSF.Enabled =1 AND CSF.Farm_ID = D.farmID),'''')) =0 ) or    LEN(ISNULL((SELECT TOP 1 CSF.FarmName FROM dbo.Const_Farm CSF WHERE CSF.Enabled =1 AND CSF.Farm_ID = D.farmID),'''')) > 26','Mandatory or Length is not proper')        ,( 1,'BulkUpload', 'Employee Address Details - Residential: Country Code', 'Not Applicabale', 3285,1,'Mandatory','#tempEmployee','PhysicalCountryID', 'ISNULL(PhysicalCountryID,-1) = -1 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) not IN (''N'') ','Employee Address Details - Residential: Country Code is Mandatory if Nature of Person is not N')     ,( 1,'BulkUpload', 'Employees` postal address details: Post Office', 'Not Applicabale', 3253,1,'Mandatory','#tempEmployee','PostalPostOffice', 'Len(isnull(PostalPostOffice,'''')) =0 or Len(isnull(PostalPostOffice,'''')) > 22','PostalPostOffice is Mandatory')    ,( 1,'BulkUpload', 'Employee Postal Address Details Country Code ', 'Not Applicabale', 3286,1,'Mandatory','#tempEmployee','PostalCountryID', 'isnull(PostalCountryID,-1)= -1 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and CNP.NatureOfPerson_ID =NatureOfPersonID) not IN (''N'')','This field is mandaroty for Nature of person is not N')    ,( 1,'BulkUpload', 'Employees` address details: Street/name of farm', 'Not Applicabale', 3258,1,'Mandatory','#tempEmployee','PostalStreetID', 'LEN(ISNULL((SELECT top 1 SuburbName FROM dbo.Const_Suburb CSB WHERE CSB.enabled=1 and Suburb_ID =PostalStreetID),'''')) > 26 OR isnull(PostalStreetID,-1) = -1','Employees address details: Street/name of farm is Mandatory')    ,( 1,'BulkUpload', 'Employee Postal Address Details : Line 1', 'Not Applicabale', 3289,1,'Mandatory','#tempEmployee','PostalAddress1', 'LEN(isnull(PostalAddress1,'''')) = 0 or len(PostalAddress1) > 35',' Mandatory field')      ,( 1,'BulkUpload', 'Employees` bank account:  Type', 'Not Applicabale', 3240,1,'Mandatory','#tempEmployee','AccountTypeID', '(SELECT top 1 BankAccountTypeID FROM dbo.Const_BankAccountType CBA where CBA.Enabled =1 and BankAccountTypeID = AccountTypeID and BankAccountType IN (''Not Paid by electronic bank transfer '',''Cheque/Current Account '',    ''Savings Account'',''Transmission Account'',''Bond Account'',''Credit Card Account'',''Subscription Share Account'',''Foreign Bank Account'')) <> AccountTypeID',' This code is not as per Rules')     */     /*  Ending validation rules here */      SELECT  @SQLQuery = STUFF((SELECT    'UNION ALL     Select FirstName,' + QUOTENAME(CodeName, '''') + ' AS FieldName,CONVERT(NVARCHAR,'          + QUOTENAME(FieldName) + ') as FieldValue,(Case when ' + Formula + ' then ''' + ErrorDescription          + ''' else '''' end) AS Valid, ' + QUOTENAME(CodeValue, '''') + ' AS [Code],    ' + QUOTENAME(Mandatory, '''') + ' as Mandatory,''payrollCycle'' as cycle ,''    TaxPeriod '' as TaxPeriod ,''TaxYear'' as TaxYear,' + QUOTENAME(ExceptionType, '''') + ' as ExceptionType FROM ' + QUOTENAME(TableName) + ' D '    FROM  Payroll_ValidationRules C WHERE C.exceptionType = 'BulkUpload' AND C.Enable = 1     and C.CodeValue IN (3020,3030,3100,3170,3180,3214,3285,3253,3286,3258,3289,3240) FOR XML PATH('') , TYPE).value('.', 'NVARCHAR(max)'), 1, 11, '');              SET @SQLQuery = 'Select distinct A.code, A.FirstName, A.FieldName, A.Mandatory From (' + @SQLQuery + ') A Where Len(Valid) > 0 and A.ExceptionType=''BulkUpload'' AND Enable = 1 Order By FirstName';         --   EXECUTE (@SQLQuery);      --SET NOCOUNT OFF    SELECT '' AS FirstName, '' AS FieldName, '' AS Code, '' AS Mandatory      END;  

GO

