  CREATE procedure [dbo].[Payroll_ValidateBulkUploadEmployeeDetails_sp] @table sysname, @BulkUploadHeaderID int  as  begin     declare @i int = 1,     @c int = 0,     @name sysname = null,     @parentTableName sysname = null,     @is_primary_key bit = null,     @is_foreign_key bit = null,     @is_computed bit = null,     @is_nullable bit = null,     @sql nvarchar(max) = '',     @error_line int = null,     @error_message nvarchar(2048) = null,     @error_procedure nvarchar(2048) = null     declare @keys table (      [ID] [int] identity(1, 1) not null,    [idx] [int] null,    [name] [sysname] not null,    [SortOrder][int] not null,    [is_primary_key] [bit] not null,    [is_foreign_key] [bit] null,    [is_identity] [bit] not null,    [is_default] [bit] null,    [is_computed] [bit] not null,    [is_nullable] [bit] not null     )     declare @foreignKeys table (      [ID] [int] identity(1, 1) not null,    [ParentColumnName] [sysname] not null,    [ParentTableName] [sysname] not null,    [ChildColumnName] [sysname] not null,    [ChildTableName] [sysname] not null,    [FkName] [sysname] not null     )     set nocount on;     begin try      if (not object_id('tempdb..#Payroll_BulkUploadEmployeeDetails') is null)       drop table [#Payroll_BulkUploadEmployeeDetails]      select * into [#Payroll_BulkUploadEmployeeDetails]      from Payroll_BulkUploadEmployeeDetails where BulkUploadHeaderID = @BulkUploadHeaderID      insert into @keys exec [Payroll_GetColumns_sp] @table,0                  delete from @keys where ([name] in('Employee_ID'))      insert into @foreignKeys exec [Payroll_GetTableDependencies] @table      select @c = count([ID]) from @keys      while (@i <= @c)    begin       select @name = [name], @is_primary_key = [is_primary_key], @is_foreign_key = [is_foreign_key], @is_computed = [is_computed], @is_nullable = [is_nullable] from @keys where ([ID] = @i)       if (@is_foreign_key = 0  and @is_nullable = 0)     begin        set @sql =         'insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID],[FirstName],[Surname], [ValidationType], [ErrorMessage], [Blocking])         select ' + cast(@BulkUploadHeaderID as nvarchar) + ', [Employee_ID],[FirstName],[Surname], ''Employee'', ''Enter a valid ' + @name + ''', 1          from [#Payroll_BulkUploadEmployeeDetails]          where (isnull(cast([' + @name + '] as nvarchar), '''') in (''0'',''''))'        exec sp_executesql @sql       end       if (@is_foreign_key = 1)     begin        select @sql =         'insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID],[FirstName],[Surname], [ValidationType], [ErrorMessage], [Blocking])         select ' + cast(@BulkUploadHeaderID as nvarchar) + ', [c].[Employee_ID],[c].[FirstName],[c].[Surname], ''Employee'', ''Invalid ' + @name + ' ('' + cast([c].[' + @name + '] as nvarchar) + '') -> ' + [ParentTableName] + ''', 1          from [#Payroll_BulkUploadEmployeeDetails] as [c] with(nolock)           left join [' + [ParentTableName] + '] as [p] with(nolock) on [p].[' + [ParentColumnName] + '] = [c].[' + [ChildColumnName] + ']          where (not [c].[' + @name + '] is null and ([p].[' + [ParentColumnName] + '] is null or isnull([p].[Enabled], 0) = 0))', @parentTableName = [ParentTableName]         from @foreignKeys where ([ChildColumnName] = @name)        if (col_length(@parentTableName, 'Enabled') is null)         set @sql = replace(@sql, ' or isnull([p].[Enabled], 0) = 0', '')        exec sp_executesql @sql       end       set @i = @i + 1      end      if (not object_id('tempdb..#Payroll_BulkUploadEmployeeDetails') is null)       drop table [#Payroll_BulkUploadEmployeeDetails]     end try     begin catch      select @error_line = error_line(), @error_message = error_message(), @error_procedure = error_procedure()     end catch     set nocount off;     if (not @error_line is null)   begin      insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID], [ValidationType], [ErrorMessage], [Blocking])       values(@BulkUploadHeaderID, 0, 'Global', @error_message, 1)     end    end

GO

