-- ============================================
  CREATE procedure [Payroll_ValidateBulkUploadTransactionDetails_sp] @BulkUploadTransactionDetails [Payroll_BulkUploadTransactionDetails] readonly, @table sysname, @BulkUploadHeaderID int  as  begin     declare @i int = 1,     @c int = 0,     @name sysname = null,     @parentTableName sysname = null,     @is_primary_key bit = null,     @is_foreign_key bit = null,     @is_computed bit = null,     @is_nullable bit = null,     @sql nvarchar(max) = '',     @error_line int = null,     @error_message nvarchar(2048) = null,     @error_procedure nvarchar(2048) = null     declare @keys table (      [ID] [int] identity(1, 1) not null,    [name] [sysname] not null,    [is_primary_key] [bit] not null,    [is_foreign_key] [bit] null,    [is_identity] [bit] not null,    [is_default] [bit] null,    [is_computed] [bit] not null,    [is_nullable] [bit] not null     )     declare @foreignKeys table (      [ID] [int] identity(1, 1) not null,    [ParentColumnName] [sysname] not null,    [ParentTableName] [sysname] not null,    [ChildColumnName] [sysname] not null,    [ChildTableName] [sysname] not null,    [FkName] [sysname] not null     )     set nocount on;     begin try      if (not object_id('tempdb..#Payroll_BulkUploadTransactionDetails') is null)       drop table [#Payroll_BulkUploadTransactionDetails]      select * into [#Payroll_BulkUploadTransactionDetails] from @BulkUploadTransactionDetails      insert into @keys exec [Payroll_GetColumns_sp] @table,1            delete from @keys where ([name] in('PeriodID', 'Enabled', 'CapturerID', 'DateCaptured', 'ModifierID', 'DateModified'))      insert into @foreignKeys exec [Payroll_GetTableDependencies] @table            delete from @foreignKeys where ([ChildColumnName] in('PeriodID'))      select @c = count([ID]) from @keys      while (@i <= @c)    begin       select @name = [name], @is_primary_key = [is_primary_key], @is_foreign_key = [is_foreign_key], @is_computed = [is_computed], @is_nullable = [is_nullable] from @keys where ([ID] = @i)       if ((@is_primary_key = 1 or @is_foreign_key = 1) and @is_computed = 0 and @is_nullable = 0)     begin        set @sql =         'insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID], [ValidationType], [ErrorMessage], [Blocking])         select ' + cast(@BulkUploadHeaderID as nvarchar) + ', [EmployeeID], ''Employee'', ''Enter a valid ' + @name + ''', 1          from [#Payroll_BulkUploadTransactionDetails]          where (isnull(cast([' + @name + '] as nvarchar), '''') = '''')'        exec sp_executesql @sql       end       if (@is_foreign_key = 1 and @is_nullable = 1)     begin        select @sql =         'insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID], [ValidationType], [ErrorMessage], [Blocking])         select ' + cast(@BulkUploadHeaderID as nvarchar) + ', [c].[EmployeeID], ''Employee'', ''Invalid ' + @name + ' ('' + cast([c].[' + @name + '] as nvarchar) + '') -> ' + [ParentTableName] + ''', 1          from [#Payroll_BulkUploadTransactionDetails] as [c] with(nolock)           left join [' + [ParentTableName] + '] as [p] with(nolock) on [p].[' + [ParentColumnName] + '] = [c].[' + [ChildColumnName] + ']          where (not [c].[' + @name + '] is null and ([p].[' + [ParentColumnName] + '] is null or isnull([p].[Enabled], 0) = 0))', @parentTableName = [ParentTableName]         from @foreignKeys where ([ChildColumnName] = @name)        if (col_length(@parentTableName, 'Enabled') is null)         set @sql = replace(@sql, ' or isnull([p].[Enabled], 0) = 0', '')        exec sp_executesql @sql       end       set @i = @i + 1      end      if (not object_id('tempdb..#Payroll_BulkUploadTransactionDetails') is null)       drop table [#Payroll_BulkUploadTransactionDetails]     end try     begin catch      select @error_line = error_line(), @error_message = error_message(), @error_procedure = error_procedure()     end catch     set nocount off;     if (not @error_line is null)   begin      insert into [Payroll_BulkErrors]([BulkUploadHeaderID], [EmployeeID], [ValidationType], [ErrorMessage], [Blocking])       values(@BulkUploadHeaderID, 0, 'Global', @error_message, 1)     end    end

GO

-- ============================================
-- SP: Payroll_ValidateCertificate_sp
-- Schema: dbo
-- ============================================
  /*=============================================   Create date: 08/Oct/2016  Name: Jaydev Jangid  Description:  Call all 3 validation SPs here ( employee, header, financial rules )  [Payroll_ValidateCertificate_sp]  'August', '2017/2018',17,0  =============================================  */  CREATE procedure [dbo].[Payroll_ValidateCertificate_sp] @TaxPeriod nvarchar(100), @TaxYear nvarchar(100), @PayrollCycleId int, @IsTerminated bit = 0  as  begin     set nocount on;        declare @table table (      [Code] nvarchar(20),    [Employee_Id] nvarchar(50),    [EmployeeNumber] nvarchar(100),    [EmpCode] nvarchar(50),    [FieldName] nvarchar(500),    [ExceptionType] varchar(50),    [TableValue] varchar(250),    [Valid] nvarchar(500),          [FieldValue] nvarchar(200),    [Mandatory] nvarchar(50),    [Cycle] nvarchar(50),    [TaxPeriod] nvarchar(20),    [TaxYear] nvarchar(20)     )             insert into @table      exec [Payroll_ValidateHeader_sp] @TaxPeriod, @TaxYear, @PayrollCycleId        insert into @table      exec [Payroll_ValidateEmployee_sp] @TaxPeriod, @TaxYear, @PayrollCycleId, @IsTerminated          insert into @table      exec [Payroll_ValidateFinancial_sp] @TaxPeriod, @TaxYear, @PayrollCycleId        select * from @table;     set nocount off;    end  

GO

-- ============================================
-- SP: Payroll_ValidateEmployee_sp
-- Schema: dbo
-- ============================================
    -- exec [Payroll_ValidateEmployee_sp] 'February','2016/2017',0,0    CREATE procedure [dbo].[Payroll_ValidateEmployee_sp] @TaxPeriod varchar(100), @TaxYear varchar(100), @PayrollCycleId int, @IsTerminated bit = 0  as    BEGIN         set nocount on;       declare @FromDate datetime,      @ToDate datetime,     @SQLQuery nvarchar(max),     @Month nvarchar(2),     @payrollCycle nvarchar(100),     @TerminationCondition nvarchar(max),     @PayeCode varchar(50)         select top 1 @FromDate = PeriodStartDate FROM dbo.Payroll_CyclePeriodDetails WITH ( NOLOCK ) WHERE   ( CycleID = @PayrollCycleId OR @PayrollCycleId = 0 )              AND FinancialYear = @TaxYear ORDER BY Period_ID;         SELECT TOP 1 @payrollCycle = CycleDesc FROM    dbo.Const_Cycle WHERE   Cycle_ID = @PayrollCycleId;        SELECT TOP 1 @PayeCode = PayeRegistrationNo FROM    dbo.Payroll_Municipality;        IF @PayrollCycleId = 0    SET @PayrollCycle = ISNULL(@PayrollCycle, 'ALL');        IF @TaxPeriod = 'February'          BEGIN              SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));              SET @Month = '02';          END;      ELSE          BEGIN              SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));              SET @Month = '08';          END;     -- fetch IRP5 code data      IF OBJECT_ID('tempdb..#TEMPDATA') IS NOT NULL          DROP TABLE #TEMPDATA;        SELECT DISTINCT EmployeeNumber , Employee_Id , [EmpCode] , [IRP5Code] ,              ISNULL(SUM(Amount) OVER ( PARTITION BY EmployeeNumber, Employee_Id, [EmpCode], [IRP5Code] ), 0) AS amount       INTO    #TEMPDATA FROM    VwEmployeeIRP5CodeValue WHERE   CASE WHEN @IsTerminated = 1 THEN EndDate              ELSE @FromDate END BETWEEN @FromDate AND @ToDate              AND PeriodEndDate BETWEEN @FromDate AND @ToDate AND ( CycleId = @PayrollCycleId OR @PayrollCycleId = 0);        SET @TerminationCondition = ' where Enabled =1 AND IsDummy = 0 and CASE WHEN '          + CONVERT(VARCHAR, @IsTerminated) + '= 1 THEN EndDate ELSE ''' + CONVERT(VARCHAR, @FromDate) + ''' END BETWEEN '''          + CONVERT(VARCHAR, @FromDate) + ''' AND ''' + CONVERT(VARCHAR, @ToDate) + '''';          SELECT  @SQLQuery = STUFF((SELECT    'UNION ALL    Select dbo.AppendString_fxn(Employee_ID, 8, ''0'') AS EmployeeNumber ,Cast([Employee_Id] as Varchar(255)) [Employee_Id],[Empcode],'   + QUOTENAME('' + CodeName + '', '''') + ' AS FieldName,   + Convert(varchar(200),' + FieldName + ') AS TableValue,'   + QUOTENAME('' + FieldName + '', '''') + ' AS ValidatedColumn,   ''Employee'' as FieldValue,(Case when '   + Formula + ' then ''' + ErrorDescription + ''' else '''' end) AS Valid, '   + QUOTENAME(CodeValue, '''') + ' AS [Code], ' + QUOTENAME(Mandatory, '''') + ' as Mandatory,''' + @payrollCycle   + ''' as cycle ,''' + @TaxPeriod + ''' as TaxPeriod ,' + QUOTENAME(TaxYear, '''') + ' as TaxYear ,' + QUOTENAME(ExceptionType, '''') + ' as ExceptionType    FROM ' + QUOTENAME(TableName) + ' D ' + @TerminationCondition   FROM      Payroll_ValidationRules C WHERE C.exceptionType = 'Employee' and C.Enable = 1   FOR  XML PATH('') , TYPE).value('.', 'varchar(max)'), 1, 11, '');            SET @SQLQuery = 'Select distinct CONVERT(INT, code) as code , CONVERT(INT, Employee_ID) as Employee_ID,EmployeeNumber, EmpCode, FieldName,ExceptionType,TableValue, Valid as Valid, FieldValue, Mandatory , Cycle ,TaxPeriod , TaxYear  From (' + @SQLQuery      + ') A Where Len(Valid) > 0 and A.Employee_ID IN (SELECT DISTINCT EmployeeID FROM dbo.Payroll_EmployeePayslip WHERE PeriodID IN (SELECT Period_ID FROM dbo.Payroll_CyclePeriodDetails WHERE PeriodEndDate BETWEEN '''      + CONVERT(VARCHAR, @FromDate) + ''' AND ''' + CONVERT(VARCHAR, @ToDate) + ''' AND (CycleID = '      + CONVERT(VARCHAR, @PayrollCycleId) + ' OR ' + CONVERT(VARCHAR, @PayrollCycleId)      + ' = 0) )) and A.ExceptionType=''Employee'' and A.TaxYear='''+ @TaxYear + ''' ORDER BY CONVERT(INT, Employee_ID), CONVERT(INT, code)';        execute (@SQLQuery);     set nocount off;    end    

GO

