-- SP: Payroll_ValidateFinancial_sp
-- Schema: dbo
-- ============================================
  /* =============================================      Author: Jaydev Jangid / Maulik  Create date:  21 Oct 2016   Description: Validate employee financial rules  [Payroll_ValidateFinancial_sp]  'February', '2015/2016',0,0  =============================================    */  CREATE procedure [Payroll_ValidateFinancial_sp] @TaxPeriod nvarchar(100), @TaxYear nvarchar(100), @PayrollCycleId int, @IsTerminated bit = 0  as    BEGIN     set nocount on;        DECLARE @FromDate DATETIME;       DECLARE @ToDate DATETIME;       DECLARE @Month NVARCHAR(2);    DECLARE @SQLQuery NVARCHAR(MAX) = '';      DECLARE @PayrollCycle NVARCHAR(100);         SELECT TOP 1 @FromDate = PeriodStartDate FROM    dbo.Payroll_CyclePeriodDetails WITH ( NOLOCK ) WHERE   ( CycleID = @PayrollCycleId OR @PayrollCycleId = 0              ) AND FinancialYear = @TaxYear ORDER BY Period_ID;         SELECT TOP 1 @PayrollCycle = CycleDesc FROM    dbo.Const_Cycle WHERE   Cycle_ID = @PayrollCycleId;       IF @PayrollCycleId = 0    SET @PayrollCycle = ISNULL(@PayrollCycle, 'ALL');        IF @TaxPeriod = 'February'          BEGIN              SET @ToDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate));              SET @Month = '02';          END;      ELSE          BEGIN              SET @ToDate = DATEADD(DAY, -1, DATEADD(MONTH, 6, @FromDate));              SET @Month = '08';          END;        IF OBJECT_ID('tempdb..#TempFinancialData') IS NOT NULL          DROP TABLE #TempFinancialData;        SELECT DISTINCT EmployeeNumber , Employee_Id , [EmpCode] , [IRP5Code] , ISNULL(SUM(Amount) OVER ( PARTITION BY EmployeeNumber,              Employee_Id, [EmpCode], [IRP5Code] ), 0) AS amount INTO    #TempFinancialData FROM    VwEmployeeIRP5CodeValue      WHERE   CASE WHEN @IsTerminated = 1 THEN EndDate ELSE @FromDate END BETWEEN @FromDate AND @ToDate              AND PeriodEndDate BETWEEN @FromDate AND @ToDate AND ( CycleId = @PayrollCycleId OR @PayrollCycleId = 0 );       /*  Starting validation rules here */   /*   INSERT  INTO  Payroll_ValidationRules    (Enable, ExceptionType, CodeName, TaxYear ,CodeValue,CodeCount, Mandatory, TableName, FieldName, Formula, ErrorDescription )   VALUES   (1, 'Financial', 'Income received', @TaxYear,  0000,1,'Optional','#TempFinancialData','Financial', 'IRP5Code != case when Exists (SELECT 1 FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4493'' and  Amount > 0) then ''3810'' else ''0'' end   and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3817'' else ''0'' end  and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3867'' else ''0'' end    and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3825'' else ''0'' end  and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3875'' else ''0'' end    and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3828'' else ''0'' end  and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3878'' else ''0'' end    and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3619'' else ''0'' end and IRP5Code != case when ' +  CONVERT(NVARCHAR, Year(@ToDate)) + ' >= 2017 then ''3669'' else ''0'' end   and IRP5Code != ''3615'' and    ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData  T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code in (''3601'',''3651'',''3602'',''3652'',''3603'',''3653'',''3605'',''3655'',''3606'',''3656'',''3608'',''3658'',''3610'',''3660'',''3611'',''3661'',''3613'',''3663'',''3614'',''3664'',''3615'',''3665'',''3616'',''3666'',''3617'',''3667'',''3619'',''3669'',''3701'',''3751'',''3702'',''3752'',''3703'',''3753'',''3704'',''3754'',''3707'',''3757'',''3708'',''3758'',''3713'',''3763'',''3714'',''3464'',''3715'',''3465'',''3717'',''3767'',''3718'',''3768'',''3801'',''3851'',''3802'',''3852'',''3805'',''3855'',''3806'',''3856'',''3808'',''3858'',''3809'',''3859'',''3810'',''3860'',''3813'',''3863'',''3815'',''3865'',''3816'',''3866'',''3817'',''3867'',''3818'',''3868'',''3819'',''3869'',''3820'',''3870'',''3821'',''3871'',''3822'',''3872'',''3825'',''3875 '',''3828'',''3878'',''3901'',''3951'',''3906'',''3956'',''3907'',''3957'',''3908'',''3909'',''3915'',''3920'',''3921'',''3922'') ),0) <= (SELECT top 1 ISNULL(Amount,0) FROM #TempFinancialData T WHERE T.IRP5Code = ''3615'' AND T.Employee_ID = D.Employee_ID ) ','amount must be greater than zero.' )        ,(1, 'Financial', 'Medical services costs (PAYE)', @TaxYear, 3813,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code IN (''3813'',''3863'')),0) = 0.00 and (SELECT TOP 1 B.NatureOfPersonCode FROM PAYROLL_EMPLOYEE A INNER JOIN Const_NatureOfPerson_Sys B ON A.NatureOfPersonID = B.NatureOfPerson_ID WHERE A.Employee_ID = D.Employee_Id) IN (''A'', ''B'', ''C'', ''M'', ''N'' , ''R'')','Value should be greater than zero for A, B, C, M, N or R' )   ,(1, 'Financial', 'Medical aid contributions (PAYE)', @TaxYear, 3810,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code IN (''3810'',''3860'')),0) = 0.00 and (SELECT TOP 1 B.NatureOfPersonCode FROM PAYROLL_EMPLOYEE A INNER JOIN Const_NatureOfPerson_Sys B ON A.NatureOfPersonID = B.NatureOfPerson_ID WHERE A.Employee_ID = D.Employee_Id) IN (''A'', ''B'', ''C'', ''M'', ''N'' , ''R'')','Value should be greater than zero for A, B, C, M, N or R' )   ,(1, 'Financial', 'Medical aid contributions (PAYE)', @TaxYear, 3810,2,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code IN (''3810'',''3860'')),0) != (SELECT TOP 1 T.AMOUNT  FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4474'')','equal to the value for code 4474' )   ,(1, 'Financial', 'Medical aid contributions (PAYE)', @TaxYear,  3810,3,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''3810''),0) > 0.00 and ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4493''),0) > 0.00','3810 should be greater than or equal to 4493' )   ,(1, 'Financial', 'Retirement /termination of employment lump sum benefits / Commutation of annuities (PAYE)', @TaxYear, 3915,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code IN (''3915'', ''3920'', ''3921'')),0) = 0  AND (SELECT TOP 1 ISNULL(T.AMOUNT,0)  FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4115'') > 0','3915, 3920, 3921 ARE mandatory' )   ,(1, 'Financial', 'Retirement /termination of employment lump sum benefits / Commutation of annuities (PAYE)', @TaxYear,  3915,2,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code IN (''3915'', ''3920'', ''3922'')),0) = 0  AND (SELECT TOP 1 ISNULL(T.AMOUNT,0)  FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4115'') > 0','3915, 3920, 3922 ARE mandatory' )   ,(1, 'Financial', 'Medical services costs (PAYE)', @TaxYear,  3813,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''3813''),0) < (SELECT TOP 1 ISNULL(T.AMOUNT,0)  FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4024'') ','3813 should be greater than or equal to 4024' )   ,(1, 'Financial', 'Medical services costs (PAYE)', @TaxYear,  3863,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''3863''),0) < (SELECT TOP 1 ISNULL(T.AMOUNT,0)  FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4024'') ','3863 should be greater than or equal to 4024' )   ,(1, 'Financial', 'Director’s remuneration (PAYE)', @TaxYear,  3615,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''3615''),0) = 0.00 and (SELECT TOP 1 B.NatureOfPersonCode FROM PAYROLL_EMPLOYEE A INNER JOIN Const_NatureOfPerson_Sys B ON A.NatureOfPersonID = B.NatureOfPerson_ID WHERE A.Employee_ID = D.Employee_Id) = ''C''','3863 should be greater than or equal to 4024' )       ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4005,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4005''),0) = 0.00 and (SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData  T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code in (''3810'',''3860'')) > 0 and (SELECT TOP 1 B.NatureOfPersonCode FROM PAYROLL_EMPLOYEE A INNER JOIN Const_NatureOfPerson_Sys B ON A.NatureOfPersonID = B.NatureOfPerson_ID WHERE A.Employee_ID = D.Employee_Id) IN (''A'', ''B'', ''C'', ''M'', ''N'' , ''R'')','It is mandatory' )   ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4493,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4493''),0) = 0.00 and (SELECT TOP 1 B.NatureOfPersonCode FROM PAYROLL_EMPLOYEE A INNER JOIN Const_NatureOfPerson_Sys B ON A.NatureOfPersonID = B.NatureOfPerson_ID WHERE A.Employee_ID = D.Employee_Id) IN (''A'', ''B'', ''C'', ''M'', ''N'' , ''R'')','It is mandatory' )   ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4582,1,'Optional','#TempFinancialData','Financial', 'CONVERT(INT,' + CONVERT(NVARCHAR, Year(@ToDate)) + ') >= 2017 AND ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4582''),0) = 0.00 and (SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData  T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code in (''3701'',''3702'',''3802'',''3816'')) > 0 ','This field become mandatory' )   ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4582,2,'Optional','#TempFinancialData','Financial', 'CONVERT(INT,' + CONVERT(NVARCHAR, Year(@ToDate)) + ') >= 2017 AND ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4582''),0) > (SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData  T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code in (''3701'',''3702'',''3802'',''3816'')) ','4582 must not greater than other codes.' )     ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4102,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4102''),NULL) IS NULL AND ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData  T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code in (''4115'',''4150'')),null) IS NULL ','4102 is mandatory.' )   ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4102,1,'Optional','#TempFinancialData','Financial', ' ISNULL((SELECT TOP 1 Sum(ISNULL(Amount,0)) FROM #TempFinancialData T WHERE T.Employee_Id = D.Employee_Id AND IRP5Code = ''4102''),0) > 0 AND ISNULL((select PayeRegistrationNo from Payroll_Municipality where PayeRegistrationNo LIKE ''7%''),null) IS NULL ','4102 is not valid.' )   ,(1, 'Financial', 'Deductions/Contributions', @TaxYear,  4115,1,'Optional','#TempFinancialData','Financial', ' ISN