cialData WHERE IRP5Code in (''3601'',''3651'',''3602'',''3652'',''3603'',''3653'',''3605'',''3655'',''3606'',''3656'',''3608'',''3658'',''3610'',''3660'',''3611'',''3661'',''3613'',''3663'',''3614'',''3664'',''3615'',''3665'',''3616'',''3666'',''3617'',''3667'',''3619'',''3669'',''3701'',''3751'',''3702'',''3752'',''3703'',''3753'',''3704'',''3754'',''3707'',''3757'',''3708'',''3758'',''3713'',''3763'',''3714'',''3464'',''3715'',''3465'',''3717'',''3767'',''3718'',''3768'',''3801'',''3851'',''3802'',''3852'',''3805'',''3855'',''3806'',''3856'',''3808'',''3858'',''3809'',''3859'',''3810'',''3860'',''3813'',''3863'',''3815'',''3865'',''3816'',''3866'',''3817'',''3867'',''3818'',''3868'',''3819'',''3869'',''3820'',''3870'',''3821'',''3871'',''3822'',''

