-- SP: Payroll_ValidateHeader_sp
-- Schema: dbo
-- ============================================
    /*  -- =============================================      -- Author: Richa Mills  -- Create date:  2018/07/09  -- Description: Validate Municipaliry rules Header  [Payroll_ValidateHeader_sp]  'August', '2017/2018',17  -- =============================================     */   CREATE procedure [dbo].[Payroll_ValidateHeader_sp]     @TaxPeriod nvarchar(100),   @TaxYear nvarchar(100),   @PayrollCycleId int    as    begin     set nocount on;        declare @PayrollCycle nvarchar(100),     @SQLQuery nvarchar(MAX)        select top 1 @PayrollCycle = CycleDesc FROM    dbo.Const_Cycle WHERE   Cycle_ID = @PayrollCycleId;        IF ISNULL(@PayrollCycleId,0) = 0    SET @PayrollCycle = ISNULL(@PayrollCycle, 'ALL');     SELECT  @SQLQuery = STUFF((SELECT    'UNION ALL    Select MunicipalityNo AS EmployeeNumber,Municipality_ID as [Employee_Id],MunicipalityNo as Empcode, '    + QUOTENAME(CodeName, '''') + ' AS FieldName,     Convert(varchar(200),' + FieldName + ') AS TableValue,    ''Header'' as FieldValue,    (Case when ' + Formula + ' then ''' + ErrorDescription + ''' else '''' end) AS Valid, '          + QUOTENAME(CodeValue, '''') + ' AS [Code], ' + QUOTENAME(Mandatory, '''') + ' as Mandatory, ''' + @PayrollCycle    + ''' as cycle , ''' + @TaxPeriod + ''' as TaxPeriod , ' + QUOTENAME(TaxYear, '''') + ' as TaxYear , ' + QUOTENAME(ExceptionType, '''') + ' as ExceptionType    FROM ' + QUOTENAME(TableName) FROM Payroll_ValidationRules C WHERE C.exceptionType = 'Header'      FOR XML PATH('') , TYPE).value('.', 'varchar(max)'), 1, 11, '');             SET @SQLQuery = 'Select distinct CONVERT(INT, code) as code , CONVERT(INT, Employee_ID) as Employee_ID, EmployeeNumber,EmpCode ,FieldName,ExceptionType,TableValue,Valid as Valid,              FieldValue , Mandatory , Cycle ,TaxPeriod , TaxYear From (' + @SQLQuery + ') A Where Len(Valid) > 0 and A.ExceptionType=''Header'' and A.TaxYear='''+ @TaxYear + ''' ORDER BY CONVERT(INT, Employee_ID), CONVERT(INT, code)';        Exec (@SQLQuery)     SET NOCOUNT OFF  END;          

GO

