        CREATE PROCEDURE [dbo].[Payroll_ValidateIndividualEmployee_sp] @dtValidateEmployee Payroll_ValidateAddEmployee_ut READONLY  AS      BEGIN      SET NOCOUNT ON    -- Create employee temporary table and insert all fields     IF OBJECT_ID('tempdb..#tempEmployeeValidate') IS NOT NULL              DROP TABLE #tempEmployeeValidate;            CREATE TABLE #tempEmployeeValidate              (      NatureOfPersonID  INT   NULL,  --3020      Surname NVARCHAR (100) NULL,  --3030      FirstName NVARCHAR (100) NULL,  --3040      SecondName NVARCHAR (100) NULL,  --      Initials NVARCHAR (100) NULL,  --3050      IdNo NVARCHAR (100) NULL,  --3060      AlternateIDType INT NULL,  --3065 No      AlternateIDNumber NVARCHAR (60) NULL,  --3066       PassportNumber NVARCHAR (100) NULL,  --3070      PassportCountryID  INT  NULL,  --3075      DateOfBirth  DATETIME  NULL,  --3080      IncomeTaxNumber NVARCHAR (200) NULL,  --3100      EmailAddress NVARCHAR (200) NULL,  --3125      HomeNumber NVARCHAR (200) NULL,  --3135      WorkNumber NVARCHAR (200) NULL,  --3136      FaxNumber NVARCHAR (200) NULL,  --3137      CellNumber NVARCHAR (200) NULL,  --3138      PhyWorkUnit NVARCHAR (8) NULL,  --3144      PhyWorkComplex NVARCHAR (400) NULL,  --3145      PhyWorkStreetNo NVARCHAR(8) NULL,  --3146      PhyWorkStreetId INT  NULL,  --3147      WorkSuburbID INT  NULL,  --3148      WorkPostalCode NVARCHAR (100) NULL,  --3150      PhyWorkCountryId  INT  NULL,  --3151      Employee_ID INT  NULL,  --3160      JoiningDate DATETIME  NULL,  --3170      EndDate DATETIME  NULL,  --3180      PhysicalFlatUnitSuiteNo NVARCHAR (400) NULL,  --3211      PhysicalComplexName NVARCHAR (400) NULL,  --3212      PhysicalStreetNo  NVARCHAR(8) NULL,  --3213      PhysicalStreetID INT  NULL,  --3214      PhysicalSuburbID INT  NULL,  --3215      PhysicalPostalCode NVARCHAR (200) NULL,  --3217      AccountTypeID INT  NULL,  --3240      AccountNumber NVARCHAR (100) NULL,  --3241      BranchID INT  NULL,  --3242      BankID INT NULL,  --3243      --BankID int NULL,  --3244      AccountHolderName NVARCHAR (200) NULL,  --3245      AccountHolderRelationshipID INT  NULL,  --3246      PostalAddressTypeID INT  NULL,  --3249      PostalFlatUnitSuiteNo NVARCHAR (400) NULL,  --3251      PostalPostOffice NVARCHAR (100) NULL,  --3253      PostalPostalCode NVARCHAR (100) NULL,  --3254      PostalAddressUnitNumber NVARCHAR (420) NULL,  --3255      PostalComplexName NVARCHAR (400) NULL,  --3256      PostalStreetName NVARCHAR (200) NULL,  --3257      PostalStreetID INT  NULL,  --3258      PostalSuburbID INT  NULL,  --3259      PostalAddressNo NVARCHAR (8) NULL,  --3262         PoSpecialService NVARCHAR (42) NULL,  --3280      CareOfIntermediary NVARCHAR (1000) NULL,  --3283      PhysicalCountryID INT  NULL,  --3285      PostalCountryID INT  NULL,  --3286      PostalSameAsPhysical BIT  NULL,  --3288      PostalAddress1 NVARCHAR (200) NULL,  --3289      PostalAddress2 NVARCHAR (200) NULL,  --3290      PostalAddress3 NVARCHAR (200) NULL,  --3291      PostalAddress4 NVARCHAR (200) NULL,  --3292      WorkTownID INT  NULL,        PhysicalTownID INT  NULL,        PaymentTypeID INT  NULL,        PostalTownID INT  NULL,        AddressIndicator INT NULL,      FarmId int null,      PhyAddressComplex NVARCHAR (200) NULL,      PhyAddressUnit NVARCHAR (8) NULL              );            INSERT  INTO #tempEmployeeValidate          SELECT * FROM @dtValidateEmployee      /*  Starting validation rules here */    /*    INSERT  INTO  Payroll_ValidationRules     (Enable, ExceptionType, CodeName, TaxYear ,CodeValue,CodeCount, Mandatory, TableName, FieldName, Formula, ErrorDescription )    VALUES        (1,'AddEmployee', 'Nature of person', '2016/2017',  3020,1,'Mandatory','#tempEmployeeValidate','NatureOfPersonID', 'LEN (ISNULL(CONVERT(VARCHAR,(SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID)),'''')) = 0','Nature of person is mandatory')    ,( 1,'AddEmployee', 'Employee surname or trading name', '2016/2017', 3030,1,'Mandatory','#tempEmployeeValidate','Surname', 'Surname like  N''%[0-9]%'' and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'')','Numeric characters are not allowed ')    ,( 1,'AddEmployee', 'Employee surname or trading name', '2016/2017', 3030,2,'Mandatory','#tempEmployeeValidate','Surname', 'len(isnull(Surname,'''')) = 0 or len(Surname) > 120 ','Mandatory field')        ,( 1,'AddEmployee', 'First names', '2016/2017', 3040,1,'Conditional','#tempEmployeeValidate','FirstName', '(len(isnull(FirstName,0)) > 90 or len(isnull(FirstName,'''')) = 0 or FirstName like  N''%[0-9]%'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'') and ISNUMERIC(FirstName) = 0','Numeric characters are not allowed ')    ,( 1,'AddEmployee', 'First names', '2016/2017', 3040,2,'Conditional','#tempEmployeeValidate','FirstName', '(len(IdNo) >0 or LEN(PassportNumber) > 0 ) AND LEN(idno) >0 AND LEN(Initials) >0 AND  LEN(DateOfBirth)>0  and LEN(isnull(FirstName,'''')) =0','FirstName Mandatory if initials, date of birth or identity/passport number has been completed ')    ,( 1,'AddEmployee', 'First names', '2016/2017', 3040,3,'Conditional','#tempEmployeeValidate','FirstName', 'len(FirstName)> 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''D'',''E'',''F'',''G'',''H'')','Numeric characters are not allowed ')       ,( 1,'AddEmployee', 'Second names', '2016/2017', 3040,1,'Conditional','#tempEmployeeValidate','SecondName', '(len(isnull(SecondName,'''')) = 0 or len(SecondName) > 90 or SecondName like  N''%[0-9]%'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'') and ISNUMERIC(SecondName) = 0','Numeric characters are not allowed ')    ,( 1,'AddEmployee', 'Second names', '2016/2017', 3040,2,'Conditional','#tempEmployeeValidate','SecondName', '(len(IdNo) >0 or LEN(PassportNumber ) > 0 ) AND LEN(idno) >0 AND LEN(Initials) >0 AND LEN(DateOfBirth)>0  and LEN(isnull(SecondName,'''')) =0','SecondName Mandatory if initials, date of birth or identity/passport number has been completed ')    ,( 1,'AddEmployee', 'Second names', '2016/2017', 3040,3,'Conditional','#tempEmployeeValidate','SecondName', 'len(SecondName)> 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''D'',''E'',''F'',''G'',''H'')','Numeric characters are not allowed ')      ,( 1,'AddEmployee', 'Initials', '2016/2017', 3050,1,'Conditional','#tempEmployeeValidate','Initials', 'len(isnull(Initials,'''')) = 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'')','Mandatory if Nature of Person A / B / C / M / N / R')    ,( 1,'AddEmployee', 'Initials', '2016/2017', 3050,2,'Conditional','#tempEmployeeValidate','Initials', '(len(IdNo) > 0 or LEN(PassportNumber ) > 0 ) and LEN(Initials) =0','Initials Mandatory if date of birth or identity has been completed ')    ,( 1,'AddEmployee', 'Initials', '2016/2017', 3050,2,'Conditional','#tempEmployeeValidate','Initials', ' len(Initials) > 5 or Initials like  N''%[0-9]%'' or (Initials like ''%-%'' OR Initials like ''% %'' OR Initials like ''%,%'' OR Initials like ''%.%'' OR Initials like ''%.%'' OR Initials like ''%ê%'' OR Initials like ''%ë%'' OR Initials like ''%''''%'')','Special characters are not allowed ')        ,( 1,'AddEmployee', 'Identity Number', '2016/2017', 3060,1,'Conditional','#tempEmployeeValidate','IdNo', '(dbo.Payroll_ValidateIRPEmpId_Fxn(isnull(IdNo,0)) <> 1 or  len(IdNo) <> 13 or len(isnull(IdNo,'''')) = 0) and len(isnull(PassportNumber,'''')) = 0  and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''C'')','Mandatory field if Nature of Person is A / C and passport number is not completed')    ,( 1,'AddEmployee', 'Identity Number', '2016/2017', 3060,2,'Conditional','#tempEmployeeValidate','IdNo', '( len(IdNo) <> 13 or len(isnull(IdNo,'''')) = 0) and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''R'')','Mandatory field if Nature of Person is R')    ,( 1,'AddEmployee', 'Identity Number', '2016/2017', 3060,3,'Conditional','#tempEmployeeValidate','IdNo', 'len(IdNo) > 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''B'',''D'',''E'',''F'',''G'',''H'',''M'')','May not be completed for Nature of Person B / D / E / F / G / H / M')        ,( 1,'AddEmployee', 'Alternate Identification Type', '2016/2017', 3065,1,'Conditional','#tempEmployeeValidate','AlternateIDType', '(AlternateIDType) > 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''F'',''N'',''R'')','Must not be completed if Nature of Person is A / B / C / F / N or R ')    ,( 1,'AddEmployee', 'Alternate Identification Type', '2016/2017', 3065,2,'Conditional','#tempEmployeeValidate','AlternateIDType', 'len(AlternateIDType) > 1 or (isnull(AlternateIDType,-1) = -1 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''D'',''E'',''G'',''H'',''M''))','Must be completed if Nature of Person is D / E / G / H / M ')        ,( 1,'AddEmployee', 'Alternate Identification Number', '2016/2017', 3066,1,'Conditional','#tempEmployeeValidate','AlternateIDNumber', '(len(AlternateIDType) > 1 and len(isnull(AlternateIDNumber,'''')) = 0) or (len(AlternateIDType) = 0 and len(isnull(AlternateIDNumber,'''')) >1)','Not as per rules')    ,( 1,'AddEmployee', 'Alternate Identification Number', '2016/2017', 3066,2,'Conditional','#tempEmployeeValidate','AlternateIDNumber', 'AlternateIDType = 1 and (SUBSTRING(AlternateIDNumber, 5, 1) <> ''/'' or SUBSTRING(AlternateIDNumber, 12, 1) <> ''/'')','Not as per rules')    ,( 1,'AddEmployee', 'Alternate Identification Number', '2016/2017', 3066,3,'Conditional','#tempEmployeeValidate','AlternateIDNumber', 'AlternateIDType = 1 and SUBSTRING(AlternateIDNumber, 13, 2) not in (''06'', ''07'', ''08'', ''09'', ''10'', ''11'', ''20'', ''21'', ''22'', ''23'', ''24'', ''25'', ''26'', ''30'', ''31'') ','Not as per rules')      ,( 1,'AddEmployee', 'Passport number', '2016/2017', 3070,1,'Conditional','#tempEmployeeValidate','PassportNumber', '(isnull(PassportCountryID,-1) = -1 or len(isnull(PassportNumber,'''')) = 0 or len(PassportNumber) < 6 or len(PassportNumber) > 18 ) and ((SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''C'') and len(isnull(Idno,'''')) =0 )','Mandatory if Nature of Person A / C')    ,( 1,'AddEmployee', 'Passport number', '2016/2017', 3070,2,'Conditional','#tempEmployeeValidate','PassportNumber', 'len(PassportNumber) > 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''B'',''D'',''E'',''F'',''G'',''H'')','May not be completed for Nature of Person B / D / E / F / G / H')      ,( 1,'AddEmployee', 'Country of issue', '2016/2017', 3075,1,'Conditional','#tempEmployeeValidate','PassportCountryID', '(len(PassportNumber) > 0 and isnull(PassportCountryID,-1) = -1 ) or ((SELECT TOP 1 Country_ID FROM dbo.Const_Country cid where cid.CountryCode= ''ZAF'')  <> PassportCountryID and LEN(ISNULL((SELECT PassportCountryCode FROM dbo.Const_Country cid where cid.PassportCountryCode= ''ZAF''),'''')) <> 3) ','Check Passport Country of Issue')      ,( 1,'AddEmployee', 'Date of Birth', '2016/2017', 3080,1,'Conditional','#tempEmployeeValidate','DateOfBirth', '(LEN(CONVERT(VARCHAR,GETDATE(),112)) <> 8 or DateOfBirth > getdate() or len(DateOfBirth) = 0) and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''M'',''N'',''R'')','Mandatory if Nature of Person A / B / C / M / N / R')    ,( 1,'AddEmployee', 'Date of Birth', '2016/2017', 3080,2,'Conditional','#tempEmployeeValidate','DateOfBirth', 'len(DateOfBirth) > 0 and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''D'',''E'',''F'',''G'',''H'')','May not be completed for Nature of Person D / E / F / G / H')      ,( 1,'AddEmployee', 'Income Tax Reference Number', '2016/2017', 3100,1,'Mandatory','#tempEmployeeValidate','IncomeTaxNumber', 'Substring(IncomeTaxNumber,1,1) not in (''0'',''1'',''2'',''3'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''A'',''B'',''C'',''D'',''M'',''N'',''R'')','If Nature of Person A, B, C, D, M, N or R; the number may only start with either 0, 1, 2, or 3 ')    ,( 1,'AddEmployee', 'Income Tax Reference Number', '2016/2017', 3100,2,'Mandatory','#tempEmployeeValidate','IncomeTaxNumber', 'Substring(IncomeTaxNumber,1,1) not in (''9'') and (SELECT NatureOfPersonCode FROM dbo.Const_NatureOfPerson_Sys CNP WHERE CNP.enabled=1 and NatureOfPerson_ID =NatureOfPersonID) IN (''E'',''G'',''H'')','If Nature of Person E, G, H ; the number may only start with 9 ')    ,( 1,'AddEmployee', 'Income Tax Reference Number', '2016/2017', 3100,3,'Mandatory','#tempEmployeeValidate','IncomeTaxNumber', 'len(IncomeTaxNumber) > 0  and (SELECT NatureOfPersonCode FROM dbo.Const