-- ============================================
   /*   Author  : Richa M   Created  : 2021/02/10   Description : Validates the Position SCOA (Items)   Payroll_ValidatePositionScoa_sp 0,'2021/2022'    */  CREATE procedure [dbo].[Payroll_ValidatePositionScoa_sp](@PositionID int = null, @FinYear varchar(9) = null)  as  begin     declare @SalaryProjectID int = null,     @SalaryControlID int = null     declare @projectItems as table (      [DivisionID] int null,    [ProjectID] int null,    [ScoaItemID] int null,    [ScoaFunctionID] int null,    [ScoaRegionID] int null,    [PlanProjectItemId] int null     )     if (@FinYear is null)      select @FinYear = [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'ActiveFinYear')     select @SalaryProjectID = [SalaryProjectID], @SalaryControlID = [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock) where ([FinYear] = @FinYear)     insert into @projectItems([DivisionID], [ProjectID], [ScoaItemID], [ScoaFunctionID], [ScoaRegionID],[PlanProjectItemId])      select [PPI].[DivisionId], [PP].[Project_ID], [PPI].[SCOAItemID], [PPI].[SCOAFunctionId], [PPI].[SCOARegionId],[PPI].[PlanProjectItem_ID]       from [Plan_ProjectItem] as [PPI] with(nolock)        join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [PPI].[ProjectID]       where ([PP].[FinYear] = @FinYear)     Select v1.*,    --dt legs    dtDivision.DivisionCode DtDivisionCode,     dtDivision.DivisionDesc dtDivisionDesc,    dtProj.ProjectName dtProjectName,    dtProj.ProjectCode dtProjectCode,    dtstruc.ScoaCode dtScoaCode,    dtstruc.ScoaDesc dtScoaDesc,    dtfunc.ScoaCode dtScoaFunctionCode,    dtfunc.ScoaDesc dtScoaFunctionDesc,    dtRegion.ScoaCode dtScoaRegionCode,    dtRegion.ScoaDesc dtScoaRegionDesc,   --ct legs   dtDivision.DivisionCode ctDivisionCode,     ctDivision.DivisionDesc ctDivisionDesc,    ctProj.ProjectName ctProjectName,    ctProj.ProjectCode ctProjectCode,    ctstruc.ScoaCode ctScoaCode,    ctstruc.ScoaDesc ctScoaDesc,    ctfunc.ScoaCode ctScoaFunctionCode,    ctfunc.ScoaDesc ctScoaFunctionDesc,    ctRegion.ScoaCode ctScoaRegionCode,    ctRegion.ScoaDesc ctScoaRegionDesc       from (   select [POS].[Position_ID], [POS].[PositionDesc],      (case       when [POS].[Status] = 1 then 'Vacant'       when [POS].[Status] = 2 then 'Occupied'       when [POS].[Status] = 4 then 'Seconded'      end) as [Status],      [SH].[SalaryHeadTitle],      [POS].[DivisionID] DtDivisionId,      (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) DtProjectId,        (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 6 then [GL].[ScoaItemIDPostRetirement]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) DtScoaItemId,        [POS].[FunctionID] DtFunctionId,        [POS].[RegionID] DtRegionId,        [PDI].PlanProjectItemId DtProjectItemID,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) CtDivisionId,        (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) CtProjectId,        (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]          when 1 then [GL].[SCOAItemID]          when 6 then [GL].[SCOAItemID]         end)         else [GL].[SuspenseScoaItemCreditID]        end) CtScoaItemId,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) CtFunctionId,        (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end) CtRegionId,        [PCI].[PlanProjectItemId] CtProjectItemId      from [Payroll_PayrollDefination] as [PD] with(nolock)       join [Payroll_DefinitionGroup] as [DG] with(nolock) on [DG].[PayrollDefinitionGroup_ID] = [PD].[PayrollDefinitionGroupID] and [DG].[Enabled] = 1       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] in(1, 2, 3) and [IRP5].[Enabled] = 1       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[FinYear] = @FinYear and [GL].[Enabled] = 1       join [Payroll_Position] as [POS] with(nolock) on        [POS].[Position_ID] = (case when @PositionID is null then [POS].[Position_ID] else @PositionID end) and        [POS].[Status] in(1, 2, 4) and        [POS].[Enabled] = 1       left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [POS].[ProjectID]       /* DEBIT */     left outer join @projectItems as [PDI] on        [PDI].[DivisionID] = [POS].[DivisionID] and        [PDI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) and        [PDI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 6 then [GL].[ScoaItemIDPostRetirement]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) and        [PDI].[ScoaFunctionID] = [POS].[FunctionID] and        [PDI].[ScoaRegionID] = [POS].[RegionID]       /* CREDIT */     left outer join @projectItems as [PCI] on        [PCI].[DivisionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) and        [PCI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) and        [PCI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]          when 1 then [GL].[SCOAItemID]          when 6 then [GL].[SCOAItemID]         end)         else [GL].[SuspenseScoaItemCreditID]        end) and        [PCI].[ScoaFunctionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) and        [PCI].[ScoaRegionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end)       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_Consolidated] where FinyearText = @FinYear and ScoaId = [PDI].[ScoaItemID]        ) as [SDC]       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_Consolidated] where FinyearText = @FinYear and ScoaID = [PCI].[ScoaItemID]       ) as [SCC]      where ([PD].[PayrollDefinitionGroupID] = [POS].[PayrollDefinitionGroupID] and [PD].[Enabled] = 1 and [POS].[EmployeeTypeID] in(1, 6) and       [IRP5].[TransactionTypeID] in(1, 2, 3) and ([PDI].[ProjectID] is null or [PCI].[ProjectID] is null))       )V1     Left Join Const_Division dtDivision on dtDivision.Division_ID = DtDivisionId       Left Join Const_Division ctDivision on ctDivision.Division_ID = CtDivisionId        left join Plan_Project dtProj on dtProj.Project_ID = DtProjectId       left join Plan_Project ctProj on ctProj.Project_ID = CtProjectId       left join Const_SCOA_Function_Structure dtfunc on dtfunc.ScoaID = DtFunctionId       left join Const_SCOA_Function_Structure ctfunc on ctfunc.ScoaID = CtFunctionId       left join Const_SCOA_Regional_Structure dtRegion on dtRegion.ScoaID = DtRegionId       left join Const_SCOA_Regional_Structure ctRegion on ctRegion.ScoaID = CtRegionId       Left Join Const_Scoa_Structure dtstruc ON dtstruc.ScoaID = DtScoaItemId       Left Join Const_Scoa_Structure ctstruc ON ctstruc.ScoaID = CtScoaItemId       order by [V1].[Position_ID], [V1].[SalaryHeadTitle]  end

GO

-- ============================================
-- SP: Payroll_ValidatePositionScoaSalaryStructure_sp
-- Schema: dbo
-- ============================================
  /*   Author  : Ferdi Botha   Created  : 12/06/2019   Description : Validates the Position SCOA (Items)  */  create procedure [Payroll_ValidatePositionScoaSalaryStructure_sp](@PositionID int = null, @FinYear varchar(9) = null)  as  begin     declare @SalaryProjectID int = null,     @SalaryControlID int = null     declare @projectItems as table (      [DivisionID] int null,    [ProjectID] int null,    [ScoaItemID] int null,    [ScoaFunctionID] int null,    [ScoaRegionID] int null     )     if (@FinYear is null)      select @FinYear = [KeyValue] from [AAAA_ConfigSettings] with(nolock) where ([KeyName] = 'ActiveFinYear')     select @SalaryProjectID = [SalaryProjectID], @SalaryControlID = [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock) where ([FinYear] = @FinYear)     insert into @projectItems([DivisionID], [ProjectID], [ScoaItemID], [ScoaFunctionID], [ScoaRegionID])      select [PPI].[DivisionId], [PP].[Project_ID], [PPI].[SCOAItemID], [PPI].[SCOAFunctionId], [PPI].[SCOARegionId]       from [Plan_ProjectItem] as [PPI] with(nolock)        join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [PPI].[ProjectID]       where ([PP].[FinYear] = @FinYear)     select distinct [POS].[Position_ID], [POS].[PositionDesc],      (case       when [SDC].[ScoaCode] is null then (        select cast([Project_ID] as varchar) + ' ' + [ProjectDesc] from [Plan_Project] where ([Project_ID] = (case          when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID         end)        )       )       else (        select cast([Project_ID] as varchar) + ' ' + [ProjectDesc] from [Plan_Project] where ([Project_ID] = (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]          else [GL].[SCOAProjectID]         end)        )       )      end) as [ProjectDesc],      (case       when [POS].[Status] = 1 then 'Vacant'       when [POS].[Status] = 2 then 'Occupied'       when [POS].[Status] = 4 then 'Seconded'      end) as [Status],      [SH].[SalaryHeadTitle],      (case       when [SDC].[ScoaCode] is null then (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, (case          when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]           when 1 then [GL].[ScoaItemIDPermanentStaff]           when 2 then [ST].[GLScoaItem]           when 3 then [ST].[GLScoaItem]           when 6 then [GL].[ScoaItemIDPostRetirement]           when 7 then [ST].[GLScoaItem]          end)          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID         end)        )       )       else (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, (case          when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]           when 1 then [GL].[SCOAItemID]           when 2 then [ST].[GLScoaItem]           when 3 then [ST].[GLScoaItem]           when 6 then [GL].[SCOAItemID]           when 7 then [ST].[GLScoaItem]          end)          else [GL].[SuspenseScoaItemCreditID]         end)        )       )      end) as [ScoaCode]      from [Payroll_PayrollDefination] as [PD] with(nolock)       join [Payroll_DefinitionGroup] as [DG] with(nolock) on [DG].[PayrollDefinitionGroup_ID] = [PD].[PayrollDefinitionGroupID] and [DG].[Enabled] = 1       join [Payroll_SalaryHead] as [SH] with(nolock) on [SH].[SalaryHead_ID] = [PD].[PayrollSalaryHeadID] and [SH].[Enabled] = 1       join [Payroll_IRP5Code] as [IRP5] with(nolock) on [IRP5].[IRP5Code_ID] = [SH].[IRP5CodeId] and [IRP5].[TransactionTypeID] in(1, 2, 3) and [IRP5].[Enabled] = 1       join [Payroll_GLItems] as [GL] with(nolock) on [GL].[SalaryHeadID] = [SH].[SalaryHead_ID] and [GL].[FinYear] = @FinYear and [GL].[Enabled] = 1       join [Payroll_Position] as [POS] with(nolock) on        [POS].[Position_ID] = (case when @PositionID is null then [POS].[Position_ID] else @PositionID end) and        [POS].[Status] in(1, 2, 4) and        [POS].[Enabled] = 1       left outer join [Plan_Project] as [PP] with(nolock) on [PP].[Project_ID] = [POS].[ProjectID]       left outer join [Payroll_EmployeeSalaryTransaction] as [ST] with(nolock) on [ST].[EmployeeId] = [POS].[EmployeeID] and [ST].[SalaryHeadId] = [SH].[SalaryHead_ID]       /* DEBIT */     left outer join @projectItems as [PDI] on        [PDI].[DivisionID] = [POS].[DivisionID] and        [PDI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then [POS].[ProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAProjectID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryProjectID        end) and        [PDI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] in(1, 3) then (case [POS].[EmployeeTypeID]          when 1 then [GL].[ScoaItemIDPermanentStaff]          when 2 then [ST].[GLScoaItem]          when 3 then [ST].[GLScoaItem]          when 6 then [GL].[ScoaItemIDPostRetirement]          when 7 then [ST].[GLScoaItem]         end)         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SuspenseScoaItemID]         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 0 then @SalaryControlID        end) and        [PDI].[ScoaFunctionID] = [POS].[FunctionID] and        [PDI].[ScoaRegionID] = [POS].[RegionID]       /* CREDIT */     left outer join @projectItems as [PCI] on        [PCI].[DivisionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaDivisionId] else [POS].[DivisionID] end) and        [PCI].[ProjectID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then [GL].[SCOAItemProjectID]         else [GL].[SCOAProjectID]        end) and        [PCI].[ScoaItemID] = (case         when [IRP5].[TransactionTypeID] = 2 and [GL].[JournalEntryOnly] = 1 then (case [POS].[EmployeeTypeID]          when 1 then [GL].[SCOAItemID]          when 2 then [ST].[GLScoaItem]          when 3 then [ST].[GLScoaItem]          when 6 then [GL].[SCOAItemID]          when 7 then [ST].[GLScoaItem]         end)         else [GL].[SuspenseScoaItemCreditID]        end) and        [PCI].[ScoaFunctionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaFunctionId] else [POS].[FunctionID] end) and        [PCI].[ScoaRegionID] = (case when [GL].[JournalEntryOnly] = 1 then [GL].[ScoaRegionId] else [POS].[RegionID] end)       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, [PDI].[ScoaItemID])       ) as [SDC]       outer apply (        select [ScoaCode] from [Const_Scoa_Structure_ByYearID](@FinYear, [PCI].[ScoaItemID])       ) as [SCC]      where ([PD].[PayrollDefinitionGroupID] = [POS].[PayrollDefinitionGroupID] and [PD].[Enabled] = 1 and [POS].[EmployeeTypeID] in(2, 3, 7) and (       ([IRP5].[TransactionTypeID] in(1, 3) and exists(         select [SalaryTransaction_ID] from [Payroll_EmployeeSalaryTransaction] as [PES] with(nolock) where ([PES].[EmployeeId] = [ST].[EmployeeId] and [PES].[SalaryHeadId] = [SH].[SalaryHead_ID])        )       ) or ([IRP5].[TransactionTypeID] = 2)) and ([PDI].[ProjectID] is null or [PCI].[ProjectID] is null))       order by [POS].[Position_ID], [SH].[SalaryHeadTitle]    end  

GO

-- ============================================
-- SP: Payroll_WageTransactionsList
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Ilya Skavronskiy  -- Create date: 2020-09-08  -- Description: To Generate Wage Transactions report on employee for selected dates  -- =============================================    CREATE PROCEDURE [dbo].[Payroll_WageTransactionsList]   @FromDate DATETIME,   @ToDate DATETIME,   @EmployeeID INT,   @DepartmentId INT,   @DivisionId INT   , @CycleID INT   , @ExcessValue FLOAT  AS  BEGIN    SELECT dbo.BufferString_fxn(CONVERT(VARCHAR,(PE.EmployeeID)), 8, '0') as EmployeeID     ,P_E.EmpCode     ,P_E.FirstName     ,P_E.Surname     ,CDEP.DepartmentDesc     ,CDIV.DivisionDesc     ,CC.CycleDesc     ,CPD.ProcessingMonth     ,SH.SalaryHeadTitle     ,WT.Unit     ,WT.Amount     ,CASE       WHEN WT.IsApproved = 1 THEN 'Approved'       WHEN WT.IsApproved = 0 AND        WT.RejectedReason IS NOT NULL THEN 'Rejected'       ELSE 'Awaiting Approval'      END AS [Status]  FROM Payroll_WageTransaction AS WT WITH (NOLOCK)   JOIN Payroll_Employee AS P_E    ON WT.EmployeeId = P_E.Employee_ID   CROSS APPLY (SELECT TOP 1 P_EH.EmployeeID, P_EH.CycleID, P_EH.DepartmentID, P_EH.DivisionID         FROM Payroll_EmployeeHistory as P_EH               WHERE P_E.Employee_ID = P_EH.EmployeeID       AND (@CycleID = 0 OR P_EH.CycleID = @CycleID)         AND (P_EH.StartDate < @ToDate AND P_EH.EndDate >@FromDate)      AND P_EH.Enabled = 1) AS PE             JOIN Payroll_Position AS PP WITH (NOLOCK) ON PP.Position_ID = P_E.PositionID   JOIN Const_Department AS CDEP WITH (NOLOCK) ON PE.DepartmentID = CDEP.Department_ID   JOIN Const_Division AS CDIV WITH (NOLOCK) ON PE.DivisionID = CDIV.Division_ID   JOIN Payroll_CyclePeriodDetails AS CPD WITH (NOLOCK) ON WT.CapturedDuringPeriodId = CPD.Period_ID   JOIN Const_Cycle AS CC WITH (NOLOCK) ON CPD.CycleID = CC.Cycle_ID   JOIN Payroll_SalaryHead AS SH WITH (NOLOCK) ON WT.SalaryHeadId = SH.SalaryHead_ID  WHERE @FromDate <= CPD.PeriodStartDate AND @ToDate >= CPD.PeriodEndDate   AND (ISNULL(@EmployeeID,0) = 0 OR PE.EmployeeID = @EmployeeID)   AND (ISNULL(@DepartmentId,0) = 0 OR CDEP.Department_ID = @DepartmentId)   AND (ISNULL(@DivisionId,0) = 0 OR CDIV.Division_ID = @DivisionId)   AND (ISNULL(@CycleID,0) = 0 OR PE.CycleID = @CycleID )   AND (ISNULL(@ExcessValue,0) = 0 OR WT.Amount > @ExcessValue)   AND WT.Enabled = 1   AND WT.Processed = 1  ORDER BY PE.EmployeeID, CPD.PeriodInTaxYear, CDEP.DepartmentDesc, CDIV.DivisionDesc  END

GO

-- ============================================
-- SP: Payroll_WarningRequestRpt_sp
-- Schema: dbo
-- ============================================
      -- =============================================  -- Author:  MEHUL PANCHAL   -- Create date: 04 DEC 2013  -- Description:   -- CALLS : Payroll_WarningRequestRpt_sp 4  -- 2015-03-24 James Roodt: Added Enabled flag for witnesses  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_WarningRequestRpt_sp] @DisciplinaryID INT  AS       BEGIN   -- Ghanshyam Dhanani (GD) 18 Mar 2014            SELECT  P_E.FirstName + ' ' + P_E.Surname AS Name, P_J.JobTitle, P_E.Employee_ID, chairman, ( STUFF(( SELECT    ', ' + WitnessName                                                                                                                FROM      Payroll_DisciplinaryWitnessDetails b                                                                                                                WHERE     b.DisiplinaryId = P_Dis.Disiplinary_ID AND b.Enabled = 1                                                                                                              FOR                                                                                                                XML PATH('')                                                                                                              ), 1, 2, '') ) AS Witness, C_DOT.DisiplinaryOffenceType, FinalOutcome, CONVERT(NVARCHAR, SanctionDate, 101) AS Sanction, CONVERT(NVARCHAR, PeriodOfEffect, 101) AS PeriodOfEffect, ( STUFF(( SELECT ', ' + DocumentName                                                                                                                                                                                                                                                                                                           FROM   Payroll_DisciplinaryDocumentDetails b                                                                                                                                                                                                                                                                                                           WHERE  b.DisiplinaryId = P_Dis.Disiplinary_ID                                                                                                                                                                                                                                                                                                          FOR                                                                                                                                                                                                                                                                                                           XML PATH('')                                                                                                                                                                                                                                                                                                         ), 1, 2, '') ) AS DocumentName, GETDATE() AS SystemDate, C_ST.SanctionDesc AS Warning, P_Dis.Disiplinary_ID, dbo.BufferString_fxn(CONVERT(VARCHAR, ( Disiplinary_ID )), 8, '0') AS DisiplinaryNo, C_Dep.DepartmentDesc          FROM    Payroll_Disciplinary AS P_Dis                  INNER JOIN Const_DisiplinaryOffenceType AS C_DOT ON C_DOT.DisiplinaryOffenceType_ID = P_Dis.DisciplinaryOffenceTypeID                  INNER JOIN Payroll_Employee AS P_E ON P_E.Employee_ID = P_Dis.EmployeeReceivingID      INNER JOIN Payroll_Position AS PP ON PP.Position_ID = P_E.PositionID                  LEFT OUTER JOIN Payroll_JobProfile AS P_J ON P_J.JobProfile_ID = PP.JobProfileID                  LEFT OUTER JOIN dbo.Const_Department AS C_Dep ON PP.DepartmentID = C_Dep.Department_ID                  INNER JOIN Const_SanctionType AS C_ST ON C_ST.SanctionType_ID = P_Dis.WarningNumber          WHERE   P_Dis.Disiplinary_ID = @DisciplinaryID      END        

GO

-- ============================================
-- SP: Payroll_WeeklyCyclePeriodPopulate_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:Varun Parvataneni  -- Create date: 2016-08-22  -- Description: #43519:Generate Periods For Weekly Payroll run Cycles  -- 2016-10-06 Phuti Chokoe : changed ActivePayrollYear to TaxYear  -- 2019-06-24 Artur Anzorge : changed for adding new cycle with custom date  -- 2020-02-20 Donald Asante: link payroll cycle to payroll tax periods.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_WeeklyCyclePeriodPopulate_sp]    @FromDate DATETIME,   @CapturerID INT,   @CycleId INT  AS  BEGIN   --//Get the Active PayrollYear   DECLARE @PayrollYear NVARCHAR(10),@PayrollYearEndMonth NVARCHAR(10),@PayrollYearStartMonth NVARCHAR(10)   SELECT @PayrollYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'   SELECT  @PayrollYearEndMonth =KeyValue FROM  AAAA_ConfigSettings WHERE keyname ='TaxFinYearEndMonth'   SET @PayrollYearStartMonth =@PayrollYearEndMonth+1   DECLARE @APPROVEDSTATUS NVARCHAR(10) = 'No'   --//Get the @MunicipalityID   DECLARE @MunicipalityID INT   SELECT TOP 1 @MunicipalityID = Municipality_ID FROM dbo.Payroll_Municipality   --//CyclePeriods Temp Table   DECLARE  @CYCLEENTRY TABLE    (     [CapturerID] INT,      [DateCaptured] DATETIME,     [Enabled] BIT,     [Processed] BIT,     [FinancialYear] NVARCHAR(50),     [ProcessingMonth] NVARCHAR(25),     [PeriodStartDate] DATETIME,     [PeriodEndDate] DATETIME,     [PeriodInTaxYear] INT    )       DECLARE @WEEK  NVARCHAR(50),    @STARTDATE DATETIME,    @ENDDATE DATETIME,     @CycleTypeId INT,    @PAYROLLYEARSTARTDATE DATETIME,    @PAYROLLYEARENDDATE DATETIME,    @HasMarchBeenHitOnce BIT =0,    @HasMarchBeenHitTwice BIT =0,    @TaxYearEndDate DATETIME,    @PeriodEndDate DATETIME,    @COUNT INT,    @TaxYearOpen INT,    @YEARENDDATE INT        SET @PAYROLLYEARSTARTDATE = '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)), 0, 5);    SET @PAYROLLYEARENDDATE = '28/FEB/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9);    SET @YEARENDDATE = CAST(SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9) as INT);      IF(@FromDate BETWEEN @PAYROLLYEARSTARTDATE AND @PAYROLLYEARENDDATE)    BEGIN     SET @TaxYearOpen = 1    END     ELSE    BEGIN     SET @TaxYearOpen = 0    END      if(@FromDate >= @PAYROLLYEARSTARTDATE)    BEGIN    SET @PAYROLLYEARSTARTDATE = '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9);    SET @HasMarchBeenHitOnce =1    END         SELECT @CycleTypeId=cc.CycleTypeID FROM Const_Cycle as cc WHERE cc.Cycle_ID=@CycleId    SET @STARTDATE = @FromDate    SET @COUNT =1      IF(@CycleTypeId = 2)--//Weekly    BEGIN      WHILE(@HasMarchBeenHitTwice = 0)      BEGIN        SET @TaxYearEndDate =@ENDDATE --//set to insert TaxYearEndDate into table Payroll_Municipality_CycleDetails                IF DATEADD(DAY,6,@STARTDATE) < @PAYROLLYEARSTARTDATE         SET @ENDDATE = DATEADD(DAY,6,@STARTDATE)        ELSE         SET @ENDDATE = DATEADD(DAY, ABS(DATEDIFF(DAY, @PAYROLLYEARENDDATE, @STARTDATE)), @STARTDATE)          SET @WEEK ='Week'      IF(@PAYROLLYEARSTARTDATE BETWEEN @STARTDATE AND @ENDDATE)      BEGIN       IF(@HasMarchBeenHitOnce =0)       BEGIN        SET @HasMarchBeenHitOnce =1        SET @PAYROLLYEARSTARTDATE = '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9);       END       ELSE       BEGIN        SET @HasMarchBeenHitTwice =1       END      END      IF(@HasMarchBeenHitTwice =0)      BEGIN       INSERT INTO @CYCLEENTRY        SELECT @CapturerID,GETDATE(),1,0,@PayrollYear,* FROM((SELECT  @WEEK + CONVERT(VARCHAR,@COUNT) AS CurrentMonth,        @STARTDATE AS StartingDate, @ENDDATE AS EndDate,@COUNT as TaxYear)) AS TEMP       SET @STARTDATE = DATEADD(DAY,1,@ENDDATE)       IF(@COUNT=1)       BEGIN        SET @PeriodEndDate=@ENDDATE--//set to insert PeriodEndDate into table Payroll_Municipality_CycleDetails       END      END      SET @COUNT =@COUNT+1     END    END     ELSE IF(@CycleTypeId = 3)--//Bi-Weekly    BEGIN      WHILE(@HasMarchBeenHitTwice = 0)      BEGIN       SET @TaxYearEndDate =@ENDDATE--//set to insert TaxYearEndDate into table Payroll_Municipality_CycleDetails              IF DATEADD(DAY,13,@STARTDATE) < @PAYROLLYEARSTARTDATE        SET @ENDDATE = DATEADD(DAY,13,@STARTDATE)       ELSE        SET @ENDDATE = DATEADD(DAY, ABS(DATEDIFF(DAY, @PAYROLLYEARENDDATE, @STARTDATE)), @STARTDATE)         SET @WEEK ='Bi-Week'       IF(@PAYROLLYEARSTARTDATE BETWEEN @STARTDATE AND @ENDDATE)       BEGIN        IF(@HasMarchBeenHitOnce =0)        BEGIN         SET @HasMarchBeenHitOnce =1         SET @PAYROLLYEARSTARTDATE = '01/MAR/'+ SUBSTRING(CAST(@PayrollYear AS NVARCHAR(10)),6, 9);        END        ELSE        BEGIN         SET @HasMarchBeenHitTwice =1        END       END       IF(@HasMarchBeenHitTwice =0)       BEGIN        INSERT INTO @CYCLEENTRY         SELECT @CapturerID,GETDATE(),1,0,@PayrollYear,* FROM((SELECT  @WEEK + CONVERT(VARCHAR,@COUNT) AS CurrentMonth,         @STARTDATE AS StartingDate, @ENDDATE AS EndDate,@COUNT as TaxYear)) AS TEMP        SET @STARTDATE = DATEADD(DAY,1,@ENDDATE)        IF(@COUNT=1)        BEGIN         SET @PeriodEndDate=@ENDDATE--//set to insert PeriodEndDate into table Payroll_Municipality_CycleDetails        END       END      SET @COUNT =@COUNT+1      END    END      IF NOT EXISTS (SELECT CycleDetail_ID FROM Payroll_Municipality_CycleDetails  WHERE TaxYear = @PayrollYear and CycleID = @CycleID)    BEGIN     INSERT INTO dbo.Payroll_Municipality_CycleDetails      (        MunicipalityID , CycleID , FinancialYear , TaxYearStartDate , TaxYearEndDate ,       PeriodEndDate , [Enabled] , DateCaptured , CapturerID, TaxYear      )     VALUES        (        @MunicipalityID, @CycleId, @PayrollYear, @FromDate, @TaxYearEndDate, @PeriodEndDate, 1, GETDATE(), @CapturerID, @PayrollYear      )    END     IF NOT EXISTS (SELECT Period_ID FROM Payroll_CyclePeriodDetails  WHERE TaxYear = @PayrollYear AND CycleID = @CycleId)   BEGIN    INSERT INTO Payroll_CyclePeriodDetails (PeriodInTaxYear, ProcessingMonth, PeriodStartDate, PeriodEndDate, Processed ,              MunicipalityID , FinancialYear , Enabled , DateCaptured ,              CapturerID , CycleID, CycleModeID,ApprovedStatus, TaxYear)    SELECT [PeriodInTaxYear], [ProcessingMonth], [PeriodStartDate] ,[PeriodEndDate], [Processed], @MunicipalityID,      [FinancialYear], [Enabled], [DateCaptured], [CapturerID], @CycleId, 1,@APPROVEDSTATUS, [FinancialYear] FROM @CYCLEENTRY   END     IF NOT EXISTS (SELECT TaxPeriodID from dbo.Const_Payroll_TaxPeriods where cycleID = @CycleID)   BEGIN    INSERT INTO dbo.Const_Payroll_TaxPeriods    (     TaxYear,StartDate,EndDate,cycleID,Enable,DateCaptured,CapturerID,DateModified,ModifierID,FinalRunDate,TaxYearOpen    )    VALUES    (     @YEARENDDATE,@FromDate,@TaxYearEndDate,@CycleID,1,GETDATE(),@CapturerID,null,null,null,@TaxYearOpen    )   END   END

GO

-- ============================================
-- SP: Payroll_WritePaymentInstructions
-- Schema: dbo
-- ============================================
/*   Author  : FERDI BOTHA   Create date : 08/06/2018   Description : Write Nett Salaries from Payroll_TransactionsCashbook to Payroll_PaymentInstructions for the EFT process     exec [Payroll_WritePaymentInstructions] 3, '2016/2017', 1, 1, 1        ================================     Update Date : 17/05/2019 => Corrected the Processing Month to use the SCOA Financial Month      Modiri   2019/10/23   23842 Jogeda - Error Approval Payment Instruction        25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings   2022/03/08 Richa M Fix PaymentInstruction for Positional Split (WI 83997)  */  CREATE PROCEDURE [dbo].[Payroll_WritePaymentInstructions]      @PeriodID INT,      @TaxYear NVARCHAR(15),      @UserID INT,      @Month INT,      @TransactionID NVARCHAR(30)  AS    begin      set nocount on;      begin try      declare @transactions table (       [ID] int identity(1, 1) not null,     [TransactionCashbook_ID] int not null,     [EmployeeID] int not null,     [Amount] decimal(18, 2) not null,     [PeriodID] int not null,     [ProcessedLP] int not null default(0)      )                declare @i int = 1,      @c int,      @SCOAYear varchar(500) = (select [KeyValue] from [AAAA_ConfigSettings] where ([KeyName] = 'ActiveFinYear')),      @SCOAMonth int = dbo.[GetProcessingMonthByUserID_fxn](@UserID), -- UserProcessingMonth      @EFTBatchID int = 0,      @ChequeBatchID int = 0,      @EFTCashbookTransactionTypeID int = (select [TransactionType_ID] from [Const_CashbookTransactionType] with(nolock) where ([TransactionDesc] = 'Exp - Nett Salaries EFT' and [Enabled] = 1)),      @ChequeCashbookTransactionTypeID int = (select [TransactionType_ID] from [Const_CashbookTransactionType] with(nolock) where ([TransactionDesc] = 'Exp - Nett Salaries Cheque' and [Enabled] = 1)),      @TransactionTypeID int,      @CashbookID int,      @DocTypeCode int = (select [DocumentType_ID] from [Const_DocumentType] with(nolock) where ([DocumentTypeDesc] = 'Nett Salaries' and [Enabled] = 1)),      @SalarySuspenseScoaItemID int,      @SuspenseVoteID int,      @ModuleID int = (select [Module_ID] from [User_Module] where ([ModuleDesc] = 'Payroll')),      @IsImmediate bit = 1,      @MunicipalityDepositeReference nvarchar(20) = 'Nett Salaries',      @CycleID int,      @CycleModeID int,      @PaymentDueDate datetime = (select [PaymentDueDate] from [Payroll_TrailRun_History] where ([PeriodID] = @PeriodID)),      @ItemDescriptionPTCB nvarchar(20) = 'Total Net Payment',      @EmployeeID int = 0,      @Value decimal(18, 2) = 0,      @TransactionCashbookId int = 0      select @CycleID = [CycleID], @CycleModeID = [CycleModeID] from [Payroll_CyclePeriodDetails] where ([Period_ID] = @PeriodID)            select @CashbookID = [CashBookID], @SalarySuspenseScoaItemID = [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock) where ([Enabled] = 1)      select top 1 @SuspenseVoteID = [Vote_ID] from [Led_Vote] with(nolock) where ([SCOAItemID] = @SalarySuspenseScoaItemID and [FinYear] = @SCOAYear and [VoteStatusID] = 1)      if (@CycleModeID = 1)       set @IsImmediate = 0      insert into @transactions([TransactionCashbook_ID], [EmployeeID], [Amount], [PeriodID])       select min([TransactionCashbook_ID]), [EmployeeId], sum([TotalNetAmount]), @PeriodID        from [Payroll_TransactionsCashbook] with(nolock)        where ([PeriodID] = @PeriodID)         group by [EmployeeId]      /* POPULATE Payment_Instructions */    select @c = count([ID]) from @transactions      while (@i <= @c)    begin       select @EmployeeID = [EmployeeID], @Value = [Amount],@TransactionCashbookId = TransactionCashbook_ID from @transactions where ([ID] = @i)       if (not exists(select [ID] from @transactions where ([EmployeeID] = @EmployeeID and [ProcessedLP] = -1)))     begin        select @TransactionTypeID = [PaymentTypeID] from [Payroll_Employee] with(nolock) where ([Employee_ID] = @EmployeeID)        if (@TransactionTypeID in(1, 3) and @EFTBatchID = 0)      begin         insert into [Payroll_PaymentBatches]([PayrollStatus], [LedgerPaymentStatus], [BatchType], [Payroll_CycleID], [NumberOfEmployees], [NumberOfTransactions], [InvoiceTotalAmount], [ProcessedDate], [DateCaptured], [CapturerID], [PaymentDueDate])          values('New','New', 'Nett Salary EFT Payment', @CycleID, 0, 0, 0, getdate(), getdate(), @UserID, @PaymentDueDate)         set @EFTBatchID = scope_identity()        end      else if (@TransactionTypeID = 2 and @ChequeBatchID = 0)      begin         insert into [Payroll_PaymentBatches]([PayrollStatus], [LedgerPaymentStatus], [BatchType], [Payroll_CycleID], [NumberOfEmployees], [NumberOfTransactions], [InvoiceTotalAmount], [ProcessedDate], [DateCaptured], [CapturerID], [PaymentDueDate])          values('New','New', 'Nett Salary Cheque Payment', @CycleID, 0, 0, 0, getdate(), getdate(), @UserID, @PaymentDueDate)         set @ChequeBatchID = scope_identity()        end        insert into [Payroll_PaymentInstructions]([TaxYear], [ProcessingMonth], [TransactionID], [TransactionDate], [CashbookID], [DocTypeCode], [TransactionTypeID], [EmployeeID],         [EmployeeName], [EmployeeBankName], [EmployeeBankAccountNumber], [EmployeeBankAccountType], [EmployeeBankBranchCode], [ModuleId],         [InvoiceTotalAmount], [CapturerID], [DateCaptured], [IsAuthorised], [IsImmediatePayment],         [PaymentDueDate], [MunicipalityDepositeReference], [PeriodID], [BatchID],[DocNumber])         select distinct @TaxYear, @SCOAMonth, @TransactionID, [PTCB].[TransactionDate], @CashbookID, @DocTypeCode, (case           when @TransactionTypeID in(1, 3) then @EFTCashbookTransactionTypeID -- SET CASH TO DEFAULT TO EFT           when @TransactionTypeID = 2 then @ChequeCashbookTransactionTypeID          end), [PE].[Employee_ID], [AccountHolderName], [BankDesc], [AccountNumber], [BankAccountTypeCode],[BankBranchCode], @ModuleID,                  @Value, @UserID, getdate(), 1, @IsImmediate,          @PaymentDuedate, @MunicipalityDepositeReference, @PeriodID, (case           when @TransactionTypeID in(1, 3) then @EFTBatchID -- SET CASH TO DEFAULT TO EFT           when @TransactionTypeID = 2 then @ChequeBatchID          end),@TransactionCashbookId          from ( select TransactionDate,SUM(TotalEarningAmount)TotalEarningAmount,Sum(TotalDeductionAmount)TotalDeductionAmount ,SUM(TotalNetAmount)TotalNetAmount,PeriodId,EmployeeId from [Payroll_TransactionsCashbook] where [EmployeeId] = @EmployeeID and [PeriodID] = @PeriodID           group by TransactionDate,PeriodId,EmployeeId        ) as [PTCB]            join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PTCB].[EmployeeId]           left join [Const_Bank] as [CB] with(nolock) on [CB].[Bank_ID] = [PE].[BankID]           left join [Const_BankBranchCode] as [CBBC] with(nolock) on [CBBC].[BankBranchCode_ID] = [PE].[BranchID]           left join [Const_BankAccountType] as [BT] with(nolock) on [PE].[AccountTypeID] = [BT].[BankAccountTypeId]          where ([PTCB].[EmployeeId] = @EmployeeID and [PTCB].[PeriodID] = @PeriodID)        update @transactions set [ProcessedLP] = -1 where ([EmployeeID] = @EmployeeID)       end       set @i = @i + 1      end      /* POPULATE Payment_InstructionDetails */    insert into [Payroll_PaymentInstructionDetails]([PaymentInstructions_ID], [EmployeeID], [VoteID], [VoteAmount], [VoteVATIndicator], [VoteVATAmount], [VoteVATClaimable], [DateCaptured], [CapturerID],       [ItemDescription], [SCOACostingID], [SCOAFunctionID], [SCOAFundsID], [SCOAItemID], [SCOAProjectID], [SCOARegionID],[DivisionId])       select distinct [PaymentInstructions_ID], [PE].[Employee_ID], @SuspenseVoteID, isnull([PTCB].[TotalNetAmount], 0), 0, 0, 0, getdate(), @UserID,        @ItemDescriptionPTCB, [PTCB].[SCOACostingID], [PTCB].[SCOAFunctionID], [PTCB].[SCOAFundsID], [PTCB].[SCOAItemID], [PTCB].[SCOAProjectID], [PTCB].[SCOARegionID],[PTCB].[DivisionID]        from [Payroll_TransactionsCashbook] as [PTCB] with(nolock)                   join [Payroll_Employee] as [PE] with(nolock) on [PE].[Employee_ID] = [PTCB].[EmployeeId]               join [Payroll_PaymentInstructions] as [LP] with(nolock) on [LP].[EmployeeID] = [PTCB].[EmployeeId] and [LP].[PeriodID] = [PTCB].[PeriodID]        where ([PTCB].[PeriodID] = @PeriodID and [PTCB].[EmployeeId] in(          select distinct [EmployeeID] from @transactions         )        )      /* Update Payroll_PaymentBatches */    update [UPB] set [InvoiceTotalAmount] = (        select sum([PPI].[InvoiceTotalAmount])         from [Payroll_PaymentInstructions] as [PPI] with(nolock)          join [Payroll_PaymentBatches] as [PB] with(nolock) on [PB].[Batch_ID] = [PPI].[BatchID]          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [PPI].[PeriodID]         where ([PPI].[BatchID] = [UPB].[Batch_ID])       ), [NumberOfEmployees] = (        select count([PPI].[PaymentInstructions_ID])         from [Payroll_PaymentInstructions] as [PPI] with(nolock)          join [Payroll_PaymentBatches] as [PB] with(nolock) on [PB].[Batch_ID] = [PPI].[BatchID]          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [PPI].[PeriodID]         where ([PPI].[BatchID] = [UPB].[Batch_ID])       ), [NumberOfTransactions] = (        select count([PPI].[PaymentInstructions_ID])         from [Payroll_PaymentInstructions] as [PPI] with(nolock)          join [Payroll_PaymentBatches] as [PB] with(nolock) on [PB].[Batch_ID] = [PPI].[BatchID]          join [Payroll_CyclePeriodDetails] as [CPD] with(nolock) on [CPD].[Period_ID] = [PPI].[PeriodID]         where ([PPI].[BatchID] = [UPB].[Batch_ID])       ), [PaymentDueDate] = @PaymentDueDate       from [Payroll_PaymentBatches] as [UPB]        where ([Batch_ID] in(@EFTBatchID, @ChequeBatchID))     select cast(1 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(null as tinyint) as [ErrorGroup], cast(null as nvarchar(max)) as [ErrorMessage], cast(null as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast(null as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]    end try        begin catch     select cast(0 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(1 as tinyint) as [ErrorGroup], cast(error_message() as nvarchar(max)) as [ErrorMessage], cast(error_procedure() as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast('Global' as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]    end catch    set nocount off;    end

GO

-- ============================================
-- SP: Payroll_WriteSCMInvoices
-- Schema: dbo
-- ============================================
/*   Author  : Richa Mills   Create date : 2023/11/17   Description : Cursor to create outstanding SCM Invoices  */  CREATE PROCEDURE [dbo].[Payroll_WriteSCMInvoices]        as  begin         Delete from Payroll_SCMInvoiceSummary where status = 'Completed'  Delete from Payroll_MissingStrings where DocumentType = 132    DECLARE @VendorId int  DECLARE @PeriodId int  DECLARE @SalaryHeadIds nvarchar(2000)  DECLARE @ConsolidatedEFT bit    DECLARE db_cursor CURSOR FOR    SELECT VendorId,PeriodId,SalaryheadIds,ConsolidatedEFT FROM Payroll_SCMInvoiceSummary where Status = 'Pending'    -- Open the Cursor  OPEN db_cursor    FETCH NEXT FROM db_cursor INTO @VendorId,@PeriodId ,@SalaryHeadIds,@ConsolidatedEFT    WHILE @@FETCH_STATUS = 0       BEGIN         Exec Payroll_CreateSCMInvoices @PeriodID,1,@VendorId,@SalaryHeadIds,@ConsolidatedEFT       FETCH NEXT FROM db_cursor INTO @vendorId,@PeriodId,@SalaryHeadIds,@ConsolidatedEFT  END       CLOSE db_cursor      DEALLOCATE db_cursor           end

GO

-- ============================================
-- SP: Payroll_WriteSCMInvoicestest
-- Schema: dbo
-- ============================================
           /*   Author  : Richa Mills   Create date : 2018/02/08   Description : Write SCM Invoice   EXEC Payroll_WriteSCMInvoices 89, '2019/2020',1   Updated  : 15/05/2019 => Updated Project ID => Scoa Project ID Mappings for Commission Project (Ferdi Botha)   Updated  : 28/05/2019 => Updated the SCOA ID linkaged for VAT to read from [Led_VatTransactionTypeSetup] (Ferdi Botha)   Updated  : 25/07/2019 => Updated the SCM Invoice Detail VAT Amount to write 0 for the invoice details (as per discussion with Heidi, Jean and Richa) (Ferdi Botha)   Updated  : 05/08/2019 => Updated the SCM Invoice Detail VAT Amount (Ferdi Botha)      25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings   Updated  : 2022/04/26 Richa M - Change SP to create invoices per supplier to avoid timeout errors.   Updated  : 2022/07/05 Richa M - Fix rounding issues with Commission     exec Payroll_WriteSCMInvoices 301,'2023/2024',1,157,0  */  CREATE PROCEDURE [dbo].[Payroll_WriteSCMInvoicesTest]   @PeriodID int,   @TaxYear  nvarchar(50),    @UserId int,   @VendorId int,   @TrxCount int,   @LedgerMonth int       as  begin     begin try       set nocount on;    IF OBJECT_ID('tempdb..#projectItems') IS NOT NULL      DROP TABLE #projectItems     Select PlanProjectItem_Id,ProjectId,ScoaItemId,Finyear,ScoaFundId,ScoaFunctionId,ScoaRegionId,DivisionId,ScoaCostingId into #projectItems from Plan_ProjectItem where finyear = '2023/2024' and PlanProjectItem_ID in(         Select min(PlanProjectItem_Id)PlanProjectItem_Id from Plan_ProjectItem          group by ProjectId,DivisionId,ScoaItemId,ScoaFunctionId,ScoaRegionId,FinYear)    CREATE INDEX IDX_ProjectItems ON #projectItems(ScoaItemId,ProjectId,DivisionId,ScoaRegionId,ScoaFunctionId)    DECLARE @CommPercentage decimal(18,2), @VatRegistered bit,  @HasPayrollCommission bit,  @PaymentReference varchar(500),@DocCount int, @DocNumber varchar(10)    select @CommPercentage = CommissionPercentage,    @VatRegistered = VatRegistered,    @HasPayrollCommission = bPayrollCommission   from Cons_Vendor   where Vendor_ID = @VendorId    select @PaymentReference = Paymentreference from Cons_VendorBankingDetails where VendorID = @VendorId    select @DocCount = (select  MAX(CAST(right(DocNumber,Len(DocNumber) - 4) AS int)) from Payroll_TransactionsGroup where DocNumber like '132/%' )    if(@DocCount IS NULL)   select @DocCount = 1    Set @DocCount = @DocCount + 1    SELECT @DocNumber = '132/' + CAST(@DocCount AS varchar(5))    declare @ActiveFinYear nvarchar(50)       select @ActiveFinYear  =  KeyValue from [dbo].[AAAA_ConfigSettings] with(nolock) where KeyName  = 'ActiveFinYear'  declare @COUNT int  declare @START int = 1    DECLARE @TrialResults table  (   TrialResultId int,   SalaryHeadId int,   VendorId int,   EmployeeId int,   TransactionTypeId int,   Amount decimal(18,2),   SalaryTitle nvarchar(256),   ContraSCOAFundingID int,   ContraSCOACostingID int,   ContraScoaFunctionId int,   ContraScoaItemID int,   ContraScoaProjectId int,   ContraScoaRegionId int,   ContraPlanProjectItemId int,   PlanProjectItemId int,   DivisionId int,   CommAmount decimal(18,2),   VatAmount decimal(18,2),   RoundingTrans bit     )    insert into @TrialResults   select PayrollResult_ID, SalaryHeadID,VendorID,EmployeeID,TransactionTypeID,Amount,SalaryTitle,ContraSCOAFundingID,ContraSCOACostingID,ContraScoaFunctionId,   ContraScoaItemID,ContraScoaProjectId,ContraScoaRegionId,ContraPlanProjectItemID, PlanProjectItemId,DivisionId,Amount,0,0   from Payroll_PayrollResults where periodid = @PeriodID and TaxSavePurpose = 0 and VendorId = @VendorId and TransactionTypeID IN (2,3)     DECLARE @CommisionEarnedScoaItem int,@CommProjectId int, @CommisionDivId int, @CommFunctionId int, @CommRegionId int     DECLARE @VATProjectItemId int = (select top 1 [PlanProjectItemID] from [Led_VatTransactionTypeSetup] where ([VatTransactionTypeID] = 22 and [FinYear] = @ActiveFinYear))     select @CommisionEarnedScoaItem = CommissionScoaItemID, @CommProjectId = CommissionProjectID,@CommisionDivId = CommDivisionId,@CommRegionId = CommRegionId, @CommFunctionId = CommFunctionId from Payroll_Municipality     DECLARE @VATRate decimal(18,6)   DECLARE @VatIndicator int     select @VatIndicator = VatIndicatorID    from led_vote    where ScoaItemId =     (select CommissionScoaItemID from payroll_municipality)    and Finyear = @ActiveFinYear     If IsNULL(@VatIndicator,0) in (0,1)   BEGIN    SET @VatIndicator = 6   END   If IsNULL(@VatIndicator,0) = 2   BEGIN    SET @VatIndicator = 5   END   SELECT @VatRate = (Select TOP 1 VATPercent from const_vatrate where VatIndicatorID = @VatIndicator and GetDate() >= EffectiveDate order by EffectiveDate desc)    if @CommPercentage > 0  begin   DECLARE @TotalComm decimal(18,2) = (Select SUM(Amount) * @CommPercentage/100 from @TrialResults)   DECLARE @RoundingDiff decimal(18,2)   Update @TrialResults set CommAmount = Amount * @CommPercentage/100     Select @RoundingDiff = (Select @TotalComm - SUM(CommAmount) from @TrialResults)     Update @TrialResults set VatAmount = CommAmount - (CommAmount / (1 + (@VATRate / cast(100 as decimal(18, 6)))))     if @RoundingDiff <> 0   BEGIN    Declare @RoundingTransactionId int = (select top 1 TrialResultId from @TrialResults where CommAmount > ABS(@RoundingDiff))    update @TrialResults set CommAmount = CommAmount + @RoundingDiff,RoundingTrans = 1 where TrialResultId = @RoundingTransactionId    Update @TrialResults set VatAmount = CommAmount - (CommAmount / (1 + (@VATRate / cast(100 as decimal(18, 6))))) where TrialResultId = @RoundingTransactionId     END  end       insert into Payroll_TransactionsGroup   select     GetDate(),    gl.VendorScoaId,   --VendorId (Cr)    0,       --Credit    CASE     WHEN @HasPayrollCommission = 1 THEN SUM(Amount) - SUM(CommAmount)     ELSE SUM(Amount)    END,      --Debit    @PeriodId,     --PeriodId    132,      --DocumentTypeId    piDt.SCOAFundId,   --dt    piDt.SCOARegionId,   --dt    piDt.ScoaCostingID,   --dt    dtProject.ScoaProjectID, --dt    piDt.SCOAFunctionId,  --dt    piDt.SCOAItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,NULL      --Moidier    ,@DocNumber     --DocNumber    ,tr.SalaryHeadID   --SalaryHeadId    ,tr.VendorID    --VendorId    ,sh.SalaryHeadName   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,pos.DivisionID    --DivisionId    ,ctProject.ScoaProjectID --CreditScoaProjectId    ,gl.VendorScoaId   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,piCt.SCOAFunctionId  --CreditFunctionId    ,piCt.SCOAFundId   --CreditFund    ,piCt.SCOARegionId   --CreditRegion    ,piDt.ProjectID    --ProjectId Dt    ,piDt.PlanProjectItem_ID --PlanProjectItemId Dt    ,piCt.ProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct    from     (select * from @TrialResults)tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     join #projectItems piDt       on piDt.ScoaItemId =  isnull(empType.SalarySuspenseScoaItemId, gl.SuspenseScoaItemID) and piDT.ProjectId =  Isnull(empType.SalaryProjectID, gl.SCOAProjectID) and piDT.SCOARegionId = pos.RegionID and piDT.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID         join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID     join #projectItems piCt       on piCt.SCOAItemID = gl.VendorScoaId and piCt.ProjectId = gl.VendorScoaProjectId and piCt.SCOARegionId = pos.RegionID and piCt.SCOAFunctionId = pos.FunctionID and piCt.DivisionId = pos.DivisionID      join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID  group by     gl.VendorScoaId,    piDt.SCOAFundId,    piDt.SCOARegionId,     piDt.ScoaCostingID,     dtProject.ScoaProjectID,     piDt.SCOAFunctionId,     piDt.SCOAItemID,     tr.SalaryHeadID,         tr.VendorID,        sh.SalaryHeadName,         pos.DivisionID,         ctProject.ScoaProjectID,        gl.VendorScoaId,         piCt.SCOACostingID,        piCt.SCOAFunctionId,        piCt.SCOAFundId,         piCt.SCOARegionId,          piDt.ProjectID,         piDt.PlanProjectItem_ID,    piCt.ProjectID,         piCt.PlanProjectItem_ID       if @CommPercentage > 0   BEGIN  --Cr COMM Control Account   --Dt Creditor Control     insert into Payroll_TransactionsGroup  select     GetDate(),    piCt.SCOAItemID,   --VendorId (Cr)    0,    CommAmount - VatAmount,     @PeriodId,     --PeriodId    132,      --DocumentTypeId    dt.SCOAFundId,   --dt    dt.SCOARegionId,   --dt    dt.ScoaCostingID,   --dt    dt.ScoaProjectID,   --dt    dt.SCOAFunctionId,  --dt    dt.SuspenseScoaItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,NULL      --Moidier    ,@DocNumber     --DocNumber    ,0       --SalaryHeadId    ,@VendorId     --VendorId    ,'Commision Earned'   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,piCt.DivisionID   --DivisionId    ,ctpp.ScoaProjectID          --CreditScoaProjectId    ,piCt.SCOAItemID   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,piCt.SCOAFunctionId  --CreditFunctionId    ,piCt.SCOAFundId   --CreditFund    ,piCt.SCOARegionId   --CreditRegion    ,dt.ProjectID    --ProjectId Dt    ,dt.PlanProjectItem_ID     --PlanProjectItemId Dt    ,piCt.ProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct     from    (select piDt.PlanProjectItem_Id,     SUM(tr.Amount)Amount,    SUM(Round(CommAmount,2)) CommAmount,    SUM(Round(VatAmount,2)) VatAmount,    piDt.SCOACostingID        ,piDt.SCOAFunctionId      ,piDt.SCOAFundId          ,piDt.SCOARegionId        ,piDt.ProjectId          ,gl.SuspenseScoaItemID,    pp.ScoaProjectID,    piDt.DivisionId,SalarySuspenseScoaItemCreditId,SalaryProjectid    from(     select * from @TrialResults      )tr    join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1    join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID    join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id     join Payroll_Position pos       on pos.Position_ID = emp.PositionID    join #projectItems piDt       on piDt.SCOAItemID = Isnull(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID)         and piDt.ProjectId = Isnull(empType.SalaryProjectId,gl.SCOAProjectID) and piDt.SCOARegionId = pos.RegionID and piDt.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID     join plan_project pp      on pp.Project_id = piDt.ProjectID    group by PlanProjectItem_Id,piDt.SCOACostingID        ,piDt.SCOAFunctionId      ,piDt.PlanProjectItem_Id,gl.SuspenseScoaItemID,pp.ScoaProjectID,piDt.DivisionId    ,piDt.SCOAFundId          ,piDt.SCOARegionId        ,piDt.ProjectId,SalarySuspenseScoaItemCreditId,SalaryProjectid )dt        join #projectItems piCt      on piCt.SCOAItemID =  @CommisionEarnedScoaItem       and  piCt.ProjectId =  @CommProjectId           and piCt.SCOARegionId = @CommRegionId and piCt.SCOAFunctionId = @CommFunctionId and piCt.DivisionId = @CommisionDivId    join plan_project ctpp      on ctpp.Project_id = piCt.ProjectID       --Cr VAT Control Account   --Dt Creditor Control  insert into Payroll_TransactionsGroup  select     GetDate(),    piCt.SCOAItemID,   --VendorId (Cr)    0,     VatAmount,    @PeriodId,     --PeriodId    132,      --DocumentTypeId    dt.SCOAFundId,   --dt    dt.SCOARegionId,   --dt    dt.ScoaCostingID,   --dt    dt.ScoaProjectID,   --dt    dt.SCOAFunctionId,  --dt    dt.SuspenseScoaItemID,   --dt    1,       --enabled    GETDATE(),     --CaptureDate    @UserId      --UserId    ,NULL      --DateModified    ,NULL      --Moidier    ,@DocNumber     --DocNumber    ,0       --SalaryHeadId    ,@VendorId     --VendorId    ,'Commision Earned VAT'   --SalaryHeadName    ,NEWID()     --MatchGuid    ,NULL      --FlagToSetTranGroup    ,piCt.DivisionID   --DivisionId    ,ctpp.ScoaProjectID          --CreditScoaProjectId    ,piCt.SCOAItemID   --CreditVendorScoaId    ,piCt.SCOACostingID   --CreditCostingId    ,piCt.SCOAFunctionId  --CreditFunctionId    ,piCt.SCOAFundId   --CreditFund    ,piCt.SCOARegionId   --CreditRegion    ,dt.ProjectID    --ProjectId Dt    ,dt.PlanProjectItem_ID     --PlanProjectItemId Dt    ,piCt.ProjectId    --ProjectId Ct    ,piCt.PlanProjectItem_Id --PlanProjectItemId Ct     from    (select piDt.PlanProjectItem_Id,     SUM(tr.Amount)Amount,    SUM(tr.CommAmount) CommAmount,    SUM(tr.VatAmount) vatAmount,    piDt.SCOACostingID        ,piDt.SCOAFunctionId      ,piDt.SCOAFundId          ,piDt.SCOARegionId        ,piDt.ProjectId          ,gl.SuspenseScoaItemID,pp.ScoaProjectID,piDt.DivisionId     from(     select * from @TrialResults     )tr    join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1    join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID    join const_EmployeeType_sys empType      on emp.EmployeetypeId = empType.EmployeeType_id    join Payroll_Position pos       on pos.Position_ID = emp.PositionID    join #projectItems piDt       on piDt.SCOAItemID = IsNULL(empType.SalarySuspenseScoaItemId,gl.SuspenseScoaItemID)       and piDt.ProjectId = IsNULL(empType.SalaryProjectID, gl.SCOAProjectID) and piDt.SCOARegionId = pos.RegionID and piDt.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID     join plan_project pp      on pp.Project_id = piDt.ProjectID    group by PlanProjectItem_Id,piDt.SCOACostingID        ,piDt.SCOAFunctionId      ,piDt.PlanProjectItem_Id,gl.SuspenseScoaItemID,pp.ScoaProjectID,piDt.DivisionId    ,piDt.SCOAFundId          ,piDt.SCOARegionId        ,piDt.ProjectId )dt        join #projectItems piCt      on piCt.PlanProjectItem_ID = @VATProjectItemId    join plan_project ctpp      on ctpp.Project_id = piCt.ProjectID    END    declare @StatusID int = (select Status_ID from Const_SCMVendorStatus_sys where Enabled = 1 and (Module = 'SCMInvoice' or Module = 'Invoice') and Status = ( select top 1 'Level' + Cast(ApprovalLevel as nvarchar(10)) from SCM_InvoiceApprovalSetup where IsEnabled = 1 and IsApproval = 1 order by ApprovalLevel desc))  declare @UserProcessingMonth INT = @LedgerMonth  declare @VoteSectionID int = (Select VoteSection_ID from dbo.Const_VoteSection_Sys with(nolock) where VoteSectionDesc = 'Payroll')  declare @CashbookId int = (Select CashBookID from Payroll_Municipality)  declare @RecordID int        --***************************************************Create Invoice Header ***************************************************  insert into dbo.SCM_Invoice       ( InvoiceDate,     StatusID,     FinancialYear,     ProcessingMonth,    VoteSectionID,     VendorCreditorID,     PayrollPeriodID,     Enabled,     DateCaptured,     CapturerID,     ApprovedBy,     ApprovedDate ,     DocNumber,     Comments,     VendorInvoiceNumberCustom,    PaymentReference,    CashbookId,    FinalApprovedBy,    FinalApprovedDate)    SELECT GetDate(),@StatusId,@ActiveFinYear,@UserProcessingMonth, @VoteSectionId,@VendorId, @PeriodId,1,Getdate(),@UserId,@UserId,Getdate(),@DocNumber,'',@DocNumber,@PaymentReference,@CashbookId,@UserId,GetDAte()    select  @RecordID = @@Identity    EXEC SCM_GenerateInvoiceNumber_sp @RecordID  --Get Invoice No.    --***************************************************Create Invoice Detail ***************************************************  --NB - I'm adding the ScoaFundId in the cancelReason field in order to update the InvoiceDetailsFund table  insert into dbo.SCM_InvoiceDetail    (QuantityOrder, QuantityReceived, InvoiceID, ItemDescription, UnitPrice, ReceivedUnitPrice, Amount, VatInclude, VatAmount, TotalAmount, VoteId,Enabled,DateCaptured,     CapturerID, StatusID, CancelReason, EmployeeID, SCOACostingID, SCOAFunctionID, SCOAItemID, SCOAProjectID, SCOARegionID, ApprovedBy, ApprovedDate, PlanProjectItemId, DivisionId)     select 1,1,@RecordId,SalaryTitle,Amount,Amount,Amount,0,0,Amount,Vote_ID,1,Getdate(),@UserID,@StatusId,CAST(ContraScoaFundingId AS varchar(10)),NULL,ContraScoaCostingId,     ContraScoaFunctionId,ContraScoaItemID,ContraScoaProjectId,ContraScoaRegionId,@UserID,GetDate(),PlanProjectItemId,DivisionId      from (select SalaryHeadId,   CASE     WHEN @HasPayrollCommission = 1 AND @CommPercentage > 0 THEN SUM(Amount)-SUM(CommAmount)    ELSE SUM(Amount)   END AS Amount,   SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId       from @TrialResults      group by SalaryHeadId, SalaryTitle,ContraScoaProjectId,ContraScoaItemId,ContraScoaCostingId,ContraScoaFunctionId,ContraScoaFundingId,ContraScoaRegionId,ContraPlanProjectItemID,DivisionId,PlanProjectItemId)PayrollResults        left outer join Led_Vote lv     on lv.ScoaItemID = PayrollResults.ContraSCoaItemId AND FinYear = @ActiveFinYear   --***************************************************Create SCM_VendorInvoiceHistory *****************************************  insert into SCM_VendorInvoiceHistory   (VendorId,InvoiceId,InvoiceNumber,InvoiceDate,InvoiceTotalAmount,OutstandingInvoiceAmount,PaymentStatus,CaptureId,CaptureDate,VatAmount)    select VendorCreditorID, Invoice_ID, VendorInvoiceNumber, InvoiceDate, (select SUM(TotalAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID),(select SUM(TotalAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID), @StatusId,    @UserId, GETDATE(), (select SUM(VatAmount) from SCM_InvoiceDetail where InvoiceID = Invoice_ID)    from SCM_Invoice where Invoice_ID = @RecordId    --***************************************************Create SCM_InvoiceDetailsFund ****************************************  insert  into dbo.SCM_InvoiceDetailsFund    ( InvoiceDetailID, SCOAFundID, Percentage, CapturerID, DateCaptured )    select InvoiceDetail_ID, CAST(CancelReason AS int),100,@UserId,Getdate() from SCM_InvoiceDetail where InvoiceId = @RecordId    --***************************************************Create SCM_Payroll_InvoiceDetails for 3rd Party report *****************  insert into SCM_Payroll_InvoiceDetails   select v1.EmployeeId,invoiceid,SalaryTitle,EmployeeAmount,EmployerAmount,PeriodId,ReferenceNo, case when @CommPercentage > 0 then CommAmount else 0 end  from(    select pr.EmployeeID,@RecordId invoiceid,SalaryTitle,      Case when pr.TransactionTypeID = 2 then pr.Amount Else 0 end as EmployeeAmount,      Case when pr.TransactionTypeID = 3 then pr.Amount Else 0 end as EmployerAmount,      CommAmount,      @periodId periodId,ps.ReferenceNo    from      @TrialResults pr      left join Payroll_EmployeePayrollDefinition epd on epd.PayrollSalaryHeadID = pr.SalaryHeadID and epd.Enabled = 1 and epd.EmployeeID = pr.EmployeeID      left join Payroll_EmployeePayslip ps on ps.EmployeeID = pr.EmployeeID and ps.PayrollDefinationID = epd.EmployeePayrollDefinition_ID and ps.PeriodID = @periodId and pr.Amount = ps.Amount   )v1    --***************************************************Create Payroll_Transactions *******************************************************************************  insert into Payroll_Transactions (TransactionDate, EmployeeID, VoteId, DebitAmount, CreditAmount, PeriodID, TransactionTypeID, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAFunctionID, SCOAItemID  , DateCaptured, CapturerID, ContraVoteID, EmployeePayrollDefinitionID, EntryGoesDirectlyToLedger, VendorID, SalaryHeadID, ReferenceNo, DivisionID, TrialResultID, MatchTranGuid, DocNumber, Authorized, Enabled,TransactionsGroupID)      --debit leg  select  GETDATE() AS TrxDate1        ,TR.EmployeeID         ,lv.Vote_ID        ,tr.Amount        ,0.00 CT        ,@PeriodId        ,TransactionTypeID        ,piDt.SCOAFundId        ,piDt.SCOARegionID        ,piDt.SCOACostingID        ,dtProject.SCOAProjectID        ,piDt.SCOAFunctionID        ,piDt.ScoaItemId        ,GETDATE() TrxDate        ,@UserID UserId        ,piCt.SCOAItemID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.DivisionID        ,TR.TrialResultID        ,null --group matchguid        ,null --group doc number        ,0 Auth         ,1 Enabled        ,null --groupid  from     @TrialResults tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     join #projectItems piDt       on piDt.ScoaItemId = gl.SuspenseScoaItemID and piDT.ProjectId = gl.SCOAProjectID and piDT.SCOARegionId = pos.RegionID and piDT.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionID      join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID     join #projectItems piCt       on piCt.SCOAItemID = gl.VendorScoaId and piCt.ProjectId = gl.VendorScoaProjectId and piCt.SCOARegionId = pos.RegionID and piCt.SCOAFunctionId = pos.FunctionID and piCt.DivisionId = pos.DivisionID      join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID     join Led_vote lv      on lv.SCOAItemID = piDt.SCOAItemID and lv.Finyear = @ActiveFinyear     join Payroll_EmployeePayrollDefinition EPD             on tr.SalaryHeadID = EPD.PayrollSalaryHeadID and EPD.EmployeeID = TR.EmployeeID and epd.Enabled = 1  UNION ALL  --credit leg  select  GETDATE() AS TrxDate1        ,TR.EmployeeID         ,lv.Vote_ID        ,0.00        ,tr.Amount        ,@PeriodId        ,TransactionTypeID        ,piCt.SCOAFundId        ,piCt.SCOARegionID        ,piCt.SCOACostingID        ,ctProject.SCOAProjectID        ,piCt.SCOAFunctionID        ,piCt.ScoaItemId        ,GETDATE() TrxDate        ,@UserID UserId        ,piDt.SCOAItemID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.DivisionID        ,TR.TrialResultID        ,null --group matchguid        ,null --group doc number        ,0 Auth         ,1 Enabled        ,null --groupid  from     @TrialResults tr     join Payroll_GlItems gl       on gl.SalaryHeadId = tr.SalaryHeadId and gl.enabled = 1     join Payroll_Employee emp       on emp.Employee_ID = tr.EmployeeID     join Payroll_Position pos       on pos.Position_ID = emp.PositionID     join #projectItems piDt       on piDt.ScoaItemId = gl.SuspenseScoaItemID and piDT.ProjectId = gl.SCOAProjectID and piDT.SCOARegionId = pos.RegionID and piDT.SCOAFunctionId = pos.FunctionID and piDt.DivisionId = pos.DivisionId     join Plan_Project dtProject       on dtProject.Project_Id = piDt.ProjectID     join #projectItems piCt       on piCt.SCOAItemID = gl.VendorScoaId and piCt.ProjectId = gl.VendorScoaProjectId and piCt.SCOARegionId = pos.RegionID and piCt.SCOAFunctionId = pos.FunctionID and piCt.DivisionId = pos.DivisionId     join Plan_Project ctProject       on ctProject.Project_Id = piCt.ProjectID     join Payroll_SalaryHead sh      on sh.SalaryHead_ID = tr.SalaryHeadID     join Led_vote lv      on lv.SCOAItemID = piCt.SCOAItemID and lv.Finyear = @ActiveFinyear     join Payroll_EmployeePayrollDefinition EPD             on tr.SalaryHeadID = EPD.PayrollSalaryHeadID and EPD.EmployeeID = TR.EmployeeID and epd.Enabled = 1    --***************************************************Cursor to update TransactionGroupId's in Payroll_Transactions *********************************************    declare @grpTransactionGroupId int, @dtScoaFundsId int, @dtScoaRegionId int,@dtScoaCostingId int,@dtScoaPRojectId int,@dtScoaFunctionId int, @dtScoaItemID int,@ctScoaFundsId int,     @ctScoaRegionId int,@ctScoaCostingId int,@ctScoaPRojectId int,@ctScoaFunctionId int, @ctScoaItemID int,@grpSalaryHeadId int,@grpMatchTranGuid uniqueidentifier, @grpDocNumber varchar(10),@trvendorId int    declare payrollcursor cursor for      select TransactionGroup_Id, ScoaFundsId, ScoaRegionId,ScoaCostingId,ScoaPRojectId,ScoaFunctionId, ScoaItemID,ContraSCOAFundingID, ContraSCOARegionID,ContraSCOACostingID,ContraSCOAProjectID,        ContraSCOAFunctionID, ContraSCOAItemID,SalaryHeadId,MatchTranGuid, DocNumber,vendorId      from payroll_transactionsgroup where DocumentTypeId = 132 and PeriodId = @PeriodId and VendorID = @VendorId    open payrollcursor;      fetch next from payrollcursor into @grpTransactionGroupId, @dtScoaFundsId, @dtScoaRegionId,@dtScoaCostingId,@dtScoaPRojectId,@dtScoaFunctionId, @dtScoaItemID, @ctScoaFundsId, @ctScoaRegionId,@ctScoaCostingId,@ctScoaPRojectId,      @ctScoaFunctionId, @ctScoaItemID, @grpSalaryHeadId,@grpMatchTranGuid, @grpDocNumber,@trvendorId    while @@FETCH_STATUS = 0      begin  --update debit entries   update payroll_transactions set TransactionsgroupId = @grpTransactionGroupId, DocNumber = @grpDocNumber, MatchTranGuid = @grpMatchTranGuid      where periodid = @periodid and debitAmount > 0 and SCoaFundsId = @dtScoaFundsId and SCOARegionID = @dtScoaRegionId and SCOACostingID = @dtScoaCostingId       and SCOAProjectID = @dtScoaPRojectId and SCOAFunctionID = @dtScoaFunctionId and scoaitemid = @dtScoaItemID and SalaryHeadId = @grpSalaryHeadId and vendorId = @trvendorId        and DocNumber Is NULL    ----update credit entries   update payroll_transactions set TransactionsgroupId = @grpTransactionGroupId, DocNumber = @grpDocNumber, MatchTranGuid = @grpMatchTranGuid      where periodid = @periodid and CreditAmount > 0 and SCoaFundsId = @ctScoaFundsId and SCOARegionID = @ctScoaRegionId and SCOACostingID = @ctScoaCostingId       and SCOAProjectID = @ctScoaPRojectId and SCOAFunctionID = @ctScoaFunctionId and scoaitemid = @ctScoaItemID and SalaryHeadId = @grpSalaryHeadId and vendorId = @trvendorId        and DocNumber Is NULL    fetch next from payrollcursor into @grpTransactionGroupId, @dtScoaFundsId, @dtScoaRegionId,@dtScoaCostingId,@dtScoaPRojectId,@dtScoaFunctionId, @dtScoaItemID, @ctScoaFundsId, @ctScoaRegionId,@ctScoaCostingId,@ctScoaPRojectId,      @ctScoaFunctionId, @ctScoaItemID, @grpSalaryHeadId,@grpMatchTranGuid, @grpDocNumber,@trvendorId    end     close payrollcursor;    deallocate payrollcursor;      --***************************************************Post Transactions to Ledger *******************************************************************************  begin    declare @Led_GeneralLedger TABLE (     PostingDate DATETIME       ,ProcessingMonth INT       ,VoteID INT       ,FinYear NVARCHAR(130)       ,PayrollLinkID INT       ,TransactionTypeID INT       ,TransactionDetails NVARCHAR(130)       ,DocumentNumber NVARCHAR(130)       ,DocumentTypeId INT       ,Debit DECIMAL(18, 2)       ,Credit DECIMAL(18, 2)       ,DateCaptured DATETIME       ,CapturerID INT       ,MatchTranGuid UNIQUEIDENTIFIER       ,SCOACostingID INT       ,SCOAFunctionID INT       ,SCOAFundsID INT       ,SCOAItemID INT       ,SCOAProjectID INT       ,SCOARegionID INT       ,DivisionID INT       ,ROWNO INT IDENTITY (1, 1)       ,ProjectId INT       ,PlanProjectItemId int    )    --Insert into GL Transaction from TransactionGroup  declare @cycleId int = (Select CycleID from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)  declare @Cycle varchar(50) = (select cycledesc from Const_Cycle where Cycle_ID = @cycleId)     INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID,SCOAItemID, SCOAProjectID, SCOARegionID, DivisionID,ProjectId,PlanProjectItemId)       SELECT      pt.TransactionDate        ,@UserProcessingMonth        ,vote.Vote_ID        ,@ActiveFinYear        ,pt.TransactionGroup_ID        ,pt.DocumentTypeID        ,pt.SCMInvoiceSalaryHeadName + ' (' + cpd.ProcessingMonth + ' - ' + @Cycle + ')'        ,pt.DocNumber        ,pt.DocumentTypeID        ,pt.DebitAmount        ,pt.CreditAmount        ,GETDATE()        ,@UserID        ,pt.MatchTranGuid        ,ppi.SCOACostingID        ,ppi.SCOAFunctionID        ,ppi.SCOAFundId        ,ppi.SCOAItemID        ,pt.SCOAProjectID        ,ppi.SCOARegionID        ,ppi.DivisionID        ,ppi.ProjectId        ,ppi.PlanProjectItem_ID     FROM (Select * from Payroll_TransactionsGroup where PeriodID = @PeriodID AND DocumentTypeId = 132 and VendorID = @VendorId) pt     LEFT JOIN Payroll_CyclePeriodDetails cpd WITH (NOLOCK)      ON cpd.Period_ID = PeriodID     LEFT JOIN #projectItems ppi on ppi.PlanProjectItem_ID = pt.PlanProjectItemID     LEFT JOIN Led_Vote vote on vote.SCOAItemID = pt.SCOAItemID and vote.FinYear = @ActiveFinYear      --Insert Contra Entry from Transaction Group   INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID,SCOAItemID, SCOAProjectID, SCOARegionID, DivisionID,ProjectId,PlanProjectItemId)  SELECT      pt.TransactionDate        ,@UserProcessingMonth        ,vote.Vote_ID        ,@ActiveFinYear        ,pt.TransactionGroup_ID        ,pt.DocumentTypeID        ,pt.SCMInvoiceSalaryHeadName + ' (' + cpd.ProcessingMonth + ' - ' + @Cycle + ')'        ,pt.DocNumber        ,pt.DocumentTypeID        ,pt.CreditAmount        ,pt.DebitAmount        ,GETDATE()        ,@UserID        ,pt.MatchTranGuid        ,pt.ContraSCOACostingID         ,pt.ContraSCOAFunctionID        ,pt.ContraSCOAFundingID        ,pt.VoteID        ,pt.ContraSCOAProjectID        ,pt.ContraSCOARegionID        ,pt.DivisionID        ,pt.ContraProjectId        ,pt.ContraPlanProjectItemId     FROM (select * from Payroll_TransactionsGroup where PeriodID = @PeriodID AND DocumentTypeID = 132 AND VendorId = @VendorId) pt      LEFT JOIN Payroll_CyclePeriodDetails cpd WITH (NOLOCK)      ON cpd.Period_ID = PeriodID     LEFT JOIN Led_Vote vote on vote.SCOAItemID = pt.VoteID and vote.FinYear = @ActiveFinYear     DECLARE @TransactionDate DATETIME        ,@VOTEIDScoa INT        ,@TransactionLinkID INT        ,@TransactionDesc NVARCHAR(MAX)        ,@DocumentNumber NVARCHAR(130)        ,@DocumentTypeId INT        ,@DebitAmt DECIMAL(18, 2)        ,@CreditAmt DECIMAL(18, 2)        ,@CapturerID INT        ,@MatchTGuid UNIQUEIDENTIFIER        ,@SCOACostingID INT        ,@SCOAFunctionID INT        ,@SCOAFundsID INT        ,@SCOAItemID INT        ,@SCOAProjectID INT        ,@SCOARegionID INT        ,@DivID INT        ,@ProjectId INT        ,@PlanProjectItemId INT         SELECT     @COUNT = COUNT(*)    FROM @Led_GeneralLedger      SET @START = 1      WHILE (@START <= @COUNT)    BEGIN      SELECT     @TransactionDate = PostingDate       ,@VOTEIDScoa = VoteID       ,@TransactionLinkID = PayrollLinkID       ,@DocumentNumber = DocumentNumber       ,@DocumentTypeID = DocumentTypeID       ,@TransactionDesc = TransactionDetails       ,@DebitAmt = Debit       ,@CreditAmt = Credit       ,@CapturerID = CapturerID       ,@SCOACostingID = SCOACostingID       ,@SCOAFunctionID = SCOAFunctionID       ,@SCOAFundsID = SCOAFundsID       ,@SCOAItemID = SCOAItemID       ,@SCOAProjectID = SCOAProjectID       ,@SCOARegionID = SCOARegionID       ,@MatchTGuid = MatchTranGuid       ,@DivID = DivisionID       ,@ProjectId = ProjectId       ,@PlanProjectItemId = PlanProjectItemId    FROM @Led_GeneralLedger    WHERE ROWNO = @START      IF (@VOTEIDScoa IS NOT NULL)    BEGIN       EXECUTE Led_Posting_Payroll_sp @TransactionDate              ,@UserProcessingMonth              ,@VOTEIDScoa              ,@ActiveFinYear              ,@TransactionLinkID              ,@DocumentTypeID              ,@TransactionDesc              ,@DocumentNumber              ,@DebitAmt              ,@CreditAmt              ,@CapturerID              ,@MatchTGuid              ,@SCOACostingID              ,@SCOAFunctionID              ,@SCOAFundsID              ,@SCOAItemID              ,@SCOAProjectID              ,@SCOARegionID              ,@DivID              ,@ProjectId              ,@PlanProjectItemId    END    SET @START = @START + 1    END      END      --Return True if the update was successfull        select cast(1 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(nul

GO

-- ============================================
-- SP: Payroll_WriteTransactionAndPostToLedger
-- Schema: dbo
-- ============================================
  /*   Author  : Richa Mills   Create date : 2017/11/13   Description : Writes transactions and posts to ledger     In this process we need to do 2 things (131)   1. EARNINGS AND COMPANY CONTRIBUTIONS    DT EXPENSE ACCOUNT (As setup on Salary Head)    CT CONTROL ACCOUNT (As setup on Salary Head)     2. DEDUCTIONS (131)     DT BASIC SALARY CONTROL ACCOUNT (As setup on Payroll Municipal settings)    CR Control Account (As setup on Salary head)        ================================      Change list:      25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings   2025/06/11 Richa M - Transactions for Councillors where JournalEntryOnly is true should not be exclused (WI121027)     Payroll_WriteTransactionAndPostToLedger 485,'2025/2026',1,5  */       CREATE PROCEDURE [dbo].[Payroll_WriteTransactionAndPostToLedger]    @PeriodID INT,   @FinYear NVARCHAR(10),   @UserID INT,   @ProcessingMonth INT    AS  BEGIN    BEGIN TRY     SET NOCOUNT ON;   SET XACT_ABORT ON;   DECLARE @COUNT INT       ,@START INT = 1       ,@MAXCOUNT INT = 0       ,@MatchTranGuid UNIQUEIDENTIFIER       ,@DocNumber INT = 0       ,@ActiveFinYear NVARCHAR(10)     --Get Active Year   SELECT    @ActiveFinYear = KeyValue   FROM [dbo].[AAAA_ConfigSettings] WITH (NOLOCK)   WHERE KeyName = 'ActiveFinYear'     DECLARE @NettPayBondProjectID int = 0,     @NettPayBondScoaItemID int = 0     SELECT  @NettPayBondProjectID =[EmployeeNetPayBondProjectID] ,      @NettPayBondScoaItemID =[EmployeeNetPayBondScoaItemID]   FROM [dbo].[Payroll_Municipality]     DECLARE @TrialResult_ID INT   DECLARE @TransactionTypeId INT   DECLARE @cycleId int = (Select CycleID from Payroll_CyclePeriodDetails WHERE Period_ID = @PeriodId)   DECLARE @Cycle varchar(50) = (select cycledesc from Const_Cycle where Cycle_ID = @cycleId)       DECLARE @FinyearStartPeriod int =  (Select KeyValue from [dbo].[AAAA_ConfigSettings] where KeyName = 'FinYearStartMonth')    IF OBJECT_ID('tempdb..#projectItems') IS NOT NULL      DROP TABLE #projectItems     Select * into #projectItems from Plan_ProjectItem where PlanProjectItem_ID in(         Select min(PlanProjectItem_Id)PlanProjectItem_Id from Plan_ProjectItem          group by ProjectId,DivisionId,ScoaItemId,ScoaFunctionId,ScoaRegionId,FinYear)    CREATE INDEX IDX_ProjectItems ON #projectItems(ScoaItemId,ProjectId,DivisionId,ScoaRegionId,ScoaFunctionId)      SET @ProcessingMonth = dbo.[GetProcessingMonthByUserID_fxn](@UserID); --UserProcessingMonth    DECLARE @DocCount int =  (select  MAX(CAST(right(DocNumber,Len(DocNumber) - 4) AS int)) from Payroll_TransactionsGroup where DocNumber like '131/%' )  IF(@DocCount IS NULL)   Select @DocCount = 0    --CREATE PAYROLL_TRANSACTIONSGROUP IN ORDER TO GET DOCUMENT NUMBERS AND MATCH GUID  --For Scoa6.2   --CREDIT  --EARNINGS and COMPANY CONTRIBUTIONS - EmployeeType 1 & 6: GL.SuspenseScoaItemCreditID  --          - EmployeeType 2,3,7: ST.ControlScoaItem  --DEDUCTIONS       - GL.SuspenseScoaItemCreditID    --DEBIT  --EARNINGS and COMPANY CONTRIBUTIONS - EmployeeType 1: GL.ScoaItemIDPermanentStaff  --          - EmployeeType 2,3,7: GL.ScoaItem  --          - EmployeeType 6: GL.ScoaItemIDPostRetirement  --DEDUCTIONS JournalEntryOnly   - GL.ScoaItemId  --DEDUCTIONS NOT JournalEntriesOnly  - @SalaryControlAccount  BEGIN  --Earnings,Deductions and Company Contributions   INSERT INTO Payroll_TransactionsGroup   SELECT    GETDATE()      ,GroupDetails.ControlVoteID -- CR      ,0      ,Amount      ,@PeriodId      ,131      ,GroupDetails.SCOAFundingID      ,GroupDetails.SCOARegionID      ,GroupDetails.SCOACostingID      ,GroupDetails.SCOAProjectID      ,GroupDetails.SCOAFunctionID      ,GroupDetails.SCOAItemID --DT      ,1      ,GETDATE()      ,@UserId      ,NULL      ,GroupDetails.ContraDivisionId      ,'131/' + CAST(rowno + @DocCount AS VARCHAR(10))      ,GroupDetails.SalaryHeadID      ,GroupDetails.VendorID      ,sh.SalaryHeadName      ,NEWID()      ,NULL      ,GroupDetails.DivisionID      ,GroupDetails.ContraSCOAProjectID      ,GroupDetails.ContraSCOAItemID      ,GroupDetails.ContraSCOACostingID      ,GroupDetails.ContraSCOAFunctionID      ,GroupDetails.ContraSCOAFundingID      ,GroupDetails.ContraSCOARegionID          ,GroupDetails.ProjectId      ,GroupDetails.PlanProjectItemId      ,GroupDetails.ContraProjectId      ,GroupDetails.ContraPlanProjectItemID   FROM (      SELECT     ROW_NUMBER() OVER (ORDER BY SalaryHeadID ASC) AS rowno       ,SalaryHeadID       ,ScoaProjectId       ,SCOAItemID       ,SCOACostingID       ,SCOAFunctionID       ,SCOAFundingID       ,SCOARegionID       ,ControlVoteID       ,DivisionID       ,VendorID       ,ContraSCOAProjectID       ,ContraSCOAItemID       ,ContraSCOACostingID       ,ContraSCOAFunctionID       ,ContraSCOAFundingID       ,ContraSCOARegionID       ,ContraDivisionId       ,PlanProjectItemID       ,ContraPlanProjectItemId       ,ProjectId       ,ContraProjectId       ,SUM(Amount) AS Amount    FROM payroll_trialresults AS PTR    WHERE periodid = @PeriodID    AND TransactionTypeID IN (1,2,3)    AND TaxSavePurpose = 0    GROUP BY SalaryHeadID      ,ScoaProjectId      ,SCOAItemID      ,SCOACostingID      ,SCOAFunctionID      ,SCOAFundingID      ,SCOARegionID      ,ControlVoteID      ,DivisionID      ,VendorID      ,ContraSCOAProjectID      ,ContraSCOAItemID      ,ContraSCOACostingID      ,ContraSCOAFunctionID      ,ContraSCOAFundingID      ,ContraSCOARegionID      ,ContraDivisionId      ,PlanProjectItemId      ,ContraPlanProjectItemID      ,ProjectId      ,ContraProjectId      ) GroupDetails     LEFT OUTER JOIN Payroll_SalaryHead sh    ON sh.SalaryHead_ID = GroupDetails.SalaryHeadID    END    --CREATE PAYROLL_TRANSACTIONS FROM PAYROLL_TRIALRESULTS FOR 131 Transactions   BEGIN    INSERT INTO Payroll_Transactions (TransactionDate, EmployeeID, VoteId, DebitAmount, CreditAmount, PeriodID, TransactionTypeID, SCOAFundsID, SCOARegionID, SCOACostingID, SCOAProjectID, SCOAFunctionID, SCOAItemID    , DateCaptured, CapturerID, ContraVoteID, EmployeePayrollDefinitionID, EntryGoesDirectlyToLedger, VendorID, SalaryHeadID, ReferenceNo, DivisionID, TrialResultID, MatchTranGuid, DocNumber, Authorized, Enabled,TransactionsGroupID)  --DEBIT LEG  SELECT      GETDATE() AS TrxDate        ,TR.EmployeeID         ,lv.Vote_ID        ,Amount DT        ,0.00 CT        ,tr.PeriodID        ,TransactionTypeID        ,TR.SCOAFundingID        ,TR.SCOARegionID        ,TR.SCOACostingID        ,TR.SCOAProjectID        ,TR.SCOAFunctionID        ,TR.SCOAItemID        ,GETDATE() TrxDate        ,@UserID UserId        ,TR.ControlVoteID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.DivisionID        ,TR.TrialResult_ID        ,grp.MatchTranGuid        ,grp.DocNumber        ,0 Auth         ,1 Enabled        ,grp.TransactionGroup_ID      FROM (SELECT       *      FROM Payroll_TrialResults      WHERE TransactionTypeID in (1,2,3) and PeriodID = @PeriodId AND TaxSavePurpose = 0      ) TR     LEFT JOIN Led_Vote lv      ON TR.SCOAItemID = lv.SCOAItemID AND lv.FinYear = @ActiveFinYear     JOIN Payroll_SalaryHead SH      ON TR.SalaryHeadID = SH.SalaryHead_ID     JOIN Payroll_GLItems AS GL      ON GL.SalaryHeadID = SH.SalaryHead_ID     JOIN Payroll_EmployeePayrollDefinition EPD      ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID       AND EPD.EmployeeID = TR.EmployeeID AND EPD.Enabled = 1     LEFt OUTER JOIN Payroll_TransactionsGroup grp      ON grp.PeriodID = @PeriodID       AND grp.SalaryHeadID = tr.SalaryHeadID      AND grp.SCOAProjectID = tr.SCOAProjectID      AND grp.SCOAItemID = tr.SCOAItemID       AND grp.SCOACostingID = tr.SCOACostingID       AND grp.SCOAFunctionID = tr.SCOAFunctionID       AND grp.SCOAFundsID = tr.SCOAFundingID       AND grp.SCOARegionID = tr.SCOARegionID      AND grp.DivisionID = tr.DivisionID       and (grp.VendorID = tr.VendorID OR ISNULL(grp.VendorID,0) = 0) AND grp.VoteID = tr.ControlVoteID       AND grp.ContraSCOAProjectID = tr.ContraSCOAProjectID      AND grp.ContraSCOAItemID = tr.ContraSCOAItemID      AND grp.ContraSCOAFunctionID = tr.ContraSCOAFunctionID      AND grp.ContraSCOAFundingID = tr.ContraSCOAFundingID      AND grp.ContraSCOACostingID = tr.ContraSCOACostingID      AND grp.ContraSCOARegionID = tr.ContraSCOARegionID      AND grp.ContraPlanProjectItemId = tr.ContraPlanProjectItemID      and grp.PlanProjectItemID = tr.PlanProjectItemID  --Credit Leg  UNION ALL  SELECT      GETDATE() AS TrxDate        ,TR.EmployeeID         ,lv.Vote_ID        ,0.00 DT        ,TR.Amount CT        ,tr.PeriodID        ,TransactionTypeID        ,TR.ContraSCOAFundingID        ,TR.ContraSCOARegionID        ,TR.ContraSCOACostingID        ,TR.ContraSCOAProjectID        ,TR.ContraSCOAFunctionID        ,TR.ControlVoteID        ,GETDATE() TrxDate        ,@UserID UserId        ,TR.SCOAItemID        ,EPD.EmployeePayrollDefinition_ID        ,GL.JournalEntryOnly        ,TR.VendorID        ,SH.SalaryHead_ID        ,SalaryTitle        ,TR.ContraDivisionId        ,TR.TrialResult_ID        ,grp.MatchTranGuid        ,grp.DocNumber        ,0 Auth         ,1 Enabled        ,grp.TransactionGroup_ID      FROM (SELECT       *      FROM Payroll_TrialResults      WHERE TransactionTypeID in (1,2,3) and PeriodID = @PeriodId      and TaxSavePurpose = 0       ) TR     LEFT JOIN Led_Vote lv      ON TR.ControlVoteID = lv.SCOAItemID AND lv.FinYear = @ActiveFinYear     JOIN Payroll_SalaryHead SH      ON TR.SalaryHeadID = SH.SalaryHead_ID     JOIN Payroll_GLItems AS GL      ON GL.SalaryHeadID = SH.SalaryHead_ID     JOIN Payroll_EmployeePayrollDefinition EPD      ON SH.SalaryHead_ID = EPD.PayrollSalaryHeadID       AND EPD.EmployeeID = TR.EmployeeID AND EPD.Enabled = 1     LEFt OUTER JOIN Payroll_TransactionsGroup grp      ON grp.PeriodID = @PeriodID       AND grp.SalaryHeadID = tr.SalaryHeadID      AND grp.SCOAProjectID = tr.SCOAProjectID      AND grp.SCOAItemID = tr.SCOAItemID       AND grp.SCOACostingID = tr.SCOACostingID       AND grp.SCOAFunctionID = tr.SCOAFunctionID       AND grp.SCOAFundsID = tr.SCOAFundingID       AND grp.SCOARegionID = tr.SCOARegionID      AND grp.DivisionID = tr.DivisionID       and (grp.VendorID = tr.VendorID OR ISNULL(grp.VendorID,0) = 0) AND grp.VoteID = tr.ControlVoteID       AND grp.ContraSCOAProjectID = tr.ContraSCOAProjectID      AND grp.ContraSCOAItemID = tr.ContraSCOAItemID      AND grp.ContraSCOAFunctionID = tr.ContraSCOAFunctionID      AND grp.ContraSCOAFundingID = tr.ContraSCOAFundingID      AND grp.ContraSCOACostingID = tr.ContraSCOACostingID      AND grp.ContraSCOARegionID = tr.ContraSCOARegionID      AND grp.ContraPlanProjectItemId = tr.ContraPlanProjectItemID      and grp.PlanProjectItemID = tr.PlanProjectItemID    END      --UPDATE TPAYROLL_TRANSACTIONSCASHBOOK USED TO GENERATE PAYMENT INSTRUCTIONS    BEGIN   --This table will be used to create PaymentInstructions for Nett Salaries   INSERT INTO Payroll_TransactionsCashbook     SELECT    GETDATE() dt,   NettSalaries.EmployeeID,   SUM(ISNULL(NettSalaries.Earning,0)) AS Earnings,   SUM(ISNULL(NettSalaries.Deduction,0)) AS Deductions,   SUM(ISNULL(NettSalaries.Earning,0) - ISNULL(NettSalaries.Deduction,0)) AS NettAmount,   @PeriodId period,   ppi.ScoaFundId,   ppi.SCOARegionId,   ppi.SCOACostingID,   pp.ScoaProjectId,   ppi.SCOAFunctionId,   @NettPayBondScoaItemID acc,   133 doc,   NettSalaries.DivisionID  FROM (  SELECT    p.*      ,@NettPayBondProjectID ProjectId   FROM (SELECT     EmployeeID       ,CASE      WHEN TransactionTypeID = 1 THEN 'Earning'      ELSE 'Deduction'     END AS TransactionType       ,pt.Amount       ,pt.DivisionID       ,pt.ScoaRegionID       ,pt.ScoaFunctionID    FROM Payroll_TrialResults pt    WHERE TransactionTypeID IN (1, 2)    AND pt.PeriodID = @PeriodId AND TaxSavePurpose = 0) t   PIVOT (   SUM(Amount)   FOR TransactionType IN (Earning, Deduction)   ) p      )NettSalaries  LEFT OUTER JOIN Plan_Project pp ON pp.Project_ID = @NettPayBondProjectID    LEFT OUTER JOIN #projectItems ppi      ON ppi.ProjectID = pp.Project_ID               and ppi.SCOAItemID = @NettPayBondScoaItemID      and NettSalaries.divisionID = ppi.divisionId      AND NettSalaries.ScoaRegionID = ppi.ScoaRegionId AND NettSalaries.ScoaFunctionId = ppi.ScoaFunctionId      group by EmployeeId,     ppi.SCOAFundId ,   ppi.SCOARegionId,   ppi.SCOACostingID,   pp.ScoaProjectId,   ppi.SCOAFunctionId,    NettSalaries.DivisionID  Having SUM(ISNULL(NettSalaries.Earning,0) - ISNULL(NettSalaries.Deduction,0)) <> 0            END     --Update SCM_Invoices  ;WITH Consolidated AS (      -- each ConsolidatedEFT=1 head is its own row      SELECT          tr.PeriodID,          tr.VendorID,          CAST(1 AS bit) AS ConsolidatedEFT,          CAST(sh.SalaryHead_ID AS nvarchar(20)) AS SalaryHeadIDs,          SUM(tr.Amount) AS Amount      FROM Payroll_TrialResults tr      JOIN Payroll_SalaryHead sh ON tr.SalaryHeadID = sh.SalaryHead_ID      WHERE tr.PeriodID = @PeriodID        AND ISNULL(tr.VendorID,0) <> 0        AND sh.ConsolidatedEFT = 1      GROUP BY tr.PeriodID, tr.VendorID, sh.SalaryHead_ID  ),  NonConByHead AS (           -- aggregate per non-consolidated head first (ensures DISTINCT)      SELECT          tr.PeriodID,          tr.VendorID,          sh.SalaryHead_ID,          SUM(tr.Amount) AS AmountPerHead      FROM Payroll_TrialResults tr      JOIN Payroll_SalaryHead sh ON tr.SalaryHeadID = sh.SalaryHead_ID      WHERE tr.PeriodID = @PeriodID        AND ISNULL(tr.VendorID,0) <> 0        AND ISNULL(sh.ConsolidatedEFT,0) = 0      GROUP BY tr.PeriodID, tr.VendorID, sh.SalaryHead_ID  ),  NonConsolidated AS (        -- one vendor row; list all heads with |      SELECT          PeriodID,          VendorID,          CAST(0 AS bit) AS ConsolidatedEFT,          STRING_AGG(CONVERT(nvarchar(20), SalaryHead_ID), N'|') WITHIN GROUP (ORDER BY SalaryHead_ID) AS SalaryHeadIDs,          SUM(AmountPerHead) AS Amount      FROM NonConByHead      GROUP BY PeriodID, VendorID  ),  FinalRows AS (      SELECT PeriodID, VendorID, Amount, ConsolidatedEFT, SalaryHeadIDs FROM Consolidated      UNION ALL      SELECT PeriodID, VendorID, Amount, ConsolidatedEFT, SalaryHeadIDs FROM NonConsolidated  )     INSERT dbo.Payroll_SCMInvoiceSummary (PeriodID, VendorID, Amount, Status, ConsolidatedEFT, SalaryHeadIDs)  SELECT PeriodID, VendorID, Amount, 'Pending', ConsolidatedEFT, SalaryHeadIDs  FROM FinalRows       --POST TRANSACTIONS TO LEDGER  DECLARE @SalaryProjectID int = (select [SalaryProjectID] from [Payroll_Municipality] with(nolock)),  @SalaryControlID int = (select [SalarySuspenseScoaItemID] from [Payroll_Municipality] with(nolock))    DECLARE @CouncillorSalaryControlId int = (select SalarySuspenseScoaItemID from Const_EmployeeType_sys where EmployeeType_ID = 3)        DECLARE @ExcludeJournals TABLE (TransactionGroup_ID int)    INSERT INTO @ExcludeJournals   SELECT TransactionGroup_ID FROM     (SELECT * FROM Payroll_TransactionsGroup WHERE PeriodID = @PeriodID AND SalaryHeadID IN      (SELECT SalaryHead_ID FROM Payroll_SalaryHead WHERE  IRP5CodeId IN      (SELECT IRP5Code_Id FROM Payroll_IRP5Code WHERE TransactionTypeID = 2)))tg   LEFT JOIN Payroll_GLItems gl ON gl.SalaryHeadID = tg.SalaryHeadID   WHERE SuspenseScoaItemID IN (@SalaryControlID) AND DocumentTypeID = 131 and JournalEntryOnly = 0    INSERT INTO @ExcludeJournals   SELECT TransactionGroup_ID FROM     (SELECT * FROM Payroll_TransactionsGroup WHERE PeriodID = @PeriodID AND SalaryHeadID IN      (SELECT SalaryHead_ID FROM Payroll_SalaryHead WHERE  IRP5CodeId IN      (SELECT IRP5Code_Id FROM Payroll_IRP5Code WHERE TransactionTypeID = 2)))tg   LEFT JOIN Payroll_GLItems gl ON gl.SalaryHeadID = tg.SalaryHeadID   WHERE gl.SCOAItemID IN (@SalaryControlID) AND DocumentTypeID = 131 and gl.JournalEntryOnly = 1    INSERT INTO @ExcludeJournals   SELECT TransactionGroup_ID FROM Payroll_TransactionsGroup WHERE PeriodID = @PeriodID and SalaryHeadID IN       (SELECT SalaryHead_ID FROM Payroll_SalaryHead WHERE  IRP5CodeId IN       (SELECT IRP5Code_Id FROM Payroll_IRP5Code WHERE TransactionTypeID = 2)) and SCOAItemID = @CouncillorSalaryControlId   and SCOAItemID = @CouncillorSalaryControlId and SalaryHeadID not in (select SalaryHeadID from Payroll_GLItems where isnull(journalEntryOnly,0) = 1)          BEGIN    DECLARE @Led_GeneralLedger TABLE (     PostingDate DATETIME       ,ProcessingMonth INT       ,VoteID INT       ,FinYear NVARCHAR(130)       ,PayrollLinkID INT       ,TransactionTypeID INT       ,TransactionDetails NVARCHAR(130)       ,DocumentNumber NVARCHAR(130)       ,DocumentTypeId INT       ,Debit DECIMAL(18, 2)       ,Credit DECIMAL(18, 2)       ,DateCaptured DATETIME       ,CapturerID INT       ,MatchTranGuid UNIQUEIDENTIFIER       ,SCOACostingID INT       ,SCOAFunctionID INT       ,SCOAFundsID INT       ,SCOAItemID INT       ,SCOAProjectID INT       ,SCOARegionID INT       ,DivisionID INT       ,ROWNO INT IDENTITY (1, 1)       ,ProjectId INT       ,PlanProjectItemId INT    )    --Insert Transaction from TransactionGroup   INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID,SCOAItemID, SCOAProjectID, SCOARegionID, DivisionID,ProjectId,PlanProjectItemId)       SELECT      pt.TransactionDate        ,@ProcessingMonth        ,vote.Vote_ID        ,@ActiveFinYear        ,pt.TransactionGroup_ID        ,pt.DocumentTypeID        ,pt.SCMInvoiceSalaryHeadName + ' (' + cpd.ProcessingMonth + ' - ' + @Cycle + ')'        ,pt.DocNumber        ,pt.DocumentTypeID        ,case when pt.DebitAmount < 0 then (pt.DebitAmount * -1) else pt.DebitAmount end        ,case when pt.CreditAmount < 0 then (pt.CreditAmount * -1) else pt.CreditAmount end        ,GETDATE()        ,@UserID        ,pt.MatchTranGuid        ,pt.SCOACostingID        ,pt.SCOAFunctionID        ,pt.SCOAFundsID        ,pt.SCOAItemID        ,pt.SCOAProjectID        ,pt.SCOARegionID        ,pt.DivisionID        ,pt.ProjectID        ,pt.PlanProjectItemID     FROM Payroll_TransactionsGroup pt WITH (NOLOCK)     LEFT JOIN Payroll_CyclePeriodDetails cpd WITH (NOLOCK)      ON cpd.Period_ID = PeriodID      LEFT JOIN Led_Vote vote on vote.SCOAItemID = pt.SCOAItemID and vote.FinYear = @ActiveFinYear     WHERE PeriodID = @PeriodID     AND TransactionGroup_ID NOT IN (SELECT TransactionGroup_ID FROM @ExcludeJournals)    --Insert Contra Entry from Transaction Group   INSERT INTO @Led_GeneralLedger (PostingDate, ProcessingMonth, VoteID, FinYear, PayrollLinkID, TransactionTypeID, TransactionDetails, DocumentNumber,DocumentTypeId, Debit, Credit, DateCaptured, CapturerID, MatchTranGuid, SCOACostingID, SCOAFunctionID, SCOAFundsID,SCOAItemID, SCOAProjectID, SCOARegionID, DivisionID,ProjectId,PlanProjectItemId)  SELECT      pt.TransactionDate        ,@ProcessingMonth        ,vote.Vote_ID        ,@ActiveFinYear        ,pt.TransactionGroup_ID        ,pt.DocumentTypeID        ,pt.SCMInvoiceSalaryHeadName + ' (' + cpd.ProcessingMonth + ' - ' + @Cycle + ')'        ,pt.DocNumber        ,pt.DocumentTypeID        ,case when pt.CreditAmount < 0 then (pt.CreditAmount * -1) else pt.CreditAmount end        ,case when pt.DebitAmount < 0 then (pt.DebitAmount * -1) else pt.DebitAmount end        ,GETDATE()        ,@UserID        ,pt.MatchTranGuid        ,pt.ContraSCOACostingID         ,pt.ContraSCOAFunctionID        ,pt.ContraSCOAFundingID        ,pt.VoteID        ,pt.ContraSCOAProjectID        ,pt.ContraSCOARegionID        ,pt.ModifierID        ,pt.ContraProjectId        ,pt.ContraPlanProjectItemId     FROM Payroll_TransactionsGroup pt WITH (NOLOCK)     LEFT JOIN Payroll_CyclePeriodDetails cpd WITH (NOLOCK)      ON cpd.Period_ID = PeriodID      LEFT JOIN Led_Vote vote on vote.SCOAItemID = pt.VoteID and vote.FinYear = @ActiveFinYear     WHERE PeriodID = @PeriodID     AND TransactionGroup_ID NOT IN (SELECT TransactionGroup_ID FROM @ExcludeJournals)        DECLARE @TransactionDate DATETIME        ,@VOTEIDScoa INT        ,@TransactionLinkID INT        ,@TransactionDesc NVARCHAR(MAX)        ,@DocumentNumber NVARCHAR(130)        ,@DocumentTypeId INT        ,@DebitAmt DECIMAL(18, 2)        ,@CreditAmt DECIMAL(18, 2)        ,@CapturerID INT        ,@MatchTGuid UNIQUEIDENTIFIER        ,@SCOACostingID INT        ,@SCOAFunctionID INT        ,@SCOAFundsID INT        ,@SCOAItemID INT        ,@SCOAProjectID INT        ,@SCOARegionID INT        ,@DivID INT        ,@ProjectId INT        ,@PlanProjectItemId INT         SELECT     @COUNT = COUNT(*)    FROM @Led_GeneralLedger      SET @START = 1      WHILE (@START <= @COUNT)    BEGIN      SELECT     @TransactionDate = PostingDate       ,@VOTEIDScoa = VoteID       ,@TransactionLinkID = PayrollLinkID       ,@DocumentNumber = DocumentNumber       ,@DocumentTypeID = DocumentTypeID       ,@TransactionDesc = TransactionDetails       ,@DebitAmt = Debit       ,@CreditAmt = Credit       ,@CapturerID = CapturerID       ,@SCOACostingID = SCOACostingID       ,@SCOAFunctionID = SCOAFunctionID       ,@SCOAFundsID = SCOAFundsID       ,@SCOAItemID = SCOAItemID       ,@SCOAProjectID = SCOAProjectID       ,@SCOARegionID = SCOARegionID       ,@MatchTGuid = MatchTranGuid       ,@DivID = DivisionID       ,@ProjectId = ProjectId       ,@PlanProjectItemId = PlanProjectItemId    FROM @Led_GeneralLedger    WHERE ROWNO = @START      --IF (@VOTEIDScoa IS NOT NULL)    --BEGIN       EXECUTE Led_Posting_Payroll_sp @TransactionDate              ,@ProcessingMonth              ,@VOTEIDScoa              ,@ActiveFinYear              ,@TransactionLinkID              ,@DocumentTypeID              ,@TransactionDesc              ,@DocumentNumber              ,@DebitAmt              ,@CreditAmt              ,@CapturerID              ,@MatchTGuid              ,@SCOACostingID              ,@SCOAFunctionID              ,@SCOAFundsID              ,@SCOAItemID              ,@SCOAProjectID              ,@SCOARegionID              ,@DivID              ,@ProjectId              ,@PlanProjectItemId      --END    SET @START = @START + 1    END     END     select cast(1 as bit) as [Success], cast(null as int) as [EmployeeID], @PeriodID as [PeriodID], cast(null as tinyint) as [ErrorGroup], cast(null as nvarchar(max)) as [ErrorMessage], cast(null as sysname) as [StoredProcedure], @UserID as [CapturedBy], getdate() as [CapturedDate], cast(null as nvarchar(50)) as [ValidationType], cast(1 as bit) as [Blocking]    end try        begin catch      insert into [Payroll_FinalErrors] ([EmployeeID],[PeriodID],[ValidationType],[ErrorMessage],[StoredProcedure],[CapturedBy],[CapturedDate],[Blocking])                 values(null, @PeriodID, 'Global Level' ,error_message(), error_procedure(), 1, getdate(),1)      end catch    set nocount off;    end

GO

-- ============================================
-- SP: Payroll_WSP_CFODetails
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,25 Aug 2014>  -- Description: <Description,,Get WSP Details :  CFO Details>  -- Call SP    : Payroll_WSP_CFODetails  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_WSP_CFODetails]     AS  BEGIN     SELECT TOP 1 Emp.FirstName, Emp.Surname, Emp.CellNumber, Emp.FaxNumber, Emp.EmailAddress, Emp.PostalAddress1 + ' ' + Emp.PostalAddress2+ ' ' + (SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=Emp.PostalSuburbID) + ' ' + Emp.PostalPostalCode AS [Address] FROM dbo.Payroll_Employee AS Emp   INNER JOIN dbo.Payroll_Position AS PP ON Emp.PositionID = PP.Position_ID   INNER JOIN dbo.Payroll_JobProfile AS PJP ON PP.JobProfileID = PJP.JobProfile_ID   WHERE PJP.JobTitle = 'CFO' AND Emp.EndDate IS NULL AND Emp.Enabled = 1     END    

GO

-- ============================================
-- SP: Payroll_WSP_S2
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,26 Aug 2014>  -- Description: <Description,,Section 2>  -- Call SP    : Payroll_WSP_S2 '2013/2014'  -- 2015-01-09 James Roodt Changed address3 to a foreign key pointing to suburbs  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_WSP_S2] @FinYear NVARCHAR(50)  AS       BEGIN          SELECT  AppointedDate, IdNo, FirstName, Surname, CellNumber, FaxNumber, EmailAddress, PostalAddress1, PostalAddress2, (SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PostalSuburbID) as PostalAddress3, PostalPostalCode, PhysicalAddress1, PhysicalAddress2, (SELECT SubUrbName FROM Const_Suburb WHERE Suburb_ID=PhysicalSuburbID) as PhysicalAddress3, PhysicalPostalCode, EthnicDesc, GenderDesc, SDFDisabled, AppointmentProcedure, JobTitle, SDFWork, OtherSDFWork, QualificationID,          SDFShortCource, SDFQualification, ConductingSkillsAudits, ETDP, OtherProgram, OtherProgram1, OtherProgram2, OtherProgram3, OtherProgram4, OtherProgram5, PreSDFNumber, LGSETASupport, HRDTrainingPolicy          FROM    dbo.Payroll_WSP_SkillsDevelopmentFacilitator AS WSP                  INNER JOIN dbo.Const_SDFWork_Sys AS SDF ON WSP.SDFWorkID = SDF.SDFWork_ID                  INNER JOIN dbo.Const_AppointmentProcedure_Sys AS AP ON WSP.ProcedureID = AP.Procedure_ID                  INNER JOIN dbo.Payroll_Employee AS EMP ON WSP.EmployeeID = EMP.Employee_ID      INNER JOIN dbo.Payroll_Position AS PP ON EMP.PositionID = PP.Position_ID                  INNER JOIN dbo.Payroll_JobProfile AS PJP ON PP.JobProfileID = PJP.JobProfile_ID                  INNER JOIN dbo.Const_Gender AS G ON EMP.GenderID = G.Gender_ID                  INNER JOIN dbo.Const_EthnicGroup AS Ethnic ON EMP.EthnicGroupID = Ethnic.Ethnic_ID                  WHERE TaxYear = @FinYear      END    

GO

-- ============================================
-- SP: Payroll_WSP_S4_1
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,GD>  -- Create date: <Create Date,,26 Aug 2014>  -- Description: <Description,,WSP report Section 4.1>  -- Call SP    : Payroll_WSP_S4_1 '2013/2014'  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[Payroll_WSP_S4_1] @FinYear NVARCHAR(50)  AS       BEGIN          DECLARE @Result TABLE              (                Id INT IDENTITY(1, 1) ,                RowNo INT ,                M_Africa INT ,                M_Color INT ,                M_India INT ,                M_White INT ,                M_Fo INT ,                M_A20 INT ,                M_A30 INT ,                M_A40 INT ,                M_A50 INT ,                M_A100 INT ,                F_Africa INT ,                F_Color INT ,                F_India INT ,                F_White INT ,                F_Fo INT ,                F_A20 INT ,                F_A30 INT ,                F_A40 INT ,                F_A50 INT ,                F_A100 INT              )                /* Ethnic Table */          DECLARE @African_Id INT ,              @India_Id INT ,              @White_Id INT          SELECT  @African_Id = ISNULL(Ethnic_ID, 0)          FROM    dbo.Const_EthnicGroup          WHERE   EthnicDesc LIKE '%African%'          SELECT  @India_Id = ISNULL(Ethnic_ID, 0)          FROM    dbo.Const_EthnicGroup          WHERE   EthnicDesc LIKE 'India%'          SELECT  @White_Id = ISNULL(Ethnic_ID, 0)          FROM    dbo.Const_EthnicGroup          WHERE   EthnicDesc LIKE 'White%'                    IF @African_Id IS NULL SET @African_Id = 0          IF @India_Id IS NULL SET @India_Id = 0          IF @White_Id IS NULL SET @White_Id = 0       /* Declare Variables*/          DECLARE @C_Count INT ,              @M_Africa INT ,              @M_Color INT ,              @M_India INT ,              @M_White INT ,              @M_Fo INT ,              @F_Africa INT ,              @F_Color INT ,              @F_India INT ,              @F_White INT ,              @F_Fo INT ,              @M_A20 INT ,              @F_A20 INT ,              @M_A30 INT ,              @F_A30 INT ,              @M_A40 INT ,              @F_A40 INT ,              @M_A50 INT ,              @F_A50 INT ,              @M_A100 INT ,              @F_A100 INT ,              @EmploymentCategory_ID INT ,              @EmploymentCode_ID INT ,              @WorkArea_ID INT ,              @EndDate DATETIME ,              @StartDate DATETIME              SELECT  @StartDate = CAST(( SELECT  KeyValue                                      FROM    dbo.AAAA_ConfigSettings                                      WHERE   KeyName = 'FinYearStartMonth'                                    ) + '/01/' + ( SELECT TOP 1                                                          Data                                                   FROM   dbo.Split(@FinYear, '/')                                                 ) AS DATETIME)          SET @StartDate = DATEADD(YEAR, -1, @StartDate)          SET @EndDate = DATEADD(DAY, -1, DATEADD(YEAR, 1, @StartDate))          IF @EndDate > GETDATE() SET @EndDate = GETDATE()          PRINT @StartDate   /* For Male GenderId = 2 and For Female GenderId = 1*/          DECLARE @M_GenderId INT = 2 ,              @F_GenderId INT = 1                SELECT  @F_GenderId = Gender_ID          FROM    dbo.Const_Gender          WHERE   GenderDesc = 'Female'          SELECT  @M_GenderId = Gender_ID          FROM    dbo.Const_Gender          WHERE   GenderDesc = 'Male'        /*Get All Employment category, code and work areas*/          DECLARE @Employment TABLE              (                Id INT IDENTITY(1, 1) ,                EmploymentCategory_ID INT ,                EmploymentCode_ID INT ,                WorkArea_ID INT              )          INSERT  INTO @Employment                  SELECT DISTINCT                          EmploymentCategory_ID, EmploymentCode_ID, WorkArea_ID                  FROM    dbo.Const_EmploymentCategory_Sys AS ECate                          INNER JOIN dbo.Const_EmolymentCategoryCode_Sys AS ECateCode ON ECate.EmploymentCategory_ID = ECateCode.EmploymentCategoryID                          INNER JOIN dbo.Const_EmploymentCode_Sys AS ECode ON ECateCode.EmploymentCodeID = ECode.EmploymentCode_ID                          LEFT OUTER JOIN dbo.Const_WorkArea_Sys AS WS ON ECode.EmploymentCode_ID = WS.EmploymentCodeId                  ORDER BY EmploymentCategory_ID, EmploymentCode_ID, WorkArea_ID        /*List of Employee*/          DECLARE @Employee TABLE              (                Id INT IDENTITY(1, 1) ,                Employee_ID INT ,                Ethnic_ID INT ,                DateOfBirth DATETIME ,                GenderID INT ,                EmploymentCategory_ID INT ,                EmploymentCode_ID INT ,                WorkArea_ID INT ,                IsPWD BIT              )          INSERT  INTO @Employee                  SELECT  Emp.Employee_ID, Ethnic_ID, DateOfBirth, GenderID, ECate.EmploymentCategory_ID, ECode.EmploymentCode_ID, WA.WorkArea_ID, EquityDisabled                  FROM    dbo.Payroll_Employee AS Emp        INNER JOIN dbo.Payroll_Position AS PP ON Emp.PositionID = PP.Position_ID                          INNER JOIN dbo.Payroll_JobProfile AS PJP ON PP.JobProfileID = PJP.JobProfile_ID                          INNER JOIN dbo.Const_EmploymentCategory_Sys AS ECate ON PJP.EmploymentCategoryID = ECate.EmploymentCategory_ID                          INNER JOIN dbo.Const_EmploymentCode_Sys AS ECode ON PJP.EmploymentCodeID = ECode.EmploymentCode_ID                          LEFT OUTER JOIN dbo.Const_WorkArea_Sys AS WA ON PJP.WorkAreaID = WA.WorkArea_ID                          INNER JOIN dbo.Const_EthnicGroup AS Ethnic ON Emp.EthnicGroupID = Ethnic.Ethnic_ID                  WHERE   IsDummy = 0                          AND Emp.Enabled = 1                          AND ( Emp.EndDate > @EndDate                                OR Emp.EndDate IS NULL                              )   --AND EndDate IS NULL            /*Declare While loop Variables*/          DECLARE @Start INT = 1 ,              @End INT ,              @RowNo INT = 10            SELECT  @End = COUNT(1)          FROM    @Employment          PRINT @End            WHILE ( @Start <= @End )               BEGIN                  SELECT  @EmploymentCategory_ID = EmploymentCategory_ID, @EmploymentCode_ID = EmploymentCode_ID, @WorkArea_ID = ISNULL(WorkArea_ID, -1)                  FROM    @Employment                  WHERE   Id = @Start                            IF @EmploymentCategory_ID = 1                      AND @RowNo < 10                       BEGIN                          SET @RowNo = 10                      END                  ELSE                       IF @EmploymentCategory_ID = 2                          AND @RowNo < 19                           BEGIN                              SET @RowNo = 19                          END                      ELSE                           IF @EmploymentCategory_ID = 3                              AND @RowNo < 41                               BEGIN                                  SET @RowNo = 41                              END                          ELSE                               IF @EmploymentCategory_ID = 4                                  AND @RowNo < 75                                   BEGIN                                      SET @RowNo = 75                                  END                              ELSE                                   IF @EmploymentCategory_ID = 5                                      AND @RowNo < 109                                       BEGIN                                          SET @RowNo = 109                                      END                                  ELSE                                       IF @EmploymentCategory_ID = 6                                          AND @RowNo < 143                                           BEGIN                                              SET @RowNo = 143                                          END                                      ELSE                                           IF @EmploymentCategory_ID = 7                                              AND @RowNo < 177                                               BEGIN                                                  SET @RowNo = 177                                              END                                          ELSE                                               IF @EmploymentCategory_ID = 8                                                  AND @RowNo < 211                                                   BEGIN                                                      SET @RowNo = 211                                                  END                                              ELSE                                                   IF @EmploymentCategory_ID = 9                                                      AND @RowNo < 245                                                       BEGIN                                                          SET @RowNo = 245                                                      END                  IF @RowNo = 14                       SET @RowNo = 15                  IF ( SELECT COUNT(1)                       FROM   @Employee                       WHERE  EmploymentCategory_ID = @EmploymentCategory_ID                              AND EmploymentCode_ID = @EmploymentCode_ID                              AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                     ) > 0                       BEGIN                          SELECT  @M_Africa = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @M_GenderId                                  AND Ethnic_ID = @African_Id                                                    SELECT  @F_Africa = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @F_GenderId                                  AND Ethnic_ID = @African_Id                                            SELECT  @M_Color = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @M_GenderId                                  AND Ethnic_ID NOT IN ( @African_Id, @India_Id, @White_Id )                                                    SELECT  @F_Color = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @F_GenderId                                  AND Ethnic_ID NOT IN ( @African_Id, @India_Id, @White_Id )                                            SELECT  @M_India = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @M_GenderId                                  AND Ethnic_ID = @India_Id                                                    SELECT  @F_India = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @F_GenderId                                  AND Ethnic_ID = @India_Id                                            SELECT  @M_White = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @M_GenderId                                  AND Ethnic_ID = @White_Id                                                    SELECT  @F_White = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND IsPWD = 0                                  AND GenderID = @F_GenderId                                  AND Ethnic_ID = @White_Id                                            SELECT  @M_Fo = COUNT(1)    