mploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @M_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 21 AND 30                                                    SELECT  @F_A30 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @F_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 21 AND 30                                            SELECT  @M_A40 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @M_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 31 AND 40                                                    SELECT  @F_A40 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @F_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 31 AND 40                                            SELECT  @M_A50 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @M_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 41 AND 50                                                    SELECT  @F_A50 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @F_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 BETWEEN 41 AND 50                                            SELECT  @M_A100 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @M_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 > 50                                                    SELECT  @F_A100 = COUNT(1)                          FROM    @Employee                          WHERE   EmploymentCategory_ID = @EmploymentCategory_ID                                  AND EmploymentCode_ID = @EmploymentCode_ID                                  AND ISNULL(WorkArea_ID, -1) = @WorkArea_ID                                  AND GenderID = @F_GenderId                                  AND DATEDIFF(hour, DateOfBirth, @EndDate) / 8766 > 50                                            INSERT  INTO @Result ( RowNo, M_Africa, M_Color, M_India, M_White, M_Fo, M_A20, M_A30, M