CREATE PROCEDURE [dbo].[PMS_EmployeeCoreCompetencyRequirementSP]  @EmployeeId INT,  @IsDeleted BIT = 0,  @CaptureId INT,  @WeightingIdOut INT OUT  AS  BEGIN   SET NOCOUNT ON;   INSERT INTO dbo.PMS_EmployeeCoreCompetencyRequirement   (       EmployeeId,       IsDeleted,       DateCaptured,       CaptureId,       DateModified,       ModifierId   )   VALUES   (   @EmployeeId,       @IsDeleted,       GETDATE(),       @CaptureId,       NULL,       NULL       )   SELECT @WeightingIdOut = WeightingId FROM dbo.PMS_EmployeeCoreCompetencyRequirement  END

GO

-- ============================================
-- SP: PMS_EmployeeCoreCompetencyRequirementWeightingSP
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_EmployeeCoreCompetencyRequirementWeightingSP]      @PMS_EmployeeCoreCompetencyRequirementWeightingTYPE [dbo].[PMS_EmployeeCoreCompetencyRequirementWeightingTYPE] READONLY,      @action NVARCHAR(50)  AS  BEGIN      SET NOCOUNT ON;      IF (@action = 'INSERT')      BEGIN          INSERT INTO dbo.PMS_EmployeeCoreCompetencyRequirementWeighting          (              WeightingId,              CoreCompetencyId,              WeightingValue,              DateCaptured,              CaptureId          )          SELECT WeightingId,                 CoreCompetencyId,                 WeightingValue,                 GETDATE(),                 CaptureId          FROM @PMS_EmployeeCoreCompetencyRequirementWeightingTYPE      END        IF (@action = 'UPDATE')      BEGIN          IF (EXISTS          (              SELECT *              FROM @PMS_EmployeeCoreCompetencyRequirementWeightingTYPE AS wType              WHERE wType.WeightingId NOT IN (                                                 SELECT WTable.WeightingId                                                 FROM dbo.PMS_EmployeeCoreCompetencyRequirementWeighting AS WTable                                             )                    AND wType.CoreCompetencyId NOT IN (                                                          SELECT WTable.CoreCompetencyId                                                          FROM dbo.PMS_EmployeeCoreCompetencyRequirementWeighting AS WTable                                                      )          )             )          BEGIN              -- if now found in existing data then insert               INSERT INTO dbo.PMS_EmployeeCoreCompetencyRequirementWeighting              (                  WeightingId,                  CoreCompetencyId,                  WeightingValue,                  DateCaptured,                  CaptureId              )              SELECT WeightingId,                     CoreCompetencyId,                     WeightingValue,                     GETDATE(),                     CaptureId              FROM @PMS_EmployeeCoreCompetencyRequirementWeightingTYPE AS pms_Type              WHERE pms_Type.WeightingId NOT IN (                                                    SELECT WTable1.WeightingId                                                    FROM dbo.PMS_EmployeeCoreCompetencyRequirementWeighting AS WTable1                                                )                    AND pms_Type.CoreCompetencyId NOT IN (                                                             SELECT WTable2.CoreCompetencyId                                                             FROM dbo.PMS_EmployeeCoreCompetencyRequirementWeighting AS WTable2                                                         )          END          ELSE          BEGIN              UPDATE W              SET W.WeightingValue = W_Type.WeightingValue,                  W.DateModified = GETDATE(),                  W.ModifierId = W_Type.ModifierId              FROM dbo.PMS_EmployeeCoreCompetencyRequirementWeighting AS W                  INNER JOIN @PMS_EmployeeCoreCompetencyRequirementWeightingTYPE AS W_Type                      ON W.WeightingId = W_Type.WeightingId                         AND W.CoreCompetencyId = W_Type.CoreCompetencyId          END      END    END

GO

-- ============================================
-- SP: PMS_EmployeePost_sp
-- Schema: dbo
-- ============================================
    -- =========================================================  -- Author:  Chris Moodley  -- Create date: 01 September 2014  -- Description: Return all posts with employee filling post  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =========================================================  CREATE PROCEDURE [dbo].[PMS_EmployeePost_sp]    -- Add the parameters for the stored procedure here    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     emp.Employee_ID,    Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile   FROM    Payroll_Employee emp     INNER JOIN     Payroll_Position pp ON      emp.PositionID = pp.Position_ID    INNER JOIN     Payroll_JobProfile jProfile ON      pp.JobProfileID = jProfile.JobProfile_ID    END        

GO

-- ============================================
-- SP: PMS_EmployeeReviewersAssessmentSearchSP
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_EmployeeReviewersAssessmentSearchSP]      @FinancialYear NVARCHAR(50) = NULL,      @EmployeeId INT = 0  AS  BEGIN      SET NOCOUNT ON;      IF (@FinancialYear != '' AND @EmployeeId = 0)      BEGIN          SELECT ER.EmpAssessmentId,                 ER.EmployeeId,                 Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS Employee,                 ER.FinancialYear,                 (STUFF(                           (                               SELECT ', #' + CONVERT(nvarchar(50), ERC.ReviewerLevel) + '.' + Surname + ' ' + FirstName                                      + ' (' + JobTitle + ')' AS Reviewer                               FROM dbo.PMS_EmployeeAssessmentReviewerConfig AS ERC                                   INNER JOIN Payroll_Employee emp                                       ON ERC.ReviewerId = emp.Employee_ID                                   INNER JOIN Payroll_Position pp                                       ON emp.PositionID = pp.Position_ID                                   INNER JOIN Payroll_JobProfile jProfile                                       ON pp.JobProfileID = jProfile.JobProfile_ID                               WHERE ER.EmpAssessmentId = Er.EmpAssessmentId                                     AND emp.Employee_ID = ERC.ReviewerId                               FOR XML PATH(''), TYPE                           ).value('.', 'NVARCHAR(MAX)'),                           1,                           1,                           ''                       )                 ) AS [Reviewers]          FROM dbo.PMS_EmployeeAssessmentReviewer AS ER              INNER JOIN Payroll_Employee emp                  ON er.EmployeeId = emp.Employee_ID              INNER JOIN Payroll_Position pp                  ON emp.PositionID = pp.Position_ID              INNER JOIN Payroll_JobProfile jProfile                  ON pp.JobProfileID = jProfile.JobProfile_ID          WHERE Er.FinancialYear = @FinancialYear        END            IF (@FinancialYear = '' AND @EmployeeId > 0)      BEGIN          SELECT ER.EmpAssessmentId,                 ER.EmployeeId,                 Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS Employee,                 ER.FinancialYear,                 (STUFF(                           (                               SELECT ', #' + CONVERT(NVARCHAR(50), ERC.ReviewerLevel) + '.' + Surname + ' ' + FirstName                                      + ' (' + JobTitle + ')' AS Reviewer                               FROM dbo.PMS_EmployeeAssessmentReviewerConfig AS ERC                                   INNER JOIN Payroll_Employee emp                                       ON ERC.ReviewerId = emp.Employee_ID                                   INNER JOIN Payroll_Position pp                                       ON emp.PositionID = pp.Position_ID                                   INNER JOIN Payroll_JobProfile jProfile                                       ON pp.JobProfileID = jProfile.JobProfile_ID                               WHERE ER.EmpAssessmentId = Er.EmpAssessmentId                                     AND emp.Employee_ID = ERC.ReviewerId                               FOR XML PATH(''), TYPE                           ).value('.', 'NVARCHAR(MAX)'),                           1,                           1,                           ''                       )                 ) AS [Reviewers]          FROM dbo.PMS_EmployeeAssessmentReviewer AS ER              INNER JOIN Payroll_Employee emp                  ON er.EmployeeId = emp.Employee_ID              INNER JOIN Payroll_Position pp                  ON emp.PositionID = pp.Position_ID              INNER JOIN Payroll_JobProfile jProfile                  ON pp.JobProfileID = jProfile.JobProfile_ID          WHERE Er.EmployeeId = @EmployeeId        END          IF (@FinancialYear != '' AND @EmployeeId > 0)      BEGIN          SELECT ER.EmpAssessmentId,                 ER.EmployeeId,                 Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS Employee,                 ER.FinancialYear,                 (STUFF(                           (                               SELECT ', #' + CONVERT(NVARCHAR(50), ERC.ReviewerLevel) + '.' + Surname + ' ' + FirstName                                      + ' (' + JobTitle + ')' AS Reviewer                               FROM dbo.PMS_EmployeeAssessmentReviewerConfig AS ERC                                   INNER JOIN Payroll_Employee emp                                       ON ERC.ReviewerId = emp.Employee_ID                                   INNER JOIN Payroll_Position pp                                       ON emp.PositionID = pp.Position_ID                                   INNER JOIN Payroll_JobProfile jProfile                                       ON pp.JobProfileID = jProfile.JobProfile_ID                               WHERE ER.EmpAssessmentId = Er.EmpAssessmentId                                     AND emp.Employee_ID = ERC.ReviewerId                               FOR XML PATH(''), TYPE                           ).value('.', 'NVARCHAR(MAX)'),                           1,                           1,                           ''                       )                 ) AS [Reviewers]          FROM dbo.PMS_EmployeeAssessmentReviewer AS ER              INNER JOIN Payroll_Employee emp                  ON er.EmployeeId = emp.Employee_ID              INNER JOIN Payroll_Position pp                  ON emp.PositionID = pp.Position_ID              INNER JOIN Payroll_JobProfile jProfile                  ON pp.JobProfileID = jProfile.JobProfile_ID          WHERE ER.FinancialYear = @FinancialYear AND Er.EmployeeId = @EmployeeId        END  END

GO

-- ============================================
-- SP: PMS_EmployeeReviewersAssessmentSP
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_EmployeeReviewersAssessmentSP]      AS      BEGIN       SET NOCOUNT ON;        SELECT     ER.EmpAssessmentId,     ER.EmployeeId,     Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS Employee,     ER.FinancialYear,     (      STUFF(        (          SELECT             ', #' + CONVERT(              NVARCHAR(50),               ERC.ReviewerLevel            ) + '.' + Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS Reviewer           FROM             dbo.PMS_EmployeeAssessmentReviewerConfig AS ERC             INNER JOIN Payroll_Employee emp ON ERC.ReviewerId = emp.Employee_ID             INNER JOIN Payroll_Position pp ON emp.PositionID = pp.Position_ID             INNER JOIN Payroll_JobProfile jProfile ON pp.JobProfileID = jProfile.JobProfile_ID           WHERE             ERC.IsDeleted = 0             AND ER.EmpAssessmentId = erc.EmpAssessmentId             AND emp.Employee_ID = ERC.ReviewerId FOR XML PATH(''),             TYPE        ).value('.', 'NVARCHAR(MAX)'),         1,         1,         ''      )    ) AS [Reviewers]   FROM     dbo.PMS_EmployeeAssessmentReviewer AS ER     INNER JOIN Payroll_Employee emp ON er.EmployeeId = emp.Employee_ID     INNER JOIN Payroll_Position pp ON emp.PositionID = pp.Position_ID     INNER JOIN Payroll_JobProfile jProfile ON pp.JobProfileID = jProfile.JobProfile_ID    END

GO

-- ============================================
-- SP: PMS_EmpReviewList_SP
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_EmpReviewList_SP]  @empId int      AS        BEGIN          SET NOCOUNT ON;             SELECT           emp.Employee_ID,          Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile         FROM          Payroll_Employee emp           INNER JOIN           Payroll_Position pp ON            emp.PositionID = pp.Position_ID          INNER JOIN           Payroll_JobProfile jProfile ON            pp.JobProfileID = jProfile.JobProfile_ID          WHERE        emp.Employee_ID IN (        SELECT A.EmployeeId FROM dbo.PMS_EmployeeAssessmentReviewer AS A      INNER JOIN       dbo.PMS_EmployeeAssessmentReviewerConfig AS B      ON A.EmpAssessmentId = B.EmpAssessmentId AND B.IsDeleted = 0      WHERE       B.ReviewerId = @empId         )      END

GO

-- ============================================
-- SP: PMS_getFinancialActuals_SP
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_getFinancialActuals_SP]  @finYear AS NVARCHAR(50),    @kpiId AS INT,    @quarters AS NVARCHAR(255)    AS    BEGIN     SET NOCOUNT ON;     select abs( sum(debit) - sum(credit) ) as FinancialActual    from Led_GeneralLedger    where finyear =@finYear  and PlanProjectItemID  IN (SELECT planProjectItem_ID FROM dbo.PMS_KPI_ProjectLink WHERE kpiID = @kpiId) and     ProcessingMonth in (SELECT value FROM STRING_SPLIT(@quarters, ','))    END

GO

-- ============================================
-- SP: PMS_GetIndicatorAnalyseProgressDetails_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Sahil Nagpal  -- Create date: 26 September 2017  -- Description: Return indicators details with Username  -- PMS_GetIndicatorAnalyseProgressDetails_sp 0,10,1  -- =============================================  CREATE PROCEDURE dbo.PMS_GetIndicatorAnalyseProgressDetails_sp    -- Add the parameters for the stored procedure here      @KPIActualAnalysisId INT ,      @KPIActualId INT ,      @UserID INT  AS      BEGIN  SELECT paa.KpiActualAnalysis_ID ,         paa.KpiActualID ,         paa.AnalysisInformation ,         paa.AnalysisNotes ,         paa.DateCaptured ,         paa.CapturerID ,         paa.DateModified ,         paa.ModifierID,      ISNULL(uud.FirstName, '') + ' ' + ISNULL(uud.LastName, '')  AS AddedByName,      ISNULL(uudm.FirstName, '') + ' ' + ISNULL(uudm.LastName, '')  AS ModifiedByName       FROM dbo.PMS_IndicatorActualAnalysis paa  LEFT JOIN dbo.User_UserDetail uud ON uud.User_ID = paa.CapturerID  LEFT JOIN dbo.User_UserDetail uudm ON uudm.User_ID = paa.ModifierID  WHERE   ( CASE WHEN @KPIActualAnalysisId = 0 THEN 0                         ELSE paa.KpiActualAnalysis_ID                    END = @KPIActualAnalysisId )        AND         ( CASE WHEN @KPIActualId = 0 THEN 0                         ELSE paa.KpiActualID                    END = @KPIActualId )        AND         ( CASE WHEN @UserID = 0 THEN 0                         ELSE uud.User_ID                    END = @UserID )  END;

GO

-- ============================================
-- SP: PMS_GETQuarterlyAssessment
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_GETQuarterlyAssessment]  @FinancialYear NVARCHAR(50),      @Quarter INT,      @EmpId INT,    @CapturedId INT,      @ReviewerLevel int      AS      BEGIN      SELECT * FROM dbo.PMS_KPAQuarterlyAssessment where       FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel;      SELECT * FROM dbo.PMS_QuarterlyCoreCometencyReview      WHERE       FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel;      END

GO

