-- SP: PMS_getQuarterlyAssessmentsReviews
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_getQuarterlyAssessmentsReviews]   @FinancialYear NVARCHAR(50),       @Quarter INT ,       @EmpId INT      AS      BEGIN          SET NOCOUNT ON;        SELECT * FROM dbo.PMS_KPAQuarterlyAssessment WHERE FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId         SELECT * FROM dbo.PMS_QuarterlyCoreCometencyReview WHERE FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId      END

GO

-- ============================================
-- SP: PMS_getReviewerLevel
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_getReviewerLevel]   @EmpId INT,     @ReviewerId INT    AS    BEGIN     SET NOCOUNT ON;     SELECT erc.ReviewerLevel FROM dbo.PMS_EmployeeAssessmentReviewer er     INNER JOIN    dbo.PMS_EmployeeAssessmentReviewerConfig erc    ON     er.EmpAssessmentId = erc.EmpAssessmentId    WHERE     er.EmployeeId = @EmpId    AND    erc.ReviewerId = @ReviewerId    AND     erc.IsDeleted = 0    END

GO

-- ============================================
-- SP: PMS_GetScorecardTypeDetails_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Sahil Nagpal  -- Create date: 25/09/2017  -- Description: Get GetScorecardTypeDetails  -- 20230610 by CM: 107120 - Filter by financial year  -- =============================================  CREATE   PROCEDURE [dbo].[PMS_GetScorecardTypeDetails_sp]   @KpiID INT,   @ScorecardTypeDesc VARCHAR(200)  AS  BEGIN     DECLARE @FinYear VARCHAR(10)      SELECT     @FinYear = FinancialYear   FROM    PMS_Indicator ind    INNER JOIN IDP_Item idp ON ind.ItemID = idp.Item_ID   WHERE    ind.Kpi_ID = @KpiID     SELECT     pmst.KpiScorecardType_ID ,    pmst.KpiID ,    pmst.ScorecardTypeID ,    pmst.ScorecardTypeApplicable ,    pmst.ScorecardKpiNumber ,    cp.ScorecardType_ID ,    cp.ScorecardTypeDesc ,    cp.ScorecardTypeEnabled    FROM     [dbo].[PMS_IndicatorScorecardType] pmst    INNER JOIN Const_PMSScorecardType cp ON pmst.ScorecardTypeID = cp.ScorecardType_ID    INNER JOIN PMS_Indicator ind ON pmst.KpiID = ind.Kpi_ID    INNER JOIN IDP_Item idp ON ind.ItemID = idp.Item_ID   WHERE     cp.ScorecardTypeDesc = @ScorecardTypeDesc     AND idp.FinancialYear = @FinYear    AND pmst.KpiID <> @KpiID     END

GO

-- ============================================
-- SP: PMS_IndicatorActual_sp
-- Schema: dbo
-- ============================================
-- =========================================================  -- Author:  Chris Moodley  -- Create date: 28 October 2014  -- Description: Return indicator actuals per KPI per Quarter  -- CM: 2017/09/22 - Return WorkDone, UnderPerformanceReason, OverPerformanceReason, OverPerformanceBudgetImplication  -- CM: 2018/04/13 - Return KpiProgressID  -- CM: 2018/05/07 - Return KpiProgressDescription  -- CM: 2020/12/02 - 46907 - Return OnHoldReason  -- MC: 2022/02/15 - 97455 - Return ProgressChallenge, ProgressCorrectiveAction  -- =========================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorActual_sp]    -- Add the parameters for the stored procedure here      @kpiID INT ,      @quarter INT  AS  BEGIN  -- SET NOCOUNT ON added to prevent extra result sets from  -- interfering with SELECT statements.      SET NOCOUNT ON;    -- Insert statements for procedure here      SELECT  indActual.KpiActual_ID ,              indActual.Comment ,              indActual.CommentOverAbove ,              indActual.Challenges ,              indActual.OnHold ,              ISNULL(indActual.StatusID, 37) AS StatusID ,              indActual.ReviewComment ,              indActual.DateCaptured ,              indActual.DateModified ,              indActual.CapturerID ,              indActual.ModifierID ,              indActual.IsAchieved ,     indActual.WorkDone ,     indActual.UnderPerformanceReason ,     indActual.OverPerformanceReason ,     indActual.OverPerformanceBudgetImplication,     ISNULL(indActual.KpiProgressID, 0) AS KpiProgressID,     ISNULL(indActual.KpiProgressDescription, '') AS KpiProgressDescription,     ISNULL(indActual.OnHoldReason, '') AS OnHoldReason,              ISNULL(indActual.ProgressChallenge, '') AS ProgressChallenge,     ISNULL(indActual.ProgressCorrectiveAction, '') AS ProgressCorrectiveAction      FROM    PMS_Indicator ind              LEFT JOIN PMS_IndicatorActual indActual ON ind.Kpi_ID = indActual.KpiID AND indActual.Quarter = @quarter      WHERE   ind.Kpi_ID = @kpiID;    END;

GO

-- ============================================
-- SP: PMS_IndicatorAnalyseProgress_sp
-- Schema: dbo
-- ============================================
        -- =============================================      -- Author:  Sahil Nagpal      -- Create date: 26 September 2017      -- Description: Return indicators for Analyse Progress      -- PMS_IndicatorAnalyseProgress_sp '2018/2019',1,0    -- 2018-12-19: ChiragPatel #78961 Fix "Unknow to" blank as per bug   -- 2018-12-20: ChiragPatel #78961 as per chris Email change Column   -- =============================================      CREATE  PROCEDURE [dbo].[PMS_IndicatorAnalyseProgress_sp]        -- Add the parameters for the stored procedure here          @finYear NVARCHAR(50) ,          @quarter INT ,          @responsiblePost INT      AS          BEGIN       -- SET NOCOUNT ON added to prevent extra result sets from       -- interfering with SELECT statements.              SET NOCOUNT ON;        DECLARE @StatusID INT;        SELECT @StatusID = Status_ID FROM dbo.Const_Status WHERE UsedBy='IndicatorQuarterlyProgressStatus' AND StatusDesc='Approved';                -- Insert statements for procedure here              SELECT  ind.Kpi_ID ,                      indActual.KpiActual_ID ,          indActual.KpiActualAnalysis_ID,                      REPLACE(REPLACE(REPLACE(proj.ProjectDesc, CHAR(10), ' '),                                      CHAR(13), ' '), CHAR(09), ' ') AS ProjectActivity ,                      ind.KpiDesc ,          0  AS KpiNumber,                      employeeResponsible.Employee_ID AS RespEmpID ,                      employeeResponsible.EmpJobProfile AS RespEmpJobProfile ,                      CASE @quarter                        WHEN 1 THEN indMeasureable.Q1TargetMeasure                        WHEN 2 THEN indMeasureable.Q2TargetMeasure                        WHEN 3 THEN indMeasureable.Q3TargetMeasure                        WHEN 4 THEN indMeasureable.Q4TargetMeasure                      END AS TargetMeasure ,                      indMeasureableActual.ActualMeasure ,                      indTask.TaskDesc ,                      indTaskActual.TaskActual ,                          --CASE WHEN indActual.IsAchieved IS NULL THEN ''                      --     WHEN indActual.IsAchieved = 1 THEN 'Yes'                      --     ELSE 'No'                      --END AS AchievedFlag,          ISNULL(indActual.ProgressDesc,'') AS   AchievedFlag,     CAST((ISNULL(indActual.WorkDone,'') + ISNULL(',' + indActual.OverPerformanceReason,'') +           ISNULL(',' + indActual.UnderPerformanceReason,'')           + ISNULL(',' + indActual.OverPerformanceBudgetImplication,'')) AS VARCHAR(Max)) AS ProgressComments,          indActual.AnalysisInformation, indActual.AnalysisNotes              FROM    PMS_Indicator ind                      INNER JOIN IDP_Item item ON ind.ItemID = item.Item_ID                                                  AND item.FinancialYear = @finYear                      INNER JOIN (select * from PMS_ActivityProjectSDBIP_vw where isProject=1) iproj ON item.Item_ID = iproj.IndicatorIDPItemID                      LEFT JOIN Plan_Project proj ON iproj.ProjectActvityID = proj.Project_ID                      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON ind.Kpi_ID = indMeasureable.KpiID                      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID                                                                    AND indMeasureableActual.Quarter = @quarter                      LEFT JOIN PMS_IndicatorMeasureableVariance indMeasureableVariance ON indMeasureableActual.KpiMeasureableActual_ID = indMeasureableVariance.KpiMeasureableActualID                      --LEFT JOIN PMS_IndicatorActual indActual ON ind.Kpi_ID = indActual.KpiID          --LEFT JOIN PMS_IndicatorScorecardType scorecard ON ind.Kpi_ID = scorecard.KpiID          LEFT JOIN             ( SELECT pdi.* ,pbr.KpiActualAnalysis_ID AS KpiActualAnalysis_ID, pbr.AnalysisInformation AS AnalysisInformation, pbr.AnalysisNotes AS AnalysisNotes ,ISNULL(CPP.ProgressDesc,'') AS   ProgressDesc,             ROW_NUMBER() OVER (PARTITION BY pdi.KpiActual_ID, ISNULL(pbr.KpiActualID,0) ORDER BY pbr.DateCaptured DESC) AS RN            FROM             dbo.PMS_IndicatorActual pdi            LEFT JOIN dbo.PMS_IndicatorActualAnalysis pbr ON pbr.KpiActualID = pdi.KpiActual_ID      LEFT JOIN dbo.Const_PMSIndicatorProgress CPP ON CPP.Progress_ID = pdi.KpiProgressID        )indActual            ON ind.Kpi_ID = indActual.KpiID AND indActual.RN = 1                            LEFT JOIN ( SELECT DISTINCT                                          KpiID ,               STUFF(( SELECT  '#' + TaskDesc                                                  FROM    PMS_IndicatorTask indTask1                                                  WHERE   indTask1.KpiID = indTask2.KpiID                                                          AND QuarterDue = @quarter                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskDesc                                  FROM    PMS_IndicatorTask indTask2                                ) indTask ON ind.Kpi_ID = indTask.KpiID                                           LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + CONVERT(VARCHAR, ISNULL(ProgressPercent,                                                                    0)) + '%'                                                  FROM    ( SELECT  KpiID ,                                                                    TaskDesc ,                                                                    ProgressPercent                                                            FROM    PMS_IndicatorTask indTask                                                                    LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                                            WHERE   Quarter = @quarter                                                          ) a                                                  WHERE   a.KpiID = b.KpiID                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskActual                                  FROM    ( SELECT    KpiID ,                                                      TaskDesc ,                                                      ProgressPercent                                            FROM      PMS_IndicatorTask indTask                                                      LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                            WHERE     Quarter = @quarter                                          ) b                                ) indTaskActual ON indTask.KpiID = indTaskActual.KpiID                      LEFT JOIN ( SELECT  emp.Employee_ID ,                                          Surname + ' ' + FirstName + ' ('                                          + JobTitle + ')' AS EmpJobProfile                                  FROM    Payroll_Employee emp               INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID                                          INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID                                ) employeeResponsible ON ind.ResponsiblePost = employeeResponsible.Employee_ID              WHERE   indActual.StatusID = @StatusID AND                       ( ( ind.ResponsiblePost = @responsiblePost )                            OR ( @responsiblePost = 0 )                          )              UNION              SELECT  ind.Kpi_ID ,                      indActual.KpiActual_ID ,          indActual.KpiActualAnalysis_ID,                      act.ActivityDesc AS Project_Activity ,                      ind.KpiDesc ,          0 AS KpiNumber,                      employeeResponsible.Employee_ID AS RespEmpID ,                      employeeResponsible.EmpJobProfile AS RespEmpJobProfile ,                      CASE @quarter                        WHEN 1 THEN indMeasureable.Q1TargetMeasure                        WHEN 2 THEN indMeasureable.Q2TargetMeasure                        WHEN 3 THEN indMeasureable.Q3TargetMeasure                        WHEN 4 THEN indMeasureable.Q4TargetMeasure                      END AS TargetMeasure ,                      indMeasureableActual.ActualMeasure ,                      indTask.TaskDesc ,                      indTaskActual.TaskActual ,                      --CASE WHEN indActual.IsAchieved IS NULL THEN 'Unknown'                      --     WHEN indActual.IsAchieved = 1 THEN 'Yes'                      --     ELSE 'No'                      --END AS AchievedFlag,       ISNULL(indActual.ProgressDesc,'') AS   AchievedFlag,         (ISNULL(indActual.WorkDone,'') + ISNULL(',' + indActual.OverPerformanceReason,'') +           ISNULL(',' + indActual.UnderPerformanceReason,'')           + ISNULL(',' + indActual.OverPerformanceBudgetImplication,'')) AS ProgressComments,          indActual.AnalysisInformation, indActual.AnalysisNotes              FROM    PMS_Indicator ind                      INNER JOIN IDP_Item item ON ind.ItemID = item.Item_ID                                                  AND item.FinancialYear = @finYear          INNER JOIN (select * from PMS_ActivityProjectSDBIP_vw where isProject=0) iact ON item.Item_ID = iact.IndicatorIDPItemID                      LEFT JOIN Plan_Activity act ON iact.ProjectActvityID = act.Activity_ID                      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON ind.Kpi_ID = indMeasureable.KpiID                      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID                                                                    AND indMeasureableActual.Quarter = @quarter                      LEFT JOIN PMS_IndicatorMeasureableVariance indMeasureableVariance ON indMeasureableActual.KpiMeasureableActual_ID = indMeasureableVariance.KpiMeasureableActualID                      --LEFT JOIN PMS_IndicatorScorecardType scorecard ON ind.Kpi_ID = scorecard.KpiID          --LEFT JOIN PMS_IndicatorActual indActual ON ind.Kpi_ID = indActual.KpiID          LEFT JOIN             ( SELECT pdi.* , pbr.KpiActualAnalysis_ID, pbr.AnalysisInformation AS AnalysisInformation, pbr.AnalysisNotes AS AnalysisNotes ,ISNULL(CPP.ProgressDesc,'') AS   ProgressDesc,             ROW_NUMBER() OVER (PARTITION BY pdi.KpiActual_ID, ISNULL(pbr.KpiActualID,0) ORDER BY pbr.DateCaptured DESC) AS RN            FROM             dbo.PMS_IndicatorActual pdi            LEFT JOIN dbo.PMS_IndicatorActualAnalysis pbr ON pbr.KpiActualID = pdi.KpiActual_ID         LEFT JOIN dbo.Const_PMSIndicatorProgress CPP ON CPP.Progress_ID = pdi.KpiProgressID           )indActual            ON ind.Kpi_ID = indActual.KpiID AND indActual.RN = 1                            LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc                                                  FROM    PMS_IndicatorTask indTask1                                                  WHERE   indTask1.KpiID = indTask2.KpiID                                                          AND QuarterDue = @quarter                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskDesc                                  FROM    PMS_IndicatorTask indTask2                                ) indTask ON ind.Kpi_ID = indTask.KpiID                      LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + CONVERT(VARCHAR, ISNULL(ProgressPercent,                                                                    0)) + '%'                                                  FROM    ( SELECT  KpiID ,                                                                    TaskDesc ,                                                                    ProgressPercent                                                            FROM    PMS_IndicatorTask indTask                                                                    LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                           WHERE   Quarter = @quarter                                                          ) a                                                  WHERE   a.KpiID = b.KpiID                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskActual                                  FROM    ( SELECT    KpiID ,                                                      TaskDesc ,                                                      ProgressPercent                                            FROM      PMS_IndicatorTask indTask                                                      LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                            WHERE     Quarter = @quarter                                          ) b                                ) indTaskActual ON indTask.KpiID = indTaskActual.KpiID                      LEFT JOIN ( SELECT  emp.Employee_ID ,                                          Surname + ' ' + FirstName + ' ('                                          + JobTitle + ')' AS EmpJobProfile                                  FROM    Payroll_Employee emp               INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID                                          INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID                                ) employeeResponsible ON ind.ResponsiblePost = employeeResponsible.Employee_ID              WHERE   indActual.StatusID = @StatusID AND                       ( ( ind.ResponsiblePost = @responsiblePost )                            OR ( @responsiblePost = 0 )                          );                END;    

GO

-- ============================================
-- SP: PMS_IndicatorMeasureableActual_sp
-- Schema: dbo
-- ============================================
      -- ================================================================  -- Author:  Chris Moodley  -- Create date: 28 October 2014  -- Description: Return KPI measureble actuals per KPI per Quarter  -- 20171004 by CM - Return isKpiApplicable  -- 20171019 by CM - Return analysis fields  -- ================================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMeasureableActual_sp]   -- Add the parameters for the stored procedure here   @kpiID INT,   @quarter INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     indMeasure.KpiMeasureable_ID,    indMeasure.UnitMeasureID,    indMeasure.isCumulativeTargetMeasure,    indMeasure.Q1TargetMeasure,    indMeasure.Q2TargetMeasure,    indMeasure.Q3TargetMeasure,    indMeasure.Q4TargetMeasure,    indMeasure.isCumulativeTargetFinancial,    indMeasure.Q1TargetFinancial,    indMeasure.Q2TargetFinancial,    indMeasure.Q3TargetFinancial,    indMeasure.Q4TargetFinancial,    indMeasureActual.KpiMeasureableActual_ID,    indMeasureActual.ActualMeasure,    indMeasureActual.ActualFinancial,    indMeasureActual.Comment,    indMeasureActual.isKpiApplicable,    indMeasureActual.ActualMeasureAnalysis,    indMeasureActual.ActualFinancialAnalysis,    indMeasureActual.CommentAnalysis,    indMeasureActual.isKpiApplicableAnalysis   FROM    PMS_IndicatorMeasureable indMeasure LEFT JOIN     PMS_IndicatorMeasureableActual indMeasureActual ON      indMeasure.KpiMeasureable_ID = indMeasureActual.KpiMeasureableID AND indMeasureActual.Quarter = @quarter   WHERE    indMeasure.KpiID = @kpiID    END        

GO

