-- SP: PMS_IndicatorMeasureableDocument_sp
-- Schema: dbo
-- ============================================
  -- ==========================================================  -- Author:  Chris Moodley  -- Create date: 28 October 2014  -- Description: Return documents per measureable per KPI  -- ==========================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMeasureableDocument_sp]    -- Add the parameters for the stored procedure here   @kpiMeasureableActualID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     indMeasureActual.KpiMeasureableActual_ID,    indMeasureDoc.KpiMeasureableDocument_ID,    indMeasureDoc.KpiMeasureableActualID,    indMeasureDoc.DocumentDesc,    indMeasureDoc.DocumentFileName   FROM    PMS_IndicatorMeasureableActual indMeasureActual INNER JOIN     PMS_IndicatorMeasureableDocument indMeasureDoc ON      indMeasureActual.KpiMeasureableActual_ID = indMeasureDoc.KpiMeasureableActualID   WHERE    indMeasureActual.KpiMeasureableActual_ID = @kpiMeasureableActualID    END    

GO

-- ============================================
-- SP: PMS_IndicatorMonthActivity_sp
-- Schema: dbo
-- ============================================
  -- =====================================================  -- Author:  Chris Moodley  -- Create date: 17 October 2014  -- Description: Return monthly activity details per KPI  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =====================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMonthActivity_sp]   -- Add the parameters for the stored procedure here   @kpiID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     KpiMonthActivity_ID,    [Month],    MonthActivityDesc,    EmpJobProfile AS ResponsiblePost   FROM    PMS_IndicatorMonthActivity monthActivity LEFT JOIN     (SELECT       emp.Employee_ID,      Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile     FROM      Payroll_Employee emp       INNER JOIN     Payroll_Position pp ON      emp.PositionID = pp.Position_ID      INNER JOIN       Payroll_JobProfile jProfile ON        pp.JobProfileID = jProfile.JobProfile_ID) post ON monthActivity.ResponsiblePost = post.Employee_ID     WHERE    KpiID = @kpiID  END      

GO

-- ============================================
-- SP: PMS_IndicatorMonthActivityActual_sp
-- Schema: dbo
-- ============================================
  -- =====================================================  -- Author:  Raindree Chetty  -- Create date: 26/03/2015  -- Description: Return Month Activity actuals per KPI per month  -- Calls : PMS_IndicatorMonthActivityActual_sp 2,1  -- =====================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMonthActivityActual_sp]    -- Add the parameters for the stored procedure here   @kpiID INT,   @month INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    indMonthActivity.KpiMonthActivity_ID,    indMonthActivity.KpiID,    indMonthActivity.MonthActivityDesc,    indMonthActivity.[Month],    kpiMonthActivityActual_ID,    indMonthActivityActual.ActivityComment,    indMonthActivityActual.ActivityProgress,    ISNULL(indMonthActivityActual.OnHold,0) AS OnHold,    indMonthActivityActual.Challenges   FROM    PMS_IndicatorMonthActivity indMonthActivity LEFT JOIN     PMS_IndicatorMonthActivityActual indMonthActivityActual ON      indMonthActivity.KpiMonthActivity_ID = indMonthActivityActual.KpiMonthActivity_ID AND indMonthActivityActual.[Month] = @month   WHERE    indMonthActivity.KpiID = @kpiID AND indMonthActivity.Month = @month    END    

GO

-- ============================================
-- SP: PMS_IndicatorMonthActivityDocument_sp
-- Schema: dbo
-- ============================================
  -- ===================================================  -- Author:  Raindree Chetty  -- Create date: 26 October 2015  -- Description: Return documents per for Month Activity per KPI and month  -- Calls : Execute PMS_IndicatorMonthActivityDocument_sp 9,1  -- 2015/08/24 RC: Logic changed to link document to the monthly activity not monthly activity actuals  -- ===================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMonthActivityDocument_sp]    -- Add the parameters for the stored procedure here   @kpiID INT,   @month INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     indMonthActivityDoc.KpiMonthActivityDocument_ID,    indMonthActivityDoc.KpiMonthActivityID,    indMonthActivityDoc.DocumentDesc,    indMonthActivityDoc.DocumentFileName,    indMonthActivity.MonthActivityDesc   FROM    PMS_IndicatorMonthActivityDocument indMonthActivityDoc    INNER JOIN PMS_IndicatorMonthActivity indMonthActivity ON      indMonthActivity.KpiMonthActivity_ID = indMonthActivityDoc.KpiMonthActivityID   WHERE    indMonthActivity.KpiID = @kpiID AND indMonthActivity.[Month] = @month     END      

GO

-- ============================================
-- SP: PMS_IndicatorMonthlyActivities_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Vincent Majatladi  -- Create date: 07 October 2015  -- Description: Return indicators for review  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- PMS_IndicatorMonthlyActivities_sp '2015/2016',1,0  -- 2016-05-23 SN : Add KPI Number  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorMonthlyActivities_sp]    -- Add the parameters for the stored procedure here      @finYear NVARCHAR(50) ,      @month INT ,      @responsiblePost INT  AS      BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.          SET NOCOUNT ON;        -- Insert statements for procedure here          SELECT  i.Kpi_ID ,                  i.KpiDesc ,                  i.KpiNumber ,                  i.ResponsiblePost ,                  ima.KpiMonthActivity_ID ,                  ima.MonthActivityDesc ,                  ima.ResponsiblePost AS ActivityResponsiblePostID ,                  imae.EmpJobProfile AS ActivityResponsiblePost ,                  ima.[Month] ,                  CASE WHEN ima.[Month] BETWEEN 1 AND 3 THEN 3                       WHEN ima.[Month] BETWEEN 4 AND 6 THEN 4                       WHEN ima.[Month] BETWEEN 7 AND 9 THEN 1                       WHEN ima.[Month] BETWEEN 10 AND 12 THEN 2                  END AS [Quarter] ,                  imaa.ActivityProgress ,                  item.FinancialYear     --,*           FROM    [dbo].[PMS_Indicator] i                  LEFT JOIN [dbo].[IDP_Item] item ON i.ItemID = item.Item_ID                  INNER JOIN [dbo].[PMS_IndicatorMonthActivity] ima ON i.Kpi_ID = ima.KpiID                  LEFT JOIN ( SELECT  *                              FROM    ( SELECT    KpiMonthActivity_ID ,                                                  ActivityProgress ,                                                  ROW_NUMBER() OVER ( PARTITION BY KpiMonthActivity_ID ORDER BY DateCaptured ) AS IDX                                        FROM      [dbo].[PMS_IndicatorMonthActivityActual]                                      ) Indexed                              WHERE   IDX = 1                            ) imaa ON ima.KpiMonthActivity_ID = imaa.KpiMonthActivity_ID                  INNER JOIN ( SELECT emp.Employee_ID ,                                      Surname + ' ' + FirstName + ' ('                                      + JobTitle + ')' AS EmpJobProfile                               FROM   Payroll_Employee emp           INNER JOIN Payroll_Position pp ON emp.PositionID = pp.Position_ID                                      INNER JOIN Payroll_JobProfile jProfile ON pp.JobProfileID = jProfile.JobProfile_ID                             ) imae ON ima.ResponsiblePost = imae.Employee_ID          WHERE   item.FinancialYear = @finYear                  AND ima.[Month] = CASE WHEN ISNULL(@month, 0) = 0                                         THEN ima.[Month]                                         ELSE @month                                    END                  AND i.ResponsiblePost = CASE WHEN ISNULL(@responsiblePost, 0) = 0                                               THEN i.ResponsiblePost                                               ELSE @responsiblePost                                          END;        END;    

GO

-- ============================================
-- SP: PMS_IndicatorProjectMonthlyAmounts_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Vincent Majatladi  -- Create date: 16 September 2015  -- Description: Return project item monthly amounts to tally up as KPI financial targets  -- =============================================    --[dbo].[PMS_IndicatorProjectMonthlyAmounts_sp] 67, '2014/2015'    CREATE PROCEDURE [dbo].[PMS_IndicatorProjectMonthlyAmounts_sp]    -- Add the parameters for the stored procedure here   @ProjectID INT,   @FinYear NVARCHAR(50)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT pp.Project_ID AS [ProjectID]     , ppim.MonthID     , CASE WHEN ppim.MonthID BETWEEN 1 AND 3 THEN 3      WHEN ppim.MonthID BETWEEN 4 AND 6 THEN 4      WHEN ppim.MonthID BETWEEN 7 AND 9 THEN 1      WHEN ppim.MonthID BETWEEN 10 AND 12 THEN 2     END AS [Quarter]     , SUM(ppim.UnitPrice) AS [MonthAmount]   FROM [dbo].[Plan_Project] pp   INNER JOIN [dbo].[Plan_ProjectFund] ppf ON pp.Project_ID = ppf.ProjectID   INNER JOIN [dbo].[Plan_ProjectItem] ppi ON pp.Project_ID = ppi.ProjectID   INNER JOIN [dbo].[Plan_ProjectFundYear] ppfy ON ppf.ProjectFund_ID = ppfy.ProjectFundID AND ppi.ProjectFundYearID = ppfy.ProjectFundYear_ID   INNER JOIN [dbo].[Plan_ProjectItemMonth] ppim ON ppi.PlanProjectItem_ID = ppim.PlanProjectItemID   --WHERE pp.Project_ID = @ProjectID AND ppfy.FinYear = @FinYear   GROUP BY pp.Project_ID, ppim.MonthID   ORDER BY pp.Project_ID, [Quarter], ppim.MonthID  END  

GO

-- ============================================
-- SP: PMS_IndicatorRejected_sp
-- Schema: dbo
-- ============================================
-- ===================================================  -- Author:  Chris Moodley  -- Create date: 22 January 2015  -- Description: Return KPI's that have been rejected  -- ===================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorRejected_sp]    -- Add the parameters for the stored procedure here    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     item.FinancialYear,    1 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 1 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (41)     UNION     SELECT     item.FinancialYear,    2 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 2 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (41)     UNION     SELECT     item.FinancialYear,    3 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 3 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (41)     UNION     SELECT     item.FinancialYear,    4 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 4 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (41)     ORDER BY    FinancialYear, QuarterDue  END  

GO

-- ============================================
-- SP: PMS_IndicatorResponsibleEmployeePost_sp
-- Schema: dbo
-- ============================================
  -- ============================================================================================  -- Author:  Chris Moodley  -- Create date: 23 October 2014  -- Description: Return all posts assigned to indicators as responsible post per financial year  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- ============================================================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorResponsibleEmployeePost_sp] --'2014/2015', 7   -- Add the parameters for the stored procedure here   @financialYear NVARCHAR(50),   @departmentID INT,   @scorecardTypeID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT DISTINCT    empJobProfile.Employee_ID,    empJobProfile.EmpJobProfile   FROM     PMS_Indicator ind INNER JOIN     (      SELECT        emp.Employee_ID,       Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile      FROM       Payroll_Employee emp        INNER JOIN        Payroll_Position pp ON         emp.PositionID = pp.Position_ID       INNER JOIN        Payroll_JobProfile jProfile ON         pp.JobProfileID = jProfile.JobProfile_ID     ) empJobProfile ON      ind.ResponsiblePost = empJobProfile.Employee_ID INNER JOIN     PMS_ActivityProject_vw actProj ON      ind.ParentID = actProj.ID and ind.isParentProject = actProj.isProject INNER JOIN     IDP_Item idp ON      actProj.IDPItemID = idp.Item_ID LEFT JOIN     PMS_IndicatorScorecardType scorecardType ON      ind.Kpi_ID = scorecardType.KpiID    WHERE     idp.FinancialYear = @financialYear AND    (DepartmentID = @departmentID OR @departmentID = 0) AND    ((ScorecardTypeID = @scorecardTypeID OR @scorecardTypeID = 0) AND (ScorecardTypeApplicable = 1))      END      

GO

-- ============================================
-- SP: PMS_IndicatorReview_sp
-- Schema: dbo
-- ============================================
-- =============================================      -- Author:  Chris Moodley      -- Create date: 16 January 2015      -- Description: Return indicators for review      -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.      -- [PMS_IndicatorReview_sp]   '2018/2019',1,0       -- SN: 2016-05-03 -- ADD (select * from PMS_ActivityProjectSDBIP_vw where isProject=1) in INNER JOIN instead of PMS_IndicatorActivity and PMS_IndicatorProject Table      -- SN: 2016-05-23 -- Add KPI Number in select statement      -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions      -- 2017-09-20 TP62196 SNagpal: Add ProgressComments      -- 2017-09-26 TP62196 SNagpal: Add Script to get correct StatusId      -- 2017-11-23 CMoodley: Rerturn indicators that have ben rejected by PMS department upon review      -- 2018-12-19: ChiragPatel #78961 Fix "Unknow to" blank as per bug      -- 2018-12-20: ChiragPatel #78961 as per chris Email change Column  -- 2023-03-29: 99021 - Filter PMS_IndicatorActual by @quarter  -- =============================================          CREATE PROCEDURE [dbo].[PMS_IndicatorReview_sp]     -- Add the parameters for the stored procedure here          @finYear NVARCHAR(50) ,          @quarter INT ,          @responsiblePost INT      AS          BEGIN       -- SET NOCOUNT ON added to prevent extra result sets from       -- interfering with SELECT statements.              SET NOCOUNT ON;              DECLARE @StatusID INT;        SELECT @StatusID = Status_ID FROM dbo.Const_Status WHERE UsedBy='IndicatorQuarterlyProgressStatus' AND StatusDesc='Awaiting Review';                -- Insert statements for procedure here              SELECT  ind.Kpi_ID ,                      indActual.KpiActual_ID ,                      REPLACE(REPLACE(REPLACE(proj.ProjectDesc, CHAR(10), ' '),                                      CHAR(13), ' '), CHAR(09), ' ') AS ProjectActivity ,                      ind.KpiDesc ,          ind.KpiNumber,                      employeeResponsible.Employee_ID AS RespEmpID ,                      employeeResponsible.EmpJobProfile AS RespEmpJobProfile ,                      CASE @quarter                        WHEN 1 THEN indMeasureable.Q1TargetMeasure                        WHEN 2 THEN indMeasureable.Q2TargetMeasure                        WHEN 3 THEN indMeasureable.Q3TargetMeasure                        WHEN 4 THEN indMeasureable.Q4TargetMeasure                      END AS TargetMeasure ,                      indMeasureableActual.ActualMeasure ,                      indTask.TaskDesc ,                      indTaskActual.TaskActual ,           ISNULL(CPP.ProgressDesc,'') AS   AchievedFlag,                  (ISNULL(indActual.WorkDone,'') + ISNULL(',' + indActual.OverPerformanceReason,'') +                       ISNULL(',' + indActual.UnderPerformanceReason,'')                       + ISNULL(',' + indActual.OverPerformanceBudgetImplication,'')) AS ProgressComments              FROM    PMS_Indicator ind                      INNER JOIN IDP_Item item ON ind.ItemID = item.Item_ID                                                  AND item.FinancialYear = @finYear                      INNER JOIN (select * from PMS_ActivityProjectSDBIP_vw where isProject=1) iproj ON item.Item_ID = iproj.IndicatorIDPItemID                      LEFT JOIN Plan_Project proj ON iproj.ProjectActvityID = proj.Project_ID                      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON ind.Kpi_ID = indMeasureable.KpiID                      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID                                                                    AND indMeasureableActual.Quarter = @quarter                      LEFT JOIN PMS_IndicatorMeasureableVariance indMeasureableVariance ON indMeasureableActual.KpiMeasureableActual_ID = indMeasureableVariance.KpiMeasureableActualID                      LEFT JOIN PMS_IndicatorActual indActual ON ind.Kpi_ID = indActual.KpiID          LEFT JOIN dbo.Const_PMSIndicatorProgress CPP   ON CPP.Progress_ID = indActual.KpiProgressID                  LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc                                                  FROM    PMS_IndicatorTask indTask1           WHERE   indTask1.KpiID = indTask2.KpiID                                                          AND QuarterDue = @quarter                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskDesc                                  FROM    PMS_IndicatorTask indTask2                                ) indTask ON ind.Kpi_ID = indTask.KpiID                      LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + CONVERT(VARCHAR, TargetFinancial)                                                  FROM    PMS_IndicatorTask indTask1                                                  WHERE   indTask1.KpiID = indTask2.KpiID                                                          AND QuarterDue = 1                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskFinancialTarget                                  FROM    PMS_IndicatorTask indTask2                                ) indTaskFinancial ON ind.Kpi_ID = indTaskFinancial.KpiID                      LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + EvidencePortfolio                             