                                                     AND QuarterDue = 1                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskEvidencePortfolio                                  FROM    PMS_IndicatorTask indTask2                                ) indTaskEvidencePortfolio ON ind.Kpi_ID = indTaskEvidencePortfolio.KpiID                      LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + CONVERT(VARCHAR, ISNULL(ProgressPercent,                                                                    0)) + '%'                                                  FROM    ( SELECT  KpiID ,                                                                    TaskDesc ,                                                                    ProgressPercent                                                            FROM    PMS_IndicatorTask indTask                                                                    LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                                            WHERE   Quarter = @quarter                                                          ) a                                                  WHERE   a.KpiID = b.KpiID                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskActual                                  FROM    ( SELECT    KpiID ,                                                      TaskDesc ,                                                      ProgressPercent                                            FROM      PMS_IndicatorTask indTask                             