                                   WHERE     Quarter = @quarter                                          ) b                                ) indTaskActualFinancial ON indTask.KpiID = indTaskActualFinancial.KpiID                      LEFT JOIN ( SELECT DISTINCT                                          KpiID ,                                          STUFF(( SELECT  '#' + TaskDesc + ' - '                                                          + CONVERT(VARCHAR, ISNULL(ProgressComment,                                                                    ' No comment captured'))                                                  FROM    ( SELECT  KpiID ,                                                                    TaskDesc ,                                                                    ProgressComment                                                            FROM    PMS_IndicatorTask indTask                                                                    LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                                            WHERE   Quarter = @quarter                                                          ) a                                                  WHERE   a.KpiID = b.KpiID                                                FOR                                                  XML PATH('')                                                ), 1, 1, '') AS TaskActualComment                                  FROM    ( SELECT    KpiID ,                                                      TaskDesc ,                                                      ProgressComment                                            FROM      PMS_IndicatorTask indTask                                                      LEFT JOIN PMS_IndicatorTaskActual indTaskActual ON indTask.KpiTask_ID = indTaskActual.KpiTaskID                                            WHERE     Quarter = @quarter                