-- ============================================
-- SP: PMS_IndicatorReviewDue_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 22 January 2015  -- Description: Return KPI's due for review  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorReviewDue_sp]    -- Add the parameters for the stored procedure here    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   DECLARE    @daysAlertKPIReviewDue INT     SELECT     @daysAlertKPIReviewDue = CONVERT(INT, KeyValue)   FROM     AAAA_ConfigSettings   WHERE    LOWER(KeyName) = 'daysalertkpireviewdue'      SELECT     item.FinancialYear,    1 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 1 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ1) <= @daysAlertKPIReviewDue)     UNION     SELECT     item.FinancialYear,    2 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 2 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ2) <= @daysAlertKPIReviewDue)     UNION     SELECT     item.FinancialYear,    3 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 3 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ3) <= @daysAlertKPIReviewDue)     UNION     SELECT     item.FinancialYear,    4 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 4 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ4) <= @daysAlertKPIReviewDue)     ORDER BY    FinancialYear, QuarterDue    END  

GO

-- ============================================
-- SP: PMS_IndicatorReviewDueNotification_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Vincent Majatladi  -- Create date: 27 August 2014  -- Description: --  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorReviewDueNotification_sp]    -- Add the parameters for the stored procedure here   @CurrentDate DATETIME  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   DECLARE    @daysAlertKPIReviewDue INT     SELECT     @daysAlertKPIReviewDue = CONVERT(INT, KeyValue)   FROM     AAAA_ConfigSettings   WHERE    LOWER(KeyName) = 'daysalertkpireviewdue'      SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    1 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 1 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ1) <= @daysAlertKPIReviewDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '1' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Review Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    2 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 2 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ2) <= @daysAlertKPIReviewDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '1' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Review Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    3 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 3 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ3) <= @daysAlertKPIReviewDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '1' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Review Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    4 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 4 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (39) AND    (DATEDIFF(DAY, GETDATE(), CustodianPostDeadlineQ4) <= @daysAlertKPIReviewDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '1' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Review Due'                          AND ModuleID = 10 )     ORDER BY    FinancialYear, QuarterDue    END  

GO

-- ============================================
-- SP: PMS_IndicatorReviewPost_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 15 January 2015  -- Description: Return posts to be reviewed  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- Exec PMS_IndicatorReviewPost_sp '2015/2016', 0  -- SN:03/05/2016 ADD Inner join PMS_ActivityProjectSDBIP_vw  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorReviewPost_sp]    -- Add the parameters for the stored procedure here      @finYear NVARCHAR(50) ,      @custodianPost INT  AS      BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.          SET NOCOUNT ON;        -- Insert statements for procedure here          SELECT DISTINCT                  respJobProfile.Employee_ID ,                  respJobProfile.EmpJobProfile          FROM    PMS_Indicator ind                  INNER JOIN ( SELECT emp.Employee_ID ,                                      Surname + ' ' + FirstName + ' ('                                      + JobTitle + ')' AS EmpJobProfile                               FROM   Payroll_Employee emp           INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID                                      INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID                             ) respJobProfile ON ind.ResponsiblePost = respJobProfile.Employee_ID                  INNER JOIN ( SELECT emp.Employee_ID ,                                      Surname + ' ' + FirstName + ' ('                                      + JobTitle + ')' AS EmpJobProfile                               FROM   Payroll_Employee emp          INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID                                      INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID                             ) custodianJobProfile ON ind.CustodianPost = custodianJobProfile.Employee_ID                  INNER JOIN IDP_Item idp ON ind.ItemID = idp.Item_ID                  INNER JOIN ( SELECT *                               FROM   PMS_ActivityProjectSDBIP_vw                             ) iproj ON idp.Item_ID = iproj.IndicatorIDPItemID                                                                        --INNER JOIN PMS_IndicatorProject project ON project.KpiID = ind.Kpi_ID       --           INNER JOIN PMS_IndicatorActivity activity ON project.KpiID = ind.Kpi_ID       --           INNER JOIN PMS_ActivityProject_vw actProj ON ( project.ProjectID = actProj.ID       --                                                         AND actProj.isProject = 1       --                                                        )       --                                                        OR ( activity.ActivityID = actProj.ID       --                                                         AND actProj.isProject = 0       --                                                         )                  LEFT JOIN PMS_IndicatorScorecardType scorecardType ON ind.Kpi_ID = scorecardType.KpiID          WHERE   idp.FinancialYear = @finYear                  AND ( ( ind.CustodianPost = @custodianPost )                        OR ( @custodianPost = 0 )                      );       END;    

GO

-- ============================================
-- SP: PMS_IndicatorStatus_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 29 January 2013  -- Description: Return indicator status  -- 24/04/2015 by RC : Department details not pulling through  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- [PMS_IndicatorStatus_sp] '2014/2015', 1, 0, 0, 0  -- SN: 2016-05-03 Apply inner join of PMS_ActivityProjectSDBIP_vw AND COMMENT UNION PART  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorStatus_sp]    -- Add the parameters for the stored procedure here      @financialYear NVARCHAR(50) ,      @quarter INT ,      @departmentID INT ,      @respPost INT ,      @statusID INT  AS      BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.          SET NOCOUNT ON;          SELECT  projectActivity.ProjectActivityName ,                  ind.KpiDesc ,                  dept.DepartmentDesc ,                  employeeResponsible.EmpJobProfile ,                  StatusDesc          FROM    PMS_Indicator ind                  LEFT JOIN PMS_IndicatorActual indActual ON ind.Kpi_ID = indActual.KpiID                                                             AND ( indActual.Quarter = @quarter )                  LEFT JOIN Const_Status indStatus ON ISNULL(indActual.StatusID,                                                             37) = indStatus.Status_ID                  --INNER JOIN PMS_IndicatorProject prj ON ind.Kpi_ID = prj.KpiID                  --LEFT JOIN PMS_ActivityProject_vw projectActivity ON prj.ProjectID = projectActivity.ID                  --                                              AND ( isProject = 1 )      LEFT JOIN IDP_Item item ON ind.ItemID = item.Item_ID      INNER JOIN PMS_ActivityProjectSDBIP_vw projectActivity ON item.Item_ID  = projectActivity.IndicatorIDPItemID                  LEFT JOIN ( SELECT  emp.Employee_ID ,                                      Surname + ' ' + FirstName + ' ('                                      + JobTitle + ')' AS EmpJobProfile                              FROM    Payroll_Employee emp           INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID                                      INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID                            ) employeeResponsible ON ind.ResponsiblePost = employeeResponsible.Employee_ID                  LEFT JOIN Const_Department dept ON projectActivity.DepartmentID = dept.Department_ID                            WHERE   ( item.FinancialYear = @financialYear )                  AND ( ( dept.Department_ID = @departmentID )                        OR ( @departmentID = 0 )                      )                  AND ( ( ind.ResponsiblePost = @respPost )                        OR ( @respPost = 0 )                      )                  AND ( ( ISNULL(indStatus.Status_ID, 37) = @statusID )                        OR ( @statusID = 0 )                      )          ORDER BY projectActivity.ProjectActivityName ,                  ind.KpiDesc ,                  dept.DepartmentDesc ,                  employeeResponsible.EmpJobProfile ,                  StatusDesc;        END;    

GO

-- ============================================
-- SP: PMS_IndicatorSubmissionDue_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 21 January 2015  -- Description: Return KPI's due for submission  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorSubmissionDue_sp]   -- Add the parameters for the stored procedure here    AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here     DECLARE    @daysAlertKPISubmissionDue INT     SELECT     @daysAlertKPISubmissionDue = CONVERT(INT, KeyValue)   FROM     AAAA_ConfigSettings   WHERE    LOWER(KeyName) = 'daysalertkpisubmissiondue'      SELECT     item.FinancialYear,    1 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 1 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ1) <= @daysAlertKPISubmissionDue)     UNION     SELECT     item.FinancialYear,    2 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 2 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ2) <= @daysAlertKPISubmissionDue)     UNION     SELECT     item.FinancialYear,    3 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 3 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ3) <= @daysAlertKPISubmissionDue)     UNION     SELECT     item.FinancialYear,    4 AS QuarterDue,    ind.Kpi_ID,    ind.KpiDesc,    ind.ResponsiblePost,    ind.CustodianPost   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 4 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ4) <= @daysAlertKPISubmissionDue)     ORDER BY    FinancialYear, QuarterDue      END  

GO

-- ============================================
-- SP: PMS_IndicatorSubmissionDueNotification_sp
-- Schema: dbo
-- ============================================
-- =============================================  -- Author: Vincent Majatladi  -- Create date: 27 August 2014  -- Description: --  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorSubmissionDueNotification_sp]   -- Add the parameters for the stored procedure here   @CurrentDate DATETIME  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here     DECLARE    @daysAlertKPISubmissionDue INT     SELECT     @daysAlertKPISubmissionDue = CONVERT(INT, KeyValue)   FROM     AAAA_ConfigSettings   WHERE    LOWER(KeyName) = 'daysalertkpisubmissiondue'      SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    1 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 1 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost   WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ1) <= @daysAlertKPISubmissionDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '1' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Update Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    2 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 2 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ2) <= @daysAlertKPISubmissionDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '2' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Update Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    3 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 3 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ3) <= @daysAlertKPISubmissionDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '3' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Update Due'                          AND ModuleID = 10 )     UNION     SELECT     ind.Kpi_ID,    ind.KpiDesc,    item.FinancialYear,    4 AS QuarterDue,    ind.ResponsiblePost AS ResponsiblePostID,    resp.FirstName + ' ' + resp.Surname AS ResponsiblePost,    resp.EmailAddress AS ResponsiblePostEmail,    ind.CustodianPost AS CustodianPostID,    cust.FirstName + ' ' + cust.Surname AS CustodianPost,    cust.EmailAddress AS CustodianPostEmail,    ResponsiblePostDeadlineQ1 AS [DueDate]   FROM    PMS_Indicator ind LEFT JOIN     PMS_IndicatorActual indActual ON      ind.Kpi_ID = indActual.KpiID AND Quarter = 4 INNER JOIN     IDP_Item item ON      ind.ItemID = item.Item_ID LEFT JOIN     Const_PMSIndicatorQuarterlySubmissionDeadline indDeadline ON      item.FinancialYear = indDeadline.FinancialYear LEFT JOIN     Payroll_Employee resp ON      resp.Employee_ID = ind.ResponsiblePost LEFT JOIN     Payroll_Employee cust ON      cust.Employee_ID = ind.CustodianPost        WHERE    ISNULL(StatusID, 37) IN (37, 38) AND    (DATEDIFF(DAY, GETDATE(), ResponsiblePostDeadlineQ4) <= @daysAlertKPISubmissionDue) AND    CAST(CAST(ind.Kpi_ID AS VARCHAR(9)) + '4' AS INT)     NOT IN (                  SELECT  ReferanceID                  FROM    Cons_Email_Schedule_Details                          INNER JOIN dbo.Cons_Email_Schedule SCH ON dbo.Cons_Email_Schedule_Details.ScheduleID = SCH.Schedule_ID                          INNER JOIN dbo.Cons_Email_Template TEM ON SCH.TemplateID = TEM.Template_ID                  WHERE   CONVERT(NVARCHAR(10), SentDate, 104) = CONVERT(NVARCHAR(10), GETDATE(), 104)                          AND TemplateTitle = 'KPI Update Due'                          AND ModuleID = 10 )     ORDER BY    FinancialYear, QuarterDue      END  

GO

-- ============================================
-- SP: PMS_IndicatorTarget_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Chris Moodley  -- Create date: 14 September 2017  -- Description: Return KPI name and targets per KPI  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTarget_sp]   -- Add the parameters for the stored procedure here   @kpiID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT      '&nbsp;&nbsp;&nbsp;&nbsp;KPI: ' + KpiDesc AS KpiHeaderDesc    ,1 AS DisplayOrder   FROM     PMS_Indicator ind   WHERE     Kpi_ID = @kpiID     UNION     SELECT      '&nbsp;&nbsp;&nbsp&nbsp;&nbsp;Measureable Output: Q1 Target = ' + Q1TargetMeasure + ';  Q2 Target = ' + Q2TargetMeasure + ';  Q3 Target = ' + Q3TargetMeasure + ';  Q4 Target = ' + Q4TargetMeasure  AS KpiHeaderDesc    ,2 AS DisplayOrder   FROM    PMS_IndicatorMeasureable indM   WHERE     KpiID = @kpiID     UNION     SELECT     '&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Task: ' + TaskDesc + ';  Due: Quarter ' + CONVERT(VARCHAR, QuarterDue) AS KpiHeaderDesc    ,3 AS DisplayOrder   FROM     PMS_IndicatorTask indT   WHERE     KpiID = @kpiID     ORDER BY    DisplayOrder    END    

GO

-- ============================================
-- SP: PMS_IndicatorTask_sp
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Chris Moodley  -- Create date: 16 October 2014  -- Description: Return task details per KPI  -- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.  -- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTask_sp]   -- Add the parameters for the stored procedure here   @kpiID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     KpiTask_ID,    QuarterDue,    TaskDesc,    EmpJobProfile AS ResponsiblePost,    EvidencePortfolio,    TargetFinancial   FROM    PMS_IndicatorTask indicatorTask LEFT JOIN     (SELECT       emp.Employee_ID,      Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile     FROM      Payroll_Employee emp      INNER JOIN       Payroll_Position PP ON        emp.PositionID  = PP.Position_ID       INNER JOIN       Payroll_JobProfile jProfile ON        PP.JobProfileID  = jProfile.JobProfile_ID) post ON indicatorTask.ResponsiblePost = post.Employee_ID     WHERE    KpiID = @kpiID    END      

GO

-- ============================================
-- SP: PMS_IndicatorTaskActual_sp
-- Schema: dbo
-- ============================================
-- ==========================================================================================  -- Author:  Chris Moodley  -- Create date: 28 October 2014  -- Description: Return task actuals per KPI per Quarter  -- 20180620 by CM - Remove filtering by quarter  -- 20180626 by CM - Return latest actuals of all tasks if not already captured for a quarter  -- 20230325 by JP - Return New field - IsKpiApplicable  -- ==========================================================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTaskActual_sp] --5, 1   -- Add the parameters for the stored procedure here   @kpiID INT,   @quarter INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   DECLARE    @kpiTaskActualID INT = 0     SELECT TOP 1    @kpiTaskActualID = KpiTaskActual_ID   FROM     PMS_IndicatorTask indTask INNER JOIN     PMS_IndicatorTaskActual indtaskActual ON      indTask.KpiTask_ID = indTaskActual.KpiTaskID   WHERE     KpiID = @kpiID AND Quarter = @quarter       IF (@kpiTaskActualID = 0)   BEGIN      SELECT     indTask.KpiTask_ID,     indTask.KpiID,     indTask.TaskDesc,     indTask.QuarterDue,     CASE @quarter        WHEN 4 THEN ISNULL(indTaskActualQ4.kpiTaskActual_ID, 0)      WHEN 3 THEN ISNULL(indTaskActualQ3.kpiTaskActual_ID, 0)      WHEN 2 THEN ISNULL(indTaskActualQ2.kpiTaskActual_ID, 0)      WHEN 1 THEN ISNULL(indTaskActualQ1.kpiTaskActual_ID, 0)     END AS kpiTaskActual_ID,     ISNULL(CONVERT(VARCHAR, COALESCE(indTaskActualQ4.ActualStartDate, indTaskActualQ3.ActualStartDate, indTaskActualQ2.ActualStartDate, indTaskActualQ1.ActualStartDate), 103), '') AS ActualStartDate,     ISNULL(CONVERT(VARCHAR, COALESCE(indTaskActualQ4.ActualEndDate, indTaskActualQ3.ActualEndDate, indTaskActualQ2.ActualEndDate, indTaskActualQ1.ActualEndDate), 103), '') AS ActualEndDate,     COALESCE(indTaskActualQ4.ProgressPercent, indTaskActualQ3.ProgressPercent, indTaskActualQ2.ProgressPercent, indTaskActualQ1.ProgressPercent) AS ProgressPercent,     COALESCE(indTaskActualQ4.ProgressFinancial, indTaskActualQ3.ProgressFinancial, indTaskActualQ2.ProgressFinancial, indTaskActualQ1.ProgressFinancial) AS ProgressFinancial,     COALESCE(indTaskActualQ4.ProgressComment, indTaskActualQ3.ProgressComment, indTaskActualQ2.ProgressComment, indTaskActualQ1.ProgressComment) AS ProgressComment,     CASE @quarter        WHEN 4 THEN (CASE ISNULL(indTaskActualQ4.IsKpiApplicable,1) WHEN 1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END)       WHEN 3 THEN (CASE ISNULL(indTaskActualQ3.IsKpiApplicable,1) WHEN 1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END)      WHEN 2 THEN (CASE ISNULL(indTaskActualQ2.IsKpiApplicable,1) WHEN 1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END)      WHEN 1 THEN (CASE ISNULL(indTaskActualQ1.IsKpiApplicable,1) WHEN 1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END)     END AS KpiNotApplicable    FROM     PMS_IndicatorTask indTask LEFT JOIN      PMS_IndicatorTaskActual indTaskActualQ1 ON       indTask.KpiTask_ID = indTaskActualQ1.KpiTaskID AND indTaskActualQ1.Quarter = 1 LEFT JOIN      PMS_IndicatorTaskActual indTaskActualQ2 ON       indTask.KpiTask_ID = indTaskActualQ2.KpiTaskID AND indTaskActualQ2.Quarter = 2 LEFT JOIN      PMS_IndicatorTaskActual indTaskActualQ3 ON       indTask.KpiTask_ID = indTaskActualQ3.KpiTaskID AND indTaskActualQ3.Quarter = 3 LEFT JOIN      PMS_IndicatorTaskActual indTaskActualQ4 ON       indTask.KpiTask_ID = indTaskActualQ4.KpiTaskID AND indTaskActualQ4.Quarter = 4    WHERE     indTask.KpiID = @kpiID    END   ELSE   BEGIN    SELECT     indTask.KpiTask_ID,     indTask.KpiID,     indTask.TaskDesc,     indTask.QuarterDue,     ISNULL(kpiTaskActual_ID, 0) AS kpiTaskActual_ID,     ISNULL(CONVERT(VARCHAR, indTaskActual.ActualStartDate, 103), '') AS ActualStartDate,     ISNULL(CONVERT(VARCHAR, indTaskActual.ActualEndDate, 103), '') AS ActualEndDate,     indTaskActual.ProgressPercent,     indTaskActual.ProgressFinancial,     indTaskActual.ProgressComment,     CASE ISNULL(indTaskActual.IsKpiApplicable,1) WHEN 1 THEN CAST(0 AS BIT) ELSE CAST(1 AS BIT) END AS KpiNotApplicable    FROM     PMS_IndicatorTask indTask LEFT JOIN      PMS_IndicatorTaskActual indTaskActual ON       indTask.KpiTask_ID = indTaskActual.KpiTaskID     WHERE     indTask.KpiID = @kpiID AND indTaskActual.Quarter = @quarter   END    END

GO

-- ============================================
-- SP: PMS_IndicatorTaskActualAnalysis_sp
-- Schema: dbo
-- ============================================
    -- =====================================================  -- Author:  Chris Moodley  -- Create date: 20 October 2017  -- Description: Return task analysis actuals per KPI per Quarter  -- =====================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTaskActualAnalysis_sp]    -- Add the parameters for the stored procedure here   @kpiID INT,   @quarter INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    indTask.KpiTask_ID,    indTask.KpiID,    indTask.TaskDesc,    indTask.QuarterDue,    kpiTaskActual_ID,    ISNULL(CONVERT(VARCHAR, indTaskActual.ActualStartDateAnalysis, 103), '') AS ActualStartDate,    ISNULL(CONVERT(VARCHAR, indTaskActual.ActualEndDateAnalysis, 103), '') AS ActualEndDate,    indTaskActual.ProgressPercentAnalysis AS ProgressPercent,    indTaskActual.ProgressFinancialAnalysis AS ProgressFinancial,    indTaskActual.ProgressCommentAnalysis AS ProgressComment   FROM    PMS_IndicatorTask indTask LEFT JOIN     PMS_IndicatorTaskActual indTaskActual ON      indTask.KpiTask_ID = indTaskActual.KpiTaskID AND indTaskActual.Quarter = @quarter   WHERE    indTask.KpiID = @kpiID AND indTask.QuarterDue = @quarter    END      

GO

-- ============================================
-- SP: PMS_IndicatorTaskDocument_sp
-- Schema: dbo
-- ============================================
  -- ===================================================  -- Author:  Chris Moodley  -- Create date: 28 October 2014  -- Description: Return documents per for task per KPI  -- ===================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTaskDocument_sp]    -- Add the parameters for the stored procedure here   @kpiID INT,   @quarter INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     indTaskActual.KpiTaskActual_ID,    indTaskDoc.KpiTaskDocument_ID,    indTaskDoc.KpiTaskActualID,    indTaskDoc.DocumentDesc,    indTaskDoc.DocumentFileName,    indTask.TaskDesc   FROM    PMS_IndicatorTaskActual indTaskActual INNER JOIN     PMS_IndicatorTaskDocument indTaskDoc ON      indTaskActual.KpiTaskActual_ID = indTaskDoc.KpiTaskActualID AND indTaskActual.Quarter = @quarter INNER JOIN     PMS_IndicatorTask indTask ON      indTaskActual.KpiTaskID = indTask.KpiTask_ID   WHERE    indTask.KpiID = @kpiID    END    

GO

-- ============================================
-- SP: PMS_IndicatorTechnicalDescription_SP
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  <ANAND,NARWADE>  -- Create date: <22 AUG 2022>  -- Description: <TO CREATE,UPDATE Kpi technical description>  -- =============================================  CREATE PROCEDURE [dbo].[PMS_IndicatorTechnicalDescription_SP]    @IndicatorId int = null,   @IndicatorName nvarchar(200),   @Definition nvarchar(200),   @SourceOfData nvarchar(200),   @MethodOfCalculation nvarchar(200),   @MeansOfVerification nvarchar(200),   @UnitOfMeasureId int,   @ReportingCycle nvarchar(50),   @ResultChainLevel nvarchar(50),   @IndicatorResponsibilityId int,   @BacktoBasicsPillar nvarchar(50) = null,   @DesiredPerformance nvarchar(200) = null,   @Assumption nvarchar(200) = null,   @AdditionalNotes nvarchar(200) = null,   @RegulatedIndicator bit = null,   @IsEnabled bit = null,   @CaptureId int,   @ModifierId int = null,   @action nvarchar(10)  AS  BEGIN   SET NOCOUNT ON;   IF(@action = 'INSERT')   BEGIN   if(@IsEnabled = null)   begin    set @IsEnabled = 1   end     INSERT INTO [dbo].[PMS_IndicatorTechnicalDescription]                ([IndicatorName]                ,[Definition]                ,[SourceOfData]                ,[MethodOfCalculation]          ,[MeansOfVerification]                ,[UnitOfMeasureId]                ,[ReportingCycle]                ,[ResultChainLevel]                ,[IndicatorResponsibilityId]                ,[BacktoBasicsPillar]                ,[DesiredPerformance]                ,[Assumption]                ,[AdditionalNotes]                ,[RegulatedIndicator]          ,[IsEnabled]                ,[DateCaptured]                ,[CaptureId]                ,[DateModified]                ,[ModifierId])          VALUES                (@IndicatorName                ,@Definition                ,@SourceOfData                ,@MethodOfCalculation          ,@MeansOfVerification                ,@UnitOfMeasureId                ,@ReportingCycle                ,@ResultChainLevel                ,@IndicatorResponsibilityId                ,@BacktoBasicsPillar                ,@DesiredPerformance                ,@Assumption                ,@AdditionalNotes                ,@RegulatedIndicator          ,@IsEnabled                ,GETDATE()                ,@CaptureId                ,null                ,null)      END   ELSE IF(@action = 'UPDATE')   BEGIN  UPDATE [dbo].[PMS_IndicatorTechnicalDescription]     SET [IndicatorName] = @IndicatorName        ,[Definition] = @Definition        ,[SourceOfData] = @SourceOfData        ,[MethodOfCalculation] = @MethodOfCalculation     ,[MeansOfVerification] = @MeansOfVerification        ,[UnitOfMeasureId] = @UnitOfMeasureId        ,[ReportingCycle] = @ReportingCycle        ,[ResultChainLevel] = @ResultChainLevel        ,[IndicatorResponsibilityId] = @IndicatorResponsibilityId        ,[BacktoBasicsPillar] = @BacktoBasicsPillar        ,[DesiredPerformance] = @DesiredPerformance        ,[Assumption] = @Assumption        ,[AdditionalNotes] = @AdditionalNotes        ,[RegulatedIndicator] = @RegulatedIndicator        ,[IsEnabled] = @IsEnabled        ,[DateModified] = GETDATE()        ,[ModifierId] = @ModifierId   WHERE IndicatorId = @IndicatorId   END   SET NOCOUNT OFF;  END

GO

-- ============================================
-- SP: PMS_IndicatorVariance_sp
-- Schema: dbo
-- ============================================
-- =========================================================================================  -- Author:  Chris Moodley  -- Create date: 01 December 2014  -- Description: Return variance details for task/measureable per financial year per quarter  -- =========================================================================================  CREATE PROCEDURE [dbo].[PMS_IndicatorVariance_sp]    -- Add the parameters for the stored procedure here   @kpiID INT,   @quarter INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT     KpiMeasureableVariance_ID AS ID,    KpiMeasureableActualID AS ActualID,    KpiDesc AS MeasureableTask,    ISNULL(VarianceComment, '') AS VarianceComment,    ISNULL(VarianceCorrectiveAction, '') AS VarianceCorrectiveAction,    1 AS Measureable   FROM    PMS_IndicatorMeasureableVariance variance INNER JOIN     PMS_IndicatorMeasureableActual indMeasureActual ON      variance.KpiMeasureableActualID = indMeasureActual.KpiMeasureableActual_ID INNER JOIN     PMS_IndicatorMeasureable indMeasure ON      indMeasureActual.KpiMeasureableID = indMeasure.KpiMeasureable_ID INNER JOIN     PMS_Indicator ind ON      indMeasure.KpiID = ind.Kpi_ID   WHERE    KpiID = @kpiID AND Quarter = @quarter     UNION     SELECT     KpiTaskVariance_ID AS ID,    KpiTaskActualID AS ActualID,    TaskDesc AS MeasureableTask,    ISNULL(VarianceComment, '') AS VarianceComment,    ISNULL(VarianceCorrectiveAction, '') AS VarianceCorrectiveAction,    0 AS Measureable   FROM    PMS_IndicatorTaskVariance variance INNER JOIN     PMS_IndicatorTaskActual indMeasureActual ON      variance.KpiTaskActualID = indMeasureActual.KpiTaskActual_ID INNER JOIN     PMS_IndicatorTask indMeasure ON      indMeasureActual.KpiTaskID = indMeasure.KpiTask_ID   WHERE    KpiID = @kpiID AND Quarter = @quarter    END  

GO

-- ============================================
-- SP: PMS_KPAQuarterlyAssessment_SP
-- Schema: dbo
-- ============================================
-- =============================================          -- Author:  <Author,,Name>          -- Create date: <Create Date,,>          -- Description: <Description,,>          -- =============================================          CREATE PROCEDURE [dbo].[PMS_KPAQuarterlyAssessment_SP]          @KPAAssessmentId INT = NULL,          @FinancialYear NVARCHAR(50),          @Quarter INT,          @EmpId INT,      @ReviewerLevel INT,          @KpiId INT,      @ReviewerId INT,    @ReviewersComment NVARCHAR(512),         @IsSubmitted BIT,        @LoggedInUser INT,          @Action NVARCHAR(50)          AS          BEGIN          IF(@Action = 'INSERT')          BEGIN                IF(EXISTS(SELECT * FROM dbo.PMS_KPAQuarterlyAssessment WHERE  FinancialYear = @FinancialYear      AND Quarter = @Quarter AND EmpId = @EmpId and ReviewerLevel = @ReviewerLevel AND CaptureId = @LoggedInUser AND KpiId = @KpiId AND ReviewerId = @ReviewerId AND IsSubmitted != 1))      BEGIN       DELETE FROM dbo.PMS_KPAQuarterlyAssessment  WHERE  FinancialYear = @FinancialYear      AND Quarter = @Quarter AND EmpId = @EmpId and ReviewerLevel = @ReviewerLevel AND CaptureId = @LoggedInUser AND KpiId = @KpiId AND ReviewerId = @ReviewerId      end             INSERT INTO dbo.PMS_KPAQuarterlyAssessment           (               FinancialYear,               Quarter,               ReviewerLevel,         ReviewerId,         KpiId,            EmpId,           ReviewersComment,            IsSubmitted,             DateCaptured,               CaptureId,               DateModified,               ModifierId           )           VALUES           (   @FinancialYear,       @Quarter,       @ReviewerLevel,    @ReviewerId,       @KpiId,    @EmpId,       @ReviewersComment,    @IsSubmitted,       GETDATE(),       @LoggedInUser,       null,       null       )          END                       END

GO

