-- ============================================
-- SP: PMS_QuarterlyAssessmentAlreadyExists
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_QuarterlyAssessmentAlreadyExists]  @FinancialYear NVARCHAR(50),        @Quarter INT,        @EmpId INT,      @ReviewerId INT,    @CapturedId INT,        @ReviewerLevel int        AS        BEGIN         IF(EXISTS(SELECT * FROM dbo.PMS_KPAQuarterlyAssessment where         FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND ReviewerId = @ReviewerId AND CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel AND IsSubmitted = 1        ))       BEGIN       SELECT * FROM dbo.PMS_KPAQuarterlyAssessment where         FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND ReviewerId = @ReviewerId AND CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel;         end       END

GO

