-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_QuarterlyCoreCometencyReview_SP]  @CompetencyReviewId INT = NULL,      @FinancialYear NVARCHAR(50),      @Quarter INT,      @CorecompetencyId INT,      @EmpId INT,      @ReviewerId INT,    @ReviewersComments NVARCHAR(512),      @ReviewerLevel INT,      @IsSubmitted BIT,      @LoggedInUser INT,      @Action NVARCHAR(50)      AS      BEGIN       IF(@Action = 'INSERT')       BEGIN             IF(EXISTS(SELECT * FROM dbo.PMS_QuarterlyCoreCometencyReview WHERE       FinancialYear = @FinancialYear AND Quarter = @Quarter AND CorecompetencyId = @CorecompetencyId       AND ReviewerLevel = @ReviewerLevel AND EmpId = @EmpId AND CaptureId = @LoggedInUser AND ReviewerId = @ReviewerId AND IsSubmitted != 1))       BEGIN       DELETE FROM dbo.PMS_QuarterlyCoreCometencyReview WHERE         FinancialYear = @FinancialYear AND Quarter = @Quarter AND CorecompetencyId = @CorecompetencyId       AND ReviewerLevel = @ReviewerLevel AND EmpId = @EmpId AND ReviewerId = @ReviewerId AND CaptureId = @LoggedInUser       END        INSERT INTO dbo.PMS_QuarterlyCoreCometencyReview        (            FinancialYear,            Quarter,            CorecompetencyId,         EmpId,         ReviewerId,          ReviewersComments,            ReviewerLevel,         IsSubmitted,            DateCaptured,            CaptureId,            DateModified,            ModfierID        )        VALUES        (   @FinancialYear,        @Quarter,        @CorecompetencyId,     @EmpId,     @ReviewerId,        @ReviewersComments,        @ReviewerLevel,     @IsSubmitted,        GETDATE(),        @LoggedInUser,        NULL,        NULL        )       END      END

GO

