-- ============================================
-- SP: PMS_ReportScorecardSetup_sp
-- Schema: dbo
-- ============================================
-- =========================================================================  -- Author:  Chris Moodley  -- Create date: 29 November 2014  -- Description: Return fields and their values to set up scorecard reports  -- 20240628 by CM: 110904 - Return field for midyear and annual actual custom fields  -- [dbo].[PMS_ReportScorecardSetup_sp] '2023/2024', 1  -- =========================================================================  CREATE PROCEDURE [dbo].[PMS_ReportScorecardSetup_sp]    -- Add the parameters for the stored procedure here   @finYear NVARCHAR(50),   @scorecardTypeID INT  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;        -- Insert statements for procedure here   SELECT    ISNULL(ReportScorecardDetailIDPLevel_ID, 0) AS ID,    ISNULL(ReportScorecardHeaderID, 0) AS HeaderID,    IDPLevelDescDetail_ID AS FieldID,    IDPLevelDesc AS FieldDesc,    ISNULL(IDPLevelDescIncluded, 0) AS FieldIncluded,    IDPLevelOrderNumber AS OrderNumber,    'IDP' AS FieldSection   FROM    Const_IDPLevelDescription_Header idpHeader LEFT JOIN     Const_IDPLevelDescription_Detail idpDetail ON      idpHeader.IDPLevelDescHeader_ID = idpDetail.IDPLevelDescHeaderID LEFT JOIN     (SELECT      rptIDPLevel.*      FROM      PMS_ReportScorecardSetup_Header rptHeader LEFT JOIN       PMS_ReportScorecardSetup_DetailIDPLevel rptIDPLevel ON        rptHeader.ReportScorecardHeader_ID = rptIDPLevel.ReportScorecardHeaderID      WHERE       FinancialYear = @finYear AND ScorecardTypeID = @scorecardTypeID) rptIDP ON      idpDetail.IDPLevelDescDetail_ID = rptIDP.IDPLevelDescDetailID   WHERE    FinancialYear = @finYear     UNION     SELECT    ISNULL(ReportScorecardDetailIndicator_ID, 0) AS ID,    ISNULL(ReportScorecardHeaderID, 0) AS HeaderID,    ReportScorecardColumn_ID AS FieldID,    ColumnDesc AS FieldDesc,    ISNULL(ColumnIncluded, 0) AS FieldIncluded,    ColumnOrderNumber AS OrderNumber,    'Indicator' AS FieldSection   FROM    PMS_ReportScorecardSetup_sys rptSys LEFT JOIN     (SELECT       rptIndicator.*      FROM      PMS_ReportScorecardSetup_Header rptHeader LEFT JOIN       PMS_ReportScorecardSetup_DetailIndicator rptIndicator ON        rptHeader.ReportScorecardHeader_ID = rptIndicator.ReportScorecardHeaderID      WHERE       FinancialYear = @finYear AND ScorecardTypeID = @scorecardTypeID) rptIndicator ON      rptSys.ReportScorecardColumn_ID = rptIndicator.ReportScorecardColumnID     UNION     SELECT    ISNULL(ReportScorecardDetailIndicatorCustomField_ID, 0) AS ID,    ISNULL(ReportScorecardHeaderID, 0) AS HeaderID,     CustomFieldDetail_ID As FieldID,    CustomFieldDesc AS FieldDesc,    ISNULL(CustomFieldIncluded, 0) AS FieldIncluded,    CustomFieldOrderNumber AS OrderNumber,    'IndicatorCustomField' AS FiedSection   FROM    Const_PMSIndicatorCustomField_Header customFieldHeader LEFT JOIN     Const_PMSIndicatorCustomField_Detail customFieldDetail ON      customFieldHeader.CustomFieldHeader_ID = customFieldDetail.CustomFieldHeaderID LEFT JOIN     (SELECT      rptCustomField.*      FROM      PMS_ReportScorecardSetup_Header rptHeader LEFT JOIN        PMS_ReportScorecardSetup_DetailIndicatorCustomField rptCustomField ON        rptHeader.ReportScorecardHeader_ID = rptCustomField.ReportScorecardHeaderID      WHERE      FinancialYear = @finYear AND ScorecardTypeID = @scorecardTypeID) rptCustomField ON      CustomFieldDetail_ID = rptCustomField.CustomFieldDetailID   WHERE    FinancialYear = @finYear AND customFieldHeader.CustomFieldSubmitted = 1 AND customFieldDetail.CustomFieldEnabled = 1     UNION     SELECT    ISNULL(ReportScorecardDetailIndicatorAnnualCustomField_ID, 0) AS ID,    ISNULL(ReportScorecardHeaderID, 0) AS HeaderID,     AnnualFieldDetail_ID As FieldID,    AnnualFieldDesc AS FieldDesc,    ISNULL(AnnualCustomFieldIncluded, 0) AS FieldIncluded,    AnnualCustomFieldOrderNumber AS OrderNumber,    'IndicatorCustomFieldAnnual' AS FiedSection   FROM    Const_PMSAnnualField_Header customFieldHeader LEFT JOIN     Const_PMSAnnualField_Detail customFieldDetail ON      customFieldHeader.AnnualFieldHeader_ID = customFieldDetail.AnnualFieldHeaderID LEFT JOIN     (SELECT      rptCustomField.*      FROM      PMS_ReportScorecardSetup_Header rptHeader LEFT JOIN        PMS_ReportScorecardSetup_DetailIndicatorCustomFieldAnnual rptCustomField ON        rptHeader.ReportScorecardHeader_ID = rptCustomField.ReportScorecardHeaderID      WHERE      FinancialYear = @finYear AND ScorecardTypeID = @scorecardTypeID) rptCustomField ON      AnnualFieldDetail_ID = rptCustomField.AnnualCustomFieldID   WHERE    FinancialYear = @finYear AND customFieldHeader.AnnualFieldSubmitted = 1 AND customFieldDetail.AnnualFieldEnabled = 1     UNION     SELECT    ISNULL(ReportScorecardDetailIndicatorMidYearCustomField_ID, 0) AS ID,    ISNULL(ReportScorecardHeaderID, 0) AS HeaderID,     MidYearFieldDetail_ID As FieldID,    MidYearFieldDesc AS FieldDesc,    ISNULL(MidYearCustomFieldIncluded, 0) AS FieldIncluded,    MidYearCustomFieldOrderNumber AS OrderNumber,    'IndicatorCustomFieldMidYear' AS FiedSection   FROM    Const_PMSMidYearField_Header customFieldHeader LEFT JOIN     Const_PMSMidYearField_Detail customFieldDetail ON      customFieldHeader.MidYearFieldHeader_ID = customFieldDetail.MidYearFieldHeaderID LEFT JOIN     (SELECT      rptCustomField.*      FROM      PMS_ReportScorecardSetup_Header rptHeader LEFT JOIN        PMS_ReportScorecardSetup_DetailIndicatorCustomFieldMidYear rptCustomField ON        rptHeader.ReportScorecardHeader_ID = rptCustomField.ReportScorecardHeaderID      WHERE      FinancialYear = @finYear AND ScorecardTypeID = @scorecardTypeID) rptCustomField ON      MidYearFieldDetail_ID = rptCustomField.MidYearCustomFieldID   WHERE    FinancialYear = @finYear AND customFieldHeader.MidYearFieldSubmitted = 1 AND customFieldDetail.MidYearFieldEnabled = 1     ORDER BY    FieldSection, FieldID    END

GO

-- ============================================
-- SP: PMS_SubmitQuarterlyAssessment
-- Schema: dbo
-- ============================================
CREATE PROCEDURE [dbo].[PMS_SubmitQuarterlyAssessment]  @FinancialYear NVARCHAR(50),            @Quarter INT,           @EmpId INT,       @ReviewerId INT,    @CapturedId INT,            @ReviewerLevel int            AS            BEGIN            BEGIN TRY     BEGIN TRANSACTION     UPDATE dbo.PMS_KPAQuarterlyAssessment SET            IsSubmitted = 1,          SubmittedOn = GETDATE()          WHERE            FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND ReviewerId = @ReviewerId and CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel;                        UPDATE dbo.PMS_QuarterlyCoreCometencyReview            SET             IsSubmitted = 1  ,          SubmittedOn = GETDATE()          WHERE            FinancialYear = @FinancialYear AND Quarter = @Quarter AND EmpId = @EmpId AND ReviewerId = @ReviewerId AND CaptureId = @CapturedId AND ReviewerLevel = @ReviewerLevel;                 COMMIT TRANSACTION    END TRY    BEGIN CATCH     ROLLBACK TRANSACTION    END CATCH       END

GO

